C   Main collection of Ptolemy subroutines
C
C  Nov 2001 - many small changes to make this more Fortran standard
C             compliant.  Add some necessary SAVE statements.
C
C*ID* AITLAG   C109.PTOLEMY.SOURCE                          PER701  15:
      FUNCTION  AITLAG ( X, STPINV, TABLE, NTABLE, NAIT )
C
C     AITKEN-LAGRANGE INTERPOLATION FOR THE DWBA
C                                                                          10   
C     PERFORMS AITKENS LAGRANGE INTERPOLATION.  THIS ROUTINE IS
C     SPECIFICALLY DESIGNED FOR THE DWBA CODE.  IT MAKES NO ERROR
C     CHECKS AND IS SPECIALIAZED IN A NUMBER OF PLACES
C
C     X - VALUE TO BE INTERPOLATED TO.
C     STPINV - INVERSE OF THE TABLE STEP SIZE.
C     TABLE - THE TABLE OF GIVEN FUNCTION VALUES.
C          TABLE(I+1) = F( I/STPINV )
C          NOTE THAT TABLE(1) ALWAYS CORRESPONDS TO X = 0.
C     NTABLE - THE NUMBER OF ENTRIES IN TABLE.                             20   
C     NAIT - THE ORDER OF INTERPOLATION TO USE.  NAIT+1 POINTS
C            WILL BE USED.
C
C     2/14/75 - FIRST VERSION, S. PIEPER
C     2/24/75 - CORRECT ERROR FOR INTERPOLATION AT ENDPOINT
C     12/26/79 - STANDARD PREFIXES - RPG
C     1/14/80 - CORRECT ABOVE: CHARACTER TO REAL - RPG
C
      implicit real*8 ( a-h, o-z )                                      implicit
CDC      ALLOCLEVEL TABLE                                                  30   
C
      DIMENSION  TABLE(NTABLE)
C
      REAL*8  FS(16), DELS(16)
C
CIB      REAL*8  HOLD / Z 4E800000 00000000 /
CIB      INTEGER ITABL2(2)
CIB      EQUIVALENCE ( ITABL2(1), DITABL )
CIB      INTEGER NO8 / Z 4E000000 /
CIB      REAL*8  DZERO / Z 00000000 00000000 /                             40   
C
CDC%';DATA' = '";DATA"' ;
C
C     FOLLOWING ARE INVERSES OF INTEGERS
C
      REAL*8  INVERS(16)
C
CIB      DATA INVERS( 1) / Z4110000000000000 /
CIB      DATA INVERS( 2) / Z4080000000000000 /
CIB      DATA INVERS( 3) / Z4055555555555555 /                             50   
CIB      DATA INVERS( 4) / Z4040000000000000 /
CIB      DATA INVERS( 5) / Z4033333333333333 /
CIB      DATA INVERS( 6) / Z402AAAAAAAAAAAAB /
CIB      DATA INVERS( 7) / Z4024924924924925 /
CIB      DATA INVERS( 8) / Z4020000000000000 /
CIB      DATA INVERS( 9) / Z401C71C71C71C71C /
CIB      DATA INVERS(10) / Z401999999999999A /
CIB      DATA INVERS(11) / Z401745D1745D1746 /
CIB      DATA INVERS(12) / Z4015555555555555 /
CIB      DATA INVERS(13) / Z4013B13B13B13B14 /                             60   
CIB      DATA INVERS(14) / Z4012492492492492 /
CIB      DATA INVERS(15) / Z4011111111111111 /
CIB      DATA INVERS(16) / Z4010000000000000 /
C
      DATA INVERS( 1) /    0.100000000000000000  0D+01 /                cni
      DATA INVERS( 2) /    0.500000000000000000  0D+00 /                cni
      DATA INVERS( 3) /    0.333333333333333329  0D+00 /                cni
      DATA INVERS( 4) /    0.250000000000000000  0D+00 /                cni
      DATA INVERS( 5) /    0.199999999999999997  0D+00 /                cni
      DATA INVERS( 6) /    0.166666666666666671  0D+00 /                   70   
      DATA INVERS( 7) /    0.142857142857142863  0D+00 /                cni
      DATA INVERS( 8) /    0.125000000000000000  0D+00 /                cni
      DATA INVERS( 9) /    0.111111111111111105  0D+00 /                cni
      DATA INVERS(10) /    0.100000000000000006  0D+00 /                cni
      DATA INVERS(11) /    0.909090909090909116  0D-01 /                cni
      DATA INVERS(12) /    0.833333333333333287  0D-01 /                cni
      DATA INVERS(13) /    0.769230769230769273  0D-01 /                cni
      DATA INVERS(14) /    0.714285714285714246  0D-01 /                cni
      DATA INVERS(15) /    0.666666666666666657  0D-01 /                cni
      DATA INVERS(16) /    0.625000000000000000  0D-01 /                   80   
C
c
CDC%';DATA' = ';INDATA'
C
C     FIND THE LOCATION OF X IN THE TABLE
C
      IF ( X .LT. 0 )  GO TO 900
      XBYH = X*STPINV
CIB      DITABL = XBYH + HOLD
CIB      ITABL2(1) = NO8                                                   90   
CIB      ITABLE = ITABL2(2)
      ITABLE = XBYH                                                     cni
C     FOLLOWING TEST ALLOWS US TO GO ONE STEPSIZE BEYOND TABLE
      IF ( ITABLE .GE. NTABLE )  GO TO 920
C
C     GET RANGE OF TABLE TO USE
C
      NAIT2 = NAIT/2
      NSTART = ITABLE - NAIT2
      IF ( NSTART .LT. 0 )  NSTART = 0                                    100   
      NEND = NSTART + NAIT
      IF ( NEND .GE. NTABLE )  NEND = NTABLE - 1
      NSTART = NEND - NAIT
C
C     GET FIRST VALUE
C
      FS(1) = TABLE(NSTART+1)
CIB      ITABL2(2) = NSTART
CIB      DEL1 = (DZERO-DITABL) + XBYH
      DEL1 = XBYH-NSTART                                                  110   
      DELS(1) = DEL1
C
C     NOW DO THE AITKEN LOOP
C
      DO 199  I = 1, NAIT
         F = TABLE(NSTART+1+I)
         DEL1 = DEL1 - 1
C
         DO 189  J = 1, I
            F = ( F*DELS(J) - FS(J)*DEL1 ) * INVERS(I+1-J)                120   
 189     CONTINUE
         DELS(I+1) = DEL1
         FS(I+1) = F
 199  CONTINUE
C
 300  AITLAG = F
      RETURN
C
C     ERROR ... X OUT OF BOUNDS
C                                                                         130   
 900  write (6, 903) X
 903  FORMAT ('0****** AITLAG - X < 0:', G15.5 )
      AITLAG = TABLE(1)
      RETURN
C
 920  write (6, 923) X, ITABLE, NTABLE
 923  FORMAT ('0***** AITLAG - X TOO LARGE:', G15.5, 2I10 )
      AITLAG = TABLE(NTABLE)
      RETURN
C                                                                         140   
      END
C*ID* AKFCR    C109.PTOLEMY.SOURCE                          PER701  21:
      SUBROUTINE AKFCR(L1,J1,L2,J2,LXX2,J,AKREST)
C
C     CONSTRUCTION OF KINEMATICAL FACTORS  W(1,2)
C     SEE THE NOTES, EQN 21
C
C     7/2/80 FIRST VERSION MRB
C     1/11/81 - BOHR & MOTTELSON CONVENTIONS - S.P.
C                                                                         150   
      implicit real*8 ( a-h, o-z )                                      implicit
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
      REAL*4 AKREST
C
      IF((L1.LT.0).OR.(L2.LT.0))GO TO 10
      RME=CLEBSH(L1,LXX2,0,0,L2,0)*SIXJ(J1,L1,J,L2,J2,LXX2)
     1   *(-1)**((J1+L1+J)/2)/RT4PI
     1   *DSQRT((LXX2+1.0D0)*(L1+1.0D0))
      AKREST=RME
      GO TO 20                                                            160   
 10   AKREST=0.
20    RETURN
      END
C*ID* ALSORT   C109.PTOLEMY.SOURCE                          PER701
      SUBROUTINE ALSORT(A,IX,N)
C - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - -
C   SUBROUTINE ALSORT: ALPHABETIZES THE R*8 ARRAY A..RETURNS IX
C       ALSORT ALPHABETIZES THE 8-BYTE LITERAL VARIABLES IN THE
C   ARRAY 'A'.  IT RETURNS AN INDEX ARRAY IX SUCH THAT THE ALPHABETICAL
C   ORDER OF 'A' IS                                                       170   
C     A(IX(1)) , A(IX(2)) , ... , A(IX(N))
C  A  - AN N-ELEMENT ARRAY OF 8-BYTE LITERALS
C  IX - AN N-ELEMENT INTEGER*4 ARRAY RETURNED BY ALSORT
C  N  - THE NUMBER OF ELEMENTS OF A AND IX
C  THIS ROUTINE USES A VERY CRUDE SORTING TECHNIQUE AND IT SHOULD NOT
C  BE USED FOR ARRAYS WITH MORE THAN A FEW HUNDRED ELEMENTS. THE ONLY
C  #ADVANTAGE' OF THIS PROGRAM IS THAT IT TAKES UP SOMEWHAT LESS CORE
C  THAN ROUTINES THAT USE MUCH FASTER SORTING ALGORITHMS
C       CAUTION:  IF THIS PROGRAM IS GIVEN AN ARRAY OF NUMBERS, IT WILL
C                 RETURN THEM IN --DECREASING-- ORDER.  THIS IS BECAUSE   180   
C                 'NUMERICALLY' IN FORTRAN.....A>B>...>Z.
C     THE ABOVE CAUTION APPLIES TO THE IBM VERSION ONLY.
C - - - - - - - - - - - - - - - - -   FRANK SERDUKE  10/15/73
C     12/26/79 - STANDARD PREFIXES, NON-INVERTED SORT - RPG
C
      CHARACTER*8 A(N)                                                  cnd
CDC      INTEGER A(N)
      INTEGER*4 IX(N)
C -- INITIALIZE THE INDEX ARRAY
      DO 10 I=1,N                                                         190   
10    IX(I) = I
C
               IF ( N .LE. 1 ) GO TO 40
C
C --- BEGIN THE BUBBLE SORT ON THE INDICES
         JLIM = N
         ILIM = N-1
C
      DO 30 I=1,ILIM
         JLIM = JLIM - 1                                                  200   
         IEX  = 0
            DO 20 J=1,JLIM
               II = IX(J)
               JJ = IX(J+1)
CIB            IF ( A(II) .GE. A(JJ) ) GO TO 20
CDC            IAII = AND( SHIFT(A(II),-1), 37777777777777777777B )
CDC            IAJJ = AND( SHIFT(A(JJ),-1), 37777777777777777777B )
CDC            IF ( IAII .LE. IAJJ ) GO TO 20
            IF ( A(II) .LE. A(JJ) )  GO TO 20                           cnd
                   IEX = IEX + 1                                          210   
                   ITEMP = IX(J)
                   IX(J) = IX(J+1)
                   IX(J+1) = ITEMP
20        CONTINUE
       IF ( IEX .EQ. 0 ) GO TO 40
30    CONTINUE
40    RETURN
      END
C*ID* AMPCAL   C109.PTOLEMY.SOURCE                          PER701  14:
      SUBROUTINE AMPCAL ( ANGLE, ELSW, NSPL, LMN, LMX, LSKP,              220   
     1   LXMX, IDNPAR, ETA, UK, SIGZRO, LOHISW, LHI,
     2   JTOCS, BETAS, ALOWFC,
     3   F, FLO, FHI, FERROR, FCOUL, PLM, CONTR, CONTI,
     4   LEBACK, FEPSLO, NFLOP )
C
C
C     CALCULATES THE TRANSITION AMPLITUDES F AT ONE ANGLE.
C
C
C     INPUT SCALARS:                                                      230   
C
C     ANGLE = C.M. ANGLE (DEGREES).
C     ELSW = .TRUE. FOR ELASTIC SCATTERING.
C     NSPL = NUMBER OF AMPLITUDES F.
C     LMN, LMX, LSKP = MINIMUM, MAXIMUM, INCREMENT IN INCOMING L.
C     LXMX = MAXIMUM LX.
C     IDNPAR = 0 IF THERE ARE NO IDENTICAL PARTICLES
C            = 1 IF ONLY ONE PAIR (IN OR OUT) IS IDENTICAL
C            = 2 IF BOTH PAIRS ARE IDENTICAL
C     ETA = COULOMB PARAMETER (ELASTIC ONLY).                             240   
C     UK = INCIDENT WAVENUMBER (ELASTIC ONLY).
C     SIGZRO = L=0 COULOMB PHASE (ELASTIC ONLY).
C     LOHISW = .TRUE. IF FLO AND FHI ARE TO BE RETURNED.
C     LHI = MAXIMUM L TO BE INCLUDED IN FHI.
C     LEBACK - NUMBER OF L VALUES TO USE IN THE EPSILON
C              ALGORITHM;  0 MEANS NOT TO BE USED.
C
C     OUTPUT SCALAR
C
C     NFLOP - APPROX NUMBER OF FLOATING OPS IN THIS CALL                  250   
C
C     INPUT ARRAYS (AND DIMENSIONS)):
C
C     JTOCS(4,NSPL) = TABLE-OF-CONTENTS FOR S AND F (SEE ANGSET).
C     BETAS(2,NSPL,LMX-LBASE+1) = (R*4) BETA (SEE BETCAL).
C     ALOWFC(2,2) = BETA CONTRIBUTIONS FROM LX=0, L=LMN,LMN+1 FROM
C        NONZERO S (ELASTIC ONLY).  (SEE BETCAL.)
C
C     OUTPUT ARRAYS:
C                                                                         260   
C     F(2,NSPL) = TRANSITION AMPLITUDES SUMMED FROM LMN TO LHI
C     FLO(2,NSPL) = F CONTRIBUTIONS FROM LMN+2 <= LO <= LMX.
C     FHI(2,NSPL) = F CONTRIBUTIONS FROM LMN <= LO <= LHI.
C     IF LEBACK > 0, THE ABOVE THREE ARRAYS ARE ALL EPSILON ACCELERATED
C     FERROR(NSPLI) = THE RELATIVE ERRORS IN |F| AS DETERMINED
C           BY THE EPSILON ALGORITHM OR FROM THE LAST TWO ELEMENTS.
C           FOR ELASTIC SCAT IT IS THE RELATIVE ERROR IN |F-FCOUL|.
C     FCOUL(2,3) = COULOMB AMPLITUDES (ELASTIC ONLY).
C     PLM(LMX+1+((2*LMX+1-LXMX)*LXMX)/2) = ASSOCIATED LEGENDRE
C        FUNCTIONS.  INDEX = LO+1 + MX* (2*LMX+1-MX )/2 .                 270   
C     CONTR, CONTI - WORK ARRAYS OF DIMENSION LMX+1
C     FEPSLO - WORK ARRAY OF DIMENSION 2*LEBACK
C
C     NOTE:  FOR ELASTIC SCATTERING OF IDENTICAL PARTICLES, ARRAYS
C     F, FLO, FHI, AND FCOUL ARE DIMENSIONED (2,3), AND WILL CONTAIN
C     SYMMETRIC, ANTISYMMETRIC, AND UNSYMMETRIZED COMBINATIONS
C     OF AMPLITUDES.
C
C
C     8/31/79 - NEW ROUTINE, FROM XSECTN AND ELDCS - RPG                  280   
C     1/31/80 - CHECK COULOMB AMPLITUDE AGAINST BIGNUM - RPG
C     4/3/80 - REAL*4 BETAS - S.P.
C     7/28/80 - REARRANGED TO ALLOW PARALLEL PROCESSING - S.P.
C     7/30/80 - USE THE BLA SSUM IN THE CRAY VERSION - S.P.
C     9/11/80 - FIX BUGS FOR LSKP=2 - S.P.
C     9/26/80 - DON'T CONSIDER LO < MX - S.P.
C     9/29/80 - FIX BUGS FOR LMAX=LIMOST - S.P.
C     6/12/81 - FIX BUG FOR LMIN=LIMOST - S.P.
C     9/17/81 - USE EPSILON ALGORITHM - S.P.
C     10/9/81 - FIX MANY BUGS FOR LSKIP=2 - S.P.                          290   
C     10/27/81 - EXTRA ROOT 2 NEEDED FOR IDENTICAL MUTUAL - S.P.
C
C******* ELAS NOT YET DONE FOR IDENTICAL PARTICLES EFFICENTLY ********
C
C
      implicit real*8 ( a-h, o-z )                                      implicit
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
C
      LOGICAL  ELSW, IDENSW, LOHISW
      REAL*4 BETAS                                                        300   
      DIMENSION  JTOCS(4,1), BETAS(2,NSPL,1), ALOWFC(2,2),
     1   F(2,*), FLO(2,*), FHI(2,*), FCOUL(2,3), PLM(1), CONTR(1),
     2   CONTI(1), FERROR(1), FEPSLO(2, 1)
C
      LOGICAL  IDELSW
      DIMENSION  FT(2), FTS(2), FTC(2), FTSC(2), FOUT(2)
C
CDC      ALLOCLEVEL  JTOCS, BETAS, F, FLO, FHI, PLM, CONTR, CONTI
c
C                                                                         310   
C
C     INITIALIZATION
C
      NFLOP = 0
      NNFLOP = 0
      IODD = MOD( IABS( JTOCS(1,1) ), 2 )
      LOMN = LMN
      IF ( LSKP .EQ. 2 )  LOMN = LOMN + IODD
      LOMX = LMX
      IF ( LSKP .EQ. 2 )  LOMX = LOMX - MOD(LOMX+IODD, 2)                 320   
      LOHI = LHI
      IF ( LSKP .EQ. 2 )  LOHI = LOHI - MOD(LOHI+IODD, 2)
      LBASE = LMN
      IDENSW = IDNPAR .NE. 0
      FACMBL = 1
      IF ( IDENSW  .AND.  .NOT. ELSW )  FACMBL = DSQRT( 2.0D0 )
      IF ( IDNPAR .EQ. 2  .AND.  .NOT. ELSW )  FACMBL = 2
      IDELSW = IDENSW .AND. ELSW
      N = 2*NSPL
      IF ( IDELSW )  N = 6                                                330   
      DO 39  K = 1, N
         F(K,1) = 0
         IF ( .NOT. LOHISW )  GO TO 39
         FLO(K,1) = 0
         FHI(K,1) = 0
 39   CONTINUE
C
C     CALCULATE THE LEGENDRE FUNCTIONS.
C
      AN = DEGREE*ANGLE                                                   340   
      ACOS = DCOS( AN )
      CALL PLMSUB( LMX, LXMX, ACOS, PLM )
      NFLOP = 16 + 7*(LMX+1)*(LXMX+1)
C
C     ELASTIC:  CALCULATE THE COULOMB AMPLITUDE.
C     IDENTICAL PARTICLES NEED IT FOR BOTH ANGLE AND PI-ANGLE.
C
      IF ( .NOT. ELSW )  GO TO 100
      LOMN = 0
      LBASE = 0                                                           350   
      TEMP = DSIN( 0.5*AN )
      TEMP = DMAX1( TEMP, 1.0D-10 )
      PHASE = 2*( SIGZRO - ETA*DLOG( TEMP ) )
      TEMP = -0.5*ETA/(UK*TEMP**2)
      IF ( DABS(TEMP) .GT. BIGNUM )  TEMP = DSIGN( BIGNUM, TEMP )
      FTC(1) = TEMP*DCOS( PHASE )
      FTC(2) = TEMP*DSIN( PHASE )
      FTSC(1) = 0
      FTSC(2) = 0
      NFLOP = NFLOP + 72                                                  360   
      IF ( .NOT. IDENSW )  GO TO 80
      AN = PI - AN
      TEMP = DSIN( 0.5*AN )
      TEMP = DMAX1( TEMP, 1.0D-10 )
      PHASE = 2*( SIGZRO - ETA*DLOG( TEMP ) )
      TEMP = -0.5*ETA/(UK*TEMP**2)
      IF ( DABS(TEMP) .GT. BIGNUM )  TEMP = DSIGN( BIGNUM, TEMP )
      FTSC(1) = TEMP*DCOS( PHASE )
      FTSC(2) = TEMP*DSIN( PHASE )
      NFLOP = NFLOP + 72                                                  370   
      FTS(1) = 0
      FTS(2) = 0
C
C     STILL ELASTIC:  STORE SYMMETRIC, ANTISYMMETRIC, AND
C     UNSYMMETRIZED COULOMB AMPLITUDES.
C
 80   DO 89  IRI = 1, 2
         FCOUL(IRI,1) = FTC(IRI) + FTSC(IRI)
         FCOUL(IRI,2) = FTC(IRI) - FTSC(IRI)
         FCOUL(IRI,3) = FTC(IRI)                                          380   
 89   CONTINUE
      NFLOP = NFLOP + 4
C
C     LOOP THROUGH KOFFS = JT, JP, LX, MX.
C
 100  DO 299  KOFFS = 1, NSPL
         IF ( JTOCS(4,KOFFS) .LT. 0 )  GO TO 299
         LX = JTOCS(2,KOFFS)
         MX = ( JTOCS(1,KOFFS) + LX + 1 )/2
         LOMNMX = MAX0( LOMN, MX )                                        390   
         IF ( LSKP .EQ. 2 )  LOMNMX = LOMNMX + MOD( LOMNMX+IODD, 2 )
         FT(1) = 0
         FT(2) = 0
         LPLM = MX*(2*LMX+1-MX)/2 + 1
C
C        SUM OVER LO.
C
C     FLO = AMPLITUDE FROM LO = LOMN, LOMN+1.
C     FOR ELASTIC AND LX=0, IT DOES NOT INCLUDE THE 1 IN 1-S(L)
C                                                                         400   
         IF ( LX .NE. 0  .OR.  .NOT. ELSW )  GO TO 110
         IF ( .NOT. LOHISW )  GO TO 110
         LTEMP = LOMN + 1
         DO 109  LO = LOMN, LTEMP, LSKP
            PLMFAC = FACMBL*PLM(LO+1)
            LPARIT = MOD( LO, 2 ) + 1
            FLO(1,1) = FLO(1,1) + PLMFAC*ALOWFC(1,LPARIT)
            FLO(2,1) = FLO(2,1) + PLMFAC*ALOWFC(2,LPARIT)
 109     CONTINUE
         NNFLOP = 5*(2+LSKP)                                              410   
C
C     COMPUTE ALL CONTRIBUTIONS FROM NON-ZERO S-MATIRCES
C
 110     DO 119  LO = LOMNMX, LOMX, LSKP
            PLMFAC = FACMBL*PLM(LO+LPLM)
            CONTR(LO+1) = PLMFAC*BETAS(1,KOFFS,LO-LBASE+1)
            CONTI(LO+1) = PLMFAC*BETAS(2,KOFFS,LO-LBASE+1)
 119     CONTINUE
         NNFLOP = NNFLOP + 5*(LOMX-LOMNMX+LSKP)
C                                                                         420   
C     FIRST SUM AMPLITUDE UP TO LMIN+1 TO GET FLO
C
         LTEMP = MIN0( LOMN+1, LOMX )
         IF ( LTEMP .LT. LOMNMX )  GO TO 125
         DO 124  LO = LOMNMX, LTEMP, LSKP                               cnr
            FT(1) = FT(1) + CONTR(LO+1)                                 cnr
            FT(2) = FT(2) + CONTI(LO+1)                                 cnr
 124     CONTINUE                                                       cnr
C
CRA      NUM = (LTEMP-LOMNMX)/LSKP + 1                                    430   
CRA      FT(1) = FT(1) + SSUM( NUM, CONTR(LOMNMX+1), LSKP )
CRA      FT(2) = FT(2) + SSUM( NUM, CONTI(LOMNMX+1), LSKP )
C
 125     IF ( .NOT. LOHISW )  GO TO 130
         IF ( ELSW  .AND.  LX .EQ. 0 )  GO TO 130
         FLO(1,KOFFS) = FT(1)
         FLO(2,KOFFS) = FT(2)
C
C     SUM CONTRIBUTION FOR LMIN+2 TO LMAX  (LMAX-2 FOR ELASTIC)
C                                                                         440   
 130     LTEMP = MAX0( LOMN+2, LOMNMX )
            IF ( LTEMP .GT. LOHI )  GO TO 140
         DO 139  LO = LTEMP, LOHI, LSKP                                 cnr
            FT(1) = FT(1) + CONTR(LO+1)                                 cnr
            FT(2) = FT(2) + CONTI(LO+1)                                 cnr
 139     CONTINUE                                                       cnr
C
CRA      NUM = (LOHI-LTEMP)/LSKP + 1
CRA      FT(1) = FT(1) + SSUM( NUM, CONTR(LTEMP+1), LSKP )
CRA      FT(2) = FT(2) + SSUM( NUM, CONTI(LTEMP+1), LSKP )                450   
C
C     FHI = AMPLITUDE FROM  LO <= LOHI.
C
 140     FHI(1,KOFFS) = FT(1)
         FHI(2,KOFFS) = FT(2)
C
C     NOW THE LAST TERMS > LMAX OR LMAX-1
C
         LTEMP = LOHI+LSKP
         IF ( LTEMP .GT. LOMX )  GO TO 150                                460   
         DO 149  LO = LTEMP, LOMX, LSKP                                 cnr
            FT(1) = FT(1) + CONTR(LO+1)                                 cnr
            FT(2) = FT(2) + CONTI(LO+1)                                 cnr
 149     CONTINUE                                                       cnr
C
CRA      NUM = (LOMX-LTEMP)/LSKP + 1
CRA      FT(1) = FT(1) + SSUM( NUM, CONTR(LTEMP+1), LSKP )
CRA      FT(2) = FT(2) + SSUM( NUM, CONTI(LTEMP+1), LSKP )
C
C                                                                         470   
C     IF NECESSARY APPLY EPSILON ALGORITHM
C
 150     FERROR(KOFFS) = ( DABS(CONTR(LOMX+1))+DABS(CONTI(LOMX+1)) )
     1      / ( DABS(FT(1))+DABS(FT(2)) + SMLNUM )
         IF ( LEBACK .LE. 0 )  GO TO 200
         N = MIN0( (LOMX-LOMNMX)/LSKP, LEBACK-1 )
         IF ( N .LE. 5 ) GO TO 200
         NN = N+1
         FEPSLO(1,NN) = FT(1)
         FEPSLO(2,NN) = FT(2)                                             480   
         DO 159  I = 1, N
            II = NN-I
            FEPSLO(1,II) = FEPSLO(1,II+1) - CONTR(LOMX+1-LSKP*(I-1))
            FEPSLO(2,II) = FEPSLO(2,II+1) - CONTI(LOMX+1-LSKP*(I-1))
 159     CONTINUE
         CALL EPSLON ( FEPSLO, NN, FT, 1.D-5, FERROR(KOFFS), IER )
C
         N = MIN0( (LOHI-LOMNMX)/LSKP, LEBACK-1 )
         IF ( N .LE. 5 )  GO TO 200
         NN = N+1                                                         490   
         FEPSLO(1,NN) = FHI(1,KOFFS)
         FEPSLO(2,NN) = FHI(2,KOFFS)
         DO 169  I = 1, N
            II = NN-I
            FEPSLO(1,II) = FEPSLO(1,II+1) - CONTR(LOHI+1-LSKP*(I-1))
            FEPSLO(2,II) = FEPSLO(2,II+1) - CONTI(LOHI+1-LSKP*(I-1))
 169     CONTINUE
         CALL EPSLON ( FEPSLO, NN, FOUT, 1.D-5, DUMMY, IER )
         FHI(1,KOFFS) = FOUT(1)
         FHI(2,KOFFS) = FOUT(2)                                           500   
C
C           FOR ELASTIC SCATTERING OF IDENTICAL PARTICLES,
C           DO IT AGAIN FOR PI - ANGLE.
C
C     ****  THIS COULD ALSO BE DONE MORE EFFICENTLY ****
C
 200     IF ( .NOT. IDELSW )  GO TO 270
         DO 259  LO = LOMNMX, LOMX, LSKP
            CONR = CONTR(LO+1)
            CONI = CONTI(LO+1)                                            510   
            IF ( MOD( LO, 2 ) .EQ. 0 )  GO TO 220
            CONR = -CONR
            CONI = -CONI
 220        FTS(1) = FTS(1) + CONR
            FTS(2) = FTS(2) + CONI
            IF ( .NOT. LOHISW )  GO TO 259
            IF ( LO .GT. LOMN+1 )  GO TO 250
            LPARIT = MOD( LO, 2 ) + 1
            PLMFAC = FACMBL*PLM(LO+LPLM)
            IF ( LPARIT .EQ. 2 )  PLMFAC = -PLMFAC                        520   
            FLO(1,2) = FLO(1,2) + PLMFAC*ALOWFC(1,LPARIT)
            FLO(2,2) = FLO(2,2) + PLMFAC*ALOWFC(2,LPARIT)
 250        IF ( LO .NE. LOHI )  GO TO 259
            FHI(1,2) = FTS(1)
            FHI(2,2) = FTS(2)
C
 259     CONTINUE
         NNFLOP = NNFLOP + 5*(LOMX-LOMNMX+LSKP)
C
C        END OF LO SUM.  TRANSFER TO OUTPUT ARRAYS.                       530   
C        FLO IS ALL EXCEPT THE FIRST 2 L'S.
C
 270     F(1,KOFFS) = FT(1)
         F(2,KOFFS) = FT(2)
C
         IF ( .NOT. LOHISW )  GO TO 299
         FLO(1,KOFFS) = FT(1) - FLO(1,KOFFS)
         FLO(2,KOFFS) = FT(2) - FLO(2,KOFFS)
 299  CONTINUE
C                                                                         540   
C     END OF KOFFS LOOP.
C
      NFLOP = NFLOP + NNFLOP/LSKP
C
C     FOR ELASTIC SCATTERING, ADD THE COULOMB AMPLITUDES.
C
      IF ( .NOT. ELSW )  RETURN
      DO 359  IRI = 1, 2
         F(IRI,1) = F(IRI,1) + FTC(IRI)
         IF ( .NOT. LOHISW )  GO TO 330                                   550   
         FHI(IRI,1) = FHI(IRI,1) + FTC(IRI)
         FLO(IRI,1) = FLO(IRI,1) + FTC(IRI)
C
C        FOR ELASTIC SCATTERING OF IDENTICAL PARTICLES,
C        FORM SYMMETRIC, ANTISYMMETRIC, AND UNSYMMETRIZED
C        COMBINATIONS.
C
 330     IF ( .NOT. IDELSW )  GO TO 359
C
         FTS(IRI) = FTS(IRI) + FTSC(IRI)                                  560   
         F(IRI,3) = F(IRI,1)
         F(IRI,1) = F(IRI,3) + FTS(IRI)
         F(IRI,2) = F(IRI,3) - FTS(IRI)
         IF ( .NOT. LOHISW )  GO TO 359
         FLO(IRI,2) = FTS(IRI) - FLO(IRI,2)
         FLO(IRI,3) = FLO(IRI,1)
         FLO(IRI,1) = FLO(IRI,3) + FLO(IRI,2)
         FLO(IRI,2) = FLO(IRI,3) - FLO(IRI,2)
         FHI(IRI,2) = FHI(IRI,2) + FTSC(IRI)
         FHI(IRI,3) = FHI(IRI,1)                                          570   
         FHI(IRI,1) = FHI(IRI,3) + FHI(IRI,2)
         FHI(IRI,2) = FHI(IRI,3) - FHI(IRI,2)
 359  CONTINUE
      NFLOP = NFLOP+6
      RETURN
      END
C*ID* ANAPOW   C109.PTOLEMY.SOURCE                          PER701  10:
      SUBROUTINE ANAPOW ( ANGMIN, ANGMAX, ANGSTP, JA, JB, JBIGA, JBIGB,
     1   NSPL, IPARIT, PRNTSW, PBUGSW, APNAME, ELAB, CHNM,
     2   IF, ITOCS, IAPOW )                                               580   
C
C
C     COMPUTES AND PRINTS ANALYZING POWERS (REACTION OR SCATTERING ).
C
C
C     THE ANALYZING POWERS ARE RETURNED IN AN ALLOCATOR ARRAY POINTED
C     TO BY ARGUMENT IAPOW AND NAMED BY ARGUMENT  APNAME.  THE
C     ANGLE VARIES MOST RAPIDLY, THE ANALYZING POWER TYPE LEAST RAPIDLY.
C     THE TYPES INCLUDE ONLY POSITIVE, ALLOWED VALUES OF Q.
C     IMAGINARY ANALYZING POWERS ARE RETURNED AS THE REAL PART OF         590   
C     I* THE ANALYZING POWER;  I.E. THE ORDER IS IT11, T20, T21, T22,
C     IT31, IT32, IT33, ETC.  K GOES FROM 1 TO 2*JA.
C
C           THE ANALYZING POWERS ARE RELATED TO THE MUELLER MATRIX Z
C     BY THE EQUATION
C        T(K,Q) = (-1)**Q * Z(K,-Q,0,0,0,0,0,0).
C     CHANGING -Q TO Q INTRODUCES (-1)**(K+Q).  FOR ODD K, Z IS
C     IMAGINARY, AND I*T(K,Q) = IM( Z(K,Q,ETC.) ), BECAUSE THE
C     MULTIPLTCATION BY I CANCELS THE (-1)**K.
C                                                                         600   
C
C     INPUT SCALARS:
C
C     ANGMIN, ANGMAX, ANGSTP = MINIMUM, MAXIMUM, STEP IN ANGLE.
C     JA, JB, JBIGA, JBIGB = 2 * SPINS OF THE PARTICLES.
C     NSPL = THE NUMBER OF AMPLITUDES (F) AT EACH ANGLE.
C     IPARIT = THE PARITY CHANGE OF THE REACTION (+1 OR -1).
C     PRNTSW = .TRUE. IF ANALYZING POWERS ARE TO BE PRINTED.
C     PBUGSW = .TRUE. IF DEBUGGING STUFF IS TO BE PRINTED.
C     APNAME = 8-CHARACTER NAME TO BE ASSIGNED TO THE ANALYZING           610   
C        POWER ARRAY ('ANPOW', 'ANPOWA', 'ANPOWB').
C     ELAB = LAB ENERGY ( FOR PRINTING ONLY ).
C     CHNM = 8-CHARACTER NAME IDENTIFYING THE CHANNEL
C        ('REACTION', 'ELASTIC', 'INCOMING', 'OUTGOING').
C
C     INPUT POINTERS (NALLOC'S TO INPUT ARRAYS IN THE ALLOCATOR):
C
C     IF = REACTION AMPLITUDES.
C     ITOCS = TABLE OF CONTENTS FOR F.
C                                                                         620   
C     RETURNED POINTER (NALLOC TO RETURNED ARRAY):
C
C     IAPOW = ANALYZING POWERS.
C
C
C     11/2/79 - NEW ROUTINE - RPG
C     6/26/80 - PASS PBUGSW TO MUELCO - S.P.
C     8/4/80 - CALL SETLOG - S.P.
C     5/3/83 - FIX F SUBSCRIPTS PER 12/14/80 XSECTN CHANGE - S.P.
C     7/19/83 - LAB-ANGLE PRINT OUT - S.P.                                630   
C
C
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
      CHARACTER*1  REACT, HEADER                                        /hedcom/
      COMMON /HEDCOM/  REACT(45), HEADER(65)
 
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
      COMMON /KANDM/ AKI, AKO, REDMI, REDMO, RIMAX, ROMAX, ISIGS(2),    /kandm/
     &  RSCTS(2), ASCTS(2), RCSCTS(2) ,ISMATS(2), LOMOST, LCRIT,
     &  ISCTMN, ISCTCR, ETAS(2), RCSCTP(2), RCSCTT(2), LCRITS(2),
     &  RATMSS(2), QMIN, ABAR
 
      DIMENSION  AKS(2), REDMS(2), RMAXS(2)
      EQUIVALENCE ( AKI, AKS(1) ), ( REDMI, REDMS(1) ),
     &  ( RIMAX, RMAXS(1) )
 
C
      LOGICAL  PRNTSW, PBUGSW, SKIPSW                                     640   
      CHARACTER*8  APNAME, CHNM
      INTEGER  QMIN, Q
      DIMENSION  LSTK(12), LSTQ(12)
      CHARACTER*1  LSTI(12), ILABL(2)
      DATA  ILABL / ' ', 'i' /, LINEMX / 57 /
      CHARACTER*4  LABCM, LABWRD /'LAB.'/, CMWRD /'C.M.'/
C
c
C
C                                                                         650   
C     COUNT AND ALLOCATE THE ANALYZING POWER ARRAY, AND CLEAR IT.
C
      LABCM = CMWRD
      IF ( LABANG .NE. 0 )  LABCM = LABWRD
      NUMANG = ( ANGMAX - ANGMIN )/ANGSTP + 1.5
      NUMAP = ( (JA+2)*JA )/2
      IAPOW = NALLOC( NUMANG*NUMAP, APNAME )
      CALL INIT8 (IAPOW, 0.D0 )
C
C     "APCO" AND "APSCR" ARE THE COEFFICIENT AND SCRATCH ARRAYS USED BY   660   
C     SUBROUTINE MUELCO.  "FTIMESF' IS THE PRODUCT OF AMPLITUDES, AND
C     "TEMPCROS" IS THE CROSS SECTION.
C
      NQ = JA + MOD( JA+1, 2 )
      N = NSPL**2 * NQ
      IAPCO = NALLOC( N, 'APCO    ' )
      N = NQ + 2*JA + 3
      IAPSCR = NALLOC( N, 'APSCR   ' )
      IFTF = NALLOC( NUMANG, 'FTIMESF ' )
      ICROS = NALLOC( NUMANG, 'TEMPCROS' )                                670   
      CALL INIT8 ( ICROS, SMLNUM )
      KCROS = MIN0( JA, 2 )
C
C     ALLOCATIONS ARE FINISHED.  GET ADDRESSES.
C
      CALL SETLOG ( 1 )
C
      LCOEP = Z(IAPSCR)
      LCOET = LCOEP + NQ
      LCOEX = LCOET + 1                                                   680   
      LTERMK = LCOEX + JA + 1
      LTOCS = Z(ITOCS)*FACFR4 - FACFR4
      LF = Z(IF) - 2*NUMANG - 2
      LFTF = Z(IFTF) - 1
      LCROS = Z(ICROS) - 1
C
C     LOOP THROUGH K (1=VECTOR, 2=TENSOR, ETC.).
C
      DO 309  K = 1, JA
C                                                                         690   
         QMIN = MOD( K, 2 )
         NQ = K + 1 - QMIN
         ASSIGN 180 TO JUMPIM
         IF ( QMIN .EQ. 0 )  ASSIGN 170 TO JUMPIM
         LAPOW = ( (K+1)*(K-1) + QMIN )/2 - QMIN
         LAPOW = Z(IAPOW) - 1 + NUMANG*LAPOW
C
C     SUBROUTINE MUELCO CALCULATES THE ANGLE-INDEPENDENT COEFFICIENTS
C     OF F * F'*  FOR ALL F, F', Q, FOR FIXED K.
C                                                                         700   
         CALL MUELCO ( K, 0, 0, 0, JA, JB, JBIGA, JBIGB,
     1      NQ, 1, 1, 1, NSPL, IPARIT,
     2      ILLOC(LTOCS+1), ALLOC(Z(IAPCO)), ALLOC(LCOEP),
     3      ALLOC(LCOET), ALLOC(LCOEX), ALLOC(LTERMK), PBUGSW )
C
C     NOW LOOP THROUGH ALL POSSIBLE F, F'* COMBINATIONS.
C
         DO 289  KOFFP = 1, NSPL
            IF ( ILLOC(LTOCS+4*KOFFP) .LT. 0 )  GO TO 289
            DO 269  KOFF = 1, NSPL                                        710   
               IF ( ILLOC(LTOCS+4*KOFF) .LT. 0 )  GO TO 269
               SKIPSW = .FALSE.
               LAPCO = Z(IAPCO) - QMIN + NQ*( KOFF-1 + NSPL*(KOFFP-1) )
C
C     IF THIS IS A DIAGONAL TERM AND K = MAX( JA, 2 ), INCREMENT THE
C     CROSS SECTION AND FILL IN "FTIMESF".
C
               IF ( KOFF .NE. KOFFP  .OR.  K .NE. KCROS )  GO TO 150
               T = 2.
               MX = ( ILLOC(LTOCS+4*KOFF-3)+ILLOC(LTOCS+4*KOFF-2)+1 )/2   720   
               IF ( MX .EQ. 0 )  T = 1.
               DO 139  NANG = 1, NUMANG
                  I = (LF + 2*NUMANG*KOFF) + 2*NANG
                  ALLOC(LFTF+NANG) = ALLOC(I)**2 + ALLOC(I+1)**2
                  ALLOC(LCROS+NANG) = ALLOC(LCROS+NANG)
     1               + T*ALLOC(LFTF+NANG)
 139           CONTINUE
C
C     PRINT THE COEFFICIENTS IF REQUESTED.
C                                                                         730   
 150           IF ( PBUGSW )  write (6, 153)  KOFF, KOFFP,
     1            ( ALLOC(LAPCO+Q), Q = QMIN, K )
 153           FORMAT ( ' APCO', 2I2, ( T11, 10G12.5 ) )
C
C     LOOP THROUGH THE Q'S, LOOKING FOR A NONZERO COEFFICIENT.
C
               DO 249   Q = QMIN, K
                  IF ( ALLOC(LAPCO+Q) .EQ. 0 )  GO TO 249
C
C     IF NECESSARY, CALCULATE THE F * F'* PRODUCTS AT ALL ANGLES.         740   
C     WE NEED THE REAL PART FOR EVEN K, THE IMAGINARY PART FOR ODD K.
C
                  IF ( SKIPSW )  GO TO 200
                  DO 189  NANG = 1, NUMANG
                     I = (LF + 2*NUMANG*KOFF) + 2*NANG
                     II = (LF + 2*NUMANG*KOFFP) + 2*NANG
                     GO TO JUMPIM, ( 170, 180 )
 170                 ALLOC(LFTF+NANG) = ALLOC(I)*ALLOC(II)
     1                  + ALLOC(I+1)*ALLOC(II+1)
                     GO TO 189                                            750   
 180                 ALLOC(LFTF+NANG) = ALLOC(II)*ALLOC(I+1)
     1                  - ALLOC(I)*ALLOC(II+1)
 189              CONTINUE
                  SKIPSW = .TRUE.
C
C     NOW INCREMENT THE ANALYZING POWERS.
C
 200              LAP = LAPOW + NUMANG*Q
                  T = ALLOC(LAPCO+Q)
                  DO 229  NANG = 1, NUMANG                                760   
                     ALLOC(LAP+NANG) = ALLOC(LAP+NANG)
     1                  + T*ALLOC(LFTF+NANG)
 229              CONTINUE
C
 249           CONTINUE
C     END OF Q LOOP.
C
 269        CONTINUE
C     END OF KOFF LOOP
C                                                                         770   
 289     CONTINUE
C     END OF KOFFP LOOP
C
 309  CONTINUE
C     END OF K LOOP
C
C     FINALLY, DIVIDE THEM ALL BY THE CROSS SECTION.
C
      I = Z(IAPOW)
      DO 339  II = 1, NUMAP                                               780   
         DO 329  NANG = 1, NUMANG
            ALLOC(I) = ALLOC(I)/ALLOC(LCROS+NANG)
            I = I + 1
 329     CONTINUE
 339  CONTINUE
C
C     ALL ANALYZING POWERS ARE COMPUTED.
C     FREE THE TEMPORARY ARRAYS.
C
      Z(IAPCO) = -Z(IAPCO)                                                790   
      Z(IAPSCR) = -Z(IAPSCR)
      Z(IFTF) = -Z(IFTF)
      Z(ICROS) = -Z(ICROS)
C
C     NOW PRINT THEM IF REQUESTED.
C
      IF ( .NOT. PRNTSW )  RETURN
C
C     MAKE SPACES TO MATCH THE CROSS SECTION PRINTOUT.
C                                                                         800   
      ANGBLK = 300
      IF ( NUMANG .LE. 40 )  GO TO 500
      ANGBLK = 10
      IF ( ANGSTP .GE. .99 )  GO TO 500
      ANGBLK = 5
      IF ( ANGSTP .GT. .201 ) GO TO 500
      ANGBLK = 1
 500  NUMBLK = ANGBLK/ANGSTP + .5
C
C     PRINT AS MANY ANALYZING POWERS ON EACH PAGE AS WILL FIT             810   
C     WITHOUT SPLITTING A K.
C
      IIS = Z(IAPOW) - 1
      KS = 1
 550  KE = MIN0( JA, 4 )
      IF ( KS .EQ. 5 )  KE = MIN0( JA, 6 )
      IF ( KS .GT. 5 )  KE = KS
C
C     CONSTRUCT THE COLUMN LABELS FOR THIS PAGE.
C                                                                         820   
      N = 0
      DO 589  K = KS, KE
         QMIN = MOD( K, 2 )
         DO 579  Q = QMIN, K
            N = N + 1
            LSTK(N) = K
            LSTQ(N) = Q
            LSTI(N) = ILABL(QMIN+1)
 579     CONTINUE
 589  CONTINUE                                                            830   
      IIE = IIS + (N-1)*NUMANG
      LINECT = 1000
C
C     LOOP THROUGH ANGLES, PRINTING.
C
      DO 699  NANG = 1, NUMANG
         ANGLE = ANGMIN + ANGSTP*(NANG-1)
         IF ( LABANG .EQ. 0 )  GO TO 602
         IF ( ANGLE .GT. ABAR )  ANGLE = 2*ABAR - ANGLE
C                                                                         840   
C     DO WE NEED A HEADER?
C
 602     IF ( LINECT .LT. LINEMX )  GO TO 620
         write (6, 603)  CHNM, REACT, ELAB, HEADER
 603     FORMAT ( '1', T56, 'P T O L E M Y' /
     1      10X, 'ANALYZING POWERS FOR THE  >>>> ', A8,
     2      ' <<<<  CHANNEL' /
     3      '0', 45A1, F7.2, ' MEV', 5X, 65A1 )
         write (6, 613) labcm, ( LSTI(I), LSTK(I), LSTQ(I), I = 1, N )
 613     FORMAT ( '0', 2X, A4, 1X, 12( 6X, A1, 'T', 2I1 ) )               850   
         write (6, 614)
 614     FORMAT ( '  ANGLE' / )
         LINECT = 8
C
C     PRINT IT, WITH OCCATIONAL SPACES.
C
 620     write (6, 633)  ANGLE, (ALLOC(II+NANG), II = IIS, IIE, NUMANG)
 633     FORMAT ( 1X, F6.2, 2X, 12F10.5 )
         LINECT = LINECT + 1
         IF ( DMOD( ANGLE+ANGSTP+1.D-7, ANGBLK ) .GT. 1.D-5 )             860   
     1      GO TO 699
         write (6, 633)
         LINECT = LINECT + 1
         IF ( LINECT+NUMBLK .GT. LINEMX )  LINECT = 1000
 699  CONTINUE
C     END OF LOOP THROUGH ANGLES.
C
C     IF THERE ARE MORE ANALYZING POWERS, GO PRINT THEM.
C
      IIS = IIE + NUMANG                                                  870   
      KS = KE + 1
      IF ( KS .LE. JA )  GO TO 550
C
      RETURN
      END
C*ID* ANGSET   C109.PTOLEMY.SOURCE                          PER701  11:
      SUBROUTINE ANGSET ( IRTN )
C
C     SETS UP ARRAYS FOR THE ANGULAR TRANSFORMS IN THE RADIAL INTS.
C                                                                         880   
C     THIS ROUTINE IS CALLED AFTER THE WAVPOT CALLS AND BEFORE INELDC.
C     IT ALLOCATES ARRAYS USED BY A12 AND OTHER ARRAYS USED BY
C     INELDC.  IT MUST BE CALLED AFTER WAVPOT TO ALLOW THE COULOMB
C     ROUTINE IN WAVPOT TO USE LOTS OF ALLOCATOR AS TEMPORARY SCRATCH.
C
C     IRTN IS SET TO 0 IF AN ERROR OCCURS, 1 OTHERWISE.
C
C     FOR THE HISTORY PRIOR TO THE SPLIT, SEE GRDSET.
C
C     5/28/75 - SPLIT OFF FROM GRDSET.                                    890   
C     6/11/75 - SAVEHS/USEHS
C     7/20/75 - ALLOW DIFFERENT L'S ON USEHS;  H  ARRAYS
C     8/26/75 - SMALLER ILILOLX TABLES
C     9/10/75 - FIX MSTOP
C     2/25/76 - NOTATION OF CHAPTER 2 OF THE PTOLEMY MANUAL
C     5/27/76 - ARRAYS FOR INTERPOLATION
C     12/20/76 - INELASTIC SCATTERING
C     5/7/77 - FIX BUG WHEN INELASTIC LOMOST < LMAX
C     4/20/78 - ALLOW DEEXCITATION - S.P.
C               DO NOT GENERATE COULOMB STUFF FOR BETA(COULOMB)=0.        900   
C     4/24/78 - LI AND LO INTERCHANGED - S.P.
C     7/12/78 - CORRECT CHECK FOR DEFINED L'S IN USEHS RUNS
C     5/12/79 - CLINTS TIME DONE SEPARATELY - S.P.
C     6/1/79 - SPIN-ORBIT AND TENSOR POTENTIALS - RPG
C     6/8/79 - STANDARD PREFIXES, CHARACTER TYPE - RPG
C     7/21/79 - FREE EXTRA AREAS ON PASS >=2 - RPG
C     8/7/79 - CHANGE S-MATRIX STRUCTURE - RPG
C     11/3/79 - COULOMB AND DIAG-COULOMB INTO BOB'S VERSION - S.P.
C     11/20/79 - S-MATRICES STORED BY LO-LI - S.P.
C                STORE ALL DIAGONAL FF3'S - S.P.                          910   
C     12/27/79 - COUPLED CHANNELS ADDED - S.P.
C     2/7/80 - SMALL FIX IN ABOVE - S.P.
C     3/26/80 - GET IT STRAIGHT FOR NEGATIVE PARITY - S.P.
C     4/7/80 - FILL IN LI'S FOR LMIN < LXMAX - S.P.
C     4/22/80 - ALLOCATE ELCOUPS (IELCUP) FOR C.C. - S.P.
C     4/25/80 - PBUGSW LOCAL; PASS TO SETSPT - S.P.
C     5/1/80 - FIX 4/7/80 FOR LSKIP=2 - S.P.
C     6/12/81 - MAKE ENOUGH DINTS FOR SMALL LOMOST - S.P.
C     7/12/81 - COMPUTE EXTRAPOLATION OVERLAP REGION - S.P.
C     10/26/81 - SETSPT NOW NEEDS THE BASDEF ARRAY - S.P.                 920   
C     10/14/83 - INTEGER TABLE WAS NOT BIG ENOUGH - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      parameter ( NUMJWORD = 12 )                                       /jblock/
      COMMON /JBLOCK/  J, JS(5),
     &  JP, JSP, JST,
     &  JPARM1, JPARM2, JPARM3
 
      COMMON /KANDM/ AKI, AKO, REDMI, REDMO, RIMAX, ROMAX, ISIGS(2),    /kandm/
     &  RSCTS(2), ASCTS(2), RCSCTS(2) ,ISMATS(2), LOMOST, LCRIT,
     &  ISCTMN, ISCTCR, ETAS(2), RCSCTP(2), RCSCTT(2), LCRITS(2),
     &  RATMSS(2), QMIN, ABAR
 
      DIMENSION  AKS(2), REDMS(2), RMAXS(2)
      EQUIVALENCE ( AKI, AKS(1) ), ( REDMI, REDMS(1) ),
     &  ( RIMAX, RMAXS(1) )
 
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
C
c                                                                       /formf/
c ***  LNKADB was  numLINKULES but only 12 are used ???
c
      COMMON /FORMF/  IBDS(2), NPOTS(2), LBP, LBT, NBP, NBT, JBP, JBT,
     &  BNDMAX(2), BNDSTP(2), NSTPBD(2), RBNDS(2), ABNDS(2),
     &  RCBNDS(2), BNDMAS(2), BRATMS(2), RSOBDS(2), ASOBDS(2),
     &  VBNDS(2), VSOBDS(2), TAUBDS(2), LNKADB(6, 2, 12)
 
      DIMENSION R2S(4)
      EQUIVALENCE ( R2S(1), RBNDS(1) )
C
      REAL*8  JACOB                                                     /gridcm/
      COMMON /GRIDCM/  JACOB, STPINV, COSSTP,
     &  IMSVAL, IINTS, INTOFF, IA12VL, ICOSIN,
     &  IPHIT, IPHIP, IPHI, LOGIC, LOCTRP,
     &  IRI, IRO, ILOR, ILOI, ILIR, ILII, IWIO, NOFLO, NRIROI, NCRIT,
     &  IXLAM, INLAM, IA12N, MSKCOS, MAXCNT, ISMHPT, ISMIPT,
     &  ICOSS4, IJA12S, IHS, IIINDX, IA12TM, IDW, IHINT, IHABS,
     &  IABS1, IGRDC1, NPSUMI, RVRLIM, ISMHWK, ISMHVL, ISMIVL,
     &  IRIOEX, NUMHS, IGRDC2(4),
     &  IWFII, IWFIO, NWFI, NWFO, IDWI
 
      LOGICAL ONELSW, IDENSW                                            /inelcm/
      COMMON /INELCM/  JBPF, JBTF, LXMIN, LXMAX, ILILOR, ILILOI, MSTOP,
     &  IA12M, NMLOLX, ONELSW, NUMLX, IRDINT, IELCUP, LILOSZ, NUMLIS,
     &  ILIS, IBETAS(3), ICL2FF, LXSTEP, IDENSW, LSKIP,
     &  JPMIN, JPMAX, JPBASE, NJP, JTMIN, JTMAX, JTBASE, NJT,
     &  IINDXS, ISMATR, ISMATI, NSMAT, NLX, NSPLI, ITOCS,
     &  NASPLI, IUNITR, LIFIT, ILIFIT, NOLFIT, IDELSR, IDELSI
      INTEGER INDXJS(4,2)
      EQUIVALENCE ( INDXJS(1,1), JPMIN )
 
      COMMON /CCBLK/  ICHNDF, ICHNCP, ITRANS, IBASDF, IBASCP,           /ccblk/
     &    ICCBLK(2), IORDX, MCHNVL, ICHNVL,
     &    IHOMOA, IHOMOB, IINHR8, IINHI8
 
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
C
C
      LOGICAL   PBUGSW, PINFSW, COULSW, MULTSW, COUPSW
      CHARACTER*8 NAMER(2) / 'WAVSAVIR', 'WAVSAVOR' /
      CHARACTER*8 NAMEI(2) / 'WAVSAVII', 'WAVSAVOI' /
C
      INTEGER  NUMFRE /21/
      CHARACTER*8 FRENAM(21) / 'TORUTHIN', 'SMAG', 'SPHASE', 'SINMAG',
     1   'SINPHASE', 'SOUTMAG', 'SOUTPHAS', 'TORUTHOT', 'CROSSSEC',
     2   'LXCROSSS', 'LXTOTS', 'MXTOTS', 'BETAS', 'FIN', 'FOUT', 'F',     950   
     3   'LABCROSS', 'MXCROSSS', 'ANPOW', 'ANPOWA', 'ANPOWB' /
C
      DIMENSION  DUMMY(1), IDUMMY(1,1)
C
c
C
      IRTN = 0
C
      IPRNT = MOD( IPRINT, 10 )
      PBUGSW = IPRNT .GE. 3                                               960   
      PINFSW = IPRNT .GE. 2
C
      COUPSW = PROBLM .EQ. 24
C
C     ON PASS>=2, FREE AREAS NO LONGER NEEDED.
C
      IF ( IBSPAS .LE. 1 )  GO TO  300
      DO  259  K = 1, NUMFRE
         I = NAMLOC(FRENAM(K))
         IF ( I .GT. 0 )  Z(I) = -Z(I)                                    970   
  259 CONTINUE
C
C
C     WE DO NOT NECESSARILY COMPUTE EVERY I( LI, LO, LX ).  RATHER
C     WE FIND ONLY THOSE FOR
C        LI = LMIN, LMIN+LSTEP, LMIN+2LSTEP, ..., LMAX
C     AND
C        LI = LMIN, LMIN+1, ..., LXMAX
C     WHERE THE SERIES TERMINATES AT OR BEFORE LMAX.  ALL LO AND LX
C     FOR THE ABOVE LI'S ARE FOUND.  THE ARRAY "LIS" CONTAINS THOSE       980   
C     LI'S FORWHICH THE CALCULATION IS TO BE DONE
C     NOTE THAT IF LMIN < LXMAX, WE EFFECTIVELY START OUT WITH
C     LSTEP=1 TO POVIDE A SMOOTH STARTING POINT FOR INTERPOLATION
C
C**************************************************
C
C     NOTE:  FOR COUPLED CHANNELS CALCULATIONS THESE ARE
C            REALLY THE TOTAL J VALUES.  HOWEVER WE DO
C            NOT YET DOUBLE THEM.
C                                                                         990   
C**************************************************
C
C
 300  IF ( LSTEP .NE. 1  .AND.  TCSWS(1) ) write (6, 307)
  307 FORMAT ( '0***** WARNING:  LSTEP MUST = 1 FOR TR OR TP',
     1  ' POTENTIALS IN INCIDENT CHANNEL.' )
      IF ( TCSWS(1) ) LSTEP = 1
C
C     COMPUTE THE NUMBER OF LI'S INCLUDING THE LI<LXMAX PART
C                                                                        1000   
      NUMLIS = (LMAX-LMIN+LSTEP)/LSTEP
      N = 0
      IF ( LXMAX .GT. LMIN )  N = (LXMAX-LMIN)/LSKIP
     1    - (LXMAX-LMIN)/LSTEP
      NUMLIS = NUMLIS+N
      ILIS = NALLOC( (NUMLIS+1)/FACFR4, 'LIS     ' )
      DO  309  I = 1, NUMLIS
         L = LMIN + (I-1)*LSKIP
         IF ( L .GT. LXMAX )  L = (I-N-1)*LSTEP + LMIN
         ILLOC(FACFR4*Z(ILIS)-FACFR4+I) = L                              1010   
  309 CONTINUE
C
      IF ( IHSAVE .EQ. 1 )  WRITE (1, ERR=9950)  NUMLIS
      IF ( IHSAVE .EQ. 1 )  WRITE (1, ERR=9950)
     1  ( ILLOC(FACFR4*Z(ILIS)-FACFR4+I), I = 1, NUMLIS )
      IF ( IHSAVE .NE. 2 )  GO TO 400
C
C     RECOVER LI'S FROM THE H'S FILE AND MAKE SURE THE PRESENT SET
C     IS A SUBSET.
C                                                                        1020   
      READ ( 1, ERR=9950, END=9950 )  NUMLIH
      ITEMP = IALLOC( (NUMLIH+1)/FACFR4 )
      READ ( 1, ERR=9950, END=9950 )
     1  ( ILLOC(FACFR4*Z(ITEMP)-FACFR4+I), I = 1, NUMLIH )
      ILIH = 1
      DO  359  ILI = 1, NUMLIS
         LI = ILLOC(FACFR4*Z(ILIS)-FACFR4+ILI)
  330    LIH = ILLOC(FACFR4*Z(ITEMP)-FACFR4+ILIH)
         IF ( LI - LIH )   380,  359,  340
  340    ILIH = ILIH + 1                                                 1030   
         IF ( ILIH .LE. NUMLIH )  GO TO  330
      GO TO  380
  359 CONTINUE
      Z(ITEMP) = -Z(ITEMP)
      GO TO 400
  380 write (6,  383) LMIN, LSTEP, LMAX,
     1  ( ILLOC(FACFR4*Z(ILIS)-FACFR4+ILI), ILI = 1, NUMLIS )
  383 FORMAT ( '0***** ERROR: THIS SPECIFICATION OF LMIN, LSTEP,',
     1  ' LMAX (', 3I5, ' ) REQUIRES LI''S THAT WERE NOT SAVED',
     2  ' IN THE SAVEHS RUN.' /                                          1040   
     3  '0***** REQUIRED LI''S -' / (15X, 20I5 ) )
      write (6,  387)
     1  ( ILLOC(FACFR4*Z(ITEMP)-FACFR4+ILI), ILI = 1, NUMLIH )
  387 FORMAT ( '0***** AVAILABLE LI''S -' / (15X, 20I5) )
      IRTN = 0
      RETURN
C
C     DETERMINE THE RANGE OF LI'S TO BE USED FOR EXTRAPOLATION.
C
 400  LLIS = FACFR4*Z(ILIS)-FACFR4                                       1050   
      IF ( LBACK .EQ. NOTDEF )
     1   LBACK = LMAX - ILLOC(LLIS+NUMLIS-3)
      LIFIT = LMAX - LBACK
      DO 429  ILI = 1, NUMLIS
         IF ( LIFIT .LT. ILLOC(LLIS+ILI) )  GO TO 430
 429  CONTINUE
 430  ILIFIT = ILI - 1
      LIFIT = ILLOC(LLIS+ILIFIT)
      NOLFIT = NUMLIS - ILIFIT + 1
C                                                                        1060   
C
C     "INDXS" WILL CONTAIN ALL INFORMATION NECESSARY TO FIND A
C     GIVEN S-MATRIX ELEMENT.  IT HAS 3 VALUES FOR EACH
C     (LX, JP, JT) TRIPLE, INDEXED BY
C        K = 1 + LX + NLX*( JP-JPBASE + NJP*(JT-JTBASE) )/2
C
C        (3*K-2) = KOFFS = OFFSET INTO S-MATRIX (=0 IF NONEXISTENT).
C        (3*K-1) = LDELMN = MINIMUM (LO-LI).
C        (3*K  ) = NDEL = NUMBER OF (LO-LI) VALUES.
C                                                                        1070   
C
C     "TOCS" WILL CONTAIN A TABLE OF CONTENTS FOR THE S MATRIX.
C     IT HAS 4 VALUES IDENTIFYING EACH S-MATRIX ELEMENT USED, INDEXED
C     BY ITS POSITION (KOFFS + (LO-LI+LDELMN)/2 ) IN THE S MATRIX:
C
C        (4*KOFFS-3) = LO - LI
C        (4*KOFFS-2) = LX
C        (4*KOFFS-1) = JP
C        (4*KOFFS  ) = JT
C                                                                        1080   
C
C     "SMATR", "SMATI" WILL HOLD THE CALCULATED (NOT INTERPOLATED)
C     REACTION S MATRIX.  FOR A GIVEN (LO, LX, JP, JT, LI), THE
C     S MATRIX IS INDEXED AS
C
C        (LI-LMIN)*NSPLI/LSTEP + KOFFS + ( LO - LI - LDELMN )/2
C
C     WHERE KOFFS AND LDELMN ARE TAKED FROM "INDXS" AS DESCRIBED ABOVE.
C
C                                                                        1090   
C     FIRST PASS, ALLOCATE "INDXS" AND "TOCS" AND INITIALIZE POINTERS.
C
      IF ( IBSPAS .GT. 1 ) GO TO 1450
C
C     FIRST FIND INDXS SIZE
C
      ISIZE = 0
      IF ( COUPSW )  GO TO 1410
      CALL SETSPT ( ISIZE, LOC, 1, JS(4), JS(2), PBUGSW,
     1   IDUMMY, 1, 1 )                                                  1100   
      GO TO 1420
C
 1410 LCHNDF = FACFR4*(Z(ICHNDF)-1) + 1
      NCHNDF = ILLOC(LCHNDF)
      MCHNDF = ILLOC(LCHNDF+1)
      LCHNDF = LCHNDF + ILLOC(LCHNDF+2)
      DO  1419  I = 2, NCHNDF
         LCHNDF = LCHNDF + MCHNDF
         ILLOC(LCHNDF+11) = ISIZE
         CALL SETSPT ( ISIZE, LOC, 1,                                    1110   
     1      IABS(ILLOC(LCHNDF+1)), IABS(ILLOC(LCHNDF+3)), PBUGSW,
     2      IDUMMY, 1, 1 )
 1419 CONTINUE
C
C     DEFINE THE INDXS ARRAY
C
 1420 IINDXS = NALLOC ( (ISIZE+1)/FACFR4, 'INDXS   ' )
      CALL INIT4I ( IINDXS, 0 )
      LINDXS = Z(IINDXS)*FACFR4 - FACFR4
C     NASPLI IS NSPLI SUMMED OVER ALL CHANNELS                           1120   
      NASPLI = 0
C
C     NOW FILL IN "INDXS" FOR ALL S-MATRIX ELEMENTS NEEDED ON THIS
C     AND SUBSEQUENT PASSES.
C
      IF ( COUPSW )  GO TO 1430
      CALL SETSPT ( NASPLI, LINDXS, 2, JS(4), JS(2), PBUGSW,
     1   IDUMMY, 1, 1 )
      GO TO 1440
C                                                                        1130   
 1430 LCHNDF = FACFR4*(Z(ICHNDF)-1) + 1
      LCHNDF = LCHNDF + ILLOC(LCHNDF+2)
      LBASDF = FACFR4*(Z(IBASDF)-1) + 1
      MBASDF = ILLOC(LBASDF+1)
      LBASDF = LBASDF + ILLOC(LBASDF+2)
      DO 1439  I = 2, NCHNDF
         LCHNDF = LCHNDF + MCHNDF
         IB = ILLOC(LCHNDF+7)
         NBASDF = ILLOC(LCHNDF+8)
         ILLOC(LCHNDF+9) = NUMLIS*NASPLI                                 1140   
         ILLOC(LCHNDF+12) = 4*NASPLI
         CALL SETSPT ( NASPLI, LINDXS+ILLOC(LCHNDF+11), 2,
     1      IABS(ILLOC(LCHNDF+1)), IABS(ILLOC(LCHNDF+3)), PBUGSW,
     2      ILLOC(LBASDF+MBASDF*(IB-1)), MBASDF, NBASDF )
         ILLOC(LCHNDF+10) = NSPLI
 1439 CONTINUE
C
C     ALLOCATE AND INITIALIZE THE S-MATRIX AND ITS TABLE OF CONTENTS.
C     DELTASR, DELTASI  ARE FOR S - S(BORN).  WE START OUT WITH
C     THEM DEFINED AS THE FULL S-MATRIX ARRAYS.                          1150   
C
 1440 NSMAT = NASPLI*NUMLIS
      ISMATR = NALLOC ( NSMAT, 'SMATR   ' )
      ISMATI = NALLOC ( NSMAT, 'SMATI   ' )
      IDELSR = ISMATR
      IDELSI = ISMATI
      ITOCS = NALLOC ( 4*NASPLI/FACFR4, 'TOCS    ' )
      CALL INIT8 ( ISMATR, 0.D0 )
      CALL INIT8 ( ISMATI, 0.D0 )
      CALL INIT4I ( ITOCS, -1 )                                          1160   
      IF ( PROBLM .GE. 23 )  IELCUP = NALLOC( 2*NUMLIS, 'ELCOUPS ' )
C
C
C     ALL PASSES:  FILL IN "TOCS" FOR THOSE S-MATRIX ELEMENTS WHICH
C     ARE USED ON THIS PASS.
C
 1450 LINDXS = Z(IINDXS)*FACFR4 - FACFR4
      LTOCS = Z(ITOCS)*FACFR4 - FACFR4
      IF ( COUPSW )  GO TO 1460
      CALL SETSPT ( LTOCS, LINDXS, 3, JS(4), JS(2), PBUGSW,              1170   
     1  IDUMMY, 1, 1 )
C
C     THIS IS THE NUMBER OF (LO', LX') PAIRS PER LI IN THE INNER
C     INTEGRATION LOOPS.  LX'S DUE ONLY TO SPIN-ORBIT DISTORTIONS
C     ARE NOT INCLUDED.
C
      NMLOLX = ( (LXMAX+LXMIN+1)*(LXMAX-LXMIN+1)
     1   + MOD(LXMIN+LBP+LBT+1, 2) )/2
      GO TO 1500
C                                                                        1180   
 1460 LCHNDF = FACFR4*(Z(ICHNDF)-1) + 1
      LCHNDF = LCHNDF + ILLOC(LCHNDF+2)
      DO 1469  I = 2, NCHNDF
         LCHNDF = LCHNDF + MCHNDF
         CALL SETSPT ( LTOCS+ILLOC(LCHNDF+12),
     1      LINDXS+ILLOC(LCHNDF+11), 3,
     2      IABS(ILLOC(LCHNDF+1)), IABS(ILLOC(LCHNDF+3)), PBUGSW,
     3      IDUMMY, 1, 1 )
 1469 CONTINUE
C                                                                        1190   
C     FOR C.C. WE USE NMLOLX = NASPLI
C
      NMLOLX = NASPLI
C
C
C     STORAGE FOR THE H'S (TRANSFER ONLY)
C
 1500 IHS = 0
      IHINT = 0
      IHABS = 0                                                          1200   
      INLAM = 0
      IXLAM = 0
      IA12VL = 0
      IMSVAL = 0
      IJA12S = 0
      IA12TM = 0
      IF ( ISTRIP .EQ. 0 )  GO TO 1800
      IA12TM = (3*NUMLX+1)/FACFR4
      IF ( IHSAVE .EQ. 2 )  GO TO 1750
C                                                                        1210   
      IHS = NALLOC ( NMLOLX, 'H       ' )
      IHINT = NALLOC ( NMLOLX, 'HINTEGRL' )
      IHABS = NALLOC ( NMLOLX, 'HABSINT ' )
C
C     ALLOCATE ARRAYS FOR  A12
C
      MSTOP = MAX0( LXMAX+LBP, LXMAX+LBT, LBP+LBT+1, 2*LXMAX )
      MSTOP = 2*(MSTOP/2)
      INEED = (MSTOP/2+1) * (LOMOST+1)
      INLAM = NALLOC ( (LOMOST+1)/FACFR4+1, 'NLAMBDA ' )                 1220   
      IXLAM = NALLOC ( INEED, 'XLAMBDA ' )
C
C     FOLLOWING IS AN UPPER LIMIT ON THE NUMBER OF TERMS IN THE
C     A12 SUMS.
C     FIRST THE MAXIMUM NUMBER OF M1 AND M2
C     COMBINATIONS.  WE USE
C        M1  <= (LBP, LX+LBT)    M2  <= (LBT, LX+LBP)
C        MX  <= (LX,LBP+LBT)   M1+LBP AND M2+LBT  EVEN
C
      IA12M = (MIN0(LXMAX,LBP+LBT)+1) * (MIN0(LBP,LBT)+1)                1230   
C
C     THEN FOR EACH OF THE ABOVE MU TAKES ON VALUES SUCH THAT
C       0 <= MU <= LO <= LOMOST,    MU+LO EVEN
C     AND WE HAVE  NMLOLX  SETS OF SUCH A12 VALUES.
C
      IA12N = IA12M * (LOMOST/2+1) * NMLOLX
C
C
C     FOR EACH (M1, M2) PAIR WE HAVE UP TO FIVE ITEMS TO STORE
C                                                                        1240   
      IA12M = 5*IA12M
      IA12VL = NALLOC( IA12N, 'A12VALS ' )
      IMSVAL = NALLOC( IA12M, 'A12MSVAL' )
      IJA12S = NALLOC( (IA12M+1)/FACFR4, 'JA12S    ' )
C
C     FOLLOWING IS 3 ARRAYS; ONLY THE THIRD IS USED FOR USEHS RUNS.
C     REAL*8   NUMLX
C     REAL*8   2*LXMAX+2
C     INTEGER  3*NUMLX  ( WE TREAT AS REAL*8 TO ALLOW FOR CDC )
C                                                                        1250   
      IA12TM = 4*NUMLX + 2*LXMAX + 2
 1750 IA12TM = NALLOC( IA12TM, 'A12TEMPS' )
C
C     "IDWFI" WILL CONTAIN INFORMATION ABOUT THE INCIDENT
C     SCATTERING WAVE FUNCTIONS, FOR A GIVEN LI:
C
C        (3*K-2) = LASI - LI
C        (3*K-1) = JPI - 2*LI  (MAX. VALUE IF NO S. O.)
C        (3*K  ) = INDEX TO BASE OF WF IN ALLOCATOR
C                                                                        1260   
 1800 IWFII = NALLOC ( (3*NUMJS(1)+1)/FACFR4, 'IDWFI   ' )
      LWFII = Z(IWFII)*FACFR4 - FACFR4
      I = 0
      IF ( TCSWS(1) ) I = JSPS(1)
      LASMIN = -I
      LASMAX = I
      NWFI = 0
C     THE OUTER LOOP IS OVER LAS = ASYMPTOTIC L (TENSOR ONLY).
      DO 1819 LAS = LASMIN, LASMAX, 2
C        THE INNER LOOP IS OVER JP = TOTAL PROJECTILE J                  1270   
         JPMX = MIN0(2*LAS,0) + JSPS(1)
         JPMN = JPMX
         IF ( SOSWS(1) ) JPMN = MAX0(2*LAS,0) - JSPS(1)
         DO 1809 JPI = JPMN, JPMX, 2
            NWFI = NWFI + 1
            ILLOC(LWFII+3*NWFI-2) = LAS
            ILLOC(LWFII+3*NWFI-1) = JPI
            ILLOC(LWFII+3*NWFI) = (NWFI-1)*NRIROI
 1809    CONTINUE
 1819 CONTINUE                                                           1280   
      I = 3*NWFI
      IF ( PBUGSW ) write (6, 1823) ( ILLOC(LWFII+K), K = 1, I )
 1823 FORMAT ( ' IDWFI', 3I10 )
C
      IF ( COUPSW )  GO TO 2100
C
C     "IDWFO" WILL CONTAIN INFORMATION ABOUT THE OUTGOING
C     SCATTERING WAVE FUNCTIONS, FOR A GIVEN LI:
C
C        (4*K-3) = LO - LI                                               1290   
C        (4*K-2) = LASO - LI
C        (4*K-1) = JPO - 2*LI
C        (4*K  ) = INDEX TO BASE OF WF ARRAY (SET IN INELDC).
C
      I = 0
      IF ( ISTRIP .NE. 0 ) I = MOD ( LBP+LBT+LXMAX, 2 )
      NOFLO = LXMAX + 1 - I
      IWFIO = NALLOC ( 4*NOFLO*NUMJS(2)/FACFR4, 'IDWFO   ' )
      LWFIO = Z(IWFIO)*FACFR4 - FACFR4
      LOMAX = NOFLO - 1                                                  1300   
      LOMIN = -LOMAX
      LASR = 0
      IF ( TCSWS(2) ) LASR = JSPS(2)
      NWFO = 0
      DO 1869 LO = LOMIN, LOMAX, 2
         LASMIN = LO - LASR
         LASMAX = LO + LASR
         DO 1859 LAS = LASMIN, LASMAX, 2
            JPMX = 2*MIN0(LO,LAS) + JSPS(2)
            JPMN = JPMX                                                  1310   
            IF ( SOSWS(2) ) JPMN = 2*MAX0(LO,LAS) - JSPS(2)
            DO 1849 JPO = JPMN, JPMX, 2
C     ELIMINATE INITIAL JPO'S TOO LOW TO COUPLE TO LI.
               IF ( SOSWS(2)  .AND.  NWFO .EQ. 0  .AND.
     1            JPO+JSPS(1)+JBT .LT. 0 ) GO TO 1849
               NWFO = NWFO + 1
               ILLOC(LWFIO+4*NWFO-3) = LO
               ILLOC(LWFIO+4*NWFO-2) = LAS
               ILLOC(LWFIO+4*NWFO-1) = JPO
 1849       CONTINUE                                                     1320   
 1859    CONTINUE
 1869 CONTINUE
C     ELIMINATE FINAL JP'S TOO LARGE TO COUPLE TO LI.
      IF ( .NOT. SOSWS(2) ) GO TO 1900
      I = NWFO
      DO 1879 K = 1, I
         IF ( ILLOC(LWFIO+4*NWFO-1) .LE. JSPS(1)+JBT ) GO TO 1890
         NWFO = NWFO - 1
 1879 CONTINUE
 1890 IF ( NWFO .LT. NOFLO*NUMJS(2) )                                    1330   
     1   CALL IREDEF ( 4*NWFO/FACFR4, IWFIO )
 1900 I = 4*NWFO
      IF ( PBUGSW ) write (6, 1903) ( ILLOC(LWFIO+K), K = 1, I )
 1903 FORMAT ( ' IDWFO', 4I10 )
C
C     NOW ALLOCATE SPACE FOR THE WAVE FUNCTIONS (AT GAUSS POINTS)
C
      I = (NWFI*NRIROI+1)/FACFR4
      ILIR = NALLOC ( I, 'WAVEAR  ' )
      ILII = NALLOC ( I, 'WAVEAI  ' )                                    1340   
      I = (NWFO*NRIROI+1)/FACFR4
      ILOR = NALLOC ( I, 'WAVEBR  ' )
      ILOI = NALLOC ( I, 'WAVEBI  ' )
C     FOR TENSOR COUPLING, WAVETC NEEDS SOME SCRATCH STORAGE SPACE.
      I = 4*NRIROI/FACFR4
      DO 1909 K = 1, 2
         IF ( .NOT. TCSWS(K) ) GO TO 1909
         IWAVRS(K) = NALLOC ( I, NAMER(K) )
         IWAVIS(K) = NALLOC ( I, NAMEI(K) )
 1909 CONTINUE                                                           1350   
C     THIS POINTER CONTROLS WF STORAGE IN THE CIRCULAR BUFFER.
      NCRIT = NWFO*NRIROI - NRIROI
C
C     "DW" WILL CONTAIN PRODUCTS OF SCATTERING WAVE FUNCTIONS.
C     "INDXDW" WILL CONTAIN POINTERS USED TO CALCULATE AND USE "DW".
C
      IDW = NALLOC ( NWFI*NWFO*2, 'DW      ' )
      IDWI = NALLOC ( NWFI*NWFO*4/FACFR4, 'INDXDW  ' )
      GO TO 2200
C                                                                        1360   
C     FOR C.C. THERE ARE NO OUTGOING WAVE ARRAYS BUT WE
C     STILL STORE INCOMING S SEPARATELY.
C
 2100 LCHNDF = FACFR4*(Z(ICHNDF)-1)+1
      LCHNDF = LCHNDF + ILLOC(LCHNDF+2)
      ILLOC(LCHNDF+9) = -1
      ILLOC(LCHNDF+10) = NWFI
      ILLOC(LCHNDF+11) = 0
      ILLOC(LCHNDF+12) = 0
C                                                                        1370   
C     COMPUTE MAX NUMBER OF H'S THAT WILL EVER OCCUR.
C     THE SPACE PREVIOUSLY WASTED HAS BEEN ELIMINATED.
C
 2200 NUMHS = NMLOLX
C
      IF ( COUPSW )  GO TO 3000
      I = NUMHS*NUMJS(1)*NUMJS(2)
C
C     "RIROABS" WILL CONTAIN INTEGRAL(RI,RO) | INTEGRAL(X) INTEGRAND |,
C     WHICH IS USED TO CHECK FOR EXCESSIVE ROUND-OFF ERRORS DUE TO       1380   
C     CANCELLATIONS.
C
      IABS1 = NALLOC ( I, 'RIROABS ' )
C
      IF ( ISTRIP .EQ. 0 )  GO TO 3000
C
C     "SUMHVALS" AND "SUMIVALS" ARE THE H'S (AFTER X INTEGRATION)
C     BEFORE AND AFTER INTERPOLATION IN (RO+RI)/2, RESPECTIVELY.
C
      ISMHVL = NALLOC( NPSUM*NUMHS, 'SUMHVALS' )                         1390   
      ISMIVL = NALLOC( NPSUMI*NUMHS, 'SUMIVALS' )
C
C     "I1REAL" AND "I1IMAG" WILL CONTAIN THE FINAL 3-DIMENSIONAL
C     INTEGRALS, FOR A FIXED VALUE OF LI.
C     "IINDEX" WILL CONTAIN POINTERS INTO H ("SUMIVAL") AND INTO
C     "DW" (WF PRODUCTS) FOR EACH INTEGRAL.
C
      ILILOR = NALLOC ( I, 'I1REAL  ' )
      ILILOI = NALLOC ( I, 'I1IMAG  ' )
      IIINDX = NALLOC ( 4*I/FACFR4, 'IINDEX  ' )                         1400   
C
      IF ( IHSAVE .EQ. 2 )  GO TO 3000
C
C     SETUP FOR HIGH SPEED COSINE
C
C     OUR ALGORITHM REQUIRES THAT THE SIZE OF THE TABLE BE A
C     POWER OF TWO.  SO WE FORCE IT.
C
      I = DLOG( DFLOAT(NCOSIN) ) / DLOG(2.D0) + .5
      NCOSIN = 2**I                                                      1410   
      DICOSS = NCOSIN
      COSSTP = 2*PI/DICOSS
      ICOSS4 = NCOSIN/4
      STPINV = DICOSS/(2*PI)
      MSKCOS = NCOSIN-1
      ICOSSP = NCOSIN+1
      ICOSIN = NALLOC( ICOSSP, 'COSINES ' )
      X = -COSSTP
      DO 2559 II = 1, ICOSSP
         X = X + COSSTP                                                  1420   
2559  ALLOC(Z(ICOSIN)+II-1)=DCOS(X)
C
C     WE USE A TABLE OF INTEGERS IN DOUBLE PRECISION FORM TO AVOID
C     FREQUENT CONVERSIONS FROM I TO R .
C
C     WE SET THAT TABLE UP HERE
C
      I = LMAX + LXMAX + LBP + LBT
      IMIN = MAX0 ( I, 2*(LBP+LBT)+20 )
      INTOFF = IMIN + 1                                                  1430   
      IMAX = MAX0( IMIN, 2*I+2 )
      IINTS = NALLOC( IMAX+IMIN+1, 'INTEGERS' )
      LINTS = Z(IINTS)-1+INTOFF
      IMIN = -IMIN
      X = IMIN
      DO 2659 I = IMIN, IMAX
         ALLOC(LINTS+I) = X
         X = X + 1
 2659 CONTINUE
C                                                                        1440   
 3000 IRTN = 1
C
      RETURN
C
C
C
 9950 write (6, 9953)
 9953 FORMAT ( '0**** ERROR IN READING OR WRITING H''S FILE.' )
      RETURN
C                                                                        1450   
      END
C*ID* A12      C109.PTOLEMY.SOURCE                          PER701  09:
      SUBROUTINE A12 ( LI, LXMIN, LXMAX, LMIN, LMAX, XLAM,
     1  NLAM, A12VL, DMSVAL, JA12S, JA12M, JA12N, JA12AN, IINDEX,
     2  IHMAX, LOMNMN, LOMXMX, DINTS, OUTTMP,
     3  XLOTMP, LXTMP, LHSM1, LA12VL, IPRINT, INIT,
     4  INDXDW, NDW, NI, IDWFI, IDWFO )
C
C     COMPUTES THE ANGULAR MOMENTUM TRANSFORMATION FUNCTION A12.
C                                                                        1460   
C  THIS VERSION GOES WITH THE INELDC74. LARGE ARRAYS ARE USED AND
C  CORE REQUIREMENTS ARE HIGH BUT IS FASTER THAT OLD VERSION
C      THESE MODIFCATIONS  7/74    D.G.
C     1/30/75 - M'S STORED IN REAL*8 ARRAY; USE DINTS; REMOVE UNUSED
C               ARGUMENTS - S.P.
C     3/8/75 - USE ONLY MU >= 0;  FACTOR OUT A 3-J - S.P.
C     3/22/75 - SPLIT INTO (M,MM) AND MU SUMS; DON'T STORE ALL XLAMS
C     3/27/75 - USE M' LOOP VARIABLE; M, M', MU IN ONE ARRAY;
C               DECIDE WHICH INTERVAL TO HALVE.
C     4/6/75 - LI, LX LOOPS INTERNAL; LX, LBT, LBP NAMES                 1470   
C     4/23/75 - PBUGSW IN ARG LIST DUE TO NEW COMMONS
C     5/21/75 - DO ALL LI FOR GIVEN LO.
C     5/30/75 - INTRODUCE (-)**LO TO GET SMOOTHER PHASES
C     6/11/75 - USEHS
C     8/26/75 - SMALLER ILILOLX TABLE
C     9/10/75 - FIX BUG FOR ODD L BOUNDSTATES
C     2/24/76 - SIGN CONVENTIONS AND NOTATION OF CHAPTER II OF MANUAL
C     8/8/76 - USE IPRINT AND HAVE PMCHSW.
C     4/28/78 - INTERCHANGE LI AND LO - S.P.
C     6/30/78 - CHANGE IPRINT CONVENTION                                 1480   
C     3/6/79 - CHANGE TO S-MATRIX; CONSISTANT PICKUP AND STRIPING - S.P.
C     6/6/79 - ADD INDXDW-IDWFO, CHANGE IINDEX, USE MOD - RPG
C     6/8/79 - STANDARD PREFIXES - RPG
C     6/19/79 - REMOVE (-1)**LX FOR PICKUP - RPG
C     6/19/79 - INIT IN ARG LIST TO ALLOW NO OVERLAYS - S.P.
C     7/21/79 - SOME DEVUG PRINT WHEN PRINT=50000 - RPG
C     10/6/80 - FIX TWO-YEAR OLD BUG FOR ONE ODD BOUND L - S.P.
C     6/12/81 - FIX BUG FOR LBP,LBT < LMAX - S.P.
C
C     COMPUTES THE ANGULAR FUNCTION A12(X) DEFINED AS PART OF GENERAL    1490   
C     VECTOR TRANSFORM BY EQ.(II-41) OF THE PTOLEMY MANUAL.
C
C     IN THIS ROUTINE THE NON-X PART OF A12 IS COMPUTED AND IS STORED
C     IN THE ARRAY A12VL.  THE CORRESPONDING INDICES  MP, MT AND MU ARE
C     STORED IN ARRAYS ALSO.  JA12N WILL BE SET TO THE NUMBER OF A12
C     TERMS.  JA12M WILL BE SET TO (THE NUMBER OF DIFFERENT MP, MT
C     PAIRS)*5 - 4.
C     JA12AN IS SET TO THE NUMBER OF DIFFERENT (MP, MT, MU) TRIPLES.
C     IHMAX IS SET TO THE MAXIMUM NUMBER OF (LO,LX) PAIRS FOR A
C           GIVEN MP, MT, MU.                                            1500   
C     (LOMNMN, LOMXMX) IS SET TO THE EXTREME RANGE OF LO FOR THIS LI.
C          IF THERE IS NO RANGE THEN IMMEDIATE RETURN IS MADE
C          WITH  LOMNMN > LOMXMX.
C
C     WE USE A SLIGHTLY DIFFERENT NOTATION HERE (SUBROUTINE = MANUAL):
C        MP = MX - LITTLE M
C        MT = LITTLE M
C        LO = LOUT
C
C     THE INDEX (KA12M) OF THE DMSVAL AND JA12S ARRAYS GOES UP           1510   
C     BY 5 FOR EACH PAIR OF (MT, MP).  THUS WE HAVE KA12M = 1, 6, ...
C     FOR GIVEN KA12M THE FOLLOWING ARE STORED:
C       DMSVAL(KA12M)   = MT
C       DMSVAL(KA12M+1) = MP
C       DMSVAL(KA12M+2) = FIRST MU FOR THIS (MT,MP) - 2
C       JA12S(KA12M)   = OFFSET FROM FIRST H LOC TO CORRESPONDING
C                        A12VAL.
C       JA12S(KA12M+1) = NUMBER OF MU FOR THIS (MT,MP)
C       JA12S(KA12M+2) = FIRST IH LOCATION FOR THIS (MT,MP) AND EACH MU.
C       JA12S(KA12M+3) = NUMBER OF H'S FOR THIS (MP,MT) AND EACH MU.     1520   
C
C     THE IINDEX ARRAY WILL HAVE 4 ELEMENTS FOR EACH RADIAL INTEGRAL
C     I(LX,JP,JT; LO,LASO,JPO; LI,LASI,JPI). FOR THIS LI.
C        IINDEX(1,KI) = INDEX INTO H ARRAY
C           (INCL. BASE ADDRESS Z(ISMIVL), NOT IU).
C        IINDEX(2,KI) = INDEX INTO DW = FI*FO ARRAY
C           (EVEN, STARTS AT Z(IDW)+2).
C        IINDEX(3,KI) = KDW = INDEX INTO "INDXDW" ARRAY
C           (1 <= KDW <= NDW).
C        IINDEX(4,KI) = LX                                               1530   
C     WHERE KI = INDEX INTO I ("I1REAL", "I1IMAG") ARRAYS.
C     ALSO, NI = THE MAXIMUM VALUE OF II IS RETURNED.
C
C     THE INDXDW ARRAY WILL HAVE 4 ELEMENTS FOR EACH DW = JI*FO,
C     I. E. EACH PRODUCT OF INCIDENT AND OUTCOING DISTORTED WAVES.
C        INDXDW(1,KDW) = KWI = POINTER INTO ARRAY WFINDXI.
C        INDXDW(2,KDW) = KWO = POINTER INTO ARRAY WFINDXO.
C        INDXDW(3,KDW) = INDEX TO BASE OF INCIDENT WF IN ARRAYS WAVEAR/I
C        INDXDW(4,KDW) = INDEX TO BASE OF OUTGOING WF IN ARRAYS WAVEBR/I
C     WHERE KDW = INDEX INTO ARRAY "DW".                                 1540   
C     ALSO, NDW = THE MAXIMUM VALUE OF KDW IS RETURNED.
C
C     THE IDWFI AND IDWFO ARRAYS ARE INPUT TO A12, WHICH MUST CONTAIN
C     INFORMATION ABOUT THE STORED INCIDENT AND OUTGOING WAVE
C     FUNCTIONS RESPECTIVELY:
C        IDWFI(1,KWI) = LASI - LI.
C        IDWFI(2,KWI) = JPI - 2*LI  (MAX. VALUE IF NO S. O.).
C        IDWFE(3,KWI) = INDEX TO BASE OF WF IN ARRAYS WAVEAR/I.
C        IDWFO(1,KWO) = LO - LI.
C        IDWFO(2,KWO) = LASO - LI.                                       1550   
C        IDWFO(3,KWO) = JPO - 2*LI  (MAX. VALUE IF NO S. O.).
C        IDWFO(4,KWO) = INDEX TO BASE OF WF IN ARRAYS WAVEBR/I.
C
C     IF A USEHS IS IN EFFECT, THEN ONLY THE LI, LX LIMITS AND INDICES
C     ARE COMPUTED.
C
      implicit real*8 ( a-h, o-z )                                      implicit
CDC      ALLOCLEVEL XLAM,NLAM,A12VL,DMSVAL,JA12S,IINDEX,DINTS,OUTTMP,
CDC     1  XLOTMP,LXTMP,INDXDW,IDWFI,IDWFO
C                                                                        1560   
      DIMENSION XLAM(1), NLAM(1), JA12S(1), IINDEX(4,1), OUTTMP(1),
     1   XLOTMP(1), LXTMP(1), INDXDW(4,1), IDWFI(3,1), IDWFO(4,1),
     2   DMSVAL(1), A12VL(1), DINTS(1)
C
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      REAL*8  JACOB                                                     /gridcm/
      COMMON /GRIDCM/  JACOB, STPINV, COSSTP,
     &  IMSVAL, IINTS, INTOFF, IA12VL, ICOSIN,
     &  IPHIT, IPHIP, IPHI, LOGIC, LOCTRP,
     &  IRI, IRO, ILOR, ILOI, ILIR, ILII, IWIO, NOFLO, NRIROI, NCRIT,
     &  IXLAM, INLAM, IA12N, MSKCOS, MAXCNT, ISMHPT, ISMIPT,
     &  ICOSS4, IJA12S, IHS, IIINDX, IA12TM, IDW, IHINT, IHABS,
     &  IABS1, IGRDC1, NPSUMI, RVRLIM, ISMHWK, ISMHVL, ISMIVL,
     &  IRIOEX, NUMHS, IGRDC2(4),
     &  IWFII, IWFIO, NWFI, NWFO, IDWI
 
c                                                                       /formf/
c ***  LNKADB was  numLINKULES but only 12 are used ???
c
      COMMON /FORMF/  IBDS(2), NPOTS(2), LBP, LBT, NBP, NBT, JBP, JBT,
     &  BNDMAX(2), BNDSTP(2), NSTPBD(2), RBNDS(2), ABNDS(2),
     &  RCBNDS(2), BNDMAS(2), BRATMS(2), RSOBDS(2), ASOBDS(2),
     &  VBNDS(2), VSOBDS(2), TAUBDS(2), LNKADB(6, 2, 12)
 
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
C                                                                        1570   
      COMMON /INELCM/  I6SP(6), MSTOP, IA12M, NMLOLX
C
      LOGICAL  FRSTSW, HALFSW, LBUGSW, PMCHSW, MBUGSW
C
C
      SAVE
C
C
C
      IF(INIT.NE.5) GO TO 500                                            1580   
C
      I = MOD(IPRINT/10 000 , 10)
      LBUGSW = I .GE. 4  .OR.  MOD(IPRINT, 10) .GE. 4
      MBUGSW = I .GE. 5
      PMCHSW = I .GE. 6
C
C     IF LBT OR LBP IS ODD, WE HALVE THAT INTERVAL; ELSE WE HALVE THE
C     LO INTERVAL.
C
      HALFSW = .FALSE.                                                   1590   
      MTMIN = -LBT
      MPMIN = -LBP
      IF ( MOD(LBT,2) .EQ. 0 )  GO TO 20
C
C     HALVE MT
C
      HALFSW = .TRUE.
      MTMIN = 1
      GO TO 50
C                                                                        1600   
 20   IF ( MOD(LBP,2) .EQ. 0 )  GO TO 50
      HALFSW = .TRUE.
      MPMIN = 1
C
 50   ICO=1
      LOMOST = LMAX + MAX0( LXMAX, LBP, LBT )
C
      IF ( IHSAVE .EQ. 2 )  GO TO 500
C
      NLAM(1)=1                                                          1610   
      XLAM(1)=1.D0
      M = 0
      OUTTER = 1
      IF ( LOMOST .EQ. 0 )  GO TO 200
C
C     IF WE HALVE THE MT OR MP INTERVAL, WE WILL NEED LAMBDA(L,L-M)
C     WHILE IF WE HALVE LO INTERVAL WE NEED LAMBDA(L,M) WHERE IN BOTH
C     CASES   M <= MSTOP.  WE GENERATE THESE HERE AND BIAS NLAM(L+1)
C     SUCH THAT  XLAM(NLAM(L+1)+M/2) ALWAYS WORKS.
C                                                                        1620   
      IF ( MBUGSW )  write (6, 53) LBT, LBP, LO, LXMIN, LXMAX, LMIN,
     1  LMAX, LOMOST, MTMIN, MPMIN, MSTOP, IA12M, NMLOLX, HALFSW
 53   FORMAT ( '0START', 13I8, L5 )
      IF ( HALFSW )  GO TO 160
C
      DO 149  LL = 1, LOMOST
         M = 1-M
         OUTTER = OUTTER* DSQRT( DINTS(LL+M-1)/DINTS(LL+M) )
         IF ( M .EQ. 1 )  OUTTER = -OUTTER
         ICO = ICO + 1                                                   1630   
         NLAM(LL+1) = ICO
         XLAM(ICO) = OUTTER
         MU = MIN0( MSTOP, LL )
         MMTMIN = M+2
         IF ( MMTMIN .GT. MU )  GO TO 149
         DO 139  MM = MMTMIN, MU, 2
            ICO = ICO + 1
            XLAM(ICO) = -XLAM(ICO-1) *
     1        DSQRT( DINTS(LL-MM+2)*DINTS(LL+MM-1) /
     2              (DINTS(LL+MM)*DINTS(LL-MM+1)) )                      1640   
      IF ( MBUGSW )  write (6, 57) ICO, LL, M, MU, MM, NLAM(LO+1),
     1  XLAM(ICO), DINTS(LL+MM), DINTS(LL-MM+1)
 57   FORMAT ( ' XLAM', 6I8, 3G15.5 )
 139     CONTINUE
 149  CONTINUE
      GO TO 200
C
C     HERE GENERATE  LAMBDA( L, L-M )
C
 160  DO 189  LL = 1, LOMOST                                             1650   
         OUTTER = -DSQRT( DINTS(2*LL-1)/DINTS(2*LL) ) * OUTTER
         LLEVEN = LL - MOD(LL, 2)
         MLOW = MIN0( MSTOP, LLEVEN )
         NUM = MLOW/2 + 1
         ICO = ICO + NUM
         XLAM(ICO) = OUTTER
         NLAM(LL+1) = ICO-LL/2
         IF ( NUM .EQ. 1 )  GO TO 189
         MM = LL
         ICOO = ICO                                                      1660   
         DO 169  I = 2, NUM
            MM = MM - 2
            ICOO = ICOO - 1
            XLAM(ICOO) = -XLAM(ICOO+1) * DSQRT( DINTS(LL-MM-1)
     1        *DINTS(LL+MM+2) / (DINTS(LL-MM)*DINTS(LL+MM+1)) )
 169     CONTINUE
 189  CONTINUE
C
 200  INIT=0
      LLBT = 2*LBT                                                       1670   
      LLBP = 2*LBP
C
C
 500  LLI=2*LI
      IF ( IHSAVE .EQ. 2 )  GO TO 510
C
      XN=DINTS(LLI+1)*DINTS(LLBT+1)*DINTS(LLBP+1)
      XN=.5*DSQRT(XN)
C
C     FOR INTERNAL A12 USE WE STORE FOR EACH LX:                         1680   
C     1)  INDEX TO THE H ARRAY OF FIRST ELEMENT FOR THIS LX
C     2)  LOMIN FOR LX
C     3)  LOMAX FOR LX.
C     ALSO THE MINIMUM AND MAXIMUM LO OVER ALL LX  ARE FOUND ( LOMNMN,
C     LOMXMX).
C
 510  LOMNMN = LI+500
      IH = 0
      IX = 0
      DO 559  LX = LXMIN, LXMAX                                          1690   
         LOMIN = IABS(LI-LX)
         LOMAX = LI+LX
         LOMIN = LOMIN + MOD( LBT+LBP+LI+LOMIN, 2 )
         LOMAX = LOMAX - MOD( LBT+LBP+LI+LOMAX, 2 )
         LXTMP(IX+1) = IH+1
         LXTMP(IX+2) = LOMIN
         LXTMP(IX+3) = LOMAX
         IX = IX + 3
         LOMNMN = MIN0( LOMIN, LOMNMN )
         IF ( LOMIN .GT. LOMAX )  GO TO 559                              1700   
         IH = IH + (LOMAX-LOMIN)/2 + 1
 559  CONTINUE
C
      IHMAX = IH
      LOMXMX = LOMAX
C
C     LOOP THROUGH ALL COMBINATIONS OF INCIDENT AND OUTGOING
C     DISTORTED WAVES.  FOR EACH PAIR THAT CAN BE
C     COUPLED, STORE POINTERS IN ARRAY INDXDW.
C                                                                        1710   
      NDW = 0
      JPOMIN = MAX0 ( 0, 2*LI-JSPS(1)-JBT)
      DO 659 KWI = 1, NWFI
         LASI = IDWFI(1,KWI) + LI
         IF ( LASI .LT. LMIN  .OR.  LASI .GT. LMAX ) GO TO 659
         JPI = IDWFI(2,KWI) + 2*LI
         IF ( JPI .LT. IABS(2*LI-JSPS(1)) ) GO TO 659
         JPOMAX = JPI + JBT
         IF ( SOSWS(1) ) JPOMIN = IABS(JPI-JBT)
         DO 649 KWO = 1, NWFO                                            1720   
            LO = IDWFO(2,KWO) + LI
            IF ( LO .LT. LOMNMN ) GO TO 649
            IF ( .NOT. SOSWS(2) ) GO TO 620
            LASO = IDWFO(2,KWO) + LI
            IF ( LASO .LT. 0 ) GO TO 649
            JPO = IDWFO(3,KWO) + 2*LI
            IF ( JPO .LT. IABS(2*LO-JSPS(2)) ) GO TO 649
            IF ( JPO .LT. JPOMIN  .OR.  JPO .GT. JPOMAX ) GO TO 649
            GO TO 630
 620        IF ( 2*LO+JSPS(2) .LT. JPOMIN                                1730   
     1         .OR.  2*LO-JSPS(2) .GT. JPOMAX ) GO TO 649
C           WEEDING IS DONE, STORE POINTERS.
 630        NDW = NDW + 1
            INDXDW(1,NDW) = KWI
            INDXDW(2,NDW) = KWO
            INDXDW(3,NDW) = IDWFI(3,KWI)
            INDXDW(4,NDW) = IDWFO(4,KWO)
            IF ( MBUGSW ) write (6, 643)  NDW, (INDXDW(I,NDW), I = 1, 4)
 643        FORMAT ( ' INDXDW', 5I8 )
 649     CONTINUE                                                        1740   
 659  CONTINUE
C
C     IN IINDEX WE STORE POINTERS INTO THE H ("SUMIVAL") AND
C     FI*FO ("DW") ARRAYS FOR EACH RADIAL INTEGRAL.
C
      NI = 0
      IX = 0
      DO 759 LX = LXMIN, LXMAX
         IH = LXTMP(IX+1) - 1
         LOMIN = LXTMP(IX+2)                                             1750   
         LOMAX = LXTMP(IX+3)
         IX = IX + 3
         DO 749 KDW = 1, NDW
            KWO = INDXDW(2,KDW)
            LO = IDWFO(1,KWO) + LI
            IF ( LO .LT. LOMIN  .OR.  LO .GT. LOMAX ) GO TO 749
            NI = NI + 1
            IINDEX(1,NI) = Z(ISMIVL) - 1 + ( IH + (LO-LOMIN)/2 )*NPSUMI
            IINDEX(2,NI) = Z(IDW) - 1 + 2*KDW
            IINDEX(3,NI) = KDW                                           1760   
            IINDEX(4,NI) = LX
            IF ( MBUGSW ) write (6, 743)  NI, ( IINDEX(I,NI), I = 1, 4 )
 743        FORMAT ( ' IINDEX', 5I8 )
 749     CONTINUE
 759  CONTINUE
C
      IF ( IHSAVE .EQ. 2 )  RETURN
C
      IZERCT = 0
C                                                                        1770   
C     PREPARE FOR THE TRIPLE SUM ON  MP, MT, MU
C
      MUSTRT = MOD( LI, 2 )
      IF (HALFSW)  MUSTRT = -LI
C
      JA12M = -4
      JA12N=0
      JA12AN = 0
      TEMPS=10.0D0
      TEMPL=0                                                            1780   
      TEMPC=0
C
      IF ( LOMNMN .GT. LOMXMX )  RETURN
C
      DO 899  MP = MPMIN, LBP, 2
C
         DO 859   MT = MTMIN, LBT, 2
C
            MX = MT+MP
            IF ( IABS(MX) .GT. LXMAX )  GO TO 859                        1790   
            ILAMLT=NLAM(LBT+1)+IABS(MT)/2
            ILAMLP=NLAM(LBP+1)+IABS(MP)/2
            IP3 = 0
            IP4 = 0
            IF(MT.LT.0)  IP3 = LBT
            IF(MP.LT.0)  IP4 = LBP
C
C     SETUP THE A12 FACTORS THAT DEPEND ONLY ON MT, MP, LX, MX.
C     IF ALL ARE ZERO, SKIP THIS (MT,MP) PAIR.
C                                                                        1800   
            FRSTSW = .FALSE.
            DO 329  LX = LXMIN, LXMAX
               OUTTER = XLAM(ILAMLT)*XLAM(ILAMLP)*XN*
     1          THREEJ( LLBT, LLBP, 2*LX, 2*MT, 2*MP, -2*MX )
               OUTTMP(LX-LXMIN+1) = OUTTER
               IF ( OUTTER .NE. 0 )  FRSTSW = .TRUE.
      IF ( PMCHSW )  write (6, 323) MP, MT, LX, ILAMLT, ILAMLP,
     1      XLAM(ILAMLT), XLAM(ILAMLP), OUTTER
 323  FORMAT ( ' OUTTMP', 5I8, 3G15.5 )
 329        CONTINUE                                                     1810   
            IF ( .NOT. FRSTSW )  GO TO 859
C
            FRSTSW = .TRUE.
            DO 799  MU = MUSTRT, LI, 2
C
               MUPOS=IABS(MX-MU)
               IF(MUPOS.GT.LOMXMX) GO TO 799
C
               IF ( .NOT. FRSTSW )  GO TO 340
C                                                                        1820   
C     FIRST VALID MU, MX-MU.  GET LAMBDA FROM TABLE
C
               DO 339  LO = LOMNMN, LOMXMX
                  XLOTMP(LO-LOMNMN+1) = 0
 339           CONTINUE
C
 340           LOSTRT = MAX0( LOMNMN, MUPOS )
C
C     FIND THE A12 TERMS DEPENDANT ON LO, LI, AND MU BUT NOT LX.
C                                                                        1830   
               DO 359  LO = LOMNMN, LOMXMX, 2
                  OUTTER = 0
                  IF ( LO .LT. LOSTRT )  GO TO 355
                  OUTTER = XLOTMP(LO-LOMNMN+1)
                  IF ( OUTTER .NE. 0 )  GO TO 350
C
C     FIRST MU VALID FOR THIS LO, LI - USE TABLE TO GET INITIAL
C     LAMBDA'S.
C     ALSO SET UP THE SIGN DUE TO ANY NEGATIVE M'S IN THE LOT
C     AS MU IS SUBSIQUENTLY INCREASED, (-1)**((...+MU+...+MX-MU)/2)      1840   
C     DOES NOT CHANGE.
C
                  IP1 = 0
                  IP2 = 0
                  IF ( MU .LT. 0 )  IP1 = LI
                  IF((MX-MU).LT.0)  IP2 = LOMNMN
                  ITES = IP4+IP3+IP2+IP1
CDC                  ITES = ITES + 2
                  OUTTER = XLAM(NLAM(LI+1)+IABS(MU)/2) *
     1                XLAM(NLAM(LO+1)+MUPOS/2) *                         1850   
     2                DSQRT(DINTS(2*LO+1))
                  IF ( MOD(ITES, 2) .NE. 0 )  OUTTER = -OUTTER
                  GO TO 355
C
C     ON SUCCESIVE MU'S, ITERATE TO NEW LAMBDA'S
C     AGAIN WE ARE BUILDING THAT PART OF A12 THAT IS INDEPENDANT OF
C     LX.
C
 350              OUTTER = OUTTER * DSQRT( DINTS(LI-MU+2)
     1              *DINTS(LI+MU-1)*DINTS(LO-MX+MU-1)                    1860   
     2              *DINTS(LO+MX-MU+2) / (DINTS(LI+MU)
     3              *DINTS(LI-MU+1)*DINTS(LO-MX+MU)*DINTS(LO+MX-MU+1)) )
 355              XLOTMP(LO-LOMNMN+1) = OUTTER
      IF ( PMCHSW )  write (6, 358) MP, MT, MU, LI, LO, LOSTRT,
     1  XLAM(NLAM(LO+1)+IABS(MU)/2),
     2  DINTS(LO-MU+2), OUTTER
 358  FORMAT ( ' OUTTER', 6I8, 3G15.5 )
 359           CONTINUE
C
               LXONE = MAX0( IABS(MX), LXMIN )                           1870   
               JA12ON = JA12N+1
               DO 499  LX = LXONE, LXMAX
                  LOMIN = LXTMP(3*(LX-LXMIN)+2)
                  LOMAX = LXTMP(3*(LX-LXMIN)+3)
                  IF ( LOMIN .GT. LOMAX )  GO TO 499
                  DO 489  LO = LOMIN, LOMAX, 2
                     TTT = THREEJ(LLI, 2*LO, 2*LX, 2*MU, 2*(MX-MU),
     1                         -2*MX )
                     TEMP = XLOTMP(LO-LOMNMN+1)*OUTTMP(LX-LXMIN+1)*
     1                TTT                                                1880   
      IF ( PMCHSW )  write (6, 483) MP, MT, MU, LX, LO, LOMNMN,
     1  LXMIN, XLOTMP(LO-LOMNMN+1), OUTTMP(LX-LXMIN+1), TTT, TEMP
 483  FORMAT ( ' ANSWER', 7I8, 4G15.5 )
C
                     IF ( TEMP .EQ. 0 )  IZERCT = IZERCT+1
                     IF(DABS(TEMP).GT.TEMPL)TEMPL=DABS(TEMP)
                     IF(DABS(TEMP).LT.TEMPS.AND.DABS(TEMP).NE.0)
     1                 TEMPS = DABS(TEMP)
                     IF ( HALFSW  .OR.  MU .NE. 0 )  TEMP = TEMP+TEMP
                     TEMPC=TEMPC+DABS(TEMP)                              1890   
                     JA12N=JA12N+1
                     A12VL(JA12N) = TEMP
 489              CONTINUE
 499           CONTINUE
               MULAST = MU
               IF ( .NOT. FRSTSW )  GO TO 799
               FRSTSW = .FALSE.
C
C     FOR FIRST MU OF THIS (M,MM) PAIR, STORE STUFF
C                                                                        1900   
               MUONE = MU
               JA12M = JA12M+5
               DMSVAL(JA12M) = DINTS(MT)
               DMSVAL(JA12M+1) = DINTS(MP)
               DMSVAL(JA12M+2) = DINTS(MU) - 2
               JA12S(JA12M+2) = LXTMP(3*(LXONE-LXMIN)+1) + LHSM1
               JA12S(JA12M) = LA12VL+JA12ON-JA12S(JA12M+2)
               JA12S(JA12M+3) = IHMAX - LXTMP(3*(LXONE-LXMIN)+1) + 1
C
  799       CONTINUE                                                     1910   
            IF ( .NOT. FRSTSW )  JA12S(JA12M+1) = (MULAST-MUONE)/2+1
            IF ( .NOT. FRSTSW )  JA12AN = JA12AN + JA12S(JA12M+1)
      IEND = JA12M+3
      IF ( PMCHSW )  write (6, 793) MUONE, JA12M, JA12AN,
     1  ( DMSVAL(III), III = JA12M, IEND  ),
     2  ( JA12S(III), III = JA12M, IEND )
 793  FORMAT ( ' MS,JA', 3I5 / (T10, 4I15 ))
  859    CONTINUE
  899 CONTINUE
C                                                                        1920   
C     NOTE:  THE FOLLOWING "AVERAGE" IS THE AVERAGE TERM AND NOT
C            THE AVERAGE A12 VALUE (I.E. JA12N IS NOT A WEIGHTED
C           DIVISOR).
C
      TEMPC=TEMPC/JA12N
      IF (LBUGSW)  WRITE(6, 933) LI, LOMNMN, LOMXMX, IHMAX, JA12M,
     1  JA12AN, JA12N, IZERCT, TEMPS, TEMPL, TEMPC
 933  FORMAT('0LI, LOMNMN, LOMXMX, IHMAX, JA12M, JA12AN, JA12N:', 5I4,
     1     2I8 /
     2  ' NUM OF ZEROS; SMALLEST, LARGEST AND ',                         1930   
     3      'AVERAGE A12VAL:', I6, 3G15.5 )
      RETURN
      END
C*ID* BASCPL   C109.PTOLEMY.SOURCE                          PER701  11:
      SUBROUTINE BASCPL(IRET)
C
C     CONSTRUCTS BASIS COUPLING ARRAY
C
C     THIS SUBROUTINE SELECTS FROM INPUT DATA
C     ALL POSSIBLE POTENTIAL TERMS AND STORES THEM IN Z(IBASCP)          1940   
C
C     WE ASSUME USUAL PREFACE CONSTRUCTION
C     THE ARRAY HAS THE FORM
C     +0 EQUATION NO. CORRESPONDING TO CHANNEL BEING COUPLED
C     +1 EQUATION NO. COUPLED TO +0
C     +2 ORDER OF COUPLING
C     +3 TOTAL MULTIPOLE OF COUPLING FOR ORDER IN +2
C     +4 NUCLEAR;RADIAL INDEPENDANT COUPLING TERM
C     +5 COULOMB;RADIAL INDEPENDANT COUPLING TERM
C     +6 LABEL FOR TERM I**(L2-L1)   WE STORE                            1950   
C        IFAC FOR I**(L2-L1)
C         -2         -I
C         -1         -1
C         +1         +1
C         +2         +I
C        (ONLY AN ENGLISHMAN COULD THINK OF THIS)
C     +7 TOTAL J, ORBITAL ANGULAR MOMENTUM AND K DEPENDANT
C       "KINEMATIC" FACTOR.  THIS FACTOR IS INDEPENDANT OF THE
C        NUCLEAR MODEL USED TO DESCRIBE THE COUPLING.  THE FACTOR IS
C        STORED BY COUPLN AS EACH VALUE OF THE TOTAL J IS PROCESSED.     1960   
C        HERE WE STORE AN INDICATOR FOR INGRST AS FOLLOWS
C           1 - 1ST DERIVATIVE
C           2 - 2ND DERIVATIVE
C           M+3 - DEFORMED PROJECTILE
C           M+4 - DEFORMED TARGET
C           M+5 - DEFORMED MUTUAL
C        WHERE   M = 10000*LXT + 100*LXP
C     +8 POINTER TO BINDEX (NEG IF FLIPPED CHANNELS)  (SET BY COULST)
C     +9 POINTER TO NUCLEAR COUPLING POTENTIAL    (SET BY INGRST)
C     +10 POINTER TO COULOMB COUPLING POTENTIAL  (SET BY INGRST)         1970   
C     + 9 AND + 10 CALCULATED IN INGRST
C
C     12/79 - FIRST VERSION - MRB
C     1/16/80 - USE CCBLK - S.P.
C     28/1/80 INTRODUCE TEMPORARY COUPLING TYPE IN +7
C          FOR RHS CALCULATION IN INGRST.FORT
C     7/2/80 - COMMENTS, IMPROVE DIAGNOSTICS - S.P.
C     7/3/80 - PRINT HEADER FOR BE, Q, GATHER LXTOP,
C              WHEN BETA IS DEFINED AND SEVERAL LX POSSIBLE,
C              PRINT MSG AND USE ONLY FIRST - S.P.                       1980   
C     7/7/80 - CONVERT BE TO BETA IN TRANS ARRAY, PASS LTRANS AS REAL
C              START OF TRANS ARRAY, PASS  DEBUG PRINTOUT - S.P.
C     7/8/80 - PASS E*'S TO POTRHS, COMBINE IRTN AND IET - S.P.
C     9/11/80 - FIX BUG I INTRODUCED IN 2ND ORDER - S.P.
C     9/16/80 - DO NOT STORE XN=XC=0; DO NOT ALLOW L1+L2+LAM ODD;
C               STORE THE I**(L2-L1) FACTOR - S.P.
C     9/19/80 - NO LAMBDA=0 FOR 2ND ORDER AT ONE VERTEX; FIX
C              IN CHOOSING LOWEST MULTIPOLE; MOVE TESTS FROM
C              PORTRHS TO HERE - S.P.
C     10/2/80 - MASSIVE REARRANGEMENT - S.P.                             1990   
C     12/8/80 - PRINT R.M.E. - S.P.
C     12/10/80 - USE K-QUANTUM NUMBERS - S.P.
C     1/8/81 - REVISED 2ND ORDER; CUPSPN, CUPAB CALLS - S.P.
C     1/25/80 - SCALE FACTORS - S.P.
C     7/9/81 - FIX BUG IN SPECIFIED LX FOR 2ND ORDER COULOMB - S.P.
C     8/25/81 - MODIFED INGRST INDICATOR; ALLOW UNDEFINED BETAS - S.P.
C     9/18/81 - DEFINE LOG(FACTORIAL) TABLE - S.P.
C     10/13/81 - ALLOW TOTAL LAMBDA=0 AT ONE VERTEX - S.P.
C     10/16/81 - BUILD LX1 AND LX2 INTO IPT1 - S.P.
C     10/19/81 - PASS IPT TO BEBETA FOR MEBDEF - S.P.                    2000   
C     10/22/81 - IDENTICAL PARTICLE PROCESSING - S.P.
C     11/10/81 - FIX GIESSEN BUG MAKING EVERYTHING SYM - S.P.
C     3/20/82 - SOME SYMETRIES WERE MISSED IN GIESSEN - S.P.
C     6/9/83 - REMOVE EXTRA NOW STATEMENT - S.P.
C     7/24/84 - ADD HOTFUDGE - S.P.
C     10/16/84 - SET XC = 0 WHEN  ZP*ZT = 0 - S.P.
C     5/6/85 - USE CHARACTER*8 FOR ANAMES
C
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
C
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
C
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      DIMENSION IZPT(2)
      EQUIVALENCE ( IZPT(1), IZS(2) )
C
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
C
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      COMMON /CCBLK/  ICHNDF, ICHNCP, ITRANS, IBASDF, IBASCP,           /ccblk/
     &    ICCBLK(2), IORDX, MCHNVL, ICHNVL,
     &    IHOMOA, IHOMOB, IINHR8, IINHI8
 
C
      LOGICAL ONELSW, IDENSW                                            /inelcm/
      COMMON /INELCM/  JBPF, JBTF, LXMIN, LXMAX, ILILOR, ILILOI, MSTOP,
     &  IA12M, NMLOLX, ONELSW, NUMLX, IRDINT, IELCUP, LILOSZ, NUMLIS,
     &  ILIS, IBETAS(3), ICL2FF, LXSTEP, IDENSW, LSKIP,
     &  JPMIN, JPMAX, JPBASE, NJP, JTMIN, JTMAX, JTBASE, NJT,
     &  IINDXS, ISMATR, ISMATI, NSMAT, NLX, NSPLI, ITOCS,
     &  NASPLI, IUNITR, LIFIT, ILIFIT, NOLFIT, IDELSR, IDELSI
      INTEGER INDXJS(4,2)
      EQUIVALENCE ( INDXJS(1,1), JPMIN )
 
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
C
      INTEGER GIVEAL,CHOPIT
      CHARACTER*8 NAME5/'TEMPCUP'/, ANAMES
      COMMON /NAMCOM/ANAMES(1)
C
      LOGICAL   PBUGSW, SYMSW, FLIPSW                                    2030   
      INTEGER  IFACS(4) / 1, 2, -1, -2 /
C
      DATA MBASCP/11/,LPL/3/
C
C     HERE WE STORE THE NUCLEAR J'S K-NUMBERS AND E*'S AS
C       JNUC(IPT,I) AND ENUC(IPT,I)
C     IPT = 1 FOR PROJECTILE AND 2 FOR TARGET;
C     I = 1 FOR LEFT SIDE AND 2 FOR RIGHT SIDE.
C     AND
C       SCHN(I)  FOR THE CHANNEL SPIN                                    2040   
C
      DIMENSION  JNUC(2,2),  ENUC(2,2), KNUC(2,2)
      INTEGER SCHN(2)
      EQUIVALENCE (JNUC(1,1), JP1), (JNUC(1,2), JP2),
     1      (JNUC(2,1), JT1), (JNUC(2,2), JT2)
      EQUIVALENCE (ENUC(1,1), EP1), (ENUC(1,2), EP2),
     1      (ENUC(2,1), ET1), (ENUC(2,2), ET2)
      DIMENSION  JPT12(2,2), EPT12(2,2), KPT12(2,2)
C
      DIMENSION  NAME12(2)                                               2050   
      EQUIVALENCE  ( NAME1, NAME12(1) ),  ( NAME2, NAME12(2) )
C
C     HERE WE STORE THE NUCLEAR RADII AS  RNUC(IPT)
C
      DIMENSION  RNUC(2), RCOUL(2)
C
C     HERE WE STORE LX'S, BETA'S, ETC FOR THE COUPLING BEING
C     CONSIDERED.  FOR SECOND ORDER THERE ARE TWO OF THEM.
C
      real*4 BETACS(2), BETANS(2)                                        2060   
      DIMENSION LXX2S(2), xcs(2), xns(2), IBETAC(2), IPTS(2)
      DIMENSION  LXS(2), IBETAN(2), RMENUC(2), RMECOU(2)
      DIMENSION  SCLFAC(2)
C
C     VALS GETS ALL THE VARIATIONS ON THE COULOMB COUPLING DEFORMATION
C
      DIMENSION  VALS(8,2), DELTAN(2)
C
      CHARACTER*8 IPTWRD(2) / 'PROJ', 'TARG' /
      CHARACTER*8  ORDWRD(2) / 'FIRST', 'SECOND' /                       2070   
      CHARACTER*8  MODNAM, MODELS(7) /'ROTATION', 'VIBRATIO',
     1   'DEFORMED', 'HOTFUDGE', 'MODEL5', 'MODEL6', 'MODEL7' /
C
c
C
C
      PBUGSW = MOD(IPRINT, 10) .GE. 5
C
C
C     GET THE DEFORMATION RADII.  IF POINT AND SPHERE COULOMB IS BEING   2080   
C     USED, THEN RCP IS ZERO AND WE MUST USE VALUES COMPUTED FROM RC0
C
      RCOUL(1) = RCP
      RCOUL(2) = RCT
      I = 0
      IF ( RCP .EQ. UNDEF  .OR.  RCP .EQ. 0  .OR.
     1   RCT .EQ. UNDEF )  I = 1
      RNUC(1) = R0 * AMA**.333333333333333 0D0
      IF ( I .EQ. 1 )
     1    RCOUL(1) = RC0 * AMA**.333333333333333 0D0                     2090   
      RNUC(2) = R0 * AMBIGA**.333333333333333 0D0
      IF ( I .EQ. 1 )
     1    RCOUL(2) = RC0 * AMBIGA**.333333333333333 0D0
      write (6, 13) ORDWRD(MEORD+1), ( RNUC(I), RCOUL(I), I=1,2 )
  13  FORMAT ( '-ELECTROMAGNETIC MATRIX ELEMENTS ARE RELATED',
     1   ' TO BETAS UP TO ', A6, ' ORDER.' /
     2  '0', T16, 'DEFORMED RADII' /
     3  T15, 'NUCLEAR   COULOMB' /
     4   ' PROJECTILE', T12, 2F10.4 /
     5   ' TARGET', T12, 2F10.4 )                                        2100   
C
C     WE NEED THE LOG(FACTORIAL) TABLE FOR VALUES
C       N < S(1)+S(2)+LX(1)+LX(2)+JP(1)+JT(2)
C         << 8*MAX(LIN-LOUT)
C     MAX(LIN-LOUT)  HAS BEEN STORED IN LXMAX BY BASLBL
C
      I = 8*LXMAX
      CALL SETLOG(I)
C
C     IF THE OUTGOING NUCLEI ARE IDENTICAL WE WILL DOUBLE                2110   
C     COUPLINGS TO CHANNELS CONTAINING IDENTICAL STATES IF
C     THE COUPLING COMES FROM CHANNELS WITH NON-IDENTICAL STATES.
C
      SYMSW = ISTATS(2) .LT. 3
      IF ( SYMSW )  write (6, 17)
  17  FORMAT ( '0SYMMETRIZED COUPLINGS ARE BEING GENERATED FOR',
     1  ' IDENTICAL NUCLEAR STATES.' )
C
C     WE START OUT WITH A TEMPORARY ARRAY AND PUT STUFF INTO
C     IT IN ANY ORDER AND LATER ON SORT THEM INTO THE                    2120   
C     DESIRED ORDER
C
      N5=NAMLOC(NAME5)
      IF ( N5.EQ.0)Z(N5)=-Z(N5)
      ITMPCP=GIVEAL(IWRDS)
      LBASCP=Z(ITMPCP)
      ANAMES(ITMPCP)=NAME5
      LBASCP=FACFR4*(LBASCP-1)+1
C
      CALL SETLOG(I)                                                     2130   
      LCHNDF=Z(ICHNDF)
      LCHNDF=FACFR4*(LCHNDF-1)+1
      NCHNDF=ILLOC(LCHNDF)
      MCHNDF=ILLOC(LCHNDF+1)
      LCHNDF=ILLOC(LCHNDF+2)+LCHNDF
      LCHNCP=Z(ICHNCP)
      LCHNCP=FACFR4*(LCHNCP-1)+1
      NCHNCP=ILLOC(LCHNCP)
      MCHNCP=ILLOC(LCHNCP+1)
      LCHNCP=ILLOC(LCHNCP+2)+LCHNCP                                      2140   
      LBASDF=Z(IBASDF)
      LBASDF=FACFR4*(LBASDF-1)+1
      NBASDF = ILLOC(LBASDF)
      MBASDF=ILLOC(LBASDF+1)
      LBASDF=LBASDF+ILLOC(LBASDF+2)
      LTRANS = 0
      IF ( ITRANS.EQ.0 ) GO TO 20
      LTRANS=Z(ITRANS)
      LTRANS=FACFR4*(LTRANS-1)+1
      MTRANS = ILLOC(LTRANS+1)                                           2150   
C
C     THE PHILOSOPHY FOR SELECTING MULTIPOLES IS AS FOLLOWS:
C     1 CALCULATE FULL RANGE OF POSSIBLE MULTIPOLES
C     2 SELECT FROM FULL RANGE THOSE SPECIFIED IN Z(ITRANS)
C     3 IF VALUES ARE SPECIFIED IN Z(ICHNCP) USE IN
C     4 CONJUNCTION WITH CTRANS OR REPLACE CTRANS VALUES IF ALREADY GIVE
C     ANY MULTIPOLE VALUE NOT SPECIFIED IS SET TO ZERO
C
C     FOR MUTUAL LXTOT=0 IS ALWAYS ALLOWED.  FOR 1ST OR 2ND ORDER
C     AT ONE VERTEX, LXTOT=0 IS ALLOWED ONLY IF EITHER                   2160   
C     1)  IT IS THE ONLY POSSIBILITY (COUPLING 0+ TO 0+)
C     2)  IT IS EXPLICITLY SPECIFIED
C     NOTE THAT THE STANDARD FORM FACTORS ARE NOT REALLY APPRORIATE
C     FOR LXTOT = 0
C     COULOMB M.E. ARE ALWAYS SET TO 0 FOR LXTOT=0.
C
  20  IORDX=1
C
C
C     LET US BEGIN THE GUTS OF THE CALCULATION                           2170   
C
      NBASCP = 0
      write (6, 23)
 23   FORMAT ( '-COUPLINGS USED IN THE CALCULATION:' /
     1  '0  CHANNEL', 4X, 'MODEL ORDER NUC. LX', 4X, 'SCALE',
     2      T47, 'BETAN', 2X, 'DELTAN', 2X, 'R.M.E.',
     3      7X, 'BETAC', 2X, 'DELTAC', T92, 'R.M.E.', T104, 'BE UP',
     4      T117, 'Q', T126, 'MEANLIFE' /
     5   '  FROM   TO', T37, 'FACTOR', T56, 'FM', T62, 'ALPHA',
     5      T84, 'FM',                                                   2180   
     6      T91, 'E B**LX/2', T102, 'E**2 B**LX', T115, 'E BARN',
     7      T128, 'SEC.' )
C
C
C     LOOP OVER ALL CHANNELS ON THE LEFT SIDE
C     THESE ARE THE CHANNELS BEING COUPLED TO.
C
      DO 999 ICH1 = 1, NCHNDF
      ICH1PT = (ICH1-1)*MCHNDF+LCHNDF
      NAME1=ILLOC(ICH1PT)                                                2190   
      JPT12(2,1) = IABS(ILLOC(ICH1PT+1))
      EPT12(2,1) = ALLOC4(ICH1PT+2)
      JPT12(1,1) = IABS(ILLOC(ICH1PT+3))
      IPARI1 = ISIGN(1, ILLOC(ICH1PT+1)) * ISIGN(1, ILLOC(ICH1PT+3))
      EPT12(1,1) = ALLOC4(ICH1PT+4)
      IB1ST=ILLOC(ICH1PT+7)
      IB1END = IB1ST-1 + ILLOC(ICH1PT+8)
      KPT12(2,1) = ILLOC(ICH1PT+15)
      KPT12(1,1) = ILLOC(ICH1PT+16)
      write (6, 73)                                                      2200   
 73   FORMAT (1X)
C
C     LOOP OVER CHANNELS ON THE RIGHT SIDE
C     THESE ARE THE CHANNELS BEING COUPLED FROM
C
      DO 979  ICH2 = 1, NCHNDF
      ICH2PT = (ICH2-1)*MCHNDF+LCHNDF
      NAME2 = ILLOC(ICH2PT)
      JPT12(2,2) = IABS(ILLOC(ICH2PT+1))
      EPT12(2,2) = ALLOC4(ICH2PT+2)                                      2210   
      JPT12(1,2) = IABS(ILLOC(ICH2PT+3))
      IPARI2 = ISIGN(1, ILLOC(ICH2PT+1)) * ISIGN(1, ILLOC(ICH2PT+3))
      EPT12(1,2) = ALLOC4(ICH2PT+4)
      IB2ST=ILLOC(ICH2PT+7)
      IB2END = IB2ST-1 + ILLOC(ICH2PT+8)
      KPT12(2,2) = ILLOC(ICH2PT+15)
      KPT12(1,2) = ILLOC(ICH2PT+16)
C
C     IPARTY = 0 FOR NO PARITY CHANGE, = 1 FOR PARITY CHANGE.
C     THAT IS    PARITY CHANGE = (-1)**IPARTY                            2220   
C
      IPARTY = 0
      IF ( IPARI1*IPARI2 .LT. 0 )  IPARTY = 1
C
C     LOOP OVER ALL CHANNEL COUPLINGS
C     AND FIND THE ONES THAT COUPLE THIS PAIR OF CHANNELS
C
      DO 949 ICP=1,NCHNCP
      ICOUNT = 0
      ICNT2 = 0                                                          2230   
      NAME1 = IABS(NAME1)
      NAME2 = IABS(NAME2)
      ICPPT=(ICP-1)*MCHNCP+LCHNCP
      ICFLIP = 2
      IF ( IABS(ILLOC(ICPPT)) .EQ. NAME2  .AND.
     1   ILLOC(ICPPT+1) .EQ. NAME1 )  GO TO 150
      IF ( ILLOC(ICPPT+3) .EQ. 2 )  GO TO 949
      ICFLIP = 1
      IF ( IABS(ILLOC(ICPPT)) .NE. NAME1  .OR.
     1   ILLOC(ICPPT+1) .NE. NAME2 )  GO TO 949                          2240   
C
 150  IORDER=ILLOC(ICPPT+2)
      ITYPE=ILLOC(ICPPT+3)
      SCALE = 1
      DO 169  I = 1, IORDER
         LXX2S(I) = ILLOC(ICPPT+3+I)
         BETACS(I) = ALLOC4(ICPPT+5+I)
         BETANS(I) = ALLOC4(ICPPT+7+I)
         IBETAC(I) = ILLOC(ICPPT+10+I)
         IBETAN(I) = ILLOC(ICPPT+14+I)                                   2250   
         SCLFAC(I) = ALLOC4(ICPPT+16+I)
         SCALE = SCALE*SCLFAC(I)
 169  CONTINUE
      IMUL=ILLOC(ICPPT+4)
      IF ( IORDER .GE. 2 )  IMUL = NOTDEF
      IPT = ILLOC(ICPPT+10)
      ILLOC(ICPPT+13) = 1
      MODEL = ILLOC(ICPPT+14)
      MODNAM = MODELS(MODEL)
      LXTOT = ILLOC(ICPPT+19)                                            2260   
      LXTOP = ILLOC(ICPPT+20)
C
C     THE LEFTSIDE CHANNEL MAY HAVE BEEN REVERSED
C
      FLIPSW = ILLOC(ICPPT) .LT. 0
      IF ( FLIPSW )  NAME12(ICFLIP) = -NAME12(ICFLIP)
      DO 229  IC = 1, 2
         DO 229  I = 1, 2
            II = I
            IF ( FLIPSW  .AND.  IC .EQ. ICFLIP )  II = 3-I               2270   
            JNUC(II,IC) = JPT12(I,IC)
            ENUC(II,IC) = EPT12(I,IC)
            KNUC(II,IC) = KPT12(I,IC)
 229  CONTINUE
C
C     FOR FIRST ORDER DEFINE IPT TO BE 1 FOR PROJECTILE,
C     AND 2 FOR TARGET.  FOR SECOND ORDER WE LEAVE IT UNTOUCHED
C
      IF ( IORDER .GE. 2 )  GO TO 500
      IF ( IPT .NE. NOTDEF )  GO TO 450                                  2280   
C
C     WHICH NUCLEUS IS BEING COUPLED IN FIRST ORDER ?
C
      IPT = 1
      IF ( JP1 .NE. JP2  .OR.  EP1 .NE. EP2 )  GO TO 450
      IPT = 2
      IF ( JT1 .NE. JT2  .OR.  ET1 .NE. ET2 )  GO TO 450
C
C     IT IS DIAGONAL;  IF ONE IS THE G.S. OR 0+, THEN THE OTHER
C     IS BEING COUPLED, ELSE WE CANNOT DECIDE.                           2290   
C
      IF ( EP1 .EQ. 0  .OR.  JP1 .EQ. 0 )  GO TO 450
      IPT = 1
      IF ( ET1 .EQ. 0  .OR.  JT1 .EQ. 0 )  GO TO 450
      write (6, 438)
 438  FORMAT ( '0**** CANNOT DETERMIN WHICH NUCLEUS (PROJECTILE ',
     1  'OR TARGET) TO COUPLE IN FIRST ORDER.' )
 445  write (6, 448)
     &   NAME1, JP1, EP1, JT1, ET1, NAME2, JP2, EP2, JT2, ET2
 448  FORMAT ( 6X, 'NUCLEI SPINS AND ENERGIES ARE:' /                    2300   
     1  6X, 'CHANNEL', I4,
     1     ', PROJ. AND TARGET:', 2( I4, '/2', F7.3, 2X ) /
     1  6X, 'CHANNEL', I4,
     2     ', PROJ. AND TARGET:', 2( I4, '/2', F7.3, 2X ) )
      IRET=0
      GO TO 949
C
C     MAKE SURE IT IS A LEGAL 1ST ORDER COUPLING
C
 450  IF ( JNUC(3-IPT,1) .EQ. JNUC(3-IPT,2)  .AND.                       2310   
     1   ENUC(3-IPT,1) .EQ. ENUC(3-IPT,2) )  GO TO 470
      write (6, 453) IPTWRD(IPT)
 453  FORMAT ( '0*** BOTH NUCLEII CANNOT CHANGE STATE IN A ',
     1   ' FIRST ORDER COUPLING.' /
     2   6X, 'OR THE WRONG NUCLEUS (', A4,
     3      ') WAS SPECIFIED AS BEING EXCITED. ' )
      GO TO 445
C
C     IF BETAS WERE SPECIFIED WITHOUT THE MULTIPOLE, THEN
C     WE MUST CHOOSE AN APPROPRIATE MULTIPOLE BASED ON THE               2320   
C     COUPLED SPINS.  THIS IS STILL ONLY FIRST ORDER
C     ALSO SET THE POSSIBLE RANGE OF MULTIPOLARITIES.
C
 470  ILLOC(ICPPT+10) = IPT
      MINLAM = IABS( JNUC(IPT,1)-JNUC(IPT,2) )
      MAXLAM = JNUC(IPT,1)+JNUC(IPT,2)
      IF ( LXTOP .NE. NOTDEF )  MAXLAM = MIN0( LXTOP, MAXLAM )
C
C  ********************************************************
C     HERE WE SET MINLAM AND MAXLAM ASSUMING ONLY E(LX)                  2330   
C     TRANSISTIONS.
C
      MINLAM = MINLAM + MOD( MINLAM+2*IPARTY, 4 )
      MAXLAM = MAXLAM - MOD( MAXLAM+2*IPARTY, 4 )
C ************************************************************
C
      IF ( MINLAM .LE. MAXLAM )  GO TO 475
      write (6, 473) NAME1, NAME2, MINLAM, MAXLAM
 473  FORMAT ( '0*** CHANNEL', I5, ' IS TO BE COUPLED TO', I5,
     1  ' IN FIRST ORDER BUT SPINS AND PARITIES CANNOT BE.' /            2340   
     2  6X, 'MINLAM, MAXLAM =', 2( I5, '/2' ) )
      GO TO 445
C
 475  IF ( IMUL .NE. NOTDEF  .OR.  LXTOT .NE. NOTDEF )  GO TO 480
C
C     LX NOT EXPLICITLY GIVEN;  IF 0 IS ONLY POSSIBILITY,
C     SO BE IT, ELSE START FROM LXMIN>0.
C
      IF ( MINLAM .EQ. 0  .AND.  MAXLAM .GE. 4 )  MINLAM = 4
      IF ( BETACS(1) .EQ. UNDEF4  .AND.                                  2350   
     1     BETANS(1) .EQ. UNDEF4 )  GO TO 600
      IF ( MINLAM .NE. MAXLAM )  write (6, 478) NAME1, NAME2,
     1  MINLAM, MAXLAM
 478  FORMAT ( '0*** WARNING, CHANNEL', I4,
     1  ' CAN BE COUPLED TO CHANNEL', I4,
     2  ' IN FIRST ORDER WITH MULTIPOLES FROM', I4, '/2 TO',
     3  I4, '/2.' /
     2  6X, 'YOU HAVE SPECIFIED BETAS BUT NOT A PARTICULAR',
     3    ' MULTIPOLE, ONLY THE LOWEST WILL BE USED.' / )
      MAXLAM = MINLAM                                                    2360   
      IMUL = MINLAM
      GO TO 600
C
C     IS THE SPECIFIED FIRST-ORDER MULTIPOLARITY O.K.
C
 480  IF ( IMUL .EQ. NOTDEF )  IMUL = LXTOT
      IF ( IMUL .GE. MINLAM  .AND.
     1     IMUL .LE. MAXLAM )  GO TO 485
      write (6, 483) NAME1, NAME2, IMUL, MINLAM, MAXLAM
 483  FORMAT ( '0*** CHANNEL', I5, ' IS TO BE COUPLED TO', I5,           2370   
     1  ' IN FIRST ORDER WITH MULTIPOLARITY', I3, '/2' /
     2  6X, 'BUT ONLY', I3, '/2 =< LX =<', I3,
     2      '/2 IS POSSIBLE.' )
      GO TO 949
 485  MINLAM = IMUL
      MAXLAM = IMUL
      GO TO 600
C
C     FOR SECOND ORDER COUPLING GET POSSIBLE RANGE OF
C     MULTIPOLARITIES                                                    2380   
C
 500  MINLAM = IABS( LXX2S(1)-LXX2S(2) )
      MAXLAM = LXX2S(1) + LXX2S(2)
      IF ( LXTOP .NE. NOTDEF )  MAXLAM = MIN0( LXTOP, MAXLAM )
C
C     FOR MUTUAL EXCITATION BE SURE EACH LX IS O.K.
C
      IF ( IPT .NE. 3 )  GO TO 550
      DO 519  I = 1, 2
         IF ( LXX2S(I) .LT. IABS(JNUC(I,1)-JNUC(I,2))                    2390   
     1      .OR. LXX2S(I) .GT. JNUC(I,1)+JNUC(I,2) )  GO TO 560
 519  CONTINUE
      GO TO 600
C
C     FOR NON-MUTUAL SECOND ORDER, TOTAL LX MUST COUPLE THE
C     RELAVANT SPINS
C
 550  MINLAM = MAX0( MINLAM, IABS(JNUC(IPT,1)-JNUC(IPT,2)) )
      MAXLAM = MIN0( MAXLAM, JNUC(IPT,1)+JNUC(IPT,2) )
      IF ( MINLAM .LE. MAXLAM )  GO TO 570                               2400   
 560  write (6, 563) NAME1, NAME2, LXX2S
 563  FORMAT ( '0*** CHANNEL', I5, ' IS TO BE COUPLED TO', I5,
     1         ' IN SECOND ORDER WITH MULTIPOLES', 2(I3, '/2') /
     2   6X, 'BUT THESE CANNOT CONNECT THE NUCLEAR SPINS.' )
      GO TO 445
C
C     SEE IF A SPECIFIC MULTIPOLE HAS BEEN SPECIFIED
C
 570  LXX2 = LXTOT
      IF ( LXX2 .NE. NOTDEF )  GO TO 572                                 2410   
      LXX2 = 2*BETACS(1)
      IF ( IBETAC(1) .EQ. 3 )  GO TO 572
      IF ( IBETAN(1) .NE. 3 )  GO TO 580
      LXX2 = 2*BETANS(1)
 572  IF ( LXX2 .GE. MINLAM  .AND.  LXX2 .LE. MAXLAM
     1  .AND.  MOD(LXX2+MINLAM,4) .EQ. 0 )  GO TO 575
      write (6, 573) NAME1, NAME2, LXX2, MINLAM, MAXLAM
 573  FORMAT ( '0*** CHANNEL', I5, ' IS TO BE COUPLED TO', I5,
     1  ' IN 2ND ORDER WITH TOTAL LX =', I3, '/2' /
     2  5X, 'WHICH IS OUTSIDE OF THE ALLOWED RANGE:', 2(I3, '/2') )      2420   
      GO TO 445
 575  MINLAM = LXX2
      MAXLAM = LXX2
      GO TO 600
C
C     ALLOW LXTOT=0 ONLY IF REQUIRED
C
 580  IF ( MINLAM .EQ. 0  .AND.  MAXLAM .GE. 4 )  MINLAM = 4
C
C     LOOP OVER MULTIPOLARITIES                                          2430   
C
C     DUE TO PARITY WE CAN INCREMENT LX BY 2
C
 600  DO 829  LXX2 = MINLAM, MAXLAM, 4
C
C     MUTUAL EXCITATION IS THE PRODUCT OF TWO FIRST-ORDER
C     EXCITATION RME'S, WHICH NEED TO BE FOUND ONLY FOR THE FIRST
C     TOTAL LAMBDA.
C
      IF ( IPT .EQ. 3  .AND.  LXX2 .GT. MINLAM )  GO TO 700              2440   
C
C     GET THE VALUES OF THE BETAS
C
      IF ( IORDER .EQ. 1 )  LXX2S(1) = LXX2
      RMESGN = +1
      DO 659  I = 1, IORDER
         II = IPT
         IORD = IORDER
         IF ( IPT .EQ. 3 )  IORD = 1
         IF ( IPT .EQ. 3 )  II = I                                       2450   
         IPTS(I) = II
         LX = LXX2S(I)
         LXS(I) = LX/2
C
C     FIRST, IF NECESSARY, MERGE IN STUFF FROM THE TRANSISTIONS
C     TABLE.  NOTE THAT IN CONSULTING THIS TABLE, WE IGNOR
C     K AND DELTA K.
C
         IF ( BETACS(I) .NE. UNDEF4  .AND.  BETANS(I) .NE. UNDEF4 )
     1      GO TO 630                                                    2460   
         IF ( LTRANS .EQ. 0 )  GO TO 630
         L1 = LTRANS + ILLOC(LTRANS+5-II)
         IF ( L1 .EQ. LTRANS )  GO TO 630
         L2 = L1 + MTRANS*(ILLOC(LTRANS+7-II)-1)
         DO 619  I2 = L1, L2, MTRANS
            IF ( ILLOC(I2) .NE. LX )  GO TO 619
            IF ( BETACS(I) .NE. UNDEF4  .OR.
     1        ALLOC4(I2+1) .EQ. UNDEF4 )  GO TO 615
C
C     CAN NOT ACCEPT BE FOR 2ND ORDER                                    2470   
C
            IF ( IORD .EQ. 2  .AND.  ILLOC(LTRANS+9-II) .NE. 0 )
     1         GO TO 615
            IBETAC(I) = ILLOC(LTRANS+9-II)
            BETACS(I) = ALLOC4(I2+1)
 615        IF ( BETANS(I) .NE. UNDEF4  .OR.
     1        ALLOC4(I2+2) .EQ. UNDEF4 )  GO TO 630
            IBETAN(I) = 0
            BETANS(I) = ALLOC4(I2+2)
            GO TO 630                                                    2480   
 619     CONTINUE
C
C     WE HAVE CONSULTED ALL SOURCES.  IF BOTH BETAS ARE STILL
C     UNDEFINED, WE MUST ABANDON ALL HOPE FOR THIS LX.
C     IF ONLY ONE IS UNDEFINED, WE USE EQUAL DEFORMATION LENGTHS
C     IF DELTA IS DEFINED, CONVERT TO BETA
C
 630     IF ( BETANS(I) .EQ. UNDEF4 )  GO TO 640
         IF ( IBETAN(I) .NE. 1 )  GO TO 635
         BETANS(I) = BETANS(I)/RNUC(II)                                  2490   
         IBETAN(I) = 0
 635     IF ( BETACS(I) .NE. UNDEF4 )  GO TO 645
         BETACS(I) = RNUC(II)/RCOUL(II) * BETANS(I)
         IBETAC(I) = IBETAN(I)
         GO TO 645
 640     IBETAN(I) = -99
         IF ( BETACS(I) .NE. UNDEF4 )  GO TO 645
         IF ( IORD .EQ. 2  .AND.  I .EQ. 1 )  GO TO 829
         IBETAC(I) = -99
         GO TO 650                                                       2500   
 645     IF ( IBETAC(1) .NE. 1 )  GO TO 647
         BETACS(I) = BETACS(I)/RCOUL(II)
         IBETAC(I) = 0
 647     IF ( BETANS(I) .NE. UNDEF4  .OR.  IBETAC(I) .NE. 0 ) GO TO 650
         BETANS(I) = RCOUL(II)/RNUC(II) * BETACS(I)
C
C     PREPARE FOR POSSIBLE BETAC CONVERSION, AND IN ANY CASE
C     GET THE REDUCED MATRIX ELEMENTS BETWEEN NUCLEAR STATES
C     AND GET ALL THE OTHER COULOMB DEFORMATION SPECIFICATIONS
C                                                                        2510   
C     FOR 2ND ORDER AT ONE VERTEX THIS IS DONE ONLY ON THE 2ND PASS.
C     MUTUTAL EXCITATION IS REALLY TWO FIRST ORDERS.
C
C     NOTE THAT BEBETA RETURNS REDUCED MATRIX ELEMENTS FOR
C        <HIGHER E* || ... || LOWER E*>
C     RMESGN CONTAINS THE SIGN NECESSARY TO CONVERT TO
C        < 1 || ... || 2 >
C
C     IUP LABELS THE STATE OF THIS NUCLEUS WITH HIGHER ENERGY
C                                                                        2520   
 650     IF ( IORD .EQ. 2  .AND.  I .EQ. 1 )  GO TO 659
         IUP = 1
         IF ( ENUC(II,2) .GT. ENUC(II,1) )  IUP = 2
         IF ( IUP .EQ. 2 )  RMESGN = RMESGN *
     1      (-1)**((JNUC(II,1)-JNUC(II,2))/2)
         ITEMP = LXX2
         IF ( IORD .EQ. 1 )  ITEMP = LXX2S(I)
         TEMP = SCALE
         IF ( IORD .EQ. 1 )  TEMP = SCLFAC(I)
C                                                                        2530   
C     FOR NON-MUTUAL WE CANNOT ALLOW COULOMB FOR LXTOT=0
C     IN THE HOTFUDGE MODEL, BETAC IS A POINTER TO THE PARAMS
C
         BETTMP = BETACS(I)
         IF ( MODEL .EQ. 4 )  BETACS(I) = 0
         IF ( IPT .EQ. 3 )  GO TO 655
         IF ( LXX2 .NE. 0 )  GO TO 655
         BETACS(I) = 0
         IBETAC(I) = 2
C                                                                        2540   
c    beta_s must be real*4 here for undef4, but bebeta, etc, wants
c           real*8
c
 655     do iii = 1, 2
            xcs(iii) = betacs(iii)
            xns(iii) = betans(iii)
         enddo
         CALL BEBETA ( MODEL, IORD, I, IBETAC(I), MEORD, xcs,
     1      ITEMP, LXX2S, IZPT(II),
     1      AMS(2*II-1), RCOUL(II), ENUC(II,IUP)-ENUC(II,3-IUP),         2550   
     2      JNUC(II,IUP), JNUC(II,3-IUP), KNUC(II,IUP),
     3      KNUC(II,3-IUP),
     4      IBETAN(I),  xns, RNUC(II), TEMP, II,
     5      RMENUC(I), RMECOU(I), IRTN, VALS(1,I) )
         do iii = 1, 2
            betacs(iii) = xcs(iii)
            betans(iii) = xns(iii)
         enddo
         IF ( MODEL .EQ. 4 )  BETACS(I) = BETTMP
      IF ( PBUGSW )  write (6, 658) NAME1, NAME2, I, II, IORD, IORDER,   2560   
     1  ITEMP, IUP, LXX2, LXX2S, IBETAC(I), IBETAN(I),
     2  IZPT(II),
     3  BETACS, BETANS, RMENUC(I), RMECOU(I), IRTN
 658  FORMAT ( ' BEBETA' , 14I3, 6G13.4, I2 )
         IF ( IRTN .NE. 0 )  GO TO 445
C
C     IF BOTH RME'S ARE STILL UNDEFINED, MUST GIVE UP
C
         IF ( DABS(RMENUC(I))+DABS(RMECOU(I)) .EQ. 0 )  GO TO 829
C                                                                        2570   
C     NO MATTER WHAT THE INPUT WAS, BETANS AND BETACS
C     NOW CONTAIN BETA, UNLESS THIS IS 2ND ORDER AT ONE
C     VERTEX, IN WHICH CASE THEY HAVE BETA OR R.M.E. AND
C     THE IBETAS ARE ALREADY CORRECT OR DON'T MATTER SINCE
C     IF IT IS R.M.E., LX WAS GIVEN EXPLICITLY AND WE LOOP
C     ONLY ONCE.
C
         IF ( IORD .EQ. 2 )  GO TO 659
         IBETAN(I) = 0
         IBETAC(I) = 0                                                   2580   
C
         DELTAN(I) = BETANS(I)*RNUC(II)
C
 659  CONTINUE
C
C     PRINT SOMELINES ABOUT THE COUPLING
C
      IF ( IORD .EQ. 2 )  GO TO 665
      write (6, 663) NAME2, NAME1, MODNAM,
     1   IORDER, ( IPTWRD(IPTS(I)), LXS(I), SCLFAC(I), BETANS(I),        2590   
     1      DELTAN(I), RMENUC(I),
     2   BETACS(I), ( VALS(II,I), II=1,5 ), I = 1, IORDER )
 663  FORMAT ( 1X, 2I5, 1X, A8, I3,
     1   ( T27, A4, I3, F9.4,  F9.4, F8.4, G11.4,
     2     F9.4, F8.4, G12.4, G12.4, F9.4, G13.4 ) )
      GO TO 700
 665  IF ( LXX2 .GT. MINLAM )  GO TO 670
      write (6, 666) NAME2, NAME1, MODNAM, IORDER,
     1  IPTWRD(IPTS(1)), SCALE, LXS
 666  FORMAT ( 1X, 2I5, 1X, A8, I3, T27, A4, T34, F9.4, 3X,              2600   
     1  'LX1 =', I2, T93, 'LX2 =', I2 )
      IF ( IBETAN(1) .EQ. 0 )  write (6, 667) BETANS
 667  FORMAT ( '+', T54, 'BETAN =', F7.4, T101, 'BETAN =', F7.4 )
      IF ( IBETAC(1) .EQ. 0 )  write (6, 668) BETACS
 668  FORMAT ( '+', T70, 'BETAC =', F7.4, T117, 'BETAC =', F7.4 )
 670  L = LXX2/2
      write (6, 671) L, RMENUC(2), ( VALS(II,2), II = 2, 5 )
 671  FORMAT ( T31, I3, '  (TOTAL)', T60, G12.4, 16X,
     1  G12.4, G12.4, F9.4, G13.4 )
C                                                                        2610   
C     NOW GENERATE THE R.M.E. OF G AS DEFINED IN THE
C     NOTES 47, 70, 46, 71.
C
 700  CALL CUPAB ( IORDER, IPT, LXX2S, LXX2, RMENUC, RMECOU,
     1   RNUC, IZPT, RMEGN, RMEGC, IPT1 )
C
C     SETUP THE INGRST INDICATOR
C     IT IS
C       1 OR 2 FOR 1ST OR 2ND ORDER DERIVATIVE COUPLING
C       10000*LXT + 100*LXP + N  FOR MODELS 3, 5, 6, 7 ...               2620   
C     WHERE N = 3 FOR PROJECTILE, 4 FOR TARGET, 5 FOR MUTUAL
C     LX1 AND LX2 ARE NOT MULTIPLIED BY 2
C       6 + 100*BETAC  FOR MODEL 4 (HOTFUDGE)  IN WHICH CASE
C     BETAC IS SUPPOSED TO BE A POINTER TO THE PARAMS FOR THE
C     WOODSSAXON PARAMETERS.
C
      IPT1 = IORDER
      IF ( MODEL .LE. 2 )  GO TO 710
      IF ( IPT .EQ. 1 )  IPT1 = 3 + 50*LXX2S(1)
      IF ( IPT .EQ. 2 )  IPT1 = 4 + 5000*LXX2S(1)                        2630   
      IF ( IPT .EQ. 3 )  IPT1 = 5 + 50*LXX2S(1)+ 5000*LXX2S(2)
      IF ( MODEL .EQ. 4 )  IPT1 = 6 + 100*BETTMP
 710  IF ( PBUGSW )  write (6, 713) RMENUC, RMECOU, RMEGN, RMEGC,
     1  RMESGN, IPT1
 713  FORMAT ( ' CUPAB', 7G15.4, I5 )
C
      RMEGN = RMESGN*RMEGN
      RMEGC = RMESGN*RMEGC
C
C     LOOP OVER BASIS STATES FOR CHANNEL 1                               2640   
C
      DO 799  IB1 = IB1ST, IB1END
      IB1PT = LBASDF + (IB1-1)*MBASDF
      SCHN(1) = ILLOC(IB1PT+1)
      L1 = ILLOC(IB1PT+2)
C
C     LOOP OVER ALL BASIS STATES COUPLED TO
C
      DO 789  IB2 = IB2ST, IB2END
      IB2PT = LBASDF + (IB2-1)*MBASDF                                    2650   
      SCHN(2)=ILLOC(IB2PT+1)
      L2=ILLOC(IB2PT+2)
C
C     THE TOTAL LX MUST BE ABLE TO COUPLE THE CHANNEL SPINS AND
C     THE ORBITAL ANGULAR MOMENTA
C
      LDIFX2 = L2-L1
      IF ( IABS(LDIFX2) .GT. LXX2  .OR.
     1     IABS(SCHN(1)-SCHN(2)) .GT. LXX2 )  GO TO 789
      IF ( SCHN(1)+SCHN(2) .LT. LXX2 )   GO TO 789                       2660   
C
C     SETUP THE SYMMETRY INDICATOR
C
      FAC = 1
      IF ( .NOT. SYMSW )  GO TO 740
      IF ( ILLOC(IB1PT+6) .EQ. 2 )  GO TO 740
      IF ( ILLOC(IB2PT+6) .NE. 2 )  GO TO 730
      FAC = 2
      IF ( IPT .NE. 3 )  GO TO 740
      I = LXX2S(1) + LXX2S(2) + SCHN(2)                                  2670   
      IF ( btest(i, 1) )  GO TO 789
      GO TO 740
C
C     WE COME HERE IF BOTH "FROM" AND "TO" STATES CONSIST OF
C     NUCLEI IN IDENTICAL STATES.  IF THE COUPLING IS IN ONLY
C     ONE NUCLEUS (ONLY POSSIBLE FOR REORIENTATION) OR IF THE
C     COUPLING IS DIFFERENT IN P AND T, THEN WE DOUBLE.
C
  730 IF ( IPT .NE. 3  .OR. ( IPT .EQ. 3  .AND.
     1  ( LXX2S(1) .NE. LXX2S(2) ) ) )  FAC = 2                          2680   
C
C     FLIPPED CHANNELS GET A (-1)**S
C
  740 IF ( .NOT. FLIPSW )  GO TO 750
      I = SCHN(ICFLIP)
      IF ( btest(i, 1) )  FAC = -FAC
C
C     COMPUTE THE I**(L2-L1) FACTOR
C
 750  LDIF = LDIFX2/2                                                    2690   
      IFAC = MOD(LDIF+4000, 4) + 1
      IFAC = IFACS(IFAC)
C
C     NOW GET THE MATRIX ELEMENTS
C     REALLY THE MATRIX ELEMENTS GENERATED HERE DO NOT DEPEND
C     ON L1 NOR L2, SO THIS CALL COULD BE DONE ONLY ONCE
C     FOR EACH PAIR OF S1 AND S2.
C
      CALL CUPSPN ( IRTN,  LXX2, IPT, SCHN,
     1   LXX2S, JNUC, RMEGN, RMEGC, XN, XC )                             2700   
C
      IF ( PBUGSW )  write (6, 763) NAME1, NAME2, IB1, IB2, L1, L2,
     1    JT1, JP1, JT2, JP2, SCHN, IPARI1, IPARI2, ICP, IORDER,
     2     LXX2S, LXX2, IRTN, IPT1, XN, XC, FAC
 763  FORMAT ( ' CUPSPN', 4I3, 8(I3, '/2'), 2I2, I3, I2,
     1  3(I3,'/2'), 2I3, 2G15.5, F3.0 )
      IF ( IRTN .NE. 0 )  GO TO 770
      IRET = 0
      GO TO 789
 770  ICNT2 = ICNT2 + 1                                                  2710   
      IF ( IZPT(1)*IZPT(2) .EQ. 0 )  XC = 0
      IF ( DABS(XN)+DABS(XC) .EQ. 0 )  GO TO 789
      ICOUNT=ICOUNT+1
      ILLOC(LBASCP)=IB1
      ILLOC(LBASCP+1)=IB2
      ILLOC(LBASCP+2)=IORDER
      ILLOC(LBASCP+3)=LXX2
      ALLOC4(LBASCP+4) = FAC*XN
      ALLOC4(LBASCP+5) = FAC*XC
      ILLOC(LBASCP+6)=IFAC                                               2720   
      ILLOC(LBASCP+7)=IPT1
      ILLOC(LBASCP+8)=NOTDEF
      ILLOC(LBASCP+9)=NOTDEF
      ILLOC(LBASCP+10)=NOTDEF
C
C     ACCUMULATE MAXIMUM ORDER FOR INGRST
C
      IF ( IORDER.EQ.2)IORDX=2
C
      LBASCP = LBASCP + MBASCP                                           2730   
      NBASCP = NBASCP + 1
C
C     FOR C.C. WE WANT  LXTOP = MAX( LOUT-LIN, MULTIPOLE )
C     BASLBL DID THE FIRST PART, WE DO THE SECOND PART HERE.
C
      LXTOP = MAX0( LXTOP, LXX2/2 )
C
C
C     END OF LOOPS OVER BASIS STATES IN BOTH CHANNELS
C                                                                        2740   
 789  CONTINUE
 799  CONTINUE
C
      IF ( IORDER .NE. 1 )  GO TO 829
C
C     FOR FIRST ORDER, BETAS MUST BE FOUND AGAIN FOR EACH LX
C
      BETANS(1) = UNDEF4
      BETACS(1) = UNDEF4
C                                                                        2750   
C     END OF LOOP OVER MULTIPOLARITIES
C
 829  CONTINUE
C
      IF ( ICNT2 .NE. 0 )  GO TO 840
      write (6, 833) NAME1, NAME2, IORDER, IMUL
 833  FORMAT ( '0**** CHANNEL', I5, ' IS TO BE COUPLED TO', I5,
     1   ' BY ORDER =', I2, ' AND MULTIPOLE =', I3, '/2' /
     1  6X, '(****/2 MEANS MULTIPOLE WAS NOT SPECIFIED; ALL',
     1      ' POSSIBILITIES WERE TRIED.)' /                              2760   
     1  6X, 'BUT THERE IS NO DEFINITION OF THE REQUIRED BETAS,',
     1      ' OR THE SPECIFIED MULTIPOLE IS IMPOSSIBLE TO USE.' /
     2  6X, '(CHECK TRANSISTIONS SPECIFICATIONS.)' /
     3   6X, '(OR PERHAPS PARITY IS VIOLATED)' /
     4  6X, 'YOU NEVER KNOW FOR SURE.' )
      IRET = 0
      GO TO 949
 840  IF ( ICOUNT .NE. 0 )  GO TO 949
      write (6, 843) NAME1, NAME2, IORDER, IMUL
 843  FORMAT ( '0**** CHANNEL', I5, ' IS TO BE COUPLED TO', I5,          2770   
     1   ' BY ORDER =', I2, ' AND MULTIPOLE =', I3, '/2' /
     1  6X, '(****/2 MEANS MULTIPOLE WAS NOT SPECIFIED; ALL',
     1      ' POSSIBILITIES WERE TRIED.)' /
     1  6X, 'BUT ALL COUPLING CONSTANTS WERE ZERO (SUSPISCOUS)' )
C
C     END OF LOOP OVER ALL SPECIFIED CHANNEL COUPLINGS
C
 949  CONTINUE
C
C                                                                        2780   
C     END OF LOOPS OVER ALL CHANNELS
C
 979  CONTINUE
 999  CONTINUE
C
      X = dFLOAT(NBASCP)/NBASDF
      write (6, 1003) NBASCP, X
 1003 FORMAT ( '0THERE ARE A TOTAL OF', I6,
     1   ' COUPLINGS OF BASIS STATES FOR AN AVERAGE OF', F6.1,
     2   ' COUPLINGS PER BASIS STATE.' )                                 2790   
C
      IWRDS=(MBASCP*NBASCP)/FACFR4+1
      IL=CHOPIT(IWRDS)
C
C     WAS EVERY COUPLING SPECIFICATION USED
C
      DO 1049  ICP = 1, NCHNCP
         ICPPT = (ICP-1)*MCHNCP + LCHNCP
         IF ( ILLOC(ICPPT+13) .NE. 0 )  GO TO 1049
         write (6, 1043) ILLOC(ICPPT), ILLOC(ICPPT+1)                    2800   
 1043    FORMAT ( '0*** CHANNEL', I5, ' IS TO BE COUPLED TO', I5,
     1      ' BUT ONE OF THESE CHANNELS IS NOT DEFINED.' )
         IRET = 0
 1049 CONTINUE
C
C     NOW PREPARE TO SORT THE BASIS COUPLING ARRAY
C
      IF ( IRET .EQ. 0 )  RETURN
      ITEMP = NALLOC( NBASCP, 'SORTINDX' )
      IBASCP = NALLOC( (NBASCP*MBASCP+LPL+1)/FACFR4, 'BASISCUP' )        2810   
      LBASCP = FACFR4*(Z(IBASCP)-1)+1
      ILLOC(LBASCP) = NBASCP
      ILLOC(LBASCP+1) = MBASCP
      ILLOC(LBASCP+2) = LPL
      LBASCP = LBASCP+LPL
      LTMPCP = FACFR4*(Z(ITMPCP)-1)+1
      LTEMP = FACFR4*(Z(ITEMP)-1)
      LTMP2 = (LBASCP+1)/FACFR4
C
C     CONSTRUCT THE SORT PARAMETER.  WE SORT INTO THE ORDER              2820   
C     (MOST SLOWLY VARYING TO MOST RAPIDLY VARYING)
C       BASIS 1,  BASIS 2,  ORDER,  MULTIPOLARITY
C
      DO 1299  IBC = 1, NBASCP
         IBCPT = LTMPCP + (IBC-1)*MBASCP
         ALLOC(LTMP2+IBC) = ILLOC(IBCPT+3)
     1      + 100*( ILLOC(IBCPT+2) + 10*( ILLOC(IBCPT+1)
     2      + 5000*ILLOC(IBCPT) ) )
 1299 CONTINUE
C                                                                        2830   
      CALL IXSORT ( ILLOC(LTEMP+1), ALLOC(LTMP2+1), NBASCP )
C
C     NOW STRAIGHTEN IT OUT, PUT POINTERS INTO BASISDEF,
C     AND MAKE SURE EVERY BASIS STATE IS COUPLED.
C
      LCHNDF=Z(ICHNDF)
      LCHNDF=FACFR4*(LCHNDF-1)+1
      LCHNDF=ILLOC(LCHNDF+2)+LCHNDF
      LBASDF=Z(IBASDF)
      LBASDF=FACFR4*(LBASDF-1)+1                                         2840   
      LBASDF=LBASDF+ILLOC(LBASDF+2)
      IB1 = 1
      ILLOC(LBASDF+3) = 1
      DO 1379  IBC = 1, NBASCP
         IBCPT = LTMPCP + (ILLOC(LTEMP+IBC)-1)*MBASCP
         DO 1349  I = 1, MBASCP
            ILLOC(LBASCP+I-1) = ILLOC(IBCPT+I-1)
 1349    CONTINUE
         LBASCP = LBASCP + MBASCP
C                                                                        2850   
C     WHEN WE CHANGE BASIS STATES, UPDATE POINTERS
C
         IF ( IB1 .EQ. ILLOC(IBCPT) )  GO TO 1379
         ILLOC(LBASDF+4) = IBC-ILLOC(LBASDF+3)
         IF ( ILLOC(LBASDF+4) .GT. 0 )  GO TO 1350
         write (6, 1353) IB1, ILLOC(LCHNDF+(ILLOC(LBASDF)-1)*MCHNDF)
         IRET = 0
 1350    IB1 = IB1+1
         LBASDF = LBASDF+MBASDF
         ILLOC(LBASDF+3) = IBC                                           2860   
         IF ( IB1 .GE. ILLOC(IBCPT) )  GO TO 1379
         write (6, 1353) IB1, ILLOC(LCHNDF+(ILLOC(LBASDF)-1)*MCHNDF)
 1353    FORMAT ('0*** BASIS STATE', I5, ' OF CHANNEL', I5,
     1      ' IS NOT COUPLED TO ANYTHING.' )
         IRET = 0
         GO TO 1350
 1379 CONTINUE
      ILLOC(LBASDF+4) = NBASCP-ILLOC(LBASDF+3)+1
      IF ( IB1 .EQ. NBASDF )  GO TO 1400
      IB1 = IB1+1                                                        2870   
      write (6, 1383) IB1, NBASDF
 1383 FORMAT ( '0*** BASIS STATES', I5, ' THROUGH', I5,
     1   ' ARE NOT COUPLED TO ANYTHING.' )
      IRET = 0
C
 1400 IF ( MOD(IPRINT/100,10) .GT. 0 )  RETURN
      Z(ITEMP) = -Z(ITEMP)
      Z(ITMPCP) = -Z(ITMPCP)
      RETURN
      END                                                                2880   
C*ID* BASLBL   C109.PTOLEMY.SOURCE                          PER701  11:
      SUBROUTINE BASLBL
C
C     CONSTRUCTS BASIS STATES DEFINITIONS
C
C     WE CONSTRUCT CENTRAL LABELLING ARRAY FOR C.C.
C     WE ASSUME USUAL PREFACE STRUCTURE
C     THIS ARRAY HAS THE STRUCTURE
C     +0 CHANNEL INDEX
C     +1 J(PROJ)+J(TARG) = CHANNEL SPIN                                  2890   
C     +2 L-J VALUES  (STORED FOR J=0; MAY BE < 0)
C     +3 POINTER TO CHANNELS
C     +4 NUMBER OF CHANNELS COUPLED TO POINTER IN +3
C     +5 STARTING PARAMETER FOR HOMOGENEOUS/INHOMOGENEOUS
C     +6 SYMMETRY INDICATOR:
C        = 1 MEANS THE CHANNEL IS NOT TO BE SYMMETRIZED (EITHER
C            THE NUCLEI ARE NOT IDENTICAL OR THE STATES ARE THE SAME)
C        = 2 MEANS THE CHANNEL IS TO BE SYMMETRIZED, S MATRICES
C            ARE TO BE MULTIPLIED BY ROOT 2.  THIS IS FOR IDENTICAL
C            NUCLEI WITH NON-IDENTICAL STATES SO THERE ARE TWO           2900   
C            SUCH BASIS STATES, ONLY ONE OF WHICH IS COMPUTED.
C
C     +3 AND +4 COMPUTED IN BASCPL
C     +5 CALCULATED IN COUPLN.FORT
C
C        12/79 - FIRST VERSION - MRB
C     1/16/80 - STORE ADDRESS IN CCBLK, USE CCBLK - S.P.
C     12/9/80 - PRINT K-QUANTUM NUMBER - S.P.
C     10/19/81 - LEAVE OUT FORBIDDEN CHANNEL SPINS FOR IDEN. - S.P.
C     10/26/81 - GENERATE AND STORE SYMMETRY INDICATORS - S.P.           2910   
C     7/1/83 - GET QMIN FOR XSECTN - S.P.
C     10/15/84 - DEFINE CHANVALS - S.P.
C     5/6/85 - CHARACTER*8 ANAMES - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      parameter ( ibufsize = 200 )                                      /inpbuf/
      CHARACTER*1 IBUF(ibufsize)
      COMMON /INPBUF/ NOCH, INCH, IBUF
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      COMMON /KANDM/ AKI, AKO, REDMI, REDMO, RIMAX, ROMAX, ISIGS(2),    /kandm/
     &  RSCTS(2), ASCTS(2), RCSCTS(2) ,ISMATS(2), LOMOST, LCRIT,
     &  ISCTMN, ISCTCR, ETAS(2), RCSCTP(2), RCSCTT(2), LCRITS(2),
     &  RATMSS(2), QMIN, ABAR
 
      DIMENSION  AKS(2), REDMS(2), RMAXS(2)
      EQUIVALENCE ( AKI, AKS(1) ), ( REDMI, REDMS(1) ),
     &  ( RIMAX, RMAXS(1) )
 
      LOGICAL ONELSW, IDENSW                                            /inelcm/
      COMMON /INELCM/  JBPF, JBTF, LXMIN, LXMAX, ILILOR, ILILOI, MSTOP,
     &  IA12M, NMLOLX, ONELSW, NUMLX, IRDINT, IELCUP, LILOSZ, NUMLIS,
     &  ILIS, IBETAS(3), ICL2FF, LXSTEP, IDENSW, LSKIP,
     &  JPMIN, JPMAX, JPBASE, NJP, JTMIN, JTMAX, JTBASE, NJT,
     &  IINDXS, ISMATR, ISMATI, NSMAT, NLX, NSPLI, ITOCS,
     &  NASPLI, IUNITR, LIFIT, ILIFIT, NOLFIT, IDELSR, IDELSI
      INTEGER INDXJS(4,2)
      EQUIVALENCE ( INDXJS(1,1), JPMIN )
 
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
      COMMON /CCBLK/  ICHNDF, ICHNCP, ITRANS, IBASDF, IBASCP,           /ccblk/
     &    ICCBLK(2), IORDX, MCHNVL, ICHNVL,
     &    IHOMOA, IHOMOB, IINHR8, IINHI8
 
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
      INTEGER GIVEAL
      CHARACTER*8 NAME9/'BASISSTA'/, ANAMES
      COMMON/NAMCOM/ANAMES(1)
      DATA LENDAT/7/,LPL/3/,JLTP/10000/
      CHARACTER*1  SIGNS(2) / '+', '-' /
C                                                                        2930   
C
      LCHNDF=FACFR4*(Z(ICHNDF)-1)+1
      NCHNDF=ILLOC(LCHNDF)
      MCHNDF=ILLOC(LCHNDF+1)
      MCHNVL = 2
      ICHNVL = NALLOC( MCHNVL*NCHNDF, 'CHANVALS' )
      I=NAMLOC(NAME9)
      IF(I.NE.0)Z(I)=-Z(I)
      IBASDF=GIVEAL(IWRDS)
      ANAMES(IBASDF)=NAME9                                               2940   
      LBASDF=FACFR4*(Z(IBASDF)-1)+1+LPL
      LCHNDF=FACFR4*(Z(ICHNDF)-1)+1
      AWN=2.0*REDMI/(HBARC**2)
      LCHNDF=ILLOC(LCHNDF+2)+LCHNDF
      LCHNVL = Z(ICHNVL)
C
C     WE ACCUMULATE MAX|LIN-LOUT|
C
      LXMAX = 0
      LXMIN = 0                                                          2950   
      QMIN = 0
C
      DO 10 I=1,NCHNDF
C     LABELS FOR ETA AND K IN Z(IDATA1) RESPECTIVELY
      I1=LCHNDF+5+(I-1)*MCHNDF
      I2=I1+1
C
C     FIRST WE CALCULATE ETA AND K
C     IN EACH CHANNEL AND STORE IN Z(IDATA1)
C                                                                        2960   
      AKC=AWN*(ALLOC4(I1-1)+ALLOC4(I1-3))
      AKC=DSQRT(AKI*AKI-AKC)
      ETAC=ETAS(1)*AKI/AKC
      ALLOC(LCHNVL+MCHNVL*(I-1)) = AKC
      ALLOC(LCHNVL+MCHNVL*(I-1)+1) = ETAC
      ALLOC4(I1)=ETAC
 10   ALLOC4(I2)=AKC
C     IN THIS VERSION WE WILL ASSUME G.S. SPINS=0+
C     AND HENCE ELASTICC HANNEL PARITIES =(-1)**L(EL)
      I1=0                                                               2970   
      I3=0
      ILLOC(LCHNDF+7)=1
C
C     LOOP OVER CHANNELS
C
      DO 299 I=1,NCHNDF
C     DONT FORGET NXHINT GIVES 2*JP(JT)
      JP=IABS(ILLOC(LCHNDF+(I-1)*MCHNDF+3))
      JT=IABS(ILLOC(LCHNDF+(I-1)*MCHNDF+1))
      EP = ALLOC4(LCHNDF+(I-1)*MCHNDF+4)                                 2980   
      ET = ALLOC4(LCHNDF+(I-1)*MCHNDF+2)
      I1=I1+1
      I2=0
      J1=IABS(JP-JT)
      J2=JP+JT
      I5=0
      J4=J2/2
      IF(btest(J4, 0))I5=1
      I4=LCHNDF+(I-1)*MCHNDF+8
      LXMAX = MAX0( LXMAX, J2/2 )                                        2990   
C
C     LOOP OVER CHANNEL SPINS
C
      DO 259 J=J1,J2,2
      J3=J/2
C
C     FOR IDENTICAL SPIN-0 BOSONS, WE CAN OMIT ODD CHANNEL SPINS
C
      IF ( LSKIPS(2) .NE. 2 )  GO TO 15
      IF ( JP .NE. JT  .OR.  EP .NE. ET )  GO TO 15                      3000   
      IF ( btest(J3, 0) )  GO TO 259
C
C     SET UP SYMMETRY INDICATOR
C
 15   ISYM = 1
      IF ( ISTATS(2) .EQ. 3 )  GO TO 20
      IF ( JP .NE. JT  .OR.  EP .NE. ET )  ISYM = 2
C
 20   L1=IABS(JLTP-J)
      L2=JLTP+J                                                          3010   
      IF(I5.EQ.1)GO TO 27
      IF(btest(J3, 0))L1=L1+2
      IF(btest(J3, 0))L2=L2-2
      GO TO 28
27    J3=J3+1
      IF(btest(J3, 0))L1=L1+2
      IF(btest(J3, 0))L2=L2-2
C
C     LOOP OVER L-J
C                                                                        3020   
28    DO 199 L = L1, L2, 4
      I2=I2+1
      I3=I3+1
      LABEL2=(I3-1)*LENDAT+LBASDF
      ILLOC(LABEL2)=I1
      ILLOC(LABEL2+1)=J
      ILLOC(LABEL2+2) = L-JLTP
      ILLOC(LABEL2+6) = ISYM
 199  CONTINUE
      ILLOC(I4)=I2                                                       3030   
      IF(I.EQ.NCHNDF)GO TO 259
      ILLOC(I4+MCHNDF-1)=I2+ILLOC(I4-1)
 259  CONTINUE
 299  CONTINUE
C
      LOMOST = LMAX + LXMAX
C
C     LET US WORK OUT TOTAL NUM. OF DIFF. EQNNS.
C
      write (6, 333)                                                     3040   
 333  FORMAT ( '-  CHANNEL', T19, 'PROJECTILE', T46, 'TARGET',
     1  T65, 'Q', T73, 'ETA', T85, 'K', T93, 'NUMBER OF' /
     2  8X, 2( 6X, 'E(MEV)', 4X, 'J', 5X, 'K', 1X ),
     3    T64, 'MEV', T84, '1/FM', T93, 'EQUATIONS' / )
 337  FORMAT ( 1X, I7, 2( F12.4, I4, '/2', A1, I3, '/2' ),
     3    F12.3, 2F10.3, I10 )
      L=0
      DO  369 I=1,NCHNDF
         J=LCHNDF+(I-1)*MCHNDF
         J1=ILLOC(J)                                                     3050   
         JP=ILLOC(J+3)
         IP = 1
         IF ( JP .LT. 0 )  IP = 2
         JP = IABS(JP)
         JT=ILLOC(J+1)
         IT = 1
         IF ( JT .LT. 0 )  IT = 2
         JT = IABS(JT)
         EP=ALLOC4(J+4)
         ET=ALLOC4(J+2)                                                  3060   
         Q = -(EP+ET)
         QMIN = DMIN1( QMIN, Q )
         N = ILLOC(J+8)
         L = L+N
         write (6, 337) J1, EP, JP, SIGNS(IP), ILLOC(J+16),
     1     ET, JT, SIGNS(IT), ILLOC(J+15),
     2     Q, ALLOC4(J+5), ALLOC4(J+6), N
 369  CONTINUE
      WRITE(6,380)L
 380  FORMAT('0WE MUST SOLVE',I5,' COUPLED EQUATIONS'/)                  3070   
      ILLOC(LBASDF-LPL)=L
      ILLOC(LBASDF-LPL+1)=LENDAT
      ILLOC(LBASDF-LPL+2)=LPL
      LABEL2=LABEL2+LENDAT
      IWRDS=(LABEL2+LPL-LBASDF)/FACFR4+1
      IL=CHOPIT(IWRDS)
      RETURN
      END
C*ID* BEBETA   C109.PTOLEMY.SOURCE                          PER701  14:
      SUBROUTINE  BEBETA ( MODEL, IORD, I12, IBETAC, MEORD,              3080   
     1  XCS, LXX2, LXX2S, IZ, AMVAL,
     1  RC, DELTAE, J2, J1, K2, K1,
     3  IBETAN, XNS, RNUC, SCALE, IPT,
     4  RMENUC, RMECOU, IRTN, VALS )
C
C     COMPUTES E(LX) MATRIX ELEMENTS AND RELATED PARAMETERS
C
C     DEPENDING ON THE INPUT QUANTITIES,  BETA OR A R.M.E.
C     IS COMPUTED FOR BOTH COULOMB AND NUCLEAR.  FOR COULOMB
C     THE R.M.E. IS OF E(LX); FOR NUCLEAR IT IS OF ALPHA.                3090   
C     IN SECOND ORDER IT IS THE 2ND ORDER PART OF E(LX) OR
C     OF ALPHA X ALPHA.  THE COMPUTED E(LX) IS ALSO USED TO
C     FIND THINGS LIKE BE, Q, LIFETIME.
C
C     THIS PROGRAM IS COMPLETELY GENERAL.  THE RELATION OF
C     BETA TO THE REDUCED MATRIX ELEMENT IS MODEL DEPENDANT
C     AND IS DONE BY MEBROT FOR THE ROTATIONAL MODEL.
C
C     ARGUMENTS:
C                                                                        3100   
C     MODEL - 0 MEANS THE ROTATIONAL MODEL
C     IORD - ORDER OF THE COUPLING (1 FOR EACH PIECE OF MUTUAL)
C     I12 - 1 OR 2 TO INDICATE WHICH ELEMENTS OF XNS, XCS TO USE
C     IBETAC - DEFINES THE INPUT COULOMB QUANTITY (XCS):
C           0 = BETA
C           1 = DELTA = RC*BETA (FM)
C           2 = R.M.E. OF ALPHA
C           3 = TOTAL LX FOR 2ND ORDER  ( NEVER RECIEVED HERE )
C                 < J,M=J | Q | J,M=J >
C           4 = HALF LIFE (SEC)                                          3110   
C           5 = MEAN LIFE (SEC)
C           6 = BE(DOWN)
C           7 = REDUCED MATRIX ELEMENT (E BARN**LX/2), BOHR-MOTTELSON
C               CONVENTIONS ARE USED.  THIS IS
C               <J2,K2|| E(LX) ||J1,K1> .
C           8 = BE(UP, WEISSKOPF UNITS)
C           9 = BE(DOWN, WEISSKOPF UNITS)
C           10 = BE(UP)  (E**2 BARN**LX)
C           11 = Q (E BARN) THE QUADRUPOLE MOMENT (NOT Q0 BUT
C                THE SPECTROSCOPIC QUADRUPOLE MOMENT.                    3120   
C           12 = WIDTH IN MEV
C           -1 = BE UP FROM J=0 TO J=LX.  J1 AND J2 ARE IGNORED FOR
C               FINDING BETA.
C           -99 = NOT DEFINED
C     MEORD - =0 MEANS USE FIRST ORDER RELATION BETWEEN REDUCED MATRIX
C                ELEMENT AND BETA.
C             =1 MEANS USE SECOND ORDER RELATION.
C     XCS - THE INPUT COULOMB QUANTITIY.  IT IS REDEFINED TO BE
C           BETA UNDER MOST CIRCUMSTANCES.
C     LXX2 - 2*MULTIPOLE                                                 3130   
C     LXX2S - 2* PIECES OF TOTAL LX FOR 2ND ORDER
C     IZ - (INTEGER)  THE ATOMIC NUMBER.
C     AMVAL - THE ATOMIC MASS
C     RC - COULOMB RADIUS OF THE NUCLEUS
C     DELTAE - DIFFERENCE IN ENERGY OF THE TWO STATES (>0)
C     J2 - 2*SPIN OF THE HIGHER STATE.
C     J1 - 2*SPIN OF THE LOWER STATE
C     K2, K1 - 2*(K-QUANTUM NUMBERS) OF HIGHER AND LOWER STATES.
C     IBETAN - DEFINES INPUT NUCLEAR QUANTITY (XNS).  IT IS 0-3
C           WITH THE SAME MEANINGS AS IBETAC, OR -99 IF NOT DEFINED.     3140   
C     XNS - INPUT NUCLEAR QUANTITY.  IT IS REDEFINED TO BETA
C           UNDER MOST CIRCUMSTANCES.
C     RNUC - NUCLEAR RADIUS
C     SCALE - SCALE FACTOR BY WHICH THE RME'S ARE TO BE MULTIPLIED.
C     IPT - 1 FOR PROJECTILE, 2 FOR TARGET - NEVER 3.
C     RMENUC - SET TO < ||ALPHA|| >  ( OR ALPHA X ALPHA )
C     RMECOU - SET TO < ||E(LX)|| >  (1ST OR 2ND ORDER PART)
C     IRTN - SET TO 0 IF ALL O.K.; 1 IF RME'S COULD NOT BE FOUND
C     VALS - A 5-ELEMENT OUTPUT ARRAY THAT IS SET AS FOLLOWS:
C        1 - DELTA                                                       3150   
C        2 - BE(UP)
C        3 - Q
C        4 - HALFLIFE
C        5 - MEAN LIFE.
C
C     IF PARITY IS VIOLATED (OR SOMETHING SIMILAR) THEN
C     XCS, XNS AND VALS ARE ALL SET TO ZERO.
C
C     10/8/80 - COMPLETE REWRITE - S.P.
C     12/8/80 - SEPARATE OUT MEBROT; WEISSKOPF UNITS - S.P.              3160   
C     12/11/80 - K-QUANTUM NUMBERS ADDED - S.P.
C     1/8/81 - ALSO PROCESSES NUCLEAR STUFF - S.P.
C     1/25/81 - SCALE FACTOR ADDED - S.P.
C     6/25/81 - FIX DIVIDE BY 0 IN LIFETIME - S.P.
C     6/28/81 - WIDTH ADDED - S.P.
C     8/25/81 - ALLOW BOTH XCS AND XNS TO BE NOT DEFINED - S.P.
C     10/13/81 - FIX FOR LX=0 - S.P.
C     10/19/81 - IPT RECIEVED AND PASSED TO MEBDEF - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
C
      DIMENSION XCS(2), XNS(2), VALS(5), LXX2S(2)
C
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
C
      IRTN = 1
C
C
C     GET SOME COEFFICENTS.  THESE ARE GENERAL
C                                                                        3180   
C     LIFETIME TO BE.  WE USE C = SPEED OF LIGHT IN FM/SEC = 3E23
C
      LX = LXX2/2
      TJ1P1 = J1+1
      TJ2P1 = J2+1
      ALIFE = 0
      IF ( LX .EQ. 0 )  GO TO 40
      ALIFE = 1.D11*(10*DELTAE/HBARC)**LX
      DO 29  L = 1, LX
         ALIFE = ALIFE/(2*L+1)                                           3190   
 29   CONTINUE
      ALIFE = 8*PI*(LX+1)*2.9979*10*DELTAE /
     1   (LX*AFINE*HBARC) * ALIFE**2
 40   DLN2 = DLOG(2.D0)
C
C     Q TO M.E. AND BE TO M.E.
C
      AQ = DSQRT( 16*PI/(5*TJ1P1) ) *
     1   CLEBSH( J1, 4, J1, 0, J1, J1 )
      ABE = TJ1P1                                                        3200   
C
C     NOW GET THE RME(E(LX)) IF NECESSARY
C
C     THE CONVERSIONS TO RME THAT FOLLOW ARE ALL GENERAL
C
      IBC = -99
      IF ( IBETAC .EQ. -99 )  GO TO 520
      IBC = 3
      X = XCS(I12)
      IGOTO = IBETAC+2                                                   3210   
      GO TO ( 250, 390, 110, 350, 910, 150, 160, 200, 500, 230, 240,
     1     210, 300, 260 ), IGOTO
C
C     DELTA INPUT
C
 110  X = X/RC
      IBETAC = 0
      GO TO 390
C
C     HALFLIFE INPUT; CONVERT TO MEAN LIFE                               3220   
C
 150  X = X/DLN2
C
C     MEAN LIFE; CONVERT TO BE(DOWN)
C
 160  IF ( DELTAE .GT. 0 )  GO TO 170
      write (6, 163)
 163  FORMAT ( '0*** LIFETIME MAY BE SPECIFIED ONLY FOR',
     1   ' DIFFERENT NUCLEAR STATES.' )
      RETURN                                                             3230   
 170  X = 1/(ALIFE*X)
C
C     BE(DOWN); CONVERT TO BE(UP)
C
 200  X = TJ2P1/TJ1P1 * X
C
C     BE(UP) FROM J1 TO J2; COMPUTE R.M.E
 210  RME = DSQRT( DABS(ABE*X) )
 220  X = DSIGN( RME, X )
      GO TO 500                                                          3240   
C
C     BE(UP) IN WEISSKOPF UNITS; CONVERT TO E**2 BARN**LX
C
 230  X = 1/(4*PI) * ( 3*(.12*AMVAL**.333333333333330D0)**LX
     1    / (LX+3) )**2
      GO TO 210
C
C     BE(DOWN) IN W.U.
C
 240  X = TJ2P1/TJ1P1 * X                                                3250   
      GO TO 230
C
C     BE(UP) FROM 0 TO LX;  CHANGE THE R.M.E. TO BETA FORMULA
C     AND GET R.M.E.
C
 250  RME = DSQRT(DABS(X))
      IBC = 4
      GO TO 220
C
C     WIDTH - CONVERT TO MEAN LIFE                                       3260   
C
 260  X = HBARC / (2.9979E23*X)
      GO TO 160
C
C     Q - COMPUTE R.M.E.
C
 300  IF ( J1 .EQ. J2  .AND.  DELTAE .EQ. 0 )  GO TO 310
      write (6, 303)
 303  FORMAT ( '0*** CANNOT INPUT QUADRUPOLE MOMENT FOR',
     1   ' OFF-DIAGONAL TRANSISTIONS.' )                                 3270   
      RETURN
 310  IF ( LX .EQ. 2 )  GO TO 320
      write (6, 313)
 313  FORMAT ( '0*** QUADRUPOLE MEOMENT MAY BE SPECIFIED ONLY FOR ',
     1   ' LX = 2.' )
      RETURN
 320  X = X/AQ
      GO TO 500
C
C     <|| ALPHA(COULOMB) ||>                                             3280   
C
 350  IBC = 2
      GO TO 500
C
C     BETAC IS ALREADY KNOWN
C
 390  IBC = 1
C
C     X IS NOW BETA, <||M(ELX)||>, OR <||ALPHA||>
C                                                                        3290   
 500  XCS(I12) = X
      IF ( IBC .EQ. 2 )  IBETAC = 7
C
 520  IBN = 1
      IF ( IBETAN .EQ. 2 )  IBN = 2
      IF ( IBETAN .EQ. -99 )  IBN = -99
C
C     NOW DO THE MODEL-DEPENDANT CNVERSIONS BETWEEN BETA AND RME
C
      GO TO ( 610, 620, 630 ), MODEL                                     3300   
C
 610  CALL MEBROT ( IORD, I12, IBN, XNS, IBC, XCS,
     1  MEORD, LXX2, LXX2S, IZ,
     1  RNUC, RC, DELTAE, J2, J1, K2, K1, RMENUC, RMECOU, IRTN )
      GO TO 700
C
 620  CALL MEBVIB ( IORD, I12, IBN, XNS, IBC, XCS,
     1  MEORD, LXX2, LXX2S, IZ,
     1  RNUC, RC, DELTAE, J2, J1, K2, K1, RMENUC, RMECOU, IRTN )
      GO TO 700                                                          3310   
C
 630  CALL MEBDEF ( IORD, I12, IBN, XNS, IBC, XCS,
     1  MEORD, LXX2, LXX2S, IZ,
     2  RNUC, RC, DELTAE, J2, J1, K2, K1, RMENUC, RMECOU, IRTN,
     3  IPT )
      GO TO 700
C
 700  IF ( DABS(RMENUC)+DABS(RMECOU) .EQ. 0 )  GO TO 900
      IF (  IRTN .NE. 0 )  GO TO 900
C                                                                        3320   
      RMENUC = SCALE*RMENUC
      RMECOU = SCALE*RMECOU
C
C     NOW GET VARIOUS MODEL-INDEPENDANT STUFF
C
      BEUP = RMECOU**2/ABE
      BEDOWN = TJ1P1/TJ2P1 * BEUP
      TMEAN = 0
      IF ( DELTAE .GT. 0  .AND.  BEDOWN .NE. 0 )
     1  TMEAN = 1/(ALIFE*BEDOWN)                                         3330   
      THALF = DLN2*TMEAN
      Q = 0
      IF ( DELTAE .EQ. 0  .AND.  J1 .EQ. J2  .AND.
     1      LXX2 .EQ. 4 )  Q = AQ*RMECOU
      DELTA = RC*XCS(I12)
      VALS(1) = DELTA
      VALS(2) = RMECOU
      VALS(3) = BEUP
      VALS(4) = Q
      VALS(5) = TMEAN                                                    3340   
C
C     CONVERT RME E(LX) TO FM FOR CALCULATIONS
C
      RMECOU = RMECOU * 10**LX
      RETURN
C
 900  X = 0
      DO 909  I = 1, 5
         VALS(I) = 0
 909  CONTINUE                                                           3350   
      RETURN
 910  write (6, 913)
 913  FORMAT ( '0*** TOTAL LX INCORRECTLY PLACED IN INPUT' )
      GO TO 900
C
      END
C*ID* BETCAL   C109.PTOLEMY.SOURCE                          PER701  15:
      SUBROUTINE BETCAL ( ELSW, UK, JSP, NSPL, LMN, LMX, LSKP,
     1   LXMN, LXMX, LDELMX, NTEMPS, ISTAT, PRNTSW,
     2   SIGTOT, SIGREA,                                                 3360   
     3   JTOCS, S, SMAG, SPHASE, SIGIN, SIGOT,
     4   BETAS, TOTLX, TOTMX, ALOWFC, TEMPS )
C
C
C     CALCULATES THE ANGLE-INDEPENDENT PARTS (BETA) OF THE AMPLITUDES F.
C
C
C     INPUT SCALARS:
C
C     ELSW = TRUE FOR ELASTIC SCATTERING.                                3370   
C     UK = INCIDENT WAVENUMBER (FM**-1).
C     JSP = 2 * PROJECTILE SPIN (ELASTIC ONLY).
C     NSPL = NUMBER OF S-MATRIX ELEMENTS PER INCIDENT L.
C     LMN, LMX, LSKP = MINIMUM, MAXIMUM, AND INCREMENT IN INCIDENT L.
C     LXMN, LXMX = MINIMUM AND MAXIMUM LX.
C     LDELMX = MAXIMUM LI-LO (= ABS(MINIMUM)).
C     NTEMPS = LENGTH OF  TEMPS  ARRAY
C        = ( LXMX+1 )*( LXMX-LXMN+1 )*( LDELMX+1 )
C     ISTAT = 1 IF INCIDENT CHANNEL HAS IDENTICAL POSONS, 2 IF IDENTICAL
C        FERMIONS, 3 IF NOT IDENTICAL.                                   3380   
C     PRNTSW = TRUE IF BETAS ARE TO BE PRINTED.
C
C     OUTPUT SCALARS:
C
C     SIGTOT = TOTAL CROSS SECTION (NUCLEAR C.S. IF ELASTIC).
C     SIGREA = TOTAL REACTION CROSS SECTION (ELASTIC ONLY).
C
C     INPUT ARRAYS (AND DIMENSIONS):
C
C     JTOCS(4,NSPL) = TABLE-OF-CONTENTS FOR S MATRIX (SEE ANGSET).       3390   
C     S(2,NSPL,LMX+1) = S-MATRIX (ELASTIC ONLY).
C     SMAG(NSPL, LMX-LMN+1) = (R*4) MAGNITUDE OF S (NON-ELASTIC ONLY).
C     SPHASE(NSPL,LMX-LMN+1) = (R*4) PHASE OF S (RADIANS)
C              (NON-ELASTIC ONLY).
C     SIGIN(LMX+1) = INCOMING COULOMB PHASES.
C     SIGOT(LMX+1) = OUTGOING COULOMB PHASES (NOT USED FOR ELASTICS).
C
C     OUTPUT ARRAYS
C
C     BETAS(2,NSPL,LMX-LMN+1) = (R*4) BETA = (R*4) COEFFICIENTS          3400   
C                 OF P(L,M) IN THE
C        EXPRESSION FOR THE REACTION AMPLITUDES F.
C     TOTLX(LXMX+1) = TOTAL CROSS SECTION FOR EACH LX
C        (NON-ELASTIC ONLY).
C     TOTMX(NSPL) = TOTAL CROSS SECTION FOR EACH JP, JT, LX, MX
C        (NON-ELASTIC ONLY).
C     ALOWFC(2,2) = THE CONTRIBUTION TO BETA FOR LX=0, L=LMN, LMN+1
C        FROM NONZERO S (ELASTIC ONLY).  THE SECOND INDEX IS THE PARITY.
C
C     SCRATCH ARRAY:                                                     3410   
C
C     TEMPS(NTEMPS) = SCRATCH ARRAY, USED BOTH FOR CLEBSCH-GORDAN
C        FACTORS AND FOR SQUARE ROOTS OF FACTORIALS.
C
C     11/14/79 - FIRST VERSION - RPG
C     11/20/79 - S-MATRICES STORED BY LO-LI - S.P.
C     4/3/80 - REAL*4 SMAG, SPHASE, BETA - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
C
      LOGICAL ELSW, PRNTSW
      REAL*4  SMAG, SPHASE, BETAS
      DIMENSION  JTOCS(4,1), S(2,NSPL,1), SMAG(NSPL,1), SPHASE(NSPL,1),
     1   SIGIN(1), SIGOT(1), BETAS(2,NSPL,1),
     2   TOTLX(1), TOTMX(1), ALOWFC(2,2), TEMPS(1)
C
      DIMENSION FOPT(2), REACTN(2)
      DATA  IZERO / 0 /
C                                                                        3430   
CDC      ALLOCLEVEL  JTOCS, S, SMAG, SPHASE, SIGIN, SIGOT, BETAS,
CDC     1   TOTLX, TOLMX, TEMPS
c
C
C
C     INITIALIZATION
C
      IODD = MOD( LDELMX, 2 )
      FACTOR = 0.5/UK
      IF ( IODD .NE. 0 )  FACTOR = -FACTOR                               3440   
      NMX = LXMX + 1
      NMLX = LXMX - LXMN + 1
      IF (ELSW )  GO TO 30
C     REACTION ONLY
      DO 19  KOFFS = 1, NSPL
         TOTMX(KOFFS) = 0
 19   CONTINUE
      DO 29  LX = IZERO, LXMX
         TOTLX(LX+1) = 0
 29   CONTINUE                                                           3450   
      SIGTOT = 0
      LBASE = LMN
      LOMN = LMN
      IF ( LSKP .EQ. 2 )  LOMN = LOMN + IODD
      GO TO 40
C     ELASTIC SCATTERING ONLY
 30   LBASE = 0
      LOMN = 0
      FOPT(1) = 0
      FOPT(2) = 0                                                        3460   
      REACTN(1) = 0
      REACTN(2) = 0
      DO 39  I = 1, 4
         ALOWFC(I,1) = 0
 39   CONTINUE
C     BOTH ELASTIC AND REACTION
 40   N = 2*NSPL*(LMX-LBASE+1)
      DO 59  I = 1, N
         BETAS(I,1,1) = 0
 59   CONTINUE                                                           3470   
C
C     THE FOLLOWING FORCES THE COMMON BLOCKS USED BY CLEBSH TO BE
C     LOADED INTO CORE.
C
      CALL DUMMY1
C
C
C     THE OUTER LOOP IS OVER LO.
C
      DO 499  LO = LOMN, LMX, LSKP                                       3480   
         DLO = LO
         D2L1 = 2*DLO + 1.
         ILO = LO - LBASE + 1
         LPARIT = MOD( LO, 2 ) + 1
         LIMN = LO - LDELMX
         LIMX = LO + LDELMX
         MXMX = MIN0( LXMX, LO )
C
C     INSERT CLEBSCH-GORDANS ETC. INTO THE TEMP ARRAY.
C                                                                        3490   
         DO 159  I = 1, NTEMPS
            TEMPS(I) = 0
 159     CONTINUE
         DO 189  LI = LIMN, LIMX, 2
            IF ( LI .LT. LBASE )  GO TO 189
            LX1  = MAX0( IABS( LI-LO ), LXMN )
            DO 179  LX = LX1, LXMX
               MXZ = MOD( LX+LI-LO, 2 )
               I = 1 + NMX*( LX-LXMN + NMLX*(LI-LIMN)/2 )
               DO 169  MX = MXZ, LX                                      3500   
                  TEMPS(I+MX) = FACTOR * (2*LI+1)
     1               * CLEBSH( 2*LI, 2*LX, 0, 2*MX, 2*LO, 2*MX )
 169           CONTINUE
 179        CONTINUE
 189     CONTINUE
C
C     START THE MAIN LOOP OVER JT, JP, LX, LI-LO.
C
         LIPREV = -100000
         DO 299  KOFFS = 1, NSPL                                         3510   
            IF ( JTOCS(4,KOFFS) .LT. 0 )  GO TO 299
            LX = JTOCS(2,KOFFS)
            LI = LO - JTOCS(1,KOFFS)
C
C     A INCREASE OR NO CHANGE IN LI MEANS A NEW (JT,JP,LX) SET, AND
C     HENCE A NEW SET OF MX VALUES TO INCLUDE IN THE SUM.
C     SET UP POINTERS FOR THIS SET OF MX'S.
C     THE FIRST MX IS 0 OR 1 FOR NATURAL OR UNNATURAL PARITY.
C
            IF ( LI .LT. LIPREV )  GO TO 210                             3520   
               MXZ = LX + JTOCS(1,KOFFS)
               KOFFZ = KOFFS - MXZ
 210        LIPREV = LI
            IF ( LI .LT. LBASE  .OR.  LI .GT. LMX )  GO TO 299
C
C     INSERT THE COULOMB PHASES INTO THE S-MATRIX ELEMENT, AND
C     DIVIDE BY I.
C
C     FOR REACTIONS, S COMES FROM SMAG AND SPHASE.
C                                                                        3530   
            I = LI - LBASE + 1
            IF ( ELSW )  GO TO 230
            AMAG = SMAG(KOFFS,I)
            IF ( AMAG .EQ. 0 )  GO TO 299
            PHASE = SPHASE(KOFFS,I) + SIGIN(LI+1) + SIGOT(LO+1)
            SMATR = AMAG * DSIN( PHASE )
            SMATI = -AMAG * DCOS( PHASE )
            GO TO 250
C
C     FOR ELASTIC SCATTERING, S COMES FROM S.                            3540   
C     ALSO UPDATE REACTION CROSS SECTION.
C
 230        PHASE = SIGIN(LI+1) + SIGIN(LO+1)
            TR = DCOS(PHASE)
            TI = DSIN(PHASE)
            IF ( LO .GE. LMN )  GO TO 235
               SMATR = 0
               SMATI = 0
               IF ( LX )  250, 240, 250
 235        SR = S(1,KOFFS,I)                                            3550   
            SI = S(2,KOFFS,I)
            SMATR = SR*TI + SI*TR
            SMATI = SI*TI - SR*TR
            REACTN(LPARIT) = REACTN(LPARIT) - D2L1*( SR**2 + SI**2 )
            IF ( LX .NE. 0 )  GO TO 250
               IF ( LO .GT. LMN+1 ) GO TO 240
                  ALOWFC(1,LPARIT) = FACTOR*D2L1*SMATR
                  ALOWFC(2,LPARIT) = FACTOR*D2L1*SMATI
 240           SMATR = SMATR - TI
               SMATI = SMATI + TR                                        3560   
               REACTN(LPARIT) = REACTN(LPARIT) + D2L1
C
C     MULTIPLY  S  BY THE CLEBSCH-GORDAN ETC, AND SUM INTO  BETAS
C     FOR EACH RELEVANT MX.
C
 250        I = 1 + NMX*( LX-LXMN + NMLX*(LI-LIMN)/2 )
            DO 269  MX = MXZ, LX
               BETAS(1,KOFFZ+MX,ILO) = BETAS(1,KOFFZ+MX,ILO)
     1            + TEMPS(I+MX)*SMATR
               BETAS(2,KOFFZ+MX,ILO) = BETAS(2,KOFFZ+MX,ILO)             3570   
     1            + TEMPS(I+MX)*SMATI
 269        CONTINUE
C
 299     CONTINUE
C
C     END OF MAIN LOOP THROUGH KOFFS.
C
C     NOW CALCULATE THE SQRT(FACTORIALS) INTO TEMPS.
C
         TEMPS(1) = 1                                                    3580   
         IF ( MXMX .EQ. 0 )  GO TO 320
         DO 309  MX = 1, MXMX
            TEMPS(MX+1) = TEMPS(MX) / DSQRT( (DLO+MX)*(DLO-MX+1) )
 309     CONTINUE
C
C     CROSS SECTIONS MUST BE DOUBLED FOR IDENTICAL PARTICLES.
C
 320     TEMP = 40*PI/(2*DLO+1)
         IF ( ISTAT .NE. 3 )  TEMP = 2*TEMP
C                                                                        3590   
C     SECOND PASS THROUGH KOFFS LOOP:
C     INCREMENT THE TOTAL AND PARTIAL CROSS SECTIONS,
C     AND PUT THE SQRT(FACTORIALS) INTO BETA.
C
         DO 399  KOFFS = 1, NSPL
            IF ( JTOCS(4,KOFFS) .LT. 0 )  GO TO 399
            LX = JTOCS(2,KOFFS)
            MX = ( JTOCS(1,KOFFS) + LX + 1 )/2
            BETAR = BETAS(1,KOFFS,ILO)
            BETAI = BETAS(2,KOFFS,ILO)                                   3600   
            IF ( ELSW )  GO TO 350
C           REACTION ONLY.
            TERM = TEMP*( BETAR**2 + BETAI**2 )
            TOTMX(KOFFS) = TOTMX(KOFFS) + TERM
            IF ( MX .GT. 0 )  TERM = 2*TERM
            SIGTOT = SIGTOT + TERM
            TOTLX(LX+1) = TOTLX(LX+1) + TERM
            GO TO 360
C           ELASTICS ONLY
 350        IF ( MX .EQ. 0 )  FOPT(LPARIT) = FOPT(LPARIT) + BETAI        3610   
C
 360        BETAR = TEMPS(MX+1)*BETAR
            BETAI = TEMPS(MX+1)*BETAI
            BETAS(1,KOFFS,ILO) = BETAR
            BETAS(2,KOFFS,ILO) = BETAI
C
            IF ( PRNTSW)  write (6, 393) JTOCS(3,KOFFS), JTOCS(4,KOFFS),
     1         LX, MX, LO, BETAR, BETAI
 393        FORMAT ( ' JP, JT, LX, MX, LO, B =', 2(I3, '/2'),
     1         2I3, I4, G17.5, ' +', G13.5, 'I' )                        3620   
C Debug BETCAL reaction: (LDEL=-2,LX=2,JP=1,MX=0) all Lo<=9
            IF (.NOT.ELSW .AND. JTOCS(1,KOFFS).EQ.-2 .AND. LX.EQ.2
     1         .AND. JTOCS(3,KOFFS).EQ.1 .AND. MX.EQ.0 .AND. LO.LE.9)
     2      THEN
              WRITE(0,9701) LO, BETAR, BETAI
 9701         FORMAT('FTN_RXN_BETAS LDEL=-2_LX2_JP1_MX0 Lo=',I2,
     1               ' BR=',G12.5,' BI=',G12.5)
              FLUSH(0)
            END IF
C
 399     CONTINUE
C
 499  CONTINUE
C
C     FOR ELASTICS, FINISH CALCULATING THE REACTION AND
C     NUCLEAR CROSS SECTIONS.
C
      IF ( .NOT. ELSW )  RETURN
      SIGREA = REACTN(1) + REACTN(2)                                     3630   
      SIGTOT = FOPT(1) + FOPT(2)
      IF ( ISTAT .EQ. 3 )  GO TO 520
      TEMP = JSP
      TERM = TEMP + 1
      SIGREA = ( TEMP*SIGREA + 2*REACTN(ISTAT) )/TERM
      SIGTOT = ( TEMP*SIGTOT + 2*FOPT(ISTAT) )/TERM
 520  SIGREA = 10*PI*SIGREA/UK**2
      SIGTOT = 40*PI*SIGTOT/UK
      RETURN
      END                                                                3640   
C*ID* BOUND    C109.PTOLEMY.SOURCE                          PER701  15:
      SUBROUTINE BOUND(IRET,IVOUT,IWF2)
C
C     BOUND STATE PROGRAM
C
C  CODED 2/22/73  D.GLOECKNER
C     1/20/75 - FIX NSTEP CALCULATION - S. PIEPER
C     1/31/75 - USE /CNSTNT/, IPRINT CONTROLS PRINTING
C     2/9/75 - STORE STUFF THAT WAS STORED BY CONTRL - S.P.
C     2/11/75 - RETURN CORRECT PHI, V AT R = 0 - S.P. & D.G.             3650   
C     2/17/75 - ALLOW UP TO 9 OUTPUT VBOUNDS AND PHIS
C     2/24/75 - REMOVE MER STUFF; LOTS OF INPUT CHECKS
C     4/15/75 - NEW COMMON BLOCKS, USE TAU FOR VSO ALSO
C     4/21/75 - FIX BUG IN ASYMPTOTIC EXPANSION
C     4/23/75 - USE WHITTAKER FUNC FOR ASYMPTOTIC FORM
C     5/2/75 - SMALL FIXES; CHANGE COMPUTATION OF POTENTIALS
C     5/21/75 - MORE CHECKS ON INPUT
C     5/26/75 - MODIFY NUCONL SWITCH
C     6/11/75 - USEHS; PRINT SUMMARY AFTER FAILURE
C     6/26/75 - STEPSPER ADDED; NEW ZPZT=0 TREATMENT OF RC; NEW          3660   
C               NORM OF WHITAKER FUNCS
C     8/29/75 - PRINT R0.
C     11/10/76 - USE LOG-DERIVATIVE AT MATCHING POINT, EXTENSIVE
C                REWRITE OF SEARCH ROUTINES, USE 1 TO 3 LOOPS - S.P.
C     11/16/76 - USE NORMALIZED DERIVATIVES FOR MATCHING.
C     3/7/77 - FIX SMALL BUG IN CHOICE OF NMTOP
C     6/23/78 - DON=T COMPARE TO XP WHEN NOT DEFINED (FOR CDC)
C     5/4/79 - STORE RATMAS; PARITIES; USE BIGNUM - S.P.
C     6/6/79 - REMOVE BOUNDV ENTRY, TBIT - RPG
C     6/8/79 - STANDARD PREFIXES, CHARACTER TYPE - RPG                   3670   
C     7/6/79 - LINKULES AND MULTIPASS STUFF - RPG
C     1/14/80 - REPLACE MYSTERIOUS DROPPED CONTINUATION SYMBOL BEFORE
C               STATEMENT 559 - RPG
C     2/25/80 - DELETE FIRST INDEX FROM  LNKNAM  - RPG
C     6/3/80 - CHANGE PARPRT CALLS - S.P.
C     8/6/80 - IN DESPERATION, CALL LINKU2 FOR NOS - S.P.
C     3/3/07 - allow < 0 R,A if WAVEFUNCTION linkule being used
C
C     NOTE...  THE CHANNEL NUMBER (1 OR 2) IS INPUT VIA  ICHANB BELOW
C                                                                        3680   
C     IFIT = 0  MEANS FIT E TO V.
C            1  MEANS FIT V TO E.
C
C     ON OUTPUT:
C     IRET IS 1 IF BOUND WAS SUCCESSFUL  OR
C          IS 0 IF BOUND WAS NOT SUCCESSFUL
C     IVOUT POINTS TO THE COMPLETE POTENTIAL
C     IWF2 POINTS TO THE WAVEFUNCTION
C
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
c                                                                       /formf/
c ***  LNKADB was  numLINKULES but only 12 are used ???
c
      COMMON /FORMF/  IBDS(2), NPOTS(2), LBP, LBT, NBP, NBT, JBP, JBT,
     &  BNDMAX(2), BNDSTP(2), NSTPBD(2), RBNDS(2), ABNDS(2),
     &  RCBNDS(2), BNDMAS(2), BRATMS(2), RSOBDS(2), ASOBDS(2),
     &  VBNDS(2), VSOBDS(2), TAUBDS(2), LNKADB(6, 2, 12)
 
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      parameter ( NUMJWORD = 12 )                                       /jblock/
      COMMON /JBLOCK/  J, JS(5),
     &  JP, JSP, JST,
     &  JPARM1, JPARM2, JPARM3
 
c                                                                       /lnkblk/
c  STRUCTURE OF   /LNKBLK/
c
c  THERE IS A BLOCK OF 3 DOUBLE WORDS FOR EACH POSSIBLE USE
c  OF A LINKULE.  THE NUMLNK = NUMLINKULES USES ARE IN THE ORDER
c    REALPOTEN  IMAGPOTEN  REALVSO  IMAGVSO  COULOMB
c    WAVEFUNCTION  AND 6 TENSOR POTENTIALS
c  THE THREE-DOUBLE-WORD BLOCKS EACH HAVE THE STRUCTURE
c
c    LNKNAM(1,I)   LINKULE NAME
c
c      LNKADR(3,I)   LINKULE ADDRESS, O IF NO LINKULE IN USE.
c      LNKADR(4,I)   0 - NO L OR J DEPENDENCE IN POTENTIAL
c                    1 - L DEPENDENCE BUT NO J DEPENDENCE
c                    2 - BOTH L  AND J DEPENDENCE
c
c      LNKADR(5&6,I)  MYINTS - A TWO-ELEMENT ARRAY THAT THE
c                     LINKULE MAY USE FOR COMMUNICATION BETWEEN
c                     CALLS TO ITSELF.
c
      parameter ( NUMLINKULES = 13 )
      COMMON /LNKBLK/  NUMLNK, IUNIQU, LNKADR(6,NUMLINKULES)
      character*8  LNKNAM(3,NUMLINKULES)
      EQUIVALENCE ( LNKNAM(1,1), LNKADR(1,1) )
 
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
C                                                                        3700   
C
C     THESE EQUIVALENCES ARE IN COMMON /FORMF/.
C
      DIMENSION LBNDS(2), NBNDS(2), JBNDS(2)
      EQUIVALENCE (LBNDS(1), LBP), (NBNDS(1), NBP), (JBNDS(1), JBP)
C
C
C     THE X'S IN THESE NAMES GET REPLACED BY THE CHANNEL NUMBER.
      CHARACTER*8  NAMES(2)  / 'PHIX', 'VBOUNDX' /
CDC      INTEGER NAMES2(2) / 'PHIX', 'VBOUNDX' /                         3710   
      CHARACTER*1  NAMES1(8, 2),  mychar
      EQUIVALENCE ( NAMES(1), NAMES1(1, 1) )
C
      CHARACTER*8 CHANMS(2,3) /
     1  'PROJECTI', 'LE', '    TARG', 'ET', ' ', ' ' /
C
      DIMENSION UKS(3), ETAS(3), LWFS(3), UK2S(3), VS(3), DRIN(3),
     1  DROUT(3), PHIS(3), VALOUT(3), SUMOUT(3), SUMIN(3), NODCNT(3),
     2  IPTYPS(4)
      EQUIVALENCE ( LWFS(1), LWF1 ), ( LWFS(2), LWF2 ),                  3720   
     1  ( LWFS(3), LWF3 ), ( PHIS(1), PHI1 ), (PHIS(2), PHI2 ),
     2  ( PHIS(3), PHI3 )
C
      CHARACTER*8  PWORD(3) / '-1', 'UNKNOWN', '+1' /
      CHARACTER*1 CHNUM(9) / '1', '2', '3', '4', '5', '6', '7',         cnd
     1  '8', '9' /                                                      cnd
      CHARACTER*1 LINKID(4) / '*', '1', '0', '0' /
      character*8  linkfmtout
      equivalence ( linkfmtout, linkid(1) )
C                                                                        3730   
C
C
C  IFIT=1  MEANS FIT V0
C  IFIT=0  MEANS FIT E
C
      LOGICAL  PRNTSW, PCONSW, SOSW
      DATA IPTYPS / 1, 3, 5, 6 /
C
c
C                                                                        3740   
ccccCNS%'CALL LINKUL (' = 'CALL LINKU2 ('
C
CUN      NAMES1(I,J) = SUBSTR(NAMES(J),I,1)
C
      ISEAR = 0
C
 10   T1 = second()
      PCONSW = MOD(IPRINT/100, 10) .GE. 2
      PRNTSW = MOD(IPRINT, 10) .GE. 1
C                                                                        3750   
C   INITIALIZE PARAMETERS
C
      IF ( ICHANB .GT. 9 )  ICHANB = 1
      mychar = CHNUM(ICHANB)                                            cnd
      NAMES1(4,1) = mychar                                              cnd
      NAMES1(7,2) = mychar                                              cnd
CDC      ENCODE(20,2,NAMES)NAMES2(1),ICHANB,NAMES2(2),ICHANB
CDC    2 FORMAT(A3,I1,6X,A6,I1)
C
      SOSW = VSO .NE. 0  .OR.  TAU .NE. 0                                3760   
C
C     60 IS A REASONABLE GUESS FOR V UNDER MANY CIRCUMSTANCES
C
      IF ( V .EQ. 0 )  V = 60
C
C     TEST THE INPUT AND RETURN  0  COMPLETION CODE IF BAD
C
      IRET = 1
      IF ( R .GT. 0  .AND.  A .GT. 0 )  GO TO 30
      IF ( LNKADR(3,1) .GT. 0 .or. LNKADR(3,6) .GT. 0  )  GO TO 30       3770   
      write (6, 23) R, A
 23   FORMAT ('0**** R OR A HAS INVALID VALUE:', 2G15.5 )
      IRET = 0
 30   IF ( .NOT. SOSW )  GO TO 40
      IF ( RSO .GT. 0  .AND.  ASO .GT. 0 )  GO TO 32
      IF ( LNKADR(3,3) .GT. 0 )  GO TO 32
      write (6, 31) RSO, ASO
 31   FORMAT ( '0**** RSO OR ASO HAS INVALID VALUE:', 2G15.5 )
      IRET = 0
 32   IF ( JP .NE. NOTDEF )  GO TO 34                                    3780   
      write (6, 33)
 33   FORMAT ('0**** JP MUST BE DEFINED FOR SPIN ORBIT FORCE.')
      IRET = 0
 34   IF ( JSP .NE. NOTDEF )  GO TO 36
      write (6, 35)
 35   FORMAT ( '0**** WARNING:  SP WAS NOT DEFINED; ',
     1  'IT IS ASSUMED TO BE 1/2 FOR THE SPIN-ORBIT FORCE.' )
      JSP = 1
 36   IF ( JP .LE. JSP+2*L  .AND.  JP .GE. IABS(JSP-2*L)
     1  .AND.  MOD(JP+JSP,2) .EQ. 0  )  GO TO 40                         3790   
      write (6, 37) L, JSP, JP
 37   FORMAT ( '0**** ERROR: L, SP AND JP DO NOT FORM A TRIANGLE OR ',
     1  'THEY ARE MIXED INTEGER AND HALF-INTEGER: ',
     2  I5, 2(I5, '/2') )
      IRET = 0
 40   IF ( IFIT .EQ. 1  .AND.  V .EQ. 0 )  V = 50
      IF ( IFIT .EQ. 0  .AND.  E .EQ. UNDEF )  E = -15
      IF ( E .LT. 0  .AND.  V .GT. 0  .AND. AM .GT. 0  .AND.
     1   E .NE. UNDEF )  GO TO 50
      write (6, 43) E, V, AM                                             3800   
 43   FORMAT ('0**** E OR V OR M (REDUCED MASS) HAS INVALID',
     1  ' VALUE:', 3G15.5 )
      IRET = 0
 50   IF ( R .LT. ASYMPT  .OR.  LNKADR(3,1) .GT. 0 )  GO TO 60
      write (6, 53) R, ASYMPT
 53   FORMAT ('0**** R MUST BE LESS THAN ASYMTOPIA:', 2G15.5 )
      IRET = 0
 60   RCSAVE = RC
      IF ( RC .EQ. UNDEF  .AND.  IZP*IZT .EQ. 0 )  RC = 1
      IF ( RC .GT. 0  .OR.  LNKADR(3,5) .GT. 0 )  GO TO 70               3810   
      write (6, 63) RC
 63   FORMAT ('0**** RC IS INVALID:', G15.5 )
      IRET = 0
 70   IF ( LNKADR(3,6) .GT. 0 ) GO TO 75
      IF ( L .NE. NOTDEF  .AND.  NODES .NE. NOTDEF )  GO TO 75
      write (6, 73)
 73   FORMAT ( '0**** BOTH L AND NODES MUST BE DEFINED.' )
      IRET = 0
 75   I = PARITY*PARIPT(1)*PARIPT(2)
      IF ( I .EQ. 0 )  GO TO 80                                          3820   
      I = (I+3)/2 + L
      IF ( MOD(I,2) .EQ. 0 )  GO TO 80
      write (6, 78) L, PARITY, PARIPT
 78   FORMAT ('0**** L AND PARITIES ARE INCOMPATABLE:', 4I5 )
      IRET = 0
C
  80  ITER=0
      ITERN=0
C
      IF ( IRET .EQ. 0 )  GO TO 8875                                     3830   
C
C  K IS
      UK=DSQRT(-2*AM*E)/HBARC
      IF ( STPSPR .NE. UNDEF )  STEPSZ =
     1  DMIN1( 1/UK, A ) / STPSPR
      STPSZ2=STEPSZ*STEPSZ
      AFAC=2.0D0*AM/(HBARC*HBARC)
      DL2=L*(L+1)
C
      NSTEPS=ASYMPT/STEPSZ+1.5                                           3840   
C
C     WE DO THE MATCHING BEYOND BOTH THE REAL RADIUS
C     AND THE LAST NODE.
C
      NMTOP = DMAX1(R, A)/STEPSZ + .5
      NMTOP = MAX0( NMTOP, 20 )
      NMBOT = MAX0( NMTOP-20, 3 )
C
      IWF2 = 0
      IVOUT = 0                                                          3850   
C
      NODEH = NODES
      IF ( IHSAVE .EQ. 2 )  GO TO 900
C
C  ASK FOR SPACE FOR POTENTIAL
      IV1L= NALLOC( NSTEPS, 'BOUNDV1 ' )
      IV2L= NALLOC( NSTEPS, 'BOUNDV2 ' )
      IVOUT = NALLOC( NSTEPS, NAMES(2) )
C     AND SPACE FOR THE WAVE FUNCTIONS
      IWF1= NALLOC( NSTEPS, 'BNDPHI1 ' )                                 3860   
      IWF2= NALLOC( NSTEPS, NAMES(1) )
      IWF3= NALLOC( NSTEPS, 'BNDPHI3 ' )
C
C     INITIALIZE THE LINKULES FOR CENTRAL, COULOMB, SPIN-ORBIT,
C     AND WAVE FUNCTION.
C
      DO 99 II = 1, 4
         I = IPTYPS(II)
         IF ( LNKADR(3,I) .EQ. 0 ) GO TO 99
         IUNIQU = IUNIQU + 1                                             3870   
ccc         CALL I4LIT ( IUNIQU, LINKID(2), -3 )
         write ( unit=LINKfmtout, fmt='("*", i3.3)' )  IUNIQU
         CALL LINKUL ( LNKADR(3,I), LNKNAM(1,I), LNKADR(5,I), I, 1,
     1      IRETUR, L, JP, 0.D0, STEPSZ, NSTEPS, DUMMY, DUMMY, LINKID )
         IF ( IRETUR .LT. 0 )  GO TO 295
         LNKADR(4,I) = IRET
 99   CONTINUE
C
C     NO MORE ALLOCATOR CALLS SO GET LOCATIONS FOR REST OF SUBROUTINE
C                                                                        3880   
      LV1 = Z(IV1L)
      LV2 = Z(IV2L)
      LVOUT = Z(IVOUT)
      LWF1 = Z(IWF1)
      LWF2 = Z(IWF2)
      LWF3 = Z(IWF3)
C
C
C
C                                                                        3890   
C  AFINE IS FINE STRUCTURE CONSTANT
C NEED CI1,CI2 FOR COULOMB POTENTIAL INSIDE NUCLEAR RADIUS
C
      CI1=IZP*IZT*HBARC*1.5D0/(AFINE*RC)
      CI2=IZP*IZT*HBARC*.5D0/(AFINE*RC*RC*RC)
C
C  C0 IS COLOUMB OUTSIDE OF POTENTIAL
C
      C0=IZP*IZT*HBARC/AFINE
C                                                                        3900   
C
C  CALCULATE POTENTIAL AT ALL STEPS
C
C     THE ARRAYS ARE
C
C     ALLOC(LV1) = -(FIXED PART OF V) -- FIXED PART INCLUDES COULOMB
C          D      AND VSO PART OF SPIN ORBIT.
C     ALLOC(LV2) = -(VARIABLE PART OF V)/DEPTH -- INCLUDES REAL W.S.
C                  WELL AND TAU PART OF SPIN ORBIT.
C                                                                        3910   
C     TOTAL POTENTIAL IS
C        -( ALLOC(LV1) + V*ALLOC(LV2) )
C     ALLOC(LVOUT) = -(FIXED PART OF EFFECTIVE TRANSITION OPERATOR)
C
C     IN EACH CASE
C        ALLOC(L+I) = V( STEPSIZE*(I-1) )
C
C
C     GET THE COULOMB POTENTIAL.
C                                                                        3920   
      VMUL = -1.
      I = 5
      LL = LV1
      ASSIGN 150 TO JUMP
      IF ( LNKADR(3,5) .GT. 0 ) GO TO 290
      RVAL = -STEPSZ
      DO 139 I = 1, NSTEPS
         RVAL = RVAL + STEPSZ
         IF ( RVAL .GE. RC ) GO TO 120
         VC = CI1 - CI2*(RVAL**2)                                        3930   
         GO TO 130
 120     VC = C0/RVAL
 130     ALLOC(LV1-1+I) = -VC
 139  CONTINUE
C
C     INITIALIZE THE FIXED PART OF THE EFFECTIVE TRANSITION OPERATOR.
C
 150  DO 159 I = 1, NSTEPS
         ALLOC(LVOUT-1+I) = 0
         IF ( NUCONL .NE. 1 )  ALLOC(LVOUT-1+I) = ALLOC(LV1-1+I)         3940   
 159  CONTINUE
C
C     NOW THE CENTRAL POTENTIAL
C
      VMUL = -1./V
      I = 1
      LL = LV2
      ASSIGN 180 TO JUMP
      IF ( LNKADR(3,1) .GT. 0 )  GO TO 290
      CALL WOODSX ( NSTEPS, 0.D0, STEPSZ, ALLOC(LV2), N1, N2,            3950   
     1   1, -1.D0, R, A, POWRL )
C
C     NOW THE SPIN-ORBIT POTENTIAL (IF ANY)
C
 180  IF ( .NOT. SOSW )  GO TO 300
C     THIS IS SIGMA.L.  NOTE THAT JP, JSPS ARE DOUBLED.
      ALS = JP*(JP+2) - JSP*(JSP+2)
      ALS = (0.25*ALS - DL2)/JSP
      BLS = TAU*ALS
      ALS = VSO*ALS                                                      3960   
      VSOSV = VSO
      VSO = 1.
      VMUL = -1.
      I = 3
      LL = LWF1
      ASSIGN 200 TO JUMP
      IF ( LNKADR(3,3) .GT. 0 ) GO TO 290
      CALL WOODSX ( NSTEPS, 0.D0, STEPSZ, ALLOC(LWF1), N1, N2,
     1   2, -1.D0, RSO, ASO, 1.D0 )
C     SPLIT SPIN-ORBIT INTO FIXED (VSO) AND VARIABLE (TAU) PARTS.        3970   
 200  DO 209 I = 1, NSTEPS
         ALLOC(LV1-1+I) = ALLOC(LV1-1+I) + ALS*ALLOC(LWF1-1+I)
         ALLOC(LVOUT-1+I) = ALLOC(LVOUT-1+I) + ALS*ALLOC(LWF1-1+I)
         ALLOC(LV2-1+I) = ALLOC(LV2-1+I) + BLS*ALLOC(LWF1-1+I)
 209  CONTINUE
      VSO = VSOSV
      GO TO 300
C
C     GET THE POTENTIAL FROM A LINKULE.
C                                                                        3980   
 290  CALL LINKUL ( LNKADR(3,I), LNKNAM(1,I), LNKADR(5,I),
     1   I, 3, IRETUR, L, JP,
     2   0.D0, STEPSZ, NSTEPS, ALLOC(LL), -1.D0, 0 )
      IF ( IRETUR .GE. 0 )  GO TO JUMP, ( 150, 180, 200 )
 295  IRET = 0
      RETURN
C
C
C     NOW CALCULATE THE WAVE FUNCTION.
C                                                                        3990   
C     IF A LINKULE DOES IT, SKIP MOST OF THE FOLLOWING.
C
 300  IF ( LNKADR(3,6) .GT. 0 )  GO TO 800
C
C     WE FIND SOLUTIONS FOR THREE VALUES OF V OR K.  DELTA IS THE
C     RELATIVE SPACING TO USE.  AS APPROPRIATE, DELTAV OR DELTAK ARE
C     THE ABSOULTE SPACINGS TO USE.  SOLUTIONS ARE FOUND FOR
C     V-DELTAV, V, V+DELTAV   OR   K-DELTAK, K, K+DELTAK
C
 3020 DELTA = DELTVK                                                     4000   
      IF (PCONSW)  WRITE(6,771) ITER,V,UK, DELTA
      VST = V
      UKST = UK
C
C     SET K+, K, K- AND CORRESPONDING ETAS EACH TIME E CHANGES
C     (THIS IS FOR WHEN E AND NOT V IS BEING VARIED)
C
 3030 IF(IFIT.EQ.1)GO TO 301
      DELTAK = UK*DELTA
      DELTAV = 0                                                         4010   
      GO TO 302
 301  DELTAV = V*DELTA
      DELTAK = 0
C
 302  UKM = UK-DELTAK
      UKP=UK+DELTAK
      UKS(1) = UKM
      UKS(2) = UK
      UKS(3) = UKP
      DO 329  I = 1, 3                                                   4020   
         UK2S(I) = UKS(I)**2
         ETAS(I) = IZP*IZT*AM/(HBARC*AFINE*UKS(I))
 329  CONTINUE
      ETA = ETAS(2)
C
C     FIND ASYMPTOTIC FORM AS A WHITTAKER FUNCTION.
C     IASYMP = 1 ( SKIPASYMP )  MEANS TO JUST USE 2 AND 1 AS THE
C            LAST TWO FUNCTION VALUES.  IF THIS IS ELECTED THEN
C            ASYMPTOPIA MUST BE EXTENDED BY ABOUT 5 FM TO GIVE
C            THE WAVEFUNCTION TIME TO HEAL TO THE CORRECT FORM.          4030   
C
      RGET = ASYMPT - STEPSZ
C
C     WE NEED A NORM TERM THAT IS SMALL FOR SMALL RHO AND
C     ETA+L+1 FOR LARGE RHO.  WHEN THE WHITTAKER IS DIVIDED BY
C     GAMMA(THIS NORM) IT WILL GENERALLY NOT BE TOO LARGE OR SMALL
C
      TEMP = RGET*UK
      TEMP = (L+ETA+1) * (TEMP/(2+TEMP))**2
C                                                                        4040   
C
      DO 359  II = 1, 2
         DO 349  I = 1, 3
            IF ( I .GT. 1  .AND.  IFIT .EQ. 1 )  GO TO 345
            IF ( IASYMP .EQ. 1 )  GO TO 340
            X = COULNG( L, ETAS(I), UKS(I)*RGET, TEMP )
C
C     COULNG RETURNS THE WHITTAKER TIMES A FACTOR.  HERE WE
C     PATCH UP THE RATIO BETWEEN W(ASYMPT-STEPSZ) AND W(ASYMPT)
C                                                                        4050   
            IF ( II .EQ. 1 )  X = X *
     1         DEXP( UKS(I)*STEPSZ + ETAS(I)*DLOG(ASYMPT/RGET) )
            GO TO 345
 340        X = (3-II)
 345        ALLOC(LWFS(I)+NSTEPS-3+II) = X
 349     CONTINUE
         RGET = RGET + STEPSZ
 359  CONTINUE
      IF (PCONSW)  write (6, 363) ALLOC(LWF2+NSTEPS-2),
     1  ALLOC(LWF2+NSTEPS-1)                                             4060   
 363  FORMAT ( ' ASYMPTOTIC FORM AT LAST TWO STEPS:', 2G18.8 )
C
C  NOW HAVE ASYMPTOTIC WAVEFUNCTIONS
C
C
C
C
C
C  STEP INTO MATCHING RADIUS
C                                                                        4070   
C     FIND THE MAXIMUM VALUE OF THE MINIMUM OVER V-DELTA, V, V+DELTA,
C     OF THE WAVEFUNCTION IN THE INNER 20 STEPS AND USE AS THE MATCHING
C     RADIUS.
C
C
C     WE COME HERE FOR EACH NEW VALUE OF V
C
 500  VS(1) = V-DELTAV
      VS(2) = V
      VS(3) = V+DELTAV                                                   4080   
C
      XX = 0
      NGO=NSTEPS-NMBOT+1
      DO 529 I=3,NGO
         II=NSTEPS-I+1
         ALL= DL2/(STEPSZ*II)**2
         TEMP = BIGNUM
         DO 519  IVK = 1, 3
            K = LWFS(IVK)+II
            X = VS(IVK)*ALLOC(LV2+II)+ALLOC(LV1+II)                      4090   
            X = 2 + STPSZ2*(UK2S(IVK) - AFAC*X + ALL)
            ALLOC(K-1) = X*ALLOC(K)-ALLOC(K+1)
            TEMP = DMIN1( TEMP, DABS(ALLOC(K)) )
 519     CONTINUE
         IF ( II .GT. NMTOP )  GO TO 529
         IF ( TEMP .LE. XX )  GO TO 529
         NMATCH = II
         XX = TEMP
529   CONTINUE
C                                                                        4100   
C     COMPUTE OUTER MATCHING PARAMETERS -- DERIVATIVES, NORM
C     OF OUTER PART, VALUE AT MATCHING POINT AND NUMBER OF NODES.
C
      DO 539  IVK = 1, 3
         K = LWFS(IVK) + NMATCH
         DROUT(IVK) = (.5/STEPSZ)*(ALLOC(K+1)-ALLOC(K-1))
         VALOUT(IVK) = ALLOC(K)
         NODCNT(IVK) = 0
         SUMIN(IVK) = 0
         SUMOUT(IVK) = .5*(ALLOC(K)**2 + ALLOC(LWFS(IVK)+NSTEPS-1)**2)   4110   
         NGO = NMATCH+3
         DO 539  II = NGO, NSTEPS
            K = LWFS(IVK)-2+II
            SUMOUT(IVK) = SUMOUT(IVK) + ALLOC(K)**2
C     HERE WE COUNT THE NODE IF IT IS EXACTLY AT R(MATCH)
            IF ( ALLOC(K)*ALLOC(K-1) .LE. 0 )  NODCNT(IVK) = NODCNT(IVK)
     1         +1
 539  CONTINUE
C
C  FIND POWER SERIES SOLUTION (KEEP FIRST TWO TERMS) IN ORDER            4120   
C  TO FIX FUNCTION AT FIRST STEP.  THEN STEP TO MATCHING RADIUS
C
C     FOLLOWING IS AN APPROXIMATE EXPRESION AND NEED NOT BE TOO
C     ACCURATE.  THIS EXPRESSION IS SUCH THAT FOR L = 0
C        PHI(R) = U(R)/R ---> 1   FOR R = 0.  (BEFORE NORMALIZATION)
C     WE USE THIS FACT ONLY FOR L = 0 SO WE CAN LATER ON EXTRACT
C     PHI(0).  REALLY THIS IS JUST FINESSE SINCE PHI(0) IS NEVER
C     SIGNIFICANT.  SINCE THIS VALUE IS SIGNIFICANT ONLY FOR L = 0,
C     WE ASSUME L = 0 AND THUS IGNORE SPIN-ORBIT FORCES.
C                                                                        4130   
C     INCLUDE IT.
C
      DO 559  IVK = 1, 3
         K = LWFS(IVK)
         ALLOC(K)=0.0D0
C
C     POTENTIAL + K**2  AT R = STEPSZ.
C
         TEMP = -AFAC * ( ALLOC(LV1+1) + VS(IVK)*ALLOC(LV2+1) )
     1      + UK2S(IVK)                                                  4140   
         ALLOC(K+1) = STEPSZ * ( 1 + STPSZ2*TEMP/6 )
 559  CONTINUE
C
C  STEP OUT TO MATCHING RADIUS
C
      DO 589  II=1, NMATCH
         ALL= DL2/(STEPSZ*II)**2
         DO 589  IVK = 1, 3
            K = LWFS(IVK)+II
            X = VS(IVK)*ALLOC(LV2+II)+ALLOC(LV1+II)                      4150   
            X = 2 + STPSZ2*(UK2S(IVK) - AFAC*X + ALL)
            ALLOC(K+1) = X*ALLOC(K)-ALLOC(K-1)
            SUMIN(IVK) = SUMIN(IVK) + ALLOC(K)**2
            IF ( ALLOC(K)*ALLOC(K-1) .LT. 0 )  NODCNT(IVK) =
     1         NODCNT(IVK) + 1
589   CONTINUE
C
C     MATCH SOLUTIONS;  DERIVATIVES FOR INNER SIDE.
C
      DO 599  IVK = 1, 3                                                 4160   
         K = LWFS(IVK) + NMATCH
         SUMIN(IVK) = SUMIN(IVK) - .5*ALLOC(K)**2
C
C     SUMOUT MULTIPLIES THE OUTER SOLUTION TO NORMALIZE IT
C     SUMIN  MULTIPLIES THE INNER SOLUTION TO NORMALIZE IT
C
         XX = ALLOC(K)/VALOUT(IVK)
         X = 1/DSQRT( STEPSZ*(SUMIN(IVK) + XX**2*SUMOUT(IVK)) )
         SUMIN(IVK) = X
         SUMOUT(IVK) = XX*X                                              4170   
         VALOUT(IVK) = (XX*X) * VALOUT(IVK)
         DROUT(IVK) = (XX*X) * DROUT(IVK)
         DRIN(IVK) = X * (.5/STEPSZ)*(ALLOC(K+1)-ALLOC(K-1))
         PHIS(IVK) = DROUT(IVK) - DRIN(IVK)
 599  CONTINUE
C
C     WE LOOK FOR A ZERO OF THE DIFFERENCE OF THE INNER AND OUTER
C     DERIVATIVES.
C
      NODEH = NODCNT(2)                                                  4180   
      X = NMATCH*STEPSZ
      IF (PCONSW)  write (6, 7853) X, VS, DRIN, UKS, DROUT, VALOUT,
     1  PHIS, NODCNT
 7853 FORMAT (' DERIVATIVES AT R =', F7.2, ' FM' ,
     1        T86, 'V =', 3G15.6  /
     1  T5, 'INNER =', 3G16.6 ,   T86, 'K =', 3G15.6  /
     2  T4, 'OUTER =', 3G16.6  , T83, 'U(R) =', 3G15.6  /
     2  T7, 'DIF =', 3G16.6 , T82, 'NODES =', 3(I9, 6X) )
      IF(DABS(PHI2).LT.ACCURA)GO TO 600
      PPHI2=DABS(PHI2)                                                   4190   
      IF (PCONSW)  WRITE(6,7854)ITER,PPHI2,ACCURA
7854  FORMAT(' FOR ITER=',I3,' THE  FUNCTION IS',G11.3,' >',G11.3)
      IF(ITER.GT.MAXITR)GO TO 1001
      DP=(PHI3-PHI1)/(2.0D0*DELTA)
      DPP=(PHI3-2.0D0*PHI2+PHI1)/(DELTA*DELTA)
      XL=-PHI2/DP
      XQ = 0
      X = XL
C
C  IF DPP IS ZERO DO LINEAR APPROXIMATION                                4200   
C
      IF ( DABS(DPP) .LT. 1.E-5*DABS(DP) )  GO TO 7398
      CSQRT=(DP*DP)-2.0D0*PHI2*DPP
      IF(CSQRT.LT.0)GO TO 7398
C
      XQ =(-DP+(DP/DABS(DP))*DSQRT(CSQRT))/DPP
      IF ( LINEAR .NE. 1 )  X = XQ
C
 7398 IF ( DABS(X) .GT. .5 )  X = DSIGN( .5 0D0, X )
      IF (PCONSW)  WRITE(6,9123)DP,DPP, XL, XQ, X                        4210   
9123  FORMAT(' DP,DPP =',2G14.5 /
     1  ' LINEAR, QUADRATIC METHODS =', 2G12.3,
     2  5X, 'REL. STEP OF V OR K USED =', G14.5 )
C
C     FIND A NEW DELTAVK.  WE USE THE STEP LENGTH USED IN THIS
C     ITERATION UNLESS IT STAYED WITHIN THE THE PREVIOUS DELTA,
C     INWHICH CASE WE USE .5 OF IT.
C
      XX = DELTA
      DELTA = DABS(X)                                                    4220   
      IF ( DELTA .LT. XX )  DELTA = .5*DELTA
      IF(DELTA.LT.(1.0D-7))DELTA=1.0D-7
      DELTA = DMIN1( DELTA, .2 0D0 )
      IF(IFIT.NE.0)GO TO 3070
      XX = UK*(1+X)
      IF(XX.LE.0.0D0)UK=UK/2.0D0
      IF(XX.GT.0.0D0)UK=XX
      GO TO 3737
 3070 XX = V*(1+X)
      IF ( XX .GT. 0 )  V = XX                                           4230   
      IF ( XX .LE. 0 )  V = .5*V
 3737 ITER = ITER + 1
      IF (PCONSW)  WRITE(6,771) ITER,V,UK, DELTA
 771  FORMAT ( '0ITERATION', I3, 5X, 'V =', G16.8, '  K =', G16.8,
     1  5X, 'DELTAVK =', G12.4 )
      IF(IFIT.EQ.0)GO TO 3030
      DELTAV = DELTA*V
      GO TO 500
C
C  MAXITRTER EXCEDED.  SEE IF WE HAVE RIGHT NUMBER OF NODES              4240   
C
 1001 IF(NODES.NE.NODEH)GO TO 6666
      WRITE(6,901)
CXX      IF(ISEAR.EQ.0)GO TO 1111
CXX      E=99.99D0
CXX      IRET = 0
CXX      GO TO 8875
901    FORMAT(' ******** NO SOLUTION FOUND *********')
C
C     RETURN AFTER A FAILURE                                             4250   
C
 1111 IRET = 0
      GO TO 850
C
C     HAVE CONVERGED ON A V OR UK - CHECK FOR PROPER NUMBER OF NODES
C
600   PPHI2=DABS(PHI2)
      IF (PCONSW)  WRITE(6,8457)ITER,PPHI2,ACCURA
8457  FORMAT(' ON ITERATION ',I3,' THE FUNCTION IS',G11.3,' <',
     1  G11.3)                                                           4260   
      E=-UK2S(2)*HBARC*HBARC/(2.0D0*AM)
      IF (PCONSW)  WRITE(6,5546)V,E
5546  FORMAT(/'   FIT LOCATED WITH V=',F14.8,' AND E=',F14.8/)
C
C
C  RENORMALIZE WAVEFUNCTION AND CHECK NODES
C
      IF(NODEH.EQ.NODES)GO TO 6041
C
C     SOLUTION HAS WRONG NUMBER OF NODES - TRY ANOTHER V OR UK           4270   
C
 6666 WRITE(6,6044) V, E, NODEH,NODES
6044  FORMAT(' FOR V =', F8.2, ',  E =', F7.2, ', WAVEFUNCTION HAS',
     1  I3, ' NODES BUT', I3, ' ARE DESIRED.' )
      IF ( ITERN .LE. MAXITR )  GO TO 6668
      write (6, 6667) NODES
 6667 FORMAT ( '0**** COULD NOT FIND A SOLUTION WITH', I3, ' NODES.')
      GO TO 1111
 6668 ITER=0
      ITERN=ITERN+1                                                      4280   
C
C     WE USE
C
C       X = DESIRED NUMBER OF NODES
C       XQ = NUMBER OF NODES WE JUST GOT
C       XP = PREVIOUS NUMBER OF NODES
C       PHI1 = PRESENT V OR K
C       PHI2 = NEXT V OR K
C       PHIP = PREVIOUS V OR K
C                                                                        4290   
      X = NODES
      XQ = NODEH
C
C     WE USE THE STARTING OR FINAL V OR K, WHICH EVER IS CLOSER
C     TO WHERE WE WANT TO GO.
C
      IF ( NODES .LT. NODEH )  GO TO 8130
      V = DMAX1( V, VST )
      UK = DMIN1( UK, UKST )
      GO TO 8150                                                         4300   
 8130 V = DMIN1( V, VST )
      UK = DMAX1( UK, UKST )
 8150 PHI1 = V
      IF ( IFIT .EQ. 0 )  PHI1 = UK**2
      IF ( ITERN .LE. 1)  GO TO 8160
      IF ( XP .NE. XQ )  GO TO 8200
C
C     WE HAVE ONLY ONE POINT TO WORK WITH
C
 8160 IF ( IFIT .EQ. 0 )  GOTO 8170                                      4310   
      PHI2 = (X+1)*PHI1/(XQ+1)
      GO TO 8300
 8170 PHI2 = ( 1 + (XQ-X)/(XQ+1) )*PHI1
      GO TO 8300
C
C     HAVE TWO POINTS - USE STRAIGHT LINE
C
 8200 PHI2 = PHI1 + (X-XQ)*(PHI1-PHIP)/(XQ-XP)
C
C     DO NOT ALLOW TO GO NEGATIVE                                        4320   
C
 8300 IF ( PHI2 .LE. 0 )  PHI2 = .5*PHI1
C
      PHIP = PHI1
      XP = XQ
      IF ( IFIT .EQ. 1 )  GO TO 8350
      UK = DSQRT(PHI2)
      E = -(UK*HBARC)**2 / (2*AM)
      WRITE(6,4459) E
4459  FORMAT(' WILL TRY A NEW E: ', G14.5 )                              4330   
      GO TO 3020
 8350 V = PHI2
      WRITE(6,7210)V
7210  FORMAT(' WILL TRY A NEW V:  ',G14.5)
      GO TO 3020
C
C     SOLUTION HAS PROPER NUMBER OF NODES - CLEAN UP
C
 6041 IF (PCONSW)  WRITE(6,5564)NODES,L, JP
5564  FORMAT('  SOLUTION HAS ',I1,' NODE(S). L=',I2,' JP=',I2,'/2')      4340   
      GO TO 850
C
C
C     WAVE FUNCTION IS CALCULATED BY A LINKULE.
C     ARRAY1 IS THE ANSWER, ARRAY2 IS (-1/V)*THE VARIABLE POTENTIAL,
C     ID IS A POINTER TO -1*THE FIXED POTENTIAL.
C
 800  CALL LINKUL ( LNKADR(3,6), LNKNAM(1,6), LNKADR(5,6), 6, 3,
     1   IRETUR, L, JP, 0.D0, STEPSZ, NSTEPS,
     2   ALLOC(LWF2), ALLOC(LV2), LV1 )                                  4350   
      IF ( IRETUR .LT. 0 )  GO TO 295
      SUMIN(2) = 1
      SUMOUT(2) = 1
      NMATCH = NSTEPS/2
      NODEH = NODES
C
C     NORMALIZE THE SOLUTION AND CONVERT TO   PHI = U/R
C
 850  RVAL = STEPSZ
      NGO = NMATCH + 1                                                   4360   
      DO 859  II = 1, NGO
         ALLOC(LWF2+II) = SUMIN(2)*ALLOC(LWF2+II)/RVAL
         RVAL = RVAL + STEPSZ
 859  CONTINUE
      NGO = NGO + 2
      DO 869  II = NGO, NSTEPS
         ALLOC(LWF2-1+II) = SUMOUT(2)*ALLOC(LWF2-1+II)/RVAL
         RVAL = RVAL + STEPSZ
 869  CONTINUE
C                                                                        4370   
C     FOR L = 0 GET WAVEFUNCTION AT ORIGIN BASED ON STARTING
C     VALUE DEFINED ABOVE
C
      IF ( L .EQ. 0 )  ALLOC(LWF2) = SUMIN(2)
C
C     FOR L=0 WAVEFUNCTIONS FROM LINKULES, WE EXTRAPOLATE, USING THE
C     FACT THAT THE DERIVATIVE = 0 AT R=0.
C
      IF ( L .EQ. 0  .AND.  LNKADR(3,6) .GT. 0 )
     1   ALLOC(LWF2) = ( 4*ALLOC(LWF2+1) - ALLOC(LWF2+2) )/3             4380   
C
C  FREE SECONDARY AREAS HERE
C
      Z(IWF1)=-Z(IWF1)
      Z(IWF3)=-Z(IWF3)
      Z(IV1L) = -Z(IV1L)
C
C     PRINT RESULTS NICELY
C
 900  IF ( .NOT. PRNTSW )  GO TO 990                                     4390   
      I = ICHANB
      IF ( I .GT. 2 )  I = 3
      UK = DSQRT(-2*AM*E)/HBARC
      ETA = IZP*IZT*AM / (HBARC*AFINE*UK)
      write (6, 913) CHANMS(1,I), CHANMS(2,I), E, UK
 913  FORMAT ( / '0', T10, A8, A2, ' BOUND STATE PARAMETERS' /
     1  '0E =', F10.4, ' MEV', 5X, 'KAPPA =', F8.5 )
      Q1 = 0
      Q2 = 0
      Q3 = 0                                                             4400   
      IF ( AMP .EQ. UNDEF  .OR.  AMT .EQ. UNDEF )  GO TO 920
      write (6, 918) AMP, AMT, AM
 918  FORMAT ( ' PROJECTILE MASS =', F7.2, ' AMU', 5X,
     1    'TARGET MASS =', F7.2, ' AMU', 5X,
     2    'REDUCED MASS =', F10.2, ' MEV/C**2' )
      GO TO 925
 920  write (6, 923) AM
 923  FORMAT ( ' REDUCED MASS =', F10.2, ' MEV/C**2' )
 925  write (6, 928) L, NODEH
 928  FORMAT ( ' L =', I3, I9, ' NODES' )                                4410   
      IF ( JSP .NE. NOTDEF  .AND.  JST .NE. NOTDEF )  write (6, 933)
     1  JSP, JST
 933  FORMAT ( ' PROJECTILE SPIN =', I3, '/2', 5X,
     1  'TARGET SPIN =', I3, '/2' )
      IF ( JP .NE. NOTDEF )  write (6, 935) JP
 935  FORMAT (' J PROJECTILE =', I3, '/2' )
      IF ( J .NE. NOTDEF )  write (6, 937) J
 937  FORMAT ( ' TOTAL J =', I3, '/2' )
      write (6, 943) PWORD(PARIPT(1)+2), PWORD(PARIPT(2)+2),
     1  PWORD(PARITY+2)                                                  4420   
 943  FORMAT ( ' PROJECTILE PARITY IS ', A7,
     1  '   TARGET PARITY IS ', A7,
     2  '   TOTAL PARITY IS ', A7 )
      write (6, 953) IZP, IZT
 953  FORMAT ( ' Z PROJECTILE =', I4, 5X, 'Z TARGET =', I4 /
     7  '0POTENTIAL', T20, 'COUPLING CONS.', T38, 'RADIUS',
     8      T48, 'DIFFUSENESS', T63, 'RADIUS PARAM.' )
      CALL PARPRT ( 1, 'REAL CENTRAL      ', V, R, A,
     1   R/R0MASS, POWRL, '   POWER', IRETUR )
      CALL PARPRT ( 3, 'REAL SPIN-ORBIT   ', VSO, RSO, ASO,              4430   
     1   RSO/R0MASS, TAU, '     TAU', IRETUR )
      CALL PARPRT ( 5, 'PT.&SPHERE COULOMB', ETA, RC, 0.D0,
     1   RC/R0MASS, 0.D0, '        ', IRETUR )
C
      TEMP = DMIN1( 1/UK, A ) / STEPSZ
      write (6, 963) ASYMPT, STEPSZ, TEMP
 963  FORMAT ( '0ASYMPTOPIA =', T15, F8.3, ' FM' /
     1  ' STEP SIZE =', T15, F8.3, ' FM' ,
     2     5X, F8.3, ' STEPS PER "ASYMPTOTIC RANGE"' / )
C                                                                        4440   
C     IF THE WAVEFUNCTION IS CALCULATED BY A LINKULE, CALL IT TO
C     PRINT STUFF ABOUT ITSELF.
C
      IF ( LNKADR(3,6) .EQ. 0 )  GO TO 990
      write (6, 973)  LNKNAM(1,6)
 973  FORMAT ( '0 THE BOUND WAVEFUNCTION WAS COMPUTED BY THE ', A8,
     1   ' LINKULE:' )
      CALL LINKUL ( LNKADR(3,6), LNKNAM(1,6), LNKADR(5,6), 6, 2,
     1   IRETUR, L, JP, 0.D0, STEPSZ, NSTEPS,
     2   ALLOC(LWF2), ALLOC(LV2), LV1 )                                  4450   
      IF ( IRETUR .LT. 0 )  GO TO 295
      write (6, 983)
 983  FORMAT ( 1X )
C
C
C     SAVE THE POTENTIAL AND OTHER STUFF FOR GRDSET
C
 990  IF ( ICHANB .GT. 2  .OR.  ICHANB .LT. 1 )  GO TO 6330
      IBDS(ICHANB) = IWF2
      NPOTS(ICHANB) = IVOUT                                              4460   
      LBNDS(ICHANB) = L
      NBNDS(ICHANB) = NODES
      JBNDS(ICHANB) = JP
      BNDMAX(ICHANB) = ASYMPT
      write(0,'(A,I2,A,F10.4,A,F10.4,A,I5)')
     &  'FTN_BNDMAX(',ICHANB,')=',ASYMPT,
     &  ' STEPSZ=',STEPSZ,' NSTEPS=',NSTEPS
      BNDSTP(ICHANB) = STEPSZ
      NSTPBD(ICHANB) = NSTEPS
      RBNDS(ICHANB) = R
      ABNDS(ICHANB) = A
      RCBNDS(ICHANB) = RC
      BNDMAS(ICHANB) = AM                                                4470   
      EBNDS(ICHANB) = E
      BRATMS(ICHANB) = RATMAS
C
C     THE FOLLOWING WILL BE NEEDED FOR THE NEXT PASS (IF ANY).
C
      RSOBDS(ICHANB) = RSO
      ASOBDS(ICHANB) = ASO
      VBNDS(ICHANB) = V
      VSOBDS(ICHANB) = VSO
      TAUBDS(ICHANB) = TAU                                               4480   
      DO 993  I = 1, 12
         DO 993  II = 1, 6
            LNKADB(II,ICHANB,I) = LNKADR(II,I)
 993  CONTINUE
C
C     CAN WE COMPUTE THE Q OF THE REACTION
C
      IF ( EBNDS(3-ICHANB) .EQ. UNDEF )  GO TO 6330
      Q = EBNDS(1) - EBNDS(2)
      IF ( ISTRIP .EQ. -1 )  Q = -Q                                      4490   
C
 6330 IF ( IHSAVE .EQ. 2 )  GO TO 8875
C
C     CONSTRUCT THE COMPLETE POTENTIAL FOR V PHI
C
      DO 6339  I = 1, NSTEPS
         ALLOC(LVOUT-1+I) = -( ALLOC(LVOUT-1+I)
     1      + V*ALLOC(LV2-1+I) )
 6339 CONTINUE
      Z(IV2L) = -Z(IV2L)                                                 4500   
C
C     IF REQUESTED, PRINT THE WAVEFUNCTION
C
      RVAL=0.0D0
      IF ( WRITES .eq. undef ) GO TO 8875
      NWRITE = DMAX1( WRITES/STEPSZ+.5, 1.D0 )
      WRITE(6,7071)
7071  FORMAT(' PSI=F(R)/R' /
     2  4X, 'STEP', 6X, 'RADIUS', 8X, 'WAVEFUNCTION' /)
      DO 6061 II=1,NSTEPS,NWRITE                                         4510   
         RVAL=(II-1)*STEPSZ
         WRITE(6,7707)II, RVAL, ALLOC(LWF2+II-1)
 7707    FORMAT ( I8, F12.5, G15.5 )
6061   CONTINUE
C
8875  RC = RCSAVE
      T1 = second() - T1
      IF ( PCONSW )  write (6, 8878) T1
 8878 FORMAT ( ' BOUND STATE CPU TIME =', F7.3, ' SECONDS.' )
      RETURN                                                             4520   
C
C
C
CXX      ENTRY BOUNDV (IRET,  IV2L, IWF2, VV0, VVSO)
CXX      ISEAR=1
CXX      V=VV0
CXX      VSO = VVSO
CXX      GO TO 10
      END
C*ID* BSPROD   C109.PTOLEMY.SOURCE                          PER701  14:  4530   
      SUBROUTINE BSPROD ( FPFT, ITYPE, RA, RB, X, ISCAT, NAIT,
     1  RP, RT, * )
CDC     1  RP, RT),RETURNS(IRTRN1)
C
C     COMPUTES BOUND-STATE PRODUCT PHI(RT)*VEFF*PHI(RP)
C     USING SUBROUTINE AITLAG TO INTERPOLATE IN TABLES
C
C     ITYPE - CONTROLS FUNCTION COMPUTED:
C       = 1 - PHI V PHI
C       = 2 - PHI' V PHI'                                                4540   
C       = 3 - RPSI PHI V PHI RPSI
C       = 4 - RPSI PHI' V PHI' RPSI
C       WHERE
C         PHI = BOUNDSTATE WAVEFUNCTION;
C         PHI' = PHI         FOR R > LOC(MAX(PHI))
C              = MAX(PHI)    FOR  < LOC(MAX(PHI))
C         RPSI = R* SCATTERING WAVEFUNCTION
C     RP AND RT ARE COMPUTED FROM RA, RB AND X.
C     ISCAT IS THE ALLOCATOR INDEX OF THE SCATTERING WAVEFUNC TO USE.
C     *  IS ST. NO. TO GO TO WHEN RP OR RT EXCEEDS MAX. ALLOWED VALUE    4550   
C
C     IF RA OR RB > ASYMPTOPIA; THEN WE USE R INPLACE OF R*PSI
C
C     IF NUCONL.EQ.2 VEFF INCLUDES CORE-COULOMB CORRECTION
C     EVALUATED AT (RCORE,RSCAT)
C     IF NUCONL.EQ.3 VEFF INCLUDES BOTH COULOMB AND (REAL) NUCLEAR
C     CORE CORRECTIONS
C
C     6/1/75   (MHM)
C     7/7/75 - COMPUTE RP, RT, RCORE, RSCAT                              4560   
C
C     4/29/76 - MHM
C               MAJOR MODIFICATIONS AND ADDITIONS
C               NEW ENTRY SETRS ADDED
C     5/23/76 - SETRS CHANGED TO BSSET AND INCLUDES INITIALIZATION
C               OF BS ARRAYS - S.P.
C     11/20/77 - V, NOT V/E, IS NOW IN WAVCOM - S.P.
C     12/13/77 - DEFINE IPRNT PROPERLY - S.P.
C     8/10/79 - STANDARD PREFIXES, PUT V*PHI IN ITS OWN ARRAY,
C        KEEP V AND PHI FOR MULTIPASS - RPG                              4570   
C     3/9/83 - AVOID DIVIDE BY V = 0 - S.P.
C     11/7/85 - DO NOT USE UNDEFINED ARGS DURING BSSET ENTRY - S.P.
C
C
C     PERMITS USE OF FOLDED-UNIFORM COULOMB POTENTIAL
C     IF NUCONL.EQ.3 INCLUDES CORE-CORRECTION TO VEFF FROM
C     REAL PART OF OPTICAL POTENTIAL IN APPROPRIATE CHANNEL
C
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      COMMON /KANDM/ AKI, AKO, REDMI, REDMO, RIMAX, ROMAX, ISIGS(2),    /kandm/
     &  RSCTS(2), ASCTS(2), RCSCTS(2) ,ISMATS(2), LOMOST, LCRIT,
     &  ISCTMN, ISCTCR, ETAS(2), RCSCTP(2), RCSCTT(2), LCRITS(2),
     &  RATMSS(2), QMIN, ABAR
 
      DIMENSION  AKS(2), REDMS(2), RMAXS(2)
      EQUIVALENCE ( AKI, AKS(1) ), ( REDMI, REDMS(1) ),
     &  ( RIMAX, RMAXS(1) )
 
      LOGICAL  IOUTSW, PINFSW                                           /bsblk/
      REAL*4  PHISGN
      COMMON /BSBLK/
     &  S1, S2, T1, T2, BNDMXP, BNDMXT, RLPMAX, RLTMAX,
     &  VPMAX, VTMAX, SCTMAX, SCTSP,
     &  BNDSPT, BNDSPP, BNDSPV, NSPBDT, NSPBDP, NSPBDV,
     &  JBDT, JBDP, JPOT, IOUTSW, NSPSCT, ALPHAP, ALPHAT,
     &  PINFSW, PHISGN, ROFMAX
      DIMENSION  RLMAXS(2), VMAXS(2)
      EQUIVALENCE ( RLMAXS(1), RLPMAX ), ( VMAXS(1), VPMAX )
 
c                                                                       /formf/
c ***  LNKADB was  numLINKULES but only 12 are used ???
c
      COMMON /FORMF/  IBDS(2), NPOTS(2), LBP, LBT, NBP, NBT, JBP, JBT,
     &  BNDMAX(2), BNDSTP(2), NSTPBD(2), RBNDS(2), ABNDS(2),
     &  RCBNDS(2), BNDMAS(2), BRATMS(2), RSOBDS(2), ASOBDS(2),
     &  VBNDS(2), VSOBDS(2), TAUBDS(2), LNKADB(6, 2, 12)
 
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
C                                                                        4590   
      LOGICAL  ALLSW
CCC many more also      save isc
      save
C
c
C
C     STEP 1 - COMPUTE  PHI V PHI   OR   PHI' V PHI'
C
      RP = (S2*RA)**2 + (T2*RB)**2 +
     1   2*(S2*RA)*(T2*RB)*X                                             4600   
      RT = (S1*RA)**2 + (T1*RB)**2 +
     1   2*(S1*RA)*(T1*RB)*X
      IF ( DABS(RP) .LT. 1.D-8 )  RP = 0
      IF ( DABS(RT) .LT. 1.D-8 )  RT = 0
      RP = DSQRT(RP)
      RT = DSQRT(RT)
C
      FPFT = 0
      IF ( RP .GT. BNDMXP  .OR.  RT .GT. BNDMXT )  RETURN 1
C                                                                        4610   
      FP = VPMAX
      FT = VTMAX
      ALLSW = MOD( ITYPE, 2 ) .NE. 0
      DELVNU=0
C
      IF ( ALLSW .OR. RT .GT. RLTMAX )
     1  FT=AITLAG(RT,BNDSPT,ALLOC(Z(JBDT)),NSPBDT,NAIT)
      IF ( ALLSW .OR. RP .GT. RLPMAX )
     1  FP=AITLAG(RP,BNDSPP,ALLOC(Z(JBDP)),NSPBDP,NAIT)
      FACTOR=1                                                           4620   
      FPFT = FP*FT
      IF ( NUCONL .NE. 2  .AND.  NUCONL .NE. 3 ) GO TO 200
      IF ( DABS(FPFT) .LT. SMLNUM )  GO TO 200
C
C     MULTIPLY V*PHI BY (V+DV)/V ; THIS GIVES (V+DV)*PHI
C     DV IS CORE CORRECTION TO VEFF
C     NUCONL = 2 ; DV=VCOUL(RCORE)-VCOUL(RSCAT)
C     NUCONL = 3 ; DV=DV(COUL)+VNUC(RCORE)-VNUC(RSCAT)
C     WHERE VNUC IS REAL PART OF NUCLEAR OPTICAL POTENTIAL
C                                                                        4630   
      RSCAT = RA
      IF ( IOUTSW )  RSCAT = RB
      RCORE = DSQRT( ((S1-S2)*RA)**2 + ((T1-T2)*RB)**2
     1  + 2*((S1-S2)*RA)*((T1-T2)*RB)*X )
      CALL VCSQ12(RCORE,POT,3)
      DELVCO=POT
      CALL VCSQ12(RSCAT,POT,ISC)
      DELVSC=POT
      DELV=DELVCO-DELVSC
      IF((NUCONL.NE.3).OR.(NAIT.EQ.2)) GO TO 8                           4640   
      XCORE=(RCORE-RNCORE)/AOPT
      IF(XCORE.LT.BIGLOG) GO TO 400
      FCORE=0
      GO TO 440
  400 IF(XCORE.GT.-BIGLOG) GO TO 420
      FCORE=1
      GO TO 440
  420 FCORE=1/(1+DEXP(XCORE))
  440 XSCAT=(RSCAT-RNSCAT)/AOPT
      IF(XSCAT.LT.174) GO TO 460                                         4650   
      FSCAT=0
      GO TO 500
  460 IF(XSCAT.GT.-175) GO TO 480
      FSCAT=1
      GO TO 500
  480 FSCAT=1/(1+DEXP(XSCAT))
  500 DELVNU=VOPT*(FCORE-FSCAT)
      DELV=DELV+DELVNU
    8 RBND=RT*(IVRTEX-1)+RP*(2-IVRTEX)
      VEFF=AITLAG(RBND,BNDSPV,ALLOC(Z(JPOT)),NSPBDV,NAIT)                4660   
      FACTOR=1+DELV/VEFF
      FPFT = FACTOR*FPFT
      IF ( IPRNT .GE. 9 )
     1 write (6, 193) RA, RB, RP, RT, RCORE,
     2   VEFF, DELVSC, DELVCO, DELVNU, DELV, FACTOR, FPFT
 193  FORMAT ( ' BSP', 5F8.4, 7G12.4 )
C
C     NOW WE MULTIPLY IN THE PSI'S IF DESIRED.
C     IN FACT WE MULTIPLY IN R*PSI
C                                                                        4670   
 200  IF ( ITYPE .LE. 2 )  RETURN
C
      IF ( RA .GT. SCTMAX )  GO TO 220
      FPFT = FPFT *
     1  AITLAG( RA, SCTSP, ALLOC(Z(ISCAT)), NSPSCT, NAIT )
C     AVOID UNDERFLOWS
      IF ( DABS(FPFT) .GT. 1.D-34 )  GO TO 250
      FPFT = 0
      RETURN
 220  FPFT = FPFT * RA                                                   4680   
C
 250  IF ( RB .GT. SCTMAX )  GO TO 270
      FPFT = FPFT *
     1  AITLAG( RB, SCTSP, ALLOC(Z(ISCAT)), NSPSCT, NAIT )
      RETURN
 270  FPFT = FPFT * RB
      RETURN
C
C     INITIALIZE THE FORM-FACTOR CALCULATION
C                                                                        4690   
      ENTRY BSSET
C
C
C     COMPUTE APPROPRIATE  V*PHI  AND STORE IT IN "VPHI".  NOTE THAT FOR
C     NUCONL.GE.2 (SEE BELOW) THIS IS ONLY A TEMPORARY V*PHI FOR SETTING
C     UP THE GRIDS.  THE REAL V*PHI IS THEN FOUND AT STMNT. NO. 830.
C
C     IVRTEX = 1  FOR PROJECTILE VERTEX
C            = 2  FOR TARGET VERTEX
C                                                                        4700   
C     ALSO FIND THE MAXIMUM VALUES OF THE FORMFACTOR AND BOUND STATE
C     AND GET LOCS OF THE MAXIMA
C
      IPRNT=MOD(IPRINT/10000,10)
      JPOT = NPOTS(IVRTEX)
      JBD1 = IBDS(IVRTEX)
      JBD2 = IBDS(3-IVRTEX)
      NSPBDV = NSTPBD(IVRTEX)
      NSPBDT = NSTPBD(3-IVRTEX)
      IVPHI = NALLOC ( NSPBDV, 'VPHI    ' )                              4710   
      LVPHI = Z(IVPHI) - 1
      LPOT = Z(JPOT) - 1
      LBD1 = Z(JBD1) - 1
      LBD2 = Z(JBD2) - 1
      VMAXS(IVRTEX) = 0
      VMAXS(3-IVRTEX) = 0
C
      RRP = -BNDSTP(IVRTEX)
      DO 219  I = 1, NSPBDV
         RRP = RRP + BNDSTP(IVRTEX)                                      4720   
         TEMP = ALLOC(LBD1+I)*ALLOC(LPOT+I)
         IF ( DABS(TEMP) .LE. VMAXS(IVRTEX) )  GO TO 215
         RLMAXS(IVRTEX) = RRP
         VMAXS(IVRTEX) = DABS(TEMP)
 215     ALLOC(LVPHI+I) = TEMP
 219  CONTINUE
      RRT = -BNDSTP(3-IVRTEX)
      DO 229  I = 1, NSPBDT
         TEMP = ALLOC(LBD2+I)
         RRT = RRT + BNDSTP(3-IVRTEX)                                    4730   
         IF ( DABS(TEMP) .LE. VMAXS(3-IVRTEX) ) GO TO 229
         RLMAXS(3-IVRTEX) = RRT
         VMAXS(3-IVRTEX) = DABS(TEMP)
 229  CONTINUE
C
      IF (PINFSW)  write (6, 233) VMAXS, RLMAXS
      write(0,'(A,2G15.5,A,2G15.5)') 'FTN_RLMAXS V=',VMAXS,
     &  ' RL=',RLMAXS
 233  FORMAT ( ' PROJECTILE AND TARGET FORMFACTOR MAXIMA:',
     1    2G15.5 /
     1  ' LOCATION OF PROJECTILE AND TARGET FORM-FACTOR MAXIMA:',
     2   2G15.5 )                                                        4740   
C
C     FREE POTENTIAL AT VERTEX WHERE INTERACTION ISNT (IF NOT MULTIPASS)
C
      IF ( IBSPAS .GT. 0 )  GO TO 1620
      Z(NPOTS(3-IVRTEX))=-Z(NPOTS(3-IVRTEX))
      IF(NUCONL.GE.2) GO TO 1620
      Z(JPOT)=-Z(JPOT)
C
 1620 JBDP = IBDS(1)
      IF ( IVRTEX .EQ. 1 )  JBDP = IVPHI                                 4750   
      JBDT = IBDS(2)
      IF ( IVRTEX .EQ. 2 )  JBDT = IVPHI
      BNDSPP = 1/BNDSTP(1)
      BNDSPT = 1/BNDSTP(2)
      BNDSPV = 1/BNDSTP(IVRTEX)
      NSPBDP = NSTPBD(1)
      NSPBDT = NSTPBD(2)
      BNDMXP = BNDMAX(1)
      BNDMXT = BNDMAX(2)
C                                                                        4760   
C     EXPONENTIAL TAIL FACTORS FOR H-INTERPOLATION
C
      ALPHAP = SQRT( -2*BNDMAS(1)*EBNDS(1) ) / HBARC
      ALPHAT = SQRT( -2*BNDMAS(2)*EBNDS(2) ) / HBARC
      IF ( IPRNT .GE. 4 )  write (6, 1643) ALPHAP, ALPHAT
 1643 FORMAT ( '0EXPONENTIAL DECAYS OF FORM FACTOR:  RP =',
     1  G13.5, 5X, 'RT =', G13.5 )
C
      IF ( NUCONL .LT. 2 )  RETURN
C                                                                        4770   
C
C     COMPUTE POTENTIAL PARAMETERS FOR CORE TERMS IN VEFF
C
C
C     COMPUTE  RADII AND COUPLING CONSTANTS FOR CORE TERMS IN VEFF
C
C     NUCONL  SPECIFIES WHAT IS TO BE DONE ABOUT CORE TERMS IN
C     THE VERTEX POTENTIAL:
C     0 - USESIMPLECOULOMB - V = V(NUC, IVERTEX) + V(COUL, IVERTEX)
C         HERE BOTH THE NUCLEAR AND COULOMB ARE FUNCTIONS OF JUST        4780   
C        ONE VERTEX COORDINATE (RP OR RT).
C     1 - NUCONLY - V = V(NUC, IVERTEX).  NO COULOMB TERMS AT ALL.
C     2 - USECOULOMB - V = V(NUC, IVERTEX) + V(COUL, RP, RT, PHI)
C         HERE THE COULOMB PART CONTAINS CORRECTIONS DUE TO THE
C         CORES AND IS A FUNCTION OF ALL 3 COORDINATES.
C     3 - USECORE - V = V(NUCONL=2) + DV(NUC)
C     WHERE DV(NUC) IS CORE CORRECTION FROM REAL PART OF VOPT
C     NUCONL = 0 OR 1  IS TAKEN CARE OF BY BOUND.  NUCONL.GE.2 IS
C     TREATED AS 0 BY BOUND AND MUST BE FURTHER CORRECTED HERE.
C                                                                        4790   
      POW=1.D0/3.D0
      AMA3=AMA**POW
      AMB3=AMB**POW
      AMBGA3=AMBIGA**POW
      AMBGB3=AMBIGB**POW
      FACTOR=1
C
C     FOLDED COULOMB POTENTIALS IN BOTH CHANNELS 0
C
      ISEE=0                                                             4800   
      DO 20 I=1,2
   20 IF((RCSCTP(I).EQ.0).OR.(RCSCTT(I).EQ.0)) ISEE=1
C
C     PHISGN = +1 ; STRIPPING ;
C     PHISGN = -1 ; PICK-UP
C     IVRTEX =  1 ; VEFF AT PROJECTILE VERTEX
C     IVRTEX =  2 ; VEFF AT TARGET VERTEX
C
      IF(PHISGN.EQ.-1) GO TO 60
      IF(IVRTEX.EQ.2) GO TO 40                                           4810   
C
C     STRIPPING ; PROJECTILE VERTEX
C
      ISC=2
      IZS1=IZS(2)
      IZS2=IZS(4)
      IZC1=IZS(2)
      IZC2=IZS(3)
      IF(ISEE.EQ.0) FACTOR=AMBGA3/AMBGB3
      IF(ISEE.EQ.1) FACTOR=(AMBGA3+AMB3)/(AMBGB3+AMB3)                   4820   
      RCPSCT=RCSCTP(2)
      RCTSCT=RCSCTT(2)
      RCCOP=RCPSCT
      RCCOT=RCTSCT*FACTOR
      IOUTSW=.TRUE.
      IF(NUCONL.NE.3) GO TO 100
      RNSCAT=RSCTS(2)
      RNCORE=RNSCAT*((AMBGA3+AMB3)/(AMBGB3+AMB3))
      VOPT=-V0RS(2)
      AOPT=ASCTS(2)                                                      4830   
      GO TO 100
C
C     STRIPPING ; TARGET VERTEX
C
   40 ISC=1
      IZS1=IZS(1)
      IZS2=IZS(3)
      IZC1=IZS(2)
      IZC2=IZS(3)
      IF(ISEE.EQ.0) FACTOR=AMB3/AMA3                                     4840   
      IF(ISEE.EQ.1) FACTOR=(AMB3+AMBGA3)/(AMA3+AMBGA3)
      RCPSCT=RCSCTP(1)
      RCTSCT=RCSCTT(1)
      RCCOP=RCPSCT*FACTOR
      RCCOT=RCTSCT
      IOUTSW=.FALSE.
      IF(NUCONL.NE.3) GO TO 100
      RNSCAT=RSCTS(1)
      RNCORE=RNSCAT*((AMB3+AMBGA3)/(AMA3+AMBGA3))
      VOPT=-V0RS(1)                                                      4850   
      AOPT=ASCTS(1)
      GO TO 100
C
C     PICK-UP ; PROJECTILE VERTEX
C
   60 IF(IVRTEX.EQ.2) GO TO 80
      ISC=1
      IZS1=IZS(1)
      IZS2=IZS(3)
      IZC1=IZS(1)                                                        4860   
      IZC2=IZS(4)
      IF(ISEE.EQ.0) FACTOR=AMBGB3/AMBGA3
      IF(ISEE.EQ.1) FACTOR=(AMBGB3+AMA3)/(AMBGA3+AMA3)
      RCPSCT=RCSCTP(1)
      RCTSCT=RCSCTT(1)
      RCCOP=RCPSCT
      RCCOT=RCTSCT*FACTOR
      IOUTSW=.FALSE.
      IF(NUCONL.NE.3) GO TO 100
      RNSCAT=RSCTS(1)                                                    4870   
      RNCORE=RNSCAT*((AMBGB3+AMA3)/(AMBGA3+AMA3))
      VOPT=-V0RS(1)
      AOPT=ASCTS(1)
      GO TO 100
C
C     PICK-UP ; TARGET VERTEX
C
   80 ISC=2
      IZS1=IZS(2)
      IZS2=IZS(4)                                                        4880   
      IZC1=IZS(1)
      IZC2=IZS(4)
      IF(ISEE.EQ.0) FACTOR=AMA3/AMB3
      IF(ISEE.EQ.1) FACTOR=(AMA3+AMBGB3)/(AMB3+AMBGB3)
      RCPSCT=RCSCTP(2)
      RCTSCT=RCSCTT(2)
      RCCOP=RCPSCT*FACTOR
      RCCOT=RCTSCT
      IOUTSW=.TRUE.
      IF(NUCONL.NE.3) GO TO 100                                          4890   
      RNSCAT=RSCTS(2)
      RNCORE=RNSCAT*((AMA3+AMBGB3)/(AMB3+AMBGB3))
      VOPT=-V0RS(2)
      AOPT=ASCTS(2)
C
C     INITIALIZE COULOMB-POTENTIAL SUBROUTINE
C
  100 CALL SETVSQ(RCCOP,RCCOT,IZC1,IZC2,3)
C
      IF(IPRNT.LE.4) RETURN                                              4900   
      write (6, 550)ISC,IZS1,IZS2,IZC1,IZC2,NUCONL
  550 FORMAT(1H0,2X,'++++ SETRS ++++'/3X,'CHANNEL ',I2,
     1'(Z1,Z2) = ( ',I2,1X,I2,' )'/3X,'  CORE  (Z1,Z2) = (',
     2I2,1X,I2,') NUCONL = ',I2)
      write (6, 600)RCPSCT,RCTSCT,RCCOT,RCCOP
  600 FORMAT(1H ,2X,'SCATTERING :(RT,RP) = ',G12.6,1X,G12.6,
     1'(COULOMB)'/3X,'CORE :(RT,RP) = ',G12.6,1X,G12.6,
     2'(COULOMB)')
      IF(NUCONL.NE.3) RETURN
      write (6, 650)RNSCAT,RNCORE,VOPT,AOPT                              4910   
  650 FORMAT(1H0,2X,' (RNSCAT,RNCORE)=',G12.6,1X,G12.6/
     13X,'(-V,A)=(',G12.6,1X,G12.6,1X,G12.6,')')
      RETURN
      END
C*ID* CALANG   C109.PTOLEMY.SOURCE                          PER701  15:
      SUBROUTINE  CALANG ( GRADSW, LLMIN, LLMAX, LSKIP, MPARA,
     1   ANGLE,
     2   PL, COULPH, DFDX, SINCOS, SMAT, DSDP,
     3   FR, FI, RUTH, HIGHR, HIGHI )
C                                                                        4920   
C     EVALUATES CROSS SECTIONS AND GRADIENTS FOR ONE ANGLE
C
C     THIS ROUTINE IS CALLED FROM CALFUN TO DO THE CALCULATION AT ONE
C     ANGLE.  IT IS A SEPARATE ROUTINE TO IMPROVE COMPILATION.
C
C     5/22/78 - SPLIT OFF FROM CALFUN - S.P.
C     12/26/79 - CFR%F - RPG
C
      implicit real*8 ( a-h, o-z )                                      implicit
C                                                                        4930   
      LOGICAL GRADSW
      DIMENSION  PL(LLMAX), COULPH(LLMAX), DFDX(2,MPARA),
     1  SINCOS(2,LLMAX), SMAT(2,LLMAX), DSDP(2,MPARA,LLMAX)
C
CDC      ALLOCLEVEL  PL, COULPH, DFDX, SINCOS, SMAT, DSDP
C
C
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      COMMON /LOCFIT/ IDATA, LPL, LSIGMA, LSMAT, IESETS, IMASK,         /locfit/
     &   IEQUAL, NPARA, IPARA, ITEMP, LSCSIG, LEPARM, LFS, NPTS, LEQNAM,
     &   MAXEQL, MAXVS, LVDERV, LSDELS, LDVTYP, LDSDP, LDFDX, LFGRAD,
     &   LTGRAD, LMASK, LEQUAL, MNDRIV, MXDRIV, IESIZE, LENPRE,
     &   LENKEY, LENHED,  ILNKBL
 
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
      COMMON /KANDM/ AKI, AKO, REDMI, REDMO, RIMAX, ROMAX, ISIGS(2),    /kandm/
     &  RSCTS(2), ASCTS(2), RCSCTS(2) ,ISMATS(2), LOMOST, LCRIT,
     &  ISCTMN, ISCTCR, ETAS(2), RCSCTP(2), RCSCTT(2), LCRITS(2),
     &  RATMSS(2), QMIN, ABAR
 
      DIMENSION  AKS(2), REDMS(2), RMAXS(2)
      EQUIVALENCE ( AKI, AKS(1) ), ( REDMI, REDMS(1) ),
     &  ( RIMAX, RMAXS(1) )
 
C
C
C
C     GET LEGENDRE POLYNOMIALS
C
 250  CALL PLSUB ( LLMAX, DCOS(ANGLE), PL)                               4950   
C
C  RUTHEFORD CROSS SECTION FIRST
C
      RATJAC = ETAS(1)/(2*AKS(1))
      TEMP = ANGLE
      FR = 0
      FI = 0
C
C   ******************************************************
C   *                                                    *               4960   
C   *  FOLLOWING WORKS ONLY FOR:                         *
C   *   1) NON-IDENTICAL PARTICLES (LSKIP=1)             *
C   *   2) IDENTICAL SPIN-0 PARTICLES (LSKIP=2)          *
C   *                                                    *
C   ******************************************************
C
      DO 269  I = 1, LSKIP
         S2=DSIN(TEMP*.5)
         FR = FR - RATJAC/S2**2 *DCOS(2*(COULPH(1)
     1      - ETAS(1)*DLOG(S2)) )                                        4970   
         FI = FI - RATJAC/S2**2 *DSIN(2*(COULPH(1)
     1      - ETAS(1)*DLOG(S2)) )
         TEMP = PI - TEMP
 269  CONTINUE
C  CROSS SECTIONS IN MILLI BARNS
      RUTH= 10.0D0 * (FR*FR + FI*FI)
      IF ( RUTH .EQ. 0 )  RUTH = 1
C
C  NOW NUCLEAR AMPS
C     FOLLOWING FACTORS CONTAIN FACTOR OF 2 FOR IDENTICAL PARTICLES      4980   
C
      CINCR = LSKIP/AKS(1)
      C = .5*CINCR
      CINCR = LSKIP*CINCR
C
      IF ( .NOT. GRADSW )  GO TO 310
      DO 309  I = 1, MPARA
         DFDX(1,I) = 0
         DFDX(2,I) = 0
 309  CONTINUE                                                           4990   
C
 310  IF ( LLMIN .EQ. 0 )  GO TO 330
C
C     SUM FOR L < LMIN; S = 0
C
      LMINM1 = LLMIN-LSKIP
      IZERO = 0
      DO 329  LL = IZERO, LMINM1, LSKIP
         AFAC = C*PL(LL+1)
         C = C + CINCR                                                   5000   
         FR = FR - AFAC*SINCOS(1,LL+1)
         FI = FI + AFAC*SINCOS(2,LL+1)
 329  CONTINUE
C
C     NOW SUM FOR  LLMIN =< L =< LLMAX
C
 330  ASSIGN 360 TO IGOTO
      ASSIGN 360 TO JGOTO
      IF (GRADSW)  GO TO 335
      ASSIGN 369 TO IGOTO                                                5010   
      ASSIGN 369 TO JGOTO
 335  IF ( ITEMP .NE. 2 )  ASSIGN 355 TO IGOTO
C
      DO 369  LL = LLMIN, LLMAX, LSKIP
         AFAC = C*PL(LL+1)
         SINSIG = AFAC*SINCOS(1,LL+1)
         COSSIG = AFAC*SINCOS(2,LL+1)
         C = C + CINCR
         FR = FR + SINSIG*(SMAT(1,LL+1)-1)
     1     + COSSIG*SMAT(2,LL+1)                                         5020   
         FI = FI + SINSIG*SMAT(2,LL+1)
     1     - COSSIG*(SMAT(1,LL+1)-1)
C
         GO TO IGOTO, ( 355, 360, 369 )
 355     IF(LL.NE.(LLMAX-2))GO TO 359
         HIGHR=FR
         HIGHI=FI
 359     GO TO JGOTO, ( 360, 369 )
C
C     COMPUTE THE GRADIENT OF F IF NEEDED                                5030   
C
 360     DO 365  I = 1, MPARA
            DFDX(1,I) = DFDX(1,I)
     1        + SINSIG*DSDP(1,I,LL+1)
     2               + COSSIG*DSDP(2,I,LL+1)
            DFDX(2,I) = DFDX(2,I)
     1        + SINSIG*DSDP(2,I,LL+1)
     2               - COSSIG*DSDP(1,I,LL+1)
 365     CONTINUE
C                                                                        5040   
369   CONTINUE
C
      RETURN
C
      END
C*ID* CALFUN   C109.PTOLEMY.SOURCE                          PER701  15:
      FUNCTION  CALFUN ( NPTST, MPARA, FS, XS )                         cnd
CDC      FUNCTION  CALFN2 ( NPTST, MPARA, FS, XS, FGRAD, TGRAD )
C
C  CALCULATE CHI SQUARE SUM WITH GIVEN OPTICAL PARAMETER SET             5050   
C
C     ENTRIES:
C       CALFUN - COMPUTES THE CHI-SQUARED SUM AND THE ARRAY FS
C                OF INDIVIDUAL ERRORS
C         CHI-SUM  =  SUM(I) FS(I)**2
C
C       CALGRA - COMPUTES THE ABOVE AND THE JACOBIAN ARRAY FGRAD
C           FGRAD(I,M) = D( FS(I) ) / D( PARAMETER(M) )
C                 ALSO FINDS THE TOTAL GRADIEND TGRAD
C           TGRAD(M) = D( CHI-SUM ) / D( PARAMETER(M) )                  5060   
C
C     IF  MOD ( IPRINT, 100 )  IS NON-ZERO, WE PRINT A LINE EACH
C     TIME CALFUN OR CALGRA IS CALLED.
C
C  THIS ROUTINE IS CALLED FROM VA02A
C  AND FROM FITEL WHEN ROCORD SPECIFIED
C     AND VIA INTERFACES FOR THE OTHER FITTERS.
C
C *************************************************************
C *   THIS ROUTINE WILL NEED ADDITIONAL WORK FOR S.O. FORCES  *          5070   
C *************************************************************
C
C  THIS FIRST VERSION 8/15/75  D.G.
C     10/2/75 - MERGE INTO SEPTEMBER PTOLEMY - S.P.
C     10/7/75 - USE MAKPOT FOR POTENTIALS - S.P.
C     10/11/75 - TABLE OF SIN/COS(SIGMA)
C     10/15/75 - ELAB-DEPENDENT LMIN/LMAX AND STEPSIZE
C     10/21/75 - ESQ PARAMETERS
C     10/23/75 - PRINT POTENTIALS; PRINT EQUALS
C     10/28/75 - COMPUTE GRADIENTS                                       5080   
C     11/4/75 - OUT-OF-BOUNDS STEPS; SEPARATE PRTCHI.
C     11/6/75 - IMPROVED TIMING; OTHER SMALL FIXES
C     11/12/75 - FIX RENORMALIZATION AND WEIGHT - S.P.
C     11/20/75 - LAB-ANGLE SHIFT - S. P.
C     12/28/75 - PRINT TRANSFORMED DATA
C     1/15/76 - MADE INTO A FUNCTION; USE IPRINT
C     1/31/76 - SMALL PRINTOUT FIXES
C     7/31/76 - NEW DATA STRUCTURE; LAB ANGLES; CDC/IBM
C     4/15/77 - MULTIPLE CHANNELS; DATA IN STANDARD FORM; CHANGE PRINTIN
C     4/21/77 - RENORM AND ANGLE SHIFT CAN BE FIT                        5090   
C     4/26/77 - IDENTICAL PARTICLES; DATA HAS LENGTH INDICATORS
C     11/22/77 - NEW SETFIT, PRTCHI - S.P.
C     12/1/77 - RESTORE LINKULE STUFF - S.P.
C     2/14/78 - NUMERICAL DERIVATIVES
C     4/15/78 - CALGR2 FOR CDC OVERLAY; IESIZE INSTEAD OF 9 - S.P.
C     4/17/78 - PRINT DIAGNOSTIC MESSAGE AT ENTRY - S.P.
C     4/24/78  - REVERSE LOMOST FOR LIMOST - S.P.
C         5/22/78 - SEPARATE OUT CALANG - S.P.
C     5/4/79 - RATMAS FROM DATA - S.P.
C     12/26/79 - STANDARD MORTRAN - RPG                                  5100   
C
C
      implicit real*8 ( a-h, o-z )                                      implicit
CDC      ALLOCLEVEL FS,XS,FGRAD,TGRAD
C
      DIMENSION FS(NPTST),XS(MPARA)
      DIMENSION FGRAD(NPTST, MPARA),  TGRAD(MPARA)
      REAL*4 DUMMY4(1)
C
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
C
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      COMMON /LOCFIT/ IDATA, LPL, LSIGMA, LSMAT, IESETS, IMASK,         /locfit/
     &   IEQUAL, NPARA, IPARA, ITEMP, LSCSIG, LEPARM, LFS, NPTS, LEQNAM,
     &   MAXEQL, MAXVS, LVDERV, LSDELS, LDVTYP, LDSDP, LDFDX, LFGRAD,
     &   LTGRAD, LMASK, LEQUAL, MNDRIV, MXDRIV, IESIZE, LENPRE,
     &   LENKEY, LENHED,  ILNKBL
 
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
      COMMON /KANDM/ AKI, AKO, REDMI, REDMO, RIMAX, ROMAX, ISIGS(2),    /kandm/
     &  RSCTS(2), ASCTS(2), RCSCTS(2) ,ISMATS(2), LOMOST, LCRIT,
     &  ISCTMN, ISCTCR, ETAS(2), RCSCTP(2), RCSCTT(2), LCRITS(2),
     &  RATMSS(2), QMIN, ABAR
 
      DIMENSION  AKS(2), REDMS(2), RMAXS(2)
      EQUIVALENCE ( AKI, AKS(1) ), ( REDMI, REDMS(1) ),
     &  ( RIMAX, RMAXS(1) )
 
      REAL*4  TBEGIN, TIMES                                             /ftimef/
      COMMON /FTIME/ TBEGIN, NUMLOP, NUMWAV, TIMES(6), NUMCAL, NUMGRA
 
c                                                                       /lnkblk/
c  STRUCTURE OF   /LNKBLK/
c
c  THERE IS A BLOCK OF 3 DOUBLE WORDS FOR EACH POSSIBLE USE
c  OF A LINKULE.  THE NUMLNK = NUMLINKULES USES ARE IN THE ORDER
c    REALPOTEN  IMAGPOTEN  REALVSO  IMAGVSO  COULOMB
c    WAVEFUNCTION  AND 6 TENSOR POTENTIALS
c  THE THREE-DOUBLE-WORD BLOCKS EACH HAVE THE STRUCTURE
c
c    LNKNAM(1,I)   LINKULE NAME
c
c      LNKADR(3,I)   LINKULE ADDRESS, O IF NO LINKULE IN USE.
c      LNKADR(4,I)   0 - NO L OR J DEPENDENCE IN POTENTIAL
c                    1 - L DEPENDENCE BUT NO J DEPENDENCE
c                    2 - BOTH L  AND J DEPENDENCE
c
c      LNKADR(5&6,I)  MYINTS - A TWO-ELEMENT ARRAY THAT THE
c                     LINKULE MAY USE FOR COMMUNICATION BETWEEN
c                     CALLS TO ITSELF.
c
      parameter ( NUMLINKULES = 13 )
      COMMON /LNKBLK/  NUMLNK, IUNIQU, LNKADR(6,NUMLINKULES)
      character*8  LNKNAM(3,NUMLINKULES)
      EQUIVALENCE ( LNKNAM(1,1), LNKADR(1,1) )
 
C
      REAL*4  T0, TTIMER
C
      LOGICAL GRADSW, BACKSW, PRNTSW
      CHARACTER*1  mychar, BLANK /' '/,  STAR /'*'/
C
c
C
      GRADSW = .FALSE.
      NUMCAL = NUMCAL + 1                                                5130   
      GO TO 1
C
C     FOLLOWING ENTRY IS FOR GRADIANT COMPUTATIONS
C
      ENTRY  CALGRA ( NPtst, MPARA, FS, XS, FGRAD, TGRAD )              cnd
CDC      ENTRY CALGR2
C
      GRADSW = .TRUE.
      NUMGRA = NUMGRA + 1
C                                                                        5140   
  1   T0=second()
C
C
C
      IRET=0
      CHISQ=0
C
      PRNTSW = MOD(IPRINT/100, 10) .GT. 0
      IF ( PRNTSW )  write (6, 3) XS
 3    FORMAT (' CALFUN INPUT:', ( T16, 8G14.5 ) )                        5150   
C
      IF ( .NOT. GRADSW )  GO TO 10
      DO 5  I = 1, MPARA
 5    TGRAD(I) = 0
 10   LEKEY = IDATA + LENPRE-1
      ICNTPT=0
      LWAVR = Z(IWAVR)
      LWAVI = Z(IWAVI)
      LVREAL = Z(IRLVS(1))
      LVIMAG = Z(IIMVS(1))                                               5160   
      LCENTR = Z(ICENTR(1))
C
C     LOOP OVER THE DATA SETS WE ARE FITTING TO ( MAY BE ONLY ONE ).
C
      DO 789  IOFFIT = 1, IESETS
C
      LEHED = LEKEY + LENKEY+1
      LLNKBL = FACFR4*Z(ILNKBL)-FACFR4 + 3*NUMLNK*(IOFFIT-1) - 3
      LADATA = LEHED + LENHED
      LLEPRM = LEPARM + IESIZE*(IOFFIT-1)                                5170   
C
C     GET ALL THE CHANNEL PARAMETERS
C
      ELAB = ALLOC4(LEHED+4)
      IZP = ILLOC(LEHED+5)
      IZT = ILLOC(LEHED+6)
      AMP = ALLOC4(LEHED+7)
      AMT = ALLOC4(LEHED+8)
      LSKIP = ILLOC(LEHED+22)
      RATMAS = ALLOC4(LEHED+24)                                          5180   
      LLMIN = ILLOC(FACFR4*LLEPRM+1)
      LLMAX = ILLOC(FACFR4*LLEPRM+2)
      NSTPSS(1) = ILLOC(FACFR4*LLEPRM+3)
CDC      LLEPRM = LLEPRM + 2
      RSTEPS(1) = ALLOC(LLEPRM+3)
      ETAS(1) = ALLOC(LLEPRM+4)
      AKS(1) = ALLOC(LLEPRM+5)
      E = ALLOC(LLEPRM+6)
      R0MASS = ALLOC(LLEPRM+7)
      RCP = ALLOC(LLEPRM+8)                                              5190   
      RCT = ALLOC(LLEPRM+9)
      ES(1) = E
      HS(1) = AKS(1)*RSTEPS(1)
C
      DO 69  I = 1, NUMLNK
         DO 69  II = 1, 3
            LNKADR(3+II,I) = ILLOC(LLNKBL+3*I+II)
 69   CONTINUE
C
C     GENERATE THE POTENTIAL ARRAYS FOR WAVELJ                           5200   
C
      CALL SETFIT ( XS, IRET, 1 )
C
C     DID SETFIT DETECT AN OUT-OF-BOUNDS STEP
C
      IF ( IRET .LE. 0 )  GO TO 900
C
C     GET DATA DESCRIPTORS AND OVERALL WEIGHT, RENORMALIZATION AND
C     AND ANGLE SHIFT
C                                                                        5210   
C
C     WE USE
C
C     RENORM - RENORMALIZATION FACTOR FOR DATA
C               ( DATA VALUE = RENORM*INPUT )
C     ASHIFT - LAB ANGLE SHIFT
C
C     POLARIZATION DATA 0  ( NOT ACTUALLY USED YET )
C
CCCC      IPOL = ILLOC(LEKEY+3)                                          5220   
C
      LENDAT = ILLOC(LEKEY+5)
C
      NPTSE=ILLOC(LEHED)
      WEIGHT =ALLOC4(LEHED+1)
      WT = DSQRT(WEIGHT)
      RENORM=ALLOC4(LEHED+2)
      ASHIFT = ALLOC4(LEHED+3)
C
      mychar = BLANK                                                     5230   
      IF ( ASHIFT .NE. 0  .OR.  RENORM .NE. 1 )  mychar = STAR
C
      LSIG = LSIGMA + (IOFFIT-1)*(LOMOST+1)
      LSC = LSCSIG + (IOFFIT-1)*(LOMOST+1)*2
C
C     FOR INITIAL AND FINAL FUNCITON REFS, PRINT STUFF
C
      IF ( ITEMP .NE. 2 )  CALL PRTCHI ( WEIGHT, ASHIFT,
     1   ILLOC(LEHED+9), RENORM )
C                                                                        5240   
C     SETUP POTENTIAL GRADIENT ARRAY
C
      IF (GRADSW)  CALL MAKDER ( NSTPSS(1)+1, NUMVS, MAXVS, MPARA,
     1  XS, DERIVS, ALLOC(LVDERV), illoc(ldvtyp+1), ALLOC(Z(IRLVS(1))),
     2  ALLOC(Z(IIMVS(1))), ALLOC(LWAVR), ALLOC(LWAVI) )
C
C     COMPUTE ALL S-MATRICES AND THEIR GRADIENTS
C
      T1 = second()
C                                                                        5250   
      DO 100 LL = LLMIN, LLMAX, LSKIP
C
C  FOR NOW NO SPIN ORBIT -- ONLY ONE JVALUE
C
         CALL WAVELJ(LL, 0, ICHANW, 0, DUMMY4, DUMMY4, DUMMY4,
     1      ALLOC(LWAVR), ALLOC(LWAVI), ALLOC(LVREAL), ALLOC(LVIMAG),
     2      ALLOC(LCENTR) )
C
         IF (GRADSW)  CALL SDERIV ( NFIRST, NSTPSS(1)+1, NUMVS, MAXVS,
     1     MPARA, ALLOC(LWAVR), ALLOC(LWAVI), ALPHAR, ALPHAI,            5260   
     2     ALLOC(LVDERV), illoc(ldvtyp+1), ALLOC(LSDELS),
     3     ALLOC(LDSDP+(2*MPARA)*LL) )
C
100   CONTINUE
C
C     SDERIV HAS FOUND ONLY THE ANALYTIC DERIVATIVES
C     IF THERE ARE SOME NUMERIC ONES TO BE DONE; WE PERTURB
C     THINGS AND DO THEM NOW.
C
      IF ( .NOT. GRADSW )  GO TO 150                                     5270   
      II = 0
      DO 149  NX = 1, MPARA
         IF ( ILLOC(LDVTYP+NX) .LT. 4 )  GO TO 149
         II = 1
         PSAVE = XS(NX)
         DEL = FITACC*PSAVE
         IF ( PSAVE .EQ. 0 )  DEL = FITACC
         XS(NX) = PSAVE+DEL
         CALL SETFIT ( XS, IRET, 1 )
         DO 139  LL = LLMIN, LLMAX, LSKIP                                5280   
            S1 = ALLOC(LSMAT+2*LL)
            S2 = ALLOC(LSMAT+2*LL+1)
            CALL WAVELJ ( LL, 0, ICHANW, 0, DUMMY4, DUMMY4, DUMMY4,
     1        ALLOC(LWAVR), ALLOC(LWAVI), ALLOC(LVREAL), ALLOC(LVIMAG),
     2        ALLOC(LCENTR) )
            ALLOC(LDSDP+2*NX+(2*MPARA)*LL-2) =
     1         (ALLOC(LSMAT+2*LL) - S1)/DEL
            ALLOC(LDSDP+2*NX+(2*MPARA)*LL-1) =
     1         (ALLOC(LSMAT+2*LL+1) - S2)/DEL
            ALLOC(LSMAT+2*LL) = S1                                       5290   
            ALLOC(LSMAT+2*LL+1) = S2
 139     CONTINUE
         XS(NX) = PSAVE
 149  CONTINUE
      IF ( II .EQ. 1 )  CALL SETFIT ( XS, IRET, 0 )
C
 150  TIMES(6) = TIMES(6) + second()-T1
C
C  GET CROSS SECTIONS
C                                                                        5300   
      IF ( ITEMP .NE. 2 )  write (6, 153) mychar, mychar
 153  FORMAT( '0', 8X, 'ANGLE', A1, T25,
     1    'EXPERIMENT', A1, T44, 'FIT',
     2    T61, 'FIT', T75, 'EXP ERROR', T89, '(FIT-EXP)/ERROR', T109,
     3    '%/L AT LMAX' /
     4  9X, 'C.M.', T25, 'SIGMA/RUTH', T41,
     5    'SIGMA/RUTH', T60, '(M.B.)', T79, '%', T91, '(UNWEIGHTED)' / )
      CHISQR=0
      SUM1=0
      SUM2=0                                                             5310   
      SUM3=0
C
C     DO ALL ANGLES AT THIS ELAB
C
      DO 589 IANG=1,NPTSE
C
C     GET THE DATA.  IT HAS BEEN STORED IN THE STANDARD FORM OF
C       C.M. ANGLE,  C.M. SIGMA (MB),  % ERROR
C
C     WE USE                                                             5320   
C
C     ANGL - C.M. ANGLE IN DEGREES
C     ANGLE - C.M. ANGLE IN RADIANS
C             (BOTH OF ABOVE ARE MODIFIED BY LAB ANGLE SHIFT)
C     ERR - ERROR IN PERCENT
C     ERROR - WILL BE SET TO ERROR IN M.B. (INCLUDES EFFECT OF BOTH
C             LAB ANGLE SHIFT AND RENORM.)
C     SIGMA - EXP. CROSS SEC IN M.B. (WILL BE MODIFIED BY LAB ANGLE
C             SHIFT BUT NOT BY RENORM.)
C     RSIGMA - RENORMALIZED EXP. CROSS SEC. IN M.B. (WILL INCLUDE        5330   
C             BOTH LAB ANGLE SHIFT AND RENORM.)
C     CROSS - FITTED VALUE OF SIGMA (M.B.).
C     RUTH - RUTHERFORD CROSS SECTION IN M.B.
C
C
      ANGL=ALLOC4(LADATA)
      ANGLE=ANGL*DEGREE
      ERR=ALLOC4(LADATA+1)
      SIGMA=ALLOC4(LADATA+2)
C                                                                        5340   
C     IF WE ARE MAKING AN ANGLE SHIFT IN THE LAB, DO IT NOW
C
      IF ( ASHIFT .EQ. 0 )  GO TO 250
C
C     FIRST GET OLD JACOBIAN AND LAB ANGLE
C
      TEMP = 1 + RATMAS*( RATMAS + 2*DCOS(ANGLE) )
      RATJAC = (1+RATMAS*DCOS(ANGLE)) / (TEMP*DSQRT(TEMP))
      BACKSW = DCOS(ANGLE) .LT. -1/RATMAS
      ANGLE = DATAN2( DSIN(ANGLE), DCOS(ANGLE)+RATMAS )                  5350   
C
C     NOW SHIFT IN LAB AND CONVERT BACK TO C.M.  ALSO GET NEW JACOBIAN
C
      ANGLE = ANGLE + ASHIFT*DEGREE
      TEMP = 1 - (RATMAS*DSIN(ANGLE))**2
      IF ( TEMP .LT. 0 )  TEMP = 0
      TEMP = SQRT(TEMP)
      IF ( BACKSW )  TEMP = -TEMP
      ANGL = DCOS(ANGLE)*TEMP - RATMAS*DSIN(ANGLE)**2
      ANGLE = ACOS(ANGL)                                                 5360   
      TEMP = 1 + RATMAS*(RATMAS+2*ANGL)
      RATJAC = (1+RATMAS*ANGL)/(RATJAC * TEMP*DSQRT(TEMP))
      ANGL = ANGLE*RADIAN
C
C     COMPUTE TRANSFORMED CROSS SECTION
C
      SIGMA = SIGMA*RATJAC
C
C     GET PREDICTED CROSS SECTION AND GRADIENT
C                                                                        5370   
 250  CALL CALANG ( GRADSW, LLMIN, LLMAX, LSKIP, MPARA,
     1  ANGLE,
     2  ALLOC(LPL), ALLOC(LSIG), ALLOC(LDFDX),
     3  ALLOC(LSC), ALLOC(LSMAT), ALLOC(LDSDP),
     4  FR, FI, RUTH, HIGHR, HIGHI )
C
C
C  CROSS SECTIONS IN MILLI BARNS
C
      CROSS= 10.0D0 * (FR*FR + FI*FI)                                    5380   
      RSIGMA = RENORM*SIGMA
C
C     CONVERT % ERRORS TO MB
C
      ERROR = .010D0*ERR*RSIGMA
C
C     COMPUTE DEVIATION
C
      RATJAC = (CROSS-RSIGMA)/ERROR
      FS(ICNTPT+IANG) = WT*RATJAC                                        5390   
      CHISQ = CHISQ + (WT*RATJAC)**2
C
C     COMPUTE GRADIANT IF NEEDED
C
      IF ( .NOT. GRADSW )  GO TO 450
      RAT = 20*WT/ERROR
      DO 439  I = 1, MPARA
         KEY = ILLOC(LMASK+I-1)
         IF ( KEY .LT. 0 )  GO TO 410
         TEMP = RAT*( FR*ALLOC(LDFDX+2*I-2)                              5400   
     1     + FI*ALLOC(LDFDX+2*I-1) )
         GO TO 435
C
C     THE PARAMETER IS A RENORMALIZATION OR ANGLE SHIFT -
C     IT MAY NOT EFFECT THIS DATA SET.
C
 410     TEMP = 0
         ISET = MOD( -KEY/10000, 100 )
         ITYPE = -KEY/100 0000
         IF ( ISET .EQ. IOFFIT )  GO TO 425                              5410   
         INDEX = LEQUAL
 415     IMANY = ILLOC(INDEX)
         IF ( IMANY .EQ. 0 )  GO TO 435
         IF ( ILLOC(INDEX+1) .EQ. KEY )  GO TO 420
         INDEX = INDEX + IMANY+2
         GO TO 415
 420     DO 424  IM = 1, IMANY
            IF ( MOD( -ILLOC(INDEX+1+IM)/10000, 100 ) .EQ. IOFFIT )
     1         GO TO 425
 424     CONTINUE                                                        5420   
         GO TO 435
C
C     IT DOES EFFECT THIS GUY.
C    WE CAN COMPUTE THE GRADIENT ONLY FOR RENORMALIZATION
C
 425     IF ( ITYPE .EQ. 0 )  TEMP = -WT*CROSS/(ERROR*RENORM)
C
C     STORE GRADIENT OF F AND COMPUTE GRADIENT OF CHI SQUARE
C
 435     FGRAD(ICNTPT+IANG,I) = TEMP                                     5430   
         TGRAD(I) = TGRAD(I) + 2*TEMP*(WT*RATJAC)
 439  CONTINUE
C
 450  IF(ITEMP.EQ.2)GO TO 580
C
C     WE PRINT SIGMA/RUTH
C
      RSIGMA = RSIGMA/RUTH
      RCROSS = CROSS/RUTH
      PERCEN=(1.0D0-(HIGHR*HIGHR+HIGHI*HIGHI)*10.0D0/CROSS) * 50         5440   
      WRITE(6,501)ANGL,RSIGMA,RCROSS,CROSS,ERR,RATJAC,PERCEN
501   FORMAT ( F15.4, 2X, 5G17.4, F14.2 )
      CHISQR=CHISQR+RATJAC**2
      ERR=ERROR*ERROR
      SUM1=SUM1+CROSS*SIGMA/ERR
      SUM2=SUM2+SIGMA*SIGMA/ERR
      SUM3=SUM3+CROSS*CROSS/ERR
C
C     ADVANCE TO NEXT ANGLE
C                                                                        5450   
 580  LADATA = LADATA + LENDAT
C
589   CONTINUE
C
C     END OF THE LOOP OVER ANGLES FOR THIS ELAB
C
      IF(ITEMP.EQ.2)GO TO 780
C
C     PRINT A SUMMARY OF THIS DATA SET
C                                                                        5460   
      IF ( mychar .EQ. STAR )  write (6, 623) ASHIFT, RENORM
 623  FORMAT ( '0* INCLUDES LAB-ANGLE SHIFT OF', F7.3,
     1  ' DEGREES AND RENORMALIZATION OF', F7.4 )
      THISCN = WEIGHT * CHISQR/NPTST
      CHISQR=CHISQR/NPTSE
      WCHISQ = WEIGHT*CHISQR
C
C     ROPT IS A FACTOR TO SCALE THE DATA TO THE FIT:
C       BEST DATA = ROPT * DATA
C       BEST FIT  = FIT / ROPT                                           5470   
C
      ROPT=SUM1/SUM2
      FOPT = (ROPT*ROPT*SUM2-2*ROPT*SUM1+SUM3)/NPTSE
      WRITE(6,633)  NPTSE, RENORM, CHISQR, WCHISQ, ROPT,FOPT
 633  FORMAT ( '0', I5, ' POINTS' /
     1  ' RENORMALIZATION =', F8.4, '  GIVES UNWEIGHTED CHI.SQR./PT. =',
     2      G12.4, 5X, 'WEIGHTED CHI.SQR./PT. =', G12.4 /
     3  ' OPTIMUM RENORMALIZATION =', G12.4,
     4      5X, 'OPTIMUM UNWEIGHTED CHI.SQR./PT. =', G12.4 )
      IF ( IESETS .GT. 1 )  write (6, 643) THISCN                        5480   
 643  FORMAT ( ' CONTRIBUTION OF THIS DATASET TO TOTAL CHI SQ/PT =',
     1  G12.4 )
C
C     END OF THIS ELAB, GO TO THE NEXT ONE
C
 780  ICNTPT=ICNTPT+NPTSE
      LEKEY = LADATA-1
 789  CONTINUE
C
C     THE FUNCTION VALUE IS THE CHI-SQ SUM.                              5490   
C
      CALFUN = CHISQ
      CHISQ = CHISQ/NPTST
C
      IF ( PRNTSW )  write (6, 803) CHISQ
 803  FORMAT ( ' CALFUN OUTPUT =', G20.10 )
C
      IF(ITEMP.EQ.2  )GO TO 950
C
      CHISQR = CALFUN/(NPTST-MPARA)                                      5500   
      WRITE(6,813)  MPARA, NPTST, CHISQ, CHISQR
 813  FORMAT ( '0', I3, ' PARAMETERS,',
     1  I5, ' POINTS,    TOTAL CHI.SQR./PT. =', G12.4,
     1  5X, 'TOTAL CHI.SQR./DEG.FREEDOM =', G12.4 // )
      GO TO 950
C
C     ATTEMPTED TO STEP OUT OF BOUNDS
C
 900  CALFUN = 0
      DO 959  I = 1, NPTST                                               5510   
         FS(NPTST) = 1.D+10
         CALFUN = CALFUN + 1.D+20
 959  CONTINUE
C
C     COMPUTE TOTAL FUNCTION OR FUNCTION & GRADIENT TIME
C
 950  T0 = second() - T0
      IF ( .NOT. GRADSW )  TIMES(4) = TIMES(4) + T0
      IF ( GRADSW )  TIMES(5) = TIMES(5) + T0
CDC      CALFN2 = CALFUN                                                 5520   
      RETURN
C
CDC      END
CDC      FUNCTION CALFUN ( NPTST, MPARA, FS, XS )
CDC      IMPLICIT
CDC      ALLOCLEVEL FS,XS
CDC      DIMENSION FS(1), XS(1)
CDC      CALFUN = CALFN2 ( NPTST, MPARA, FS, XS, A, B )
CDC      RETURN
CDC      END                                                             5530   
CDC      FUNCTION CALGRA ( NPTST, MPARA, FS, XS, FT, TG )
CDC      IMPLICIT
CDC      DIMENSION FS(1), XS(1), FT(1), TG(1)
CDC      ALLOCLEVEL FS, XS, FT, TG
CDC      CALGRA = CALGR2( NPTST, MPARA, FS, XS, FT, TG )
CDC      RETURN
C
      END
C*ID* CCDUMP   C109.PTOLEMY.SOURCE                          PER701  14:
      SUBROUTINE CCDUMP                                                  5540   
C
C     PRINTS THE VARIOUS COUPLED CHANNEL ARRAYS
C
C     9/16/80 - FIRST VERSION - S.P.
C     12/10/80 - ADD K QUANTUM NUMBER - S.P.
C     10/17/81 - MORE DIGITS FOR IPT PRINTOUT - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      COMMON /CCBLK/  ICHNDF, ICHNCP, ITRANS, IBASDF, IBASCP,           /ccblk/
     &    ICCBLK(2), IORDX, MCHNVL, ICHNVL,
     &    IHOMOA, IHOMOB, IINHR8, IINHI8
 
      CHARACTER*1  REACT, HEADER                                        /hedcom/
      COMMON /HEDCOM/  REACT(45), HEADER(65)
 
C
C
      IF ( ICHNDF .EQ. 0 )  GO TO 900
C
      LCHNDF = FACFR4*(Z(ICHNDF)-1) + 1
      NCHNDF = ILLOC(LCHNDF)
      MCHNDF = ILLOC(LCHNDF+1)
      LCHNDF = LCHNDF + ILLOC(LCHNDF+2)
C                                                                        5560   
      write (6, 103) HEADER, REACT, NCHNDF, MCHNDF
 103  FORMAT ( '1', 65A1, 20X, 45A1 /
     1  '0CHANNEL DEFINITION ARRAY:', I5, ' CHANNELS,',
     2    I5, ' ELEMENTS PER CHANNEL.' /
     3  '0  N  NAME   JT    KT    ET     JP    KP    EP',
     4    T54, 'ETA', T63, 'K', T70, 'BASIS',
     5    T78,  'SMAT  NS', T91, 'POINTERS' /
     6  T69,   'PNT NUM', T77, '  PNT PLI', T87, 'INDX TOCS',
     7    ' SMAT LIMOST' / )
 108  FORMAT ( 2I5, 2( 2( I4, '/2' ), F7.3 ), F9.2, F8.2, I6, I4, I6,    5570   
     1   I4, 2I5, 1X, 6I5 )
C
      MCHN = MCHNDF-1
      DO 159  NCHN = 1, NCHNDF
         L = LCHNDF + (NCHN-1)*MCHNDF
         write (6, 108) NCHN, ILLOC(L), ILLOC(L+1), ILLOC(L+15),
     1      ALLOC4(L+2), ILLOC(L+3), ILLOC(L+16),
     2      (ALLOC4(L+I), I=4, 6), (ILLOC(L+I), I=7,MCHN)
 159  CONTINUE
C                                                                        5580   
      IF ( IBASDF .EQ. 0 )  RETURN
      LBASDF = FACFR4*(Z(IBASDF)-1) + 1
      NBASDF = ILLOC(LBASDF)
      MBASDF = ILLOC(LBASDF+1)
      LBASDF = LBASDF + ILLOC(LBASDF+2)
C
      write (6, 203) NBASDF, MBASDF
 203  FORMAT ( '-' / '-BASIS DEFINITION ARRAY:', I5,
     1    ' BASIS STATES,', I5, ' ELEMENTS PER STATE.' /
     2  '0  N  CHAN   S    L-J', T24, 'BASIS COUP',                      5590   
     3      T36, 'WAVE' /
     4  T25, 'PTR  NUM', T36, 'STRT' )
 208  FORMAT ( 2I5, I4, '/2', I4, '/2', 2I5, 2X, I5, 1X, 5I5 )
C
      LAST = -987654
      MBAS = MBASDF-1
      DO 259  NBAS = 1, NBASDF
         L = LBASDF + (NBAS-1)*MBASDF
         IF ( ILLOC(L) .EQ. LAST )  GO TO 240
         LAST = ILLOC(L)                                                 5600   
         write (6, 213)
 213     FORMAT ( ' ' )
 240     write (6, 208) NBAS, ILLOC(L), (ILLOC(L+I), I=1, MBAS)
 259  CONTINUE
C
      LBASCP = FACFR4*(Z(IBASCP)-1) + 1
      NBASCP = ILLOC(LBASCP)
      MBASCP = ILLOC(LBASCP+1)
      LBASCP = LBASCP + ILLOC(LBASCP+2)
C                                                                        5610   
      write (6, 303) NBASCP, MBASCP
 303  FORMAT ( '-' / '-BASIS COUPLING ARRAY:', I6,
     1  ' COUPLINGS,', I5, ' ELEMENTS PER COUPLINGS.' /
     2  '0  N1-N2  ORD MULT', T26, 'COUP. CONS.',
     3      T44, 'IFAC', 5X, 'IPT', T60, 'POINTERS' /
     4  T23, 'NUCLEAR', T34, 'COULOMB', T58, 'BFAC',
     5      T64, 'NUC', T68, 'COUL' )
 308  FORMAT ( I5, '-', I3, I4, I3, '/2', G13.4, G12.4,
     2  I4, I8, 3I5, 1X, 4I5 )
C                                                                        5620   
      LAST = -987654
      MBAS = MBASCP-1
      DO 359  NBAS = 1, NBASCP
         L = LBASCP + (NBAS-1)*MBASCP
         IF ( ILLOC(L) .EQ. LAST )  GO TO 340
         LAST = ILLOC(L)
         write (6, 213)
 340     write (6, 308) ILLOC(L), (ILLOC(L+I),I=1,3),
     1      ALLOC4(L+4), ALLOC4(L+5),
     2      ( ILLOC(L+I), I=6, MBAS )                                    5630   
 359  CONTINUE
C
      RETURN
C
 900  write (6, 903)
 903  FORMAT ('0*** NO ARRAYS TO DUMP' )
      RETURN
      END
C*ID* CCHAN    C109.PTOLEMY.SOURCE                          PER701  11:
      SUBROUTINE CCHAN(IRET)                                             5640   
C
C    INPUT ROUTINE FOR CHANNEL SPECIFICATION
C    STRUCTURE OF DATA IN ALLOCATOR
C    PREFACE
C     LDATA4 +0 #BLOCKS
C            +1 LENGTH OF BLOCK
C            +2 LENGTH OF PREFACE
C    LABEL  +0 NUMERICAL NAME FORCHANNEL
C           +1 TARGET LEVEL SPIN AND PARITY       2*PARITY*J
C           +2 TARGET LEVEL ENERGY                                       5650   
C           +3 PROJECTILE LEVEL SPIN AND PARITY   2*PARITY*J
C           +4 PROJECTILE LEVEL ENERGY
C           +5 CHANNEL ETA VALUE              SET BY BASLBL
C           +6 CHANNEL MOMENTUM VALUE         SET BY BASLBL
C           +7 POINTER FOR BASIS STATES       SET BY BASLBL
C           +8 DEGENERACY OF BASIS STATES     SET BY BASLBL
C           +9  POINTER TO S-MATRICES         SET BY ANGSET
C           +10 NSPLI FOR THIS CHANNEL        SET BY ANGSET
C           +11 POINTER TO S-MATRICES INDXS   SET BY ANGSET
C           +12 POINTER TO S-MATRICES TOCS    SET BY ANGSET              5660   
C           +13 KSMAT                         SET BY LINTRP
C           +14 LIMOST                        SET BY LINTRP
C           +15 KT QUANTUM NUMBER OF ROTATIONAL MODEL
C           +16 2*KP
C
C           +5-+8 CALCULATED IN BASLBL(IRET)
C
C     12/1/79 - FIRST VERSION - MRB
C     1/15/80 - STORE ADDRESS IN CCBLK - S.P.
C     6/24/80 - PUT BACK WORDS 14&15 -- THIS WAS LOST - S.P.             5670   
C     9/26/80 - SET +5 THROUGH +14 TO NOTDEF - S.P.
C     12/10/80 - K QUANTUM NUMBER - S.P.
C     5/6/85 - USE CHARACTER*8 - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      parameter ( ibufsize = 200 )                                      /inpbuf/
      CHARACTER*1 IBUF(ibufsize)
      COMMON /INPBUF/ NOCH, INCH, IBUF
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      COMMON /CCBLK/  ICHNDF, ICHNCP, ITRANS, IBASDF, IBASCP,           /ccblk/
     &    ICCBLK(2), IORDX, MCHNVL, ICHNVL,
     &    IHOMOA, IHOMOB, IINHR8, IINHI8
 
C                                                                        5680   
      character*1 PLUS/'+'/,MINUS/'-'/
      character*1 ipm
C
      DATA NUMKEY /7/
      CHARACTER*8 KEYS(7) /'NAME','JT','ET','JP','EP',
     1  'KT', 'KP' /
      CHARACTER*8  AKEY
C
      DATA LENDAT /17/,  LEKEY /3/,  LAL/5/
      CHARACTER*8 NAME8/'CHANNELS'/, ANAMES                              5690   
      COMMON/NAMCOM/ANAMES(1)
      INTEGER GIVEAL
C
c
C
C
      ICD3I=0
      IRET=0
      INAME=0
      IJT=0                                                              5700   
      IET=0
      IJP=0
      IEP=0
      IKP = 0
      IKT = 0
      ICH=0
      I=NAMLOC(NAME8)
      IF(I.NE.0)Z(I)=-Z(I)
      ICHNDF=GIVEAL(IWRDS)
      LDATA=Z(ICHNDF)                                                    5710   
      ANAMES(ICHNDF)=NAME8
      LDATA4=FACFR4*(LDATA-1)+1
      ILLOC(LDATA4+1)=LENDAT
      ILLOC(LDATA4+2)=LAL
      ILLOC(LDATA4+3)=0
      ILLOC(LDATA4+4)=0
      LABEL=LDATA4+LAL
      CALL FITKEY(AKEY,*90,*900,*900,*900)
      GO TO 900
C                                                                        5720   
C     FIRST GET THE KEYWORDS AND ORDER OF SPIN
C
C    ( ENCOUNTERED LETS GO
 90   IORDER=0
 100  CALL NXWORD(AKEY,*699,*900,*900)
      DO 110 I=1,NUMKEY
      IF(KEYS(I).NE.AKEY)GO TO 110
      GO TO (200,250,300,350,400,410,420 ),I
 110  CONTINUE
      GO TO 900                                                          5730   
 200  IORDER=IORDER+1
      INAME=IORDER
      IF(INAME.NE.1)GO TO 930
      GO TO 100
 250  IORDER=IORDER+1
      IJT=IORDER
      GO TO 100
 300  IORDER=IORDER+1
      IET=IORDER
      GO TO 100                                                          5740   
 350  IORDER=IORDER+1
      IJP=IORDER
      GO TO 100
 400  IORDER=IORDER+1
      IEP=IORDER
      GO TO 100
 410  IORDER = IORDER+1
      IKT = IORDER
      GO TO 100
 420  IORDER = IORDER+1                                                  5750   
      IKP = IORDER
      GO TO 100
 699  IF(IORDER.LT.LEKEY)GO TO 940
      LABEL=LABEL-LENDAT
C
C     ADVANCE TO TAHE NEXT CHANNEL
C
 700  LABEL=LABEL+LENDAT
      ILLOC(LABEL+1)=0
      ILLOC(LABEL+3)=0                                                   5760   
      ALLOC4(LABEL+2)=0.0
      ALLOC4(LABEL+4)=0.0
      ALLOC4(LABEL+5) = UNDEF4
      ALLOC4(LABEL+6) = UNDEF4
      DO 709 I = 8, LENDAT
         ILLOC(LABEL+I-1) = NOTDEF
 709  CONTINUE
C
C     KT AND KP ARE ZERO BY DEFAULT
C                                                                        5770   
      ILLOC(LABEL+15) = 0
      ILLOC(LABEL+16) = 0
      DO 799 I=1,IORDER
      IF(I.EQ.INAME)GO TO 720
      IF(I.EQ.IJT)GO TO 730
      IF(I.EQ.IJP)GO TO 740
      IF ( I .EQ. IKT )  GO TO 750
      IF ( I .EQ. IKP )  GO TO 760
      CALL NXVALF(TEMP,*910,*910,*910,*910)
      IF(I.EQ.IET)ALLOC4(LABEL+2)=TEMP                                   5780   
      IF(I.EQ.IEP)ALLOC4(LABEL+4)=TEMP
      GO TO 799
 720  CALL NXINT(INT,*910,*910,*800)
      ILLOC(LABEL)=INT
      GO TO 799
 730  CALL NXHINT(INT,*910,*910,*910)
      IPM=IBUF(INCH-1)
      IF(IPM.EQ.PLUS)ILLOC(LABEL+1)=INT
      IF(IPM.EQ.MINUS)ILLOC(LABEL+1)=-INT
      GO TO 799                                                          5790   
 740  CALL NXHINT(INT,*910,*910,*910)
      IPM=IBUF(INCH-1)
      IF(IPM.EQ.PLUS)ILLOC(LABEL+3)=INT
      IF(IPM.EQ.MINUS)ILLOC(LABEL+3)=-INT
      GO TO 799
 750  CALL NXHINT ( ILLOC(LABEL+15), *910, *910, *910 )
      GO TO 799
 760  CALL NXHINT ( ILLOC(LABEL+16), *910, *910, *910 )
 799  CONTINUE
      ICH=ICH+1                                                          5800   
      GO TO 700
 800  CALL FITKEY(AKEY,*900,*900,*810,*900)
      GO TO 900
 810  ILLOC(LDATA4)=ICH
      IWRDS=(LABEL-LDATA4)/FACFR4+1
      IL=CHOPIT(IWRDS)
      IRET=1
      RETURN
C
900   WRITE(6,901)(KEYS(I),I=1,NUMKEY)                                   5810   
901   FORMAT ( '0****  CHANNEL DEFINITIONS NOT ENCLOSED IN',
     1      ' PARENTHESES OR A KEYWORD IS MISPELLED;',
     1' CHANNELS KEYWORDS ARE:' // ( 1X, 10A9 ) )
      RETURN
910   WRITE(6,911)I
911   FORMAT ( '0****  ERROR IN READING',I5,' NUMERICAL DATA ',
     1      'IN SET.' )
      RETURN
920   WRITE(6,921)LEKEY
921   FORMAT ( '0****  INPUT ERROR - NUMBER OF INPUT NUMBERS MUST BE',   5820   
     1     I5, '*N' )
      RETURN
930   WRITE(6,931)
931   FORMAT ( '0****  CHANNEL SPECIFICATION MUST BE FIRST KEYWORD')
      RETURN
 940  write (6, 943)
 943  FORMAT ( '0*** AT LEAST THREE KEYWORDS ARE REQUIRED.')
      RETURN
      END
C*ID* CCMTCH   C109.PTOLEMY.SOURCE                          PER701  17:  5830   
      SUBROUTINE CCMTCH ( ILI, J, IB, SMATS, CFAC, NBASDF,
     1  WAVR, WAVI, NPTSAV, HOMO, MBASDF, BASDEF,
     2  MBASCP, BASCUP, RBASCP, MCHNVL, CHNVAL,
     2  BFACS, MBNDX, BINDEX, FG, VSCALE )
C
C     EXTRACTS S-MATRIX ELEMENT AND HOMO C-FACTOR FROM C.C. SOLUTION
C
C     THE PARTICULAR SOLUTION IS IN WAVR AND WAVI.  IT IS EXPRESSED
C     INTERMS OF INCOMING AND OUTGOING WAVES AND THE HOMO
C     SOLUTION TO DETERMIN THE S-MATRIX AND CFAC:                        5840   
C
C       R'(IB) = 12*R(IB) --> (6I)*( IN(IB0,IB) -
C            SUM(IB') SQRT(K0/K') S(IB',0) OUT(IB',IB) )
C           = Z'(IB) + CFAC*(IB)
C
C     HERE IN AND OUT ARE THE COUPLED INCOMING AND OUTGOING
C     COULOMB SOLUTIONS.
C
C     NOTE THAT THE PARTICULAR SOLUTION IS 12*(CORRECT SOLUTION) AND WE
C     GENERATE  R' = 12*(CORRECT R).                                     5850   
C
C     ILI & J - THE LIS POINTER AND 2*TOTAL J.
C     IB - BASIS STATE TO BE SOLVED FOR.
C     SMATS (COMPLEX*16) - COMPLETE ARRAY OF S-MATRICES AS FOUND
C           SO FAR.  SMAT(IB) WILL BE UPDATED.
C           IT SHOULD BE INITIALIZED TO   S(HOMO), 0, 0, ... 0
C           AT THE BEGINNING OF THE ITERATIONS.
C     CFAC (COMPLEX*16) - WILL BE SET TO THE C-FACTOR
C     NBASDF - NUMBER OF BASIS STATES.
C     WAVR, WAVI - THE JUST COMPUTED Z'(IB) = 12*Z(IB)                   5860   
C     HOMO (COMPLEX*16) - THE TWO-DIMENSIONAL ARRAY OF HOMO SOLUTIONS .
C            AT THE TWO MATCHING POINTS.
C     MBASDF - LENGTH OF A BASIS STATE DEFINITION.
C     BASDEF - THE TWO-DIMENSIONAL PART OF THE BASIS STATE DEFS.
C     MBASCP - LENGTH OF A BASIS COUPLING ENTRY.
C     BASCUP, RBASCP - THE BASIS COUPLING ARRAY PAST THE HEADER.
C     MCHNVL, CHNVAL - THE LENGTH OF AND CHANNEL VALUES (K, ETA)
C     BFACS - THE BFACTORS AS RETURNED BY GETBFC
C     BINDEX - THE B-INDEX ARRAY (IBINDX)
C     FG - THE COULOMB FUNCS ARRAY  NFS(1)                               5870   
C
C     VSCALE - A FACTOR FOR THE ENTIRE COUPLING POTENTIAL
C     2/17/80 - FIRST VERSION - S.P.
C     3/9/80 - FIX UP USING REVERSED CHANNELS - S.P.
C     3/27/80 - FIX IT RIGHT THIS TIME - S.P.
C     4/27/80 - NPTSAV DIMENSION - S.P.
C     5/29/80 - CDC HAS 3 DIMS FOR FG, WAVR(1) - S.P.
C               PASS MBNDX FOR CDC COMPATABILITY.
C     10/26/81 - MULT BY ROOT 2 FOR SYMMETRIC CHANNELS - S.P.
C     3/15/82  TEMPORARY REAL8 VERSION                                   5880   
C     3/15/82 - ADD VSCALE
C     4/10/82 - BACK TO REAL*4 - S.P.
C     10/10/83 - HOMO ARRAY IS COMPLEX*16 WITH JUST 2 NEEDED POINTS;
C                CFAC IS COMPLEX*16 - S.P.
C     10/15/84 - REAL*8 F & G POSSIBILITY, CHNVAL - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
C
      COMPLEX*16  SMATS(NBASDF), CFAC
      COMPLEX*8  BFACS(2,1)                                              5890   
      COMPLEX*16   HOMO(2, NBASDF)
      REAL*8  WAVR(1), WAVI(1), CHNVAL(MCHNVL, 1)
      INTEGER  BASDEF(MBASDF, NBASDF),  BASCUP(MBASCP, 1)
      REAL*4  RBASCP(MBASCP,1)
      REAL*4  FG(2,2,NBASDF,1)                                          c4f
C8F      REAL*8  FG(2,2,NBASDF,1)                                       cnd
CDC      DIMENSION  FG(4, NBASDF, 1)
CDC%'FG(#,#,#,#)' = 'FG(2*#2-2+#1, #3, #4)'
      INTEGER BINDEX(MBNDX, 1)
C                                                                        5900   
C
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
      COMMON /GRIDCM/  RCUEFF, GRDCM1(2),                               /gridcmf
     &  IBINDX, MBINDX, NBINDX, NMFFAC, MXLXGS, NMBFAC,
     & IINHR, IINHI, IRHSR, IRHSI,
     &  INUCH, ICOULH, ILOR, ILOI, ILIR, ILII,
     &  NPTMIN, NOFLO, NUMPT, NCRIT,
     & ISMX, ISMSQ, IPADE, IHOMO,
     &  ISMTSV, IRPTS4, IRPTS,
     &  IGRDC4(5), IDW, IGRDC5(2),
     &  IABS1, IGRDC6(2), GRDCM2, IGRDC7(2), IRWTS,
     &  IGRDC8(2), ICL1FF, ICL1FG, ICL1GF, ICL1GG
 
C
      COMPLEX*16  S1(2), S2(2), S3(2), A(2,2), D(2), BFAC(2),
     1  OUTCOU(2), INCOU(2), FAC, FAC2, DET
      REAL*8  RBFAC(2,2)
      EQUIVALENCE  ( BFAC(1), RBFAC(1,1) )
C                                                                        5910   
C     MARK STORES -2, -1, 1, 2  TO MEAN  -I, -1, +1, +I (STRANGE)
C
      COMPLEX*16  ITOL(5) / (0.D0,-1.D0), (-1.D0,0.D0),
     1  (0.D0, 0.D0), (1.D0,0.D0), (0.D0,+1.D0) /
C
      DATA ROOT2 / 1.41421 35623 731 0D0 /
C
      LOGICAL PBUGSW
C
c                                                                        5920   
C
      PBUGSW = MOD(IPRINT,10) .GE. 8
C
      DO 29  I = 1, 2
         S1(I) = 0
         S2(I) = 0
         S3(I) = 1
C
C     FOLLOWING ARE 6I*INCOMING AND 6I*OUTGOING WAVES
C                                                                        5930   
         INCOU(I) = CMPLX( 6*FG(1,I,IB,ILI), 6*FG(2,I,IB,ILI) )
         OUTCOU(I) = CMPLX(-6*FG(1,I,IB,ILI), 6*FG(2,I,IB,ILI) )
 29   CONTINUE
C
      AK0 = CHNVAL(1,1)
      IC1 = BASDEF(1,IB)
      AK1 = CHNVAL(1,IC1)
      L1MJ = BASDEF(3,IB)
C
      IF ( NOBFAC .EQ. 1 )  GO TO 300                                    5940   
C
C     COMPUTE THE BFACTOR CONTRIBUTIONS
C
      ICPST = BASDEF(4,IB)
      ICPEND = ICPST + BASDEF(5,IB) - 1
C
C     LOOP OVER ALL COUPLED STATES LOOKING FOR THOSE WITH B-FACTORS
C
      DO 289  ICUP = ICPST, ICPEND
C                                                                        5950   
         IBNDX = BASCUP(9,ICUP)
         IF ( IBNDX .EQ. 0 )  GO TO 289
         IBP = BASCUP(2,ICUP)
         L2MJ = BASDEF(3,IBP)
         IF ( J .LT. -L2MJ )  GO TO 289
C
C     HERE ARE THE ANGULAR-MOMENTUM COUPLING TERMS AND THE
C     I**(L2-L1) OR WHATEVER
C
         FAC = RBASCP(6,ICUP)*RBASCP(8,ICUP)*ITOL(BASCUP(7,ICUP)+3)      5960   
         FAC = VSCALE*FAC
C
C     COMPUTE SUBSCRIPT TO B-FACTOR ARRAY
C
         LL1MJ = L1MJ
         LL2MJ = L2MJ
         ASSIGN 185 TO IGOTO
         IF ( IBNDX .GT. 0 )  GO TO 150
         LL1MJ = L2MJ
         LL2MJ = L1MJ                                                    5970   
         IBNDX = -IBNDX
         ASSIGN 180 TO IGOTO
 150     LX = BINDEX(1,IBNDX)
 
!  The following ishft fails sometimes in gfortran and
!  returns a large negative number
!!!         Iii1 = iSHFT( (LX+1)*(LL1MJ-BINDEX(6,IBNDX))+LL2MJ-LL1MJ,
!!!     1     -1 )  + LX
         Iii1 = ( (LX+1)*(LL1MJ-BINDEX(6,IBNDX))+LL2MJ-LL1MJ )/2 + lx
         I = iSHFT(Iii1, -1) + BINDEX(8,IBNDX)                           5980   
C
C     PICK UP THE TWO BFACTORS AND IF NECESSARY ADJUST SIGN
C     OF THE REAL PART FOR REVERSED CHANNELS.
C
         DO 189  II = 1, 2
            BFAC(II) = BFACS(II,I)
            GO TO IGOTO, ( 180, 185 )
 180        RBFAC(1,II) = -RBFAC(1,II)
 185        BFAC(II)=FAC*BFAC(II)
 189     CONTINUE                                                        5990   
C
         IF ( IBP .EQ. IB )  GO TO 250
C
C     THIS IS NOT DIAGONAL COUPLING
C
         ICP = BASDEF(1,IBP)
         FAC2 = SQRT(AK0/CHNVAL(1,ICP)) * SMATS(IBP)
         IF ( BASDEF(7,IBP) .EQ. 2 )  FAC2 = FAC2/ROOT2
         S2(1) = S2(1) + FAC2*BFAC(1)
         S2(2) = S2(2) + FAC2*BFAC(2)                                    6000   
C
C     IF THIS IS THE G.S. COUPLED TO IB, THEN NEED AN INCOMING
C     TERM ALSO.
C
         IF ( ICP .NE. 1 )  GO TO 289
         IF(btest(LX, 0))GO TO 240
         S1(1) = S1(1) + BFAC(1)
         S1(2) = S1(2) + BFAC(2)
         GO TO 289
240      S1(1)=S1(1)-BFAC(1)                                             6010   
         S1(2)=S1(2)-BFAC(2)
         GO TO 289
C
C     DIAGONAL COUPLING IS SUMMED IN S3
C
 250     S3(1) = S3(1) + BFAC(1)
         S3(2) = S3(2) + BFAC(2)
C
 289  CONTINUE
C                                                                        6020   
C     NOW SOME OVERALL FACTORS FOR THE B-FACTOR STUFF
C
      DO 299  I = 1, 2
         S1(I) = -CONJG(S1(I)) * INCOU(I)
         S2(I) = S2(I)*OUTCOU(I)
 299  CONTINUE
C
      IF ( PBUGSW )  write (6, 293) S1, S2, S3
 293  FORMAT ( ' B-CONTRIBS:', ( T15, 4( G15.5, G13.5 ) ) )
C     NOW CONSTRUCT THE COEFICENTS IN THE 2X2 EQUATIONS.                 6030   
C
 300  N = NUMPT-NBACK
      DO 329  I = 1, 2
         A(I,1) = -SQRT(AK0/AK1) * S3(I)*OUTCOU(I)
         A(I,2) = -HOMO(I,IB)
         D(I) = CMPLX( WAVR(N), WAVI(N) ) + S1(I)+S2(I)
         IF ( IC1 .EQ. 1 )  D(I) = D(I) - INCOU(I)
         N = NUMPT
 329  CONTINUE
C                                                                        6040   
      DET = 1/( A(1,1)*A(2,2) - A(1,2)*A(2,1) )
C
      IF ( PBUGSW )  write (6, 353) A, D, DET
 353  FORMAT ( ' MATCH:', ( T15, 4( G15.5, G13.5 ) ) )
C
      SMATS(IB) = ( D(1)*A(2,2) - D(2)*A(1,2) )*DET
      CFAC = ( D(2)*A(1,1) - D(1)*A(2,1) )*DET
C
      IF ( BASDEF(7,IB) .EQ. 2 )  SMATS(IB) = ROOT2*SMATS(IB)
C                                                                        6050   
      RETURN
      END
C*ID* CCONV    C109.PTOLEMY.SOURCE                          PER701  16:
      SUBROUTINE CCONV ( CSMATS, ITR, ITEST, NBASDF, PADE,
     1  MAXIT1, ELAST, EXR, EXI, INDXS, CHNDEF, MCHNDF,
     1  BASDEF, MBASDF, IJ, NCHNDF, JT, NLINE, IHEAD, NFLOP )
C
C     CHECK CONVERGENCE OF S-MATRIX ELEMENTS AND USE WYNN ALGORITHUM
C
C     FIRST VERSION 26/2/80 MRB                                          6060   
C     6/22/81 - USE COMPLEX ARITHMATIC, FIX CONVERG CHECK - S.P.
C     10/13/81 - CONTROL PRINTINT FOR PRINT=0 - S.P.
C     8/9/84 - CHECK ONLY PADE TABLE FOR CONVERGENCE - S.P.
C     10/17/84 - REMOVE /0 PROTECTION; FIX CONVERG PRINTOUT;
C                STOP IF OVERFLOW IS IMMENENT - S.P.
C
C     THE WYNN ALGORITHUM HAS THE SAME EFFECT ON A BRAIN AS  VALLIUM
C
C     CSMATS IS A NUM.BASIS.STATES X 2  COMPLEX
C            ARRAY.  THE FIRST COLUMN IS THE LATEST ADDITION TO IT.      6070   
C            THE SECOND COLUMN IS THE PREVIOUS ITERATION
C     PADE IS A 3 X (MAXITR+1)/2 X NUM.BASIS.STATES  COMPLEX ARRAY OF
C            THE LAST THREE DIAGONALS AND OFF-DIAGONALS OF THE
C            WYNN ALGORITHYM.
C
      IMPLICIT  COMPLEX*16 (C),  REAL*8 (A, B, D-H, O-Z)
C
      COMPLEX*16  CSMATS(NBASDF, *)
      COMPLEX*16  PADE(3, MAXIT1, NBASDF)
CXP      COMPLEX*32  PADE(3, MAXIT1, NBASDF)                             6080   
      REAL*8 ELAST(*),EXR(*),EXI(*)
      INTEGER*4 INDXS(1), CHNDEF(MCHNDF,1),  BASDEF(MBASDF,1)
CXP      COMPLEX*32 CW1, CW2, CW3, CW4, CW5
C
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      CHARACTER*1  REACT, HEADER                                        /hedcom/
      COMMON /HEDCOM/  REACT(45), HEADER(65)
 
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
C                                                                        6090   
      LOGICAL PRSW, ITRSW
      CHARACTER*1 BLANK /' '/
C
      QWIKAB(CA) = ABS(REAL(CA)) + ABS(IMAG(CA))
C
      nflop = 0
      PRSW = MOD(IPRINT, 10) .GT. 0
      ITRSW = MOD(IPRINT, 10) .GE. 3
      NADD = 1
      IF ( PRSW )  NADD = NBASDF                                         6100   
C
      ITEST = 0
      II2 = 0
      IF ( ITR .LT. 3 )  GO TO 700
C
C     USE PADE TABLE TO ACCELERATE CONVERGENCE
C     WE USE WYNN ALGORITHUM
C     ONLY LOWER HALF TABLE CONSTRUCTED
C     WE COMPARE DIAGONAL ELEMENTS FOR ODD ITERATION
C     WE COMPARE OFF DIAGONAL WITH PREVIOUS DIAGONAL FOR EVEN            6110   
C
 100  ITR1=(ITR-1)/2
      ITR1P1 = ITR1+1
      DO 199 I=1,NBASDF
         PADE(3,1,I) = CSMATS(I,1)
         IF ( QWIKAB(CSMATS(I,1)) .GT. 1.E-10*BIGEST )  ITEST = 2
         DO 189 J=1,ITR1
            CW1 = PADE(2,J,I)
            CW2 = PADE(1,J,I)-CW1
            CW3 = PADE(3,J,I)                                            6120   
            IF ( QWIKAB(CW3) .EQ. 0 )  GO TO 170
            CW3 = CW3-CW1
            CW4 = 0
            IF ( J .EQ. 1)GO TO 150
            CW4 = PADE(1,J-1,I)-CW1
            CW4 = 1/CW4
 150        CW5 = 1/CW2 + 1/CW3 - CW4
            CW5 = 1/CW5
CCC            CW4 = 1/(CW4+0.D-60)
CCC 150        CW5 = 1/(CW2+0.D-60) + 1/(CW3+0.D-60) - CW4               6130   
CCC            CW5 = 1/(CW5+0.D-60)
            CW3 = CW5+CW1
 170        PADE(3,J+1,I) = CW3
 189     CONTINUE
 199  CONTINUE
C
      NFLOP = (12*ITR1 + 1)*NBASDF
C
      DD1 = 0
      IF ( ITR .LE. 3 )  GO TO 700                                       6140   
C
C     CHECK FOR CONVERGENCE OF PADE S-MATRIX
C
      DO 459  ICHAN = 1, NCHNDF
         D1 = 0
         D2 = 0
         I1 = CHNDEF(8,ICHAN)
         II2 = CHNDEF(9,ICHAN) + I1-1
         DO 449 I3 = I1, II2
            CS1 = PADE(3,ITR1P1,I3)                                      6150   
            CS2 = PADE(2,ITR1P1,I3)
            IF ( btest(ITR, 0) )  CS2 = PADE(1,ITR1,I3)
            SMOD = QWIKAB(CS1)
            IF ( SMOD .EQ. 0 )  GO TO 449
            D2 = DMAX1( D2, SMOD )
            CS1MS2 = CS1-CS2
            DIFMOD = QWIKAB(CS1MS2)
            IF ( CONVRG .EQ. 2 )  DIFMOD = DIFMOD/SMOD
            D1 = DMAX1( D1, DIFMOD )
 449     CONTINUE                                                        6160   
         IF ( CONVRG .EQ. 0 )  D1 = D1/D2
         DD1 = MAX( DD1, D1 )
         IF ( D1 .LE. ACCURA )  GO TO 459
         IF ( ITR .LT. MAXITR .AND. .NOT. ITRSW )  GO TO 700
 459  CONTINUE
      IF ( DD1 .LT. ACCURA )  ITEST = 1
C
C
C
 700  IF ( ITEST .EQ. 0  .AND.  ( .NOT. ITRSW )                          6170   
     1    .AND.  ITR .LT. MAXITR )  GO TO 950
      IF ( IHEAD .EQ. 1 )  GO TO 720
      IF ( NLINE+NADD+3 .LE. 59 )  GO TO 750
      write (6, 713) REACT, ELAB, HEADER
 713  FORMAT ( '1', T60, 'P T O L E M Y' /
     1  1X, 'COMPUTATION OF COUPLED INELASTIC CHANNELS S-MATRICES',
     2     T95, 'WIN A FEW, LOOSE A FEW' /
     3  '0', 45A1, 'ELAB =', F7.2, ' MEV', 5X, 65A1 / )
      NLINE = 5
 720  write (6, 723)                                                     6180   
 723  FORMAT ( '0', 'CHANNEL', 1X, 'SOUT', 1X, 'LOUT',
     1    T27, 'S-MATRIX(ITER)', T51, 'S-MATRIX(PADE)',
     2    T72, '|S(PADE)|', T95,  'RELATIVE DIFFERENCES' /
     3  T88, 'PADE-ITER', T100, 'ITER CONVRG.', T114, 'PADE CONVRG.' )
      NLINE = NLINE+3
      IHEAD = 2
C
 750  write (6, 753) JT, ITR, DD1, (BLANK, I=1,ITEST)
 753  FORMAT ( '0J =', I5, ',', I5, ' ITERATIONS',
     1    5X, 'CONVERGENCE =', G9.2, 2A1, 'STOPPING FOR OVERFLOW' )      6190   
C
C     STORE CONVERGED S-MATRIX ELEMENTS, PRINT CONVERGENCE
C
      DO 899  ICHAN = 1, NCHNDF
      NAME = CHNDEF(1,ICHAN)
      I1 = CHNDEF(8,ICHAN)
      I2 = CHNDEF(9,ICHAN) + I1-1
      IPOINT = CHNDEF(10,ICHAN)
      NSPLI = CHNDEF(11,ICHAN)
      IPINDX = CHNDEF(12,ICHAN)                                          6200   
      DO 889 I3 = I1, I2
         CS2 = CSMATS(I3,1)
         CS1 = CS2
         IF ( ITR .GE. 3 )  CS1 = PADE(3,ITR1P1,I3)
         CS3 = 0
         IF ( ITR .GE. 2  .OR.  I3 .EQ. 1 )  CS3 = CSMATS(I3,2)
         JOUT = BASDEF(2,I3)/2
         I4 = JOUT+1
         LOUT = BASDEF(3,I3)/2
         SMOD = QWIKAB(CS1)+1.D-30                                       6210   
         D2 = 0
         SITMOD = QWIKAB(CS2) + 1.D-30
         D1 = QWIKAB(CS3-CS2) / SITMOD
         IF ( ITR .LE. 3 )  GO TO 840
         CS4 = PADE(2,ITR1P1,I3)
         IF ( btest(ITR, 0) )  CS4 = PADE(1,ITR1,I3)
         D2 = QWIKAB(CS4-CS1) / SMOD
 840     D3 = QWIKAB(CS1-CS2)/SMOD
         SMOD = ABS(CS1)
C                                                                        6220   
         IF(I3.EQ.1)GO TO 850
         KBASE=INDXS(3*I4-1+IPINDX)
         LDELMN=INDXS(3*I4+IPINDX)
         KOFFS=KBASE+(LOUT-LDELMN)/2
         LABEL=(IJ-1)*NSPLI+IPOINT+KOFFS+1
         EXR(LABEL) = DREAL(CS1)
         EXI(LABEL) = DIMAG(CS1)
         GO TO 860
 850     ELAST(1) = DREAL(CS1)
         ELAST(2) = DIMAG(CS1)                                           6230   
 860     LOUT=LOUT+JT
         IF ( LOUT .LT. IABS(JT-JOUT) )  GO TO 889
         IF ( ICHAN .NE. 1  .AND.  .NOT. PRSW )  GO TO 889
         NLINE = NLINE+1
cccc         IF ( SITMOD .GT. 100 )  GO TO 875
         IF ( SITMOD .GT. 10 )  GO TO 875
         write (6, 873)  NAME, JOUT,LOUT, CS2, CS1, SMOD, D3, D1, D2
 873     FORMAT ( 1X, I5, 2I6, 2X, 2( F12.6, '+', F9.6, 'I' ),
     1         G16.5, 3G14.3 )
         GO TO 889                                                       6240   
 875     write (6, 878)  NAME, JOUT,LOUT, CS2, CS1, SMOD, D3, D1, D2
 878     FORMAT ( 1X, I5, 2I6, 1X, G12.4,     G11.4, 'I',
     1         F12.6, '+', F9.6, 'I',
     1         G16.5, 3G14.3 )
 889  CONTINUE
 899  CONTINUE
      NLINE = NLINE+3
C
      IF ( ITR .LT. MAXITR  .OR.  ITEST .EQ. 1 )  GO TO 950
      write (6, 913) JT, ACCURA                                          6250   
 913  FORMAT ( '0*** ERROR - FOR J =', I5,
     1  ', S-MATRICES NOT CONVERGED TO SPECIFIED ACCURACY OF', G12.3 )
      NLINE = NLINE+2
C
C     NOW DEFINE PREVIOUS ITERATION FOR NEXT ITERATION
C
 950  DO 959  I = 1, NBASDF
         CSMATS(I,2) = CSMATS(I,1)
 959  CONTINUE
      NFLOP = NFLOP + 7*II2                                              6260   
      IF ( ITR .GE. 3 )  GO TO 970
      DO 969  I = 1, NBASDF
         PADE(ITR,1,I) = CSMATS(I,1)
 969  CONTINUE
      RETURN
C
C     STORE PADE APPROXIMANTS FOR NEXT ITERATION
C
 970  DO 979 I=1,NBASDF
      DO 974 J=1,ITR1P1                                                  6270   
         PADE(1,J,I) = PADE(2,J,I)
         PADE(2,J,I) = PADE(3,J,I)
 974  CONTINUE
979   CONTINUE
      RETURN
      END
C*ID* CCOUP    C109.PTOLEMY.SOURCE                          PER701  09:
      SUBROUTINE CCOUP(IRET)
C
C     INPUT ROUTINE FOR CHANNEL COUPLING SPECIFICATION                   6280   
C
C     STRUCTURE OF DATA IN ALLOCATOR
C     PREFACE
C     LDATA4+0 TOTAL NO OF COUPLING SCHEMES
C      +1 LENGTH OF BLOCK   (17)
C      +2 LENGTH OF PREFACE (3)
C     DATA
C     LABEL  +0 CHANNEL COUPLED TO CHANNEL IN LABEL +1
C     +1 CHANNEL COUPLED TO CHANNEL IN LABEL +0
C     +2 ORDER OF TAYLOR EX. IN COUPLING POT(MAX=2)                      6290   
C     +3 TYPE OF COUPLING I.E. UPDOWN=1
C                              UPONLY=2
C     +4,5 MULTIPOLE
C     +6,7 BELX
C     +8,9 BETAN
C     +10 NUCLEUS BEING COUPLED IE P(+1) T(+2) PT(+3)
C     +11,+12 - METHOD USED TO SPECIFY BETA COULOMB:
C           0 - BETAC
C           1 - DELTAC (DEFORMATION LENGTH)  (FM)
C           2 - R.ME. OF ALPHA                                           6300   
C           3 - TOTAL LX (FOR 2ND ORDER RME)
C           4 - HALFLIFE  (SEC)
C           5 - MEANLIFE   (SEC)
C           6 - BE(DOWN)  (E**2 BARN**LX)
C           7 - REDUCED MATRIX ELEMENT OF M(E LX) (BOHR & MOTTELSON)
C                   (E BARN**LX/2)
C               THIS IS <J2,K2|| E(LX) ||J1,K1>  FOR E2 > E1.
C           8 - BE(UP, WEISSKOPF UNITS WITH R0=1.2)
C           9 - BE(DOWN, WEISSKOPF UNITS WITH R0=1.2)
C          10 - BE(UP)  (E**2 BARN**LX)                                  6310   
C          11 - Q (QUADRUPOLE MOMENT)    (E BARN)
C          12 - WIDTH IN MEV
C     +13 - USE INDICATOR.  SET TO ZERO HERE.
C     +14 - MODEL   1 = ROTATIONAL MODEL
C                   2 = VIBRATIONAL MODEL
C                   3 = DEFORMED, 4 = HOTFUDGE  (SEE BELOW)
C                   5 = MODEL5  6 = MODEL6  7 = MODEL7
C     +15,+16 - METHOD USED TO SPECIFY BETA NUCLEAR
C          0 - BETAN
C          1 - DELTAN                                                    6320   
C          2 - R.M.E. OF ALPHA
C          3 - TOTAL LX FOR 2ND ORDER RME
C     +17,+18 - SCALE FACTORS FOR R.M.E. (DEFAULT=1)
C     +19 - TOTAL LX
C     +20 - MAXIMUM LX
C
C     IN THE HOTFUDGE MODEL, THE FORMFACTOR IS A WOODS SAXON
C     (NOT ITS DERIVATIVE) WITH RADIUS PARAMETER GIVEN BY
C     PARAM(I) AND DIFUSNESS PARAM(I+1).  HERE I IS ENTERED
C     AS BETAC; THERE IS NO COULOMB COUPLING IN HOTFUDGE.                6330   
C
C     LABEL +0 AND +1 COMPULSORY
C     IF ORDERMAX=2 NEED 2 MULTIPOLES/BETAN/BETAC AND NUCLEUS
C     ; DENOTES NO MORE DATA FOR GIVEN CHANNEL-DEFAULT ASSSUMED
C     IF ORDERMAX IS TO  BE SPECIFIED MUST BE SECOND INPUT KEYWORD
C     IF ORDERMAX=2 TWO MULTIPOLES REQUIRED ALWAYS
C     FOR SECOND ORDER COUPLING MUST USE NUCLEAS KEY
C
C     12/80 - FIRST VERSION - MRB
C     1/16/80 - STORE ADDRESS IN CCBLK - S.P.                            6340   
C     7/3/80 - FIX ORDER OF NXVALF RETURNS, ALLOW
C              SEMI-COLON AT END OF FULL SPECIFICATION - S.P.
C     7/16/80 - ALLOW SEMICOLON INPLACE OF NUCLEUS, ORDER KEYWORD
C     7/17/80 - CHARACTER*8 VARIABLES, IMPROVE ERROR MSGS - S.P.
C     9/21/80 - CHANGE IPT(+10) TO BE 1=P, 2=T - S.P.
C     10/1/80 - CONVERT TP TO PT; BETAC KEYWORDS; MASSIVE REWRITE - S.P.
C     12/8/80 - ALLOW DEFAULTS TO BE READ; WEISSKOPF UNITS - S.P.
C     1/6/81 - MODEL KEYWORD; DIFFERENT BETAN TYPES - S.P.
C     1/22/81 - FIX SUBTLE BLUNDER  - S.P.
C     1/25/81 - SCALE FACTORS ADDED, BETTER TP FLIPS - S.P.              6350   
C     6/28/81 - WIDTH KEYWORD - S.P.
C     8/25/81 - TOTALLX, MAXLX, DEFORMED KEYWORDS - S.P.
C     10/15/81 - ALLOC MULTIPOLARITY=0 - S.P.
C     7/24/84 - ADD HOTFUDGE MODEL - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      parameter ( ibufsize = 200 )                                      /inpbuf/
      CHARACTER*1 IBUF(ibufsize)
      COMMON /INPBUF/ NOCH, INCH, IBUF
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      COMMON /CCBLK/  ICHNDF, ICHNCP, ITRANS, IBASDF, IBASCP,           /ccblk/
     &    ICCBLK(2), IORDX, MCHNVL, ICHNVL,
     &    IHOMOA, IHOMOB, IINHR8, IINHI8
 
C
      DATA NUMKEY/16/
      CHARACTER*8 KEYS(16) / 'COUPLED', 'ORDER', 'ORDERMAX','TYPE',
     1   'MULTIPOL', 'LX', 'NUCLEUS', 'MODEL', 'SCALE', 'SCALEFAC',
     2   'TOTALLX', 'TOTALMUL', 'MAXLX', 'MAXIMUML', 'MAXMULTI',
     3   'MAXIMUMM' /
C
      DATA NMBCKY /21/
      CHARACTER*8  BCKEYS(21) / 'BETAC', 'BETACOUL',
     1  'DELTAC', 'DELTACOU', 'BE', 'BELX', 'BEUP',                      6370   
     2  'Q', 'QMOMENT', 'QUADRUPO', 'HALFLIFE', 'MEANLIFE',
     3   'BEDOWN', 'RMEC', 'RMECOULO', 'BEUPWU', 'BEDOWNWU',
     4   'RMECALPH', 'LX', 'TOTALLX', 'WIDTH' /
      INTEGER IBCKYS(21) / 0, 0,
     1  1, 1, 10, 10, 10,
     2  11, 11, 11, 4, 5,
     3   6, 7, 7, 8, 9,
     4   2, 3, 3, 12 /
C
      DATA NMBNKY /9/                                                    6380   
      CHARACTER*8  BNKEYS(9) / 'BETAN', 'BETANUCL',
     1   'DELTAN', 'DELTANUC', 'RMEN', 'RMENUCLE',
     2   'RMENALPH', 'LX', 'TOTALLX' /
      INTEGER  IBNKYS(9) / 0, 0,
     1   1, 1, 2, 2,
     3   2, 3, 3 /
C
      DATA LENDAT /21/,LAL/3/
      CHARACTER*8 NAME8/'CHANCOUP'/
      CHARACTER*8 ANAMES                                                 6390   
      COMMON/NAMCOM/ANAMES(1)
C
      DATA LISTN /4/
      CHARACTER*8 KEY1(4) /'UPDOWN','UPONLY','DIAGONAL','BORN'/
      INTEGER KEY1VL(4) / 1, 2, 1, 2 /
C
      DATA LISTN1/10/
      CHARACTER*8 KEY2(10) /'P','T','PT','TP', 'PP', 'TT',
     1  'PROJ', 'PROJECTI', 'TARG', 'TARGET' /
      INTEGER KEY2VL(10) / 1, 2, 3, 4, 1, 2, 1, 1, 2, 2 /                6400   
C
C
C     MODELS
C
      DATA  NUMMOD /7/
      CHARACTER*8  MODELS(7) / 'ROTATION', 'VIBRATIO', 'DEFORMED',
     1   'HOTFUDGE', 'MODEL5', 'MODEL6', 'MODEL7' /
C
      CHARACTER*8 AKEY
      LOGICAL SCNDSW                                                     6410   
C
      INTEGER GIVEAL
C
C     THE FOLLOWING ARE THE FIRST INDEX OF PAIRS THAT MUST BE
C     FLIPPED TO CONVERT TP TO PT.
C
      DATA NUMFLP /6/
      INTEGER IFLIPS(6) / 4, 6, 8, 11, 15, 17 /
C
C     ARRAYS FOR THE DEFAULT VALUES                                      6420   
C
      REAL*4  DFLTS(30)
      DIMENSION   IDFLTS(30)
      EQUIVALENCE ( DFLTS(1), IDFLTS(1) )
      CHARACTER*8  BLANK /' ' /, AKEY2, AKEY3
      LOGICAL  EQULSW
c
C
      IRET=0
      ICOP=0                                                             6430   
      IOR=0
      ITY=0
      IMUL=0
      IBC=0
      IBN=0
      INC=0
      ICH=0
      IMD = 0
      ISC = 0
      ITOTMU = 0                                                         6440   
      IMAXMU = 0
C
C     INITIALIZE THE DEFAULT VALUES.  MOST ARE NOT DEF
C
      DO 29  I = 1, 30
         iDFLTS(I) = notDEF
 29   CONTINUE
C
C     DEFINED DEFALTS:
C        ORDER=1,  TYPE=UPDOWN,  USE=0,  MODEL=ROTATIONAL,   SCALE=1     6450   
C
      IDFLTS(2) = 1
      IDFLTS(3) = 1
      IDFLTS(13) = 0
      IDFLTS(14) = 1
      DFLTS(17) = 1
      DFLTS(18) = 1
C
      I=NAMLOC(NAME8)
      IF ( I.NE.0)Z(I)=-Z(I)                                             6460   
      ICHNCP=GIVEAL(IWRDS)
      LDATA=Z(ICHNCP)
      ANAMES(ICHNCP)=NAME8
      LDATA4=FACFR4*(LDATA-1)+1
      ILLOC(LDATA4+2)=LAL
      LABEL=LDATA4+LAL
      CALL FITKEY(AKEY,*90,*900,*900,*900)
      GO TO 900
C
C     (ENCOUNTERED LETS GO                                               6470   
C     PROCESS KEYWORDS FIRST
C
 90   IORDER=0
      AKEY2 = BLANK
C
C     GET NEXT KEY WORD; MAY HAVE BEEN ALREAD READ
C
 100  AKEY = AKEY2
      IF ( AKEY2 .EQ. BLANK )
     1   CALL NXWORD(AKEY,*400,*900,*900)                                6480   
C
C     LOOK FOR POSSIBLE = SIGN AFTER THIS KEYWORD
C
      EQULSW = .FALSE.
      CALL FITKEY ( AKEY2, *900, *120, *900, *130 )
      GO TO 150
C
C     = FOUND OR FIRST DATA FIELD
C
 120  EQULSW = .TRUE.                                                    6490   
 130  AKEY2 = BLANK
C
C     IDENTIFY THE KEYWORD
C
 150  DO 159 I=1,NUMKEY
         IF ( KEYS(I).NE.AKEY ) GO TO 159
         GO TO ( 200, 210, 210, 220, 230, 230, 250, 260, 270, 270 ,
     1  280, 280, 290, 290, 290, 290 ), I
 159  CONTINUE
C                                                                        6500   
C     IS IT A DEFAULT COULOMB BETA SPECIFICATION
C
      DO 169  I = 1, NMBCKY
         IF ( AKEY .NE. BCKEYS(I) )  GO TO 169
         IDFLTS(11) = IBCKYS(I)
         IDFLTS(12) = IBCKYS(I)
         IORDER = IORDER+1
         IBC = IORDER
         IF ( .NOT. EQULSW )  GO TO 100
         CALL NXVAL ( DFLTS(6), *945, *945, *945 )                       6510   
         DFLTS(7) = DFLTS(6)
         GO TO 100
 169  CONTINUE
C
C     IS IT A DEFAULT NUCLEAR BETA
C
      DO 179  I = 1, NMBNKY
         IF ( AKEY .NE. BNKEYS(I) )  GO TO 179
         IDFLTS(15) = IBNKYS(I)
         IDFLTS(16) = IBNKYS(I)                                          6520   
         IORDER = IORDER+1
         IBN = IORDER
         IF ( .NOT. EQULSW )  GO TO 100
         CALL NXVAL ( DFLTS(8), *945, *945, *945 )
         DFLTS(9) = DFLTS(8)
         GO TO 100
 179  CONTINUE
C
      GO TO 900
C                                                                        6530   
C     COUPLED
C
 200  IORDER=IORDER+1
      ICOP=IORDER
      IF ( ICOP.NE.1 ) GO TO 930
      GO TO 100
C
C     ORDER
C
 210  IORDER=IORDER+1                                                    6540   
      IOR=IORDER
      IF ( IOR.NE.2 ) GO TO 940
      IF (EQULSW)  CALL NXINT ( IDFLTS(2), *945, *945, *945 )
      GO TO 100
C
C     TYPE
C
 220  IORDER=IORDER+1
      ITY=IORDER
      IF ( .NOT. EQULSW )  GO TO 100                                     6550   
      CALL NXWORD ( AKEY3, *945, *945, *945 )
      AKEY = AKEY3
      GO TO 472
 225  IDFLTS(3) = INT
      GO TO 100
C
C     MULTIPOLARITY
C
 230  IORDER=IORDER+1
      IMUL=IORDER                                                        6560   
      IF ( .NOT. EQULSW )  GO TO 100
      CALL NXHINT ( INT, *945, *945, *945 )
      IDFLTS(4) = INT
      IDFLTS(5) = INT
      GO TO 100
C
C     NUCLEUS
C
250   IORDER=IORDER+1
      INC=IORDER                                                         6570   
      IF ( .NOT. EQULSW )  GO TO 100
      CALL NXWORD ( AKEY3, *945, *945, *945 )
      AKEY = AKEY3
      GO TO 555
 255  IDFLTS(10) = INT
      GO TO 100
C
C     MODEL
C
260   IORDER=IORDER+1                                                    6580   
      IMD=IORDER
      IF ( .NOT. EQULSW )  GO TO 100
      CALL NXWORD ( AKEY3, *945, *945, *945 )
      AKEY = AKEY3
      GO TO 572
 265  IDFLTS(14) = INT
      GO TO 100
C
C     SCALE FACTOR
C                                                                        6590   
 270  IORDER = IORDER+1
      ISC = IORDER
      IF ( .NOT. EQULSW )  GO TO 100
      CALL NXVAL ( DFLTS(17), *945, *945, *945 )
      DFLTS(18) = DFLTS(17)
      GO TO 100
C
C     TOTALLX
C
 280  IORDER=IORDER+1                                                    6600   
      ITOTMU = IORDER
      IF ( .NOT. EQULSW )  GO TO 100
      CALL NXHINT ( INT, *945, *945, *945 )
      IDFLTS(19) = INT
      GO TO 100
C
C     MAXIMUMLX
C
 290  IORDER=IORDER+1
      IMAXMU = IORDER                                                    6610   
      IF ( .NOT. EQULSW )  GO TO 100
      CALL NXHINT ( INT, *945, *945, *945 )
      IDFLTS(20) = INT
      GO TO 100
C
C     DONE WITH KEYWORDS, GO ON TO DATA
C
 400  ILLOC(LDATA4+1)=LENDAT
      LABEL=LABEL-LENDAT
      EQULSW = .FALSE.                                                   6620   
C
C     GO TO NEXT BATCH OF DATA
C
 410  LABEL=LABEL+LENDAT
      II=1
 420  CALL NXINT ( INT,*910,*420,*800)
      ILLOC(LABEL)=INT
      I1=2
      II = 2
      CALL NXINT ( INT,*910,*910,*910)                                   6630   
      ILLOC(LABEL+1)=-INT
      IF ( INT .GT. 0 )  GO TO 915
      ICH=ICH+1
C
C     MOVE IN THE DEFAULTS
C
      DO 432  I = 2, 5
         ILLOC(LABEL+I) = IDFLTS(I)
 432  CONTINUE
      DO 434 I=6,9                                                       6640   
 434  ALLOC4(LABEL+I)=DFLTS(I)
      L = LENDAT - 1
      DO 436  I = 10, L
         ILLOC(LABEL+I) = IDFLTS(I)
 436  CONTINUE
      JORDER = ILLOC(LABEL+2)
      SCNDSW = JORDER .EQ. 2
C
C     PROCESS THE COUPLING ORDER IF SPECIFIED
C                                                                        6650   
      IF ( IOR.EQ.0 ) GO TO 440
      II=3
      I1=3
      CALL NXINT ( JORDER,*910, *410, *810 )
      ILLOC(LABEL+2)=JORDER
 440  IF ( JORDER .NE. 1  .AND.  JORDER .NE. 2 )  GO TO 925
      SCNDSW = JORDER .EQ. 2
      IF ( SCNDSW .AND.(IMUL.EQ.0) ) GO TO 950
      IF ( SCNDSW .AND.(INC.EQ.0) ) GO TO 980
C                                                                        6660   
C     PROCESS THE KEYWORDS AFTER ORDER.  THESE CAN BE IN ANY ORDER
C
      IF ( I1.GT.IORDER ) GO TO 410
 450     II = II+1
         IF ( I1 .EQ. IMUL ) GO TO 490
         IF ( I1 .EQ. IBC ) GO TO 500
         IF ( I1 .EQ. IBN ) GO TO 530
         IF ( I1 .EQ. INC ) GO TO 550
         IF ( I1 .EQ. IMD ) GO TO 570
         IF ( I1 .EQ. ITY )  GO TO 470                                   6670   
         IF ( I1 .EQ. ISC )  GO TO 580
         IF ( I1 .EQ. ITOTMU )  GO TO 590
         IF ( I1 .EQ. IMAXMU )  GO TO 600
C
         write (6, 453) I1
 453     FORMAT ( '0*** THE', I3, ' INPUT FIELD CANNOT BE',
     1      ' CLASSIFIED.  DID YOU SPECIFY THE SAME TYPE OF DATA',
     2      ' TWICE IN THE KEYWORD LIST?' )
         GO TO 908
C                                                                        6680   
C     COUPLING TYPE
C
 470     CALL NXWORD(AKEY,*960,*700,*810 )
 472     DO 479 J=1,LISTN
            IF ( KEY1(J).NE.AKEY ) GO TO 479
            INT = KEY1VL(J)
            IF ( EQULSW )  GO TO 225
            ILLOC(LABEL+3) = INT
            GO TO 689
 479     CONTINUE                                                        6690   
         GO TO 960
C
C     MULTIPOLARITY
C
 490     CALL NXHINT ( INT,*910, *700, *810 )
         ILLOC(LABEL+4)=INT
         IF ( INT .LT. 0 )  GO TO 935
         IF ( .NOT. SCNDSW ) GO TO 689
         II = II+1
         CALL NXHINT ( INT, *910,  *950, *950 )                          6700   
         ILLOC(LABEL+5)=INT
         IF ( INT .LT. 0 )  GO TO 935
         GO TO 689
C
C     BETA COULOMB
C
 500     DO 529  J = 1, JORDER
 505        CALL NXVAL ( TEMP, *510, *595, *805 )
            GO TO 525
C                                                                        6710   
C     CHECK FOR KEYWORD SPECIFYING OTHER METHOD FOR BETAC
C
 510        CALL NXWORD ( AKEY, *910, *595, *805 )
            DO 519  I2 = 1, NMBCKY
               IF ( AKEY .NE. BCKEYS(I2) )  GO TO 519
               ILLOC(LABEL+10+J) = IBCKYS(I2)
               GO TO 505
 519        CONTINUE
            write (6, 523) AKEY, BCKEYS
 523        FORMAT ( '0*** INVALID KEYWORD FOR SPECIFYING COULOMB',      6720   
     1         ' DEFORMATION: ', A8, ',  VALID KEYWORDS ARE:' /
     2         ( 6X, 10A10 ) )
            RETURN
 525        ALLOC4(LABEL+5+J) = TEMP
            II = II+1
 529     CONTINUE
         GO TO 689
C
C     NUCLEAR DEFORMATION OR BETA
C                                                                        6730   
 530     DO 549  J = 1, JORDER
 535        CALL NXVAL ( TEMP, *537, *595, *805 )
            GO TO 545
C
C     CHECK FOR KEYWORD SPECIFYING OTHER METHOD FOR BETAN
C
 537        CALL NXWORD ( AKEY, *910, *595, *805 )
            DO 539  I2 = 1, NMBNKY
               IF ( AKEY .NE. BNKEYS(I2) )  GO TO 539
               ILLOC(LABEL+14+J) = IBNKYS(I2)                            6740   
               GO TO 535
 539        CONTINUE
            write (6, 543) AKEY, BNKEYS
 543        FORMAT ( '0*** INVALID KEYWORD FOR SPECIFYING NUCLEAR',
     1         ' DEFORMATION: ', A8, ',  VALID KEYWORDS ARE:' /
     2         ( 6X, 10A10 ) )
            RETURN
 545        ALLOC4(LABEL+7+J) = TEMP
            II = II+1
 549     CONTINUE                                                        6750   
         GO TO 689
C
C     NUCLEUS
C
550      CALL NXWORD ( AKEY, *970,*700,*810 )
 555     DO 559 J=1,LISTN1
            IF ( KEY2(J).NE.AKEY)  GO TO 559
            INT = KEY2VL(J)
            IF ( EQULSW )  GO TO 255
            ILLOC(LABEL+10) = INT                                        6760   
            GO TO 689
559      CONTINUE
         GO TO 970
C
C     MODEL
C
 570     CALL NXWORD ( AKEY, *975, *700, *810 )
 572     DO 579  J = 1, NUMMOD
            IF ( AKEY .NE. MODELS(J) )  GO TO 579
            INT = J                                                      6770   
            IF ( EQULSW )  GO TO 265
            ILLOC(LABEL+14) = INT
            GO TO 689
 579     CONTINUE
         GO TO 975
C
C     SCALE FACTOR
C
 580     CALL NXVAL ( VAL, *910, *700, *810 )
         ALLOC4(LABEL+17) = VAL                                          6780   
         IF ( .NOT. SCNDSW )  GO TO 689
         II = II+1
         CALL NXVAL ( VAL, *910, *700, *810 )
         ALLOC4(LABEL+18) = VAL
         GO TO 689
C
C     TOTALLX
C
 590     CALL NXHINT ( INT,*910, *700, *810 )
         ILLOC(LABEL+19)=INT                                             6790   
         IF ( INT .LT. 0 )  GO TO 935
         GO TO 689
C
C     MAXIMUMLX
C
 600     CALL NXHINT ( INT,*910, *700, *810 )
         ILLOC(LABEL+20)=INT
         IF ( INT .LT. 0 )  GO TO 935
         GO TO 689
689   I1 = I1+1                                                          6800   
      IF ( I1 .LE. IORDER )  GO TO 450
         GO TO 700
C
C     ALL DATA FOR ONE COUPLING HAS BEEN READ.
C     MAKE SURE IT IS CONSISTANT
C
 595  IF ( J .NE. 1 )  GO TO 950
 700  IPT = ILLOC(LABEL+10)
      IF ( .NOT. SCNDSW )  GO TO 750
      IF ( IPT .EQ. NOTDEF )  GO TO 980                                  6810   
      IF ( ILLOC(LABEL+4) .EQ. NOTDEF )  GO TO 950
C
C     CONVERT TP TO PT INPUT
C
      IF ( IPT .NE. 4 )  GO TO 790
      DO 729  II = 1, NUMFLP
         I = IFLIPS(II)
         ITEMP = ILLOC(LABEL+I)
         ILLOC(LABEL+I) = ILLOC(LABEL+I+1)
         ILLOC(LABEL+I+1) = ITEMP                                        6820   
729   CONTINUE
      ILLOC(LABEL+10) = 3
      GO TO 790
C
C     FIRST ORDER CANNOT HAVE PT
C
 750  IF ( IPT .LE. 2  .OR.  IPT .EQ. NOTDEF )  GO TO 790
      write (6, 753)
 753  FORMAT ('0*** NUCLEUS SPECIFICATION OF PT OR TP',
     1  ' IS INVALID FOR FIRST ODER.' )                                  6830   
      RETURN
 790  IF ( I1 .LT. 0 )  GO TO 840
      GO TO 410
C
C     CHECK FOR ) TO STOP THE INPUT
C
 800  CALL FITKEY(AKEY,*920,*920,*850,*920)
      GO TO 920
 805  IF ( J .NE. 1 )  GO TO 950
 810  I1 = -1                                                            6840   
      CALL FITKEY ( AKEY, *920, *920, *700, *920 )
      GO TO 920
 840  LABEL = LABEL + LENDAT
 850  ILLOC(LDATA4)=ICH
      IWRDS=(LABEL-LDATA4)/FACFR4+1
      IL=CHOPIT(IWRDS)
      IRET=1
      RETURN
C
900   WRITE(6,901)  KEYS, BCKEYS, BNKEYS                                 6850   
901   FORMAT(' *** DATA NOT ENCLOSED IN PARENTHESIS OR KEYWORD',
     1   'MISPELLED.   DATA KEYWORDS ARE:' // ( 1X, 10A9 ) )
 905  write (6, 907) AKEY
 907  FORMAT ( '0*** THIS OR LAST KEYWORD READ IS: ', A8 )
 908  write (6, 909) ( IBUF(I), I = 1, INCH )
 909  FORMAT ( '0*** INPUT LINE UP TO ERROR IS:  ', 80A1 )
      RETURN
910   WRITE(6,911) II
911   FORMAT ( '0*** ERROR IN READING',I5,' DATA VALUE IN SET')
      GO TO 908                                                          6860   
 915  write (6, 918)
 918  FORMAT ( '0*** CHANNELS TO BE COUPLED MUST BE SPECIFIED',
     1  ' AS CH1-CH2.  YOU HAVE LEFT OUT THE "-".' )
      GO TO 908
 920  write (6, 923)
 923  FORMAT ( '0*** INVALID OR MISPLACED PUNCTUATION.' )
      GO TO 908
 925  write (6, 928) JORDER
 928  FORMAT ( '0*** INVALID ORDER OF COUPLING:', I12 )
      GO TO 908                                                          6870   
930   WRITE(6,931)
931   FORMAT ( '0*** COUPLED MUST BE FIRST KEYWORD')
      GO TO 905
 935  write (6, 938) INT
 938  FORMAT ( '0*** ILLEGAL MULTIPOLARITY:', I12 )
      GO TO 908
940   WRITE(6,941)
941   FORMAT ( '0*** IF USING ORDER MUST BE SECOND KEYWORD')
      GO TO 905
 945  write (6, 947)                                                     6880   
 947  FORMAT ( '0*** INCORRECTLY SPECIFIED DEFAULT VALUE.' )
      GO TO 905
950   WRITE(6,951)
951   FORMAT ( '0*** FOR SECOND ORDER COUPLING MUST DEFINE TWO ',
     1  'MULTIPOLES.' )
      GO TO 908
960   WRITE(6,961)(KEY1(I),I=1,LISTN)
961   FORMAT ( '0*** COUPLING TYPE MISPELLED OR MISPLACED.  ',
     1    'VALID KEYWORDS ARE:' // (1X,10A9 ) )
      GO TO 905                                                          6890   
970   WRITE(6,971)(KEY2(I),I=1,LISTN1)
971   FORMAT ( '0*** NUCLEUS KEYWORD MISPELLED OR MISPLACED.  ',
     1    'VALID KEYWORDS ARE:' // (1X,10A9))
      GO TO 905
 975  write (6, 978) (MODELS(I), I = 1, NUMMOD )
 978  FORMAT ( '0*** MODEL SPECIFICATION MISSPELLED OR',
     1  ' MISPLACED.  VALID MODELS ARE' // (1X, 10A9) )
      GO TO 905
980   WRITE(6,981)
981   FORMAT ( '0*** FOR SECOND ORDER COUPLING MUST USE NUCLEUS KEY')    6900   
      GO TO 905
      END
C*ID* CHANEL   C109.PTOLEMY.SOURCE                          PER701  22:
      SUBROUTINE CHANEL ( IRET )
C
C     SCANS A CHANNEL SPECIFICATION
C
C     FORMS ARE
C        N15 + 209BI(9/2- 1.3)     ( FOR SCATTERING )
C        P + 208PB = BI209(7/2 .9)    ( FOR BOUND STATES )               6910   
C        O16 = N15 + P                ( ALTERNATIVE B.S. )
C     NOTE THAT PROJECTILE ALWAYS COMES FIRST.
C
C
C     AND STORES  Z'S,  M'S,  J'S,  E*'S   OF
C     THE 2 OR 3 PARTILCES INTO THE COMMON BLOCKS.
C     FOR BOUNDSTATES THE TOTAL J AND BINDING ENERGY ARE ALSO STORED.
C
C     9/22/75 - BASED ON REACTN - S. PIEPER
C     4/24/77 - STORE E* IN EXSPT                                        6920   
C     9/24/77 - RECOGNIZE E*=0; ALLOW LATTER DEF OF MASS EXCESS
C     12/10/77 - FIX ERROR IN ABOVE TO DEFINE J FOR B.S.
C     5/6/79 - G.S. MASS EXCESS, PARITIES, L & NODES FROM LEVEL - S.P.
C     12/31/79 - STANDARD MORTRAN - RPG
C     1/14/80 - CHARDATAVALUE IS NUMERIC, " IN FORMAT 313 - RPG
C     1/25/80 - CHARACTER SYMBOL, ALPHA - RPG
C
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      DIMENSION AMPTS(2)                                                 6930   
      EQUIVALENCE ( AMPTS(1), AMP )
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      DIMENSION IZPTS(2)
      EQUIVALENCE ( IZPTS(1), IZP )
      parameter ( NUMJWORD = 12 )                                       /jblock/
      COMMON /JBLOCK/  J, JS(5),
     &  JP, JSP, JST,
     &  JPARM1, JPARM2, JPARM3
 
      INTEGER JSPTS(2)
      EQUIVALENCE ( JSPTS(1), JSP )
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      CHARACTER*1  REACT, HEADER                                        /hedcom/
      COMMON /HEDCOM/  REACT(45), HEADER(65)
 
      parameter ( ibufsize = 200 )                                      /inpbuf/
      CHARACTER*1 IBUF(ibufsize)
      COMMON /INPBUF/ NOCH, INCH, IBUF
 
C
      CHARACTER*8  GUY(3)
      CHARACTER*2  SYMBOL
      CHARACTER*4  ALPHA
      REAL*8  ESTARS(3), XCESES(3)
      INTEGER  NODVLS(3), LVALS(3), JVALS(3), IPARYS(3)
      CHARACTER*1  BLANK1 /' '/, mychar
C
      CHARACTER*16 NAMES(3) / 'PROJECTILE', 'TARGET', 'BOUND STATE' /    6950   
c
C
      IRET = 0
C
C     GET PAST ANY INITIAL DELIMITORS
C
 100  mychar =  IBUF(INCH)
      IF ( mychar .GE. 'A'  .AND.  mychar .LE. 'Z'  .or.
     &     mychar .GE. 'a'  .AND.  mychar .LE. 'z'  .or.
     1     mychar .GE. '0'  .AND.  mychar .LE. '9' )  GO TO 150          6960   
      INCH = INCH + 1
      IF ( INCH .LE. NOCH )  GO TO 100
      write (6, 123)
 123  FORMAT ( '0**** CHANNEL KEYWORD AND COMPLETE SPECIFICATION',
     1  ' MUST BE ON ONE LINE.' )
      RETURN
C
C     START OF SPECIFICATION FOUND.  BREAK IT INTO 2 OR 3 PIECES.
C
 150  INCHST = INCH                                                      6970   
      CALL CHNSCN ( GUY, ESTARS, NODVLS, LVALS, JVALS, IPARYS, IRTN )
      IF ( IRTN .LT. 0 )  RETURN
C
C     NOW GET THE A AND Z VALUES
C
      NUMSYM = IRTN
      DO 239  I = 1, NUMSYM
         CALL AZCODE ( GUY(I), IZ, IA, SYMBOL, IRTN )
         IF ( IRTN .EQ. 0 )  GO TO 230
         IF (IRTN .NE. -2)  write (6, 213) GUY(I)                        6980   
 213     FORMAT ( '0**** A SYMBOL HAS INCORRECT SYNTAX:  ',
     1       'SYMBOL = ', A8 )
         IF ( IRTN .EQ. -2 )  write (6, 217) GUY(I)
 217     FORMAT ( '0**** THE SYMBOL ', A6, ' IS NOT A KNOWN ELEMENT.' )
         RETURN
 230     IF ( I .EQ. 3 )  GO TO 250
         IZPTS(I) = IZ
         AMPTS(I) = IA
         NODEPT(I) = NODVLS(I)
         LSPCPT(I) = LVALS(I)                                            6990   
         JSPTS(I) = JVALS(I)
         EXSPT(I) = ESTARS(I)
         IF ( EXSPT(I) .EQ. UNDEF ) EXSPT(I) = 0
         PARIPT(I) = IPARYS(I)
 239  CONTINUE
      GO TO 300
C
 250  J = JVALS(3)
      PARITY = IPARYS(3)
      NODES = NODVLS(3)                                                  7000   
      L = LVALS(3)
      IAB = IA
      IZB = IZ
      IF ( IAB .EQ. AMPTS(1)+AMPTS(2)  .AND.  IZ .EQ. IZPTS(1)
     1  +IZPTS(2) )  GO TO 300
      write (6, 253) IZPTS, IZ, AMPTS, IA
 253  FORMAT ( '0**** BOUNDSTATE DOES NOT CONSERVE NUCLEON NUMBER',
     1  ' OR CHARGE:' /
     2  ' ZP, ZT, Z(BOUND) =', 3I8 /
     3  ' MP, MT, M(BOUND) =', 2F8.0, I8 )                               7010   
      RETURN
C
C     NOW GET GROUND STATE MASS EXCESS AND DETERMIN IF THE NUCLEII
C     EXIST.
C
 300  DO 359  I = 1, NUMSYM
         IF ( I .EQ. 3 )  then
            IA = IAB
            IZ = IZB
         else                                                            7020   
            IA = AMPTS(I)
            IZ = IZPTS(I)
         endif
         N = IA-IZ
         AMXCES = EXCESS( IZ, IA, IRTN )
         IF ( IRTN .EQ. 0 )  GO TO 330
         write (6, 313) IA, IZ, N
 313     FORMAT ( '0**** THE NUCLEUS WITH A =', I4, ',  Z =', I4,
     1         ',  N =', I4, '  IS NOT BOUND ',
     2          'ACCORDING TO PTOLEMY"S MASS TABLE.' )                   7030   
         GO TO 359
 330     XCESES(I) = AMXCES
         IF ( I .LE. 2 )  AMXGPT(I) = AMXCES
         IF ( I .LE. 2 )  XCESES(I) = XCESES(I) + EXSPT(I)
         IF ( I .EQ. 3  .AND.  ESTARS(3) .NE. UNDEF )
     1     XCESES(3) = XCESES(3) + ESTARS(3)
 359  CONTINUE
C
C     NOW GET J FOR EACH OF THE GROUND STATES
C                                                                        7040   
      DO 459  I = 1, NUMSYM
C
         IF ( I .EQ. 3 )  then
            IA = IAB
            IZ = IZB
            JJ = J
         ELSE
            IA = AMPTS(I)
            IZ = IZPTS(I)
            JJ = JSPTS(I)                                                7050   
         endif
         ESTAR = ESTARS(I)
C
C     IF E* HAS BEEN ENTERED THEN G.S. J IS MEANINGLESS
C
 410     IF ( ESTAR .GT. 1.D-5  .AND.  ESTAR .NE. UNDEF )  GO TO 459
         N = IA - IZ
         CALL GSINFO ( IZ, IA, JVAL, IPARIT, ALPHA, IRTN )
         IF ( IRTN .EQ. 0  .AND.  JVAL .NE. NOTDEF )  GO TO 430
C     NO ERROR IF J IS ALREADY DEFINED OR IS EXPLICITLY GIVEN            7060   
C     IN THE REACTION.
         IF ( JJ .NE. NOTDEF )  GO TO 459
C
C     DINEUTRON OR DIPROTON IS J = 0
C
         IF ( IA .NE. 2  .OR.  IZ .EQ. 1 )  GO TO 420
         JVAL = 0
         GO TO 450
 420     write (6, 423)  IA, IZ, N
 423     FORMAT ( '0**** WARNING:  THE GROUND STATE SPIN OF THE',        7070   
     1     ' NUCLEUS WITH A =', I4, ',  Z =', I4, ',  N =', I4,
     3     '  IS NOT KNOWN TO PTOLEMY.' )
         GO TO 459
C
C     IF J HAS BEEN DEFINED TO BE DIFFERENT FROM G.S. THEN NEED E*
C
 430     IF ( JJ .EQ. NOTDEF )  GO TO 450
         IF ( JJ .EQ. JVAL  .OR.  ESTAR .NE. UNDEF )  GO TO 459
         write (6, 433) NAMES(I), JVAL, JJ
 433     FORMAT ( '0**** WARNING:  GROUND STATE SPIN FOR ', A10,         7080   
     1     ' IS', I3, '/2.  YOU HAVE SPECIFIED J',
     2     ' =', I3, '/2, BUT HAVE NOT SPECIFIED E*' )
         GO TO 459
C
 450     IF ( I .NE. 3 )  GO TO 455
         J = JVAL
         IF ( IPARIT .NE. 0 )  PARITY = IPARIT
         GO TO 459
 455     JSPTS(I) = JVAL
         IF ( IPARIT .NE. 0 )  PARIPT(I) = IPARIT                        7090   
 459  CONTINUE
C
C     DEFINE BINDING ENERGY
C
      IF ( NUMSYM .EQ. 3 )
     1  E = XCESES(3) - XCESES(1) - XCESES(2)
C
C     IT WAS SUCCESFUL, COPY REACTION FOR HEADER
C
      DO 649  I = 1, 45                                                  7100   
         REACT(I) = BLANK1
 649  CONTINUE
      N = MIN0( 45, INCH-INCHST )
      DO 659  I = 1, N
         REACT(I) = IBUF(INCHST-1+I)
 659  CONTINUE
      IRET = 1
      RETURN
      END
C*ID* CHNSCN   C109.PTOLEMY.SOURCE                          PER701  15:  7110   
      SUBROUTINE CHNSCN ( GUY, ESTARS, NODVLS, LVALS, JVALS, IPARYS,
     1  IRTN )
C
C - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - -
C  SCANS AN INPUT LINE FOR CHANNEL SPECIFICATIONS
C
C  DESCRIPTION OF PARAMETERS:
C  GUY    R*8 A 3-COMPONENT ARRAY THAT WILL CONTAIN THE PARTICIPANTS
C  ESTARS R*8 WILL BE SET TO EXPLICITLY GIVEN EXCITED STATE E'S.
C  NODVLS I*4 WILL BE SET TO THE GIVEN NODE VALUE FROM A LEVEL           7120   
C             SPECIFICATION (2P3/2- MEANS NODVLS = 1).
C  LVALS  I*4 WILL BE SET TO THE L VALUES FROM LEVEL SPECS.
C  JVALS  I*4 WILL BE SET TO EXPLICITLY GIVEN J'S.
C  IPARYS I*4 WILL BE SET TO THE PARITIES
C  IRTN   I*4 AN ERROR RETURN CODE
C          > 0 = NUMBER OF FIELDS ( 2 OR 3 ) FOUND.  ALL O.K.
C        = -1 - SYNTAX ERROR
C
C     IF AN = IS CODED, THE SUM IS STORED IN THE 3RD ELEMENT.
C                                                                        7130   
C     IN THIS VERSION, THE INPUT LINE IS IN   /INPBUF/.
C     THIS VERSION DOES NOT RECOGNIZE  *'S  OR  &'S.
C
C     9/22/75 - BASED ON QVSCAN - S. PIEPER
C     10/13/75 - FIX END OF CHANNEL SPECIFICATION BUG.
C     8/25/76 - REMOVE FIELD
C     9/24/77 - ESTAR = UNDEF WHEN NOT ENTERED
C     6/23/78 - ALWASY SET ALL 3 ITEMS TO UNDEIFNED FOR CDC
C     5/6/79 - NODES, L-VALUES, PARITIES - S.P.
C     12/26/79 - STANDARD MORTRAN - RPG                                  7140   
C     1/30/80 - SEPARATE CVALU ARG TO MSCAN; ESTARS, VALU REAL - RPG
C     5/29/80 - SEPARATE '(' AND 1H( DATA STATEMENTS - S.P.
C
C - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - -
C
      IMPLICIT INTEGER*4 (A-Z)
C
      DIMENSION  NODVLS(3), LVALS(3), JVALS(3), IPARYS(3)
C
      REAL*8 UNDEF                                                       7150   
      COMMON /INTRNL/  UNDEF, NOTDEF
C
      parameter ( ibufsize = 200 )                                      /inpbuf/
      CHARACTER*1 IBUF(ibufsize)
      COMMON /INPBUF/ NOCH, INCH, IBUF
 
C
      CHARACTER*1  SLASH /'/'/,  PLUS /'+'/,  MINUS /'-'/, EQUAL / '=' /
      CHARACTER*8 GUY(3), BLANK8/' '/,  CVALU
      REAL*8  ESTARS(3), VALU, DUMVAL
      CHARACTER*1 STPCHR, BLANK/' '/,  COMMA /','/
      LOGICAL PREDSW, EREDSW
C                                                                        7160   
      CHARACTER*1 LEFTP
      DATA LEFTP / '(' /
C
c
C
      IRTN = 0
      INCHST = INCH
      PREDSW = .FALSE.
      EREDSW = .FALSE.
      DO 59  I = 1, 3                                                    7170   
         GUY(I) = BLANK8
         NODVLS(I) = NOTDEF
         LVALS(I) = NOTDEF
         IPARYS(I) = 0
         JVALS(I) = NOTDEF
         ESTARS(I) = UNDEF
  59  CONTINUE
C
C --- LOOP ON THE REACTION PARTICIPANTS
      I = 1                                                              7180   
 100  CONTINUE
C
      CALL MSCAN ( -20, ITOKEN, GUY(I), DUMVAL, IVALU, IBUF, IMESS,
     1   STPCHR )
      IF ( IMESS .GT. 5 )  GO TO 9004
      IF ( IMESS .EQ. 0 )  GO TO 9005
         INCH = INCH+1
C
C
C     IF STOPPED BY A  (  PROCESS EXCITED STATE                          7190   
C     STATE.
C
      IF ( STPCHR .NE. LEFTP )  GO TO 400
C
C     GET E* AND J
C
 200  CALL MSCAN ( 18, ITOKEN, CVALU, VALU, IVALU, IBUF, IMESS, STPCHR )
      IF ( ITOKEN .EQ. -9)  GO TO 9900
      IF ( ITOKEN .EQ. -8 )  GO TO 9007
      IF ( ITOKEN .NE. -2 )  GO TO 230                                   7200   
C
C     IT IS E*
C
      IF ( ESTARS(I) .EQ. UNDEF )  GO TO 220
      write (6, 213)
 213  FORMAT ( '0**** ATTEMPTING TO ENTER 2 VALUES FOR E*' )
      GO TO 9900
 220  ESTARS(I) = VALU
      GO TO 200
C                                                                        7210   
 230  IF ( ITOKEN .NE. -5 )  GO TO 270
C
C     IT IS J
C
      IF ( JVALS(I) .EQ. NOTDEF )  GO TO 240
      write (6, 233)
 233  FORMAT ( '0**** ATTEMPTING TO ENTER 2 VALUES FOR J' )
      GO TO 9900
 240  JVALS(I) = 2*IVALU
      IF ( STPCHR .NE. SLASH )  GO TO 250                                7220   
C
C     BYPASS /2
C
      INCH = INCH+1
      JVALS(I) = IVALU
C
C     IT IS NECESSARY TO CODE THE 2 FOLLOWING THE /
C     MAKE SURE IT IS JUST A SIMPLE 2
C
      CALL MSCAN ( 18, ITOKEN, CVALU, VALU, IVALU, IBUF, IMESS, STPCHR ) 7230   
      IF ( ITOKEN .EQ. -9 )  GO TO 9900
      IF ( ITOKEN .EQ. -8 )  GO TO 9007
      IF ( ITOKEN .EQ. -5  .AND. IVALU .EQ. 2 )  GO TO 250
      write (6, 243)
 243  FORMAT ( '0**** INVALID J FIELD' )
      GO TO 9900
C
C     PARITY MAY BE GIVEN BY TERMINAL + OR -
C
 250  IP = +1                                                            7240   
      IF ( STPCHR .EQ. PLUS )  GO TO 255
      IP = -1
      IF ( STPCHR .NE. MINUS )  GO TO 200
 255  IPARYS(I) = IP
      INCH = INCH+1
      GO TO 200
C
 270  IF ( ITOKEN .NE. -3 )  GO TO 280
C
C     IT IS A NODES AND L PART OF A LEVEL DESCRIPTOR                     7250   
C
      IF ( LVALS(I) .EQ. NOTDEF )  GO TO 275
      write (6, 273)
 273  FORMAT ( '0**** ATTEMPTING TO ENTER TWO LEVEL DESCRIPTORS' )
      GO TO 9900
 275  LVALS(I) = IVALU
      NODVLS(I) = VALU
      GO TO 200
C
C     IS IT THE CLOSING )                                                7260   
C
 280  IF ( ITOKEN .EQ. 11 )  GO TO 290
      write (6, 283) ITOKEN
 283  FORMAT ( '0**** UNRECOGNIZABLE EXCITED STATE DESCRIPTOR (TOKEN =',
     1  I4, ')' )
      GO TO 9900
C
C     ALL DONE WITH THE EXCITED STATE; BYPASS FINAL ).
C
 290  STPCHR = IBUF(INCH)                                                7270   
      INCH = INCH + 1
C
C
C
C     READY TO PROCESS THE NEXT FIELD IF THERE IS ONE TO
C     PROCESS.
C     IF WE ARE DONE, WE WANT TO PROCESS THE FINAL STPCHR AS
C     THE NEXT "FIELD".
C
 400  INCH = INCH - 1                                                    7280   
C     IS IT POSSIBLE TO HAVE ANOTHER FIELD
      IF ( PREDSW .AND. EREDSW )  GO TO 800
C
C     BYPASS BLANKS
C
 420  INCH = INCH + 1
      IF ( STPCHR .NE. BLANK )  GO TO 450
      IF ( INCH .GE. NOCH )  GO TO 460
      STPCHR = IBUF(INCH)
      GO TO 420                                                          7290   
C
C     ONLY + AND = ARE VALID DELIMATORS INSIDE THE SPECIFICATION.
C
 450  IF ( STPCHR .EQ. EQUAL )  GO TO 500
      IF ( STPCHR .EQ. PLUS )  GO TO 550
C
C     END OF CHANNEL - STPCHR WILL BE RECONSIDERED BY CONTRL.
C     DID WE GET MINIMAL CHANNEL SPECIFICATION
C
      INCH = INCH - 1                                                    7300   
 460  IF ( PREDSW )  GO TO 800
      write (6, 463)
 463  FORMAT ( '0**** CHANNEL SPECIFICATION REQUIRES TWO',
     1  ' NUCLEAR SYMBOLS SEPARATED BY A "+".' )
      GO TO 9900
C
C     = SIGN; IS THIS 1ST SUCH0
C
 500  IF ( EREDSW )  GO TO 9020
      EREDSW = .TRUE.                                                    7310   
C
C     ALWAYS STORE RESULT OF = IN 3RD SPOT
C
      IF ( I .EQ. 2 )  GO TO 520
      GUY(3) = GUY(1)
      JVALS(3) = JVALS(1)
      ESTARS(3) = ESTARS(1)
      GO TO 100
C
 520  I = 3                                                              7320   
      GO TO 100
C
C     + SIGN; IS THIS 1ST
C
 550  IF ( PREDSW )  GO TO 9022
      PREDSW = .TRUE.
      I = I + 1
      GO TO 100
C
 800  IRTN = 2                                                           7330   
      IF ( EREDSW )  IRTN = 3
      RETURN
C
C     LOTS OF ERROR MESSAGEES
C
C  ONE OF THE GUYS HAS MORE THAN 5 CHARACTERS IN IT
9004  write (6, 9014)
 9014 FORMAT ( '0**** TOO MANY CHARACTERS IN SYMBOL AND ATOMIC MASS.' )
      GO TO 9900
 9005 write (6, 9015)                                                    7340   
 9015 FORMAT ( '0**** UNEXPECTED DELIMITOR OR END OF LINE ENCOUNTERED',
     1  ' WHEN LOOKING FOR ELEMENT SYMBOL.' )
      GO TO 9900
 9007 write (6, 9017)
 9017 FORMAT ( '0**** COMPLETE SPECIFICATION MUST BE ON SAME LINE AS',
     1  ' CHANNEL KEYWORD.' )
      GO TO 9900
 9020 write (6, 9021)
 9021 FORMAT ( '0**** TWO "=" SIGNS ARE NOT ALLOWED' )
      GO TO 9900                                                         7350   
 9022 write (6, 9023)
 9023 FORMAT ( '0**** TWO "+" SIGNS ARE NOT ALLOWED.' )
      GO TO 9900
C
 9900 INCHM1 = INCH - 1
      write (6, 9903) I, ( IBUF(II), II = INCHST, INCHM1 )
 9903 FORMAT ( 6X, 'WAS PROCESSING FIELD', I2, ' OF THE SPECIFICATION' /
     1  6X, 'SPECIFICATION UP TO THE ERROR IS: ', 80A1 )
      write (6, 9907) stpchr, itoken, guy, predsw, eredsw
 9907 format ( ' last scanned character: ', a1, ' token:', i15 /         7360   
     &   ' Fields: ', 3(a8,', '), ' +, = processed: ', 2l3 )
      IRTN = -1
      RETURN
      END
C*ID* CLINTS   C109.PTOLEMY.SOURCE                          PER701  11:
      SUBROUTINE CLINTS ( RLOWER, ETAI, ETAF, FKI, FKF, SIGI, SIGF,
     1  ACCURA, ASMULT, FFINT, FGINT, GFINT, GGINT,
     2   PTS, WTS, FA, FPA, GA, GPA, WORK,
     3  N, LI, LF, NTERMS, NPTS, IRET, IPRINT )
C                                                                        7370   
C     EVALUATES INTEGRAL(RLOWER, INF) DR FCOUL FCOUL / R**N
C
C     THE FOUR INTEGRALS:
C
C     XYINT = INTEGRAL(RLOWER, INF) DR X(LF,ETAF,KF*R) Y(LI,ETAI,KI*R)
C             /R**N
C
C     WHERE X AND Y ARE EITHER F OR G (REG. AND IRREG. COUL. FUNCS)
C     ARE EVALUATED.  THE INTEGRALS ARE DONE IN THREE PIECES:
C        RLOWER  TO  R1  TO  R2  TO  INFINITY                            7380   
C     RLOWER TO R1 - THE WHOLE WORKS IS DONE NUMERICALLY WITH NPTS
C            GAUSS POINTS PER CYCLE OF THE COULOMB FUNCTIONS.
C     R1 TO R2 - THE (PHI+PHI) PIECE (SEE BELOW) IS DONE BY BELLING
C                AND THE (PHI-PHI) PIECE IS DONE NUMERICALLY.
C     R2 TO INF. - BOTH PIECES ARE DONE BY BELLING.  DEPENDING ON
C     THE CIRCUMSTANCES, THE FIRST AND/OR SECOND REGION MAY BE
C     SKIPPED.
C
C     EACH COULOMB FN = SIN(PHI) OR COS(PHI) / SQRT(Z)
C     THEN (BELLING J.PHYS.B1,136,(1968) THE INTEGRALS CAN BE            7390   
C     GIVEN IN TERMS OF INT(R,INF)(R**-N)*(SQRT(ZI*ZF)**-1)*COS(ANGLE)
C     OR SIN(ANGLE) WITH ANGLE = PHI(IN)+PHI(OUT) OR PHI(IN)-PHI(OUT)
C     FOR + INTEGRAL USE BELLING'S ASYMPTOTIC EXPANSION IN R**-1
C     THE - INTEGRAL (SLOWLY OSCILLATING INTEGRAND) IS DONE
C     NUMERICALLY BY GAUSS-LEGENDRE QUADRATURE AFTER SPLITTING (R INF)
C     INTO INTERVALS OF LENGTH PI/CHI
C     WHERE CHI=D/DR(ANGLE)
C     WITH THE VERY-LARGE L PART BY BELLINGS METHOD
C
C                                                                        7400   
C     ***  ARGUMENT LIST ***
C     ***** FOLLOWING ARGUMENTS ARE REAL*8 *****
C     RLOWER: LOWER LIMIT OF INTEGRATION
C     ETAI  : COULOMB PARAMETER IN INGOING CHANNEL
C     ETAF  : COULOMB PARAMETER IN OUTGOING CHANNEL
C     FKI   : INGOING WAVE NUMBER
C     FKF   : OUTGOING WAVE NUMBER
C     SIGI  : SUPPLIED VALUE OF INCOMING COULOMB PHASE SHIFT
C     SIGF  : SUPPLIED VALUE OF OUTGOING COULOMB PHASE SHIFT
C     ACCURA:  REQUIRED RELATIVE ACCURACY OF THE INTEGRALS.  THIS IS     7410   
C              USED TO CHECK THE BELLINGS RESULTS BUT THE GAUSS
C              INTEGRATIONS ARE NOT CHECKED FOR CONVERGENCE.
C     ASMULT: BELLING'S METHOD IS USED WHEN A CERTAIN QUANTITY
C           : IS LESS THAN   ASMULT * ACCURA  .  REASONABLE
C           : VALUES OF ASMULT ARE AROUND .1 TO .5 .  IF THE INPUT VALUE
C           : IS TOO LARGE, IT
C           : IS AUTOMATICALLY (AT SOME COST) REDUCED.
C     FFINT, FGINT, GFINT, GGINT:  THE FOUR INTEGRALS DEFINED ABOVE
C     PTS, WTS : WORK ARRAYS OF DIMENSION NPTS.
C     FA TO GPA, WORK : WORK ARRAYS OF DIMENSION                         7420   
C          MAX( LI, LF, 4*NTERMS ) + 1
C     ***** FOLLOWING ARGUMENTS ARE INTEGER*4 *****
C     N     : POWER OF R (INTEGRAL OF 1/(R**N))
C     LI,LF : L-VALUES OF PARTIAL WAVES FOR COULOMB FUNCTIONS
C     NTERMS: MAXIMUM NO OF TERMS IN BELLING'S SERIES (20 IS REASONABLE)
C     NPTS  : ORDER OF GAUSS-LEGENDRE QUADRATURE (TYPICALLY 3 - 10)
C     IRET  : ERROR INDICATOR FROM COULOMB SR. ALL'S WELL IF = 0
C     IPRINT: = 4 YIELDS SOME DIAGNOSTIC PRINT-OUT
C           : = 8 YIELDS COPIOUS DIAGNOSTIC PRINT-OUT
C                                                                        7430   
C     M.H.M - JUNE 1 1976
C     NOV 1976 - IMPROVEMENTS - S.P.
C     JAN 1977 - USE RCASYM - S. P.
C     9/15/78 - IMPROVED DIAGNOSTIC PRINTOUT - S.P.
C     10/25/78 - FIX ERROR IN DECIDING WHEN TO GO TO BELLING - S.P.
C     12/26/79 - STANDARD MORTRAN - RPG
C     4/13/87 - AVOID COS(BIG.NUMBER) - S.P.
C
C
      IMPLICIT REAL*8(A-H,O-Z)                                           7440   
C
      DIMENSION PTS(NPTS), WTS(NPTS)
      DIMENSION FA(1), FPA(1), GA(1), GPA(1), WORK(1)
C
      DATA  PI /3.14159 26535 89793 0D0/,  ACCUR /1.D-14/
      LOGICAL ODDSW, ASYMSW
C
c
C
      IF ( IPRINT .GE. 3 )  write (6, 13) N, LI, LF, NTERMS, NPTS,       7450   
     1  RLOWER, ETAI, ETAF, FKI, FKF, SIGI, SIGF, ACCURA
 13   FORMAT ( / '0CLINTS:', I3, 2I4, 2I3, 7G15.6 / ' ACCURA=', G15.5 )
C
C     SETUP GAUSS POINTS
C
      CALL GAUSSL ( NPTS, PTS, WTS )
C
      ICHI = 0
      EPSILO = ASMULT * ACCURA
      EPSIL = EPSILO                                                     7460   
C
C     INITIALIZE BELLING METHOD FOR SUM
C
      ISYN=1
      FFINT = 0
      FGINT = 0
      GFINT = 0
      GGINT = 0
      DELTA = PI/DMAX1(FKI,FKF)
      IPIECE = 0                                                         7470   
      RVAL = RLOWER
C
C     GET TURNING POINT
C
      RTURN = DMAX1( (ETAI + DSQRT(ETAI**2+LI*(LI+1)))/FKI,
     1  (ETAF + DSQRT(ETAF**2+LF*(LF+1)))/FKF )
      ASYMSW = .FALSE.
      IF ( IPRINT .GE. 3 )  write (6, 93) RTURN, EPSILO, DELTA
  93  FORMAT ( ' RTURN, EPSILO, DELTA =', 3G15.6 )
C                                                                        7480   
C     GET COULOMB WAVE FUNCTION AND BELLING PARAMETERS AT R = RVAL
C
 100  ROI=FKI*RVAL
      ROF=FKF*RVAL
C
      IF ( ASYMSW )  GO TO 120
      IF ( RVAL .LT. 1.2*RTURN )  GO TO 110
C
C     GET ASYMPTOTIC EXPANSION PARAMETERS
C                                                                        7490   
      NMAX = MAX0( LI, 4*NTERMS )
      CALL RCASYM ( LI, ETAI, ROI, IPRINT-4, SIGI, ZI, PHSI, DZI,
     1  FI, FPI, GI, GPI, FA, GA, GPA, WORK,
     2  ACCURA, NMAX, NASYI, IRET )
      IF ( IRET .NE. 0 )  GO TO 110
      CALL RCASYM ( LF, ETAF, ROF, IPRINT-4, SIGF, ZF, PHSF, DZF,
     1  FF, FPF, GF, GPF, FPA, GA, GPA, WORK,
     2  ACCURA, NMAX, NASYF, IRET )
      IF ( IRET .NE. 0 )  GO TO 110
C                                                                        7500   
C     FA NOW HAS EXPANSION PARAMETERS FOR INCOMING
C     FPA HAS PARAMETERS FOR FINAL.
C
      RHO0I = ROI
      RHO0F = ROF
      ASYMSW = .TRUE.
      GO TO 130
C
 110  CALL RCWFN(ROI,ETAI,LI,LI,FA,FPA,GA,GPA,ACCUR,IRET)
      IF(IRET.NE.0)  GO TO 900                                           7510   
      FI=FA(LI+1)
      GI=GA(LI+1)
      FPI=FPA(LI+1)
      GPI=GPA(LI+1)
      CALL RCWFN(ROF,ETAF,LF,LF,FA,FPA,GA,GPA,ACCUR,IRET)
      IF(IRET.NE.0) GO TO 900
      FF=FA(LF+1)
      GF=GA(LF+1)
      FPF=FPA(LF+1)
      GPF=GPA(LF+1)                                                      7520   
      ZI=1/(FI**2+GI**2)
      ZF=1/(FF**2+GF**2)
      GO TO 130
C
C     FIND STUFF FROM THE ASYMPTOTIC EXPANSION
C
 120  RI = RHO0I/ROI
      RF = RHO0F/ROF
      ZI = 1
      ZF = 1                                                             7530   
      DZI = 0
      DZF = 0
      WI = RI
      WF = RF
      PHSI = 0
      PHSF = 0
C
      DI = 1
      TERM2 = 1
      DO 124  I = 2, NASYI                                               7540   
         TERM = WI*FA(I)
         WI = WI*RI
         ZI = ZI + TERM
         DZI = DZI - DI*TERM
         IF ( I .GT. 2 )  PHSI = PHSI + TERM/(DI-1)
         DI = DI + 1
         IF ( DABS(TERM)+TERM2 .LT. ACCURA*ZI )  GO TO 125
         TERM2 = DABS(TERM)
 124  CONTINUE
      I = NASYI                                                          7550   
 125  NASYI = I
      PHSI = ROI - ETAI*DLOG(2*ROI) + SIGI - .5*PI*LI - ROI*PHSI
      DZI = DZI/ROI
C
      DI = 1
      TERM2 = 1
      DO 127  I = 2, NASYF
         TERM = WF*FPA(I)
         WF = WF*RF
         ZF = ZF + TERM                                                  7560   
         DZF = DZF - DI*TERM
         IF ( I .GT. 2 )  PHSF = PHSF + TERM/(DI-1)
         DI = DI + 1
         IF ( DABS(TERM)+TERM2 .LT. ACCURA*ZF )  GO TO 128
         TERM2 = DABS(TERM)
 127  CONTINUE
      I = NASYF
 128  NASYF = I
      PHSF = ROF - ETAF*DLOG(2*ROF) + SIGF - .5*PI*LF - ROF*PHSF
      DZF = DZF/ROF                                                      7570   
      FI = DSIN(PHSI)/DSQRT(ZI)
      GI = DCOS(PHSI)/DSQRT(ZI)
      FPI = ZI*GI - (.5*DZI/ZI)*FI
      GPI = -ZI*FI - (.5*DZI/ZI)*GI
      FF = DSIN(PHSF)/DSQRT(ZF)
      GF = DCOS(PHSF)/DSQRT(ZF)
      FPF = ZF*GF - (.5*DZF/ZF)*FF
      GPF = -ZF*FF - (.5*DZF/ZF)*GF
 130  TI=FI*FPI+GI*GPI
      TF=FF*FPF+GF*GPF                                                   7580   
 140  CHI = FKI*ZI + ISYN*FKF*ZF
C
C     FOR VERY SMALL CHI (DIFFERENCE PIECE FOR INITIAL = FINAL CASE)
C     WE DO THE WHOLE THING NUMERICALLY
C
      B = 1.D-8*FKI*ZI
      IF ( IPRINT .GE. 4 )  write (6, 143) RVAL, ZI, ZF, CHI, B, TI, TF
 143  FORMAT ( ' R, Z''S, CHI, TINY, T''S:', G12.4, 2G20.10,
     1  2( G14.4, G12.4 ) )
C                                                                        7590   
      IF ( DABS(CHI) .LT. B )  GO TO 150
      IF ( DABS(GI) .GT. 1000 )  GO TO 200
C
      F = 1 / ( DSQRT(ZI*ZF) * RVAL**N )
      A0=F/CHI
C
C     FOR DIFFERENCE WE MAY NOT NEED MUCH CONVERGENCE DUE TO
C     A LARGE NUMERIC CONTRIBUTION.
C     CAN WE NOOW USE BELLING
C                                                                        7600   
      R = ( N/RVAL + 2*(FKI*ZI*DABS(TI)+FKF*ZF*DABS(TF)) ) / DABS(CHI)
      EPS = EPSIL
      IF ( ISYN .EQ. -1 )  EPS = EPS * ( 1 + DABS(CUMC/A0) )
      DB = R**3
      IF ( DB**2 .LE. EPS )  GO TO 300
C
C     NO, INTEGRATE ONE CYCLE OF THE WHOLE WORKS OR OF JUST
C         THE DIFFERENCE PARTS.
C
 150  IF ( ISYN .EQ. -1 )  DELTA = PI/(DABS(CHI)+N/RVAL)                 7610   
      GO TO 200
C
C
 200  IPIECE = IPIECE + 1
      CI = 0
      SI = 0
C
      DO 259  I = 1, NPTS
         R = RVAL + .5*DELTA + .5*DELTA*PTS(I)
         ROI = FKI*R                                                     7620   
         ROF = FKF*R
         ZFAC = .5*DELTA*WTS(I)/R**N
         IF ( ASYMSW )  GO TO 210
         CALL RCWFN(ROI,ETAI,LI,LI,FA,FPA,GA,GPA,ACCUR,IRET)
         IF(IRET.NE.0) GO TO 900
         FI=FA(LI+1)
         GI=GA(LI+1)
         CALL RCWFN(ROF,ETAF,LF,LF,FA,FPA,GA,GPA,ACCUR,IRET)
         IF(IRET.NE.0) GO TO 900
         FF=FA(LF+1)                                                     7630   
         GF=GA(LF+1)
         IF ( ISYN .EQ. -1 )  GO TO 250
         GO TO 230
C
C     HERE USE ASYMPTOTIC EXPANSION
C
 210     RI = RHO0I/ROI
         ZI = FA(NASYI)*RI
         PHSI = 0
         DJ = NASYI - 2                                                  7640   
         DO 214  JJ = 3, NASYI
            J = NASYI+2-JJ
            ZI = RI*(FA(J) + ZI)
            PHSI = RI*(FA(J+1)/DJ + PHSI)
            DJ = DJ - 1
 214     CONTINUE
         ZI = 1 + ZI
         PHSI = ROI - ETAI*DLOG(2*ROI) + SIGI - .5*PI*LI - RHO0I*PHSI
C
         RF = RHO0F/ROF                                                  7650   
         ZF = FPA(NASYF)*RF
         PHSF = 0
         DJ = NASYF - 2
         DO 219  JJ = 3, NASYF
            J = NASYF+2-JJ
            ZF = RF*(FPA(J) + ZF)
            PHSF = RF*(FPA(J+1)/DJ + PHSF)
            DJ = DJ - 1
 219     CONTINUE
         ZF = 1 + ZF                                                     7660   
         PHSF = ROF - ETAF*DLOG(2*ROF) + SIGF - .5*PI*LF - RHO0F*PHSF
C
         IF ( ISYN .EQ. -1 )  GO TO 255
C
         FI = DSIN(PHSI)/DSQRT(ZI)
         GI = DCOS(PHSI)/DSQRT(ZI)
         FF = DSIN(PHSF)/DSQRT(ZF)
         GF = DCOS(PHSF)/DSQRT(ZF)
 230     FFINT = FFINT + ZFAC*FF*FI
         FGINT = FGINT + ZFAC*FF*GI                                      7670   
         GFINT = GFINT + ZFAC*GF*FI
         GGINT = GGINT + ZFAC*GF*GI
         GO TO 259
C
C     FOLLOWING ARE COS(PHII-PHIF) AND SIN(PHII-PHIF)
C
 250     CI = CI + ZFAC*(GI*GF+FI*FF)
         SI = SI + ZFAC*(FI*GF-GI*FF)
         GO TO 259
 255     CI = CI + (ZFAC/SQRT(ZI*ZF)) * COS(PHSI-PHSF)                   7680   
         SI = SI + (ZFAC/SQRT(ZI*ZF)) * SIN(PHSI-PHSF)
C
 259  CONTINUE
C
      IF ( IPRINT .LT. 7 )  GO TO 280
      IF ( ISYN .EQ. +1 )  write (6, 273) IPIECE, RVAL, FFINT, FGINT,
     1  GFINT, GGINT
 273  FORMAT (' INTS:', I4, F6.1, 4G14.6 )
      IF ( ISYN .EQ. -1 )  write (6, 278) IPIECE, RVAL, CI, SI
 278  FORMAT ( ' NUMERIC C-, S-:', I4, G12.4, 2G14.6 )                   7690   
C
 280  RVAL = RVAL + DELTA
      IF ( ISYN .EQ. +1 )  GO TO 100
      CUMC = CUMC + CI
      CUMS = CUMS + SI
C
C     HAAVE WE GONE SO FAR IN DIFFERRENCE THAT THE BILLING'S
C     PIECE WON'T MATTER.
C
      IF ( DABS(CI) .LT. ACCURA*DABS(FFINT+.5*(CUMC-CIP))  .AND.         7700   
     1     DABS(SI) .LT. ACCURA*DABS(GFINT+.5*(CUMS+SIP)) )  GO TO 810
      GO TO 100
C
C     ALL DONE WITH NUMERIC PART OF TOTALS
C
 300  IF ( IPRINT .LT. 3  .OR.  IPIECE .EQ. 0 )  GO TO 350
      IF ( ISYN .EQ. +1 )  write (6, 303)
     1  IPIECE, FFINT, FGINT, GFINT, GGINT
 303  FORMAT ( '0NUMERIC VALUES FOR', I4, ' CYCLES:' /  4G15.8 )
      IF ( ISYN .EQ. -1 )  write (6, 313) IPIECE, CUMC, CUMS             7710   
 313  FORMAT ( ' NUMERIC C-, S- FROM', I4, ' CYCLES:', 2G15.8 )
C
C     FOR SUM WE USE THE FF INTEGRAL AS A GUIDE TO ERRORS
C
 350  IF ( ISYN .EQ. -1 )  GO TO 400
      CUMC = FFINT
      CUMS = FFINT
C
C     BELLINGS METHOD FOR SUM OR DIF
C     HERE WE SET UP  Y(I), Y(F), ..., DF/DK, D2F/DK2, ...               7720   
C     WHICH ARE NEEDED FOR BELLING'S METHOD.  (SEE "SERIES
C     EXPANSION OF COULOMB INTEGRALS" PP 1-5.)
C
 400  PHSI=DATAN2(FI,GI)
      PHSF=DATAN2(FF,GF)
      DZI=-2*FKI*ZI*ZI*TI
      DZF=-2*FKF*ZF*ZF*TF
      DCHI=FKI*DZI+ISYN*FKF*DZF
      D1=DZI/ZI+DZF/ZF
      C1=DFLOAT(N)/RVAL+.5*D1                                            7730   
      DF=-F*C1
      WI=1-(2*ETAI)/ROI-(LI*(LI+1))/(ROI**2)
      WF=1-(2*ETAF)/ROF-(LF*(LF+1))/(ROF**2)
      DTI=FKI*(FPI**2+GPI**2-WI/ZI)
      DTF=FKF*(FPF**2+GPF**2-WF/ZF)
      D2ZI=-2*FKI*ZI*(2*DZI*TI+ZI*DTI)
      D2ZF=-2*FKF*ZF*(2*DZF*TF+ZF*DTF)
      D2CHI=FKI*D2ZI+ISYN*FKF*D2ZF
      D12=(DZI/ZI)**2+(DZF/ZF)**2
      D2=D2ZI/ZI+D2ZF/ZF                                                 7740   
      D2F=(F/RVAL-DF)*C1-(F*D1)/(2*RVAL)-.5*F*(D2-D12)
      IF ( IPRINT .GE. 4 )  write (6, 423) RVAL, ROI, ROF, R
 423  FORMAT ('0R =', G12.4, '   RHO''S =', 2G12.4,
     1  '   EPSILON =', G10.2 )
      DB = 0
      TIMS=1/(RVAL*CHI)
      PHANG=PHSI+ISYN*PHSF
      SN=DSIN(PHANG)
      CSN=DCOS(PHANG)
C                                                                        7750   
C     EACH ITERATION ON NITS BRINGS IN A HIGHER DERIVATIVE OF BETA.
C     RIGHT NOW WE ONLY HAVE 0TH AND 1ST DERIVATIVES
C
      IF ( IPRINT .GE. 6 )  write (6, 433)
 433  FORMAT ( '0NIT  K', 6X, 'B', 9X, 'DB', 10X, 'A',
     1   13X, 'EVEN', 13X, 'ODD' )
C
      DO 499  NIT = 1, 2
C
      FACTOR=F/CHI                                                       7760   
C
C     BELLING'S EXPANSION ( SEE "SERIES...", P 6)
C     COLLECT ODD AND EVEN A-COEFFICIENTS INTO SIN AND COS INTEGRALS
C
C     SEE "LONG-RANGE PART OF COULOMB FUNCTION INTEGRALS", P 8,
C     EQS 33-34
C
         EVEN = A0
         AM1 = A0
         B = 1                                                           7770   
         ODD = 0
         SIGN = +1.
         ODDSW = .TRUE.
         DO 469 I = 1, NTERMS
            FACTOR=FACTOR*TIMS
            C2=DF/F-(I*DCHI)/CHI
            BM1 = B
            B=RVAL*DB+(C2*RVAL-I+1)*B
            IF ( NIT .GT. 1 )
     1        DB=(C2*RVAL-I+2)*DB+(C2-RVAL*((DF/F)**2                    7780   
     2          - I*(DCHI/CHI)**2)+RVAL*(D2F/F-I*D2CHI/CHI))*BM1
            A=B*FACTOR
C
            IF ( ODDSW )  GO TO 440
            EVEN = EVEN + SIGN*A
            GO TO 445
 440        ODD = ODD + SIGN*A
            SIGN = -SIGN
 445        ODDSW = .NOT. ODDSW
C                                                                        7790   
            IF ( IPRINT .GE. 6 )  write (6, 447) NIT, I, B, DB,
     1        A, EVEN, ODD
 447        FORMAT ( I3, I4, 3G11.4, 2G17.9 )
            IF ( I .EQ. 1 )  GO TO 465
            IF ( DABS(A) .GT. DABS(AM2) )  GO TO 700
            IF ( DABS(A) .LT. ACCURA*(DABS(A0)+DMIN1(DABS(CUMC),
     1            DABS(CUMS))) )   GO TO 470
C
 465        AM2 = AM1
            AM1 = A                                                      7800   
 469     CONTINUE
         GO TO 700
C
 470     CI = -EVEN*SN-ODD*CSN
         SI = -ODD*SN+EVEN*CSN
         ARAT = A/A0
         IF ( IPRINT .GE. 4 )  write (6, 473) NIT, I, ARAT, CI, SI
 473     FORMAT ( ' NIT =', I2, '   A(', I2, ')/A(0) =', G9.2,
     1     '   COS, SIN =', 2G15.8 )
         IF ( NIT .EQ. 1 )  GO TO 490                                    7810   
         EVEN = DABS( (CILAST-CI)/(CUMC+CI) )
         ODD  = DABS( (SILAST-SI)/(CUMS+SI) )
         IF ( IPRINT .GE. 4 )  write (6, 483) EVEN, ODD
 483     FORMAT ( 11X, 'REL. ERR. =', 2G10.2 / )
 490     CILAST = CI
         SILAST = SI
 499  CONTINUE
C
C
C     WAS THE DERIVATIVE A BIG CORRECTION?                               7820   
C
      IF ( DMAX1(EVEN, ODD)**2 .GT. ACCURA )  GO TO 700
C
      ICHI = 0
      IF(ISYN.EQ.-1) GO TO 800
      CIP = CI
      SIP = SI
C
C     NOW DO  PH(IN)-PH(OUT)
C                                                                        7830   
      IPIECE = 0
      ISYN = -1
      CUMS=0
      CUMC=0
      EPSIL = EPSILO
      GO TO 140
C
C
C
C     WE NEED TO MAKE ASMULT SMALLER                                     7840   
C
 700  R = DMIN1( .5*EPSIL, .75*R**6*(EPSIL/EPS) )
      ASMULT = ASMULT * R/EPSIL
      EPSIL = R
      ICHI = ICHI + 1
      IF ( ICHI .GT. 20 )  GO TO 720
      IF ( IPRINT .GE. 4 )  write (6, 703) ASMULT, EPSIL
 703  FORMAT (
     2  '0+++ REDOING CALCULATION WITH NEW ASMULT:', 2G12.4 )
      GO TO 140                                                          7850   
C
 720  write (6, 723)
 723  FORMAT ( '0*** COULD NOT GET CONVERGENCE IN CLINTS *** ' )
      IRET = -1
      GO TO 50
C
C
C     ALL DONE, COLLECT PIECES AND LEAVE
C
 800  CUMC = CUMC+CI                                                     7860   
      CUMS = CUMS+SI
 810  FFINT = FFINT + .5*( CUMC - CIP )
      GGINT = GGINT + .5*( CUMC + CIP )
      FGINT = FGINT + .5*( SIP - CUMS )
      GFINT = GFINT + .5*( SIP + CUMS )
      IF ( IPRINT .GE. 3 )  write (6, 813) CIP, SIP, CUMC, CUMS, FFINT,
     1  FGINT, GFINT, GGINT
 813  FORMAT ( '0C+ S+ C- S-:', 4G15.8 / ' FF FG GF GG:', 4G15.8 )
      GO TO 50
C                                                                        7870   
C     ERROR IN RCWFN
C
 900  write (6, 903) IRET, LI, LF, ETAI, ETAF, ROI, ROF
  903 FORMAT(1H0, '*** ERROR IRET = ',I5,' IN RCWFN ***' /
     1  ' L''S, ETA''S, RHO''S =', 2I5, 4G20.10 )
C
   50 RETURN
      END
C*ID* CLRCHN   C109.PTOLEMY.SOURCE                          PER701  15:
      SUBROUTINE  CLRCHN ( ICHAN )                                       7880   
C
C     CLEAR THE DEFINITIONS OF CHANNEL VARIABLES ( P, T, AND POTS )
C
C     THIS ROUTINE IS CALLED AFTER EACH BOUNDSTATE AND OPTICAL
C     MODEL SCATTERING STATE.  IT SETS CHANNEL VARIABLES THAT ARE
C     NOT LIKELY TO BE SIGNIFICANT FOR LATER CALCULATIONS TO
C     UNDEFINED STATUS.
C
C     FOR STAND ALONES, THINGS ARE SET TO UNDEFINED ONLY IF SOMETHING
C     ELSE CAN STILL DEFINE THEM (E.G., R IS SET UNDEFINED IF R0,        7890   
C     MP AND MT ARE ALL DEFINED).
C
C     5/2/75 - FIRST VERSION - S. PIEPER
C     5/17/75 - SELECTIVE CLEARS FOR STANDALONE CALCS.
C     5/22/75 - VSI ADDED
C     8/28/75 - CLEAR R0'S WHEN CLEARING A'S.
C     10/13/75 - CLEAR RC0 WHICH WE FORGOT ABOUT.
C     10/23/75 - ESQ PARMS; DON'T CLEAR V'S BETWEEN SCAT STATES
C     4/30/76 - MODIFIED COULOMB INPUT  (MHM)
C     4/20/77 - DO NOT FREE RC0 BETWEEN B.S. - S.P.                      7900   
C     4/24/77 - USE WASSET FOR RC STUFF; EXSPT CLEARED.
C     9/24/77 - UNDJFINE JP, J, L WHEN SET BY SETCHN
C     11/20/77 - FREE ASYMPTOPIA
C     11/25/77 - LINKULES
C     12/5/77 - RESTORE STUFF FOR INELASTIC - S.P.
C     2/11/78 - FREE ELAB WHEN APPRORIATE
C     3/15/78 - DO NOT SET NEXT TO 0 (MUNICH CHANGE) - S.P.
C     2/2/79 - ADD TENSOR POTENTIALS - RPG
C     3/22/79 - RESTORE ALL 6 WORDS OF /LNKBLK/ - S.P.
C     5/6/79 - AMXGPT, PARITIES, LEVEL DESCRIPTORS; FREE RCP, RCT LIKE   7910   
C               OTHERS - S.P.
C     7/6/79 - ICHAN=0 AFTER A MULTIPASS CALCULATION. - RPG
C     2/25/79 - INITIALIZE LNKNAM FROM LNKNM2 - RPG
C
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      parameter ( NUMJWORD = 12 )                                       /jblock/
      COMMON /JBLOCK/  J, JS(5),
     &  JP, JSP, JST,
     &  JPARM1, JPARM2, JPARM3
 
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
c                                                                       /lnkblk/
c  STRUCTURE OF   /LNKBLK/
c
c  THERE IS A BLOCK OF 3 DOUBLE WORDS FOR EACH POSSIBLE USE
c  OF A LINKULE.  THE NUMLNK = NUMLINKULES USES ARE IN THE ORDER
c    REALPOTEN  IMAGPOTEN  REALVSO  IMAGVSO  COULOMB
c    WAVEFUNCTION  AND 6 TENSOR POTENTIALS
c  THE THREE-DOUBLE-WORD BLOCKS EACH HAVE THE STRUCTURE
c
c    LNKNAM(1,I)   LINKULE NAME
c
c      LNKADR(3,I)   LINKULE ADDRESS, O IF NO LINKULE IN USE.
c      LNKADR(4,I)   0 - NO L OR J DEPENDENCE IN POTENTIAL
c                    1 - L DEPENDENCE BUT NO J DEPENDENCE
c                    2 - BOTH L  AND J DEPENDENCE
c
c      LNKADR(5&6,I)  MYINTS - A TWO-ELEMENT ARRAY THAT THE
c                     LINKULE MAY USE FOR COMMUNICATION BETWEEN
c                     CALLS TO ITSELF.
c
      parameter ( NUMLINKULES = 13 )
      COMMON /LNKBLK/  NUMLNK, IUNIQU, LNKADR(6,NUMLINKULES)
      character*8  LNKNAM(3,NUMLINKULES)
      EQUIVALENCE ( LNKNAM(1,1), LNKADR(1,1) )
 
      COMMON /LOCFIT/  LNKAD2(6,2,NUMLINKULES)                          /locfitf
 
      COMMON /KANDM/ AKI, AKO, REDMI, REDMO, RIMAX, ROMAX, ISIGS(2),    /kandm/
     &  RSCTS(2), ASCTS(2), RCSCTS(2) ,ISMATS(2), LOMOST, LCRIT,
     &  ISCTMN, ISCTCR, ETAS(2), RCSCTP(2), RCSCTT(2), LCRITS(2),
     &  RATMSS(2), QMIN, ABAR
 
      DIMENSION  AKS(2), REDMS(2), RMAXS(2)
      EQUIVALENCE ( AKI, AKS(1) ), ( REDMI, REDMS(1) ),
     &  ( RIMAX, RMAXS(1) )
 
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
C
c
C
C
C
      IF ( ICHAN .LT. 5 )  GO TO 200                                     7930   
C
C     CLEAR ONLY THINGS THAT CAN BE REDEFINED LATER
C
      IF ( AMP .EQ. UNDEF  .OR.  AMT .EQ. UNDEF )  GO TO 150
      AM = UNDEF
      IF ( R0 .NE. UNDEF )  R = UNDEF
      IF ( RI0 .NE. UNDEF )  RI = UNDEF
      IF ( RSO0 .NE. UNDEF )  RSO = UNDEF
      IF ( RSOI0 .NE. UNDEF )  RSOI = UNDEF
      IF ( RSI0 .NE. UNDEF )  RSI = UNDEF                                7940   
      IF ( RC0 .NE. UNDEF )  RC = UNDEF
      IF ( RC0P .NE. UNDEF )  RCP = UNDEF
      IF ( RC0T .NE. UNDEF )  RCT = UNDEF
      DO 129 I = 1, 6
         IF ( RTEN0(I) .NE. UNDEF )  RTEN(I) = UNDEF
 129  CONTINUE
      IF ( ELAB .NE. UNDEF ) E = UNDEF
C
 150  IF ( ECM .NE. UNDEF )  E = UNDEF
      GO TO 400                                                          7950   
C
C     WHEN DOING DWBA; FREE LOTS
C
 200  E = UNDEF
      AM = UNDEF
      AMP = UNDEF
      AMT = UNDEF
      R = UNDEF
      RC = UNDEF
      RCP = UNDEF                                                        7960   
      RCT = UNDEF
      RI = UNDEF
      RSO = UNDEF
      RSOI = UNDEF
      RSI = UNDEF
      DO 209 I = 1, 6
         RTEN(I) = UNDEF
 209  CONTINUE
      SPAM = UNDEF
      L = NOTDEF                                                         7970   
      NODES = NOTDEF
      IZP = NOTDEF
      IZT = NOTDEF
      J = NOTDEF
      JP = NOTDEF
      JSP = NOTDEF
      JST = NOTDEF
      PARITY = 0
      DO 219  I = 1, 2
         PARIPT(I) = 0                                                   7980   
         AMXGPT(I) = UNDEF
         EXSPT(I) = UNDEF
         LSPCPT(I) = NOTDEF
         NODEPT(I) = NOTDEF
 219  CONTINUE
C
C     DO NOT SET POTENTIALS TO 0 WHEN GOING FROM ONE SCAT. STATE TO
C     THE NEXT.
C
      IF ( ICHAN .GE. 3  .AND.  IDONE/4 .NE. 3 )  GO TO 400              7990   
      TAU = 0
      TAUI = 0
      VSO = 0
      VSOI = 0
      VSI = 0
      VE = 0
      VIE = 0
      VESQ = 0
      VIESQ = 0
      DO 229 I = 1, 6                                                    8000   
         VTEN(I) = 0
 229  CONTINUE
      V = 0
      VI = 0
C
C     CANCEL LINKULE REFERENCES EXCEPT FROM ONE SCAT STATE TO ANOTHER
C
C     ALSO DO NOT CANCEL PRIOR TO EFFECTIVE EXCITATION POTENTIAL
C
      IF ( ISTRIP .EQ. 0 )  GO TO 300                                    8010   
C
      DO 259  I = 1, NUMLNK
         LNKADR(3,I) = 0
 259  CONTINUE
C
C
C     WE LEAVE THE A'S DEFINED FROM ONE BOUND STATE TO ANOTHER AND
C     FROM ONE SCATTERING TO ANOTHER BUT NOT FROM BOUND TO SCATTER
C
      IF ( ICHAN .EQ. 0 )  GO TO 310                                     8020   
 300  IF ( IDONE .EQ. 2**(ICHAN-1) )  GO TO 400
      IF ( IDONE .EQ. 3 + 2**(ICHAN-1) )  GO TO 400
      IF ( IDONE .EQ. 12 + 2**(ICHAN-1) )  GO TO 400
 310  A = UNDEF
      AI = UNDEF
      ASO = UNDEF
      ASOI = UNDEF
      ASI = UNDEF
      R0 = UNDEF
      RI0 = UNDEF                                                        8030   
      RSO0 = UNDEF
      RSOI0 = UNDEF
      RSI0 = UNDEF
      R0E = 0
      RI0E = 0
      R0ESQ = 0
      RI0ESQ = 0
      RC0 = UNDEF
      RC0P = UNDEF
      RC0T = UNDEF                                                       8040   
      AE = 0
      AIE = 0
      AESQ = 0
      AIESQ = 0
      DO 319 I = 1, 6
         RTEN0(I) = UNDEF
         ATEN(I) = UNDEF
 319  CONTINUE
      ASYMPT = UNDEF
C                                                                        8050   
C     WE ALWAYS UNDEFINE PARAMETERS THAT WERE SET TO OTHER PARAMETERS
C     BY SETPOT
C
 400  IF ( .NOT. WASSET(1) )  GO TO 410
      RI0 = UNDEF
      RI0E = 0
      RI0ESQ = 0
 410  IF ( .NOT. WASSET(2) )  GO TO 420
      AI = UNDEF
      AIE = 0                                                            8060   
      AIESQ = 0
 420  IF ( WASSET(3) )  RSO = UNDEF
      IF ( WASSET(4) )  ASO = UNDEF
      IF ( WASSET(5) )  RSOI = UNDEF
      IF ( WASSET(6) )  ASOI = UNDEF
      IF ( WASSET(7) )  RSI = UNDEF
      IF ( WASSET(8) )  ASI = UNDEF
      IF ( WASSET(9) )  RC0 = UNDEF
      IF ( WASSET(9) )  RC = UNDEF
      IF ( WASSET(10) )  RCP = UNDEF                                     8070   
      IF ( WASSET(11) )  RCT = UNDEF
      IF ( WASSET(12) )  JP = NOTDEF
      IF ( WASSET(13) )  J = NOTDEF
      IF ( WASSET(14) )  L = NOTDEF
      IF ( WASSET(15) )  ASYMPT = UNDEF
      IF ( WASSET(16) )  ELAB = UNDEF
      DO 439 I = 1, 6
         IF ( WASSET(2*I+15) ) RTEN(I) = UNDEF
         IF ( WASSET(2*I+16) ) ATEN(I) = UNDEF
 439  CONTINUE                                                           8080   
      IF ( WASSET(29) )  PARITY = 0
C
C     IF THIS IS INELASTIC SCATTERING, SET BACK TO FIRST CHANNEL
C     AFTER BOTH CHANNELS ARE DONE.
C
      IF ( ISTRIP .NE. 0  .OR.  IDONE .NE. 12 )  GO TO 800
C
      DO 529  I = 1, NUMLNK
CVA         LNKNAM(I) = LNKNM2(1,I)
         DO 529  II = 1, 6                                               8090   
            LNKADR(II,I) = LNKAD2(II,1,I)
 529  CONTINUE
      R = RSCTS(1)
      RI = RIS(1)
      RC = RCSCTS(1)
      A = ASCTS(1)
      AI = AIS(1)
      V = V0RS(1)
      VI = V0IS(1)
      RSI = RSIS(1)                                                      8100   
      ASI = ASIS(1)
      VSI = V0SIS(1)
      POWRL = POWRLS(1)
      POWIM = POWIMS(1)
C
 800  RETURN
      END
C*ID* CONTRL   C109.PTOLEMY.SOURCE                          PER701  16:
      SUBROUTINE CONTRL ( IGOTO, JGOTO, IPRM1, IPRM2, IPRM3, PRM1 )
C                                                                        8110   
C  CONTROL ROUTINE FOR PTOLEMY
C
C          * * *  P T O L E M Y  * * *
C
C     SOPHISTICATED PROGRAMS CONTAIN SUBTLE ERRORS.
C
C
C
C
C     THE ARGUMENTS ARE:                                                 8120   
C
C     IGOTO: SET BY CONTRL BEFORE RETURNING, TO DETERMINE THE NEXT STEP.
C        = 0 AFTER RETURN, TO STOP.
C        = 1 AFTER ; AFTER PROJECTILE OR TARGET, TO CALL BOUND.
C        = 2 AFTER ; AFTER FIT OR FITELASTIC, TO CAL FITEL & FITEL2.
C        = 3 AFTER CALLTSO, TO CALL SUBROUTINE TSO.
C        = 4 NOT USED (COMES RIGHT BACK).
C        = 5 AFTER ; AFTER INCOMING OR OUTGOING, TO CALL WAVSET.
C        = 6 AFTER ; AFTER GRIDSETUP, TO CALL PRBPRT, GETSCT,
C              GRDSET OR INGRST, AND ANGSET.                             8130   
C        = 7 AFTER ; AFTER RADIALIN, TO CALL INELDC, INRDIN, OR COUPLE2.
C        = 8 AFTER ; AFTER LINTERPO, TO CALL LINTER.
C        = 9 AFTER ; AFTER CROSSSEC, TO CALL XSECTN.
C        = 10 AFTER ; AFTER DOTEMP1, TO CALL TEMP1.
C        = 11 AFTER ; AFTER DOTEMP2, TO CALL TEMP2.
C        = 12 AFTER ; AFTER DOTEMP3, TO CALL TEMP3.
C        = 13 AFTER ; AFTER SCATTERING, TO CALL WAVEF.
C        = 14 AFTER ; AFTER ALL CHANNELS ARE SET UP:  DO THE WHOLE
C           DWBA OR CC CALCULATION.
C        = 15 AFTER ; AFTER CROSSSEC IF L INTERP. IS NOT DONE,           8140   
C              TO CALL LINTERP AND XSECTN.
C
C     JGOTO:  USED BY CONTRL TO TELL IT WHAT TO DO FIRST.
C        = 1 TO GET THE NEXT KEYWORD.
C        = 2 TO CHECK THE RETURN CODE (IPARM1) AFTER A CALCULATION
C              STEP.
C        = 3 TO INITIALIZE THINGS ON THE FIRST CALL.
C        = 4 AFTER A BOUND STATE OR SCATTERING CALCULATION, TO
C              UPDATE IDONE AND GET READY FOR THE NEXT CHANNEL.
C        = 5 AFTER USEHS, TO READ THE SAVED COMMON BLOCKS.               8150   
C        = 6 AFTER A PASS OF A MULTIPASS CALCULATION, TO PREPARE FOR
C              CHANNEL CHANGES.
C
C     IPRM1 = 0 IF AN ERROR HAS OCCURRED IN THE PREVIOUS STEP.
C
C     IPRM2 = NALLOC TO B.S. POTENTIAL, SET BY BOUND.
C
C     IPRM3 = NALLOC TO B.S. WAVE FUNCTION, SET BY BOUND.
C
C     PRM1 = THE PARAMETER PASSED TO SUBROUTINE TSO; NOT USED HERE.      8160   
C
C
C
C
C     1/18/75 - REARRANGED TO BE OVERLAYED - S. P.
C     1/24/75 - AMT, AMP IN AMU, ANGLES IN DEGREES INTERNALLY
C     1/30/75 - CHANGE ASYMTOPIC BOUND STATE LIMIT; STORE J1, J2;
C               PRINT, NINTS, TEMPORARY  KEYWORDS ADDED - S.P. & MHM
C     2/9/75 - CALL GRIDSET, DSIGMA, TEMP1, TEMP2, TEMP3
C     2/17/75 - RENAME AND KEEP KEYWORDS.  OTHER LITTLE THINGS           8170   
C     3/4/75 - MAPTYPE ADDED; CHECK RETURN CODES; OTHER LITTLE THINGS
C     3/5/75 - MAPSUM, MAPDIF, NPSUM, NPDIF, NPPHI (REPLACES NPLEG)
C     4/14/75 - MAJOR REWRITE, MANY KEYWORD NAMES CHANGED.
C     5/6/75 - USE SETCHN, SETPOT;  NEW USE OF SEMICOLON
C     5/17/75 - REACTION, HEADER, RESET KEYWORDS; MUCH MOVING.
C     5/26/75 - NEW NUCONLY WORDS; VSI; UNDEFINE; BETTER ERROR MSGS.
C     6/11/75 - SAVEHS/USEHS ADDED
C     6/24/75 - ADD COPY; DUMP=NSDUMP, DUMPALL; TSO=CALLTSO
C     6/27/75 - ADD STEPSPER; FIX NEXT RESETTING FOR STANDALONE
C     7/19/75 - NRNLIMS - LIMITS IN FM.                                  8180   
C     8/7/75  - FIT,DATA,ETC KEYWRDS ADDED
C     8/28/75 - LMAXMULT, LMINMULT, LBACK, SPFACP, SPFACT
C     9/24/75 - ADD CHANNEL, MAXLEXTRAP;  REMOVE VCUTOFF
C     9/30/75 - LMAXMULT BECOMES LMAXADD
C     10/1/75 - MORE FITTING STUFF
C     10/19/75 - MORE FITTERS; ESQ PARAMETERS; PARAM INSTEAD OF TEMP
C     11/6/75 - DERIVSTEP, MAXFUNCTIONS KEYWORDS; MORE FITTERS
C     1/29/76 - FITMULTI, FITRATIO, FITMODE % NUMRANDO KEYWORDS
C     4/30/76 - MODIFY INPUT TO PERMIT FOLDED COULOMB AND INCLUSION
C               OF NUCLEAR CORE TERMS IN VEFF (MHM)                      8190   
C     6/20/76 - SUMPOINTS KEYWORDS - S.P.
C     7/30/76 - KORFRE REMOVED.
C     9/15/76 - EPOWERS, EINVERSES KEYWORDS ADDED
C     11/7/76 - SAVEMXCR, SAVEB KEYWORDS; NEW KEEP
C     12/26/76 - INELASTIC SCATTERING; ALIAI; ALLOCATE REWRITTEN; NEWPAG
C     1/25/77 - LABANGLE SWITCH
C     2/5/77 - REALWAVE/COMPLEXWAVE ADDED; SAVEWAVE/NOSAVEWAVE REMOVED
C     4/15/77 - ALMXMT; LMINSB; ALIASES TO FITINP
C     10/16/77 - POWERS OF WOODS SAXONS
C     11/20/77 - BOUNDASYM, SCATASYM KEYWORDS ADDED - S.P.               8200   
C     11/25/77 - LINKULES
C     11/27/77 - GET - S.P.
C     12/6/77 - DO NOT PRINT ALLOC STATS FOR TSO - S.P.
C     12/10/77 - AUF DEUTSCH!; FIX PRINTWAVE BUG - S.P.
C     1/18/78 - BIG DATA AREAS BROKEN APART FOR CDC - S.P.
C     4/14/78 - PARAM6 - PARAM20 ADDED - S.P.
C     5/8/78 - SET NSPTSW; PROBLM IN /SWITCH/; SEPARATE LINTERP CALL
C     12/13/78 - ADD TENSOR POTENTIALS - RPG
C     5/6/79 - MXCGP, MXCGT, PARITIES - S.P.
C     6/14/79 - ALLOW MULTIPASS CALCULATIONS, REMOVE LAND,               8210   
C        STANDARD LABELS, CHARACTER TYPE, REWIND 1 BEFORT QUITTING - RPG
C     6/7/79 - DOCUMENT ARGUMENTS, FIX MULTIPASS STUFF - RPG
C     7/2/79 - SAVEF KEYWORDS REPLACE SAVEB WORDS - S.P.
C     7/22/79 - SMALL FIX - RPG
C     7/24/79 - NEW DUMP KEYWORDS AND NSDUMP CALL - S.P.
C     9/20/79 - UNDEFINE LX IN RETURN FROM MULTIPASS - RPG
C     11/10/79 - FIX ERROR AT STMNTS 750, 760 - S.P.
C     12/12/79 - ADD SCRFILE KEYWORD (/SWITCH/) - RPG
C     12/19/79 - COUPLED CHANNELS; FIX DOTEMPS - S.P.
C     1/17/80 - BFACTORS SWITCH - S.P.                                   8220   
C     2/22/80 - CONVRG SWITCH - S.P.
C     3/15/80 - DUMP IS NOT THE SAME AS DUMPR8;
C               MERGE IN FOLLOWING VAX CHANGES FROM BOB - S.P.
C     1/21/80 - CHARACTER*8 WORD; SPLIT OFF DATA FOR SWTNUM, SWTSET;
C        CVX TO CVA - RPG
C     2/5/80 - ADD "BLOCKSIZE", "TIMELIMIT" - RPG
