C
C     THE FOLLOWING TWO WORDS IN /SWITCH/ CONTROL THE COURSE OF
C     THE CALCULATION.
C
C     PROBLM - SPECIFIES THE PROBLEM BEING SOLVED:
C
C        5 (BOUNDSTATE) - STAND-ALONE BOUND STATE.
C        6 (SCATTERING) - STAND-ALONE ELASTIC SCATTERING.                8260   
C       20 (DWBA, NZRDWBA) - TRANSFER BY DWBA.
C       21 (FIT, FITELASTIC) - ELASTIC SCATTERING FIT
C       22 (INELASTIC) - EXCITATION BY COLLECTIVE DWBA
C       23 (COUPLE2) - 2-STATE COUPLED CHANNELS
C
C       IF PROBLM IS NOT EXPLICITLY SET BY ONE OF THE ABOVE KEYWORDS,
C       IT IS SET AS FOLLOWS:
C
C         1)  IF NO DWBA SUBCHANNELS (PROJECTILE, INCOMING, ETC.)
C           HAVE BEEN SPECIFIED, THE STAND-ALONE CALCULATION SUITABLE    8270   
C           FOR THE SPECIFIED ENERGY IS DONE.  IN THIS CASE PROBLM
C           IS LEFT UNDEFINED (0).
C         2)  OTHERWISE PROBLM IS SET TO 20 OR 22 DEPENDING ON
C           THE VALUE OF ISTRIP (THE MASS TRANSFER).
C
C     NEXT - SPECIFIES THE STEP OF THE CALCULATION THAT IS BEING DONE:
C
C        1 (PROJECTILE) - PROJECTILE BOUND-STATE FOR TRANSFER
C        2 (TARGET) - TARGET BOUND-STATE FOR TRANSFER
C        3 (INCOMING) - INCOMING SCATTERING FOR DWBA AND COUPLED         8280   
C        4 (OUTGOING) - OUTGOING SCATTERING FOR DWBA AND COUPLED
C       10 (GRIDSETUP) - DWBA GRID SETUP.
C       11 (RADIALINTEGRAL) - DWBA INTEGRALS; COUPLED CHANNELS.
C       12 (LINTERPOLATION) - L-INTERPOLATIONS.
C       13 (CROSSSECTIONS) - CROSS SECTIONS; IF NOT PRECEEDED BY 12
C           THEN BOTH 12 AND 13 ARE DONE.
C
C     IF NEXT IS NOT DEFINED (0) WHEN A ; IS ENCOUNTERED, IT IS SET TO
C     PROBLM.  IF THE RESULT IS THEN NON-ZERO, THE COMPLETE CALCULATION
C     SO SPECIFIED IS THEN DONE.  IF THE RESULT IS STILL ZERO, THE       8290   
C     DEFAULT CALCULATION AS OUTLINED UNDER PROBLM IS CHOOSEN AND
C     IS THEN DONE.
C
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
C
C     SOME WORDS IN /INTRNL/
C
C     UNDEF, NOTDEF - THE THINGS TO COMPARE AGAINST TO DETERMIN IF
C            SOMETHING IS NOT DEFINED.
C     ICHANB, ICHANW - CHANNEL NUMBER FOR BOUND AND SCATTERING STATES    8300   
C     IDONE - BITS THAT ARE TURNED ON AS THE CALCULATION PROGRESSES:
C      (1)  31 - PROJECTILE BOUND STATE
C      (2)  30 - TARGET BOUND STATE
C      (4)  29 - INCOMING SCATTERING
C      (8)  28 - OUTGOING SCATTERING
C     (16)  27 - DWBA OR INELASTIC CALCULATION (OR PIECE THEREOF)
C     (32)  26 - L INTERPOLATION
C     ISTRIP - -1 = PICKUP SCATTERING
C               0 = INELASTIC EXCITATION
C              +1 = STRIPPING SCATTERING                                 8310   
C     IHSAVE - 0 = NO SAVEHS/USEHS
C              1 = USEHS
C              2 = SAVEHS
C     IEXCIT - 1 = PROJECTILE EXCITATION
C              2 = TARGET EXCITATION
C
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
