     S  'DUMP8', 'DUMPR8', 'NSDUMP', 'DUMPR8', 'DUMPINTE', 'DUMPI4',
     T  'DUMPOCTA', 'DUMPHEX', 'DUMPHEXA', 'DUMPHEX',
     U  'DUMP4', 'DUMPR4', 'BETAPROJ', 'BETAP',
     V  'BETATARG', 'BETAT', 'MAXITERA', 'MAXITER',
     W  'TRANSITI', 'TRANSIST', 'TSO', 'INTERACT' /                      8560   
C
C
c
C
C     JGOTO IS USED TO RESUME AFTER RETURNING TO MAIN TO GET
C     SOMETHING DONE.
C
      GO TO ( 10, 990, 5, 750, 550, 740 ), JGOTO
C
C     INITIALIZE ON FIRST CALL                                           8570   
C
  5   CALL DEFALT ( NUMFLT, NUMINT, NUMJ, NUMSW, .FALSE. )
      CALL NEWCD
C
C
C  SEARCH FOR NEXT KEY
C
C     GET NEXT KEYWORD AND LOOK FOR IT IN THE VARIOUS TABLES
C     OF WORDS.
C                                                                        8580   
 10   CALL NXWORD( KYWORD, *925, *600, *925 )
C
C
 20   DO 29  I = 1, NUMFLT
         IF ( FLTWRD(I) .NE. KYWORD )  GO TO 29
         CALL NXVAL( VAL, *910, *910, *910 )
         FLOAT(I) = VAL
         GO TO 10
 29   CONTINUE
C                                                                        8590   
      DO 34  I = 1, NUMINT
         IF ( INTWRD(I) .NE. KYWORD )  GO TO 34
         CALL NXINT ( IVAL, *915, *915, *915 )
         INTGER(I) = IVAL
         GO TO 10
 34   CONTINUE
C
      DO 39  I = 1, NUMJ
         IF ( JWRDS(I) .NE. KYWORD )  GO TO 39
         CALL NXHINT ( IVAL, *920, *920, *920)                           8600   
         JBLOCK(I) = IVAL
         GO TO 10
 39   CONTINUE
C
      DO 44  I = 1, NUMSWW
         IF ( SWTWRD(I) .NE. KYWORD )  GO TO 44
         SWITCH(SWTNUM(I)) = SWTSET(I)
         GO TO 10
 44   CONTINUE
C                                                                        8610   
C     IF IT IS A CONTROL KEYWORD, DO IT NOW
C
      NSPTSW = MOD( IPRINT/100 000, 10 ) .GT. 1
C
      DO 69  I = 1, NUMKEY
         IF ( KEYWRD(I) .NE. KYWORD )  GO TO 69
         GO TO (
     1      110, 140, 270, 500, 510,
     2      150, 290, 280, 130, 160,
     3      236, 231, 200, 260, 420,                                     8620   
     4      350, 360, 480, 380, 120,
     5      233, 210, 250, 400, 430,
     6      300, 360, 530, 540, 220,
     7      320, 492, 496, 505, 470,
     8      360, 560, 560, 560, 560,
     9      560, 560, 295, 560, 560,
     A      560, 560, 560, 560, 232,
     B      234, 497, 498, 499, 570,
     C      230, 340, 360, 360, 560,
     D      300, 305                                                     8630   
     X                               ), I
 69   CONTINUE
C
C     IS THE WORD A SYNONUM.  IF SO START THE WHOLE SEARCH OVER AGAIN.
C
      DO 89  I = 1, NUMALI, 2
         IF ( ALIAI(I) .NE. KYWORD )  GO TO 89
         KYWORD = ALIAI(I+1)
         GO TO 20
 89   CONTINUE                                                           8640   
C
      write (6, 93) KYWORD
 93   FORMAT ( '0**** MISSPELLED KEYWORD: ', A8 )
      IF ( ITSO .EQ. 1 )  GO TO 980
      ASSIGN 955 TO JUMP
      VALSW = .FALSE.
      GO TO 125
C
C
C     LISTKEYS  (KEYWORD LIST WITHOUT VALUES)                            8650   
C
 110  VALSW = .FALSE.
      ASSIGN 10 TO JUMP
      GO TO 125
C
C     KEYWORDS    (LIST WORDS AND VALUES)
C
 120  VALSW = .TRUE.
      ASSIGN 10 TO JUMP
 125  CALL LSTKEY ( VALSW, NUMFLT, FLTWRD, NUMINT, INTWRD,               8660   
     1  NUMJ, JWRDS, NUMSWW, SWTWRD, SWTNUM, SWTSET,
     2  NUMKEY, KEYWRD, NUMALI, ALIAI )
      GO TO  JUMP, ( 10, 955 )
C
C     RESET - RESET KEYWORDS AND ALLOCATOR
C
 130  CALL DEFALT ( NUMFLT, NUMINT, NUMJ, NUMSW, .TRUE. )
      GO TO 280
C
C     RETURN                                                             8670   
C
 140  KEYRET=1
      IGOTO = 0
      IF ( IHSAVE .GT. 0 ) REWIND 1
      IF ( ITSO .EQ. 1 )  RETURN
      GO TO 215
C
C     PRINTFIT
C
 150  write (6, 153 ) E, V                                               8680   
 153  FORMAT ( ' ENERGY =', G16.7, 5X, 'V =', G16.7 )
      GO TO 10
C
C     PRINTWAVE
C
 160  WRITE(6, 163)
 163  FORMAT('    STEP       R          POT          WAVEFUNCTION')
      IF ( WRITES .EQ. UNDEF )  GO TO  175
      IF ( IPOT .EQ. 0 )  GO TO 170
      NWRITE = WRITES/STEPSZ + .5                                        8690   
      IF ( NWRITE .LT. 1 )  NWRITE = 1
      NSTEPS = BNDASY/STEPSZ + 1.5
      IF ( ASYMPT .NE. UNDEF )  NSTEPS = ASYMPT/STEPSZ + 1.5
      DO  169 III=1,NSTEPS,NWRITE
      RRR=(III-1)*STEPSZ
      WRITE(6,168)III,RRR, ALLOC(z(IPOT)+III-1),
     1  ALLOC(z(IWFN)+III-1)
168   FORMAT(' ',I6,F12.5, 2G15.5 )
 169  CONTINUE
      GO TO 10                                                           8700   
 170  write (6, 173)
 173  FORMAT ( '0**** PRINTWAVE CAN BE USED ONLY AFTER BOUNDSTATE' )
      GO TO 10
 175  WRITE(6, 178)
 178  FORMAT('0**** CANNOT---- WRITESTEP MUST BE SET NON-ZERO ')
      GO TO 10
C
C     NSCATALOG
C
 200  IF ( ICNTT .NE. 0 )  CALL NSCAT(IDUM)                              8710   
      GO TO 10
C
C     NSSTATUS
C
 210  KEYRET = 0
 215  IF ( ICNTT .NE. 0 )  CALL NSSTAT (IDUM)
      IF(KEYRET .NE. 1 )  GO TO 10
      TIME = second() - TBEGIN
      write (6, 218) TIME
 218  FORMAT ( '-TOTAL PTOLEMY CPU TIME =', F7.2, ' SECONDS.' )          8720   
      RETURN
C
C     DUMPALL
C
 220  CALL NSDUMP ( 0, 1 )
      GO TO 10
C
C     DUMPXX <NAME OR NUMBER>
C       WHERE XX IS ONE OF  8, R8, 4, R4, I4, I2, HEX, HEXADECIMAL,
C          OCTAL, INTEGER OR UNSPECIFIED.                                8730   
C          NSDUMP IS ALSO THE SAME AS DUMP.
C
C
 230  I = 1
      GO TO 240
 231  I = 2
      GO TO 240
 232  I = 3
      GO TO 240
 233  I = 4                                                              8740   
      GO TO 240
 234  I = 5
      GO TO 240
 236  I = 6
C
 240  CALL GETNUM( IDUM, *980 )
      CALL NSDUMP ( IDUM, I )
      GO TO 10
C
C     ALLOCATE <NAME> <COMPLETE LIST OF VALUES>                          8750   
C
 250  CALL NXWORD ( WORD, *930, *930, *930 )
      IF ( ICNTT .EQ. 0 )  CALL ISTART( ISIZE )
      ICNTT = 1
      CALL DEFINE ( WORD, NUM1, NUM2 )
      write (6, 253) NUM1, WORD
 253  FORMAT ( I8, ' NUMBERS READ TO DEFINE OBJECT ', A8 )
      IF ( NUM1 .GT. NUM2 )  GO TO 950
      GO TO 10
C                                                                        8760   
C     FREE <NAME OR NUMBER>
C
 260  CALL GETNUM ( NUM1, *980 )
      z(NUM1)=-z(NUM1)
      GO TO 10
C
C     RENAME  <NAME OR NUMBER>  <NEW NAME>
C
  270 CALL GETNUM ( NUM1, *950 )
      CALL NXWORD ( WORD, *930, *930, *930 )                             8770   
      NAMES(NUM1) = WORD
      GO TO 10
C
C     CLEAR
C
 280  IF ( ICNTT .NE. 0 )  CALL ICLEAR(IDUM)
         MAXLF = 0
      GO TO 10
C
C     KEEP  <NAME>  <MEMBER NAME>                                        8780   
C
 290  CALL KEEPIT                                                       csp
Cap 290  write (6, 293)
Cap 293  FORMAT ( '0**** SPEAKEASY KEEP NOT AVAILABLE IN this',
Cap     1  ' VERSION -- USE WRITENS.' )
Cap      GO TO 950
      GO TO 10
C
C     GET  <PTOLEMY NAME>   <MEMBER NAME>
C                                                                        8790   
 295  IF ( ICNTT .EQ. 0 )  CALL ISTART ( ISIZE )
      ICNTT = 1
      CALL GETIT ( IRET )                                               csp
      IF ( IRET )  950, 950, 10                                         csp
cap      write (6, 298)
Cap 298  FORMAT ( '0**** SPEAKEASY GET NOT AVAILABLE IN this VERSION.',
Cap     1  ' -- USE ALLOCATE.' )
Cap      GO TO 950
C
C     WRITENS, writens8, writens4 <NAME OR NUM>                          8800   
C     WRITES TO FILE 15
C
 300  keylen = 1
      go to 310
 305  keylen = 2
c
 310  CALL GETNUM ( ISEND, *980 )
      LLL = keylen*LENG(ISEND)
      WRITE(6, 313) ISEND, lll
 313  FORMAT(' NUMBERED STORAGE OBJECT ',I3, ' with', i7, ' elements',   8810   
     &  ' WRITTEN TO FT15 WITH', ' 5G14.5 FORMAT')
      LOCC = keylen*(z(ISEND)-1) + 1
      IF ( LLL .gt. 0 ) then
         if ( keylen .eq. 1 ) WRITE(15, 317)
     &      ( ALLOC(LOCC+III-1), III = 1 ,LLL )
         if ( keylen .eq. 2 ) WRITE(15, 317)
     &      ( ALLOC4(LOCC+III-1), III = 1 ,LLL )
 317     FORMAT(' ', 5G14.5)
      else
         WRITE(6, 318)                                                   8820   
 318     FORMAT('  Nothing to write!!' )
      endif
      GO TO 10
C
C     COPY  <NAME1 OR NUM1>  <NAME2>
C
 320  CALL GETNUM ( NUM1, *900 )
      INEED = LENG(NUM1)
      CALL NXWORD ( WORD, *900, *900, *900 )
C     IS THE "TO" AREA ALREADY DEFINED                                   8830   
      NUM2 = NAMLOC( WORD )
      IF ( NUM2 .EQ. 0 )  GO TO 325
C     YES, IS IT THE CORRECT SIZE
      LLL = LENG(NUM2)
      IF ( INEED .EQ. LLL )  GO TO 326
C     NO, FREE AND MAKE A NEW ONE
      write (6, 323) WORD, LLL, INEED
 323  FORMAT ( ' WARNING:  LENGTH OF ', A8, ' IS PRESENTLY', I6,
     1  ' BUT COPY IS CHANGING IT TO', I6 )
      z(NUM2) = -z(NUM2)                                                 8840   
 325  NUM2 = NALLOC( INEED, WORD )
 326  DO 329  I = 1, INEED
         ALLOC(z(NUM2)-1+I) = ALLOC(z(NUM1)-1+I)
 329  CONTINUE
      GO TO 10
C
C     CCDUMP
C
 340  CALL CCDUMP
      GO TO 10                                                           8850   
C
C     CALLTSO  KEYWORD ENTERED
C
 350  IGOTO = 3
      JGOTO = 1
      RETURN
C
C     DEFINE A KEYWORD THAT HAS A VARIABLE NUMBER OF VALUES.
C     THE VALUES ARE STORED IN THE ALOCATOR WITH THE KEYWORD NAME.
C                                                                        8860   
C     PRESENT CASES ARE BETA, BETAP, BETAT,  BETACOULOMB & BELX
C
 360  WORD = KYWORD
      IF ( ICNTT .EQ. 0 )  CALL ISTART( ISIZE )
      ICNTT = 1
      CALL DEFINE ( WORD, NUM1, NUM2 )
      IF ( NUM1 .GT. NUM2 )  GO TO 950
      GO TO 10
C
C     PARAMETERSET KEYWORD IS USED TO INITIALIZE PARAMETER PACKAGES      8870   
C
 380  CALL PARAM ( IGOTO )
      IF (IGOTO) 10, 900, 10
C
C     BIMULT <NAME OR NUM>  <NAME OR NUM>
C     OVERLAP OF TWO WAVEFUNCTIONS
C
  400 CALL GETNUM ( NUM1, *980 )
      CALL GETNUM ( NUM2, *980 )
      INEED=LENG(NUM1)                                                   8880   
      ITWO = LENG(NUM2)
      IF ( INEED .NE. ITWO )  write (6, 403 ) INEED, ITWO
 403  FORMAT ( '0*** WARNING: LENGTHS NOT EQUAL, THEY ARE',
     1  2I8, '.  THE SHORTER WILL BE USED.' )
      INEED = MIN0( INEED, ITWO )
      IALL=IALLOC(INEED)
      DO  409 II=1,INEED
 409  ALLOC(z(IALL)+II-1)=ALLOC(z(NUM1)+II-1)*ALLOC(z(NUM2)+II-1)
      WRITE(6, 413)INEED,NUM1,NUM2,IALL
 413  FORMAT(' HAVE MULTIPLIED TWO ',I5,'-ELEMENT ARRAYS ',I3,' AND',    8890   
     1  I3,' AND PUT THE RESULT IN ',I4)
      GO TO 10
C
C     NUMRNUM <NAME OR NUM>  <POWER>  <NAME OR NUM>
C     MATRIX ELEMENT OF A POWER OF R
C
 420  CALL GETNUM ( NUM1, *980 )
      CALL NXINT(IARE,*900,*900,*900)
      CALL GETNUM ( NUM2, *980 )
      ISTP1 = 1                                                          8900   
      INEED = LENG(NUM1)
      ITWO = LENG(NUM2)
      IF ( INEED .NE. ITWO )  write (6, 403) INEED, ITWO
      ISTP2 = MIN0( INEED, ITWO )
      GO TO 435
C
C      NRNLIMS <NAME OR NUM> <POWER> <NAME OR NUM> <START INDEX>
C                <END INDEX>
C     PARTIAL MATRIX ELEMENT OF R**N
C                                                                        8910   
 430  CALL GETNUM ( NUM1, *980 )
      CALL NXINT(IARE,*900,*900,*900)
      CALL GETNUM ( NUM2, *980 )
      CALL NXVAL( TEMP, *900, *900, *900)
      ISTP1 = TEMP/STEPSZ + 1.5
      CALL NXVAL( TEMP, *900, *900, *900)
      ISTP2 = TEMP/STEPSZ + 1.5
 435  WRITE(6, 438)NUM1,NUM2,IARE,ISTP1,ISTP2
 438  FORMAT(' AM CALCULATING ME BETWEEN OBJECTS',I3,' AND',I3,' OF R**'
     1  ,I1,' FROM STEPS',I5,' TO ',I5)                                  8920   
      AME=0.0D0
      LLLL = MIN0( LENG(NUM1), LENG(NUM2) )
      IF ( LLLL .GE. ISTP2 )  GO TO 445
      TEMP = STEPSZ*(LLLL-1)
      write (6, 443 ) TEMP
 443  FORMAT ( '0**** WARNING:  OBJECTS EXTEND ONLY TO R =', F10.2,
     1  ' FMS; WE WILL STOP AT END OF OBJECTS.' )
      ISTP2 = LLLL
 445  DO  449 II=ISTP1,ISTP2
      RRR=(II-1)*STEPSZ                                                  8930   
      TEMP = 1
      IF ( IARE .NE. 0 )  TEMP = RRR**IARE
      AME=AME + TEMP*STEPSZ*ALLOC(z(NUM1)+II-1)*ALLOC(z(NUM2)
     1  +II-1)
 449  CONTINUE
      WRITE(6, 453)AME
 453  FORMAT(/'        MATRIX ELEMENT =',E14.5/)
      GO TO 10
C
C     NEWPAGE                                                            8940   
C
 470  write (6, 473)
 473  FORMAT ( '1' )
      GO TO 10
C
C     UNDEFINE  < DATA KEYWORD >
C
 480  CALL NXWORD ( WORD, *900, *900, *900 )
      DO 482  I = 1, NUMFLT
         IF ( FLTWRD(I) .NE. WORD )  GO TO 482                           8950   
         FLOAT(I) = UNDEF
         GO TO 10
 482  CONTINUE
      DO 484  I = 1, NUMINT
         IF ( INTWRD(I) .NE. WORD )  GO TO 484
         INTGER(I) = NOTDEF
         GO TO 10
 484  CONTINUE
      DO 486  I = 1, NUMJ
         IF ( JWRDS(I) .NE. WORD )  GO TO 486                            8960   
         JBLOCK(I) = NOTDEF
         GO TO 10
 486  CONTINUE
      write (6, 488) WORD
 488  FORMAT ( '0**** ', A8, ' IS NOT A DATA-DEFINING KEYWORD.' )
      GO TO 950
C
C   FIT BEING SPECIFIED--- READ INPUT
C
 492  IF ( ICNTT .EQ. 0 )  CALL ISTART ( ISIZE )                         8970   
      ICNTT = 1
      CALL FITINP(IRET, NUMFLT, FLTWRD, NUMALI, ALIAI )
      PROBLM = 21
      GO TO 535
C
C     DATA ( ... )  READS IN DATA FOR FITTER
C
 496  IF ( ICNTT .EQ. 0 )  CALL ISTART ( ISIZE )
      ICNTT = 1
      CALL DATAIN(IRET)                                                  8980   
      GO TO 535
C
C     CHANNELS (...)  DEFINES CHANNS FOR COUPLED CHAN
C
497   IF(ICNTT.EQ.0)CALL ISTART(ISIZE)
      ICNTT=1
      CALL CCHAN(IRET)
      GO TO 535
C
C     COUPLING (...)  DEFINES THE COUPLING SCHEME AND SETS               8990   
C                     THE CCINELAS SWITCH
C
498   IF(ICNTT.EQ.0)CALL ISTART(ISIZE)
      ICNTT=1
      CALL CCOUP(IRET)
      PROBLM = 24
      GO TO 535
C
C     TRANSISTIONS (...)  DEFINES THE TRANSISITIONS TO USE
C                                                                        9000   
499   IF(ICNTT.EQ.0)CALL ISTART(ISIZE)
      ICNTT=1
      CALL CTRAN(IRET)
      GO TO 535
C
C     REACTION  208PB(16O, N15)BI209(1/2- 3.23)  TYPE INPUT
C
 500  CALL REACTN( IRET )
      GO TO 535
C                                                                        9010   
C     CHANNEL   P + 208PB = 209BI(7/2- .9)
C
 505  CALL CHANEL ( IRET )
      GO TO 535
C
C     HEADER < REST OF LINE IS HEADER >
C
 510  DO 514  I = 1, 65
 514  HEADER(I) = BLANK1
      DO 519  I = INCH, NOCH                                             9020   
      IF ( IBUF(I) .NE. BLANK1 )  GO TO 520
 519  CONTINUE
      GO TO 528
 520  NUM2 = MIN0( NOCH, I+64 )
      II = 0
      DO 524  INCH = I, NUM2
         IF ( IBUF(INCH) .NE. BLANK1 )  II = INCH
 524  CONTINUE
C
C     RIGHT JUSTIFY HEADER FOR PRINTING ON RIGHT SIDE OF PAGE            9030   
C
      DO 526  INCH = I, II
         HEADER(65-II+INCH) = IBUF(INCH)
 526  CONTINUE
 528  INCH = NOCH + 1
      GO TO 10
C
C     SAVEHS
C
 530  CALL SAVEHS( IRET )                                                9040   
CDC 530  CALL SAVEHS ( NUMFLT, FLOAT, NUMINT, INTGER, NUMJ,
CDC     1  JBLOCK, NUMSW, SWITCH, IRET )
 535  IF ( IRET )  10, 950, 10
C
C     USEHS
C
 540  IRET = 1
 545  CALL USEHS ( NUMFLT, FLOAT, NUMINT, INTGER, NUMJ, JBLOCK,
     1  NUMSW, SWITCH, IRET )
      IF ( IRET )  10, 950, 547                                          9050   
C
C     ARE WE STILL PROCESSING BOUND STATE
C
 547  JGOTO = 5
      IF ( NEXT .LE. 2 )  GO TO 720
      NEXT = 0
C     INDICATE BOTH BOUND STATES DONE
      IDONE = 3
      IF ( IBSPAS .GT. 1 )  IDONE = 15
      GO TO 10                                                           9060   
C
C     DONE WITH A READIN BOUND STATE; GET NEXT SET OF COMMON BLOCKS
C
 550  IRET = 2
      GO TO 545
C
C     REALPOTEN <NAME>  ,  IMAGPOTEN <NAME>   , ETC.
C
 560  CALL GETLNK ( KYWORD, IRET )
      IF ( IRET )  950, 950, 10                                          9070   
C
C     TIMELIMIT (VAX/VMS ONLY)
C
 570  CALL NXVAL( TEMP, *900, *900, *900 )
CVA      CALL TLIMIT( TEMP )
      write (6, 573)                                                    cnv
 573  FORMAT ( '0**** TIMELIMIT IS NOT IN THIS VERSION.  IGNORED.' )    cnv
      GO TO 10
C
C                                                                        9080   
C     ; ENCOUNTERED.  DO A STAGE OF THE CALCULATION
C
 600  NSPTSW = MOD( IPRINT/100 000, 10 ) .GT. 0
      IF(ICNTT.EQ.0)CALL ISTART(ISIZE)
      ICNTT=1
C
C  NUMBERED STORAGE INITIALIZED
C  NOW ON OUR WAY
C
C     NOW DETERMINE WHAT TO DO FOR THE ;                                 9090   
C
      IF ( NEXT .EQ. 0 )  NEXT = PROBLM
      IF ( NEXT .NE. 0 )  GO TO 700
C
C     HE DIDN'T SPECIFY; EITHER FINISH A DWBA OR DO A STAND ALONE
C     CHANNEL.
C
      IF ( IDONE .GT. 0 )  GO TO 650
C
C     IT IS STAND ALONE                                                  9100   
C
      IF ( E .NE. UNDEF )  GO TO 630
      IF ( ELAB .NE. UNDEF  .OR.  ECM .NE. UNDEF )  GO TO 635
      write (6, 623)
 623  FORMAT ( '0**** E OR ELAB OR ECM MUST BE SPECIFIED.' )
      GO TO 950
 630  NEXT = 5
      IF ( E .LT. 0 )  GO TO 700
 635  NEXT = 6
      GO TO 700                                                          9110   
C
C     ASSUME (FOR THE MOMENT) THAT ALL 2-BODY CHANNELS ARE
C     DEFINED AND START A TRANSFER OR INELASTIC SCATTERING CALCULATION
C
 650  NEXT = 20
      IF ( ISTRIP .EQ. 0 )  NEXT = 22
      PROBLM = NEXT
C
C     NEXT SAYS WHAT TO DO NEXT
C                                                                        9120   
 700  IF ( NEXT .GE. 10 )  GO TO 770
C
C     INITIALIZE A CHANNEL AND ITS POTENTIAL
C
      CALL SETCHN ( NEXT, IRET )
      IF ( IRET .EQ. 0 )  GO TO 995
      CALL SETPOT ( IRET )
      IF ( IRET .EQ. 0 )  GO TO 995
C
C     NOW DO BOUND STATE OR SCATTERING.  UPON RETURN CLEAR MANY          9130   
C     DEFINITIONS
C
      JGOTO = 4
 720  IGOTO = 1
      GO TO ( 722, 724, 726, 728, 730, 732, 900, 736 ), NEXT
C     PROJECTILE
 722  ICHANB = 1
      RETURN
C     TARGET
 724  ICHANB = 2                                                         9140   
      RETURN
C     INCOMING
 726  ICHANW = 1
      IGOTO = 5
      RETURN
C     OUTGOING
 728  ICHANW = 2
      IGOTO = 5
      RETURN
 730  ICHANB = ICHANB + 1                                                9150   
      RETURN
 732  ICHANW = ICHANW + 1
      IGOTO = 13
      RETURN
C
C********   THIS METHOD OF GETTING TO FITTER NOT USED
C
736   ICHANW=1
      IGOTO=2
      RETURN                                                             9160   
C
C     WE HAVE RETURNED FROM A PASS OF A MULTIPASS CALCULATION.
C     PREPARE FOR NEW BOUND STATE PARAMETERS.
C
 740  NEXT = 0
      IDONE = 31
      IBSPAS = 2
      LX = NOTDEF
      IRET = 3
      IF ( IHSAVE .EQ. 2 )  GO TO 545                                    9170   
      GO TO 760
C
C     WE HAVE RETURNED FROM A BOUND STATE OR SCATTERING STATE
C
 750  IRET = 1
      IF ( IPRM1 .EQ. 0 )  GO TO 760
      IF ( NEXT .LE. 4 )  IDONE = ior( IDONE, 2**(NEXT-1) )
      IF ( E .GT. 0 )  GO TO 760
      IPOT = IPRM2
      IWFN = IPRM3                                                       9180   
      IF ( IHSAVE .EQ. 1 )  CALL SAVECM ( NUMFLT, FLOAT, NUMINT, INTGER,
     1  NUMJ, JBLOCK, NUMSW, SWITCH, IRET )
 760  CALL CLRCHN( NEXT )
      IF ( IPRM1 .EQ. 0 )  GO TO 995
      IF ( IRET .EQ. 0 )  GO TO 950
 765  NEXT = 0
      GO TO 10
C
C     WE ARE NOW DOING THINGS SUBSEQUENT TO THE CHANNEL INPUT
C                                                                        9190   
 770  JGOTO = 2
      IF ( NEXT .EQ. 21 )  GO TO 780
      IF ( NEXT .LT. 30 )  GO TO 800
C
C     THIS IS A DOTEMP CALL
C
      IGOTO = NEXT - 20
      RETURN
C
C     START ELASTIC SCATTERING FIT                                       9200   
C
 780  IGOTO = 2
      JGOTO = 4
      RETURN
C
C     CARRY ON WITH THE DWBA OR C.C. IF ALL CHANNELS WERE DEFINED.
C
 800  IF ( ISTRIP .EQ. 0 )  GO TO 805
      IF ( PROBLM .EQ. 0 )  PROBLM = 20
      IF ( IBSPAS .GT. 0 ) JGOTO = 6                                     9210   
      IF ( MOD(IDONE, 16) .EQ. 15 )  GO TO 810
      write (6, 803)
 803  FORMAT ( '0**** PROJECTILE, TARGET, INCOMING AND OUTGOING',
     1  ' CHANNELS MUST ALL BE DEFINED' )
      GO TO 950
 805  IF ( PROBLM .EQ. 0 )  PROBLM = 22
      IF ( MOD(IDONE/4, 4) .EQ. 3 )  GO TO 810
      write (6, 808)
 808  FORMAT ( '0**** INCOMING AND OUTGOING CHANNELS MUST BE',
     1  ' DEFINED FOR INELASTIC EXCITATION.' )                           9220   
      GO TO 950
C
 810  IF ( NEXT .GE. 20 )  GO TO 850
C
C     HE IS DOING IT IN PIECES AND WE DON'T CHECK MUCH
C
      IDONE = ior( IDONE, 16 )
      IGOTO = NEXT - 4
      IF ( NEXT .EQ. 10 )  GO TO 870
C                                                                        9230   
C     IF CROSSSECTIONS IS SPECIFIED, IT IMPLIES LINTERPOLATION ALSO
C     UNLESS THAT HAS JUST BEEN DONE.
C
      IF ( NEXT .EQ. 13  .AND.  MOD(IDONE/32, 2) .EQ. 0 )  IGOTO = 15
      IF ( NEXT .EQ. 12 )  IDONE = ior( IDONE, 32 )
      RETURN
C
C     DO THE WHOLE THING; DON'T ALLOW REPEATS (EXCEPT MULTIPASS)
C
 850  IF ( MOD(IDONE/16, 2) .EQ. 0 )  GO TO 860                          9240   
      IF ( IBSPAS .GT. 0 ) GO TO 855
      write (6, 853)
 853  FORMAT ( '0**** YOU ARE REQUESTING THINGS OUT OF ORDER')
      GO TO 950
 855  IBSPAS = 2
      IDONE = MOD(IDONE, 16)
 860  IGOTO = 14
C
C     FOR SAVEHS SAVE COMMONS AT ENTRY TO GRDSET
C                                                                        9250   
 870  IRET = 1
      IF ( IHSAVE .EQ. 1 )  CALL SAVECM ( NUMFLT, FLOAT, NUMINT, INTGER,
     1  NUMJ, JBLOCK, NUMSW, SWITCH, IRET )
      IF ( IRET .EQ. 0 )  GO TO 950
      RETURN
C
C
C     ERRORS DETECTED, FOR TSO KEEP GOING, FOR BATCH QUIT
C
900   WRITE(6, 903)  KYWORD                                              9260   
 903  FORMAT('0****         ------  INPUT ERROR  -------' /
     1  ' KEYWORD BEING PROCESSED WAS  ', A8 / )
      GO TO 950
C
 910  write (6, 913) KYWORD
 913  FORMAT ( '0**** A NUMERIC DATA VALUE MUST FOLLOW THE ', A8,
     1  ' KEYWORD.' )
      GO TO 950
 915  write (6, 918) KYWORD
 918  FORMAT ( '0**** AN INTEGER DATA VALUE MUST FOLLOW THE ', A8,       9270   
     1  ' KEYWORD.' )
      GO TO 950
 920  write (6, 923) KYWORD
 923  FORMAT ( '0**** AN INTEGER OR HALF-INTEGER DATA VALUE MUST ',
     1  'FOLLOW THE ', A8, ' KEYWORD.' )
      GO TO 950
 925  III = INCH - 1
      write (6, 928) ( IBUF(I), I = 1, III )
 928  FORMAT ( '0**** INVALID FIELD ENCOUNTERED WHEN LOOKING FOR A',
     1  ' KEYWORD.' /                                                    9280   
     2  6X, 'INPUT UP TO ERROR IS: ', 80A1 )
      GO TO 950
 930  write (6, 933) KYWORD
 933  FORMAT ( '0**** A NAME MUST FOLLOW THE ', A8, ' KEYWORD.' )
      GO TO 950
C
 950  IF(ITSO.EQ.1) GO TO 980
C
C     IN BATCH, GIVE A LIST OF EVERYTHING AND TERMINATE
C                                                                        9290   
      VALSW = .TRUE.
      ASSIGN 955 TO JUMP
      GO TO 125
 955  IF ( ICNTT .NE. 0 )  CALL NSCAT ( IDUM )
      IF ( IHSAVE .GT. 0 ) REWIND 1
      STOP 1230
C
C     IN TSO GIVE HIM ANOTHER TRY
C
 980  write (6, 983)                                                     9300   
 983  FORMAT (' ***** CONTINUING WITH NEXT INPUT LINE **** ' /)
      CALL NEWCD
      GO TO 10
C
C     CHECK RETURN CODE AFTER A STEP OF THE CALCULATION
C
 990  IF ( IPRM1 .NE. 0 )  GO TO 765
 995  write (6, 998)
 998  FORMAT ( '0**** ERROR DETECTED IN PREVIOUS STEP.'/)
      GO TO 950                                                          9310   
C
      END
C*ID* COULIN   C109.PTOLEMY.SOURCE                          PER701  11:
      SUBROUTINE COULIN ( N, MAXDEL, LMIN, LMAX, ETAOUT, AKOUT, SIGOUT,
     1  ETAIN, AKIN, SIGIN, R, ALLSW, FF, FG, GF, GG, LDLDIM,
     2  ACCURA, ASMULT, NTERMS, NPTS,
     3  WORK, FI, FO, GI, GO, STARTS,
     4  IPRINT, IRET, CLTIME )
C
C     COULOMB INTEGRALS BY RECURSION                                     9320   
C
C     COMPUTES
C
C       FF = INTEGRAL( R TO INF ) DR F(LOUT,ETAOUT,KOUT*R)
C            * F(LIN,ETAIN,KIN*R) / R**N
C
C     AND SIMILARLY FOR FG, GF, AND GG  FOR
C
C       LMIN =< (LOUT+LIN)/2 =< LMAX
C       -MAXDEL =< LIN-LOUT =< MAXDEL                                    9330   
C
C     THESE ARE STORED AS
C
C       FF( (LIN-LOUT+MAXDEL)/2+1, LIN+LOUT-2*LMIN+1 )
C
C     WHICH MEANS THAT  FF(ID,IL)  CORRESPONDS TO
C
C       LIN  = (IL+2*LMIN+MAXDEL)/2 + ID-1 - MAXDEL
C       LOUT = (IL+2*LMIN-1+MAXDEL)/2 + 1-ID
C            = IL+2*LMIN-1 - LIN   .                                     9340   
C
C     WE SEE THAT
C
C       1  =<  IL  =<  2*(LMAX-LMIN) + 1
C       1  =<  ID  =<  MAXDEL + MOD(MAXDEL+IL, 2)
C
C     SO THAT ONE MUST HAVE
C
C       DIMENSION  FF( LDLDIM, 2(LMAX-LMIN)+1 )
C     WITH                                                               9350   
C       LDLDIM >= MAXDEL+1
C
C     ALSO THE METHOD WILL WORK ONLY FOR MAXDEL >= 2 SO MAXDEL = 2
C     WILL BE ASSUMED IF MAXDEL = 0 OR 1.
C
C     ARGUMENTS:
C
C     N - INVERSE POWER OF R TO INCLUDE IN THE INTEGRALS.
C     MAXDEL - MAXIMUM RANGE OF LIN-LOUT.
C     LMIN, LMAX - MAXIMUM RANGE OF THE AVERAGE OF LIN AND LOUT.         9360   
C     ETAOUT, AKOUT - COULOMB PARAMETER AND WAVENUMBER IN OUTGOING
C             STATE.
C     SIGIN - SUPPLIED ARRAY OF COULOMB PHASE SHIFTS FOR INGOING
C              CHANNEL FOR
C                LMIN-MAXDEL =< L =< LMAX+MAXDEL
C              WITH INDEX  L+1 .
C     ETAIN, AKIN - COULOMB PARAMETER AND WAVENUMBER IN INCOMING
C             STATE.
C     SIGOUT - SUPPLIED ARRAY OF COULOMB PHASE SHIFTS FOR OUTGOING
C              CHANNEL FOR                                               9370   
C                LMIN-MAXDEL =< L =< LMAX+MAXDEL
C              WITH INDEX  L+1 .
C     R - STARTING POINT FOR THE INTEGRAL.  R >= 0.
C     ALLSW = .TRUE. MEANS ALL FOUR TYPES OF INTEGRAL ARE COMPUTED.
C                    IN THIS CASE  R > 0  IS REQUIRED.
C           = .FALSE. MEANS FIND ONLY FF.  IN THIS CASE FG, GF, AND GG
C              NEED BE ONLY SCALARS.
C     FF, FG, GF, GG - OUTPUT ARRAYS DIMENSIONED AS DESCRIBED ABOVE.
C     LDLDIM - FIRST DIMENSION OF THE ABOVE 4 ARRAYS.
C     ACCURA - APPROXIMATE DESIRED ACCURACY.  AN ERROR MESSAGE WILL BE   9380   
C              PRINTED IF THE FINAL ERROR EXCEEDS 10*ACCURA
C     ASMULT, NTERMS, NPTS - PARAMETERS FOR CLINTS WHICH SEE.
C     WORK - WORK ARRAY OF DIMENSION
C             MAX( 2*LMAX+2*MAXDEL+1, 2*NPTS+LMAX+MAXDEL,
C                  2*NPTS+4*NTERMS ) + 1
C     FI, FO, GI, GO - WORK ARRAYS OF DIMENSION
C            MAX( LMAX+MAXDEL, 4*NTERMS ) + 1
C     STARTS - WORK ARRAY OF DIMENSION  16*LDLDIM .
C     IPRINT = 0 SUPPRESSES DIAGNOSTIC PRINT OUT.
C            = 1 CAUSES SOME PRINT OUT FROM COULIN.                      9390   
C            >= 2 CAUSES INCREASING AMOUTS OF PRINTOUT FROM CLINTS.
C     IRET - A RETURN CODE:
C          = 0 MEANS ALL WENT WELL.
C          =< -10  MEANS AN ERROR WAS DETECTED IN COULIN.
C          -9 =< IRET < 0  MEANS CLINTS DETECTED TROUBLE.
C          > 0 MEANS A FAILURE IN RCWFN.
C     CLTIME - THE TIME (IN SECONDS) SPENT IN CLINTS.
C
C
C     12/10/76 - FIRST VERSION - S. PIEPER                               9400   
C     1/27/77 - FF DONE FORWARD FOR R > 0.
C     3/9/77 - ALLOW VERY SMALL RHO IN THE NUMERIC INWARDS INTEGRAL
C     6/27/78 - DIAGNOSTIC PRINTOUTS
C     5/11/79 - DO NOT ASSUME KIN*ETAIN = KOUT*ETAOUT - S.P.
C               KEEP CLINTS TIME IN CLTIME.
C     12/27/79 - CIB TO CND PREFIX - RPG
C     7/31/80 - USE ACCURA AS LOWER POINT OF INWARDS INTEGRAL - S.P.
C     4/13/87 - LIMIT ACCURACY REQUIRED OF CLINTS FOR R=0 - S.P.
C
C                                                                        9410   
      IMPLICIT REAL*8 ( A-H, O-Z )
C
      DIMENSION SIGIN(1), SIGOUT(1)
      DIMENSION FF(LDLDIM,1), FG(LDLDIM,1), GF(LDLDIM,1), GG(LDLDIM,1)
      DIMENSION FI(1), FO(1), GI(1), GO(1), WORK(1)
      DIMENSION STARTS(LDLDIM, 2, 4, 2)                                 cnd
CDC      DIMENSION STARTS(LDLDIM, 2, 8)
CDC%'STARTS(#,#,#,#)' = 'STARTS(#1,#2,#3+4*#4-4)';;
C
CDC      ALLOCLEVEL SIGIN, SIGOUT, FF, FG, GF, GG, FI, FO,               9420   
CDC     1  GI, GO, WORK, STARTS
C
      DIMENSION  RTURNS(2), RMINS(2), ACCS(2)
      LOGICAL ALLSW
C
      MXDEL = MAX0(2, MAXDEL)
      LMAXMX = LMAX+MXDEL
      LMINMN = MAX0(0, LMIN-MXDEL)
      IF ( LDLDIM .GT. MXDEL )  GO TO 20
C     LDLDIM TOO SMALL                                                   9430   
      IRET = -10
      RETURN
 20   MMXDEL = -MXDEL
      DN = N
      NTRM = MAX0( NTERMS, LMAX/4 )
C
C     FOLLOWING IS AN ATTEMPT TO ALLOW FOR LOSS OF ACCURACY
C
      ACC = ACCURA * DEXP( 10 - 5*N - 2*DABS(ETAIN-ETAOUT)
     1      - (LMAX-LMIN)/100. )                                         9440   
      ACC = DMAX1( ACC, 1.D-12, ACCURA*.01 )
C
C     IF THE INTEGRAL IS TO BE FROM 0, FIND A SUITABLE STARTING
C     POINT
C
      RMINS(1) = R
      RMINS(2) = R
      ACCS(1) = ACC
      ACCS(2) = .01*ACCURA
      IF ( R .GT. 0 )  GO TO 50                                          9450   
      ACCS(1) = .1*ACCURA
      ACCS(2) = .1*ACC
      IF ( .NOT. ALLSW )  GO TO 30
      IRET = -12
      RETURN
 30   RTURNS(1) = DMAX1( (ETAIN+DSQRT(ETAIN**2+LMINMN*(LMINMN+1)))/AKIN,
     1  (ETAOUT+DSQRT(ETAOUT**2+LMINMN*(LMINMN+1)))/AKOUT )
      RTURNS(2) = DMAX1( (ETAIN+DSQRT(ETAIN**2+LMAXMX*(LMAXMX+1)))/AKIN,
     1  (ETAOUT+DSQRT(ETAOUT**2+LMAXMX*(LMAXMX+1)))/AKOUT )
      IF ( IPRINT .GE. 1 )  write (6, 33) RTURNS                         9460   
 33   FORMAT ( ' RTURN''S =', 2G12.4 )
C
C     WE DO THE NUMERIC INTEGRAL MORE EFFICENTLY HERE SINCE WE DO
C     ALL OF THEM AT ONCE.  SO FORCE CLINTS RIGHT TO THE PLACE WHERE
C     IT STARTS TO USE RCASYM.
C
      RMINS(1) = 1.4*RTURNS(1)
      RMINS(2) = 1.4*RTURNS(2)
C
C     GET STARTING VALUES FOR RECURSIONS AND FINAL VALUES                9470   
C     TO CHECK THE STABILITY OF THE RECURSIONS.
C
 50   LS = 2*LMIN
      IF ( IPRINT .GE. 1 )  write (6, 53) ACCS
 53   FORMAT ( ' REQUESTED CLINTS ACCURACIES ARE', 2G13.3 )
C
C     FOR RECURSION UPWARDS WE WILL NEED TO START WITH A
C     FULL WIDTH SET.  ALSO THE DOWNWARDS RECURSION CAN NOT GO
C     BENEATH  LIN+LOUT = N-2  EVEN THOUGH FOR R > 0 THE RESULTS
C     WILL STILL BE FINITE.  THEREFORE WE GENERATE ALL THESE SMALL       9480   
C     L VALUES NUMERICALLY.
C
      ISTOPR = MAX0( N-2*LMIN, 2 )
      IF ( ALLSW )  ISTOPR = MAX0( MXDEL+1-2*LMIN, ISTOPR )
      ISTOP = ISTOPR
      LSUMMN = 2*LMIN+1 + ISTOPR-2
      LSUMMX = 2*LMAX-1
C
      TT = second()
      DO 79  II = 1, 2                                                   9490   
C
C     LIN+LOUT = LS+I-1
C
         DO 69  I = 1, ISTOP
            IL = LS-2*LMIN+I
            MD = MXDEL + MOD(MXDEL+IL, 2 )
            IS = 1
            IF ( I .EQ. ISTOP )  IS = 2
            DO 59  ID = 1, MD
               LIN = (LS+I+MXDEL)/2 + ID-1 - MXDEL                       9500   
               LOUT = LS+I-1 - LIN
               IF ( LIN .LT. 0  .OR.  LOUT .LT. 0 )  GO TO 59
               A = ASMULT
               CALL CLINTS ( RMINS(II), ETAIN, ETAOUT, AKIN, AKOUT,
     1           SIGIN(LIN+1), SIGOUT(LOUT+1),
     1           ACCS(II), A, STARTS(ID,IS,1,II), STARTS(ID,IS,2,II),
     2           STARTS(ID,IS,3,II), STARTS(ID,IS,4,II),
     2           WORK, WORK(NPTS+1), FI, FO, GI, GO, WORK(2*NPTS+1),
     3           N, LIN, LOUT, NTRM, NPTS, IRET, IPRINT )
               IF ( IRET .NE. 0 )  RETURN                                9510   
 59         CONTINUE
C
C
C     SAVE END OF THE FF RECURSION AND
C     STORE START OF FG, GF, GG STUFF
C
            DO 64  ID = 1, MD
               FF(ID,IL) = STARTS(ID,IS,1,II)
               IF ( .NOT. ALLSW )  GO TO 64
               FG(ID,IL) = STARTS(ID,IS,2,II)                            9520   
               GF(ID,IL) = STARTS(ID,IS,3,II)
               GG(ID,IL) = STARTS(ID,IS,4,II)
 64         CONTINUE
C
 69      CONTINUE
         LS = 2*LMAX - 1
         ISTOP = 2
 79   CONTINUE
C
      CLTIME = second() - TT                                             9530   
C
      IF ( R .NE. 0 )  GO TO 400
C
C     HERE WE DO THE INTEGRAL  0 < R < 1.4*RTURN  BACKWARDS UNTIL
C     WE COME TO INSIGNIFICANT CONTRIBUTIONS.
C
      DELTA = 3.1/AKIN
      ISTOP = ISTOPR
      LMN = LMINMN
      LMX = LMIN + (ISTOP+MXDEL+1)/2                                     9540   
      LS = 2*LMIN
      DO 169  II = 1, 2
         RTOP = RMINS(II)
 110     RBOT = DMAX1( 0.D0, RTOP-DELTA )
         IF ( RBOT .GE. RTOP )  GO TO 165
         B = RTOP - RBOT
         DO 159  IPT = 1, NPTS
            RVAL = RTOP - .5*B*(1+WORK(IPT))
            CALL RCWFN( AKIN*RVAL, ETAIN, LMN, LMX, FI, FO,
     1         GI, GO, 1.D-8, IRET )                                     9550   
            IF ( IRET .NE. 0  .AND.  IRET .NE. 2 )  GO TO 900
            IF ( DABS(FI(LMN+1)) .LT. ACCURA  .AND.
     1       RVAL .LT. RTURNS(II) )  GO TO 165
            CALL RCWFN ( AKOUT*RVAL, ETAOUT, LMN, LMX, FO, GI,
     1         GO, WORK(2*NPTS+1), 1.D-8, IRET )
            IF ( IRET .NE. 0  .AND.  IRET .NE. 2 )  GO TO 900
            IF ( DABS(FO(LMN+1)) .LT. ACCURA  .AND.
     1        RVAL .LT. RTURNS(II) )  GO TO 165
            X = .5*B*WORK(NPTS+IPT)/RVAL**N
            DO 149  I = 1, ISTOP                                         9560   
               IL = LS-2*LMIN+I
               MD = MXDEL + MOD(MXDEL+IL, 2)
               IS = 1
               IF ( I .EQ. ISTOP )  IS = 2
               DO 149  ID = 1, MD
                  LIN = (LS+I+MXDEL)/2 + ID-1-MXDEL
                  LOUT = LS+I-1 - LIN
                  IF ( LIN .LT. 0  .OR.  LOUT .LT. 0 )  GO TO 149
                  A = X*FI(LIN+1)*FO(LOUT+1)
                  FF(ID,IL) = FF(ID,IL) + A                              9570   
                  STARTS(ID,IS,1,II) = FF(ID,IL)
 149        CONTINUE
 159     CONTINUE
         RTOP = RBOT
         RVAL = RBOT
         GO TO 110
 165     RMINS(II) = RVAL
         LS = 2*LMAX-1
         ISTOP = 2
         LMN = (LS-MXDEL-1)/2                                            9580   
         LMX = LMAXMX
 169  CONTINUE
C
      CLTIME = second() - TT
C
      IF ( IPRINT .GE. 1 )  write (6, 173) RMINS
 173  FORMAT ( ' RMIN''S = ', 2G12.4 )
      MD = MXDEL + 1
      IF ( IPRINT .GE. 2 )  write (6, 177) ((STARTS(ID,IS,1,2),
     1   ID = 1, MD), IS = 1, 2 )                                        9590   
 177  FORMAT ( '0FF STARTING VALUES:' / ( 3G20.10 ) )
C
C
C     RECURSE DOWNWARD FOR FF
C     WE GO FROM  LSUM  TO  LSUM-1  AND GENERATE ALL THE
C     LIN-LOUT FOR EACH LSUM.
C
      DO 399  LS = LSUMMN, LSUMMX
         LSUM = LSUMMX+LSUMMN-LS
         DO 299  LDEL = MMXDEL, MXDEL                                    9600   
C
C     LIN, LOUT POINT TO THE CORNER WE WILL EXTRAPOLATE FROM
C
            LIN = (LSUM-LDEL)
            IF ( LIN .LT. 0 )  GO TO 299
            LIN = LIN/2
            LOUT = (LSUM+LDEL)/2
            IF ( LSUM .NE. LIN+LOUT )  GO TO 299
            LOUTP = LOUT-1
            IF ( IABS(LIN-LOUTP) .GT. MXDEL )  GO TO 299                 9610   
            IF ( LOUTP .LT. 0  )  GO TO 299
            IF ( IABS(LOUT+1-LIN) .GT. MXDEL )  GO TO 299
C
C     LIN, LOUT-1  IS NEEDED AND WE HAVE ALL THE STUFF NEEDED TO
C     FIND IT. BY RECURSION DOWNWARD ON LOUT.
C
            DLI = LIN
            DLO = LOUT
            ID = (LIN-LOUT+MXDEL) + 2
            IL = LIN+LOUT-2*LMIN+1                                       9620   
            ID2 = (ID+1)/2
            ID = ID/2
C
            E = (2*DLO+1)/((DLI+DLO-DN+2)*DSQRT(DLO**2+ETAOUT**2))
            A = ETAOUT * (DLI-DN+2)/(DLO+1)
     1          - (ETAIN*(AKIN/AKOUT)) * DLO/(DLI+1)
            B = (AKIN/AKOUT)*(DLO/(DLI+1))*DSQRT((DLI+1)**2+ETAIN**2)
            C = DLO*(DLO-DLI+DN-1)*DSQRT((DLO+1)**2+ETAOUT**2)
     1              / ((DLO+1)*(2*DLO+1))
            FF(ID2,IL-1) = E*( A*FF(ID,IL) + C*FF(ID2-1,IL+1)            9630   
     1             + B*FF(ID2,IL+1) )
 299     CONTINUE
C
C     DLI, DLO, ETC, REFER TO THE LAST CASE FOR WHICH WE REDUCED
C     LOUT.  NOW REDUCE LIN FOR THAT SAME CASE TO COMPLETE THE
C     GENERATION OF LSUM-1 FROM LSUM.
C
         IF ( DLI .LE. 0 )  GO TO 399
C
         E = (2*DLI+1)/((DLI+DLO-DN+2)*DSQRT(DLI**2+ETAIN**2))           9640   
         A = ETAIN * (DLO-DN+2)/(DLI+1)
     1       - (ETAOUT*(AKOUT/AKIN)) * DLI/(DLO+1)
         B = (AKOUT/AKIN)*(DLI/(DLO+1))*DSQRT((DLO+1)**2+ETAOUT**2)
         C = DLI*(DLI-DLO+DN-1)*DSQRT((DLI+1)**2+ETAIN**2)
     1          / ((DLI+1)*(2*DLI+1))
         FF(ID2-1,IL-1) = E*( A*FF(ID,IL) + B*FF(ID2-1,IL+1)
     1       + C*FF(ID2,IL+1) )
C
 399  CONTINUE
C                                                                        9650   
      GO TO 800
C
C     GET THE INHOMO TERMS
C
 400  TT = second()
C
      CALL RCWFN ( AKIN*R, ETAIN, LMINMN, LMAXMX, FI, WORK,
     1  GI, WORK(LMAXMX+1), 1.D-14, IRET )
      IF ( IRET .NE. 0 )  GO TO 910
      CALL RCWFN ( AKOUT*R, ETAOUT, LMINMN, LMAXMX, FO, WORK,            9660   
     1  GO, WORK(LMAXMX+1), 1.D-14, IRET )
      IF ( IRET .NE. 0 )  GO TO 910
C
      CLTIME = CLTIME + second()-TT
C
C     RECURSE UPWARDS ON FG, GF, AND GG. AND FF WHEN R > 0.
C
      DO 599  LSUM = LSUMMN, LSUMMX
         DO 499  LDEL = MMXDEL, MXDEL
C                                                                        9670   
C     LIN, LOUT POINT TO THE CORNER WE WILL EXTRAPOLATE FROM
C
            LIN = (LSUM+LDEL)/2
            LOUT = (LSUM-LDEL)/2
            IF ( LSUM .NE. LIN+LOUT )  GO TO 499
            LOUTP = LOUT+1
            IF ( IABS(LIN-LOUTP) .GT. MXDEL )  GO TO 499
            IF ( IABS(LOUT-1-LIN) .GT. MXDEL )  GO TO 499
C
C     LIN, LOUT+1  IS NEEDED AND WE HAVE ALL THE STUFF NEEDED TO         9680   
C     FIND IT. BY RECURSION UPWARD ON LOUT.
C
            DLI = LIN
            DLO = LOUT
            LINLS = LIN
            LOUTLS = LOUT
            ID = (LIN-LOUT+MXDEL) + 2
            IL = LIN+LOUT-2*LMIN+1
            ID2 = (ID+1)/2
            ID = ID/2                                                    9690   
            E = (2*DLO+1)/((DLI+DLO+DN)*DSQRT((DLO+1)**2+ETAOUT**2))
            A = ETAOUT * (DLI+DN-1)/DLO
     1          - (ETAIN*(AKIN/AKOUT)) * (DLO+1)/DLI
            B = (AKIN/AKOUT)*((DLO+1)/DLI)*DSQRT(DLI**2+ETAIN**2)
            C = (DLO+1)*(DLO-DLI-DN+1)*DSQRT(DLO**2+ETAOUT**2)
     1         / (DLO*(2*DLO+1))
            D = (DLO+1)/(AKOUT*R**N)
C
            FF(ID2-1,IL+1) = E*( A*FF(ID,IL) + C*FF(ID2,IL-1) +
     1         B*FF(ID2-1,IL-1) + D*FO(LOUT+1)*FI(LIN+1) )               9700   
            IF ( .NOT. ALLSW )  GO TO 499
            FG(ID2-1,IL+1) = E*( A*FG(ID,IL) + C*FG(ID2,IL-1) +
     1         B*FG(ID2-1,IL-1) + D*FO(LOUT+1)*GI(LIN+1) )
            GF(ID2-1,IL+1) = E*( A*GF(ID,IL) + C*GF(ID2,IL-1) +
     1         B*GF(ID2-1,IL-1) + D*GO(LOUT+1)*FI(LIN+1) )
            GG(ID2-1,IL+1) = E*( A*GG(ID,IL) + C*GG(ID2,IL-1) +
     1         B*GG(ID2-1,IL-1) + D*GO(LOUT+1)*GI(LIN+1) )
 499     CONTINUE
C
C     DLI, DLO, ETC, REFER TO THE LAST CASE FOR WHICH WE INCREASED       9710   
C     LOUT.  NOW INCREASE LIN FOR THAT SAME CASE TO COMPLETE THE
C     GENERATION OF LSUM+1 FROM LSUM.
C
         E = (2*DLI+1)/((DLI+DLO+DN)*DSQRT((DLI+1)**2+ETAIN**2))
         A = ETAIN * (DLO+DN-1)/DLI
     1       - (ETAOUT*(AKOUT/AKIN)) * (DLI+1)/DLO
         B = (AKOUT/AKIN)*((DLI+1)/DLO)*DSQRT(DLO**2+ETAOUT**2)
         C = (DLI+1)*(DLI-DLO-DN+1)*DSQRT(DLI**2+ETAIN**2)
     1        / (DLI*(2*DLI+1))
         D = (DLI+1)/(AKIN*R**N)                                         9720   
C
         FF(ID2,IL+1) = E*( A*FF(ID,IL) + B*FF(ID2,IL-1)
     1         + C*FF(ID2-1,IL-1) + D*FO(LOUTLS+1)*FI(LINLS+1) )
         IF ( .NOT. ALLSW )  GO TO 599
         FG(ID2,IL+1) = E*( A*FG(ID,IL) + B*FG(ID2,IL-1)
     1         + C*FG(ID2-1,IL-1) + D*FO(LOUTLS+1)*GI(LINLS+1) )
         GF(ID2,IL+1) = E*( A*GF(ID,IL) + B*GF(ID2,IL-1)
     1         + C*GF(ID2-1,IL-1) + D*GO(LOUTLS+1)*FI(LINLS+1) )
         GG(ID2,IL+1) = E*( A*GG(ID,IL) + B*GG(ID2,IL-1)
     1         + C*GG(ID2-1,IL-1) + D*GO(LOUTLS+1)*GI(LINLS+1) )         9730   
C
 599  CONTINUE
C
C
C     CHECK THE ACCURACY OF THE RECURSIONS
C
  800 DO 869  I = 1, 2
         IL = I + ISTOPR-2
         MD = MXDEL + MOD(MXDEL+IL,2)
         IF ( R .GT. 0 )  GO TO 850                                      9740   
         DO 849  ID = 1, MD
            LIN = (2*LMIN+IL+MXDEL)/2 + ID-1 - MXDEL
            LOUT = 2*LMIN+IL-1 - LIN
            IF ( LIN .LT. 0  .OR.  LOUT .LT. 0 )  GO TO 849
      IF ( IPRINT .GE. 1 )  write (6, 8853) I, MD, ID, IL, LIN, LOUT,
     1   FF(ID,IL), STARTS(ID,I,1,1)
            IF ( DABS( FF(ID,IL)/STARTS(ID,I,1,1) - 1 ) .GT. 10*ACCURA )
     1        write (6, 843) LIN, LOUT, FF(ID,IL), STARTS(ID,I,1,1)
 843        FORMAT ( '0**** FOR LIN, LOUT =', 2I4,
     1        ' FF RECURSION IS POOR:', 2G20.10 )                        9750   
 849     CONTINUE
         GO TO 869
C
 850     MD = MXDEL + MOD(MXDEL+I+1, 2)
         DO 859  ID = 1, MD
            IL = 2*(LMAX-LMIN)-1 + I
            LIN = (IL+2*LMIN+MXDEL)/2 + ID-1 - MXDEL
            LOUT = IL+2*LMIN-1 - LIN
      IF (IPRINT .GE. 1)  write (6, 8853) I, MD, ID, IL, LIN, LOUT,
     1  FF(ID,IL), FG(ID,IL), GF(ID,IL), GG(ID,IL),                      9760   
     2  ( STARTS(ID,I,III,2), III = 1, 4 )
 8853 FORMAT ( 9H CHECKING , 6I7 / ( 10X, 4G20.10 ) )
            IF ( DABS( FF(ID,IL)/STARTS(ID,I,1,2) - 1 ) .GT. 10*ACCURA )
     1        write (6, 851) LIN, LOUT, FF(ID,IL), STARTS(ID,I,1,2)
 851        FORMAT ( '0**** FOR LIN, LOUT =', 2I4,
     1        ' FF RECURSION IS POOR:', 2G20.10 )
            IF ( .NOT. ALLSW )  GO TO 859
            IF ( DABS( FG(ID,IL)/STARTS(ID,I,2,2) - 1 ) .GT. 10*ACCURA )
     1        write (6, 852) LIN, LOUT, FG(ID,IL), STARTS(ID,I,2,2)
 852        FORMAT ( '0**** FOR LIN, LOUT =', 2I4,                       9770   
     1        ' FG RECURSION IS POOR:', 2G20.10 )
            IF ( DABS( GF(ID,IL)/STARTS(ID,I,3,2) - 1 ) .GT. 10*ACCURA )
     1        write (6, 853) LIN, LOUT, GF(ID,IL), STARTS(ID,I,3,2)
 853        FORMAT ( '0**** FOR LIN, LOUT =', 2I4,
     1        ' GF RECURSION IS POOR:', 2G20.10 )
            IF ( DABS( GG(ID,IL)/STARTS(ID,I,4,2) - 1 ) .GT. 10*ACCURA )
     1        write (6, 857) LIN, LOUT, GG(ID,IL), STARTS(ID,I,4,2)
 857        FORMAT ( '0**** FOR LIN, LOUT =', 2I4,
     1        ' GG RECURSION IS POOR:', 2G20.10 )
 859     CONTINUE                                                        9780   
 869  CONTINUE
C
      IRET = 0
      RETURN
C
C     ERROR DETECTED BY RCWFN
C
 900  write (6, 903) IRET, RVAL, LMN, LMX, ETAIN, ETAOUT, AKIN, AKOUT,
     1  RTOP, DELTA, B, II, IPT
 903  FORMAT ( 28H0***RCWFN FROM COULIN IRET =, I6, G15.5, 2I5, 4G15.5 / 9790   
     1  4H $$$, 3G20.10, 2I5 )
      RETURN
 910  RVAL = R
      LMN = LMINMN
      LMX = LMAXMX
      B = 123456789.
      GO TO 900
      END
C*ID* COULNG   C109.PTOLEMY.SOURCE                          PER701  15:
      FUNCTION COULNG ( L, ETA, RHO, ANORM )                             9800   
C
C     COMPUTE COULOMB WAVEFUNCTION FOR NEGATIVE ENERGY
C
C     THE RETURNED FUNCTION IS
C
C       COULNG =  GAMMA(L+ETA+1) / GAMMA(ANORM)
C              * EXP(RHO) * (2*RHO)**ETA * W( -ETA, L+1/2, 2*RHO )
C
C     WHERE W IS THE WHITTAKER FUNCTION OF ABRAMOWITZ AND STEGUN
C                                                                        9810   
C     AN INTEGRAL EXPRESSION FOR W (RHYDZAK AND ZIMMERMAN XXXXXX)
C     IS COMPUTED USING GAUSS-LAGUERRE QUADRATURE.  THIS IS A CRUDE
C     AND SLOW TECHNIQUE BUT IT SEEMS RELIABLE FOR THE ARGUMENT RANGES
C     OF INTEREST.
C
C     THIS ROUTINE REQUIRES (BUT DOES NOT CHECK FOR)
C           ETA > -L.
C
C     THE ROUTINE HAS BEEN CHECKED FOR:
C           0 =< L =< 10,                                                9820   
C           0 =< ETA =< 120
C           20 =< RHO =< 200
C     FOR WHICH IT USUALLY GIVES BETTER THAN 10 PLACES OF ACCURACY.
C     FOR LARGE RHO AND ETA THE ACCURACY DETERIORATES ( FOR RHO =100,
C     ETA = 120 IT HAS ONLY 6 PLACES ) BUT IF ONE OR THE OTHER
C     OF RHO OR ETA IS NOT LARGE THEN IT HAS GOOD ACCURACY.
C
C     4/23/75 - FIRST VERSION - S. PIEPER
C     6/26/75 - ANORM ADDED;  NEW FACTORIZATION FOR SMALL RHO
C     12/27/79 - CFR%F - RPG                                             9830   
C     1/27/80 - USE BIGLOG, PASS A, B, C TO LAGUER - RPG
C
      IMPLICIT REAL*8 (A-H, O-Z)
C
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
C
      DATA  NPTS /28/
      DIMENSION X(28), DX(28), A(28), B(28), C(28)
c
C                                                                        9840   
      ETA1 = DMOD( ETA, 1.D0 )
      L1 = MOD( L, 10 )
      IF (ETA .LT. 0)   L1 = 0
      L2 = L - L1
      DL1 = L1
      ETA1 = ETA1 + DMAX1( DMIN1( 10-DL1, ETA-ETA1 ), 0.D0 )
      IETA2 = ETA - ETA1
C
      GAM = 1
      IF ( ETA+L .NE. 0 )  GAM = DEXP( -DLGAMA(ANORM)/(ETA+L) )          9850   
      XLIM = 0
      IF ( L2+IETA2 .LE. 1 )  GO TO 100
      XLIM = DEXP( -BIGLOG/(L2+IETA2) ) / GAM
C
 100  CALL LAGUER ( NPTS, X, DX, ETA1+DL1, 1.D-20, CSX, CSW, TSX, TSW,
     1   A, B, C )
C
      COULNG = 0
      DO 159  N = 1, NPTS
         IF ( X(N) .LT. XLIM )  GO TO 159                                9860   
         IF ( RHO .LT. 2 )  GO TO 130
         COULNG = COULNG + DX(N) * (GAM*X(N))**(L2+IETA2) *
     1      (1+X(N)/(2*RHO))**(L-ETA)
         GO TO 159
 130     TEMP = 1 + X(N)/(2*RHO)
         COULNG = COULNG + DX(N) * (GAM*X(N)/TEMP)**(L2+IETA2)
     1      * TEMP**(L+L2-ETA1)
 159  CONTINUE
C
      COULNG = COULNG * GAM**(ETA1+DL1)                                  9870   
      IF ( ETA+L .EQ. 0 )  COULNG = COULNG / DGAMMA(ANORM)
      RETURN
      END
C*ID* COULST   C109.PTOLEMY.SOURCE                          PER701  16:
      SUBROUTINE COULST ( IRTN )
C
C     COULOMB INTEGRALS FOR INELASTIC DWBA & COUPLED CHANNELS
C
C     FIRST WE FIND THE MAXIMUM LI TO BE USED FOR THE COULOMB INTEGRALS
C     WE USE AN ASYMPTOTIC FORM TO BE FOUND IN                           9880   
C       ALDER, BOHR, HUUS, MOTTELSON AND WINTHER, REV. MOD. PHYS. 28,
C       (1956) 432.
C
C     WE SETUP INTEGRAL(R TO INF) FF, FG, GF AND GG FOR LMIN TO LMAX,
C     AND JUST FF FOR (0 TO INF) AND LMIN TO LIMOST.
C     FOR THE LATTER WE ALSO EVALUATE LIMOST AND EXPAND THE
C     COULOMB PHASE SHIFT ARRAYS.
C     IN EACH CASE WE MUST STRUCTURE THE ARRAYS TO BE THE SAME
C     AS THE I(LX,LI,LO) ARRAYS.
C                                                                        9890   
C     IN THE CASE OF COUPLED CHANNELS (BUT NOT COUPL2) WE HAVE
C     A MORE COMPLICATED STORAGE SCHEME AND A B-FACTOR INDEX ARRAY
C     IS DEFINED.  IN THIS CASE WE ALSO STORE ONLY FF+GG AND FG-GF.
C
C     IRTN IS SET TO 0 IF AN ERROR OCCURS, 1 OTHERWISE.
C
C
C     1/7/80 - SPLIT OFF FROM ANGSET - S.P.
C     2/7/80 - MAKE FG ARRAY REAL*4 - S.P.
C     2/19/80 - MOVE A LOOP TO SETBFC - S.P.                             9900   
C     3/31/80 - SMALL FIXES - S.P.
C     4/27/80 - ALLOCATIONS FOR COUPLN; PBUGSW - S.P.
C     9/25/80 - COMPUTE LIMOST SEPARATELY FOR EACH CHANNEL - S.P.
C     12/16/80 - FIX BUG IN ABOVE - S.P.
C     6/25/81 - FIX BUG WHEN NO BFACTORS ARE NEEEDED - S.P.
C     6/29/81 - SMALLER S-MATRIX SEQUENCE AND PADE TABLES - S.P.
C     9/3/81 - GET AND USE MXLXBF; REMOVE COUPL2 - S.P.
C     10/22/81 - FIX COULSIG BUG IF SOME LX > MAX(CHN SPIN) - S.P.
C     3/8/82 - FIX ARRAY SIZE BUGS FOR LXMAX = 1, 0 - S.P.
C     3/15/82  TEMPORARY REAL8 VERSION                                   9910   
C     4/10/82 - BACK TO REAL*4 VERSION; NOBFAC BUG
C     5/4/82 - FIX K TO INDXS FOR 1/2 INTEGER SPINS - S.P
C     6/25/82 - ADD SMATITER DEFINITION - S.P.
C     8/9/84 - EXPAND SMATITER DEFINITION - S.P.
C     10/15/84 - REAL*8 FG & HOMO POSSIBILITIES - S.P.
C     10/30/84 - PROTECT LEXTRAP FORMULAT AGAINST LCRIT=0 - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      COMMON /KANDM/ AKI, AKO, REDMI, REDMO, RIMAX, ROMAX, ISIGS(2),    /kandm/
     &  RSCTS(2), ASCTS(2), RCSCTS(2) ,ISMATS(2), LOMOST, LCRIT,
     &  ISCTMN, ISCTCR, ETAS(2), RCSCTP(2), RCSCTT(2), LCRITS(2),
     &  RATMSS(2), QMIN, ABAR
 
      DIMENSION  AKS(2), REDMS(2), RMAXS(2)
      EQUIVALENCE ( AKI, AKS(1) ), ( REDMI, REDMS(1) ),
     &  ( RIMAX, RMAXS(1) )
 
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
      COMMON /GRIDCM/  RCUEFF, GRDCM1(2),                               /gridcmf
     &  IBINDX, MBINDX, NBINDX, NMFFAC, MXLXGS, NMBFAC,
     & IINHR, IINHI, IRHSR, IRHSI,
     &  INUCH, ICOULH, ILOR, ILOI, ILIR, ILII,
     &  NPTMIN, NOFLO, NUMPT, NCRIT,
     & ISMX, ISMSQ, IPADE, IHOMO,
     &  ISMTSV, IRPTS4, IRPTS,
     &  IGRDC4(5), IDW, IGRDC5(2),
     &  IABS1, IGRDC6(2), GRDCM2, IGRDC7(2), IRWTS,
     &  IGRDC8(2), ICL1FF, ICL1FG, ICL1GF, ICL1GG
 
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
C
c                                                                       /formf/
c ***  LNKADB was  numLINKULES but only 12 are used ???
c
      COMMON /FORMF/  IBDS(2), NPOTS(2), LBP, LBT, NBP, NBT, JBP, JBT,
     &  BNDMAX(2), BNDSTP(2), NSTPBD(2), RBNDS(2), ABNDS(2),
     &  RCBNDS(2), BNDMAS(2), BRATMS(2), RSOBDS(2), ASOBDS(2),
     &  VBNDS(2), VSOBDS(2), TAUBDS(2), LNKADB(6, 2, 12)
 
      DIMENSION R2S(4)
      EQUIVALENCE ( R2S(1), RBNDS(1) )                                   9930   
C
      LOGICAL ONELSW, IDENSW                                            /inelcm/
      COMMON /INELCM/  JBPF, JBTF, LXMIN, LXMAX, ILILOR, ILILOI, MSTOP,
     &  IA12M, NMLOLX, ONELSW, NUMLX, IRDINT, IELCUP, LILOSZ, NUMLIS,
     &  ILIS, IBETAS(3), ICL2FF, LXSTEP, IDENSW, LSKIP,
     &  JPMIN, JPMAX, JPBASE, NJP, JTMIN, JTMAX, JTBASE, NJT,
     &  IINDXS, ISMATR, ISMATI, NSMAT, NLX, NSPLI, ITOCS,
     &  NASPLI, IUNITR, LIFIT, ILIFIT, NOLFIT, IDELSR, IDELSI
      INTEGER INDXJS(4,2)
      EQUIVALENCE ( INDXJS(1,1), JPMIN )
 
      COMMON /CCBLK/  ICHNDF, ICHNCP, ITRANS, IBASDF, IBASCP,           /ccblk/
     &    ICCBLK(2), IORDX, MCHNVL, ICHNVL,
     &    IHOMOA, IHOMOB, IINHR8, IINHI8
 
      REAL*4  TBEGIN, TIMES                                             /ftimei/
      COMMON /FTIME/ TBEGIN, NUMLOP, NUMWAV, TIMES(8)
 
C
      character*1 anames
      COMMON /NAMCOM/  ANAMES(1)
      character*8  BNDXNM / 'BFACINDX'/
C
      INTEGER  GIVEAL, chopit                                            9940   
C
      LOGICAL PBUGSW, PINFSW, COULSW, COUPSW
      real*8 dummy8(1)
C
c
C
      IRTN = 0
C
      IPRNT = MOD( IPRINT, 10 )
      PBUGSW = IPRNT .GE. 3                                              9950   
      PINFSW = IPRNT .GE. 2
C
      COUPSW = PROBLM .EQ. 24
C
C     THESE INTEGRALS WILL BE JUST ZERO IF THE BETA(COULOMB) IS ZERO.
C
C     IN THIS CASE THE LARGE COULOMB LMAX IS ALSO NOT NEEDED.
C
      LIMOST = LMAX
      TIMES(5) = 0                                                       9960   
      TIMES(6) = 0
      TIMES(7) = 0
      TIMES(8) = 0
      CLTIME = 0
      COULSW = .FALSE.
      MXLXBF = LXMAX
C
      IF ( COUPSW )  GO TO 100
      NCHNDF = 2
      LBETAR = Z(IBETAS(3)) - LXMIN/2                                    9970   
      DO   69  LX = LXMIN, LXMAX, 2
         IF ( ALLOC(LBETAR+LX/2) .EQ. 0 )  GO TO 69
         COULSW = .TRUE.
         GO TO 200
   69 CONTINUE
C
C     NO COULOMB TERMS WILL BE NEEDED
C
      COULSW = .FALSE.
      NOBFAC = 1                                                         9980   
      GO TO  300
C
C     FOR COUPLED CHANNES WE GO THROUGH THE BASIS COUPLING ARRAY
C     AND FOR ALL COULOMB COUPLINGS
C     1)  FIND THE REQUIRED STORAGE SIZE FOR B-FACTORS,
C         CONSTRUCT THE B INDEX ARRAY, AND STORE POINTERS
C         TO IT.
C     3)  CONSTRUCT POINTERS FOR THE FF2 INTEGRALS FOR ALL
C         COULOMB COUPLINGS TO THE G.S.  THE SIZE OF THE FF2
C         ARRAY IS ALSO FOUND.                                           9990   
C
C
 100  IBINDX = GIVEAL(I)
      ANAMES(IBINDX) = BNDXNM
      LBINDX = FACFR4*(Z(IBINDX)-1) + 1
      MBINDX = 9
C
      LBASCP = FACFR4*(Z(IBASCP)-1) + 1
      NBASCP = ILLOC(LBASCP)
      MBASCP = ILLOC(LBASCP+1)                                          10000   
      LBASCP = LBASCP + ILLOC(LBASCP+2)
C
      LBASDF = FACFR4*(Z(IBASDF)-1) + 1
      NBASDF = ILLOC(LBASDF)
      MBASDF = ILLOC(LBASDF+1)
      LBASDF = LBASDF + ILLOC(LBASDF+2)
C
      LCHNDF = FACFR4*(Z(ICHNDF)-1) + 1
      NCHNDF = ILLOC(LCHNDF)
      MCHNDF = ILLOC(LCHNDF+1)                                          10010   
      LCHNDF = LCHNDF + ILLOC(LCHNDF+2)
C
      CALL GENBNX ( 1, NBINDX, MBINDX, ILLOC(LBINDX), NBASCP,
     1  MBASCP, ILLOC(LBASCP), MBASDF, ILLOC(LBASDF), MCHNDF,
     2  ALLOC4(LCHNDF), NMBFAC, NMFFAC, MXLXGS, MXLXBF,
     3   COULSW, PBUGSW )
C
      I = MAX0( ( NBINDX*MBINDX+1)/FACFR4, 1 )
      ixx = CHOPIT (I)
      IF ( NBINDX .NE. 0 )  GO TO 150                                   10020   
C
C     B-FACTORS ARE NOT NEEDED OR ARE INHIBITED.
C
      NOBFAC = 1
 150  IF ( MAXLEX .EQ. 0  .OR.  .NOT. COULSW )  GO TO 300
C
C     COULOMB COUPLING EXISTS.  COMPUTE APPROPRIATE EXTRAPOLATION
C     LIMIT (LIMOST)
C
C     FIRST WE FIND THE MAXIMUM LI TO BE USED FOR THE COULOMB INTEGRALS 10030   
C     WE USE AN ASYMPTOTIC FORM TO BE FOUND IN
C       ALDER, BOHR, HUUS, MOTTELSON AND WINTHER, REV. MOD. PHYS. 28,
C       (1956) 432, FORMULA II E.83 .
C     FOR CC THIS IS DONE SEPARATELY FOR EACH CHANNEL AND THE RESULT
C     STORED IN THE CHANNEL DEFINITION ARRAY.
C
  200 IF ( PINFSW )  write (6, 223)
  223 FORMAT ( '-CHN LX  LO-LI  MAXIMUM L NEEDED' )
      DLCRIT = LCRIT
      LX = LXMIN                                                        10040   
      DO 249  NCHN = 2, NCHNDF
         LI = LMAX
         IF ( .NOT. COUPSW )  GO TO 230
         I = LCHNDF + (NCHN-1)*MCHNDF
         IF ( ILLOC(I+14) .EQ. NOTDEF )  GO TO 249
         ETAS(2) = ALLOC4(I+5)
         LX = ILLOC(I+14)
C
 230     MLX = -LX
         DO  239  LDEL = MLX, LX, 2                                     10050   
            ATERM = DABS( (ETAS(2)-ETAS(1))/ETAS(1) )
            BTERM = (LX+LDEL+1.D0)/2
            CTERM = DLOG(DWCUT) - ATERM*(DLCRIT+.5)
     1              - BTERM*DLOG(DLCRIT+.5)
            L = RTXLNX( ATERM, BTERM, CTERM, .1D0 ) + .5
            LI = MAX0( LI, L )
            IF ( PINFSW )  write (6,  233) NCHN, LX, LDEL, L
  233       FORMAT ( I4, I3, I6, I13 )
            IF ( PBUGSW )  write (6,  237) ATERM, BTERM, CTERM
  237       FORMAT ( '+', T50, 3G15.5 )                                 10060   
  239    CONTINUE
C
C     LIMIT BY MAXLEX
C
         LI = MIN0( LI, LMAX+MAXLEX )
         IF ( COUPSW )  ILLOC(I+14) = LI
         LIMOST = MAX0( LIMOST, LI )
 249  CONTINUE
C
  300 LOMOST = LIMOST + LXMAX                                           10070   
C
C     NOW GENERATE POINTERS TO THE B AND FF2 ARRAYS
C
      IF ( COUPSW )
     1   CALL GENBNX ( 2, NBINDX, MBINDX, ILLOC(LBINDX), NBASCP,
     1   MBASCP, ILLOC(LBASCP), MBASDF, ILLOC(LBASDF), MCHNDF,
     2   ALLOC4(LCHNDF), NMBFAC, NMFFAC, MXLXGS, MXLXBF,
     3   COULSW, PBUGSW )
C
C     EXPAND THE COULOMB PHASE SHIFT ARRAYS                             10080   
C     WE ARE SLOPPY AND FIND SOME MORE THAN ARE REALLY NECESSARY
C
      LMXMX = LOMOST + 2*LXMAX
      CALL IREDEF( LMXMX+1, ISIGS(1) )
C
      IF ( COUPSW )  GO TO 370
C
      CALL IREDEF( LMXMX+1, ISIGS(2) )
      LSIGI = Z(ISIGS(1))
      LSIGO = Z(ISIGS(2))                                               10090   
      CI = ALLOC(LSIGI+LMAX)
      CO = ALLOC(LSIGO+LMAX)
      LMP1 = LMAX+1
      DO  329  L = LMP1, LMXMX
         CI = CI + DATAN( ETAS(1)/L )
         CO = CO + DATAN( ETAS(2)/L )
         ALLOC(LSIGI+L) = CI
         ALLOC(LSIGO+L) = CO
  329 CONTINUE
C                                                                       10100   
C     WE SETUP INTEGRAL(R TO INF) FF, FG, GF AND GG FOR LMIN TO LMAX,
C     AND JUST FF FOR (0 TO INF) AND LMIN TO LIMOST.
C     FOR THE LATTER WE ALSO EVALUATE LIMOST AND EXPAND THE
C     COULOMB PHASE SHIFT ARRAYS.
C     IN EACH CASE WE MUST STRUCTURE THE ARRAYS TO BE THE SAME
C     AS THE I(LX,LI,LO) ARRAYS.
C
C     THIS IS FOR NON-C.C. CALCULATIONS
C     FIRST THE (R, INF) STUFF
C                                                                       10110   
      ICL1FF = NALLOC( NSMAT, 'FF1INTS ' )
      ICL1FG = NALLOC( NSMAT, 'FG1INTS ' )
      ICL1GF = NALLOC( NSMAT, 'GF1INTS ' )
      ICL1GG = NALLOC( NSMAT, 'GG1INTS ' )
      DO  339  I = 1, NSMAT
         ALLOC(Z(ICL1FF)-1+I) = 0
         ALLOC(Z(ICL1FG)-1+I) = 0
         ALLOC(Z(ICL1GF)-1+I) = 0
         ALLOC(Z(ICL1GG)-1+I) = 0
  339 CONTINUE                                                          10120   
      GO TO 400
C
C     FOR COUPLED CHANNELS WE STORE IT ALL IN ONE
C     BIG ARRAY THAT IS NOT EVEN DEFINED IF THE
C     B FACTORS ARE NOT TO BE USED.
C
C     A SECOND WORK ARRAY FOR THE B-FACTORS IS SIMILARLY DEFINED
C     BOTH POINTERS ARE SET TO 1 TO MAKE THNKS EASY IF THERE
C     ARE TO BE NO BFACTORS.
C                                                                       10130   
 370  ISIGS(2) = NALLOC( LMXMX+1, 'COULSIGB' )
      ISMATS(2) = NALLOC( 2*LMXMX+2, 'SOPTICAL' )
      NUMJS(2) = NUMJS(1)
C
      TT = second()
      ICL1FF = 1
      ICL1FG = 1
      IF ( NOBFAC .EQ. 1 )  GO TO 800
C
      ICL1FF = NALLOC( (2*NMBFAC*NUMLIS+1)/FACFR4, 'BFACTORS' )         10140   
      CALL INIT4 ( ICL1FF, 0. )
      ICL1FG = NALLOC( (4*NMBFAC+1)/FACFR4, 'BFACFORJ' )
C
C     IN C.C. CALCULATIONS,   LXMAX IS  MAX(J2) = MAX|L2-J|
C     MXLXBF IS THE MAXIMUM LX USED IN BFACTORS
C     OTHERWISE IT HAS BEEN SET TO BE LXMAX
C
  400 MAXDL1 = MAX0( 2, MXLXBF )
      LDLDIM = MAXDL1 + 1
      MAXDL1 = MAX0( MAXDL1, LXMAX )                                    10150   
      LMNMN1 = MAX0( LMIN-MAXDL1, 0 )
      IWRKST = NALLOC( 16*LDLDIM, 'COULSTRT' )
C
      TT = second()
      IF ( NOBFAC .EQ. 1 )  GO TO 500
C
      LMXMX = LMAX+LXMAX
      LMXMX1 = LMAX + MAXDL1
      IDIM1 = LDLDIM*(2*(LMXMX1-LMNMN1)+1)
      IWRKFF = NALLOC( 4*IDIM1, 'FFWORK  ' )                            10160   
      IDIM2 = MAX0( LMXMX1+MAXDL1, 4*MXCOUL ) + 1
      IWRKFI = NALLOC( 4*IDIM2, 'FIWORK  ' )
      IWRKWK = NALLOC( MAX0(2*NPCOUL+4*MXCOUL, 2*(LMXMX1+MAXDL1)+1,
     1     2*NPCOUL+LMXMX1+MAXDL1)+1, 'COULWORK' )
C
      LWRKFF = Z(IWRKFF)
      LWRKFI = Z(IWRKFI)
      LWRKWK = Z(IWRKWK)
      LWRKST = Z(IWRKST)
      LLIS = FACFR4*(Z(ILIS)-1)                                         10170   
      LSIG1 = Z(ISIGS(1))
      LSIG2 = Z(ISIGS(2))
C
      IF ( COUPSW )  GO TO 700
C
      LINDXS = Z(IINDXS)*FACFR4 - FACFR4
      LWRKFG = LWRKFF+IDIM1
      LWRKGF = LWRKFG+IDIM1
      LWRKGG = LWRKGF+IDIM1
      LWRKFO = LWRKFI+IDIM2                                             10180   
      LWRKGI = LWRKFO+IDIM2
      LWRKGO = LWRKGI+IDIM2
C
      DO  439 LX = LXMIN, LXMAX, 2
         LMNMN = MAX0( LMIN-(LX+1)/2, LX/2 )
         CALL COULIN ( LX+1, LX, LMNMN, LMXMX, ETAS(2), AKO,
     1      ALLOC(LSIG2),
     1      ETAS(1), AKI, ALLOC(LSIG1), SUMMAX, .TRUE.,
     2      ALLOC(LWRKFF), ALLOC(LWRKFG), ALLOC(LWRKGF),
     3      ALLOC(LWRKGG),                                              10190   
     4      LDLDIM, ACCINE, COULML, MXCOUL, NPCOUL,
     5      ALLOC(LWRKWK), ALLOC(LWRKFI), ALLOC(LWRKFO),
     6      ALLOC(LWRKGI), ALLOC(LWRKGO), ALLOC(LWRKST),
     7      MOD(IPRINT/100, 10), IRET, CLTIME )
         IF ( IRET .NE. 0 )  GO TO 9960
         MAXDEL = MAX0(2, LX)
C
C     STORE THE INTEGRALS IN THE SAME ORDER AS THE I(LX,LI,LO)
C     ARRAYS.
C     MULTIPLY IN THE CHARGE AND RADIUS FACTORS (BUT NOT THE BETA'S)    10200   
C
         K = LX+1 + NLX*(LX-INDXJS(3,IEXCIT)/2)
         KBASE = ILLOC(LINDXS+3*K-2)
         LDELMN = ILLOC(LINDXS+3*K-1)
         NDEL = ILLOC(LINDXS+3*K)
         DO  439  ILI = 1, NUMLIS
            LI = ILLOC(LLIS+ILI)
            IDELMN = 1
            IF ( LI .LT. LX )  IDELMN = LX+1 - LI
            DO  439  IDEL = IDELMN, NDEL                                10210   
               LDEL = LDELMN-2 + 2*IDEL
               LO = LI + LDEL
               ID = iSHFT( MAXDEL-LDEL, -1 )
               IL = LO+LI - 2*LMNMN
               I1 = ID + IL*LDLDIM
               I = NSPLI*(ILI-1) + KBASE-2 + IDEL
               ALLOC(Z(ICL1FF)+I) = -R2S(4)*ALLOC(LWRKFF+I1)
               ALLOC(Z(ICL1FG)+I) = -R2S(4)*ALLOC(LWRKFG+I1)
               ALLOC(Z(ICL1GF)+I) = -R2S(4)*ALLOC(LWRKGF+I1)
               ALLOC(Z(ICL1GG)+I) = -R2S(4)*ALLOC(LWRKGG+I1)            10220   
  439 CONTINUE
C
C
  490 TIMES(5) = CLTIME
      TIMES(7) = second() - TT
C
C     NOW THE PURE COULOMB (FF) INTEGRALS OUT TO LOMOST
C
  500 IDIM1 = NMLOLX*(LIMOST-LMIN+1)
      ICL2FF = NALLOC( IDIM1, 'FF2INTS ' )                              10230   
      LMXMX = LOMOST
      LMXMX1 = LMXMX + MAXDL1-LXMAX
      DO  519  I = 1, IDIM1
         ALLOC(Z(ICL2FF)-1+I) = 0
  519 CONTINUE
C
      IF ( .NOT. COULSW )  GO TO  990
C
      IDIM1 = LDLDIM*(2*(LMXMX1-LMNMN1)+1)
      IWRKFF = NALLOC( IDIM1, 'FFWORK  ' )                              10240   
      IDIM2 = MAX0( LMXMX1+MAXDL1, 4*MXCOUL ) + 1
      IWRKFI = NALLOC( IDIM2, 'FIWORK  ' )
      IWRKFO = NALLOC( IDIM2, 'FOWORK  ' )
      IWRKGI = NALLOC( IDIM2, 'GIWORK  ' )
      IWRKGO = NALLOC( IDIM2, 'GOWORK  ' )
      IWRKWK = NALLOC( MAX0(2*NPCOUL+4*MXCOUL, 2*(LMXMX1+MAXDL1)+1,
     1     2*NPCOUL+LMXMX1+MAXDL1)+1, 'COULWORK' )
      LINDXS = Z(IINDXS)*FACFR4 - FACFR4
C
      TT = second()                                                     10250   
      DO  599 LX = LXMIN, LXMAX, 2
         LMNMN = MAX0( LMIN-(LX+1)/2, LX/2 )
         CALL COULIN ( LX+1, LX, LMNMN, LMXMX, ETAS(2), AKO,
     1      ALLOC(Z(ISIGS(2))),
     1      ETAS(1), AKI, ALLOC(Z(ISIGS(1))), 0.D0, .FALSE.,
     2      ALLOC(Z(IWRKFF)), DUMMY8, DUMMY8, DUMMY8,
     4      LDLDIM, ACCINE, COULML, MXCOUL, NPCOUL,
     5      ALLOC(Z(IWRKWK)), ALLOC(Z(IWRKFI)), ALLOC(Z(IWRKFO)),
     6      ALLOC(Z(IWRKGI)), ALLOC(Z(IWRKGO)), ALLOC(Z(IWRKST)),
     7      MOD(IPRINT/100, 10), IRET, CLTIME )                         10260   
         IF ( IRET .NE. 0 )  GO TO 9960
         MAXDEL = MAX0(2, LX)
         K = LX+1 + NLX*(LX-INDXJS(3,IEXCIT)/2)
         KBASE = ILLOC(LINDXS+3*K-2)
         LDELMN = ILLOC(LINDXS+3*K-1)
         NDEL = ILLOC(LINDXS+3*K)
         DO  599  LI = LMIN, LIMOST
            IDELMN = 1
            IF ( LI .LT. LX )  IDELMN = LX+1 - LI
            DO  599  IDEL = IDELMN, NDEL                                10270   
               LDEL = LDELMN-2 + 2*IDEL
               LO = LI + LDEL
               ID = iSHFT( MAXDEL-LDEL, -1 )
               IL = LO+LI - 2*LMNMN
               I1 = ID + IL*LDLDIM
               I = NSPLI*(LI-LMIN) + KBASE-2 + IDEL
               ALLOC(Z(ICL2FF)+I) = -R2S(4)*ALLOC(Z(IWRKFF)+I1)
  599 CONTINUE
      TIMES(6) = CLTIME
      TIMES(8) = second() - TT                                          10280   
      Z(IWRKFO) = -Z(IWRKFO)
      Z(IWRKGI) = -Z(IWRKGI)
      Z(IWRKGO) = -Z(IWRKGO)
      Z(IWRKFF) = -Z(IWRKFF)
      Z(IWRKFI) = -Z(IWRKFI)
      Z(IWRKWK) = -Z(IWRKWK)
      Z(IWRKST) = -Z(IWRKST)
      GO TO 990
C
C     FOR COUPLED CHANNELS WE LOOP THROUGH BINDEX AND COMPUTE           10290   
C     EACH REQUIRED SET.
C     ALSO HERE WE MUST COMPUTE ALL THE COULOMBP PHASE FACTORS
C     EACH TIME.
C     ALL OF THIS IS DONE IN THE SUBROUTINE
C
 700  LBINDX = FACFR4*(Z(IBINDX)-1) + 1
      LCL1FF = FACFR4*(Z(ICL1FF)-1) + 1
      LCHNDF = FACFR4*(Z(ICHNDF)-1) + 1
      LCHNDF = LCHNDF + ILLOC(LCHNDF+2)
C                                                                       10300   
      CALL SETBFC ( NBINDX, MBINDX, ILLOC(LBINDX),
     1   MCHNDF, ILLOC(LCHNDF), ALLOC4(LCHNDF),
     2   NUMLIS, ILLOC(LLIS+1), R2S, LMXMX,
     3   ALLOC(LSIG1), ALLOC(LSIG2),
     4   SUMMAX, .TRUE., 2, NMBFAC, ALLOC4(LCL1FF),
     5   ALLOC(LWRKFF), IDIM1, LDLDIM, ALLOC(LWRKWK),
     6   ALLOC(LWRKFI), IDIM2, ALLOC(LWRKST), IRET, CLTIME )
      IF ( IRET .NE. 0 )  GO TO 9960
C
      Z(IWRKFF) = -Z(IWRKFF)                                            10310   
      Z(IWRKFI) = -Z(IWRKFI)
      Z(IWRKWK) = -Z(IWRKWK)
      Z(IWRKST) = -Z(IWRKST)
C
C     REESTABLISH ELASTIC PHASE SHIFTS
C
 800  CALL DSGMAL ( ETAS(1), LOMOST+LXMAX, ALLOC(Z(ISIGS(1))) )
C
      T4 = second()
      T2 = T4-TT                                                        10320   
C
C     NOW FIND ALL THE REQUIRED F'S AND G'S
C
      I = 4*NBASDF*NUMLIS/FACFR4
C8F      I = FACFR4*I
      IFG = NALLOC ( I, 'FANDG    ' )
      NFS(1) = IFG
      CALL INIT4 ( IFG, 0. )
      L2P1 = LMAX+LXMAX+1
      IWRKFG = NALLOC ( 6*L2P1, 'F&GWORK ' )                            10330   
      LCHNDF = FACFR4*(Z(ICHNDF)-1) + 1
      LCHNDF = LCHNDF + ILLOC(LCHNDF+2)
      LBASDF = FACFR4*(Z(IBASDF)-1) + 1
      LBASDF = LBASDF + ILLOC(LBASDF+2)
C
      CALL SETFG ( NCHNDF, MCHNDF, ILLOC(LCHNDF),
     1  ALLOC4(LCHNDF), NBASDF, MBASDF, ILLOC(LBASDF),
     1  MCHNVL, ALLOC(Z(ICHNVL)),
     2  NUMLIS, ALLOC(Z(ILIS)), ALLOC(Z(IFG)),
     3  MAX0(0, LMIN-LXMAX), L2P1, ALLOC(Z(IWRKFG)),                    10340   
     4  SUMMAX-NBACK*RSTEPS(1), SUMMAX, IRTN )
C
      Z(IWRKFG) = -Z(IWRKFG)
C
      T4 = second() - T4
      T3 = T2 - CLTIME
      TALL = T4+T2
      write (6, 893) CLTIME, T3, T2, T4, TALL
 893  FORMAT ( '-MATCHING CONDITION TIMES (SECONDS):' /
     1  ' BELLINGS:',   T30, F8.2 /                                     10350   
     2  ' RECURSIONS AND COUL. PHASES:', T30, F8.2 /
     3  ' TOTAL FOR B FACTOR:', T40, F8.2 /
     4  ' F AND G FUNCTIONS:', T30, F8.2 /
     3  ' TOTAL:', T50, F8.2 )
C
C
C     ALLOCATIONS FOR COUPLN
C
C     HOMOGENEOUS SOLUTION STORAGE
      NWRDS=(2*(NUMPT-NPTMIN)*NBASDF+FACFR4-1)/FACFR4                   10360   
      NWRDS = FACFR4*NWRDS                                              c8h
      IHOMO=NALLOC(NWRDS,'CCHOMO  ')
C     PARTICULAR INTEGRAL STORAGE
      NWRDS=((NUMPT-NPTMIN)*NBASDF+FACFR4-1)/FACFR4
      NWRDS = FACFR4*NWRDS                                              c8h
      IINHR=NALLOC(NWRDS,'CCINHR  ')
      IINHI=NALLOC(NWRDS,'CCINHI  ')
C     R.H.S.(ONLY 1 FOR SEQENTIAL ITERATION)
      IRHSR=NALLOC(NUMPT,'CCRHSR  ')
      IRHSI=NALLOC(NUMPT,'CCRHSI  ')                                    10370   
      DO 929  I = 1, NUMPT
         ALLOC(Z(IRHSR)+I-1) = 0
         ALLOC(Z(IRHSI)+I-1) = 0
 929  CONTINUE
C     SEQUENCE OF STORED S-MATRIX ELEMENTS
      NWRDS= 4*NBASDF
      ISMSQ=NALLOC(NWRDS,'CCSMSQ  ')
C     ELEMENTS OF THE PADE TABLE
      NWRDS=6*((MAXITR+1)/2)*NBASDF
      IPADE=NALLOC(NWRDS,'PADE    ')                                    10380   
C
C     WE STORE THE FOLLOWING IN FULL PRECISION
C     HOMOA - HOMO SOLUTION (REAL,IMAG) AT THE 2 STARTING POINTS
C     HOMOB - HOMO SOLUTION (REAL,IMAG) AT THE 2 MATCHING POINTS
C     INHR8 - REAL PART OF INHOMO SOLUTION AT THE 2 START POINTS
C     INHI8 - IMAG PART OF INHOMO SOLUTION AT THE 2 START POINTS
C
      IHOMOA = NALLOC( 4*NBASDF, 'CCHOMO8A' )
      IHOMOB = NALLOC( 4*NBASDF, 'CCHOMO8B' )
      IINHR8 = NALLOC( 2*NBASDF, 'CCINHR8 ' )                           10390   
      IINHI8 = NALLOC( 2*NBASDF, 'CCINHI8 ' )
C
      IF ( ISAVSM .EQ. 0 )  GO TO 990
      I = 1
      IF ( ISAVSM .EQ. 3 ) I = 2
      ISMTSV = NALLOC( 2*MAXITR*I*NBASDF, 'SMATITER' )
C
  990 IRTN = 1
      RETURN
C                                                                       10400   
C
 9960 write (6, 9963) IRET
 9963 FORMAT ( '0**** ERROR RETURN FROM COULIN:', I12 )
      RETURN
C
      END
C*ID* COUPLN   C109.PTOLEMY.SOURCE                          PER701  17:
      SUBROUTINE COUPLN(IRET)
C
C     ITERATIVE SOLUTION OF MULTI-CHANNEL COUPLED EQUATIONS             10410   
C
C *************************************************************
C *                                                           *
C *   THE LARGE 2-D ARRAYS OF HOMOGENEOUS AND CURRENT         *
C *   ITERATED INHOMOGENEOUS SOLUTIONS ARE STORED IN SINGLE   *
C *   PRECISION.  HOWEVER THE HOMOGENEOUS VALUES USED IN THE  *
C *   MATCHING AND BOTH THE HOMO AND INHOMO VALUES USED TO    *
C *   START THE INTEGRATION ARE STORED IN DOUBLE PRECISON.    *
C *   FOR VERY DIFFICULT CASES IT IS WORTH WHILE TO HAVE THE  *
C *   ENTIRE HOMOGENEOUS SOLUTION STORED IN DOUBLE PRECISION  *         10420   
C *   TO ALLOW LARGE CANCELLATIONS WHEN ADDING THE HOMO       *
C *   SOLUTION TO THE INHOMO IN THE NORMALIZATION LOOP.       *
C *   THIS MAY BE ACCOMPLISHED BY ACTIVATING ALL THE CARDS    *
C *   WITH  C8H   IN COLUMN 1 HERE AND IN  DRIVE & COULST     *
C *                                                           *
C *   THE ARRAY OF COULOMB FUNCTIONS FG IS ALSO REAL*4        *
C *   ACTIVATING THE CARDS THAT HAVE  C8F IN COL 1            *
C *   WILL MAKE THIS ARRAY BE REAL*8.  IT IS ALSO NECESSARY   *
C *   TO CHANGE  COULST, SETFG, GETBFC, CCMTCH, WAVELJ,       *
C *   AND GETSCT.                                             *         10430   
C *                                                           *
C *************************************************************
C
C     2/7/80 FIRST VERSION MRB
C     4/17/80 - BETTER TIMING; MINOR CHANGES - S.P.
C     4/19/80 - RHS ARRAYS ARE REAL*8 - S.P.
C     4/24/80 - USE IPARM3 AS NFIRST OFFSET; PBUGSW - S.P.
C     4/27/80 - NPTMIN IS LEAST POINT TO USE; MOVE ALLOCATIONS - S.P.
C     6/3/80 - DIMS PASSED TO CCMTCH, DRIVE, GETBFC FOR CDC - S.P.
C     6/11/80 - USE DIMAG INSTEAD OF IMAG - S.P.                        10440   
C     7/28/80 - USE IODEP TO HELP CRAY - S.P.
C     8/1/80 - CALL SETLOG - S.P.
C     8/25/80 - USE AIMAG, NOT DIMAG - S.P.
C     6/24/81 - REMOVE TRI, SANE USE OF NCHNDF, JT - S.P.
C               FIX BUG STORING O'TH ORDER ELASTIC S-MATRIX - S.P.
C     10/27/81 - JBLOCK TO STORE J; WRITEWAVE STUFF - S.P.
C     11/19/81 - USE WAVELJ TO COUPUTE THE DIAGONAL POT - S.P.
C     3/12/82 - ALLOW BLENDING OF NEW AND OLD SOLUTIONS - S.P.
C     3/15/82 - ****** TEMPORARY REAL*8 VERSION *****
C     3/15/82 - ADD GRADUAL SCALLING OF COUPLING STRENGTH               10450   
C     3/16/82 - ADD BLOCK ITERATION - S.P.
C     4/10/82 - BACK TO REAL*4 VERSION - S.P.
C     6/25/82 - SAVE COMPUTED S MATRICES FOR EACH ITERATION - S.P.
C     4/8/83 - FIX BUG IN ITERATION TIME - S.P.
C     8/8/83 - CHANGES FOR INCOMING BOUNDARY - S.P.
C     10/6/83 - REAL*8 FOR START & STOP - S.P.
C     8/9/84 - SAVE PADE ITERATIONS - S.P.
C     10/15/84 - ADD  REAL*8 FG POSSIBILITY; CHANVALS  - S.P.
C     8/21/85 - LOTS OF CRAY DIRECTIVES - S.P.
C                                                                       10460   
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
      COMMON /CCBLK/  ICHNDF, ICHNCP, ITRANS, IBASDF, IBASCP,           /ccblk/
     &    ICCBLK(2), IORDX, MCHNVL, ICHNVL,
     &    IHOMOA, IHOMOB, IINHR8, IINHI8
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      parameter ( NUMJWORD = 12 )                                       /jblock/
      COMMON /JBLOCK/  J, JS(5),
     &  JP, JSP, JST,
     &  JPARM1, JPARM2, JPARM3
 
      COMMON /GRIDCM/  RCUEFF, GRDCM1(2),                               /gridcmf
     &  IBINDX, MBINDX, NBINDX, NMFFAC, MXLXGS, NMBFAC,
     & IINHR, IINHI, IRHSR, IRHSI,
     &  INUCH, ICOULH, ILOR, ILOI, ILIR, ILII,
     &  NPTMIN, NOFLO, NUMPT, NCRIT,
     & ISMX, ISMSQ, IPADE, IHOMO,
     &  ISMTSV, IRPTS4, IRPTS,
     &  IGRDC4(5), IDW, IGRDC5(2),
     &  IABS1, IGRDC6(2), GRDCM2, IGRDC7(2), IRWTS,
     &  IGRDC8(2), ICL1FF, ICL1FG, ICL1GF, ICL1GG
 
      REAL*4  TBEGIN, TIMES                                             /ftimei/
      COMMON /FTIME/ TBEGIN, NUMLOP, NUMWAV, TIMES(8)
 
      LOGICAL ONELSW, IDENSW                                            /inelcm/
      COMMON /INELCM/  JBPF, JBTF, LXMIN, LXMAX, ILILOR, ILILOI, MSTOP,
     &  IA12M, NMLOLX, ONELSW, NUMLX, IRDINT, IELCUP, LILOSZ, NUMLIS,
     &  ILIS, IBETAS(3), ICL2FF, LXSTEP, IDENSW, LSKIP,
     &  JPMIN, JPMAX, JPBASE, NJP, JTMIN, JTMAX, JTBASE, NJT,
     &  IINDXS, ISMATR, ISMATI, NSMAT, NLX, NSPLI, ITOCS,
     &  NASPLI, IUNITR, LIFIT, ILIFIT, NOLFIT, IDELSR, IDELSI
      INTEGER INDXJS(4,2)
      EQUIVALENCE ( INDXJS(1,1), JPMIN )
 
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      COMMON /KANDM/ AKI, AKO, REDMI, REDMO, RIMAX, ROMAX, ISIGS(2),    /kandm/
     &  RSCTS(2), ASCTS(2), RCSCTS(2) ,ISMATS(2), LOMOST, LCRIT,
     &  ISCTMN, ISCTCR, ETAS(2), RCSCTP(2), RCSCTT(2), LCRITS(2),
     &  RATMSS(2), QMIN, ABAR
 
      DIMENSION  AKS(2), REDMS(2), RMAXS(2)
      EQUIVALENCE ( AKI, AKS(1) ), ( REDMI, REDMS(1) ),
     &  ( RIMAX, RMAXS(1) )
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      CHARACTER*1  REACT, HEADER                                        /hedcom/
      COMMON /HEDCOM/  REACT(45), HEADER(65)
 
c                                                                       /lnkblk/
c  STRUCTURE OF   /LNKBLK/
c
c  THERE IS A BLOCK OF 3 DOUBLE WORDS FOR EACH POSSIBLE USE
c  OF A LINKULE.  THE NUMLNK = NUMLINKULES USES ARE IN THE ORDER
c    REALPOTEN  IMAGPOTEN  REALVSO  IMAGVSO  COULOMB
c    WAVEFUNCTION  AND 6 TENSOR POTENTIALS
c  THE THREE-DOUBLE-WORD BLOCKS EACH HAVE THE STRUCTURE
c
c    LNKNAM(1,I)   LINKULE NAME
c
c      LNKADR(3,I)   LINKULE ADDRESS, O IF NO LINKULE IN USE.
c      LNKADR(4,I)   0 - NO L OR J DEPENDENCE IN POTENTIAL
c                    1 - L DEPENDENCE BUT NO J DEPENDENCE
c                    2 - BOTH L  AND J DEPENDENCE
c
c      LNKADR(5&6,I)  MYINTS - A TWO-ELEMENT ARRAY THAT THE
c                     LINKULE MAY USE FOR COMMUNICATION BETWEEN
c                     CALLS TO ITSELF.
c
      parameter ( NUMLINKULES = 13 )
      COMMON /LNKBLK/  NUMLNK, IUNIQU, LNKADR(6,NUMLINKULES)
      character*8  LNKNAM(3,NUMLINKULES)
      EQUIVALENCE ( LNKNAM(1,1), LNKADR(1,1) )
 
C
      COMPLEX*16 CFAC
c4h      REAL*4  CFACR, CFACI
      REAL*8  CFACR, CFACI                                              c8h
      LOGICAL PBUGSW, CONVSW, BLOKSW                                    10480   
      CHARACTER*8  ACCWRD(3) / 'BLOCKREL', 'ABSOLUTE', 'RELATIVE' /
      REAL*4 DUMMY4(1)
      character*9 thedat
C
c
C
      TSTART=second()
      TRIGHT=0
      TUOPT = 0
      TINHO=0                                                           10490   
      TWAVE=0
      TNORM = 0
      TITER = 0
      NMINHO = 0
      NMINPT = 0
      FLPINH = 0
      FLPRHS = 0
      FLPUOP = 0
      FLPADE = 0
      TPADE = 0                                                         10500   
      FLPNRM = 0
      IPRNT = MOD(IPRINT,10)
      write (6, 3) REACT, ELAB, HEADER
  3   FORMAT ( '1', T60, 'P T O L E M Y' /
     1  1X, 'COMPUTATION OF COUPLED INELASTIC CHANNELS S-MATRICES',
     2    T95, 'WIN A FEW, LOOSE A FEW' /
     3  '0', 45A1, 'ELAB =', F7.2, ' MEV', 5X, 65A1 / )
C *************** TEMPORARY FOLLOWS ******************************
      BLEND = PAR620(15)
      IF ( BLEND .EQ. UNDEF )  BLEND = 1                                10510   
      VSCALE = PAR620(14)
      IF ( VSCALE .EQ. UNDEF )  VSCALE = 0
      BLOKSW = ISW3 .EQ. 1
      write (6, 23) ACCWRD(CONVRG+1), ACCURA, BLEND, VSCALE
  23  FORMAT ( 1X, A8, ' ACCURACY REQUIREMENT IS', G12.3 /
     1  ' BLENDING FACTOR IS', G15.5 /
     2  ' COUPLING STRENGTH SCALED BY 1 - (', G14.5,
     3     ')**ITERATION.'   )
      IF ( .NOT. BLOKSW )  write (6, 27)
 27   FORMAT ( ' USING SEQUENTIAL ITERATION' / )                        10520   
      IF ( BLOKSW )  write (6, 28)
 28   FORMAT ( ' USING BLOCK (BORN) ITERATION' / )
      NLINE = 10
      IHEAD = 1
      PBUGSW = IPRNT .GE. 4
C
C
C
C     NO SPIN ORBIT FORCE
C                                                                       10530   
      ISPUN=1
C
C     SOME VARIABLES
C
C     SUMMAX = ASYMPTOPIA = MATCHING POINT
C     NUMPT = NUMBER OF GRID POINTS FROM 0 TO SUMMAX INCLUDING THE
C             LAST POINT.  THIS IS THE DIMENSION OF THE ONE-DIMENSIONAL
C             ARRAYS SUCH AS WAVR, RHSR, AND THE POTENTIALS
C     NSTEP = THE NUMBER OF STEPS = NUMPT-1
C     NPTMIN = THE NUMBER OF POINTS THAT ARE NEVER USED BECAUSE EVEN    10540   
C              THE WAVEFUNC FOR LMIN-LXMIN DOESN'T GO IN THAT FAR.
C              NPTMIN=0 MEANS ALL STEPS ARE USED.
C     NPTSAV = NUMPT-NPTMIN = THE NUMBER OF VALUES OF THE HOMO FUNCS
C              AND SOLUTIONS THAT MUST BE SAVED.  THIS IS THE FIRST
C              DIMENSION OF THE HOMO, INHR AND INHI ARRAYS.
C     NPSTRT = NPTMIN+1 = THE FIRST POINT TO BE USED.
C
C     ALLOC(LSMSQ) - S MATRICES FOR CURRENT AND PREVIOS ITERATION,
C                    RESPECTIVELY.
      NSTEP = NUMPT-1                                                   10550   
      NPTSAV = NUMPT-NPTMIN
      NPSTRT = NPTMIN+1
C
C************** TEMPORARY ****************************
C
      LBASDF=FACFR4*Z(IBASDF)-FACFR4+1
      NBASDF=ILLOC(LBASDF)
      NUMINH = NPTSAV*NBASDF
      IF ( BLOKSW )  IBLOCK = NALLOC( (2*NUMINH+1)/FACFR4, 'BLOCKSAV' )
      IF ( BLOKSW )  ISBLOK = NALLOC( 2*NBASDF, 'SBLOCKSA' )            10560   
C
C************** END TEMPORARY ************************
C
      CALL SETLOG ( 2*(LOMOST+LXMAX) )
C
C     WE WILL HAVE NO MORE  ALLOC CALLS SO GET ADDRESSES
C
      LHOMO = FACFR4*Z(IHOMO)-FACFR4+1 - 2*NPTMIN
      LHOMO = Z(IHOMO) - 2*NPTMIN                                       c8h
cccC8H%'ALLOC4(LHOMO' = 'ALLOC(LHOMO'                                   10570   
cccC8H%'ALLOC4(NHOMO' = 'ALLOC(NHOMO' ;;;
      LINHR = FACFR4*Z(IINHR)-FACFR4+1 - NPTMIN
      LINHI = FACFR4*Z(IINHI)-FACFR4+1 - NPTMIN
      LINHR = Z(IINHR) - NPTMIN                                         c8h
      LINHI = Z(IINHI) - NPTMIN                                         c8h
cccC8H%'ALLOC4(LINH' = 'ALLOC(LINH'
cccC8H%'ALLOC4(NINH' = 'ALLOC(NINH' ;;;
      LHOMOA = Z(IHOMOA)
      LHOMOB = Z(IHOMOB)
      LINHR8 = Z(IINHR8) - 1                                            10580   
      LINHI8 = Z(IINHI8) - 1
      IF ( BLOKSW )  LBLOCK = FACFR4*Z(IBLOCK)-FACFR4
      IF ( BLOKSW )  LSBLOK = Z(ISBLOK)
      LRHSR=Z(IRHSR)
      LRHSI=Z(IRHSI)
      LSMSQ=Z(ISMSQ)
      LPADE=Z(IPADE)
      LLIS=FACFR4*Z(ILIS)-FACFR4
      LFG=FACFR4*Z(NFS(1))-FACFR4+1
      LWAVR=Z(IWAVR)                                                    10590   
      LWAVI=Z(IWAVI)
      LWRK1 = LWAVR-1
      LWRK2 = LWAVI-1
      LVRL1=Z(IRLVS(1))
      LVRL2=Z(IRLVS(2))
      LVIM1=Z(IIMVS(1))
      LVIM2=Z(IIMVS(2))
      LNUCH=FACFR4*Z(INUCH)-FACFR4+1
      LCOULH=FACFR4*Z(ICOULH)-FACFR4+1
      LCENT1=Z(ICENTR(1))                                               10600   
      LCENT2=Z(ICENTR(2))
      LCL1FF=FACFR4*Z(ICL1FF)-FACFR4+1
      LCL1FG=FACFR4*Z(ICL1FG)-FACFR4+1
      LBINDX=FACFR4*Z(IBINDX)-FACFR4+1
      LSMATS=Z(ISMATS(1))
      LCHNDF=FACFR4*Z(ICHNDF)-FACFR4+1
      LBASDF=FACFR4*Z(IBASDF)-FACFR4+1
      LBASCP=FACFR4*Z(IBASCP)-FACFR4+1
      NCHNDF=ILLOC(LCHNDF)
      NBASDF=ILLOC(LBASDF)                                              10610   
      NBASCP=ILLOC(LBASCP)
      MCHNDF=ILLOC(LCHNDF+1)
      MBASDF=ILLOC(LBASDF+1)
      MBASCP=ILLOC(LBASCP+1)
      LCHNDF=LCHNDF+ILLOC(LCHNDF+2)
      LBASDF=LBASDF+ILLOC(LBASDF+2)
      LBASCP=LBASCP+ILLOC(LBASCP+2)
      LCHNVL = Z(ICHNVL)
      LSMATR=Z(ISMATR)-1
      LSMATI=Z(ISMATI)-1                                                10620   
      LINDXS=FACFR4*(Z(IINDXS)-1)
      LELCUP=Z(IELCUP)-2
C
      IF ( IWRTWV .EQ. 0 )  GO TO 80
      call get_date ( thedat )
      WRITE ( 1, 53 )  HEADER, REACT, ELAB, THedat,
     1  NBASDF, NUMPT, SUMMAX, RSTEPS(1), AKI, REDMI
 53   FORMAT ( 65A1 / 45A1, F12.3, 1X, A /
     1  2I5, 2G25.15 /  2G25.15 )
C                                                                       10630   
C     INTRODUCE MAJOR LOOP OVER TOTAL ANGULAR MOMENTUN J
C
 80   DO 999 IJ=1,NUMLIS
C
C     INITIALISE RELEVANT ARRAYS TO ZERO
C
      CONVSW = MOD( IWRTWV, 10) .EQ. 2
CDIR$ IVDEP
      DO 84 I=1,NUMINH
c4h         ALLOC4(LINHR+NPTMIN+I-1)=0.                                 10640   
c4h         ALLOC4(LINHI+NPTMIN+I-1)=0.
         ALLOC(LINHR+NPTMIN+I-1)=0.                                     c8h
         ALLOC(LINHI+NPTMIN+I-1)=0.                                     c8h
 84   CONTINUE
      II = 2*NBASDF
CDIR$ IVDEP
      DO 85  I = 1, II
         ALLOC(LINHR8+I) = 0
         ALLOC(LINHI8+I) = 0
  85  CONTINUE                                                          10650   
      NWRDS = 4*NBASDF
      DO 87 I=1,NWRDS
      ALLOC(LSMSQ+I-1)=0.
 87   CONTINUE
C
C
      JT = ILLOC(LLIS+IJ)
      J = 2*JT
      NELCUP=LELCUP+2*IJ
      NADD = NBASDF                                                     10660   
      IF ( IPRNT .EQ. 0 )  NADD = 1
      IF ( NLINE+NADD+3 .LE. 59 )  GO TO 100
      write (6, 3) REACT, ELAB, HEADER
      NLINE = 5
C
C     CALCULATE B FACTORS
C
 100  IF (NOBFAC .EQ. 0)  CALL GETBFC ( IJ, J, NBACK*STEPSZ, SUMMAX,
     1   NMBFAC, ALLOC4(LCL1FF), ALLOC4(LCL1FG), MBINDX, ILLOC(LBINDX),
     2   MCHNDF, ILLOC(LCHNDF), MCHNVL, ALLOC(LCHNVL),                  10670   
     3   MBASDF, ILLOC(LBASDF), NBASDF, ALLOC4(LFG) )
C
C     LOOP OVER CHANNEL ARRAY INPUT
C
      DO 199 I1=1,NCHNDF
      LABEL=(I1-1)*MCHNDF+LCHNDF
      CKC = ALLOC(LCHNVL+MCHNVL*(I1-1))
C
C     INTRODUCE POINTERS I2,I3 FOR BASLBL ARRAY
C                                                                       10680   
      I2=ILLOC(LABEL+7)
      I3=ILLOC(LABEL+8)
      I3=I3+I2-1
C
C     LOOP OVER BASLBL ARRAY
C
      DO 194 I4=I2,I3
      LABEL1=(I4-1)*MBASDF+LBASDF
      J1=ILLOC(LABEL1+1)
      L1X2=ILLOC(LABEL1+2)                                              10690   
      L1X2 = L1X2+J
      IF ( L1X2 .LT. 0 )  GO TO 194
      L1 = L1X2/2
C
C     INTRODUCE POINTERS I5,I6 TO GENERATE BASCPL ARRAY
C
      I5=ILLOC(LABEL1+3)
      I6=ILLOC(LABEL1+4)
      I6=I6+I5-1
C                                                                       10700   
C     LOOP  OVER BASCPL ARRAY TO CALCULATE UNKNOWN QUANTITIES
C
      DO 120 I7=I5,I6
         LABEL2=(I7-1)*MBASCP+LBASCP
         IMULT=ILLOC(LABEL2+3)
         IPT=ILLOC(LABEL2+1)
         J2=ILLOC((IPT-1)*MBASDF+LBASDF+1)
         L2X2=ILLOC((IPT-1)*MBASDF+LBASDF+2)
         L2X2=L2X2+J
         CALL AKFCR(L1X2,J1,L2X2,J2,IMULT,J,ALLOC4(LABEL2+7))           10710   
 120  CONTINUE
C
C     GENERATE HOMOGENEOUS WAVEFUNCTION
C
      NWP=2
C     FOR INELASTIC SCATTERING USE NWP=1
      IF(I2.EQ.1)NWP=1
C
      AKS(NWP) = CKC
      HS(NWP)=CKC*RSTEPS(NWP)                                           10720   
C     LABEL FOR COULOMB FUNCTIONS
      LABEL2 = 4*(I4-1)+4*NBASDF*(IJ-1)
C8FC     CONVERT REAL*8 OFFSET TO REAL*4
C8F      LABEL2 = 2*LABEL2
      LABEL2 = LFG + LABEL2
      TT=second()
C
      IF(NWP.EQ.1)CALL WAVELJ(L1,ISPUN,1,0,DUMMY4,ALLOC4(LABEL2),DUMMY4,
     1ALLOC(LWAVR),ALLOC(LWAVI),ALLOC(LVRL1),ALLOC(LVIM1),ALLOC(LCENT1))
      IF(NWP.EQ.2)CALL WAVELJ(L1,ISPUN,2,0,DUMMY4,ALLOC4(LABEL2),DUMMY4,10730   
     1ALLOC(LWAVR),ALLOC(LWAVI),ALLOC(LVRL2),ALLOC(LVIM2),ALLOC(LCENT2))
C     STARTING LABEL
C
      TT1=second()
      TWAVE=TWAVE+TT1-TT
C
C     STARTING VALUE FOR THIS BASIS STATE
C
      NFIRST = MAX0( LASTNF(NWP) + NFIROF, NPTMIN+2 )
      ILLOC(LABEL1+5) = NFIRST                                          10740   
      ISTRT = NFIRST-2
C
C     LABEL FOR STORING HOMOGENEOUS WAVEFUNCTION
      II = 2*(I4-1)*NPTSAV
      IF ( PBUGSW )  write (6, 123) J, I4, NFIRST, ISTRT, NSTEP, II,
     1  NPTSAV, NPTMIN, LHOMO, LWAVR
 123  FORMAT (' J, BASIS, NFIRST =', I5, '/2', 10I9 )
CRACDIR$ IVDEP
      DO 125 I7 = ISTRT, NSTEP
c4h         ALLOC4(LHOMO+II+2*I7) = ALLOC(LWAVR+I7)                     10750   
c4h         ALLOC4(LHOMO+II+2*I7+1) = ALLOC(LWAVI+I7)
         ALLOC(LHOMO+II+2*I7) = ALLOC(LWAVR+I7)                         c8h
         ALLOC(LHOMO+II+2*I7+1) = ALLOC(LWAVI+I7)                       c8h
 125  CONTINUE
C
C     WE WANT FULL PRECISION FOR THE FIRST AND LAST VALUES
C
      ITEMP = NSTEP - NBACK
      DO 129  I = 1, 2
         ALLOC(LHOMOA+4*(I4-1)+2*I-2) = ALLOC(LWAVR+ISTRT+I-1)          10760   
         ALLOC(LHOMOA+4*(I4-1)+2*I-1) = ALLOC(LWAVI+ISTRT+I-1)
         ALLOC(LHOMOB+4*(I4-1)+2*I-2) = ALLOC(LWAVR+ITEMP)
         ALLOC(LHOMOB+4*(I4-1)+2*I-1) = ALLOC(LWAVI+ITEMP)
         ITEMP = NSTEP
 129  CONTINUE
C
      IF(I2.NE.1)GO TO 180
C
C     STORE ELASTIC WAVEFUNCTION FOR 0TH GUESS
C     STORE ELASTIC HOMOGENEOUS S-MATRIX                                10770   
C
      ALLOC(LSMSQ) = ALLOC(LSMATS+2*L1)
      ALLOC(LSMSQ+2*NBASDF) = ALLOC(LSMATS+2*L1)
      ALLOC(LSMSQ+1) = ALLOC(LSMATS+2*L1+1)
      ALLOC(LSMSQ+1+2*NBASDF) = ALLOC(LSMATS+2*L1+1)
C
      DO 175  I = 1, 2
         ALLOC(LINHR8+I) = ALLOC(LWAVR+ISTRT+I-1)
         ALLOC(LINHI8+I) = ALLOC(LWAVI+ISTRT+I-1)
 175  CONTINUE                                                          10780   
      II = II/2
CRACDIR$ IVDEP
      DO 179 I7 = ISTRT, NSTEP
c4h         ALLOC4(LINHR+II+I7) = ALLOC(LWAVR+I7)
c4h         ALLOC4(LINHI+II+I7) = ALLOC(LWAVI+I7)
         ALLOC(LINHR+II+I7) = ALLOC(LWAVR+I7)                           c8h
         ALLOC(LINHI+II+I7) = ALLOC(LWAVI+I7)                           c8h
 179  CONTINUE
180   CONTINUE
 194  CONTINUE                                                          10790   
 199  CONTINUE
C
      IF ( .NOT. BLOKSW )  GO TO 300
CDIR$ IVDEP
      DO 209  I = 1, NUMINH
c4h         ALLOC4(LBLOCK+I) = ALLOC4(LINHR+NPTMIN+I-1)
c4h         ALLOC4(LBLOCK+NUMINH+I) = ALLOC4(LINHI+NPTMIN+I-1)
         ALLOC4(LBLOCK+I) = ALLOC(LINHR+NPTMIN+I-1)                     c8h
         ALLOC4(LBLOCK+NUMINH+I) = ALLOC(LINHI+NPTMIN+I-1)              c8h
 209  CONTINUE                                                          10800   
CDIR$ IVDEP
      DO 219  I = 1, NBASDF
         ALLOC(LSBLOK+2*I-2) = ALLOC(LSMSQ+2*I-2)
         ALLOC(LSBLOK+2*I-1) = ALLOC(LSMSQ+2*I-1)
 219  CONTINUE
C
C     START ITERATIVE SOLUTION OF INHOMOGENEOUS EQUATIONS
C
 300  TT=second()
      VFACTR = 1                                                        10810   
      DO 899 ITR=1,MAXITR
C
      VFACTR = VFACTR*VSCALE
      VMULT = 1 - VFACTR
C
C     LOOP OVER CHANNEL ARRAY INPUT
C      DO ELASTIC CHANNEL LAST
C
      DO 699 I1=1,NCHNDF
      ICHAN = I1+1                                                      10820   
      IF ( I1 .EQ. NCHNDF )  ICHAN = 1
      LABEL=(ICHAN-1)*MCHNDF+LCHNDF
C
      NWP = 2
      IF ( ICHAN .EQ. 1 )  NWP = 1
C
      HS(NWP) = ALLOC(LCHNVL+MCHNVL*(ICHAN-1))*RSTEPS(NWP)
C     INTRODUCE POINTERS I2,I3 FOR BASLBL ARRAY
      I2=ILLOC(LABEL+7)
      I3=ILLOC(LABEL+8)                                                 10830   
      I3=I3+I2-1
C
C     LOOP OVER BASLBL ARRAY AND PICK UP RELEVANT QUANTITIES
C
      DO 689 I4=I2,I3
      LABEL1=(I4-1)*MBASDF+LBASDF
      L1X2 = ILLOC(LABEL1+2)
      L1X2 = L1X2+J
      IF ( L1X2 .LT. 0 )  GO TO 689
      L1 = L1X2/2                                                       10840   
      NFIRST=ILLOC(LABEL1+5)
C     INTRODUCE POINTERS I5,I6 TO ANALYSE BASCPL ARRAY
      I5=ILLOC(LABEL1+3)
      I6=ILLOC(LABEL1+4)
      I6=I6+I5-1
C
C     CONSTRUCT DRIVING TERM OF INHOMOGENEOUS EQUATION
C
      TT2=second()
c4h      CALL DRIVE ( ALLOC(LRHSR),ALLOC(LRHSI),I5,I6,NFIRST,ITR,       10850   
c4h     1  MBASCP, ILLOC(LBASCP), ALLOC4(LBASCP), ALLOC4(LNUCH),
c4h     2  ALLOC4(LCOULH), NUMPT, NPTSAV, ALLOC4(LINHR), ALLOC4(LINHI),
c4h     3  FLP, VMULT )
      CALL DRIVE ( ALLOC(LRHSR),ALLOC(LRHSI),I5,I6,NFIRST,ITR,          c8h
     1  MBASCP, ILLOC(LBASCP), ALLOC4(LBASCP), ALLOC4(LNUCH),           c8h
     2  ALLOC4(LCOULH), NUMPT, NPTSAV, ALLOC(LINHR), ALLOC(LINHI),      c8h
     3  FLP, VMULT )                                                    c8h
C
C     IF NO RHS WAS COMPUTED, THERE IS NOTHING TO DO
C                                                                       10860   
      IF ( FLP .EQ. 0 )  GO TO 689
C
      TT3=second()
      TRIGHT=TRIGHT+TT3-TT2
      FLPRHS = FLPRHS + FLP
C
C     CONSTRUCT DIAGONAL POTENTIAL IN FORM USEFULL FOR
C     NUMEROV ALGORITHUM AND SOLVE INHOMOGENEOUS EQUNS.
C
C     THE STORING TECHNIQUE IS TAKEN FROM WAVELJ PLUS DRIVING TERM      10870   
C     WE COMPUTE 12*WAVEFUNCTION
C     THIS IS CORRECTED FOR IN CONSTRUCTING R.H.S AND C-FACTOR
C
      ISTRT=(I4-1)*NPTSAV
      NHOMO=LHOMO+2*ISTRT
      NINHR=LINHR+ISTRT
      NINHI=LINHI+ISTRT
      NINHR8 = LINHR8 + 2*(I4-1)
      NINHI8 = LINHI8 + 2*(I4-1)
      NHOMOA = LHOMOA + 4*(I4-1) - 2                                    10880   
      IF ( BLOKSW )  NINHR = LBLOCK - NPTMIN+ISTRT+1
      IF ( BLOKSW )  NINHI = NINHR + NUMINH
      ISTRT=NFIRST-2
C
C     GET FIRST TWO 12*U'S
C
      II=ISTRT+1
 530  DO 539 I = 1, 2
         ALLOC(LWRK1+ISTRT+I) = ALLOC(NINHR8+I)
         ALLOC(LWRK2+ISTRT+I) = ALLOC(NINHI8+I)                         10890   
539   CONTINUE
C
C     CONSTRUCT DIAGIONAL POTENTIAL AND STORE IN WORK ARRAY
C
 540  CALL WAVELJ ( L1, JP, NWP, -NFIRST, DUMMY4, DUMMY4, DUMMY4,
     1  ALLOC(LWRK1+1), ALLOC(LWRK2+1),
     2  ALLOC(Z(IRLVS(NWP))), ALLOC(Z(IIMVS(NWP))),
     3  ALLOC(Z(ICENTR(NWP))) )
C
      IF ( IPRNT .GE. 5 )  write (6, 543) I4, ISTRT,                    10900   
     1  ( ALLOC(LWRK1+I7+1), ALLOC(LWRK2+I7+1), I7 = ISTRT, II ),
     2  ALLOC(LWRK1+II+4), ALLOC(LWRK2+II+4),
     3  ALLOC(LRHSR+NFIRST-1), ALLOC(LRHSI+NFIRST-1)
 543  FORMAT ( ' ++', I3, I5, 8G15.6 )
C
C     START ACTUAL INTGRATION OF INHOMOGENEOUS EQUATION
C
      TT2 = second()
      TUOPT = TUOPT + TT2-TT3
      FLPUOP = FLPUOP + 3*(NSTEP-NFIRST)                                10910   
C
      CALL WAVINH ( NFIRST, NSTEP, ALLOC(LWRK1+1), ALLOC(LWRK2+1),
     1  ALLOC(LRHSR), ALLOC(LRHSI), FLP, NSTEP+5 )
C
      TINHO = TINHO + second() - TT2
      FLPINH = FLPINH + FLP
      NMINHO = NMINHO + 1
      NMINPT = NMINPT + NSTEP - NFIRST +1
C
C     CALCULATE MATCHING CONDITION                                      10920   
C
      CALL CCMTCH(IJ,J,I4,ALLOC(LSMSQ),CFAC,NBASDF,ALLOC(LWRK1+1),
     1  ALLOC(LWRK2+1), NPTSAV, ALLOC(LHOMOB), MBASDF, ILLOC(LBASDF),
     2  MBASCP, ILLOC(LBASCP), ALLOC4(LBASCP),
     3  MCHNVL, ALLOC(LCHNVL), ALLOC4(LCL1FG),
     4  MBINDX, ILLOC(LBINDX), ALLOC4(LFG), VMULT )
C
      IF ( PBUGSW ) write (6, 593) ITR, J, I4, ALLOC(LSMSQ+2*I4-2),
     1  ALLOC(LSMSQ+2*I4-1)
     1,CFAC                                                             10930   
593   FORMAT(' CCMTCH,ITER,J,I4=',2I5,'/2',I5,3X,
     1'S=',2G15.5,3X,'C=',2G15.5)
C
C     IF NECESSARY, PATCH UP FOR BLOCK BY PRESERVING THE OLD S-MATRIX
C
      IF ( .NOT. BLOKSW )  GO TO 610
      DO 609  I = 1, 2
         TEMP = ALLOC(LSMSQ+2*I4+I-3)
         ALLOC(LSMSQ+2*I4+I-3) = ALLOC(LSBLOK+2*I4+I-3)
         ALLOC(LSBLOK+2*I4+I-3) = TEMP                                  10940   
 609  CONTINUE
C
C     CALCULATE NORMALISED WAVEFUNCTION AND BLEND IT IN
C
 610  CFACR8=REAL(CFAC)
      CFACR = CFACR8
      CFACI8=DIMAG(CFAC)
      CFACI = CFACI8
      TT2 = second()
      IF ( BLEND .NE. 1 )  GO TO 640                                    10950   
      DO 632  I = 1, 2
         ALLOC(NINHR8+I) = ALLOC(LWRK1+ISTRT+I)
     1    + ( CFACR8*ALLOC(NHOMOA+2*I) - CFACI8*ALLOC(NHOMOA+2*I+1) )
         ALLOC(NINHI8+I) = ALLOC(LWRK2+ISTRT+I)
     1    + ( CFACR8*ALLOC(NHOMOA+2*I+1) + CFACI8*ALLOC(NHOMOA+2*I) )
 632  CONTINUE
CRACDIR$ IVDEP
      DO 634 I=ISTRT, NSTEP
c4h         ALLOC4(NINHR+I)=ALLOC(LWRK1+I+1) + (CFACR*ALLOC4(NHOMO+2*I)
c4h     1     -CFACI*ALLOC4(NHOMO+2*I+1))                               10960   
c4h         ALLOC4(NINHI+I)=ALLOC(LWRK2+I+1) + (CFACR*ALLOC4(NHOMO+2*I+1
c4h     1     +CFACI*ALLOC4(NHOMO+2*I))
         ALLOC(NINHR+I)=ALLOC(LWRK1+I+1) + (CFACR*ALLOC(NHOMO+2*I)      c8h
     1     -CFACI*ALLOC(NHOMO+2*I+1))                                   c8h
         ALLOC(NINHI+I)=ALLOC(LWRK2+I+1) + (CFACR*ALLOC(NHOMO+2*I+1)    c8h
     1     +CFACI*ALLOC(NHOMO+2*I))                                     c8h
 634  CONTINUE
      TEMP = 8
      GO TO 650
C                                                                       10970   
C     HERE WE ARE REALLY BLENDING
C
 640  TEMP = 1-BLEND
      DO 642  I = 1, 2
         ALLOC(NINHR8+I) = TEMP*ALLOC(NINHR8+I)
     1    + BLEND*( ALLOC(LWRK1+ISTRT+I)
     2    + ( CFACR8*ALLOC(NHOMOA+2*I) - CFACI8*ALLOC(NHOMOA+2*I+1) ) )
         ALLOC(NINHI8+I) = TEMP*ALLOC(NINHI8+I)
     1    + BLEND*( ALLOC(LWRK2+ISTRT+I)
     2    + ( CFACR8*ALLOC(NHOMOA+2*I+1) + CFACI8*ALLOC(NHOMOA+2*I) ) ) 10980   
 642  CONTINUE
CDIR$ IVDEP
      DO 645  I = ISTRT, NSTEP
c4h         ALLOC4(NINHR+I) = TEMP*ALLOC4(NINHR+I) + BLEND*(
c4h     1         ALLOC(LWRK1+I+1) + (CFACR*ALLOC4(NHOMO+2*I)
c4h     1     -CFACI*ALLOC4(NHOMO+2*I+1)) )
c4h         ALLOC4(NINHI+I) = TEMP*ALLOC4(NINHI+I) + BLEND*(
c4h     1          ALLOC(LWRK2+I+1) + (CFACR*ALLOC4(NHOMO+2*I+1)
c4h     1     +CFACI*ALLOC4(NHOMO+2*I)) )
         ALLOC(NINHR+I) = TEMP*ALLOC(NINHR+I) + BLEND*(                 10990   
     1         ALLOC(LWRK1+I+1) + (CFACR*ALLOC(NHOMO+2*I)               c8h
     1     -CFACI*ALLOC(NHOMO+2*I+1)) )                                 c8h
         ALLOC(NINHI+I) = TEMP*ALLOC(NINHI+I) + BLEND*(                 c8h
     1          ALLOC(LWRK2+I+1) + (CFACR*ALLOC(NHOMO+2*I+1)            c8h
     1     +CFACI*ALLOC(NHOMO+2*I)) )                                   c8h
 645  CONTINUE
      TEMP = 14
 650  TT4 = second()
      TNORM = TNORM + TT4 - TT2
      FLPNRM = FLPNRM + TEMP*(NSTEP-ISTRT+1)                            11000   
C
      IF ( .NOT. CONVSW )  GO TO 689
C
C     WRITE OUT THE WAVEFUNCTIONS AND RHS
C
      IF ( IWRTWV .GE. 10  .AND.  ICHAN .NE. 1 )  GO TO 689
      I = NFIRST-1
c4h      WRITE ( 1, 663 )  JT, ITR, ICHAN, I4, I,
c4h     1  ( ALLOC4(NINHR+I7), ALLOC4(NINHI+I7), ALLOC(LRHSR+I7),
c4h     2    ALLOC(LRHSI+I7), I7 = ISTRT, NSTEP )                       11010   
      WRITE ( 1, 663 )  JT, ITR, ICHAN, I4, I,                          c8h
     1  ( ALLOC(NINHR+I7), ALLOC(NINHI+I7), ALLOC(LRHSR+I7),            c8h
     2    ALLOC(LRHSI+I7), I7 = ISTRT, NSTEP )                          c8h
 663  FORMAT ( 5I5 / ( 4G16.8 ) )
C
C     END OF LOOPS OVER ALL CHANNELS AND BASIS STATES
C
689   CONTINUE
699   CONTINUE
C                                                                       11020   
C     NOW MOVE OVER THE NEW S-MATRICES FOR BLOCK ITERATION
C
      NWRDS = 2*NBASDF
      IF ( .NOT. BLOKSW )  GO TO 820
CDIR$ IVDEP
      DO 804  I = 1, NWRDS
         ALLOC(LSMSQ+I-1) = ALLOC(LSBLOK+I-1)
 804  CONTINUE
C
C     TEST FOR CONVERGENCE OF S-MATRIX ELEMENTS                         11030   
C
 820  TT4 = second()
      CALL CCONV(ALLOC(LSMSQ), ITR, ITEST, NBASDF, ALLOC(LPADE),
     1   (MAXITR+1)/2,
     1   ALLOC(NELCUP), ALLOC(LSMATR), ALLOC(LSMATI), ILLOC(LINDXS),
     2   ILLOC(LCHNDF), MCHNDF, ILLOC(LBASDF), MBASDF, IJ, NCHNDF,
     3   JT, NLINE, IHEAD, NFLOP )
      FLPADE = FLPADE + NFLOP
      TPADE = TPADE + second() - TT4
C                                                                       11040   
C     IF DESIRED, SAVE THE S-MATRICES FOR EACH ITERATION
C
      IF ( ISAVSM .EQ. 0 )  GO TO 840
      IP = ISAVSM/2
      IS = ISAVSM - 2*IP
      LSMTSV = Z(ISMTSV) + 2*(IS+IP)*NBASDF*(ITR-1) - 1
      IF ( IS .EQ. 0 )  GO TO 835
CDIR$ IVDEP
      DO 834  I = 1, NWRDS
         ALLOC(LSMTSV+I) = ALLOC(LSMSQ+I-1)                             11050   
 834  CONTINUE
      LSMTSV = LSMTSV + 2*NBASDF
 835  IF ( IP .EQ. 0 )  GO TO 840
      IS = 2*3*((MAXITR+1)/2)
      IP = LPADE + 2*( 3*((ITR-1)/2) + 3 - 1 )
CDIR$ IVDEP
      DO 839  I = 1, NBASDF
         ALLOC(LSMTSV+2*I-1) = ALLOC(IP+(I-1)*IS)
         ALLOC(LSMTSV+2*I) = ALLOC(IP+(I-1)*IS+1)
 839  CONTINUE                                                          11060   
 840  IF ( ITEST .EQ. 0 )  GO TO 850
C
C     WE HAVE CONVERGE, MUST WE DO ONE MORE TO WRITE IT OUT?
C
      IF ( IWRTWV .EQ. 0  .OR.  CONVSW )  GO TO 950
      CONVSW = .TRUE.
C
C     FOR BLOCK, TRANSFER THE NEW SET OF SOLUTIONS NOW
C
 850  IF ( .NOT. BLOKSW )  GO TO 899                                    11070   
CDIR$ IVDEP
      DO 859  I = 1, NUMINH
c4h         ALLOC4(LINHR+NPTMIN+I-1) = ALLOC4(LBLOCK+I)
c4h         ALLOC4(LINHI+NPTMIN+I-1) = ALLOC4(LBLOCK+NUMINH+I)
         ALLOC(LINHR+NPTMIN+I-1) = ALLOC4(LBLOCK+I)                     c8h
         ALLOC(LINHI+NPTMIN+I-1) = ALLOC4(LBLOCK+NUMINH+I)              c8h
 859  CONTINUE
C
C     END OF ITERATION LOOP
C                                                                       11080   
899   CONTINUE
      ITR = MAXITR
C
 950  TT1=second()
      TITER=TITER+TT1-TT
C
999   CONTINUE
C
C     TIMING INFORMATION
C                                                                       11090   
      TFIN=second()
      TTOT=TFIN-TSTART
      TREST=TTOT-TITER-TWAVE
      TITER2 = TITER - TRIGHT - TINHO - TNORM - TUOPT - TPADE
      IF ( NLINE .GT. 38 )  write (6, 3) REACT, ELAB, HEADER
      write (6, 1503) TWAVE, TRIGHT, TUOPT, TINHO, TNORM, TPADE,
     1  TITER2, TREST, TTOT
1503  FORMAT('0COUPLED EQUATIONS COMPUTATION TIME (SECONDS):'/
     1  '0HOMOGENEOUS SOLUTIONS:', T25, F9.3/
     2  ' DRIVING TERM:', T25, F9.3/                                    11100   
     2  ' CONSTRUCTING OPT. POT.', T25, F9.3 /
     3  ' INHOMOGENEOUS SOLUTIONS:', T25, F9.3 /
     3  ' NORMALIZATION:', T25, F9.3 /
     3  ' PADE AND CONVERG. CHECK:', T25, F9.3 /
     3  ' OTHER ITERATION TIME:', T25, F9.3 /
     4  ' REST OF COUPLN TIME:', T25, F9.3/
     5  ' TOTAL COUPLN TIME:', T35, F9.3/)
C
      NUMITS = NMINHO/NBASDF
      TPRJ = TTOT/NUMLIS                                                11110   
      TPRIT = TITER/NUMITS
      TPRRHS = 1000.*TRIGHT/NMINHO
      FLPRHS = 1.E-6*FLPRHS
      TFLRHS = FLPRHS/(TRIGHT+1.e-20)
      TPRINH = 1000.*TINHO/NMINHO
      FLPINH = 1.E-6*FLPINH
      TFLINH = FLPINH/(TINHO+1.e-20)
      TPRSTP = 1.E+6*TINHO/NMINPT
      TPRNRM = 1000.*TNORM/NMINHO
      FLPNRM = 1.D-6*FLPNRM                                             11120   
      TFLNRM = FLPNRM/(TNORM+1.e-20)
      TPRPAD = 1000.*TPADE/NMINHO
      FLPADE = 1.D-6*FLPADE
      TFLPAD = FLPADE/(TPADE+1.e-20)
CCC      FLPITR = FLPRHS + FLPINH + FLPNRM + 1.E-6*FLPUOP + FLPPAD
CCC      TFLITR = FLPITR/TITER
C
      write (6, 1533) TPRJ, TPRIT,  NMINHO, TPRRHS,
     1  FLPRHS, TFLRHS, TPRINH, FLPINH, TFLINH,
     2  TPRNRM, FLPNRM, TFLNRM,                                         11130   
     3  TPRPAD, FLPADE, TFLPAD, NMINPT, TPRSTP
 1533 FORMAT ( '0TOTAL TIME PER J-VALUE:',
     1      T42, F13.3, ' SECONDS' /
     2  ' TIME PER ITERATION:',
     1      T42, F13.3, ' SECONDS'  /
     3  I8, ' RIGHT-HAND SIDES; TIME PER RHS:',
     4      T42, F13.3, ' MILLISECONDS',
     5      T80, '(', F12.3, ' MFLOP,', F10.3, ' MFLOP/SEC.)' /
     6  9X, 'TIME PER INHOMO. SOLUTION:',
     4      T42, F13.3, ' MILLISECONDS',                                11140   
     5      T80, '(', F12.3, ' MFLOP,', F10.3, ' MFLOP/SEC.)' /
     9  9X, 'TIME PER NORMALIZATION:',
     4      T42, F13.3, ' MILLISECONDS',
     5      T80, '(', F12.3, ' MFLOP,', F10.3, ' MFLOP/SEC.)' /
     9  9X, 'TIME PER PADE & CONVRG:',
     4      T42, F13.3, ' MILLISECONDS',
     5      T80, '(', F12.3, ' MFLOP,', F10.3, ' MFLOP/SEC.)' /
     7  I10, ' NUMEROV STEPS, TIME PER STEP:',
     8      T42, F13.3, ' MICROSECONDS' )
C                                                                       11150   
C     FREE ARRAYS
C
      IF(MOD(IPRINT/100,10).GE.1)GO TO 2000
C
      IF ( BLOKSW )  Z(IBLOCK) = -Z(IBLOCK)
      Z(IHOMO)=-Z(IHOMO)
      Z(IINHR)=-Z(IINHR)
      Z(IINHI)=-Z(IINHI)
      Z(IRHSR)=-Z(IRHSR)
      Z(IRHSI)=-Z(IRHSI)                                                11160   
      Z(ISMSQ)=-Z(ISMSQ)
      Z(IWAVR)=-Z(IWAVR)
      Z(IWAVI)=-Z(IWAVI)
      Z(IPADE)=-Z(IPADE)
      Z(INUCH) = -Z(INUCH)
      Z(ICOULH) = -Z(ICOULH)
      Z(ICL1FF) = -Z(ICL1FF)
      Z(ICL1FG) = -Z(ICL1FG)
      Z(NFS(1)) = -Z(NFS(1))
      DO 1699  I = 1, 2                                                 11170   
         Z(IRLVS(I)) = -Z(IRLVS(I))
         Z(IIMVS(I)) = -Z(IIMVS(I))
         Z(ICENTR(I)) = -Z(ICENTR(I))
 1699 CONTINUE
2000  CONTINUE
C
      I = 1
      IF ( ISAVSM .EQ. 3 )  I = 2
      IF ( ISAVSM .NE. 0 )  CALL IREDEF ( 2*I*NBASDF*ITR, ISMTSV )
      RETURN                                                            11180   
      END
C*ID* CTRAN    C109.PTOLEMY.SOURCE                          PER701  22:
      SUBROUTINE CTRAN(IRET)
C
C     INPUT ROUTINE FOR GENERAL MULTIPLE/BETA VALUES
C
C     STRUCTURE OF DATA IN ALLOCATOR IS
C     PREFACE
C     LDATA +0 #BLOCKS
C           +1 BLOCK LENGTH                                             11190   
C           +2 PREFACE LENGTH
C     +3 FOR TARGET:  0 = NOT SPECIFIED; > 0 IS POINTER (RELATIVE TO
C           LTRANS) OF FIRST ENTRY.
C     +4 FOR PROJECTILE:  SAME AS +3 BUT FOR PROJECTILE.
C     +5 NO OF TARGET SETS
C     +6 NO OF PROJECTILE SETS
C     +7 IS BE(UP) (-1) OR BETAC (0) BEING USED FOR TARGET
C     +8 IS BE(UP) (-1) OR BETAC (0) BEING USED FOR PROJECTILE
C     FOR EACH DATA SET
C     LABEL +0 MULTIPOLE                                                11200   
C     +1 BELX/BETAC
C     +2 BETAN
C
C     12/79 - FIRST VERSION - MRB
C     1/16/80 - STORE ADDRESS IN CCBLK - S.P.
C     7/3/80 - FIX ORDER OF NXVALF CALLS, COMMENTS - S.P.
C     7/7/80 - CHANGE DEFS OF +3 AND +4 - S.P.
C     12/10/80 - -1 FOR BE - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      COMMON /CCBLK/  ICHNDF, ICHNCP, ITRANS, IBASDF, IBASCP,           /ccblk/
     &    ICCBLK(2), IORDX, MCHNVL, ICHNVL,
     &    IHOMOA, IHOMOB, IINHR8, IINHI8
 
      parameter ( ibufsize = 200 )                                      /inpbuf/
      CHARACTER*1 IBUF(ibufsize)
      COMMON /INPBUF/ NOCH, INCH, IBUF
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      DATA NUMKEY/8/
      character*8 KEYS(8) /'TARGET','PROJECTI','MULTIPOL','BELX',
     1  'BEUP', 'BE', 'BETAC','BETAN'/
      DATA LENDAT /3/,LAL/9/
      character*8 NAME8/'TRANSITI'/
      character*8 anames, akey                                          11220   
      COMMON /NAMCOM/ ANAMES(1)
      INTEGER GIVEAL
C
c
C
      ICD3I=1
      IRET=0
      ICG=1
      ICH1=0
10    ICH=0                                                             11230   
      IBN=0
      IBC=0
      IMT=0
      IF(ICG.EQ.2)GO TO 90
      I=NAMLOC(NAME8)
      IF(I.NE.0)Z(I)=-Z(I)
      ITRANS=GIVEAL(IWRDS)
      LDATA=Z(ITRANS)
      ANAMES(ITRANS)=NAME8
      LTRANS=FACFR4*(LDATA-1)+1                                         11240   
      LABEL=LTRANS+LAL
      ILLOC(LTRANS+3)=0
      ILLOC(LTRANS+4)=0
      ILLOC(LTRANS+5)=0
      ILLOC(LTRANS+6)=0
      ILLOC(LTRANS+7) = NOTDEF
      ILLOC(LTRANS+8) = NOTDEF
20    CALL FITKEY(AKEY,*90,*900,*900,*900)
      GO TO 900
C                                                                       11250   
C     (ENCOUNTERED LETS GO
C     FIRST READ THE KEYWORD LIST
C
C     *** NOTE ***  HERE WE HAVE IPT = 1, 2 FOR TARGET, PROJECTILE,
C     BUT IN BASCPL AND POTRHS, IT IS THE OTHER WAY AROUND (ENGLISHMEN
C     CAN BE MOST PECULIAR).
C
90    IORDER=0
      IPT = 0
100   CALL NXWORD(AKEY,*699,*900,*900)                                  11260   
      DO 110 I=1,NUMKEY
      IF(KEYS(I).NE.AKEY)GO TO 110
      IF ( I .GE. 3  .AND.  IPT .EQ. 0 )  GO TO 930
      GO TO (200,200,300,350,350,350,400,450 ),I
110   CONTINUE
      GO TO 900
200   ILLOC(LTRANS+2+I) = LABEL-LTRANS
      IF(IORDER.NE.0)GO TO 930
      IPT = I
      GO TO 100                                                         11270   
300   IORDER=IORDER+1
      IMT=IORDER
      GO TO 100
C     BE
350   IORDER=IORDER+1
      IBC=IORDER
      ILLOC(LTRANS+6+IPT) = -1
      GO TO 100
C     BETAC
400   IORDER=IORDER+1                                                   11280   
      IBC=IORDER
      ILLOC(LTRANS+6+IPT) = 0
      GO TO 100
C     BETAN
450   IORDER=IORDER+1
      IBN=IORDER
      GO TO 100
C
C     END OF KEYWORDS, GO ON TO DATA
C                                                                       11290   
699   CONTINUE
      LABEL=LABEL-LENDAT
C
C     READ THE NEXT SET OF DATA
C
700   LABEL=LABEL+LENDAT
      ILLOC(LABEL)=NOTDEF
      ALLOC4(LABEL+1)=UNDEF4
      ALLOC4(LABEL+2)=UNDEF4
      DO 750 I=1,IORDER                                                 11300   
      IF(I.EQ.IMT)GO TO 720
      IF(I.EQ.IBC)GO TO 730
      CALL NXVALF(TEMP, *910, *800, *910,*890)
      ALLOC4(LABEL+2)=TEMP
      GO TO 750
720   CALL NXHINT(INT,*910,*800,*885)
      ILLOC(LABEL)=INT
      GO TO 750
730   CALL NXVALF(TEMP, *910, *800, *910,*890)
      ALLOC4(LABEL+1)=TEMP                                              11310   
750   CONTINUE
      ICH=ICH+1
      GO TO 700
C
C     SEMI-COLON FOUND, GO TO NEXT NUCLEUS
C
 800  ILLOC(LTRANS+4+IPT) = ICH
      ICH1=ICH
      ICG=ICG+1
      GO TO 10                                                          11320   
885   CALL FITKEY(AKEY,*900,*900,*890,*900)
      GO TO 900
 890  ILLOC(LTRANS+4+IPT) = ICH
      ILLOC(LTRANS)=ICH1+ICH
      ILLOC(LTRANS+1)=LENDAT
      ILLOC(LTRANS+2)=LAL
      IWRDS=(LABEL-LTRANS)/FACFR4+1
      IL=CHOPIT(IWRDS)
      IRET=1
      RETURN                                                            11330   
C
900   WRITE(6,901)(KEYS(I),I=1,NUMKEY)
901   FORMAT ( '0**** DATA NOT ENCLOSED IN PARENTHESIS OR KEYWORD',
     1   ' MISSPELLED, DATA KEYWORDS ARE:' // ( 1X, 10A9 ) )
      RETURN
910   WRITE(6,911)I
911   FORMAT ( '0**** ERROR IN READING THE',I5,
     1  ' NUMERICAL DATA VALUE IN A SET' )
      RETURN
930   WRITE(6,931)                                                      11340   
931   FORMAT ( '0**** MUST USE PROJECTILE OR TARGET KEYWORD FIRST' )
      RETURN
      END
C*ID* CUBMAP   C109.PTOLEMY.SOURCE                          PER701  17:
      SUBROUTINE CUBMAP (MAPTYP, XLO, XMID, XHI, GAMMA, ARGS, WTS, NPTS)
C
C     CUBIC-SINH MAPPING OF _-1,1_ INTO _XLO,XHI_
C
C     MAPTYP CONTROLS THE TYPE OF MAP:
C     0 - LINEAR MAP                                                    11350   
C     1 - CUBIC SINH MAP
C     2 - RATIONAL SINH MAP
C     3 - LINEAR SINH MAP
C
C     0 MAPPED ON XMID; GAMMA SCALES SINH TRANSFORMATION SUCH
C     THAT GAUSS POINTS ARE PILED UP MOST DENSELY AROUND XMID
C      MHM 2/19/75
C     IF MAPTYP.NE.1 REPLACE CUBIC-SINH BY RATIONAL-SINH MAP
C     MHM 2/21/75
C     3/4/75 - LINEAR MAP ADDED - S.P.                                  11360   
C     3/5/75 - MAPTYP MADE AN ARGUMENT
C     6/28/75 - USE GAUSSL
C
C
      implicit real*8 ( a-h, o-z )                                      implicit
CDC      ALLOCLEVEL ARGS,WTS
C
      DIMENSION ARGS(1),WTS(1)
C
C     FOLLOWING IS ARCSINH(GAMMA)                                       11370   
C
      IF ( GAMMA .GT. 1.D-6 )  TAU=DLOG(GAMMA+DSQRT(GAMMA**2+1.D0))
      IF ( GAMMA .LE. 1.D-6 )  TAU = GAMMA*(1 - GAMMA**2/6)
C
      CALL GAUSSL ( NPTS, ARGS, WTS )
      XLEN=XHI-XLO
      XADD=XLO+XHI
C
      JGO = MAPTYP + 1
      GO TO ( 100, 200, 300, 400 ), JGO                                 11380   
C
C     LINEAR MAP
C
 100  DO 159  I = 1, NPTS
         ARGS(I) = XLO + (.5*XLEN)*(ARGS(I)+1)
         WTS(I) = (.5*XLEN) * WTS(I)
 159  CONTINUE
      RETURN
C
C     CUBIC-SINH MAPPING                                                11390   
C
 200  XMID=DMAX1 (XMID,XLO+XLEN/7.D0)
      XMID=DMIN1 (XMID,.5*XADD)
      A=.5*XADD-XMID
      B=.5*XLEN
      C=.5*XADD
      DO 259 I=1,NPTS
      TU=TAU*ARGS(I)
      XI=DSINH(TU)/GAMMA
      ARGS(I)=A*(XI**2-1.D0)*(XI+1.D0)+B*XI+C                           11400   
  259 WTS(I)=WTS(I)*(TAU/GAMMA)*DCOSH(TU)*((3.D0*XI-1.D0)*(XI+1.D0)*A+B)
      RETURN
C
C     RATIONAL-SINH MAPPING
C
C     THIS MAP IS DEFINED FOR ALL   XLO < XMID < XHI
C     HOWEVER, FOR   XMID = (XLO+XHI)/2   IT REDUCES TO A LINEAR
C     MAP, AND FOR   XMID > (XLO+XHI)/2   IT BUNCHES POINTS AT THE
C     HIGH END.
C                                                                       11410   
  300 A=-XMID*XLEN
      B=XLEN
      C=XMID*XADD-2.D0*XLO*XHI
      D=XADD-2.D0*XMID
      DO 359 I=1,NPTS
      TU=TAU*ARGS(I)
      SH=DSINH(TU)
      DENOM=B-(D/GAMMA)*SH
      ARGS(I)=(-A+(C/GAMMA)*SH)/DENOM
  359 WTS(I)=WTS(I)*(TAU/GAMMA)*DCOSH(TU)*((B*C-A*D)/DENOM**2)          11420   
      RETURN
C
C     LINEAR SINH MAPPING
C
 400  DO 459  I = 1, NPTS
         TU = TAU*ARGS(I)
         ARGS(I) = XLO + (.5*XLEN) * (DSINH(TU)/GAMMA + 1)
         WTS(I) = (.5*XLEN*TAU/GAMMA) * DCOSH(TU) * WTS(I)
 459  CONTINUE
      RETURN                                                            11430   
C
      END
C*ID* CUPAB    C109.PTOLEMY.SOURCE                          PER701  20:
      SUBROUTINE  CUPAB ( IORDER, IPT, LXX2S, LXX2,
     1  RMENUC, RMECOU, RNUC, IZPT, RMEGN, RMEGC, IPT1 )
C
C     COMPUTES THE  <JA, JBIGA|| G(LX) ||JB, JBIGB>
C
C     THESE FORMULAS ARE ALL GENERAL
C     SEE NOTES EQUATIONS  47, 70, 46, 71                               11440   
C
C     IORDER - ORDER OF COUPLING (1 OR 2)
C     IPT - NUCLEUS BEING COUPLED:
C        1 = PROJECTILE (1ST OR 2ND ORDER)
C        2 = TARGET
C     LXX2S(2) - 2*MULTIPOLES.  FOR FIRST ORDER THERE IS ONLY
C              LXX2S(1)=LXX2.  FOR SECOND ORDER LXX2, LXX2S(1),
C              AND LXX2S(2) OBEY TRIANGLE RULES.
C     LXX2 - 2*(TOTAL L-TRANSFER)
C     RMENUC(2) - INPUT < J || ALPHA(NUC) || J >                        11450   
C     RMECOU(2) - INPUT < J || E(LX) || J >
C     RNUC(2) - THE NUCLEAR RADII.
C     IZPT(2) = THE ATOMIC NUMBERS FOR P, T
C     RMEGN - THE NUCLEAR MATRIX ELEMENT IS TO BE STORED HERE
C     RMEGC - THE COULOMB MATRIX ELEMENT
C     IPT1 - SET AS FOLLOWS FOR INGRST:
C           1 - 1ST ORDER PROJECTILE EXCITATION
C           2 - 1ST ORDER TARGET
C           3 - 2ND ORDER PROJECTILE
C           4 - 2ND ORDER TARGET                                        11460   
C           5 - 2ND ORDER MUTUAL
C
C     1/8/81 - CUPAB MADE FROM CUPROT - S.P.
C     8/2/81 - MAKE SURE XC, XN ARE ALWAYS DEFINED - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
C
      DIMENSION  LXX2S(2), RMENUC(2), RMECOU(2), RNUC(2)
      DIMENSION  IZPT(2)
C                                                                       11470   
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
C
      COMMON/FACTRL/MAXFAC,ISPACE,TABLE(97)
C
c
C
      F(L1, L2, L) = DSQRT( (L1+1.D0)*(L2+1.D0)/(16*PI*(L+1.D0)) )
     1   * CLEBSH( L1, L2, 0, 0, L, 0 )
C
      LX = LXX2/2                                                       11480   
      XN = 1
      XC = 1
C
C     CHECK FOR ORDER OF COUPLING
C
      IPT1 = IPT
      IF(IORDER.EQ.2)GO TO 300
C
C     FIRST AND SECOND ORDER AT THE SAME VERTEX
C                                                                       11490   
 200  SGNFAC = +1
      IF ( IPT .EQ. 1 )  SGNFAC = (-1)**LX
      RMEGN = SGNFAC*RNUC(IPT)*XN*RMENUC(IORDER)
      RMEGC = SGNFAC*4*PI/((LXX2+1)*3.D0*IZPT(IPT))
     1   * XC*RMECOU(IORDER)
      RETURN
C
C     SECOND-ORDER EXCITATION
C
 300  IPT1 = IPT+2                                                      11500   
      IF(IPT.GT.2)GO TO 500
C
C     NON-MUTUAL SECOND-ORDER EXCITATION (PROJECTILE OR TARGET)
C     A FEX EXTRA FACTORS ON TOP OF FIRST ORDER FOR NUCLEAR
C     ALSO SOUBLE IF LX1 ^= LX2
C
      IF ( LXX2S(1) .NE. LXX2S(2) )  XC = 2
      XN = XC * RNUC(IPT)*F( LXX2S(1), LXX2S(2), LXX2 )
      GO TO 200
C                                                                       11510   
C     SECOND ORDER MUTUAL EXCITATION OF TARGET AND PROJECTILE
C
 500  IPT1=5
C
      SGNFAC = (-1)**(LXX2S(1)/2)
      RMEGN = SGNFAC * 2*F( LXX2S(1), LXX2S(2), LXX2 )
     1   * RNUC(1)*RNUC(2)*RMENUC(1)*RMENUC(2)
C
      RMEGC = 0
      IF ( LXX2 .NE. LXX2S(1)+LXX2S(2) )  RETURN                        11520   
      RMEGC = SGNFAC * 4*PI*RT4PI
     1   * TABLE(LXX2+2)/(TABLE(LXX2S(1)+2)*TABLE(LXX2S(2)+2) )
     2  / (3*(LXX2+1)*IZPT(1)*IZPT(2))
     3  * RMECOU(1)*RMECOU(2)
      RETURN
      END
C*ID* CUPSPN   C109.PTOLEMY.SOURCE                          PER701  20:
      SUBROUTINE  CUPSPN ( IRTN, LXX2, IPT, SCHN,
     1  LXX2S, JNUC, RMEGN, RMEGC,
     3  XN, XC )                                                        11530   
C
C     CALCULATES CHANNEL-SPIN COUPLING MATRIX ELEMENTS
C
C     THESE ARE THE MODEL-INDEPENDANT COUPLING COEFFICENTS THAT
C     CONVERT THE NUCLEAR SPIN BASIS (JA, MA, JBIGA, MBIGB) TO THE
C     CHANNEL SPIN BASIS (S(ALPHA), M(ALPHA)).
C
C     IRTN IS SET AS FOLLOWS:
C        +1 - ALL IS O.K.
C         0 - AN ERROR MESSAGE WAS PRINTED (NONE PRESENTLY)             11540   
C     LXX2 - 2*(TOTAL L-TRANSFER)
C     IPT - NUCLEUS BEING COUPLED:
C        1 = PROJECTILE (1ST OR 2ND ORDER)
C        2 = TARGET
C        3 = BOTH PROJECTILE AND TARGET (2ND ORDER MUTUAL)
C     SCHN(2) - 2*(TOTAL CHANNEL SPINS) ON LEFT (1) AND RIGHT (2)
C                 THIS IS AN INTEGER ARRAY
C     LXX2S(2) - 2*MULTIPOLES.  FOR FIRST ORDER THERE IS ONLY
C              LXX2S(1)=LXX2.  FOR SECOND ORDER LXX2, LXX2S(1),
C              AND LXX2S(2) OBEY TRIANGLE RULES.                        11550   
C     JNUC(2,2) - 2*(THE NUCLEAR SPINS).  THIS IS JNUC(IPT,I)
C              WHERE IPT=1,2 FOR PROJECTILE, TARGET, AND
C              I=1,2 FOR LEFT AND RIGHT SIDES.
C     RMEGN, RMEGC - INPUT VALUES OF THE REDUCED MATRIX ELEMENTS
C            <JA, JBIGA|| G(LX) ||JB, JBIGB>
C         AS DEFINED BY EQ. 47, 70, 46, 71 FOR BOTH NUCLEAR AND
C         COULOMB.
C     XN - THE NUCLEAR MATRIX ELEMENT IS TO BE STORED HERE
C     XC - THE COULOMB MATRIX ELEMENT
C                                                                       11560   
C
C     THE FOLLOWING TRIANGLE CONDITIONS ARE SATISFIED AND NEED
C     NOT BE CHECKED IN THIS ROUTINE.
C
C     1)  ALL ORDERS:
C        S1, S2, LX     S1, S2 ARE THE CHANNEL SPINS IN SCHN.
C        JP1, JT1, S1   JT1 IS JNUC(2,1), ETC.
C        JP2, JT2, S2
C     2)  FIRST ORDER:
C        JP1, JP2, LX   OR   JT1, JT2, LX  AS APPROPRIATE.              11570   
C     3)  SECOND ORDER:
C        A) AT SAME VERTEX:
C           JP1, JP2, LX  OR  JT1, JT2, LX
C        B) MUTUAL:
C           JP1, JP2, LX1
C           JT1, JT2, LX2
C
C
C
C     DEC 1979 FIRST VERSION M.R.B.                                     11580   
C     JAN 1980 PUT IN APPROPIATE FACTORS FOR FIRST ORDER B COEFF.
C     29/1/80/ PUT IN ALL RADIUS PARAMETERS INTO X FACTORS
C     6/3/80 - FIXES SUGGESTED BY MARK AS I LEFT ARGONNE - S.P.
C     7/2/80 - SMALL FIXES TO FORMATS AND VAR. NAMES - S.P.
C     7/3/80 - PRINT BELX AND Q, DEFINE BETAS BY EQUAL DEF. LENGTHS - S.
C      7/4/80 - FIX BUGS IN BELX-BETA CONVERSIONS - S.P.
C     7/7/80 - FIX BUG IN CTRANS PTR, CHANGE LTRANS TO STRT OF ARRAY,
C              BELX IS NOLONGER IN CTRANS ARRAY - S.P.
C     7/8/80 - FIX BUGS IN FINDING WHICH NUCLEUS IS 1ST ORDER COUPLED
C              COMPINE IET AND IRET INTO IRTN - S.P.                    11590   
C     7/10/80 - PUT IN MARK'S 2ND ORDER FIXES - S.P.
C     8/25/80 - COPY /RT4PI INTO 2ND ORDER MUTUAL FROM MARK - S.P.
C     9/11/80 - FIX 2ND ORDER BUGS IN SEARCHING TRANS TABLE - S.P.
C     9/19/80 - SOME TESTS MOVED TO BASCPL - S.P.
C     9/21/80 - FIX SOME BUGS IN SECOND-ORDER MUTUAL EXCITATION - S.P.
C     9/23/80 - "HERMITICITY" (-)**LX REMOVED FROM 1ST ORDER - S.P.
C     10/2/80 - MASSIVE SIMPLIFICATION; RENAMED CUPROT - S.P.
C     12/11/80 - K-QUANTA ADDED.
C     1/8/81 - MODEL INDEPENDANT STUFF SPLIT OFF INTO CUPSPN - S.P.
C                                                                       11600   
C
      implicit real*8 ( a-h, o-z )                                      implicit
C
      DIMENSION  LXX2S(2), JNUC(2,2),
     1   RCOUL(2), RNUC(2), KNUC(2,2), ENUC(2,2)
      INTEGER SCHN(2)
C
c
C
C                                                                       11610   
C
C     CHECK FOR MUTUAL EXCITATION
C
      IF ( IPT .EQ. 3 )  GO TO 500
C
C
C     FIRST AND SECOND ORDER AT THE SAME VERTEX
C
 200  RME = DSQRT( (SCHN(1)+1.D0)*(SCHN(2)+1) )
     2   * SIXJ( SCHN(1),     SCHN(2),     LXX2,                        11620   
     3           JNUC(IPT,2), JNUC(IPT,1), JNUC(3-IPT,1) )
     4   * (-1)**((LXX2+JNUC(1,IPT)+JNUC(2,IPT)+SCHN(3-IPT))/2)
C
 300  XN = RME*RMEGN
      XC = RME*RMEGC
      IRTN = 1
      RETURN
C
C     SECOND ORDER MUTUAL EXCITATION OF TARGET AND PROJECTILE
C                                                                       11630   
 500  MUL=LXX2S(1)+LXX2S(2)
      IPT1=5
C
      RME = DSQRT( (SCHN(1)+1)*(SCHN(2)+1.D0)*(LXX2+1.D0) )
     4   * WIG9J( SCHN(1),   SCHN(2),   LXX2,
     5            JNUC(1,1), JNUC(1,2), LXX2S(1),
     6            JNUC(2,1), JNUC(2,2), LXX2S(2) )
C
      GO TO 300
C                                                                       11640   
      END
C*ID* DATAIN   C109.PTOLEMY.SOURCE                          PER701  12:
      SUBROUTINE DATAIN(IRET)
C
C  INPUT ROUTINE FOR DATA KEYWORD.  PROCESSES   DATA ( SPECIFICATIONS )
C
C  STURCTURE OF DATA IN ALLOCATOR IS  :
C
C     POINTER WORD CONTENTS
C                                                                       11650   
C     PREFACE:
C
C     LDATA4   +0  TOTAL NUMBER OF DATA POINTS.
C              +1  TOTAL NUMBER OF DATA SETS ( DIFFERENT ELAB'S )
C              +2  NUMBER OF WORDS IN PREFACE
C              +3  NUMBER OF WORDS IN EACH KEY
C              +4  NUMBER OF WORDS IN EACH HEADER
C
C     FOR EACH DATA SET
C                                                                       11660   
C     LEKEY    +0   (POINTS TO JUST BEFORE THE DATA SET)
C              +1   0 = MB ERRORS; 1 = % ERRORS; 2 = SIGMA UNITS
C               2   0 = SIGMA/RUTHERFORD; 1 = SIGMA IN MB;
C                   2 = LAB SIGMA IN MB.
C               3   0 = NO POLARIZATION; 1 = POLARAIZATION DATA.
C               4   0 = ANGLES ARE IN C.M.; 1 = LAB ANGLES.
C              +5   NUMBER OF WORDS FOR EACH ANGLE
C     LEHED    +0   NUMBER OF DATA POINTS IN THIS SET
C              +1   OVERALL WEIGHT FOR THIS SET.
C              +2   RENORMALIZATION OF THIS SET.                        11670   
C              +3   LAB-ANGLE SHIFT.
C              +4   ELAB FOR THIS SET.
C              +5   IZP FOR THIS DATA SET
C              +6   IZT
C              +7   AMP
C              +8   AMT
C              +9-  REACTION SPECIFICATION FOR
C               14   THIS DATA SET
C             +20   JSP - PROJECTILE SPIN * 2
C             +21   JST - TARGET SPIN * 2                               11680   
C             +22   LSKIP - 0=NOT SET; 1=NONIDENTICAL, 2=IDENTICAL PARTI
C             +23   LBASE - 0=BOSONS, 1=FERMIONS, NOMEANING IF LSKIP=1
C             +24   RATMAS = MP/MT (KINEMATIC MASSES)
C             +25   MXCGP = PROJECTILE G.S. MASS EXCESS
C             +26   MXCGT
C             +27   E*P = PROJECTILE EXCITATION ENERGY
C             +28   E*T
C             +29   0=ELAB, 1=ECM WAS ENTERED (0 MAY MEAN NEITHER)
C
C     FOR EACH ANGLE                                                    11690   
C
C     LADATA   +0   ANGLE IN DEGREES (C.M. OR LAB - SEE ABOVE)
C              +1   ERROR AS DESCRIBED ABOVE.
C              +2   CROSS SECTIONS AS DESCRIBED ABOVE.
C              +3   POLARIZATION.
C
C     THE ENTIRE OBJECT IS TREATED AS REAL*4 OR INTEGER*4 AND THUS
C     WORD MEANS 4-BYTE WORD.
CDCC     ON THE CDC EACH WORD IS A 60-BIT WORD.
C                                                                       11700   
C
C   FIRST VERSION  8/20/75  D.G.
C     10/11/75 - INDICATE WHEN ELAB IS NOT DEFINED
C     10/22/75 - CHECK FOR FUNNY OR INVALID ANGLES
C     10/31/75 - SIMPLIFIED NUMBER OF POINTS COUNTING
C     11/20/75 - LAB-ANGLE SHIFT
C     7/31/76 - CDC/IBM, REAL*4, LABANGLE.
C     4/14/77 - LABSIGMA AND ANGLE; SIGMA MADE GENERAL; CHANNEL
C     4/25/77 - IDENTICAL PARTICLES; LENGTHS STORED IN DATA
C     5/4/79 - STORE RATMAS, MASS EXCESS, E* - S.P.                     11710   
C     12/27/79 - STANDARD MORTRAN - RPG
C     5/3/82 - ECM INPUT, CHECK FOR DOUBLE SPECIFICATION - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
C
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
C
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      parameter ( NUMJWORD = 12 )                                       /jblock/
      COMMON /JBLOCK/  J, JS(5),
     &  JP, JSP, JST,
     &  JPARM1, JPARM2, JPARM3
 
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
C
      CHARACTER*1  REACT, HEADER                                        /hedcom/
      COMMON /HEDCOM/  REACT(45), HEADER(65)
 
      INTEGER  REACT4(10)
      EQUIVALENCE ( REACT(1), REACT4(1) )
C
      COMMON / INTRNL /  UNDEF
C
      CHARACTER*8  KEYS(18), NAME8, ANAMES, AKEY
      DATA NUMKEY/18/                                                   11730   
      DATA  KEYS / 'ELAB', 'ECM', 'ANGLE', 'MBERROR', 'PERCENTE',
     1  'POLARIZA', 'SIGMA', 'SIGMATOR', 'WEIGHT', 'RENORMAL',
     2  'ANGLESHI', 'LABANGLE', 'CMANGLE', 'CMSIGMA', 'LABSIGMA',
     3  'ERROR', 'CHANNEL', 'RENORM' /
      DATA  NAME8 / 'DATA' /
      COMMON/NAMCOM/ANAMES(75)
C
      LOGICAL MORESW
      INTEGER KEY(4) / 4*0 /
      INTEGER GIVEAL, CHOPIT                                            11740   
C
      DATA LENPRE /5/,  LENKEY /5/,  LENHED /30/
C
c
C
C
      IRET=0
      IANGLE=0
      ISIGMA=0
      IERROR=0                                                          11750   
      IPOL=0
      ICNT=0
      IAT=0
      NPTSE=0
      NPTS = 0
      I = NAMLOC(NAME8)
      IF ( I .NE. 0 )  Z(I) = -Z(I)
      IDATA = GIVEAL(IWRDS)
      ANAMES(IDATA)=NAME8
      LDATA = Z(IDATA)                                                  11760   
      LDATA4 = FACFR4*(LDATA-1) + 1
      ALLOC(LDATA) = 0
      ILLOC(LDATA4+2) = LENPRE
      ILLOC(LDATA4+3) = LENKEY
      ILLOC(LDATA4+4) = LENHED
      LEKEY = LDATA4  + LENPRE-1
C
      CALL FITKEY(AKEY,*90,*900,*900,*900)
      GO TO 900
C                                                                       11770   
C  (  ENCOUNTERED  --  LETS GO
90    IORDER=0
      LEHED = LEKEY + LENKEY+1
      LADATA = LEHED + LENHED
      ALLOC4(LEHED+1) = 1
      ALLOC4(LEHED+2) = 1
      ALLOC4(LEHED+3) = 0
      IELAB = 0
100   CALL NXWORD(AKEY,*800,*900,*900)
      ANGLAS = 0                                                        11780   
105   DO 110 I=1,NUMKEY
      IF(KEYS(I).NE.AKEY)GO TO 110
      GO TO (200, 210, 250, 300, 310, 400, 450, 470, 500, 510, 520,
     1  260, 265, 460, 465, 320, 550, 510 ), I
110   CONTINUE
      GO TO 900
C
C  ELAB
C
 200  IELAB = 0                                                         11790   
      GO TO 220
 210  IELAB = 1
 220  CALL NXVAL ( ELAB, *900, *900, *900 )
      GO TO 100
C
C  ANGLE - MEANS C.M. ANGLE.  HOWEVER, USE OF THE COMMENTED CARD
C       WOULD CAUSE ANGLE MEANING TO DEPEND ON THE LABANGLE/CMANGLE
C       SWITCH THAT IS SET EXTERNAL TO  DATA ( ... )
C
CCCC 250  KEY(4) = LABANG                                               11800   
 250  KEY(4) = 0
255   IORDER=IORDER+1
      IANGLE=IORDER
      GO TO 100
C
C     LABANGLE
C
 260  KEY(4) = 1
      GO TO 255
C                                                                       11810   
C     CMANGLE
C
 265  KEY(4) = 0
      GO TO 255
C
C  MBERROR
C
 300  KEY(1) = 0
 305  IORDER=IORDER+1
      IERROR=IORDER                                                     11820   
      GO TO 100
C
C  % ERROR
C
 310  KEY(1) = 1
      GO TO 305
C
C     ERROR IS IN SAME UNITS AS DATA
C
 320  KEY(1) = 2                                                        11830   
      GO TO 305
C
C  POLORIZATION
C
400   IORDER=IORDER+1
      IPOL=IORDER
      KEY(3) = 1
      GO TO 100
C
C  SIGMA                                                                11840   
C
 450  KEY(2) = -1
 455  IORDER=IORDER+1
      ISIGMA=IORDER
      GO TO 100
C
C     CMSIGMA
C
 460  KEY(2) = 1
      GO TO 455                                                         11850   
C
C     LABSIGMA
C
 465  KEY(2) = 2
      GO TO 455
C
C  SIGMATOR
C
 470  KEY(2) = 0
      GO TO 455                                                         11860   
C
C  WEIGHT
C
500   CALL NXVAL(WEIGH,*900,*900,*900)
      ALLOC4(LEHED+1)=WEIGH
      GO TO 100
C
C     RENORMALIZATION
C
510   CALL NXVAL(RNORM,*900,*900,*900)                                  11870   
      ALLOC4(LEHED+2)=RNORM
      GO TO 100
C
C     ANGLESHIFT
C
 520  CALL NXVAL ( ASHIFT, *900, *900, *900 )
      ALLOC4(LEHED+3) = ASHIFT
      GO TO 100
C
C     CHANNEL < CHANNEL SPECIFICATION >                                 11880   
C
 550  CALL CHANEL ( IRET )
      IF ( IRET )  100, 950, 100
C
C  NUMBER ENCOUNTERED ---  NOW READ IN NUMBERS.
C
800   IAT=IAT+4
      IF(IERROR.EQ.0.OR.IANGLE.EQ.0.OR.ISIGMA.EQ.0)GO TO 930
C
C     SIGMA KEYWORD MEANING DEPENDS ON ANGLE SPECIFICATION              11890   
C
      IF ( KEY(2) .EQ. -1 )  KEY(2) = KEY(4) + 1
C
      NTHISE = 0
      LENDAT = 3
      IF ( IPOL .NE. 0 )  LENDAT = 4
C  LENDAT= ANGLE + SIGMA + ERROR +POL
 850  DO 860 I=1,LENDAT
      CALL NXVALF(TEMP,*880,*910,*910,*885)
      IF(I .EQ. IANGLE)GO TO 862                                        11900   
      IF(I .EQ. ISIGMA)GO TO 864
      IF(I .EQ. IERROR)GO TO 866
      IF ( I .EQ. IPOL )  GO TO 868
      GO TO 945
C
C     PERFORM SOME VALIDITY CHECKS ON THE ANGLE IN AN ATTEMPT TO
C    DETECT OUT-OF-SEQUENCE DATA
C
 862  IF ( TEMP .LT. 0  .OR.  TEMP .GT. 180 )  GO TO 940
      IF (TEMP .LT. 1 )  write (6, 853) TEMP                            11910   
 853  FORMAT ( ' **** WARNING:  ANGLE (', G13.5,
     1  ' DEGREES) IS UNUSUALLY SMALL.' )
      IF ( TEMP .LT. ANGLAS )  write (6, 854) TEMP
 854  FORMAT ( ' **** WARNING:  ANGLE (', F6.2,
     1  ' DEGREES) IS LESS THAN PREVIOUS ANGLE.' )
      ANGLAS = TEMP
      ALLOC4(LADATA)=TEMP
      NTHISE = NTHISE + 1
      NPTS = NPTS + 1
      GO TO 860                                                         11920   
864   ALLOC4(LADATA+2)=TEMP
      GO TO 860
866   ALLOC4(LADATA+1)=TEMP
      GO TO 860
868   ALLOC4(LADATA+3)=TEMP
      GO TO 860
860   CONTINUE
      LADATA = LADATA + LENDAT
      GO TO 850
C                                                                       11930   
C  FINISHED THIS GROUP -- APPARENTLY MORE
C
 880  MORESW = .TRUE.
      GO TO 890
C
C     ) ENCOUNTERED - ALL DONE
C
 885  MORESW = .FALSE.
C
C     FINISH THIS SET OFF                                               11940   
C
 890  IF ( I .NE. 1 )  GO TO 920
      DO 892  I = 1, 4
 892  ILLOC(LEKEY+I) = KEY(I)
      ILLOC(LEKEY+5) = LENDAT
      ILLOC(LEHED) = NTHISE
      ALLOC4(LEHED+4) = ELAB
      ILLOC(LEHED+5) = IZP
      ILLOC(LEHED+6) = IZT
      ALLOC4(LEHED+7) = AMP                                             11950   
      ALLOC4(LEHED+8) = AMT
      DO 895  I = 9, 19
         ILLOC(LEHED+I) = REACT4(I-8)
 895  CONTINUE
      ILLOC(LEHED+20) = JSP
      ILLOC(LEHED+21) = JST
C
C     DO NOT STORE LSKIP, LBASE IF CHANNEL NOT FULLY SPECIFIED
C
      ILLOC(LEHED+22) = 0                                               11960   
      ILLOC(LEHED+23) = 0
      IF ( EXSPT(1) .EQ. UNDEF )  GO TO 897
      ILLOC(LEHED+22) = 1
      ILLOC(LEHED+23) = 3
      IF ( AMP .NE. AMT  .OR.  IZP .NE. IZT  .OR.  JSP .NE. JST
     1    .OR.  EXSPT(1) .NE. EXSPT(2) )  GO TO 897
      IF ( JSP .EQ. 0 )  ILLOC(LEHED+22) = 2
      ILLOC(LEHED+23) = MOD(JSP,2)+1
C
 897  ALLOC4(LEHED+25) = AMXGPT(1)                                      11970   
      ALLOC4(LEHED+26) = AMXGPT(2)
      ALLOC4(LEHED+27) = EXSPT(1)
      ALLOC4(LEHED+28) = EXSPT(2)
      ILLOC(LEHED+29) = IELAB
      NPTSE = NPTSE + 1
      LEKEY = LEKEY + LENKEY+LENHED + LENDAT*NTHISE
C
      IF (MORESW)  GO TO 90
C
      ILLOC(LDATA4) = NPTS                                              11980   
      ILLOC(LDATA4+1) = NPTSE
      IWRDS = (LEKEY-LDATA4)/FACFR4 + 1
      IL=CHOPIT(IWRDS)
      IRET=1
      RETURN
C
900   WRITE(6,901)(KEYS(I),I=1,NUMKEY)
901   FORMAT(' DATA NOT ENCLOSED IN PARENTHESIS OR KEYWORD MISPELLED',
     1' DATA KEYWORDS ARE:' // ( 1X, 10A9 ) )
      RETURN                                                            11990   
910   WRITE(6,911)
911   FORMAT(' ERROR IN READING NUMERICAL DATA VALUES')
      RETURN
920   WRITE(6,921)LENDAT
921   FORMAT(' INPUT ERROR - NUMBER OF INPUT NUMBERS MUST BE',I5,'*N')
      RETURN
930   WRITE(6,931)
931   FORMAT(' ORDER OF ANGLE,ERROR AND SIGMA MUST BE SPECIFIED')
      RETURN
 940  write (6, 941) TEMP                                               12000   
 941  FORMAT ( '0**** INVALID ANGLE (', G13.5,
     1  ' DEGREES); CHECK ORDER OF INPUT.' )
      RETURN
 945  write (6, 947) I, IANGLE, ISIGMA, IERROR, IPOL
 947  FORMAT ( '0*** A DATA-ENTERING KEYWORD HAS BEEN SPECIFIED',
     1  ' TWICE OR AN INTERNAL ERROR OCCURRED:', 6I5 )
 950  RETURN
      END
C*ID* DEFALT   C109.PTOLEMY.SOURCE                          PER701  17:
      SUBROUTINE  DEFALT ( NUMFLT, NUMINT, NUMJ, NUMSW, RESTSW )        12010   
C
C     INITIALIZATION OF THE DWBA CODE
C
C     1/18/75 - SEPARATEDED FROM CONTRL - S.P.
C     1/18/75 - REARRANGED TO BE OVERLAYED - S. P.
C     2/10/75 - MOVE  NUCONLY AND JX
C     2/16/75 - LOAD IEWSZOVR, PRINT DATE
C     2/20/75 - MOST DEFAULTS SET TO 0 - S. P.
C     3/5/75 - NEW GRID DEFAULTS
C     4/15/75 - MAJOR REVISION FOR NEW COMMON BLOCKS                    12020   
C     5/5/75 - STUFF FOR SETCHN
C     5/18/75 - RESTSW ADDED.
C     5/22/75 - VSI ADDED
C     5/30/75 - FIX FOR RESET
C     6/11/75 - SAVEHS/USEHS
C     8/7/75  - ADD R0E,VE,ETC TO COMMON
C     8/28/75 - LMINMULT, LMAXMULT, SPFACP SPFACT
C     9/3/75 - MAXLEXTRAP ADDED; USECOULOMB IS DEFAULT
C     9/25/75 - CHANGE DWCUT; REMOVE VCUT
C     9/30/75 - LMAXMULT BECOMES LMAXADD                                12030   
C     10/1/75 - FITTING KEYWORDS
C     10/19/75 - ESQ PARAMETERS, TBEGIN
C     11/6/75 - DERIVSTEP, MAXFUNCTIONS;  LMCHOL IS DEFAULT FITTER
C     1/29/76 - FITMULTI, FITRATIO, FITMODE, NUMRANDO
C     2/26/76 - LMAXADD INCREASED FOR ELASTIC STUFF
C     6/1/76 - NVPOLY, SUMPTS ADDED
C     6/17/76 - LARGE FAKE AMDMLT
C     9/16/76 - SEPT. 76 VERSION; FITMUL FIX
C     12/26/76 - INELASTIC SCATTERING
C     4/15/77 - LMINSB, ALMXAD ADDED                                    12040   
C     5/8/77 - PRINT=10001; MAY 77 VERSION
C     9/24/77 - USECORE DEFAULT; SEPT 77 VERSION
C     10/16/77 - POWERS OF WOODS-SAXONS
C     11/20/77 - SEPARATE BOUND & SCAT ASYMP; DEC 77 VERSION
C     11/25/77 - LINKULES
C     3/19/78 - MARCH, 1978 VERSION
C     4/24/78 - APRIL VERSION FOR LI, LO REVERSALS - S.P.
C     4/28/78 - BIG AND SMALL STUFF IN /CNSTNT/ - S.P.
C     5/23/78 - JUNE 1978 VERSION - S.P.
C     12/7/78 - ADD TENSOR POTENTIALS - RPG                             12050   
C     3/21/79 - APRIL 1979 VERSION - S.P.
C     5/6/79 - MAY 1979 VERSION; PARITIES AND LEVEL SPEC ARRAYS - S.P.
C     6/10/79 - CMS VERSION - S.P.
C     6/8/79 - JUNE 1979 VERSION; STANDARD PREFIXES, CHARACTER TYPE,
C        UNIVAC STUFF - RPG
C     6/18/79 - PROPERLY RESTORE IECHO FOR RESET - S.P.
C     9/10/79 - SEPTEMBER 1979 VERSION - RPG
C     11/3/79 - OCTOBER 1979 VERSION; TIME AND CPU VERSION STAMP - S.P.
C     11/15/79 - NOVEMBER 1979 VERSION; CMPUTR SUBROUTINE - S.P.
C     12/31/79 - DECEMBER 1979 VERSION; VAX STUFF - RPG                 12060   
C     1/14/80 - FIX CVA IUNDEF/AUNDEF DATA; CHARACTER*1 BLANK1 - RPG
C     1/18/80 - CALL EDTDAT FOR CND; CHAACTER*8 DATE, THISDT - RPG
C     1/25/80 - CND CHARACTER*1 THEDAT, WRITE(6,-) TO PRINT - RPG
C     2/5/80 - INITIALIZE NBLKSZ, CVA CALL TLIMIT - RPG
C     2/19/80 - INITIALIZE MAPPHI, PHIMID, GAMPHI; FEB. 1980 VERSION - R
C     3/15/80 - MARCH 1980 VERSION FOR RPG MERGED BACK TO ANL - S.P.
C     5/2/80 - APRIL 1980 VERSION - C.C. WORKING FAIRLY WELL! S.P.
C     6/13/80 - CHAR*8 FOR CDC THEDAT, SHIFT FOR NOS - S.P.
C     7/10/80 - CWD, CHR PREFIXES, JULY 1980 VERSION - S.P.
C     7/17/80 - FIX CRAY NOTDEF, UNDEF VALUES - S.P.                    12070   
C     8/25/80 - JULY 1980 VERSION, SOMEHOW LOST ON CDC - S.P.
C     9/16/80 - SEPT. 1980 VERSION; ZERO CCBLK; L-EXTRAP DEFAULT - S.P.
C     10/8/80 - OCTOBER 1980 VERSION FOR NEW BASCPL, ETC. - S.P.
C     12/17/80 - DECEMBER 1980 VERSION FOR COMPLETION OF ABOVE - S.P.
C     1/8/81 - JANUARY 1981 VERSION FOR NEW COUPLING SCHEME  - S.P.
C     6/24/81 - JUNE 1981 VERSION FOR REWORKS OF COUPLN - S.P.
C     8/28/81 - AUGUST 1981 VERSION FOR DEFORMED POTENS - S.P.
C     9/17/81 - SEPT 1981 VERSION; LEBACK DEFAULT - S.P.
C     10/12/81 - OCT 1981 VERSION FOR GIESSEN CHANGES - S.P.
C     2/11/82 - JANUARY 1982 VERSION                                    12080   
C     3/12/82 - MARCH 1982 VERSION
C     4/10/82 - APRIL 1982 VERSION
C     5/3/83 - MAY 1983 VERSION - VARIOUS SMALL FIXES - S.P.
C     7/20/83 - USE ISIZE=-500 FOR NOS - S.P
C     8/17/83 - AUGUST 1983 VERSION = FINAL AT MUNICH - S.P.
C     10/16/84 - OCT 1984 VERSION; SCTASY < 0 - S.P.
C     12/19/84 - DEC 1984 VERSION; ROOM FOR SIPOTENT - S.P.
C     5/10/85 - INITIALIZE PLM WORK ARRAY FOR CRA - S.P.
C     6/10/85 - JUNE, 1985 VERSION - S.P.
C     11/16/01 - Nov, 2001 version; new date routine                    12090   
C
C
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      parameter ( NUMJWORD = 12 )                                       /jblock/
      COMMON /JBLOCK/  J, JS(5),
     &  JP, JSP, JST,
     &  JPARM1, JPARM2, JPARM3
 
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
c                                                                       /lnkblk/
c  STRUCTURE OF   /LNKBLK/
c
c  THERE IS A BLOCK OF 3 DOUBLE WORDS FOR EACH POSSIBLE USE
c  OF A LINKULE.  THE NUMLNK = NUMLINKULES USES ARE IN THE ORDER
c    REALPOTEN  IMAGPOTEN  REALVSO  IMAGVSO  COULOMB
c    WAVEFUNCTION  AND 6 TENSOR POTENTIALS
c  THE THREE-DOUBLE-WORD BLOCKS EACH HAVE THE STRUCTURE
c
c    LNKNAM(1,I)   LINKULE NAME
c
c      LNKADR(3,I)   LINKULE ADDRESS, O IF NO LINKULE IN USE.
c      LNKADR(4,I)   0 - NO L OR J DEPENDENCE IN POTENTIAL
c                    1 - L DEPENDENCE BUT NO J DEPENDENCE
c                    2 - BOTH L  AND J DEPENDENCE
c
c      LNKADR(5&6,I)  MYINTS - A TWO-ELEMENT ARRAY THAT THE
c                     LINKULE MAY USE FOR COMMUNICATION BETWEEN
c                     CALLS TO ITSELF.
c
      parameter ( NUMLINKULES = 13 )
      COMMON /LNKBLK/  NUMLNK, IUNIQU, LNKADR(6,NUMLINKULES)
      character*8  LNKNAM(3,NUMLINKULES)
      EQUIVALENCE ( LNKNAM(1,1), LNKADR(1,1) )
 
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
      CHARACTER*1  REACT, HEADER                                        /hedcom/
      COMMON /HEDCOM/  REACT(45), HEADER(65)
 
      COMMON /CCBLK/  ICHNDF, ICHNCP, ITRANS, IBASDF, IBASCP,           /ccblk/
     &    ICCBLK(2), IORDX, MCHNVL, ICHNVL,
     &    IHOMOA, IHOMOB, IINHR8, IINHI8
 
C
      REAL*4  TBEGIN, TIMES                                             /ftimef/
      COMMON /FTIME/ TBEGIN, NUMLOP, NUMWAV, TIMES(6), NUMCAL, NUMGRA
 
CRA      COMMON /INTWRK/  MAXINT, INBIAS, WKBIAS, INTTBL(1)
C
      LOGICAL  RESTSW
C
      DIMENSION FLOAT(1), INTGER(1), JBLOCK(1)
      INTEGER SWITCH(1)                                                 12110   
      EQUIVALENCE ( FLOAT(1), A ),  ( INTGER(1), L ),
     1  ( JBLOCK(1), J ),  ( SWITCH(1), IASYMP )
C
C
C
C
      CHARACTER*1  BLANK1 /' '/
C
CCC Ci3e      DATA  IUNDEF / Z F0F0F0F0 /,  AUNDEF / Z F0F0F0F0 F0F0F0F0
      DATA  IUNDEF / Z"F0F0F0F0"/,  AUNDEF / Z"F0F0F0F0F0F0F0F0"/       12120   
CIB      DATA  IUNDEF / Z F0F0F0F0 /,  AUNDEF / Z F0F0F0F0 00000000 /
CDC      DATA  IUNDEF / 7070707070 7070707070 B /,
CDC     1  AUNDEF / 7070707070 7070707070 B /
C
CRA      DATA  IUNDEF / 1 57070 70707070 70707070 B /
CRA      DATA  AUNDEF / 1 57070 70707070 70707070 B /
C
CVA      DATA  IUNDEF / 'F0F0F0F0'X /
CVA      REAL*4  SUNDEF(2) / 'F0F0F0F0'X, 'F0F0F0F0'X /
CVA      EQUIVALENCE  ( SUNDEF(1), AUNDEF )                             12130   
      character*8  date8
      character*5  zone
      integer time_values(8)
      CHARACTER*9  THEDAT
      CHARACTER*10  THETIM /'        '/
      CHARACTER*40  CPUID, hostname
C
C
C     IS THIS THE FIRST CALL TO DEFALT
C                                                                       12140   
      IF ( RESTSW )  GO TO 10
C
C     START TIMER
C
ccc      CALL STIMER
      TBEGIN = second()
C
C
C  INITIALIZE INPUT
C                                                                       12150   
C     FIRST SET EVERYTHING TO UNDEFINED STATUS
C
 10   NOTDEF = IUNDEF
      UNDEF = AUNDEF
C
      DO 39  I = 1, NUMFLT
 39   FLOAT(I) = UNDEF
      DO 49  I = 1, NUMINT
 49   INTGER(I) = NOTDEF
      DO 59  I = 1, NUMJ                                                12160   
 59   JBLOCK(I) = NOTDEF
C
C     SET ALL OPTIONS OFF
C
      ITSOSV = ITSO
      IECHSV = IECHO
      DO 69  I = 1, NUMSW
 69   SWITCH(I) = 0
      ITSO = ITSOSV
      IECHO = IECHSV                                                    12170   
C
      DO 79  I = 1, 110
 79   REACT(I) = BLANK1
C
C
C     FIND OUT ABOUT THE MACHINE AND OPERATING SYSTEM
C
      CALL CMPUTR ( CPUID, hostname )
C
      IF ( RESTSW )  GO TO 110                                          12180   
C
      IECHO=1
C     INDICATE NO ALLOCATOR YET.
      ICNTT = 0
C  IECHO MUST BE INITIALIZED BEFORE NEWCD IF FIRST INPUT... ISTOBEVISIBL
 110  IF(ITSO.EQ.0)  write (6, 118)
      IF(ITSO.EQ.1)  write (6, 113)
 113  FORMAT('1           P T O L E M Y')
 118  FORMAT(  T50, 'P T O L E M Y' )
C                                                                       12190   
C     GET CURRENT DATE
C
  150 call get_DATE ( THEDAT )
C
      call date_and_time ( date8, thetim, zone, time_values )
C
C     **********************************************************
C     *                                                        *
C     *                STOP     THINK                          *
C     *                                                        *        12200   
C     *    IS IT TIME TO CHANGE THE DATE OF THE VERSION ??     *
C     *                                                        *
C     **********************************************************
C
      IF ( ITSO .EQ. 0 )  write (6, 153) trim(CPUID), trim(hostname),
     &    THEDAT, THETIM
 153  FORMAT ( ' April 2007 version',
     1  5x, 'Computer: ', a, 2X, a,
     2  10x,  a, 2X,  A / )
      IF ( ITSO .EQ. 1 )  write (6, 158) THEDAT                         12210   
 158  FORMAT ( ' February 2007 version', 5X, a / )
C
C
C     SETUP CONSTANTS
C
      PI = 3.1415 92653 58979 32 0D0
      RT4PI = DSQRT(4*PI)
      PIINV = 1/PI
      RADIAN = 180/PI
      DEGREE = 1/RADIAN                                                 12220   
C
C     FOLLOWING FROM  E. R. COHEN AND B. N. TAYLOR, J. PHYS. AND CHEM.
C     REF. DATA, 2, 663 (1973).
C
      HBARC = 197.32858 0D0
      AMUMEV = 931.5016 0D0
      AFINE = 137.03604 0D0
C
C     UNDERFLOW AND OVERFLOW LIMITS
C                                                                       12230   
      BIGEST = 1.E+300                                                  ci3e
c      bignum must fit in real*4                                        ci3e
      BIGNUM = 1.E+30                                                   ci3e
C
CIB      BIGEST = 1.D+75
CIB      BIGNUM = 1.D+30
C
CDC      BIGEST = 1.E+290
CDC      BIGNUM = 1.E+135
C                                                                       12240   
CRA      BIGEST = 1.E+2400
CRA      BIGNUM = 1.E+1200
C
CUN      BIGEST = 1.D+290
CUN      BIGNUM = 1.D+135
C
CVA      BIGEST = 1.D+36
CVA      BIGNUM = 1.D+18
C
      SMLEST = 1/BIGEST                                                 12250   
      SMLNUM = 1/BIGNUM
      BIGLOG = DLOG( BIGNUM )
C
C     TO TRAP A TROLLOP TRAVELLING ON A TROLLY
C     (I.E. RESET POINTER TO BOUND STATE POLENTIAL.)
C
      IPOT = 0
C
C     SETUP DEFAULT VALUES
C                                                                       12260   
      DWCUT=1.D-3
      NCOSIN=256
      NBACK=4
      DELTVK=.050D0
      MAXITR=10
      IFIT=1
      IVRTEX=1
      ACCURA=1.0D-12
      BNDASY = 20.0
      SCTASY = -20.0                                                    12270   
      STEP1R=1.0
      STEP1I=1.0
      isize = 200 000
cib       isize = 20 000
CVAC      VAX VIRTUAL MEMORY IS CHEAP.
CVA      ISIZE = 1 000 000
      STEPSZ=.10D0
C  DEFAULT VALUES FOR ANGLES
      ANGMIN=0
      ANGMAX = 90                                                       12280   
      ANGSTP = 1
      LSTEP = 1
      NPPHI=10
      NPSUM = 15
      NPDIF = 10
      NVPOLY = 3
      SUMPTS = 6
      SPAMP=1.0D0
      SPAMT=1.0D0
      SPFACP = 1                                                        12290   
      SPFACT = 1
      NAITKN=4
      IPRINT = 10001
      IF ( ITSO .EQ. 1 )  IPRINT = 01
      LOOKST = 250
      ICHANB = 0
      ICHANW = 0
      IDONE = 0
      ISTRIP = 0
      MAPSUM = 2                                                        12300   
      MAPDIF = 1
      MAPPHI = 2
      GAMSUM = 1
      GAMDIF = 5
      GAMPHI = 1.D-6
      AMDMLT = 2
      PHIMID = 0.5
      NPHIAD = 4
      NUCONL = 3
      IHSAVE = 0                                                        12310   
      ALMXMT = 1.6
      LMAXAD = 30
      ALMNMT = .6
      LMINSB = 20
      MAXLEX = 100
      LEBACK = 15
C
      NWAVEF = 0
C     EXCITATION ENERGIES ARE 0 BY DEFAULT
C     PARITY = 0 MEANS UNDEFINED                                        12320   
C
      DO 309  I = 1, 5
         PARITS(I) = 0
 309  EXS(I) = 0
      PARITY = 0
C
      NBLKSZ = 5632
C
C     VAX/VMS:  THE DEFAULT CPU TIME LIMIT IS ONE HOUR.
C                                                                       12330   
CVA      CALL TLIMIT ( 60.D0 )
      DO 319  I = 1, 4
         LSPECS(I) = NOTDEF
         NODESP(I) = NOTDEF
 319  CONTINUE
      DO 329  I = 1, 2
         LSPCPT(I) = NOTDEF
         NODEPT(I) = NOTDEF
         PARIPT(I) = 0
         EBNDS(I) = UNDEF                                               12340   
 329  CONTINUE
C
C     POTENTIALS ARE 0 BY DEFAULT
C
      V = 0
      VI = 0
      VSO = 0
      VSOI = 0
      TAU = 0
      TAUI = 0                                                          12350   
      VSI = 0
      DO 359 I = 1, 6
 359     VTEN(I) = 0
C
C  ENERGY DEPENDENCE ZERO BY DEFAULT
C
      R0E=0
      RI0E=0
      AE=0
      AIE=0                                                             12360   
      VE=0
      VIE=0
      R0ESQ = 0
      RI0ESQ = 0
      AESQ = 0
      AIESQ = 0
      VESQ = 0
      VIESQ = 0
C
C     POTENTIALS ARE LINEAR WOODS SAXONS                                12370   
C
      POWRL = 1
      POWIM = 1
C
C     INDICATE NO LINKULES IN USE.
C
      NUMLNK = NUMLINKULES
      IUNIQU = 100
      DO 409  I = 1, NUMLINKULES
         LNKADR(3,I) = 0                                                12380   
 409  CONTINUE
C
C     FITTING KEYWORDS
C
      FITACC = 1.D-3
      FITMUL = 500
      FITRAT = 1.D-4
      MODEFT = 1
      NUMRAN = 0
      MAXFUN = 50                                                       12390   
      IREINI = 0
      IFITER = 6
      DERIVS = 1.D-6
C
C     INELASTIC SCATTERING
C
      ACCINE = 1.D-5
      COULML = 1
      NPCOUL = 8
      MXCOUL = 80                                                       12400   
C
C     COUPLED CHANNELS
C
      IEXTYP = 1
      ICHNDF = 0
      ICHNCP = 0
      ITRANS = 0
      IBASDF = 0
      NFIROF = 1
CRAC     FOR THE PLM RECURSION                                          12410   
CRA      MAXINT = -1
      RETURN
      END
C*ID* DEFINE   C109.PTOLEMY.SOURCE                          PER701  15:
      SUBROUTINE DEFINE ( ANAME, ILEN, ISIZE )
C
C     DEFINES AN OBJECT IN THE ALLOCATOR WITH THE NAME ANAME.
C
C     THE OBJECT IS LOADED WITH A LIST OF NUMBERS READ FROM THE
C     INPUT STREAM.  THE LIST DETERMINS THE LENGTH OF THE OBJECT        12420   
C     AND IS TERMINATED BY A NON-NUMBER.
C
C     ANAME - NAME OF THE OBJECT TO BE DEFINED.
C     ILEN - SET TO THE LENGTH OF THE LIST OF NUMBERS READ.
C     ISIZE - SET TO THE MAXIMUM SIZE AVAILABLE IN THE ALLOCATOR.
C             IF  ILEN > ISIZE,  THEN ALL THE NUMBERS WERE READ
C             BUT ONLY THE FIRST ISIZE VALUES WERE STORED INTO THE
C             ARRAY.
C
C     12/14/76 - FIRST VERSION - S. PIEPER                              12430   
C     1/24/80 - CHARACTER*8 NAMES, ANAME - RPG
C     7/21/80 - FIX BLUNDER IN PRINT STMNT - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
C
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      CHARACTER*8 NAMES, ANAME
      COMMON /NAMCOM/  NAMES(1)
      COMMON /LENGTH/  LENG(1)
C                                                                       12440   
      parameter ( ibufsize = 200 )                                      /inpbuf/
      CHARACTER*1 IBUF(ibufsize)
      COMMON /INPBUF/ NOCH, INCH, IBUF
 
      INTEGER GIVEAL, chopit
C
C
C     GET THE OBJECT NUMBER IF IT PRESENTLY EXISTS
C
      IDOLD = NAMLOC(ANAME)
C
C     GET MAXIMUM AMOUT POSSIBLE FROM ALLOCATOR TO READ IN NUMBERS
C                                                                       12450   
      IDATA = GIVEAL(ISIZE)
      NAMES(IDATA) = ANAME
      LDATA = Z(IDATA)
      ILEN = 0
C
 50   CALL NXVAL ( X, *310, *300, *310 )
      ILEN = ILEN + 1
      IF ( ILEN .GT. ISIZE+1 )  GO TO 50
      IF ( ILEN .LE. ISIZE )  GO TO 100
      write (6, 73) ANAME, ILEN                                         12460   
 73   FORMAT ( '0**** EXCEEDED ALLOCATOR WHEN DEFINING ',
     1  A8, ' ROOM FOR ONLY', I6, ' VALUES.' )
      GO TO 50
C
 100  ALLOC(LDATA-1+ILEN) = X
      GO TO 50
C
C     END OF LIST -- BACKUP FOR SEMICOLON.
C
 300  INCH = INCH-1                                                     12470   
 310  ixxxx = CHOPIT ( MIN0(ILEN,ISIZE) )
C
C     IF OBJECT PREVIOUSLY EXISTED, ASSIGN IT THE SAME NUMBER
C
      IF ( IDOLD .EQ. 0 )  RETURN
      LOLD = Z(IDOLD)
      Z(IDOLD) = LDATA
      Z(IDATA) = -LOLD
      X = ALLOC(LDATA-1)
      ALLOC(LDATA-1) = ALLOC(LOLD-1)                                    12480   
      ALLOC(LOLD-1) = X
      LENG(IDATA) = LENG(IDOLD)
      LENG(IDOLD) = MIN0( ILEN, ISIZE )
C
      RETURN
      END
C*ID* DEFWOO   C109.PTOLEMY.SOURCE                          PER701  16:
      SUBROUTINE DEFWOO ( NUMPTS, RSTRT, STEPSZ, VRAY, N1, N2,
     1  ITYPE, V, R, A, POWER, IPORT, LXMIN, LDEFMX, RBETAS,
     2  LXS, NUMPT )                                                    12490   
C
C     COMPUTES DEFORMED WOODS-SAXON TYPE POTENTIALS
C
C     NUMPTS - NUMBER OF DESIRED POTENTIAL VALUES
C     RSTRT - FIRST R VALUE
C     STEPSZ - INCREMENT IN R - LASTR = RSTRT + (NUMPTS-1)*STEPSZ
C     VRAY - ARRAY OF NUMPTS LOCATIONS TO GET V
C     N1 - SET TO INDEX OF FIRST ELEMENT OF VRAY THAT IS NONTRIVIAL
C     N2 - SET TO INDEX OF LAST NON-ZERO ELEMENT IN VRAY.
C     ITYPE - TYPE OF POTENTIAL DESIRED:                                12500   
C       1 - WOODS SAXON.
C          -V / ( 1 + EXP((RVAL-R)/A) )**POWER
C       3 - DERIVATIVE OF W.S.
C          + 4*V*A * D/DR 1 / ( 1 + EXP((RVAL-R)/A) )
C     V, R, A, POWER - POTENTIAL PARAMETERS
C
C     IPORT - THE PROJECTION THAT IS DESIRED:
C      0 - DEFORMED OPTICAL POTENTIAL
C      1 - PROJECTILE EXCITATION
C      2 - TARGET EXECITATION                                           12510   
C      3 - MUTUAL
C     LXMIN - LOWER LIMIT OF LX'S TO USE IN THE DEFORMATION
C             APPLYS TO BOTH PROJECTILE AND TARGET
C     LDEFMX(2) - THE UPPER LIMIT OF LX'S TO USE FOR PROJECTILE
C             AND TARGET.  0 MEANS NO DEFORMATION.
C     RBETAS(2,) - RBETAS(I,LX) IS THE DEFORMATION LENGTH
C              I=1 IS PROJECTILE, =2 IS TARGET
C     LXS(2) - THE DESIRED PROJECTED LAMBDA IN THE PROJ AND
C              TARGET.
C     NUMPT - THE NUMBER OF POINTS TO USE IN THE INTEGRATION.           12520   
C             IF ODD LX'S ARE PRESENT, TWICE THIS NUMBER ARE USED.
C
C     FOR IPORT = 0, THE POTENTIAL COMPUTED IS
C       1/2  INTEGRAL(-1,1) DX V( R(X) )
C       OR 1/4 THE DOUBLE INTEGRAL IF BOTH NUCLEI ARE DEFORMED
C     FOR IPORT > 0 IT IS
C       SQRT( PI*(2LXOUT+1) ) INTEGRAL(-1,1) DX V( R(X) ) P(LXOUT,0,X)
C     WHERE
C       R(X) = R + SUM(LX) RBETAS(LX)*Y(LX,0,X)
C     IS THE DEFORMED POTENTIAL RADIUS.                                 12530   
C     IF BOTH NUCLEI ARE DEFORMED THEN A DOUBLE INTEGRAL IS DONE.
C
C     7/27/81 - FIRST VERSION MADE FROM WOODSX - S.P.
C     10/16/81 - ALLOW MUTUAL DEFORMATION - S.P.
C     12/19/84 - ADD SURFACE POT - S.P.
C
C
      implicit real*8 ( a-h, o-z )                                      implicit
      DIMENSION  VRAY(NUMPTS), RBETAS(2,1), LXS(2), LDEFMX(2)
      LOGICAL  ODDLSW                                                   12540   
      DIMENSION  XS(50), YS(2,50), WTS(50), PLM(20),
     1   FACS(2,20), WT(2,50)
C
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
C
c
C
C     CHECK FOR ZERO POTENTIAL
C
      N1 = 0                                                            12550   
      N2 = 0
      IF ( V .EQ. 0 )  GO TO 300
C
C
C     WILL WE NEED TO INTEGRATE FROM -1 TO 1
C     ALSO FIND AT LEAST ONE NUCLEUS THAT IS DEFORMED
C     AND THE NUMBER OF NUCLEI THAT ARE DEFORMED
C
      ODDLSW = .FALSE.
      NDIM = 0                                                          12560   
      DO 39  I = 1, 2
         LXMAX = LDEFMX(I)
         IF ( LXMAX .EQ. 0 )  GO TO 39
         NDIM = NDIM + 1
         IPT = I
         DO 29  LX = LXMIN, LXMAX
            IF ( btest(LX, 0) .AND.  RBETAS(I,LX) .NE. 0 )
     1         ODDLSW = .TRUE.
            FACS(I,LX) = DSQRT((2*LX+1)/(4*PI)) * RBETAS(I,LX)
 29      CONTINUE                                                       12570   
         LX = LXS(I)
         IF ( btest(LX, 0)  .AND.  .NOT. ODDLSW )  GO TO 300
 39   CONTINUE
      NGAUSS = NUMPT
      IF ( ODDLSW )  NGAUSS = 2*NUMPT
C
C     SETUP THE TOTAL DEFORMATION AND WEIGHTS AT EACH
C     INTEGRATION POINT
C
      CALL GAUSSL ( NGAUSS, XS, WTS )                                   12580   
      VSCALE = .5**NDIM * V
      IF ( IPORT .EQ. 0 )  GO TO 50
      IF ( IPORT .LT. 3 )  VSCALE = SQRT( PI*(2*LXS(IPORT)+1) )
     1     * 2*VSCALE
      IF ( IPORT .EQ. 3 )  VSCALE = PI * SQRT(
     1   (2*LXS(1)+1)*(2*LXS(2)+1.D0) ) * V
C
 50   LXMAX = MAX0( LXS(1), LXS(2), LDEFMX(1), LDEFMX(2) )
      DO 99  I = 1, NGAUSS
         X = XS(I)                                                      12590   
         IF ( .NOT. ODDLSW )  X = .5*(1+X)
         CALL PLMSUB ( LXMAX, 0, X, PLM )
         DO 89  II = 1, 2
            LXM = LDEFMX(II)
            Y = 1
            IF ( LXM .EQ. 0 )  GO TO 85
            Y = 0
            DO 79  LX = LXMIN, LXM
               Y = Y + FACS(II,LX)*PLM(LX+1)
 79         CONTINUE                                                    12600   
            Y = DEXP(-Y/A)
 85         YS(II,I) = Y
            WT(II,I) = WTS(I)*PLM(LXS(II)+1)
 89      CONTINUE
 99   CONTINUE
C
C
      XSTP = STEPSZ/A
      YSTP = DEXP(XSTP)
      X = (RSTRT-STEPSZ - R)/A                                          12610   
C
C     BREAK THE REGION (RSTRT, REND) INTO THREE REGIONS:
C     1) SMALL R:  EXP((RVAL-R)/A)  <  EXP(-100)
C     2) MODERATE R:  EXP(..)**POWER IS COMPUTABLE
C     3) LARGE R:  V/( EXP((RVAL-R)/A) )**POWER  <  EXP(-46) = 1.E-20
C
      N1 = -(100+X)/XSTP
      N1 = MAX0( N1, 1 )
      N1 = MIN0( N1, NUMPTS )
      Y = 46 + DLOG( DABS(V) )                                          12620   
      Y = DMIN1( Y, BIGLOG )
      IF ( POWER .GT. 1 )  Y = Y/POWER
      N2 = (Y-X)/XSTP
      N2 = MIN0( N2, NUMPTS )
      N2 = MAX0( N2, N1 )
C
C     REGION 1 - POTENTIAL IS -V OR ZERO.
C
      IF ( N1 .EQ. 1 )  GO TO 200
      Y = -V                                                            12630   
      IF ( ITYPE .GT. 1  .OR.  IPORT .NE. 0 )  Y = 0
      DO 189  I = 1, N1
         VRAY(I) = Y
 189  CONTINUE
C
C     REGION 2 - COMPUTE THE POTENTIAL
C
 200  X = X + N1*XSTP
      Y = DEXP(X)
      IF ( ITYPE .EQ. 3 )  GO TO 300                                    12640   
C
C     STRAIGHT W.S.
C
 210  IF ( POWER .NE. 1 )  GO TO 250
      ASSIGN 220 TO IGO
      IF ( NDIM .EQ. 2 )   ASSIGN 230 TO IGO
      DO 249  I = N1, N2
         VV = 0
         GO TO IGO, ( 220, 230 )
 220     DO 224  II = 1, NGAUSS                                         12650   
            VV = VV + WT(IPT,II)/(1+Y*YS(IPT,II))
 224     CONTINUE
         GO TO 240
 230     DO 235  II = 1, NGAUSS
         DO 235  III = 1, NGAUSS
            VV = VV + WT(1,II)*WT(2,III) /
     1        ( 1 + Y*YS(1,II)*YS(2,III) )
 235     CONTINUE
 240     VRAY(I) = -VSCALE*VV
         Y = Y*YSTP                                                     12660   
 249  CONTINUE
      GO TO 500
C
C     POWER OF W.S.
C
 250  ASSIGN 260 TO IGO
      IF ( NDIM .EQ. 2 )   ASSIGN 270 TO IGO
      DO 299  I = N1, N2
         VV = 0
         GO TO IGO, ( 260, 270 )                                        12670   
 260     DO 264  II = 1, NGAUSS
            VV = VV + WT(IPT,II)/(1+Y*YS(IPT,II))**POWER
 264     CONTINUE
         GO TO 280
 270     DO 274  II = 1, NGAUSS
         DO 274  III = 1, NGAUSS
            VV = VV + WT(1,II)*WT(2,III) /
     1        ( 1 + Y*YS(1,II)*YS(2,III) )**POWER
 274     CONTINUE
 280     VRAY(I) = -VSCALE*VV                                           12680   
         Y = Y*YSTP
 299  CONTINUE
      GO TO 500
C
C     DERIVATIVE OF W.S.
C
 300  VSCALE = +4*VSCALE
      ASSIGN 320 TO IGO
      IF ( NDIM .EQ. 2 )   ASSIGN 330 TO IGO
      DO 349  I = N1, N2                                                12690   
         VV = 0
         GO TO IGO, ( 320, 330 )
 320     DO 324  II = 1, NGAUSS
            YY = Y*YS(IPT,II)
            VV = VV + WT(IPT,II)/(1+YY)*YY/(1+YY)
 324     CONTINUE
         GO TO 340
 330     DO 335  II = 1, NGAUSS
         DO 335  III = 1, NGAUSS
            YY = Y*YS(1,II)*YS(2,III)                                   12700   
            VV = VV + WT(1,II)*WT(2,III)/(1+YY) *
     1        YY/(1+YY)
 335     CONTINUE
 340     VRAY(I) = -VSCALE*VV
         Y = Y*YSTP
 349  CONTINUE
C
C     NOW FILL OUT THE REST OF THE ARRAY WITH 0
C
 500  IF ( N2 .EQ. NUMPTS )  RETURN                                     12710   
      N2P1 = N2+1
      DO 329  I = N2P1, NUMPTS
         VRAY(I) = 0
 329  CONTINUE
      RETURN
      END
C*ID* DERCHK   C109.PTOLEMY.SOURCE                          PER701  22:
      SUBROUTINE  DERCHK ( NPARA, NPTS, STEP, PARAM, FS, FGRAD, TGRAD,
     1  FSAVE )
C                                                                       12720   
C     NUMERICALLY CHECKS THE GRADIENT COMPUTATION
C
C     10/29/75 - FIRST VERSION - S.P.
C     1/29/76 - STEP IS INPUT
C     4/22/77 - FIX DIVIDE BY 0
C     11/20/77 - NEW SETFIT CALL - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
CDC      ALLOCLEVEL PARAM,FS,FGRAD,TGRAD,FSAVE
C                                                                       12730   
      DIMENSION  PARAM(NPARA), FS(NPTS), FGRAD(NPTS,NPARA),
     1  TGRAD(NPARA), FSAVE(NPTS)
C
C     GET F(PARAM) AND THE ANALYTIC GRADIENT
C
      Chisq = CALGRA ( NPTS, NPARA, FS, PARAM, FGRAD, TGRAD )
C
      DO 89  N = 1, NPTS
         FSAVE(N) = FS(N)
 89   CONTINUE                                                          12740   
C
C     NOW NUMERICALLY COMPUTE THEM
C
C
C     DO IT FOR EACH PARAMETER
C
         DO 589  IP = 1, NPARA
            PSAVE = PARAM(IP)
            STEPP = STEP*PSAVE
            PARAM(IP) = PARAM(IP) + STEPP                               12750   
C
            xxxx = calfun ( NPTS, NPARA, FS, PARAM )
            RMS = 0
            T = 0
            F = 0
            write (6, 203) IP, PSAVE, STEPP
 203        FORMAT ( '1PARAMETER', I2, ' =', G25.15, 5X,
     1        'STEP =', G15.5 /
     2        '0POINT     VALUE', T30, 'ANALYTIC', T55, 'NUMERIC',
     3           T75, 'REL. DIF.' / )                                   12760   
C
            DO 299  N = 1, NPTS
               DFDP = (FS(N)-FSAVE(N))/STEPP
               F = F + FSAVE(N)
               T = T + 2*FSAVE(N)*DFDP
               REL = 0
               IF ( DFDP .NE. 0 )  REL = (DFDP-FGRAD(N,IP))/DFDP
               RMS = RMS + REL**2
               write (6, 233) N, FSAVE(N), FGRAD(N,IP), DFDP, REL
 233           FORMAT ( I5, G15.5, 2G25.15, G15.5 )                     12770   
 299        CONTINUE
            RMS = DSQRT(RMS/NPTS)
            REL = 0
            IF ( T .NE. 0 )  REL = (T-TGRAD(IP))/T
            write (6, 303) F, TGRAD(IP), T, REL, RMS
 303        FORMAT ( '0TOTAL', G14.5, 2G25.15, G15.5 /
     1      ' RMS ERROR IN GRAD(FS) =', G15.5 )
C
            PARAM(IP) = PSAVE
 589     CONTINUE                                                       12780   
C
C     RESTORE COMMON BLOCKS TO UNMODIFIED FORM
C
      CALL SETFIT ( PARAM, IRET, 0 )
C
      RETURN
      END
C*ID* DRIVE    C109.PTOLEMY.SOURCE                          PER701  17:
      SUBROUTINE DRIVE ( RHSR, RHSI, I5, I6, NFIRST, ITR, MBASCP,
     1  BASCUP, RBASCP, NUCH, COULH, NPTIN, NPTSAV, INHR, INHI, FLP,    12790   
     2  VMULT )
C
C     CONTRUCT DRIVING TERM OF INHOMOGENEOUS EQUATION
C
C     FIRST VERSION 12/2/80 MRB
C     4/17/80 - REMOVE ALLOCS - S.P.
C     4/19/80 - ALL ARITHMATIC IN REAL*4; COMBINED COULOMB AND NUC - S.P
C     4/27/80 - NPTSAV DIMENSION FOR INHR, INHI - S.P.
C     5/3/80 - FAKE REAL*4 RHS TO SAVE REAL8-REAL4 CONVERSION S.P.
C     6/2/80 - PASS NUMPT AS NPTIN FOR CDC COMPATIBILITY - S.P.         12800   
C     7/2/80 - FIX 4/19/80 BLUNDER FOR ODD PARITY - S.P.
C     7/28/80 - ALLOW ZEROING LOOP TO VECTORIZE ON CRAY - S.P.
C     3/15/82 - TEMPORARY REAL8 VERSION
C     3/15/82 - ADD SCALING OF THE COUPLING - S.P.
C     4/10/82 - BACK TO REAL*4 - S.P.
C     10/15/84 - REAL*8 BY MEANS OF C8H, C4H - S.P.
C
C     IN THIS VERSION WE WILL NOT ASSUME NUCLEAR TRANSISTION
C     POTENTIAL IS INDEPENDANT OF MULTIPOLE; HENCE VALID FOR
C     MORE GENERAL PROBLEMS                                             12810   
C
      implicit real*8 ( a-h, o-z )                                      implicit
C
      REAL*8 RHSR(1),RHSI(1)
cccCIBC4H      REAL*4  RHSR(2,1), RHSI(2,1)
cccCIBC8H      REAL*8  RHSR(1,1), RHSI(1,1)
cccCNI%'RHSR(1,' = 'RHSR('
cccCNI%'RHSI(1,' = 'RHSI('
C
      INTEGER BASCUP(MBASCP, 1)                                         12820   
      REAL*4 RBASCP(MBASCP, 1),  NUCH(2, NPTIN, 1),
     1  COULH(NPTIN, 1)
C4H      REAL*4   INHR(NPTSAV, 1),  INHI(NPTSAV, 1)
      REAL*8   INHR(NPTSAV, 1),  INHI(NPTSAV, 1)                        c8h
C
C4H      REAL*4  XN, XC, XKF, FAC, XCBYXN, TERM
      REAL*8  XN, XC, XKF, FAC, XCBYXN, TERM                            c8h
C
      COMMON /GRIDCM/  RCUEFF, GRDCM1(2),                               /gridcmf
     &  IBINDX, MBINDX, NBINDX, NMFFAC, MXLXGS, NMBFAC,
     & IINHR, IINHI, IRHSR, IRHSI,
     &  INUCH, ICOULH, ILOR, ILOI, ILIR, ILII,
     &  NPTMIN, NOFLO, NUMPT, NCRIT,
     & ISMX, ISMSQ, IPADE, IHOMO,
     &  ISMTSV, IRPTS4, IRPTS,
     &  IGRDC4(5), IDW, IGRDC5(2),
     &  IABS1, IGRDC6(2), GRDCM2, IGRDC7(2), IRWTS,
     &  IGRDC8(2), ICL1FF, ICL1FG, ICL1GF, ICL1GG
 
C                                                                       12830   
C
c
C
      ISTRT=NFIRST-1
      IFLOP = 0
C
C     MAKE SURE RHS EQUALS ZERO
C
      NPSTRT = NPTMIN+1
      NDO2 = NUMPT - iand( NUMPT-NPTMIN, 3 )                            12840   
      DO 10 I = NPSTRT, NDO2, 4                                         cnr
CRA      DO 10  I = NPSTRT, NUMPT
         rhsr(I)=0.
         rhsi(I)=0.
         rhsr(I+1)=0.                                                   cnr
         rhsi(I+1)=0.                                                   cnr
         rhsr(I+2)=0.                                                   cnr
         rhsi(I+2)=0.                                                   cnr
         rhsr(I+3)=0.                                                   cnr
         rhsi(I+3)=0.                                                   12850   
 10   CONTINUE
      IF ( NDO2 .EQ. NUMPT ) GO TO 50                                   cnr
      NDO2 = NDO2+1                                                     cnr
      DO 19  I = NDO2, NUMPT                                            cnr
         rhsr(I) = 0.                                                   cnr
         rhsi(I) = 0.                                                   cnr
 19   CONTINUE                                                          cnr
C
C     LOOP OVER ALL POSSIBLE RHS COMPONENTS AND SELECT
C     APPROPIATE F ACTORS AND POINTERS                                  12860   
C
 50   DO 999 I7=I5,I6
      IPTWF = BASCUP(2,I7)
C
C
      XN=RBASCP(5,I7)
      XC=RBASCP(6,I7)
      ITRI=BASCUP(7,I7)
      ITRAB=IABS(ITRI)
      XKF=RBASCP(8,I7)                                                  12870   
      IF ( XKF .EQ. 0 )  GO TO 999
      IPTN= BASCUP(10,I7)
C
C     IPTN IS STORED AS 1,3, 5  FOR THE 1ST, 2ND, 3RD, ...
C     RADIAL WAVEFUNCTION.  HERE SET IT TO WHAT IT SHOULD BE
C
      IPTN = (IPTN+1)/2
      IPTC= BASCUP(11,I7)
C
C     FACTOR OF 12 CORRECTS SIMPLIFIED NUMEROV ALGORITHUM               12880   
C     DONT NEED FACTOR OF 12 FOR INITIAL GUESS ELASTIC WAVEFUNCTION
C
      FAC = XKF*VMULT
      IF ( ITRI .LT. 0 )  FAC = -FAC
      IF ( ITR .NE. 1   .OR.  IPTWF .NE. 1 )  FAC = FAC/12.
      XN = FAC*XN
      XC = FAC*XC
C
      IF(ITRAB.GT.1)GO TO 500
C                                                                       12890   
C     THIS SECTION FOR REAL TIME REVERSAL INVARIANCE
C     CALCULATE PRODUCT OF W.F. AND NUCLEAR POTENTIAL
C
      IF(XN.EQ.0)GO TO 200
      IF ( XC .NE. 0 )  GO TO 150
C
C     HERE WE ONLY HAVE THE A NUCLEAR POTENTIAL
C
      IFLOP = IFLOP + 10
      DO 139 I=ISTRT,NUMPT                                              12900   
         rhsr(I)=(NUCH(1,I,IPTN)*INHR(I,IPTWF)
     1     -NUCH(2,I,IPTN)*INHI(I,IPTWF))*XN+rhsr(I)
         rhsi(I)=(NUCH(1,I,IPTN)*INHI(I,IPTWF)
     1     +NUCH(2,I,IPTN)*INHR(I,IPTWF))*XN+rhsi(I)
 139  CONTINUE
      GO TO 999
C
C     HERE WE HAVE BOTH THE COULOMB AND NUCLEAR POTENTIAL
C
 150  IFLOP = IFLOP+12                                                  12910   
      XCBYXN = XC/XN
      DO 169  I = ISTRT, NUMPT
         TERM = NUCH(1,I,IPTN) + XCBYXN*COULH(I,IPTC)
         rhsr(I) = rhsr(I) + XN*( TERM*INHR(I,IPTWF)
     1       - NUCH(2,I,IPTN)*INHI(I,IPTWF) )
         rhsi(I)  = rhsi(I) + XN*( TERM*INHI(I,IPTWF)
     1       + NUCH(2,I,IPTN)*INHR(I,IPTWF) )
 169  CONTINUE
      GO TO 999
C                                                                       12920   
C     HERE ONLY A COULOMB POTENTIAL
C
200   IF(XC.EQ.0)GO TO 999
      IFLOP = IFLOP + 5
      DO 249 I=ISTRT,NUMPT
         rhsr(I) = rhsr(I) + (XC*COULH(I,IPTC))*INHR(I,IPTWF)
         rhsi(I) = rhsi(I) + (XC*COULH(I,IPTC))*INHI(I,IPTWF)
249   CONTINUE
      GO TO 999
C                                                                       12930   
C     THIS SECTION FOR IMAGINARY TIME REVERSAL INVARIENCE
C     CALCULATE PRODUCT OF W.F. AND NUCLEAR POTENTIAL
C
 500  IF(XN.EQ.0)GO TO 600
      IF ( XC .NE. 0 )  GO TO 550
C
C     HERE JUST A NUCLEAR FORCE
C
      IFLOP = IFLOP + 10
      DO 539 I=ISTRT,NUMPT                                              12940   
         rhsr(I)=-(NUCH(1,I,IPTN)*INHI(I,IPTWF)
     1     +NUCH(2,I,IPTN)*INHR(I,IPTWF))*XN+rhsr(I)
         rhsi(I)=(NUCH(1,I,IPTN)*INHR(I,IPTWF)
     1     -NUCH(2,I,IPTN)*INHI(I,IPTWF))*XN+rhsi(I)
539   CONTINUE
C
      GO TO 999
C
C     HERE WE HAVE BOTH COULOMB AND NUCLEAR POTENTIALS
C                                                                       12950   
 550  IFLOP = IFLOP + 12
      XCBYXN = XC/XN
      DO 569  I = ISTRT, NUMPT
         TERM = NUCH(1,I,IPTN) + XCBYXN*COULH(I,IPTC)
         rhsr(I) = rhsr(I) - XN*( TERM*INHI(I,IPTWF)
     1       + NUCH(2,I,IPTN)*INHR(I,IPTWF) )
         rhsi(I) = rhsi(I) + XN*( TERM*INHR(I,IPTWF)
     1       - NUCH(2,I,IPTN)*INHI(I,IPTWF) )
 569  CONTINUE
      GO TO 999                                                         12960   
C
C     HERE ONLY A COULOMB POTENTIAL
C
600   IF(XC.EQ.0)GO TO 999
      IFLOP = IFLOP + 5
      DO 649 I=ISTRT,NUMPT
         rhsr(I) = rhsr(I) - (XC*COULH(I,IPTC))*INHI(I,IPTWF)
         rhsi(I) = rhsi(I) + (XC*COULH(I,IPTC))*INHR(I,IPTWF)
649   CONTINUE
999   CONTINUE                                                          12970   
C
      FLP = IFLOP*(NUMPT-NFIRST+1)
      RETURN
      END
C*ID* DUMMY1   C109.PTOLEMY.SOURCE                          PER701  17:
      SUBROUTINE DUMMY1
C
C     USED TO FORCE COMMON BLOCKS INTO CORE AT RIGHT TIME.
C
C     6/19/75 - CALLS DUMMY2 TO GET /LOGFAC/                            12980   
C
      CALL DUMMY2
      RETURN
      END
      SUBROUTINE DUMMY2
      RETURN
      END
C*ID* ELDCS    C109.PTOLEMY.SOURCE   PART 2                 PER701  13:
      SUBROUTINE ELDCS ( UK, ETA, ANGMIN, ANGMAX, ANGSTP,
     1  LMN, LMX, LSKP, ISTAT, JSP,                                     12990   
     2  ISMAT, ITOC, NSPL, ISIG, ELAB, TAU, PRNTSW, ITORUT, RUTNAM,
     3  FKEPSW, IFEL, FNAME, SIGREA, IRUTH, RUTHNM )
C
C     CALCULATES DIFFERENTIAL CROSS SECTIONS FOR ELASTIC SCATTERING
C     FOR THE FOLLOWING CASES:
C     1)  NON-IDENTICAL PARTICLES WITH NO SPIN DEPENDENCE IN THE FORCE
C     2)  IDENTICAL PARTICLES OF ARBITRARY SPIN WITH NO SPIN
C         DEPENDENCE IN THE FORCE.
C     3)  NON-IDENTICAL PARTICLES OF ARBITRARY SPIN, WITH SPIN-ORBIT
C         AND/OR TENSOR FORCES INVOLVING THE PROJECTILE SPIN ONLY       13000   
C         (I.E. INDEPENDENT OF TARGET SPIN).
C     ATTEMPTING TO MIX CASES 2 AND 3  WILL RESULT IN GARBAGE.
C
C
C     ARGUMENTS (INPUT UNLESS MARKED 'RETURNED'):
C
C     UK = WAVE NUMBER (FM**-1).
C     ETA = COULOMB PARAMETER.
C     ANGMIN, ANGMAX, ANGSTEP = MINIMUM, MAXIMUM, STEP IN ANGLE
C        (DEGREES).                                                     13010   
C     LMN, LMX = MINIMUM, MAXIMUM LI.
C     LSKP = ANGLE STEP = 2 FOR IDENTICAL SPIN-0 PARTICLES, 1 OTHERWISE.
C     ISTAT = 1 FOR IDENTICAL BOSONS, 2 FOR IDENTICAL FERMIONS,
C        3 IF NOT IDENTICAL.
C     JSP = 2 * PROJECTILE SPIN.
C     ISMAT = NALLOC TO THE S-MATRIX.
C     ITOC = NALLOC TO THE TABLE OF CONTENTS FOR S.
C     NSPL = NUMBER OF JT, JP, LX, LO COMBINATIONS PER LI.
C     ISIG = NALLOC TO COULOMB PHASES.
C     ELAB = LAB ENERGY (MEV).                                          13020   
C     TAU = MASS RATIO (PROJECTILE/TARGET).
C     PRNTSW = .TRUE. IF CROSS SECTIONS ARE TO BE PRINTED.
C     ITORUT = NALLOC TO CROSS SECTIONS/RUTHERFORD (RETURNED).
C     RUTNAM = NAME TO BE ASSIGNED TO ARRAY ABOVE.
C     FKEPSW = .TRUE. IF AMPLITUDES F ARE TO BE SAVED.
C     IFEL = NALLOC TO SAVED F (RETURNED).
C     FNAME = NAME TO BE ASSIGNED TO F ARRAY.
C     SIGREA = TOTAL REACTION CROSS SECTION (MB) (RETURNED).
C
C                                                                       13030   
C     THIS FIRST VERSION 8/15/73 D.GLOECKNER
C     SMALL CHANGES 9/22/75
C     10/7/75 - STORE CROSS SECTIONS - S.P.
C     10/14/75 - PRINT ERRORS; NICE PRINTOUT
C     6/7/76 - LAB ANGLES
C     1/3/77 - FIX BUG FOR SPIN-ORBIT FORCE.
C     1/26/77 - LAB ANGLES
C     2/10/77 - REMOVE ARRAYS FROM ARG. LIST
C     4/24/77 - IDENTICAL PARTICLES
C     5/7/77 - REMOVE C COEFS; PRNTSW; VARIABLE NAMES; TOTAL REACT      13040   
C     10/22/77 - FIX ERROR IN 180 DEGREE CROSS SECTIONS.
C     5/12/79 - STORE ANGLE-INDEPENDENT STUFF IN ARRAYS - S.P.
C     9/3/79 - STANDARD PREFIXES; ARBITRARY PROJECTILE SPIN WITH
C        S.O., TENSOR FORCES - RPG
C     1/31/80 - CHARACTER*8 FNAME, RUTNAM - RPG
C     7/28/80 - PASS NEW WORK ARRAYS TO AMPCAL - S.P.
C     8/1/80 - CALL SETLOG - S.P.
C     9/17/81 - CHANGED AMPCAL CALL; SAVE RUTHERFORD - S.P.
C     10/27/81 - AMPCAL CHANGED AGAIN FOR SYM INDICATOR - S.P.
C     3/9/82 - FIX BUGS SAVING CROSSSECT - S.P.                         13050   
C     5/19/83 - REORGANIZE FS AS DONE IN XSECTN - S.P.
C     7/1/83 - ALWAYS STORE XSEC; WHEN FOR XSECTN, STORE LAB SIG
C              AND USE ABAR IN COMMON IF LABANGLES - S.P.
C     5/12/85 - CALL SETINT FOR CRAY VERSION
C
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
      COMMON /KANDM/ AKI, AKO, REDMI, REDMO, RIMAX, ROMAX, ISIGS(2),    /kandm/
     &  RSCTS(2), ASCTS(2), RCSCTS(2) ,ISMATS(2), LOMOST, LCRIT,
     &  ISCTMN, ISCTCR, ETAS(2), RCSCTP(2), RCSCTT(2), LCRITS(2),
     &  RATMSS(2), QMIN, ABAR
 
      DIMENSION  AKS(2), REDMS(2), RMAXS(2)
      EQUIVALENCE ( AKI, AKS(1) ), ( REDMI, REDMS(1) ),
     &  ( RIMAX, RMAXS(1) )
 
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
      CHARACTER*1  REACT, HEADER                                        /hedcom/
      COMMON /HEDCOM/  REACT(45), HEADER(65)
 
C
      LOGICAL  PRNTSW, PBETSW, IDNTSW, FKEPSW
      CHARACTER*8   RUTHNM, RUTNAM, FNAME
C
      DIMENSION FCOUL(2,3), ALOWFC(2,2)
      REAL*4 DUM4(1,1)
      REAL*8 DUM8(1)
C                                                                       13070   
c
C
      PBETSW = MOD( IPRINT, 10 ) .GE. 4
C
C
C     PRINT HEADER
C
      IF (PRNTSW)  WRITE(6, 13)  REACT, ELAB, HEADER
 13   FORMAT('1',T48,'P T O L E M Y' /
     1  1X, 45A1, F8.2, ' MEV', 5X, 65A1 /                              13080   
     2  '0    ANGLE', T21, 'SIGMA/', T40, 'SIGMA', T59, 'RUTHERFORD',
     3    T78, '% PER', T87, '% PER'  /
     4  '  C.M.    LAB     RUTHERFORD', T34, 'C.M.', T47, 'LAB',
     5    T62, 'C.M.', T78, 'LOW L', T86, 'HIGH L' / )
C
      ANMIN = ANGMIN
      ANMAX = ANGMAX
      IF ( PRNTSW )  ABAR = 180
C
C     FOR LAB ANGLES WE HAVE FUNNY STUFF IF TAU > 1                     13090   
C     FOR XSECTN CALLS, IT HAS ALL BEEN WORKED OUT ALREADY
C
      IF ( LABANG .EQ. 0 )  GO TO 50
      IF ( .NOT. PRNTSW )  GO TO 50
      IF ( TAU .LE. 1 )  GO TO 50
C
C     OUR CONVENTION IS THAT NEGATIVE VALUES FOR ANGLEMIN OR ANGLEMAX
C     CORRESPOND TO THE 2ND BRANCH.
C
      ANGBAR = RADIAN * ASIN(1/TAU)                                     13100   
      ANGSTP = DABS(ANGSTP)
      ABAR = ANGSTP * (DINT( (ANGBAR-ANMIN)/ANGSTP + 1.D-10 )
     1  + ANMIN)
C
  50  TABAR = 2*ABAR
      ANMAX = DMIN1( ANMAX, TABAR )
      ANGSTP = DSIGN( ANGSTP, ANMAX-ANMIN )
      NUMANG = (ANMAX-ANMIN)/ANGSTP + 1.5
C
C     MAKE A SPACE EVERY ONCE AND A WHILE.                              13110   
C
      ANGBLK = 52
      IF ( NUMANG .LE. 50 )  GO TO 80
      ANGBLK = 10
      IF ( ANGSTP .GE. 1 )  GO TO 80
      ANGBLK = 5
      IF ( ANGSTP .GE. .5 )  GO TO 80
      ANGBLK = 1
 80   LINECT = 1
      NUMBLK = ANGBLK/ANGSTP + .5                                       13120   
      LINEMX = 53
C
      IF ( NSPL .EQ. 1  .OR.  ISTAT .EQ. 3 )  GO TO 100
      write (6, 98)
 98   FORMAT ( '0**** CANNOT EVALUATE ELASTIC SCATTERING FOR ',
     1  'IDENTICAL PARTICLES WITH S.O. FORCE' )
      RETURN
C
C     ALLOCATE SPACE FOR THETA-INDEPENDENT ARRAYS
C                                                                       13130   
 100  LXMX = 0
      IF ( NSPL .GT. 1 )  LXMX = JSP
      LDELMX = LXMX - MOD( LXMX, 2 )
      NTEMPS = (LXMX+1)**2 * (LDELMX+1)
      ITEMPS = NALLOC( NTEMPS, 'TEMPS   ' )
      IBETA = NALLOC( 2*NSPL*(LMX+1), 'BETAELAS' )
C
      CALL SETLOG ( 2*(LMX+LXMX) )
C
C     CALCULATE "BETAELAS", THE ANGLE-INDEPENDENT PARTS OF F.           13140   
C     ALSO CALCULATE TOTAL REACTION AND NUCLEAR CROSS SECTIONS.
C
      LTOC = FACFR4*Z(ITOC) - FACFR4 + 1
      LBETA = FACFR4*Z(IBETA) - FACFR4 + 1
      CALL BETCAL ( .TRUE., UK, JSP, NSPL, LMN, LMX, LSKP,
     1   0, LXMX, LDELMX, NTEMPS, ISTAT, PBETSW,
     2   SIGNUC, SIGREA,
     3   ILLOC(LTOC), ALLOC(Z(ISMAT)), DUM4, DUM4, ALLOC(Z(ISIG)),
     4   DUM8, ALLOC4(LBETA), DUM8, DUM8, ALOWFC, ALLOC(Z(ITEMPS)) )
C                                                                       13150   
C     RELEASE TEMPORARY ARRAY.
C
      Z(ITEMPS) = -Z(ITEMPS)
C
C     ALLOCATE SPACE FOR LEGENDRE FUNCTIONS, AMPLITUDES, CROSS SECTIONS.
C
      ISPACE = LMX + 1 + ( (2*LMX+1-LXMX)*LXMX )/2
      IPLM = NALLOC( ISPACE, 'PLM     ' )
      ITMPCN = NALLOC( 2*(LMX+1), 'TMPCONTR' )
      IDNTSW = ISTAT .NE. 3                                             13160   
      IDNPAR = 0
      IF ( IDNTSW )  IDNPAR = 2
      NF = 2*NSPL
      IF ( IDNTSW )  NF = 6
      IFTEMP = NALLOC( NF, 'FTEMP   ' )
      IFLO = NALLOC( NF, 'FLO     ' )
      IFHI = NALLOC( NF, 'FHI     ' )
      IFERR = NALLOC( NF, 'FERROR  ' )
      IFEPSL = NALLOC( 2*LEBACK+1, 'FEPSILON' )
      IFEL = 0                                                          13170   
      IF ( FKEPSW )  IFEL = NALLOC( NF*NUMANG, FNAME )
      ICROSS = NALLOC( NUMANG, 'CROSSSEC' )
      ITORUT = NALLOC( NUMANG, RUTNAM )
      ILAB = 0
      IF (PRNTSW)  ILAB = NALLOC( NUMANG, 'LABCROSS' )
      IRUTH = NALLOC( NUMANG, RUTHNM )
CRA      CALL SETINT ( LMX )
C
C     ALLOCATIONS ARE DONE, GET THE BASE ADDRESSES.
C                                                                       13180   
      LFTEMP = Z(IFTEMP) - 2
      LFLO = Z(IFLO) - 2
      LFHI = Z(IFHI) - 2
      LFERR = Z(IFERR)-1
      LTOC = Z(ITOC)*FACFR4 - FACFR4
      LF = Z(IFEL) - 2*NUMANG - 2
      LBETA = FACFR4*Z(IBETA) - FACFR4 + 1
      LPLM = Z(IPLM)
      LTMPCN = Z(ITMPCN)
C                                                                       13190   
      STATFC = 0
      IF ( ISTAT .LT. 3 )  STATFC = (ISTAT-1.50D0)*JSP/(JSP+1.D0)
      LHI = LMX - 2 - MOD( LMX, LSKP )
      SIGZRO = ALLOC(Z(ISIG))
C
C
C     LOOP OVER ALL ANGLES
C
      DO 489  NANG = 1, NUMANG
C                                                                       13200   
         ANGLE = ANMIN + (NANG-1)*ANGSTP
C
         IF ( LABANG .EQ. 0 )  GO TO 120
         AN = DEGREE*ANGLE
         IF ( ANGLE .GT. ABAR )  AN = DEGREE*(TABAR-ANGLE)
         TERM2 = 1 - (TAU*DSIN(AN))**2
         IF ( TERM2 .LT. 0 )  TERM2 = 0
         TERM2 = DCOS(AN)*DSQRT(TERM2)
         IF ( ANGLE .GT. ABAR )  TERM2 = -TERM2
         ANGLE = RADIAN * ACOS( -TAU*(DSIN(AN))**2 + TERM2 )            13210   
C
 120     COSAN=DCOS(ANGLE*DEGREE)
         ANGLAB = RADIAN*DATAN2( DSIN(ANGLE*DEGREE), COSAN+TAU )
C
         TERM2 = 1 + TAU*(TAU+2*COSAN)
         TEMP = 1 + TAU*COSAN
         AJACOB = 0
         IF ( TERM2 .LT. 0 ) TERM2 = 0
         IF ( TEMP .NE. 0 )  AJACOB = DABS( TERM2*DSQRT(TERM2)/TEMP )
C                                                                       13220   
C        CALCULATE THE AMPLITUDES FOR THIS ANGLE.
C
         CALL AMPCAL ( ANGLE, .TRUE., NSPL, LMN, LMX, LSKP,
     1      LXMX, IDNPAR, ETA, UK, SIGZRO, PRNTSW, LHI,
     2      ILLOC(LTOC+1), ALLOC4(LBETA), ALOWFC,
     3      ALLOC(LFTEMP+2), ALLOC(LFLO+2), ALLOC(LFHI+2),
     4      ALLOC(LFERR+1), FCOUL, ALLOC(LPLM), ALLOC(LTMPCN),
     4      ALLOC(LTMPCN+LMX+1),
     5      LEBACK, ALLOC(Z(IFEPSL)), NFLPAM )
C                                                                       13230   
C        CALCULATE THE CROSS SECTIONS.
C
         SIGMA = 0
         SIGLOW = 0
         SIGHI = 0
         IF ( IDNTSW )  GO TO 250
         DO 229  KOFFS = 1, NSPL
            IF ( ILLOC(LTOC+4*KOFFS) .LT. 0 )  GO TO 229
            MX = ( ILLOC(LTOC+4*KOFFS-3) + ILLOC(LTOC+4*KOFFS-2) + 1 )/2
            TEMP = 10.                                                  13240   
            IF ( MX .NE. 0 )  TEMP = 20.
            SIGMA = SIGMA + TEMP *
     1         ( ALLOC(LFTEMP+2*KOFFS)**2 + ALLOC(LFTEMP+2*KOFFS+1)**2 )
            IF ( .NOT. PRNTSW )  GO TO 229
            SIGLOW = SIGLOW + TEMP *
     1         ( ALLOC(LFLO+2*KOFFS)**2 + ALLOC(LFLO+2*KOFFS+1)**2 )
            SIGHI = SIGHI + TEMP *
     1         ( ALLOC(LFHI+2*KOFFS)**2 + ALLOC(LFHI+2*KOFFS+1)**2 )
 229     CONTINUE
         RUTH = ( FCOUL(1,3)**2 + FCOUL(2,3)**2 )*10.                   13250   
         GO TO 260
C
C        IDENTICAL PARTICLES (NO SPIN-DEPENDENT FORCES).
C
 250     RUTH = ( FCOUL(1,ISTAT)**2 + FCOUL(2,ISTAT)**2
     1      + STATFC*( FCOUL(1,1)**2 + FCOUL(2,1)**2
     2      - FCOUL(1,2)**2 - FCOUL(2,2)**2 ) )*10.
         SIGMA = ( ALLOC(LFTEMP+2*ISTAT)**2 + ALLOC(LFTEMP+2*ISTAT+1)**2
     1      + STATFC*( ALLOC(LFTEMP+2)**2 + ALLOC(LFTEMP+3)**2
     2      - ALLOC(LFTEMP+4)**2 - ALLOC(LFTEMP+5)**2 ) )*10.           13260   
         IF ( .NOT. PRNTSW )  GO TO 260
         SIGLOW = ( ALLOC(LFLO+2*ISTAT)**2 + ALLOC(LFLO+2*ISTAT+1)**2
     1      + STATFC*( ALLOC(LFLO+2)**2 + ALLOC(LFLO+3)**2
     2      - ALLOC(LFLO+4)**2 - ALLOC(LFLO+5)**2 ) )*10.
         SIGHI = ( ALLOC(LFHI+2*ISTAT)**2 + ALLOC(LFHI+2*ISTAT+1)**2
     1      + STATFC*( ALLOC(LFHI+2)**2 + ALLOC(LFHI+3)**2
     2      - ALLOC(LFHI+4)**2 - ALLOC(LFHI+5)**2 ) )*10.
C
C        SAVE F IF NECESSARY.
C                                                                       13270   
 260     IF ( .NOT. FKEPSW )  GO TO 280
C
C     NF/2 = NSPL EXCEPT =3 FOR IDENTICAL PARTICLES
C
         NFBY2 = NF/2
         DO 269  K = 1, NFBY2
            ALLOC(LF+2*NANG+2*NUMANG*K) = ALLOC(LFTEMP+2*K)
            ALLOC(LF+2*NANG+2*NUMANG*K+1) = ALLOC(LFTEMP+2*K+1)
 269     CONTINUE
C                                                                       13280   
C        COMPUTE RELATIVE ERRORS FROM LOWER AND UPPER L-TRUNCATIONS
C
 280     EL = 50 * (1 - SIGLOW/SIGMA)
         EH = 50 * (1 - SIGHI/SIGMA)
         SIGMAR = 0
         IF ( RUTH .NE. 0 )  SIGMAR = SIGMA/RUTH
C
         IF ( .NOT. PRNTSW )  GO TO 400
C
         SIGLAB = AJACOB*SIGMA                                          13290   
C
C        PRINT EVERTHING IN MILLIBARNS
C
         LINECT = LINECT + 1
         IF ( LINECT .LE. LINEMX  .OR.  NANG .EQ. NUMANG )  GO TO 300
         write (6, 13) REACT, ELAB, HEADER
         LINECT = 1
C
 300     WRITE(6, 303)ANGLE, ANGLAB, SIGMAR, SIGMA, SIGLAB, RUTH, EL, EH
 303     FORMAT( 2F7.2, 2G14.4, G12.4, G15.4, F13.2, F8.2 )             13300   
C
         IF ( DMOD(ANGLE+ANGSTP+1.D-7, ANGBLK) .GT. 1.D-5 )  GO TO 380
         write (6, 343)
 343     FORMAT ( ' ' )
         LINECT = LINECT + 1
         IF ( LINECT+NUMBLK .GT. LINEMX )  LINECT = LINEMX + 1
 380     ALLOC(Z(ILAB)-1+NANG) = SIGLAB
 400     ALLOC(Z(ITORUT)-1+NANG) = SIGMAR
         ALLOC(Z(IRUTH)-1+NANG) = RUTH
         IF ( LABANG .NE. 0  .AND.  .NOT. PRNTSW )                      13310   
     1      SIGMA = AJACOB*SIGMA
         ALLOC(Z(ICROSS)-1+NANG) = SIGMA
C
 489  CONTINUE
C
      IF (PRNTSW)  write (6, 813) SIGREA, SIGNUC
 813  FORMAT ( / '0TOTAL REACTION CROSS SECTION =', F13.3, ' MB' /
     1  '  NUCLEAR TOTAL CROSS SECTION =', F13.3, ' MB' )
C
C  FREE ALLOCATED SPACE                                                 13320   
C
      Z(IPLM)=-Z(IPLM)
      Z(IBETA) = -Z(IBETA)
      Z(IFTEMP) = -Z(IFTEMP)
      Z(IFLO) = -Z(IFLO)
      Z(IFHI) = -Z(IFHI)
      RETURN
      END
C*ID* EPSLON   C109.PTOLEMY.SOURCE                          PER701  17:
      SUBROUTINE EPSLON ( XIN, N, FRET, DEPS, DERR, IER )               13330   
C
C     EPSILON ALGORITHM FOR A COMPLEX ARRAY
C
C     X - COMPLEX*16 ARRAY CONTAINING THE SEQUENCE TO BE ACCELERATED.
C         ON RETURN THE FIRST N ELEMENTS ARE THE ACCELERATED SEQUENCE.
C     N - NUMBER OF ELEMENTS IN X.  MODIFIED TO BE THE NUMBER OF OUTPUT
C         ELEMENTS.  ON INPUT THIS MUST BE AT LEAST 5.
C     FIN - (COMPLEX*16) COMPUTED LIMIT OF THE SEQUENCE.  THIS IS THE
C         AVERAGE OF THE N FINAL ELEMENTS IN X.
C     DEPS - REQUESTED ACCURACY OF FIN.  ITERATION IS HALTED WHEN THE N 13340   
C         FINAL ELEMENTS OF X ALL DIFFER BY LESS THAN DEPS (RELATIVELY)
C         FROM THE AVERAGE (FIN).
C     DERR - SET TO THE MAXIMUM RELATIVE DEVIATION OF THE N FINAL ELEMEN
C         OF X FROM FIN.  IF CONVERGENCE WAS ACHIEVED,  DERR < DEPS.
C     IER - SET TO 0 IF CONVERGENCE ACHIEVED; 1 IF NOT; -1 IF N < 10
C
C     9/9/81 - FIRST VERSION BASED ON THE SSP ROUTINE TEAS - S.P.
C     8/17/83 - DON'T MAKE ERROR CHECKS ON ONE ELEMENT - S.P.
C     4/12/85 - ADD COMPLEX*16 Z FOR CRAY - S.P.
C     11/15/01 - fudge complex X to satisfy compat checks               13350   
C
      IMPLICIT REAL*8 (A-H, O-Z)
C
      REAL*8 XIN(2, N), FRET(2)
      COMPLEX*16 X(2000), FIN
      COMPLEX*16 T, W1, W2, W3, W4, W5, W6, W7
      LOGICAL  ISW1, ISW2
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
C
      LOGICAL NONZER, ZERO                                              13360   
      COMPLEX*16 Z
      APXABS(Z) = DABS(DREAL(Z))+DABS(DIMAG(Z))
      NONZER(Z) = APXABS(Z) .NE. 0
      ZERO(Z) = APXABS(Z) .EQ. 0
C
C  FUDGE
C
      IF ( N .GT. 2000 ) THEN
         WRITE(6,*) 'EPSLON: N > 2000 NOT ALLOWED', N
         WRITE(0,*) 'EPSLON: N > 2000 NOT ALLOWED', N                   13370   
         STOP 9876
      ENDIF
      DO I = 1, N
         X(I) = CMPLX( XIN(1,I), XIN(2,I) )
      ENDDO
C
      IER = -1
      IF ( N .LT. 5 )  RETURN
C
      BIG = 1.D+38                                                      13380   
C
C     TEST FOR ACCURACY, ON FIRST TEST REQUIRE MORE ACCURACY
C     TO COMPLETELY BYPASS EPSILON.
C
      ACC = DMAX1( 1.D-8, DEPS**2 )
  41  IF ( N .LE. 0 )  RETURN
      FIN = X(N)
      FRET(1) = REAL(FIN)
      FRET(2) = DIMAG(FIN)
      IF ( N .EQ. 1 )  RETURN                                           13390   
      DERR = 0
      DO 43  I = 1, N
         DERR = DMAX1( DERR, APXABS( FIN-X(I) ) )
  43  CONTINUE
      DERR = DERR / ( APXABS(FIN) + SMLNUM )
      IER = 0
CCC      write (6, 403) N, IMIN, IAUS, ISW1, ISW2, FIN, DERR, ACC
CCC 403  FORMAT ( ' END', 3I4, 2L2, 2G28.18 , 2G14.3 )
      IF ( DERR .LE. ACC )  RETURN
      ACC = DEPS                                                        13400   
C
      IF ( N .GE. 6 )  GO TO 2
      IER = 1
      RETURN
C
C     INITIAL VALUES OF THE EPSILON ARRAY
C
  2   ISW1 = .FALSE.
      ISW2 = .FALSE.
      W1 = BIG                                                          13410   
      W7 = X(4)-X(3)
      IF ( NONZER(W7) )  W1 = 1/W7
      W5 = BIG
      W7 = X(2)-X(1)
      IF ( NONZER(W7) )  W5 = 1/W7
      W4 = X(3)-X(2)
      IF ( NONZER(W4) )  GO TO 9
      W4 = BIG
      T = X(2)
      W2 = X(3)                                                         13420   
  8   W3 = BIG
      GO TO 17
C
  9   W4 = 1/W4
      T = BIG
      W7 = W4-W5
      IF ( NONZER(W7) )  T = X(2) + 1/W7
      W2 = W1-W4
      IF ( NONZER(W2) )  GO TO 15
      W2 = BIG                                                          13430   
      ISW2 = DREAL(T) .NE. BIG
      W3 = W4
      GO TO 17
C
  15  W2 = X(3)+1/W2
      W7 = W2-T
      IF ( ZERO(W7) )  GO TO 8
      W3 = W4 + 1/W7
C
   17 ISW1 = ISW2                                                       13440   
      ISW2 = .FALSE.
      IMIN = 4
CCC      write (6, 303) N, ISW1, BIG, (I, X(I),I=1,N)
CCC 303  FORMAT ( '0EPS, N=', I6, L5, G28.18 / (I4, 2G28.18) )
CCC      write (6, 307) W1, W2, W3, W4, W5, W6, W7
CCC 307  FORMAT ( ' W=', (T5, 2G28.18) )
C
C     CALCULATE DIAGONALS OF THE EPSILON ARRAY
C
      DO 40  I = 5, N                                                   13450   
      IAUS = I-IMIN
      W4 = BIG
      W5 = X(I-1)
      W7 = X(I)-X(I-1)
      IF ( ZERO(W7) )  GO TO 24
      W4 = 1/W7
      IF ( DREAL(W1) .EQ. BIG )  GO TO 25
      W6 = W4-W1
C
C     TEST FOR NECESSITY OF A SINGULAR RULE                             13460   
C
      IF ( APXABS(W6) .GT. 1.D-12*APXABS(W4) )  GO TO 22
      ISW2 = .TRUE.
      IF ( NONZER(W6) )  GO TO 22
      W5 = BIG
      W6 = W1
      IF ( DREAL(W2) .NE. BIG )  GO TO 28
      GO TO 26
C
  22  W5 = X(I-1) + 1/W6                                                13470   
C
C     TEST FOR LOSS OF SIGNIFICANCE
C
      IF ( APXABS(W5) .GE. 1.D-10*APXABS(X(I-1)) )  GO TO 24
      IF ( NONZER(W5) )  GO TO 36
C
  24  W7 = W5-W2
      IF ( NONZER(W7) )  GO TO 27
  25  W6 = BIG
  26  ISW2 = .FALSE.                                                    13480   
      X(IAUS) = W2
      GO TO 37
  27  W6 = W1 + 1/W7
  28  IF ( .NOT. ISW1 )  GO TO 33
C
C     CALCULATE X(IAUS) WITH SINGULAR RULE
C
      IF ( DREAL(W2) .EQ. BIG )  GO TO 32
      W7 = W5/(W2-W5) + T/(W2-T) + X(I-2)/(X(I-2)-W2)
      IF ( ZERO(W7+1) )  GO TO 38                                       13490   
      X(IAUS) = W7*W2/(1+W7)
      GO TO 39
C
  32  X(IAUS) = W5 + T - X(I-2)
      GO TO 39
C
  33  W7 = W6-W3
      IF ( ZERO(W7) )  GO TO 38
      X(IAUS) = W2 + 1/W7
C                                                                       13500   
C     SECOND TEST FOR LOSS OF SIGNIFICANCE
C
      IF ( APXABS(X(IAUS)) .GE. 1.D-10*APXABS(W2) )  GO TO 37
      IF ( NONZER(X(IAUS)) )  GO TO 36
C
C
  37  IF ( DREAL(W2) .NE. BIG )  GO TO 39
  38  X(IAUS) = BIG
      IMIN = I
C                                                                       13510   
  39  W1 = W4
      T = W2
      W2 = W5
      W3 = W6
      ISW1 = ISW2
  40  ISW2 = .FALSE.
C     ALL DONE LOOPING
C
C
      N = N-IMIN                                                        13520   
      GO TO 41
  36  N = IAUS-1
      GO TO 41
      END
C*ID* FFACST   C109.PTOLEMY.SOURCE                          PER701  18:
      SUBROUTINE FFACST ( IRTN )
C
C     GETS THE COULOMB BORN S MATRIX ELEMENTS FOR C.C.
C
C     THE COULOMB FF2 INTEGRALS ARE EVALUATED FOR ALL CHANNELS          13530   
C     WITH FIRST-ORDER COULOMB COUPLING TO THE GROUND STATE.
C     THESE ARE THEN CONVERTED TO THE REAL OR IMAGINARY PART
C     OF THE BORN S-MATRIX:
C
C     S(BORN) = I**(LX-1) X(1) SQRT((2LX+1)/4PI) *
C               |CLEBSCH( LOUT, LX, 0, 0; LIN, 0 )| *
C               2MU/HBAR**2 * 6*ZP*ZT*ALPHA*HBARC/SQRT(KIN*KOUT) *
C               INTEGRAL( F(IN) F(OUT) / R**(LX+1) )
C
C     THE SIGN OF THE I**(LX-1) FACTOR IS INCLUDED; ALL THAT            13540   
C     IS LEFT TO DETERMIN IS WETHER S IS REAL (LX ODD) OR
C     IMAGINARY (LX EVEN).
C
C     3/21/80 - FIRST VERSION - S.P.
C     7/4/80 - USE MXLXGS INSTEAD OF LXMAX - S.P.
C     8/11/80 - CALL SETLOG - S.P.
C     9/25/80 - TOTAL NMFFAC NOW FOUND BY GENBNX
C     7/12/81 - STORE DIFFERENCES IN DELTASR, DELTASI - S.P.
C     3/8/82 - FIX DIMENSION BUGS FOR LXMAX = 1, 0 - S.P.
C                                                                       13550   
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      COMMON /GRIDCM/  RCUEFF, GRDCM1(2),                               /gridcmf
     &  IBINDX, MBINDX, NBINDX, NMFFAC, MXLXGS, NMBFAC,
     & IINHR, IINHI, IRHSR, IRHSI,
     &  INUCH, ICOULH, ILOR, ILOI, ILIR, ILII,
     &  NPTMIN, NOFLO, NUMPT, NCRIT,
     & ISMX, ISMSQ, IPADE, IHOMO,
     &  ISMTSV, IRPTS4, IRPTS,
     &  IGRDC4(5), IDW, IGRDC5(2),
     &  IABS1, IGRDC6(2), GRDCM2, IGRDC7(2), IRWTS,
     &  IGRDC8(2), ICL1FF, ICL1FG, ICL1GF, ICL1GG
 
      COMMON /KANDM/ AKI, AKO, REDMI, REDMO, RIMAX, ROMAX, ISIGS(2),    /kandm/
     &  RSCTS(2), ASCTS(2), RCSCTS(2) ,ISMATS(2), LOMOST, LCRIT,
     &  ISCTMN, ISCTCR, ETAS(2), RCSCTP(2), RCSCTT(2), LCRITS(2),
     &  RATMSS(2), QMIN, ABAR
 
      DIMENSION  AKS(2), REDMS(2), RMAXS(2)
      EQUIVALENCE ( AKI, AKS(1) ), ( REDMI, REDMS(1) ),
     &  ( RIMAX, RMAXS(1) )
 
c                                                                       /formf/
c ***  LNKADB was  numLINKULES but only 12 are used ???
c
      COMMON /FORMF/  IBDS(2), NPOTS(2), LBP, LBT, NBP, NBT, JBP, JBT,
     &  BNDMAX(2), BNDSTP(2), NSTPBD(2), RBNDS(2), ABNDS(2),
     &  RCBNDS(2), BNDMAS(2), BRATMS(2), RSOBDS(2), ASOBDS(2),
     &  VBNDS(2), VSOBDS(2), TAUBDS(2), LNKADB(6, 2, 12)
 
      DIMENSION R2S(4)
      EQUIVALENCE ( R2S(1), RBNDS(1) )
C                                                                       13560   
      LOGICAL ONELSW, IDENSW                                            /inelcm/
      COMMON /INELCM/  JBPF, JBTF, LXMIN, LXMAX, ILILOR, ILILOI, MSTOP,
     &  IA12M, NMLOLX, ONELSW, NUMLX, IRDINT, IELCUP, LILOSZ, NUMLIS,
     &  ILIS, IBETAS(3), ICL2FF, LXSTEP, IDENSW, LSKIP,
     &  JPMIN, JPMAX, JPBASE, NJP, JTMIN, JTMAX, JTBASE, NJT,
     &  IINDXS, ISMATR, ISMATI, NSMAT, NLX, NSPLI, ITOCS,
     &  NASPLI, IUNITR, LIFIT, ILIFIT, NOLFIT, IDELSR, IDELSI
      INTEGER INDXJS(4,2)
      EQUIVALENCE ( INDXJS(1,1), JPMIN )
 
      COMMON /CCBLK/  ICHNDF, ICHNCP, ITRANS, IBASDF, IBASCP,           /ccblk/
     &    ICCBLK(2), IORDX, MCHNVL, ICHNVL,
     &    IHOMOA, IHOMOB, IINHR8, IINHI8
 
      CHARACTER*1  REACT, HEADER                                        /hedcom/
      COMMON /HEDCOM/  REACT(45), HEADER(65)
 
C
      IRTN = 1
      IF ( NMFFAC .EQ. 0 )  RETURN
      T1 = second()
      write (6, 3) REACT, HEADER
  3   FORMAT ( '1', T60, 'P T O L E M ' /
     1  T33, 'EVALUATION OF COULOMB BORN S-MATRIX ELEMENTS FOR',        13570   
     2     ' EXTRAPOLATION' /
     3  1X, 45A1, 22X, 65A1 )
C
      ICL2FF = NALLOC( (NMFFAC+1)/FACFR4, 'FF2INTS ' )
      CALL INIT4 ( ICL2FF, 0. )
      IDELSR = NALLOC( NASPLI*NUMLIS, 'DELTASR ' )
      IDELSI = NALLOC( NASPLI*NUMLIS, 'DELTASI ' )
C
      MAXDL1 = MAX0(2, MXLXGS)
      LDLDIM = MAXDL1 + 1                                               13580   
      LMXMX = LOMOST
      LMNMN1 = MAX0( LMIN-MAXDL1, 0 )
      IDIM1 = LDLDIM*(2*(LMXMX-LMNMN1)+1)
      IWRKFF = NALLOC( IDIM1, 'FFWORK  ' )
      IDIM2 = MAX0( LMXMX+MAXDL1, 4*MXCOUL ) + 1
      IWRKFI = NALLOC( 4*IDIM2, 'FIWORK  ' )
      IWRKWK = NALLOC( MAX0(2*NPCOUL+4*MXCOUL, 2*(LMXMX+MAXDL1)+1,
     1     2*NPCOUL+LMXMX+MAXDL1)+1, 'COULWORK' )
      IWRKST = NALLOC( 16*LDLDIM, 'COULSTRT' )
C                                                                       13590   
      CALL SETLOG ( 2*(LOMOST+MAXDL1) )
C
      LBASCP = FACFR4*(Z(IBASCP)-1) + 1
      MBASCP = ILLOC(LBASCP+1)
      LBASCP = LBASCP + ILLOC(LBASCP+2)
C
      LBASDF = FACFR4*(Z(IBASDF)-1) + 1
      MBASDF = ILLOC(LBASDF+1)
      LBASDF = LBASDF + ILLOC(LBASDF+2)
C                                                                       13600   
      LCHNDF = FACFR4*(Z(ICHNDF)-1) + 1
      MCHNDF = ILLOC(LCHNDF+1)
      LCHNDF = LCHNDF + ILLOC(LCHNDF+2)
C
      LBINDX = FACFR4*(Z(IBINDX)-1) + 1
      LCL2FF = FACFR4*(Z(ICL2FF)-1) + 1
      LSIG1 = Z(ISIGS(1))
      LSIG2 = Z(ISIGS(2))
C
C     MOVE COMPUTED S-MATRICES IN TO DELTA ARRAY                        13610   
C
      LDELSR = Z(IDELSR)
      LDELSI = Z(IDELSI)
      II = NASPLI*NUMLIS
      DO 159  I = 1, II
         ALLOC(LDELSR+I-1) = ALLOC(Z(ISMATR)+I-1)
         ALLOC(LDELSI+I-1) = ALLOC(Z(ISMATI)+I-1)
 159  CONTINUE
C
      CALL SETBFC ( NBINDX, MBINDX, ILLOC(LBINDX),                      13620   
     1  MCHNDF, ILLOC(LCHNDF), ALLOC4(LCHNDF), NUMJS, 2*LMIN,
     2  R2S, LMXMX, ALLOC(LSIG1), ALLOC(LSIG2),
     3  0.D0, .FALSE., 1, NMFFAC, ALLOC4(LCL2FF),
     4  ALLOC(Z(IWRKFF)), IDIM1, LDLDIM, ALLOC(Z(IWRKWK)),
     5  ALLOC(Z(IWRKFI)), IDIM2, ALLOC(Z(IWRKST)), IRET, CLTIME )
      IF ( IRET .NE. 0 )  GO TO 9960
C
      Z(IWRKFF) = -Z(IWRKFF)
      Z(IWRKFI) = -Z(IWRKFI)
      Z(IWRKWK) = -Z(IWRKWK)                                            13630   
      Z(IWRKST) = -Z(IWRKST)
C
      T2 = second()
C
C     NOW CONVERT FF2 INTS TO THE COMPLETE BORN S-MATRIX
C     AND SUBTRACT FROM C.C. VALUES
C
      CALL SETBRN ( NBINDX, MBINDX, ILLOC(LBINDX),
     1  MCHNDF, ILLOC(LCHNDF), MBASDF, ILLOC(LBASDF),
     2  MBASCP, ILLOC(LBASCP), ALLOC4(LBASCP),                          13640   
     3  NUMLIS, ALLOC(Z(ILIS)), 2*LMIN,
     4  ALLOC4(LCL2FF), ALLOC(Z(IINDXS)),
     5  ALLOC(LDELSR), ALLOC(LDELSI) )
C
      T3 = second()
      TTOT = T3-T1
      T3 = T3-T2
      T2 = T2-T1
      TRECUR = T2-CLTIME
      write (6, 383) CLTIME, TRECUR, T2, T3, TTOT                       13650   
 383  FORMAT ('-TIMES FOR COULOMB BORN S-MATRIX ELEMENTS',
     1    ' (SECONDS):' /
     2  ' BELLINGS:', T30, F9.3 /
     3  ' RECURSIONS:', T30, F9.3 /
     4  ' TOTAL COULOMB INTEGRALS:', T30, F18.3 /
     5  ' CLEBSCH FACTORS:', T30, F18.3 /
     6  ' TOTAL TIME:', T30, F27.3 )
C
      RETURN
C                                                                       13660   
 9960 write (6, 9963)
 9963 FORMAT ( ' **** ERROR IN SETBFC' )
      IRTN = 0
      RETURN
C
      END
C*ID* FITEL    C109.PTOLEMY.SOURCE                          PER701  12:
      SUBROUTINE FITEL(IRET)
C
C  ELASTIC FITTER - SETUP WORK AREA AND WAVELJ VALUES FOR FIT           13670   
C
C
C   THIS ROUTINE MAY CHANGE SOME VALUES IN TH E COMMON FLOAT
C   RI0,ELAB,E,ETC  MAY BE CHANGED
C
C
C     IFITER DETERMINS WHICH FITTER TO USE:
C      1 - POWELL65 - AMD ROUTINE VA02A
C      2 - ROCORD - THE MINROD VERSION OF PIEPER'S ROCORD.
C      3 - OCOPTR - FROM MINPACK.                                       13680   
C      4 - LMGENV - DLSMIN FROM MINPACK = VA05A OF HARWELL
C      5 - CHECKDERIV - CHECK THE SEMI-ANALYTIC DERIVATIVES - NO FIT.
C      6 - LMCHOL - LEAST SQUARES WITH ANALYTIC DERIVATIVES.
C      7 - MINIM - DAVIDON AND FLETCHER-DAVIDON FITTERS.
C      8 - QUAVER - STRAIGHT JTJ TYPE FITTER.
C      9 - DAVIDON - ORIGINAL AMD VERSION OF DAVIDON ( Z013S ).
C
C   8/17/75   FIRST VERSION   D.G.
C     10/1/75 - MERGE IN TO SEPT. PTOLEMY - S.P.
C     10/10/75 - USE MINROD INPLACE OF ROCORD                           13690   
C     10/12/75 - TABLE OF SIN/COS(SIGMA); ALLOW THINGS DEFINED AFTER FIT
C     10/15/75 - ENERGY DEPENDENT LMIN/LMAX AND STEPSIZE.
C     10/20/75 - MORE FITTERS ADDED
C     10/23/75 - MAXITE CHANGED TO MAXFUN
C     10/29/75 - WORK AREAS FOR GRADIENT CALCULATION
C     11/6/75 - SPLIT INTO TWO PIECES - FITEL AND FITEL2
C     12/28/75 - CHECK FOR UNDEFINED DATA
C     1/15/76 - ADD MINIM, QUAVER, DAVIDON
C     7/31/76 - DATA ARRAY IS ALL REAL*4
C     4/14/77 - EXPANDED DATA ARRAY; MAKE DATA STANDARD HERE            13700   
C     4/20/77 - RENORM AND SHIFT MAY BE FIT
C     4/26/77 - IDENTICAL PARTICLES
C     11/22/77 - CHANGES FOR NEW WAVSET, WAVPOT - S.P.
C     12/1/77 - SAVE STUFF FOR LINKULES; NEW LCRIT - S.P.
C     4/24/78 - REVERSE LOMOST FOR LIMOST - S.P.
C     5/4/79 - RATMAS, MASS EXCESS IN DATA - S.P.
C     12/27/79 - STANDARD MORTRAN - RPG
C     5/3/82 - ALLOW FOR ECM IN INPUT - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
C
C
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      COMMON /LENGTH/ LENG(1)
C
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      REAL*8  FLOAT(1)
      EQUIVALENCE  ( FLOAT(1), A )
C
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      parameter ( NUMJWORD = 12 )                                       /jblock/
      COMMON /JBLOCK/  J, JS(5),
     &  JP, JSP, JST,
     &  JPARM1, JPARM2, JPARM3
 
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
      COMMON / TEMPVS /  TVR, TVI, TVSOR, TVSOI, TAR, TAI               /tempvs/
 
      COMMON /KANDM/ AKI, AKO, REDMI, REDMO, RIMAX, ROMAX, ISIGS(2),    /kandm/
     &  RSCTS(2), ASCTS(2), RCSCTS(2) ,ISMATS(2), LOMOST, LCRIT,
     &  ISCTMN, ISCTCR, ETAS(2), RCSCTP(2), RCSCTT(2), LCRITS(2),
     &  RATMSS(2), QMIN, ABAR
 
      DIMENSION  AKS(2), REDMS(2), RMAXS(2)
      EQUIVALENCE ( AKI, AKS(1) ), ( REDMI, REDMS(1) ),
     &  ( RIMAX, RMAXS(1) )
 
      REAL*4  TBEGIN, TIMES                                             /ftimef/
      COMMON /FTIME/ TBEGIN, NUMLOP, NUMWAV, TIMES(6), NUMCAL, NUMGRA
 
      COMMON /LOCFIT/ IDATA, LPL, LSIGMA, LSMAT, IESETS, IMASK,         /locfit/
     &   IEQUAL, NPARA, IPARA, ITEMP, LSCSIG, LEPARM, LFS, NPTS, LEQNAM,
     &   MAXEQL, MAXVS, LVDERV, LSDELS, LDVTYP, LDSDP, LDFDX, LFGRAD,
     &   LTGRAD, LMASK, LEQUAL, MNDRIV, MXDRIV, IESIZE, LENPRE,
     &   LENKEY, LENHED,  ILNKBL
 
      REAL*4 T0                                                         /fitcom/
      COMMON /FITCOM/ T0, IP, IPL, IEPARM, IFS, MAXCAL,
     & NROC, ISCSIG
 
c                                                                       /lnkblk/
c  STRUCTURE OF   /LNKBLK/
c
c  THERE IS A BLOCK OF 3 DOUBLE WORDS FOR EACH POSSIBLE USE
c  OF A LINKULE.  THE NUMLNK = NUMLINKULES USES ARE IN THE ORDER
c    REALPOTEN  IMAGPOTEN  REALVSO  IMAGVSO  COULOMB
c    WAVEFUNCTION  AND 6 TENSOR POTENTIALS
c  THE THREE-DOUBLE-WORD BLOCKS EACH HAVE THE STRUCTURE
c
c    LNKNAM(1,I)   LINKULE NAME
c
c      LNKADR(3,I)   LINKULE ADDRESS, O IF NO LINKULE IN USE.
c      LNKADR(4,I)   0 - NO L OR J DEPENDENCE IN POTENTIAL
c                    1 - L DEPENDENCE BUT NO J DEPENDENCE
c                    2 - BOTH L  AND J DEPENDENCE
c
c      LNKADR(5&6,I)  MYINTS - A TWO-ELEMENT ARRAY THAT THE
c                     LINKULE MAY USE FOR COMMUNICATION BETWEEN
c                     CALLS TO ITSELF.
c
      parameter ( NUMLINKULES = 13 )
      COMMON /LNKBLK/  NUMLNK, IUNIQU, LNKADR(6,NUMLINKULES)
      character*8  LNKNAM(3,NUMLINKULES)
      EQUIVALENCE ( LNKNAM(1,1), LNKADR(1,1) )
 
C
      CHARACTER*1  REACT, HEADER                                        /hedcom/
      COMMON /HEDCOM/  REACT(45), HEADER(65)
 
C
      REAL*4 TTIMER
C
      CHARACTER*8  FITERS(14), STATWD(3), ANGLWD(2), SIGMWD(3), ERRWD(3)
      DATA FITERS / 'POWELL65', 'ROCORD', 'OCOPTR', 'LMGENV',
     1  'CHECKDER', 'LMCHOL', 'MINIM', 'QUAVER', 'DAVIDON',
     2  'FITTER10', 'FITTER11', 'FITTER12', 'FITTER13', 'FITTER14' /    13740   
C
      character*4  IBLANK / ' ' /
      LOGICAL  PRTSW, ERRSW, SIGMSW, ANGLSW
C
      DATA STATWD / 'BOSE', 'FERMI', 'NONE' /
      DATA  ANGLWD / 'C.M.', 'LAB.' /
      DATA  SIGMWD / '/RUTHER', 'C.M.(MB)', 'LAB.(MB)' /
      DATA  ERRWD  / ' MB', '  %', 'UNITS' /
c
C                                                                       13750   
      DO 1 I=1, 6
1     TIMES(I)=0
      NUMCAL = 0
      NUMGRA = 0
      NUMLOP = 0
      T0=second()
C
C
      IP=NAMLOC('PARAMETE')
      IF(IP.EQ.0)GO TO 900                                              13760   
      IDATA=NAMLOC('DATA    ')
      IF ( IDATA .EQ. 0 )  GO TO 902
      IEQUAL=NAMLOC('EQUAL   ')
      IMASK=NAMLOC('MASK    ')
C
      NPARA=LENG(IP)
C
      LDATA4 = FACFR4*(Z(IDATA)-1) + 1
      NPTS=ILLOC(LDATA4)
      IESETS=ILLOC(LDATA4+1)                                            13770   
      LENPRE = ILLOC(LDATA4+2)
      LENKEY = ILLOC(LDATA4+3)
      LENHED = ILLOC(LDATA4+4)
      IFS=NALLOC(NPTS,'EXPMINTH')
C
      MAXCAL = MAXFUN
      IF ( IREINI .NE. 0 )  MAXCAL = MIN0( MAXFUN,
     1  MAX0( (NPARA*IREINI)/3, 3*NPARA ) )
C
C  MAXITER KEYWORD NOW USED FOR FIRST ROCORD CALL                       13780   
C     WHEN FLETPOW IS TO FOLLOW
      NROC=MAXFUN
      IF(IREINI.NE.0)NROC=MAXITR
C
C
      WRITE(6,5)
5     FORMAT('1',T48,'P T O L E M Y')
      IWORDS=NAMLOC('FITWORDS')
      WRITE(6,6)(ALLOC(Z(IWORDS)+I-1),I=1,NPARA)
6     FORMAT(10X,' ELASTIC SCATTERING FIT',T75,'FITTING:', ( T85,6A8 ) )13790   
      write (6, 7) HEADER
 7    FORMAT ( 65X, 65A1 )
C
      write (6, 13) FITERS(IFITER)
 13   FORMAT ( / '0THE ', A8, ' MINIMIZER IS BEING USED.' / )
C
C     CHECK THAT ALL FIT PARAMETERS WERE INITIALIZED
C     AND INITIALIZE THE PARAMETER VECTOR
C
      LMASK = FACFR4*(Z(IMASK)-1)                                       13800   
      LDATA4 = FACFR4*(Z(IDATA)-1)+1
      DO 39  I = 1, NPARA
         KEY = ILLOC(LMASK+I)
         IF ( KEY .LT. 0 )  GO TO 25
         TEMP = FLOAT(KEY)
         GO TO 35
C     FITTING TO RENORM OR SHIFT
 25      ISET = MOD( -KEY/10000, 100 )
         KEY = -KEY/100 0000
         IF ( KEY .EQ. 1  .AND.  IFITER .GE. 5 )  GO TO 935             13810   
         IF ( ISET .GT. IESETS )  GO TO 930
         LEKEY = LDATA4 + LENPRE-1
         LEHED = LEKEY + LENKEY+1
         IDTSET = 1
 30      IF ( IDTSET .EQ. ISET )  GO TO 32
            IDTSET = IDTSET + 1
         LEKEY = LEKEY + LENKEY+LENHED + ILLOC(LEHED)*ILLOC(LEKEY+5)
         LEHED = LEKEY + LENKEY+1
         GO TO 30
 32      K = LEHED+2+KEY                                                13820   
         KEY = K-LDATA4 + 10000*(ISET +100*KEY)
         TEMP = ALLOC4(K)
         ILLOC(LMASK+I) = -KEY
C
 35      ALLOC(Z(IP)-1+I) = TEMP
         IF ( TEMP .EQ. UNDEF )  GO TO 914
 39   CONTINUE
C
C     INITIALIZE THE "=" ASSIGNMENTS TO THE FIRST GUY OF THE CHAIN
C                                                                       13830   
      LEQUAL = FACFR4*(Z(IEQUAL)-1) + 1
 40   IMANY = ILLOC(LEQUAL)
      IF ( IMANY .LE. 0 )  GO TO 100
      IMANY = IMANY + 1
      DO 59  I = 1, IMANY
         KEY = ILLOC(LEQUAL+I)
         IF ( KEY .GT. 0 )  GO TO 55
C     FITTING TO RENORM OR SHIFT
         ISET = MOD( -KEY/10000, 100 )
         KEY = -KEY/100 0000                                            13840   
         IF ( KEY .EQ. 1  .AND.  IFITER .GE. 5 )  GO TO 935
         IF ( ISET .GT. IESETS )  GO TO 930
         LEKEY = LDATA4 + LENPRE-1
         LEHED = LEKEY + LENKEY+1
         IDTSET = 1
 45      IF ( IDTSET .EQ. ISET )  GO TO 47
            IDTSET = IDTSET + 1
         LEKEY = LEKEY + LENKEY+LENHED + ILLOC(LEHED)*ILLOC(LEKEY+5)
         LEHED = LEKEY + LENKEY+1
         GO TO 45                                                       13850   
 47      K = LEHED+2+KEY
         KEY = K-LDATA4 + 10000*(ISET +100*KEY)
         ILLOC(LEQUAL+I) = -KEY
         IF ( I .EQ. 1 )  TEMP = ALLOC4(K)
         ALLOC4(K) = TEMP
         GO TO 59
C
 55      IF ( I .EQ. 1 )  TEMP = FLOAT(KEY)
         FLOAT(KEY) = TEMP
 59   CONTINUE                                                          13860   
C
      LEQUAL = LEQUAL + IMANY+ 1
      GO TO 40
C
C     INITIALIZE FOR WAVELJ
C
 100  ICHANW=1
      NUMFIT = IESETS
C
C     LOOP THROUGH THE DATA ARRAY.                                      13870   
C     ADD CHANNEL AND ELAB SPECIFICATIONS IF NOT THERE
C     CONVERT ELAB TO ECM
C
C     FIND THOSE PARAMETERS (LMIN, LMAX, STEPSIZE) THAT MIGHT DEPEND
C     ON ELAB.  THESE ARE NOW FOUND AND STORED FOR EACH ELAB.
C
C     WE STORE MOST MAXIMUM LMAX IN LOMOST;  AND MOST MAXIMUM NSTEP
C     IN NSTPSS(2).
C
      LOMOST = 0                                                        13880   
      NSTPSS(2) = 0
      LLMIN = LMIN
      LLMAX = LMAX
      IESIZE = 7 + 4/FACFR4
      IEPARM = NALLOC( IESIZE*IESETS, 'EPARAMS ' )
      ILNKBL = NALLOC( (3*NUMLNK*IESETS+FACFR4-1)/FACFR4, 'LNKBLKS ' )
      ICNT = LENPRE
      write (6, 113)
 113  FORMAT ('0  ELAB', 5X, 'ECM', 5X, 'LMIN', 3X, 'LMAX',
     1   5X, 'STEPSIZE',                                                13890   
     1   5X, 'ASYMPTOPIA', 4X, 'STATISTICS', 4X, 'CHANNEL'  / )
C
      DO 159  IOFFIT = 1, IESETS
         LEKEY = FACFR4*(Z(IDATA)-1) + ICNT
         LEHED = LEKEY + LENKEY+1
         TEMP = ALLOC4(LEHED+4)
         IF ( TEMP .EQ. UNDEF )  GO TO 115
         ELAB = UNDEF
         ECM = UNDEF
         IF ( ILLOC(LEHED+29) .EQ. 0 )  ELAB = TEMP                     13900   
         IF ( ILLOC(LEHED+29) .EQ. 1 )  ECM = TEMP
 115     IF ( ILLOC(LEHED+5) .NE. NOTDEF )  IZP = ILLOC(LEHED+5)
         ILLOC(LEHED+5) = IZP
         IF ( ILLOC(LEHED+6) .NE. NOTDEF )  IZT = ILLOC(LEHED+6)
         ILLOC(LEHED+6) = IZT
         IF ( ALLOC4(LEHED+7) .NE. UNDEF4 )  AMP = ALLOC4(LEHED+7)
         ALLOC4(LEHED+7) = AMP
         IF ( ALLOC4(LEHED+8) .NE. UNDEF4 )  AMT = ALLOC4(LEHED+8)
         ALLOC4(LEHED+8) = AMT
         IF ( ALLOC4(LEHED+25) .NE. UNDEF4) AMXGPT(1) = ALLOC4(LEHED+25)13910   
         ALLOC4(LEHED+25) = AMXGPT(1)
         IF ( ALLOC4(LEHED+26) .NE. UNDEF4) AMXGPT(2) = ALLOC4(LEHED+26)
         ALLOC4(LEHED+26) = AMXGPT(2)
         IF ( ALLOC4(LEHED+27) .NE. UNDEF4) EXSPT(1) = ALLOC4(LEHED+27)
         ALLOC4(LEHED+27) = EXSPT(1)
         IF ( ALLOC4(LEHED+28) .NE. UNDEF4) EXSPT(2) = ALLOC4(LEHED+28)
         ALLOC4(LEHED+28) = EXSPT(2)
         IF ( chlloc(4*(LEHED+9)-4+1) .NE. ' ' )  GO TO 120
         DO 119  I = 1, 44
            chlloc(4*(LEHED+9)-4+I) = REACT(I)                          13920   
 119     CONTINUE
C
C     IF THE REACTION HAD NOT BEEN READ, THE STATISTICS MAY NOT BE SET
C
         IF ( ILLOC(LEHED+20) .EQ. NOTDEF )  ILLOC(LEHED+20) = JSP
         IF ( ILLOC(LEHED+21) .EQ. NOTDEF )  ILLOC(LEHED+21) = JST
C
C     GET THE STUFF THAT SETCHN AND WAVSET NORMALLY GET
C     GET POTENTIAL PARAMETERS AT THIS ENERGY AND VERIFY THAT INITIAL
C     PARAMETER VECTOR IS LEGAL.                                        13930   
C     WE MUST FIND R0MASS, RCP, RCT, FOR EACH CHANNEL
C
 120     IF ( IOFFIT .NE. 1 )  CALL CLRCHN(21)
         JSP = ILLOC(LEHED+20)
         JST = ILLOC(LEHED+21)
         CALL SETCHN(6,IRET)
         IF(IRET.EQ.0)GO TO 910
         CALL SETPOT ( IRET )
         IF ( IRET .EQ. 0 )  GO TO 910
         CALL WAVSET(IRET, .TRUE., .TRUE. )                             13940   
         IF ( IRET .EQ. 0 )  GO TO 910
         LEKEY = FACFR4*(Z(IDATA)-1) + ICNT
         LEHED = LEKEY + LENKEY+1
         ALLOC4(LEHED+4) = ELAB
         ILLOC(LEHED+29) = 0
         ALLOC4(LEHED+24) = RATMAS
         IF ( ILLOC(LEHED+22) .NE. 0 )  GO TO 125
         ILLOC(LEHED+22) = LSKIPS(1)
         ILLOC(LEHED+23) = ISTATS(1)
C                                                                       13950   
C
C     IS AUTOMATIC LMIN/LMAX BEING USED
C
 125     LCRIT = LCRITS(1)
C
         IF ( LMIN .EQ. NOTDEF )
     1      LLMIN = MIN0( INT(LCRIT*ALMNMT), LCRIT-LMINSB )
         LLMIN = MAX0( LLMIN, 0 )
         IF ( LMAX .EQ. NOTDEF )
     1      LLMAX = MAX0( INT(LCRIT*ALMXMT), LCRIT+LMAXAD )             13960   
C
 130     LSKIP = ILLOC(LEHED+22)
         ISTAT = ILLOC(LEHED+23)
         IF ( LSKIP .EQ. 2 )  LLMIN = IABS( LLMIN - MOD(LLMIN,2) )
         IF ( LSKIP .EQ. 2 )  LLMAX = LLMAX + MOD(LLMAX,2)
C
         NSTEP = NSTPSS(1)
C
C     SHOW WHAT WE CHOSE
C                                                                       13970   
         write (6, 143) ELAB, ECM, LLMIN, LLMAX, STEPSZ, ASYMPS(1),
     1      STATWD(ISTAT), ( ILLOC(LEHED+I), I = 9, 19 )
 143     FORMAT ( 2F8.3, 2I7, F13.4, F15.2, 8X, A5, 6X, 11A4 )          cnd
CDC 143     FORMAT ( 2F8.3, 2I7, F13.4, F15.2, 8X, A5, 6X, 11A1 )
C
         IF ( ISTAT .NE. 3  .AND.  JSP .NE. 0 )  GO TO 940
C
C     WE STORE STUFF FOR EACH ENERGY AS FOLLOWS
C
C           IBM              CDC                                        13980   
C     LMIN    LMAX          LMIN
C     NSTEP     -           LMAX
C         STEPSIZE          NSTEP
C         ETA                 -
C         K                 STEPSIZE
C         E (C.M.)          ETA
C         R0MASS            K
C         RCP               E
C         RCT               R0MASS
C                           RCP                                         13990   
C                           RCT
C
C     IN THE IBM COLUMN, EACH LINE IS ONE 8-BYTE UNIT.
C
         LEPARM = Z(IEPARM) + IESIZE*IOFFIT - IESIZE - 1
         ILLOC(FACFR4*LEPARM+1) = LLMIN
         ILLOC(FACFR4*LEPARM+2) = LLMAX
         ILLOC(FACFR4*LEPARM+3) = NSTEP
CDC      LEPARM = LEPARM + 2
         ALLOC(LEPARM+3) = STEPSZ                                       14000   
         ALLOC(LEPARM+4) = ETAS(1)
         ALLOC(LEPARM+5) = AKS(1)
         ALLOC(LEPARM+6) = E
         ALLOC(LEPARM+7) = R0MASS
         ALLOC(LEPARM+8) = RCP
         ALLOC(LEPARM+9) = RCT
C
         LOMOST = MAX0( LOMOST, LLMAX )
         ICNT = ICNT + LENKEY+LENHED + ILLOC(LEHED)*ILLOC(LEKEY+5)
C                                                                       14010   
C     SAVE LINKULE STUFF
C
         LLNKBL = Z(ILNKBL)*FACFR4-FACFR4 + 3*NUMLNK*(IOFFIT-1) - 3
         DO 149  I = 1, NUMLNK
            DO 149  II = 1, 3
               ILLOC(LLNKBL+3*I+II) = LNKADR(3+II,I)
 149     CONTINUE
C
 159  CONTINUE
C                                                                       14020   
C  ALLOCATE PLM AND SIN/COS(SIGMA) SPACE
C
      IPL=NALLOC(LOMOST+1, 'PL      ' )
      ISCSIG = NALLOC( 2*IESETS*(LOMOST+1), 'SINCOSSG' )
C
C     LOOP OVER ALL ELABS AND GET COULOMB WAVEFUNCS AND SIGMAS
C
      DO 179  IOFFIT = 1, NUMFIT
         LEPARM = Z(IEPARM) - 1 + IESIZE*(IOFFIT-1)
         LLMAX = ILLOC(FACFR4*LEPARM+2)                                 14030   
         NSTPSS(1) = ILLOC(FACFR4*LEPARM+3)
CDC      LEPARM = LEPARM+2
         RSTEPS(1) = ALLOC(LEPARM+3)
         ETAS(1) = ALLOC(LEPARM+4)
         AKS(1) = ALLOC(LEPARM+5)
         HS(1)=AKS(1)*RSTEPS(1)
         ES(1) = ALLOC(LEPARM+6)
         CALL WAVPOT ( IRET )
         IF ( IRET .EQ. 0 )  GO TO 910
         LSIG = Z(ISIGS(1)) + (IOFFIT-1)*(LOMOST+1)                     14040   
         LSC = Z(ISCSIG) + (IOFFIT-1)*(LOMOST+1)*2
         IZERO = 0
         DO 169  LL = IZERO, LLMAX
            SIGMA = 2*ALLOC(LSIG+LL)
            ALLOC(LSC+2*LL) = DSIN(SIGMA)
            ALLOC(LSC+2*LL+1) = DCOS(SIGMA)
 169     CONTINUE
C
 179  CONTINUE
C                                                                       14050   
C     CONVERT DATA INTO STANDARD FORM OF
C        C.M. ANGLE,  C.M. SIGMA (MB),  % ERROR
C
      LEKEY = FACFR4*(Z(IDATA)-1) + LENPRE
C
      DO 499  IE = 1, IESETS
C
         LEHED = LEKEY + LENKEY+1
         LADATA = LEHED + LENHED
         LEPARM = Z(IEPARM) + IESIZE*(IE-1) - 1                         14060   
CDC         LEPARM = LEPARM + 2
         NPTSE = ILLOC(LEHED)
         ERRSW = ILLOC(LEKEY+1) .NE. 1
         SIGMSW = ILLOC(LEKEY+2) .NE. 1
         ANGLSW = ILLOC(LEKEY+4) .NE. 0
         LENDAT = ILLOC(LEKEY+5)
         PRTSW = ANGLSW .OR. ERRSW .OR.  ILLOC(LEKEY+2) .GE. 2
         IF ( .NOT. (PRTSW .OR. SIGMSW) )  GO TO 490
         PRTSW = PRTSW .AND. MOD(IPRINT/10 000, 10) .GE. 1
C                                                                       14070   
C     MUST DO A CONVERSION
C
         ELAB = ALLOC4(LEHED+4)
         RATMAS = ALLOC4(LEHED+7)/ALLOC4(LEHED+8)
         ETA = ALLOC(LEPARM+4)
         RUTHFC = 10 * (.5*ETA/ALLOC(LEPARM+5))**2
         ISTAT = ILLOC(LEHED+23)
         IERR = ILLOC(LEKEY+1) + 1
         ISIGM = ILLOC(LEKEY+2) + 1
         IANGL = ILLOC(LEKEY+4) + 1                                     14080   
C
         IF ( PRTSW )  write (6, 403) IE, ELAB, ANGLWD(IANGL),
     1      SIGMWD(ISIGM), ERRWD(IERR)
 403     FORMAT ( / '0CONVERSION OF DATA TO STANDARD FORM FOR',
     1      ' DATA SET', I3, ',  ELAB =', F6.1 /
     2  '0', 6X, '(ANGLESHIFT AND RENORMALIZATION NOT INCLUDED)' /
     3  '0', T14, 'INPUT VALUES', T57, 'STANDARD FORM' /
     4  2( 5X, 'ANGLE', 6X, 'SIGMA', 10X, 'ERROR', 9X ) /
     5  6X, A8, 1X, A8, 8X, A8, 12X, 'C.M.', 5X, '/RUTHER',
     6    9X, '  %' / )                                                 14090   
 407     FORMAT ( 2 ( F10.2, G15.4, G15.4, 5X ) )
C
         ILLOC(LEKEY+1) = 1
         ILLOC(LEKEY+2) = 1
         ILLOC(LEKEY+4) = 0
C
         DO 479  IANG = 1, NPTSE
            ANGLIN = ALLOC4(LADATA)
            ANGLE = ANGLIN*DEGREE
            ANGLOT = ANGLIN                                             14100   
            ERRIN = ALLOC4(LADATA+1)
            ERROT = ERRIN
            SIGMIN = ALLOC4(LADATA+2)
            SIGMOT = SIGMIN
C
            GO TO ( 430, 425 ), IANGL
C     CONVERT LAB ANGLE
 425        TEMP = 1 - (RATMAS*DSIN(ANGLE))**2
            IF ( TEMP .LT. 0 )  TEMP = 0
            TEMP = DSQRT(TEMP)                                          14110   
            IF ( ANGLE .LT. 0 )  TEMP = -TEMP
            ANGLE = ACOS( DCOS(ANGLE)*TEMP - RATMAS*DSIN(ANGLE)**2 )
            ANGLOT = RADIAN*ANGLE
C
 430        RUTH = 1
            IF ( ISTAT .NE. 3 )  RUTH = 1 + TAN(.5*ANGLE)**2 *
     1         ( TAN(.5*ANGLE)**2
     2           + 2*COS(2*ETA*DLOG(TAN(.5*ANGLE))) )
            RUTH = RUTHFC * RUTH/SIN(.5*ANGLE)**4
            IF ( RUTH .EQ. 0 )  RUTH = 1                                14120   
            GO TO ( 432, 440, 434 ), ISIGM
C     SIG/RUTH
 432        SIGMOT = RUTH*SIGMIN
            GO TO 440
C     LAB SIGMA
 434        TEMP = 1 + RATMAS*(RATMAS + 2*DCOS(ANGLE))
            AJACOB = (1+RATMAS*DCOS(ANGLE)) / (TEMP*DSQRT(TEMP))
            SIGMOT = AJACOB*SIGMIN
C
 440        GO TO ( 442, 450, 444 ), IERR                               14130   
C     MB ERROR
 442        ERROT = 100*ERRIN/SIGMOT
            IF ( ISIGM .EQ. 3 )  ERROT = ERROT*AJACOB
            GO TO 450
C     SAME UNITS AS SIGMA
 444        ERROT = 100*ERRIN/SIGMIN
C
 450  CONTINUE
C
            RUTH = SIGMOT/RUTH                                          14140   
            IF ( PRTSW )  write (6, 407) ANGLIN, SIGMIN, ERRIN, ANGLOT,
     1         RUTH, ERROT
            ALLOC4(LADATA) = ANGLOT
            ALLOC4(LADATA+1) = ERROT
            ALLOC4(LADATA+2) = SIGMOT
C
            LADATA = LADATA + LENDAT
C
 479     CONTINUE
C                                                                       14150   
C     NEXT SET
C
 490     LEKEY = LEKEY + LENKEY+LENHED + NPTSE*LENDAT
 499  CONTINUE
C
      IRET = 1
C
      RETURN
C
900   WRITE(6,901)                                                      14160   
901   FORMAT ( '0**** PARAMETER VECTOR LOST')
      GO TO 990
 902  write (6, 903)
 903  FORMAT ( '0**** DATA MUST BE DEFINED FOR FIT' )
      GO TO 990
910   WRITE(6,911)
911   FORMAT ( '0**** ALL PARAMETERS MUST BE DEFINED BEFORE WE FIT')
      GO TO 990
 914  write (6, 915)
 915  FORMAT ( '0**** ALL FIT PARAMETERS MUST BE INITIALIZED.' )        14170   
      GO TO 990
C
C
 930  write (6, 933) ISET, IESETS
 933  FORMAT ( '0*** ERROR:  ATTEMPTING TO FIT RENORM OR ANGLE',
     1  ' SHIFT FOR DATA SET', I3, ' BUT THERE ARE ONLY',
     2  I3, ' DATA SETS' )
      GO TO 990
 935  write (6, 937)
 937  FORMAT ( '0*** CANNOT VARY LAB ANGLE SHIFT WITH A MINIMIZER',     14180   
     1  ' THAT REQUIRES DERIVATIVES -' /
     2  '     USE POWELL65 OR ROCORD.' )
      GO TO 990
C
 940  write (6, 943)
 943  FORMAT ( ' **** ERROR:  FOR NOW WE CAN FIT ONLY SPIN 0',
     1  ' IDENTICAL PARTICLES.' )
      GO TO 990
C
 990  IRET = 0                                                          14190   
      RETURN
      END
C*ID* FITEL2   C109.PTOLEMY.SOURCE                          PER701  11:
      SUBROUTINE FITEL2 (IRET)
C
C  ELASTIC FITTER - SELECT METHOD OF FITTING AND DO IT
C
C
C   THIS ROUTINE MAY CHANGE SOME VALUES IN TH E COMMON FLOAT
C   RI0,ELAB,E,ETC  MAY BE CHANGED                                      14200   
C
C
C     IFITER DETERMINS WHICH FITTER TO USE:
C      1 - POWELL65 - AMD ROUTINE VA02A
C      2 - ROCORD - THE MINROD VERSION OF PIEPER'S ROCORD.
C      3 - OCOPTR - FROM MINPACK.
C      4 - LMGENV - DLSMIN FROM MINPACK = VA05A OF HARWELL
C      5 - DERIVCHECK - CHECK THE SEMI-ANALYTIC DERIVATIVES - NO FIT.
C      6 - LMCHOL - LEAST SQUARES WITH ANALYTIC DERIVATIVES.
C      7 - MINIM : DAVIDON FITTER                                       14210   
C      8 - QUAVER - JTJ TYPE FIT WITH OPTIONAL LINEAR SEARCH
C      9 - DAVIDON - AMD VERSION OF DAVIDON  ( Z013S = VMMIN )
C
C     THE FOLLOWING ARE KEYWORDS FOR THE FITTERS:
C
C     KEYWORD (COMMON NAME) (DEFAULT VALUE)
C
C     FITACCURACY (FITACC) (.001) - FOR ALL FITTERS THIS IS THE
C          RELATIVE ACCURACY WITH WHICH EACH PARAMETER IS TO BE FOUND.
C          DERIVCHECK: THE STEPSIZE FOR THE NUMERICAL DERIVATIVES       14220   
C
C     FITMULTIPLE (FITMUL) (500)
C        VA02A - MAXIMUM RELATIVE STEP ALLOWED IS FITMUL*FITACC
C        OCOPTR - (FL0) SHOULD BE ABOUT 3.
C        LMGENV -
C        MINIM, QUAVER - STEP IS REDUCED BY FITMUL WHEN IT RESULTS
C            IN A LARGER FUNCTION VALUE.  ALSO THE SIGN AND MAGNITUDE
C            DETERMIN THE METHOD OF FITTING.  IF > 100, 5 IS USED.
C        VMMIN - IF 0 OR >100, JTJ IS USED AS INITIAL METRIC; ELSE
C            FITMUL*(UNIT MAT) IS THE INITIAL METRIC.                   14230   
C
C     FITRATIO (FITRAT) (.0001) -
C        OCOPTR - ABSOLUTE STEPSIZE FOR GRADIENT CALCULATIONS
C        LMGENV - STEP SIZE FOR INITIAL NUMERIC DERIVATIVES.
C        QUAVER - RATIO OF MINIMUM USED SINGULAR VALUE TO THE LARGEST
C            SINGULAR VALUE.
C
C     FITMODE (MODEFT) (1) -
C        LMCHOL - DETERMINS HOW THE MARQUEDT SCALLING ARRAY IS CHOSEN.
C        ROCORD - INITIAL VALUE OF IRET                                 14240   
C        SECDER - 1 MEANS FIRST DERIV CHECK, 2 IS 2ND DERIV.
C
C     NUMRANDOM (NUMRAN) (0)
C        ROCORD AND VMMIN - NUMBER OF RANDOM STEPS USED TO COMFIRM MINIM
C
C     DERIVSTEP (DERIVS) (1E-6) - FOR ALL FITTERS THAT REQUIRE GRADIENTS
C        THIS IS THE RELATIVE STEP USED IN COMPUTING THE GRADIENT
C        OF THE POTENTIALS.
C
C                                                                       14250   
C
C   8/17/75   FIRST VERSION   D.G.
C     10/1/75 - MERGE IN TO SEPT. PTOLEMY - S.P.
C     10/10/75 - USE MINROD INPLACE OF ROCORD
C     10/12/75 - TABLE OF SIN/COS(SIGMA); ALLOW THINGS DEFINED AFTER FIT
C     10/15/75 - ENERGY DEPENDENT LMIN/LMAX AND STEPSIZE.
C     10/20/75 - MORE FITTERS ADDED
C     10/23/75 - MAXITE CHANGED TO MAXFUN
C     10/29/75 - WORK AREAS FOR GRADIENT CALCULATION
C     2/14/78 - NUMERICAL DERIVATIVES (KEY >= 4)                        14260   
C     11/6/75 - SPLIT INTO TWO PIECES - FITEL AND FITEL2
C     12/28/75 - ADD PRTDER CALL
C     1/5/76 - ADD MINIM
C     1/8/76 - ADD QUAVER
C     1/14/76 - ADD VMMIN = AMD VERSION OF DAVIDON
C     1/22/76 - CHANGES TO VA02A
C     1/29/76 - DERIVCHECK CHANGES
C     7/31/76 - REMOVE SOME FITTERS.
C     4/20/77 - RENORM AND SHIFT MAY BE FIT
C     2/78 - NUMERIC DERIVATIVES FOR NON-POTENTIAL PARAMS - S.P.        14270   
C     4/7/78 - SAVE COVARIEANCE EIGENVALS AND VECS - S.P.
C     4/24/78 - REVERSE LOMOST FOR LIMOST - S.P.
C     6/12/79 - CMS VERSION DOES NOT HAVE MINROD - S.P.
C     12/27/79 - CFR%F - RPG
C     4/3/81 - REMOVE ROCORD - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
C
      LOGICAL ALONSW/.TRUE./
C                                                                       14280   
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
C
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      parameter ( NUMJWORD = 12 )                                       /jblock/
      COMMON /JBLOCK/  J, JS(5),
     &  JP, JSP, JST,
     &  JPARM1, JPARM2, JPARM3
 
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
      COMMON /KANDM/ AKI, AKO, REDMI, REDMO, RIMAX, ROMAX, ISIGS(2),    /kandm/
     &  RSCTS(2), ASCTS(2), RCSCTS(2) ,ISMATS(2), LOMOST, LCRIT,
     &  ISCTMN, ISCTCR, ETAS(2), RCSCTP(2), RCSCTT(2), LCRITS(2),
     &  RATMSS(2), QMIN, ABAR
 
      DIMENSION  AKS(2), REDMS(2), RMAXS(2)
      EQUIVALENCE ( AKI, AKS(1) ), ( REDMI, REDMS(1) ),
     &  ( RIMAX, RMAXS(1) )
 
      REAL*4  TBEGIN, TIMES                                             /ftimef/
      COMMON /FTIME/ TBEGIN, NUMLOP, NUMWAV, TIMES(6), NUMCAL, NUMGRA
 
      COMMON /LOCFIT/ IDATA, LPL, LSIGMA, LSMAT, IESETS, IMASK,         /locfit/
     &   IEQUAL, NPARA, IPARA, ITEMP, LSCSIG, LEPARM, LFS, NPTS, LEQNAM,
     &   MAXEQL, MAXVS, LVDERV, LSDELS, LDVTYP, LDSDP, LDFDX, LFGRAD,
     &   LTGRAD, LMASK, LEQUAL, MNDRIV, MXDRIV, IESIZE, LENPRE,
     &   LENKEY, LENHED,  ILNKBL
 
      REAL*4 T0                                                         /fitcom/
      COMMON /FITCOM/ T0, IP, IPL, IEPARM, IFS, MAXCAL,
     & NROC, ISCSIG
 
      CHARACTER*1  REACT, HEADER                                        /hedcom/
      COMMON /HEDCOM/  REACT(45), HEADER(65)
 
C
C     FOLLOWING ARE THE FUNCTION ROUTINES FOR OCOPTR AND LMGENV
C
CXX      EXTERNAL  OCOFCN, DLSFCN
      EXTERNAL LMCFUN
      EXTERNAL MINMON                                                   14300   
C
      REAL*4 T1
C
      LOGICAL GRADSW, HESNSW
C
c
C
      IPRT = MOD(IPRINT, 10)
C
C                                                                       14310   
C     ALLOCATE THE WORK AREAS SPECIFIC TO EACH FITTER
C
      GRADSW = .FALSE.
      HESNSW = .FALSE.
      GO TO ( 220, 240, 300, 350, 375, 400, 425, 425, 425 ) , IFITER
C
C     ALLOCATE WORK AREA ( W )  FOR POWELL65
C
 220  I = (NPARA+1)*(NPTS+NPARA+1) + ((NPARA+1)*NPARA)/2
      IWORK = NALLOC( I, 'POWELL  ' )                                   14320   
      GO TO 490
C
CXXC     ALLOCATE AREAS FOR ROCORD/MINROD
CXXC
CXX 240  IUP=NAMLOC('UPPERB  ')
CXX      IF(IUP.NE.0)GO TO 260
CXX      IUP=NALLOC(NPARA,'UPPERB  ')
CXXC
CXXC  DEFAULT UPPER BOUND
CXXC                                                                    14330   
CXX      DO 249 I=1,NPARA
CXX         TEMP = 100*DABS( ALLOC(Z(IP)-1+I) )
CXX         IF ( TEMP .EQ. 0 )  TEMP = 1
CXX         ALLOC(Z(IUP)-1+I) = TEMP
CXX 249  CONTINUE
CXX 260  IDO=NAMLOC('LOWERB  ')
CXX      IF(IDO.NE.0)GO TO 280
CXX      IDO=NALLOC(NPARA,'LOWERB  ')
CXXC
CXXC  DEFALUT LOWER BOUND                                               14340   
CXXC
CXX      DO 269 I=1,NPARA
CXX 269  ALLOC(Z(IDO)+I-1) = -ALLOC(Z(IUP)-1+I)
CXXC
CXXC     FOR NOW WE DO NOT PUT THE ROBLK INTO THE ALLOCATOR
CXXC
CXX 280  IWORK = 0
CXX      IF ( IREINI .NE. 0 )  GO TO 220
CXX      GO TO 500
 240  GO TO 300                                                         14350   
C
C
CXXC     WORK AREAS FOR  OCOPTR
CXXC
CXX 300  IX0 = NALLOC( NPARA, 'OCOPTRX0' )
CXX      IWORK = NALLOC( NPARA**2, 'OCOPTR ' )
CXX      LWORK = Z(IWORK) - 1
CXX      IPARA = Z(IP)-1
CXX      DO 329  I = 1, NPARA
CXX         DO 325  II = 1, NPARA                                       14360   
CXX            ALLOC(LWORK+(I-1)*NPARA+II) = 0
CXX 325     CONTINUE
CXX         TEMP = DSQRT( DABS(ALLOC(IPARA+I)) )
CXX         IF ( TEMP .EQ. 0 )  TEMP = FITACC
CXX         ALLOC(LWORK+(I-1)*NPARA+I) = TEMP
CXX 329  CONTINUE
CXX      GO TO 500
CXXC
CXXC     WORK AREAS FOR LMGENV
CXXC                                                                    14370   
CXX 350  I = 2*NPTS*(NPARA+1) + NPARA*(2*NPARA+5)
CXX      IWORK = NALLOC( I, 'DLSMIN ' )
CXX      GO TO 500
C
C     DERIVCHECK CHECKS THE SEMI-ANALYTIC DERIVATIVES
C     OR IT COMPUTES THE COMPLETE SECOND DERIVATIVE MATRIX
C
 375  I = NPARA*( 2*NPARA + 2*NPTS + 1 ) + NPTS
      IWORK = NALLOC( I, 'DERIVCHE' )
      GO TO 475                                                         14380   
 300  write (6, 303)
 303  FORMAT ( '0**** THE CHOSEN FITTER IS NOT AVAILABLE IN',
     1  ' THIS VERSION OF PTOLEMY.' )
      IRET = 0
      RETURN
 350  GO TO 300
C
C     LMCHOL - A LEAST SQUARES FITTER WITH DERIVATIVES
C
 400  I = NPTS + 4*NPARA                                                14390   
      IWORK = NALLOC( I, 'LMCHOL  ' )
      GO TO 475
C
C     MINIM - DAVIDON-FLETCHER TYPE FITTER; QUAVER - JTJ;
C     VMMIN - ORIGINAL DAVIDON
C
 425  I = 6*NPARA
      IWORK = NALLOC( I, 'DAVIDON ' )
      GO TO 475
C                                                                       14400   
C     THE FITTER WILL WANT ANALYTIC DERIVATIVES - GET WORK AREAS
C
 475  IDVTYP = NAMLOC('DERIVTYP')
      IF ( IDVTYP .EQ. 0 )  GO TO 900
      GRADSW = .TRUE.
C
C     HOW MANY "RAW" DERIVATIVES WILL WE COMPUTE
C
      MAXVS = 0
      DO 479  I = 1, NPARA                                              14410   
         KEY = ILLOC(FACFR4*Z(IDVTYP)-FACFR4+I)
         IF ( KEY .LT. 4 )  MAXVS = MAXVS + (KEY+1)/2
 479  CONTINUE
      MAXVS = MAX0( MAXVS, 1 )
C
      IVDERV = NALLOC( MAXVS*(NSTPSS(2)+1), 'VDERIV  ' )
      ISDELS = NALLOC( 4*NPARA, 'DSDXK   ' )
      IDSDP = NALLOC( 2*NPARA*(LOMOST+1), 'DSDP    ' )
      IDFDX = NALLOC( 2*NPARA, 'DFDX    ' )
      IFGRAD = NALLOC( NPARA*NPTS, 'FGRADS   ' )                        14420   
      ITGRAD = NALLOC( NPARA, 'TGRAD   ' )
C
 490  IGNVAL = NALLOC( NPARA, 'CHIGNVAL' )
      IGNVEC = NALLOC( NPARA**2, 'CHIGNVEC' )
C
      LGNVAL = Z(IGNVAL)
      LGNVEC = Z(IGNVEC)
      IF ( IFITER .EQ. 1 )  GO TO 500
C
      LVDERV = Z(IVDERV)                                                14430   
      LSDELS = Z(ISDELS)
      LDSDP = Z(IDSDP)
      LDFDX = Z(IDFDX)
      LFGRAD = Z(IFGRAD)
      LTGRAD = Z(ITGRAD)
      LDVTYP = FACFR4*Z(IDVTYP) - FACFR4
C
C  NO ALLOCATIONS EXPECTED BEFORE FITTING IS OVER
C  ---  SO FILL IN FITCOM
C                                                                       14440   
 500  IPARA=Z(IP)
      LEQUAL = FACFR4*(Z(IEQUAL)-1) + 1
      LMASK = FACFR4*(Z(IMASK)-1) + 1
      LPL=Z(IPL)
      IDATA = FACFR4*(Z(IDATA)-1) + 1
      LSIGMA=Z(ISIGS(1))
      LSMAT=Z(ISMATS(1))
      LSCSIG = Z(ISCSIG)
      LWORK = Z(IWORK)
      LEPARM = Z(IEPARM) - 1                                            14450   
      LFS = Z(IFS)
      LEQNAM = Z(NAMLOC('EQUALNAM'))
      MAXEQL = ILLOC(FACFR4*(LEQNAM-1)+1)
C
C  PRINT INITIAL GUESS -  THIS IN NOW AUTOMATIC
C
      T1=second()
      ITEMP=1
      IF ( IPRT .NE. 0 )  xxxx = calfun ( NPTS, NPARA, ALLOC(LFS),
     1  ALLOC(IPARA) )                                                  14460   
      ITEMP=2
C
C
C     USE DESIRED FITTER
C
 505  GO TO ( 510, 600, 650, 675, 700, 725, 750, 750, 750 ) , IFITER
C
C     POWELL 1965 FITTER ( VA02A )
C
C                                                                       14470   
 510  CALL VA02A(NPTS, NPARA, ALLOC(LFS), ALLOC(IPARA), FITACC,
     1  1.D-12, FITMUL, IPRT, MAXCAL, IRTN,  ALLOC(LWORK) )
C
C
C     THIS TERMINATION ROUTINE IS USED BY ALL THE FITTERS
C     HOW DID IT STOP0
C
 520  IF ( IRTN .EQ. 0 )  GO TO 530
      IF ( IRTN .NE. 1 )  GO TO 538
C                                                                       14480   
C     WE COME HERE WHEN WE HAVE RUN OUT OF FUNCTION REFS AND MAY
C     BE ABOUT TO REINITIALIZE THE FITTER AGAIN.
C
      IF ( IREINI .EQ. 0 )  GO TO 535
      IF ( NUMCAL .GE. MAXFUN )  GO TO 535
      GO TO 505
C
 530  write (6, 531)
 531  FORMAT(/'     FIT COMPLETE.  FINAL RESULTS FOLLOW')
      GO TO 540                                                         14490   
 535  write (6, 533)
 533  FORMAT( '0**** NOT ENOUGH  ITERATIONS TO ACHIEVE A GOOD FIT -  -',
     1  '  - WHAT YOU GOT :')
      GO TO 540
 538  write (6, 539) IRTN
 539  FORMAT ('0**** ABNORMAL TERMINATION OF THE FITTER - RETURN CODE ='
     1  , I12 /
     2  '0 SITUATION AT TERMINATION -' )
C
 540  IF ( IFITER .NE. 1 )  GO TO 545                                   14500   
C
C     FOR POWELL65 GET THE METRIC MATRIX
C
      CALL SV01A(NPTS,NPARA,ALLOC(LGNVEC),NPARA,2, ALLOC(LWORK) )
      HESNSW = .TRUE.
      LTGRAD = LWORK + NPARA
C
C     HAVE CALFUN PRINT THE FINAL FIT
C
 545  ITEMP=3                                                           14510   
      xxxx = calfun(NPTS,NPARA,ALLOC(LFS),ALLOC(IPARA))
C
C
C     IF AVAILABLE, PRINT GRADIENT AND/OR COVARIANCE MATRIX
C     ALSO PRINT FIT TIMES
C
      IF ( IPRT .EQ. 0 )  GO TO 800
      CALL PRTDER ( ALLOC(IPARA),
     1  GRADSW, ALLOC(LTGRAD), HESNSW, ALLOC(LGNVEC), ALLOC(LGNVAL),
     2  NPARA, T1 )                                                     14520   
C
      GO TO 800
C
C
CXXC  THIS SECTION FOR ROCORD/MINROD
CXXC
CXX600   IRET=-1021
CXX      IF(MODEFT.NE.1)IRET=MODEFT
CXX      CALL MINROD ( ALLOC(IPARA), F, ALLOC(Z(IDO)), ALLOC(Z(IUP)),
CXX     1  NPARA, NUMRAN, FITACC/200., NROC, IRET )                     14530   
CXX630   xxxx = calfun(NPTS,NPARA,ALLOC(LFS),ALLOC(IPARA))
CXX      F=0
CXX      DO 639 I=1,NPTS
CXX639   F=F+ALLOC(Z(IFS)+I-1)**2
CXX      CALL MINEXT(F,IRET)
CXX      GO TO ( 630, 630, 530, 640 ), IRET
CXX      GO TO 538
CXXC
CXXC  IF ROCORD SPECIFIED AND REINTIALIZE ALSO SPECIFIED  THEN CALL
CXXC        FLETPOW AFTER FIRST ITERATION                               14540   
CXX 640  I = 5
CXX      CALL MINEXT ( F, I )
CXX      IF(IREINI.EQ.0)GO TO 535
CXX      IFITER=1
CXX      GO TO 510
 600  GO TO 300
C
C
CXXC     OCOPTR
CXXC                                                                    14550   
CXX 650  EPS = FITACC**2
CXX      CALL OCOPTR ( NPARA, NPARA, NPARA, ALLOC(IPARA), DUMMY,
CXX     1  ALLOC(Z(IX0)), F0, OCOFCN, I, ALLOC(LWORK),
CXX     2  MAXFUN, IRET, EPS, FITRAT, FITMUL, 0.D0, IPRT-1 )
CXX      IF ( IRTN .EQ. 1 )  GO TO 530
CXX      IF ( IRTN .EQ. 0 )  GO TO 535
CXX      GO TO 538
CXXC
CXXC     LMGENV  (DLSMIN)
CXXC                                                                    14560   
CXX 675  I = MAXCAL
CXX      CALL DLSMIN ( NPARA, NPTS, ALLOC(IPARA), FITMUL, FITACC,
CXX     1  I, DLSFCN, IRTN, ALLOC(LFS), ALLOC(LWORK), MINMON, IPRT,
CXX     2  FITRAT, 1.D-15 )
CXX      GO TO 520
 650  CONTINUE
 675  GO TO 300
C
C     CHECKDERIVATIVE
C                                                                       14570   
 700  L3 = LWORK + NPTS
      L4 = L3 + NPARA**2
      L5 = L4 + NPARA**2
      L6 = L5 + NPARA*NPTS
      L8 = L6 + NPARA*NPTS
C
C
      CALL SECDER ( MODEFT, NPARA, NPTS, FITACC, ALLOC(IPARA),
     1  ALLOC(LFS), ALLOC(LFGRAD), ALLOC(LTGRAD), ALLOC(LWORK),
     2  ALLOC(LGNVEC), ALLOC(L3), ALLOC(L4), ALLOC(L5),                 14580   
     3  ALLOC(L6), ALLOC(LGNVAL), ALLOC(L8) )
      GO TO 800
C
C     LMCHOL
C
 725  L3 = LWORK
      L4 = L3 + NPARA
      L5 = L4 + NPARA
      L6 = L5 + NPARA
      L7 = L6 + NPARA                                                   14590   
      IPRT = MIN0( IPRT, 1 )
C
      CALL LMCHOL ( NPARA, NPTS, ALLOC(IPARA), MODEFT, MAXCAL,
     1  ALLOC(LGNVAL), LMCFUN, FITACC, 1.D-12, ALLOC(LFS), ALLOC(LFGRAD)
     2  , ALLOC(LGNVEC), IRTN, I, II, ALLOC(L3), ALLOC(L4), ALLOC(L5),
     3  ALLOC(L6), ALLOC(L7), DUMMY, MINMON, IPRT )
C
      GO TO 760
C
C     MINIM - DAVIDON-FLETCHER                                          14600   
C     QUAVER - JTJ TYPE
C     VMMIN  - ORIGINAL AMD DAVIDON VARIABLE METRIC
C
 750  L2 = LWORK
      L3 = L2 + NPARA
      L4 = L3 + NPARA
      L5 = L4 + NPARA
      L6 = L5 + NPARA
      L7 = L6 + NPARA
      DMODE = 5                                                         14610   
      IF ( IFITER .EQ. 9 )  DMODE = 0
      IF ( FITMUL .LT. 100 )  DMODE = FITMUL
C
C
      IF ( IFITER .EQ. 8 )  GO TO 755
      IF ( IFITER .EQ. 9 )  GO TO 758
C
      CALL MINIM ( DMODE, FITACC, ALLOC(IPARA), ALLOC(LGNVAL),
     1  ALLOC(LTGRAD), ALLOC(L2), ALLOC(L3), ALLOC(L4), ALLOC(L5),
     2  ALLOC(L6),  ALLOC(L7), ALLOC(LGNVEC), ALLOC(LFS),               14620   
     3  ALLOC(LFGRAD), NPTS, NPARA, IPRT, MAXCAL, IRTN )
      GO TO 760
C
 755  CALL QUAVER ( DMODE, FITACC, FITRAT, ALLOC(IPARA), ALLOC(LGNVAL),
     1  ALLOC(LTGRAD), ALLOC(L2), ALLOC(L3), ALLOC(L4), ALLOC(L5),
     2  ALLOC(L6),  ALLOC(L7), ALLOC(LGNVEC), ALLOC(LFS),
     3  ALLOC(LFGRAD), NPTS, NPARA, IPRT, MAXCAL, IRTN )
      GO TO 760
C
 758  CALL VMMIN ( DMODE, FITACC, ALLOC(IPARA), ALLOC(LGNVAL),          14630   
     1  ALLOC(LTGRAD), ALLOC(L2), ALLOC(L3), ALLOC(L4), ALLOC(L5),
     2  ALLOC(L6),  ALLOC(L7), ALLOC(LGNVEC), ALLOC(LFS),
     3  ALLOC(LFGRAD), NPTS, NPARA, IPRT, NUMRAN, MAXCAL, IRTN )
C
 760  HESNSW = .TRUE.
      GO TO 520
C
C
C     ALL DONE WITH FITTING, CLEAN UP AND LEAVE
C                                                                       14640   
 800  IRET=1
      IF ( IWORK .NE. 0 )  Z(IWORK) = -Z(IWORK)
      Z(IFS) = -Z(IFS)
      Z(IPL) = -Z(IPL)
      Z(IEPARM) = -Z(IEPARM)
      Z(NFS(1)) = -Z(NFS(1))
      Z(NGS(1)) = -Z(NGS(1))
      Z(NF1S(1)) = -Z(NF1S(1))
      Z(NG1S(1)) = -Z(NG1S(1))
      Z(IRLVS(1)) = -Z(IRLVS(1))                                        14650   
      Z(IIMVS(1)) = -Z(IIMVS(1))
      Z(IWAVR) = -Z(IWAVR)
      Z(IWAVI) = -Z(IWAVI)
      Z(ISCSIG) = -Z(ISCSIG)
      Z(ISIGS(1)) = -Z(ISIGS(1))
      Z(ISMATS(1)) = -Z(ISMATS(1))
C
      IF ( .NOT. GRADSW )  GO TO 850
      Z(IVDERV) = -Z(IVDERV)
      Z(ISDELS) = -Z(ISDELS)                                            14660   
      Z(IDSDP) = -Z(IDSDP)
      Z(IDFDX) = -Z(IDFDX)
      Z(IFGRAD) = -Z(IFGRAD)
      Z(ITGRAD) = -Z(ITGRAD)
C
C
 850  RETURN
C
 900  write (6, 903)
 903  FORMAT ( '0**** INTERNAL ERROR:  DERIVTYP LOST' )                 14670   
      IRET = 0
      RETURN
      END
C*ID* FITINP   C109.PTOLEMY.SOURCE                          PER701  15:
      SUBROUTINE FITINP(IRET, NUMFLT, FLTWRD, NUMALI, ALIAI )
C
C  INPUT ROUTINE FOR FIT KEYWORD.
C  READS INPUT IN THE FOLLOWING FORMAT: (R0,RI0,A=AI,V,VI)  ETC.
C
C     EACH PARAMETER MAY BE FOLLOWED BY DERIV OR NODERIV TO             14680   
C     INDICATE WHETER THE DERIVATIVES MAY BE COMPUTED ANALYTICALLY
C     OR NOT.
C     IF THIS IS NOT DONE, THEN ONLY THE WORDS LISTED IN REALS AND
C     IMAGS BELOW WILL BE DONE ANALYTICALLY.
C
C  THIS VERSION 8/13/75  D.GLOECKNER
C     10/2/75 - EXPAND NAMLOC NAMES TO 8 CHARACTERS - S.P.
C     10/19/75 - USE THE FLTWRD ARRAY FROM CONTRL.
C     10/23/75 - MAKE AN ARRAY OF EQUAL NAMES FOR CALFUN TO PRINT
C     10/29/75 - STORE ARRAY INDICATING REAL OR IMAG NATURE OF PARAMETER14690   
C     4/13/77 - PROCESS AIASES
C     4/20/77 - RENORM AND SHIFT CAN BE FIT
C     2/14/78 - INDICATE NUMERIC DERIVS FOR UNKNOWNS - S.P.
C     3/26/78 - DERIV/NODERIV ADDED; MUNICH CHANGES - S.P.
C     12/27/79 - STANDARD MORTRAN - RPG
C     6/3/80 - DERIVS DATA REQUIRES TWO LINES - S.P.
C     6/24/80 - CHARACTER*8 STATEMENTS - S.P.
C
C
      implicit real*8 ( a-h, o-z )                                      implicit
C
      CHARACTER*8  FLTWRD(NUMFLT), ALIAI(NUMALI)
C
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      CHARACTER*8  CH8LOC(1)
      EQUIVALENCE ( CH8LOC(1), ALLOC(1) )
C
      DATA NUMREN / 22 /
      CHARACTER*8 RENWRD(22) / 'RENORM', 'RENORMAL',
     1  'RENORM1', 'RENORM2', 'RENORM3', 'RENORM4', 'RENORM5',          14710   
     2  'RENORM6', 'RENORM7', 'RENORM8', 'RENORM9', 'RENORM10',
     3  'RENORM11', 'RENORM12', 'RENORM13', 'RENORM14', 'RENORM15',
     4  'RENORM16', 'RENORM17', 'RENORM18', 'RENORM19', 'RENORM20' /
      CHARACTER*8 SHFWRD(22) / 'SHIFT', 'ANGLESHI',
     1  'SHIFT1', 'SHIFT2', 'SHIFT3', 'SHIFT4', 'SHIFT5',
     2  'SHIFT6', 'SHIFT7', 'SHIFT8', 'SHIFT9', 'SHIFT10',
     3  'SHIFT11', 'SHIFT12', 'SHIFT13', 'SHIFT14', 'SHIFT15',
     4  'SHIFT16', 'SHIFT17', 'SHIFT18', 'SHIFT19', 'SHIFT20' /
C
C  ADDITIONAL KEYWORDS                                                  14720   
C
      CHARACTER*8  DERIVS(4) / 'DERIV', 'DERIVATI', 'NODERIV',
     1  'NODERIVA' /
      CHARACTER*8 UP/'UPPERBOU'/,DOWN/'LOWERBOU'/
      CHARACTER*8 BLANK / ' ' /,  EQUAL / '  =  ' /
      CHARACTER*8  AKEY, AKEYP
C
C     THE FOLLOWING KEYWORDS AFFECT THE REAL PART OF THE POTENTIAL
C
      DATA NUMRL / 22 /                                                 14730   
      CHARACTER*8  REALS(22)  / 'A', 'ASO', 'TAU', 'R', 'R0', 'RC',
     1  'RC0', 'RSO', 'RSO0', 'V', 'VSO', 'R0E', 'AE', 'VE',
     2  'R0ESQ', 'AESQ', 'VESQ', 'RCP', 'RCT', 'RC0P', 'RC0T',
     3  'REALPOWE' /
C
C     THE FOLLOWING KEYWORDS AFFECT THE IMAGINARY PART OF THE POTENTIAL
C
      DATA NUMIM / 20 /
      CHARACTER*8  IMAGS(20)  / 'AI', 'ASOI', 'TAUI', 'RI', 'RI0',
     1  'RSOI', 'RSOI0', 'VI', 'VSOI', 'ASI', 'RSI', 'RSI0', 'VSI',     14740   
     2  'RI0E', 'AIE', 'VIE', 'RI0ESQ', 'AIESQ', 'VIESQ', 'IMAGPOWE' /
C
c
C
CUN      LOR(I,J) = OR(I,J)
CVX      LOR(I,J) = IOR(I,J)
C
C  TEMPORAY STORAGE FOR PARAMETER VECTOR
      IRET=0
      IWORD = NALLOC( NUMFLT, 'FITWORDS' )                              14750   
      ILONG=NUMFLT/FACFR4+1
      IMASK=NALLOC(ILONG,'MASK    ')
      IL=NALLOC(ILONG,'EQUAL   ')
      ITMPNM = NALLOC( NUMFLT, 'TMPEQNAM' )
      IDRSET = NALLOC(NUMFLT, 'TMPDERIV' )
      LTMPNM = Z(ITMPNM)
      IQ = FACFR4*(Z(IL)-1) + 1
      LMASK = FACFR4*(Z(IMASK)-1)
      LDRSET = FACFR4*Z(IDRSET) - FACFR4
      DO 5 I=1,ILONG                                                    14760   
      ALLOC(Z(IMASK)+I-1)=0
5     ALLOC(Z(IL)+I-1)=0
C
C     WE DEFINE THE FOLLOWING OBJECTS
C
C     Z(IWORD)
C       EACH WORD CONTAINS THE NAME OF A PRIMARY QUANTITY THAT
C       IS BEING VARIED.  EQUAL NAMES ARE NOT STORED HERE.
C
C     Z(IMASK)                                                          14770   
C       EACH INTEGER WORD CONTAINS THE OFF-SET IN FLOAT TO
C       THE PRIMARY QUANTITY IN Z(IWORD).
C       FOR RENORM OR SHIFT KEYWORDS IT IS
C         -TII0000     WHERE
C           T = 0 MEANS RENORM;  = 1 MEANS SHIFT
C           II IS THE DATASET TO BE AFFECTED.
C
C     Z(IL)
C       CONTAINS A BLOCK FOR EACH SET OF EQUAL THINGS.
C       THE LAST BLOCK IS FOLLOWED BY 0.                                14780   
C       EACH BLOCK HAS THE INTEGER STRUCTURE
C         WORD1  NUMBER OF EQUAL SIGNS
C         WORD2  POINTER TO PRIMARY QUANTITY IN FLOAT.
C         THEREAFTER  WORD1 POINTERS TO THE SECONDARY QUANTITIES IN
C                     FLOAT.
C
C     Z(IDRSET)
C       EACH INTEGER RELATES TO A PRIMARY FIT-WORD.
C       0 = DERIV CONTROL KEYWORDS NOT SPECIFIED
C       1 = DERIV SPECIFIED FOR THIS FIT WORD                           14790   
C       2 = NODERIV.
C
      NUMFIT=0
      IEKEY=0
      IECNT=0
      IEFST=0
      MAXEQL = 0
      IECNTS = 0
C
C  IEKEY=1  FOR NEXT KEY AFTER =                                        14800   
C  IEKEY=0  MEANS NEXT KEY AFTER KEYWORD
C
C  IEFST=1  MEANS NOT THE FIRST = ENCOUNTERED
C  IEFST=0  MEANS THE FIRST = ENCOUNTERED
C
C  REQUIRE ( TO PROCEED
      CALL FITKEY(AKEY,*100,*900,*900,*900)
      GO TO 900
100   CALL FITKEY(AKEY,*200,*300,*400,*905)
      AKEYP = AKEY                                                      14810   
      IF(AKEY.EQ.UP)GO TO 500
      IF(AKEY.EQ.DOWN)GO TO 550
C
C     FIND THE FIT WORD AND CONSTRUCT KEY ( POINTER TO FLOAT OR
C     ELSE   -TII0000   FOR RENORM OR SHIFT )
C
C     LOOK FIRST FOR RENORM OR SHIFT
C
      DO 119  I = 1, NUMREN
         IF ( AKEY .NE. RENWRD(I) )  GO TO 105                          14820   
         K = 0
         GO TO 110
 105     IF ( AKEY .NE. SHFWRD(I) )  GO TO 119
         K = 1
 110     KEY = I-2
         IF ( KEY .LE. 0 )  KEY = 1
         KEY = -10000*( 100*K + KEY )
         GO TO 150
 119  CONTINUE
C                                                                       14830   
C     NOW TRY WORDS IN FLOAT
C
 120  DO 129 I=1,NUMFLT
         IF(AKEY.NE. FLTWRD(I))GO TO 129
         KEY = I
         GO TO 150
129   CONTINUE
C
C     IS IT AN ALIAS
C                                                                       14840   
      DO 139  I = 1, NUMALI, 2
         IF ( AKEY .NE. ALIAI(I) )  GO TO 139
         AKEY = ALIAI(I+1)
         GO TO 120
 139  CONTINUE
C
C     IS IT A DERIVATIVE CONTROL WORD
C
      DO 144  I = 1, 4
         IF ( AKEY .NE. DERIVS(I) )  GO TO 144                          14850   
         IF ( NUMFIT .EQ. 0 )  GO TO 940
         ILLOC(LDRSET+NUMFIT) = (I+1)/2
         GO TO 100
 144  CONTINUE
      GO TO 910
C
C     FIT WORD HAS BEEN IDENTIFIED
C
 150  IF(IEKEY.EQ.1)GO TO 310
      NUMFIT=NUMFIT+1                                                   14860   
      IEFST=0
      CH8LOC(Z(IWORD)+NUMFIT-1)= AKEYP
      ILLOC(LMASK+NUMFIT) = KEY
      IKEY=KEY
      GO TO 100
C
C  (  ENCOUNTERED --  THIS IS AN EXTRA ONE
C
200   GO TO 100
C                                                                       14870   
C   =  ENCOUNTERED
C
300   IEKEY=1
      IF(IEFST.EQ.1)GO TO 100
      IEFST=1
      IECNT=IECNT+2
      LTMPNM = LTMPNM+2
      ILLOC(IQ+IECNT-1)= IKEY
      MAXEQL = MAX0( MAXEQL, IECNTS )
      IECNTS=0                                                          14880   
      GO TO 100
C
C  PROCESS EQUAL
C
310   IECNT=IECNT+1
      LTMPNM = LTMPNM+1
      ILLOC(IQ+IECNT-1)= KEY
      CH8LOC(LTMPNM) = AKEYP
      IECNTS=IECNTS+1
      ILLOC(IQ+IECNT-IECNTS-2)=IECNTS                                   14890   
      IEKEY=0
      GO TO 100
C
C  ALL FINISHED.  ) ENCOUNTERED
C
400   IPARA=NALLOC(NUMFIT,'PARAMETE')
      CALL IREDEF ( NUMFIT, IWORD )
      CALL IREDEF ( (NUMFIT+FACFR4-1)/FACFR4, IMASK )
      CALL IREDEF ( (IECNT+FACFR4)/FACFR4, IL )
C                                                                       14900   
C     FOR POSSIBLE USE BY THE GRADIENT CALCULATION, WE SETUP AN ARRAY
C     INDICATING WHICH PART OF THE POTENTIAL EACH PARAMETER AFFECTS:
C       0 - EFFECTS NEITHER (RENORM OR SHIFT)
C       1 - PARAM EFFECTS REAL(V)
C       2 - PARAM EFFECTS IMAG(V)
C       3 - PARAM EFFECTS BOTH ( POSSIBLE THROUGH EQUALS ).
C     >=4 - UNKNOWN - DERIVATIVE MUST BE FOUND NUMERICALLY
C
C     ALSO SETUP A TWO-DIM ARRAY OF THE EQUALS TO BE PRINTED BY CALFUN.
C                                                                       14910   
      IDVTYP = NALLOC( (NUMFIT+FACFR4-1)/FACFR4, 'DERIVTYP' )
C
C     MAXEQL IS TWICE THE NUMBER OF EQUALS IN ONE STRING.
C
      MAXEQL = 2*MAX0( MAXEQL, IECNTS )
      IENAME = NALLOC( 1+MAXEQL*NUMFIT, 'EQUALNAM' )
      LENAME = Z(IENAME)
      LDVTYP = FACFR4*Z(IDVTYP) - FACFR4
      ILLOC(FACFR4*(LENAME-1)+1) = MAXEQL
      IQ = FACFR4*(Z(IL)-1) + 1                                         14920   
      LTMPNM = Z(ITMPNM)
      LMASK = FACFR4*Z(IMASK) - FACFR4
      LDRSET = FACFR4*Z(IDRSET) - FACFR4
      DO 459  NF = 1, NUMFIT
C
C     IS IT REAL OR IMAG
C
         IREAL = 0
         IIMAG = 0
         INUMER = 0                                                     14930   
         KEY = ILLOC(LMASK+NF)
         KEYDR = ILLOC(LDRSET+NF)
      IF ( KEYDR .EQ. 2 )  INUMER = 4
         IF ( KEY .LT. 0 )  GO TO 425
      IF ( INUMER .EQ. 4 )  GO TO 425
C
         AKEY = FLTWRD(KEY)
         DO 422  II = 1, NUMRL
            IF ( AKEY .NE. REALS(II) )  GO TO 422
            IREAL = 1                                                   14940   
            GO TO 425
 422     CONTINUE
         DO 424  II = 1, NUMIM
            IF ( AKEY .NE. IMAGS(II) )  GO TO 424
            IIMAG = 2
            GO TO 425
 424     CONTINUE
C
C     WE DON'T KNOW SO DO NUMERICALLY OR BOTH
C                                                                       14950   
         INUMER = 4
         IF ( KEYDR .EQ. 1 )  INUMER = 3
C
 425     IF ( MAXEQL .EQ. 0 )  GO TO 450
         DO 429  I = 1, MAXEQL
            CH8LOC(LENAME+(NF-1)*MAXEQL+I) = BLANK
 429     CONTINUE
         IMANY = ILLOC(IQ)
         IF ( IMANY .EQ. 0 )  GO TO 450
         IF ( ILLOC(IQ+1) .NE. KEY )  GO TO 450                         14960   
         IQ = IQ + 2
         LTMPNM = LTMPNM+2
         DO 439  I = 1, IMANY
            CH8LOC(LENAME+(NF-1)*MAXEQL+2*I-1) = EQUAL
            AKEYP = CH8LOC(LTMPNM+1)
            KEY = ILLOC(IQ)
            CH8LOC(LENAME+(NF-1)*MAXEQL+2*I) = AKEYP
            IQ = IQ + 1
            LTMPNM = LTMPNM+1
            IF ( KEY .LT. 0 )  GO TO 439                                14970   
            IF ( INUMER .GT. 0 )  GO TO 439
            AKEY = FLTWRD(KEY)
            DO 435  II = 1, NUMRL
               IF ( AKEY .NE. REALS(II) )  GO TO 435
               IREAL = 1
               GO TO 439
 435        CONTINUE
            DO 437  II = 1, NUMIM
               IF ( AKEY .NE. IMAGS(II) )  GO TO 437
               IIMAG = 2                                                14980   
               GO TO 439
 437        CONTINUE
C
C     WE DON'T KNOW SO DO NUMERICALLY OR BOTH
C
            INUMER = 4
            IF ( KEYDR .EQ. 1 )  INUMER = 3
C
 439     CONTINUE
 450     ILLOC(LDVTYP+NF) = ior( IREAL+IIMAG, INUMER )                  14990   
 459  CONTINUE
C
      IRET=1
      Z(ITMPNM) = -Z(ITMPNM)
      Z(IDRSET) = -Z(IDRSET)
      RETURN
C
C  FOR NOW ASSUME UPPERB OR LOWERB COME AFTER ALL FIT KEYWORDS
C
500   IUP=NALLOC(NUMFIT,'UPPERB  ')                                     15000   
      DO 510 I=1,NUMFIT
      CALL NXVAL(VAL,*930,*930,*930)
510   ALLOC(Z(IUP)+I-1)=VAL
      GO TO 100
550   IDO=NALLOC(NUMFIT,'LOWERB  ')
      DO 560 I=1,NUMFIT
      CALL NXVAL(VAL,*930,*930,*930)
560   ALLOC(Z(IDO)+I-1)=VAL
      GO TO 100
C                                                                       15010   
900   WRITE(6,901)
901   FORMAT ( ' *** EXPECT ( FIRST IMMEDIATELY AFTER KEYWORD FIT')
      RETURN
905   WRITE(6,906)
906   FORMAT ( ' *** MISPLACED SPECIAL CHARACTER OR NUMBER')
      RETURN
910   WRITE(6,911)AKEY
911   FORMAT ( ' *** INPUT ERROR. ',A8,' IS NOT A VALID FIT PARAMETER')
      RETURN
930   WRITE(6,931)                                                      15020   
931   FORMAT(' ERROR IN READING BOUNDS. NOTE BOUNDS MUST FOLLOW ALL F',
     1  'IT PARAMETERS')
      RETURN
 940  write (6, 941)
 941  FORMAT ( '0**** DERIV/NODERIV MUST FOLLOW A KEYWORD.' )
      RETURN
      END
C*ID* GENBNX   C109.PTOLEMY.SOURCE                          PER701  14:
      SUBROUTINE GENBNX ( IPASS, NBINDX, MBINDX, BINDEX, NBASCP,
     1  MBASCP, BASCUP, MBASDF, BASDEF, MCHNDF, CHNDEF,                 15030   
     2  NMBFAC, NMFFAC, MXLXGS, MXLXBF,  COULSW, PBUGSW )
C
C     DETERMINS THE SIZE OF THE B-FACTORS ARRAY AND CONSTRUCTS INDEX
C
C     FOR COUPLED CHANNES WE GO THROUGH THE BASIS COUPLING ARRAY
C     AND FOR ALL COULOMB COUPLINGS
C     1)  FIND THE REQUIRED STORAGE SIZE FOR B-FACTORS,
C         CONSTRUCT THE B INDEX ARRAY, AND STORE POINTERS
C         TO IT.
C     2)  STORE THE MINIMUM LX IN CHNDEF(15,..) OF EACH CHANNEL         15040   
C         THAT REQUIRES COULOMB FF2 INTEGRALS.  OTHER CHNDEF(15,..)
C         ARE LEFT AS NOTDEF.
C     3)  CONSTRUCT POINTERS FOR THE FF2 INTEGRALS FOR ALL
C         COULOMB COUPLINGS TO THE G.S.  THE SIZE OF THE FF2
C         ARRAY IS ALSO FOUND.
C
C     THIS ROUTINE MUST FIRST BE CALLED WITH IPASS=1 AND THEN
C     WITH IPASS=2.  IN BETWEEN THESE CALLS, LIMOST MUST BE
C     COMPUTED FOR EACH CHANNEL REQUIRING COULOMB FF2 INTS
C     (EACH CHANNEL WITH A MINIMUM LX STORED IN CHNDEF(15,..))          15050   
C     AND STORED IN CHNDEF(15,..).
C
C     THE BFACTOR INDEX ARRAY HAS THE FOLLOWING ENTRIES FOR
C     EACH COMBINATION OF (LX, CHANNEL 1, CHANNEL 2)  FOR WHICH
C     B FACTORS ARE NEEDED.
C
C     1  LX  (TOTAL LAMBDA)
C     2  CHANNEL 1
C     3  CHANNEL 2
C     4  2*MAX(L1-J)                                                    15060   
C     5  2*MAX(L2-J)
C     6  2*MIN(L1-J)
C     7  2*MIN(L2-J)
C     8  POINTER TO THE B FACTORS.FOR C.C. MATCHING.  THE LEAST
C        VALUE IS 1. (0 MEANS B-FACTORS WERE SUPPRESSED).
C     9  POINTER TO FF2 INTS FOR EXTRAPOLATION.  THE LEAST
C        VALUE IS 1 (0 MEANS NO FF2 INTS FOR THIS COUPLING).
C
C
C     IPASS - =1 OR 2 TO INDICATE THE PASS.                             15070   
C     NBINDX, MBINDX, BINDEX - THE B INDEX ARRAY THAT IS CONSTRUCTED.
C     NBASCP, MBASCP, BASCUP - THE BASIS COUPLING ARRAY
C     MBASDF, BASDEF - THE BASIS DEFINITION ARRAY
C     MCHNDF, CHNDEF - THE CHANNEL DEFINITION ARRAY
C     NMBFAC - SET TO THE  NUMBER OF BFACTORS THAT WILL BE
C              PER J-VALUE.
C     NMFFAC - SET TO THE NUMBER/NUMJVALS OF FF2 INTS THAT WILL BE
C              NEEDED.
C     MXLXGS - SET TO THE MAXIMUM LX FOR WHICH FF2 INTS ARE NEEDED.
C     MXLXBF - MAX LX NEEDED FOR B FACTORS                              15080   
C     COULSW - SET TO .TRUE. IF ANY CHANNELS ARE 1ST ORDER COULOMB
C              COUPLED TO THE G.S.
C     PBUGSW - MUST BE .TRUE. TO GET DEBUGGING OUTPUT.
C
C     1/8/80 - FIRST VERSION - S.P.
C     2/18/80 - STORE INFO NEEDED FOR FF2 INTEGRALS - S.P.
C     3/15/80 - STORE IN J-BLOCKS INSTEAD OF CHANNEL BLOCKS - S.P.
C     3/27/80 - ALWAYS STORE POINTERS IN BASCUP - S.P.
C     9/25/80 - STORE LX IN CHNDEF(15,), CHNDEF(14,) NOBORNSUB
C               SWITCH; IPASS - S.P.                                    15090   
C     12/18/80 - REVERSE N1 AND N2 (WERE INCORRECT) IN FF2 - S.P.
C                 THIS HAS EFFECT ONLY FOR UPONLY COUPLING.
C     9/3/81 - MXLXBF ADDED - S.P.
C     9/12/81 - DISREGARD ORDER - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
C
      INTEGER  BINDEX(MBINDX,1),  BASCUP(MBASCP, NBASCP),
     1  BASDEF(MBASDF,1), CHNDEF(MCHNDF,1)
      LOGICAL  PBUGSW, COULSW                                           15100   
C
C
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
C
       LOGICAL BFACSW
C
C
C     WE START OUT WITH THESE 1 TOO LARGE FOR GENERATING POINTERS       15110   
C
      BFACSW = NOBFAC .NE. 1
      NMBFAC = 1
      NMFFAC = 1
      IF ( IPASS .EQ. 2 )  GO TO 305
      MXLXGS = 0
      MXLXBF = 0
      NBINDX = 0
C
C     PASS 1 -- PROCESS ALL BASIS-STATE COUPLINGS AND DETERMIN          15120   
C     MAXIMUM RANGES OF L NEEDED FOR THE B FACTORS.  HERE
C     WE ARE INTERESETED ONLY IN COULOMB COUPLINGS.
C
      DO 299  IBC = 1, NBASCP
         BASCUP(9,IBC) = 0
c
c     is there coulomb coupling?
c     on IEEE must also check for -0 when using I*4 equiv R*4
c
         IF ( BASCUP(6,IBC) .EQ. 0 ) GO TO 299                          15130   
         IF ( BASCUP(6,IBC) .EQ.  -2147483648 ) GO TO 299               ci3e
C
C     FIND THE INVOLVED CHANNELS
C
         IB1 = BASCUP(1,IBC)
         N1 = BASDEF(1,IB1)
         IB2 = BASCUP(2,IBC)
         N2 = BASDEF(1,IB2)
C
C                                                                       15140   
C     WE NEED B-FACTORS FOR THIS PAIR OF STATES.
C     SEE IF THEY HAVE ALREADY BEEN PROCESSED.
C
         LAMBDA = BASCUP(4,IBC)/2
         LMJ1 = BASDEF(3,IB1)
         LMJ2 = BASDEF(3,IB2)
         IF ( NBINDX .EQ. 0 )  GO TO 200
         DO 149  IBF = 1, NBINDX
            IF ( LAMBDA .NE. BINDEX(1,IBF) )  GO TO 149
            NN1 = BINDEX(2,IBF)                                         15150   
            NN2 = BINDEX(3,IBF)
            IF ( N1 .EQ. NN1  .AND.  N2 .EQ. NN2 )  GO TO 220
            IF ( N1 .EQ. NN2  .AND.  N2 .EQ. NN1 )  GO TO 230
 149     CONTINUE
C
C     WE NEED A NEW SET OF B FACTORS FOR THIS PAIR OF CHANNELS
C     AND LAMBDA.  START COLLECTING STATISTICS.
C
 200     NBINDX = NBINDX+1
         BINDEX(1,NBINDX) = LAMBDA                                      15160   
         BINDEX(2,NBINDX) = N1
         BINDEX(3,NBINDX) = N2
         BINDEX(4,NBINDX) = LMJ1
         BINDEX(5,NBINDX) = LMJ2
         BINDEX(6,NBINDX) = LMJ1
         BINDEX(7,NBINDX) = LMJ2
         BINDEX(9,NBINDX) = 0
         BASCUP(9,IBC) = NBINDX
         IBF = NBINDX
      MXLXBF = MAX0( MXLXBF, LAMBDA )                                   15170   
         GO TO 250
C
C     THIS CHANNEL HAS BEEN PROCESSED, COLLECT MAXIMUM REQUIREMENTS.
C
  220    BINDEX(4,IBF) = MAX0( BINDEX(4,IBF), LMJ1 )
         BINDEX(5,IBF) = MAX0( BINDEX(5,IBF), LMJ2 )
         BINDEX(6,IBF) = MIN0( BINDEX(6,IBF), LMJ1 )
         BINDEX(7,IBF) = MIN0( BINDEX(7,IBF), LMJ2 )
         BASCUP(9,IBC) = IBF
         GO TO 250                                                      15180   
C
C     FOUND IN REVERSE ORDER
C
  230    BINDEX(4,IBF) = MAX0( BINDEX(4,IBF), LMJ2 )
         BINDEX(5,IBF) = MAX0( BINDEX(5,IBF), LMJ1 )
         BINDEX(6,IBF) = MIN0( BINDEX(6,IBF), LMJ2 )
         BINDEX(7,IBF) = MIN0( BINDEX(7,IBF), LMJ1 )
         BASCUP(9,IBC) = -IBF
C
C     STORE MINIMUM LX FOR CHANNELS REQUIRING FF2 INTS                  15190   
C
 250     IF ( N1 .EQ. 1  .OR.  N2 .NE. 1 )  GO TO 299
         IF ( IBRNSB .EQ. 1 )  GO TO 299
         COULSW = .TRUE.
         L = LAMBDA
         IF ( CHNDEF(15,N1) .NE. NOTDEF )
     1      L = MIN0( L, CHNDEF(15,N1) )
         CHNDEF(15,N1) = L
C
C     INDICATE THAT THIS PAIR OF CHANNELS NEEDS COULOMB FF2 INTEGRALS   15200   
C
         BINDEX(9,IBF) = 1
         MXLXGS = MAX0( MXLXGS, LAMBDA)
C
 299  CONTINUE
C
      IF ( PBUGSW )  write (6, 303) NBINDX, MXLXGS, MXLXBF
 303  FORMAT ( '0', I8, ' SETS OF B-FACTORS NEEDED;',
     1  3X, 'MAXIMUM LX FOR F, B FACTORS =', 2I5 )
      RETURN                                                            15210   
C
 305  IF ( NBINDX .EQ. 0 )  GO TO 800
C
C     PASS 2 -- PROCESS THE B-INDEX ARRAY.   ORDER THE CHANNELS
C     SO THAT  L(1)-J < L(2)-J  TO MIMIMIZE STORAGE USED FOR THE
C     B FACTORS.  COMPUTE THE REQUIRED BSFACTOR SIZE AND STORE
C     POINTERS TO THE BSFACTORS.
C
      DO 399  IBF = 1, NBINDX
         INEG = +1                                                      15220   
         IF ( BINDEX(6,IBF) .GT. BINDEX(7,IBF) )  GO TO 330
         INEG = -1
         DO 309  I = 2, 6, 2
            II = BINDEX(I,IBF)
            BINDEX(I,IBF) = BINDEX(I+1,IBF)
            BINDEX(I+1,IBF) = II
 309     CONTINUE
C
 330     BINDEX(8,IBF) = INEG*NMBFAC
C                                                                       15230   
C     THE SUBSCRIPTING SCHEME FOR THE B FACTORS IS GIVEN
C     IN SETBFC.
C
         NM1FRJ = (BINDEX(4,IBF)-BINDEX(6,IBF))/4 + 1
         NMBFRJ = (BINDEX(1,IBF)+1)*NM1FRJ
         IF ( BFACSW )  NMBFAC = NMBFAC + NMBFRJ
C
C     STORE NUMBER OF FF2 INTEGRALS PER J-VALUE
C
         IF ( BINDEX(9,IBF) .NE. 1 )  GO TO 390                         15240   
         BINDEX(9,IBF) = NMFFAC
         N2 = BINDEX(3,IBF)
         NUMLIS = CHNDEF(15,N2)-LMIN+1
         NMFFAC = NMFFAC + NMBFRJ*NUMLIS
 390     IF ( PBUGSW )  write (6, 393) ( BINDEX(I,IBF), I=1,9 )
 393     FORMAT ( ' LX, CH1, CH2, L-J, ..., BPTR =', 9I10 )
 399  CONTINUE
C
C
C     PASS 3 -- SCAN BASIS-STATE COUPLING ARRAY AND INDICATE            15250   
C     THOSE BFACTORS THAT WILL BE STORED IN REVERSE ORDER.
C
      DO 449  IBC = 1, NBASCP
         IBF = BASCUP(9,IBC)
         IF ( IBF .EQ. 0 )  GO TO 449
         IF ( BINDEX(8,IABS(IBF))  .LT. 0 )  BASCUP(9,IBC) = -IBF
 449  CONTINUE
C
C     PASS 4 -- SCAN B-INDEX ARRAY AND MAKE ALL POINTERS > 0
C                                                                       15260   
      DO 499  IBF = 1, NBINDX
         BINDEX(8,IBF) = IABS(BINDEX(8,IBF))
 499  CONTINUE
C
 800  NMBFAC = NMBFAC - 1
      NMFFAC = NMFFAC - 1
      IF ( PBUGSW )  write (6, 803) NMBFAC, NMFFAC
 803  FORMAT ( ' TOTAL NUMBER OF B AND FF2 FACTORS:', I10,
     1    1X, '(PER J-VALUE)', I10 )
      RETURN                                                            15270   
      END
C*ID* GETBFC   C109.PTOLEMY.SOURCE                          PER701  17:
      SUBROUTINE GETBFC ( ILI, J, DELTA, RASYMP, NMBFC, BFACIN, BFACOT,
     1  MBNDX, BINDEX, MCHNDF, CHNDEF, MCHNVL, CHNVAL,
     2  MBASDF, BASDEF, NBASDF, FG )
C
C     COMPUTES THE B-FACTORS AT  RASYMP-DELTA  FROM THOSE AT  RASYMP.
C
C     ILI - INDEX OF J IN THE LIS ARRAY
C     J - 2*TOTAL J                                                     15280   
C     DELTA - NBACK*STEPSZ - MATCHING DELTA IN FERMIS.
C     RASYMP- ASYMPTOPIA IN FERMIS
C     BFACIN IS THE BFACTORS AT R FOR ALL J'S AS FOUND BY SETBFC
C            THIS IS POINTED TO BY ICL1FF
C     BFACOT WILL BE THE B-FACTORS AT R-DELTA AND R FOR THIS J:
C            (THIS IS POINTED TO BY ICL1FG)
C
C        BFACOT(IC,IR,K):
C           IC=1 FOR REAL, 2 FOR IMAG PART;
C           IR=1 FOR R-DELTA, 2 FOR R;                                  15290   
C           K = BINDEX(8,IB) + L2-L1+LX + (LX+1)(L1-J - MIN(L1-J))
C
C     THE X(1,2) TERM IS STILL OMITTED SO THAT
C        B(2,1) = X(1,2) * BFACOT
C
C     BINDEX - B-FACTORS INDEX ARRAY (IBINDX) STORED BY GNBNDX.
C     MCHNDF - NUMBER OF WORDS PER CHANNEL IN CHANDEF.
C     CHNDEF - THE CHANNEL DEFINITION ARRAY (CHNDEF).
C           THIS IS THE TWO-DIMENSIONAL PART FOLLOWING THE HEADER.
C     MCHNVL, CHNVAL - THE CHANNAL VALUES ARRAY (K, ETA)                15300   
C     MBASDF - NUMBER OF WORDS PER BASIS STATE IN BASDEF.
C     BASDEF - THE BASIS DEFINITION ARRAY (IBASDF).  THIS IS THE
C              PART FOLLOWING THE HEADER.
C     NBASDF - THE NUMBER OF BASIS STATES
C     FG - THE FANDG (NFS(1)) ARRAY.
C
C     2/15/80 - FIRST VERSION - S.P.
C     3/15/80 - STORED BY J-BLOCKS - S.P.
C      6/2/80 - NMBFC, MBNDX PASSED TO ALLOW CDC COMPATIBILITY - S.P.
C     10/16/84 - ALLOW FOR REAL*8 F&G ARRAY - S.P.                      15310   
C
      implicit real*8 ( a-h, o-z )                                      implicit
C
      REAL*4  BFACIN(2,NMBFC,1),  BFACOT(2,2,NMBFC)
      INTEGER  BINDEX(MBNDX, 1),  CHNDEF(MCHNDF, 1)
      INTEGER  BASDEF(MBASDF, NBASDF)
      REAL*4  FG(4, NBASDF, 1)                                          c4f
C8F      REAL*8  FG(4, NBASDF, 1)
      DIMENSION CHNVAL(MCHNVL, 1)
C                                                                       15320   
C
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
      COMMON /GRIDCM/  RCUEFF, GRDCM1(2),                               /gridcmf
     &  IBINDX, MBINDX, NBINDX, NMFFAC, MXLXGS, NMBFAC,
     & IINHR, IINHI, IRHSR, IRHSI,
     &  INUCH, ICOULH, ILOR, ILOI, ILIR, ILII,
     &  NPTMIN, NOFLO, NUMPT, NCRIT,
     & ISMX, ISMSQ, IPADE, IHOMO,
     &  ISMTSV, IRPTS4, IRPTS,
     &  IGRDC4(5), IDW, IGRDC5(2),
     &  IABS1, IGRDC6(2), GRDCM2, IGRDC7(2), IRWTS,
     &  IGRDC8(2), ICL1FF, ICL1FG, ICL1GF, ICL1GG
 
C
      LOGICAL DBUGSW
C
      DBUGSW = MOD(IPRINT, 10)  .GE. 5
C                                                                       15330   
      FAC = 3*IZS(1)*IZS(3)*HBARC*DELTA/(4*AFINE) * 2*AM/HBARC**2
C
      IF ( DBUGSW )  write (6, 13) ILI, J, DELTA, RASYMP, FAC
 13   FORMAT ( ' BFACTORS:', 2I5, '/2', 3G16.6 )
C
C     LOOP OVER ALL SETS OF BFACTORS
C
      DO 899  IBSET = 1, NBINDX
         LX = BINDEX(1,IBSET)
         IC1 = BINDEX(2,IBSET)                                          15340   
         IC2 = BINDEX(3,IBSET)
         MXLMJ1 = BINDEX(4,IBSET)
         MNLMJ1 = BINDEX(6,IBSET)
         LB = BINDEX(8,IBSET)
C
         MINL1 = (MNLMJ1+J)/2
C
         AK1 = CHNVAL(1,IC1)
         IB1ST = CHNDEF(8,IC1)
         IB1END = IB1ST + CHNDEF(9,IC1) - 1                             15350   
         AK2 = CHNVAL(1,IC2)
         IB2ST = CHNDEF(8,IC2)
         IB2END = IB2ST + CHNDEF(9,IC2) - 1
C
         IF ( DBUGSW )  write (6, 203) IC1, IC2, LB
 203     FORMAT ( ' CHANNELS', 2I4, 5X, 'LB =', I6 )
C
         FACTOR = FAC/SQRT(AK1*AK2)
C
C     THINGS GET A BIT CONTORTED HERE BECAUSE WE NEED THE COULOMB       15360   
C     FUNCTIONS F AND G WHICH WERE STORED IN THE ORDER OF THE
C     BASIS STATES.  THEREFORE WE LOOP THROUGH BOTH SETS OF
C     BASIS STATES AND COMPUTE THE B'S FOR EVERY VALID PAIR OF
C     L1 AND L2.  THIS MEANS THAT WE MAY COMPUTE SOME PAIRS
C     SEVERAL TIMES BUT TOO BAD.
C
         DO 879  IB1 = IB1ST, IB1END
C
            L1 = J + BASDEF(3,IB1)
            IF ( L1 .LT. 0 )  GO TO 879                                 15370   
            L1 = iSHFT(L1, -1)
C
            DO 859  IB2 = IB2ST, IB2END
C
               L2 = J + BASDEF(3,IB2)
               IF ( L2 .LT. 0 )  GO TO 859
               L2 = ishft(L2, -1)
               IF ( IABS(L1-L2) .GT. LX )  GO TO 859
               I = (LX+1)*(L1-MINL1) + LX - L1 + L2
               I = ishft(I, -1) + LB                                    15380   
C
C     HERE WE USE ONE TRAPEZIOD TO INTEGRATE FROM RASYMP TO RASYMP-DELTA
C
               BFACOT(1,1,I) = BFACIN(1,I,ILI) + FACTOR*(
     1            (FG(1,IB1,ILI)*FG(2,IB2,ILI) -
     2              FG(2,IB1,ILI)*FG(1,IB2,ILI))/(RASYMP-DELTA)**(LX+1)
     3          + (FG(3,IB1,ILI)*FG(4,IB2,ILI) -
     4              FG(4,IB1,ILI)*FG(3,IB2,ILI))/RASYMP**(LX+1) )
C
               BFACOT(1,2,I) = BFACIN(1,I,ILI)                          15390   
C
               BFACOT(2,1,I) = BFACIN(2,I,ILI) + FACTOR*(
     1            (FG(1,IB2,ILI)*FG(1,IB1,ILI) +
     2              FG(2,IB2,ILI)*FG(2,IB1,ILI))/(RASYMP-DELTA)**(LX+1)
     3          + (FG(3,IB2,ILI)*FG(3,IB1,ILI) +
     4              FG(4,IB2,ILI)*FG(4,IB1,ILI))/RASYMP**(LX+1) )
C
               BFACOT(2,2,I) = BFACIN(2,I,ILI)
C
               IF ( DBUGSW )  write (6, 833) L1, L2, I, BFACOT(1,1,I),  15400   
     1           BFACOT(2,1,I), BFACOT(1,2,I), BFACOT(2,2,I)
 833           FORMAT ( 3I4, 2( G20.10, G18.10 ) )
C
 859        CONTINUE
 879     CONTINUE
 899  CONTINUE
C
      RETURN
      END
C*ID* GETIT    C109.PTOLEMY.SOURCE                          PER701      15410   
      SUBROUTINE  GETIT ( IRET )                                        csp
C                                                                       csp
C     DOES A GET OR KEPT OF A SPEAKEASY OBJECT                          csp
C                                                                       csp
C     FORMAT OF THE COMMAND IS                                          csp
C                                                                       csp
C     GET  PTOLEMY-NAME  MEMBER-NAME                                    csp
C                                                                       csp
C     AN OBJECT WITH THE APPROPRIATE NUMBER OF WORDS WILL BE DEFINED    csp
C     WITH THE NAME "PTOLEMY-NAME".  IF SUCH A NAME ALREADY EXISTS,     15420   
C     IT WILL BE AUTOMATICALLY DELETED.                                 csp
C                                                                       csp
C     11/27/77 - FIRST VERSION - S.PIEPER                               csp
C     12/27/79 - STANDARD MORTRAN - RPG                                 csp
C     3/19/04 - pass blank for libname                                  csp
C                                                                       csp
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
C                                                                       csp
      INTEGER BYTES(9) / 4, 8, 8, 16, 4, 8, 2, 1, 1 /                   15430   
      CHARACTER*8  KINDS(9) / 'INTEGER', 'REAL*8', 'REAL*8', 'COMPLEX', csp
     1  'REAL*4', 'NAME LIT', 'INTGER*2', 'INTGER*1', 'CHAR LIT' /      csp
C                                                                       csp
      CHARACTER*8  MEMBER , MYKEEP /'MYKEEP'/                           csp
C                                                                       csp
c                                                                       csp
C                                                                       csp
      CALL NXWORD ( OBNAME, *900, *900, *900 )                          csp
      CALL NXWORD ( MEMBER, *900, *900, *900 )                          csp
                                                                        15440   
      write (6,*) 'GET/KEPT needs to be coded for unix!!!!'             csp
      go to 950                                                         csp
C                                                                       csp
      CALL KEPT ( DUMMY, KIND, KLAS, NROW, NCOL, MEMBER, MYKEEP, IER, 0 csp
     1  0 )                                                             csp
      IF ( IER .EQ. 0 )  GO TO 200                                      csp
      IF ( IER .NE. 2 )  GO TO 150                                      csp
      write (6, 143) MYKEEP                                             csp
 143  FORMAT ( '0**** THERE MUST BE A ', A8, ' DD CARD FOR GET.' )      csp
      GO TO 950                                                         15450   
 150  IF ( IER .NE. 5 )  GO TO 160                                      csp
      write (6, 153)                                                    csp
 153  FORMAT ( '0**** NOT ENOUGH CORE FOR I/O BUFFERS FOR GET.' )       csp
      GO TO 950                                                         csp
 160  IF ( IER .NE. 7777 )  GO TO 170                                   csp
      write (6, 163) MEMBER                                             csp
 163  FORMAT ( '0**** COULD NOT FIND A MEMBER NAMED ', A8 )             csp
      GO TO 950                                                         csp
 170  write (6, 173) IER                                                csp
 173  FORMAT ( '0**** ERROR CODE FROM KEPT:', I10 )                     15460   
      GO TO 950                                                         csp
C                                                                       csp
C     DETERMINE SIZE OF OBJECT                                          csp
C                                                                       csp
 200  IF ( KIND .LT. 10 )  GO TO 250                                    csp
      write (6, 213) MEMBER, KIND, KLAS, NROW, NCOL                     csp
 213  FORMAT ( '0**** ', A8, ' IS INVALID FOR PTOLEMY'/                 csp
     1  6X, 'KIND, CLASS, NROWS, NCOLS =', 4I10 )                       csp
      CALL KEPTCL                                                       csp
      GO TO 950                                                         15470   
C                                                                       csp
 250  NELS = NROW*NCOL                                                  csp
      NWORDS = ( BYTES(KIND)*NELS + 7 ) / 8                             csp
      write (6, 263) MEMBER, NROW, NCOL, KINDS(KIND), NWORDS, OBNAME    csp
 263  FORMAT ( 1X, A8, ' WAS A ', I6, ' BY', I6, 2X, A8,                csp
     1   ' SPEAKEASY OBJECT;' /                                         csp
     2  ' IT WILL BE A', I8, '-WORD (8-BYTE WORDS) PTOLEMY ARRAY',      csp
     3   ' NAMED ', A8 )                                                csp
      I = NALLOC( NWORDS, OBNAME )                                      csp
      CALL KEPTCN ( ALLOC(Z(I)), IER, 8*NWORDS )                        15480   
      IF ( IER .NE. 0 )  GO TO 170                                      csp
      IRET = 1                                                          csp
      RETURN                                                            csp
C                                                                       csp
 900  write (6, 903)                                                    csp
 903  FORMAT ( '0**** GET REQUIRES TWO NAMES AS OPERANDS.' )            csp
 950  IRET = 0                                                          csp
      RETURN                                                            csp
      END                                                               csp
C*ID* GETNUM   C109.PTOLEMY.SOURCE                          PER701      15490   
      SUBROUTINE GETNUM ( NUM, * )                                      cnd
CDC      SUBROUTINE GETNUM ( NUM ), RETURNS ( IRTRN1 )
C
C     GETS THE NUMBER OF AN OBJECT FROM THE INPUT.
C
C     THE INPUT MAY BE EITHER THE OBJECT NUMBER OR NAME.
C     IF THE OBJECT IS UNDEFINED, OR THERE IS AN ERROR IN INPUT THEN
C     RETURN 1  IS MADE (WITH NUM = 0).
C
C     8/30/76 - ORIGINAL VERSION?                                       15500   
C     12/27/79 - STANDARD MORTRAN - RPG
C
      COMMON /USAGE/  IBASE, NWRDS, IMAX
      integer z
      COMMON /LOCptrs/  z(1)
      COMMON /LENGTH/  LENG(1)
C
      CHARACTER*8  NAME
C
      CALL  NXINT ( NUM, *200, *900, *200 )                             15510   
C
C     NUMBER HAS BEEN FOUND, IS IT DEFINED
C
      IF ( NUM .GT. IMAX  .OR.  NUM .LE. 0 )  GO TO 150
      IF ( z(NUM) .GT. 0  .AND.  LENG(NUM) .GT. 0 )  RETURN
 150  write (6, 153) NUM
 153  FORMAT ( '0***** NUMBERED OBJECT', I8, ' IS NOT DEFINED *****' /)
      NUM = 0
       RETURN 1
C                                                                       15520   
C     TRY TO FIND IT BY NAME
C
 200  CALL NXWORD ( NAME, *900, *900, *900 )
      NUM = NAMLOC( NAME )
      IF ( NUM .NE. 0 )  RETURN
      write (6, 253) NAME
 253  FORMAT ( '0******  ', A8, ' IS NOT A DEFINED NAME. ******' /)
      NUM = 0
      RETURN 1
C                                                                       15530   
C
 900  write (6, 903)
 903  FORMAT ('0***** INPUT ERROR - EXPECTING NAME OR NUMBER *****')
      NUM = 0
      RETURN 1
      END
C*ID* GETSCT   C109.PTOLEMY.SOURCE                          PER701  08:
      SUBROUTINE GETSCT (IRET)
C
C     COMPUTES SCATTERING WAVES AT LMIN AND LCRIT FOR GRDSET            15540   
C
C     7/8/75 - FIRST VERSION - S. P.
C     8/3/75 - LCRIT IS ALREADY IN COMMON
C     9/4/75 - MULTIPLIER FOR LCRIT
C     11/7/75 - REMOVE ABOVE MULTIPLIER
C     9/1/76 - FIX FOR VERY LARGE L'S
C     11/20/77 - NEW ORDERING OF WAVSET, WAVPOT, ETC - S.P.
C     12/20/77 - FIX ERROR IN ABOVE CHANGE - S.P.
C     5/23/78 - NEW CALLING SEQUENCE FOR WAVELJ - S.P.
C     8/27/78 - FORCE WAVELJ TO ALWAYS START OVER - S.P.                15550   
C     10/9/79 - TURN OFF SPIN-ORBIT AND TENSOR POTENTIALS - RPG
C     4/14/80 - ZERO STORED S-MATRICES TO STOP DOUBLE COUNTING - S.P.
C     12/14/81 - ALSO FOR C.C.; SAVE LNKBLK - S.P.
C     10/15/84 - ALLOW FOR REAL*8 F&G - S.P.
C     12/20/84 - LNKAD3 IN COMMON WITH NUMLINKULES - S.P.
C
C
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
      LOGICAL ONELSW, IDENSW                                            /inelcm/
      COMMON /INELCM/  JBPF, JBTF, LXMIN, LXMAX, ILILOR, ILILOI, MSTOP,
     &  IA12M, NMLOLX, ONELSW, NUMLX, IRDINT, IELCUP, LILOSZ, NUMLIS,
     &  ILIS, IBETAS(3), ICL2FF, LXSTEP, IDENSW, LSKIP,
     &  JPMIN, JPMAX, JPBASE, NJP, JTMIN, JTMAX, JTBASE, NJT,
     &  IINDXS, ISMATR, ISMATI, NSMAT, NLX, NSPLI, ITOCS,
     &  NASPLI, IUNITR, LIFIT, ILIFIT, NOLFIT, IDELSR, IDELSI
      INTEGER INDXJS(4,2)
      EQUIVALENCE ( INDXJS(1,1), JPMIN )
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
      COMMON /KANDM/ AKI, AKO, REDMI, REDMO, RIMAX, ROMAX, ISIGS(2),    /kandm/
     &  RSCTS(2), ASCTS(2), RCSCTS(2) ,ISMATS(2), LOMOST, LCRIT,
     &  ISCTMN, ISCTCR, ETAS(2), RCSCTP(2), RCSCTT(2), LCRITS(2),
     &  RATMSS(2), QMIN, ABAR
 
      DIMENSION  AKS(2), REDMS(2), RMAXS(2)
      EQUIVALENCE ( AKI, AKS(1) ), ( REDMI, REDMS(1) ),
     &  ( RIMAX, RMAXS(1) )
 
      DIMENSION  ISCRTS(2)
      EQUIVALENCE ( ISCRTS(1), ISCTMN )
      LOGICAL  IOUTSW, PINFSW                                           /bsblk/
      REAL*4  PHISGN
      COMMON /BSBLK/
     &  S1, S2, T1, T2, BNDMXP, BNDMXT, RLPMAX, RLTMAX,
     &  VPMAX, VTMAX, SCTMAX, SCTSP,
     &  BNDSPT, BNDSPP, BNDSPV, NSPBDT, NSPBDP, NSPBDV,
     &  JBDT, JBDP, JPOT, IOUTSW, NSPSCT, ALPHAP, ALPHAT,
     &  PINFSW, PHISGN, ROFMAX
      DIMENSION  RLMAXS(2), VMAXS(2)
      EQUIVALENCE ( RLMAXS(1), RLPMAX ), ( VMAXS(1), VPMAX )
 
c                                                                       /lnkblk/
c  STRUCTURE OF   /LNKBLK/
c
c  THERE IS A BLOCK OF 3 DOUBLE WORDS FOR EACH POSSIBLE USE
c  OF A LINKULE.  THE NUMLNK = NUMLINKULES USES ARE IN THE ORDER
c    REALPOTEN  IMAGPOTEN  REALVSO  IMAGVSO  COULOMB
c    WAVEFUNCTION  AND 6 TENSOR POTENTIALS
c  THE THREE-DOUBLE-WORD BLOCKS EACH HAVE THE STRUCTURE
c
c    LNKNAM(1,I)   LINKULE NAME
c
c      LNKADR(3,I)   LINKULE ADDRESS, O IF NO LINKULE IN USE.
c      LNKADR(4,I)   0 - NO L OR J DEPENDENCE IN POTENTIAL
c                    1 - L DEPENDENCE BUT NO J DEPENDENCE
c                    2 - BOTH L  AND J DEPENDENCE
c
c      LNKADR(5&6,I)  MYINTS - A TWO-ELEMENT ARRAY THAT THE
c                     LINKULE MAY USE FOR COMMUNICATION BETWEEN
c                     CALLS TO ITSELF.
c
      parameter ( NUMLINKULES = 13 )
      COMMON /LNKBLK/  NUMLNK, IUNIQU, LNKADR(6,NUMLINKULES)
      character*8  LNKNAM(3,NUMLINKULES)
      EQUIVALENCE ( LNKNAM(1,1), LNKADR(1,1) )
 
C
C     THIS IS A DUPLICATE OF LNKBLK
C
      COMMON /SCRTCH/ LNKAD3(6,NUMLINKULES)
      REAL*4 FG(4)                                                      c4f
C8F      REAL*8 FG(4)
C
      CHARACTER*8 NAMES(2) / 'MAGSCTMN', 'MAGSCTCR' /
      LOGICAL  SSOSW, STCSW, CCSW
      REAL*4 DUMMY4(1)                                                  15580   
C
c
C
      IPRNT = MOD(IPRINT, 10)
      CCSW = PROBLM .EQ. 24
      ITOP = 2
      IF (CCSW)  ITOP = 1
C
C     INITIALIZE THE COULOMB FUNCTIONS, ETC.
C                                                                       15590   
      DO 59  ICHANW = 1, ITOP
         CALL WAVPOT ( IRET )
        IF ( IPRNT .GE. 5 )  write (6, 53) ICHANW, IRET, IHSAVE
 53     FORMAT (' ++++ WAVPOT CALL, ICHANW, IRET, IHSAVE =', 4I10 )
         IF ( IRET .EQ. 0 )  RETURN
 59   CONTINUE
C
      IF ( IHSAVE .EQ. 2 )  RETURN
C
C                                                                       15600   
      LC = LCRIT
      IF ( LC .LT. LMIN  .OR.  LC .GT. LMAX )  LC = (LMIN+LMAX)/2
C
C
      IF ( IPRNT .GE. 3 )  write (6, 83) LCRIT, LC
 83   FORMAT ( '0 L CRITICAL:  AVERAGE =', I4, 5X,
     2  'USED FOR GRID SETUP =', I4 )
C
C     COMPUTE THE WAVEFUNCTIONS, USING CENTRAL POTENTIALS ONLY.
C                                                                       15610   
      STANSW = .TRUE.
      SSOSW = SOSWS(1)
      SOSWS(1) = .FALSE.
      STCSW = TCSWS(1)
      TCSWS(1) = .FALSE.
C
      L = MAX0( 0, LMIN-LXMAX )
      NSTEPS = NSTPSS(1) + 1
      RSTEP = RSTEPS(1)
C                                                                       15620   
C     WAVELJ WILL SET LNKBLK BACK TO THE STATUS FOR THE INCOMING
C     CHANNEL.  IT MAY HAVE BEEN CHANGED JUST FOR THE FORM FACTOR.
C     THEREFORE WE SAVE ITS STATUS.
C
      DO 152  II = 1, NUMLNK
      DO 152  I = 1, 6
         LNKAD3(I,II) = LNKADR(I,II)
 152  CONTINUE
C
      DO 399  II = 1, ITOP                                              15630   
         LWAVR = Z(IWAVR)
         LWAVI = Z(IWAVI)
         LVREAL = Z(IRLVS(1))
         LVIMAG = Z(IIMVS(1))
         LCENTR = Z(ICENTR(1))
         LSMATS = Z(ISMATS(1))
C
C     ALWAYS FORCE WAVELJ TO START OVER AND STEP OUT SLOWLY LOOKING FOR
C     OVERFLOWS.  THIS IS NECESSARY SINCE WE MAKE A LARGE JUMP IN L THAT
C     WAVELJ IS NOT EXPECTING.                                          15640   
C
         LASTL(1) = 999999
         FG(1) = ALLOC(Z(NF1S(1))+L)
         FG(2) = ALLOC(Z(NG1S(1))+L)
         FG(3) = ALLOC(Z(NFS(1))+L)
         FG(4) = ALLOC(Z(NGS(1))+L)
         CALL WAVELJ( L, 2*L+JSPS(1), 1, 0, DUMMY4, FG, DUMMY4,
     1      ALLOC(LWAVR), ALLOC(LWAVI),
     2      ALLOC(LVREAL), ALLOC(LVIMAG), ALLOC(LCENTR) )
C                                                                       15650   
C     JPTOLX HAS STORED AN S-MATRIX.  LATER ON WE WILL ACCUMULATE A
C     SUM OF CONTRIBUTIONS IN THIS SPOT SO WE MUST ZERO IT AGAIN.
C
         ALLOC(LSMATS+2*L) = 0
         ALLOC(LSMATS+2*L+1) = 0
C
C     COMPUTE AND STORE   RPSI
C
         IF ( CCSW )  GO TO 400
         PSIMX = 0                                                      15660   
         RPSIMX = 0
         ISCRTS(II) = NALLOC(NSTEPS, NAMES(II))
         LSCRTS = Z(ISCRTS(II)) - 1
         RVAL = -RSTEP
C
         DO 389  I = 1, NSTEPS
            RVAL = RVAL + RSTEP
            PSI = DABS(ALLOC(LWAVR-1+I)) +
     1          DABS(ALLOC(LWAVI-1+I))
            IF ( PSI .GT. PSIMX )  ROFMAX = RVAL                        15670   
            PSIMX = DMAX1( PSIMX, PSI )
            RPSIMX = DMAX1( RPSIMX, RVAL*PSI )
            ALLOC(LSCRTS+I) = RVAL*PSI
 389     CONTINUE
         IF (IPRNT .GE. 4)  write (6, 393) L, PSIMX, ROFMAX, RPSIMX, PSI
 393     FORMAT (' FOR L =', I4, ', MAX(PSI) =', G11.3,
     1     '   IS AT R =', F5.1, 5X, 'MAX(R*PSI) =', G11.3,
     2     5X, 'FINAL PSI =', G11.3 )
C
         L = LC                                                         15680   
 399  CONTINUE
C
 400  STANSW = .FALSE.
      SOSWS(1) = SSOSW
      TCSWS(1) = STCSW
C
      DO 159  II = 1, NUMLNK
      DO 159  I = 1, 6
         LNKADR(I,II) = LNKAD3(I,II)
 159  CONTINUE                                                          15690   
C
      IF ( .NOT. CCSW )  GO TO 500
C
C     WAVPOT ESPECIALLY SETUP COULOMB FUNCITONS FOR THIS ONE CALL
C     THEY ARE NOLONGER NEEDED SO RESTORE TO NORMAL C.C. MODE.
C
      Z(NFS(1)) = -Z(NFS(1))
      Z(NGS(1)) = -Z(NGS(1))
      Z(NF1S(1)) = -Z(NF1S(1))
      Z(NG1S(1)) = -Z(NG1S(1))                                          15700   
C
C     SAVE STUFF FOR BSPROD
C
 500  NSPSCT = NSTEPS
      SCTMAX = ASYMPS(1)
      SCTSP = 1/RSTEP
      RETURN
      END
C*ID* GRDSET   C109.PTOLEMY.SOURCE                          PER701  09:
      SUBROUTINE GRDSET ( IRTN )                                        15710   
C
C     SETS UP INTEGRATION GRIDS FOR THE TRANSFER INTEGRALS I(LI,LO,LX)
C
C     THIS ROUTINE PREPARES THE THREE-DIMENSIONAL GRID FOR THE
C     INELDC INTEGRALS.  IT COMPUTES ALL THE NECESSARY BOUND STATE
C     PRODUCTS ON THIS GRID.
C     THIS ROUTINE IS CALLED BEFORE THE WAVPOT CALLS.  BASED ON
C     THE VALUES OF THE BOUND STATE PRODUCTS IT DETERMINES THE
C     MAXIMUM RI AND RO VALUES THAT WILL BE REQUIRED.  THESE ARE
C     USED BY WAVPOT TO ALLOCATE SCRATCH SPACE FOR WAVELJ.              15720   
C
C       SEE INELDC FOR HISTORY PRIOR TO THE SPLIT
C     2/7/75 - SPLIT OFF FROM INELDC - S. PIEPER
C     2/13/75 - REMOVE  */RIX  STUFF FROM BOUND STATES - S.P.
C     2/19/75 - CUBIC MAPPINGS IN U V INTEGRALS; VARIABLE NO OF PTS
C               IN V INTEGRAL (DENSITY CONSTANT) -MHM
C     2/21/75 - USE AITLAG
C     2/23/75 - USE REAL*4 FOR THE VERY LARGE ARRAYS
C     3/5/75 - USE NEW GRID KEYWORDS, DIFFERENT MAPTYPES
C     3/7/75 - CHANGE CHOICE OF TRANSFERRED L                           15730   
C     3/17/75 - USE IXADD TO INCREASE X-RANGES.
C     3/20/75 - WAVEFUNCTIONS IN SINGLE PRECISION
C     3/23/75 - NEW ARRANGEMENT OF A12
C     3/27/75 - COSINE TABLE TO 2PI; ONE MSVAL ARRAY
C     4/7/75 - NEW LA, LX STUFF; REMOVE VARIABLE POINTS
C     4/18/75 - NEW COMMON; VERTEX CHOICE; AUTO FLIP OF LINES
C     5/20/75 - USE LSTEP; NEW RT AND RP NAMES
C     5/21/75 - ALLOC SPACE FOR ALL LA'S FOR GIVEN LB'S.
C     5/24/75 - V*PHI INCLUDES CORE-COULOMB CORRECTION (NUCONL=3)
C     5/28/75 - GOOD GOD, WE MUST SPLIT IT AGAIN - 3-WAY SPLIT -        15740   
C               PRBPRT, GRDSET AND ANGSET PRODUCED.
C     6/1/75  - GATHER ALL BOUND-STATE INTERPOLATIONS INTO NEW
C               SUBPROGRIM. FUNCTION BSPROD RETURNS BS PRODUCT
C               INCLUDING CORE-COULOMB CONTRIBUTION TO VEFF
C               IF NUCONL=2.   (MHM)
C     6/2/75  - MODIFIED ALSO TO HANDLE CORE CORRECTIONS FOR PICK-UP
C     6/11/75 - SAVEHS/USEHS
C     6/14/75 - MIDMULT ADDED
C     6/28/75 - USE GAUSSL; PRINT WARNINGS FOR EXCEEDING ASYMPT
C     7/1/75 - DO NOT ALLOW SMALL RP, RT VALUES OF PHI OR V*PHI         15750   
C              LIMIT THE INTEGRATION RANGES.
C     7/7/75 - MOVE RP, RT, RCORE AND RSCAT CALCS INTO BSPROD
C     7/10/75 - INCLUDE SCAT WAVE IN MAPPING PROCESS; COMPUT GAMMAS
C     8/2/75 - REMOVE AUTO GAMMA (DIDN'T WORK); NOTHING FOR PRINT=2
C     8/3/75 - RECTANGULAR GRIDS FOR CONTOUR MAPPING
C     9/8/75 - SMALL CLEANUPS
C     9/15/75 - NEW DWCUT DEFINITION
C     9/25/75 - FIX LOGIC ARRAY FOR USEHS
C     10/6/75 - NEW COMMON BLOCKS
C     2/21/76 - WHEN FINDING UMAX, CHECK FIVE V'S AT EACH U.            15760   
C     4/29/76 - MOVE SECTION SETTING UP RADII ETC. FOR USE
C               IN CALCULATING CORE TERMS IN VEFF INTO BSPROD
C               ALLOW FOR NUCONL = 3.  MHM
C      5/17/76 MAKE V-MAPPING PARAMETERS CONTINUOUS - S.P.
C      5/23/76 - USE SUMPOINTSPER; TWO SUM ARRAYS, ETC - S.P.
C     9/1/76 - FIX ERRORS FOR LARGE L
C     11/22/77 - NEW WAVPOT; MUST EXPAND WAVER,I HERE - S.P.
C     3/13/78 - DON'T USE POLYNOMIALS WHEN NPSUM=NPSUMI
C               IMPROVEMENTS IN KEEPING VMID IN BOUNDS
C     5/24/78 - BIGGER WAVR, WAVI ARRAYS FOR NEW WAVELJ - S.P.          15770   
C     5/4/79 - PROPER KINEMATIC MASSES - S.P.
C     6/6/79 - EXTEND "WAVE_" FOR TENSORS, USE BIGNUM - RPG
C     6/8/79 - STANDARD PREFIXES - RPG
C     7/6/79 - DON'T UNALLOCATE B.S. WF & POT. FOR MULTIPASS - RPG
C     9/12/79 - INTEGRATE OVER PHI, NOT COS(PHI); MAKE "LOGIC"
C        INTEGER AND DON'T SAVE IT; PUT RI*RO*JACOB IN "RIROWTS". - RPG
C     6/3/79 - ALWAYS USE CORE MASSES TO GET CORRECT NON-RELATIVISTIC
C              KINEMATICS WHEN BINDING ENERGIES CANNOT BE IGNORED - S.P.
C     10/11/79 - IGNORE MOST ASYMPTOPIA VIOLATIONS IN SUMMAX SEARCH -RPG
C     11/26/79 - MAKE SURE THE FINAL V RANGES ARE LEGAL. - RPG          15780   
C     12/12/79 - OPTIONAL SCRATCH FILE, CORRECT ABOVE, USE RI*RO WEIGHT
C        IN V SEARCH - RPG
C     2/12/80 - CVX TO CVA, USE NBLKSZ FOR SCRATCH FILE - RPG
C     2/20/80 - MAP PHI USING MAPPHI, PHIMID, GAMPHI - RPG
C     2/29/80 - REDUCE U-V RECTANGLE SIZE; CHECK LEGALITY OF INTERP. V;
C        CALL WRITSC - RPG
C     3/15/80 - WRITSC CALL MADE VAX ONLY - S.P.
C     4/14/80 - PRINT ERROR MESSAGE WHEN DIF-GRID EXCEEDS BOUNDS - S.P.
C     6/12/81 - DON'T FAIL LOOKING FOR SUMMIN WHEN IT IS GIVEN - S.P.
C                                                                       15790   
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      CHARACTER*1  REACT, HEADER                                        /hedcom/
      COMMON /HEDCOM/  REACT(45), HEADER(65)
 
      COMMON /KANDM/ AKI, AKO, REDMI, REDMO, RIMAX, ROMAX, ISIGS(2),    /kandm/
     &  RSCTS(2), ASCTS(2), RCSCTS(2) ,ISMATS(2), LOMOST, LCRIT,
     &  ISCTMN, ISCTCR, ETAS(2), RCSCTP(2), RCSCTT(2), LCRITS(2),
     &  RATMSS(2), QMIN, ABAR
 
      DIMENSION  AKS(2), REDMS(2), RMAXS(2)
      EQUIVALENCE ( AKI, AKS(1) ), ( REDMI, REDMS(1) ),
     &  ( RIMAX, RMAXS(1) )
 
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
      REAL*8  JACOB                                                     /gridcm/
      COMMON /GRIDCM/  JACOB, STPINV, COSSTP,
     &  IMSVAL, IINTS, INTOFF, IA12VL, ICOSIN,
     &  IPHIT, IPHIP, IPHI, LOGIC, LOCTRP,
     &  IRI, IRO, ILOR, ILOI, ILIR, ILII, IWIO, NOFLO, NRIROI, NCRIT,
     &  IXLAM, INLAM, IA12N, MSKCOS, MAXCNT, ISMHPT, ISMIPT,
     &  ICOSS4, IJA12S, IHS, IIINDX, IA12TM, IDW, IHINT, IHABS,
     &  IABS1, IGRDC1, NPSUMI, RVRLIM, ISMHWK, ISMHVL, ISMIVL,
     &  IRIOEX, NUMHS, IGRDC2(4),
     &  IWFII, IWFIO, NWFI, NWFO, IDWI
 
c                                                                       /formf/
c ***  LNKADB was  numLINKULES but only 12 are used ???
c
      COMMON /FORMF/  IBDS(2), NPOTS(2), LBP, LBT, NBP, NBT, JBP, JBT,
     &  BNDMAX(2), BNDSTP(2), NSTPBD(2), RBNDS(2), ABNDS(2),
     &  RCBNDS(2), BNDMAS(2), BRATMS(2), RSOBDS(2), ASOBDS(2),
     &  VBNDS(2), VSOBDS(2), TAUBDS(2), LNKADB(6, 2, 12)
 
      LOGICAL  IOUTSW, PINFSW                                           /bsblk/
      REAL*4  PHISGN
      COMMON /BSBLK/
     &  S1, S2, T1, T2, BNDMXP, BNDMXT, RLPMAX, RLTMAX,
     &  VPMAX, VTMAX, SCTMAX, SCTSP,
     &  BNDSPT, BNDSPP, BNDSPV, NSPBDT, NSPBDP, NSPBDV,
     &  JBDT, JBDP, JPOT, IOUTSW, NSPSCT, ALPHAP, ALPHAT,
     &  PINFSW, PHISGN, ROFMAX
      DIMENSION  RLMAXS(2), VMAXS(2)
      EQUIVALENCE ( RLMAXS(1), RLPMAX ), ( VMAXS(1), VPMAX )
 
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
C
      INTEGER  IZDUMY(45)
      EQUIVALENCE ( IZDUMY(1), IMSVAL )
C
      LOGICAL  PAS1SW, ZEROSW
      LOGICAL  PRNTSW, PGRDSW
C                                                                       15810   
C     NPLYSW = .TRUE. MEANS V-POLYNOMIALS ARE NOT TO BE USED
C
      LOGICAL  NPLYSW
C
      DIMENSION VS(5), XS(2)
      DATA  XS / 1.D0, 0.D0 /
      DIMENSION VRANGE(3)
C
c
C                                                                       15820   
      TSTART = second()
      TINTRP = 0
      NINTRP = 0
      IRTN = 0
C
      IPRNT = MOD( IPRINT, 10 )
      PGRDSW = IPRNT .GE. 5
      PINFSW = IPRNT .GE. 4
      PRNTSW = IPRNT .GE. 1
      IF ( PINFSW )  write (6, 3)                                       15830   
  3   FORMAT ( / '0SETUP OF THE INTEGRATION GRIDS:' )
C
C     MAKE THINGS EASY FOR INELDC WHEN  USEHS  IS IN EFFECT BY
C     ALLOWING DUMMY  Z(I...)'S.
C
      DO 39  I = 1, 45
 39   IZDUMY(I) = 1
C
C     RESTORE STUFF FROM H''S FILE IF NEEDED
C                                                                       15840   
      IF ( IHSAVE .NE. 2 )  GO TO 50
      READ ( 1, END=9950, ERR=9950 )  NPSUM, NPDIF, NPPHI,
     2    MAXCNT, JSIZE, GAMSUM, SUMMIN, SUMMID, SUMMAX,
     3    GAMDIF, VRNGMN, VRNGMX, X0MIN, X0AV, RPMAX, RTMAX,
     4    NRIROH, ALPHAP, ALPHAT, AREA, WVWMAX, NPLYSW
C
 50   INADD=2
      IF(NUCONL.GE.2) INADD=3
C
C********  TEMPORARY  ******************************************        15850   
      IRECT = ISW3
C*******************  END OF TEMPORARIES  **********************
C
C     THE CODE IS BASED ON THE ASSUMPTION THAT THE INCOMING PROJECTILE
C     IS COMPOSITE ( A = B+X ).  IF THIS IS NOT SO, WE CHANGE THE
C     DEFINITION OF S1, T1, S2, T2 SO THAT
C        RT = S1*RI + T1*RO
C        RP = S2*RI + T2*RO
C     WHERE
C        RT = VECTOR FROM CORE TO X IN TARGET                           15860   
C        RP = VECTOR FROM CORE TO X IN PROJECTILE.
C     FOR BOTH CASES.  IN THIS WAY IT IS NOT NECESSARY TO FLIP
C     AROUND THE BOUND STATE WAVEFUNCTIONS NOR L1 AND L2.  HOWEVER,
C     THE FLIP DOES REQUIRE THAT THE SYNES OF PHI1 AND PHI2 BE
C     MADE NEGATIVE.
C
CCCC      TEMP = 1/(AMX*(AMB+AMBIGA+AMX))
CCCC      S1 =  (AMB+AMX)*(AMBIGA+AMX)*TEMP
CCCC      T1 = -AMB * ((AMBIGA+AMX)*TEMP)
CCCC      S2 =  AMBIGA * (AMB+AMX)*TEMP                                 15870   
C
C     THE FOLLOWING EXPRESS THE ABOVE COMMENTED LINES IN TERMS
C     OF THE KINEMATICALLY CORRECT MASS RATIOS
C        X/B   X/BIGA
C
      TEMP = 1 / ( BRATMS(1) + BRATMS(2) * (1+BRATMS(1)) )
      S1 = ( 1 + BRATMS(1) ) * ( (1 + BRATMS(2) ) * TEMP )
      T1 = - ( 1 + BRATMS(2) ) * TEMP
      S2 = ( 1 + BRATMS(1) ) * TEMP
C                                                                       15880   
      T2 = -S1
      JACOB = S1**3
      PHISGN = 1
      IF ( ISTRIP .EQ. 1 )  GO TO 170
C
C     B = A+X, FLIP THINGS
C
C
C     IN THE FOLLOWING NOTE THAT BRATMS(1) NOW HAS X/A
C                                                                       15890   
      T2 = S2
      S2 = -S1
      S1 = T1
C
      T1 = -S2
      JACOB = T1**3
      PHISGN = -1
C
  170 IF (PINFSW)  write (6, 173) S1, T1, S2, T2, JACOB
 173  FORMAT ('0R TO RX MAPPING PARAMETERS (S1, T1, S2, T2) =',         15900   
     1  4G15.5, 5X, 'JACOB =', G15.5 )
      ST1=2.D0*S1*T1
      ST2=2.D0*S2*T2
C
      IF ( IHSAVE .EQ. 2 )  GO TO 400
C
C     INITIALIZE THE COMPUTATION OF  (PHI V PHI)
C
      CALL BSSET                                                        cnd
CDC      CALL BSSET (FIFO,1,U,U,XS,ISCTMN,1,RP,RT),RETURNS(180)         15910   
CDC 180  CONTINUE
C
      IF(LOOKST.GT.254) LOOKST=254
       DXV=2.D0/LOOKST**2
      XS(2) = 1 - DXV
C
C     FIND THE MAXIMUM  ( R PSI PHI V PHI PSI R )   THAT WE WILL
C     ENCOUNTER AND USE THIS TO SCALE DWCUT
C
      WVWMAX = 0                                                        15920   
      U = .5*ROFMAX
      N = 1.5*ROFMAX/.20D0 + 1
      VS(3) = 0
      TIME1 = second()
      DO 269  IU = 1, N
C
C     WE LOOK AT 5 DIFFERENT V'S FOR EACH U
C
         D = 2*(RLMAXS(2)-(S1+T1)*U)/(S1-T1)
         IF ( DABS(D) .GT. 2*U )  D = DSIGN(2*U, D)                     15930   
         VS(1) = D
         VS(2) = .5*D
         D = 2*(RLMAXS(1)-(S2+T2)*U)/(S2-T2)
         IF ( DABS(D) .GT. 2*U )  D = DSIGN(2*U, D)
         VS(4) = .5*D
         VS(5) = D
         DO 265  IV = 1, 5
            VVAL = VS(IV)
            DO 265  I = 1, 2
               CALL BSPROD ( FIFO, 3, U+.5*VVAL, U-.5*VVAL, XS(I),      15940   
     1             ISCTMN, 1, RP, RT, *264 )
               IF ( DABS(FIFO) .LE. WVWMAX )  GO TO 264
               WVWMAX = DABS(FIFO)
               UMAX = U
               VMAX = VVAL
               RPMAX = RP
               RTMAX = RT
 264        CONTINUE
 265     CONTINUE
         U = U + .20D0                                                  15950   
 269  CONTINUE
      TINTRP = TINTRP + second() - TIME1
      NINTRP = NINTRP + 10*N*(INADD+2)
      IF ( PINFSW )  write (6, 273) UMAX, VMAX, RPMAX, RTMAX, WVWMAX
 273  FORMAT ( '0MAX(RI PSI PHI V PHI PSI RO) OCCURS AT',
     1    ' SUM, DIF, RP, RT =', 4F8.2, 5X, 'VALUE =', G13.3 )
      RVRLIM = DWCUT*WVWMAX
      write(0,'(A,G15.5,A,G15.5,A,G15.5)')
     &  'FTN_WVWMAX=',WVWMAX,' DWCUT=',DWCUT,' RVRLIM=',RVRLIM
C
C     STEP OUT FROM  U = 0  LOOKING FOR SUMMIN.
C     WE LOOK FOR U SUCH THAT                                           15960   
C       PSI(LMIN) PHI' V PHI' PSI(LMIN)
C     EXCEEDS VZERO.
C
      USTEP = .20D0
      U = 0
      TIME1 = second()
 320     DO 324  I = 1, 2
            CALL BSPROD ( FIFO, 4, U, U, XS(I), ISCTMN, 1,
     1         RP, RT, *325 )
            IF ( DABS(FIFO) .GE. RVRLIM )  GO TO 330                    15970   
 324     CONTINUE
         NINTRP = NINTRP + 2*(INADD+2)
         U = U + USTEP
         GO TO 320
C
 325  write (6, 326)
 326  FORMAT ('0**** ASYMPTOPIA IS FAR TOO SMALL - CANNOT FIND',
     1  ' SUMMIN.' )
      U = U-USTEP
      IF ( SUMMIN .NE. UNDEF )  GO TO 330                               15980   
      IRTN = 0
      RETURN
C
C     SUMMIN FOUND, DO WE OVERRIDE IT
C
 330  TINTRP = TINTRP + second() - TIME1
      U = DMAX1( 0.D0, U-USTEP )
      IF ( SUMMIN .EQ. UNDEF )  SUMMIN = U
      IF ( PINFSW )  write (6, 333) U, SUMMIN
 333  FORMAT ( '0SUMMIN:  PROPOSED =', G14.5, 5X, 'USED =', G14.5 )     15990   
C
C     NOW FIND SUMMAX USING
C       PSI(L CRIT) PHI V PHI PSI(L CRIT)
C     AND COMPUTE MOMENTS OF THE WEIGHT FUNCTION.  NOTE THAT WE
C     MAKE SURE THAT WE DON'T STOP TOO SOON DUE TO SMALL RP OR RT.
C
      SUM0 = 0
      SUM1 = 0
      SUM2 = 0
      PVPMAX = 0                                                        16000   
      IF ( IPRNT .GE. 7 )  write (6, 347)
 347  FORMAT ( '0', 6X, 'U', 9X, 'SUM(F''S)', 6X, 'MAX(F)',
     1  5X, 'V OF MAX', 4X, 'RP OF MAX', 4X, 'RT OF MAX' / )
      U = SUMMIN
      ULIM = DMAX1( RSCTS(1)+10*ASCTS(1), ROFMAX+5 )
      TIME1 = second()
C
 350     TEMP = 0
         WVWMAX = 0
         ZEROSW = .TRUE.                                                16010   
C
C     WE LOOK AT 5 DIFFERENT V'S FOR EACH U
C     AT EACH U, V PAIR WE LOOK AT 2 X'S
C     FOR THIS SEARCH, VIOLATIONS OF BOUND-STATE ASYMPTOPIA ARE
C     IGNORED (TREATED AS ZERO) UNLESS ALL TEST POINTS ARE BAD.
C
         D = 2*(RLMAXS(2)-(S1+T1)*U)/(S1-T1)
         IF ( DABS(D) .GT. 2*U )  D = DSIGN(2*U, D)
         VS(1) = D
         VS(2) = .5*D                                                   16020   
         D = 2*(RLMAXS(1)-(S2+T2)*U)/(S2-T2)
         IF ( DABS(D) .GT. 2*U )  D = DSIGN(2*U, D)
         VS(4) = .5*D
         VS(5) = D
         DO 359  IV = 1, 5
            VVAL = VS(IV)
            DO 359  I = 1, 2
               CALL BSPROD ( FIFO, 3, U+.5*VVAL, U-.5*VVAL, XS(I),
     1             ISCTCR, 1, RP, RT, *359 )
               TEMP = TEMP + DABS(FIFO)                                 16030   
               IF ( WVWMAX .GT. DABS(FIFO) )  GO TO 359
               WVWMAX = DABS(FIFO)
               VMAX = VVAL
               RPMAX = RP
               RTMAX = RT
               ZEROSW = .FALSE.
 359     CONTINUE
         IF ( ZEROSW )  GO TO 375
         NINTRP = NINTRP + 10*(INADD+2)
         SUM0 = SUM0 + TEMP                                             16040   
         SUM1 = SUM1 + TEMP*U
         SUM2 = SUM2 + TEMP*U*U
         IF ( PVPMAX .GT. TEMP )  GO TO 364
         PVPMAX = TEMP
         UMAX = U
 364     IF (IPRNT .GE. 7)  write (6, 367) U, TEMP, WVWMAX, VMAX, RPMAX,
     1      RTMAX
 367     FORMAT ( 6G13.3 )
         IF ( WVWMAX .GE. RVRLIM  .OR.  U .LT. ULIM )  GO TO 365
         write(0,'(A,F8.3,A,E12.4,A,E12.4,A,2F8.3,A,2F8.3)')
     &     'FTN_SCAN U=',U,' WVM=',WVWMAX,' RVR=',RVRLIM,
     &     ' RP,RT=',RP,RT,' RLM=',RLMAXS(1),RLMAXS(2)
         IF ( RP .GT. RLMAXS(1)  .AND.  RT .GT. RLMAXS(2) )  GO TO 380  16050   
 365     U = U + USTEP
         GO TO 350
C
C     COMPLAIN IF ALL TEST POINTS FOR A GIVEN VALUE OF U ARE BEYOND
C     BOUND-STATE ASYMPTOPIA.
C
 375  write (6, 378)
 378  FORMAT ( '0**** WARNING:  SEARCH FOR SUMMAX WAS STOPPED',
     1   'BY THE BOUND STATE ASYMPTOPIA.' /
     2   '0**** IN FUTURE RUNS INCREASE ONE OR BOTH ASYMPTOPIA.' )      16060   
      U = U - USTEP
C
C     SUMMAX IS FOUND.
C
 380  TINTRP = TINTRP + second() - TIME1
      IF ( SUMMAX .EQ. UNDEF )  SUMMAX = U
      IF ( PINFSW )  write (6, 381) U, SUMMAX
 381  FORMAT ( ' SUMMAX:  PROPOSED =', G14.5, 5X, 'USED =', G14.5 )
      write(0,'(A,F10.4,A,F10.4,A,F10.4)')
     &  'FTN_SUMMAX proposed=',U,' used=',SUMMAX,' SUMMID=',SUMMID
C
C     COMPUTE SUMMID AS THE FIRST MOMENT OF U.                          16070   
C
      U = SUM1/SUM0
      SUM2 = SUM2/SUM0
      SUM2 = DSQRT(SUM2)
      IF ( SUMMID .EQ. UNDEF )  SUMMID = U*AMDMLT
      IF ( PINFSW )  write (6, 388) U, SUM2, UMAX, U, SUMMID
 388  FORMAT ( '0<SUM> =', G14.5, 5X, 'SQRT<SUM**2> =', G14.5,
     1  5X, 'SUM(MAX TERM) =', G14.5 /
     2  ' SUMMID:  PROPOSED =', G14.5, 5X, 'USED =', G14.5 )
C                                                                       16080   
C     ADJUST SUMMIN, SUMMID TO REQUIREMENTS OF CUBIC MAP.  THESE ARE
C     LIKELY TO BE REASONABLE CONDITIONS EVEN WHEN NOT USING CUBIC MAP
C
      SUMMIN = DMIN1( SUMMIN, 7.D0*(SUMMID-SUMMAX/7.D0)/6.D0 )
      SUMMID = DMIN1( SUMMID, .5*(SUMMIN+SUMMAX) )
      IF (PINFSW)  write (6,  393) SUMMIN, SUMMID, SUMMAX
  393 FORMAT ( ' FINAL CHOICE OF SUMMIN, SUMMID, SUMMAX =', 5G15.5 )
C
C     SUMMIN AND SUMMAX NOW KNOWN; PERFORM SINH MAP OF @SUMMIN,SUMMAX@
C     TO @-1,1@ ; COMPUTE AND STORE GAUSS-LEGENDRE PTS                  16090   
C        FOR BOTH THE H'S AND THE INTERPOLATED INTEGRAL GRID
C
 400  ISMHPT=NALLOC( NPSUM, 'SUMHPTS ' )
      ISMHWK=NALLOC( 3*NPSUM, 'SUMHWORK' )
C
C     THE NUMBER OF POINTS FOR THE INTERPOLATED INTEGRAL GRID
C     IS BASED ON THE WAVE-LENGTH
C
      NPSUMI = (SUMMAX-SUMMIN)*SUMPTS*(AKI+AKO)/(4*PI)
      NPSUMI = MAX0( NPSUMI, NPSUM )                                    16100   
      IF ( IHSAVE .NE. 2 )  NPLYSW = NPSUMI .EQ. NPSUM
      IF ( .NOT. NPLYSW  .OR.  NPSUM .EQ. NPSUMI )  GO TO 404
      write (6, 403) NPSUMI, NPSUM
 403  FORMAT ( '0**** WARNING:  NPSUMI WAS COMPUTED TO BE', I5 /
     1  6X, 'BUT DUE TO LIMITATIONS OF THE SAVEHS RUN',
     2    ' IT WILL BE LIMITED TO', I5 )
      NPSUMI = NPSUM
C
 404  ISMIPT = NALLOC( NPSUMI, 'SUMIPTS ' )
      ISMIVL = NALLOC( NPSUMI, 'SUMIVALS' )                             16110   
C     GENERATE GAUSS POINTS FOR U
      CALL CUBMAP ( MAPSUM,  SUMMIN, SUMMID, SUMMAX, GAMSUM,
     1  ALLOC(Z(ISMIPT)), ALLOC(Z(ISMIVL)), NPSUMI )
C
      NRIROI = NPSUMI*NPDIF
      N4RIO = (NRIROI+FACFR4-1)/FACFR4
      IWIO = NALLOC( N4RIO, 'RIROWTS ' )
      IRI = NALLOC( N4RIO, 'RIPTS   ' )
      IRO = NALLOC( N4RIO, 'ROPTS   ' )
      IDIFPT = NALLOC( NPDIF, 'DIFPTS  ' )                              16120   
      IDIFWT = NALLOC( NPDIF, 'DIFWTS  ' )
      NPOLSV = 3*NVPOLY+3
      IVPOLS = NALLOC( NPOLSV, 'VPOLYS  ' )
C
C     IF USING H'S, RESTORE GENERATED SUM POINTS AND POLYS
C
      IF ( IHSAVE .NE. 2 )  GO TO 405
      READ ( 1, END=9950, ERR=9950 )
     1  ( ALLOC(Z(IVPOLS)-1+I), I = 1, NPOLSV ),
     2  ( ALLOC(Z(ISMHPT)-1+I), I = 1, NPSUM )                          16130   
      II = 3*NPSUM
      IF ( NPLYSW )  READ ( 1, END=9950, ERR=9950 )
     1  ( ALLOC(Z(ISMHWK)-1+I), I = 1, II )
      GO TO 700
C
 405  CALL CUBMAP ( MAPSUM,  SUMMIN, SUMMID, SUMMAX, GAMSUM,
     1  ALLOC(Z(ISMHPT)), ALLOC(Z(ISMHWK)), NPSUM )
C
C
C     SETUP THE DIFFERENCE GRID.                                        16140   
C
C
C     THE STAGES ARE
C
C     1)  DETERMINE THE RANGE OF V FOR EACH VALUE OF U.
C
C     2)  INSIDE EACH V-RANGE, FIND THE MOMENTS OF V AND THUS
C         THE "MID-POINT".
C
C     3)  MAKE A LOW-DEGREE POLYNOMIAL FIT TO THE MID- AND END-         16150   
C         POINTS.  THIS POLY IS THEN USED TO PROVIDE CONTINUOUS
C         U-V CONTOURS.
C
C     4)  GENERATE ALL THE RI, RO PAIRS FOR FINDING H'S
C
C     5)  GENERATE ALL RI, RO PAIRS FOR THE INTERPOLATED INTEGRATION
C         GRID.
C
C     IN ALL THESE OPERATIONS WE DO NOT INCLUDE THE SCATTERING
C     WAVEFUNCTIONS SINCE  V << U  SO THAT RI, RO WILL VARY ONLY        16160   
C     A LITTLE FOR FIXED U.  THIS ASSUMPTION IS NOT NECESSARILY TRUE
C     FOR LIGHT IONS.
C
C     IN FINDING THE EXTREMA OF THE V'S, WE USE
C       PHI' V PHI'
C
      NRIROH = NPDIF*NPSUM
      IRIOEX = NALLOC( NRIROH, 'RIROEXPS' )
      IRIH = NALLOC( NRIROH, 'RIH     ' )
      IROH = NALLOC( NRIROH, 'ROH     ' )                               16170   
C     WORK AREAS FOR STAGE 3
      IVWORK = NALLOC( 4*NPSUM+3+(NVPOLY+1)**2, 'VPOLYWRK' )
      LVPOLS = Z(IVPOLS)
      LVWTS = Z(IVWORK)
      LVRESD = LVWTS+NPSUM
      LVSMSQ = LVRESD + 3*NPSUM
      LVAMAT = LVSMSQ + 3
      LVMIN=Z(ISMHWK)-1
      LVMID = LVMIN + NPSUM
      LVMAX = LVMID + NPSUM                                             16180   
      LRIH = Z(IRIH) - 1
      LROH = Z(IROH) - 1
      LRIOEX = Z(IRIOEX) - 1
      LDIFPT=Z(IDIFPT)-1
      LDIFWT=Z(IDIFWT)-1
      LSUMPT = Z(ISMHPT) - 1
C
C        STAGE 1)  END POINTS OF EACH V-RANGE.
C
      VMAX = 1                                                          16190   
      VMIN = 1
      NBUMPS = 0
      RPMAX = 0
      RTMAX = 0
      DV = 1.D0/LOOKST
C
      DO 489  IU=1,NPSUM
C
         U=ALLOC(LSUMPT+IU)
         VLEN=2.D0*U                                                    16200   
         IF ( U .LT. 1 )  GO TO 465
         VVAL=VMAX
         SYNE= +.5*VLEN
C
         TIME1 = second()
 420     VVAL = DMIN1( 1.D0, VVAL+3*DV )
 422        IF ( VVAL .LE. .5*DV )  GO TO 450
            RI=U+VVAL*SYNE
            RO=U-VVAL*SYNE
            ULIM = RVRLIM/DMAX1( 1.D-2, RI*RO )                         16210   
            DO 429  I = 1, 2
               CALL BSPROD ( FIFO, 2, RI, RO, XS(I), ISCTMN, 1, RP, RT,
     1           *435 )
               NINTRP=NINTRP+INADD
               IF ( DABS(FIFO) .GT. ULIM )  GO TO 450
 429        CONTINUE
 435        VVAL=VVAL-DV
            GO TO 422
C
 450     VVAL = DMIN1( 1.D0, VVAL+DV )                                  16220   
C
C     MAKE SURE THIS DESIRED VALUE OF V DOES NOT VIOLATE ASYMPTOPIA
C
C     BECAUSE  S1*T1 < 0  AND  S2*T2 < 0,  RP2 > RP1 AND
C     RT2 > RT1 ALWAYS.
C
         RI=U+VVAL*SYNE
         RO=U-VVAL*SYNE
         RT=DSQRT((S1*RI)**2+(T1*RO)**2+ST1*RI*RO*(1.D0-DXV))
         RP=DSQRT((S2*RI)**2+(T2*RO)**2+ST2*RI*RO*(1.D0-DXV))           16230   
         RTMAX = DMAX1( RTMAX, RT )
         RPMAX = DMAX1( RPMAX, RP )
         IF ( RT .LE. BNDMXT  .AND. RP .LE. BNDMXP )  GO TO 455
C
C     CANNOT USE DESIRED VALUE
C
         NBUMPS = NBUMPS + 1
         VVAL = VVAL - DV
C
 455     IF(SYNE .GT. 0) VMAX=VVAL                                      16240   
         IF(SYNE .LT. 0 ) VMIN=VVAL
         IF(SYNE .LT. 0 ) GO TO 460
         VVAL=VMIN
         SYNE=-SYNE
         GO TO 420
C
460      TINTRP = TINTRP + second() - TIME1
C
C     COME HERE IF U < 1.
C                                                                       16250   
 465     IF ( PGRDSW )  write (6, 468 ) U, VMIN, VMAX,
     1     RP, RT, FIFO
 468     FORMAT ( ' U VMIN VMAX =', 8G13.5 )
C     THESE ARE EXTREMA OF V=DIF FOR EACH POINT IN THE U=SUM GRID.
         ALLOC(LVMIN+IU) = -VMIN*VLEN
         ALLOC(LVMAX+IU) = VMAX*VLEN
C
C     CHECK FOR RANGES CONTRACTED TO ZERO BY ASYMPTOPIA LIMITATIONS
C
         VVAL = 2*U*(VMIN+VMAX)                                         16260   
         IF ( VVAL .LT. .1*DV*U )  write (6, 473) U, VVAL
 473     FORMAT ( '0**** ERROR:  THE DIF GRID RANGE FOR SUM =', F8.2,
     1     ' IS ESSENTIALLY ZERO DUE TO BOUND STATE ASYMPTOPIA ',
     2     'LIMITATIONS; RANGE =', G13.3 /
     3     ' **** IN FUTURE RUNS ASYMPTOPIA MUST BE INCREASED.' )
C
 489  CONTINUE
C
C     END OF IU (SUM) LOOP
C                                                                       16270   
      IF ( NBUMPS .NE. 0 )  write (6, 493) NBUMPS
 493  FORMAT ('0**** WARNING:  SEARCH FOR THE DIF GRIDS WAS STOPPED',
     1  I4, ' TIMES BY BOUND STATE ASYMPTOPIA.' )
      IF ( NBUMPS .NE. 0 )  write (6, 897) RPMAX, RTMAX
C
C     STAGE 2)  FIND V-MOMENTS OF THE WEIGHT FUNC. FOR EACH VALUE OF U
C     FOR EACH U, VMID IS
C     DETERMINED AS THE POINT AT WHICH <PHI@V@PHI> IS MAXIMUM.
C
      IF ( PGRDSW )  write (6, 503)                                     16280   
 503  FORMAT ('0 IU', 8X, 'U', 11X, 'VMIN', 10X, 'VMID', 10X, 'VMAX',
     1  9X, 'V(MAX)', 9X, 'PVPMAX',
     1  11X, '<V>', 9X, '<V**2>', 8X, '<V VAR>' )
C
      DO 559   IU = 1, NPSUM
         U = ALLOC(LSUMPT+IU)
         VMIN = ALLOC(LVMIN+IU)
         VMAX =  ALLOC(LVMAX+IU)
         ALLOC(LVWTS-1+IU) = 1/(VMAX-VMIN)**2
         IMAX = 2*NPDIF                                                 16290   
         DV = (VMAX-VMIN)/(IMAX+1)
         VVAL = VMIN
         PVPMAX = 0
         SUM0 = 0
         SUM1 = 0
         SUM2 = 0
         DO 539  IV = 1, IMAX
            VVAL = VVAL + DV
            RI = U + .5*VVAL
            RO = U - .5*VVAL                                            16300   
            TEMP = 0
            DO 529  I = 1, 2
               CALL BSPROD ( FIFO, 1, RI, RO, XS(I), ISCTCR, 1, RP, RT,
     1           *539 )
               NINTRP=NINTRP+INADD
               TEMP = DABS(FIFO) + TEMP
 529        CONTINUE
            SUM0 = SUM0 + TEMP
            SUM1 = SUM1 + TEMP*VVAL
            SUM2 = SUM2 + TEMP*VVAL*VVAL                                16310   
            IF ( TEMP .LE. PVPMAX )  GO TO 539
            PVPMAX = TEMP
            VOFMAX = VVAL
 539     CONTINUE
C
         SUM1 = SUM1/SUM0
         SUM2 = SUM2/SUM0
         SUM0 = DSQRT(SUM2-SUM1**2)
         SUM2 = DSQRT(SUM2)
C                                                                       16320   
C     DO NOT ALLOW VMID TO BE TOO CLOSE TO AN EDGE
C
         VMID = VOFMAX
         TEMP = .3*(VMAX-VMIN)
         VMID = DMIN1( DMAX1( VMID, VMIN+TEMP ), VMAX-TEMP )
         IF ( PGRDSW )  write (6, 553) IU, U, VMIN, VMID, VMAX, VOFMAX,
     1      PVPMAX, SUM1, SUM2, SUM0
 553     FORMAT ( I4, 9G14.4 )
C
C     STORE VMID AS THE RELATIVE DISTANCE ACROSS THE RANGE.             16330   
C     THIS WILL IMPROVE THE POLYNOMIAL FIT
C
         VMID = (VMID-VMIN)/(VMAX-VMIN)
         ALLOC(LVMID+IU) = VMID
 559  CONTINUE
C
C     END OF IU (SUM) LOOP
C
C     STAGE 3)  FIND THE POLYNOMIAL FITS
C                                                                       16340   
C     THE POLYNOMIALS ARE ALWAYS GENERATED BUT ARE NOT USED IF
C     NPSUMI = NPSUM.
C
      NVTERM = NVPOLY+1
      CALL LSQPOL ( ALLOC(LSUMPT+1), ALLOC(LVMIN+1), ALLOC(LVWTS),
     1  ALLOC(LVRESD), NPSUM, ALLOC(LVSMSQ), 3, ALLOC(LVAMAT),
     2  ALLOC(LVPOLS), NVTERM, NPSUM, NVTERM )
C
      IF ( PINFSW )  write (6, 573) NVPOLY, ((ALLOC(LVPOLS+N-1+
     1  NVTERM*(I-1)), I = 1,3), N = 1, NVTERM)                         16350   
 573  FORMAT ( / '0', I2, '-DEGREE POLYNOMIAL FITS TO DIF RANGES:' /
     1  '0', 7X, 'V LO', 11X, 'V MID', 10X, 'V HI' /
     2  (3G15.5) )
      IF ( PGRDSW )  write (6, 574)
 574  FORMAT ( '0', 7X, 'U', 14X, 'V LO', 5X, 'RESID', 15X,
     1  'V MID', 5X, 'RESID', 15X, 'V HI', 5X, 'RESID' / )
C
      VRNGMX = 0
      VRNGMN = BIGNUM
      VMAXMX = 0                                                        16360   
      DO 589  IU = 1, NPSUM
         IF ( NPLYSW )  GO TO 585
         DO 584  I = 1, 3
            ALLOC(LVMIN+(I-1)*NPSUM+IU) = ALLOC(LVMIN+(I-1)*NPSUM+IU)
     1        +ALLOC(LVRESD-1+(I-1)*NPSUM+IU)
 584     CONTINUE
C
 585     VMIN = ALLOC(LVMIN+IU)
         VMAX = ALLOC(LVMAX+IU)
         VMID = (VMAX-VMIN)*ALLOC(LVMID+IU) + VMIN                      16370   
         ALLOC(LVMID+IU) = VMID
         IF ( PGRDSW )  write (6, 587) ALLOC(LSUMPT+IU),
     1      (ALLOC(LVMIN+(I-1)*NPSUM+IU),
     2        ALLOC(LVRESD-1+(I-1)*NPSUM+IU), I = 1, 3)
 587     FORMAT ( G14.4, 3( 3X, G14.4, G12.2 ) )
         VRNGMX = DMAX1( VRNGMX, VMAX-VMIN )
         VRNGMN = DMIN1( VRNGMN, VMAX-VMIN )
         VMAXMX = DMAX1( VMAXMX, VMAX, -VMIN )
         TEMP = .2*(VMAX-VMIN)
         IF ( VMIN .GT. VMID-TEMP  .OR.  VMAX .LT. VMID+TEMP )          16380   
     1       write (6, 588) VMIN, VMID, VMAX
 588     FORMAT ( ' **** INVALID VMIN, VMID, VMAX:', 3G15.5 )
  589 CONTINUE
C
C     4)  GENERATE THE POINTS
C
C     FOR RECTANGULAR GRIDS EXPAND THE V-RANGE.
C
      IF ( IRECT .EQ. 1 )  VRNGMX = 2.*VMAXMX
      IF ( IRECT .EQ. 1 )  VRNGMN = VRNGMX                              16390   
C
      DO 689 IU=1,NPSUM
C
         U=ALLOC(LSUMPT+IU)
         VMIN=ALLOC(LVMIN+IU)
         VMAX=ALLOC(LVMAX+IU)
         VMID = ALLOC(LVMID+IU)
         IF ( IRECT .NE. 1 )  GO TO 620
         VMAX = .5*VRNGMX
         VMIN = -VMAX                                                   16400   
         VMID = 0
C
C     MAKE SURE THE FINAL V RANGES ARE LEGAL.
C
 620     IF ( VMIN .LT. -2*U  .OR.  VMAX .GT. 2*U )
     1      write (6, 623) IU, U, VMIN, VMAX
 623     FORMAT ( '0*** ILLEGAL VMIN OR VMAX:', I3, 3G15.5 /
     1      ' *** VALUES SET TO MAXIMUM ALLOWED.' )
C
         VMIN = DMAX1( VMIN, -2*U )                                     16410   
         VMAX = DMIN1( VMAX, 2*U )
         TEMP = .3*(VMAX-VMIN)
         VMID = DMIN1( DMAX1( VMID, VMIN+TEMP ), VMAX-TEMP )
C
         SYNE=1
         IF(VMID.LE.(.5*(VMAX+VMIN))) GO TO 630
         VMID=-VMID
         TEMP=VMAX
         VMAX=-VMIN
         VMIN=-TEMP                                                     16420   
         SYNE=-1
C
 630     CALL CUBMAP (MAPDIF, VMIN, VMID, VMAX, GAMDIF, ALLOC(LDIFPT+1),
     1      ALLOC(LDIFWT+1), NPDIF )
C
         DO 689 IV=1,NPDIF
C
            IPLUNK = IV - 1
            IF ( SYNE .LT. 0 )  IPLUNK = NPDIF - IV
            IPLUNK = NPSUM*IPLUNK + IU                                  16430   
            VVAL=ALLOC(LDIFPT+IV)
            RI=U+.5*VVAL*SYNE
            RO=U-.5*VVAL*SYNE
            ALLOC(LRIH+IPLUNK)=RI
            ALLOC(LROH+IPLUNK)=RO
C
C     WE REMOVE A FACTOR
C        EXP( -(ALPHAP*RP' + ALPHAT*RT') )
C     FROM THE H'S FOR INTERPOLATION.  RP' AND RT' ARE RP AND RT
C     WITH THE ABSOLUTE VALUE SINGULARITY REMOVED.                      16440   
C
            RP = SQRT( 1 + (S1*RI+T1*RO)**2 )
            RT = SQRT( 1 + (S2*RI+T2*RO)**2 )
            ALLOC(LRIOEX+IPLUNK) = EXP( ALPHAP*RP + ALPHAT*RT )
C
 689  CONTINUE
C
C     DONE WITH U AND V GAUSS PARAMETERS; FREE THEM
C
      Z(IVWORK) = -Z(IVWORK)                                            16450   
      Z(ISCTMN) = -Z(ISCTMN)
      Z(ISCTCR) = -Z(ISCTCR)
C
C
C     5)  GENERATE THE POINTS FOR THE INTERPOLATED INTEGRAL GRID
C         COMPUTE THE AREA OF THE INTEGRATION REGION
C
 700  AREA = 0
      LVPOLS = Z(IVPOLS) - 1
      LSMIVL = Z(ISMIVL) - 1                                            16460   
      LSUMPT = Z(ISMIPT) - 1
      LWIO = FACFR4*Z(IWIO) - FACFR4
      LRI = FACFR4*Z(IRI) - FACFR4
      LRO=FACFR4*Z(IRO)-FACFR4
      LVMIN = Z(ISMHWK) - 1
C
C     ALSO FIND THE MAX RI AND RO THAT WILL BE REQUIRED OF WAVELJ
C
      RIMAX = 0
      ROMAX = 0                                                         16470   
      LDIFPT=Z(IDIFPT)-1
      LDIFWT=Z(IDIFWT)-1
C
      DO 749  IU = 1, NPSUMI
         WOW = ALLOC(LSMIVL+IU)
         U = ALLOC(LSUMPT+IU)
C
C     EVALUATE THE POLYNOMIAL-DETERMINED RANGES
C
         ITEMP = LVPOLS                                                 16480   
         DO 709  I = 1, 3
C
C     ARE WE USING POLYNOMIALS OR JUST COPYING THE H-POINTS
C
            VRANGE(I) = ALLOC(LVMIN+(I-1)*NPSUM+IU)
            IF ( NPLYSW )  GO TO 709
            ITEMP = ITEMP + NVPOLY + 1
            VRANGE(I) = ALLOC(ITEMP)
            DO 704  N = 1, NVPOLY
               VRANGE(I) = ALLOC(ITEMP-N) + U*VRANGE(I)                 16490   
 704        CONTINUE
 709     CONTINUE
         VMIN = VRANGE(1)
         VMID = VRANGE(2)
         VMAX = VRANGE(3)
         IF ( NPLYSW )  GO TO 715
         VMID = (VMAX-VMIN)*VMID + VMIN
 715     IF ( IRECT .NE. 1 )  GO TO 720
         VMAX = .5*VRNGMX
         VMIN = -VMAX                                                   16500   
         VMID = 0
C
 720     IF ( VMIN .LT. -2*U  .OR.  VMAX .GT. 2*U )
     1      write (6, 723) IU, U, VMIN, VMAX
 723     FORMAT ( '0*** ILLEGAL INTERPOLATED VMIN OR VMAX:', I4,
     1      3G15.5 /
     2      ' *** VALUES SET TO MAXIMUM ALLOWED.' )
C
         AREA = AREA + WOW*(VMAX-VMIN)
         VMIN = DMAX1( VMIN, -2.*U )                                    16510   
         VMAX = DMIN1( VMAX, 2.*U )
         TEMP = .3*( VMAX - VMIN )
         VMID = DMIN1( DMAX1( VMID, VMIN+TEMP ), VMAX-TEMP )
         SYNE=1
         IF(VMID.LE.(.5*(VMAX+VMIN))) GO TO 730
         VMID=-VMID
         TEMP=VMAX
         VMAX=-VMIN
         VMIN=-TEMP
         SYNE=-1                                                        16520   
C
 730     CALL CUBMAP (MAPDIF, VMIN, VMID, VMAX, GAMDIF, ALLOC(LDIFPT+1),
     1      ALLOC(LDIFWT+1), NPDIF )
C
         DO 749 IV=1,NPDIF
C
            IPLUNK = IV - 1
            IF ( SYNE .LT. 0 )  IPLUNK = NPDIF - IV
            IPLUNK = NPSUMI*IPLUNK + IU
            VVAL=ALLOC(LDIFPT+IV)                                       16530   
            RI=U+.5*VVAL*SYNE
            RO=U-.5*VVAL*SYNE
            RIMAX = DMAX1( RIMAX, RI )
            ROMAX = DMAX1( ROMAX, RO )
            ALLOC4(LRI+IPLUNK)=RI
            ALLOC4(LRO+IPLUNK)=RO
C
C     HERE WE MAKE THE EXP FACTORS TO PUT BACK IN AFTER INTERPOLATION
C
            RP = DSQRT( 1 + (S1*RI+T1*RO)**2 )                          16540   
            RT = DSQRT( 1 + (S2*RI+T2*RO)**2 )
            TEMP = DEXP( -(ALPHAP*RP + ALPHAT*RT ) )
C
C     "RIROWTS" CONTAINS ALL WEIGHTING FACTORS FOR THE RI,RO
C     INTEGRATION, INCLUDING THE SUM AND DIF GAUSS WEIGHTS,
C     RI, RO, THE JACOBIAN, AND THE EXPONENTIAL FACTOR.
C
            ALLOC4(LWIO+IPLUNK) = JACOB*RI*RO*WOW*ALLOC(LDIFWT+IV)*TEMP
C
 749  CONTINUE                                                          16550   
C
      Z(IDIFPT) = -Z(IDIFPT)
      Z(IDIFWT) = -Z(IDIFWT)
      Z(ISMIVL) = -Z(ISMIVL)
C
      IF (PINFSW)  write (6, 753 ) RIMAX, ROMAX
 753  FORMAT ( ' MAXIMUM RI AND RO:', 2G15.5 )
C
C     IF WAVEFUNCTIONS ARE NEEDED BEYOND ASYMPTOPIA,
C     MUST EXPAND THE WORK AREA NOW.                                    16560   
C
      NSTP2S(1) = RIMAX/RSTEPS(1) + 3.5
      NSTP2S(2) = ROMAX/RSTEPS(2) + 3.5
      I = MAX0( NSTP2S(1), NSTP2S(2) ) + 6
      IF ( I .LE. NWAVEF )   GO TO 800
      NWAVEF = I
      IF ( TCSWS(1) .OR. TCSWS(2) ) I = 4*I
      IWAVR = NALLOC( I, 'WAVER   ' )
      IWAVI = NALLOC( I, 'WAVEI   ' )
C                                                                       16570   
C     THE SUM, DIF GRIDS ARE SET UP.
C     THE PHI GRID IS NOT NEEDED FOR USEHS RUNS.
C
 800  IF ( IHSAVE .EQ. 2 )  GO TO 900
C
C
C     FIND ALL THE PRODUCTS OF THE BOUNDSTATES AND V ON THE
C     (RI, RO, PHI) GRID.
C
C                                                                       16580   
C     TWO PASSES OVER (RI,RO)
C     FIRST TIME ; FIND AND STORE END-PTS X0(RI,RO) FOR PHI-INTEGRALS
C     SECOND ; COMPUTE AND STORE BOUND STATE PRODUCTS
C
C
C     "LOGIC" WILL CONTAIN THE NUMBER OF POINTS FOR WHICH THE
C     INTEGRAND IS BIG ENOUGH.
C
      INEED=NRIROH/FACFR4+1
      LOGIC=NALLOC( INEED, 'LOGIC   ' )                                 16590   
C
C     FIRST PASS; SET PHI-INTEGRATION LIMITS
C
      IXTOPZ = LOOKST + 1
      DXV = 2.D0/LOOKST**2
      NNAIT = 2
      IBSTYP = 2
      PAS1SW = .TRUE.
      X0MIN = 1
      X0AV = 0                                                          16600   
C
C     SETUP GAUSS-LEGENDRE POINTS, MAPPED AND SCALED TO (0,1).
C
      IPHIPT = NALLOC( NPPHI, 'PHIPTS  ' )
      IPHIWT = NALLOC( NPPHI, 'PHIWTS  ' )
      PHIMID = DMAX1( PHIMID, 0.10D0 )
      PHIMID = DMIN1( PHIMID, 0.90D0 )
      GAMPHI = DMAX1( GAMPHI, 1.D-6 )
      CALL CUBMAP ( MAPPHI, 0.D0, PHIMID, 1.D0, GAMPHI,
     1   ALLOC(Z(IPHIPT)), ALLOC(Z(IPHIWT)), NPPHI )                    16610   
C
C     COME BACK HERE TO START PASS 2.
C
 810  JCNT = 0
      RTMAX = 0
      RPMAX = 0
      NBUMPS = 0
      LLOGIC = FACFR4*Z(LOGIC)-FACFR4
      LPHIPT = Z(IPHIPT)-1
      LPHIWT = Z(IPHIWT)-1                                              16620   
      LRIH = Z(IRIH) - 1
      LROH = Z(IROH) - 1
C
C     LOOP THROUGH ALL RI, RO COMBINATIONS.
C
      DO  869 IPLUNK = 1,NRIROH
         RI=ALLOC(LRIH+IPLUNK)
         RO = ALLOC(LROH+IPLUNK)
         ULIM = RVRLIM / ( DMAX1(1.D0, RI) * DMAX1(1.D0, RO) )
         IF ( PAS1SW )  GO TO  820                                      16630   
C
C     PASS 2:  SET UP END POINT.
C     WE ALWAYS INTEGRATE AT LEAST TO THE SECOND TEST POINT.
C
         IEND = ILLOC(LLOGIC+IPLUNK)
         IEND = MAX0( IEND, 2 )
         X0 = 1.D0-DXV*(IEND-1)**2
         PHI0 = acos( X0 )
C
  820    IF (PAS1SW)  TIME1 = second()                                  16640   
C
C     LOOP THROUGH PHI TEST POINTS (PASS 1) OR GAUSS POINTS (PASS 2).
C
         DO  859 II=1, IXTOPZ
C
            X = 1.D0 - DXV*(II-1)**2
            IF ( PAS1SW )  GO TO  825
C
C     PASS 2:  GET GAUSS POINT AND WEIGHT.
C                                                                       16650   
            PHI = PHI0*ALLOC(LPHIPT+II)
            DPHI = PHI0*ALLOC(LPHIWT+II)*DSIN( PHI )
            X = DCOS( PHI )
C
C     CALCULATE BOUND-STATE PRODUCT.
C
 825        NBUMPS = NBUMPS + 1
            CALL BSPROD ( FIFO, IBSTYP, RI, RO, X, ISCTMN, NNAIT,
     1         RP, RT, *830 )
            NBUMPS = NBUMPS - 1                                         16660   
            NINTRP = NINTRP + INADD
 830        RTMAX = DMAX1( RTMAX, RT )
            RPMAX = DMAX1( RPMAX, RP )
            IF ( PAS1SW )  GO TO  840
C
C     PASS 2:  KEEP PHIT, PHIP, PHI, AND WEIGHTED B. S. PRODUCT.
C
            JCNT = JCNT + 1
            TEMP = (T1*RO + S1*RI*X)/RT
            ALLOC4(LPHIT+JCNT) = PHISGN*acos(TEMP)                      16670   
            TEMP = (T2*RO + S2*RI*X)/RP
            ALLOC4(LPHIP+JCNT) = PHISGN*acos(TEMP)
            ALLOC4(LPHI+JCNT) = PHI
            ALLOC4(LTRP+JCNT) = DPHI*FIFO
            RTMAX = DMAX1( RTMAX, RT )
            RPMAX = DMAX1( RPMAX, RP )
            GO TO  859
C
C     PASS 1, FINDING X0
C                                                                       16680   
  840       FIFO = DABS(FIFO)
            IF ( II .EQ. 1 )  GO TO  845
            IF ( FIFO .LT. ULIM  .AND.  WOW .LT. ULIM )  GO TO  865
  845       WOW = FIFO
C
  859    CONTINUE
C
C     END OF LOOP THROUGH PHI TEST OR GAUSS POINTS.
C
         IF ( PAS1SW )  GO TO  864                                      16690   
C
C     PASS 2:  DUMP WEIGHTED B. S. PRODUCT IF REQUIRED.
C
         N = JCNT - NPPHI + 1
         IF ( IPRNT .GE. 9 )  write (6, 863) RI, RO, PHI0,
     &      ( ALLOC4(LTRP+I), I = N, JCNT )
 863     FORMAT ( 1X, 2F7.2, F7.4, (T24, 1P 13G9.1) )
C
C     PASS 2:  WRITE THE "PHIANG", "PHIANG1", "PHIANG2", AND "FIFODX"
C     ARRAYS ON THE SCRATCH FILE IF REQUIRED.                           16700   
C
         IF ( ISCRFL .EQ. 0 )  GO TO 869
CVA         CALL WRITSC ( NPPHI, ALLOC4(LPHI+1), ALLOC4(LPHIP+1),
CVA     1      ALLOC4(LPHIT+1), ALLOC4(LTRP+1), *874 )
         WRITE ( 2, ERR=874 )                                           cnv
     1      ( ALLOC4(LPHI+I), I = 1, NPPHI ),                           cnv
     2      ( ALLOC4(LPHIP+I), I = 1, NPPHI ),                          cnv
     3      ( ALLOC4(LPHIT+I), I = 1, NPPHI ),                          cnv
     4      ( ALLOC4(LTRP+I), I = 1, NPPHI )                            cnv
         JCNT = 0                                                       16710   
         GO TO 869
C
 864     II = LOOKST + 2
 865     TINTRP = TINTRP + second() - TIME1
         IEND = MIN0 ( II  - 1 + NPHIAD, IXTOPZ )
C
C     NOTE:  ADDING NPHIAD CAN RESULT IN PHI'S THAT GIVE RP'S AND RT'S
C     THAT ARE OUT OF BOUNDS.  WE COULD CHECK FOR THAT HERE BUT INSTEAD
C     WE LET THEM GET CAUGHT ON PASS 2 AND SUBSTITUTE 0'S.
C                                                                       16720   
         ILLOC(LLOGIC+IPLUNK) = IEND
         IF ( IEND .NE. 1 )  JCNT = JCNT + NPPHI
         X0 = 1.D0 - DXV*(IEND-1)**2
         X0MIN = DMIN1( X0MIN, X0 )
         X0AV = X0AV + X0
C
 869  CONTINUE
C
C     END OF LOOP THROUGH RI, RO COMBINATIONS.
C                                                                       16730   
      IF ( .NOT. PAS1SW )  GO TO  890
C
C     END OF PASS 1 - ALLOCATE SPACE AND SETUP FOR PASS 2
C
      IF ( NBUMPS .NE. 0 )  write (6,  873) NBUMPS
  873 FORMAT (' **** WARNING:  IN THE PHI-GRID SEARCHES', I8,
     1  ' BOUND STATE WAVEFUNCTIONS WERE NEEDED BEYOND THE',
     2  ' BOUND STATE ASYMPTOPIA.' )
      IF ( NBUMPS .NE. 0 )  write (6, 897) RPMAX, RTMAX
C                                                                       16740   
C     OPEN THE SCRATCH FILE IF REQUIRED.
C
CVA      NBLKSZ = ( (NBLKSZ+511)/512 )*512
CVA      IF ( ISCRFL .NE. 0  .AND.  IBSPAS .LE. 1 )
CVA     1   OPEN ( UNIT = 2, TYPE = 'SCRATCH',
CVA     2   BLOCKSIZE = NBLKSZ, FORM = 'UNFORMATTED',
CVA     3   INITIALSIZE = (16*JCNT+2*NRIROH+NBLKSZ)/NBLKSZ,
CVA     4   ERR = 874 )
C
      GO TO 876                                                         16750   
CVAC
CVAC     SCRATCH FILE ERROR.
CVAC
 874  write (6, 875)
 875  FORMAT ( '0**** ERROR IN OPENING OR WRITING SCRATCH FILE.' /
     1   ' **** ARRAYS WILL BE KEPT IN MEMORY IF POSSIBLE.' )
      ISCRFL = 0
C
C     THE SIZE OF THESE FOUR ARRAYS MAY BE DRASTICALLY REDUCED IF A
C     SCRATCH FILE IS USED (KEYWORD "SCRFILE").                         16760   
C
 876  JSIZE = (JCNT+FACFR4-1)/FACFR4
      IF ( ISCRFL .NE. 0 )  JSIZE = (NPPHI+FACFR4-1)/FACFR4
      LOCTRP = NALLOC(  JSIZE , 'FIFODX  ' )
      IPHIT = NALLOC(  JSIZE , 'PHIANG1 ' )
      IPHIP = NALLOC(  JSIZE , 'PHIANG2 ' )
      IPHI = NALLOC(  JSIZE , 'PHIANG  ' )
      MAXCNT = JCNT
      X0AV = X0AV/NRIROH
C                                                                       16770   
      IF ( IPRNT .GE. 9 )  write (6, 878)
 878  FORMAT ( '1', 4X, 'RI', 5X, 'RO', 15X,
     1   'PHI V PHI  AT EACH X' / )
C
      LPHIT = FACFR4*Z(IPHIT) - FACFR4
      LPHIP = FACFR4*Z(IPHIP) - FACFR4
      LPHI = FACFR4*Z(IPHI) - FACFR4
      LTRP = FACFR4*Z(LOCTRP) - FACFR4
      IXTOPZ = NPPHI
      NNAIT = NAITKN                                                    16780   
      IBSTYP = 1
      INADD = 0
      PAS1SW = .FALSE.
C
C     GO START PASS 2.
C
      GO TO 810
C
C     END OF PASS 2.  CHECK FOR ASYMPTOPIA OVERRUNS.
C                                                                       16790   
 890  IF ( NBUMPS .NE. 0 )  write (6,  893) NBUMPS
  893 FORMAT (' **** ERROR:', I8,
     1  ' BOUND STATE WAVEFUNCTIONS WERE NEEDED BEYOND THE',
     2  ' BOUND STATE ASYMPTOPIA.' )
      IF ( NBUMPS .NE. 0 )  write (6, 897) RPMAX, RTMAX
 897  FORMAT ( ' **** IN FUTURE RUNS INCREASE ASYMPTOPIA TO MORE THAN:',
     1  F15.2, ' (PROJECTILE)', F15.2, ' (TARGET)' )
C
C     BOUND STATE PRODUCTS HAVE BEEN COMPUTED AND STORED.
C                                                                       16800   
      IF ( IBSPAS .EQ. 0 )  Z(IBDS(1)) = -Z(IBDS(1))
      IF ( IBSPAS .EQ. 0 )  Z(IBDS(2)) = -Z(IBDS(2))
      Z(IPHIPT) = -Z(IPHIPT)
      Z(IPHIWT) = -Z(IPHIWT)
      IF ( NUCONL .GE. 2  .AND.  IBSPAS .EQ. 0 )  Z(JPOT) = -Z(JPOT)
      I = NAMLOC( 'VPHI    ' )
      Z(I) = -Z(I)
      Z(LOGIC) = -Z(LOGIC)
      IF ( ISCRFL .NE. 0 )  REWIND 2
C                                                                       16810   
C
C     PRINT IT NICELY
C
 900  IF ( .NOT. PRNTSW )  GO TO 950
C
      write (6, 903) NPSUMI, MAPSUM, GAMSUM, SUMMIN, SUMMID, SUMMAX,
     1  NPSUM, NPDIF, MAPDIF, GAMDIF, VRNGMN, VRNGMX,
     2  NPPHI, MAPPHI, GAMPHI, NPHIAD, X0MIN, X0AV, PHIMID
 903  FORMAT ( // '0', 12X, ' SUMMARY OF THE INTEGRATION GRIDS' /
     1  '0', 9X, 'NUM. PTS.   MAP TYPE   GAMMA    MINIMUM',             16820   
     2      '   "MID. PT."   MAXIMUM' /
     3  ' (RI+RO)/2:', I5, I11, F11.2, F10.2, 2F11.2 ,
     4   5X, '(H''S FOUND AT', I4, ' (RI+RO)/2 VALUES)' /
     4  '0', 40X, 'MIN. WIDTH   MAX. WIDTH' /
     5  ' RI-RO:', I9, I11, F11.2, F11.3, F13.3 /
     6  '0', 42X, 'NPHIADD    MIN. START   AV. START     PHIMID' /
     7  ' COS(PHI):', I6, I11, F11.2, I9, F16.5, F12.5, F12.4 )
C
      IF ( IRECT .EQ. 1 )  write (6, 908)
 908  FORMAT ( '0"SW3ON" WAS SPECIFIED:  (RI,RO) GRID IS RECTANGULAR.') 16830   
      write (6, 913) DWCUT, RPMAX, RTMAX, RIMAX, ROMAX
 913  FORMAT ( '0DWCUTOFF =', 1P G12.2, 0P /
     1  ' MAXIMUM R''S USED FOR BOUND STATES:  PROJECTILE =',
     2    F5.1, 5X, 'TARGET =', F5.1 /
     3  ' MAXIMUM R''S USED FOR SCATTERING STATES:  INCOMING =',
     4    F5.1, 5X, 'OUTGOING =', F5.1 )
C
      write (6, 933) NRIROH, MAXCNT, NRIROI, AREA
 933  FORMAT ( '0THERE ARE', I6, ' POINTS IN THE (RI, RO) GRID',
     1    ' ON WHICH THE H''S ARE FOUND, ',                             16840   
     1    ' AND', I8, ' POINTS IN THE COMPLETE 3-D GRID.'  /
     2  ' THERE ARE', I6, ' POINTS IN THE (RI, RO) INTERPOLATED',
     3    ' INTEGRATION GRID.' /
     2  ' AREA OF  SUM X DIF  INTEGRATION REGION =',
     3     F9.3, ' FM**2.' / )
C
C     IF SAVING H'S, SAVE THE (RI, RO) GRID STUFF
C
 950  IF ( IHSAVE .NE. 1 )  GO TO 1000
      TEMP = 0                                                          16850   
      ITEMP = 0
      WRITE ( 1, ERR=9950 )  NPSUM, NPDIF, NPPHI,
     2    MAXCNT, JSIZE, GAMSUM, SUMMIN, SUMMID, SUMMAX,
     3    GAMDIF, VRNGMN, VRNGMX, X0MIN, X0AV, RPMAX, RTMAX,
     4    NRIROH, ALPHAP, ALPHAT, AREA, WVWMAX, NPLYSW,
     5    ITEMP, TEMP, TEMP, TEMP
      WRITE ( 1, ERR=9950 )
     1  ( ALLOC(Z(IVPOLS)-1+I), I = 1, NPOLSV ),
     2  ( ALLOC(Z(ISMHPT)-1+I), I = 1, NPSUM ),
     2  ( ALLOC(Z(IRIOEX)-1+I), I = 1, NRIROH ),                        16860   
     2  ( ALLOC(Z(IRIH)-1+I), I = 1, NRIROH ),
     3  ( ALLOC(Z(IROH)-1+I), I = 1, NRIROH )
      II = 3*NPSUM
      IF ( NPLYSW )  WRITE ( 1, ERR=9950 )
     1  ( ALLOC(Z(ISMHWK)-1+I), I = 1, II )
C
 1000 IRTN = 1
      Z(IVPOLS) = -Z(IVPOLS)
      IF ( IHSAVE .EQ. 2 )  GO TO 1100
      Z(IRIH) = -Z(IRIH)                                                16870   
      Z(IROH) = -Z(IROH)
C
C     FIX DWCUT FOR SAVEHS TO BE SURE STUFF IS AVAILABLE FOR USEHS
C
 1100 TEMP = DWCUT
      IF ( IHSAVE .EQ. 1 )  TEMP = DMIN1( 1.D-30, DWCUT )
      RVRLIM = WVWMAX*TEMP
C
C     PRINT SOME TIMING INFO.
C                                                                       16880   
      IF ( IHSAVE .EQ. 2  .OR.  .NOT. PINFSW )  RETURN
C
      WOW = second() - TSTART
      TEMP = WOW - TINTRP
      U = 1000.*TINTRP/NINTRP
      write (6, 9903) TINTRP, TEMP, WOW, NINTRP, U
 9903 FORMAT ('0        END OF GRID INITIALIZATION' /
     1  '0ROUGH INTERPOLATION TIME FOR GRID SEARCHING:',
     2      T54, F7.3, ' SECONDS' /
     3  ' OTHER TIME (INCLUDES FINAL INTERPOLATIONS):',                 16890   
     4      T54, F7.3, ' SECONDS' /
     5  ' TOTAL TIME:', T54, F7.3, ' SECONDS' /
