C
C - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - -
C                                                                       17390   
CDC%';DATA' = ';INITDATA'
c
C
C  IE HAS LOWEST Z FOR EACH A-SERIES...
C  IA HAS ADDRESS OF LOWEST Z FOR EACH A-SERIES IN AM ARRAY...
C  AM HAS MASS-EXCESS ES STORED IN ORDER OF INCREASING A, AND WITHIN
C  EACH A-SERIES IN ORDER OF INCREASING Z.  MISSING INNER Z'S INDICATED
C  BY A QUESTION MARK '0' IN AA OR AJ OR BOTH.
C
      NOTTAB=0                                                          17400   
      JVAL = NOTDEF
      PARITY = 0
C  GREATEST A IS 268, LEAST IS 1...
      IF(KA.LE.0.OR.KA.GT.NTAB) GO TO 5
      KZLO=IE(KA+1)
      KZHI=IA(KA+2)-IA(KA+1)+KZLO-1
C  CHECK FOR VALID Z...
      IF(KZ.GT.KZHI.OR.KZ.LT.KZLO) GO TO 5
C  CALCULATE POSITION IN AM ARRAY...
      IT=KZ-KZLO+IA(KA+1)                                               17410   
      JPI = AJ(IT+1)
C  CHECK FOR MISSING ENTRY...
      IF ( JPI.EQ.QMARK ) GO TO 5
C
C     DECODE THE J VALUE
C
      JVL = 0
      JCHAR = JPI
      JFND = 0
      DO 159  I = 1, 4                                                  17420   
         IF ( mychar(I) .EQ. BLANK )  GO TO 159
         IF ( mychar(I) .EQ. QMARK1 )  RETURN
         IF ( mychar(I) .EQ. SLASH )  GO TO  180
         KCHAR = ichar(mychar(I)) - ichar('0')
         IF ( KCHAR .LT. 0  .OR.  KCHAR .GT. 9 )  GO TO 170
         JFND = 1
         JVL = 10*JVL + KCHAR
 159  CONTINUE
C
C     DONE WITH FIELD AND NO SLASH FOUND - EITHER NOTHING OR INTEGER    17430   
C
 170  IF ( JFND .NE. 1 )  RETURN
      JVAL = 2*JVL
      GO TO 200
C
C     SLASH FOUND SO IT IS HALF-INTEGER AND IS DEFINED
C
 180  JVAL = JVL
C
C     NOW SCAN FOR THE PARITY                                           17440   
C
 200  DO 209  I = 1, 4
         IF ( mychar(I) .EQ. PLUS )  PARITY = +1
         IF ( mychar(I) .EQ. MINUS )  PARITY = -1
 209  CONTINUE
      RETURN
    5 NOTTAB=1
      JPI = QMARK
      RETURN
      END                                                               17450   
C
C
C*ID* INELDC   C109.PTOLEMY.SOURCE                          PER701  14:
      SUBROUTINE INELDC ( IRTN )
C
C     COMPUTES THE TRANSFER REACTION RADIAL INTEGRALS.
C
C
C         THE ROUTINE GRDSET IS CALLED BEFORE THIS ROUTINE TO
C     INITIALIZE THE THREE-DIMENSIONAL GRIDS AND SETUP THE REQUIRED     17460   
C     BOUND STATE PRODUCTS.  ALSO  WAVSET  IS CALLED FOR EACH
C     CHANNEL TO INITIALIZE THE COMPUTATION OF THE SCATTERING WAVES.
C     INELDC CALLS WFGET EACH TIME IT NEEDS A NEW WAVE FUNCTION.
C
C     THIS ROUTINE THEN CALCULATES H(LI,LO,LX) WHICH IS THE INTEGRAL OF
C     A12, V, AND THE BOUND STATE WAVEFUNCTIONS
C
C     IT THEN INTEGRATES H(LI,LO,LX) OVER THE DISTORTED WAVES.
C     SFROMI IS THEN CALLED TO RENORMALIZE THE RESULTS AND SAVE
C     THEM AS S(LI,LO,LX,JP,JT).                                        17470   
C
C
C   D.GLOECKNER 10/15/73
C
C     THIS VERSION ASSUMES GAUSS INTEGRATION FOR ALL L-VALUES HAS SAME
C     GRID.  THIS ALLOWS SOME R-DEPENDENT (AND L-INDEPENDENT) SUMS TO
C     BE TAKEN OUT OF INNER LOOP AT THE EXPENSE OF LARGE ARRAYS.
C     6/74  D.G.
C
C        7/29/74  D.GLOECKNER                                           17480   
C
C     1/16/75 - ADD DG CORRECTIONS; USE YLM AND REMOVE AFAC.
C               BY S.P.
C     1/21/75 - FINAL INELDC74 VERSION.  ADD LOTS OF COMMENTS.
C
C     1/23/75 - SPLIT INTO TWO PIECES - INELDC AND XSECTN - S.P.
C     1/26/75 - REVISE TIMES; REMOVE MUCH Z(...) STUFF FROM DX LOOP;
C               USE TABLE OF INTEGERS; IMPROVE INITIAL INTERPOLATIONS;
C                IMPROVE FAST COSINE (SMALL); OTHER SMALL FIXES
C     1/27/75 - FIX LOWER LIMIT X0(RI,RO) OF X-INTEGRATION (MHM)        17490   
C               BS PRODUCT LT VZERO WHEN X LT X0
C     1/29/75 - REWRITE INLINE COSINE - S.P.
C     1/30/75 - REVAMP A12 USING DOUBLE PRE. ARRAYS FOR M'S;
C               AVOID USING LARGE RIX, ROX.
C     1/31/75 - CONTROL OVER PRINTING; USE J1 J2 OF BOUND STATE
C     2/4/75  - REWRITE RI,RO INTEGRATION
C     2/6/75  - SPLIT  GRDSET  OFF FROM INELDC - S. P.
C             VARIABLES U=(RI+RO)/2 V=RI-RO WITH SINH MAPPINGS TO BUNCH
C             GAUSS POINTS AROUND U=R V=0
C             CALL WAVEF (NEW ENTRY WAVELJ) DURING LI-LO LOOP           17500   
C             STORE SCATTERING WAVE FUNCTIONS IN A CLOCKWISE PATTERN
C             (MHM FEB 4 1975)
C     2/7/75 - SPLIT OFF GRDSET. S.P.
C     CALL DUMMY1 TO SETUP OVERLAY
C     2/23/75 - USE REAL*4 ARRAYS
C     2/27/75 - AVOID UNDERFLOWS FOR SMALL R, LARGE L.
C     3/6/75 - FIX BUG FOR LO = 0, OTHER STUFF IN LO,LI LOOPS
C     3/7/75 - USE INPUT VALUE OF JX; ALLOW FREE OVERRIDE.
C     3/20/75 - WAVEFUNCTIONS IN SINGLE PRECISION
C     3/23/75 - NEW A12 ARRANGEMENT; USE COS(THETA-2PHI) METHOD         17510   
C     3/27/75 - ONE MSVAL ARRAY; COSINE TABLE TO 2PI
C     4/7/75 - LI, LX LOOPS INSIDE.
C     4/10/75 - USE OVERRIDING ASM. LANG. ROUTINE FOR INNER LOOPS
C     4/18/75 - NEW COMMON
C     5/20/75 - USE LOS ARRAY AND DO ONLY SOME I(LI,LO,LX).
C     6/3/75 - CHANGE PHASE OF I(LI,LO,LX)
C     6/9/75 - DO NOT INCLUDE COULOMB PHASES IN INPUT TO INTERPOLATION
C              BUT DO INCLUDE THEM IN XSECTION INPUT.
C     6/11/75 - SAVEHS/USEHS
C     7/19/75 - ALLOW DIFFERENT LO'S IN USEHS;  INTEGRAND  CHECKS       17520   
C     8/26/75 - SMALLER ILILOLX TABLES
C     9/8/75 - SMALL FIXES
C     9/15/75 - NEW DWCUTOFF
C     9/17/75 - SAVEHS AS REAL*4
C     2/11/76 - INELD2 SPLIT OFF - S. P.
C     2/24/76 - SIGN CONVENTIONS AND NOTATION OF CHAPTER II OF MANUAL
C     5/26/76 - INTERPOLATION IN U
C     6/20/76 - FIX USEHS BUG INTRODUCED ABOVE
C     4/28/78 - LI & LO INTERCHANGED - S.P.
C     5/24/78 - NEW WAVELJ CALLS - S.P.                                 17530   
C     7/9/78 - PUT SALLOC IN /SCMALO/
C     6/25/78 - AVOID 0/0 IN CANCELLATIONS
C     3/6/79 - S-MATRICES - S.P.
C     5/17/79 - FULL ARG LIST ON FIRST SETLOP CALL TO FORCE STORES
C     6/6/79 - MANY CHANGES FOR S.O., TENSOR POTENTIALS - RPG
C     6/8/79 - STANDARD PREFIXES, ETC. - RPG
C     6/19/79 - PASS INIA12 TO A12 TO ALLOW NO OVERLAY - S.P.
C     6/20/79 - OMIT REWIND; SCAN TO END ON MULTIPASS USEHS - RPG
C     9/12/79 - DELETE REFERENCES TO DEFUNCT "LOGIC" ARRAY - RPG
C     11/20/79 - PASS ILI TO SFROMI - S.P.                              17540   
C     12/12/79 - OPTIONAL SCRATCH FILE, ADD /SWITCH/ - RPG
C     1/21/80 - CIB PREFIX ON SETLOP CALLS - RPG
C     2/5/80 - CVA NPFAUL CALLS TO COUNT PAGE FAULTS - RPG
C     2/29/80 - CALL READSC, WRITHS, READHS FOR EFFICIENT I/O - RPG
C     3/15/80 - CALL ABOVE ONLY IN VAX VERSION - S.P.
C     4/14/80 - FIGURE OUT WHERE TO START IN THE IWFIO BUFFER - S.P.
C     4/22/80 - FIX BUG IN ABOVE FIX - S.P.
C     4/26/80 - PBUGSW NOLONGER IN WAVCOM - S.P.
C     8/11/80 - CALL SETLOG - S.P.
C     10/28/81 - ROOT 2 FOR IDENTICAL PARTICLES - S.P.                  17550   
C
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      CHARACTER*1  REACT, HEADER                                        /hedcom/
      COMMON /HEDCOM/  REACT(45), HEADER(65)
 
c                                                                       /formf/
c ***  LNKADB was  numLINKULES but only 12 are used ???
c
      COMMON /FORMF/  IBDS(2), NPOTS(2), LBP, LBT, NBP, NBT, JBP, JBT,
     &  BNDMAX(2), BNDSTP(2), NSTPBD(2), RBNDS(2), ABNDS(2),
     &  RCBNDS(2), BNDMAS(2), BRATMS(2), RSOBDS(2), ASOBDS(2),
     &  VBNDS(2), VSOBDS(2), TAUBDS(2), LNKADB(6, 2, 12)
 
      REAL*8  JACOB                                                     /gridcm/
      COMMON /GRIDCM/  JACOB, STPINV, COSSTP,
     &  IMSVAL, IINTS, INTOFF, IA12VL, ICOSIN,
     &  IPHIT, IPHIP, IPHI, LOGIC, LOCTRP,
     &  IRI, IRO, ILOR, ILOI, ILIR, ILII, IWIO, NOFLO, NRIROI, NCRIT,
     &  IXLAM, INLAM, IA12N, MSKCOS, MAXCNT, ISMHPT, ISMIPT,
     &  ICOSS4, IJA12S, IHS, IIINDX, IA12TM, IDW, IHINT, IHABS,
     &  IABS1, IGRDC1, NPSUMI, RVRLIM, ISMHWK, ISMHVL, ISMIVL,
     &  IRIOEX, NUMHS, IGRDC2(4),
     &  IWFII, IWFIO, NWFI, NWFO, IDWI
 
      LOGICAL ONELSW, IDENSW                                            /inelcm/
      COMMON /INELCM/  JBPF, JBTF, LXMIN, LXMAX, ILILOR, ILILOI, MSTOP,
     &  IA12M, NMLOLX, ONELSW, NUMLX, IRDINT, IELCUP, LILOSZ, NUMLIS,
     &  ILIS, IBETAS(3), ICL2FF, LXSTEP, IDENSW, LSKIP,
     &  JPMIN, JPMAX, JPBASE, NJP, JTMIN, JTMAX, JTBASE, NJT,
     &  IINDXS, ISMATR, ISMATI, NSMAT, NLX, NSPLI, ITOCS,
     &  NASPLI, IUNITR, LIFIT, ILIFIT, NOLFIT, IDELSR, IDELSI
      INTEGER INDXJS(4,2)
      EQUIVALENCE ( INDXJS(1,1), JPMIN )
 
      COMMON /KANDM/ AKI, AKO, REDMI, REDMO, RIMAX, ROMAX, ISIGS(2),    /kandm/
     &  RSCTS(2), ASCTS(2), RCSCTS(2) ,ISMATS(2), LOMOST, LCRIT,
     &  ISCTMN, ISCTCR, ETAS(2), RCSCTP(2), RCSCTT(2), LCRITS(2),
     &  RATMSS(2), QMIN, ABAR
 
      DIMENSION  AKS(2), REDMS(2), RMAXS(2)
      EQUIVALENCE ( AKI, AKS(1) ), ( REDMI, REDMS(1) ),
     &  ( RIMAX, RMAXS(1) )
 
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
      REAL*4  TBEGIN, TIMES                                             /ftimei/
      COMMON /FTIME/ TBEGIN, NUMLOP, NUMWAV, TIMES(8)
 
C
CDLC
CDLC     FOLLOWING TINY ALLOCATOR IS USED FOR THE H'S
CDLC
      DIMENSION SALLOC(1)                                               17570   
CDL      COMMON /SCMALO/  SALLOC
CDS      EQUIVALENCE ( SALLOC(1), ALLOC(1) )
      EQUIVALENCE ( SALLOC(1), ALLOC(1) )                               cnd
C
CIB      REAL*8  HOLD / Z 46800000 80000000 /
CIB      INTEGER  MASK8 / Z FF7F FFFF /
CIB      DATA  RNN / 0.D0 /
CIB      EQUIVALENCE  (DNN, NN4),  (RNN, IRNN)
C
C                                                                       17580   
      LOGICAL  PBUGSW, PINFSW
      LOGICAL  NXLISW
CVA      LOGICAL  FIRSTL
      REAL*4 TSTART, TTIMER, TT, TT1, TT2, TT5, TT7
C
      DATA  HAFNEG / -.50D0 /
C
c
C
      TSTART = second()                                                 17590   
      IRTN = 0
      DO   14 III=1, 8
  14  TIMES(III)=0.0
      NUMTIM = 4
      NUMANG = 0
      NUMTRM = 0
      NUM3 = 0
      NUM4 = 0
      NUM5 = 0
      NUM6 = 0                                                          17600   
      NUMHIN = 0
CVA      FIRSTL = .TRUE.
C
      IPRNT = MOD( IPRINT, 10 )
      PBUGSW = IPRNT .GE. 4
      PINFSW = IPRNT .GE. 2
      INIA12 = 5
C
C
      write (6, 23) REACT, ELAB, HEADER                                 17610   
 23   FORMAT ( '1', T60, 'P T O L E M Y' /
     1  10X, 'COMPUTATION OF TRANSFER S-MATRIX ELEMENTS',
     2   T95, 'WHEELS WITHIN WHEELS' /
     3  '0', 45A1, 'ELAB =', F7.2, ' MEV', 5X, 65A1 / )
C
      NLINE = 1000
C
      CALL SETLOG ( 2*(LOMOST+LXMAX) )
C
C     HERE WE START THE REAL GUTS OF THE CALCULATION.                   17620   
C
C
C     THE PRINCIPAL LOOPS ARE IN THE ORDER:
C
C     PARITY OF LI
C       LI   LMIN <= LI <= LMAX
C         RI-RO  NPDIF TERMS
C           (RI+RO)2  NPSUM TERMS
C             DX   (NPPHI POINTS)
C               MP AND MT   (LIMITS FROM A12)                           17630   
C                 MU       (LIMITS FROM A12)
C                   LX&LO - COMBINED LOOP WITH LIMITS FROM A12
C           INTERPOLATION AND THEN:
C           (RI+RO)/2  NPSUMI TERMS
C             JPI,JPO,LO COMBINED LOOP FOR WF PRODUCTS
C             JPI,JPO,LO',LX' COMBINED LOOP FOR INTEGRALS I
C         CALL SFROMI TO CONVERT TO S MATRIX
C
C
C     WE WILL HAVE NO MORE  IALLOC  CALLS SO GET ADDRESSES              17640   
C
      LMSVAL = Z(IMSVAL) - 1
      LJA12S = FACFR4*Z(IJA12S) - FACFR4
      LINTS = Z(IINTS) - 1 + INTOFF
      LA12VL = Z(IA12VL)-1
      LHS = Z(IHS)
CDL      LHS = 1
      LHSM1 = LHS - 1
      LIINDX = FACFR4*Z(IIINDX) - FACFR4
      LA12T1 = Z(IA12TM)                                                17650   
      LA12T2 = LA12T1 + NUMLX
      LA12T3 = FACFR4*(LA12T2 + 2*LXMAX + 2) - FACFR4
      IF ( IHSAVE .EQ. 2 )  LA12T3 = FACFR4*LA12T1 - FACFR4
      LCOSIN = Z(ICOSIN)
      LPHIT = FACFR4*Z(IPHIT) - FACFR4
      LPHIP = FACFR4*Z(IPHIP) - FACFR4
      LPHI = FACFR4*Z(IPHI) - FACFR4
      LTRP = FACFR4*Z(LOCTRP) - FACFR4
      LRI = FACFR4*Z(IRI) - FACFR4
      LRO = FACFR4*Z(IRO) - FACFR4                                      17660   
      LLIR = FACFR4*Z(ILIR) - FACFR4
      LLII = FACFR4*Z(ILII) - FACFR4
      LLOR = FACFR4*Z(ILOR) - FACFR4
      LLOI = FACFR4*Z(ILOI) - FACFR4
      LWIO = FACFR4*Z(IWIO) - FACFR4
      LDW = Z(IDW) - 1
      LLIS = FACFR4*Z(ILIS) - FACFR4
      LLILOR = Z(ILILOR) - 1
      LLILOI = Z(ILILOI) - 1
      LHINT = Z(IHINT) - 1                                              17670   
      LHABS = Z(IHABS) - 1
      LABS1 = Z(IABS1) - 1
      LSMHPT = Z(ISMHPT)
      LSMIPT = Z(ISMIPT)
      LSMHVL = Z(ISMHVL) - 1
      LSMIVL = Z(ISMIVL) - 1
      LSMHWK = Z(ISMHWK)
      LRIOEX = Z(IRIOEX) - 1
      LWAVR = Z(IWAVR)
      LWAVI = Z(IWAVI)                                                  17680   
      LVRL1 = Z(IRLVS(1))
      LVRL2 = Z(IRLVS(2))
      LVIM1 = Z(IIMVS(1))
      LVIM2 = Z(IIMVS(2))
      LCENT1 = Z(ICENTR(1))
      LCENT2 = Z(ICENTR(2))
      LATERM = Z(IBETAS(1))
      LDWI = FACFR4*Z(IDWI) - FACFR4
      LWFIO = FACFR4*Z(IWFIO) - FACFR4
      LWFII = FACFR4*Z(IWFII) - FACFR4                                  17690   
      LINDXS = FACFR4*Z(IINDXS) - FACFR4
C
C     WE ASSUME THAT
C       L1+L2+LX <= 256   AND   NUMCOSIN <= 16384
C
      PI256 = 256*PI
C
C
C
C     FORCE THE OVERLAYS TO GET THE THREEJ COMMON BLOCKS IN.            17700   
C     THREEJ IS USED BY A12 WHICH IS
C     CALLED REPTIVELY BELOW.  HOWEVER, NOTHING WILL HAPPEN
C     FROM NOW ON THAT WOULD CAUSE THE OVERLAYS TO CHANGE.
C
      CALL DUMMY1
C
      FACTOR = 2*DSQRT( AKI*AKO/(ES(1)*ES(2)) )
      IF ( IDENSW )  FACTOR = SQRT(2.D0) * FACTOR
C
C                                                                       17710   
C     THE LOOPS BEGIN NOW
C
      TT7 = second()
C
C
C     LOOP OVER LI
C
C
C     TWO PASSES OVER LI LOOP NOW; EVEN LI FIRST,THEN ODD
C                                                                       17720   
      LIMIN=LMIN+1
      LIL=LMIN
      IF(MOD(LMIN,2) .EQ. 1 ) GO TO 150
      LIMIN=LMIN
      LIL=LMIN+1
C
C     LIPRTY = 1 FOR LI EVEN,  = 2 FOR LI ODD
C
 150  DO 989  LIPRTY = 1, 2
C                                                                       17730   
      IF(LIMIN.GT.LMAX) GO TO 980
      NXLISW = .FALSE.
      ILI = 1
C
      DO 959 LI=LIMIN,LMAX,2
C
C     GET THE REQUIRED SCATTERING WAVEFUNCTIONS.
C     WE ALWAYS DO THIS EVEN IF LI WON'T BE USED SO AS TO GET THE
C     ELASTIC S-MATRIX ELEMENTS.
C                                                                       17740   
      IF ( NXLISW )  GO TO 250
C
C     FOR FIRST LI, FILL UP THE OUT-CHANNEL WAVEFUNCTION ARRAY
C
      ITRK=0
C
      DO 239 KWO = 1, NWFO
         LO = ILLOC(LWFIO+4*KWO-3) + LI
         LASO = ILLOC(LWFIO+4*KWO-2) + LI
         JPO = ILLOC(LWFIO+4*KWO-1) + 2*LI                              17750   
         ILLOC(LWFIO+4*KWO) = ITRK
         CALL WFGET ( LO, LASO, JPO, 2, NRIROI, ALLOC4(LRO+1),
     1     ALLOC4(LLOR+ITRK+1), ALLOC4(LLOI+ITRK+1),
     2     ALLOC(LWAVR), ALLOC(LWAVI),
     3     ALLOC(LVRL2), ALLOC(LVIM2), ALLOC(LCENT2) )
 239  ITRK=ITRK+NRIROI
C
      ITRK=0
      NXLISW = .TRUE.
      GO TO 280                                                         17760   
C
C     ON SUBSEQUENT LI'S WE NEED OUT-CHANNEL WAVE FUNCTIONS FOR ONE
C     NEW LO.
C     WE MUST DETERMIN WHERE THE NEW LO STARTS.
 
C
 250  LO = ILLOC(LWFIO+1) + 2
      LASO = ILLOC(LWFIO+2) + 2
      JPO = ILLOC(LWFIO+3) + 4
      DO 254  II = 1, NWFO                                              17770   
         IF ( LO .NE. ILLOC(LWFIO+4*II-3)
     1      .OR.  LASO .NE. ILLOC(LWFIO+4*II-2)
     2      .OR.  JPO .NE. ILLOC(LWFIO+4*II-1) )  GO TO 254
         I = NWFO-II+1
         GO TO 255
 254  CONTINUE
      I = 0
      GO TO 260
C
C     MOVE POINTERS DOWN.                                               17780   
C
 255  DO 259 KWO = 1, I
         K = KWO + (NWFO-I)
         ILLOC(LWFIO+4*KWO) = ILLOC(LWFIO+4*K)
 259  CONTINUE
C     NOW PUT THE NEW WAVE FUNCTIONS INTO THE CIRCULAR BUFFER.
 260  I = I + 1
      DO 269 KWO = I, NWFO
         LO = ILLOC(LWFIO+4*KWO-3) + LI
         LASO = ILLOC(LWFIO+4*KWO-2) + LI                               17790   
         JPO = ILLOC(LWFIO+4*KWO-1) + 2*LI
         ILLOC(LWFIO+4*KWO) = ITRK
         CALL WFGET ( LO, LASO, JPO, 2, NRIROI, ALLOC4(LRO+1),
     1     ALLOC4(LLOR+ITRK+1), ALLOC4(LLOI+ITRK+1),
     2     ALLOC(LWAVR), ALLOC(LWAVI),
     3     ALLOC(LVRL2), ALLOC(LVIM2), ALLOC(LCENT2) )
         ITRK=ITRK+NRIROI
         IF(ITRK.GT.NCRIT) ITRK=0
 269  CONTINUE
C                                                                       17800   
C     FOR EACH LI, WE MUST GET THE IN-CHANNEL WAVE FUNCTIONS
C
C
 280  DO 289 KWI = 1, NWFI
         LASI = ILLOC(LWFII+3*KWI-2) + LI
         JPI = ILLOC(LWFII+3*KWI-1) + 2*LI
         I = ILLOC(LWFII+3*KWI) + 1
         CALL WFGET ( LI, LASI, JPI, 1, NRIROI, ALLOC4(LRI+1),
     1     ALLOC4(LLIR+I), ALLOC4(LLII+I),
     2     ALLOC(LWAVR), ALLOC(LWAVI),                                  17810   
     3     ALLOC(LVRL1), ALLOC(LVIM1), ALLOC(LCENT1) )
 289  CONTINUE
C
C     WAVEFUNCTIONS ALL FOUND, WILL WE DO THIS VALUE OF LI
C
C
 290  IF ( LI - ILLOC(LLIS+ILI) )  959, 300, 295
 295  IF ( ILI .GE. NUMLIS )  GO TO 959
      ILI = ILI + 1
      GO TO 290                                                         17820   
C
C     THIS IS AN LI TO DO, FIND THE A12 COEFFICENTS
C
 300  TT1=second()
C
      LNLAM = FACFR4*Z(INLAM) - FACFR4
      CALL A12 ( LI, LXMIN, LXMAX, LMIN, LMAX,
     1  ALLOC(Z(IXLAM)), ILLOC(LNLAM+1), ALLOC(LA12VL+1),
     2  ALLOC(LMSVAL+1),
     3  ILLOC(LJA12S+1), JA12M, JA12N, JA12AN, ILLOC(LIINDX+1),         17830   
     4  IHMAX, LOMNMN, LOMXMX, ALLOC(LINTS+1), ALLOC(LA12T1),
     5  ALLOC(LA12T2), ILLOC(LA12T3+1), LHSM1, LA12VL, IPRINT, INIA12,
     6  ILLOC(LDWI+1), NDW, NI, ILLOC(LWFII+1), ILLOC(LWFIO+1) )
      NUMHSU = IHMAX*NPSUM
C
      IF ( ( JA12M .GT. IA12M  .OR.  JA12N .GT. IA12N )  .AND.
     1  IHSAVE .NE. 2 )  write (6, 303)
     1  IA12M, JA12M, IA12N, JA12N
 303  FORMAT(' **** ERROR *** A12 HAS TOO MANY TERMS:', 4I8 )
      TIMES(4)=TIMES(4)+second()-TT1                                    17840   
      NUMTIM = NUMTIM + 2
C
      IF ( LOMNMN .GT. LOMXMX )  GO TO 959
C
C     NOW PROCEED TO THE (RI, RO) INTEGRATION LOOP
C
      LHEND = LHSM1 + IHMAX
      MCNT=1
      NSKIP = 0
      DWRIOS=10.0D0                                                     17850   
      DWRIOL=0
      DWRIOC=0
      DWCONT = 0
C
C     INITIALIZE "I1REAL", "I1IMAG" (= FULL INTEGRALS)
C     AND "RIROABS" (= INTEGRALS OF ABSOLUTE VALUES, OVER
C     RI, RO) FOR THIS LI.
C
      DO 329 II = 1, NI
         ALLOC(LLILOR+II) = 0                                           17860   
         ALLOC(LLILOI+II) = 0
         ALLOC(LABS1+II) = 0
 329  CONTINUE
C
      TT5 = second()
C
C
C     LOOP OVER THE V-GRID AND FOR EACH ONE DO A COMPLETE
C     U-INTEGRAL.
C                                                                       17870   
      DO 859  IV = 1, NPDIF
C
C
C     GET THE H'S FOR INTERPOLATION INPUT
C
C     INDEX TO THE H'S FILE
C
      LIIP = 1000*( 1000*LIPRTY + LI ) + IV
      IF ( IHSAVE .EQ. 2 )  GO TO 560
C                                                                       17880   
C     LOOP OVER U-VALUES AND COMPUTE THE H'S
C
      IPLUNK = NPSUM*(IV-1)
      TT2=second()
C
      DO 549  IU = 1, NPSUM
C
      IPLUNK = IPLUNK+1
C
      DO 409  IH = 1, IHMAX                                             17890   
         SALLOC(LHSM1+IH) = 0
         ALLOC(LHINT+IH) = 0
         ALLOC(LHABS+IH) = 0
 409  CONTINUE
      IF ( ISCRFL .EQ. 0 )  GO TO 420
CVA      CALL READSC ( NPPHI, ALLOC4(LPHI+1), ALLOC4(LPHIP+1),
CVA     1   ALLOC4(LPHIT+1), ALLOC4(LTRP+1), *9960 )
      READ ( 2, END=9960, ERR=9960 )                                    cnv
     1   ( ALLOC4(LPHI+II), II = 1, NPPHI ),                            cnv
     2   ( ALLOC4(LPHIP+II), II = 1, NPPHI ),                           17900   
     3   ( ALLOC4(LPHIT+II), II = 1, NPPHI ),                           cnv
     4   ( ALLOC4(LTRP+II), II = 1, NPPHI )                             cnv
      MCNT = 1
C
C
C     THE DX INTEGRAL  (AT LAST)
C
C
 420  DO 489 II=1,NPPHI
C                                                                       17910   
      PHI = ALLOC4(LPHI+MCNT)
      KMEND = LMSVAL + JA12M
      PHIP = ALLOC4(LPHIP+MCNT)
      ARG = PHI+PHI
      PHIT =ALLOC4(LPHIT+MCNT)
      PVPDX = ALLOC4(LTRP+MCNT)
      JA12OF = LJA12S - LMSVAL + 1
C
C     FOLLOWING IS THE HIGH SPEED INLINE COSINE AND SINE(ARG)
C     FOR THIS CASE   ARG = 2*PHI    AND WE ARE FINDING COS(2PHI)       17920   
C     AND SIN(2PHI) WHICH WE USE IN THE RECURSION TO N*PHI
C
CIB      DNN = ARG*STPINV + HOLD
CIB      NN = iand( NN4, MSKCOS )
CIB      IRNN = iand( NN4, MASK8 )
      RNN=AINT(ARG*STPINV+.5)                                           cnd
      NN=RNN                                                            cnd
      NN = MOD(NN, NCOSIN)                                              cnd
      DELTAC = ARG - RNN*COSSTP                                         cnd
      S2PHI = ( (1+HAFNEG*DELTAC**2)*ALLOC(LCOSIN+IABS(NN-ICOSS4))      17930   
     1   + DELTAC*ALLOC(LCOSIN+NN) )                                    cnd
      C2PHI = (1+HAFNEG*DELTAC**2)*ALLOC(LCOSIN+NN)                     cnd
     1    - DELTAC*ALLOC(LCOSIN+IABS(NN-ICOSS4))                        cnd
CDC      S2PHI = SIN(ARG)
CDC      C2PHI = COS(ARG)
C
C     THE COSINE AND SINE(ARG) HAS BEEN FOUND
      S2PHI2 = S2PHI**2
C
C     LOOP OVER TERMS IN A12                                            17940   
C
      DO 479  KA12M = LMSVAL, KMEND, 5
C
C     THE MAGIC ANGLE FOR THE FIRST VALUE OF MU-2
C     WE ADD 256*PI TO FORCE IT POSITIVE
C
      ARG = PI256 + ALLOC(KA12M+1) * PHIT
     1            + ALLOC(KA12M+2) * PHIP
     2            - ALLOC(KA12M+3) * PHI
C                                                                       17950   
      LA12OF = ILLOC(JA12OF+KA12M)
C
C     FOLLOWING IS THE HIGH SPEED INLINE COSINE AND SINE(ARG)
C
      NUMMU = ILLOC(JA12OF+KA12M+1)
CIB      DNN = ARG*STPINV + HOLD
CIB      NN = iand( NN4, MSKCOS )
CIB      IRNN = iand( NN4, MASK8 )
      RNN=AINT(ARG*STPINV+.5)                                           cnd
      NN=RNN                                                            17960   
      NN = MOD(NN, NCOSIN)                                              cnd
      DELTAC = ARG - RNN*COSSTP                                         cnd
C
C     COSTHE = COS(MT*PHIT+MP*PHIP-MU*PHI)
C     SINSIN = SIN(MT*PHIT+MP*PHIP-MU*PHI) * SIN(2*PHI)
C
      COSTHE = (1+HAFNEG*DELTAC**2)*ALLOC(LCOSIN+NN)                    cnd
     1    - DELTAC*ALLOC(LCOSIN+IABS(NN-ICOSS4))                        cnd
      SINSIN = ( (1+HAFNEG*DELTAC**2)*ALLOC(LCOSIN+IABS(NN-ICOSS4))     cnd
     1   + DELTAC*ALLOC(LCOSIN+NN) ) * S2PHI                            17970   
CDC      COSTHE = COS(ARG)
CDC      SINSIN = SIN(ARG) * S2PHI
C
C     THE COSINE AND SINE(ARG) HAS BEEN FOUND
C
      LHSTRT = ILLOC(JA12OF+KA12M+2)
      COSTHE = PVPDX*COSTHE
      NUMIH = ILLOC(JA12OF+KA12M+3)
      SINSIN = PVPDX*SINSIN
C                                                                       17980   
C     FOLLOWING IS THE INNERMOST AND INNERMOST INNERMOST LOOP.
C     WE DO ALL THE MU'S HERE.
C     EACH ONE IS 2 GREATER THAN THE PREVIOUS, SO THETA IS DECREMENTED
C     BY 2PHI AND COS(THETA) IS FOUND ITERATIVELY.
C
cccCNV      CALL SETLOP ( LA12OF, LHSTRT, COSTHE, LHEND, NUMIH, C2PHI,
cccCNV     1  NUMMU, SINSIN, 8, S2PHI2, ALLOC, SALLOC )
C
      DO 469  NMU = 1, NUMMU
         COSNEW = COSTHE*C2PHI + SINSIN                                 17990   
         SINSIN = SINSIN*C2PHI - COSTHE*S2PHI2
         COSTHE = COSNEW
C
C     LOOP OVER ALL (LX, LO) PAIRS FOR THIS LI
         DO 459  LH = LHSTRT, LHEND
            SALLOC(LH) = SALLOC(LH) + COSNEW*ALLOC(LA12OF+LH)
 459     CONTINUE
         LA12OF = LA12OF + NUMIH
 469  CONTINUE
C                                                                       18000   
cccCNV      CALL SETLOP ( LA12OF, LHSTRT, COSTHE, LHEND, NUMIH, C2PHI,
cccCNV     1  NUMMU, SINSIN, 8, S2PHI2, ALLOC, SALLOC )
C
C
 479  CONTINUE
C
C     END OF LOOP OVER A12 TERMS
C
      MCNT = MCNT + 1
C                                                                       18010   
C     ACCUMULATE THE DESIRED INTEGRAL IN  LHINT  AND THE INTEGRAL
C     OF  INTEGRAND  IN  LHABS.  THE LATTER IS USED FOR CHECKS ON
C     LOSS OF SIGNIFICANCE
C
      DO 485  IH = 1, IHMAX
         ALLOC(LHINT+IH) = ALLOC(LHINT+IH) + SALLOC(LHSM1+IH)
         ALLOC(LHABS+IH) = ALLOC(LHABS+IH) + DABS(SALLOC(LHSM1+IH))
         SALLOC(LHSM1+IH) = 0
 485  CONTINUE
C                                                                       18020   
 489  CONTINUE
C
C     END OF DX INTEGRAL TERMS
C
C
      NUMTRM = NUMTRM + JA12N
      NUMANG = NUMANG + JA12AN
      NUM3 = NUM3 + JA12M
      NUM4 = NUM4 + 1
C                                                                       18030   
C     STORE THE H'S WITH THE FACTOR
C        EXP( -ALPHAP*RP - ALPHAT*RT )
C     REMOVED IN THE INTERPOLATION INPUT ARRAY
C
      DO 509  IH = 1, IHMAX
         ALLOC(LSMHVL+IU+NPSUM*(IH-1)) = ALLOC(LHINT+IH)
     1      * ALLOC(LRIOEX+IPLUNK)
 509  CONTINUE
C
      IF ( IPRNT .GE. 9 )  write (6, 513) LIIP, IPLUNK,                 18040   
     1  ( ALLOC(LHINT+IH), IH = 1, IHMAX )
 513  FORMAT ( ' CMPTED:', I9, I5, ( T23, 7G14.5 ) )
C
 549  CONTINUE
C
C     END OF LOOP ON U
C
      TIMES(5)=TIMES(5)+second()-TT2
      NUMTIM = NUMTIM + 2
C                                                                       18050   
C     SAVE H'S NOW
C
CVA      IF ( IHSAVE .EQ. 1 )  CALL WRITHS ( NUMHSU, LIIP,
CVA     1   ALLOC(LSMHVL+1), *9950 )
      IF ( IHSAVE .EQ. 1 )  WRITE ( 1, ERR=9950 )                       cnv
     1  LIIP, ( ALLOC(LSMHVL+I), I = 1, NUMHSU )                        cnv
C
      GO TO 590
C
C     HERE WE READ SAVED H'S.  MAKE SURE WE DO NOT GET OUT OF           18060   
C     SYNCHRONIZATION.
C
CVA 560  CALL READHS ( NUMHSU, LIIPH, ALLOC(LSMHVL+1), *9950 )
 560  READ ( 1, END=9950, ERR=9950 )                                    cnv
     1  LIIPH, ( ALLOC(LSMHVL+I), I = 1, NUMHSU )                       cnv
      IF ( LIIPH .EQ. LIIP )  GO TO 590
      IF ( LIIPH .LT. LIIP )  GO TO 560
      write (6, 563) LIIP, LIIPH
 563  FORMAT ( '0**** SYNCHRONIZATION ERROR:', 2I12 )
      GO TO 9950                                                        18070   
C
 590  NUM5 = NUM5 + NPSUM
      NUM6 = NUM6 + NUMHSU
C
C
C     NOW INTERPOLATE
C
      TT2 = second()
      DO 609  IH = 1, IHMAX
         ITEMP = LSMHVL+1 + (IH-1)*NPSUM                                18080   
         CALL SPLNCB ( NPSUM, ALLOC(LSMHPT), ALLOC(ITEMP),
     1     ALLOC(LSMHWK), ALLOC(LSMHWK+NPSUM), ALLOC(LSMHWK+2*NPSUM) )
         CALL INTRPC ( NPSUM, ALLOC(LSMHPT), ALLOC(ITEMP),
     1     ALLOC(LSMHWK), ALLOC(LSMHWK+NPSUM), ALLOC(LSMHWK+2*NPSUM),
     2     NPSUMI, ALLOC(LSMIPT), ALLOC(LSMIVL+1+(IH-1)*NPSUMI) )
         NUMHIN = NUMHIN + NPSUMI
 609  CONTINUE
      TIMES(6) = TIMES(6) + second()-TT2
      NUMTIM = NUMTIM + 2
C                                                                       18090   
C     NOW DO INTEGRAL DU FOR FIXED V.
C
      IPLUNK = NPSUMI*(IV-1)
      DO 789  IU = 1, NPSUMI
         IPLUNK = IPLUNK + 1
C
C        COMPUTE IMAG AND REAL PARTS OF PRODUCT OF THE DISTORTED
C        SCATTERING WAVES.
C
         DWMAX = 0                                                      18100   
         DO 739 KDW = 1, NDW
            I = ILLOC(LDWI+4*KDW-1) + IPLUNK
            FIR = ALLOC4(LLIR+I)
            FII = ALLOC4(LLII+I)
            I = ILLOC(LDWI+4*KDW) + IPLUNK
            FOR = ALLOC4(LLOR+I)
            FOI = ALLOC4(LLOI+I)
            DWR=FOR*FIR-FOI*FII
            DWI=FOR*FII+FOI*FIR
            DWLIM=DMAX1(DABS(DWR),DABS(DWI))                            18110   
            IF(DWLIM.GT.DWRIOL) DWRIOL=DWLIM
            IF((DWLIM.LT.DWRIOS).AND.(DWLIM.NE.0)) DWRIOS=DWLIM
            DWRIOC=DWRIOC+DWLIM
            DWMAX = DMAX1( DWMAX, DWLIM )
            ALLOC(LDW+2*KDW-1) = DWR
            ALLOC(LDW+2*KDW) = DWI
            DWCONT = DWCONT + 1
 739     CONTINUE
C
C        SKIP THE NEXT PART IF ALL DISTORTED-WAVE PRODUCTS ARE SMALL.   18120   
C
         IF ( DWMAX .LT. 1.D-30 ) GO TO 780
C
         TERM = ALLOC4(LWIO+IPLUNK)
C
C
C        NOW ADD THESE H'S INTO THE APPROPRIATE I(JO,JI,LO,LX)
C        ALONG WITH THE PRODUCT OF THE DISTORTED WAVES
C
         DO 779 II = 1, NI                                              18130   
            ITEMP = ILLOC(LIINDX+4*II-3) + IU
            KDW = ILLOC(LIINDX+4*II-2)
            ALLOC(LLILOR+II) = ALLOC(LLILOR+II)
     1         + TERM*ALLOC(ITEMP)*ALLOC(KDW-1)
            ALLOC(LLILOI+II) = ALLOC(LLILOI+II)
     1         + TERM*ALLOC(ITEMP)*ALLOC(KDW)
C
C        COMPUTE AN INDICATION OF LOSS OF SIGNIFICANCE:
C           "RIROABS" = INTEGRAL(RI,RO)  \ INTEGRAL(PHI) INTEGRAND \
C                                                                       18140   
         IF ( PINFSW ) ALLOC(LABS1+II) = ALLOC(LABS1+II)
     1      + DABS(TERM*ALLOC(ITEMP))
     2      * ( DABS(ALLOC(KDW-1)) + DABS(ALLOC(KDW)) )
 779     CONTINUE
C
C
         GO TO 789
C
C        WE COME HERE WHEN SKIPPING I CALCULATION DUE TO THE PRODUCT
C        OF THE DISTORTED WAVES BEING SMALL.                            18150   
C
 780     NSKIP = NSKIP + 1
C
C
 789  CONTINUE
 859  CONTINUE
C
      TIMES(7) = TIMES(7) + second()-TT5
      NUMTIM = NUMTIM + 2
C                                                                       18160   
C     END OF (RI,RO) INTEGRATION
C
      DWRIOC=DWRIOC/DWCONT
      IF (PBUGSW)  WRITE(6, 863)DWRIOS,DWRIOL,DWRIOC
 863  FORMAT(' SMALLEST, LARGEST AND AVERAGE DABS(DWRIRO)=', 3G15.5 / )
C
C
C     SUBROUTINE SFROMI CALCULATES S-MATRIX ELEMENTS FROM THE
C     RADIAL INTEGRALS.
C                                                                       18170   
      CALL SFROMI ( LI, ILI, ALLOC(Z(ISMATR)), ALLOC(Z(ISMATI)),
     1   ILLOC(LINDXS+1), ALLOC(LLILOR+1), ALLOC(LLILOI+1),
     2   ILLOC(LIINDX+1), NI, ILLOC(LDWI+1), ILLOC(LWFII+1),
     3   ILLOC(LWFIO+1), ALLOC(LABS1+1), ALLOC(LATERM),
     4   FACTOR, PINFSW, NLINE )
C
      IF ( IHSAVE .EQ. 2 )  GO TO 955
C
      IF ( ISCRFL .NE. 0 )  REWIND 2
      IF ( MCNT-1 .GT.MAXCNT )                                          18180   
     1  write (6, 923) MCNT, MAXCNT
 923  FORMAT (' **** ERROR ****  PHI COUNTS MESSED UP:', 5I10 )
      I = LHSTRT+LA12OF - LA12VL - 1
      IF ( I .NE. JA12N )  write (6, 933) I, JA12N,
     1  LI, JA12M, IHMAX, LHSTRT, LA12OF, LA12VL
 933  FORMAT (' ******* A12 COUNTS MESSED UP:', 8I10 )
C
C     FOR VAX/VMS, START THE PAGE-FAULT COUNT AFTER THE FIRST L.
C
 955  CONTINUE                                                          18190   
CVA      IF ( FIRSTL )  NPAGF = NPFAUL( 0 )
CVA      FIRSTL = .FALSE.
C
C
 959  CONTINUE
C
C     END OF THE LI LOOP FOR A GIVEN PARITY OF LI
C     IF LI IS EVEN HAVE ANOTHER BASH AT LI LOOP WITH ODD LI
C
 980  LIMIN=LIL                                                         18200   
 989  CONTINUE
C
      TT = second()
      TIMES(8) = TT - TT7
C
C     VAX/VMS:  PRINT THE NUMBER OF PAGE FAULTS SINCE THE FIRST L.
C
CVA      NPAGF = NPFAUL( NPAGF )
CVA      write (6, 993)  NPAGF
CVA 993  FORMAT ( '0THERE HAVE BEEN', I8,                               18210   
CVA     1   ' PAGE FAULTS SINCE THE FIRST L.' )
C
C     END OF THE 2 LI LOOPS (EVEN AND ODD PARITY OF LI)
C
C
C
C     IF NECESSARY, CLEAN UP AFTER SAVEHS/USEHS
C
      IF ( IHSAVE-1 )  2000, 1600, 1700
C                                                                       18220   
C     WRITE A DUMMY RECORD AT THE END
C
 1600 LIIP = 300000000
CVA      CALL WRITHS ( NUMHS, LIIP, ALLOC(LSMHVL+1), *9950 )
      WRITE ( 1, ERR=9950 )                                             cnv
     1  LIIP, ( ALLOC(LSMHVL+I), I = 1, NUMHS )                         cnv
      GO TO 1780
C
C
C     FOR A MULTIPASS, USEHS RUN, READ PAST THE DUMMY RECORD.           18230   
C
 1700 IF ( IBSPAS .EQ. 0 ) GO TO 1780
 1720 IF ( LIIPH .EQ. 300000000 ) GO TO 1780
CVA      CALL READHS ( 1, LIIPH, DUMMY, *1780 )
      READ ( 1, ERR=9950, END=1780 ) LIIPH                              cnv
      GO TO 1720
C
 1780 CONTINUE
C
C                                                                       18240   
C
C     A L L    D O N E
C
 2000 IRTN = 1
C
      CALL INELD2 ( TSTART, NUMHIN, NUMTIM, NUMTRM, NUMANG,
     1  NUM3, NUM4, NUM5, NUM6 )
C
      RETURN
C                                                                       18250   
 9950 write (6, 9953)
 9953 FORMAT ( '0**** ERROR IN READING OR WRITING H''S FILE.' )
      RETURN
C
 9960 write (6, 9963)
 9963 FORMAT ( '0**** ERROR IN READING SCRATCH FILE (UNIT 2).' )
      RETURN
C
      END
C*ID* INELD2   C109.PTOLEMY.SOURCE                          PER701  15: 18260   
      SUBROUTINE INELD2 ( TSTART, NUMHIN, NUMTIM, NUMTRM, NUMANG,
     1  NUM3, NUM4, NUM5, NUM6 )
C
C     FINISH-UP INELDC - FREE AREAS AND PRINT TIMING
C
C     2/11/76 - SPLIT OFF FROM INELDC - S.P.
C     5/29/76 - INTERPOLATION TIMES
C     6/26/78 - LI AND LO INTERCHANGED
C     6/6/79 - REMOVE IABS2, DEALLOCATE NEW AREAS USED FOR
C        S.O. AND TENSOR DISTORTIONS ETC. - RPG                         18270   
C     6/8/79 - STANDARD PREFIXES - RPG
C     7/21/79 - ADD /SWITCH, KEEP SCATTERING AREAS FOR MULTIPASS - RPG
C
C
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      REAL*8  JACOB                                                     /gridcm/
      COMMON /GRIDCM/  JACOB, STPINV, COSSTP,
     &  IMSVAL, IINTS, INTOFF, IA12VL, ICOSIN,
     &  IPHIT, IPHIP, IPHI, LOGIC, LOCTRP,
     &  IRI, IRO, ILOR, ILOI, ILIR, ILII, IWIO, NOFLO, NRIROI, NCRIT,
     &  IXLAM, INLAM, IA12N, MSKCOS, MAXCNT, ISMHPT, ISMIPT,
     &  ICOSS4, IJA12S, IHS, IIINDX, IA12TM, IDW, IHINT, IHABS,
     &  IABS1, IGRDC1, NPSUMI, RVRLIM, ISMHWK, ISMHVL, ISMIVL,
     &  IRIOEX, NUMHS, IGRDC2(4),
     &  IWFII, IWFIO, NWFI, NWFO, IDWI
 
      LOGICAL ONELSW, IDENSW                                            /inelcm/
      COMMON /INELCM/  JBPF, JBTF, LXMIN, LXMAX, ILILOR, ILILOI, MSTOP,
     &  IA12M, NMLOLX, ONELSW, NUMLX, IRDINT, IELCUP, LILOSZ, NUMLIS,
     &  ILIS, IBETAS(3), ICL2FF, LXSTEP, IDENSW, LSKIP,
     &  JPMIN, JPMAX, JPBASE, NJP, JTMIN, JTMAX, JTBASE, NJT,
     &  IINDXS, ISMATR, ISMATI, NSMAT, NLX, NSPLI, ITOCS,
     &  NASPLI, IUNITR, LIFIT, ILIFIT, NOLFIT, IDELSR, IDELSI
      INTEGER INDXJS(4,2)
      EQUIVALENCE ( INDXJS(1,1), JPMIN )
 
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
      REAL*4  TBEGIN, TIMES                                             /ftimei/
      COMMON /FTIME/ TBEGIN, NUMLOP, NUMWAV, TIMES(8)
 
C
      LOGICAL  FREESW
      REAL*4   TSTART, TTIMER
C
C
      FREESW = MOD( IPRINT/100, 10 ) .EQ. 0
C                                                                       18290   
C
C     FREE WORK ARRAYS CREATED FOR INELDC AND WAVELJ
C
C
      IF ( .NOT. FREESW )  GO TO 1500
      IF ( IHSAVE .EQ. 2 )  GO TO 995
C
C     FIRST THE AREAS THAT ARE NOT MADE FOR USEHS RUNS
C
      Z(IHS) = -Z(IHS)                                                  18300   
      Z(IHINT) = -Z(IHINT)
      Z(IHABS) = -Z(IHABS)
      Z(IPHI) = -Z(IPHI)
      Z(IPHIP) = -Z(IPHIP)
      Z(IPHIT) = -Z(IPHIT)
      Z(LOCTRP) = -Z(LOCTRP)
      Z(IA12VL) = -Z(IA12VL)
      Z(IMSVAL) = -Z(IMSVAL)
      Z(IJA12S) = -Z(IJA12S)
      Z(IINTS) = -Z(IINTS)                                              18310   
      Z(IA12TM) = -Z(IA12TM)
      Z(ICOSIN) = -Z(ICOSIN)
      Z(IXLAM) = -Z(IXLAM)
      Z(INLAM) = -Z(INLAM)
      Z(IRIOEX) = -Z(IRIOEX)
C
C     FREE AREAS USED IN ALL CALCULATIONS
C
 995  Z(IRI) = -Z(IRI)
      Z(IRO) = -Z(IRO)                                                  18320   
      Z(ILOR) = -Z(ILOR)
      Z(ILOI) = -Z(ILOI)
      Z(ILIR) = -Z(ILIR)
      Z(ILII) = -Z(ILII)
      Z(IWIO) = -Z(IWIO)
      Z(ISMHPT) = -Z(ISMHPT)
      Z(ISMIPT) = -Z(ISMIPT)
      Z(ISMHVL) = -Z(ISMHVL)
      Z(ISMIVL) = -Z(ISMIVL)
      Z(ISMHWK) = -Z(ISMHWK)                                            18330   
C
      Z(LOGIC) = -Z(LOGIC)
      Z(IDW) = -Z(IDW)
      Z(IABS1) = -Z(IABS1)
      Z(ILILOR) = -Z(ILILOR)
      Z(ILILOI) = -Z(ILILOI)
      Z(IIINDX) = -Z(IIINDX)
      Z(IDWI) = -Z(IDWI)
      Z(IWFII) = -Z(IWFII)
      Z(IWFIO) = -Z(IWFIO)                                              18340   
C
C     AREAS FOR WAVELJ, WAVETC - ONE FOR INCOMING AND ONE FOR OUTGOING
C
C     KEEP THESE FOR MULTIPASS CALCULATIONS.
C
      IF ( IBSPAS .GT. 0 )  GO TO 1500
      DO 1099  I = 1, 2
         Z(NFS(I)) = -Z(NFS(I))
         Z(NGS(I)) = -Z(NGS(I))
         Z(NF1S(I)) = -Z(NF1S(I))                                       18350   
         Z(NG1S(I)) = -Z(NG1S(I))
         Z(IRLVS(I)) = -Z(IRLVS(I))
         Z(IIMVS(I)) = -Z(IIMVS(I))
         Z(ICENTR(I)) = -Z(ICENTR(I))
         IF ( V0SORS(I) .NE. 0 )  Z(ISORS(I)) = -Z(ISORS(I))
         IF ( V0SOIS(I) .NE. 0 )  Z(ISOIS(I)) = -Z(ISOIS(I))
         DO 1059 ITEN = 1, 6
            IF ( VTENS(I,ITEN) .NE. 0 )
     1         Z(ITENS(I,ITEN)) = -Z(ITENS(I,ITEN))
 1059    CONTINUE                                                       18360   
         IF ( TCSWS(I) ) Z(IWAVRS(I)) = -Z(IWAVRS(I))
         IF ( TCSWS(I) ) Z(IWAVIS(I)) = -Z(IWAVIS(I))
 1099 CONTINUE
      Z(IWAVR) = -Z(IWAVR)
      Z(IWAVI) = -Z(IWAVI)
C
C
C     PRINT SOME TIMING INFO.
C
C     BEFORE WE START MESSING AROUND HERE:                              18370   
C     I  TIMES(I)
C     1  WAVELJ INITIALIZATION
C     2  WAVELJ LOOP
C     3  WAVELJ INTERPOLATION AND NORMALIZATIONS
C     4  A12
C     5  PHI, A12 AND FIRST U LOOPS
C     6  H-INTERPOLATIONS
C     7  COMPLETE V-LOOP WITH ALL INTERNALS (5 & 6)
C     8  COMPLETE LO-LOOP WITH ALL INTERNALS (1, 2, 3, 4, & 7)
C                                                                       18380   
 1500  TOTTIM = second() - TSTART
      OTHTIM = TOTTIM - TIMES(8)
      TIMES(2) = TIMES(2) + TIMES(1)
      TIMES(8) = TIMES(8) - TIMES(7) - TIMES(4) - TIMES(3)
     1   - TIMES(2)
      TIMES(7) = TIMES(7) - TIMES(6) - TIMES(5)
C
      write (6, 2581) (TIMES(I), I=4,6), TIMES(2), TIMES(3),
     1  TIMES(7), TIMES(8), OTHTIM, TOTTIM, NUMTIM
2581  FORMAT('0TIME IN A12           ', T35, F7.3, ' SEC'   /           18390   
     1  ' IN PHI & A12 LOOP', T35, F7.3, ' SEC'   /
     2  ' INTERPOLATING H''S', T35, F7.3, ' SEC' /
     3  ' COMPUTING SCATTERING WAVES', T35, F7.3, ' SEC' /
     4  ' INTERPOLATING SCATTERING WAVES', T35, F7.3, ' SEC' /
     5  ' REST OF RI & RO LOOP  ', T35, F7.3, ' SEC'   /
     6  ' REST OF LO LOOP      ', T35, F7.3, ' SEC'   /
     7  ' ALL OTHER TIME', T35, F7.3, ' SEC'   /
     8  ' TOTAL TIME', T35, F7.3, ' SEC'   /
     9  ' NUMBER OF CALLS TO second', T35, I7, ' CALLS' )
      NUMTRM = NUMTRM*NPPHI                                             18400   
      NUMANG = NUMANG*NPPHI
      TIMES(7) = 1.E3*( TIMES(4)+TIMES(5)+TIMES(7) )/NUM6
      TIMES(4) = 1.E6*TIMES(5)/(NUMTRM+1)
      TIMES(5) = 1.E6*TIMES(5)/(NUMANG+1)
      TIMES(6) = 1.E6*TIMES(6)/NUMHIN
      NUM3 = NPPHI*( (NUM3+4*NUM4)/5 )
      NUM4 = NUM4*NPPHI
      TERM = NUMLIS*NPSUM*NPDIF
      TERM = 100*(TERM-NUM5)/TERM
      write (6, 2587)                                                   18410   
 2587 FORMAT ( ' ' )
      IF ( IHSAVE .NE. 2 )
     1  write (6, 2593) NUMTRM, TIMES(4), NUMANG, TIMES(5), NUM3, NUM4
 2593 FORMAT (I12, ' PASSES WERE MADE THROUGH THE INNERMOST LOOP;',
     1    T65, ' AVERAGE TERM TIME =', F9.3, ' MICROSECONDS' /
     2  I12, ' ITERATIONS OF COS(ARG-MU*PHI) WERE MADE;',
     3    T63,   ' AVERAGE COSINE TIME =', F9.3, ' MICROSECONDS' /
     4  I12, ' PASSES WERE MADE THROUGH THE (M1, M2) LOOP' /
     5  I12, ' PASSES WERE MADE THE PHI LOOP' )
      write (6, 2594) NUM6, TIMES(7), NUMHIN, TIMES(6), TERM            18420   
 2594 FORMAT (  I12, ' H''S WERE COMPUTED OR READ',
     1     T69, 'AVERAGE H TIME =', F9.3, ' MILLISECONDS' /
     2  I12, ' H''S WERE FOUND BY INTERPOLATION',
     3      T55, 'AVERAGE H-INTERPOLATION TIME =', F9.3,
     4     ' MICROSECONDS' /
     5  F12.2, '% OF THE (RI,RO) POINTS WERE SKIPPED DUE TO DWCUTOFF.'
     6  // )
C
      RETURN
C                                                                       18430   
      END
C*ID* INGRST   C109.PTOLEMY.SOURCE                          PER701  16:
      SUBROUTINE  INGRST ( IRET )
C
C     INITIALIZES THE GRID FOR THE INELASTIC SCATTERING RADIAL INTEGRAL
C
C     THIS ROUTINE IS CALLED BY MAIN.  IT SETS UP THE ONE-DIMENSIONAL
C     GRID AND POTENTIAL VALUES FOR INRDIN.
C
C     1/77 - FIRST VERSION - S.P.                                       18440   
C     11/22/77 - NEW SCTASYOPIA - S.P.
C     12/4/77 - LINKULES - S.P.
C     5/7/78 - STUFF TO ALLOW 2 COUPLED STATES - S.P.
C     5/23/78 - FIX BUG IN 11/22/77 - ALWAYS DEFINE VWORK - S.P.
C               BIGGER WAVR, WAVI ARRAYS FOR NEW WAVELJ - S.P.
C     3/12/79 - CLEAN UP DEF OF SUMMAX, NSTEPS; DEFINE MORE FOR LINKULES
C     12/20/79 - INELASTIC NAMES INPLACE OF TRANSFER NAMES - S.P.
C                START OF FULL COUPLED CHANNELS CHANGES - S.P.
C      1/2/80 PUT IN FULL COUPLED CHANNELS FOR ROTATIONAL MODEL
C            UP TO 2 ORDER M.R.B.                                       18450   
C     3/18/80 - FIX BUG IN FREEING ITEMP - S.P.
C     4/27/80 - GET NPTMIN, FREE UNNEEDED ARRAYS FOR C.C. - S.P.
C     4/28/80 - REASSIGN LRPTS AFTER GIVALL - S.P.
C     6/24/80 - SAVE RC IN RCUEFF - S.P.
C     7/9/80 - FIX BUG IN FREEING COULH, DON'T OVERFLOW AREA
C              RETURNED BY GIVEAL - S.P.
C     8/25/80 - FIX TYPING ERROR AT STMNT 820 - S.P.
C     12/9/80 - MAKPOT NOLONGER COMPUTES COULOMB; DON'T
C               DEFINE COULOMB COUPLING FOR BETAC=0 - S.P.
C     12/30/80 - FIX ERRORS IN 2ND ORDER NUCLEAR - S.P.                 18460   
C     1/11/81 - ALWAYS 1/R**(LX+1); NO MORE COUPL2 - S.P.
C     7/13/81 - FIX BUG FROM 1/11/81 (JUMPSZ) - S.P.
C     7/16/81 - SAVE LNKBLK TO ALLOW FORM-FACTOR CHANGES - S.P.
C     7/29/81 - FIRST CRUDE STUFF FOR DEFORMED POTENTIALS - S.P.
C     8/28/81 - MORE FOR DEFORMED POTENTIALS - S.P.
C     9/21/81 - DON'T LOOK WHEN THERE ARE NO POTENTIALS - S.P.
C     10/16/81 - DONT' CONDISDER LXTOT FOR MUTUAL - S.P.
C     12/14/18 - LET GETSCT GET WAVEFUNC ALSO FOR C.C. - S.P.
C     4/14/82 - FORMASIS ALSO WORKS FOR DWBA - S.P.
C     6/10/83 - FIX BUGS AT STMNT 235, 408 - S.P.                       18470   
C     7/24/84 - HOTFUDGE - S.P.
C     10/16/84 - USE ABS(SCTASY) - S.P.
C     12/19/84 - USE PARPRT; DEFORMED SI - S.P.
C     4/29/86 - FIX BUG FOR IMAG+DEFORMED+HOTFUDGE - S.P.
C     11/16/01 - initialize IFIRST, ISECND at very start
C
      implicit real*8 ( a-h, o-z )                                      implicit
C
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      parameter ( NUMJWORD = 12 )                                       /jblock/
      COMMON /JBLOCK/  J, JS(5),
     &  JP, JSP, JST,
     &  JPARM1, JPARM2, JPARM3
 
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      COMMON /KANDM/ AKI, AKO, REDMI, REDMO, RIMAX, ROMAX, ISIGS(2),    /kandm/
     &  RSCTS(2), ASCTS(2), RCSCTS(2) ,ISMATS(2), LOMOST, LCRIT,
     &  ISCTMN, ISCTCR, ETAS(2), RCSCTP(2), RCSCTT(2), LCRITS(2),
     &  RATMSS(2), QMIN, ABAR
 
      DIMENSION  AKS(2), REDMS(2), RMAXS(2)
      EQUIVALENCE ( AKI, AKS(1) ), ( REDMI, REDMS(1) ),
     &  ( RIMAX, RMAXS(1) )
 
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
      COMMON /GRIDCM/  RCUEFF, GRDCM1(2),                               /gridcmf
     &  IBINDX, MBINDX, NBINDX, NMFFAC, MXLXGS, NMBFAC,
     & IINHR, IINHI, IRHSR, IRHSI,
     &  INUCH, ICOULH, ILOR, ILOI, ILIR, ILII,
     &  NPTMIN, NOFLO, NUMPT, NCRIT,
     & ISMX, ISMSQ, IPADE, IHOMO,
     &  ISMTSV, IRPTS4, IRPTS,
     &  IGRDC4(5), IDW, IGRDC5(2),
     &  IABS1, IGRDC6(2), GRDCM2, IGRDC7(2), IRWTS,
     &  IGRDC8(2), ICL1FF, ICL1FG, ICL1GF, ICL1GG
 
      LOGICAL ONELSW, IDENSW                                            /inelcm/
      COMMON /INELCM/  JBPF, JBTF, LXMIN, LXMAX, ILILOR, ILILOI, MSTOP,
     &  IA12M, NMLOLX, ONELSW, NUMLX, IRDINT, IELCUP, LILOSZ, NUMLIS,
     &  ILIS, IBETAS(3), ICL2FF, LXSTEP, IDENSW, LSKIP,
     &  JPMIN, JPMAX, JPBASE, NJP, JTMIN, JTMAX, JTBASE, NJT,
     &  IINDXS, ISMATR, ISMATI, NSMAT, NLX, NSPLI, ITOCS,
     &  NASPLI, IUNITR, LIFIT, ILIFIT, NOLFIT, IDELSR, IDELSI
      INTEGER INDXJS(4,2)
      EQUIVALENCE ( INDXJS(1,1), JPMIN )
 
      COMMON /CCBLK/  ICHNDF, ICHNCP, ITRANS, IBASDF, IBASCP,           /ccblk/
     &    ICCBLK(2), IORDX, MCHNVL, ICHNVL,
     &    IHOMOA, IHOMOB, IINHR8, IINHI8
 
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
C
c                                                                       /formf/
c ***  LNKADB was  numLINKULES but only 12 are used ???
c
      COMMON /FORMF/  IBDS(2), NPOTS(2), LBP, LBT, NBP, NBT, JBP, JBT,
     &  BNDMAX(2), BNDSTP(2), NSTPBD(2), RBNDS(2), ABNDS(2),
     &  RCBNDS(2), BNDMAS(2), BRATMS(2), RSOBDS(2), ASOBDS(2),
     &  VBNDS(2), VSOBDS(2), TAUBDS(2), LNKADB(6, 2, 12)
 
      DIMENSION R2S(4)
      EQUIVALENCE ( R2S(1), RBNDS(1) )
C
c                                                                       /lnkblk/
c  STRUCTURE OF   /LNKBLK/
c
c  THERE IS A BLOCK OF 3 DOUBLE WORDS FOR EACH POSSIBLE USE
c  OF A LINKULE.  THE NUMLNK = NUMLINKULES USES ARE IN THE ORDER
c    REALPOTEN  IMAGPOTEN  REALVSO  IMAGVSO  COULOMB
c    WAVEFUNCTION  AND 6 TENSOR POTENTIALS
c  THE THREE-DOUBLE-WORD BLOCKS EACH HAVE THE STRUCTURE
c
c    LNKNAM(1,I)   LINKULE NAME
c
c      LNKADR(3,I)   LINKULE ADDRESS, O IF NO LINKULE IN USE.
c      LNKADR(4,I)   0 - NO L OR J DEPENDENCE IN POTENTIAL
c                    1 - L DEPENDENCE BUT NO J DEPENDENCE
c                    2 - BOTH L  AND J DEPENDENCE
c
c      LNKADR(5&6,I)  MYINTS - A TWO-ELEMENT ARRAY THAT THE
c                     LINKULE MAY USE FOR COMMUNICATION BETWEEN
c                     CALLS TO ITSELF.
c
      parameter ( NUMLINKULES = 13 )
      COMMON /LNKBLK/  NUMLNK, IUNIQU, LNKADR(6,NUMLINKULES)
      character*8  LNKNAM(3,NUMLINKULES)
      EQUIVALENCE ( LNKNAM(1,1), LNKADR(1,1) )
 
      COMMON / TEMPVS /  TVR, TVI, TVSOR, TVSOI, TAR, TAI               /tempvs/
 
      COMMON/NAMCOM/ANAMES(1)
C
      character*1  LINKID(4) / '*', '3', '0', '0' /                     18500   
C
      LOGICAL SOSW, SOISW, DRIVSW, DBUGSW
      LOGICAL CCSW
      REAL*4  FG(4)
      INTEGER  GIVEAL,CHOPIT
c
C
      IFIRST = 0
      ISECND = 0
      IRET = 0                                                          18510   
      IPRT = MOD( IPRINT, 10 )
      DBUGSW = IPRT .GE. 4
      CCSW = PROBLM .EQ. 24
C
      I = 1
      IF ( CCSW )  GO TO 150
C
C     FIND WHERE LMIN SCATTERING WAVE EXCEEDS 1E-15
C
 110  NSTEPS = NSTPSS(1)                                                18520   
      LSCTMN = Z(ISCTMN)
      DO 129  I = 1, NSTEPS
         IF ( DABS(ALLOC(LSCTMN+I)) .GT. 1.D-15 )  GO TO 140
 129  CONTINUE
      write (6, 133)
 133  FORMAT ( '0**** ERROR:  U(LMIN) < 1E-15 EVERYWHERE.' )
      RETURN
C
C     USE THIS AS THE LOWER POINT OF THE INTEGRAL, EXCEPT FOR C.C.
C                                                                       18530   
 140  Z(ISCTMN) = -Z(ISCTMN)
      Z(ISCTCR) = -Z(ISCTCR)
      GO TO 160
C
C     FOR C.C. WE START AT NFIRST OF THE LOWEST L.
C
 150  I = MAX0( 1, LASTNF(1)-5 )
C
 160  IF ( SUMMIN .EQ. UNDEF )  SUMMIN = RSTEPS(1)*(I-1)
      NPTMIN = SUMMIN/RSTEPS(1) + 0.5                                   18540   
      IF ( SUMMAX .EQ. UNDEF )  SUMMAX = ABS(SCTASY)
      IF ( CCSW )  SUMMAX = ASYMPS(1)
      IF ( SUMMID .EQ. UNDEF )  SUMMID = .5*(SUMMIN+SUMMAX)
C
C     NUMBER OF GAUSS POINTS IS DETERMINED FROM SUMPTSPER,
C     EXCEPT FOR C.C. IT IS NUMBER OF INCOMING STEPS
C
      NUMPT = (SUMMAX-SUMMIN) * ( SUMPTS*(AKI+AKO)/(4*PI) )
      NUMPT = MAX0( NUMPT, NPSUM )
      NMPTSV = NUMPT                                                    18550   
      IF ( CCSW )  NUMPT = NSTPSS(1) + 1
      IF ( CCSW )  NMPTSV = NUMPT-NPTMIN
      RMAXS(1) = SUMMAX
      RMAXS(2) = SUMMAX
C
C     MAY HAVE TO REDEFINE WAVELJ WORK AREAS
C
      I = SUMMAX/RSTEPS(1) + .5
      NSTP2S(1) = MAX0( I, NSTP2S(1) )
      I = SUMMAX/RSTEPS(2) + .5                                         18560   
      NSTP2S(2) = MAX0( I, NSTP2S(2) )
      I = MAX0( NSTP2S(1), NSTP2S(2) )
      IF ( I .LE. MAX0( NSTPSS(1), NSTPSS(2) ) )  GO TO 200
      IWAVR = NALLOC( I+6, 'WAVER   ' )
      IWAVI = NALLOC( I+6, 'WAVEI   ' )
C
C     THE ARRAYS WILL BE:
C       IRPTS, IRWTS - GAUSS POINTS  AND WEIGHTS
C       IRPTS4 - REAL*4 GAUSS POINTS FOR WAVELJ INTERPOLATOR
C       INUCH - COMPLEX NUCLEAR POTENTIAL PART OF H WITH R'S AND GAUSS  18570   
C             WEIGHT BUT NO BETA.
C       ICOULH - COULOMB PART OF H WITH RC AND GAUSS WEIGHT BUT NO BETAS
C
 200  IF ( CCSW )  GO TO 210
      IRPTS = NALLOC( NUMPT, 'RPTS    ' )
      IRWTS = NALLOC( NUMPT, 'RWT   S ' )
      IRPTS4 = NALLOC( (NUMPT+FACFR4-1)/FACFR4, 'RPTS4 ' )
      INUCH = NALLOC( 2*NUMPT, 'NUCH    ' )
      ICOULH = NALLOC( NUMPT, 'COULH   ' )
      IFIRST = 1                                                        18580   
      GO TO 300
C
C     DEFINE NUCLEAR AND COULOMB H-ARRAYS (RADIAL PART)
C     FOR COUPLED CHANNELS.
C
C     DETERMIN HOW MANY DIFFERENT RADIAL FORMS WILL BE NEEDED
C     AND SET UP THE POINTERS FOR THE NUCLEAR FORM FACTORS
C
 210  LBASCP=FACFR4*Z(IBASCP)-FACFR4+1
      NBASCP=ILLOC(LBASCP)                                              18590   
      MBASCP=ILLOC(LBASCP+1)
      LBASCP=ILLOC(LBASCP+2)+LBASCP
      NNUCFF = 0
      IFIRST = 0
      ISECND = 0
      DO 229  I = 1, NBASCP
         K = LBASCP + (I-1)*MBASCP
         IF ( ALLOC4(K+4) .NE. 0 )  GO TO 215
         ILLOC(K+9) = 0
         GO TO 229                                                      18600   
 215     IPT = ILLOC(K+7)
         IF ( ILLOC(K+9) .NE. NOTDEF )  GO TO 229
C
C     THIS IS A NEW RADIAL FORM
C
         LX = ILLOC(K+3)
         NNUCFF = NNUCFF+1
         IF ( IPT .EQ. 1 )  IFIRST = NNUCFF
         IF ( IPT .EQ. 2 )  ISECND = NNUCFF
         DO 219  II = I, NBASCP                                         18610   
            KK = LBASCP + (II-1)*MBASCP
            IF ( ILLOC(KK+7) .NE. IPT )  GO TO 219
C
C     FOR DEFORMED MUST ALSO CONSIDER LX EXCEPT FOR MUTUAL
C
            ITEMP = MOD( IPT, 100 )
            IF ( ( ITEMP .EQ. 3  .OR. ITEMP .EQ. 4 )  .AND.
     1         LX .NE. ILLOC(KK+3) )  GO TO 219
            IF ( ALLOC4(KK+4) .EQ. 0 )  GO TO 219
            ILLOC(KK+9) = 2*NNUCFF-1                                    18620   
 219     CONTINUE
 229  CONTINUE
C
C     NOW DETERMIN HOW MANY COULOMB COUPLING RADIAL FORMS
C     ARE NEEDED AND ASSIGN THE COULOMB FORM FACTOR POINTERS
C
      NCOUFF = 0
      DO 259  I = 1, NBASCP
         K = LBASCP + (I-1)*MBASCP
         IF ( ALLOC4(K+5) .NE. 0 )  GO TO 235                           18630   
         ILLOC(K+10) = 0
         GO TO 259
 235     IF ( ILLOC(K+10) .NE. NOTDEF )  GO TO 259
         IORDER = ILLOC(K+2)
         IMULT = ILLOC(K+3)
         NCOUFF = NCOUFF + 1
         DO 249  II = 1, NBASCP
            KK = LBASCP + (II-1)*MBASCP
            IF ( ILLOC(KK+2) .NE. IORDER  .OR.
     1           ILLOC(KK+3) .NE. IMULT  .OR.                           18640   
     2           ALLOC4(KK+5) .EQ. 0 )  GO TO 249
            ILLOC(KK+10) = NCOUFF
 249     CONTINUE
 259  CONTINUE
C
      write (6, 263) NNUCFF, NCOUFF
 263  FORMAT ( '0THERE ARE', I3, ' NUCLEAR AND', I3,
     1  ' COULOMB FORM-FACTOR RADIAL FUNCTIONS.' )
C
C     NUCLEAR STORAGE FOR DERIVATIVE OF W.S.                            18650   
C
      I = MAX0( (2*NUMPT*NNUCFF+FACFR4-1)/FACFR4, 1 )
      INUCH=NALLOC(I, 'NUCH    ')
      I = MAX0( (NUMPT*NCOUFF+FACFR4-1)/FACFR4, 1 )
      ICOULH=NALLOC( I, 'COULH   ')
C
C     NOW SETUP THE POTENTIALS * GAUSS WEIGHTS * R'S
C
C     FIRST WE GET THE POTENTIALS ON THE ARRAY ( 0, SUMMAX )
C     THEN WE DEFINE CUBICS AND USE THEM TO GET THE DERIVATIVES.        18660   
C
C     TO GET THE POTENTIALS WE SETUP SOME WORK AREAS INPLACE OF
C     THE CHANNEL 1 ARRAYS.
C
 300  ICHANW = 1
      NSTEP1 = NSTPSS(1)
      IREAL1 = IRLVS(1)
      IIMAG1 = IIMVS(1)
      ICENT1 = ICENTR(1)
C                                                                       18670   
C     WE USE THE STEPSIZE OF THE FIRST CHANNEL
C     WE GO SLIGHTLY FURTHER TO GIVE THE SPLINES TIME TO SETTLE DOWN
C
      STEPSZ = RSTEPS(1)
      H = HS(1)
      E = ES(1)
      NSTEP = SUMMAX/STEPSZ + 20.5
      NSTEPS = NSTEP+1
      NSTPSS(1) = NSTEP
      IRLVS(1) = NALLOC(NSTEPS, 'INELREAL')                             18680   
      IIMVS(1) = NALLOC(NSTEPS, 'INELIMAG')
      ICENTR(1) = NALLOC(NSTEPS, 'INELCENT')
      IVWORK = NALLOC(NSTEPS, 'VWORK   ' )
C
C     SETUP STUFF AS IF IN FIRST CHANNEL
C
      AMP = AMA
      AMT = AMBIGA
      AM = REDMI
      IZP = IZS(1)                                                      18690   
      IZT = IZS(3)
C
C     INITIALIZE LINKULES IF NEEDED
C
      DO 359  II = 1, 6
         I = II
         IF ( II .EQ. 6 )  I = 13
         IF ( LNKADR(3,I) .EQ. 0 )  GO TO 359
C
C     GENERATE THE SPECIAL UNIQUE NAME                                  18700   
C
         IUNIQU = IUNIQU + 1
         LINKID(3) = char( ichar('0') + MOD(IUNIQU/10, 10) )
         LINKID(4) = char( ichar('0') + MOD(IUNIQU, 10) )
C
C     MAKE INITIALIZING CALL
C
         CALL LINKUL ( LNKADR(3,I), LNKNAM(1,I), LNKADR(5,I), I, 1,
     1      IRET, L, J, 0.D0, STEPSZ, NSTEP+1, DUMMY, DUMMY, LINKID )
         IF ( IRET .GE. 0 )  GO TO 340                                  18710   
         IRET = 0
         RETURN
 340     LNKADR(4,I) = IRET
 359  CONTINUE
C
C
C     NOW COMPUTE THE POTENTIAL, NWP=3 IS CONVERT TO NWP=1
C    BY MAKPOT EXCEPT THE COULOMB IS NOT COMPUTED.1
C
C     FOR C.C. THE RESULTS OF THIS CALL ARE USED FOR THE                18720   
C     FIRST AND SECOND DERIVATIVE FORMS.  LX=-1 INDICATES THIS
C
      LX = -1
      IRET = 1
      J = NOTDEF
      IF ( IFIRST+ISECND .NE. 0 )  CALL MAKPOT ( 3, IRET )
      DRIVSW = KFRMTP .EQ. 1
      IF ( IRET .GE. 0 )  GO TO 400
      IRET = 0
      RETURN                                                            18730   
C
C     SUMMARIZE THE POTENTIALS TO BE USED
C
C     FOLLOWING LIFTED FROM WAVSET
C
 400  IF ( .NOT. DRIVSW )  write (6, 403)
 403  FORMAT ( '-POTENTIALS WHOSE DERIVATIVES ARE THE',
     1  ' EFFECTIVE INTERACTION OPERATOR:' )
      IF ( DRIVSW )  write (6, 408)
 408  FORMAT ( '-RADIAL FORM FACTORS FOR FIRST-ORDER COUPLINGS.' )      18740   
      IF ( DRIVSW .AND. ISECND .NE. 0 )  write (6, 409)
 409  FORMAT ( ' (DERIVATIVES OF THESE ARE USED FOR SECOND ORDER.)' )
C
      SOSW = .FALSE.
      SOISW = .FALSE.
      ETA = ETAS(1)
C
C     IF POSSIBLE, RECOMPUTE R0'S FOR PRINTING
C
      TEMP1 = 0                                                         18750   
      TEMP2 = 0
      TEMP3 = 0
      TEMP4 = 0
      TEMP5 = 0
      TEMP6 = 0
      IF ( R0MASS .EQ. UNDEF )  GO TO 420
      TEMP1 = R/R0MASS
      IF ( TVI .NE. 0 )  TEMP2 = RI/R0MASS
      IF ( SOSW ) TEMP3 = RSO/R0MASS
      IF ( SOISW )  TEMP4 = RSOI/R0MASS                                 18760   
      IF ( VSI .NE. 0 )  TEMP5 = RSI/R0MASS
      TEMP6 = RC/R0MASS
C
 420  write (6, 429)
 429  FORMAT (
     1  '0POTENTIAL', T20, 'COUPLING CONS.', T38, 'RADIUS',
     2      T48, 'DIFFUSENESS', T63, 'RADIUS PARAMETER' /)
      CALL PARPRT ( 1, 'REAL CENTRAL       ', TVR, R, TAR,
     1  TEMP1, POWRL, '   POWER', IRET )
      CALL PARPRT ( 2, 'VOLUME ABSORPTION   ', TVI, RI, TAI,            18770   
     1  TEMP2, POWIM, '   POWER   ', IRET )
      CALL PARPRT ( 13, 'SURFACE ABSORPTION   ', VSI, RSI, ASI,
     1  TEMP5, 0.D0, '        ', IRET )
      CALL PARPRT ( 3, 'REAL SPIN-ORBIT   ', VSO, RSO, ASO,
     1  TEMP3, TAU, '     TAU', IRET )
      CALL PARPRT ( 4, 'IMAG. SPIN-ORBIT   ', VSOI, RSOI, ASOI,
     1  TEMP4, TAUI, '    TAUI', IRET )
      CALL PARPRT ( 5, 'COULOMB           ', ETA, RC, 0.D0,
     1  TEMP6, 0.0D0, '        ', IRET )
      IF((RCP.EQ.0).OR.(RCT.EQ.0)) GO TO 500                            18780   
      write (6, 487) RCP, RCT, RC0P, RC0T
  487 FORMAT( ' FOLDED COULOMB POTENTIALS - RCP = ',F7.4,2X,
     1'RCT = ',F7.4,2X,'RC0P = ',F7.4,2X,'RC0T = ',F7.4)
C
 500  write (6, 503)
 503  FORMAT ( '0' )
      GO TO 600
C
C     PREPARE TO COMPUTE DERIVATIVE OF POTENTIAL
C     IF THE DERIVATIVE WAS DIRECTLY SUPPLIED, THEN WE                  18790   
C     DON'T NEED TO COMPUTE IT UNLESS IF THERE IS 2ND ORDER.
C
 600  ICUBIC = 0
      IF ( IFIRST+ISECND .EQ. 0 ) GO TO 605
      IF ( ISECND .EQ. 0  .AND. DRIVSW .AND. CCSW )  GO TO 605
      ICUBIC = NALLOC( 4*NSTEPS, 'INELCUBS' )
      LR = Z(ICUBIC)
      LB = LR+NSTEPS
      LC = LB+NSTEPS
      LD = LC+NSTEPS                                                    18800   
 605  LREALV = Z(IRLVS(1))-1
      LIMAGV = Z(IIMVS(1))-1
      LVWORK = Z(IVWORK)
      LNUCH = Z(INUCH) - 2
      LCOULH = Z(ICOULH) - 1
      IF ( IFIRST+ISECND .EQ. 0 ) GO TO 630
      IF ( CCSW )  GO TO 620
C
C     GET THE GAUSS POINTS FOR DWBA
C                                                                       18810   
      LRPTS = Z(IRPTS) - 1
      LRWTS = Z(IRWTS) - 1
      LRPTS4 = FACFR4*Z(IRPTS4) - FACFR4
      CALL CUBMAP ( MAPSUM, SUMMIN, SUMMID, SUMMAX, GAMSUM,
     1  ALLOC(LRPTS+1), ALLOC(LRWTS+1), NUMPT )
C
C
C     FIRST DO THE REAL AND COULOMB PARTS
C
C     GET THE SPLINES                                                   18820   
C     GENERATE INPUT GRID FOR THE SPLINES
C
 620  RVAL = 0
      IF ( ISECND .EQ. 0  .AND. DRIVSW .AND. CCSW )  GO TO 630
      DO 629  I = 1, NSTEPS
         ALLOC(LR-1+I) = RVAL
         RVAL = RVAL + STEPSZ
 629  CONTINUE
C
      CALL SPLNCB ( NSTEPS, ALLOC(LR), ALLOC(LREALV+1),                 18830   
     1  ALLOC(LB), ALLOC(LC), ALLOC(LD) )
C
 630  VC = R2S(4)
      RCUEFF = RC
C
      IF ( CCSW )  GO TO 670
C
      ASSIGN 652 TO IGOTO
      IF ( DRIVSW )  ASSIGN 654 TO IGOTO
      DO 659  I = 1, NUMPT                                              18840   
         RVAL = ALLOC(LRPTS+I)
         WT = ALLOC(LRWTS+I)
         ALLOC4(LRPTS4+I) = RVAL
         N = RVAL/STEPSZ
         X = RVAL - N*STEPSZ
         GO TO IGOTO, (652, 654)
 652     XX = ( ALLOC(LB+N) + X*(2*ALLOC(LC+N) + X*3*ALLOC(LD+N) ))
         GO TO 655
 654     XX = ALLOC(LREALV+N+1) + X*( ALLOC(LB+N) + X*( ALLOC(LC+N)
     1      + X*ALLOC(LD+N) ) )                                         18850   
 655     TERM = + (12*E/H**2) * R2S(1) * WT * XX
         ALLOC(LNUCH+2*I) = TERM
         IF ( RVAL .LT. RC )  XX = (RVAL/RC**2)**LXMIN / RC
         IF ( RVAL .GE. RC )  XX = 1 / RVAL**(LXMIN+1)
         ALLOC(LCOULH+I) = -WT*VC*XX
 659  CONTINUE
      GO TO 700
C
C     SET UP RADIAL PARTS OF REAL POT FOR COUPLED CHANNELS
C     WE STORE                                                          18860   
C        - (2*MU/HBARC**2) (STEPSIZE**2/12) DV/DR
C
C     NOTE THAT MAKPOT HAS GENERATED ESPECIALLY FOR US
C        - (H**2/12) (V/E)
C
 670  LNUCH=FACFR4*Z(INUCH)-FACFR4+1
      WT = - (2*REDMI/HBARC**2) * (STEPSZ**2/12.) * (12.*E/H**2)
      IF ( IFIRST .EQ. 0 )  GO TO 672
      K = LNUCH + 2*NUMPT*(IFIRST-1)
      IF (DRIVSW)  LB = LREALV+1                                        18870   
C
      DO 671 I=1,NUMPT
         ALLOC4(K+2*I-2) = -WT * ALLOC(LB+I-1)
 671  CONTINUE
C
 672  IF ( ISECND .EQ. 0 )  GO TO 700
C
C     NOW GO ON TO SECOND ORDER
C     WE STORE
C        + (2*MU/HBARC**2) (STEPSIZE**2/12) D**2 V / DR**2              18880   
C
      CALL SPLNCB ( NSTEPS, ALLOC(LR), ALLOC(LB),
     1   ALLOC(LC), ALLOC(LD), ALLOC(LVWORK) )
C
      K = LNUCH + 2*NUMPT*(ISECND-1)
      DO 675 I=1,NUMPT
         ALLOC4(K+2*I-2) = +WT * ALLOC(LC+I-1)
 675  CONTINUE
C
C     NOW GO ON TO THE IMAGINARY PART                                   18890   
C
 700  IF ( IFIRST+ISECND .EQ. 0 ) GO TO 770
      IF ( ISECND .EQ. 0  .AND. DRIVSW .AND. CCSW )  GO TO 750
      CALL SPLNCB ( NSTEPS, ALLOC(LR),
     1 ALLOC(LIMAGV+1),  ALLOC(LB), ALLOC(LC), ALLOC(LD) )
C
      IF ( CCSW )  GO TO 750
C
      ASSIGN 732 TO IGOTO
      IF ( DRIVSW )  ASSIGN 734 TO IGOTO                                18900   
      DO 739  I = 1, NUMPT
         RVAL = ALLOC(LRPTS+I)
         WT = ALLOC(LRWTS+I)
         N = RVAL/STEPSZ
         X = RVAL - N*STEPSZ
         GO TO IGOTO, (732, 734)
 732     XX = ( ALLOC(LB+N) + X*(2*ALLOC(LC+N) + X*3*ALLOC(LD+N) ))
         GO TO 735
 734     XX = ALLOC(LIMAGV+N+1) + X*( ALLOC(LB+N) + X*( ALLOC(LC+N)
     1      + X*ALLOC(LD+N) ) )                                         18910   
 735     TERM = + (12*E/H**2) * R2S(2) * WT * XX
         ALLOC(LNUCH+2*I+1) = TERM
 739  CONTINUE
      GO TO 950
C
C     SET UP RADIAL PARTS OF IMAG POT FOR COUPLED CHANNELS
C
 750  IF ( DRIVSW )  LB = LIMAGV+1
      IF ( IFIRST .EQ. 0 )  GO TO 760
      K = LNUCH + 2*NUMPT*(IFIRST-1)                                    18920   
      DO 759 I=1,NUMPT
         ALLOC4(K+2*I-1) = -WT * ALLOC(LB+I-1)
 759  CONTINUE
C
 760  IF ( ISECND .EQ. 0 )  GO TO 770
C
C      NOW GO ON TO SECOND ORDER
C
      CALL SPLNCB ( NSTEPS, ALLOC(LR), ALLOC(LB),
     1   ALLOC(LC), ALLOC(LD), ALLOC(LVWORK) )                          18930   
C
      K = LNUCH + 2*NUMPT*(ISECND-1)
      DO 769 I=1,NUMPT
         ALLOC4(K+2*I-1) = +WT * ALLOC(LC+I-1)
 769  CONTINUE
C
C     NOW PROCESS DEFORMED REQUESTS FOR C.C.
C
 770  LBASCP=FACFR4*Z(IBASCP)-FACFR4+1
      LBASCP=ILLOC(LBASCP+2)+LBASCP                                     18940   
      IB1 = 1
      IF ( NNUCFF .EQ. 0 )  GO TO 800
      DO 799  IP = 1, NNUCFF
         IF ( IP .EQ. IFIRST  .OR.  IP .EQ. ISECND )  GO TO 799
C
C     FIND AN EXAMPLE OF THIS RADIAL FORM
C
 775     IPP = (ILLOC(LBASCP+9)+1)/2
         IF ( IPP .EQ. IP )  GO TO 780
         LBASCP = LBASCP + MBASCP                                       18950   
         IB1 = IB1+1
         IF ( IB1 .LE. NBASCP )  GO TO 775
         write (6, 778) IP, IPP
 778     FORMAT ('0*** INTERNAL ERROR AT 778 IN INGRST', 2I8 )
         IRET = 0
         RETURN
 780     L = ILLOC(LBASCP+2)
         LX = ILLOC(LBASCP+3)/2
         J = ILLOC(LBASCP+7)
C                                                                       18960   
C    FOR VALUES OF MODL SEE IPT1 IN BASCPL JUST AFTER 700
C    HERE FOR MODEL 4 (HOTFUDGE) WE MUST SET UP THE WOODS SAXON
C    PARAMETERS FROM THE PARAMS.  ALSO THERE IS NO IMAG COUPLING
C    IN HOTFUDGE.
C
         MODL = MOD(J,100)
         T1 = TVR
         T2 = R
         T3 = TAR
         T4 = POWRL                                                     18970   
         T5 = TVI
         T6 = VSI
         IT1 = LNKADR(3,1)
         IT2 = LNKADR(3,2)
         IF ( MODL .NE. 6 )  GO TO 782
         TVR = 1.
         INDXP = J/100
         R = R0MASS*PARAMS(INDXP)
         TAR = PARAMS(INDXP+1)
         POWRL = 1                                                      18980   
         TVI = 0
         VSI = 0
         LNKADR(3,1) = 0
         LNKADR(3,2) = 0
         write (6, 781) INDXP, R, TAR
 781     FORMAT ( ' HOTFUDGE:', I4, 5X, 'R =', F7.3, 5X, 'A =', F7.3 )
 782     IF ( DBUGSW )  write (6, 783) IP, IB1, L, LX, J
 783     FORMAT ( ' GENERATING NUCLEAR FF:', 5I10 )
         CALL MAKPOT ( 3, IRET )
         TVR = T1                                                       18990   
         R = T2
         TAR = T3
         POWRL = T4
         TVI = T5
         VSI = T6
         LNKADR(3,1) = IT1
         LNKADR(3,2) = IT2
C
C     IN THIS CASE WE JUST COPY THE RESULTS OF MAKPOT
C                                                                       19000   
         K = LNUCH + 2*NUMPT*(IP-1)
         DO 789  I = 1, NUMPT
            ALLOC4(K+2*I-2) = -WT*ALLOC(LREALV+I)
            ALLOC4(K+2*I-1) = -WT*ALLOC(LIMAGV+I)
 789     CONTINUE
 799  CONTINUE
C
C     SET UP RADIAL PARTS OF COULOMB POT FOR COUPLED CHANNELS
C
 800  IF ( NCOUFF .EQ. 0 )  GO TO 950                                   19010   
      LCOULH=Z(ICOULH)
      LCOULH=FACFR4*(LCOULH-1)+1
      LBASCP=FACFR4*Z(IBASCP)-FACFR4+1
      LBASCP=ILLOC(LBASCP+2)+LBASCP
      IP = 1
C
C     LOOP OVER ALL COUPLINGS FINDING 1ST INSTANCE
C     OF EACH RADIAL FORM.
C
C                                                                       19020   
      DO 869 J=1,NBASCP
         LABEL=(J-1)*MBASCP+LBASCP
         IORDER=ILLOC(LABEL+2)
         IMULT=ILLOC(LABEL+3)
         IPOINT=ILLOC(LABEL+10)
         IF(IPOINT.NE. IP )GO TO 869
         IMT=IMULT/2
C
C     THE RADIAL FACTORS IN INGRST ARE COMPUTED SUCH THAT
C     WHEN MULTIPLIED BY THE X FACTORS IN BASCPL THE CORRECT            19030   
C     ANSWER RESULTS
C
C     THEY ARE
C
C       - (2*MU/HBARC**2) (STEPSIZE**2/12) (3 ZP ZT ALPHA HBARC) F(R)
C     WHERE
C       FIRST ORDER:
C         F(R) = R**LX / RC**(2LX+1)    R < RC
C              = 1/R**(LX+1)            R > RC
C       SECOND ORDER:                                                   19040   
C         F(R) = (1-LX)/(2+LX) R**LX / R**(2LX+1)   R < RC
C              = 1 / R**(LX+1)                      R > RC
C
C     THE FOLLOWING FORMULAS ARE CORRECT FOR A POINT AND SINGLE
C     DEFORMED SPHERE OF DEFORMATION RADIUS RC.  IN THIS CASE WE
C     WOULD ALSO HAVE RT=RC IN THE COUPLING CONSTANTS.  WE USE
C     THESE FORMULAS EVEN WHEN RP IS NOT ZERO.  THIS GIVES THE
C     CORRECT RESULT FOR R > RC  BUT IS INCORRECT FOR R < RC.
C     HOWEVER, R < RC IS NOT IMPORTANT.
C                                                                       19050   
         RVAL = -STEPSZ
         WT = -(2*REDMI/HBARC**2) * (STEPSZ**2/12.) * VC
         IPOW = IMT
         TMPFAC = 1/RC**(IMULT+1)
         IF (IORDER .EQ. 2)  TMPFAC = (1.D0-IMT)/(2+IMT) * TMPFAC
         ASSIGN 830 TO IGOTO
         IF ( DBUGSW )  write (6, 823) IP, J, IORDER, IMULT,
     1      ILLOC(LABEL+7)
 823     FORMAT ( ' GENERATING COULOMB FF:', 4I10, '/2', I10 )
         DO 849 I1=1,NUMPT                                              19060   
            RVAL = RVAL + STEPSZ
C
            GO TO IGOTO, ( 830, 835 )
C
C     CHECK TO SEE IF  R < RC  STILL
C
 830        IF ( RVAL .LT. RC )  GO TO 835
            ASSIGN 835 TO IGOTO
            IPOW = -(IMT+1)
            TMPFAC = 1                                                  19070   
C
 835        XX = TMPFAC * RVAL**IPOW
            ALLOC4(LCOULH+I1-1+(IP-1)*NUMPT) = WT*XX
 849     CONTINUE
         IP = IP+1
         IF ( IP .GT. NCOUFF )  GO TO 950
 869  CONTINUE
C
C
C     FREE WORK AREAS                                                   19080   
C
 950  IF (ICUBIC .NE. 0)  Z(ICUBIC) = -Z(ICUBIC)
      Z(IRLVS(1)) = -Z(IRLVS(1))
      Z(IIMVS(1)) = -Z(IIMVS(1))
      Z(ICENTR(1)) = -Z(ICENTR(1))
      Z(IVWORK) = -Z(IVWORK)
C
C     RESTORE FIRST CHANNEL
C
      NSTPSS(1) = NSTEP1                                                19090   
      IRLVS(1) = IREAL1
      IIMVS(1) = IIMAG1
      ICENTR(1) = ICENT1
C
      IF ( IPRT .EQ. 0 )  GO TO 990
C
C     SUMMARIZE THINGS NICELY
C
      write (6, 983)
     1  NMPTSV, MAPSUM, GAMSUM, SUMMIN, SUMMID, SUMMAX                  19100   
 983  FORMAT (
     5  '-ONE-DIMENSIONAL INTEGRATION GRID:' /
     6  '0NUM. PTS.   MAP TYPE   GAMMA    MINIMUM',
     7    '   "MID. PT."   MAXIMUM' /
     8  I6, I11, F11.2, F10.2, F12.2, F14.2 )
C
 990  IRET = 1
      RETURN
      END
C*ID* INIT8    C109.PTOLEMY.SOURCE                          PER701  15: 19110   
      SUBROUTINE INIT8 ( I, X8 )
C
C     INITIALIZES ALLOCATOR ARRAY I TO CONSTANT X, ANY LENGTH.
C
C
C     8/7/79 - NEW ROUTINE - RPG
C     6/3/80 - CDC VERSION - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      COMMON /LENGTH/ LENG(1)
C
      REAL*4  X4
      INTEGER*2  X2
      character*1  X1
C
C
C
C     ENTRY  INIT8  IS FOR LENGTH 8.
C                                                                       19130   
      N = LENG(I)
      LL = Z(I) - 1
      DO 99  K = 1, N
         ALLOC(LL+K) = X8
 99   CONTINUE
      RETURN
C
C
C     ENTRY  INIT4  IS FOR LENGTH 4 reals
C     The input scalar is Real*8 to allow double constants everywheres  19140   
C
      ENTRY INIT4 ( I, X8 )
      N = LENG(I)*FACFR4
      LL = Z(I)*FACFR4 - FACFR4
      DO 199  K = 1, N
         ALLOC4(LL+K) = X8
 199  CONTINUE
      RETURN
C
C     ENTRY  INIT4I  IS FOR LENGTH 4 integers                           19150   
C
      ENTRY INIT4i ( I, i4 )
      N = LENG(I)*FACFR4
      LL = Z(I)*FACFR4 - FACFR4
      DO   K = 1, N
         illoc(LL+K) = i4
      ENDDO
      RETURN
C
C                                                                       19160   
C     ENTRY  INIT2  IS FOR LENGTH 2
C
      ENTRY INIT2 ( I, X2 )
      N = LENG(I)*FACFR2
      LL = Z(I)*FACFR2 - FACFR2
      DO 299  K = 1, N
         ILLOC2(LL+K) = X2
 299  CONTINUE
      RETURN
C                                                                       19170   
C
C     ENTRY  INIT1  IS FOR LENGTH 1
C
      ENTRY INIT1 ( I, X1 )
      N = LENG(I)*FACFR1
      LL = Z(I)*FACFR1 - FACFR1
      DO 399  K = 1, N
         chlloc(LL+K) = X1
 399  CONTINUE
      RETURN                                                            19180   
      END
C*ID* INRDIN   C109.PTOLEMY.SOURCE                          PER701  17:
      SUBROUTINE INRDIN ( IRTN )
C
C     COMPUTES THE INELASTIC EXCITATION RADIAL INTEGRALLS  I(LI,LO,LX)
C
C     COMPUTES THE INELASTIC EXCITATION INTEGRALS
C       INTEGRAL(0 TO SUMMAX) DR U(R) H U(R)
C     WHERE H IS THE FULL H
C     AND THEN COMPUTES                                                 19190   
C       I(NUCLEAR) = I(0 TO SUMMAX) + I(SUMMAX TO INF) - I(COULOMB)
C
C     12/15/76 - BASED ON INELDC - S. P.
C     4/24/78 - INTERCHANGE LI AND LO - S.P.
C     5/24/78 - NEW WAVELJ CALLS - S.P.
C     3/6/79 - COMPUTE S-MATRIX - S.P.
C     5/12/79 - CLINTS TIME PRINTED SEPARATELY - S.P.
C     11/3/79 - USE BOB'S S-MATRIX ADDRESSES - S.P.
C               INTRODUCE FINAL EXTRA I INTO THE S-MATRICES - S.P.
C     11/20/79 - S-MATRICES STORED BY LO-LI - S.P.                      19200   
C     12/27/79 - STANDARD MORTRAN.  NOTE VAX WARNING - RPG
C     1/18/80 - CVA%M,%F FOR VAX COMPLEX*16 - RPG
C     4/18/80 - GRIDCMFORINEL -- HOW WAS THIS LOST? - S.P.
C     4/26/80 - PBUGSW NOLONGER IN WAVCOM; FREE MORE - S.P.
C     6/2/80 - COMMA IN DATA LIST FOR PHASES - S.P.
C     6/24/80 - USE RCUEFF INSTEAD OF RC - S.P.
C     8/11/80 - CALL SETLOG - S.P.
C     9/23/80 - EXTRA (-)**LX TO MAKE I**(-LX-1) - S.P.
C     10/28/81 - ROOT 2 FOR IDENTICAL PARTICLES - S.P.
C     5/4/82 - FIX K TO INDXS FOR 1/2 INTEGER SPINS - S.P.              19210   
C     8/14/86 - 5/82 FIX WAS INCORRECT FOR PROJECTILE WITH SPIN
C
C
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      CHARACTER*1  REACT, HEADER                                        /hedcom/
      COMMON /HEDCOM/  REACT(45), HEADER(65)
 
      COMMON /GRIDCM/  RCUEFF, GRDCM1(2),                               /gridcmf
     &  IBINDX, MBINDX, NBINDX, NMFFAC, MXLXGS, NMBFAC,
     & IINHR, IINHI, IRHSR, IRHSI,
     &  INUCH, ICOULH, ILOR, ILOI, ILIR, ILII,
     &  NPTMIN, NOFLO, NUMPT, NCRIT,
     & ISMX, ISMSQ, IPADE, IHOMO,
     &  ISMTSV, IRPTS4, IRPTS,
     &  IGRDC4(5), IDW, IGRDC5(2),
     &  IABS1, IGRDC6(2), GRDCM2, IGRDC7(2), IRWTS,
     &  IGRDC8(2), ICL1FF, ICL1FG, ICL1GF, ICL1GG
 
      LOGICAL ONELSW, IDENSW                                            /inelcm/
      COMMON /INELCM/  JBPF, JBTF, LXMIN, LXMAX, ILILOR, ILILOI, MSTOP,
     &  IA12M, NMLOLX, ONELSW, NUMLX, IRDINT, IELCUP, LILOSZ, NUMLIS,
     &  ILIS, IBETAS(3), ICL2FF, LXSTEP, IDENSW, LSKIP,
     &  JPMIN, JPMAX, JPBASE, NJP, JTMIN, JTMAX, JTBASE, NJT,
     &  IINDXS, ISMATR, ISMATI, NSMAT, NLX, NSPLI, ITOCS,
     &  NASPLI, IUNITR, LIFIT, ILIFIT, NOLFIT, IDELSR, IDELSI
      INTEGER INDXJS(4,2)
      EQUIVALENCE ( INDXJS(1,1), JPMIN )
 
      COMMON /KANDM/ AKI, AKO, REDMI, REDMO, RIMAX, ROMAX, ISIGS(2),    /kandm/
     &  RSCTS(2), ASCTS(2), RCSCTS(2) ,ISMATS(2), LOMOST, LCRIT,
     &  ISCTMN, ISCTCR, ETAS(2), RCSCTP(2), RCSCTT(2), LCRITS(2),
     &  RATMSS(2), QMIN, ABAR
 
      DIMENSION  AKS(2), REDMS(2), RMAXS(2)
      EQUIVALENCE ( AKI, AKS(1) ), ( REDMI, REDMS(1) ),
     &  ( RIMAX, RMAXS(1) )
 
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
      REAL*4  TBEGIN, TIMES                                             /ftimei/
      COMMON /FTIME/ TBEGIN, NUMLOP, NUMWAV, TIMES(8)
 
C
C     WARNING:  VAX VERSION MAY BE INACCURATE (NO COMPLEX*16).
      COMPLEX*16  INUC, ICOMP, IRTOIN, ITOTAL, SIN, SOUT, IFACTR
      DATA  IFACTR / (0.D0, 1.D0) /                                     cnv
CVA      DATA  IFACTR / (0., 1.) /                                      19230   
C
C
      LOGICAL PBUGSW, PINFSW
      LOGICAL  NXLISW
      REAL*4 TSTART, TTIMER
C
C     FOLLOWING ARE  -(I)**LX
C
      COMPLEX*16  PHASE
      COMPLEX*16  PHASES(4) / (0.D0, -1.D0),                            19240   
     1  (-1.D0, 0.D0), (0.D0, 1.D0), (+1.D0, 0.D0) /                    cnv
CVA      COMPLEX  PHASES(4)
CVA      DATA  PHASES  / (0., -1.), (-1., 0.), (0., 1.), (+1., 0.) /
C
C
c
C
      TSTART = second()
      IRTN = 0
      DO   14 I=1, 3                                                    19250   
  14  TIMES(I)=0.0
C
      IPRNT = MOD( IPRINT, 10 )
CCCC      PEAKSW = IPRNT .GE. 7
      PBUGSW = IPRNT .GE. 4
      PINFSW = IPRNT .GE. 2
C
C
      write (6, 23) REACT, ELAB, HEADER
 23   FORMAT ( '1', T60, 'P T O L E M Y' /                              19260   
     1  49X, 'COMPUTATION OF INELASTIC S-MATRIX ELEMENTS' /
     3  '0', 45A1, 'ELAB =', F7.2, ' MEV', 5X, 65A1 / )
C
      NLINE = 1000
C
C****************************************************************
C         NOTE -- NO SPIN ORBIT FORCE
      ISPUN=1
C****************************************************************
C                                                                       19270   
      CALL SETLOG ( 2*(LOMOST+LXMAX) )
C
C     HERE WE START THE REAL GUTS OF THE CALCULATION.
C
C
C     THE PRINCIPAL LOOPS ARE IN THE ORDER:
C
C       LI   LMIN <= LI <= LMAX
C           (RI+RO)2  NPSUM TERMS
C                                                                       19280   
C
C     WE WILL HAVE NO MORE  IALLOC  CALLS SO GET ADDRESSES
C
      LNUCH = Z(INUCH) - 2
      LCOULH = Z(ICOULH) - 1
      LRPTS = Z(IRPTS) - 1
      LRPTS4 = FACFR4*(Z(IRPTS4)-1) + 1
      LLIR = FACFR4*Z(ILIR) - FACFR4
      LLII = FACFR4*Z(ILII) - FACFR4
      LLOR = FACFR4*Z(ILOR) - FACFR4                                    19290   
      LLOI = FACFR4*Z(ILOI) - FACFR4
      LDW = Z(IDW)
      LLIS = FACFR4*Z(ILIS) - FACFR4
      LSMATR = Z(ISMATR) - 1
      LSMATI = Z(ISMATI) - 1
      LCL1FF = Z(ICL1FF) - 1
      LCL1FG = Z(ICL1FG) - 1
      LCL1GF = Z(ICL1GF) - 1
      LCL1GG = Z(ICL1GG) - 1
      LCL2FF = Z(ICL2FF) - 1                                            19300   
      LSIN = Z(ISMATS(1))
      LSOUT = Z(ISMATS(2))
      LABS1 = Z(IABS1) - 1
      LBNRAT = Z(IBETAS(2)) - LXMIN/2
      LBRAT = Z(IBETAS(3)) - LXMIN/2
      LWAVR = Z(IWAVR)
      LWAVI = Z(IWAVI)
      LVRL1 = Z(IRLVS(1))
      LVRL2 = Z(IRLVS(2))
      LVIM1 = Z(IIMVS(1))                                               19310   
      LVIM2 = Z(IIMVS(2))
      LCENT1 = Z(ICENTR(1))
      LCENT2 = Z(ICENTR(2))
      LINDXS = FACFR4*Z(IINDXS) - FACFR4
C
      FACTOR = DSQRT( AKI*AKO/(ES(1)*ES(2)*PI) )
      IF ( IDENSW )  FACTOR = SQRT(2.D0)*FACTOR
C
C
C     FORCE THE OVERLAYS TO GET THE THREEJ COMMON BLOCKS IN.            19320   
C     CALLED REPTIVELY BELIW.  HOWEVER, NOTHING WILL HAPPEN
C     FROM NOW ON THAT WOULD CAUSE THE OVERLAYS TO CHANGE.
C
      CALL DUMMY1
C
C
C
      LRANGE = NOFLO - 1
C
C     THE LOOPS BEGIN NOW                                               19330   
C
C
C
C     LOOP OVER LI
C
C
C     TWO PASSES OVER LI LOOP NOW; EVEN LI FIRST,THEN ODD
C
      LIMIN=LMIN+1
      LIL=LMIN                                                          19340   
      IF(MOD(LMIN,2) .EQ. 1 ) GO TO 150
      LIMIN=LMIN
      LIL=LMIN+1
C
C     LIPRTY = 1 FOR LI EVEN,  = 2 FOR LI ODD
C
 150  DO 989  LIPRTY = 1, 2
C
      IF(LIMIN.GT.LMAX) GO TO 980
      NXLISW = .FALSE.                                                  19350   
      ILI = 1
C
      DO 959 LI=LIMIN,LMAX,2
C
C     GET THE REQUIRED SCATTERING WAVEFUNCTIONS.
C     WE ALWAYS DO THIS EVEN IF LI WON'T BE USED SO AS TO GET THE
C     ELASTIC S-MATRIX ELEMENTS.
C
      LOMIN=LI - LRANGE
      LOMAX=LI + LRANGE                                                 19360   
C
      IF ( NXLISW )  GO TO 250
C
C     FOR FIRST LI, FILL UP THE OUT-CHANNEL WAVEFUNCTION ARRAY
C
      ITRK=0
C
      DO 239  LO=LOMIN,LOMAX,2
         CALL WAVELJ(LO, ISPUN, 2, NUMPT, ALLOC4(LRPTS4),
     1     ALLOC4(LLOR+ITRK+1), ALLOC4(LLOI+ITRK+1),                    19370   
     2     ALLOC(LWAVR), ALLOC(LWAVI),
     3     ALLOC(LVRL2), ALLOC(LVIM2), ALLOC(LCENT2) )
 239  ITRK=ITRK+NUMPT
C
      ITRK=0
      LOBASE = LOMIN
      NXLISW = .TRUE.
      GO TO 280
C
C     ON SUBSEQUENT LI'S WE NEED ONE NEW OUT-CHANNEL WAVEFUNC.          19380   
C
 250  LO=LI + LRANGE
      CALL WAVELJ(LO, ISPUN, 2, NUMPT, ALLOC4(LRPTS4),
     1  ALLOC4(LLOR+ITRK+1), ALLOC4(LLOI+ITRK+1),
     2  ALLOC(LWAVR), ALLOC(LWAVI),
     3  ALLOC(LVRL2), ALLOC(LVIM2), ALLOC(LCENT2) )
      IF ( ITRK .EQ. 0 )  LOBASE = LO
      ITRK=ITRK+NUMPT
      IF(ITRK.GT.NCRIT) ITRK=0
C                                                                       19390   
C     FOR EACH LI, WE MUST GET THE O-CHANNEL WAVE FUNCTION
C
C
 280  CALL WAVELJ(LI, ISPUN, 1, NUMPT, ALLOC4(LRPTS4), ALLOC4(LLIR+1),
     1  ALLOC4(LLII+1),
     2  ALLOC(LWAVR), ALLOC(LWAVI),
     3  ALLOC(LVRL1), ALLOC(LVIM1), ALLOC(LCENT1) )
C
C     WAVEFUNCTIONS ALL FOUND, WILL WE DO THIS VALUE OF LI
C                                                                       19400   
C
 290  IF ( LI - ILLOC(LLIS+ILI) )  959, 300, 295
 295  IF ( ILI .GE. NUMLIS )  GO TO 959
      ILI = ILI + 1
      GO TO 290
C
C     THIS IS AN LI TO DO
C
 300  LOMNMN = MAX0( MOD(LOMAX,2) , LOMIN )
      LOMXMX = LOMAX                                                    19410   
      NSKIP = 0
      DWRIOS=10.0D0
      DWRIOL=0
      DWRIOC=0
      DWCONT = 0
C
C     IN ABS1 WE ACCUMULATE INTEGRAL |INTEGRAND| FOR
C     THIS LI.
C
      DO 329  IH = 1, NMLOLX                                            19420   
         ALLOC(LABS1+IH) = 0
 329  CONTINUE
C
C
C     LOOP OVER R-VALUES AND COMPUTE THE H'S
C
      DO 489  IU = 1, NUMPT
         RVAL = ALLOC(LRPTS+IU)
         RAT = 1/RVAL
         IF ( RVAL .LT. RCUEFF )  RAT = RVAL/RCUEFF**2                  19430   
         RAT = RAT**2
C
C     COMPUTE IMAG AND REAL PARTS OF PRODUCT OF THE DISTORTED
C     SCATTERING WAVES.
C
         FIR=ALLOC4(LLIR+IU)
         FII=ALLOC4(LLII+IU)
         IF ( DABS(FIR)+DABS(FII) .LT. 1.D-20 )  GO TO 480
C
C     UNDO THE WRAP AROUND A STORAGE AND COMPUTE ALL PSI(A)*PSI(B)'S    19440   
C     FOR THIS (RI, RO).
C
         DO 439  LO = LOMNMN, LOMXMX, 2
            ITRKLO = NUMPT*( (LO-LOBASE)/2 )
            IF ( ITRKLO .LT. 0 )  ITRKLO = ITRKLO + NUMPT+NCRIT
            FOR = ALLOC4(LLOR+ITRKLO+IU)
            FOI = ALLOC4(LLOI+ITRKLO+IU)
            IF ( DABS(FOR) .LT. 1.D-20 )  FOR = 0
            IF ( DABS(FOI) .LT. 1.D-20 )  FOI = 0
            DWR=FOR*FIR-FOI*FII                                         19450   
            DWI=FOR*FII+FOI*FIR
            DWLOM=DMAX1(DABS(DWR),DABS(DWI))
            IF(DWLOM.GT.DWRIOL) DWRIOL=DWLOM
            IF((DWLOM.LT.DWRIOS).AND.(DWLOM.NE.0)) DWRIOS=DWLOM
            DWRIOC=DWRIOC+DWLOM
            ALLOC(LDW+LO-LOMNMN) = DWR
            ALLOC(LDW+LO-LOMNMN+1) = DWI
            DWCONT = DWCONT + 1
 439     CONTINUE
C                                                                       19460   
C
         HNUCR = ALLOC(LNUCH+2*IU)
         HNUCI = ALLOC(LNUCH+2*IU+1)
         HCOUL = ALLOC(LCOULH+IU)
C
C
C     NOW ADD THESE H'S INTO THE APPROPRIATE I(LI,LO,LX)
C     ALONG WITH THE PRODUCT OF THE DISTORTED WAVES
C     NOTE THAT THE BETA ARRAYS ALSO CONTAIN
C          CLEBSCH( JIN LX K 0 : JOUT K )                               19470   
C
         IH = 0
         DO 479  LX = LXMIN, LXMAX, 2
            HR = HNUCR*ALLOC(LBNRAT+LX/2) + HCOUL*ALLOC(LBRAT+LX/2)
            HI = HNUCI*ALLOC(LBNRAT+LX/2)
            HCOUL = RAT * HCOUL
            LOMN = IABS(LI-LX)
            LOMX = LI+LX
            K = LX+1 + NLX*INDXJS(4,3-IEXCIT)*(LX-INDXJS(3,IEXCIT)/2)
            KBASE = ILLOC(LINDXS+3*K-2)                                 19480   
            LDELMN = ILLOC(LINDXS+3*K-1)
            DO 479  LO = LOMN, LOMX, 2
               KOFFS = KBASE + (LO-LI-LDELMN)/2
               I = (ILI-1)*NSPLI + KOFFS
               LDWBAS = LDW-LOMNMN+LO
               IH = IH + 1
               TERMR = HR*ALLOC(LDWBAS) - HI*ALLOC(LDWBAS+1)
               ALLOC(LSMATR+I) = ALLOC(LSMATR+I) + TERMR
               TERMI = HR*ALLOC(LDWBAS+1) + HI*ALLOC(LDWBAS)
               ALLOC(LSMATI+I) = ALLOC(LSMATI+I) + TERMI                19490   
C
C     COMPUTE INDICATION OF LOSS OF SIGNIFICANCE:
C       ABS1 = INTEGRAL(R) |INTEGRAND|
C
               ALLOC(LABS1+IH) = ALLOC(LABS1+IH) + DABS(TERMR)
     1            + DABS(TERMI)
 479  CONTINUE
C
C
      GO TO 489                                                         19500   
C
C     WE COME HERE WHEN SKIPPING H CALCULATION DUE TO THE PRODUCT
C     OF THE DISTORTED WAVES BEING SMALL.
C
 480     NSKIP = NSKIP + 1
C
C
 489  CONTINUE
C
C                                                                       19510   
C     END OF INTEGRATION
C
      DWRIOC=DWRIOC/DWCONT
      IF (PBUGSW)  WRITE(6, 533)DWRIOS,DWRIOL,DWRIOC
 533  FORMAT(' SMALLEST, LARGEST AND AVERAGE DABS(DWRIRO)=', 3G15.5 / )
C
      IF ( .NOT. PINFSW )  GO TO 550
      NLINE = NLINE + NMLOLX + 1
      IF ( NLINE .LE. 58 )  GO TO 550
      IF ( NLINE .LT. 1000 )  write (6, 23) REACT, ELAB, HEADER         19520   
      write (6, 538)
 538  FORMAT ( '  L   L  LX', T25, 'INTEGRAL(0, SUMMAX)',
     1    T55, 'COULOMB', T70, 'NUCLEAR PART', T94, 'TOTAL AMPLITUDE' /
     2  '  IN OUT', 11X, 'MAG.', 6X, 'PHASE', 4X, 'CANCELLATION',
     3    T54, 'AMPLITUDE',
     4    T68, 2( 'MAG.', 6X, 'PHASE', 9X ) / )
      NLINE = 7+NMLOLX
C
C
C     ADD ON PIECE FROM SUMMAX TO INFINITY,                             19530   
C     MULTIPLY IN CLEBSH GORDEN FACTOR,
C     COMPUTE CANCELLATIONS,
C     AND SEPARATE INTO NUCLEAR AND COULOMB PIECES
C     ALSO PUT IN THE I**(-LX-1)
C
C
 550  SIN = DCMPLX( ALLOC(LSIN+2*LI), ALLOC(LSIN+2*LI+1) )
      IH = 0
      DO 559  LX = LXMIN, LXMAX, 2
         LOMN = IABS(LI-LX)                                             19540   
         LOMX = LI+LX
         BETRAT = ALLOC(LBRAT+LX/2)
         PHASE = PHASES(iand(LX,3)+1)
         K = LX+1 + NLX*INDXJS(4,3-IEXCIT)*(LX-INDXJS(3,IEXCIT)/2)
         KBASE = ILLOC(LINDXS+3*K-2)
         LDELMN = ILLOC(LINDXS+3*K-1)
         DO 559  LO = LOMN, LOMX, 2
            KOFFS = KBASE + (LO-LI-LDELMN)/2
            IH = IH + 1
            I1 = (ILI-1)*NSPLI + KOFFS                                  19550   
            I2 = (LI-LMIN)*NSPLI + KOFFS
            C = FACTOR *  DABS( CLEBSH( 2*LI, 2*LX, 0, 0, 2*LO, 0 ) )
            ICOMP = C*DCMPLX( ALLOC(LSMATR+I1), ALLOC(LSMATI+I1) )
            SOUT = DCMPLX( ALLOC(LSOUT+2*LO), ALLOC(LSOUT+2*LO+1) )
            IRTOIN = .25*C*BETRAT*( (1+SOUT)*(1+SIN)*ALLOC(LCL1FF+I1)
     1         - (1-SOUT)*(1-SIN)*ALLOC(LCL1GG+I1)
     2        + IFACTR*( (1+SOUT)*(1-SIN)*ALLOC(LCL1FG+I1)
     3                 + (1-SOUT)*(1+SIN)*ALLOC(LCL1GF+I1) ) )
            FFI = C*BETRAT*ALLOC(LCL2FF+I2)
            ITOTAL = ICOMP + IRTOIN                                     19560   
            INUC = ITOTAL - FFI
            INUC = PHASE*INUC
            ALLOC(LSMATR+I1) = DREAL(INUC)
            ALLOC(LSMATI+I1) = DIMAG(INUC)
            IF ( .NOT. PINFSW )  GO TO 559
            ICOMP = PHASE*ICOMP
            ITOTAL = PHASE*ITOTAL
            AMPCOM = CDABS(ICOMP)
            THISR = C*ALLOC(LABS1+IH)/AMPCOM
            AMPNUC = CDABS(INUC)                                        19570   
            AMPTOT = CDABS(ITOTAL)
            PHSCOM = ATAN2( DIMAG(ICOMP), DREAL(ICOMP) )
            PHSNUC = ATAN2( DIMAG(INUC), DREAL(INUC) )
            PHSTOT = ATAN2( DIMAG(ITOTAL), DREAL(ITOTAL) )
C
            write (6, 553)  LI, LO, LX, AMPCOM, PHSCOM,
     1        THISR, FFI, AMPNUC, PHSNUC, AMPTOT, PHSTOT
  553       FORMAT ( 2I4, I3, G16.4, G11.4, F9.2, G16.4,
     1     2( G13.4, G11.4 ) )
 559  CONTINUE                                                          19580   
C
      IF ( PINFSW )  write (6, 563)
 563  FORMAT ( ' ' )
C
 959  CONTINUE
C
C     END OF THE LI LOOP FOR A GIVEN PARITY OF LI
C     IF LI IS EVEN HAVE ANOTHER BASH AT LI LOOP WITH ODD LI
C
 980  LIMIN=LIL                                                         19590   
 989  CONTINUE
C
C
C     END OF THE 2 LI LOOPS (EVEN AND ODD PARITY OF LI)
C
C
C     FREE WORK AREAS
C
      IF ( MOD(IPRINT/100,10) .GE. 1 )  GO TO 1500
C                                                                       19600   
      Z(INUCH) = -Z(INUCH)
      Z(ICOULH) = -Z(ICOULH)
      Z(ILIR) = -Z(ILIR)
      Z(ILII) = -Z(ILII)
      Z(ILOR) = -Z(ILOR)
      Z(ILOI) = -Z(ILOI)
      Z(IDW) = -Z(IDW)
      Z(IRPTS) = -Z(IRPTS)
      Z(IRWTS) = -Z(IRWTS)
      Z(IRPTS4) = -Z(IRPTS4)                                            19610   
      Z(IABS1) = -Z(IABS1)
      Z(ICL1FF) = -Z(ICL1FF)
      Z(ICL1FG) = -Z(ICL1FG)
      Z(ICL1GF) = -Z(ICL1GF)
      Z(ICL1GG) = -Z(ICL1GG)
C
C     THE AREAS FOR WAVELJ - ONE FOR INCOMING AND ONE FOR OUTGOING
C
      DO 1099  I = 1, 2
         Z(NFS(I)) = -Z(NFS(I))                                         19620   
         Z(NGS(I)) = -Z(NGS(I))
         Z(NF1S(I)) = -Z(NF1S(I))
         Z(NG1S(I)) = -Z(NG1S(I))
         Z(IRLVS(I)) = -Z(IRLVS(I))
         Z(IIMVS(I)) = -Z(IIMVS(I))
         Z(ICENTR(I)) = -Z(ICENTR(I))
         IF ( V0SORS(I) .NE. 0 )  Z(ISORS(I)) = -Z(ISORS(I))
         IF ( V0SOIS(I) .NE. 0 )  Z(ISOIS(I)) = -Z(ISOIS(I))
 1099 CONTINUE
      Z(IWAVR) = -Z(IWAVR)                                              19630   
      Z(IWAVI) = -Z(IWAVI)
C
C
C     TIMING INFO
C
 1500 TOTTIM = second() - TSTART
      WAVTIM = TIMES(1) + TIMES(2) + TIMES(3)
      RTIM1 = TIMES(7)-TIMES(5)
      RTIM2 = TIMES(8)-TIMES(6)
      OTHTIM = TOTTIM - WAVTIM                                          19640   
      TOTTIM = TOTTIM + TIMES(7) + TIMES(8)
      write (6, 1503) ( TIMES(I), I = 1, 3 ), WAVTIM, OTHTIM, TIMES(5),
     1  RTIM1, TIMES(7), TIMES(6), RTIM2,
     1  TIMES(8), TOTTIM
 1503 FORMAT ( / '0RADIAL INTEGRAL COMPUTATION TIMES (SECONDS):' /
     1  '0SCATTERING WAVE INITIALIZATIONS:', T35, F9.3 /
     2  ' SCATTERING WAVE LOOP:', T35, F9.3 /
     3  ' SCATTERING WAVE INTERPOLATIONS:', T35, F9.3 /
     3  ' TOTAL SCATTERING WAVE TIME', T45, F9.3 /
     4  ' INTEGRATIONS AND CLEBSCH''S:', T45, F9.3 /                    19650   
     5  ' BELLINGS (SUMMAX, INFINITY):', T35, F9.3 /
     5  ' RECURSION (SUMMAX, INFINITY):', T35, F9.3 /
     5  ' TOTAL COULOMB (SUMMAX, INFINITY):', T45, F9.3 /
     6  ' BELLINGS (0, INFINITY):', T35, F9.3 /
     6  ' RECURSION (0, INFINITY):', T35, F9.3 /
     6  ' TOTAL PURE COULOMB (0, INFINITY):', T45, F9.3 /
     7  ' TOTAL:', T55, F9.3, ' SEC.' / )
C
C     A L L    D O N E
C                                                                       19660   
      IRTN = 1
C
C
      RETURN
C
C
      END
C*ID* INTRCF   C109.PTOLEMY.SOURCE                          PER701  15:
      SUBROUTINE INTRCF ( NCHN, JP, JT, LX, LDEL,
     &   NUMLIS, LIS, LSTEP, LXMAX,                                     19670   
     &   SR, SI, LOFF1, ISDIM1, LISW,
     &   LSTRT, LMAX, SOUT, SOUT4,
     &   LOFF2, ISDIM2, LBASE2, FOURSW,
     &   BIGBOY, LPEAK, CMPLXL, CMPLXS )
C
C     USES CONTINUED FRACTION TO INTERPOLATE S-MATRICES
C
C     ARGUMENTS:
C
C     NCHN, JP, JT, LX, LDEL - IDENTIFIERS FOR DIAGNOSTIC PRINTOUT      19680   
C     NUMLIS, LIS - ARRAY OF L'S ATWHICH S IS DEFINED.
C     LSTEP - IF LSTEP=1, NO INTERP IS DONE, ONLY COPING.
C     LXMAX - MINIMUM LI TO USE AS INTERP INPUT, FOR LI<LXMAX
C             INPUT MUST BE DENSE AND IS JUST COPIED.
C     SR, SI - REAL AND IMAG PARTS OF INPUT S'S
C     LOFF1 - FIRST SUBSCRIPT OF THE SR, SI ARRAYS (FIXED).
C     ISDIM1 - FIRST DIMENSTION OF THE SR, SI ARRAYS.
C     LISW - IF .TRUE., SECOND SUBSCRIPT IS LI+1, ELSE ILI.
C     LSTRT, LMAX - RANGE OF OUTPUT.
C     SOUT, SOUT4 - COMPLEX*16 OR COMPLEX*8 OUTPUT ARRAYS.              19690   
C     LOFF2, ISDIM2 - AS ABOVE FOR THE OUTPUT ARRAYS
C     LBASE2 - SECOND SUBSCRIPT OF THE OUTPUT IS LI-LBASE2
C     FOURSW - IF .TRUE., OUTPUT IS IN SOUT4, ELSE SOUT.
C     BIGBOY, LPEAK - SET TO MAXIMUM MAGNITUDE
C     CMPLXL, CMPLXS - COMPLEX*16 WORK ARRAYS OF DIMENSION NUMLIS.
C
C     NOTE THAT THE INPUT IS IN SEPARATE REAL AND IMAG ARRAYS WHILE
C     THE OUTPUT IS IN ONE COMPLEX ASRRAY (EITHER *8 OR *16).
C
C     4/7/80 - SEPARATED FROM LINTRP - S.P.                             19700   
C     4/24/80 - FIX PHASEING OF LIS ARRAY BUG - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
C
      INTEGER  LIS(NUMLIS)
      REAL*8  SR(ISDIM1, 1),  SI(ISDIM1, 1),  SOUT(2, ISDIM2, 1)
      REAL*4  SOUT4(2, ISDIM2, 1)
      LOGICAL  FOURSW, LISW
      REAL*8  CMPLXS(2, NUMLIS)
      REAL*8  CMPLXL(2, NUMLIS)                                         19710   
C
      COMPLEX*16  CFLI, CTEMP
C
c
      BIGBOY=0
      LPEAK=LSTRT
C
C     SKIP INTERPOLATION IF LSTEP = 1.
C
      IF ( LSTEP .EQ. 1 )  GO TO 800                                    19720   
C
C     FIT CONTINUED FRACTION TO S-MATRICES WITH DESIGNATED
C     LI VALUES.
C
      ICOUNT=0
      DO 149 ILI=1,NUMLIS
         LI=LIS(ILI)
         IF( LI .LT. LXMAX ) GO TO 149
         ICOUNT=ICOUNT+1
         CMPLXL(1,ICOUNT) = LI                                          19730   
         CMPLXL(2,ICOUNT) = 0
         II = ILI
         IF (LISW)  II=LI+1
         CMPLXS(1,ICOUNT)=SR(LOFF1,II)
         CMPLXS(2,ICOUNT)=SI(LOFF1,II)
  149 CONTINUE
C
      CALL CCNFRC ( ICOUNT, CMPLXL, CMPLXS
     1         )
CDC     1         , X, Y )                                              19740   
C
C     COMPUTE S(LO,LI,LX) FOR THIS (LX,DEL) AND LI TO LMAX USING
C     THE CONTINUED-FRACTION INTERPOLATION DETERMINED ABOVE
C
      ILI = 1
C
      DO 799 LI = LSTRT, LMAX
         CFLI = LI
         CALL CCONTF ( ICOUNT, CMPLXL, CMPLXS,
     1      CFLI, CTEMP )                                               19750   
         RE=DREAL(CTEMP)
         HIM=DIMAG(CTEMP)
         SIZE=(RE**2+HIM**2)
C
C        WHEN AVAILABLE, USE INELDC COMPUTED VALUES TO CHECK
C        THE CONTINUED FRACTION.
C
 500     IF ( LIS(ILI) - LI )  510, 550, 780
 510     IF ( ILI .EQ. NUMLIS )  GO TO 550
         ILI = ILI+1                                                    19760   
         GO TO 500
 550     II = ILI
         IF (LISW)  II=LI+1
         F = SR(LOFF1,II)
         G = SI(LOFF1,II)
         SIZE = F**2 + G**2
         ILI = ILI + 1
         IF ( LI .LT. LXMAX )  GO TO 775
         IF ( (F-RE)**2 + (G-HIM)**2 .GT. 1.D-6*(SIZE) )
     1     write (6, 773)  NCHN, JP, JT, LX, LDEL, LI, RE, HIM, F, G    19770   
 773     FORMAT ( ' **** WARNING: FOR CHAN, 2*JP, 2*JT, LX, LO-LI',
     1     ', LI =', 6I5 /
     1     5X, 'CONT. FRAC. =', 2G13.5, 5X, 'EXACT =', 2G13.5 )
 775     RE = F
         HIM = G
 780     IF ( FOURSW )  GO TO 785
         SOUT(1,LOFF2,LI-LBASE2) = RE
         SOUT(2,LOFF2,LI-LBASE2) = HIM
         GO TO 790
 785     SOUT4(1,LOFF2,LI-LBASE2) = RE                                  19780   
         SOUT4(2,LOFF2,LI-LBASE2) = HIM
 790     IF(SIZE.LT.BIGBOY) GO TO 799
         BIGBOY=SIZE
         LPEAK=LI
  799 CONTINUE
      GO TO 850
C
C        NO INTERPOLATION  (LSTEP = 1).
C        JUST TRANSFER AND SCAN.
C                                                                       19790   
 800  LBASE1 = LIS(1)-1
      IF ( LISW )  LBASE1 = -1
      DO 849  LI = LSTRT, LMAX
         F = SR(LOFF1,LI-LBASE1)
         G = SI(LOFF1,LI-LBASE1)
         IF ( FOURSW )  GO TO 835
         SOUT(1,LOFF2,LI-LBASE2) = F
         SOUT(2,LOFF2,LI-LBASE2) = G
         GO TO 840
 835     SOUT4(1,LOFF2,LI-LBASE2) = F                                   19800   
         SOUT4(2,LOFF2,LI-LBASE2) = G
 840     SIZE = F**2 + G**2
         IF ( SIZE .LT. BIGBOY )  GO TO 849
         BIGBOY = SIZE
         LPEAK = LI
 849  CONTINUE
C
 850  RETURN
      END
C*ID* IXSORT   C109.PTOLEMY.SOURCE                          PER701  13: 19810   
      SUBROUTINE IXSORT(IX,X,N)
      IMPLICIT REAL*8 (A-H,O-Z)
C
C - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - -
C
C      THIS IS A FORTRAN-IV ADAPTATION OF A PL/I QUICKSORT PROGRAM
C      PUBLISHED IN
C         ROBERT P. RICH
C         INTERNAL SORTING METHODS ILLUSTRATED WITH PL/1 PROGRAMS
C         PRENTICE-HALL    (SERIES IN AUTOMATIC COMPUTATION)            19820   
C         ENGLEWOOD CLIFFS, NEW JERSEY       1972
C
C             LIBRARY OF CONGRESS NUMBER
C                     QA76.5
C                     .R499
C
C      THE PROGRAM ITSELF IS FOUND ON PAGE 80...THE DISCUSSION OF
C     THE PARTITIONING TECHNIQUE USED STARTS ON PAGE 77.
C
C           THE TIMING OF THIS PROGRAM IS INTERESTING.....              19830   
C     ON A 360/91 THE TIMES REQUIRED FOR THE QUICKSORT AND A
C     BUBBLE SORT TO SORT   'N'   INTEGERS IS GIVEN BELOW
C
C       N         BUBBLE      QUICKSORT
C                  (MS)          (MS)
C       4          .13           .16
C      18          1.24          .69
C      72          18.3          3.32
C     280          277.          15.4
C    1073         4123           71.1                                   19840   
C   10000       370000           870.
C       ----- THESE TIMES ARE FROM THE ABOVE REFERENCE
C             USING PL/I PROGRAMS WRITTEN
C
C   IN ESSENCE, THE TIME REQUIRED FOR THE BUBBLE SORT IS PROPORTIONAL
C   TO N**2 WHEREAS THE QUICKSORT TIME GOES AS N*LOG2(N).
C
C ===========
C    TIMING ON THE 360/75
C      T(MILLISECONDS) = N LOG2(N)/100                                  19850   
C ===========
C - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - -
C     USAGE:
C              CALL IXSORT(IX,X,N)
C
C                IX  IS AN N-ELEMENT ARRAY.  THE SORTED INDICES
C                    WILL BE RETURNED IN THIS ARRAY.
C        WHERE   N   IS THE NUMBER OF ELEMENTS TO BE SORTED
C                X   IS THE DIMENSIONED VARIABLE WHOSE ELEMENTS
C                    ARE TO BE SORTED                                   19860   
C - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - -
C
      INTEGER*4 LV(16),UV(16),N,P,LP,UP,IY
      DIMENSION X(1),IX(1)
C
C --- INITIALIZE IX
      DO 5 I = 1,N
    5 IX(I) = I
C
C --- INITIALIZE THE PUSHDOWN LIST                                      19870   
            LV(1)=1
            UV(1)=N
            P=1
C
C -- PARTITION NEXT SEGMENT
   10 IF ( P .LT. 1 ) RETURN
   20 IF ( (UV(P)-LV(P)) .GE. 1 ) GO TO 30
      P=P-1
      GO TO 10
C                                                                       19880   
C -- CHOOSE BOUND
   30 LP = LV(P)-1
      UP = UV(P)
      Y  = X(UP)
      IY = IX(UP)
C
C -- MOVE LOWER POINTER
   40 IF ( (UP-LP) .LT. 2 ) GO TO 70
      LP = LP + 1
      IF ( X(LP) .LE. Y ) GO TO 40                                      19890   
      X(UP) = X(LP)
      IX(UP)= IX(LP)
C
C -- MOVE UPPER POINTER
   50 IF ( (UP-LP) .LT. 2 ) GO TO 60
      UP = UP - 1
      IF ( X(UP) .GE. Y ) GO TO 50
      X(LP) = X(UP)
      IX(LP)= IX(UP)
      GO TO 40                                                          19900   
C
C --- FINISH UP
   60 UP = UP - 1
   70 X(UP) = Y
      IX(UP)= IY
      IF ( (UP-LV(P)) .GE. (UV(P)-UP) )GO TO 80
      LV(P+1) = LV(P)
      UV(P+1) = UP-1
      LV(P)   = UP+1
            GO TO 90                                                    19910   
C
   80 LV(P+1) = UP+1
      UV(P+1) = UV(P)
      UV(P)   = UP-1
   90 P = P+1
      GO TO 20
      END
C*ID* JPTOLX   C109.PTOLEMY.SOURCE                          PER701  15:
      SUBROUTINE JPTOLX ( L, LAS, JP, NWP, SJR, SJI, INDX, SLX )
C                                                                       19920   
C     TRANSLATES ELASTIC S-MATRIX FROM (L',L,JP) TO (L',L,LX) SYSTEM.
C
C
C     L = ORBITAL ANGULAR MOMENTUM.
C     LAS = ASYMPTOTIC L.
C     JP = 2 * TOTAL PROJECTILE ANGULAR MOMENTUM (L + JSPS(NWP)).
C     NWP = 1 FOR INCOMING, 2 FOR OUTGOING.
C     (SJR,SJI) = THE JP-SYSTEM ELEMENT TO BE TRANSLATED.
C     INDX = INDEX ARRAY (SEE BELOW).
C     SLX = OUTPUT S-MATRIX, IN THE LX SYSTEM.  SLX MUST BE INITIALIZED 19930   
C        TO ZERO BEFORE THE FIRST JPTOLX CALL.
C
C
C           THE  INDX  ARRAY HAS THE FOLLOWING STRUCTURE:
C     INDX(1,K) = KOFFS = OFFSET INTO THE S-MATRIX.
C     INDX(2,K) = LDELMN = MINIMUM (LI-LO).
C     INDX(3,K) = NDEL = NUMBER OF (LI-LO) VALUES.
C     WHERE K = 1 + LX*(JSPS(NWP)+2).
C
C     THIS FORMAT FOLLOWS FROM THE "INDXS" FORMAT (SEE ANGSET COMMENTS) 19940   
C     IF JT = 0, I. E. NO TARGET SPIN EFFECTS.
C
C
C     8/1/79 - NEW ROUTINE - RPG
C     11/20/79 - S-MATRICES STORED BY L-LAS - S.P.
C
C
      implicit real*8 ( a-h, o-z )                                      implicit
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
C                                                                       19950   
      DIMENSION INDX(3,1), SLX(1)
C
C
C
C     IF NO SPIN-ORBIT, JUST TRANSFER IT.
C
      IF ( SOSWS(NWP) )  GO TO 100
      I = 2*L + 1
      SLX(I) = SJR
      SLX(I+1) = SJI                                                    19960   
      RETURN
C
C     SPIN-ORBIT EXISTS.  MULTIPLY BY RACAH'S ETC., AND ADD
C     TO EXISTING VALUES FOR EACH LX.
C
 100  LXMN = MAX0( 0, IABS( L-LAS ) )
      LXMX = MIN0( JSPS(NWP), L+LAS )
      COEF = (JSPS(NWP)+1)*(2*LAS+1)
      COEF = (JP+1)/DSQRT(COEF)
      I = ( JSPS(NWP) - JP + L + LAS )/2                                19970   
      IF ( MOD(I, 2) .NE. 0 )  COEF = -COEF
      DO 199  LX = LXMN, LXMX
         LX2 = 2*LX
         T = LX2 + 1
         T = COEF * DSQRT(T) * RACAH ( 2*L, 2*LAS, JSPS(NWP), JSPS(NWP),
     1      LX2, JP )
         K = 1 + LX*( JSPS(NWP) + 2 )
         IF ( INDX(1,K) .LE. 0 )  GO TO 199
         I = LAS*NUMJS(NWP) + INDX(1,K) + (L-LAS-INDX(2,K))/2
         I = 2*I - 1                                                    19980   
         SLX(I) = SLX(I) + T*SJR
         SLX(I+1) = SLX(I+1) + T*SJI
 199  CONTINUE
      RETURN
      END
C*ID* LCRITL   C109.PTOLEMY.SOURCE                          PER701  15:
      SUBROUTINE LCRITL ( E, FK, ETA, RC, NSTEPS, RSTART, STEPSZ,
     1 IV, IW, NGAUSS, IPRINT, LC1, LC2, LC )
C
C     USE CLASSICAL DEFLECTION AND WKB PHASES TO ESTIMATE CRITICAL L    19990   
C     LC IS TAKEN TO BE GREATER OF TWO ESTIMATES LC1 AND LC2
C     LC1 IS THE FIRST L FOR WHICH |S(L)| > (|S|MIN + 1)/2.
C     LC2 IS L-VALUE OF ALGEBRAICALLY MINIMUM THETA(L)
C     WHERE THETA(L) IS THE CLASSICAL DEFLECTION FUNCTION.
C     IF IPRINT.NE.0 PRINT OUT WKB PHASES AND CLASSICAL TURNING PTS
C     IF NEITHER LC1 NOR LC2 EXISTS (ABOVE NOISE), LC IS SET TO THE
C     L FOR WHICH THE COULOMB CLASSICAL TURNING POINT = MAX( RC, 1.2 ).
C
C     9/18/75 - VERSION WITH WKB - MHM
C     9/22/75 - CORRECTED AND CHANGED TO HANDLE V OR VI OR BOTH  =  0   20000   
C     12/1/77 - USE POTENTIAL DEFINED BY ARRAYS - S.P.
C               DO NOT GO ON TO LARGE L-VALUES; INTERPOLATE TO LCRIT
C     2/14/78 - AVOID UNDERFLOWS FOR EXTREME ABSORBTION
C     4/3/78 - AVOID UNDERFLOWS FOR SMALL ABSORBTION AT LARGE R - S.P.
C     7/27/79 - INITIALIZE MINSW, CHANGE DEFINITION OF LC1 FOR WEAK
C        ABSORPTION, START AT L=0 FOR LIGHT IONS - RPG
C     11/7/79 - INTRODUCE NOISE CONSTANT; INCREASE EPS; SET LC TO L FOR
C        WHICH COULOMB CTP=RC IF THE OTHER 2 ESTIMATES FAIL - RPG
C     12/27/79 - MAKE EPS 1E-14 AGAIN; IT MUST BE SMALL TO ALLOW
C                THE INTEGRAL WITH SINGULAR END POINT - S.P.            20010   
C     1/16/80 - CORRECT MYSTERIOUS SCREWED-UP COMMENTS - RPG
C     5/8/80 - PASS VCONS TO SWKB - S.P.
C     5/8/80 - IN DESPERATION MAKE EPS 1E-12 - S.P.
C     6/3/80 - LMAX=1.5*ROW, DO NOT SET TO LMAX FOR S=1 ALWAYS - S.P.
C     6/16/80 - DO NOT LOOK FOR MIN(1/2-PT) IF MIN > .99 - S.P.
C
C
      implicit real*8 ( a-h, o-z )                                      implicit
C
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
C
      LOGICAL  MINSW
C     EPS IS THE ACCURACY REQUIRED IN SWKB.
      DATA  EPS / 1.D-12 /
C
C     SET MINIMUM AND MAXIMUM L FOR SEARCH
C     ROW IS THE L WHERE COULOMB CLASSICAL TURNING POINT IS MAX(RC,1.2)
C
      MINSW = .FALSE.                                                   20030   
      RCL = DMAX1( RC, 1.20D0 )
      ROW = FK*RCL
      ROW = ROW**2 - 2*ETA*ROW + .25
      IF ( ROW .LT. 0 )  ROW = 0
      IF ( ROW .GT. 0 )  ROW = 0.5 + DSQRT( ROW )
      LMIN = .2*ROW - 4.
      LMIN = MAX0( LMIN, 0 )
      LMAX = 1.5*ROW
      LMAX = MAX0( LMAX, LMIN+50 )
      LC1 = 0                                                           20040   
      LC2 = 0
      LC = 0
      DLSMAT = 0
      DLDFLC = 0
      NOLS = LMAX-LMIN+1
      AMPMIN = 1.D20
      VCONS = 1
      IF ( PROBLM .EQ. 24 )  VCONS = 0
C
C     ALLOCATE SPACE FOR GAUSS POINTS AND WKB STUFF                     20050   
C     SET UP STARTING ADDRESSES
C
    5 IWKBPT = NALLOC(NGAUSS,'WKBPTS')
      IWKBWT = NALLOC(NGAUSS,'WKBWTS')
      NSEMIC = 5*NOLS
      ISEMIC = NALLOC(NSEMIC,'SCSTUF')
      ICUBIC = NALLOC(7*NSTEPS, 'WKBCUBIC' )
      LRVAL = Z(ICUBIC)
      LVCUB = LRVAL + NSTEPS
      LWCUB = LVCUB + 3*NSTEPS                                          20060   
      LV = Z(IV)
      LW = Z(IW)
      IAMP = Z(ISEMIC)
      LAMP = IAMP-1
      IDNUC = IAMP+NOLS
      LDNUC = IDNUC-1
      IDEFL = IDNUC+NOLS
      LDEFL = IDEFL-1
      ICTP = IDEFL+NOLS
      LCTP = ICTP-1                                                     20070   
      ICTPC = ICTP+NOLS
      LCTPC = ICTPC-1
C
C     DETERMINE UNMAPPED GAUSS POINTS FOR (-1,1)
C
      CALL GAUSSL(NGAUSS,ALLOC(Z(IWKBPT)),ALLOC(Z(IWKBWT)))
C
C     GET CUBIC SPLINES FOR THE POTENTIALS
C
      ROSTRT = FK*RSTART                                                20080   
      RHO = ROSTRT
      H = FK*STEPSZ
      DO 159  I = 1, NSTEPS
            ALLOC(LRVAL-1+I) = RHO
            RHO = RHO+H
 159  CONTINUE
      ROEND = RHO - H - EPS
C
      CALL SPLNCB ( NSTEPS, ALLOC(LRVAL), ALLOC(LV), ALLOC(LVCUB),
     1  ALLOC(LVCUB+NSTEPS), ALLOC(LVCUB+2*NSTEPS) )                    20090   
C
      CALL SPLNCB ( NSTEPS, ALLOC(LRVAL), ALLOC(LW), ALLOC(LWCUB),
     1  ALLOC(LWCUB+NSTEPS), ALLOC(LWCUB+2*NSTEPS) )
C
C     CALCULATE AND STORE WKB S-MATRIX ELEMENTS (AMP AND ARG)
C     CLASSICAL DEFLECTION FUNCTIONS(DEFL) AND CLASSICAL TPS(CTP CTPC)
C
C     WE GO TO LMAX OR TO BOTH
C     1)  |S| > .95 + .05*MIN(|S|)   AND
C     2)  DEFLECT FUNCT HAS A MIN FOLLOWED BY A MAX WHILE |S| > .05     20100   
C
      DO 299 I = 1,NOLS
         L = LMIN+I-1
         CALL SWKB ( E, FK, L, EPS, IPRINT, ETA, RC,
     1     NSTEPS, ROSTRT, H, VCONS, ALLOC(LV), ALLOC(LVCUB), ALLOC(LW),
     2     ALLOC(LWCUB), NGAUSS, ALLOC(Z(IWKBPT)), ALLOC(Z(IWKBWT)),
     3     DELTR, DELTIM, THETA, THETC, RHOT, ROTC, DUEFF )
         IF((DELTR.NE.5.D0).OR.(DELTIM.NE.5.D0)) GO TO 250
         write (6, 213)
  213    FORMAT( '0**** ERROR RETURN IN LCRITL FROM SWKB ')             20110   
         GO TO 640
  250    ALLOC(LCTP+I) = RHOT
         ALLOC(LCTPC+I) = ROTC
         AMPL = 0
         IF ( DELTIM .LT. 20 )  AMPL = DEXP(-2.D0*DELTIM)
         ALLOC(LAMP+I) = AMPL
         AMPMIN = DMIN1( AMPMIN, AMPL )
         IF(THETA.GT.THETC) THETA = THETC
         ALLOC(LDEFL+I) = THETA
         ALLOC(LDNUC+I) = 2*DELTR                                       20120   
         IF ( RHOT .GE. ROEND )  GO TO 280
C
C     CHECK ON THE PROGRESS OF THE DEFLECTION FUNCTION
C
         IF ( AMPL .LT. .05  .OR.  I .EQ. 1 )  GO TO 299
         IF ( MINSW )  GO TO 260
         MINSW = THETA .GT. ALLOC(LDEFL+I-1)+EPS
         GO TO 299
 260     IF ( THETA .GT. ALLOC(LDEFL+I-1)-EPS )  GO TO 299
C                                                                       20130   
C     DEFLECTION FUNCTION IS FALLING FROM A MAX AFTER A MIN.
C     IF |S| IS CLOSE TO 1 WE STOP
C
         IF ( AMPL .LT. .95+.05*AMPMIN )  GO TO 299
 280     LMAX = L
         GO TO 300
 299  CONTINUE
C
 300  NOLS = LMAX-LMIN+1
C                                                                       20140   
C     PRINT WKB PHASES AND CLASSICAL DEFLECTION FUNCTION
C
      IF(IPRINT.EQ.0) GO TO 500
      write (6, 303)
  303 FORMAT(1H0,4X,'---  WKB S-MATRIX ELEMENTS AND CLASSICAL TPS ---'/
     11X,' L ',4X,' AMP(S(L))  ',4X,' ARG(S(L))  ',4X,' DEFL.ANGLE ',
     24X,'CLASSICAL TP',4X,'  COULOMB TP')
      DO 349 I = 1,NOLS
         L = LMIN+I-1
         CTR = ALLOC(LCTP+I)/FK                                         20150   
         CTRC = ALLOC(LCTPC+I)/FK
         AMP = ALLOC(LAMP+I)
         DNUC = ALLOC(LDNUC+I)
         DEFL = ALLOC(LDEFL+I)
         write (6, 343)L,AMP,DNUC,DEFL,CTR,CTRC
  343    FORMAT(1H , 1X, I3, G16.5, G16.5, 3(G16.5))
 349  CONTINUE
C
C     ESTIMATE CRITICAL L FROM PHASE-SHIFTS AND DEFLECTION FN
C                                                                       20160   
 500  MINSW = .FALSE.
      AMPMIN = 0.5*(AMPMIN+1.)
C
      DO 599  I = 1, NOLS
         I1 = NOLS-I+1
         L = LMAX +1 - I
         IF ( DLSMAT .NE. 0 )  GO TO 550
         IF ( ALLOC(LAMP+I1) .GT. AMPMIN )  GO TO 550
C
C     |S| < .5*(MIN(|S|)+1).  INTERPOLATE UNLESS LAST POINT             20170   
C
         IF ( AMPMIN .GT. .99 )  GO TO 550
         IF ( I .GT. 1 )  GO TO 520
         write (6, 513) LMAX, ALLOC(LAMP+I1)
 513     FORMAT ( '0**** LCRITL PICKED LMAX TOO SMALL TO FIND',
     1      ' |S| > .5*(MIN(|S|)+1):', I5, G15.5,
     2      '  LCRIT SET TO LMAX' )
         DLSMAT = LMAX
         GO TO 550
C                                                                       20180   
 520     DLSMAT = L + (AMPMIN-ALLOC(LAMP+I1))/(ALLOC(LAMP+I1+1)
     1      -ALLOC(LAMP+I1))
C
C     LOOK FOR OUTERMOST MINIMUM OF DEFLECT FUNCTION
C
 550     IF ( DLDFLC .NE. 0  .OR.  L .EQ. LMAX )  GO TO 599
         IF ( MINSW )  GO TO 560
         MINSW = ALLOC(LDEFL+I1) .LT. ALLOC(LDEFL+I1+1)-EPS
         GO TO 599
C     HAVE WE PASSED A MINIMUM                                          20190   
 560     IF ( ALLOC(LDEFL+I1) .LT. ALLOC(LDEFL+I1+1)+EPS )  GO TO 599
         C = ALLOC(LDEFL+I1) - 2*ALLOC(LDEFL+I1+1)
     1      + ALLOC(LDEFL+I1+2)
         DLDFLC = L + 1 + (ALLOC(LDEFL+I1)-ALLOC(LDEFL+I1+2))/(2*C)
C
 599  CONTINUE
C
      LC1 = DLSMAT + .5
      LC2 = DLDFLC + .5
      LC = MAX0( LC1, LC2 )                                             20200   
C
      IF(IPRINT.NE.0) write (6, 623) DLSMAT, DLDFLC, LC
  623 FORMAT(1H0,2X,'--- 1/2 POINT OF |S(L)|  =  ',G15.5,
     1  5X, 'MINIMUM OF DEFLECTION FUNC =', G15.5,
     2  5X, 'L CRIT =', I5 )
 640  IF ( DLSMAT .NE. 0  .OR.  DLDFLC .NE. 0 )  GO TO 700
      LC = ROW + .5
      write (6, 643)  LC, RCL
 643  FORMAT ( '0**** NO CRITICAL L FOUND; SET LC =', I5,
     1   ' = L FOR WHICH CLASSICAL COULOMB TURNING POINT =', F10.3 )    20210   
C
C     FREE ALLOCATOR AREAS
C
 700  Z(IWKBPT) = -Z(IWKBPT)
      Z(IWKBWT) = -Z(IWKBWT)
      Z(ISEMIC) = -Z(ISEMIC)
      Z(ICUBIC) = -Z(ICUBIC)
C
      RETURN
      END                                                               20220   
C*ID* LINLSQ   C109.PTOLEMY.SOURCE                          PER701  15:
      SUBROUTINE LINLSQ ( IFUNC,N,XVALS,SVALS,CVAL,AVAL,B,CHI,PBUGSW )
C
C     TWO-TERM LINEAR LEAST-SQUARES FIT
C
C     FINDS AVAL AND CVAL SUCH THAT
C        F(X) = AVAL + CVAL*F2(X)
C     WHERE F AND F2 ARE:
C
C     IFUNC    F2        F          USED FOR                            20230   
C       1      -X      LN(S)      S = A*EXP(-C*L)
C       2    EXP(B*X)   1/S       S = 1/(A + C*EXP(B*L) )
C       3     LN(X)    LN(S)      S = A/L**C
C       4       X      S/X**B     S = (A + C/L)/L**B
C       5      X**B     S         PHASE(S) = A + C/L**B
C                                NOTE THAT LINTRP THEN REVERSES
C                                THE NAMES A=CP, C=AP.
C
C     NOTE THAT IN THE FIRST TWO FORMS  X IS L-LBAR  WHILE
C     IN THE LAST THREE IT IS LBAR/L.                                   20240   
C
C     THE LEAST-SQUARES FIT IS WEIGHTED BY 1/F**2
C
C     THERE ARE N INTEGRALS TO BE FITTED
C
C     THIS IS A LINEAR LEAST SQUARES PROBLEM SOLVED BY
C     MATRIX INVERSION
C
C     MHM - 9/1/76
C     12/28/79 - CFR%F - RPG                                            20250   
C     2/15/80 - USE  SCAL  TO AVOID UNDERFLOW (DELTA ^ \S\**4) - RPG
C     4/11/80 - ADD IFUNC AND VARIOUS FUNCTION FORMS; REMOVE
C               TEST ON A<0 - S.P.
C     5/6/80 - TYPE 5. - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
C
      DIMENSION XVALS(N),SVALS(N)
C
CDC      ALLOCLEVEL XVALS, SVALS                                        20260   
C
      LOGICAL  PBUGSW
C
      G1=0
      G2=0
      G11=0
      G12=0
      G22=0
C
C     SCALE THE S MATRIX ELEMENTS BY THE AVERAGE OF THE FIRST TWO       20270   
C     TO AVOID UNDERFLOW.
C
      SCAL = 1
      IF ( IFUNC .EQ. 2  .OR.  IFUNC .EQ. 4 )
     1   SCAL = .5 * (SVALS(1)+SVALS(2))
      IF ( IFUNC .EQ. 4 )  SCAL = (.5*(XVALS(1)+XVALS(2)))**B / SCAL
      DO 299 I=1,N
         X = XVALS(I)
         S = SVALS(I)
C                                                                       20280   
         GO TO ( 110, 120, 130, 140, 150 ), IFUNC
C
 110     F2 = -X
         F = DLOG(S)
         GO TO 200
C
 120     F2 = DEXP( B*X )
         F = 1/S
         GO TO 200
C                                                                       20290   
 130     F2 = DLOG(X)
         F = DLOG(S)
         GO TO 200
C
 140     F2 = X
         F = S/X**B
         GO TO 200
C
 150     F2 = X**B
         F = S                                                          20300   
C
 200     F = SCAL*F
         WT = 1/F**2
C
         G1=G1+WT*F
         G2=G2+WT*F*F2
         G11=G11+WT
         G12=G12+WT*F2
         G22=G22+WT*F2*F2
 299  CONTINUE                                                          20310   
C
      DELTA=G11*G22-G12*G12
      A=(G22*G1-G12*G2)*(1/(SCAL*DELTA))
      C=(G11*G2-G12*G1)*(1/(SCAL*DELTA))
C
C     THIS IS REALLY  CHISQ * SCAL**2
C
      CHI = N - ( A*G1 + C*G2 )* SCAL
      AVAL = A
      CVAL=C                                                            20320   
      IF ( PBUGSW )  write (6, 403) B, AVAL, CVAL, CHI, SCAL
 403  FORMAT ( ' LINLSQ:', G16.9, 2G14.6, G16.9, G11.2 )
      RETURN
      END
C*ID* LINTRP   C109.PTOLEMY.SOURCE                          PER701  10:
      SUBROUTINE LINTRP
C
C     INTERPOLATION AND EXTRAPOLATION IN L OF THE REACTION S-MATRICES
C
C     THIS SUBROUTINE TAKES S-MATRIX ELEMENTS S(LI,LO,LX)               20330   
C     COMPUTED AT A SET OF VALUES OF LI SPACED BY LSTEP, AND
C     ALL POSSIBLE (LO,LX) VALUES FOR EACH LO CONSISTENT WITH
C     A.M. AND PARITY SELECTION RULES ,FITS THOSE S(LI,LO,LX) WITH
C     CONTINUED FRACTIONS (ONE FOR EACH LX AND  LO-LI)
C     THEN USES THIS REPRESENTATION TO FILL IN THE SPACES
C
C     THE CONTINUED FRACTION IS USED FROM LMIN TO LMAX
C     THEN IT IS ASSUMED THAT THE MAGNITUDE OF S(L)
C     IS DESCENDING TOWARD ZERO EXPONENTIALLY
C     I.E.  S(L)  = A / (1 + C * EXP (B*L) )  FOR LARGE L               20340   
C     THE CONSTANTS A ,B AND C ARE FIXED BY A LEAST SQUARES FIT
C     TO THE LAST FEW INTEGRALS (AT LEAST 3) UP TO LMAX
C
C     LARGE-L PHASES ARE REPRESENTED BY A * ( SUM OF ELASTIC PHASES)
C
C     THE EXPONENTIAL IS THEN USED TO CONTINUE S(L) OUT TO LIMOST
C     (THE SMALLEST L SUCH THAT |S(L)|  IS LESS THAN BOTH
C     MAX(|S(L)|)/500 AND MIN( (|S(L)|)/5 (FOR L LESS
C     THAN LPEAK))
C     FOR INELASTIC EXCITATION, LIMOST WAS PREVIOUSLY DETERMINED BY     20350   
C     ANGSET BASED ON THE ASYMPTOTIC (IN L) FORM OF THE COULOMB
C     INTEGRALS AND IS NOT CHANGED HERE.
C
C     8/1/75 - MHM
C     8/11/75 - USE WOODS SAXON FORM FOR EXTRAPOLATION - S.P.
C     8/28/75 - FIT ONLY TO THE INELDC COMPUTED STUFF
C     9/2/75 - TURN INSIDE OUT TO BE CORRECT, ADD MAXLEXTRAP
C     4/28/76 - CHANGE DEBUG CONTROL; GO ON EVEN AFTER ERROR
C     9/3/76 - FIX ERRORS FOR LMIN = 0;  ALWAYS PRINT SUMMARY
C     9/10/76 - COMPLETE REWRITE OF EXTRAPOLATION - MHM                 20360   
C     9/26/76 - TOTAL SKIP OF EXTRAP FOR MAXLEXTRAP=0 - SP
C     9/30/76 - DO NOT INCLUDE 2L+1 IN DETERMINING HOW FAR TO
C               EXTRAPOLATE; SMALL CLEANUP; CHANGE SIGN OF DEL - S.P.
C     12/26/76 - INELASTIC SCATTERING
C     12/30/76 - EXPRESS WOODS-SAXON INTERMS OF L(WS) INSTEAD OF C
C     4/19/77 - MORE EFFORTS TO AVOID OVERFLOWS
C     2/6/78 - EXTRAPOLATION OF ELASTIC MADE SAFER - S.P.
C     4/21/78 - EXTRAPOLATE EXCITATION; DON'T NEEDLESSLY REDEFINE
C               ELASTIC ARRAYS - S.P.
C     4/24/78 - REVERSE LI AND LO - S.P.                                20370   
C     4/26/78 - NO COULOMB PHASES; DEFINE COMPLEX "I" ARRAY - S.P.
C      4/27/78 - DON'T EXTRAPOLATE PAST 1E-30 - S.P.
C     10/18/78 - MULTIPLY BETABAR INTO FF CORRECTION FOR COUPL2
C     3/6/79 - NO MORE BETABAR DUE TO S-MATRICES - S.P.
C              INTERPOLATE ELASTIC S-MATRIX; AVOID UNDERFLOWING
C              IMAG(S-ELASTIC)
C     3/25/79 - EXTRAPOLATION OF S(EL) FOR COUPLED CHANS - S.P.
C     5/10/79 - FIX TRANSFER ERROR IN ABOVE - S.P.
C     4/12/79 - IMPROVED S(EL) EXTRAPOLATION - S.P.
C     7/26/79 - STANDARD PREFIXES ETC, MANY CHANGES FOR                 20380   
C        SPIN-ORBIT, MULTIPASS, ETC. - RPG
C     11/3/79 - FIXUP INELASTIC CALCS IN BOB'S VERSION - S.P.
C               INTRODUCE EXTRA FACTOR OF I IN INELASTIC S - S.P.
C     11/20/79 - S-MATRICES STORED BY LO-LI - S.P.
C     11/22/79 - USE (2L+1)|S(L)| DO DETERM HOW FAR TO EXTRAP - S.P.
C     1/16/80 - USE BIGNUM, BIGLOG - RPG
C     3/26/80 - C.C. VERSION; OUTPUT IS REAL*4; RENUMBER - S.P.
C     4/7/80 - USE INTRCF SUBROUTINE; DO NOT USE LI<LXMAX INPUT - S.P.
C     4/12/80 - USE LXTRP1, LXTRP2; POWER EXTRAPOLATIONS - S.P.
C               ALWAYS USE 4 INPUT VALUES TO THE EXTRAP FIT - S.P.      20390   
C     4/26/80 - PBUGSW NOT IN WAVCOM - S.P.
C     4/30/80 - SKIP ELAS PHASE EXTRAP WHEN ONLY NOISE - S.P.
C     5/6/80 - EXTRAP PHASES BY POWERS WHEN IFUNC=2 - S.P.
C     5/9/80 - FIX BLUNDER IN 339 LOOP -- HOW DID IT WORK? - S.P.
C     7/2/80 - USE NCHN, NOT MCHN, IN 979 LOOP - S.P.
C     7/17/80 - REMOVE ,, IN FORMAT - S.P.
C     7/31/80 - CALL SETLOG - S.P.
C     8/4/80 - IVDEP'S FOR CRAY - S.P.
C     8/8/80 - DEFINE MWORK FOR MAXLEXTRAP = 0 - S.P.
C     9/23/80 - FIX BORN ADD-BACK FOR EXTRA (-)**LX - S.P.              20400   
C     9/25/80 - GET LIMOST FROM CHNDEF; MARK'S ATAN; LXTRPM - S.P.
C     9/29/80 - GRIND OUT TO SMLNUM - S.P.
C     7/12/81 - USE DELTA S ARRAYS FOR C.C. EXTRAPOLATION - S.P.
C     10/28/81 - BORN S REQUIRES ROOT 2 FOR IDENTICAL - S.P.
C     1/27/82 - FIX BUG WHEN A, AI NOT DEFINED - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
c                                                                       /formf/
c ***  LNKADB was  numLINKULES but only 12 are used ???
c
      COMMON /FORMF/  IBDS(2), NPOTS(2), LBP, LBT, NBP, NBT, JBP, JBT,
     &  BNDMAX(2), BNDSTP(2), NSTPBD(2), RBNDS(2), ABNDS(2),
     &  RCBNDS(2), BNDMAS(2), BRATMS(2), RSOBDS(2), ASOBDS(2),
     &  VBNDS(2), VSOBDS(2), TAUBDS(2), LNKADB(6, 2, 12)
 
      CHARACTER*1  REACT, HEADER                                        /hedcom/
      COMMON /HEDCOM/  REACT(45), HEADER(65)
 
      LOGICAL ONELSW, IDENSW                                            /inelcm/
      COMMON /INELCM/  JBPF, JBTF, LXMIN, LXMAX, ILILOR, ILILOI, MSTOP,
     &  IA12M, NMLOLX, ONELSW, NUMLX, IRDINT, IELCUP, LILOSZ, NUMLIS,
     &  ILIS, IBETAS(3), ICL2FF, LXSTEP, IDENSW, LSKIP,
     &  JPMIN, JPMAX, JPBASE, NJP, JTMIN, JTMAX, JTBASE, NJT,
     &  IINDXS, ISMATR, ISMATI, NSMAT, NLX, NSPLI, ITOCS,
     &  NASPLI, IUNITR, LIFIT, ILIFIT, NOLFIT, IDELSR, IDELSI
      INTEGER INDXJS(4,2)
      EQUIVALENCE ( INDXJS(1,1), JPMIN )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      COMMON /KANDM/ AKI, AKO, REDMI, REDMO, RIMAX, ROMAX, ISIGS(2),    /kandm/
     &  RSCTS(2), ASCTS(2), RCSCTS(2) ,ISMATS(2), LOMOST, LCRIT,
     &  ISCTMN, ISCTCR, ETAS(2), RCSCTP(2), RCSCTT(2), LCRITS(2),
     &  RATMSS(2), QMIN, ABAR
 
      DIMENSION  AKS(2), REDMS(2), RMAXS(2)
      EQUIVALENCE ( AKI, AKS(1) ), ( REDMI, REDMS(1) ),
     &  ( RIMAX, RMAXS(1) )
 
      CHARACTER*8 NAMES
      COMMON /NAMCOM/ NAMES(1)
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
      COMMON /CCBLK/  ICHNDF, ICHNCP, ITRANS, IBASDF, IBASCP,           /ccblk/
     &    ICCBLK(2), IORDX, MCHNVL, ICHNVL,
     &    IHOMOA, IHOMOB, IINHR8, IINHI8
 
      COMMON /GRIDCM/  RCUEFF, GRDCM1(2),                               /gridcmf
     &  IBINDX, MBINDX, NBINDX, NMFFAC, MXLXGS, NMBFAC,
     & IINHR, IINHI, IRHSR, IRHSI,
     &  INUCH, ICOULH, ILOR, ILOI, ILIR, ILII,
     &  NPTMIN, NOFLO, NUMPT, NCRIT,
     & ISMX, ISMSQ, IPADE, IHOMO,
     &  ISMTSV, IRPTS4, IRPTS,
     &  IGRDC4(5), IDW, IGRDC5(2),
     &  IABS1, IGRDC6(2), GRDCM2, IGRDC7(2), IRWTS,
     &  IGRDC8(2), ICL1FF, ICL1FG, ICL1GF, ICL1GG
 
C
      COMPLEX*16   CFLI
C
C
C     NOTE:  LDEL = LO - LI
C
C
      LOGICAL   BADSW, XTRPSW, TRANSW, BIGRSW, IMAGSW, INVRSW, CCSW     20430   
      LOGICAL PBUGSW
      COMPLEX*16 CTEMP
C
      CHARACTER*2  WRDS(2) / 'RE', 'IM' /
      CHARACTER*8 XWORDS(2,6) / 'WOODS-SA', 'XON', 'POWER-LA', 'W',
     1  'POWER-LA', 'W 2',  'WKB POWE', 'R-LAW',
     2  'LEXTRAP4', ' ', 'LEXTRAP5', ' ' /
C
      REAL*8 DUMMY3(1,1,1)
      REAL*4 DUMMY4(1,1,1)                                              20440   
C
C     MWORK IS THE NUMBER OF ENTRIES PER LX, LDEL IN THE
C     EXTRAPOLATION WORK TABLE.
C
      DATA MWORK / 12 /
C
c
C
      TSTART=second()
C                                                                       20450   
C     Define things that might never get defined
C
      AP = 0
      BP = 0
      CP = 0
C
      TRANSW = ISTRIP .NE. 0
      IPRNT = MOD( IPRINT, 10 )
      PBUGSW = MOD(IPRINT/100, 10) .GE. 4
      CCSW = PROBLM .EQ. 24                                             20460   
C
      XTRPSW = MAXLEX .GT. 0
C
      write (6, 13) REACT, ELAB, HEADER
 13   FORMAT ( '1', T60, 'P T O L E M Y'  /
     1  T48, 'INTERPOLATION AND EXTRAPOLATION IN L' /
     2  '0', 45A1, 'ELAB =', F7.2, ' MEV', 5X, 65A1  / )
C
      write (6, 17) XWORDS(1,IEXTYP), XWORDS(2,IEXTYP)
 17   FORMAT ( '0USING ', A8, A8, 'EXTRAPOLATION FUNCTIONS.' )          20470   
C
      DLMAX = LMAX
      LIPREV = LIMOST
      IF (TRANSW)  LIMOST = LMAX
C     THESE 2 WORK AREAS ARE USED FOR CONTINUED-FRACTION INTERPOLATION.
      ICL = NALLOC( 2*NUMLIS, 'CMPLXLS ' )
      ICINTS = NALLOC( 2*NUMLIS, 'CMPLXIS ' )
      IF ( .NOT. XTRPSW )  GO TO 90
C
C     "LWORK" WILL CONTAIN EXTRAPOLATION PARAMETERS.                    20480   
C     "FITLS" WILL CONTAIN A LIST OF L'S TO BE USED FOR EXTRAPOLATION.
C     "FITIS" WILL CONTAIN THE CORRESPONDING |S|'S.
C
      IWORK = NALLOC( MWORK*NASPLI, 'LWORK   ' )
      ILVALS = NALLOC( 2*NOLFIT, 'FITLS   ' )
      IXINTS = NALLOC( 2*NOLFIT, 'FITIS   ' )
      CALL INIT8 ( IWORK, 0.D0 )
C
C     ALLOCATION IS FINISHED FOR NOW.
C                                                                       20490   
      LTOCS = Z(ITOCS)*FACFR4 - FACFR4
      LLIS = FACFR4*Z(ILIS)-FACFR4
      LWORK = Z(IWORK) - MWORK
      LLVALS = Z(ILVALS)-1
      LLVAL2 = LLVALS+NOLFIT
      LXINTS=Z(IXINTS)-1
      LXINT2 = LXINTS+NOLFIT
C
      write (6, 83) LIFIT, LMAX
 83   FORMAT ( '0EXTRAPOLATION AND CONTINUED FRACTION OVERLAP',         20500   
     1  ' REGION:', I4, ' < LI <', I4  / )
C
C     POSSIBLY SETUP FOR MULTIPLE CHANNELS
C
 90   NCHNDF = 2
      KSMAT = 0
      KSMAT2 = 0
      JMOST = 0
      IF ( .NOT. CCSW )  GO TO 100
      LCHNDF = FACFR4*(Z(ICHNDF)-1) + 1                                 20510   
      NCHNDF = ILLOC(LCHNDF)
      MCHNDF = ILLOC(LCHNDF+1)
      LCHNDF = LCHNDF + ILLOC(LCHNDF+2) + MCHNDF
      LTOCSV = LTOCS
      LBINDX = FACFR4*(Z(IBINDX)-1)
C
C
C     LOOP OVER ALL CHANNELS FOR C.C. CALCULATIONS
C     AND OVER ALL VALUES OF JT, JP, LX,
C     AND OVER ALL VALUES OF DEL=LO-LI FOR EACH LX                      20520   
C
C     FIRST PASS ;
C
C     FIT WOODS SAXON AND DETERMINE LIMOST
C
C
C
 100  DO  299  NCHN = 2, NCHNDF
         MCHN = NCHN
         LMAXL = LMAX                                                   20530   
         IF ( .NOT. CCSW )  GO TO 110
C
         MCHN = ILLOC(LCHNDF)
         ETAS(2) = ALLOC4(LCHNDF+5)
         KSMAT = ILLOC(LCHNDF+9)
         NSPLI = ILLOC(LCHNDF+10)
         LTOCS = LTOCSV + ILLOC(LCHNDF+12)
C
C     CHECK TO SEE FI THERE ARE FIRSTORDER COULOMB COUPLINGS
C     TO THE G.S.  IF NOT THEN DO NOT FORCE EXTRAPOLATION               20540   
C     TO LIMOST.  IF SO USE ALREADY DETERMINED LIMOST.
C
         LIMOST = ILLOC(LCHNDF+14)
         IF  ( LIMOST .EQ. NOTDEF )  LIMOST = LMAX
C
 110     IF ( .NOT. XTRPSW ) GO TO 290
C
C
      DO 289 KOFFS = 1, NSPLI
         JT = ILLOC(LTOCS+4*KOFFS)                                      20550   
         IF ( JT .LT. 0 )  GO TO 289
         JP = ILLOC(LTOCS+4*KOFFS-1)
         LX = ILLOC(LTOCS+4*KOFFS-2)
         LDEL = ILLOC(LTOCS+4*KOFFS-3)
         LDELSR = Z(IDELSR) + ( KOFFS + KSMAT - 1 )
         LDELSI = Z(IDELSI) + ( KOFFS + KSMAT - 1 )
C
C        LOCATE L-PEAK AND CHECK FOR DECAYING FORM OF S.
C         THIS IS IN TERMS OF DELTA S
C                                                                       20560   
 120     LPEAK=LMIN
         BIGBOY=0
         BADSW = .FALSE.
C
         DO 179 ILI=1,NUMLIS
            LI=ILLOC(LLIS+ILI)
            LO = LI  + LDEL
            IF ( LO+LI .LT. LX )  GO TO 179
            IADD=(ILI-1)*NSPLI
            RE = ALLOC(LDELSR+IADD)                                     20570   
            HIM = ALLOC(LDELSI+IADD)
            SIZE = RE**2 + HIM**2
            IF ( LI .LT. LIFIT )  GO TO 170
            SIGNR = SIGN( 1.D0, RE )
            SIGNI = SIGN( 1.D0, HIM )
            IF(LI.EQ.LIFIT) GO TO 160
            IF ( SIZLAS .GT. SIZE )  GO TO 155
            BADSW = .TRUE.
            B = DSQRT(SIZE)
            C = DSQRT(SIZLAS)                                           20580   
            write (6, 153)  MCHN, JP, JT, LX, LDEL, LI, B, C
 153        FORMAT ('0**** ERROR:  CANNOT EXTRAPOLATE FOR ',
     1         'CHANNEL', I3, 2X,
     1        '(JP,JT,LX,LO-LI) = (', 2(I3,'/2'), I2, I3, ') ****' /
     2        ' ****', 9X, 'SINCE FOR LI =', I4,
     3        ' |S| EXCEEDS PREVIOUS:', 2G11.4, ' ****' )
            GO TO 160
 155        IF ( SIGNR .NE. SIGNRL  .OR.  SIGNI .NE. SIGNIL )
     1        write (6, 157)  MCHN, JP, JT, LX, LDEL, LI
  157       FORMAT( '0**** WARNING:  PHASE OF S(L) FOR ',               20590   
     1         'CHANNEL', I3, 2X,
     1         '(JP,JT,LX,LO-LI,LI) = (', 2(I3,'/2'),I3,1X,I3,1X,I3,
     2         ') HAS FLUCTUATING SIGN' )
 160        SIZLAS = SIZE
            SIGNRL = SIGNR
            SIGNIL = SIGNI
 170        SIZE = (2*LI+1)*SIZE
            IF(SIZE.LT.BIGBOY) GO TO 179
            LPEAK=LI
            BIGBOY=SIZE                                                 20600   
  179    CONTINUE
C
C        HAS EXTRAPOLATION BEEN SUPPRESSED FOR THIS ( LX, DELTA )
C
         IF ( BADSW )  GO TO 289
C
C        LOCATE MINIMAL (2LI+1)\S\**2 FOR LI < LPEAK
C
         WEEBOY=1.E+06
C                                                                       20610   
         DO 189 ILI=1,NUMLIS
            LI=ILLOC(LLIS+ILI)
            LO = LI  + LDEL
            IF ( LO+LI .LT. LX )  GO TO 189
            IF(LI.GT.LPEAK) GO TO 189
            IADD=(ILI-1)*NSPLI
            SIZE=(ALLOC(LDELSR+IADD)**2+ALLOC(LDELSI+IADD)**2)
            SIZE = (2*LI+1)*SIZE
            IF(SIZE.GT.WEEBOY) GO TO 189
            WEEBOY=SIZE                                                 20620   
  189    CONTINUE
C
C     WE EXTRAPOLATE TILL SQRT(2LI+1)|S(L)| HAS FALLEN TO WEEBOY
C     WHICH WE USE AS THE MINIMUM OF
C       .2*MIN( SQRT(2L+1)|S| ),  DWCUTOFF*MAX( SQRT(2L+1)|S| )
C
C
         WEEBOY=.2*SQRT(WEEBOY)
         BIGBOY= DWCUT*SQRT(BIGBOY)
         WEEBOY =  DMIN1( WEEBOY, BIGBOY )                              20630   
C
C     FIT WOODS-SAXON FORM   AA / (1 + C * EXP(B*LI) ) IN L
C     TO MODULI |S(L)| OF REACTION S-MATRICES
C     OR FIT POWER LAW OR OTHER SPECIFIED EXTRAP FUNCIION.
C
         DO  209 ILI=ILIFIT,NUMLIS
            I=ILI-ILIFIT+1
            ALLOC(LLVALS+I)=ILLOC(LLIS+ILI)
            ALLOC(LLVAL2+I) = ILLOC(LLIS+ILI)
            IADD=(ILI-1)*NSPLI                                          20640   
            F=DSQRT(ALLOC(LDELSR+IADD)**2+ALLOC(LDELSI+IADD)**2)
            ALLOC(LXINTS+I)=F
            F = DATAN2( ALLOC(LDELSI+IADD), ALLOC(LDELSR+IADD) )
            ALLOC(LXINT2+I) = F
 209     CONTINUE
         CALL LXTRP1 ( IEXTYP,NOLFIT,ISIG,IPRNT,ALLOC(LLVALS+1),
     1      ALLOC(LXINTS+1), FLCRIT, AA, WID, .30D0, 1.D-5,
     2      BARL, BARA, B, BARC, DLMAX, CHISQ, LX, LDEL, ETAS,
     3      MCHN, JP, JT )
         IF(ISIG.GE.0) GO TO  220                                       20650   
 212     write (6, 213)  MCHN, JP, JT, LX, LDEL
  213    FORMAT(1H0,2X,'**** ERROR RETURN FROM L-EXTRAP SUBROUTINE'/
     1         3X, 'CHANNEL', I3, 2X,
     1      7X, 'EXTRAPOLATION SUPPRESSED FOR (JP,JT,LX,LO-LI)=(',
     2      2(I3,'/2'), 2I4, ') ')
         BADSW=.TRUE.
         GO TO 289
  220    IF(ISIG.NE.0) write (6,  223)  MCHN, JP, JT, LX, LDEL
  223    FORMAT(1H0,2X,'SIMPLE EXP OR POWER  USED FOR |S(L)| ',
     1         3X, 'CHANNEL', I3, 2X,                                   20660   
     1      '(JP,JT,LX,LO-LI)=(', 2(I3, '/2'), 2I4, ')' )
C
C
C     FOR POWER LAW EXTRAP, USE A POWER LAW FOR THE PHASES
C
 240     IF ( IEXTYP .EQ. 1 )  GO TO 250
         CALL LXTRP1 ( 3, NOLFIT, ISIG, IPRNT, ALLOC(LLVAL2+1),
     1      ALLOC(LXINT2+1), X, Y, X2, .30D0, 1.D-5,
     2      X3, CP, BP, AP, DLMAX, CHISQ, LX, LDEL, ETAS,
     3      MCHN, JP, JT )                                              20670   
         IF ( ISIG .GE. 0 )  GO TO 250
         write (6, 241)
 241     FORMAT ('0**** FOLLOWING REFERS TO PHASE EXTRAP.' )
         GO TO 212
C
C
C     NOW FIND LIMOST
 250     LI = LXTRPM( IEXTYP, BARA, B, BARC, BARL, DLMAX, LX,
     1      LDEL, ETAS, WEEBOY )
         IF (PBUGSW)  write (6, 263)  MCHN, JP, JT, LX, LDEL, LI        20680   
 263     FORMAT ( ' FOR CHANNEL', I3, 3X,
     1            ' FOR 2*JP, 2*JT, LX, LO-LI =', 4I3, 3X,
     1     'ESTIMATED LARGEST SIGNIFICANT LI IS', I4 )
         LMAXL = MAX0( LMAXL, LI )
C
C        SAVE STUFF FOR LATER
C
C        ALLOC(LAREA)  CONTENTS
C          +0          A = NUMERATOR OF W.S.
C           1          B = INVERSE WIDTH OF W.S.                        20690   
C           2          BARL = ACTUAL PARAMETER FOR GENERALIZED W.S.
C           3          LC = L(1/2) OF W.S.
C           4          AP = NORM OF PHASE EXTRAP.
C           5          CP = 0 OR PI FOR PHASE EXTRAP
C           6          BARA = ACTUAL PARAMETER FOR GENERALIZED W.S.
C           7          BARC = ACTUAL PARAMETER FOR GENERALIZED W.S.
C           8          LMAX AS PREDICTED BY W.S.
C           9          LPEAK
C          10          PEAK VALUE
C          11          BP = POWER OF PHASE EXTRAP                       20700   
C
         LAREA = LWORK + MWORK*KOFFS
         ALLOC(LAREA) = AA
         ALLOC(LAREA+1) = B
         ALLOC(LAREA+2) = BARL
         ALLOC(LAREA+3) = FLCRIT
         ALLOC(LAREA+4) = AP
         ALLOC(LAREA+5) = CP
         ALLOC(LAREA+6) = BARA
         ALLOC(LAREA+7) = BARC                                          20710   
         ALLOC(LAREA+8) = LI
         ALLOC(LAREA+11) = BP
C
C        END OF FIRST LOOP ON JP, JT, LX, AND LO-LI
C
 289  CONTINUE
C
C     COMPUTE SIZE REQUIREMENTS OF THIS CHANNEL
C     IF LIMOST HAS BEEN PICKED BY COULOMB BORN EXTRAP, WE CANNOT
C     CHANGE IT NOW.                                                    20720   
C
  290    IF ( LIMOST .LE. LMAX )  LIMOST = MIN0( LMAXL, LMAX+MAXLEX )
         JMOST = MAX0( JMOST, LIMOST )
         LNSMAT = NSPLI*(LIMOST-LMIN+1)
         IF ( .NOT. CCSW )  GO TO 295
         ILLOC(LCHNDF+13) = KSMAT2
         ILLOC(LCHNDF+14) = LIMOST
C
C     POSSIBLY GO ON TO NEXT CHANNEL
C                                                                       20730   
         LCHNDF = LCHNDF + MCHNDF
         LWORK = LWORK + MWORK*NSPLI
C
 295     KSMAT2 = KSMAT2 + LNSMAT
C
 299  CONTINUE
C
      LILOSZ = KSMAT2
C
C     ALLOCATE SPACE FOR REACTION S-MATRICES TO XSECTN                  20740   
C
      I1 = 2*LILOSZ
      IRDINT = NALLOC( I1/FACFR4, 'S       ' )
      IUNITR = NALLOC( (JMOST-LMIN+2)/FACFR4, 'UNITARIT' )
      CALL INIT4 ( IUNITR, 0. )
      CALL INIT4 ( IRDINT, 0. )
         BIGRSW = TRANSW  .OR.  JMOST .GT. LIPREV
C
C     EXTEND ARRAYS OF ELASTIC S-MATRIX ELEMENTS OUT TO
C     MAXIMUM L-S NEEDED IN TRANSFER CALCULATION                        20750   
C     USING BORN APPROXIMATION L-DEPENDENCE WHICH IS
C
C        S(L) = EXP( -2 I DELTA(L) )
C        DELTA(L) = DELTA(LMAX) * EXP( -(RT(L)-RT(LMAX))/A' )
C     WHERE
C        RT = ( ETA + SQRT(L(L+1)+ETA**2) ) / K  =  TURNING POINT
C        A' = A      FOR RE(DELTA)
C           = AI (OR ASI)  FOR IM(DELTA)
C           IS THE DIFFUSNESS OF THE RELEVANT POTENTIAL.
C                                                                       20760   
C     NOTE THAT THIS FORM ASSUMES AN EXPONENTIAL DECAY OF V+IW THAT
C     IS GIVEN BY A AND AI OR ASI.
C
C     NOTE THAT ONLY THE LX=0 (CENTRAL) S-MATRIX ELEMENTS ARE
C     EXTRAPOLATED; OTHERS ARE SET TO 0 FOR LARGE L.
C
C     NOTE THAT IN THE CASE OF COUPLED CHANNELS, SIN IS STILL THE
C     OPTICAL MODEL SIN.
C
C                                                                       20770   
      LOMOST = JMOST + LXMAX
      IF ( JMOST.LE.LMAX )  GO TO 500
C
      IF ( CCSW )  NUMJS(2) = NUMJS(1)
C
      DO 399 I=1,2
C
C        EXTEND THE S-MATRIX AND COULOMB PHASE ARRAYS,
C        AND SET THE NEW PART OF S TO 0.
C                                                                       20780   
         IF (BIGRSW)  CALL IREDEF(LOMOST+1,ISIGS(I))
         N = 2*NUMJS(I)*(LMAX+1) + 1
         NN = 2*NUMJS(I)*(LOMOST+1)
         CALL IREDEF ( NN, ISMATS(I) )
         LSMAT = Z(ISMATS(I))
         LSIG = Z(ISIGS(I))
         DO 339  II = N, NN
            ALLOC(LSMAT+II-1) = 0
 339     CONTINUE
C                                                                       20790   
C        SET UP THE EXTRAPOLATION PARAMETERS.
C
         IF ( I .EQ. 2  .AND. CCSW )  GO TO 399
         CPH=ALLOC(LSIG+LMAX)
         E2=ETAS(I)**2+ DLMAX*(DLMAX+1)
         E2=DSQRT(E2)
         EXRFAC = 1.D10
         IF ( ASCTS(I) .NE. UNDEF )  EXRFAC = 1/(AKS(I)*ASCTS(I))
         EXIFAC = 1.D10
         IF ( AIS(I) .NE. UNDEF )  EXIFAC = 1/(AKS(I)*AIS(I))           20800   
         IF ( ASIS(I) .NE. UNDEF )  EXIFAC = 1/(AKS(I)*ASIS(I))
         BADSW = EXRFAC .EQ. 1.D10  .OR.  EXIFAC .EQ. 1.D10
         IF ( BADSW )  write (6, 348) I
 348     FORMAT ('0**** WARNING:  ELASTIC S MATRIX FOR CHANNEL',
     1     I2, ' NOT EXTRAPOLATED BECAUSE A OR AI IS',
     2     ' NOT DEFINED.' )
         IF ( BADSW )  GO TO 350
         LOC = LSMAT + 2*LMAX*NUMJS(I)
         SIZE=DSQRT(ALLOC(LOC)**2+ALLOC(LOC+1)**2)
         DTIM=-.5*DLOG(SIZE)                                            20810   
         DTRE = .5*DATAN2(ALLOC(LOC+1),ALLOC(LOC))
 350     IF (PBUGSW)  write (6, 353) I, E2, EXRFAC, EXIFAC, SIZE,
     &      DTRE, DTIM
 353  FORMAT ( '0EXTRAPOLATION OF OPTICALS:', I2, 6G15.5 )
C
C        NOW LOOP THROUGH THE L VALUES, EXTRAPOLATING S FOR LX=0.
C     FOR CHECKING AND TO FILL IN GAPS IN C.C. CALCS, WE START FROM
C      A LOWER L-VALUE AND COMPARE OR STORE
C
         LO = LIFIT-LXMAX                                               20820   
         RE = 1
         HIM = 0
         DO 389 L = LO, LOMOST
            LOC = LSMAT + 2*NUMJS(I)*L
            IF ( BADSW )  GO TO 380
            E1=ETAS(I)**2+L*(L+1)
            DRO=DSQRT(E1)-E2
            EXR = 0
            X = DRO*EXRFAC
            IF ( X .LT. BIGLOG )  EXR = DEXP(-X)                        20830   
            EXI = 0
            X = DRO*EXIFAC
            IF ( X .LT. BIGLOG )  EXI = DEXP(-X)
            DRE=EXR*DTRE
            DIM=EXI*DTIM
            SIZE=DEXP(-2.D0*DIM)
            RE =SIZE*DCOS(2.D0*DRE)
            HIM =SIZE*DSIN(2.D0*DRE)
            IF ( L .GT. LMAX )  GO TO 380
            IF ( DABS(ALLOC(LOC))+DABS(ALLOC(LOC+1)) .EQ. 0 )  GO TO 38020840   
            IF ( DABS(ALLOC(LOC)-RE)+DABS(ALLOC(LOC+1)-HIM) .GT.
     1        .1*(LMAX+1-L)*(DABS(DRE)+DIM) )
     &         write (6, 373) I, L, RE, HIM,
     2           ALLOC(LOC), ALLOC(LOC+1), DRE, DIM, EXR, EXI
 373        FORMAT ( '0*** POOR OPTICAL EXTRAP:', 2I4 /
     1       4X, 4G16.6, 4G14.4 )
            GO TO 389
 380        ALLOC(LOC) = RE
            ALLOC(LOC+1) = HIM
            IF ( L .LE. LMAX  .OR.  .NOT. BIGRSW )  GO TO 389           20850   
            CPH=CPH+DATAN(ETAS(I)/L)
            ALLOC(LSIG+L) = CPH
  389    CONTINUE
C
  399 CONTINUE
C
C     END OF ELASTIC S-MATRIX EXTRAPOLATION.
C
C
C     PREPARE FOR THE SECOND INTERPOLATION/EXTRAPOLATION PASS.          20860   
C
 500  CALL SETLOG ( 2*(LOMOST+LXMAX) )
      LCL = Z(ICL)
      LCINTS = Z(ICINTS)
      LLIS = FACFR4*Z(ILIS)-FACFR4
      LTOCS = Z(ITOCS)*FACFR4 - FACFR4
      LELIN=Z(ISMATS(1))
      LELOUT=Z(ISMATS(2))
      LUNITR = FACFR4*(Z(IUNITR)-1) + 1 - LMIN
      IF (TRANSW .OR. CCSW )  GO TO 680                                 20870   
      FACTOR = DSQRT( AKI*AKO/(ES(1)*ES(2)*PI) )
      LBRAT = Z(IBETAS(3)) - LXMIN/2
 680  IF ( .NOT. XTRPSW )  GO TO 700
      LLVALS = Z(ILVALS)-1
      LXINTS=Z(IXINTS)-1
      LWORK = Z(IWORK) - MWORK
C
C     LOOP AGAIN OVER CHANNELS, (JT,JP,LX,LO-LI)
C
C     SECOND PASS ;                                                     20880   
C     MAKE CONTINUED FRACTION INTERPOLATION (LMIN TO LMAX)
C     AND EXPONENTIAL EXTRAPOLATION (LIFIT TO LIMOST)
C     USE THESE TO COMPLETE TABLE OF S(L)
C     ACCUMULATE UNITARITY CONTRIBUTIONS
C
C     DO THIS FOR EACH CHANNEL, JT, JP, LX, LO-LI
C
C     LIFIT < LMAX  IS START OF EXPONENTIAL REGION
C
C                                                                       20890   
C
C     START OF PHASE EXTRAPOLATION.
C
      I = LELIN + 2*NUMJS(1)*LMAX
      ELFIN = .5 * DATAN2 ( ALLOC(I+1), ALLOC(I) )
C
C     INITIALIZE CLEBSCH ROUTINE
C
 700  IF ( .NOT. TRANSW )  CALL DUMMY1
C                                                                       20900   
      KSMAT2 = 0
      IF ( .NOT. CCSW )  GO TO 710
C
      LCHNDF = FACFR4*(Z(ICHNDF)-1) + 1
      LCHNDF = LCHNDF + ILLOC(LCHNDF+2) + MCHNDF
      LCHNSV = LCHNDF
      LTOCSV = LTOCS
      LBINDX = FACFR4*(Z(IBINDX)-1)
C
C     FOR CC PHASE EXTRAPOLATION WE ARE CRUDE AND USE                   20910   
C       OPTICAL PHASE SHIFT(OUTGOING) = OPTICAL PHASE(INCOMING)
C
      LELOUT = LELIN
C
 710  DO 999  NCHN = 2, NCHNDF
         MCHN = NCHN
C
         IF ( .NOT. CCSW )  GO TO 720
         MCHN = ILLOC(LCHNDF)
         ETAS(2) = ALLOC4(LCHNDF+5)                                     20920   
         KSMAT = ILLOC(LCHNDF+9)
         NSPLI = ILLOC(LCHNDF+10)
         LTOCS = LTOCSV + ILLOC(LCHNDF+12)
         KSMAT2 = ILLOC(LCHNDF+13)
         LIMOST = ILLOC(LCHNDF+14)
C
C
 720  DO 989  KOFFS = 1, NSPLI
         JT = ILLOC(LTOCS+4*KOFFS)
         IF ( JT .LT. 0 )  GO TO 989                                    20930   
         JP = ILLOC(LTOCS+4*KOFFS-1)
         LX = ILLOC(LTOCS+4*KOFFS-2)
         LDEL = ILLOC(LTOCS+4*KOFFS-3)
         LSMATR = Z(ISMATR) + ( KOFFS + KSMAT - 1 )
         LSMATI = Z(ISMATI) + ( KOFFS + KSMAT - 1 )
         LDELSR = Z(IDELSR) + ( KOFFS + KSMAT - 1 )
         LDELSI = Z(IDELSI) + ( KOFFS + KSMAT - 1 )
         LRDINT = FACFR4*(Z(IRDINT)-1)+1 + 2*(KOFFS-1 + KSMAT2)
         LISTRT = MAX0( LMIN, (LX-LDEL+1)/2 )
C                                                                       20940   
C        FIT CONTINUED FRACTION TO S-MATRICES WITH DESIGNATED
C        LI VALUES.
C
C     FOR C.C. THIS IS IN TERMS OF THE COMPLETE S-MATRIX
C
         CALL INTRCF ( MCHN, JP, JT, LX, LDEL,
     &      NUMLIS, ILLOC(LLIS+1), LSTEP, LXMAX,
     &      ALLOC(LSMATR), ALLOC(LSMATI), 1, NSPLI, .FALSE.,
     &      LISTRT, LMAX, DUMMY3, ALLOC4(LRDINT),
     &      1, NSPLI, LMIN-1, .TRUE.,                                   20950   
     &      BIGBOY, LPEAK, ALLOC(LCL), ALLOC(LCINTS) )
C
         IF ( TRANSW .AND. ( ( LPEAK.EQ.LMIN  .AND.  LMIN .GT. 0 )  .OR.
     1      LPEAK .GE. LMAX ) )  write (6,  853) JP, JT, LX, LDEL, LPEAK
  853    FORMAT( '0**** WARNING:  FOR (2*JP,2*JT,LX,LO-LI) = (', 4I3,
     1      ')    LPEAK = ',I3,' IS AT END OF L-RANGE (FISHY) ***')
C
         IF ( .NOT. XTRPSW )  GO TO  950
C
C        GET EXPONENTIAL EXTRAPOLATING FUNCTIONS                        20960   
C
         LAREA=LWORK+MWORK*KOFFS
         B = ALLOC(LAREA+1)
         BARL = ALLOC(LAREA+2)
         BARA = ALLOC(LAREA+6)
         BARC = ALLOC(LAREA+7)
         ALLOC(LAREA+9) = LPEAK
         ALLOC(LAREA+10) = DSQRT(BIGBOY)
C
C        COULD WE DO IT ?                                               20970   
C
         IF ( BARA .EQ. 0 )  GO TO  950
C
         AP = ALLOC(LAREA+4)
         CP = ALLOC(LAREA+5)
         BP = ALLOC(LAREA+11)
         IF ( IEXTYP .GE. 2 )  GO TO 890
C
C        DETERMINE SIGN AND MULTIPLIER FOR PHASE-EXTRAPOLATION
C        COMPUTE PHI EXTRAPOLATION USING ONLY INELDC STUFF              20980   
C     THIS IS THE PHASE OF S - S(BORN)
C
         LO = LMAX + LDEL
         IADD = (NUMLIS-1)*NSPLI
         PHASE=DATAN2(ALLOC(LDELSI+IADD), ALLOC(LDELSR+IADD))
         CP = 0
         IF ( DABS(PHASE) .GT. .25*PI )  CP = SIGN( .5*PI, PHASE )
         IF ( DABS(PHASE) .GT. .75*PI )  CP = SIGN( PI, PHASE )
         PHASE = PHASE - CP
         I = LELOUT + 2*NUMJS(2)*LO                                     20990   
         ELFOUT = .5*DATAN2 ( ALLOC(I+1), ALLOC(I) )
         ELPH=ELFOUT+ELFIN
         AP= (PHASE/ELPH)
         ALLOC(LAREA+4)=AP
         ALLOC(LAREA+5)=CP
C
C
C        USE EXPONENTIAL TO EXTRAPOLATE TO LIMOST
C        STORE REACTION S-MATRICES FOR XSECTN
C                                                                       21000   
C
C        FOR FIRST 2 S-MATRICES BEYOND LAST I COMPUTED BY INELDC
C        CHECK THAT EXPONENTIAL AND CONTINUED-FRACTION EXTRAPOLATION
C        AGREE TO WITHIN 10%
C
 890     IF (PBUGSW)  write (6,  893)  MCHN, JP, JT, LX, LDEL
  893    FORMAT(1H0,2X,'* EXTRAPOLATED S-MATRICES WITH ',
     1         ' CHANNEL =', I3, 3X,
     1      '(JP,JT,LX,LO-LI) = (', 2(I3,'/2'),I3,1X,I3,') *' /
     2     '  LI', 12X, 'WOODS-SAXON', T42, 'CONTINUED FRACTION' ,      21010   
     3        T74, 'DIFFERENCE' /
     3     12X, 2( 'MAG', 8X, ' PHASE ', 11X )  / )
C
         DO 949 LI=LIFIT, LIMOST
            LO = LI + LDEL
            CALL LXTRP2 ( IEXTYP, BARA, B, BARC, BARL, DLMAX, LI,
     1         SIZE, LX, LDEL, ETAS )
            IF ( SIZE .LT. SMLNUM )  GO TO 950
            I = LELOUT + 2*NUMJS(2)*LO
            II = LELIN + 2*NUMJS(1)*LI                                  21020   
            IF ( IEXTYP .GE. 2 )  GO TO 915
            ELPH = .5 * ( DATAN2(ALLOC(I+1),ALLOC(I))
     1         + DATAN2(ALLOC(II+1),ALLOC(II)) )
            PHASE = CP + AP*ELPH
            GO TO 920
 915        CALL LXTRP2 ( 3, AP, BP, CP, DLMAX, DLMAX, LI,
     1         PHASE, LX, LDEL, ETAS )
 920        RE= SIZE*DCOS(PHASE)
            HIM= SIZE*DSIN(PHASE)
            IF ( DABS(RE) .LT. 1.D-30 )  RE = 0                         21030   
            IF ( DABS(HIM) .LT. 1.D-30 )  HIM = 0
C
C        HERE THE EXPONENTIAL AND CF EXTRAPOLATIONS ARE COMPARED
C
            IF ( LSTEP .EQ. 1  .OR.  CCSW )  GO TO 940
            IF ( LI .GT. LMAX+2  .AND.  .NOT. PBUGSW )  GO TO 945
            CFLI=LI
            CALL CCONTF(ICOUNT,ALLOC(LCL),ALLOC(LCINTS),
     1         CFLI,CTEMP)
            RRE=DREAL(CTEMP)                                            21040   
            HUM=DIMAG(CTEMP)
            SIZEC = DSQRT( RRE**2 + HUM**2 )
            PHC = DATAN2( HUM, RRE )
            RRE = RE-RRE
            HUM = HIM-HUM
            F = DSQRT( RRE**2+HUM**2 )
            IF ( PBUGSW  .AND.  ( LI .LE. LMAX  .OR.
     1         MOD(LI,5) .EQ. 0 ) )  write (6,  933) LI, SIZE, PHASE,
     2         SIZEC, PHC, F
  933       FORMAT ( 1X, I4, 2X, 3( 2G13.5, 3X ) )                      21050   
            IF ( LI .GT. LMAX+2 )  GO TO 945
            F = 50 * F/DMIN1( SIZE, SIZEC )
            IF (F .GT. 100) write (6, 938) MCHN, JP, JT, LX, LDEL, LI, F
  938       FORMAT(1H ,'**** WARNING:  AT (2*JP,2*JT,LX,LO-LI,LI) = (',
     1        4I4, I3, I4,')    CF AND EXPONENTIAL EXTRAPOLANTS',
     1        ' DIFFER BY', F6.0, '% ***' )
C
C        IN OVERLAP REGION DON'T OVER-WRITE WITH THE EXTRAPOLATED
C        VALUE.
C                                                                       21060   
 940        IF ( LI .LE. LMAX )  GO TO 949
  945       IADD = 2*(LI-LMIN)*NSPLI
c  !!!!!!!
ccc            if ( abs(re) .lt. 1d-30 ) re = 0
ccc            if ( abs(him) .lt. 1d-30 ) him = 0
            ALLOC4(LRDINT+IADD) = RE
            ALLOC4(LRDINT+IADD+1) = HIM
  949    CONTINUE
C
C        FINALLY ADD THE COULOMB EXCITATION FOR INELASTIC SCATTERING    21070   
C
  950    IF ( TRANSW )  GO TO 980
         IF ( CCSW )  GO TO 960
C
         FACTR = +FACTOR
         IF ( IDENSW )  FACTR = SQRT(2.D0)*FACTR
C
C     SETUP FOR  I**(-LX-1)
C
         IF ( MOD(LX, 4) .LT. 2 )  FACTR = -FACTR                       21080   
         IMAGSW = MOD(LX, 2) .EQ. 0
         LCL2FF = Z(ICL2FF) + KOFFS - 1
C
         DO  959  LI = LISTRT, LIMOST
            LO = LI + LDEL
            IADD =  (LI-LMIN)*NSPLI
            C = FACTR*ALLOC(LBRAT+LX/2) *
     1         DABS( CLEBSH( 2*LI, 2*LX, 0, 0, 2*LO, 0 ) )
            FFI = C*ALLOC(LCL2FF+IADD)
c  !!!!!!                                                               21090   
ccc            if ( abs(ffi) .lt. 1d-30 )  ffi = 0
            IF ( .NOT. IMAGSW )
     1          ALLOC4(LRDINT+2*IADD) = ALLOC4(LRDINT+2*IADD) + FFI
            IF ( IMAGSW )
     1          ALLOC4(LRDINT+2*IADD+1) = ALLOC4(LRDINT+2*IADD+1) + FFI
  959    CONTINUE
         GO TO 980
C
C     ADD BACK THE BORN COULOMB FOR C.C. CALCULATIONSA
C                                                                       21100   
C     FIND ALL RELAVANT BORN TERMS
C
 960     IF ( NMFFAC .EQ. 0  .OR.  .NOT. XTRPSW )  GO TO 980
         LMAXP1 = LMAX+1
         LCL2FF = FACFR4*(Z(ICL2FF)-1)
         DO 979  IB = 1, NBINDX
            LBIN = LBINDX+(IB-1)*MBINDX
            LB = ILLOC(LBIN+9)
            IF ( LB .EQ. 0 )  GO TO 979
            IF ( ILLOC(LBIN+1) .NE. LX  .OR.                            21110   
     1         ILLOC(LBIN+3) .NE. NCHN )  GO TO 979
            NMBFRJ = (LX+1)*((ILLOC(LBIN+4)-ILLOC(LBIN+6))/4+1)
            INDX1 = LB + ishft(LDEL+LX,  -1)
            ASSIGN 967 TO IGOTO
            IF ( .NOT. btest(LX, 0) )  ASSIGN 968 TO IGOTO
            DO 974  LI = LMAXP1, LIMOST
               I = LRDINT + 2*NSPLI*(LI-LMIN)
               SBORN = ALLOC4(LCL2FF+INDX1+NMBFRJ*(LI-LMIN))
               GO TO IGOTO, ( 967, 968 )
 967           ALLOC4(I) = ALLOC4(I) + SBORN                            21120   
               GO TO 974
 968           ALLOC4(I+1) = ALLOC4(I+1) + SBORN
 974        CONTINUE
 979     CONTINUE
C
C     NOW COMPUTE THE UNITARITY CONTRIBUTIONS
C
CRACDIR$ IVDEP
 980     DO 984  LI = LISTRT, LIMOST
            I = LRDINT + 2*NSPLI*(LI-LMIN)                              21130   
            ALLOC4(LUNITR+LI) = ALLOC4(LUNITR+LI)
     1         + ALLOC4(I)**2 + ALLOC4(I+1)**2
 984     CONTINUE
C
C
C        END OF SECOND PASS OVER  JT, JP, LX, LO-LI
C
  989 CONTINUE
C
C     ADVANCE TO THE NEXT CHANNEL                                       21140   
C
         IF ( .NOT. CCSW )  GO TO 999
C
         LCHNDF = LCHNDF + MCHNDF
         LWORK = LWORK + MWORK*NSPLI
C
 999  CONTINUE
C
C
      IF ( .NOT. CCSW )  GO TO 2800                                     21150   
C
C
C     PASS 3
C
C     COUPLED CHANNELS CALCULATION - MUST NOW PROPERLY EXTRAPOLATE
C     THE INCOMING ELASTIC S-MATRICES.  WE USE UNITARITY BY ASSUMING
C     FOR EACH  LI > LMAX:
C
C       |S(EL)|**2 = 1 - SUM(CHAN,LX,LO)|S(INEL)|**2 - ABSORBTION
C                                                                       21160   
C     WHERE THE S(INEL) HAVE ALREADY BEEN EXTRAPOLATED AND ABSORBTION
C     IS FOUND BY
C
C       ABSORBTION(L) = ABSORBTION(LMAX) *
C                        EXP( -(RT(L)-RT(LMAX))/AI )
C       ABSORBTION(LMAX) = 1 - |S(EL,LMAX)|**2 - SUM|S(INEL,LMAX)|**2
C
C     (SEE EXTRAPOLATION OF S(EL) AT END OF PASS 1).  THUS THE
C     ABSORBTION IS ASSUMED TO BE "NUCLEAR" IN ORIGIN AND DECAYS
C     EXPONENTIALLY.  THE REST OF UNITARITY IS ASSUMED TO BE EXACTLY    21170   
C     ACCOUNTED FOR BY THE (COULOMB) REAL COUPLED CHANNELS WHICH
C     GIVE EFFECTS THAT DECAY ONLY AS L**POWER.
C
C     THE PHASE SHIFT IS FOUND BY FITTING
C
C     RAT(L) = A / ( 1 + EXP( (L-LWS)*B ) )
C            = BARA / ( BARC + EXP( (L-BARL)*B ) )
C
C     WHERE
C       RAT(L) = RE(SDIF(L))/IM(SDIF(L))                                21180   
C       SDIF(L) = S(ELAS,C.C.,L) - S(ELAS,OPTICAL,L)
C
C     IN THE OVERLAP REGION AND USING THIS TO EXTRAPOLATE.
C
C
C     FIRST MOVE THE INCOMING OPTICAL ELASTIC S-MATRICES TO THE OUTGOING
C     ARRAYS.  FROM NOW ON WE WILL HAVE THE FOLLOWING:
C       C.C. EXCITATION IN 'S'   (IRDINT)
C       C.C. ELASTIC IN 'SIN'    (ISMATS(1))
C       OPTICAL INCOMING IN 'SOUT'  (ISMATS(2))                         21190   
C
C     * * * * * NOTE * * * * *
C
C     THIS COUPLED-CHANNELS SECTION (HERE TO 2800) WILL NOT WORK
C     IN THE PRESENCE OF SPIN-ORBIT POTENTIALS.
C
C     * * * * * * * * * * * *
C
      LELOUT = Z(ISMATS(2))
      IZERO = 0                                                         21200   
CRACDIR$ IVDEP
      DO 2019  L = IZERO, LOMOST
         ALLOC(LELOUT+2*L) = ALLOC(LELIN+2*L)
         ALLOC(LELOUT+2*L+1) = ALLOC(LELIN+2*L+1)
 2019 CONTINUE
C
C     NOW INTERPOLATE THE C.C. ELASTIC S-MATRICES
C     AND STORE IN SIN
C
C     FOR COUPLN CALCULATIONS WE MUST ALSO INTERPOLATE THE              21210   
C     OPTICAL S-MATRICES.
C
      LELCUP = Z(IELCUP)
      LOTPUT = LELIN
C
      DO 2059  I = 1, 2
C
         CALL INTRCF ( I, 0, 0, 0, 0,
     1      NUMLIS, ILLOC(LLIS+1), LSTEP, LXMAX,
     2      ALLOC(LELCUP), ALLOC(LELCUP+1), 1, 2, I.EQ.2,               21220   
     3      LMIN, LMAX, ALLOC(LOTPUT), DUMMY4,
     &      1, 1, -1, .FALSE.,
     4      BIGBOY, LPEAK, ALLOC(LCL), ALLOC(LCINTS) )
C
         LOTPUT = LELOUT
         LELCUP = LELOUT
 2059 CONTINUE
C
      IF ( .NOT. XTRPSW )  GO TO 3000
C                                                                       21230   
C     DETERMINE THE ABSORPTION EXTRAPOLATION FACTORS
C
      X = ALLOC4(LUNITR+LMAX)
      Y = ALLOC(LELIN+2*LMAX)**2 + ALLOC(LELIN+2*LMAX+1)**2
      RE = 1 - (X+Y)
      ABSORB = DMAX1( RE, 0.D0 )
      E2 = DSQRT( ETAS(1)**2 + LMAX*(LMAX+1) )
      EXIFAC = -1.E10
      IF ( AIS(1) .NE. UNDEF )  EXIFAC = -1/(AKS(1)*AIS(1))
      IF ( ASIS(1) .NE. UNDEF )  EXIFAC = -1/(AKS(1)*ASIS(1))           21240   
      write (6, 2153) LMAX, Y, X, RE, ABSORB, EXIFAC
 2153 FORMAT ( / '0EXTRAPOLATION OF COUPLED-CHANNELS INCOMING',
     1   ' ELASTIC S-MATRICES:' /
     2  '0UNITARITY AT LI = LMAX =', I4, ':   ELASTIC TERM =',
     3    F7.4, 3X, 'INELASTIC SUM =', F7.4,
     4    3X, 'RESIDUAL ABSORBTION =', G12.4 /
     5  ' UNITARITY DEFECT (RESIDUAL ABSORBTION) IS EXTRAPOLATED AS' /
     6  15X, '( ', G12.4, ' ) * EXP(', F8.4,
     7    ' * (RHOTURN(L)-RHOTURN(LMAX)) )' )
      IF ( RE .LT. -.01 )  write (6, 2163)                              21250   
 2163 FORMAT ( ' **** NOTE SERIOUS VIOLATION OF UNITARITY ',
     1  'IN THE ABOVE ****' )
C
C     NOW FIT WOODS-SAXON TO RAT(L)
C
C     WE USE
C
C       SR, SI = S(COUPLED) - S(OPTICAL)
C       RRE, HUM = S(OPTICAL)
C       PH = SR/SI                                                      21260   
C
      INVRSW = .FALSE.
      DO 2249 I = 1, NOLFIT
         II = NOLFIT+1-I
         L = ILLOC(LLIS+NUMLIS+1-I)
         ALLOC(LLVALS+II) = L
         SR = ALLOC(LELIN+2*L) - ALLOC(LELOUT+2*L)
         SI = ALLOC(LELIN+2*L+1) - ALLOC(LELOUT+2*L+1)
         PH = SR/SI
         IF ( L .NE. LMAX )  GO TO 2220                                 21270   
C
C     DETERMIN SIGNS ON FIRST L (=LAST) L-VALUE
C     THEY ARE
C        CPH = SIGN(PH) = SIGN(SR/SI)
C        CCPH = SIGN OF SQRT IN QUADRATIC FORMULA FOR SI
C
         CPH = DSIGN(1.D0, PH)
         RRE = ALLOC(LELOUT+2*L)
         HUM = ALLOC(LELOUT+2*L+1)
         CR = DSQRT( Y*(1+PH**2) - (RRE-PH*HUM)**2 )                    21280   
         CI = -(HUM+PH*RRE)
         CCPH = ((1+PH**2)*SI-CI)/CR
         IF ( DABS(DABS(CCPH)-1) .GT. 1.D-10 )  write (6, 2213) L, CCPH,
     1      CR, CI, RRE, HUM, PH, SR, SI
 2213    FORMAT ( '0**** ERROR \CCPH\ ^= 1:', I4, G20.10 /
     1      7G15.5 )
 2220    PH = PH*CPH
         IF ( PH .GT. 0 )  GO TO 2230
         write (6, 2223) L
 2223    FORMAT ( '0**** ERROR, PHASE OF RE(SDIF)/IM(SDIF) CHANGES',    21290   
     1      ' SIGN IN FITTING REGION AT L =', I5 )
         IF ( DABS(ALLOC(LELIN+2*L+1)) .GT. .005 )  GO TO 2255
C
C     THE PROBLEM IS PROBABLY DUE TO NOISE IN SMALL IMAG PARTS
C
 2225    write (6, 2228)
 2228    FORMAT ( '0**** PHASE OF S-DIF ASSUMMED TO BE 0 ****' )
         LMAXL = 0
         INVRSW = .TRUE.
         GO TO 2300                                                     21300   
C
 2230    IF ( I .NE. 2 )  GO TO 2240
C
C     ON SECOND L, DETERMIN IF |SR/SI| IS INCREASING AND
C     IF SO, EXTRAPOLATE |SI/SR|
C
         INVRSW = ALLOC(LXINTS+NOLFIT) .GT. PH
         IF (INVRSW) ALLOC(LXINTS+NOLFIT) = 1/ALLOC(LXINTS+NOLFIT)
 2240    IF (INVRSW)  PH = 1/PH
         IF ( I .LT. 2  .OR.  ALLOC(LXINTS+II+1) .LT. PH )  GO TO 2245  21310   
         write (6, 2243) L, PH, ALLOC(LXINTS+II+1), INVRSW
 2243    FORMAT ( '0**** WARNING: MAGNITUDE OF RE(S-DIF)/IM(S-DIF)',
     1      ' FLUCTUATES:', I5, 2G15.5, L4 )
         IF ( DABS(ALLOC(LELIN+2*L+1)) .LT. .005 )  GO TO 2225
 2245    ALLOC(LXINTS+II)=PH
 2249 CONTINUE
      CALL LXTRP1 ( 1,NOLFIT,ISIG,IPRNT,ALLOC(LLVALS+1),ALLOC(LXINTS+1),
     1  FLCRIT,AA,WID, .30D0, 1.D-5, BARL, BARA, B, BARC, DLMAX,
     1   CHISQ, 0, 0, ETAS, 1, 0, 0 )
      IF ( ISIG .GE. 0 )  GO TO 2260                                    21320   
 2255 write (6, 2257)
 2257 FORMAT ( '0**** ERROR EXTRAPOLATING RE(SDIF)/IM(SDIF)' /
     1  6X, 'RE/IM ASSUMED TO BE CONSTANT' /
     2  1X, 20('*'), ' ELASTIC CROSS SECTIONS ARE SUSPECT ', 20('*') /)
      B = SMLNUM
      BARC = 1
      BARA = 2*ALLOC(LXINTS+1)
 2260 LMAXL = DLOG(BARA*BIGNUM)/B + BARL
      AA = CPH*AA
      BARA = CPH*BARA                                                   21330   
      I = 1
      IF ( INVRSW )  I = 2
      write (6, 2263) WRDS(I), WRDS(3-I), AA, FLCRIT, WID
 2263 FORMAT ( '0ELASTIC ', A2, '(S-DIF)/', A2, '(S-DIF) EXTRAPOLATED',
     1    ' AS' /
     1  G30.5, ' / ( 1 + EXP( ( L -', G12.4, ' ) /', F10.6, ' )' )
      IF (PBUGSW)  write (6, 2267) BARA, BARC, BARL, ISIG, CCPH, EXPLIM
 2267 FORMAT ( ' BARS:', 3G15.5, I10, '  CCPH =', G15.5, G15.2 )
C
C     NOW DO IT                                                         21340   
C
2300  LSKP = LSKIPS(1)
      LO = LMAX+LSKP
      I1 = 0
      I2 = 0
      DO 2399  LI = LO, JMOST, LSKP
         X = ALLOC4(LUNITR+LI)
         Y = (DSQRT(ETAS(1)**2+LI*(LI+1))-E2)*EXIFAC
         EXI = 0
         IF ( Y .GT. -BIGLOG )  EXI = DEXP(Y)                           21350   
         RE = ABSORB*EXI
         SIZE = 1 - X - RE
         IF ( SIZE .GE. 0 )  GO TO 2350
         I1 = I1+1
         IF ( I1 .LT. 10 )  write (6, 2343) LI, X, Y, EXI, RE, SIZE
 2343    FORMAT ( '0**** INTERNAL ERROR IN ELASTIC MAG. EXTRAP:' /
     1      I4, 6G15.5 )
         SIZE = 0
 2350    PH = CPH*SMLNUM
         IF ( LI .LE. LMAXL )                                           21360   
     1      CALL LXTRP2 ( 1, BARA, B, BARC, BARL, DLMAX, LI, PH,
     2      0, 0, ETAS )
         IF ( INVRSW )  PH = 1/PH
C
C     AT THIS POINT WE HAVE
C
C       SIZE = |S|**2
C       PH = RE(SDIF)/IM(SDIF)
C
C     SOME ALGEBRA IS NEEDED TO GET SR AND SI.                          21370   
C
         RRE = ALLOC(LELOUT+2*LI)
         HUM = ALLOC(LELOUT+2*LI+1)
         RE = SIZE*(1+PH**2) - (RRE-PH*HUM)**2
         IF ( RE .GE. 0 )  GO TO 2360
         I2 = I2+1
         IF ( I2 .LT. 10  .AND.  RE .LT. -1.D-10 )
     1     write (6, 2353) LI, SIZE, PH, RE, RRE, HUM
 2353    FORMAT ( '0**** INTRNAL ERROR IN ELASTIC PHASE EXTRAP:',
     1      I5, 5G15.5 )                                                21380   
         RE = 0
 2360    SI = (-HUM-PH*RRE + CCPH*DSQRT(RE))/(1+PH**2)
         SR = PH*SI
         RE = SR + RRE
         HIM = SI + HUM
         IF ( DABS(HIM) .LT. SMLNUM )  HIM = 0
         ALLOC(LELIN+2*LI) = RE
         ALLOC(LELIN+2*LI+1) = HIM
         IF ( .NOT. PBUGSW )  GO TO 2399
         IF ( LI .GT. LMAX+10  .AND.  MOD(LI, 5) .NE. 0 )  GO TO 2399   21390   
         X = .5 * DATAN2( HIM, RE )
         SIZE = DSQRT(SIZE)
         write (6, 2383) LI, SIZE, X,  RE, HIM, PH, RRE, HUM
 2383    FORMAT ( ' ++', I5, 7G14.5 )
 2399 CONTINUE
C
C
C     PASS 4;  TABULATE THE EXTRAPOLATION PARAMETERS
C
 2800 IF ( .NOT. XTRPSW )  GO TO 3000                                   21400   
      IF ( IBRNSB .EQ. 0  .AND.  .NOT. TRANSW )  write (6, 2823)
 2823 FORMAT ( / '0', 32X,
     1 'FOLLOWING REFER TO THE "NUCLEAR" PART OF THE INELASTIC ',
     2  'AMPLITUDES.' )
      write (6, 2833) DLMAX, DLMAX
 2833 FORMAT ( / '0', T49, 'SUMMARY OF EXTRAPOLATION PARAMETERS' /
     1  '0', 19X, '|S| = A/( C + EXP( (LI-LCRIT)/LWIDTH ) )' ,
     2      T72, 'PHASE = CP + AP*(SUM OF ELASTIC PHASE-SHIFTS)' /
     2   16X, 'OR', 6X, '= A*(', F6.0, '/L)**B * (1+LCRIT/L)',
     2      T72, 6X, '= CP + AP*(', F6.0, '/L)**BP' /                   21410   
     2   16X, 'OR', 6X, '= ABOVE * SIN(ATAN(ETA/L))**LX' /
     2   26X, '* EXP(-(ETA2-ETA1)(ATAN(ETA/L)+L/ETA))' /
     3  '0CHANNEL   JP   JT  LX LO-LI', T34, 'PEAK',
     3      T47, 'MAX L',
     3      T69, 'MAGNITUDE EXTRAPOLATION',
     4       T108, 'PHASE EXTRAPOLATION' /
     5  T31, 'LI', 5X, 'VALUE', T48, 'USED', T62, 'A', 9X, 'C',
     5     4X, 'LWIDTH', T87,
     6     'LCRIT', 3X, 'MAX L', T109, 'CP', 8X, 'AP', 8X, 'BP' /
     7  T77, 'OR B', T95, 'NEEDED' / )                                  21420   
C
      LTOCS = Z(ITOCS)*FACFR4 - FACFR4
      IF ( CCSW )  LCHNDF = LCHNSV
      LWORK = Z(IWORK)-MWORK
C
      DO 2899  NCHN = 2, NCHNDF
         MCHN = NCHN
C
         IF ( .NOT. CCSW )  GO TO 2860
         MCHN = ILLOC(LCHNDF)                                           21430   
         NSPLI = ILLOC(LCHNDF+10)
         LTOCS = LTOCSV + ILLOC(LCHNDF+12)
         LIMOST = ILLOC(LCHNDF+14)
C
 2860    DO 2889  KOFFS = 1, NSPLI
            JT = ILLOC(LTOCS+4*KOFFS)
            IF ( JT .LT. 0 )  GO TO 2889
            JP = ILLOC(LTOCS+4*KOFFS-1)
            LX = ILLOC(LTOCS+4*KOFFS-2)
            LDEL = ILLOC(LTOCS+4*KOFFS-3)                               21440   
            LAREA = LWORK + MWORK*KOFFS
            WID = ALLOC(LAREA+1)
            IF ( IEXTYP .EQ. 1  .AND.  WID .NE. 0 )  WID = 1/WID
            I = ALLOC(LAREA+7)
            LMAXL = ALLOC(LAREA+8)
            LPEAK = ALLOC(LAREA+9)
            write (6, 2873)  MCHN, JP, JT, LX, LDEL, LPEAK,
     1        ALLOC(LAREA+10), LIMOST,
     1        ALLOC(LAREA), I, WID, ALLOC(LAREA+3),
     2        LMAXL, ALLOC(LAREA+5), ALLOC(LAREA+4), ALLOC(LAREA+11)    21450   
 2873       FORMAT ( I5, I6, '/2', I3, '/2', I3, I5, I6, G13.3, I6,
     1     G17.5, I4, F10.3, G12.3, I6, F13.3, F10.3, F10.3 )
 2889    CONTINUE
C
         IF ( .NOT. CCSW )  GO TO 2899
         write (6, 2893)
 2893    FORMAT ( ' ' )
         LWORK = LWORK + NSPLI*MWORK
         IF ( CCSW )  LCHNDF = LCHNDF + MCHNDF
 2899 CONTINUE                                                          21460   
C
      Z(IWORK) = -Z(IWORK)
      Z(ILVALS) = -Z(ILVALS)
      Z(IXINTS) = -Z(IXINTS)
 3000 Z(ICL) = -Z(ICL)
      Z(ICINTS) = -Z(ICINTS)
      IF ( TRANSW )  GO TO 3300
      IF ( CCSW .AND.  NMFFAC .EQ. 0 )  GO TO 3300
      Z(ICL2FF) = -Z(ICL2FF)
C                                                                       21470   
 3300 TIME=second()-TSTART
      write (6, 3333)TIME
 3333 FORMAT( '0 TIME FOR L-INTERPOLATIONS : ',F7.3,' SECONDS'/)
      RETURN
C
C
      END
C*ID* LMCFUN   C109.PTOLEMY.SOURCE                          PER701  17:
      SUBROUTINE  LMCFUN ( ITYPE, MPARA, MPTS, X, FS, FJACOB, IERR )
C                                                                       21480   
C     CHI. SQR. FUNCTION FOR  LMCHOL
C
C     THIS IS AN INTERFACE BETWEEN LMCHOL AND CALFUN.
C
C     10/31/75 - FIRST VERSION - S. P.
C     11/25/76 - RETURN IERR = 1 FOR STEPS OUT OF BOUNDS
C
      implicit real*8 ( a-h, o-z )                                      implicit
CDC      ALLOCLEVEL X,FS,FJACOB
C                                                                       21490   
      REAL*8  X(MPARA), FS(MPTS), FJACOB(MPTS, MPARA)
C
      COMMON/LOCFIT/IDATA,LPL,LSIGMA,LSMAT,IESETS,IMASK,IEQUAL,
     1  NPARA,IPARA,ITEMP, LSCSIG, LEPARM, LFS, NPTS, LEQNAM, MAXEQL,
     2  MAXVS, LVDERV, LSDELS, LDVTYP, LDSDP, LDFDX,
     3  LFGRAD, LTGRAD
C
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
C
      IERR = 0                                                          21500   
C
CCCC      GO TO ( 10, 20, 20 ), ITYPE
CCCCC
CCCC 10   xxxx = calfun ( NPTS, NPARA, FS, X )
CCCC      RETURN
C
C     IT APPEARS TO BE MOST ECONOMICAL TO ALWAYS COMPUTE EVERYTHING
C     SINCE LMCHOL SUCCEEDS MOST OF THE TIME AND THEN WANTS THE JACOBIAN
C     ANYWAY.
C                                                                       21510   
C
 20   F = CALGRA ( NPTS, NPARA, FS, X, FJACOB, ALLOC(LTGRAD) )
      ITYPE = 3
      IF ( F .GT. 1.D20 )  IERR = 1
C
      RETURN
      END
C*ID* LSTKEY   C109.PTOLEMY.SOURCE                          PER701  15:
      SUBROUTINE LSTKEY ( VALSW, NUMFLT, FLTWRD, NUMINT, INTWRD,
     1  NUMJ, JWRDS, NUMSWW, SWTWRD, SWTNUM, SWTSET,                    21520   
     2  NUMKEY, KEYWRD, NUMALI, ALIAI )
C
C     LIST THE KEYWORDS AND THEIR VALUES
C
C     4/15/75 - COMPLETE REWRITE.
C     7/22/76 - CDC/IBM, REMOVE TEMPCM
C     12/28/79 - STANDARD MORTRAN - RPG
C     1/24/80 - MORE CHARACTER VARIABLES; QUOTES IN DATA STATEMENTS;
C        CNDCNI USE A16 FOR VALUES; BRKFMT USED FOR CDC ONLY (WHY?) - RP
C     6/2/80 - FMTSI MUST HAVE SEPARATE CDC VERSION - S.P.              21530   
C     6/24/80 - ALSO MUST AUNDF2 - S.P.
C     7/16/80 - CDM, CDO PREFIX, ONLY ARRAYS AS FORMATS - S.P.
C     7/21/80 - USE FMT(2) AT 125 - S. P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
C
      CHARACTER*8  FLTWRD(NUMFLT), INTWRD(NUMINT), JWRDS(NUMJ),
     1  SWTWRD(NUMSWW), KEYWRD(NUMKEY), ALIAI(NUMALI)
      INTEGER  SWTNUM(NUMSWW), SWTSET(NUMSWW)
      LOGICAL VALSW                                                     21540   
C
C
C
C
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      parameter ( NUMJWORD = 12 )                                       /jblock/
      COMMON /JBLOCK/  J, JS(5),
     &  JP, JSP, JST,
     &  JPARM1, JPARM2, JPARM3
 
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
C                                                                       21550   
C
      DIMENSION FLOAT(1), INTGER(1), JBLOCK(1)
      INTEGER SWITCH(1)
      EQUIVALENCE ( FLOAT(1), A ),  ( INTGER(1), L ),
     1  ( JBLOCK(1), J ),  ( SWITCH(1), IASYMP )
C
C
C
      CHARACTER*8  NAMES(250), BLANK /' '/, NOMORE /'*NOMORE*'/
      CHARACTER*8  SYNS(250)                                            21560   
      EQUIVALENCE  ( SYNS(1), VALUES(1) )
      CHARACTER*16 VALUES(250), BLANKC, AUNDEF
      CHARACTER*8  BLNKC2(2) / ' ', ' ' /,
     1  AUNDF2(2)
      EQUIVALENCE ( BLANKC, BLNKC2(1) ), ( AUNDEF, AUNDF2(1) )
C
      CHARACTER*16 VALWRD
      CHARACTER*8  FMT(3)
CDC      REAL  BRKFMT(1) / '(2A8)' /
C                                                                       21570   
      INTEGER INDEX(250)
      CHARACTER*8  FMTS(6) / 'E14.6', 'F10.6', 'F10.0', 'F10.5',
     1  'F10.3', 'F10.1' /
      CHARACTER*8 FMTSI(2)
      DATA FMTSI / 'I10',  'I8,2H/2' /
      DATA AUNDF2 / '  NOT DE',  'FINED   ' /
      DATA FMT / '(', ' ', ')' /
c
C
      DO 49  I = 1, 250                                                 21580   
         NAMES(I) = BLANK
         VALUES(I) = BLANKC
         INDEX(I) = I
  49  CONTINUE
C
C
C     COLLECT ALL THE DATA ENTRY KEYWORDS
C
      K = 0
      DO 129  I = 1, NUMFLT                                             21590   
         IF ( FLTWRD(I) .EQ. NOMORE )  GO TO 129
         K = K+1
         NAMES(K) = FLTWRD(I)
         IF ( .NOT. VALSW )  GO TO 129
         IF ( FLOAT(I) .NE. UNDEF )  GO TO 120
         VALUES(K) = AUNDEF
         GO TO 129
C     SIMULATE G FORMAT
 120     X = DABS(FLOAT(I))
         N = 3                                                          21600   
         IF ( X .EQ. 0 )  GO TO 125
         N = 1
         IF ( X .LT. .01D0  .OR.  X .GT. 1.D6 )  GO TO 125
         N = 2
         IF ( X+1.D-6 .LT. 1 )  GO TO 125
         N = 3
         IF ( DMOD(X+1.D-8, 1.D0) .LT. 1.D-7 )  GO TO 125
         N = 4
         IF ( X .LT. 100 )  GO TO 125
         N = 5                                                          21610   
         IF ( X .LT. 10000 )  GO TO 125
         N = 6
 125  FMT(2) = FMTS(N)
CIB         CALL CONVO ( FMT, VALUES(K), 0, IW, FLOAT(I) )
      write( unit=VALWRD, fmt=FMT )  FLOAT(I)                           cni
      VALUES(K) = VALWRD                                                cni
 129  CONTINUE
C
      DO 149  I = 1, NUMINT
         IF ( INTWRD(I) .EQ. NOMORE )  GO TO 149                        21620   
         K = K+1
         NAMES(K) = INTWRD(I)
         IF ( .NOT. VALSW )  GO TO 149
         IF ( INTGER(I) .NE. NOTDEF )  GO TO 140
         VALUES(K) = AUNDEF
         GO TO 149
 140  FMT(2) = FMTSI(1)
CIB         CALL CONVO  ( FMT , VALUES(K), 0, IW, INTGER(I) )
      write( unit=VALWRD, fmt=FMT ) INTGER(I)                           cni
      VALUES(K) = VALWRD                                                21630   
 149  CONTINUE
C
      DO 179  I = 1, NUMJ
         IF ( JWRDS(I) .EQ. NOMORE )  GO TO 179
         K = K+1
         NAMES(K) = JWRDS(I)
         IF ( .NOT. VALSW )  GO TO 179
         IF ( JBLOCK(I) .NE. NOTDEF )  GO TO 160
         VALUES(K) = AUNDEF
         GO TO 179                                                      21640   
160      JVAL = JBLOCK(I)
      N = 2
         IF ( MOD(JVAL, 2) .NE. 0 )  GO TO 170
         JVAL = JVAL/2
      N = 1
 170  FMT(2) = FMTSI(N)
CIB      CALL CONVO ( FMT, VALUES(K), 0, IW, JVAL )
      write( unit=VALWRD, fmt=FMT ) JVAL                                cni
      VALUES(K) = VALWRD                                                cni
 179  CONTINUE                                                          21650   
C
C     DATA ENTERING STUFF ALL COLLECTED, SORT AND PRINT
C
      N = K
      CALL ALSORT ( NAMES, INDEX, N )
      IF ( VALSW )  GO TO 250
      NN = (N+5)/6
      NNN = 6*NN
      write (6, 223) ( (NAMES(INDEX(II+I-1)), I = 1, NNN, NN),
     1   II = 1, NN )                                                   21660   
 223  FORMAT (  / ' DATA ENTERING KEYWORDS ARE:' // ( 6A12 ) )
      GO TO 300
C
 250  ICOL = 4
      IF ( ITSO .EQ. 1 )  ICOL = 3
      NN = (N+ICOL-1)/ICOL
      NNN = ICOL*NN
      IF ( ITSO .EQ. 1 )  GO TO 270
      write (6, 253)
 253  FORMAT ( / ' DATA ENTERING KEYWORDS AND THEIR VALUES ARE:' / )    21670   
      write (6, 263) ( (NAMES(INDEX(II+I-1)), VALUES(INDEX(II+I-1)),
     1  I = 1, NNN, NN), II = 1, NN )
 263  FORMAT (( 1X, 4( A8, 2A8, 8X ) ))                                 cnv
CVA 263  FORMAT (( 1X, 4( A8, A16, 8X ) ))
      GO TO 300
 270  write (6, 253)
      write (6, 273) ( (NAMES(INDEX(II+I-1)), VALUES(INDEX(II+I-1)),
     1  I = 1, NNN, NN), II = 1, NN )
 273  FORMAT ( 1X, 3(A8, 2A8) )                                         cnv
CVA 273  FORMAT ( 1X, 3(A8, A16) )                                      21680   
C
C     NOW GET SWITCH SETTINGS
C
 300  K = 0
      DO 359  I = 1, NUMSWW
         IF ( SWTWRD(I) .EQ. NOMORE )  GO TO 359
         IF ( .NOT. VALSW )  GO TO 350
         IF ( SWITCH(SWTNUM(I)) .NE. SWTSET(I) )  GO TO 359
 350     K = K+1
         NAMES(K) = SWTWRD(I)                                           21690   
 359  CONTINUE
C
      CALL ALSORT ( NAMES, INDEX, K )
      IF ( VALSW )  GO TO 380
      write (6, 373) ( NAMES(INDEX(I)), I = 1, K )
 373  FORMAT ( / ' THE FOLLOWING KEYWORDS MAY BE USED TO ',
     1  'SELECT OPTIONS:' // ( 6A12 ) )
      GO TO 400
 380  write (6, 383) ( NAMES(INDEX(I)), I = 1, K )
 383  FORMAT ( / ' THE FOLLOWING OPTIONS HAVE BEEN CHOSEN:' //          21700   
     1  ( 6A12 ) )
C
C     FINALLY THE CONTROL KEYWORDS
C
 400  IF ( VALSW )  GO TO 800
      K = 0
      DO 409  I = 1, NUMKEY
         IF ( KEYWRD(I) .EQ. NOMORE )  GO TO 409
         K = K + 1
         NAMES(K) = KEYWRD(I)                                           21710   
 409  CONTINUE
      CALL ALSORT ( NAMES, INDEX, K )
      write (6, 433) ( NAMES(INDEX(I)), I = 1, K )
 433  FORMAT ( / ' THE FOLLOWING ARE COMMAND KEYWORDS:' // (6A12) )
C
C     PRINT THE ALIAI
C
      K = 0
      DO 519  I = 1, NUMALI, 2
         K = K+1                                                        21720   
         NAMES(K) = ALIAI(I)
         SYNS(K) = ALIAI(I+1)
 519  CONTINUE
      NAMES(K+1) = BLANK
      NAMES(K+2) = BLANK
      SYNS(K+1) = BLANK
      SYNS(K+2) = BLANK
      INDEX(K+1) = K+1
      INDEX(K+2) = K+2
      CALL ALSORT ( NAMES, INDEX, K )                                   21730   
      NN = (K+2)/3
      NNN = 3*NN
      write (6, 533) ( (NAMES(INDEX(II+I-1)), SYNS(INDEX(II+I-1)),
     1   I = 1, NNN, NN ),  II = 1, NN )
 533  FORMAT ( / ' THE FOLLOWING ARE SYNONUMS FOR STANDARD',
     1    ' PTOLEMY KEYWORDS' //
     2  1X, 3( 'SYNONUM', 3X, 'KEYWORD', 6X ) //
     3  ( 1X, 3( A8, 2X, A8, 5X ) ) )
C
      CALL ALSORT ( SYNS, INDEX, K )                                    21740   
      write (6, 533) ( (NAMES(INDEX(II+I-1)), SYNS(INDEX(II+I-1)),
     1   I = 1, NNN, NN ), II = 1, NN )
C
C
 800  RETURN
C
      END
C*ID* LXTRPM   C109.PTOLEMY.SOURCE                          PER701  15:
      FUNCTION LXTRPM ( IEXTYP, BARA, B, BARC, BARL, DLMAX,
     1  LX, LDEL, ETAS, WEEBOY )                                        21750   
C
C     RETURNS L SUCH THAT  WEEBOY = SQRT(2L) * EXTRAP FUNC(L)
C
C     THE EXTRAPOLATION FUNCTIONS ARE DEFINED IN LXTRP1
C
C     9/24/80 - FIRST VERSION - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
      DIMENSION ETAS(2)
C                                                                       21760   
      DL = DLMAX
      GO TO ( 100, 200, 10, 300 ), IEXTYP
 10   write (6, 13) IEXTYP
 13   FORMAT ( '0*** CANNOT FIND LIMOST FOR FUNCTION TYPE', I3 )
      LXTRPM = 2*DLMAX
      RETURN
C
C     WOODS SAXON
C        WEEBOY = SQRT(2L)*BARA / (1 + EXP(B*(L-FLCRIT)) )
C                                                                       21770   
 100  DL = RTXLNX( B, -.50D0,
     1      DLOG(WEEBOY/BARA) - .5*DLOG(2.0D0) - B*BARL, .010D0 )
         GO TO 900
C
C     POWER LAW
C        WEEBOY = SQRT(2L)*BARA * (DLMAX/L)**B
C
 200  IF ( B .GT. .5 )  DL = DEXP( (DLOG(1.41*DABS(BARA)/WEEBOY)
     1      + B*DLOG(DLMAX) )/(B-.5) )
C                                                                       21780   
C     WKB FORM
C     WEEBOY = SQRT(2L)*BARA*ETA**LX*DLMAX**B
C            * EXP((ETA2-ETA1)/ETA * L) / L**(LX+B)
C
 300  ETA = .5*(ETAS(1)+ETAS(2))
      IF ( LX+B-.5 .GT. 0 )  DL = RTXLNX( (ETAS(2)-ETAS(1))/ETA,
     1    LX+B-.5, DLOG( DABS( WEEBOY/( 1.4142*BARA*ETA**LX ) ) )
     2       - B*DLOG(DLMAX), .010D0 )
C
 900  LXTRPM = DL+.5                                                    21790   
      RETURN
      END
C*ID* LXTRP1   C109.PTOLEMY.SOURCE                          PER701  10:
      SUBROUTINE LXTRP1 ( IEXTYP, N, ISIG, IPRINT, XVALS, SVALS,
     1  FLCRIT, AVAL, WID, STEPIN, DELIN, BARL, BARA, B,
     2  BARC, DLMAX, CHISQ, LX, LDEL, ETAS, MCHN, JP, JT )
C
C     LEAST-SQUARES FIT OF L-EXTRAPOLATING FUNCTIONS
C
C     IEXTYP = 1  MEANS FIT WOODS SAXON OF THE FORM                     21800   
C              S(L) = BARA/(BARC + EXP( B*(L-BARL) ) )
C                   = AVAL/(+-1 + EXP( (L-FLCRIT)/WID ) )
C           = 2  MEANS FIT INVERSE POWER FUNCTION OF THE FORM
C              S(L) = BARA * (DLMAX/L)**B * ( 1 + BARC*(BARL/L) )
C                   = AVAL * (DLMAX/L)**B * ( 1 +- (LCRIT/L) )
C           = 3  MEANS FIT INVERSE POWER LAW OF THE FORM
C              S(L) = BARA + BARC*(DLMAX/L)**B
C              THIS IS USED FOR THE PHASE EXTRAPOLATION
C              NOTE THAT LINTRP REVERSES THE DEFINITIONS SO
C              THAT  CP=BARA,  AP=BARC  BP=B                            21810   
C           = 4  MEANS THE WKB FORM:
C              S(L) = (SIN(ATAN(ETA/L)))**LX
C               * EXP(-(ETA2-ETA1)*(ATAN(ETA/L)+L/ETA))
C               * BARA*(DLMAX/L)**B * (1+BARC*(BARL/L))
C              THIS HAS THE SAME DEPENDANCE ON THE FITTED
C              PARAMETERS AS IEXTYP=2.  HERE
C              ETA = .5*(ETA1+ETA2)   L = (L1+L2)/2
C        IN THE ABOVE THE FIRST LINE IS THE WAY THINGS ARE TO
C        BE COMPUTED AND THE SECOND IS THE WAY THEY ARE TO BE
C        PRINTED.                                                       21820   
C     N    : NO OF S-MATRICES TO FIT
C     ISIG : 0 IF ALLS WELL
C          : NEGATIVE FOR FATAL ERROR - SUPPRESS EXTRAPOLATION
C          : POSITIVE IF EXPONENTIAL RATHER THAN WS FORM USED
C     XVALS: ARRAY OF LENGTH N. INPUT L-VALUES;
C            THESE WILL BE MODIFIED.
C     SVALS:  ARRAY(LENGTH N) OF MAGNITUDES OF S-MATRIX ELEMENTS
C               THESE WILL BE MODIFIED.
C     FLCRIT: R*8 VALUE OF LC PARAMETER IN WOODS-SAXON FUNCTION
C     AVAL : VALUE OF A (NORMALIZATION) PARAMETER                       21830   
C     WID  : VALUE OF WIDTH PARAMETER
C     STEPIN  : WIDTH STEP-SIZE IN FINDING MINIMUM W.R.T. WIDTH
C     DELIN:  STEP SIZE USED TO COMPUTE DERIVATIVES
C
C     BARL, BARA, B, BARC ARE TO BE USED TO COMPUTE THE FUNTION
C           AS DEFINED ABOVE
C     PRESENTLY BARA IS ALWAYS THE SAME AS
C     AVAL, BUT BARC WILL BE 0 FOR THE EXPONENTIAL FORM, AND
C     BARL MAY BE CHOOSEN TO MINIMIZE THE CHANCE OF OVERFLOW.
C                                                                       21840   
C
C     MHM - 9/1/76
C     4/19/77 - AVOID OVERFLOWS BY BIASING L; RETURN BAR STUFF - S.P.
C     7/12/78 - AVOID UNLIKELY LOG(0)
C     6/20/79 - DON'T REDEFINE THE STEP, AND DEL IN ARG LIST - S.P.
C     12/27/79 - CFR%F - RPG
C     1/15/80 - USE BIGNUM, BIGLOG, ADD /CNSTNT/ - RPG
C     4/11/80 - ADD POWER FITS - S.P.
C     5/2/80 - AVOID DIVIDE BY 0 IN PARAB FITS; LEAVE DEL A RATIO - S.P.
C     5/7/80 - IEXTYP=3 ADDED - S.P.                                    21850   
C     9/26/80 - IEXTYP=4 ADDED - S.P.
C     10/6/80 - RELAX BMIN RESTRICTION FOR ELASTIC RE/IM - S.P.
C     6/13/83 - BMIN = .001, NOT = 0 -- CDC PROBLEMS - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
C
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
C
      DIMENSION XVALS(N),SVALS(N), ETAS(2)
C                                                                       21860   
CDC      ALLOCLEVEL XVALS, SVALS
C
      LOGICAL PBUGSW, PLINSW
C
      PBUGSW = IPRINT .GE. 4
      PLINSW = IPRINT .GE. 6
      DEL = DELIN
      STEP = STEPIN
      IXTYP2 = 2*IEXTYP
      IF ( IEXTYP .EQ. 4 )  IXTYP2 = 4                                  21870   
      ISIG=0
      STPMUL=1
      BMIN = .001
      IF ( IEXTYP .EQ. 4 )  BMIN = -LX
C
C
C     BIAS THE L'S TO 0 TO AVOID OVERFLOW PROBLEMS
C
      ETA = .5*(ETAS(1)+ETAS(2))
      XBAR = ( XVALS(1)+XVALS(2) )/2                                    21880   
      IF ( IEXTYP .GE. 2 )  XBAR = DLMAX
C
      DO 99 I=1,N
         GO TO ( 50, 60, 60, 70 ), IEXTYP
  50     XVALS(I) = XVALS(I) - XBAR
         GO TO 99
  60     XVALS(I) = XBAR/XVALS(I)
         GO TO 99
 70      DL = XVALS(I) + .5*LDEL
         SVALS(I) = SVALS(I) / ( (DSIN(DATAN(ETA/DL)))**LX              21890   
     1      * DEXP(-(ETAS(2)-ETAS(1))*(DATAN(ETA/DL)+DL/ETA)) )
         XVALS(I) = XBAR/DL
  99  CONTINUE
C
      IF ( PBUGSW )  write (6, 101) MCHN, JP, JT, LX, LDEL,
     1   IEXTYP, N
 101  FORMAT ( '0EXTRAPOLATION FOR MCHN =', 5I5, 3X,
     1   'IEXTYP =', 5I5 )
      IF ( PLINSW )  write (6, 102) ( I, XVALS(I), SVALS(I), I=1,N )
 102  FORMAT ('0X AND S:' / (I4, 2G17.5 ) )                             21900   
C
C     GET INITIAL GUESS OF THE NON-LINEAR PARAMETER
C     FOR IEXTYP=1 USE EXP. FIT; FOR 2 USE SIMPLE POWER LAW.
C     FOR IEXTYP = 3  WE JUST USE B = 3
C
      CVAL = 1
      IF ( IEXTYP .EQ. 3 )  CVAL = 3
      CALL LINLSQ ( IXTYP2-1, N, XVALS, SVALS, BEXP, AEXP, CVAL, F,
     1   PLINSW )
      IF ( IEXTYP .NE. 3 )  GO TO 105                                   21910   
      CEXP = BEXP
      IXTYP2 = 5
      BEXP = 3
      GO TO 110
C
 105  IF(BEXP .GT. BMIN) GO TO 110
      write (6, 108)BEXP
  108 FORMAT( '0***  INITIAL B = ',G12.6,' (OUT OF BOUNDS)--')
      GO TO 940
C                                                                       21920   
C     EVALUATE CHISQ AND DERIVATIVE AT INITIAL WIDTH
C
  110 IF(PBUGSW) write (6, 120)BEXP
  120 FORMAT( '0B FOR EXP OR POWER FORM = ',G12.6)
      STEP=STEP*DABS(BEXP/10)
      IF ( IEXTYP .EQ. 3 )  STEP = .1
      BMAX = 10*DABS(BEXP)
      IF ( IEXTYP .EQ. 1 )  BMAX = 1.2
C
      X=BEXP                                                            21930   
      CALL LINLSQ ( IXTYP2, N, XVALS, SVALS, C1, A1, X, F, PLINSW )
      CHIEXP = F
C
 130  XPL=X*(1+DEL)
      XMI=X*(1-DEL)
      CALL LINLSQ ( IXTYP2, N, XVALS, SVALS, CVAL, AVAL, XPL, FPL,
     1   PLINSW )
      CALL LINLSQ ( IXTYP2, N, XVALS, SVALS, CVAL, AVAL, XMI, FMI,
     1   PLINSW )
      DF=(FPL-FMI)/(2*X*DEL)                                            21940   
      DTES=DABS(DF/F)
      IF(DTES.GT.1.D-10) GO TO 200
      IF ( DEL .GE. .5 )  GO TO 700
      DEL = 2*DEL
      GO TO 130
  200 S=DABS(STEP)
      IF(DF.GT.0) S =-S
C
C     STEP DOWNHILL TO BOX IN MINIMUM
C                                                                       21950   
      IT=1
      F1=F
      X1=X
 220  X2=X1+S
C
C     A WOODS-SAXON WITH WIDTH LESS THAN 1 DOESN'T MAKE SENSE IN
C     IN THIS CONTEXT
C
      IF ( IEXTYP .EQ. 1  .AND.  X2 .GT. 1.2 )  GO TO 950
      IF ( IEXTYP .GE. 2  .AND.  X2 .LT. BMIN )  GO TO 960              21960   
      IF ( IEXTYP .EQ. 1  .AND.  X2 .LT. BMIN )  GO TO 700
      IF ( IEXTYP .GE. 2  .AND.  X2 .GT. BMAX )  GO TO 700
C
      CALL LINLSQ ( IXTYP2, N, XVALS, SVALS, C, A, X2, F2, PLINSW )
      IF(F2.LE.F1) GO TO 250
C
C     PASSED A MINIMUM; TRY TO GET THREE POINTS WITH F2 THE LEAST
C
      S=.5*S
      X3=X2                                                             21970   
      F3=F2
      X2=X3-S
      CALL LINLSQ ( IXTYP2, N, XVALS, SVALS, C, A, X2, F, PLINSW )
      IF ( F .LT. F1 )  GO TO 240
      X3 = X2
      F3 = F
      X2 = X1
      F2 = F1
      A2 = A1
      C2 = C1                                                           21980   
      X1 = X2-S
      CALL LINLSQ ( IXTYP2, N, XVALS, SVALS, C, A, X1, F1, PLINSW )
      GO TO 300
 240  F2=F
      C2=C
      A2=A
      GO TO 300
C
C     STILL LOOKING FOR THE MINIMUM
C                                                                       21990   
  250 X1=X2
      F1=F2
      A1 = A
      C1 = C
      S=S*STPMUL
      IT=IT+1
      IF(IT.LE.1000) GO TO 220
      write (6, 263)
  263 FORMAT( '0*** MORE THAN 1000 STEPS TO BOX MINIMUM IN B-- ')
      GO TO 700                                                         22000   
C
C     FIND MINIMUM OF FITTED PARABOLA
C
 300  F2P = F1-2*F2+F3
      IF ( F2P .EQ. 0 )  GO TO 310
      SM=(.5*S*(F1-F3))/F2P
      XM=X2+SM
      IF((XM.LE.BMIN).OR.(XM.GT.BMAX)) GO TO 700
      CALL LINLSQ ( IXTYP2, N, XVALS, SVALS, CVAL, AVAL, XM, F, PLINSW )
      IF(F.LE.F2) GO TO 320                                             22010   
 310  XM=X2
      AVAL=A2
      CVAL=C2
      F=F2
  320 B=XM
      CHISQ=F
      GO TO 400
 350  IF ( PBUGSW )  write (6, 353)
  353 FORMAT( '0--- BEST-FIT IS AN EXP OR SIMPLE POWER --')
      GO TO 700                                                         22020   
C
C     USE LOCAL TAYLOR EXPANSION TO REFINE ESTIMATE OF MINIMUM
C
  400 DX=DEL*XM
      FM=F
      XPL=XM+DX
      CALL LINLSQ ( IXTYP2, N, XVALS, SVALS, C, A, XPL, FPL, PLINSW )
      XMI=XM-DX
      CALL LINLSQ ( IXTYP2, N, XVALS, SVALS, C, A, XMI, FMI, PLINSW )
      FP=(FPL-FMI)/(2*DX)                                               22030   
      F2P=(FPL-2*FM+FMI)/DX**2
      IF ( F2P .EQ. 0 )  GO TO 430
      XNEW=XM-FP/F2P
      CALL LINLSQ ( IXTYP2, N, XVALS, SVALS, C, A, XNEW, FM, PLINSW )
      IF(FM.GE.F) GO TO 430
      AVAL=A
      CVAL=C
      B=XNEW
      CHISQ = FM
C                                                                       22040   
  430 TES = CVAL + AVAL
      IF(PBUGSW) write (6, 433)AVAL,CVAL,B,X2,CHISQ
  433 FORMAT( '0-*  (A,C) = (',G12.6,1X,G12.6,')'/
     15X,'(B,B2,CH)=(',G12.6,1X,G12.6,1X,G12.6,')')
      IF ( TES .LE. 0 .AND.  IEXTYP .NE. 3 )  GO TO 350
      IF(PBUGSW) write (6, 443)IT
  443 FORMAT( '0-COMPLETE IN ',I6,' ITERATIONS')
C
      GO TO ( 540, 550, 570, 550 ), IEXTYP
C                                                                       22050   
C     RETURN VALUES FOR WOODS-SAXON
C
 540  BARA = 1/DABS(AVAL)
      WID = 1/B
      BARC = DSIGN( 1.D0, AVAL )
      FLCRIT = XBAR -WID*DLOG(BARA*CVAL)
      BARL = FLCRIT
      AVAL = BARA
      GO TO 800
C                                                                       22060   
C     RETURN VALUES FOR POWER FIT
C
 550  POWER = 1
      WID = B
      IF ( AVAL .LT. 0 )  GO TO 700
      BARA = AVAL
      BARC = 1
      BARL = CVAL*XBAR/AVAL
      FLCRIT = BARL
      GO TO 800                                                         22070   
C
C     VALUES FOR PHASE POWER (IEXTYP=3)
C
 570  BARA = AVAL
      BARC = CVAL
      FLCRIT = CVAL
      WID = B
      GO TO 800
C
C     WID-MINIMUM NOT LOCATED WITHIN BOUNDS                             22080   
C     REVERT TO EXPONENTIAL FORM
C
 700  IF ( IEXTYP .EQ. 3 )  GO TO 730
      BARA = DEXP(AEXP)
      B = BEXP
      CHISQ = CHIEXP
      BARC = 0
      ISIG=5
      IF ( IEXTYP .NE. 1 )  GO TO 720
      BARL = XBAR                                                       22090   
      AVAL = BARA
      WID = 1/BEXP
      FLCRIT = BARL
      GO TO 800
 720  WID = BEXP
      FLCRIT = 0
      BARL = 0
      AVAL = BARA
      GO TO 800
 730  AVAL = AEXP                                                       22100   
      CVAL = CEXP
      B = BEXP
      GO TO 570
C
C     MAKE A FINAL TEST OF THE CORRECTNESS OF EVERYTHING
C
 800  IF ( B .GT. BMIN )  GO TO 810
      write (6, 803) B, BARA, BARC, BARL
 803  FORMAT ( '0*** ERROR IN EXTRAP: B OUT OF BOUNDS:', 4G15.5 )
      GO TO 940                                                         22110   
C
 810  IF ( PBUGSW )  write (6, 813) IEXTYP, BARA, B, BARC, BARL, AVAL,
     1  WID, CVAL, FLCRIT, CHISQ
 813  FORMAT ( '0LXTRP1 END', I3, 9G13.5 / )
C
C     CHECK FOR SLOWLY DECAYING EXTRAPOLATION
C
      IF ( MCHN .EQ. 1 )  GO TO 900
      GO TO ( 820, 830, 900, 830 ), IEXTYP
 820  IF ( B .GT. .01 )  GO TO 900                                      22120   
      GO TO 890
 830  IF ( B .GT. BMIN+.6 )  GO TO 900
      GO TO 890
 890  write (6, 893) AVAL, B, CVAL, FLCRIT
 893  FORMAT ( '0*** WARNING:  EXTRAPOLATION DECAYS VERY SLOWLY;',
     1  '  A, B, C, LCRIT = ', 4G15.5 )
      write (6, 958) MCHN, JP, JT, LX, LDEL
C
 900  RETURN
C                                                                       22130   
C     ONE-PARAMETER MINIMIZATION W.R.T. WIDTH HAS FAILED
C     ERROR RETURN ; SUPPRESS EXTRAPOLATION
C
  940 write (6, 943)
  943 FORMAT( '0*** MINIMIZATION W.R.T. WIDTH HAS FAILED '/
     17X,'EXTRAPOLATION MUST BE SUPPRESSED --')
      ISIG=-5
      RETURN
C
 950  write (6, 953)                                                    22140   
 953  FORMAT ( '0**** ATTEMPTING TO FIT VERY SHARP WOODS-SAXON -',
     1  ' ATTEMPT ABANDONED' )
 955  write (6, 958) MCHN, JP, JT, LX, LDEL
 958  FORMAT ( 6X, 'FOR CHANNEL', I3,
     1  ', JP, JT, LX, LO-LI =', 2(I3, '/2'), 2I4 )
      GO TO 700
C
 960  write (6, 963)
 963  FORMAT ( '0*** ATTEMPTING TO FIT WITH POWER OF 0 --',
     1   ' DEFAULT STARTING VALUE USED.' )                              22150   
      GO TO 955
      END
C*ID* LXTRP2   C109.PTOLEMY.SOURCE                          PER701  15:
      SUBROUTINE LXTRP2 ( IEXTYP, BARA, B, BARC, BARL, DLMAX, LI,
     1   SIZE, LX, LDEL, ETAS )
C
C     COMPUTES THE LEXTRAPOLATION FUNCTIONS
C
C     SEE  LXTRP1 FOR THE PARAMETERS.
C     EXCEPT NOTE THAT FOR IEXTYP=3, BARA AND BARC HAVE BEEN            22160   
C     REVERSED.
C     SIZE IS SET TO THE COMPUTED VALUE AT LI.
C
C     4/12/80 - FIRST VERSION - S.P.
C     5/7/80 - IEXTYP=3 - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
      DIMENSION ETAS(2)
C
      DLI = LI                                                          22170   
C
      GO TO ( 110, 120, 130, 140 ), IEXTYP
C
 110  X = B*(DLI-BARL)
      IF ( X .LT. -46 )  X = -46
      SIZE = BARA / (BARC+DEXP(X))
      RETURN
C
 120  SIZE = BARA * (DLMAX/DLI)**B * (1+BARL/DLI)
      RETURN                                                            22180   
C
 130  SIZE = BARC + BARA*(DLMAX/DLI)**B
      RETURN
C
 140  ETA = .5*(ETAS(1)+ETAS(2))
      DLI = DLI + .5*LDEL
      SIZE = BARA * (DLMAX/DLI)**B * (1+BARL/DLI)
      SIZE = SIZE * (DSIN(DATAN(ETA/DLI)))**LX
     1   * DEXP(-(ETAS(2)-ETAS(1)) * ( DATAN(ETA/DLI) + DLI/ETA ) )
      RETURN                                                            22190   
C
      END
C*ID* MAKDER   C109.PTOLEMY.SOURCE                          PER701  15:
      SUBROUTINE MAKDER ( NSTEPS, NUMVS, MXVSIN, MPARA,
     1  PARAM, DERSTP, VDERIV, ITYPE, VR, VI, DELVR, DELVI )
C
C     COMPUTES DERIVATIVES OF V AS A FUNCTION OF R.
C
C     *************************************************************
C     *   WILL NEED CHANGES FOR SPIN-ORBIT FORCE                  *     22200   
C     *************************************************************
C
C     STORES THE QUANTITIES
C
C     VDERIV(K,N) = (8) / (STEPSZ ) W(N) D(V(R(N)))/D(X(K))
C
C     FOR
C        N = 1, ..., NSTEPS
C        K = 1, NUMVS
C                                                                       22210   
C     ONLY THE NON-ZERO REAL AND IMAGINARY PARTS OF THE DERIVATIVE
C     ARE STORED.  PARAMETERS THAT RESULT IN A COMPLETELY COMPLEX
C     DERIVATIVE GET TWO ADJACENT K'S.
C
C     PARAM - THE PARAMETER VECTOR (X) FORWHICH DV/DX IS DESIRED.
C     VR & VI - THE POTENTIAL EVALUATED AT X.
C     DELVR & DELVI - WORK ARRAYS
C
C     10/29/75 - FIRST VERSION - S.P.
C     3/10/76 - LIMIT RANGE OF DERIVATIVES USED                         22220   
C     4/21/77 - RENORM AND LABSHIFT CAN BE FIT
C     11/20/77 - NEW SETFIT CALL - S.P.
C     2/14/78 - NUMERICAL DERIVATIVES
C     5/31/78 - DO NOT TRIM OFF DERIVATIVES SO MUCH - S.P.
C     12/28/79 - CFR%F - RPG
C
C
      implicit real*8 ( a-h, o-z )                                      implicit
CDC      ALLOCLEVEL PARAM,VDERIV,ITYPE,VR,VI,DELVR,DELVI
C                                                                       22230   
      DIMENSION  PARAM(MPARA), VDERIV(MXVSIN, NSTEPS), ITYPE(MPARA),
     1  VR(NSTEPS), VI(NSTEPS), DELVR(NSTEPS), DELVI(NSTEPS)
C
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
      COMMON /LOCFIT/ IDATA, LPL, LSIGMA, LSMAT, IESETS, IMASK,         /locfit/
     &   IEQUAL, NPARA, IPARA, ITEMP, LSCSIG, LEPARM, LFS, NPTS, LEQNAM,
     &   MAXEQL, MAXVS, LVDERV, LSDELS, LDVTYP, LDSDP, LDFDX, LFGRAD,
     &   LTGRAD, LMASK, LEQUAL, MNDRIV, MXDRIV, IESIZE, LENPRE,
     &   LENKEY, LENHED,  ILNKBL
 
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
      COMMON /KANDM/ AKI, AKO, REDMI, REDMO, RIMAX, ROMAX, ISIGS(2),    /kandm/
     &  RSCTS(2), ASCTS(2), RCSCTS(2) ,ISMATS(2), LOMOST, LCRIT,
     &  ISCTMN, ISCTCR, ETAS(2), RCSCTP(2), RCSCTT(2), LCRITS(2),
     &  RATMSS(2), QMIN, ABAR
 
      DIMENSION  AKS(2), REDMS(2), RMAXS(2)
      EQUIVALENCE ( AKI, AKS(1) ), ( REDMI, REDMS(1) ),
     &  ( RIMAX, RMAXS(1) )
 
C
C     FOOL MAKPOT INTO STORING INTO DELVR, DELVI
C                                                                       22240   
      IRLVS(2) = IRLVS(1)
      IRLVS(1) = IWAVR
      IIMVS(2) = IIMVS(1)
      IIMVS(1) = IWAVI
C
C     LOOP OVER THE PARAMETERS.  FOR EACH ONE, PERTURB IT AND
C     RECALCULATE V.  DERIVATIVES ARE THEN FOUND BY DIFFERENCES.
C
      MNDRIV = NSTEPS
      MXDRIV = 0                                                        22250   
      K = 1
      DO 489  I = 1, MPARA
         KEY = ITYPE(I)
         IF ( KEY .EQ. 0  .OR.  KEY .GE. 4 )  GO TO 489
         PSAVE = PARAM(I)
         STEP = DERSTP*PSAVE
         IF ( PSAVE .EQ. 0 )  STEP = DERSTP
         PARAM(I) = PSAVE + STEP
         CALL SETFIT ( PARAM, IRET, 1 )
         FAC = 8 / ( HS(1) * STEP )                                     22260   
C
C     WE USE SIMPSONS WEIGHTS BUT DO NOT BOTHER ABOUT MAKING THE
C     FIRST AND LAST POINT CORRECT SINCE THEY DON'T MATTER (
C     (EITHER U(0) = 0  OR  D(V(RMAX)) = 0).
C
         WT = 2
         IGO = KEY - 2
         DRIVMX = 0
         DO 389  N = 2, NSTEPS
            IF ( IGO )  320, 330, 340                                   22270   
 320        VDERIV(K,N) = WT*FAC*( DELVR(N)-VR(N) )
            GO TO 380
 330        VDERIV(K,N) = WT*FAC*( DELVI(N)-VI(N) )
            GO TO 380
 340        VDERIV(K,N) = WT*FAC*( DELVR(N)-VR(N) )
            VDERIV(K+1,N) = WT*FAC*( DELVI(N)-VI(N) )
C
 380        WT = 6 - WT
            DRIVMX = DMAX1( DABS(VDERIV(K,N)), DRIVMX )
 389     CONTINUE                                                       22280   
C
C     NOW LIMIT THE DERIVATIVES TO THOSE THAT EXCEED
C     DERSTP TIMES THE MAXIMUM ONE OR JUST DERSTP.
C
      TESTMN = DMIN1( DERSTP*DRIVMX, DERSTP )
         DO 459  N = 2, NSTEPS
            TEST = DABS(VDERIV(K,N))
            IF ( IGO .GT. 0 )  TEST = DMAX1( TEST, DABS(VDERIV(K+1,N)) )
            IF ( TEST .GT. TESTMN )  GO TO 450
            VDERIV(K,N) = 0                                             22290   
            IF ( IGO .GT. 0 )  VDERIV(K+1,N) = 0
            GO TO 459
 450        MNDRIV = MIN0( MNDRIV, N )
            MXDRIV = MAX0( MXDRIV, N )
 459     CONTINUE
C
C     GO TO NEXT K
C
         K = K+1
         IF ( IGO .GT. 0 )  K = K+1                                     22300   
C
         PARAM(I) = PSAVE
 489  CONTINUE
C
C     THE PARAMETER VECTOR IS NOW BACK TO ITS ORIGINAL STATUS.
C     RESTORE THE COMMON BLOCKS
C
      IRLVS(1) = IRLVS(2)
      IIMVS(1) = IIMVS(2)
      CALL SETFIT ( PARAM, IRET, 0 )                                    22310   
C
      NUMVS = K - 1
C
      RETURN
      END
C*ID* MAKPOT   C109.PTOLEMY.SOURCE                          PER701  09:
      SUBROUTINE  MAKPOT ( NWPIN, IRET )
C
C     COMPUTES THE POTENTIALS FOR WAVELJ
C                                                                       22320   
C     WAVSET MUST BE CALLED FIRST TO INITIALIZE THINGS.
C
C     THIS ROUTINE SETS UP THE REAL AND IMAGINARY "POTENTIAL"
C     ARRAYS IN THE FORM REQUIRED BY WAVELJ:
C
C       V' = 1 - (H**2/12) * (V/E - 1)
C
C     THE S.O. TERMS ARE STORED SEPARATELY AS
C
C       VSO' = (H**2/12) * VSO/(E*S.L)                                  22330   
C     WHERE
C       S.L IS  S DOT L
C
C     10/7/75 - MADE FROM WAVELJ - S.P.
C     10/27/75 - AVOID UNDERFLOWS FOR LARGE  R/A
C     1/28/77 - DO NOT STORE VERY SMALL POTENTIALS
C     2/3/77 - RESTART FLAG FOR WAVELJ
C     3/18/77 - FIX S.O. BUG INTRODUCED IN ABOVE CHANGE.
C     10/16/77 - POWERS OF WOODS-SAXONS
C     11/21/77 - MAJOR REWRITE TO USE WOODSX SUBROUTINE - S.P.          22340   
C     11/25/77 - LINKULES
C     11/29/77 - ADD RETURN CODE
C     5/5/78 - CENTRIFIGAL TERM IN ALLOCATOR - S.P.
C     6/24/78 - USE LOCAL VARIABLE IN VCSQ12 CALL FOR CDC LCM VERSION
C     12/12/78 - ADD TENSOR POTENTIALS - RPG
C     3/1/79 - INITIALIZE LASTZR, NOW IN /WAVCOM/ - RPG
C     12/28/79 - CFR%F - RPG
C     5/2/80 MODIFY V' FOR COUPLED CHANNELS . STORE AS
C            1-H**2/12*V/E FOR EXCITED CHANNELS MRB
C     12/9/80 - IF NWPIN=3; NO COULOMB FORCE - S.P.                     22350   
C     7/16/81 - FOR NWPIN=3 ALSO COMPUTE -V, NOT 1-V - S.P.
C     5/17/82 - INCLUDE VSI WHEN LINKULE COMPUTES VI - S.P.
C     12/19/84 - VSI MAY BE DONE BY LINKULE - S.P.
C     5/10/85 - CALL SETINT FOR CRAY
C     10/28/85 - GIVE SETINT LOTS OF SURPLUS
C
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
      COMMON /KANDM/ AKI, AKO, REDMI, REDMO, RIMAX, ROMAX, ISIGS(2),    /kandm/
     &  RSCTS(2), ASCTS(2), RCSCTS(2) ,ISMATS(2), LOMOST, LCRIT,
     &  ISCTMN, ISCTCR, ETAS(2), RCSCTP(2), RCSCTT(2), LCRITS(2),
     &  RATMSS(2), QMIN, ABAR
 
      DIMENSION  AKS(2), REDMS(2), RMAXS(2)
      EQUIVALENCE ( AKI, AKS(1) ), ( REDMI, REDMS(1) ),
     &  ( RIMAX, RMAXS(1) )
 
      COMMON / TEMPVS /  TVR, TVI, TVSOR, TVSOI, TAR, TAI               /tempvs/
 
c                                                                       /lnkblk/
c  STRUCTURE OF   /LNKBLK/
c
c  THERE IS A BLOCK OF 3 DOUBLE WORDS FOR EACH POSSIBLE USE
c  OF A LINKULE.  THE NUMLNK = NUMLINKULES USES ARE IN THE ORDER
c    REALPOTEN  IMAGPOTEN  REALVSO  IMAGVSO  COULOMB
c    WAVEFUNCTION  AND 6 TENSOR POTENTIALS
c  THE THREE-DOUBLE-WORD BLOCKS EACH HAVE THE STRUCTURE
c
c    LNKNAM(1,I)   LINKULE NAME
c
c      LNKADR(3,I)   LINKULE ADDRESS, O IF NO LINKULE IN USE.
c      LNKADR(4,I)   0 - NO L OR J DEPENDENCE IN POTENTIAL
c                    1 - L DEPENDENCE BUT NO J DEPENDENCE
c                    2 - BOTH L  AND J DEPENDENCE
c
c      LNKADR(5&6,I)  MYINTS - A TWO-ELEMENT ARRAY THAT THE
c                     LINKULE MAY USE FOR COMMUNICATION BETWEEN
c                     CALLS TO ITSELF.
c
      parameter ( NUMLINKULES = 13 )
      COMMON /LNKBLK/  NUMLNK, IUNIQU, LNKADR(6,NUMLINKULES)
      character*8  LNKNAM(3,NUMLINKULES)
      EQUIVALENCE ( LNKNAM(1,1), LNKADR(1,1) )
 
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
CRA>/INELCM/
C     ITYPE HAS SHAPE CODES FOR TENSOR POTENTIALS (SEE WOODSX).
      INTEGER ITYPS(6) / 4, 5, 2, 2, 1, 3 /
      DATA IDUMMY, DUMMY / 0, 0. /
C                                                                       22370   
c
C
C     SETUP THE PARAMETERS FOR THIS CHANNEL
C
      NWP = NWPIN
      IF ( NWPIN .EQ. 3 )  NWP = 1
      IRET = 0
      STEPSZ = RSTEPS(NWP)
      EINV=1/E
      H = HS(NWP)                                                       22380   
      H2 = H**2
CRAC
CRAC      DEFORMED POTENTIALS WILL USE PLMSUB SO SETUP ITS TABLES
CRAC      JUST IN CASE.
CRAC
CRA      CALL SETINT ( 2*LXMAX+20 )
      NSTEPP = NSTPSS(NWP) + 1
      LREALV = Z(IRLVS(NWP)) - 1
      LIMAGV = Z(IIMVS(NWP)) - 1
      LCENTR = Z(ICENTR(NWP)) - 1                                       22390   
      LVWORK = Z(IVWORK) - 1
C
      RVAL = -STEPSZ
C
C     INDICATE THAT WAVELJ MUST REESTABLISH ITS STARTING POINT
C
      LASTL(NWP) = 999999
      LASTZR = 1
C
C     GET THE COULOMB POTENTIAL                                         22400   
C
      I = 5
      LL = LREALV+1
      IF ( LNKADR(3,5) .GT. 0  .AND.  NWPIN .NE. 3 )  GO TO 800
      X = 0
      DO 249  I = 1, NSTEPP
C
C     IN THIS LOOP WE HAVE
C        R = STEPSZ * (I-1)
C     WHICH IS H GREATER THAN IN WAVELJ.                                22410   
C
C
C
         RVAL = RVAL + STEPSZ
C
C     WE USE X BELOW TO HAVE AN SCM VARIABLE IN THE CDC LCM VERSION.
C
         IF ( NWPIN .NE. 3 )
     1      CALL VCSQ12 ( RVAL, X, NWP )
         ALLOC(LREALV+I) = X                                            22420   
 249  CONTINUE
C
C     GET THE REAL POTENTIAL
C
 300  I = 1
      LL = LVWORK+1
      IF ( LNKADR(3,1) .NE. 0 )  GO TO 800
C
      CALL WOODSX ( NSTEPP, 0.D0, STEPSZ, ALLOC(LVWORK+1), N1, N2,
     1  1, TVR, R, TAR, POWRL )                                         22430   
C
C     STORE COULOMB + REAL POTENTIAL
C
 400  RHO = 1.D-20
C     MODIFY FOR COUPLED CHANNELS
      AJ=1.0D0
      IF ( PROBLM .EQ. 24  .OR. NWPIN .EQ. 3 ) AJ = 0.
      TEMP = 1
      IF ( NWPIN .EQ. 3 )  TEMP = 0
      DO 489 I = 1, NSTEPP                                              22440   
         AK1 = EINV * (ALLOC(LREALV+I)+ALLOC(LVWORK+I)) - AJ
         ALLOC(LREALV+I) = TEMP - AK1*(H2/12)
         ALLOC(LCENTR+I) = -(H2/12)/RHO**2
         RHO = RHO + H
 489  CONTINUE
C
C     NOW GENERATE THE REST OF THE POTENTIALS
C
C     IMAG POTENTIAL IS SUM OF VI AND VSI
C                                                                       22450   
      I = 2
      IF ( LNKADR(3,2) .NE. 0 )  GO TO 800
      CALL WOODSX ( NSTEPP, 0.D0, STEPSZ, ALLOC(LVWORK+1), N1, N2,
     1  1, TVI, RI, TAI, POWIM )
 510  DO 529  I = 1, NSTEPP
         ALLOC(I+LIMAGV) = -(H2/(12*E)) * ALLOC(I+LVWORK)
 529  CONTINUE
C
      IF ( VSI .EQ. 0  )  GO TO 600
      I = 13                                                            22460   
      IF ( LNKADR(3,13) .NE. 0 )  GO TO 800
      CALL WOODSX ( NSTEPP, 0.D0, STEPSZ, ALLOC(LVWORK+1), N1, N2,
     1  3, VSI, RSI, ASI, 1.D0 )
 540  DO 549  I = 1, NSTEPP
         ALLOC(I+LIMAGV) = ALLOC(I+LIMAGV) - (H2/(12*E))*ALLOC(I+LVWORK)
 549  CONTINUE
C
C     NOW POSSIBLE S.O. FORCES
C
 600  IF ( ISORS(NWP) .EQ. 0 )  GO TO 650                               22470   
      LSOR = Z(ISORS(NWP))-1
      I = 3
      IF ( LNKADR(3,3) .NE. 0 )   GO TO 800
      CALL WOODSX ( NSTEPP, 0.D0, STEPSZ, ALLOC(LVWORK+1), N1, N2,
     1  2, VSO, RSO, ASO, 1.D0 )
 610  DO 629  I = 1, NSTEPP
         ALLOC(LSOR+I) = (-H2/(12*E))*ALLOC(LVWORK+I)
 629  CONTINUE
C
 650  IF ( ISOIS(NWP) .EQ. 0 )  GO TO 700                               22480   
      LSOI = Z(ISOIS(NWP))-1
      I = 4
      IF ( LNKADR(3,4) .NE. 0 )  GO TO 800
      CALL WOODSX ( NSTEPP, 0.D0, STEPSZ, ALLOC(LVWORK+1), N1, N2,
     1  2, VSOI, RSOI, ASOI, 1.D0 )
 660  DO 679  I = 1, NSTEPP
         ALLOC(LSOI+I) = (-H2/(12*E))*ALLOC(LVWORK+I)
 679  CONTINUE
C
C     NOW POSSIBLE TENSOR FORCES.                                       22490   
C
 700  DO 749 II = 1, 6
         IF ( ITENS(NWP,II) .EQ. 0 ) GO TO 749
         LTEN = Z(ITENS(NWP,II)) - 1
         I = II + 6
         IF ( LNKADR(3,I) .NE. 0 ) GO TO 800
         CALL WOODSX ( NSTEPP, 0.D0, STEPSZ, ALLOC(LVWORK+1),
     1      N1, N2, ITYPS(II), VTEN(II), RTEN(II), ATEN(II), 1.D0 )
 710     DO 729 I = 1, NSTEPP
            ALLOC(LTEN+I) = (-H2/(12*E))*ALLOC(LVWORK+I)                22500   
 729     CONTINUE
C        DIVIDE TPD POTENTIALS BY R**2
         IF ( II .LT. 5 ) GO TO 749
         RVAL = 1.D-30
         DO 739 I = 1, NSTEPP
            ALLOC(LTEN+I) = ALLOC(LTEN+I) / (RVAL*RVAL)
            RVAL = RVAL + STEPSZ
 739     CONTINUE
 749  CONTINUE
      RETURN                                                            22510   
C
C     GET THE POTENTIAL FROM A LINKULE
C
 800  CALL LINKUL ( LNKADR(3,I), LNKNAM(1,I), LNKADR(5,I),
     1  I, 3, IRET, IDUMMY, IDUMMY,
     2  0.D0, STEPSZ, NSTEPP, ALLOC(LL), DUMMY, 0 )
C
      IF ( IRET .LT. 0 )  GO TO 900
      GO TO ( 400, 510, 610, 660, 300, 710, 710, 710, 710, 710, 710,
     1  710, 540 ), I                                                   22520   
C
 900  RETURN
      END
C*ID* MEBDEF   C109.PTOLEMY.SOURCE                          PER701  14:
      SUBROUTINE  MEBDEF ( IORD, I12, IBN, XNS, IBC, XCS,
     1  MEORD, LXX2, LXX2S, IZ, RNUC, RC, DELTAE,
     1  J2, J1, K2, K1, RMENUC, RMECOU, IRTN, IPT )
C
C     DEFORMED ROTATIONAL REDUCED MATRIX ELEMENT TO AND FROM BETA
C                                                                       22530   
C     THIS SUBROUTINE CONTAINS THE MODEL DEPENDANT PARTS OF
C     BEBETA FOR THE FULL DEFORMED ROTATIONAL MODEL.
C
C     IT ALLOWS  K2=K1  OR  K2=0  OR  K1=0, HOWEVER FOR
C     K2=K1^=0, THE K --> -K TRANSISITION IS IGNORED.
C
C     IF A BETA NUCLEAR IS SUPPLIED AND A CORRESPONDING DEFORMATION
C     IS DEFINED IN THE BETAS ARRAY, THE NUCLEAR RME IS SCALED BY
C     THE RATIO BETA(INPUT)/BETA(DEFORMATION).  THIS IS ALSO DONE
C     IF BETA NUCLEAR IS FOUND FROM BETA COULOMB.  IF THERE IS NO       22540   
C     CORRESPONDING BETA IN THE BETA ARRAY, THE SUPPLED BETA IS IGNORED
C     UNLESS IT IS ZERO.
C
C
C     IORD - THE ORDER OF THE RME TO PRODUCE.  IT MUST BE 1.
C     I12 - ELEMENT OF XNS AND XCS ARRAYS TO USE.
C     IBN - TYPE OF INPUT IN XNS:
C           1 = BETA
C           2 = <||ALPHA||>
C           -99 = UNKNOWN, TO BE FOUND FROM COULOMB RESULT BY           22550   
C                 EQUAL DEFORMATION LENGTHS.
C     XNS - THE INPUT NUCLEAR QUANTITY.  FOR ALL 1ST ORDER AND
C           2ND ORDER ALPHAS, THERE IS ONLY XNS(I12).  FOR 2ND ORDER
C           BETAS THERE IS BOTH XNS(1) AND XNS(2).
C           FOR 1ST ORDER IT IS CONVERTED TO BETA.
C     IBC - TYPE OF INPUT IN XCS:
C        1 - INPUT IS BETA
C        2 - INPUT IS <J2,K2||ALPHA||J1,K1>
C        3 - INPUT IS <J2,K2||E(LX)||J1,K1>  IN  E BARN**LX/2
C        4 - INPUT IS <LX,0||E(LX)||0,0>   IN  E BARN**LX/2             22560   
C       -99 - NOT DEFINED, HAPPENS ONLY IF IBN=IBC=-99
C     XCS - THE INPUT COULOMB QUANTITIES; SEE XNS.
C     MEORD - IGNORED
C                ELEMENT OF E(LX) AND BETA.
C             =1 MEANS USE SECOND ORDER RELATION.
C     LXX2 - 2*MULTIPOLE
C     LXX2S - IGNORED
C     IZ - (INTEGER)  THE ATOMIC NUMBER.
C     RNUC - THE NUCLEAR RADIUS
C     RC - COULOMB RADIUS OF THE NUCLEUS                                22570   
C     DELTAE - DIFFERENCE IN ENERGY OF THE TWO STATES (>0)
C     J2 - 2*SPIN OF THE HIGHER STATE.
C     J1 - 2*SPIN OF THE LOWER STATE
C     K2, K1 - 2*(K-QUANTUM NUMBERS)
C     RMENUC - SET TO <||ALPHA||>
C     RMECOU - IS SET TO THE COMPUTED R.M.E.
C              <J2,K2||R.M.E.||J1,K1>   IN E BARN**LX/2
C     IRTN - SET TO 0 IF ALL O.K., 1 IF NOT
C     IPT = 1 FOR PROJECTILE, 2 FOR TARGET
C                                                                       22580   
C     8/28/81 - MEBDEF BASED ON MEBROT - S.P.
C     9/22/81 - FIX ERROR FOR UNDEFINED BETAN - S.P.
C     10/19/81 - LOOK FOR BETAP OR BETAT - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
C
      DIMENSION  XCS(2), XNS(2), LXX2S(2)
      DIMENSION  CLEBS(20)
      CHARACTER*8  BETNAM(2) / 'BETAP', 'BETAT' /
C                                                                       22590   
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      COMMON /LENGTH/  LENG(1)
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
C
C
      IRTN = 0
C
C     CANNOT PROCEED IF IORD ^= 1                                       22600   
C
      IF ( IORD .NE. 1 )  GO TO 900
C
      LX = LXX2/2
      TJ1P1 = J1+1
C
C     COEFFICENTS FOR RME TO BETA.  THESE ARE BASED ON THE ROTATIONAL
C     MODEL
C     AME1 CONVERTS < ||ALPHA(COULOMB)|| >  TO < ||E(LX)|| >  IN
C     SHARP CUTOFF MODEL.                                               22610   
C
      AME1 = 3*IZ*(RC/10)**LX / (4*PI)
C
C     AME2 CONVERTS BETA(EFFECTIVE) TO < ||ALPHA(COULOMB)|| >
C
      AME2 = CLEBSH( J1, LXX2, K1, K2-K1, J2, K2 )  * DSQRT(TJ1P1)
      IF ( K1 .EQ. K2 )  GO TO 50
      IF ( K2 .NE. 0  .AND.  K1 .NE. 0 )  GO TO 920
      AME2 = DSQRT(2.D0)*AME2
 50   IF ( AME2 .EQ. 0 )  GO TO 900                                     22620   
      AMEUSE = AME1*AME2
      AME2X = AME2
C
      IF ( IBC .EQ. -99 )  GO TO 190
C
C     GET THE POWER SERIES COEFS THAT RELATE BETA TO BETA(EFFECTIVE)
C     FOR THE LONG-RANGE PART OF THE COULOMB INTERACTION
C
C     BETA(EFFECTIVE) = BETA + X2*BETA**2 + X3*BETA**3
C                                                                       22630   
      IZERO = 0
      X3 = 0
C
C     IN THE FOLLOWING LOOP   L = 1/2 LAMBDA
C
      DO 69  L = IZERO, LX
         CLEBS(L+1) = CLEBSH( LXX2, LXX2, 0, 0, 4*L, 0 )
         X3 = X3 + CLEBS(L+1)**4/(4*L+1)
 69   CONTINUE
C                                                                       22640   
      X2 = 0
      IF (.NOT. btest(LX, 0) )
     1  X2 = .50D0 * (LX+2) * SQRT( (LXX2+1)/(4*PI) ) *
     2       CLEBS(LX/2+1)**2
      X3 = (LX+2)*(LX+1)*(LXX2+1)**2/(24*PI) * X3
C
      XC = XCS(I12)
C
C     NOW GET THE BETA COULOMB IF NECESSARY
C                                                                       22650   
C
      GO TO ( 200, 110, 150, 130 ), IBC
      GO TO 930
C
C     <|| ALPHA ||>  GET BETA EFFECTIVE
C
 110  XC = XC/AME2
      GO TO 160
C
C     <LX,0||R.M.E.||0>                                                 22660   
C
 130  AME2X = 1
C
C     <J2,K2||R.M.E.||J1,K1>   GET BETA EFFECTIVE
C
 150  XC = XC/(AME1*AME2X)
C
C     NOW GET BETA FROM BETA(EFFECTIVE) BY THREE ITERATIONS
C     OF NEWTON-RHAPSON.
C     XC HAS THE DESIRED BETA(EFFECTIVE)                                22670   
C
 160  BETA = XC
      DO 169  I = 1, 3
         A = 1+BETA*(2*X2 + 3*X3*BETA)
         BETA = BETA + (XC - BETA*(1 + BETA*(X2 + BETA*X3)) )/A
 169  CONTINUE
      XC = BETA
      GO TO 200
C
C     NOTHING ABOUT COULOMB DEFINED; USE ZERO                           22680   
C
 190  XC = 0
      XCS(I12) = 0
      RMECOU = 0
      GO TO 210
C
C     BETA IS IN XC; GET EVERYTHING FROM IT.
C
C     FIRST THE R.M.E.
C                                                                       22690   
 200  XCS(I12) = XC
      RMECOU = AMEUSE * XC * ( 1 + XC*(X2 + XC*X3) )
C
C     ADVANCE TO NUCLEAR FIRST ORDER
C
 210  XN = XNS(I12)
      BETDEF = 0
      IF ( IBN .NE. -99  .AND.  XN .EQ. 0 )  GO TO 300
C
C     LOCATE THE DEFINITIONS                                            22700   
C
      L1 = IPARM4
      IF ( L1 .EQ. NOTDEF )  L1 = 2
      IBETA = NAMLOC( BETNAM(IPT) )
      IF ( IBETA .EQ. 0 )  GO TO 910
      L2 = LX-L1+1
      IF ( L2 .LE. LENG(IBETA)  .AND.  L2 .GE. 1 )
     1  BETDEF = ALLOC(Z(IBETA)-1+L2)
C
      IF ( IBN .EQ. -99 )  GO TO 260                                    22710   
      GO TO ( 300, 250 ), IBN
      GO TO 930
C
C     <||ALPHA|>>
C
 250  XN = XN/AME2
      GO TO 300
C
C     GET NUCLEAR FROM COULOMB IF POSSIBLE
C                                                                       22720   
 260  IF ( IBC .EQ. -99 )  GO TO 270
      XN = RC/RNUC * XC
      GO TO 300
C
C     NUCLEAR BETA IS NOT DEFINED;  USE DEFORMED VALUE IF POSSIBLE
C
 270  XNS(I12) = BETDEF
      RMENUC = 1
      GO TO 310
C                                                                       22730   
C     XN IS NOW BETAN  OR 0 IF IT COULD NOT BE FOUND
C
 300  XNS(I12) = XN
      RMENUC = 1
      IF ( BETDEF .NE. 0 )  RMENUC = XN/BETDEF
      IF ( XN .EQ. 0 )  RMENUC = 0
 310  RMENUC = AME2*RMENUC
      RETURN
C
 900  RMECOU = 0                                                        22740   
      RMENUC = 0
      RETURN
C
 910  write (6, 913) BETNAM(IPT)
 913  FORMAT ( '0*** "', A5, '" MUST BE DEFINED FOR DEFORMED MODEL' )
      GO TO 925
C
 920  write (6, 923) K1, K2
 923  FORMAT ( '0*** PRESENT ROTATIONAL MODEL DOES NOT WORK',
     1  ' FOR K1, K2 =', 2(I4, '/2') )                                  22750   
 925  IRTN = 1
      GO TO 900
C
 930  write (6, 933) IBC, IBN
 933  FORMAT ( '0*** INVALID IBC OR IBN IN MEBDEF*', 2I12 )
      GO TO 925
C
      END
C*ID* MEBROT   C109.PTOLEMY.SOURCE                          PER701  10:
      SUBROUTINE  MEBROT ( IORD, I12, IBN, XNS, IBC, XCS,               22760   
     1  MEORD, LXX2, LXX2S, IZ, RNUC, RC, DELTAE,
     1  J2, J1, K2, K1, RMENUC, RMECOU, IRTN )
C
C     CONVERTS ROTATIONAL REDUCED MATRIX ELEMENT TO AND FROM BETA
C
C     THIS SUBROUTINE CONTAINS THE MODEL DEPENDANT PARTS OF
C     BEBETA FOR THE ROTATIONAL MODEL.
C
C     IT ALLOWS  K2=K1  OR  K2=0  OR  K1=0, HOWEVER FOR
C     K2=K1^=0, THE K --> -K TRANSISITION IS IGNORED.                   22770   
C
C
C     FOR SECOND ORDER, WE ASSUME THAT ALL OF THE DELTA K
C     IS IN THE FIRST STEP:
C        (LX1, K2-K1) + (LX2, 0) = (LX, K2-K1)
C
C     IORD - THE ORDER OF THE RME TO PRODUCE.  IF 2 IT IS ALSO
C           THE ORDER OF THE INPUT RME(E) OR RME(ALPHA).  IF 1,
C           MEORD INDICATES THE ORDER OF RME(E), BUT 1ST ORDER IS
C           ALWAYS PRODUCED.                                            22780   
C     I12 - ELEMENT OF XNS AND XCS ARRAYS TO USE.
C     IBN - TYPE OF INPUT IN XNS:
C           1 = BETA
C           2 = <||ALPHA||> OR <|| ALPHA X ALPHA  ||>
C           -99 = UNKNOWN, TO BE FOUND FROM COULOMB RESULT BY
C                 EQUAL DEFORMATION LENGTHS.
C     XNS - THE INPUT NUCLEAR QUANTITY.  FOR ALL 1ST ORDER AND
C           2ND ORDER ALPHAS, THERE IS ONLY XNS(I12).  FOR 2ND ORDER
C           BETAS THERE IS BOTH XNS(1) AND XNS(2).
C           FOR 1ST ORDER IT IS CONVERTED TO BETA.                      22790   
C     IBC - TYPE OF INPUT IN XCS:
C        1 - INPUT IS BETA
C        2 - INPUT IS <J2,K2||ALPHA OR ALPHA X ALPHA||J1,K1>
C        3 - INPUT IS <J2,K2||E(LX)||J1,K1>  IN  E BARN**LX/2
C        4 - INPUT IS <LX,0||E(LX)||0,0>   IN  E BARN**LX/2
C       -99 - NOT DEFINED, HAPPENS ONLY IF IBN=IBC=-99
C     XCS - THE INPUT COULOMB QUANTITIES; SEE XNS.
C     MEORD - =0 MEANS USE FIRST ORDER RELATION BETWEEN REDUCED MATRIX
C                ELEMENT OF E(LX) AND BETA.
C             =1 MEANS USE SECOND ORDER RELATION.                       22800   
C     LXX2 - 2*MULTIPOLE
C     LXX2S - 2*(LX1, LX2) FOR SECOND ORDER.
C     IZ - (INTEGER)  THE ATOMIC NUMBER.
C     RNUC - THE NUCLEAR RADIUS
C     RC - COULOMB RADIUS OF THE NUCLEUS
C     DELTAE - DIFFERENCE IN ENERGY OF THE TWO STATES (>0)
C     J2 - 2*SPIN OF THE HIGHER STATE.
C     J1 - 2*SPIN OF THE LOWER STATE
C     K2, K1 - 2*(K-QUANTUM NUMBERS)
C     RMENUC - SET TO <||ALPHA OR ALPHA X ALPHA||>                      22810   
C     RMECOU - IS SET TO THE COMPUTED R.M.E.
C              <J2,K2||R.M.E.||J1,K1>   IN E BARN**LX/2
C     IRTN - SET TO 0 IF ALL O.K., 1 IF NOT
C
C     12/8/80 - FIRST VERSION SEPARATED FROM BEBETA - S.P.
C     1/8/81 - PROCESS NUCLEAR AND 2ND ORDER - S.P.
C     7/24/81 - FIX BUG FOR BE(0-LX) SPECIFIED - S.P.
C     8/25/81 - CHECK FOR BOTH BETAS UNDEFINED - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
C
      DIMENSION  XCS(2), XNS(2), LXX2S(2)
C
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
C
C
      IRTN = 0
C
C     CANNOT PROCEED IF BOTH DEFORMATIONS ARE NOT DEFINED
C                                                                       22830   
      IF ( IBN .EQ. -99  .AND.  IBC .EQ. -99 )  GO TO 900
C
      LX = LXX2/2
      TJ1P1 = J1+1
C
C     COEFFICENTS FOR RME TO BETA.  THESE ARE BASED ON THE ROTATIONAL
C     MODEL
C     AME1 CONVERTS < ||ALPHA|| >  TO < ||E(LX)|| >  IN
C     SHARP CUTOFF MODEL.
C                                                                       22840   
      AME1 = 3*IZ*(RC/10)**LX / (4*PI)
C
C     AME2 CONVERS BETA OR BETA1*BETA2 TO < ||ALPHA|| >
C
      AME2 = CLEBSH( J1, LXX2, K1, K2-K1, J2, K2 )  * DSQRT(TJ1P1)
      IF ( K1 .EQ. K2 )  GO TO 50
      IF ( K2 .NE. 0  .AND.  K1 .NE. 0 )  GO TO 920
      AME2 = DSQRT(2.D0)*AME2
 50   IF ( AME2 .EQ. 0 )  GO TO 900
      AMEUSE = AME1*AME2                                                22850   
      AME2X = AME2
C
C
      IF ( IORD .EQ. 2 )  GO TO 500
C
C     AME3 IS SECOND-ORDER CONTRIBUTION TO R.M.E.
C
      AME3 = 0
      IF ( MEORD .EQ. 1  .AND.  IORD .EQ. 1 )
     1   AME3 = .25*(LX+2)*DSQRT( (LXX2+1)/PI )                         22860   
     1   * ( CLEBSH( LXX2, LXX2, 0, 0, LXX2, 0 ) )**2
C
C     FIRST ORDER
C
      XC = XCS(I12)
C
C     NOW GET THE BETA COULOMB IF NECESSARY
C
C
      GO TO ( 200, 110, 150, 130 ), IBC                                 22870   
      GO TO 930
C
C     <|| ALPHA ||>
C
 110  XC = XC/AME2
      GO TO 200
C
C     <LX,0||R.M.E.||0>
C
 130  AME2X = 1                                                         22880   
C
C     <J2,K2||R.M.E.||J1,K1>
C
C
C     WE ARE SOLVING   M.E. = A1*A2*BETA*( 1 + A3*BETA )
C
 150  XC = XC/(AME1*AME2X)
      IF ( AME3 .NE. 0 )
     1  XC = ( DSQRT( 1 + 4*AME3*XC ) - 1 ) / (2*AME3)
C                                                                       22890   
C     BETA IS IN XC; GET EVERYTHING FROM IT.
C
C     FIRST THE R.M.E.  THIS IS MODEL DEPENDANT
C
 200  XCS(I12) = XC
      RMECOU = AMEUSE*XC
C
C     ADVANCE TO NUCLEAR FIRST ORDER
C
      XN = XNS(I12)                                                     22900   
      IF ( IBN .EQ. -99 )  GO TO 260
      GO TO ( 300, 250 ), IBN
      GO TO 930
C
C     <||ALPHA|>>
C
 250  XN = XN/AME2
      GO TO 300
C
C     GET NUCLEAR FROM COULOMB                                          22910   
C
 260  XN = RC/RNUC * XC
C
C     XN IS NOW BETAN
C
 300  XNS(I12) = XN
      RMENUC = AME2*XN
      RETURN
C
C                                                                       22920   
C     SECOND ORDER
C
C     FIRST COULOMB
C
 500  XC = XCS(2)
C
C     AME4 CONVERTS < ALPHA ALPHA >  TO < E(LX) >
C
      AME4 = AME1 * (LX+2)*DSQRT( (LXX2S(1)+1.D0)*(LXX2S(2)+1.D0) /
     1  (16*PI*(LXX2+1.D0)) )                                           22930   
     2  * CLEBSH( LXX2S(1), LXX2S(2), 0, 0, LXX2, 0 )
      AME2 = AME2 *
     1  CLEBSH( LXX2S(1), LXX2S(2), K2-K1, 0, LXX2, K2-K1 )
 
C
      GO TO ( 520, 600, 540 ), IBC
      GO TO 930
C
C     BETAC1 AND BETAC2, GET ALPHA X ALPHA
C                                                                       22940   
 520  XC = AME2 * XCS(1)*XCS(2)
      GO TO 600
C
C     RME E(LX), GET ALPHA X ALPHA
C
 540  XC = XC/(AME4)
C
C     NOW WE HAVE  ALPHA X ALPHA, GET RME E(LX)
C
 600  RMECOU = AME4*XC                                                  22950   
C
C     GO ON TO NUCLEAR
C
      IF ( IBN .EQ. -99 )  GO TO 760
      GO TO ( 720, 740 ), IBN
      GO TO 930
C
C     BETAN1, BETAN2
C
 720  RMENUC = AME2*XNS(1)*XNS(2)                                       22960   
      GO TO 800
C
C     ALPHA X ALPHA GIVEN
C
 740  RMENUC = XNS(2)
      GO TO 800
C
C     UNKNOWN, USE COULOMB
C
 760  RMENUC = (RC/RNUC)**2 * XC                                        22970   
C
 800  RETURN
C
 900  RMECOU = 0
      RMENUC = 0
      RETURN
C
 920  write (6, 923) K1, K2
 923  FORMAT ( '0*** PRESENT ROTATIONAL MODEL DOES NOT WORK',
     1  ' FOR K1, K2 =', 2(I4, '/2') )                                  22980   
 925  IRTN = 1
      GO TO 900
C
 930  write (6, 933) IBC, IBN
 933  FORMAT ( '0*** INVALID IBC OR IBN IN MEBROT*', 2I12 )
      GO TO 925
C
      END
C*ID* MEBVIB   C109.PTOLEMY.SOURCE                          PER701  10:
      SUBROUTINE  MEBVIB ( IORD, I12, IBN, XNS, IBC, XCS,               22990   
     1  MEORD, LXX2, LXX2S, IZ, RNUC, RC, DELTAE,
     1  J2, J1, K2IN, K1IN, RMENUC, RMECOU, IRTN )
C
C     CONVERTS VIBRATIONAL REDUCED MATRIX ELEMENT TO AND FROM BETA
C
C     THIS SUBROUTINE CONTAINS THE MODEL DEPENDANT PARTS OF
C     BEBETA FOR THE VIBRATIONAL MODEL.
C
C     THE FOLLOWING COUPLINGS CAN BE CONVERTED TO AND FROM BETA
C     BY THIS ROUTINE ( < ||ALPHA|| > = FACTOR*BETA ):                  23000   
C
C            RME                          FACTOR
C     <LX || LX || 0>                       1
C     <LX,LX:J || LX || LX>              SQRT(2) JHAT/LXHAT  (J EVEN)
C     <LX',LX:J || LX || LX'>              JHAT/LXHAT
C     <LX,LX:J || (LX X LX)J || 0>        SQRT(2) JHAT/LXHAT**2
C     <LX1,LX2:J || (LX1 X LX2)J || 0>     JHAT/(LX1HAT*LX2HAT)
C     <LX || (LX X LX)J || LX>          (-)**LX 2 JHAT/LXHAT**2
C     <LX2 || (LX1 X LX2)J || LX1>      (-)**LX1 JHAT/(LX1HAT*LX2HAT)
C                                                                       23010   
C     WHERE  |LX>  IS A ONE-PHONON STATE AND |LX1,LX2:J> IS
C     A TWO-PHONON STATE.  FOR ALL THE SECOND-ORDER MATRIX ELEMENTS,
C     WE REQUIRE  LX1+LX2+LXTOTAL (LXTOTAL=J ABOVE)  TO BE EVEN
C     SINCE WE WILL HAVE THE SUM OF BOTH LX1,LX2 AND LX2,LX1
C     TERMS.  THIS PROPERTY IS ENSURED BY BASCPL.
C     ALL OF THE TRANSPOSE MATRIX ELEMENTS ARE ALSO FOUND BY
C        <J1||...||J2> = (-1)**(J2-J1) <J2||...||J1>
C
C     FOR ALL OTHER CASES, THE R.M.E. MUST BE DIRECTLY GIVEN, AND
C     THE BETAS WILL NOT BE COMPUTED.                                   23020   
C
C
C     IORD - THE ORDER OF THE RME TO PRODUCE.  IF 2 IT IS ALSO
C           THE ORDER OF THE INPUT RME(E) OR RME(ALPHA).  IF 1,
C           MEORD INDICATES THE ORDER OF RME(E), BUT 1ST ORDER IS
C           ALWAYS PRODUCED.
C     I12 - ELEMENT OF XNS AND XCS ARRAYS TO USE.
C     IBN - TYPE OF INPUT IN XNS:
C           1 = BETA
C           2 = <||ALPHA||> OR <|| ALPHA X ALPHA  ||>                   23030   
C           -99 = UNKNOWN, TO BE FOUND FROM COULOMB RESULT BY
C                 EQUAL DEFORMATION LENGTHS.
C     XNS - THE INPUT NUCLEAR QUANTITY.  FOR ALL 1ST ORDER AND
C           2ND ORDER ALPHAS, THERE IS ONLY XNS(I12).  FOR 2ND ORDER
C           BETAS THERE IS BOTH XNS(1) AND XNS(2).
C           FOR 1ST ORDER IT IS CONVERTED TO BETA.
C     IBC - TYPE OF INPUT IN XCS:
C        1 - INPUT IS BETA
C        2 - INPUT IS <J2,K2||ALPHA OR ALPHA X ALPHA||J1,K1>
C        3 - INPUT IS <J2,K2||E(LX)||J1,K1>  IN  E BARN**LX/2           23040   
C        4 - INPUT IS <LX,0||E(LX)||0,0>   IN  E BARN**LX/2
C       -99 - NOT DEFINED, HAPPENS ONLY IF IBN=IBC=-99
C     XCS - THE INPUT COULOMB QUANTITIES; SEE XNS.
C     MEORD - IGNORED FOR VIBRATIONAL MODEL
C     LXX2 - 2*MULTIPOLE
C     LXX2S - 2*(LX1, LX2) FOR SECOND ORDER.
C     IZ - (INTEGER)  THE ATOMIC NUMBER.
C     RNUC - THE NUCLEAR RADIUS
C     RC - COULOMB RADIUS OF THE NUCLEUS
C     DELTAE - DIFFERENCE IN ENERGY OF THE TWO STATES (>0)              23050   
C     J2 - 2*SPIN OF THE HIGHER STATE.
C     J1 - 2*SPIN OF THE LOWER STATE
C     K2, K1 - 2*(NUMBER OF PHONONS)
C           0 IS SET TO 1 EXCEPT FOR J=0 WHICH IS LEFT AT 0 (GS)
C           <0 IS SET TO THE NUMBER THAT CONSERVES PHONONS,
C                 EITHER 1 OR 2.
C     RMENUC - SET TO <||ALPHA OR ALPHA X ALPHA||>
C     RMECOU - IS SET TO THE COMPUTED R.M.E.
C              <J2,K2||R.M.E.||J1,K1>   IN E BARN**LX/2
C     IRTN - SET TO 0 IF ALL O.K., 1 IF NOT                             23060   
C
C     1/20/81 - MEBVIB MADE FROM MEBROT - S.P.
C     8/25/81 - CHECK FOR BOTH BETAS UNDEFINED - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
C
      DIMENSION  XCS(2), XNS(2), LXX2S(2)
C
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
C                                                                       23070   
C
      IRTN = 0
C
C     CANNOT PROCEED IF BOTH DEFORMATIONS ARE NOT DEFINED
C
      IF ( IBN .EQ. -99  .AND.  IBC .EQ. -99 )  GO TO 900
C
      LX = LXX2/2
C
C     WE ARRANGE THINS SO THAT  K2 > K1                                 23080   
C     AND THEN COMPUTE  < 2 || ... || 1 >
C     IF THIS INVOLVES FLIPING THINGS, WE INTRODUCE THE
C     REQUIRED  (-1)**(J2-J1)
C
C     FILL IN UNDEFINED NUMBERS OF PHONOS
C
      K1 = K1IN
      K2 = K2IN
      IF ( K1 .EQ. 0  .AND.  J1 .GT. 0 )  K1 = 2
      IF ( K2 .EQ. 0  .AND.  J2 .GT. 0 )  K2 = 2                        23090   
      IF ( K1 .GE. 0 )  GO TO 20
      IF ( K2 .LT. 0 )  GO TO 940
      K1 = 2*IORD
      IF ( K2 .EQ. 2 )  K1 = 6-K1
      GO TO 40
 20   IF ( K2 .GE. 0 )  GO TO 40
      K2 = 2*IORD
      IF ( K1 .EQ. 2 )  K2 = 6-K2
C
 40   IF ( K2 .LT. K1 )  GO TO 45                                       23100   
      KK1 = K1/2
      KK2 = K2/2
      JJ1 = J1
      JJ2 = J2
      SGNFAC = +1
      GO TO 50
 45   KK1 = K2/2
      KK2 = K1/2
      JJ1 = J2
      JJ2 = J1                                                          23110   
      SGNFAC = (-1)**((J2-J1)/2)
C
 50   TJ2P1 = JJ2+1
C
C     COEFFICENTS FOR RME TO BETA.  THESE ARE BASED ON THE VIBRATIONAL
C     MODEL
C     AME1 CONVERTS < ||ALPHA|| >  TO < ||E(LX)|| >  IN
C     SHARP CUTOFF MODEL.
C
      AME1 = 3*IZ*(RC/10)**LX / (4*PI)                                  23120   
C
C     AME2 CONVERS BETA OR BETA1*BETA2 TO < ||ALPHA|| >
C
C     IF THIS IS A CASE WE DON'T KNOW ABOUT, AME2 = 0
C
      AME2 = 0
C
C
      IF ( IORD .EQ. 2 )  GO TO 400
C                                                                       23130   
C     FIRST ORDER
C
      IF ( KK2 .GE. 3 )  GO TO 100
      IF ( KK2 .NE. KK1+1 )  GO TO 100
      IF ( KK1 .EQ. 0  .AND.  JJ1 .NE. 0 )  GO TO 100
      GO TO ( 70, 80 ), KK2
C
C     < 1 PHONON || LX || 0 >    LX = J2 IS ALREADY KNOWN
C
 70   AME2 = 1                                                          23140   
      GO TO 100
C
C     < 2 PHONONS; J || LX || 1 PHONON >
C
 80   AME2 = SQRT( TJ2P1/(LXX2+1) )
      IF ( LXX2 .NE. JJ1 )  GO TO 100
      IF ( MOD(JJ2, 4) .NE. 0 )  GO TO 99
      AME2 = DSQRT(2.D0)*AME2
      GO TO 100
C                                                                       23150   
 99   AME2 = 0
 100  AME2 = SGNFAC*AME2
      XC = XCS(I12)
C
C     NOW GET THE BETA COULOMB IF NECESSARY AND POSSIBLE
C
C
      GO TO ( 170, 110, 150, 130 ), IBC
      GO TO 930
C                                                                       23160   
C     <|| ALPHA ||>  CONVERT TO < ||E(LX)|| >
C
 110  XC = XC*AME1
      GO TO 150
C
C     <LX||R.M.E.||0>   GET BETA
C
 130  XC = XC/AME1
      GO TO 170
C                                                                       23170   
C     <J2,K2||R.M.E.||J1,K1>  GET BETA IF POSSIBLE
C
 150  RMECOU = XC
      XC = 0
      IF ( AME2 .NE. 0 ) XC = RMECOU/(AME1*AME2)
      GO TO 200
C
C     BETA IS IN XC; GET EVERYTHING FROM IT.
C
 170  IF ( AME2 .EQ. 0 )  GO TO 920                                     23180   
      RMECOU = AME1*AME2 * XC
C
 200  XCS(I12) = XC
C
C     ADVANCE TO NUCLEAR FIRST ORDER
C
      XN = XNS(I12)
      IF ( IBN .EQ. -99 )  GO TO 260
      GO TO ( 270, 250 ), IBN
      GO TO 930                                                         23190   
C
C     <||ALPHA|>>
C
 250  RMENUC = XN
      XN = 0
      IF ( AME2 .NE. 0 )  XN = RMENUC/AME2
      GO TO 300
C
C     GET NUCLEAR ALPHA FROM COULOMB RME
C                                                                       23200   
 260  XN = RC/RNUC * RMECOU/AME1
      GO TO 250
C
C     XN IS NOW BETAN
C
 270  IF ( AME2 .EQ. 0 )  GO TO 920
      RMENUC = AME2*XN
C
 300  XNS(I12) = XN
      RETURN                                                            23210   
C
C
C     SECOND ORDER
C
C     GET CONVERSION FACTORS
C
 400  IF ( KK2 .GE. 3 )  GO TO 500
      IF ( KK1 .EQ. 0  .AND.  KK2 .EQ. 2 )  GO TO 410
      IF ( KK1 .EQ. 1  .AND.  KK2 .EQ. 1 )  GO TO 420
      GO TO 500                                                         23220   
C
C     < 2 PHONON || (LX1 LX2)LX || 0 >   LX = J2 IS KNOWN
C
 410  AME2 = DSQRT( TJ2P1/((LXX2S(1)+1)*(LXX2S(2)+1)) )
      IF ( LXX2S(1) .EQ. LXX2S(2) )  AME2 = DSQRT(2.D0)*AME2
      GO TO 500
C
C     < 1 PHONON || (LX1 LX2)LX || 1 PHONON >
C
 420  IF ( LXX2S(1) .EQ. J1  .AND.  LXX2S(2) .EQ. J2 )  GO TO 425       23230   
      IF ( LXX2S(1) .EQ. J2  .AND.  LXX2S(2) .EQ. J1 )  GO TO 425
      GO TO 500
C
 425  AME2 = (-1)**(LXX2S(1)/2) * DSQRT( (LXX2+1.D0)/
     1  ( (LXX2S(1)+1.D0)*(LXX2S(2)+1.D0) ) )
      IF ( J2 .EQ. J1 )  AME2 = 2*AME2
C
 500  AME2 = SGNFAC*AME2
      AME4 = AME1 * (LX+2)*DSQRT( (LXX2S(1)+1.D0)*(LXX2S(2)+1.D0) /
     1  (16*PI*(LXX2+1.D0)) )                                           23240   
     2  * CLEBSH( LXX2S(1), LXX2S(2), 0, 0, LXX2, 0 )
 
C
C
C     NOW DO COULOMB
C
      XC = XCS(2)
      GO TO ( 520, 600, 540 ), IBC
      GO TO 930
C                                                                       23250   
C     BETAC1 AND BETAC2, GET ALPHA X ALPHA
C
 520  IF ( AME2 .EQ. 0 )  GO TO 920
      XC = AME2 * XCS(1)*XCS(2)
      GO TO 600
C
C     RME E(LX), GET ALPHA X ALPHA
C
 540  XC = XC/(AME4)
C                                                                       23260   
C     NOW WE HAVE  ALPHA X ALPHA, GET RME E(LX)
C
 600  RMECOU = AME4*XC
C
C     GO ON TO NUCLEAR
C
      IF ( IBN .EQ. -99 )  GO TO 760
      GO TO ( 720, 740 ), IBN
      GO TO 930
C                                                                       23270   
C     BETAN1, BETAN2
C
 720  IF ( AME2 .EQ. 0 )  GO TO 920
      RMENUC = AME2*XNS(1)*XNS(2)
      GO TO 800
C
C     ALPHA X ALPHA GIVEN
C
 740  RMENUC = XNS(2)
      GO TO 800                                                         23280   
C
C     UNKNOWN, USE COULOMB
C
 760  RMENUC = (RC/RNUC)**2 * XC
C
 800  RETURN
C
 900  RMECOU = 0
      RMENUC = 0
      RETURN                                                            23290   
C
 920  write (6, 923) J2, K2, LXX2S, LXX2, J1, K1, IORD
 923  FORMAT ( '0*** PRESENT VIBRATIONAL MODEL DOES NOT WORK',
     1  ' FOR J2, K2, LX1, LX2, LX, J1, K1, ORDER =' /
     2  6X, 7(I4, '/2'), I4 )
 925  IRTN = 1
      GO TO 900
C
 930  write (6, 933) IBC, IBN
 933  FORMAT ( '0*** INVALID IBC OR IBN IN MEBVIB*', 2I12 )             23300   
      GO TO 925
C
 940  write (6, 943)
 943  FORMAT ( '0**** CANNOT HAVE INDEFINET NUMBER OF PHONONS',
     1  ' IN BOTH STATES.' )
      GO TO 925
C
      END
C*ID* MSCAN    C109.PTOLEMY.SOURCE                          PER701  12:
      SUBROUTINE MSCAN ( KEYEX, ITOKEN, CVALU, VALU, IVALU, MESS,       23310   
     1  IMESS, STOP )
C
C     FIELD SCANNER FOR DELPHI
C     MODIFIED MFIELD SCANNER OF SPEAKEZ
C     THIS VERSION IS FOR PTOLEMY.
C
C
C     THE LINE TO SCAN IS IN IBUF.  IT CONTAINS NOCH CHARACTERS.
C     INCH IS THE FIRST CHARACTER TO CONSIDER AND IS UPDATED TO POINT
C          TO THE CHARACTER THAT STOPPED THE SCAN - I.E. TO THE FIRST   23320   
C          CHARACTER TO CONSIDER THE NEXT TIME.
C
C     ITOKEN IS SET AS FOLLOWS
C     > 0 CODE VALUE AS DESCRIBED SEVERAL LINES BELOW
C      0  NO FIELD
C     -1  ALPHANUMERIC  LEFT SHIFTED BLANK FILLED - STORED IN 'CVALU'.
C         THE NUMBER OF CHARACTERS IS STORED IN IMESS.
C     -2  NUMERIC (FLT. PT. FORM) - STORED IN 'VALU' AND 'IVALU'.
C     -3  BEGINNING OF LEVEL SPECIFICATION (E.G. 1P FROM 1P3/2-).  THE
C         NUMBER OF NODES IS STORED IN VALU (3P RESULTS IN VALU=2=3-1), 23330   
C         AND THE NUMERIC (S=0, P=1, ETC.) L-VALUE IS STORED IN IVALU.
C         ON THE NEXT CALL TO MSCAN, THE J-FIELD (IF PRESENT) WILL BE
C         SCANNED.  THE FOLLOWING ARE RECOGNIZED AS L-INDICATORS:
C             S P D F G H I J K .
C         WITH THE EXCEPTION OF E (FOR EXPONENTS) ANY OTHER ALPHABETIC
C         IN A NUMERIC FIELD IS TREATED AS AN ERROR.  NOTE THAT LEVEL
C         SPECIFICATIONS MAY NOT HAVE A DECIMAL POINT SO THAT 1.D+10
C         IS RECOGINIZED AS THE SAME AS 1E10 WHILE 1D10 WOULD BE TREATED
C         AS A LEVEL SPECIFICATION.
C     -4  LITERAL DATA (80 COL. MAX).  STORED IN MESS; IMESS IS NUM.    23340   
C         CHARACTERS STORED.
C     -5  INTEGER (NO DECIMAL PT. OR E FIELD) - STORED IN 'VALU' AND
C         'IVALU'.
C     -8  END OF CARD BEFORE ANYTHING WAS FOUND - NOTHING STORED.
C     -9  ERROR ENCOUNTERED - NOTHING RELIABLE STORED.
C
C     SPECIAL CHARACTER TOKENS ARE  ( + - * ARE NOLONGER TOKENS )
C     %(1)  #(2)  &(3)  :(4)  ;(5)
C     -(6)  +(7)  /(8)  *(9)  ((10)  (+ - NOW START NUMBERS)
C                                    (* NOW AN ALPHA CHAR.)             23350   
C     )(11) =(12) @(13) <(14) >(15)
C     |(16) �(17) ?(18) "(19) .(20)  (. IS NORMALLY NUMERIC)
C     ,(21)
C
C     \KEYEX\ TELLS NUMBER OF THE LARGEST TOKEN TO KEEP
C     OTHERS SERVE ONLY AS DELIMITERS
C
C     IF  KEYEX < 0  THEN NUMERIC FIELDS ARE NOT DECODED BUT ARE
C     TREATED AS ALPHAMERIC AND TOKEN IS SET TO 1 FOR THEM.
C     IN THIS CASE, ALPHABETICS ARE ALLOWED IN THE NUMERIC FIELD        23360   
C     (I.E. 48CA IS VALID) AND +, -, AND . ARE TREATED AS TOKENS
C     INSTEAD OF PARTS OF NUMERICS.
C
C     STOP IS SET TO THE CHARACTER THAT STOPPED THE SCAN -- I.E.
C     THE FIRST CHARACTER TO BE CONSIDERED ON THE NEXT CALL TO
C     MSCAN.  NOTE THAT FOR  ITOKEN > 0  THIS IMPLIES THAT STOP IS
C     THE CHARACTER AFTER THE TOKEN.
C
C     Except in literals lowercase is converted to uppercase
c                                                                       23370   
C     BLANKS ARE DELIMITERS AND NOT MADE INTO TOKENS
C     '(APOSTROHIES) DELIMIT LITERAL DATA, $ IS COMMENT DELIMITER
C
C
C     5/7/75 - EXTENSIVE CHANGES FOR PTOLEMY - S. PIEPER
C     8/26/76 - MUCH REWRITE FOR CDC/IBM VERSION.
C     5/6/79 - LEVELS PUT BACK; CORRECT ERROR IN LITERAL FIELDS - S.P.
C     12/28/79 - STANDARD MORTRAN, CUN, CVA - RPG
C     1/11/80 - ADD CHARACTER*8 ARGUMENT CVALUE, USE IT;  USE QUOTES IN
C        DATA STATEMENTS; OTHER RELATED CORRECTIONS - RPG               23380   
C     3/15/80 - USE 1H_ IN CDC DELIMS DEFINITION - S.P.
C     6/2/80 - CDC 1H_ VERSION OF CHARS - S.P.
C     7/14/80 - CRAY VERSION - S.P.
C     9/10/85 - CONVERT LOWERCASE TO UPPERCASE
C     3/2/07 - allow _ as a alphanum
C
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( ibufsize = 200 )                                      /inpbuf/
      CHARACTER*1 IBUF(ibufsize)
      COMMON /INPBUF/ NOCH, INCH, IBUF
 
C
      CHARACTER*1  STOP                                                 23390   
C
      CHARACTER*1 MESS(1)
      CHARACTER*8 CVALU
      CHARACTER*1  DOLLAR /'$'/,  BLANK /' '/,  DOT /'.'/
      CHARACTER*1  STAR /'*'/
C
      CHARACTER*1
     1  NUM0 /'0'/, NUM9 /'9'/,
     1  LETTRA /'A'/, LETTRZ /'Z'/,
     2  LOWERA /'a'/, LOWERZ /'z'/                                      23400   
      CHARACTER*1  LETTRE /'E'/, LETTRD /'D'/
C
      DATA NUMLS /9/
      CHARACTER*1  LCHARS(9) / 'S', 'P', 'D', 'F', 'G', 'H', 'I',
     1  'J', 'K' /
C
      CHARACTER*8 WORD, BLANK8 /' '/
      CHARACTER*1  WORD1(8)
      EQUIVALENCE ( WORD, WORD1(1) )
C                                                                       23410   
      CHARACTER*1 CHARS(21), DELIMS(4), ICH
C
c
C
      DATA  CHARS / '%', '#', '&', ':', ';',
     1  '-', '+', '/', '*', '(',
     2  ')', '=', '@', '<', '>',
     3  '|', '~', '?', '"', '.',
     4  ',' /
c                                                                       23420   
      DATA  DELIMS / '+', '-', '''', '$' /
C
C
C
C     PRESETS
C
      INCHST = INCH
      SIGN = +1
      VAL = 0
      ICNT = 0                                                          23430   
      INCH = INCH - 1
      IMESS=0
      ICOM=0
      IDEC = 0
C
C     PHASES
C     1 NOTHING COOKING
C     2 ALPHABETIC FIELD BEING PROCESSED
C     3 NUMERICAL FIELD BEING PROCESSED
C                                                                       23440   
C
      INPHAS = 1
C
C     GET NEXT CHAR IF COMMENT SKIP IF NOT FIND TYPE
C
  100 INCH=INCH+1
      IF (INCH.GT.NOCH) GO TO 710
      ICH=IBUF(INCH)
C     IS A LITERAL COMMING IN
      IF(IMESS.GT.0)GO TO 149                                           23450   
C     IS A COMMENT COMMING IN (IF SO SKIP UNTIL $ IS MET)
C
      IF(ICOM.EQ.0)GO TO 101
      IF (ICH.NE.DOLLAR) GO TO 100
      ICOM=0
      GO TO 100
C
C     BLANK ?
C
 101  IF ( ICH .EQ. BLANK )  GO TO ( 100, 210, 340 ), INPHAS            23460   
C
C     NUMBER ?
C
      IF ( ich .GE. NUM0  .AND.  ich .LE. NUM9 )  GO TO 300
C
C     ALPHABETIC ?
C
      IF ( ( ich .GE. LETTRA  .AND.  ich .LE. LETTRZ)  .OR.
     1  ICH .EQ. STAR  .or.  ich .eq. '_' )  GO TO 200
C                                                                       23470   
C     CONVERT LOWERCASE TO UPPERCASE
C
      IF ( ich .LT. LOWERA  .OR.  ich .GT. LOWERZ )  GO TO 102
      ICH = char( ichar(ICH) + ichar('A')-ichar('a') )
      GO TO 200
C
C     IT IS A SPECIAL CHARACTER
C
C     IS IT A PERIOD
C                                                                       23480   
 102  IF (ICH.EQ.DOT) GO TO 320
C
C     ALL OTHER SPECIAL CHARACTERS STOP A FIELD THAT IS IN PROGRESS
C
      GO TO(105,210,340),INPHAS
C
C     FIRST CHECK FOR  + - ' $
C
 105  DO 129  I = 1, 4
         IF ( ICH .EQ. DELIMS(I) )  GO TO 140                           23490   
 129  CONTINUE
C
C     NOW LOOK FOR TOKENS
C
      DO 139  ITOKEN = 1, 21
         IF ( ICH .EQ. CHARS(ITOKEN) )  GO TO 590
 139  CONTINUE
      GO TO 9000
C
 140  GO TO ( 141, 142, 143, 144 ), I                                   23500   
 141  SIGN = +1
      ITOKEN = 7
      IF ( KEYEX .LT. 0 )  GO TO 590
      GO TO 302
 142  SIGN = -1
      ITOKEN = 6
      IF ( KEYEX .LT. 0 )  GO TO 590
      GO TO 302
 143  IMESS = 1
      GO TO 100                                                         23510   
 144  ICOM = 1
      GO TO 100
C
C     COLLECTING A LITERAL
C
  149 MESS(IMESS)=ICH
      IMESS=IMESS+1
      IF(IMESS.GT.80) GO TO 9006
      IF (ICH.NE.DELIMS(3))GO TO 100
      IMESS=IMESS-2                                                     23520   
      MESS(IMESS+1)=BLANK
      ITOKEN=-4
      INCH = INCH+1
      GO TO 602
C
C     ALPHABETIC CHARACTER CHECK PHASE
C
C
 200  GO TO(201,202,330),INPHAS
C     START                                                             23530   
 201  WORD = BLANK8
      IWORD = 0
 202  IF (IWORD .LT. 8)  WORD1(IWORD+1) = ich
      IF (IWORD .LT. 8)  IWORD = IWORD+1
      INPHAS=2
      GO TO 100
C     DONE
 210  IMESS = IWORD
      CVALU = WORD
      ITOKEN=-1                                                         23540   
      GO TO 600
C
C
C     NUMERIC
C
 300  IF ( KEYEX .LT. 0 )  GO TO 200
      GO TO (301,202,303),INPHAS
C     START
  301 IDEC=0
      VAL = ichar(ich) - ichar(NUM0)                                    23550   
      ICNT = 1
  302 POW=1.0
      INPHAS=3
      GO TO 100
C     MORE
 303  VAL = 10*VAL +  ichar(ich) - ichar(NUM0)
      IF (IDEC.NE.0) POW=POW*10.0
      ICNT = ICNT + 1
      GO TO 100
C                                                                       23560   
C     DECIMAL PT.
C
 320  ITOKEN = 20
      IF ( KEYEX .LT. 0 )  GO TO 590
      GO TO (321,9002,310),INPHAS
C
C     DECIMAL PT ENCOUNTERED IN NUMERIC FIELD
C
  310 IF (IDEC.NE.0) GO TO 9002
      IDEC=1                                                            23570   
      GO TO 100
  321 IDEC=1
      VAL=0.0
      GO TO 302
C
C     ALPHABETIC IN NUMERIC FIELD - CHECK E FOR EXPONENTS
C
 330  IF ( ICH .EQ. LETTRE )  GO TO 332
C
C     IF WE HAVE NOT YET HAD A DECIMAL POINT THEN IT MUST BE A          23580   
C     LEVEL SPECIFICATION.
C
      IF ( IDEC .EQ. 0 )  GO TO 400
C
C     FOLLOWING A DECIMAL POINT A "D" MAY BE USED FOR AN EXPONENT
C
      IF ( ICH .NE. LETTRD )  GO TO 9012
C
C
C     E OR D FORMAT                                                     23590   
C
 332  ISG = 1
      IDEC = 1
      IPOW=0
      INCH=INCH+1
      IF (INCH.GT.NOCH) GO TO 9008
      ICH=IBUF(INCH)
      IF (ICH.EQ.DELIMS(1)) GO TO 334
      IF (ICH.NE.DELIMS(2)) GO TO 335
      ISG=-1                                                            23600   
  334 INCH=INCH+1
      IF (INCH.GT.NOCH) GO TO 3360
      ICH=IBUF(INCH)
 335  IF ( ich .LT. NUM0  .OR.  ich .GT. NUM9 )  GO TO 336
      IPOW=IPOW*10+ ichar(ich) - ichar(NUM0)
      IF ( IPOW .GT. 300 )  GO TO 9004                                  ci3e
CIB      IF (IPOW.GT.75) GO TO 9004
CDC      IF ( IPOW .GT. 300 )  GO TO 9004
CUN      IF ( IPOW .GT. 300 )  GO TO 9004
CVA      IF ( IPOW .GT. 38 ) GO TO 9004                                 23610   
CRA      IF ( IPOW .GT. 2465 )  GO TO 9004
      GO TO 334
C
 3360 CONTINUE
  336 IF (IPOW.EQ.0)GO TO 340
      P2=10.0D0**IPOW
      IF (IS G.LT.0) GO TO 337
      POW=POW/P2
      GO TO   340
  337 POW=POW*P2                                                        23620   
      GO TO 340
  340 ITOKEN=-2
      VALU1=VAL/POW
      VALU=VALU1*SIGN
      IVALU = VALU
      IF ( IDEC .EQ. 0 )  ITOKEN = -5
      IF ( ICNT .EQ. 0 )  GO TO 9010
      GO TO 600
C
C     AN ALPHABETIC WAS FOUND IN AN INTEGER NUMERIC FIELD; IT MAY BE THE23630   
C     L-DESIGNATOR OF A LEVEL-SPECIFICATION.
C
 400  VALU = SIGN*VAL - 1
      DO 409  I = 1, NUMLS
         IF ( ICH .EQ. LCHARS(I) )  GO TO 420
 409  CONTINUE
      GO TO 9012
 420  IVALU = I-1
      ITOKEN = -3
      INCH = INCH+1                                                     23640   
      GO TO 600
C
C     SPECIAL CHARACTER FOUND - SHOULD WE SKIP OVER IT0
C
  590 IF(ITOKEN.GT. IABS(KEYEX) )GO TO 100
      INCH = INCH + 1
C
C     FIELD HAS BEEN FOUND AND PROCESSED
C
 600  CONTINUE                                                          23650   
 602  STOP = IBUF(INCH)
      RETURN
C
C     END OF LINE ENCOUNTERED
C
  710 CONTINUE
      GO TO(701,210,340),INPHAS
  701 CONTINUE
      ITOKEN = -8
      RETURN                                                            23660   
C
C     ERROR MESSAGES
C
 9000 write (6, 9001) ICH, ICH
 9001 FORMAT ( '0**** UNRECOGNIZABLE CHARACTER ''', A1, '''', 5X,
     1  '(HEX IS ', Z2, ').' )
CDC     1  '(OCTAL IS ', O2, ').' )
      GO TO 9019
 9002 write (6, 9003)
 9003 FORMAT ( '0**** INVALID DECIMAL POINT.' )                         23670   
      GO TO 9019
 9004 write (6, 9005)
 9005 FORMAT ('0**** INVALID OR TOO LARGE EXPONENT FIELD.')
      GO TO 9019
 9006 write (6, 9007)
 9007 FORMAT ('0**** FIELD IS TOO LONG.' )
      GO TO 9019
 9008 write (6, 9009)
 9009 FORMAT ('0**** E OR D MUST BE FOLLOWED BY NUMBER')
      GO TO 9019                                                        23680   
 9010 write (6, 9011)
 9011 FORMAT ( '0**** MISPLACED DECIMAL POINT OR PLUS OR MINUS SIGN.' )
      GO TO 9019
 9012 write (6, 9013)
 9013 FORMAT ( '0**** INVALID ALPHABETIC IN NUMMERIC FIELD' )
C
 9019 write (6, 9023) ( IBUF(I), I = INCHST, INCH )
 9023 FORMAT ( ' FIELD UP TO THE ERROR IS: ', 80A1 )
      ITOKEN = -9
C                                                                       23690   
      RETURN
      END
C*ID* MUELCO   C109.PTOLEMY.SOURCE   PART3                  PER701  15:
      SUBROUTINE MUELCO ( KA, KB, KBIGA, KBIGB, JA, JB, JBIGA, JBIGB,
     1   NQA, NQB, NQBIGA, NQBIGB, NSPL, IPARIT,
     2   ITOC, COEF, COEP, COET, COEX, TERMK, PBUGSW )
C
C
C     CALCULATES THE ANGLE-INDEPENDENT PARTS OF THE MUELLER MATRIX
C     FOR A GIVEN SET OF K'S, ALL Q'S.                                  23700   
C
C
C     REFERENCE:  B. A. ROBSON, THE THEORY OF POLARIZATION PHENOMENA
C     (CLARENDON PRESS, OXFORD, 1974).
C
C
C     NOTE:  THIS SUBROUTINE REQUIRES 9 LEVELS OF DO-LOOP NESTING
C     AND 6 ARRAY INDICES.  MAY GIVE TROUBLE ON SOME COMPILERS.
C
C     NOTE ALSO:  THIS SUBROUTINE HAS BEEN TESTED FOR KB=KBIGA=KBIGB=0  23710   
C     (PROJECTILE ANALYZING POWERS) ONLY.  RESULTS FOR OTHER CASES
C     "SHOULD" BE RIGHT, BUT ARE NOT GUARANTEED.
C
C
C     INPUT SCALARS:
C
C     KA, KB, KBIGA, KBIGB = THE K INDICES OF THE MUELLER MATRIX.
C     JA, JB, JBIGA, JBIGB = 2 * THE PARTICLE SPINS.
C     NQA, NQB, NQBIGA, NQBIGB = THE NUMBER OF Q'S FOR EACH K.
C        THE Q'S ALWAYS END AT K, AND START AT 0, 1, OR -K.             23720   
C     NSPL = THE NUMBER OF AMPLITUDES (F'S) AT EACH ANGLE.
C     IPARIT = THE PARITY CHANGE OF THE REACTION (+1 OR -1).
C
C     INPUT ARRAY (AND DIMENSIONS):
C
C     ITOC(4,NSPL) = TABLE OF CONTENTS (SEE ANGSET COMMENTS).
C
C     OUTPUT ARRAY (AND DIMENSIONS):
C
C     COEF(NQA,NQB,NQBIGA,NQBIGB,NSPL,NSPL) = COEFFICIENT OF            23730   
C        F(KOFF) * F*(KOFFP) IN THE EXPRESSION FOR
C        Z(KA, QA, KB, QB, KBIGA, QBIGA, KBIGB, QBIGB),
C        FOR ALL KOFF, KOFFP, Q'S; FIXED K'S.
C
C     SCRATCH ARRAYS (AND DIMENSIONS):
C
C     COEP(NQA, NQB) = PROJECTILE 9-J TIMES CLEBSCHES.
C     COET(NQBIGA, NQBIGB) = TARGET 9-J TIMES CLEBSCHES.
C     COEX(KMAX+1) = THIRD 9-J ETC. FOR ALL K.
C     TERMK(KMAX+1) = COEX TIMES CLEBSCH, ALL K.                        23740   
C        WHERE  KMAX = MIN( 2*MAX(LX), KA+KB+KBIGA+KBIGB ).
C
C
C     10/30/79 - NEW ROUTINE - RPG
C     6/3/80 - FOR CDC, COEF HAS ONLZ 3 DIMENSIONS - S.P.
C     6/26/80 - DEBUGING PRINTOUT WITH PBUGSW - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
C
      DIMENSION  COEF(NQA,NQB,NQBIGA,NQBIGB,NSPL,NSPL)                  23750   
CDC      DIMENSION  COEF(NQA, NQB, 1)
CDC%'COEF(#,#,#,#,#,#)' = 'COEF(#1, #2,
CDC     1    ((#6*NSPL+#5)*NQBIGB+#4)*NQBIGA+#3
CDC     1    - ((NSPL+1)*NQBIGB+1)*NQBIGA )'
      DIMENSION  ITOC(4, NSPL),
     1   COEP(NQA,NQB), COET(NQBIGA,NQBIGB), COEX(1), TERMK(1)
      LOGICAL  PBUGSW
C
      INTEGER QA, QB, QBIGA, QBIGB, QP, QT, Q, QAS, QBS, QBIGAS, QBIGBS,
     1   QPMN, QPMX, QAMN, QAMX, QBMN, QBMX,                            23760   
     2   QPMIN, QPMAX, QTMIN, QTMAX, QMIN, QMAX
C
CDC      ALLOCLEVEL  COEF, COEP, COET, COEX, TERMK
c
C
C
C     INITIALIZATION
C
 1    JTPRV = -1
      JTPPRV = -1                                                       23770   
      KTPRV = -1
      JPPRV = -1
      JPPPRV = -1
      KPPRV = -1
      QAS = KA - NQA + 1
      QBS = KB - NQB + 1
      QBIGAS = KBIGA - NQBIGA + 1
      QBIGBS = KBIGB - NQBIGB + 1
      PARITY = IPARIT
      N = NSPL*NSPL*NQA*NQB*NQBIGA*NQBIGB                               23780   
      IF (PBUGSW) write (6, 3) KA, KB, KBIGA, KBIGB, JA, JB, JBIGA,
     1  JBIGB, NQA, NQB, NQBIGA, NQBIGB, NSPL, IPARIT, N
  3   FORMAT ( '0MUELCO...', (T15, 8I12) )
      DO 59  I = 1, N
         COEF(I,1,1,1,1,1) = 0
 59   CONTINUE
C
C     THIS GETS THE FACTORIAL TABLES INTO CORE.
C
      CALL DUMMY2                                                       23790   
C
C     THE OUTER LOOPS ARE OVER THE JP'S AND JT'S.
C     THE ACTUAL LOOP PARAMETERS, KOFS AND KOFPS, ARE POINTERS
C     TO THE FIRST F WITH A GIVEN JP,JT COMBINATION.
C
      KOFE = 0
 100  KOFS = KOFE + 1
      KOFE = KOFS
      IF ( KOFS .GT. NSPL )  RETURN
      IF ( ITOC(4,KOFS) .LT. 0 )  GO TO 100                             23800   
      JT = ITOC(4,KOFS)
      JP = ITOC(3,KOFS)
      LXMN = ITOC(2,KOFS)
C
C     SEARCH FOR THE LAST ELEMENT WITH THIS JP,JT.
C
 110  KOFE = KOFE + 1
      IF ( KOFE .GT. NSPL )  GO TO 120
      IF ( ITOC(4,KOFE) .EQ. JT  .AND.  ITOC(3,KOFE) .EQ. JP )
     1   GO TO 110                                                      23810   
 120  KOFE = KOFE - 1
      LXMX = ITOC(2,KOFE)
C
C     NOW DO THE SAME FOR JP', JT'.
C
      KOFPE = 0
 150  KOFPS = KOFPE + 1
      KOFPE = KOFPS
      IF ( KOFPS .GT. NSPL )  GO TO 100
      IF ( ITOC(4,KOFPS) .LT. 0 )  GO TO 150                            23820   
      JTP = ITOC(4,KOFPS)
      JPP = ITOC(3,KOFPS)
      LXPMN = ITOC(2,KOFPS)
 160  KOFPE = KOFPE + 1
      IF ( KOFPE .GT. NSPL )  GO TO 170
      IF ( ITOC(4,KOFPE) .EQ. JTP  .AND.  ITOC(3,KOFPE) .EQ. JPP )
     1   GO TO 160
 170  KOFPE = KOFPE - 1
      LXPMX = ITOC(2,KOFPE)
C                                                                       23830   
C     THE NEXT LOOP IS OVER KT.
C
      KTMN = MAX0( IABS( KBIGA-KBIGB ), IABS( JT-JTP )/2 )
      KTMX = MIN0( KBIGA+KBIGB, (JT+JTP)/2 )
C     THIS TEST ELIMINATES JT,JT' COMBINATIONS THAT DON'T CONTRIBUTE.
      IF ( KTMN .GT. KTMX )  GO TO 150
      DO 599  KT = KTMN, KTMX
C
       QTMIN = MAX0( -KT, QBIGBS-KBIGA )
       QTMAX = MIN0( KT, KBIGB-QBIGAS )                                 23840   
       IF ( QTMIN .GT. QTMAX )  GO TO 599
C
C     CALCULATE THE FIRST 9-J ETC. IF NECESSARY.
C
       IF ( KT .EQ. KTPRV  .AND.  JTP .EQ. JTPPRV
     1   .AND.  JT .EQ. JTPRV )  GO TO 250
       C9JT = (JBIGA+1)*(JBIGB+1)*(2*KBIGA+1)*(JT+1)*(JTP+1)*(2*KT+1)
       C9JT = DSQRT( C9JT ) * WIG9J( JBIGA, JT, JBIGB,
     1   2*KBIGA, 2*KT, 2*KBIGB, JBIGA, JTP, JBIGB )
      IF (PBUGSW) write (6, 203) JT, KT, JTP, C9JT                      23850   
 203  FORMAT ( ' 9J AT 203:', 3I8, G16.6)
       KTPRV = KT
       JTPPRV = JTP
       JTPRV = JT
       IF ( C9JT .EQ. 0 )  GO TO 599
C
C     CALCULATE THE CLEBSCH'S FOR THIS KT.
C
       DO 229  IQBIGA = 1, NQBIGA
        QBIGA = IQBIGA + QBIGAS - 1                                     23860   
        DO 219  IQBIGB = 1, NQBIGB
         QBIGB = IQBIGB + QBIGBS - 1
         COET(IQBIGA,IQBIGB) = 0
         IF ( IABS( QBIGB-QBIGA ) .LE. KT )
     1      COET(IQBIGA,IQBIGB) = C9JT * CLEBSH( 2*KBIGA, 2*KT,
     2      2*QBIGA, 2*(QBIGB-QBIGA), 2*KBIGB, 2*QBIGB )
 219    CONTINUE
 229   CONTINUE
C
 250   IF ( C9JT .EQ. 0 )  GO TO 599                                    23870   
C
C     THE NEXT LOOP IS OVER KP.
C
       KPMN = MAX0( IABS( KB-KA ), IABS( JP-JPP )/2 )
       KPMX = MIN0( KB+KA, (JP+JPP)/2 )
C     THIS TEST ELIMINATES JP,JP' COMBINATIONS THAT DON'T CONTRIBUTE.
       IF ( KPMN .GT. KPMX )  GO TO 150
       DO 589  KP = KPMN, KPMX
C
        QPMIN = MAX0( -KP, QAS-KB )                                     23880   
        QPMAX = MIN0( KP, KA-QBS )
        IF ( QPMIN .GT. QPMAX )  GO TO 589
C
C     CALCULATE THE SECOND 9-J SYMBOL ETC. IF NECESSARY
C
        IF ( KP .EQ. KPPRV  .AND.  JPP .EQ. JPPPRV
     1     .AND.  JP .EQ. JPPRV )  GO TO 285
        C9JP = (JA+1)*(JB+1)*(2*KB+1)*(JP+1)*(JPP+1)
        C9JP = (2*KP+1) * DSQRT( C9JP )
     1     * WIG9J( JB, JP, JA, 2*KB, 2*KP, 2*KA, JB, JPP, JA )         23890   
      IF (PBUGSW) write (6, 253) JP, KP, JPP, C9JP
 253  FORMAT ( ' 9J AT 253:', 3I8, G16.6 )
        KPPRV = KP
        JPPPRV = JPP
        JPPRV = JP
        IF ( C9JP .EQ. 0 )  GO TO 589
C
C     ... AND THE KP CLEBSCH'S.
C
        DO 279  IQA = 1, NQA                                            23900   
         QA = IQA + QAS - 1
         DO 269  IQB = 1, NQB
          QB = IQB + QBS - 1
          COEP(IQA,IQB) = 0
          IF ( IABS( QA-QB ) .LE. KP )  COEP(IQA,IQB) = C9JP
     1       * CLEBSH( 2*KB, 2*KP, 2*QB, 2*(QA-QB), 2*KA, 2*QA )
 269     CONTINUE
 279    CONTINUE
C
 285    IF ( C9JP .EQ. 0 )  GO TO 589                                   23910   
C
C     THE  NEXT 2 LOOPS ARE OVER LX, LX'.
C     GET THE INITIAL MX, MX' FROM THE TABLE OF CONTENTS (0 OR 1).
C
        KOFFS = KOFS
        DO 579  LX = LXMN, LXMX
         MXMN = -LX
         MXZ = ( ITOC(1,KOFFS) + LX + 1 )/2
C
         KOFFPS = KOFPS                                                 23920   
         DO 569  LXP = LXPMN, LXPMX
          MXPZ = ( ITOC(1,KOFFPS) + LXP + 1 )/2
C
C     CALCULATE THE THIRD 9-J ETC. FOR ALL K.
C
          KMN = MAX0( IABS( LX-LXP ), IABS( KP-KT ), QTMIN-QPMAX )
          KMX = MIN0( LX+LXP, KP+KT )
          IF ( KMN .GT. KMX )  GO TO 565
C
          QMIN = MAX0( -KMX, QTMIN-QPMAX )                              23930   
          QMAX = MIN0( KMX, QTMAX-QPMIN )
          IF ( QMIN .GT. QMAX )  GO TO 565
          DO 319  K = KMN, KMX
           T = 2*LX + 1
           COEX(K+1) = (2*K+1) * DSQRT( T )
     1        * WIG9J( 2*LX, JP, JT, 2*K, 2*KP, 2*KT, 2*LXP, JPP, JTP )
      IF (PBUGSW) write (6, 313) KT, KP, LX, LXP, K, JP, JT, JPP, JTP,
     1    COEX(K+1)
 313  FORMAT ( ' 9J:', 9I5, G16.6 )
 319      CONTINUE                                                      23940   
C
C     THE NEXT 2 LOOPS ARE OVER MX, MX'.  THE Q SUM IS FORMAL.
C
          DO 559  MX = MXMN, LX
           KOFF = KOFFS + IABS( MX ) - MXZ
           IF ( KOFF .LT. KOFFS )  GO TO 559
           FACT = 1.
           IF ( MX .GE. 0 )  GO TO 330
           FACT = PARITY
           IF ( MOD( LX+MX, 2 ) .NE. 0 )  FACT = -FACT                  23950   
C
 330       MXPMN = MAX0( -LXP, MX+QMIN )
           MXPMX = MIN0( LXP, MX+QMAX )
           IF ( MXPMN .GT. MXPMX )  GO TO 559
           DO 549  MXP = MXPMN, MXPMX
            KOFFP = KOFFPS + IABS( MXP ) - MXPZ
            IF ( KOFFP .LT. KOFFPS )  GO TO 549
            FAC = FACT
            IF ( MXP .GE. 0 )  GO TO 350
            FAC = FAC*PARITY                                            23960   
            IF ( MOD( LXP+MXP, 2 ) .NE. 0 )  FAC = -FAC
C
 350        Q = MXP - MX
C
C     NOW CALCULATE THE K CLEBSCH FOR ALL K.
C
            KMIN = MAX0( KMN, IABS( Q ) )
            DO 389  K = KMIN, KMX
             TERMK(K+1) = FAC * COEX(K+1)
     1          * CLEBSH( 2*LX, 2*K, 2*MX, 2*Q, 2*LXP, 2*MXP )          23970   
 389        CONTINUE
C
C     THE NEXT LOOP IS OVER QP.  THE QT SUM IS FORMAL.
C     LIMITS ON Q (VIA MXP ) INSURE THAT THE LOOP IS NOT NULL.
C
            QPMN = MAX0( QPMIN, QTMIN-Q )
            QPMX = MIN0( QPMAX, QTMAX-Q )
            DO 529  QP = QPMN, QPMX
             QT = Q + QP
C                                                                       23980   
C     ACCUMULATE THE SUM OVER K (INCLUDING ONE 9-J, TWO CLEBSCH'S,
C     AND SOME STATISTICAL FACTORS).
C
             SUMK = 0
             DO 409  K = KMIN, KMX
              SUMK = SUMK + TERMK(K+1)
     1           * CLEBSH( 2*K, 2*KP, 2*Q, 2*QP, 2*KT, 2*QT )
 409         CONTINUE
C
C     THE INNERMOST 2 LOOPS ARE OVER QBIGA AND QB.                      23990   
C     LIMITS APPLIED TO QT AND QP INSURE THAT NEITHER LOOP IS NULL.
C
             QAMN = MAX0( QBIGAS, QBIGBS-QT )
             QAMX = MIN0( KBIGA, KBIGB-QT )
             QBMN = MAX0( QBS, QAS-QP )
             QBMX = MIN0( KB, KA-QP )
             DO 519  QBIGA = QAMN, QAMX
              IQBIGA = QBIGA - QBIGAS + 1
              QBIGB = QBIGA + QT
              IQBIGB = QBIGB - QBIGBS + 1                               24000   
              TERMT = SUMK * COET(IQBIGA,IQBIGB)
              IF ( TERMT .EQ. 0 )  GO TO 519
              DO 509  QB = QBMN, QBMX
               IQB = QB - QBS + 1
               QA = QB + QP
               IQA = QA - QAS + 1
               TERM = TERMT * COEP(IQA,IQB)
C
C     FINALLY, THE ANSWER:
C                                                                       24010   
               COEF(IQA,IQB,IQBIGA,IQBIGB,KOFF,KOFFP)
     1          = COEF(IQA,IQB,IQBIGA,IQBIGB,KOFF,KOFFP) + TERM
C
      IF (PBUGSW) write (6, 503) QB, QBIGA, QP, MXP, MX, IQA, IQB,
     1  KOFFP, KOFF, IQBIGA, IQBIGB, SUMK, TERMT, TERM
 503  FORMAT( ' COEF:', 11I5, 3G15.5 )
 509          CONTINUE
C     END OF QB LOOP.
C
 519         CONTINUE                                                   24020   
C     END OF QBIGA LOOP.
C
 529        CONTINUE
C     END OF QP LOOP.
C
 549       CONTINUE
C     END OF MXP LOOP.
C
 559      CONTINUE
C     END OF MX LOOP.                                                   24030   
C
C     INCREMENT KOFFPS FOR THE NEXT LXP.
C
 565      KOFFPS = KOFFPS + LXP - MXPZ + 1
 569     CONTINUE
C     END OF LXP LOOP.
C
C     INCREMENT KOFFS FOR THE NEXT LX.
C
         KOFFS = KOFFS + LX - MXZ + 1                                   24040   
 579    CONTINUE
C     END OF LX LOOP.
C
 589   CONTINUE
C     END OF KP LOOP.
C
 599  CONTINUE
C     END OF KT LOOP.
C
C     GO BACK FOR THE NEXT JP', JT'.                                    24050   
C
      GO TO 150
      END
C*ID* NXINT    C109.PTOLEMY.SOURCE                          PER701  12:
      SUBROUTINE NXINT(INTARG,*,*,*)                                    cnd
CDC      SUBROUTINE NXINT ( INTARG, VALARG ),
CDC     1  RETURNS( IRTRN1, IRTRN2, IRTRN3, IRTRN4 )
C
C     THE INPUT INTERFACE
C                                                                       24060   
C     ABNORMAL RETURNS ARE
C     1)  WRONG TYPE OF FIELD ENCOUNTERED.
C     2)  SEMICOLON ENCOUNTERED.
C     3)  OTHER SPECIAL CHARACTER ENCOUNTERED.
C     FOR TYPES 1) AND 3) THE SAME FIELD WILL BE RESCANED FOR THE
C     NEXT CALL TO ONE OF THESE ENTRES.  FOR TYPE 2) THE ; IS
C     NOT RESCANNED.
C
C
C  THIS ROUTINE IS ADOPTED FROM ONE WITH SAME NAME WRITTEN BY           24070   
C  STAN COHEN FOR THE ARGONNE SHELL MODEL PROGRAMS
C
C     5/7/75 - EXTENSIVE CHANGES FOR PTOLEMY - S. PIEPER
C     5/21/75 - SMALL FIXES TO ABOVE.
C    8/15/75 - NEW ENTRY FITKEY,NXVALF ADDED  D.G.
C     12/28/79 - STANDARD MORTRAN - RPG
C     1/11/80 - SEPARATE CVALU ARGUMENT TO MSCAN - RPG
C     1/16/80 - INT, VAL, CVALU ARE LOCAL VARIABLES, AND INTARG, VALARG,
C        CVARG ARE ARGUMENTS - RPG
C     3/15/80 - PUT IN MARK'S FIX OF USING () AS TOKENS - S.P.          24080   
C               ALSO PUT IN MARK'S IMPROVED TEST FOR INTEGERS - S.P.
C     5/30/80 - FIX VALARG IN CDC SUBROUTINE LINE - S.P.
C     12/7/80 - FITKEY SETS UP RESCAN FOR 4TH RETURN - S.P.
C     6/10/83 - CVARG IS INT ON CDC - THIS MUST HAVE BEEN LOST - S.P.
C     6/13/83 - REALLY THE ARGUMENT IS INTARG - S.P.
C     9/10/85 - USE 80 COLUMNS EXCEPT ON IBM
C
      implicit real*8 ( a-h, o-z )                                      implicit
C
      parameter ( ibufsize = 200 )                                      /inpbuf/
      CHARACTER*1 IBUF(ibufsize)
      COMMON /INPBUF/ NOCH, INCH, IBUF
 
C
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
C
CDC%'CVARG' = 'INTARG' ;;;;;
C
      CHARACTER*1  STOP, SLASH / '/' /,  PLUS / '+' /,  MINUS /'-'/
      CHARACTER*8  CVALU, CVARG
      CHARACTER*1  IBUFN(1)
      DATA KEYEX / 11 /
C                                                                       24100   
C
c
C
C     THE SCANNER
C
C     AN INTEGER HAS BEEN REQUESTED - WE ACCEPT ANYTHING THAT IS EQUAL
C     TO ITS INTEGER PART.
C
      KEY=2
      GO TO 50                                                          24110   
  200 IF ( ICD .NE. -2  .AND.  ICD .NE. -5 )  GO TO 2000
      IF ( VAL .NE. INT )  GO TO 2000
C     DO NOT ACCEPT HALF-INTEGERS
      IF ( STOP .EQ. SLASH )  GO TO 2000
      INTARG = INT
      RETURN
C
C
C     GET NEXT FIELD
C                                                                       24120   
 50   INCHST = INCH
      CALL MSCAN( KEYEX, ICD, CVALU, VAL, INT, IBUFN, IMESS, STOP )
      IF ( ICD .NE. -8 )  GO TO 100
C
C     TIME TO READ A NEW CARD AND THEN TRY AGAIN
C
      READ (5, 63) IBUF
 63   FORMAT (200A1)
      do  noch = ibufsize, 1, -1
         if ( ibuf(noch) .ne. ' ' ) go to 70                            24130   
      enddo
      noch = 1
c
 70   INCH = 1
      IF ( IECHO .NE. 0 )  write (6, 73) ( IBUF(I), I = 1, noch )
 73   FORMAT( '0INPUT... ', 200A1 )
      GO TO 50
C
 100  IF ( ICD .EQ. 0 )  GO TO 50
      GO TO (810, 200, 300, 550, 500, 310, 2000, 800, 2000, 860), KEY   24140   
C
C
C
C
C
C
      ENTRY NXVAL(VALARG,*,*,*)
      KEY=3
      GO TO 50
 300  IF ( ICD .NE. -2  .AND.  ICD .NE. -5 )  GO TO 2000                24150   
C     DO NOT ACCEPT HALF-INTEGERS
      IF ( STOP .EQ. SLASH )  GO TO 2000
      VALARG = VAL
      RETURN
C
C
C
      ENTRY NXVALF(VALARG,*,*,*,*)
      KEY=6
      KEYEX=12                                                          24160   
      GO TO 50
310   KEYEX = 11
      IF(ICD.EQ.11)RETURN 4
      GO TO 300
C
C
C
C
C
C     J OR JP VALUES:  FORMS ARE  5 , 5+ , 5- , 5/2 , 5/2+ , 5/2-       24170   
C       THE OPTIONAL PARITY SIGN IS IGNORED.
C
      ENTRY NXHINT(INTARG,*,*,*)
      KEY=5
      GO TO 50
  500 IF (ICD.NE.-5)GO TO 2000
      INTARG = INT*2
      IF ( STOP .NE. SLASH )  GO TO 570
      IINT = INTARG/2
      INTARG = IINT                                                     24180   
      INCH = INCH + 1
      KEY = 4
      GO TO 50
 550  IF ( ICD .NE. -5  .OR.  INT .NE. 2 )  GO TO 2050
      INTARG = IINT
C     SKIP TRAILING SIGN
 570  IF ( STOP .EQ. PLUS  .OR.  STOP .EQ. MINUS )  INCH = INCH+1
      RETURN
C
C                                                                       24190   
C
C
C
C
      ENTRY NXWORD(CVARG,*,*,*)
      KEY=8
      GO TO 50
  800 IF(ICD.NE.-1)GO TO 2000
      CVARG = CVALU
      RETURN                                                            24200   
C
C
C
      ENTRY FITKEY(CVARG,*,*,*,*)
C
C     RETURNS ARE
C       NORMAL - KEYWORD WAS FOUND.
C       1 - (      2 - =      3 - )    FOUND; NO RESCAN
C       4 - ANYTHING ELSE FOUND - WILL BE RESCANNED.
C                                                                       24210   
      KEY=1
      KEYEX=12
      GO TO 50
810   KEYEX = 11
      CVARG = CVALU
      IF(ICD.EQ.-1)RETURN
      IF(ICD.EQ.10)RETURN 1
      IF(ICD.EQ.11)RETURN 3
      IF(ICD.EQ.12)RETURN 2
      INCH = INCHST                                                     24220   
      RETURN 4
C
C
CCCC      ENTRY NXFLD(INTARG)
CCCC      KEY=10
CCCC      GO TO 50
  860 INTARG = ICD
      RETURN
C
C                                                                       24230   
C     NOT FOUND; RESCAN SAME FIELD NEXT TIME.
C
 2000 IF (ICD.EQ.5) RETURN 2
      INCH = INCHST
      IF (ICD.LT.0) RETURN 1
      RETURN 3
C
2050  WRITE(6,5004) INT
5004  FORMAT('0**** NUMBER FOLLOWING / MUST BE 2', I10 )
      RETURN 1                                                          24240   
C
C
C
C     FORCE NEW CARD OR GET STARTED.
C
      ENTRY NEWCD
C
      NOCH = 0
      INCH = NOCH + 1
      RETURN                                                            24250   
C
      END
C*ID* PARAM    C109.PTOLEMY.SOURCE                          PER701  17:
      SUBROUTINE PARAM ( IRET )
C
C     SETS UP CANNED PACKAGES OF PARAMETERS
C
C     2/20/75 - MADE FROM CONTRL AND DEFALT - S.P.
C     3/5/75 - FIX BUG IN DVRS1W1
C     4/17/75 - NEW COMMONS                                             24260   
C     5/30/75 - FIX ERROR MESSAGE.
C     6/14/75 - FIRST SETS OF INTEGRATION PARAMETERS
C     6/27/75 - STEPSPER ADDED
C     7/28/75 - ALL MIDMULT'S ARE 1.
C     8/28/75 - LMAXTMULT, LMINMULT, NO MIDMULT
C     9/25/75 - NEW DWCUTOFF; REMOVE VCUTOFF
C     9/30/75 - LMAXMULT BECOMES LMAXADD
C     2/16/76 - FIX /INTGER/ COMMON BLOCK
C     2/29/76 - REDUCE LARGE ASYMPTOPIA VALUES IN PB SERIES
C     6/19/76 - REMOVE DEVRIES; STUFF FOR POINTS PER.                   24270   
C     8/11/76 - SMALL GRIDS FOR INTERPOLATION
C     10/3/76 - MORE SMALL GRIDS
C     1/12/76 - INELASTIC PARAMETER SETS
C     5/9/77 - LMINSUB, LMAXADD; ELASTIC PARAMS
C     11/22/77 - FIX ALMXMT ERROR; SPLIT ASYMPTOPIAS - S.P.
C     3/19/78 - ALPHA SETS - S.P.
C     4/20/78 - HUGH MAXLEX FOR INELASTIC SETS - S.P.
C     12/28/79 - STANDARD MORTRAN - RPG
C     1/16/80 - MOVE CFR%F DOWN; CHARACTER*8 DATANM - RPG
C     2/28/80 - PARAMETERSETS DPSA, DPDA, DPSB, DPDB; ADD PHIMID,       24280   
C        MIDMULT - RPG
C     3/20/80 - SET ACCURACY FOR INELASTIC SETS - S.P.
C     6/28/81 - POWER EXTRAPOLATION FOR INELASTIC SETS - S.P.
C     10/16/84 - DEFAULTS FOR SCTASY ARE < 0 - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
C                                                                       24290   
      CHARACTER*8 DATANM
C
      DATA NUMDAT / 16 /
      CHARACTER*8  DATAS(16)
      DATA  DATAS /
     1  'CA60A', 'CA60B', 'PB100A', 'PB100B', 'PB100C',
     2  'PBO1A', 'PBO1B', 'PBO1C', 'PBO1D',
     3  'ALPHA1', 'ALPHA2', 'ALPHA3',
     4  'DPSA', 'DPDA', 'DPSB', 'DPDB'  /
      INTEGER  DATNUM(16) /                                             24300   
     1  1, 2, 3, 4, 5,
     2  3, 4, 5, 6,
     3  7, 8, 9,
     4  10, 11, 12, 13 /
C
C     FOLLOWING ARE THE GRID PARAMETERS
C     EACH ROW CORRESPONDS TO A DIFFERENT DATA WORD
C
C     FIRST THE REAL VALUES
C     THEY ARE IN THE ORDER                                             24310   
C      DWCUT, SUMPOINT, STPSPR, GAMSUM, GAMDIF, BNDASY, ALMNMT, ALMXMT,
C      SCTASY, PHIMID, MIDMULT
C
      REAL*8  RGRIDS(11,13) /
     1  1.D-2, 6.D0, 12.D0, 5.D0, 5.D0, 20.D0, .60D0, 1.50D0, 15.D0,
     1   .50D0, 2.D0,
     2  1.D-3, 6.D0, 20.D0, 5.D0, 5.D0, 25.D0, .50D0, 1.70D0, 20.D0,
     2   .50D0, 2.D0,
     3  1.D-3, 2.50D0, 8.D0,  1.D-2, 3.D0, 45.D0, .86D0, 1.60D0, 20.D0,
     3   .50D0, 2.D0,                                                   24320   
     4  3.D-4, 3.00D0, 12.D0, 1.D-2, 3.D0, 50.D0, .78D0, 1.80D0, 23.D0,
     4   .50D0, 2.D0,
     5  1.D-4, 3.50D0, 16.D0, 1.D-2, 3.D0, 55.D0, .70D0, 2.00D0, 26.D0,
     5   .50D0, 2.D0,
     6  1.D-5, 4.00D0, 20.D0, 1.D-2, 3.D0, 60.D0, .60D0, 2.20D0, 30.D0,
     6   .50D0, 2.D0,
     7  1.D-3, 6.00D0, 12.D0, 3.D0,  5.D0, 20.D0, .60D0, 1.50D0, 15.D0,
     7   .50D0, 2.D0,
     8  1.D-4, 7.00D0, 20.D0, 3.D0,  5.D0, 25.D0, .50D0, 1.70D0, 20.D0,
     8   .50D0, 2.D0,                                                   24330   
     9  1.D-5, 8.00D0, 25.D0, 3.D0,  5.D0, 30.D0, .40D0, 2.00D0, 24.D0,
     9   .50D0, 2.D0,
     A  2.D-5, 6.00D0, 5.D0, 2.D0, 12.D0, 20.D0, 0.0D0, 1.60D0, 20.D0,
     A   .20D0, .90D0,
     B  2.D-6, 6.00D0, 5.D0, 2.D0, 20.D0, 20.D0, 0.0D0, 1.60D0, 20.D0,
     B   .15D0, .90D0,
     C  2.D-6, 8.00D0, 8.D0, 2.D0, 12.D0, 20.D0, 0.0D0, 2.00D0, 20.D0,
     C   .20D0, .90D0,
     D  5.D-7, 8.00D0, 8.D0, 2.D0, 20.D0, 20.D0, 0.0D0, 2.00D0, 20.D0,
     D   .15D0, .90D0 /                                                 24340   
C
C     NEXT THE INTEGERS.  THEY ARE IN THE ORDER
C       NPSUM, NPDIF, NPPHI, NPHIAD, LSTEP, LMAXAD, LMINSB
C
      INTEGER  IGRIDS(7,13) /
     1  10, 10, 10, 4, 3, 15, 10,
     2  15, 13, 12, 4, 2, 20, 15,
     3  10,  8, 10, 4, 5, 30, 12,
     4  15, 10, 12, 4, 4, 35, 16,
     5  20, 14, 16, 4, 3, 40, 20,                                       24350   
     6  30, 18, 20, 4, 2, 45, 25,
     7  40, 25, 12, 4, 2, 15, 10,
     8  50, 30, 14, 4, 1, 20, 15,
     9  70, 35, 16, 4, 1, 25, 20,
     A  20, 20, 10, 4, 1, 10,  8,
     B  20, 30, 15, 4, 1, 10,  8,
     C  40, 40, 20, 4, 1, 12, 10,
     D  40, 60, 30, 4, 1, 12, 10  /
C
C                                                                       24360   
C     FOLLOWING ARE FOR INELASTIC SCATTERING
C
      DATA NUMINL / 3 /
      CHARACTER*8 DATINL(3) / 'INELOCA1', 'INELOCA2', 'INELOCA3' /
C
C     INELASACC, DWCUTOFF, STEPSPER, SUMPOINT, SCTASYMPT,
C     ALMXMT, ACCURACY
C
      REAL*8  GRIDIN(7,3) /
     1  1.D-3, 1.D-3, 15.D0,  6.D0, 20.D0, 1.60D0, 1.D-2,               24370   
     2  1.D-4, 1.D-4, 20.D0,  8.D0, 25.D0, 2.00D0, 5.D-3,
     3  1.D-6, 1.D-5, 25.D0, 12.D0, 30.D0, 2.60D0, 1.D-3
     4   /
C
C     LMAXADD, NPCOULOMB
C
      INTEGER  IGRIDI(2,3) /
     1  20,  6,
     2  30,  8,
     3  50,  10   /                                                     24380   
C
C     FOLLOWING ARE FOR ELASTIC SCATTERING
C
      DATA NUMEL /3/
      CHARACTER*8  DATEL(3) / 'EL1', 'EL2', 'EL3' /
C
C     STEPSPER, SCTASYMPT, ALMNMT, ALMXMT, FITACC
C
      REAL*8  GRIDEL(5,3) /
     1  12.D0,  15.D0,  .70D0,  1.60D0,  2.D-3,                         24390   
     2  15.D0,  20.D0,  .60D0,  1.80D0,  2.D-4,
     3  20.D0,  25.D0,  .50D0,  2.00D0,  2.D-5  /
C
C     LMINSB, LMAXAD
C
      INTEGER  IGRIDE(2,3) /
     1  15,  15,
     2  20,  20,
     3  25,  25  /
C                                                                       24400   
c
C
      IRET = 0
      CALL NXWORD ( DATANM, *80, *80, *80 )
      DO 59  N = 1, NUMDAT
         IF ( DATANM .EQ. DATAS(N) )  GO TO 100
 59   CONTINUE
C
      DO 64  N = 1, NUMINL
         IF ( DATANM .EQ. DATINL(N) )  GO TO 400                        24410   
 64   CONTINUE
      DO 69  N = 1, NUMEL
         IF ( DATANM .EQ. DATEL(N) )  GO TO 500
 69   CONTINUE
C
C
      write (6, 73) DATANM, DATAS, DATINL, DATEL
 73   FORMAT ( '0**** INVALID DATA NAME: ', A8,
     1  '.  ALLOWABLE DATA NAMES ARE:' /
     2  ( 2X, 7A10 ) )                                                  24420   
      RETURN
 80   write (6, 83)
 83   FORMAT ( '0**** DATA MUST BE FOLLOWED BY A DATA NAME' )
      RETURN
C
C     TRANSFER GRID WORDS
C
 100  IRET = 1
      I = DATNUM(N)
C                                                                       24430   
C
 210  DWCUT  = RGRIDS(1,I)
      SUMPTS = RGRIDS(2,I)
      STPSPR = RGRIDS(3,I)
      GAMSUM = RGRIDS(4,I)
      GAMDIF = RGRIDS(5,I)
      BNDASY = RGRIDS(6,I)
      ALMNMT = RGRIDS(7,I)
      ALMXMT = RGRIDS(8,I)
      SCTASY = -RGRIDS(9,I)                                             24440   
      PHIMID = RGRIDS(10,I)
      AMDMLT = RGRIDS(11,I)
C
      NPSUM  = IGRIDS(1,I)
      NPDIF  = IGRIDS(2,I)
      NPPHI  = IGRIDS(3,I)
      NPHIAD = IGRIDS(4,I)
      LSTEP  = IGRIDS(5,I)
      LMAXAD = IGRIDS(6,I)
      LMINSB = IGRIDS(7,I)                                              24450   
C
      RETURN
C
C     INELASTIC PAAMETERS
C
 400  ALMNMT = 0
      GAMSUM = 5
      LSTEP = 1
      MAXLEX = 5000
      IEXTYP = 2                                                        24460   
      ACCINE = GRIDIN(1,N)
      DWCUT  = GRIDIN(2,N)
      STPSPR = GRIDIN(3,N)
      SUMPTS = GRIDIN(4,N)
      SCTASY = -GRIDIN(5,N)
      ALMXMT = GRIDIN(6,N)
      ACCURA = GRIDIN(7,N)
      LMAXAD = IGRIDI(1,N)
      NPCOUL = IGRIDI(2,N)
C                                                                       24470   
      IRET = 1
      RETURN
C
C     ELASTIC PARAMETERS
C
 500  STPSPR = GRIDEL(1,N)
      SCTASY = -GRIDEL(2,N)
      ALMNMT = GRIDEL(3,N)
      ALMXMT = GRIDEL(4,N)
      FITACC = GRIDEL(5,N)                                              24480   
      LMINSB = IGRIDE(1,N)
      LMAXAD = IGRIDE(2,N)
      IRET = 1
      RETURN
C
      END
C*ID* PARPRT   C109.PTOLEMY.SOURCE                          PER701  14:
      SUBROUTINE PARPRT ( I, NAME, VPAR, RPAR, APAR, RPAR0,
     1  P5, P5NAME, IRET )
C                                                                       24490   
C     PRINTS PARAMETERS OF ONE POTENTIAL TERM.
C
C     I = TERM NUMBER (INDEX IN LNKADR) (0 IF NO LINKULE POSSIBLE).
C     NAME = 18-CHARACTER LABEL FOR TERM, RIGHT JUSTIFIED.
C     VPAR = COUPLING CONSTANT.
C     RPAR = RADIUS.
C     APAR = DIFFUSENESS.
C     RPAR0 = RADIUS PARAMETER.
C     P5 = OPTIONAL PARAMETER, PRINTED IF NONZERO.
C     P5NAME = 8-CHARACTER LABEL FOR FIFTH PARAMETER, RIGHT JUSTIFIED.  24500   
C     IRET = ERROR FLAG, SET TO 0 IF ERROR OCCURS IN LINKULE.
C     * = ERROR RETURN, IF IFLG < 0 FROM LINKULE.
C
C     IF A LINKULE EXISTS, IT IS CALLED TO PRINT STUFF ABOUT ITSELF.
C     OTHERWISE, THE USUAL PARAMETERS ARE PRINTED INSTEAD.
C
C     12/12/78 - FIRST VERSION - RPG
C     6/3/80 - CDC VERSION, NO RETURNS, CHANGE IRET FOR ERR - S.P.
C     7/14/80 - USE CHAR*8 FOR BETTER GENERALITY - S.P.
C     7/21/81 - REMOVE UNDEFINED STEPSIZE, NUMBER OF STEPS - S.P.       24510   
C     6/13/83 - NAME(2) FOR CDC, (3) FOR OTHERS - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
c                                                                       /lnkblk/
c  STRUCTURE OF   /LNKBLK/
c
c  THERE IS A BLOCK OF 3 DOUBLE WORDS FOR EACH POSSIBLE USE
c  OF A LINKULE.  THE NUMLNK = NUMLINKULES USES ARE IN THE ORDER
c    REALPOTEN  IMAGPOTEN  REALVSO  IMAGVSO  COULOMB
c    WAVEFUNCTION  AND 6 TENSOR POTENTIALS
c  THE THREE-DOUBLE-WORD BLOCKS EACH HAVE THE STRUCTURE
c
c    LNKNAM(1,I)   LINKULE NAME
c
c      LNKADR(3,I)   LINKULE ADDRESS, O IF NO LINKULE IN USE.
c      LNKADR(4,I)   0 - NO L OR J DEPENDENCE IN POTENTIAL
c                    1 - L DEPENDENCE BUT NO J DEPENDENCE
c                    2 - BOTH L  AND J DEPENDENCE
c
c      LNKADR(5&6,I)  MYINTS - A TWO-ELEMENT ARRAY THAT THE
c                     LINKULE MAY USE FOR COMMUNICATION BETWEEN
c                     CALLS TO ITSELF.
c
      parameter ( NUMLINKULES = 13 )
      COMMON /LNKBLK/  NUMLNK, IUNIQU, LNKADR(6,NUMLINKULES)
      character*8  LNKNAM(3,NUMLINKULES)
      EQUIVALENCE ( LNKNAM(1,1), LNKADR(1,1) )
 
C
      CHARACTER*(*)  NAME
      CHARACTER*8  P5NAME
C
C     IF A LINKULE EXISTS, CALL IT TO PRINT STUFF ABOUT ITSELF.         24520   
C
      IF ( I .LE. 0 ) GO TO 100
      IF ( LNKADR(3,I) .EQ. 0 ) GO TO 100
      write (6, 53) trim(NAME), LNKNAM(1,I)
 53   FORMAT ( '0', a, ' POTENTIAL IS BEING COMPUTED BY THE ',
     1  A8, ' LINKULE:' )
C
C     NOTE IN THIS CALL TO THE LINKULE WE DO NOT PASS CORRECT VALUES
C     FOR THE STEPSIZE AND NUMBER OF STEPS.
C                                                                       24530   
      CALL LINKUL ( LNKADR(3,I), LNKNAM(1,I), LNKADR(5,I),
     1  I, 2, IRTN,
     2  L, JP, 0.D0, 0.0D0, 0, DUMMY, DUMMY, ICHANW )
      write (6, 63)
 63   FORMAT ( ' ' )
      IF (IRTN .GE. 0 ) RETURN
      IRET = -1
      RETURN
C
C     NO LINKULE.  PRINT 4 OR 5 PARAMETERS, IF VPAR IS NONZERO.         24540   
C
 100  IF ( VPAR .NE. 0 )  GO TO 110
      IF ( I .NE. 3  .AND.  I .NE. 4 )  RETURN
      IF ( P5 .EQ. 0 )  RETURN
 110  IF ( P5 .NE. 0 ) GO TO 120
      write (6, 113) NAME, VPAR, RPAR, APAR, RPAR0
 113  FORMAT ( ' ', a18, G14.5, T37, F7.4, T49, F7.4, T67, F7.4,
     1  5X, A8, ' =', G13.5 )
      RETURN
 120  write (6, 113) NAME, VPAR, RPAR, APAR, RPAR0, P5NAME, P5          24550   
      RETURN
      END
C*ID* PHSPRT   C109.PTOLEMY.SOURCE                          PER701  14:
      SUBROUTINE PHSPRT ( PRNTSW )
C
C     TABULATE THE MAGNITUDES AND PHASES OF THE S-MATRICES.
C
C     THIS ROUTINE IS CALLED BY XSECTN PRIOR TO THE COMPUTATION OF
C     THE CROSS SECTIONS.  IT COMPUTES AND STORES THE MAGNITUDES
C     AND PHASES OF THE REACTION AND ELASTIC S-MATRICES.                24560   
C     ALL PHASES ARE "SMOOTHED" AND GO TO 0 FOR LARGE L.
C       IF REQUESTED, THE PARTIAL WAVE MAGNITUDES AND PHASES ARE
C     PRINTED.
C
C     6/2/75 - FIRST VERSION - S. PIEPER
C     1/11/77 - MODS FOR INELASTIC SCATTERING
C     5/5/77 - IDENTICAL PARTICLES
C     6/22/77 - DEFINE ALL OF IMAG AND IPHASE
C     7/22/77 - FIX BUG INTRODUCED 6/22/77
C     4/25/78 - REVERSE LI AND LO - S.P.                                24570   
C     4/26/78 - ONE COMPLEX I ARRAY WITHOUT COULOMB PHASES - S.P.
C     3/6/79 - S-MATRICES AND UNITARITY - S.P.
C     4/12/79 - OUT IS IN FOR COUPLED - S.P.
C     8/8/79 -  MAJOR RE-WRITE FOR SPIN-ORBIT ETC. - RPG
C     11/20/79 - S-MATRICES STORED BY LO-LI - S.P.
C     4/1/80 - C.C. VERSION; REAL*4 S-MATRICES - S.P.
C     4/7/80 - OUTPUT 5 REACTION S-MATRICES PER LINE - S.P.
C     10/12/81 - FIX BUG IN OPTICAL S; SEVERAL BLOCKS/PAGE - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
C
      LOGICAL PRNTSW
C
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      CHARACTER*1  REACT, HEADER                                        /hedcom/
      COMMON /HEDCOM/  REACT(45), HEADER(65)
 
      COMMON /KANDM/ AKI, AKO, REDMI, REDMO, RIMAX, ROMAX, ISIGS(2),    /kandm/
     &  RSCTS(2), ASCTS(2), RCSCTS(2) ,ISMATS(2), LOMOST, LCRIT,
     &  ISCTMN, ISCTCR, ETAS(2), RCSCTP(2), RCSCTT(2), LCRITS(2),
     &  RATMSS(2), QMIN, ABAR
 
      DIMENSION  AKS(2), REDMS(2), RMAXS(2)
      EQUIVALENCE ( AKI, AKS(1) ), ( REDMI, REDMS(1) ),
     &  ( RIMAX, RMAXS(1) )
 
c                                                                       /formf/
c ***  LNKADB was  numLINKULES but only 12 are used ???
c
      COMMON /FORMF/  IBDS(2), NPOTS(2), LBP, LBT, NBP, NBT, JBP, JBT,
     &  BNDMAX(2), BNDSTP(2), NSTPBD(2), RBNDS(2), ABNDS(2),
     &  RCBNDS(2), BNDMAS(2), BRATMS(2), RSOBDS(2), ASOBDS(2),
     &  VBNDS(2), VSOBDS(2), TAUBDS(2), LNKADB(6, 2, 12)
 
      LOGICAL ONELSW, IDENSW                                            /inelcm/
      COMMON /INELCM/  JBPF, JBTF, LXMIN, LXMAX, ILILOR, ILILOI, MSTOP,
     &  IA12M, NMLOLX, ONELSW, NUMLX, IRDINT, IELCUP, LILOSZ, NUMLIS,
     &  ILIS, IBETAS(3), ICL2FF, LXSTEP, IDENSW, LSKIP,
     &  JPMIN, JPMAX, JPBASE, NJP, JTMIN, JTMAX, JTBASE, NJT,
     &  IINDXS, ISMATR, ISMATI, NSMAT, NLX, NSPLI, ITOCS,
     &  NASPLI, IUNITR, LIFIT, ILIFIT, NOLFIT, IDELSR, IDELSI
      INTEGER INDXJS(4,2)
      EQUIVALENCE ( INDXJS(1,1), JPMIN )
 
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
      COMMON /CCBLK/  ICHNDF, ICHNCP, ITRANS, IBASDF, IBASCP,           /ccblk/
     &    ICCBLK(2), IORDX, MCHNVL, ICHNVL,
     &    IHOMOA, IHOMOB, IINHR8, IINHI8
 
C
C
      DIMENSION ISMG(3), ISPH(3)
      LOGICAL ELSW, CCSW, PBUGSW, TOPSW
      CHARACTER*8  WORDS(3,2), MAGNAM(3), PHSNAM(3)                     24600   
C
C
      DATA  WORDS  / 'COUPLED ', 'INCOMING', ' OPTICAL' ,
     1   'ELASTIC ', 'OUTGOING', ' ELASTIC' /
      DATA MAGNAM / 'SMAG    ', 'SINMAG  ', 'SOUTMAG ' /
      DATA PHSNAM / 'SPHASE  ', 'SINPHASE', 'SOUTPHAS' /
C
      DIMENSION  JTTS(5), JTPS(5), LXS(5), LDELS(5), DMAGS(5), PHASES(5)
      DIMENSION KOFFSS(5)
C                                                                       24610   
C
CIB      DATA  SUBHAF / Z 407FFFFF FFFFFFFF /
      DATA SUBHAF /.4999999990D0 /                                      cni
C
      CHARACTER*1  BLANK/' '/
c
C
      DMODPI(X) = X - 2*PI*DINT( X/(2*PI) + DSIGN( SUBHAF, X ) )
      UNMOD(X, Y) = X + DMODPI( Y-X )
C                                                                       24620   
      CCSW = PROBLM .EQ. 24
      PBUGSW = MOD(IPRINT,10) .GE. 4
C
      IELUNI = NALLOC( LMAX+1, 'ELUNITAR' )
      CALL INIT8 ( IELUNI, 0.D0 )
C
C     THIS FIRST LOOP IS OVER THE "PSEUDO-CHANNEL" - REACTION,
C     INCOMING ELASTIC, AND OUTGOING ELASTIC.
C     FOR ICH=1 WE PROCESS ALL REACTION CHANNELS.
C                                                                       24630   
      DO 399  ICH = 1, 3
         ELSW = ICH .GT. 1
         ASSIGN 369 TO JGOTO
C
C     ALLOCATE SPACE TO STORE THE MAGNITUDES AND PHASES
C
         N = (LILOSZ+FACFR4-1)/FACFR4
         IF ( ELSW )  N = (NUMJS(ICH-1)*(LMAX+1)+FACFR4-1)/FACFR4
         ISMG(ICH) = NALLOC ( N, MAGNAM(ICH) )
         ISPH(ICH) = NALLOC ( N, PHSNAM(ICH) )                          24640   
         CALL INIT8 ( ISMG(ICH), 0.D0 )
         CALL INIT8 ( ISPH(ICH), 0.D0 )
C
         LMAG = FACFR4*(Z(ISMG(ICH)) - 1)
         LPHASE = FACFR4*(Z(ISPH(ICH)) - 1)
         LELUNI = Z(IELUNI)
         NUMCHN = 2
C
         IF ( ELSW )  GO TO 150
C                                                                       24650   
C     POINTERS FOR REACTION.
C
         NPLI = NSPLI
         LS = FACFR4*(Z(IRDINT) - 1)
         ASSIGN 310 TO IGOTO
         LTOCS = Z(ITOCS)*FACFR4 - FACFR4
         LLAST = LIMOST
         LBASE = LMIN
         PHSMUL = 1.
         NCHNDF = 2                                                     24660   
         IF ( .NOT. CCSW )  GO TO 160
C
C     SETUP TO DO COUPLED CHANNELS
C
         LCHNDF = FACFR4*(Z(ICHNDF)-1) + 1
         NCHNDF = ILLOC(LCHNDF)
         MCHNDF = ILLOC(LCHNDF+1)
         LCHNDF = LCHNDF + ILLOC(LCHNDF+2) + MCHNDF
         LTOCSV = LTOCS
         NUMCHN = NCHNDF                                                24670   
         LSSAVE = LS
         LMAGSV = LMAG
         LPHASV = LPHASE
         GO TO 160
C
C     POINTERS FOR ELASTIC SCATTERING.
 150     LS = Z(ISMATS(ICH-1)) - 1
         ASSIGN 315 TO IGOTO
         IF ( ICH .EQ. 2 )  ASSIGN 350 TO JGOTO
         IPROB = ICH-1                                                  24680   
         IF ( PROBLM .GE. 23 )  IPROB = 1
         LTOCS = Z(ITOCE(IPROB))*FACFR4 - FACFR4
         NPLI = NUMJS(IPROB)
         LLAST = LMAX
         LBASE = 0
         PHSMUL = 0.5
C
C
C     COMPUTE THE PARTIAL WAVE MAGNITUDES AND SMOOTHED PHASE SHIFTS
C                                                                       24690   
C     THE PHASES FOR LO = LMAX ARE SET AS CLOSE TO 0 AS IS POSSIBLE.
C     THE OTHERS ARE THEN MADE CONTINUOUS WITH THIS STARTING POINT.
C
C
C     LOOP OVER ALL REACTION CHANNELS FOR ICH=1
 160     DO 389  NCHN = 2, NUMCHN
            IF ( ELSW .OR.  .NOT. CCSW )  GO TO 180
            NPLI = ILLOC(LCHNDF+10)
            LTOCS = LTOCSV + ILLOC(LCHNDF+12)
            LSOFF = ILLOC(LCHNDF+13)                                    24700   
            LS = LSSAVE + 2*LSOFF
            LMAG = LMAGSV + LSOFF
            LPHASE = LPHASV + LSOFF
            LLAST = ILLOC(LCHNDF+14)
C
C
C        LOOP THROUGH JT, JP, LX, AND LI-LO.  SKIP UNUSED ELEMENTS.
C
 180        DO 379  KOFFS = 1, NPLI
               JTT = ILLOC(LTOCS+4*KOFFS)                               24710   
               IF ( PBUGSW )
     1           write (6, 183) ICH, ELSW, LMAG, LPHASE, NPLI, LS,
     1              LTOCS, LLAST, LBASE, LMIN, JTT
 183           FORMAT ('0PHSPRT:', I10, L3, 12I10 )
               IF ( JTT .LT. 0 )  GO TO 379
               PHASE = 0
               PHASP = 0
C
C           LOOP THROUGH LI, BACKWARD.
C           THIS WILL WORK FOR IDENTICAL PRTICLES IN EITHER CHANNEL,    24720   
C           EVEN THOUGH LSKIP IS IGNORED.
C
               DO 369  LLI = LMIN, LLAST
                  LI = LLAST + LMIN - LLI
                  I = (LI-LBASE)*NPLI + KOFFS
                  GO TO IGOTO, ( 310, 315 )
 310              SR = ALLOC4(LS+2*I-1)
                  SI = ALLOC4(LS+2*I)
                  GO TO 320
 315              SR = ALLOC(LS+2*I-1)                                  24730   
                  SI = ALLOC(LS+2*I)
 320              ALLOC4(LMAG+I) = DSQRT(SR**2+SI**2)
                  IF ( ALLOC4(LMAG+I) .EQ. 0 )  GO TO 369
                  PHASE = DATAN2( SI, SR )
                  PHASE = UNMOD ( PHASP, PHASE )
                  PHASP = PHASE
                  ALLOC4(LPHASE+I) = PHSMUL * PHASE
                  GO TO JGOTO, ( 350, 369 )
 350              ALLOC(LELUNI+LI) = ALLOC(LELUNI+LI) + (SR**2+SI**2)
 369           CONTINUE                                                 24740   
 379        CONTINUE
            IF ( CCSW )  LCHNDF = LCHNDF+MCHNDF
 389     CONTINUE
 399  CONTINUE
C
C
C     NOW PRINT THEM IF SO REQUESTED
C
      IF ( .NOT. PRNTSW )  RETURN
C                                                                       24750   
      LTOCS = Z(ITOCS)*FACFR4 - FACFR4
      LTOCI = Z(ITOCE(1))*FACFR4 - FACFR4
      LTOCO = Z(ITOCE(IPROB))*FACFR4 - FACFR4
      LMAG = FACFR4*(Z(ISMG(1)) - 1)
      LMAGI = FACFR4*(Z(ISMG(2)) - 1)
      LMAGO = FACFR4*(Z(ISMG(3)) - 1)
      LPHASE = FACFR4*(Z(ISPH(1)) - 1)
      LPHASI = FACFR4*(Z(ISPH(2)) - 1)
      LPHASO = FACFR4*(Z(ISPH(3)) - 1)
      LSIGIN = Z(ISIGS(1))                                              24760   
      LSIGOT = Z(ISIGS(IPROB))
      LUNITR = FACFR4*(Z(IUNITR)-1) + 1 - LMIN
      LELUNI = Z(IELUNI)
C
C
C     FIRST WE PRINT THE ELASTIC S-MATRIX ELEMENTS AND UNITARITY
C
      IPROB = 2
      IF ( PROBLM .GE. 23 )  IPROB = 1
      LINECT = 100                                                      24770   
      LINES = MAX0 ( NUMJS(1), NUMJS(2) )
C
C     ADJUST LO FOR ODD PARITY.
C
      LOADD = 0
      IF ( MOD( LBP+LBT, 2 ) .NE. 0  .AND. .NOT. CCSW ) LOADD = 1
C
C     LOOP THROUGH THE INCOMING L VALUES.
C
      DO 699  LI = LMIN, LMAX, LSKIP                                    24780   
         J = 2*LI
C
C     PRINT THE HEADINGS IF NECESSARY.
C
         IF ( LINECT+LINES .LE. 58 )  GO TO 550
         write (6, 533) REACT, ELAB, HEADER
 533     FORMAT ( '1', T58, 'P T O L E M Y' /
     1     T39, 'ELASTIC PARTIAL WAVE S-MATRIX ELEMENTS AND UNITARITY' /
     2     '0', 45A1, 'ELAB =', F7.2, ' MEV', 5X, 65A1 / )
         IF (.NOT. CCSW)  write (6, 543) ( WORDS(I,IPROB), I=1,3 )      24790   
 543     FORMAT (
     4     T16, 'INCOMING ', A8, T58, 'UNITARITY', T93, 2A8 /
     6      ( 4X, 'L   L'' LX  MAGNITUDE   PHASE  COULOMB  ' ),
     7     T49, 'ELASTIC  REACTION  RESIDUAL',
     6      ( 8X, 'L   L'' LX  MAGNITUDE   PHASE  COULOMB ' ) / )
         IF (CCSW)  write (6, 548)
 548     FORMAT ( T23, 'COUPLED ELASTIC', T58, 'UNITARITY',
     1       T85, 'OPTICAL ELASTIC' /
     2      4X, 'J', 6X, 'L', 7X, '|S|', 6X, 'PHASE',
     3       2X, 'COULOMB',                                             24800   
     4       T47, '   ELASTIC  REACTION  RESIDUAL',
     5       10X, '|S|', 6X, 'PHASE' /
     6      T29, 'SHIFT', 3X, 'PHASE',  T96, 'SHIFT' / )
         TOPSW = .TRUE.
         LINECT = 9
C
 550     KI = 0
         KO = 0
         UNITAR = ALLOC4(LUNITR+LI)
         ELUNIT = ALLOC(LELUNI+LI)                                      24810   
         RESID = 1 - ELUNIT - UNITAR
         CPHASI = ALLOC(LSIGIN+LI)
         LASO = LI + LOADD
         CPHASO = ALLOC(LSIGOT+LASO)
C
C     LOOP THROUGH LO, LX, JP, JT VALUES.
C
         DO 689  KOFFS = 1, LINES
            JUMP = 0
C                                                                       24820   
C     PROCESS THE INCOMING ELASTIC INFORMATION.
C
 560        KI = KI + 1
            IF ( KI .GT. NUMJS(1) )  GO TO 580
            IADD = NUMJS(1)*LI + KI
            DMAGI = ALLOC4(LMAGI+IADD)
            IF ( DMAGI .EQ. 0 )  GO TO 560
            PHASI = ALLOC4(LPHASI+IADD)
            LXI = ILLOC(LTOCI+4*KI-2)
            LOI = LI +  ILLOC(LTOCI+4*KI-3)                             24830   
            JUMP = JUMP + 2
C
C     NOW THE OUTGOING ELASTIC INFORMATION.
C
 580        KO = KO + 1
            IF ( KO .GT. NUMJS(2) )  GO TO 590
            IADD = NUMJS(2)*LASO + KO
            DMAGO = ALLOC4(LMAGO+IADD)
            IF ( DMAGO .EQ. 0 )  GO TO 580
            PHASO = ALLOC4(LPHASO+IADD)                                 24840   
            LXO = ILLOC(LTOCO+4*KO-2)
            LOO = LASO +  ILLOC(LTOCO+4*KO-3)
            JUMP = JUMP + 1
C
C     WE HAVE 4 DIFFERENT FORMATS, DEPENDING ON HOW MUCH WE
C     HAVE TO PRINT ON THIS LINE.
C
 590        IF ( KOFFS .NE. 1 )  GO TO 600
C
C     FIRST LINE:  PRINT EVERYTHING, INCLUDING COULOMB PHASES.          24850   
C
            IF ( TOPSW )  GO TO 595
            IF ( LINES .GT. 1 )  GO TO 592
            IF ( MOD(LI,10) .NE. 0 )  GO TO 595
 592        write (6, 813)
            LINECT = LINECT+1
C
 595        IF ( .NOT. CCSW )  write (6, 597)
     1         LI, LOI, LXI, DMAGI, PHASI, CPHASI,
     1         ELUNIT, UNITAR, RESID,                                   24860   
     2         LASO, LOO, LXO, DMAGO, PHASO, CPHASO
 597        FORMAT ( 1X,
     1         2( I4, I5, I3, F10.6, 2F9.3 , 4X, 3F10.5, 5X ) )
            IF ( CCSW )  write (6, 598) J, LI, DMAGI, PHASI, CPHASI,
     1        ELUNIT, UNITAR, RESID, DMAGO, PHASO
 598        FORMAT ( 1X, I4, '/2', I5, F12.6, 2F9.3, 4X, 3F10.5, F15.6,
     1         F9.3 )
            GO TO 680
C
 600        IF ( JUMP .EQ. 0 )  GO TO 699                               24870   
            GO TO ( 610, 620, 630 ), JUMP
C
C     JUMP = 1:  OUTGOING ONLY.
 610        write (6, 613)  LASO, LOO, LXO, DMAGO, PHASO
 613        FORMAT ( T81, I4, I5, I3, F10.6, F9.3 )
            GO TO 680
C
C     JUMP = 2:  INCOMING ONLY.
 620        write (6, 623)  LI, LOI, LXI, DMAGI, PHASI
 623        FORMAT ( 1X,    I4, I5, I3, F10.6, F9.3, 48X,               24880   
     1         I4, I5, I3, F10.6, F9.3 )
            GO TO 680
C
C     JUMP = 3:  ELASTICS ONLY.
 630        write (6, 623)  LI, LOI, LXI, DMAGI, PHASI,
     1         LASO, LOO, LXO, DMAGO, PHASO
C
C
 680        LINECT = LINECT + 1
            TOPSW = .FALSE.                                             24890   
 689     CONTINUE
 699  CONTINUE
C
C
C     NOW PRINT THE REACTION S-MATRICES
C
      IF ( .NOT. CCSW )  GO TO 720
      LCHNDF = FACFR4*(Z(ICHNDF)-1) + 1
      LCHNDF = LCHNDF + ILLOC(LCHNDF+2) + MCHNDF
      LTOCSV = LTOCS                                                    24900   
      LMAGSV = LMAG
      LPHASV = LPHASE
C
 720  DO 899  NCHN = 2, NCHNDF
         MCHN = NCHN
         IF ( .NOT. CCSW )  GO TO 740
         MCHN = ILLOC(LCHNDF)
         NSPLI = ILLOC(LCHNDF+10)
         LTOCS = LTOCSV + ILLOC(LCHNDF+12)
         LSOFF = ILLOC(LCHNDF+13)                                       24910   
         LMAG = LMAGSV + LSOFF
         LPHASE = LPHASV + LSOFF
         LOADD = 0
         IPT = ISIGN( 1, ILLOC(LCHNDF+1) )
         IPP = ISIGN( 1, ILLOC(LCHNDF+3) )
         IF ( IPP*IPT .LT. 0 )  LOADD = 1
C
C     COUNT THE LINES TO BE PRINTED.  WE WILL SKIP THOSE WHICH
C     HAVEN'T BEEN CALCULATED YET.
C                                                                       24920   
 740     LINES = 0
         DO 749  KOFFS = 1, NSPLI
            IF ( ILLOC(LTOCS+4*KOFFS) .GE. 0 )  LINES = LINES + 1
 749     CONTINUE
         NSETS = (LINES+4)/5
         KF1 = 1
         DO 889  NSET = 1, NSETS
C
C     FIND THE 5 (JP, JT, LX, LO-LI) FOR THIS PRINTOUT
C                                                                       24930   
            II = 0
            DO 779  K = KF1, NSPLI
               JTT = ILLOC(LTOCS+4*K)
               IF ( JTT .LT. 0 )  GO TO 779
               II = II+1
               JTTS(II) = JTT
               LDELS(II) = ILLOC(LTOCS+4*K-3)
               LXS(II) = ILLOC(LTOCS+4*K-2)
               JTPS(II) = ILLOC(LTOCS+4*K-1)
               KOFFSS(II) = K                                           24940   
               IF ( II .EQ. 5 )  GO TO 780
 779        CONTINUE
 780        NDO = II
            KF1 = K+1
            IF ( LINECT+8+1.1*(LMAX-LMIN+LSKIP)/LSKIP .GT. 58 )
     1         LINECT = 100
            TOPSW = .TRUE.
C
            DO 879  LI = LMIN, LMAX, LSKIP
C                                                                       24950   
C     PRINT HEADING IF NECESSARY
C
               IF ( LINECT .LE. 58  .AND. .NOT. TOPSW )  GO TO 820
               IF ( LINECT .GT. 58 )  write (6, 803) REACT, ELAB, HEADER
 803           FORMAT ( '1', T49, 'P T O L E M Y' /
     1            1X, 45A1, 'ELAB =', F7.2, ' MEV', 5X, 65A1 )
               IF ( LINECT .LT. 58 )  write (6, 813)
               write (6, 804) MCHN
 804           FORMAT ( '0 L IN', T20, 'S-MATRICES FOR CHANNEL', I3,
     1               '  AND PARTIAL WAVES LABELED BY ',                 24960   
     2               '( JP, JT, LX, L(OUT)-L(IN) )' )
               write (6, 807) ( BLANK, JTPS(I), JTTS(I), LXS(I),
     1             LDELS(I), I = 1, NDO )
 807           FORMAT ( '0', 4X, 5( 3X, A2, '(', I2, '/2', I3, '/2',
     2            I3, I4, ' )' ) )
               write (6, 808) ( BLANK, I = 1, NDO )
 808           FORMAT ( 5X, 5( 7X, 1A1, '|S|', 8X, 'PHASE' ) )
               write (6, 813)
 813           FORMAT ( ' ' )
               TOPSW = .TRUE.                                           24970   
               LINECT = LINECT + 8
               IF ( LINECT .GT. 58 )  LINECT = 9
C
 820           DO 849  I = 1, NDO
                  K = KOFFSS(I)
                  IADD = NSPLI*(LI-LMIN) + K
                  DMAGS(I) = ALLOC4(LMAG+IADD)
                  PHASES(I) = ALLOC4(LPHASE+IADD)
 849           CONTINUE
C                                                                       24980   
               IF ( MOD(LI,10) .NE. 0  .OR. TOPSW )  GO TO 860
               write (6, 813)
               LINECT = LINECT+1
 860           write (6, 863) LI, ( DMAGS(I), PHASES(I), I = 1, NDO )
 863           FORMAT ( I5, 5( G15.5, F9.3 ) )
               TOPSW = .FALSE.
               LINECT = LINECT+1
 879        CONTINUE
 889     CONTINUE
         IF ( CCSW )  LCHNDF = LCHNDF+MCHNDF                            24990   
 899  CONTINUE
C
      RETURN
      END
C*ID* PRBPRT   C109.PTOLEMY.SOURCE                          PER701  12:
      SUBROUTINE PRBPRT ( IRET )
C
C     MAKES CONSISTANCY CHECKS AND PRINTS PROBLEM SUMMARY
C
C     THIS ROUTINE IS CALLED BY THE GRIDSETUP KEYWORD. IT CHECKS        25000   
C     THAT ALL INPUT NECESSARY FOR THE DESCRIPTION OF THE DWBA
C     PROBLEM HAS BEEN ENTERED AND MAKES SOME CONSISTENCY CHECKS.
C
C     MUCH OF THIS ROUTINE IS SKIPPED FOR COUPLED-CHANNELS
C     CALCULATIONS SINCE THE ROUTINE IS ORIENTED TO ONLY TWO
C     CHANNELS (IT IS ALL USED FOR COUPL2, HOWEVER).
C     IT THEN PRINTS A SHORT SUMMARY OF THE REACTION.
C     FOLLOWING THIS ROUTINE, GRDSET IS CALLED BY MAIN.
C
C     FOR THE HISTORY PRIOR TO THE SPLIT, SEE GRDSET.                   25010   
C
C     5/28/75 - SPLIT OFF FROM GRDSET.
C     6/5/75 - LBTS MORE PRINTED
C     6/28/75 - SMALL FIXES
C     8/3/75 - BASE LMIN, LMAX ON LCRIT
C     8/28/75 - LMINMULT, LMAXMULT, SPFACP SPFACT
C     9/1/75 - USE LCRIT FUNCTION
C     9/18/75 - IMPROVED LCRITL FUNCTION
C     9/30/75 - LMAXMULT BECOMES LMAXADD
C     12/12/76 - INELASTIC SCATTERING                                   25020   
C     3/7/77 - CORRECT BUG WHEN LCRIT VERY SMALL
C     5/5/77 - LMINSUB, LMAXMULT;  IDENTICAL PARTICLES
C     9/24/77 - BETTER USECORE MESSAGES; GIVE HIM HIS LMIN
C     11/20/77 - V IS NOW STORED WITHOUT 1/E - S.P.
C     12/1/77 - LCRITICAL NOW FOUND BY WAVSET - S.P.
C     12/4/77 - LINKULES - S.P.
C     1/30/77 - USE CORRECT BE FOR NON-ZERO GROUND STATES.
C     4/18/78 - DO ABOVE TRUELY CORRECTLY - S.P.
C     4/20/78 - IRET FINALLY USED; DEEXCITAION ALLOWED - S.P.
C     4/24/78 - INTERCHANGE LI AND LO - S.P.                            25030   
C     3/6/79 - S-MATRICES; NO MORE BETABAR - S.P.
C     5/4/79 - PARITIES - S.P.
C     6/6/79 - CHANGE DEF. OF SPECTROSCOPIC COEFFICIENTS FOR TRANSFER,
C        ADD JPMIN, JPMAX, JTMIN, JTMAX. USE MOD - RPG
C     6/8/79 - STANDARD PREFIXES, CHARACTER TYPE - RPG
C     12/21/79 - COUPLED CHANNELS - S.P.
C     7/14/80 - CDO, CDM PREFIXES - S.P.
C     6/3/80 - MOVE CDC XWORDS - S.P.
C     7/16/80 - CHAR*8 PWORD - S.P.
C     7/1/81 - LXSTEP=1 FOR CC CALCULATIONS; FIX LX=*** FOR CC - S.P.   25040   
C     7/16/81 - ALLOW EXTERNAL SPECIFICATION OF L VALUES - S.P.
C     5/4/82 - PROPER DEF OF LBNDS FOR 1/2 INT INELASTIC - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
C
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      COMMON /LENGTH/  LENG(1)
C
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      parameter ( NUMJWORD = 12 )                                       /jblock/
      COMMON /JBLOCK/  J, JS(5),
     &  JP, JSP, JST,
     &  JPARM1, JPARM2, JPARM3
 
      EQUIVALENCE ( JS(1), JA ), ( JS(2), JB ), ( JS(3), JBIGA ),
     1  ( JS(4), JBIGB ), ( JS(5), JX )
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
      CHARACTER*1  REACT, HEADER                                        /hedcom/
      COMMON /HEDCOM/  REACT(45), HEADER(65)
 
      COMMON /KANDM/ AKI, AKO, REDMI, REDMO, RIMAX, ROMAX, ISIGS(2),    /kandm/
     &  RSCTS(2), ASCTS(2), RCSCTS(2) ,ISMATS(2), LOMOST, LCRIT,
     &  ISCTMN, ISCTCR, ETAS(2), RCSCTP(2), RCSCTT(2), LCRITS(2),
     &  RATMSS(2), QMIN, ABAR
 
      DIMENSION  AKS(2), REDMS(2), RMAXS(2)
      EQUIVALENCE ( AKI, AKS(1) ), ( REDMI, REDMS(1) ),
     &  ( RIMAX, RMAXS(1) )
 
c                                                                       /formf/
c ***  LNKADB was  numLINKULES but only 12 are used ???
c
      COMMON /FORMF/  IBDS(2), NPOTS(2), LBP, LBT, NBP, NBT, JBP, JBT,
     &  BNDMAX(2), BNDSTP(2), NSTPBD(2), RBNDS(2), ABNDS(2),
     &  RCBNDS(2), BNDMAS(2), BRATMS(2), RSOBDS(2), ASOBDS(2),
     &  VBNDS(2), VSOBDS(2), TAUBDS(2), LNKADB(6, 2, 12)
 
      DIMENSION NBNDS(2),  R2S(4), LBNDS(2)                             25060   
      EQUIVALENCE ( NBNDS(1), NBP ), ( R2S(1), RBNDS(1) )
      EQUIVALENCE ( LBNDS(1), LBP )
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
      REAL*8  JACOB                                                     /gridcm/
      COMMON /GRIDCM/  JACOB, STPINV, COSSTP,
     &  IMSVAL, IINTS, INTOFF, IA12VL, ICOSIN,
     &  IPHIT, IPHIP, IPHI, LOGIC, LOCTRP,
     &  IRI, IRO, ILOR, ILOI, ILIR, ILII, IWIO, NOFLO, NRIROI, NCRIT,
     &  IXLAM, INLAM, IA12N, MSKCOS, MAXCNT, ISMHPT, ISMIPT,
     &  ICOSS4, IJA12S, IHS, IIINDX, IA12TM, IDW, IHINT, IHABS,
     &  IABS1, IGRDC1, NPSUMI, RVRLIM, ISMHWK, ISMHVL, ISMIVL,
     &  IRIOEX, NUMHS, IGRDC2(4),
     &  IWFII, IWFIO, NWFI, NWFO, IDWI
 
      LOGICAL ONELSW, IDENSW                                            /inelcm/
      COMMON /INELCM/  JBPF, JBTF, LXMIN, LXMAX, ILILOR, ILILOI, MSTOP,
     &  IA12M, NMLOLX, ONELSW, NUMLX, IRDINT, IELCUP, LILOSZ, NUMLIS,
     &  ILIS, IBETAS(3), ICL2FF, LXSTEP, IDENSW, LSKIP,
     &  JPMIN, JPMAX, JPBASE, NJP, JTMIN, JTMAX, JTBASE, NJT,
     &  IINDXS, ISMATR, ISMATI, NSMAT, NLX, NSPLI, ITOCS,
     &  NASPLI, IUNITR, LIFIT, ILIFIT, NOLFIT, IDELSR, IDELSI
      INTEGER INDXJS(4,2)
      EQUIVALENCE ( INDXJS(1,1), JPMIN )
 
c                                                                       /lnkblk/
c  STRUCTURE OF   /LNKBLK/
c
c  THERE IS A BLOCK OF 3 DOUBLE WORDS FOR EACH POSSIBLE USE
c  OF A LINKULE.  THE NUMLNK = NUMLINKULES USES ARE IN THE ORDER
c    REALPOTEN  IMAGPOTEN  REALVSO  IMAGVSO  COULOMB
c    WAVEFUNCTION  AND 6 TENSOR POTENTIALS
c  THE THREE-DOUBLE-WORD BLOCKS EACH HAVE THE STRUCTURE
c
c    LNKNAM(1,I)   LINKULE NAME
c
c      LNKADR(3,I)   LINKULE ADDRESS, O IF NO LINKULE IN USE.
c      LNKADR(4,I)   0 - NO L OR J DEPENDENCE IN POTENTIAL
c                    1 - L DEPENDENCE BUT NO J DEPENDENCE
c                    2 - BOTH L  AND J DEPENDENCE
c
c      LNKADR(5&6,I)  MYINTS - A TWO-ELEMENT ARRAY THAT THE
c                     LINKULE MAY USE FOR COMMUNICATION BETWEEN
c                     CALLS TO ITSELF.
c
      parameter ( NUMLINKULES = 13 )
      COMMON /LNKBLK/  NUMLNK, IUNIQU, LNKADR(6,NUMLINKULES)
      character*8  LNKNAM(3,NUMLINKULES)
      EQUIVALENCE ( LNKNAM(1,1), LNKADR(1,1) )
 
      COMMON /LOCFIT/  LNKAD2(6,2,NUMLINKULES)                          /locfitf
 
      COMMON / TEMPVS /  TVR, TVI, TVSOR, TVSOI, TAR, TAI               /tempvs/
 
C
      INTEGER  IND(5) / 3, 1, 2, 4, 5 /                                 25070   
      CHARACTER*8  PARTIC(5) / 'A', 'B', 'BIGA', 'BIGB', 'X' /
C
      LOGICAL PRNTSW
C
      CHARACTER*8  XWORDS(2) / ' ', ';   X' /
      CHARACTER*8  WORDS(4) / 'PROJECTI', 'LE', 'TARGET', ' ' /
      CHARACTER*8  BETNAM(4) / 'BETA', 'BETACOUL', 'BETARATS', 'BELX ' /
      CHARACTER*8 PWORD(3) / '     -1', 'UNKNOWN', '     +1' /
      LOGICAL  BETSWS(4), TRANSW, COUPSW
C                                                                       25080   
c
C
      IRET = 1
C
      IPRNT = MOD( IPRINT, 10 )
      PRNTSW = IPRNT .GE. 1
C
      IF ( PRNTSW )  write (6, 3) REACT, ELAB, HEADER
 3    FORMAT ( '1', T49, 'P T O L E M Y' /
     1  '   CONSTRUCTION OF THE INTEGRATION GRIDS', T70,                25090   
     2  'MERELY TO CONCEIVE OF SUCH THINGS MAKES THEM APPEAR RIDICULOUS'
     3   /
     4  '0', 45A1, 'ELAB =', F7.2, ' MEV', 5X, 65A1 / )
C
C     IS THIS TRANSFER OR INELASTIC EXCITATION?
C     TREATMENT OF LX DEPENDS ON THE PROBLEM
C
      TRANSW = ISTRIP .NE. 0
      COUPSW = PROBLM .EQ. 24
C                                                                       25100   
      LXSTEP = 1
      IF ( TRANSW )  GO TO 40
C
C     FOR INELASTIC SCATTERING WE SET L(BOUNDSTATE) = DELTA(J(OUTGOING))
C     AT EACH VERTEX.
C     THIS IS APPROPRIATE FOR INTEGER SPINS WITH NO CHANGES IN
C     INTRINNSIC PARITY.  ELSE WE NEED TO KNOW MORE TO PROPERLY SET
C     UP THE LX LIMITS.
C     THIS IS FURTHER REFINED PAST STMNT NO 285
C                                                                       25110   
C     INELASTIC DWBA CAN ONLY HAVE LXSTEP=2 BY PARITY SINCE WE DON'T
C     ALLOW FOR SPIN-ORBIT.
C
      IF ( .NOT. COUPSW )  LXSTEP = 2
      LBP = IABS(JB-JA)/2
      LBT = IABS(JBIGB-JBIGA)/2
C
C     CHECK PARTICLE MASSES
C
C     AMS ARRAY CONTAINS  MA, MB, MBIGA, MBIGB, MX                      25120   
C
  40  DO 49  I = 1, 4
         IF ( AMS(I) .NE. UNDEF )  GO TO 42
         write (6, 41)  PARTIC(I)
 41      FORMAT ( '0***** ERROR:  M', A4, ' IS NOT DEFINED.' )
         IRET = 0
  42     IF ( JS(I) .NE. NOTDEF )  GO TO 44
         write (6, 43)  PARTIC(I)
 43      FORMAT ( '0***** ERROR:  J', A4, ' IS NOT DEFINED.' )
         IRET = 0                                                       25130   
  44     IF ( IZS(I) .NE. NOTDEF )  GO TO 49
         write (6, 45)  PARTIC(I)
 45      FORMAT ( '0***** ERROR:  Z', A4, ' IS NOT DEFINED.' )
         IRET = 0
 49   CONTINUE
      IF ( AMX .EQ. UNDEF )  AMX = DABS( AMA-AMB )
      IF ( DABS(AMA+AMBIGA-AMB-AMBIGB) .LT. .3 )  GO TO 55
      write (6, 53) AMBIGA, AMA, AMB, AMBIGB
 53   FORMAT ( '0**** THE REACTION DOES NOT CONSERVE MASS:' /
     1  ' MBIGA(MA, MB)MBIGB =', 4G15.5 )                               25140   
      IRET = 0
 55   IF ( IZS(1)+IZS(3) .EQ. IZS(2)+IZS(4) )  GO TO 60
      write (6, 57) IZS(3), IZS(1), IZS(2), IZS(4)
 57   FORMAT ( '0**** THE REACTION DOES NOT CONSERVE CHARGE:' /
     1  ' ZBIGA(ZA, ZB)ZBIGB =', 4I8 )
      IRET = 0
C
 60   IF ( DABS( AMX - DABS(AMA-AMB) )  .LT. .3 )  GO TO 65
      write (6, 63)
 63   FORMAT ( '0**** THE EXCHANGED MASS IS INCONSISTANT WITH THE ',    25150   
     1  'OTHER FOUR MASSES.' )
      IRET = 0
 65   IF ( AMX .GT. .7 )  GO TO 90
      IF ( .NOT. TRANSW )  GO TO 70
      write (6, 68) AMX
 68   FORMAT ( '0**** THE EXCHANGED MASS MUST NOT BE 0 OR NEGATIVE:',
     1  G15.5 )
      IRET = 0
      GO TO 90
 70   IF ( IZS(5) .EQ. 0 )  GO TO 90                                    25160   
      write (6, 73) IZS(5)
 73   FORMAT ( '0**** CANNOT TRANSFER CHARGE WITHOUT MASS TRANSFER:',
     1  ' AMX = 0, ZX =', I4 )
      IRET = 0
C
  90  CONTINUE
C
      IF ( COUPSW )  GO TO 400
      IF ( .NOT. TRANSW )  GO TO 200
C                                                                       25170   
C     FOR TRANSFER CANNOT HAVE NUCLEAR CORE CORRECTIONS FOR LINKULES
C
      IF ( LNKAD2(3,1,1) .EQ. 0  .AND.  LNKAD2(3,2,1) .EQ. 0 )
     1    GO TO 200
      IF ( NUCONL .LT. 3 )  GO TO 200
      write (6, 103)
 103  FORMAT ( '0**** WARNING - NUCLEAR CORE-CORE CORRECTIONS CANNOT',
     1  ' BE COMPUTED FOR LINKULE-COMPUTED POTENTIALS.' /
     2  6X, 'ONLY COULOMB CORE-CORE CORRECTIONS WILL BE USED.' )
      NUCONL = 2                                                        25180   
C
C     CHECK THAT JBP AND JBT ARE INSIDE ALLOWED BOUNDS
C
 200  JBPMIN=IABS(JA-JB)
      JBPMAX=JA+JB
      JBTMIN=IABS(JBIGA-JBIGB)
      JBTMAX=JBIGA+JBIGB
C
      IF ( .NOT. TRANSW )  GO TO 270
C                                                                       25190   
C     FOR TRANSFER, WE CAN HANDLE ONE (JBP, JBT) PAIR ON EACH PASS.
C     S-MATRIX VALUES WILL BE ACCUMULATED.
C
      IF ( JBP .GE. JBPMIN  .AND.  JBP .LE. JBPMAX
     1    .AND.  JBT .GE. JBTMIN  .AND.  JBT .LE. JBTMAX )  GO TO 260
      write (6, 253) JA, JB, JBIGA, JBIGB, JBPMIN, JBPMAX,
     &   JBTMIN, JBTMAX
 253  FORMAT ('0***** ERROR IN INPUT:' /
     1  ' JA, JB, JBIGA, JBIGB =', 4(I5, '/2') /
     2  ' RESULTS IN' /                                                 25200   
     3  ' JBPMIN, JBPMAX, JBTMIN, JBTMAX =', 4(I5, '/2') )
      IRET = 0
      IF ( JBP .EQ. NOTDEF  .OR.  JBT .EQ. NOTDEF )  GO TO 255
      write (6, 254) JBP, JBT
 254  FORMAT ( ' BUT  JBP, JBT =', 2(I5, '/2'), '  AND ARE OUT OF ',
     1  'BOUNDS.' )
      GO TO 260
 255  write (6, 257) JBP, JBT
 257  FORMAT ( ' THUS THERE IS MORE THAN ONE POSSIBILITY FOR',
     1  ' JP FOR THE PROJECTILE OR TARGET BOUND STATE.' /               25210   
     2  ' IN SUCH AMBIGUOUS CASES JP MUST BE EXPLICITLY INDICATED.' /
     3  ' WE PRESENTLY HAVE  JP(PROJ) = ', I3, '/2,', 4X,
     4    'JP(TARG) = ', I3, '/2' /
     5  ' WHERE THE *** INDICATES THE AMBIGUOUS CASE.' )
C
C
C     FIND LX RANGE FOR TRANSFER AND MAKE NECESSARY CHECKS
C
 260  LXMIN=IABS(JBP-JBT)
      LXMAX=JBP+JBT                                                     25220   
      IF(LXMIN.LT.IABS(2*(LBP-LBT)))LXMIN=IABS(2*(LBP-LBT))
      IF(LXMAX.GT.(2*(LBP+LBT)))LXMAX=2*(LBP+LBT)
C
C
      LXMAX=LXMAX/2
      LXMIN=LXMIN/2
      IPARIT = 1 - 2*MOD(LBP+LBT, 2)
      JPMIN = JBP
      JPMAX = JBP
      JTMIN = JBT                                                       25230   
      JTMAX = JBT
      IF ( LXMAX .GE. LXMIN )  GO TO 300
      write (6, 263) JBP, JBT, LBP, LBT, LXMIN, LXMAX
 263  FORMAT ( '0**** INVALID BOUND STATE ANGULAR MOMENTA:' /
     1  ' JP, JT, LP, LT =', 2(I5, '/2'), 2I5 /
     2  ' RESULTS IN  LXMIN, LXMAX =', 2I8 )
      IRET = 0
      GO TO 300
C
C     SETUP LX RANGE FOR INELASTIC SCATTERING                           25240   
C
C
C
 270  IF ( EXS(4) .NE. EXS(3) )  GO TO 275
C
C     PROJECTILE EXCITATION
C
      IEXCIT = 1
      LXMAX = JBPMAX
      LXMIN = JBPMIN                                                    25250   
      JPMIN = JBPMIN
      JPMAX = JBPMAX
      JTMIN = 0
      JTMAX = 0
      JIN = JA
      JOUT = JB
      IPARIT = PARITS(1)*PARITS(2)
      IF ( EXS(2) .NE. EXS(1) )  GO TO 280
      write (6, 273)
 273  FORMAT ( '0**** E*B OR E*BIGB MUST BE DEFINED' )                  25260   
      IRET = 0
      GO TO 280
C
C     TARGET EXCITATION
C
 275  IEXCIT = 2
      LXMAX = JBTMAX
      LXMIN = JBTMIN
      JPMIN = 0
      JPMAX = 0                                                         25270   
      JTMIN = JBTMIN
      JTMAX = JBTMAX
      JIN = JBIGA
      JOUT = JBIGB
      IPARIT = PARITS(3)*PARITS(4)
      IF ( EXS(2) .EQ. EXS(1) )  GO TO 280
      write (6, 278)
 278  FORMAT ( '0**** CANNOT SIMULTANEOUSLY EXCITE BOTH PROJECTILE',
     1  ' AND TARGET.' )
      IRET = 0                                                          25280   
C
 280  IF ( MOD(LXMIN, 2) .EQ. 0 )  GO TO 285
      write (6, 283) LXMIN, LXMAX, IEXCIT
 283  FORMAT ( '0**** INELASTIC EXCITATION MUST INVOLVE AN',
     1  ' INTEGER CHANGE IN NUCLEAR SPINS', 3I8 )
      IRET = 0
 285  LXMIN = LXMIN/2
      LXMAX = LXMAX/2
C
C     IF WE KNOW THE PARITIES, WE CAN REFINE LXMIN AND LXMAX            25290   
C     AND STORE A BETTER LBP OR LBT.
C
      IF ( IPARIT .EQ. 0 )  GO TO 290
      I = (IPARIT+3)/2
      LXMIN = LXMIN + MOD(I+LXMIN, 2)
      LXMAX = LXMAX - MOD(I+LXMAX, 2)
      LBNDS(IEXCIT) = LXMIN
C
 290  IF ( LXMAX .EQ. LXMIN  .OR.  LX .NE. NOTDEF )  GO TO 300
      IF ( IPARIT .NE. 0 )  GO TO 295                                   25300   
      write (6, 293)
 293  FORMAT ( '0', 120('*') /
     1  ' **** WARNING, THE PARITIES OF THE STATES MUST BE KNOWN',
     2    ' TO UNIQUELY DETERMIN THE MULTIPOLARITY OF THE EXCITATION' /
     3  ' **** PTOLEMY ASSUMES THAT THE CHANGE IN THE INTRINSIC PARITY',
     4    ' IS JUST  (-1)**|J(IN)-J(OUT)|.' /
     5  ' ', 120('*') )
      LXMAX = LXMAX - MOD( LXMIN+LXMAX, 2 )
      GO TO 300
C                                                                       25310   
 295  IF ( LXMAX .GT. LXMIN )  GO TO 300
      write (6, 298) IPARIT, JIN, JOUT, LXMIN, LXMAX
 298  FORMAT ( '0**** ERROR:  PARITIES AND J-VALUES RESULT IN',
     1  ' IMPOSSIBLE EXCITATION:', I4, 2(I4,'/2'), 2I4 )
      IRET = 0
C
C     DOES HE WANT ONLY ONE LX OR ALL OF THEM?
C
  300 ONELSW = LX .NE. NOTDEF
      IF ( .NOT. ONELSW )  GO TO  340                                   25320   
C
      IF ( LXMIN .LE. LX  .AND.  LX .LE. LXMAX )  GO TO  330
      IF ( TRANSW )
     1  write (6,  303) JBP, JBT, LBP, LBT, LXMIN, LXMAX, LX
  303 FORMAT ( '0**** ERROR IN INPUT:' /
     1  ' JBP, JBT, LBP, LBT =', 2(I5, '/2'), 2I5 /
     2  ' AND RESULTS IN' /
     3  ' LXMIN, LXMAX =', 2I5 /
     4  ' BUT LX HAS BEEN INPUT AS', I5 / )
      IF ( .NOT. TRANSW )  write (6, 307) JS(3), JS(1), JS(2), JS(4),   25330   
     1  IPARIT, LXMIN, LXMAX, LX
 307  FORMAT ( '0**** ERROR:  PARTICLE SPINS ARE', I5, '/2(',
     1    I3, '/2,', I3, '/2)', I3, '/2',
     1    4X, 'PARITY CHANGE =', I2 /
     1    ' **** WHICH RESULT IN',
     2  '  LXMIN, LXMAX =', 2I4, 5X, 'BUT LX =', I4,
     3    ' WAS SPECIFIED.' )
      IRET = 0
C
  330 LXMIN = LX                                                        25340   
      LXMAX = LXMIN
C
 340  NUMLX = LXMAX-LXMIN+1
      NUMLXI = (LXMAX-LXMIN)/2 + 1
      IF ( .NOT. TRANSW )  GO TO 400
C
C  SUM OVER JX NEXT,WHERE LBP+JX=JBP, AND LBT+JX=JBT
C
      JXMAX=2*LBP+JBP
      IF(JXMAX.GT.(2*LBT+JBT))JXMAX=2*LBT+JBT                           25350   
      JXMIN=IABS(2*LBP-JBP)
      IF(JXMIN.LT.IABS(2*LBT-JBT))JXMIN=IABS(2*LBT-JBT)
      IF ( JXMAX .GE. JXMIN )  GO TO  342
      write (6,  341) JBP, JBT, LBP, LBT, JXMIN, JXMAX
  341 FORMAT ( '0**** INVALID BOUND STATE ANGULAR MOMENTA:' /
     1  ' JP, JT, LP, LT =', 2(I5, '/2'), 2I5 /
     2  ' RESULTS IN  JXMIN, JXMAX =', 2(I7, '/2') )
      IRET = 0
C
C     WE PRESENTLY ALLOW ONLY ONE JX                                    25360   
C
  342 IF ( JX .NE. NOTDEF )  GO TO  345
      IF ( JXMIN .EQ. JXMAX )  GO TO  350
      write (6,  343) JXMIN, JXMAX
  343 FORMAT ( '0***** ERROR: MORE THAN ONE JX IS POSSIBLE BUT JX WAS',
     1  ' NOT SET.  JXMIN, JXMAX =', 2(I5, '/2') / )
      IRET = 0
      GO TO  400
  345 IF ( JXMIN .LE. JX  .AND.  JX .LE. JXMAX )  GO TO  400
      write (6,  348) JXMIN, JXMAX, JX                                  25370   
  348 FORMAT ( '0**** ERROR, JXMIN, JXMAX, JX =', 3(I5, '/2') / )
      IRET = 0
      GO TO 400
  350 JX = JXMIN
C
C     COMPUTE L CRITICAL
C
 400  LCRIT = (LCRITS(1)+LCRITS(2))/2
C
C     IF AN ARRAY NAMED LVALUES IS DEFINED, WE USE IT AS THE            25380   
C     ARRAY OF L-VALUES AT WHICH THE COMPUTATIONS ARE DONE.
C     OTHERWISE WE MUST FIND LMIN AND LMAX AND ANGSET WILL
C     SET UP AN UNIFORMLY SPACED ARRAY.
C
      ILVALU = NAMLOC( 'LVALUES  ' )
      IF ( ILVALU .EQ. 0 )  GO TO 430
      NUMLIS = LENG(ILVALU)
      ILIS = NALLOC( (NUMLIS+1)/FACFR4, 'LIS     ' )
      LLVALU = Z(ILVALU)-1
      LMIN = ALLOC(LLVALU+1)                                            25390   
      L1 = -1
      LSTEP = 1
      DO 419  I = 1, NUMLIS
         L = ALLOC(LLVALU+1)
         IF ( L .GT. L1 )  GO TO 415
         write (6, 413) I, L, L1
 413     FORMAT ( '0*** LVALUES ARRAY MUST BE INCREASING:  ',
     1     'ELEMENT', I4, ' IS ', I5, ', PREVIOUS IS', I4 )
         RETURN
 415     ILLOC(FACFR4*Z(ILIS)-FACFR4+I) = L                             25400   
         LSTEP = MAX0( LSTEP, L-L1 )
         L1 = L
 419  CONTINUE
      LMAX = L
      GO TO 450
C
C     NOW ESTIMATE LMIN, LMAX FROM L CRITICAL IF THEY WERE NOT GIVEN
C
 430  LMININ = LMIN
      IF ( LMIN .NE. NOTDEF )  GO TO 440                                25410   
      IF ( LMINSB .EQ. NOTDEF )  LMINSB = 10
      LMIN = LCRIT*ALMNMT
      LMIN = MAX0( 0, MIN0( LMIN, LCRIT-LMINSB ) )
 440  IF ( LMAX .NE. NOTDEF )  GO TO 450
      LMAX = ALMXMT*LCRIT
      LMAX = MAX0( LMAX, LCRIT + MAX0(4*LSTEP, LMAXAD) )
C
C     IF THERE ARE IDENTICAL PARTICLES IN EXIT OR ENTRANCE CHANNEL,
C     MUST FIX UP CHOICE OF L'S NOW.
C                                                                       25420   
 450  IDENSW = .FALSE.
      LSKIP = MAX0( LSKIPS(1), LSKIPS(2) )
      IF ( ISTATS(1) .EQ. 3 )  GO TO 460
      IF ( JA .EQ. 0 )  GO TO 455
 452  write (6, 453)
 453  FORMAT ( '0**** ONLY SPIN-0 IDENTICAL PARTICLES MAY BE USED',
     1    ' FOR NOW.' )
      IRET = 0
      GO TO 500
C     ENTRANCE CHANNEL MUST HAVE ONLY EVEN PARTIAL WAVES                25430   
 455  LIBASE = 0
      GO TO 470
C
 460  IF ( ISTATS(2) .EQ. 3 )  GO TO 480
      IF ( JB .GT. 0 )  GO TO 452
C     EXIT CHANNEL MUST HAVE EVEN WAVES
      LIBASE = MOD( LBP+LBT, 2 )
C
C     IDENTICAL PARTICLES; MAKE ADJUSTMENTS
C                                                                       25440   
 470  IDENSW = .TRUE.
      LSTEP = LSTEP + MOD(LSTEP, 2)
C
C     MAKE LMIN AND LMAX LSTEP MULTIPLES
C
 480  IF ( LMININ .EQ. NOTDEF )  LMIN = LSTEP*(LMIN/LSTEP)
      IF ( LSKIP .NE. 1 )  LMIN = IABS( LMIN-LIBASE )
      LMAX = LSTEP*((LMAX-LMIN+LSTEP-1)/LSTEP) + LMIN
C
C    PROCESS SPECTROSCOPIC OR DEFORMATION FACTORS                       25450   
C
 500  IF ( TRANSW )  GO TO 580
C
C     SETUP EXCITATION POTENTIAL PARAMETERS
C     ALLOW OVERRIDES OF THE POTENTIAL PARAMETERS FROM THE INCOMING
C     STATE WHICH IS THE DEFAULT.
C
      EMUL = ELAB
      IF ( IEPOW .EQ. 1 )  EMUL = 1/ELAB
      IF ( R0 .NE. UNDEF )  R = R0MASS*(R0+EMUL*(R0E+EMUL*R0ESQ))       25460   
      IF ( RI0 .NE. UNDEF )  RI = R0MASS*(RI0+EMUL*(RI0E+EMUL*RI0ESQ))
      IF ( RSI0 .NE. UNDEF )  RSI = R0MASS*RSI0
      TAR = A + EMUL*(AE+EMUL*AESQ)
      TAI = AI + EMUL*(AIE+EMUL*AIESQ)
      TVR = V + EMUL*(VE+EMUL*VESQ)
      TVI = VI + EMUL*(VIE+EMUL*VIESQ)
      IF ( RC0 .NE. UNDEF )  RC = R0MASS*RC0
C
C     ALWAYS USE POINT AND SPHERE COULOMB FOR EFFECTIVE EXCITATION
C                                                                       25470   
      RCP = 0
      RCT = RC
C
      IF ( RI .EQ. UNDEF )  RI = R
C
      IF ( R .NE. UNDEF  .AND.  RC .NE. UNDEF )  GO TO 510
      write (6, 503) R, RC
 503  FORMAT ( '0**** BOTH R AND RC (OR R0 AND RC0) MUST BE',
     1  ' DEFINED TO COMPUTE DEFORMATION LENGTHS:' /
     2  6X, 'R, RC = ', F8.3, 1X, F8.3 )                                25480   
      IRET = 0
      RETURN
C
 510  R0 = R/R0MASS
      RI0 = RI/R0MASS
      RC0 = RC/R0MASS
      VC = -3*IZS(1)*IZS(3)*HBARC / AFINE
      R2S(4) = VC
C
      IF ( COUPSW )  GO TO 600                                          25490   
C
C     DEFOMATION LENGTHS INVOLVE ONLY TARGET OR PROJECTILE RADIUS
C
      R2MASS = AMS(2*IEXCIT-1)**(1.D0/3.D0)
      R2S(1) = R0*R2MASS
      R2S(2) = RI0*R2MASS
      R2S(3) = RC0*R2MASS
C
C     PROCESS DEFORMATION PARAMETERS FOR INELASTIC SCATTERING.
C     DEFAULT VALUES ARE 1 FOR NUCLEAR AND                              25500   
C     RC2 BETAC = R2 BETA  FOR COULOMB
C
C     HERE WE SETUP THE IBETAS ARRAY AS FOLLOWS
C
C       1 - BETA (NUCLEAR)
CC      2 - BETACOULOMB
C       3 - A PRESENTLY EMPTY ARRAY
C       4 - BE(LX)
C
C     THESE DEFINITIONS WILL BE CHANGED JUST BEFORE STATEMENT 580       25510   
C
      BETA = 1
      DO 549  II = 1, 4
         IB = NAMLOC(BETNAM(II))
         BETSWS(II) = IB .NE. 0
         LEN = 0
         IF ( IB .EQ. 0 )  GO TO 540
 520     BETA = ALLOC(Z(IB))
         LEN = LENG(IB)
         IF ( LEN .EQ. NUMLXI )  GO TO 548                              25520   
         IF ( LEN .LE. 1 )  GO TO 540
         write (6, 533) BETNAM(II), LEN, NUMLXI
 533     FORMAT ( '0**** ', A8, ' WAS DEFINED TO HAVE', I4,
     1  ' VALUES BUT THERE ARE', I4, ' VALUES OF LX' )
         IRET = 0
         GO TO 548
C
 540     IB = NALLOC( NUMLXI, BETNAM(II) )
         DO 544  I = 1, NUMLXI
            ALLOC(Z(IB)-1+I) = BETA                                     25530   
 544     CONTINUE
C
 548     IBETAS(II) = IB
 549  CONTINUE
C
C
      CHARGE = IZS(2*IEXCIT-1)
      IBETNR = NALLOC( NUMLXI, 'BETANRAT' )
      LBETA = Z(IBETAS(1))-LXMIN/2
      LBETAC = Z(IBETAS(2))-LXMIN/2                                     25540   
      LBETAR = Z(IBETAS(3))-LXMIN/2
      LBELX  = Z(IBETAS(4))-LXMIN/2
      LBETNR = Z(IBETNR) - LXMIN/2
C
C     INITIALIZE FOR CLEBSCH'S IN BE TO BETA
C
      CALL DUMMY1
      K = MOD(JIN, 2)
C
C     MAKE SURE THE BETA(COULOMB) ARE DEFINED                           25550   
C
      IF ( BETSWS(2) )  GO TO 560
      IF ( BETSWS(4) )  GO TO 555
      write (6, 553)
 553  FORMAT ( '0**** WARNING:  BETA COULOMB IS BEING CHOOSEN SUCH',
     1      ' THAT:' /
     2      16X, 'RC*BETACOULOMB = R*BETA',
     3      4X, 'WHERE RC AND R REFER ONLY TO THE EXCITED NUCLEUS' )
      DO 554  LX = LXMIN, LXMAX, 2
         ALLOC(LBETAC+LX/2) = (R2S(1)/R2S(3)) * ALLOC(LBETA+LX/2)       25560   
 554  CONTINUE
      GO TO 560
C
C     GET COULOMB BETAS FROM B(E LX)
C
 555  DO 559  LX = LXMIN, LXMAX, 2
         ALLOC(LBETAC+LX/2) = (4*PI/(3*CHARGE)) *
     1      DSQRT( ALLOC(LBELX+LX/2) )
     2     / ( (R2S(3)/10)**LX * CLEBSH( JIN, 2*LX, K, 0, JOUT, K ) )
 559  CONTINUE                                                          25570   
C
C     COULOMB BETAS NOW SETUP - PROCEED TO NUCLEAR BETAS
C
 560  IF ( BETSWS(1) )  GO TO 570
      IF ( BETSWS(2) .OR. BETSWS(4) )  GO TO 565
      write (6, 563)
 563  FORMAT ( '0', 120('*') / ' **', T120, '**' /
     1      ' **    WARNING:  BETA ASSUMED TO BE 1 --',
     2       ' MUST MULTIPLY CROSS SECTIONS BY SQUARE OF ACTUAL',
     3         ' BETA TO GET TRUE VALUES.', T120, '**' /                25580   
     4      ' ** ', T120, '**' / 1X, 120('*') / )
      GO TO 570
 565  DO 569  LX = LXMIN, LXMAX, 2
         ALLOC(LBETA+LX/2) = (R2S(3)/R2S(1)) * ALLOC(LBETAC+LX/2)
 569  CONTINUE
C
C     NOW DEFINE AUXILARY QUANTITIES
C     BETARAT CONTAINS  (BETACOULOMB) ( RC2**LX / (2*LX+1) )
C         * CLEBSCH( JIN, LX, K, 0: JOUT, K )
C     BETANRAT CONTAINS  BETA                                           25590   
C         * CLEBSCH( JIN, LX, K, 0: JOUT, K )
C
 570  DO 574  LX = LXMIN, LXMAX, 2
         TEMP = CLEBSH( JIN, 2*LX, K, 0, JOUT, K )
         ALLOC(LBETAR+LX/2) = ALLOC(LBETAC+LX/2)*TEMP
     1      * R2S(3)**LX / (2*LX+1.D0)
         ALLOC(LBETNR+LX/2) = ALLOC(LBETA+LX/2)*TEMP
         ALLOC(LBELX+LX/2) = ( 3*CHARGE*ALLOC(LBETAC+LX/2)
     1      * TEMP * (R2S(3)/10)**LX
     3      / (4*PI) )**2                                               25600   
C
 574  CONTINUE
C
C     WE WILL USE BETANRAT, BETARAT  FROM NOW ON.
C
C     THE FINAL DEFINITION OF THE IBETAS ARRAY IS
C        1 - BETA (NUCLEAR)
C        2 - BETANRAT
C        3 - BETARAT
C        4 - BE(LX)                                                     25610   
C
      IBETAS(2) = IBETNR
      GO TO 600
C
C     PROCESS SPECTROSCOPIC INFO FOR TRANSFER
C
 580  IF ( SPAMP .EQ. 1 )  SPAMP = DSQRT(SPFACP)
      SPFACP = SPAMP**2
      IF ( SPAMT .EQ. 1 )  SPAMT = DSQRT(SPFACT)
      SPFACT = SPAMT**2                                                 25620   
C
C     HERE WE SETUP THE A-TERMS
C
      IBETAS(1) = NALLOC( LXMAX+1, 'ATERM    ' )
C
C     INITIALIZE FOR THE RACAHS
C
      CALL DUMMY1
      LATERM = Z(IBETAS(1))
      TEMP = (JBIGB+1.D0)/(JBIGA+1)                                     25630   
      IF ( ISTRIP .EQ. -1 )  TEMP = (JB+1.D0)/(JA+1)
      TEMP = DSQRT(TEMP)
      DO 589  LX = LXMIN, LXMAX
         ATERM = TEMP*DSQRT(2*LX+1.D0) * SPAMP*SPAMT
     1     * RACAH( 2*LBT, JBT, 2*LBP, JBP, JX, 2*LX )
         ITEST = JX - JBP + 2*(LBP+LBT)
         IF ( ISTRIP .EQ. -1 )  ITEST = JX-JBT+JA+JBIGA-JB-JBIGB
         ITEST = ITEST/2 + 1
         IF ( MOD(ITEST, 2) .NE. 0 )  ATERM = -ATERM
         ALLOC(LATERM+LX) = ATERM                                       25640   
         IF ( IPRNT .GE. 4 )  write (6, 587) LX, ITEST, ATERM
 587     FORMAT ( ' LX =', I3, 5X, 'SIGN, ATERM =', I4, G15.8 )
 589  CONTINUE
C
C     PRODUCE A NICE SUMMARY OF THE REACTIONS
C
 600  IF ( .NOT. PRNTSW )  GO TO 800
      NUMPAR = 4 + IABS(ISTRIP)
      write (6, 623) REACT, XWORDS(NUMPAR-3),
     &   (AMS(IND(J)), J = 1, NUMPAR)                                   25650   
      write (6, 624)  (IZS(IND(J)), J = 1, NUMPAR)
      write (6, 625)  (EXS(IND(J)), J = 1, NUMPAR)
      write (6, 626)  (JS(IND(J)), J = 1, NUMPAR)
      write (6, 627) ( PWORD(PARITS(IND(J))+2), J = 1, NUMPAR )
 623  FORMAT ( '0', 20X, 'SUMMARY OF THE REACTION' /
     1  '0', 23X, 45A1 /
     2  '0', T19, 'BIGA   (   A   ,    B   )  BIGB   ', A8 /
     3  '0M (AMU)', T15, 5F9.2 )
 624  FORMAT (  ' Z', T12, 5I9 )
 625  FORMAT(  ' E* (MEV)', T17, 5F9.4 )                                25660   
 626  FORMAT ( ' J', T14, 5( I7, '/2' )  )
 627  FORMAT ( ' PARITY', T16, 5( A7, 2X ) )
C
      IF ( .NOT. TRANSW )  GO TO 680
      write (6, 643) EBNDS, Q, JBP, JBT, LBP, LBT, NBNDS, SPAMP, SPAMT,
     1  SPFACP, SPFACT
 643  FORMAT ( / '0', 5X, 'BOUND STATE PROPERTIES' /
     1  '0', 11X, 'PROJECTILE', 3X, 'TARGET' /
     2  ' E', T12, 2F10.4  , 10X, 'Q =', F9.4  /
     3  ' JP', T10, 2( I8, '/2' ) /                                     25670   
     4  ' L', T9, 2I10 /
     5  ' NODES', T9, 2I10 /
     6  ' SPEC. AMP.', T12, 2F10.4 /
     7  ' SPEC. FACTOR', T14, F8.4, F10.4  )
C
C
      IF ( ISTRIP .EQ. 1 )  write (6, 663)
 663  FORMAT ( '0THIS IS A STRIPPING REACTION' )
      IF ( ISTRIP .EQ. -1 )  write (6, 664)
 664  FORMAT ( '0THIS IS A PICKUP REACTION' )                           25680   
C
      write (6, 672)
 672  FORMAT ( '0THE EXCHANGE POTENTIAL CONSISTS OF' )
      IF ( IVRTEX .EQ. 1 )  write (6, 673)
 673  FORMAT ( '    THE NUCLEAR POTENTIAL AT THE PROJECTILE VERTEX' )
      IF ( IVRTEX .EQ. 2 )  write (6, 674)
 674  FORMAT ( '    THE NUCLEAR POTENTIAL AT THE TARGET VERTEX' )
      IF ( NUCONL .EQ. 0 )  write (6, 677)
 677  FORMAT ( '    AND THE COULOMB POTENTIAL AT THE SAME VERTEX.' )
      IF ( NUCONL .GE. 2 )  write (6, 678)                              25690   
 678  FORMAT ( '    AND THE COULOMB POTENTIAL INCLUDING CORE-CORE' ,
     1  ' CORRECTION TERMS' )
      IF ( NUCONL .EQ. 3) write (6, 679)
  679 FORMAT( '    AND THE CORE-CORE CORRECTIONS FROM THE REAL' ,
     1  ' PART OF THE NUCLEAR OPTICAL POTENTIAL')
      GO TO 750
C
C     PRINTOUT FOR INELASTIC SCATTERING
C
 680  IF ( COUPSW )  GO TO 750                                          25700   
C
      write (6, 683) WORDS(2*IEXCIT-1), WORDS(2*IEXCIT),
     1  ( LX, ALLOC(LBETA+LX/2), ALLOC(LBETAC+LX/2),
     2        ALLOC(LBELX+LX/2), LX = LXMIN, LXMAX, 2 )
 683  FORMAT ( '0THE REACTION IS INELASTIC EXCITATION OF THE ', 2A8 /
     1  '0LX', 9X, 'DEFORMATION PARAMETERS', T44, 'B(E(LX))' /
     2  T13, 'NUCLEAR', T28, 'COULOMB', T41, '(E**2 BARN**LX)' /
     3  (I3, 5X, 3G15.5) )
      write (6, 687) ( R2S(I), I = 1, 3 )
 687  FORMAT ( '0DEFORMATION RADII:' /                                  25710   
     1  '0  REAL', F14.4 /
     2  3X, 'IMAGINARY', F9.4 /
     3  3X, 'COULOMB', F11.4 )
C
 750  write (6, 751) LCRITS, LCRIT
 751  FORMAT ( / '0ESTIMATED CRITICAL L''S:    INCOMING =', I4,
     1  5X, 'OUTGOING =', I4, 5X, 'AVERAGE =', I4 )
      IF ( COUPSW )  GO TO 760
      IF ( ONELSW )  write (6, 753) LXMIN
 753  FORMAT ( '0', 5X, 'LX =', I3 )                                    25720   
      IF ( .NOT. ONELSW )  write (6, 754) LXMIN, LXMAX
 754  FORMAT ( '0', I5, '  =< LX =<', I3 )
      write (6, 757) LMIN, LMAX
 757  FORMAT ( '+', T25, I5, '  =<  LIN, LOUT  =<', I4 )
      GO TO 765
 760  write (6, 763) LMIN, LMAX
 763  FORMAT ( '0FOR COMPUTED S MATRICES:', I6, ' =< J OR LIN =<', I5 )
 765  IF ( ILVALU .EQ. 0 )  write (6, 767) LSTEP
 767  FORMAT ( '+', T60, 'LSTEP =', I3 )
      IF ( ILVALU .NE. 0 )  write (6, 768) LSTEP                        25730   
 768  FORMAT ('+', T60, 'USING SPECIFIED VALUES WITH A',
     1  ' MAXIMUM LSTEP OF', I4 )
C
C
C     CHECK VALIDITY OF Q AND PRINT WARNINGS.
C
 800  IF ( .NOT. TRANSW )  GO TO 810
      IF (DABS( EBNDS(1)-EBNDS(2)-ISTRIP*Q ) .GT. .001)  write (6, 803)
 803  FORMAT ( '0**** WARNING:  Q IS NOT EQUAL TO THE DIFFERENCE',
     1  ' OF THE BOUND STATE ENERGIES.' )                               25740   
 810  IF ( DABS( ECM+Q - ES(2) ) .GT. .001 )
     1  write (6, 813)
 813  FORMAT ( '0**** WARNING:  THE DIFFERENCE OF THE C.M. SCATTERING',
     1  ' ENERGIES IS NOT EQUAL TO Q.' )
C
      LOMOST = LMAX + LXMAX
C     INCASE LINTRP IS NOT USED:
      LIMOST = LMAX
C
C     CERTAIN THINGS THAT FOLLOW DON'T LIKE  LCRIT = 0                  25750   
C
      IF ( LCRIT .EQ. 0 )  LCRIT = LMAX/2
C
      RETURN
      END
C*ID* PRTCHI   C109.PTOLEMY.SOURCE                          PER701  16:
      SUBROUTINE  PRTCHI ( WT, ASHIFT, IREACT, RENORM )
C
C     PRINT THE CHI. SQ. INFO. AT THE START AND END OF A FIT
C                                                                       25760   
C
C     11/4/75 - SEPARATED FROM CALFUN - S.P.
C     11/20/75 - ANGLESHIFT, HEADER ADDED - S.P.
C     12/28/75 - ADD PRTDER ENTRY
C     2/18/76 - PRINT GRADIENT OF CHI.SQR./POINT
C     8/1/76 - SPLIT OFF PRTDER
C     4/15/77 - SMALL FIXES
C     10/16/77 - POWERS OF WOODS SAXONS
C     11/22/77 - USE TEMPVS COMMON - S.P.
C     11/27/77 - LINKULES                                               25770   
C     1/18/78 - CDC BECOMES CDB
C     3/24/78 - WAVEFUNTION LINKULES - S.P.
C     5/10/79 - COMPUTE RCOP, RCOT; R0MASS ALWAYS DEFINED - S.P.
C     12/28/79 - STANDARD MORTRAN - RPG
C     2/25/80 - REMOVE 1ST INDEX OF LNKNAM; CHAR*8 WORDS ETC. - RPG
C     3/15/80 - BACK TO TWO SUBSCRIPTS ON LNKNAM - S.P.
C     5/17/82 - PRINT VSI EVEN WHEN VI IS DONE BY LINKULE - S.P.
C     9/25/84 - PRINT VSI EVEN WHEN THERE IS NO VI - S.P.
C
C                                                                       25780   
      implicit real*8 ( a-h, o-z )                                      implicit
C
CDC      ALLOCLEVEL IREACT
      DIMENSION IREACT(11)
C
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      COMMON /LOCFIT/ IDATA, LPL, LSIGMA, LSMAT, IESETS, IMASK,         /locfit/
     &   IEQUAL, NPARA, IPARA, ITEMP, LSCSIG, LEPARM, LFS, NPTS, LEQNAM,
     &   MAXEQL, MAXVS, LVDERV, LSDELS, LDVTYP, LDSDP, LDFDX, LFGRAD,
     &   LTGRAD, LMASK, LEQUAL, MNDRIV, MXDRIV, IESIZE, LENPRE,
     &   LENKEY, LENHED,  ILNKBL
 
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
      COMMON /KANDM/ AKI, AKO, REDMI, REDMO, RIMAX, ROMAX, ISIGS(2),    /kandm/
     &  RSCTS(2), ASCTS(2), RCSCTS(2) ,ISMATS(2), LOMOST, LCRIT,
     &  ISCTMN, ISCTCR, ETAS(2), RCSCTP(2), RCSCTT(2), LCRITS(2),
     &  RATMSS(2), QMIN, ABAR
 
      DIMENSION  AKS(2), REDMS(2), RMAXS(2)
      EQUIVALENCE ( AKI, AKS(1) ), ( REDMI, REDMS(1) ),
     &  ( RIMAX, RMAXS(1) )
 
      COMMON / TEMPVS /  TVR, TVI, TVSOR, TVSOI, TAR, TAI               /tempvs/
 
      CHARACTER*1  REACT, HEADER                                        /hedcom/
      COMMON /HEDCOM/  REACT(45), HEADER(65)
 
c                                                                       /lnkblk/
c  STRUCTURE OF   /LNKBLK/
c
c  THERE IS A BLOCK OF 3 DOUBLE WORDS FOR EACH POSSIBLE USE
c  OF A LINKULE.  THE NUMLNK = NUMLINKULES USES ARE IN THE ORDER
c    REALPOTEN  IMAGPOTEN  REALVSO  IMAGVSO  COULOMB
c    WAVEFUNCTION  AND 6 TENSOR POTENTIALS
c  THE THREE-DOUBLE-WORD BLOCKS EACH HAVE THE STRUCTURE
c
c    LNKNAM(1,I)   LINKULE NAME
c
c      LNKADR(3,I)   LINKULE ADDRESS, O IF NO LINKULE IN USE.
c      LNKADR(4,I)   0 - NO L OR J DEPENDENCE IN POTENTIAL
c                    1 - L DEPENDENCE BUT NO J DEPENDENCE
c                    2 - BOTH L  AND J DEPENDENCE
c
c      LNKADR(5&6,I)  MYINTS - A TWO-ELEMENT ARRAY THAT THE
c                     LINKULE MAY USE FOR COMMUNICATION BETWEEN
c                     CALLS TO ITSELF.
c
      parameter ( NUMLINKULES = 13 )
      COMMON /LNKBLK/  NUMLNK, IUNIQU, LNKADR(6,NUMLINKULES)
      character*8  LNKNAM(3,NUMLINKULES)
      EQUIVALENCE ( LNKNAM(1,1), LNKADR(1,1) )
 
C
      CHARACTER*8  WORDS(2) / 'INITIAL ', '  FINAL ' /
C
      CHARACTER*8 POTTYP(5) / '    REAL', 'IMAGINAR', ' REAL SO',       25800   
     1  ' IMAG SO', ' COULOMB' /
      CHARACTER*8  BLANK / ' ' /
C
C
      LOGICAL SOSW, SOISW, IMAGSW
c
C
C
      IMAGSW = TVI .NE. 0
      SOSW = TVSOR .NE. 0                                               25810   
      SOISW = TVSOI .NE. 0
      LWORDS = Z(NAMLOC('FITWORDS')) - 1
      IF(IOFFIT.NE.1)GO TO 100
      IF(ITEMP.EQ.1)WRITE(6, 63)
 63   FORMAT(/ '-INITIAL ITERATION '/)
      IF(ITEMP.EQ.3)WRITE(6, 64)
 64   FORMAT(/ '-FINAL FIT'/)
      DO  89 I=1,NPARA
CDBC
CDBC     FOLLOWING IS REALLY JUST FOR BERKELEY'S STUPIDITY              25820   
CDBC
CDB      IF ( MAXEQL .NE. 0 )  write (6, 77)
CDB     1  ( ALLOC(LEQNAM+(I-1)*MAXEQL+II), II = 1, MAXEQL )
      WRITE(6, 73)ALLOC(LWORDS+I), ALLOC(IPARA-1+I)
 73   FORMAT(' ',10X,A8,' =',G15.5)
CNB      IF ( MAXEQL .EQ. 0 )  GO TO  89
      IF ( dALLOC(LEQNAM+(I-1)*MAXEQL+1) .EQ. BLANK )  GO TO 89
CNB      write (6,  77) ( dALLOC(LEQNAM+(I-1)*MAXEQL+II), II = 1, MAXEQL
  77  FORMAT ( '+', ( T40, 6( A5, A8 ) ) )
 89   CONTINUE                                                          25830   
C
C  PRINT HEADER
C
 100  write (6, 103) WORDS(ITEMP/2+1), ( ALLOC(LWORDS+I),
     1   I = 1, NPARA )
 103  FORMAT ( '1', T48, 'P T O L E M Y' /
     1  1X, 'ELASTIC SCATTERING FIT - ', A8, 'VALUES',
     2    T75, 'FITTING:', ( T85, 6A8 ) )
      write (6, 108) IREACT, HEADER
 108  FORMAT ( 1X, 11A4, 21X, 65A1 )                                    25840   
CDC 108  FORMAT ( 1X, 11A1, 54X, 65A1 )
      WRITE(6,123)ELAB, WT, ASHIFT, RENORM
123   FORMAT( '-E LAB =', F9.4, ' MEV', 10X, ' WEIGHT =', F9.4,
     1   10X, 'LAB-ANGLE SHIFT =', F7.3, ' DEGREES' ,
     2   10X, 'RENORM =', F7.4 )
C
C     RECOMPUTE R0'S FOR PRINTING
C
      TEMP1 = R/R0MASS
      IF ( TVI .NE. 0 )  TEMP2 = RI/R0MASS                              25850   
      IF ( VSO .NE. 0 ) TEMP3 = RSO/R0MASS
      IF ( VSOI .NE. 0 )  TEMP4 = RSOI/R0MASS
      IF ( VSI .NE. 0 )  TEMP5 = RSI/R0MASS
      TEMP6 = RC/R0MASS
      ETA = ETAS(1)
      NSTEP = NSTPSS(1)
C
C     WITH THE EXCEPTION OF STMNTS 420 AND 429, ALL OF THE FOLLOWING
C     ARE LIFTED DIRECTLY FROM WAVSET.
C                                                                       25860   
 420  write (6, 429)
 429  FORMAT (
     6  '0POTENTIAL', T20, 'COUPLING CONS.', T38, 'RADIUS',
     7      T48, 'DIFFUSENESS', T63, 'RADIUS PARAMETER',
     8      T82, 'POWER' / )
C
      I = 1
      IF ( LNKADR(3,1) .NE. 0 )  GO TO 550
      write (6, 437) TVR, R, TAR, TEMP1, POWRL
 437  FORMAT ( ' REAL', T20, G14.5, T37, F7.4, T49, F7.4, T67, F7.4,    25870   
     A      T80, F7.3 )
C
 440  IF ( .NOT. IMAGSW )  GO TO 445
      I = 2
      IF ( LNKADR(3,2) .NE. 0 )  GO TO 550
      write (6, 443) TVI, RI, TAI, TEMP2, POWIM
 443  FORMAT (' IMAGINARY', T20, G14.5, T37, F7.4, T49, F7.4,
     1  T67, F7.4, T80, F7.3 )
 445  IF ( VSI .NE. 0 )  write (6, 446) VSI, RSI, ASI, TEMP5
 446  FORMAT ( ' SURFACE ABSORPTION:', T20, G14.5, T37, F7.4,           25880   
     1  T49, F7.4, T67, F7.4, T80, F7.3 )
C
 450  IF ( .NOT. SOSW )  GO TO 460
      I = 3
      IF ( LNKADR(3,3) .NE. 0 )  GO TO 550
      write (6, 453) VSO, RSO, ASO, TEMP3, TAU
 453  FORMAT (' REAL SPIN-ORBIT', T20, G14.5, T37, F7.4, T49, F7.4,
     1  T67, F7.4, 5X, 'TAU  =', G13.5 )
C
 460  IF ( .NOT. SOISW )  GO TO 470                                     25890   
      I = 4
      IF ( LNKADR(3,4) .NE. 0 )  GO TO 550
      write (6, 463) VSOI, RSOI, ASOI, TEMP4, TAUI
 463  FORMAT (' IMAG SPIN-ORBIT', T20, G14.5, T37, F7.4, T49, F7.4,
     1  T67, F7.4, 5X, 'TAUI =', G13.5 )
C
 470  IF ( ETA .EQ. 0 )  GO TO 500
      I = 5
      IF ( LNKADR(3,5) .NE. 0 )  GO TO 550
      write (6, 183) ETA, RC, TEMP6                                     25900   
 183  FORMAT ( ' COULOMB', T20, G14.5, T37, F7.4, T67, F7.4 )
      IF((RCP.EQ.0).OR.(RCT.EQ.0)) GO TO 500
      TEMP2 = RCP / AMP**0.33333333333333333333 0D0
      TEMP3 = RCT / AMT**0.33333333333333333333 0D0
      write (6, 187) RCP, RCT, TEMP2, TEMP3
  187 FORMAT( ' FOLDED COULOMB POTENTIALS - RCP = ',F7.4,2X,
     1'RCT = ',F7.4,2X,'RC0P = ',F7.4,2X,'RC0T = ',F7.4)
C
C     WILL THE WAVE FUNCTIONS BE FOUND BY A LINKULE
C                                                                       25910   
 500  IF ( LNKADR(3,6) .EQ. 0 )  GO TO 600
      write (6, 533) LNKNAM(1,6)
 533  FORMAT ( '0 THE SCATTERING WAVEFUNCTION IS BEING',
     1  ' COMPUTED BY THE ', A8, ' LINKULE:' )
      I = 6
      GO TO 560
 600  GO TO 900
C
C
C     CALL LINKULE TO PRINT STUFF ABOUT ITSELF                          25920   
C
 550  write (6, 553) POTTYP(I), LNKNAM(1,I)
 553  FORMAT ( '0', A8, ' POTENTIAL IS BEING COMPUTED BY THE ',
     1  A8, ' LINKULE:' )
C
 560  CALL LINKUL ( LNKADR(3,I), LNKNAM(1,I), LNKADR(5,I),
     1  I, 2, IRET,
     2  L, J, 0.D0, STEPSZ, NSTEP+1, DUMMY, DUMMY, 1 )
      write (6, 563)
 563  FORMAT ( ' ' )                                                    25930   
      IF ( IRET .GE. 0 )  GO TO ( 440, 445, 460, 470, 500, 600 ), I
      IRET = 0
      RETURN
C
C
  900 CONTINUE
C
C
      RETURN
      END                                                               25940   
C*ID* PRTDER   C109.PTOLEMY.SOURCE                          PER701  15:
      SUBROUTINE  PRTDER ( X, GRADSW, TGRAD, HESNSW, COVAR, WORK,
     1  MPARA, T1 )
C
C     THIS ENTRY PRINTS STUFF ABOUT THE FINAL GRADIENT AND/OR
C     THE COVARIANCE MATRIX.
C     IT ALSO PRINTS THE FIT TIMES
C
C
C     1/8/76 - SPLIT OFF FROM PRTCHI TO MAKE CDC EASIER.                25950   
C     4/8/78 - COMPUTE DIAGONAL RMS DEVIATIONS CORRECTLY - S.P.
C     5/26/78 - REAL*4 T1 FOR ALIGNMENT PROBS - S.P.
C     12/28/79 - STANDARD MORTRAN - RPG
C
      implicit real*8 ( a-h, o-z )                                      implicit
CDC      ALLOCLEVEL X,TGRAD,COVAR,WORK
C
      DIMENSION  X(MPARA), TGRAD(MPARA), COVAR(MPARA, MPARA),
     1  WORK(MPARA)
      LOGICAL GRADSW , HESNSW                                           25960   
      REAL*4 T1
C
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      CHARACTER*1  REACT, HEADER                                        /hedcom/
      COMMON /HEDCOM/  REACT(45), HEADER(65)
 
      REAL*4 T0                                                         /fitcom/
      COMMON /FITCOM/ T0, IP, IPL, IEPARM, IFS, MAXCAL,
     & NROC, ISCSIG
 
      COMMON /LOCFIT/ IDATA, LPL, LSIGMA, LSMAT, IESETS, IMASK,         /locfit/
     &   IEQUAL, NPARA, IPARA, ITEMP, LSCSIG, LEPARM, LFS, NPTS, LEQNAM,
     &   MAXEQL, MAXVS, LVDERV, LSDELS, LDVTYP, LDSDP, LDFDX, LFGRAD,
     &   LTGRAD, LMASK, LEQUAL, MNDRIV, MXDRIV, IESIZE, LENPRE,
     &   LENKEY, LENHED,  ILNKBL
 
      REAL*4  TBEGIN, TIMES                                             /ftimef/
      COMMON /FTIME/ TBEGIN, NUMLOP, NUMWAV, TIMES(6), NUMCAL, NUMGRA
 
C
C
      LWORDS = Z(NAMLOC('FITWORDS')) - 1                                25970   
C
C
      IF ( .NOT. (GRADSW .OR. HESNSW) )  GO TO 800
      write (6, 301)
 301  FORMAT ( '1', T48, 'P T O L E M Y' /
     1 T27, 'ELASTIC SCATTERING FIT - FINAL VALUES AND UNCERTAINTIES' )
      write (6, 108) REACT, HEADER
 108  FORMAT ( 1X, 48A1, 17X, 65A1 )
      write (6, 303) ( ALLOC(LWORDS+I), I = 1, NPARA )
 303  FORMAT ( / '0', T11, 'PARAMETER:', ( T23, 10( A8, 3X ) ) )        25980   
C
      write (6, 308) X
 308  FORMAT ( / '0FINAL VALUES:', ( T21, 10G11.3 ) )
C
      IF ( .NOT. GRADSW )  GO TO 400
C
C     HERE PROCESS GRADIENT
C
      DO 309  I = 1, NPARA
         TGRAD(I) = TGRAD(I)/NPTS                                       25990   
 309  CONTINUE
      write (6, 313) TGRAD
 313  FORMAT ( / '0FINAL GRADIENT:', ( T21, 10G11.3 ) )
C
      SUM = 0
      DO 319  I = 1, NPARA
         TGRAD(I) = TGRAD(I)*X(I)
         SUM = SUM + TGRAD(I)**2
 319  CONTINUE
      write (6, 323) TGRAD                                              26000   
 323  FORMAT ( '0RELATIVE GRADIENT:', ( T21, 10G11.3) )
      SUM = DSQRT(SUM)
      write (6, 328) SUM
 328  FORMAT ( ' MAGNITUDE OF RELATIVE GRADIENT =', G15.5 )
C
 400  IF ( .NOT. HESNSW )  GO TO 800
C
C     HERE PROCESS THE COVARIANCE MATRIX
C
C     TURN IT INTO .5 * SECOND DERIVATIVE MATRIX                        26010   
C
      CALL MATINV ( COVAR, NPARA, WORK, 0, DET, NPARA )
C
C     NOW PRINT DIAGONAL RMS UNCERTAINTIES
C
      DO 409  I = 1, NPARA
         WORK(I) = 666.D+66
            IF ( COVAR(I,I) .GT. 0 )  WORK(I) = DSQRT( 1/COVAR(I,I) )
 409  CONTINUE
      write (6, 413) WORK                                               26020   
 413  FORMAT ( / '0RMS UNCERTAINTIES:', (T21, 10G11.3) )
C
C     MAKE THE RELATIVE SECOND DERIV MATRIX ( TIMES .5 )
C
      DO 429  I = 1, NPARA
         DO 425  II = 1, NPARA
            COVAR(I,II) = COVAR(I,II)*(X(I)*X(II))
 425     CONTINUE
         WORK(I) = 666.D+66
            IF ( COVAR(I,I) .GT. 0 )  WORK(I) = DSQRT( 1/COVAR(I,I) )   26030   
 429  CONTINUE
      write (6, 433) WORK
 433  FORMAT ( '0RELATIVE' / ' RMS UNCERTAINTIES:', (T21, 10G11.3) )
C
      CALL SDIAG ( NPARA, NPARA, 1.D-13, 30, COVAR, WORK,
     1  COVAR, TGRAD )
C
      DO 459   I = 1, NPARA
         ALL = 666.D+66
         IF ( WORK(I) .GT. 0 )  ALL = DSQRT( 1/WORK(I) )                26040   
         WORK(I) = ALL
 459  CONTINUE
C
      write (6, 463)
 463  FORMAT ( / '0EIGEN-ANALYSIS OF THE RELATIVE COVARIANCE MATRIX' /
     1  '0SQRT(EIGENVALUE)     EIGENVECTOR' / )
      DO 469  I = 1, NPARA
      write (6, 467) WORK(I), ( COVAR(II,I), II = 1, NPARA )
 467     FORMAT ( G15.5, ( T21, 10G11.3 ) )
 469  CONTINUE                                                          26050   
C
C
C     PRINT TIMING INFORMATION
C
 800  write (6, 803)
 803  FORMAT ( '1', T48, 'P T O L E M Y' /
     1  1X, 'ELASTIC SCATTERING FIT',
     2    T108, 'TIME HEALS ALL THINGS.' / )
      write (6, 108) REACT, HEADER
C                                                                       26060   
C   TIMES FOR ELASTIC SCATTERING FIT COMPONENTS
C
      T4=second()
      ALL=T4-T0
      AINIT=T1-T0
      WAVTIM = TIMES(1)+TIMES(2)+TIMES(3)
      TCALGR = TIMES(4) + TIMES(5)
      TOTHER = ALL - AINIT - TCALGR
      IF ( .NOT. GRADSW )  TIMES(6) = WAVTIM
      TCALOT = TCALGR - TIMES(6)                                        26070   
      TIMES(6) = TIMES(6) - WAVTIM
      write (6, 853) AINIT, (TIMES(I), I = 1, 3), WAVTIM, TIMES(6),
     1  TCALOT, TCALGR, TOTHER, ALL
 853  FORMAT ( / '0', 5X, 'ELASTIC SCATTERING FIT TIMES IN SECONDS' /
     1  '0INITIALIZATION',              T42, F8.3 /
     2  '0WAVELJ INITIALIZATION', T30, F8.3 /
     3  ' WAVELJ LOOP',           T30, F8.3 /
     4  ' WAVELJ TERMINATION',    T30, F8.3 /
     5  ' TOTAL WAVELJ',             T36, F8.3 /
     5  '0S-MATRIX GRADIENT',         T36, F8.3 /                       26080   
     6  ' OTHER CHI. SQR. SUM TIME', T36, F8.3 /
     7  ' TOTAL CHI. SQR. SUM & GRADIENTS',   T42, F8.3 /
     8  '0ALL OTHER TIME',              T42, F8.3 /
     9  ' TOTAL TIME',                     T48, F8.3 )
C
      TIMES(2) = 1.E6*TIMES(2)/NUMLOP
      WAVTIM = 1.E3*WAVTIM/NUMWAV
      TIMES(4) = TIMES(4)/NUMCAL
      IF ( GRADSW )  TIMES(5) = TIMES(5) / NUMGRA
      write (6, 863) NUMLOP, TIMES(2), NUMWAV, WAVTIM, NUMCAL, TIMES(4) 26090   
 863  FORMAT ( '0', I9, ' PASSES THROUGH WAVELJ LOOP',
     1     T47, 'LOOP TIME =', F6.1, '    MICROSECONDS' /
     2  I10, ' WAVELJ CALLS',
     3     T45, 'WAVELJ TIME =', F7.2, '   MILLISECONDS' /
     4  I10, ' CHI. SQR. SUMS WITHOUT GRADIENTS',
     5     T48, 'SUM TIME =', F9.4, ' SECONDS' )
      IF ( GRADSW )  write (6, 867) NUMGRA, TIMES(5)
 867  FORMAT ( I10, ' GRADIENTS', T43, 'GRADIENT TIME =',
     1  F9.4, ' SECONDS' )
      write (6, 873)                                                    26100   
 873  FORMAT ( '1' )
      RETURN
      END
C*ID* QVSCAN   C109.PTOLEMY.SOURCE                          PER701  15:
      SUBROUTINE QVSCAN ( GUY, ESTARS, NODVLS, LVALS, JVALS, IPARYS,
     1  IRTN )
C
C - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - -
C  SCANS AN INPUT LINE FOR Q-VALUE PROGRAM
C                                                                       26110   
C  DESCRIPTION OF PARAMETERS:
C  GUY    R*8 A 4-COMPONENT ARRAY THAT WILL CONTAIN THE PARTICIPANTS
C  ESTARS R*8 WILL BE SET TO EXPLICITLY GIVEN EXCITED STATE E'S.
C  NODVLS I*4 NUMBER OF NODES FROM LEVEL SPEC (3P MEANS NODVLS=2)
C  LVALS  I*4 L-VALUE FROM LEVEL SPEC
C  JVALS  I*4 WILL BE SET TO EXPLICITLY GIVEN J'S.
C  IPARYS I*4 -1, 0, +1 FOR PARITIES.
C  IRTN   I*4 AN ERROR RETURN CODE
C         =0  AOK         =-1 SYNTAX ERROR
C                                                                       26120   
C     IN THIS VERSION, THE INPUT LINE IS IN   /INPBUF/.
C     THIS VERSION DOES NOT RECOGNIZE  *'S  OR  &'S.
C
C     CODED BY F. SERDUKE
C     5/8/75 - PTOLEMY VERSION - S. P. - USE /INPBUF/; NO *,&;
C              PROCESS EXCITED STATES.
C     7/27/76 - DON'T USE FIELD
C     9/24/77 - ESTAR = UNDEF FOR UNDEFINED
C     5/6/79 - PARITIES, LEVEL SPECS - S.P.
C     12/28/79 - STANDARD MORTRAN - RPG                                 26130   
C     1/11/80 - SEPARATE CVALU ARGUMENT TO MSCAN; QUOTES IN DATA STMT -
C     6/3/80 - CDC VERSION OF STOPS DATA - S.P.
C     7/14/80 - CDM, CDO PREFIXES - S.P.
C
C - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - -
C
      IMPLICIT INTEGER*4 (A-Z)
C
      DIMENSION  NODVLS(4), LVALS(4), JVALS(4), IPARYS(4)
C                                                                       26140   
      REAL*8  UNDEF
      COMMON /INTRNL/  UNDEF, NOTDEF
C
      parameter ( ibufsize = 200 )                                      /inpbuf/
      CHARACTER*1 IBUF(ibufsize)
      COMMON /INPBUF/ NOCH, INCH, IBUF
 
C
      CHARACTER*1  SLASH /'/'/,  PLUS /'+'/,  MINUS /'-'/
      CHARACTER*8 GUY(4), BLANK8/' '/, CVALU
      REAL*8  ESTARS(4), VALU, DUMMY
      CHARACTER*1 STPCHR, BLANK/' '/,  COMMA /','/
C                                                                       26150   
      CHARACTER*1  STOPS(4)
      DATA  STOPS / '(', ',', ')', ' ' /
C
      IRTN = 0
      INCHST = INCH
C
C --- LOOP ON THE REACTION PARTICIPANTS
      DO 699 I=1,4
      GUY(I) = BLANK8
         NODVLS(I) = NOTDEF                                             26160   
         LVALS(I) = NOTDEF
         JVALS(I) = NOTDEF
         ESTARS(I) = UNDEF
         IPARYS(I) = 0
      CALL MSCAN ( -20, ITOKEN, GUY(I), VALU, IVALU, IBUF, IMESS,
     1   STPCHR )
         IF ( IMESS .GT. 5 )  GO TO 9004
         IF ( IMESS .EQ. 0 )  GO TO 9005
         INCH = INCH+1
C                                                                       26170   
C
C     IF STOPPED BY A  (  AND NOT FIRST FIELD THEN PROCESS EXCITED STATE
C     STATE.
C
      IF ( STPCHR .NE. STOPS(1)  .OR.  I .EQ. 1 )  GO TO 400
C
C     GET E* AND J
C
 200  CALL MSCAN ( 18, ITOKEN, CVALU, VALU, IVALU, IBUF, IMESS,
     1   STPCHR )                                                       26180   
      IF ( ITOKEN .EQ. -9)  GO TO 9900
      IF ( ITOKEN .EQ. -8 )  GO TO 9007
      IF ( ITOKEN .NE. -2 )  GO TO 230
C
C     IT IS E*
C
      IF ( ESTARS(I) .EQ. UNDEF )  GO TO 220
      write (6, 213)
 213  FORMAT ( '0**** ATTEMPTING TO ENTER 2 VALUES FOR E*' )
      GO TO 9900                                                        26190   
 220  ESTARS(I) = VALU
      GO TO 200
C
 230  IF ( ITOKEN .NE. -5 )  GO TO 270
C
C     IT IS J
C
      IF ( JVALS(I) .EQ. NOTDEF )  GO TO 240
      write (6, 233)
 233  FORMAT ( '0**** ATTEMPTING TO ENTER 2 VALUES FOR J' )             26200   
      GO TO 9900
 240  JVALS(I) = 2*IVALU
      IF ( STPCHR .NE. SLASH )  GO TO 250
C
C     BYPASS /2
C
      INCH = INCH+1
      JVALS(I) = IVALU
C
C     IT IS NECESSARY TO CODE THE 2 FOLLOWING THE /                     26210   
C     MAKE SURE IT IS JUST A SIMPLE 2
C
      CALL MSCAN ( 18, ITOKEN, CVALU, VALU, IVALU, IBUF, IMESS, STPCHR )
      IF ( ITOKEN .EQ. -9 )  GO TO 9900
      IF ( ITOKEN .EQ. -8 )  GO TO 9007
      IF ( ITOKEN .EQ. -5  .AND. IVALU .EQ. 2 )  GO TO 250
      write (6, 243)
 243  FORMAT ( '0**** INVALID J FIELD' )
      GO TO 9900
C                                                                       26220   
C     BYPASS TERMINAL + OR -
C
 250  IP = +1
      IF ( STPCHR .EQ. PLUS )  GO TO 255
      IP = -1
      IF ( STPCHR .NE. MINUS )  GO TO 200
 255  IPARYS(I) = IP
      INCH = INCH+1
      GO TO 200
C                                                                       26230   
 270  IF ( ITOKEN .NE. -3 )  GO TO 280
C
C     IT IS A NODES AND L PART OF A LEVEL DESCRIPTOR
C
      IF ( LVALS(I) .EQ. NOTDEF )  GO TO 275
      write (6, 273)
 273  FORMAT ( '0**** ATTEMPTING TO ENTER TWO LEVEL DESCRIPTORS' )
      GO TO 9900
 275  LVALS(I) = IVALU
      NODVLS(I) = VALU                                                  26240   
      GO TO 200
C
C     IS IT THE CLOSING )
C
 280  IF ( ITOKEN .EQ. 11 )  GO TO 290
      write (6, 283) ITOKEN
 283  FORMAT ( '0**** UNRECOGNIZABLE EXCITED STATE DESCRIPTOR (TOKEN =',
     1  I4, ')' )
      GO TO 9900
C                                                                       26250   
C     ALL DONE WITH THE EXCITED STATE; BYPASS FINAL ).
C
 290  STPCHR = IBUF(INCH)
      INCH = INCH + 1
C
C
C
C ----- BYPASS BLANKS
 400  IF ( STPCHR .NE. BLANK .OR. I .EQ. 2  .OR. I .EQ. 4 ) GO TO 500
      CALL MSCAN ( -20, ITOKEN, CVALU, DUMMY, IVALU, IBUF, IMESS,       26260   
     1   STPCHR )
      STPCHR = IBUF(INCH-1)
      IF ( IMESS .NE. 0 )  GO TO 9006
C ... LEFT AND RIGHT PARENTHESES MUST FOLLOW 1-ST AND 3-RD GUYS
 500  IF ( (I.EQ.1 .OR. I.EQ.3)  .AND.  STPCHR.NE.STOPS(I) ) GO TO 9001
C          THERE MUST BE A BLANK OR COMMA AFTER THE SECOND GUY
      STPTYP = 2
      IF ( STPCHR .EQ. BLANK  .OR.  STPCHR .EQ. COMMA )  STPTYP = 1
      IF ( I.EQ.2 .AND. STPTYP.NE.1 ) GO TO 9002
 699  CONTINUE                                                          26270   
      IF ( STPTYP .NE. 1  .AND.  INCH .LE. NOCH )  GO TO 9003
      RETURN
C PARENTHESES NOT IN RIGHT PLACE
9001  write (6, 9011)
 9011 FORMAT ( '0**** MISSING PARENTHESIS.' )
      GO TO 9900
C BLANK OR COMMA NOT AFTER 2-ND GUY
9002  write (6, 9012)
 9012 FORMAT ( '0**** INVALID DELIMITOR AFTER INCOMING PROJECTILE.' )
      GO TO 9900                                                        26280   
9003  write (6, 9013)
 9013 FORMAT ( '0**** ONLY 4 PARTICIPANTS IN REACTION ALLOWED.' )
      GO TO 9900
C  ONE OF THE GUYS HAS MORE THAN 5 CHARACTERS IN IT
9004  write (6, 9014)
 9014 FORMAT ( '0**** TOO MANY CHARACTERS IN SYMBOL AND ATOMIC MASS.' )
      GO TO 9900
 9005 write (6, 9015)
 9015 FORMAT ( '0**** UNEXPECTED DELIMITOR OR END OF LINE ENCOUNTERED',
     1  ' WHEN LOOKING FOR ELEMENT SYMBOL.' )                           26290   
      GO TO 9900
 9006 write (6, 9016) DUMMY
 9016 FORMAT ( '0**** UNEXPECTED FIELD ENCOUNTERED WHEN LOOKING FOR ',
     1  'DELIMITOR; FIELD = ', A8 )
      GO TO 9900
 9007 write (6, 9017)
 9017 FORMAT ( '0**** COMPLETE REACTION MUST BE ON SAME LINE AS',
     1  ' REACTION KEYWORD.' )
      GO TO 9900
C                                                                       26300   
 9900 INCHM1 = INCH - 1
      write (6, 9903) I, ( IBUF(II), II = INCHST, INCHM1 )
 9903 FORMAT ( 6X, 'WAS PROCESSING FIELD', I2, ' OF THE REACTION' /
     1  6X, 'REACTION UP TO THE ERROR IS: ', 80A1 )
      IRTN = -1
      RETURN
      END
C*ID* RCASYM   C109.PTOLEMY.SOURCE                          PER701  15:
      SUBROUTINE RCASYM ( L, ETA, RHO, IPRN, SIGL, ZETA, PHI, DZETA,
     1  F, FP, G, GP, Z, DZSQ, S, ZINV, EPS, NMAX, NTZ, ISIG )          26310   
C
C     ASYMPTOTIC SERIES IN 1/RHO FOR COULOMB FUNCTIONS
C
C     THIS INVOLVES THE REPRESENTATION SIN(PHI)/SQRT(ZETA)
C     AND COS(PHI)/SQRT(ZETA) FOR F AND G
C     THE NON-LINEAR EQUATION FOR ZETA IS THEN SOLVED DIRECTLY
C     TERM BY TERM. WE WORK WITH A POWER SERIES
C     REPRESENTATION OF ZETA IN 1/RHO. THIS POWER SERIES
C     IS THEN FOUND COEFFICIENT BY COEFFICIENT IN ASCENDING POWERS
C     STOPPING WHEN LAST TERMS IS LESS IN MAGNITUDE THAN EPS            26320   
C
C     ARGUMENT-LIST FOR CALCULATION OF FL,GL(ETA,RHO)
C
C      L     (INPUT) I*4 ANGULAR MOMENTUM
C      ETA   (INPUT) R*8 COULOMB PARAMETER
C      RHO   (INPUT) R*8 RADIAL VARIABLE
C      IPRN  (INPUT) I*4 PRINT CONTROL (=0 ONLY ERROR MESSAGES)
C      SIGL  (INPUT) R*8 COULOMB PHASE-SHIFT
C      ZETA  (RETURNED) R*8  AMPLITUDE FUNCTION AT RHO
C      PHI   (RETURNED) R*8  PHASE FUNCTION                             26330   
C      DZETA (RETURNED) R*8  DERIVATIVE OF ZETA WRT RHO
C      F,G   (RETURNED) R*8  REGULAR AND IRREGULAR COULOMB FNS AT RHO
C      FP,GP (RETURNED) R*8  DERIVATIVES OF COULOMB FNS
C      Z     (RETURNED) R*8  ARRAY OF FIRST (NTZ+1) COEFFICIENTS IN
C                       OF SERIES FOR ZETA IN POWERS OF (RHO/RHO0)**-1
C            SERIES FOR ZETA IN INVERSE POWERS OF RHO/RHO0
C            WITH RHO0 = RHO
C      DZSQ,S,ZINV  R*8 WORK ARRAYS (DIMENSION NTZ+1)
C      EPS   (INPUT) R*8 DESIRED RELATIVE ACCURACY
C      NMAX   (INPUT) I*4 MAXIMUM NO OF TERMS IN SERIES                 26340   
C      NTZ   (RETURNED) I*4 NO OF TERMS IN POWER SERIES FOR ZETA
C      ISIG  (RETURNED) I*4 ERROR SIGNAL (EQ.0 IF ALL IS WELL)
C
C     MHM - DECEMBER 10, 1976
C     JAN 16, 1977 - DZ ARRAY REMOVED - S.P.
C     JAN 24, 1977 - DO NOT ALLOW ASYMPTOTIC COEFS TO INCREASE
C     12/28/79 - CFR%F - RPG
C
C
      IMPLICIT REAL*8(A-H,O-Z)                                          26350   
C
      DIMENSION Z(1),DZ(1),DZSQ(1),S(1),ZINV(1)
C
C
      DATA PI/3.14159 26535 89793 0D0/
C
c
C
      ISIG=0
      FLL=L*(L+1)                                                       26360   
      ETASQ=ETA*ETA
      RHOSQ=RHO*RHO
      BF1=2*(ETA/RHO)
      BF2=FLL/RHOSQ
      IF(ETA.GT.0) RHOT=ETA*(1+DSQRT(1.D0+FLL/ETASQ))
      IF(ETA.EQ.0) RHOT=DSQRT(FLL)
      IF((ETA.EQ.0).AND.(L.EQ.0)) RHOT=.5
      IF(ETA.LT.0) RHOT=DABS(ETA)*(DSQRT(1.D0+FLL/ETASQ)-1)
      IF(RHO.GT.RHOT) GO TO 1
      write (6, 100)                                                    26370   
  100 FORMAT(1H0,2X,'-- RCASYM. ASYMPTOTIC EAXPANSION INSIDE TP --')
      ISIG=-5
      GO TO 50
C
C     SOLVE DIFFERENTIAL EQUATION FOR ZETA TERM BY TERM FOR
C     COEFFICIENTS OF POWER-SERIES IN RHO**-N FOR ZETA
C
    1 Z(1)=1
      S(1)=1
      DZSQ(1)=0                                                         26380   
      ZINV(1)=1
      ZETA=Z(1)
      DZETA=0
      PHI=RHO-ETA*DLOG(2.D0*RHO)+SIGL-.5*L*PI
      KSER=2
      NTZ=1
      I=2
  500 Z(I)=0
      JTOP=(I+1)/2
      S(I)=0                                                            26390   
      DZSQ(I)=0
      CF=0
      IF(I.EQ.2) GO TO 515
      DO 510 J=2,JTOP
      FACTOR=2
      IF(J.EQ.(I-J+1)) FACTOR=1
  510 S(I)=S(I)+FACTOR*Z(J)*Z(I-J+1)
  515 JHI=I-1
      DO 520 J=1,JHI
  520 CF=CF+Z(J)*S(I-J+1)                                               26400   
      BF=-BF1*Z(I-1)
      IF(I.GT.2) BF=BF-BF2*Z(I-2)
      IF(I.LE.5) GO TO 545
      ILOC=I-4
      JJTOP=ILOC-1
      ZINV(ILOC)=0
      DO 540 J=1,JJTOP
  540 ZINV(ILOC)=ZINV(ILOC)-ZINV(J)*Z(ILOC-J+1)
  545 TF=0
      IF(I.LE.4) GO TO 560                                              26410   
      DO 565 J=3,JTOP
      FACTOR= 2/RHO**2
      IF(J.EQ.(I-J+1)) FACTOR= 1/RHO**2
  565 DZSQ(I)=DZSQ(I)+FACTOR*(J-2)*(I-J-1)*Z(J-1)*Z(I-J)
      JJTOP=I-4
      DO 550 J=1,JJTOP
  550 TF=TF+ZINV(J)*DZSQ(I-J+1)
  560 D2F=0
      IF(I.GT.3) D2F=(I-2)*(I-3)*(Z(I-2)/RHOSQ)
      Z(I)=(-CF+BF+.75*TF-.5*D2F)*.5                                    26420   
      IF(IPRN .GE. 5) write (6, 563)I,Z(I),CF,BF,TF,D2F
  563 FORMAT(I5, ' Z =', 5G13.6 )
      NTZ=NTZ+1
      S(I)=S(I)+2*Z(I)
      ZETA=ZETA+Z(I)
      IF(DABS(Z(I)).GE.EPS) GO TO 570
      KSER=KSER-1
  570 DZETA=DZETA - (I-2)*Z(I-1)/RHO
      IF((I.EQ.2).OR.(DABS((I-2)*Z(I-1)/RHO).GE.EPS)) GO TO 580
      KSER=KSER-1                                                       26430   
  580 IF(I.EQ.2) GO TO 590
      PHI=PHI-(Z(I)*RHO)/DFLOAT(I-2)
  590 IF(KSER.LE.0) GO TO 600
      I=I+1
      IF(I .GT. NMAX) GO TO 1000
C
C     MAKE SURE WE HAVE NOT PASSED THE MINIMUM OF THE ASYMPTOTIC
C     SERIES
C
      IF ( I .LT. 8 )  GO TO 500                                        26440   
      IF ( DABS(Z(I-1)) .GT. DABS(Z(I-7)) )  GO TO 1020
      GO TO 500
C
C     HAVE CONVERGED
C
  600 CONTINUE
      IF(IPRN.GT.0) write (6, 170)NTZ,ZETA,DZETA,PHI
  170 FORMAT(1H0,2X,'WITH ',I2,' TERMS,  ZETA = ',G22.14/
     13X,'DZETA = ',G22.14,' PHI = ',G22.14)
C                                                                       26450   
C     COMPUTE REGULAR AND IRREGULAR COULOMB FUNCTIONS AND DERIVATIVES
C     IN TERMS OF PHI ZETA AND D(ZETA)/D(RHO)
C
   90 RTZ=DSQRT(ZETA)
      F=DSIN(PHI)/RTZ
      G=DCOS(PHI)/RTZ
      FACTOR=(.5*DZETA)/(ZETA*ZETA)
      FP=ZETA*(G-FACTOR*F)
      GP=-ZETA*(F+FACTOR*G)
C                                                                       26460   
   50 RETURN
C
C     COULD NOT CONVERGE
C
 1000 IF ( IPRN .GT. -4 )  write (6, 1010)NMAX
 1010 FORMAT( ' **** MORE THAN ',I4,' TERMS NEEDED IN SERIES FOR ZETA
     1  ****')
      GO TO 1050
C
 1020 IF ( IPRN .GT. -4 )  write (6, 1023) I                            26470   
 1023 FORMAT ( ' **** COULOMB SERIES TURNS AT', I6, ' TERMS ****' )
C
 1050 IF ( IPRN .GT. -4 )  write (6, 1053) L, ETA, RHO, ZETA, Z(I-1)
 1053 FORMAT ( ' **** L, ETA, RHO, ZETA, LAST =', I4, 4G15.5 )
      ISIG = -5
      GO TO 50
C
      END
C*ID* REACTN   C109.PTOLEMY.SOURCE                          PER701  15:
      SUBROUTINE REACTN ( IRET )                                        26480   
C
C     SCANS A REACTION OF THE GENERAL FORM
C         40CA(O16, 12C(2+ 3.26))44TI(7.23 3/2)
C
C     AND STORES  Z'S,  M'S,  J'S,  E*'S,  AND  MASS EXCESSES  OF
C     THE 5 PARTILCES INTO THE COMMON BLOCKS.
C
C     5/12/75 - FIRST VERSION - S. PIEPER
C     12/12/76 - ELASTIC AND INELASTIC SCATTERING ADDED
C     9/24/77 - RECOGNIZE E*=0; ALLOW LATTER DEF OF MASS EXCESS         26490   
C     5/6/79 - PARITIES; LEVEL SPECS - S.P.
C     12/28/79 - STANDARD MORTRAN - RPG
C     1/31/80 - CHARDATAVALUE IS NUMERIC; SYMBOL, ALPHA ARE CHAR. - RPG
C     7/15/81 - ALLOW ABSURB TRANSFERS; USE CHARINT - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      parameter ( NUMJWORD = 12 )                                       /jblock/
      COMMON /JBLOCK/  J, JS(5),
     &  JP, JSP, JST,
     &  JPARM1, JPARM2, JPARM3
 
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      CHARACTER*1  REACT, HEADER                                        /hedcom/
      COMMON /HEDCOM/  REACT(45), HEADER(65)
 
      parameter ( ibufsize = 200 )                                      /inpbuf/
      CHARACTER*1 IBUF(ibufsize)
      COMMON /INPBUF/ NOCH, INCH, IBUF
 
C
      CHARACTER*8  GUY(4)
      REAL*8  ESTARS(4)
      INTEGER  NODVLS(4), LVALS(4), JVALS(4), IPARYS(4)
      CHARACTER*1  BLANK1 /' '/
      CHARACTER*2  SYMBOL
      CHARACTER*4  ALPHA                                                26510   
C
      INTEGER MAP(4)  / 3, 1, 2, 4 /
      CHARACTER*4  NAMES(5) / 'A', 'B', 'BIGA', 'BIGB', 'X' /
C
      character*1  mychar
C
c
C
      IRET = 0
C                                                                       26520   
C     GET PAST ANY INITIAL DELIMITORS ( ASSUME THE REACTION IS IN UPPER
C      CASE ).
C
 100  mychar = IBUF(INCH)
      IF ( mychar .GE. 'A'  .AND.  mychar .LE. 'Z'  .or.
     &     mychar .GE. 'a'  .AND.  mychar .LE. 'z'  .or.
     1     mychar .GE. '0'  .AND.  mychar .LE. '9' )  GO TO 150
      INCH = INCH + 1
      IF ( INCH .LE. NOCH )  GO TO 100
 120  write (6, 123)                                                    26530   
 123  FORMAT ( '0**** REACTION KEYWORD AND COMPLETE REACTION MUST BE',
     1  ' ON ONE LINE.' )
      RETURN
C
C     START OF REACTION FOUND.  BREAK IT INTO 4 PIECES.
C
 150  INCHST = INCH
      CALL QVSCAN ( GUY, ESTARS, NODVLS, LVALS, JVALS, IPARYS, IRTN )
      IF ( IRTN .NE. 0 )  RETURN
C                                                                       26540   
C     NOW GET THE A AND Z VALUES
C
 200  DO 239  I = 1, 4
         CALL AZCODE ( GUY(I), IZ, IA, SYMBOL, IRTN )
         IF ( IRTN .EQ. 0 )  GO TO 230
         IF (IRTN .NE. -2)  write (6, 213) GUY(I)
 213     FORMAT ( '0**** A SYMBOL HAS INCORRECT SYNTAX:  ',
     1       'SYMBOL = ', A8 )
         IF ( IRTN .EQ. -2 )  write (6, 217) GUY(I)
 217     FORMAT ( '0**** THE SYMBOL ', A6, ' IS NOT A KNOWN ELEMENT.' ) 26550   
         RETURN
 230     II = MAP(I)
         IZS(II) = IZ
         AMS(II) = IA
         IF ( ESTARS(I) .NE. UNDEF )  EXS(II) = ESTARS(I) + 1.D-30
         IF ( NODVLS(I) .NE. NOTDEF )  NODESP(II) = NODVLS(I)
         IF ( LVALS(I) .NE. NOTDEF )  LSPECS(II) = LVALS(I)
         IF ( JVALS(I) .NE. NOTDEF )  JS(II) = JVALS(I)
         IF ( IPARYS(I) .NE. 0 )  PARITS(II) = IPARYS(I)
 239  CONTINUE                                                          26560   
C
C     FIND X
C
      IZS(5) = IABS( IZS(1) - IZS(2) )
      AMS(5) = DABS( AMS(1) - AMS(2) )
      NUMPAR = 5
      IF ( AMS(5) .EQ. 0 )  NUMPAR = 4
C
C     NOW GET GROUND STATE MASS EXCESS AND DETERMIN IF THE NUCLEII
C     EXIST.                                                            26570   
C
      DO 359  I = 1, NUMPAR
         IA = AMS(I)
         IZ = IZS(I)
         N = IA-IZ
         AMXCES = EXCESS( IZ, IA, IRTN )
         IF ( IRTN .EQ. 0 )  GO TO 330
         IF ( I .EQ. 5 )  GO TO 320
         write (6, 313) IA, IZ, N
 313  FORMAT ( '0**** THE NUCLEUS WITH A =', I4, ',  Z =', I4,          26580   
     1      ',  N =', I4, '  IS NOT BOUND ',
     2      'ACCORDING TO PTOLEMY"S MASS TABLE.' )
         GO TO 359
 320     write (6, 323) IA, IZ, N
 323     FORMAT ( '0**** THE EXCHANGED CLUSTER HAS A =', I4,
     1      ', Z =', I4, ',  N =', I4, '  AND IS NOT BOUND.' /
     2      6X, 'MERELY TO CONCEIVE OF SUCH THINGS MAKES THEM APPEAR ',
     3           'RIDICULOUS.' )
         RETURN
 330     IF ( I .NE. 5 )  GO TO 340                                     26590   
C
C     PRINT WARNING FOR ABSURB EXCHANGES
C
         IF ( IA .LE. 2  .OR.  IZ .NE. 0  .OR.  IZ .NE. IA )
     1     GO TO 340
         write (6, 333)
 333     FORMAT ( '0**** WARNING:  THE EXCHANGED CLUSTER IS ABSURB,',
     1     ' BUT IF THAT''S WHAT YOU WANT, SO BE IT.' )
 340     AMXCGS(I) = AMXCES
 359  CONTINUE                                                          26600   
C
C     NOW GET J FOR EACH OF THE 5
C
      DO 459  I = 1, NUMPAR
C
C     IF E* HAS BEEN ENTERED THEN G.S. J IS MEANINGLESS
C
         IF ( EXS(I) .GT. 1.D-5 )  GO TO 459
         IA = AMS(I)
         IZ = IZS(I)                                                    26610   
         N = IA - IZ
         CALL GSINFO ( IZ, IA, JVAL, IPARIT, ALPHA, IRTN )
         IF ( IRTN .EQ. 0  .AND.  JVAL .NE. NOTDEF )  GO TO 430
C     NO ERROR IF J IS ALREADY DEFINED OR IS EXPLICITLY GIVEN
C     IN THE REACTION.
         IF ( JS(I) .NE. NOTDEF )  GO TO 457
C
C     DINEUTRON OR DIPROTON IS J = 0
C
         IF ( IA .NE. 2  .OR.  IZ .EQ. 1 )  GO TO 420                   26620   
         JVAL = 0
         GO TO 450
 420     write (6, 423)  IA, IZ, N
 423     FORMAT ( '0**** WARNING:  THE GROUND STATE SPIN OF THE',
     1     ' NUCLEUS WITH A =', I4, ',  Z =', I4, ',  N =', I4,
     3     '  IS NOT KNOWN TO PTOLEMY.' )
         GO TO 457
C
C     IF J HAS BEEN DEFINED TO BE DIFFERENT FROM G.S. THEN NEED E*
C                                                                       26630   
 430     IF ( JS(I) .EQ. NOTDEF )  GO TO 450
         IF ( JS(I) .EQ. JVAL  .OR.  EXS(I) .NE. 0 )  GO TO 457
         write (6, 433) NAMES(I), JVAL, NAMES(I), JS(I), NAMES(I)
 433     FORMAT ( '0**** WARNING:  GROUND STATE SPIN FOR PARTICLE ',
     1     A4, ' IS', I3, '/2.  YOU HAVE SPECIFIED J', A4,
     2     ' =', I3, '/2, BUT HAVE NOT YET SPECIFIED E*', A4, '.')
         GO TO 459
C
 450     JS(I) = JVAL
         IF ( IPARIT .NE. 0 )  PARITS(I) = IPARIT                       26640   
 457     IF ( EXS(I) .EQ. 1.D-30 )  EXS(I) = 0
 459  CONTINUE
C
C
C     IT WAS SUCCESFUL, COPY REACTION FOR HEADER
C
      DO 649  I = 1, 45
         REACT(I) = BLANK1
 649  CONTINUE
      N = MIN0( 45, INCH-INCHST )                                       26650   
      DO 659  I = 1, N
         REACT(I) = IBUF(INCHST-1+I)
 659  CONTINUE
      IRET = 1
      RETURN
      END
C*ID* REQUIV   C109.PTOLEMY.SOURCE                          PER701  17:
      SUBROUTINE REQUIV(REQ,R0EQ,IZ,IA)
C     CALCULATES RADIUS OF EQUIVALENT UNIFORM DISTRIBUTION
C     IT IS EQUIVALENT IN THAT IT HAS SAME RMS                          26660   
C     RADIUS AS FERMI DISTRIBUTION THAT FITS ELECTRON SCATTERING
C     FOR A GT 16 USES FORMULA FOR R0 GIVEN BY BOHR AND MOTTELSON
C     FOR A BETWEEN 3 AND 16 USES VALUES GIVEN ON PP 32 TO 34 OF
C     NUCLEAR RADII - LANDOLT-BORNSTEIN - SPRINGER VERLAG 1967
C     FOR A LT 3 RETURNS REQ R0EQ = 0
C     MHM 4/25/76
C
C
      implicit real*8 ( a-h, o-z )                                      implicit
C                                                                       26670   
      DIMENSION RMSR(14)
      DATA RMSR / 2.18 , 2.16 , 2.67 , 3.22 ,
     1 3.13 , 3.1 , 3.12 , 3.16 , 3.12 , 3.17 , 2.99 ,
     2 3.18 , 3.35 , 3.54 /
c
      A=IA
      POW=1.D0/3.D0
      ACUB=A**POW
      IF(IA.GT.16) GO TO 150
C                                                                       26680   
C     3HE RADIUS
C
      IF((IZ.NE.2).OR.(IA.NE.3)) GO TO 5
      REQ=2.37
      GO TO 500
C
    5 IF(IA.GE.3) GO TO 10
      REQ=0
      GO TO 500
C                                                                       26690   
C     SPECIAL CASES FROM LANDOLT-BORNSTEIN :  A FROM 3 TO 16
C
   10 REQ=RMSR(IA-2)
      GO TO 500
C
C     USE BOHR-MOTTELSON FORMULA FOR R0 IF A GT 16
C
  150 EPS=1.D-08
      NSTEPS=40
      RC=1.12*ACUB-.86/ACUB                                             26700   
      DIFF=.54D0
      RTOP=RC+DIFF*DLOG(1.D0/EPS)
      H=RTOP/NSTEPS
      XNORM=0
      RSQ=0
      EXFAC=DEXP(-RC/DIFF)
      DEX=DEXP(H/DIFF)
      R=0
  160 WT=1
      IF((R.EQ.0).OR.(R.EQ.RTOP)) WT=.5                                 26710   
      R2=R*R
      R4=R2*R2
      EXF=1/(1+EXFAC)
      XNORM=XNORM+R2*EXF*WT
      RSQ=RSQ+R4*EXF*WT
      R=R+H
      EXFAC=EXFAC*DEX
      IF(R.LE.RTOP) GO TO 160
      REQ=(5*RSQ)/(3*XNORM)
      REQ=DSQRT(REQ)                                                    26720   
  500 R0EQ=REQ/ACUB
      RETURN
      END
C*ID* RTXLNX   C109.PTOLEMY.SOURCE                          PER701  22:
      FUNCTION RTXLNX ( A, B, C, ACC )
C
C     FINDS THE REAL SOLUTION OF  A*X + B*LN(X) + C = 0
C
C     ACC IS THE REQUIRED ABSOLUTE ACCURACY
C                                                                       26730   
C     12/20/76 - FIRST VERSION - S. PIEPER
C     11/22/79 - AVOID LN(0) - S.P.
C
      IMPLICIT REAL*8 ( A-H, O-Z )
C
      IF ( A .EQ. 0 )  GO TO 800
      BP = B/A
      CP = C/A
      IF ( B .EQ. 0 )  GO TO 850
      X = -CP                                                           26740   
      IF ( X .LT. .1 )  X = .1
      DO 199  I = 1, 100
         XOLD = X
         DELTA = -(X+BP*DLOG(X)+CP)/(1+BP/X)
         X = X + DELTA
         IF ( X .LE. 0 )  X = .1*XOLD
         IF ( DABS(DELTA) .LE. ACC )  GO TO 300
 199  CONTINUE
      write (6, 203) A, B, C, X
 203  FORMAT ( '0**** COULD NOT CONVERGE IN RTXLNX', 4G20.10 )          26750   
 300  RTXLNX = X
      RETURN
 800  RTXLNX = DEXP(-C/B)
      RETURN
 850  RTXLNX = -CP
      RETURN
      END
C*ID* SAVEHS   C109.PTOLEMY.SOURCE                          PER701  15:
      SUBROUTINE SAVEHS ( IRET )                                        cnd
CDC      SUBROUTINE SAVEHS ( NUMFLT, FLOAT, NUMINT, INTGR,              26760   
CDC     1  NUMJ, JBLOCK, NUMSW, SWITCH, IRET )
C
C     INITIALIZE THE SAVING AND RESTORING OF THE H'S.
C
C
C     THE SAVEHS FILE IS A SEQUENTIAL DATA SET WRITTEN WITHOUT FORMAT
C     CONTROL.  IT CONTAINS THE FOLLOWING LOGICAL RECORDS.
C
C     1)  SAVEHS HEADER; DATE; REACTION; HEADER
C     2)  COMMONS FOR FIRST BOUNDSTATE.                                 26770   
C     3)  COMMONS FOR SECOND BOUNDSTATE.
C     4)  COMMONS AT START OF GRID SETUP.
C       ITEMS 2, 3, AND 4 HAVE THE SAME FORMAT AND ARE PRODUCED
C       BY THE ENTRY 'SAVECM' BELOW.
C     5)  GRDSET VARIABLES STARTING WITH  NPSUM, NPDIF, ...
C     6) A)  DIF-RANGE POLYS
C        B)  SUM POINTS FOR FINDING H'S
C        C)  1/(EXPONENTIAL TAILS) THAT ARE MULTIPLIED INTO
C            THE COMPUTED H'S.
C        D)  RI POINTS FOR FINDING H'S                                  26780   
C        E)  RO POINTS FOR FINDING H'S
C     7)  NUMLIS  -  A SINGLE INTEGER.
C     8)  LIS - THE ARRAY OF LI'S ATWHICH STUFF WAS COMPUTED.
C     9)  H-RECORDS.  THERE IS ONE FOR EACH VALUE OF (LI, AND DIF).
C         EACH RECORD CONSISTS OF AN IDENTIFIER,
C         AND THE HS FOR EACH VALUE OF (SUM, LX, LO-LI).
C             THE H'S HAVE BEEN MULTIPLIED BY THE EXP FACTORS IN 6.C
C         A DUMMY H-RECORD WITH A VERY LARGE IDENTIFIER IS WRITTEN
C         AT THE END OF THE H'S.
C                                                                       26790   
C           FOR MULTIPASS RUNS, RECORD TYPES 2-9 REPEAT FOR EACH PASS,
C     EXCEPT THAT RECORD 2 OR 3 MAY BE OMITTED IF NO CHANGE.
C     THE SEQUENCE TERMINATES GRACEFULLY AT AN END-OF-FILE.
C
C
C     6/10/75 - FIRST VERSION
C     7/29/75 - DON'T OVERRIDE THE HEADER
C     9/17/75 - SAVE/RESTORE R0MASS.
C     2/29/76 - ADVANCE TO TYPE 2 - INCOMPATABLE WITH EARLIER PTOLEMY
C      5/21/76 - TYPE 3                                                 26800   
C     10/3/76 - CONVERT OLD UNDEF TO NEW UNDEF
C     4/25/78 - TYPE 4 FOR REVERSAL OF LIN, LOUT - S.P.
C     5/13/79 - TYPE 5 FOR PARITIES, RATMAS.  RECONSTRUCT TYPE 4 - S.P.
C     10/26/79 - STANDARDIZE, TERMINATE GRACEFULLY AT EOF IN MULTIPASS
C        USEHS RUNS - RPG
C     2/5/80 - CHAR*8 DATE, THISDT; CVA OPEN SAVEHS FILE;
C        INTGER TO INTGR; CVA COMMON /INTGER/ - RPG
C
C     THE  SAVEHS  KEYWORD WAS USED.  CHECK VALIDITY AND INITIALIZE
C                                                                       26810   
      implicit real*8 ( a-h, o-z )                                      implicit
CVA      INTGER
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      CHARACTER*1  REACT, HEADER                                        /hedcom/
      COMMON /HEDCOM/  REACT(45), HEADER(65)
 
C
      DIMENSION  FLOAT(NUMFLT)
      INTEGER  INTGR(NUMINT), JBLOCK(NUMJ), SWITCH(NUMSW)
C
      CHARACTER*1  HEADR2(65), BLNK1 /' '/
C                                                                       26820   
      CHARACTER*8  HED(4), HED2(4)
      DATA  HED / 'PTOLEMY ', 'SAVEHS F', 'ILE     ', '        ' /
      CHARACTER*9  THEDAT
      INTEGER  TYPE / 5 /,  TYPE2
C
C
      IRET = 0
C
C     CAN ONLY HAVE SAVEHS OR USEHS; NOT BOTH
C                                                                       26830   
      IF ( IHSAVE .EQ. 0 )  GO TO 40
 32   write (6, 33)
 33   FORMAT ( '0**** SAVEHS AND USEHS ARE EXCLUSIVE; OR ',
     1  ' SAVEHS OR USEHS HAS ALREADY BEEN ENTERED.' )
      RETURN
C
 40   IF ( IDONE .EQ. 0 )  GO TO 50
 42   write (6, 43)
 43   FORMAT ( '0**** IT IS TOO LATE TO INITIALIZE FOR SAVEHS',
     1  ' OR USEHS.' )                                                  26840   
      RETURN
C
 50   CONTINUE
C
C     OPEN THE OUTPUT FILE
C
CVA      NBLKSZ = MAX0( (NBLKSZ+511)/512, 1 )*512
CVA      NBLKS = LENHF( IDUM )/NBLKSZ + 1
CVA      write (6, 53)  NBLKSZ, NBLKS
CVA 53   FORMAT ( '0BLOCK SIZE OF H"S FILE =', I6,                      26850   
CVA     1   ' BYTES, INITIAL SIZE =', I6, ' BLOCKS.' )
CVA      OPEN ( UNIT=1, TYPE='NEW', DISP='SAVE', BLOCKSIZE=NBLKSZ,
CVA     1   FORM='UNFORMATTED', INITIALSIZE=NBLKS, ERR=90 )
      REWIND 1                                                          cnv
      CALL get_date ( THEDAT )
      WRITE ( 1, ERR=90 )  HED, TYPE, THEDAT, REACT, HEADER
C
      IHSAVE = 1
      IRET = 1
      RETURN                                                            26860   
C
 90   write (6, 93)
 93   FORMAT ( '0**** ERROR IN INITIALIZING H''S FILE.' )
      RETURN
C
C
C     WRITE THE COMMON BLOCKS AFTER EACH BOUND STATE AND BEFORE
C     GRDSET.
C
      ENTRY SAVECM ( NUMFLT, FLOAT, NUMINT, INTGR, NUMJ, JBLOCK,        26870   
     1  NUMSW, SWITCH, IRET )
C
      TEMP = 0
      WRITE ( 1, ERR=190 )  ICHANB, ISTRIP, NUMFLT, NUMINT,
     1  NUMJ, NUMSW, FLOAT, INTGR, JBLOCK, SWITCH, R0MASS,
     2  RATMAS,
     5  TEMP, TEMP, TEMP, TEMP, TEMP
      IRET = 1
      RETURN
C                                                                       26880   
 190  write (6, 193)
 193  FORMAT ( '0**** ERROR IN WRITING ON H''S FILE.' )
      IRET = 0
      RETURN
C
C
C     USEHS KEYWORD READ - INITIALIZE H'S INPUT
C
      ENTRY USEHS ( NUMFLT, FLOAT, NUMINT, INTGR, NUMJ, JBLOCK,
     1  NUMSW, SWITCH, IRET )                                           26890   
C
      GO TO ( 200, 300, 300 ), IRET
C
 200  IRET = 0
      IF ( IHSAVE .NE. 0 )  GO TO 32
      IF ( IDONE .NE. 0 )  GO TO 42
C
C     OPEN THE INPUT FILE
C
      REWIND 1                                                          26900   
      READ ( 1, ERR=90, END=90 )  HED2, TYPE2, THEDAT, REACT, HEADR2
      DO 239  I = 1, 2
         IF ( HED2(I) .EQ. HED(I) )  GO TO 239
         write (6, 233)
 233     FORMAT ('0**** Unit 1 DOES NOT POINT TO A SAVEHS FILE.')
         RETURN
 239  CONTINUE
C
      write (6, 253) THEDAT, REACT, HEADR2
 253  FORMAT ( '  ON ', a, ' ARE BEING REUSED.' /                       26910   
     1  '0 ', 45A1, 5X, 65A1 / )
      DO 265  I = 1, 65
         IF ( HEADER(I) .NE. BLNK1 )  GO TO 280
 265  CONTINUE
      DO 269  I = 1, 65
         HEADER(I) = HEADR2(I)
 269  CONTINUE
C
 280  IF ( TYPE .EQ. TYPE2 )  GO TO 300
      IF ( TYPE2 .EQ. 4 )  GO TO 300                                    26920   
      write (6, 283) TYPE, TYPE2
 283  FORMAT ( '0THE H''S FILE IS INCOMPATABLE WITH THE PRESENT',
     1  ' VERSION OF PTOLEMY:', 2I10 )
      RETURN
C
C     READ BOUNDSTATE AND GRDSET COMMONS
C
 300  READ ( 1, ERR=390, END=380 )  ICHANB, ISTRIP,
     1  NF, NI, NJ, NS,
     2  ( FLOAT(I), I = 1, NF ), ( INTGR(I), I = 1, NI ),               26930   
     3  ( JBLOCK(I), I = 1, NJ ), ( SWITCH(I), I = 1, NS ), R0MASS,
     4  RATMAS
      IHSAVE = 2
      IRET = 1
CIBC
CIBC      CONVERT OLD-STYLE UNDEF TO NEW STYLE.
CIBC
CIB      DO 329  I = 1, NF
CIB         IF ( FLOAT(I) .EQ. OLDUND )  FLOAT(I) = UNDEF
CIB 329  CONTINUE                                                       26940   
C
C     TYPE 4 SAVEHS HAVE RATMAS = 0.  WE SET RATMAS = AMP/AMT AND
C     INDICATE ALL PARITES ARE UNKNOWN.
C
      IF ( RATMAS .NE. 0 )  RETURN
      RATMAS = AMP/AMT
      DO 339  I = 33, 40
         INTGR(I) = 0
 339  CONTINUE
      RETURN                                                            26950   
C
C
C     IN A MULTIPASS RUN, AN END OF FILE MAY BE OK.
C
 380  IF ( IRET .NE. 3 )  GO TO 390
      write (6, 383)
 383  FORMAT ( '0', 10X, '**** END OF H''S FILE ****' )
      IRET = -1
      IHSAVE = 0
      RETURN                                                            26960   
 390  write (6, 393)
 393  FORMAT ( '0**** ERROR OR UNEXPECTED END-OF-FILE WHEN',
     1  ' READING H''S FILE' )
      IRET = 0
      RETURN
      END
C*ID* SDERIV   C109.PTOLEMY.SOURCE                          PER701  15:
      SUBROUTINE  SDERIV ( NFIRST, NSTEPS, NUMVS, MAXVS, NPARA,
     1  WAVER, WAVEI, ALPHAR, ALPHAI, VDERIV, ITYPE, SDELS, DSDP )
C                                                                       26970   
C     COMPUTES DERIVATIVES OF THE S-MATRIX.
C
C     USES THE FIRST ORDER RELATIONSHIP:
C
C       D(S(L)) = - (4 I M) / (K HBARC**2)  <U(L)*  D(V)  U(L)>
C
C     TO COMPUTE THE DERIVATIVES OF THE S-MATRIX WITH RESPECT TO ALL
C     THE POTENTIAL PARAMETERS THAT ARE BEING VARIED BY THE FITTER.
C
C *************************************************************         26980   
C *   THIS ROUTINE WILL NEED ADDITIONAL WORK FOR S.O. FORCES  *
C *************************************************************
C
C     NFIRST - FIRST STEP THAT HAS A NON-ZERO WAVEFUNCTION (FROM WAVELJ)
C     NSTEPS - NUMBER OF STEPS + 1 IN THE SOLUTION OF THE WAVE-EQUATION.
C     NUMVS - NUMBER OF NON-ZERO  D(V)/D(X(K)).  COMPLEX D(V)/D(X(K))
C             COUNT AS TWO.
C     LMAXVS - MAXIMUM POSSIBLE VALUE OF NUMVS ( 2*NPARA ).
C     NPARA - NUMBER OF PARAMETERS.
C     WAVER & WAVEI - (DIMENSION NSTEPS) U(L, R) AS COMPUTED BY         26990   
C             WAVELJ AND NOT YET NORMALIZED.
C     ALPHAR & ALPHAI - THE NORMALIZATION FOR WAVER & WAVEI.
C     VDERIV - (DIMENSION MAXVS X NSTEPS)  THE ARRAY OF
C              (I 8 K) / (STEPSIZE HBARC**2) * W(NP) * D(V)/D(X(K))
C             WHERE
C              W(NP) = 1, 4, 2, 4, ..., 4, 2, 4, 1   ARE SIMPSON'S
C             WEIGHTS.  THIS ARRAY WAS SETUP BY MAKDER.
C             ONLY THE FIRST NUMVS ROWS ARE USED.
C     ITYPE - (DIMENSION NPARA)  AN ARRAY CONTAINING
C              1  IF D(V)/D(X(K)) IS REAL ,                             27000   
C              2  IF D(V)/D(X(K)) IS IMAGINARY
C              3  IF D(V)/D(X(K)) IS COMPLEX.
C             THIS ARRAY IS SETUP BY FITINP.
C     SDELS - (DIMENSION 2 X NUMVS)  A WORK ARRAY.
C     DSDP - (DIMENSION 2 X NPARA) - THE DERIVATIVES OF THE S-MATRIX
C            ARE STORED HERE.
C
C     10/27/75 - FIRST VERSION - S. PIEPER
C     2/23/76 - START AT 1D-30
C     3/10/76 - LIMIT THE RANGE OF THE DERIVATIVES                      27010   
C     2/3/77 - SEARCH FOR STARTING POINT NOLONGER NEEDED
C     4/21/77 - RENORM AND LABSHIFT MAY BE FIT
C     2/14/78 - NUMERICAL DERIVATIVES
C     12/28/79 - CFR%F - RPG
C
C
      implicit real*8 ( a-h, o-z )                                      implicit
CDC      ALLOCLEVEL WAVER,WAVEI,VDERIV,ITYPE,SDELS,DSDP
C
      DIMENSION  WAVER(NSTEPS), WAVEI(NSTEPS), VDERIV(MAXVS, NSTEPS),   27020   
     1  ITYPE(NPARA), SDELS(2, NUMVS), DSDP(2, NPARA)
C
      COMMON /LOCFIT/  LFITSP(26), MNDRIV, MXDRIV
C
C
      IF ( NUMVS .EQ. 0 )  GO TO 300
      DO 29  NV = 1, NUMVS
         SDELS(1,NV) = 0
         SDELS(2,NV) = 0
 29   CONTINUE                                                          27030   
C
C     STEP 1)  COMPUTE THE INTEGRALS WITHOUT REGARD TO FACTORS OF I
C              IN VDERIV.
C
C     FIND A START THAT WON'T UNDERFLOW.
C
      NP1 = MAX0( NFIRST-1, MNDRIV )
C
C     NOW DO THE INTEGRALS
C                                                                       27040   
 100  DO 189  NP = NP1, MXDRIV
         UR = WAVER(NP)**2 - WAVEI(NP)**2
         UI = WAVER(NP)*WAVEI(NP)
         UI = UI + UI
         DO 169  NV = 1, NUMVS
            SDELS(1,NV) = SDELS(1,NV) + UR*VDERIV(NV,NP)
            SDELS(2,NV) = SDELS(2,NV) + UI*VDERIV(NV,NP)
 169     CONTINUE
 189  CONTINUE
C                                                                       27050   
C     STEP 2)  COMPUTE  D(S)/D(X(K))  FROM THE ABOVE DERIVATIVES.
C              ALSO PUT IN THE WAVEFUNCTION NORMALIZATIONS.
C
 300  BETAR = ALPHAR**2 - ALPHAI**2
      BETAI = 2*ALPHAR*ALPHAI
      NV = 1
      DO 389  NX = 1, NPARA
         DSDP(1,NX) = 0
         DSDP(2,NX) = 0
         I = ITYPE(NX)                                                  27060   
         IF ( I .EQ. 0  .OR.  I .GE. 4 )  GO TO 389
         DREAL = BETAR*SDELS(1,NV) - BETAI*SDELS(2,NV)
         DIMAG = BETAR*SDELS(2,NV) + BETAI*SDELS(1,NV)
         GO TO ( 320, 330, 340 ), I
 320     DSDP(1,NX) = -DIMAG
         DSDP(2,NX) = DREAL
         NV = NV + 1
         GO TO 389
 330     DSDP(1,NX) = -DREAL
         DSDP(2,NX) = -DIMAG                                            27070   
         NV = NV + 1
         GO TO 389
 340     DSDP(1,NX) = -DIMAG - BETAR*SDELS(1,NV+1)
     1      + BETAI*SDELS(2,NV+1)
         DSDP(2,NX) = DREAL - BETAR*SDELS(2,NV+1)
     2      - BETAI*SDELS(1,NV+1)
         NV = NV + 2
 389  CONTINUE
C
      RETURN                                                            27080   
      END
C*ID* SECDER   C109.PTOLEMY.SOURCE                          PER701  22:
      SUBROUTINE SECDER ( ITYPE, N, NA, DEL, X, F, FJAC, G, FSTO,
     1  JTJ, DNL, A, FJSTO, FJACC, XSTO, VALS )
C
C     NUMERICAL CALCULATION OF COMPLETE SECOND-DERIVATIVE MATRIX
C     OR NUMERICAL CHECK OF THE CALCULATION OF THE FIRST DERIVATIVES
C
C     IF ITYPE = 1, THIS ROUTINE SIMPLY CALLS DERCHK TO CHECK THE
C        ANALYTIC DERIVATIVES.                                          27090   
C     IF ITYPE = 2, THIS ROUTINE COMPUTES THE COMPLETE SECOND
C     DERIVATIVE MATRIX BY MAKING SMALL PERTURBATIONS IN THE
C     PARAMETERS AND USING CALGRA TO THE THE FIRST DERIVATIVES.
C     VARIOUS COMPARASONS ARE THEN MADE BETWEEN THE SECOND DERIVATIVE
C     MATRIX AND THE JTJ APPROXIMATION TO IT.
C
C     1/29/75 - FIRST VERSION - MHM
C     11/20/77 - NEW SETFIT CALL - S.P.
C
C                                                                       27100   
      implicit real*8 ( a-h, o-z )                                      implicit
CDC      ALLOCLEVEL X,F,FJAC,G,FSTO,JTJ,DNL,A,FJSTO,FJACC,XSTO,VALS
C
C
      REAL*8 JTJ
      LOGICAL PRTSW
      DIMENSION X(N),G(N),F(NA),FSTO(NA),FJAC(NA,N)
      DIMENSION JTJ(N,N),DNL(N,N),XSTO(N),VALS(N),FJSTO(NA,N),
     1A(N,N)
      DIMENSION FJACC(NA, N)                                            27110   
      COMMON/INTGER/JUNK(16),IPR
C
      write (6, 3) DEL
  3   FORMAT( '-RELATIVE STEPSIZE FOR NUMERICAL DERIVATIVES =', 1PG12.3)
      IF ( ITYPE .EQ. 1 )  GO TO 1000
C
      PRTSW=MOD(IPR,10).GE.2
      CHISQ=CALGRA(NA,N,F,X,FJAC,G)
      DO 10 I=1,NA
      DO 9  K = 1, N                                                    27120   
  9     FJACC(I,K) = FJAC(I,K)
   10 FSTO(I)=F(I)
      write (6, 200)
  200 FORMAT(1H0,2X,'PARAMETER-VECTOR')
      DO 15 J=1,N
   15 XSTO(J)=X(J)
      write (6, 400)(X(I),I=1,N)
  400 FORMAT(1H ,2X,6(G12.6,1X)/3X,6(G12.6,1X))
      write (6, 250)CHISQ
  250 FORMAT(1H ,2X,'CHISQ = ',G12.6)                                   27130   
      DO 30 I=1,N
      DO 30 J=1,N
      JTJ(I,J)=0
      DO 20 K=1,NA
   20 JTJ(I,J)=JTJ(I,J)+FJAC(K,I)*FJAC(K,J)
      FACTOR=X(I)*X(J)
      JTJ(I,J)=JTJ(I,J)*FACTOR
   30 DNL(I,J)=0
C
C     HERE WE LOOP OVER THE N PARAMETERS AND PERTURB EACH ONE           27140   
C     SEPARATELY AND GET THE FIRST DERIVATIVES FROM CALGRA.
C     THE 2ND DERIVS ARE THEN COMPUTED BY SUBTRACTION.  NOTE THAT
C     WE COMPUTE 3 DIFFERENT VALUES OF THE 2ND DERIVATIVES USING:
C        X-DEL & X+DEL ;   X-DEL & X ;   X & X+DEL .
C     NOTE ALSO THAT THE COMPLETE SECOND DERIVATIVE MATRIX IS BUILT
C     UP AND THAT ITS ASYMETRY IS AN INDICATION OF THE NUMERICAL
C     ERRORS INVOLVED.
C
      DO 50 I=1,N
      DX=DEL*XSTO(I)                                                    27150   
      D2X=2*DX
      X(I)=XSTO(I)+DX
      CHISQ=CALGRA(NA,N,F,X,FJAC,G)
      DO 85 JA=1,NA
      DO 85 K=1,N
   85 FJSTO(JA,K)=FJAC(JA,K)
      X(I)=X(I)-D2X
      CHISQ=CALGRA(NA,N,F,X,FJAC,G)
      DO 45 J=1,N
      FACTOR=XSTO(I)*XSTO(J)                                            27160   
      IF(PRTSW) write (6, 450)I,J
  450 FORMAT(1H1,2X,'(I,J) = (',I2,1X,I2,')'  /
     1  '0  NID', 8X, 'F', 12X, 'D2F', 10X, 'F*D2F', 9X, 'D2F(L)',
     2     9X, 'D2F(R)', 10X, 'DF(L)', 10X, 'DF(R)'  / )
      SUMABS=0
      DO 40 IA=1,NA
      NID=400+10*IA
      DIJ=(FJSTO(IA,J)-FJAC(IA,J))/D2X
      BIT=FSTO(IA)*DIJ
      DIJL = (FJACC(IA,J) - FJAC(IA,J))/DX                              27170   
      DIJR = (FJSTO(IA,J) - FJACC(IA,J))/DX
      IF(PRTSW) write (6, 500)NID,FSTO(IA),DIJ,BIT,
     1  DIJL, DIJR, FJAC(IA,J), FJSTO(IA,J)
  500 FORMAT(1H ,2X,I3,  7G15.6 )
      SUMABS=SUMABS+DABS(BIT)
   40 DNL(I,J)=DNL(I,J)+BIT
      CANCEL=DABS(DNL(I,J))/SUMABS
      IF(PRTSW) write (6, 155)CANCEL
  155 FORMAT(1H0,2X,'CANCELLATION RATIO = ',G12.6)
      DNL(I,J)=DNL(I,J)*FACTOR                                          27180   
   45 CONTINUE
      X(I)=XSTO(I)
   50 CONTINUE
C
C     RESTORE THE COMMON BLOCKS TO THE ORIGINAL PARAMETERS
C
      CALL SETFIT ( XSTO, IRET, 0 )
C
      write (6, 950)
  950 FORMAT(1H1,2X,'--- MATRICES SCALED BY X(I)*X(J) FACTORS ---')     27190   
      write (6, 550)
  550 FORMAT(1H0,2X,' SUM(F*D2F) ')
      DO 60 I=1,N
   60 write (6, 400)(DNL(I,J),J=1,N)
      write (6, 300)
  300 FORMAT(1H0,2X,' JTJ ')
      DO 25 I=1,N
   25 write (6, 400)(JTJ(I,J),J=1,N)
      DO 65 I=1,N
      DO 65 J=1,N                                                       27200   
      FJAC(I,J)=DNL(I,J)
   65 DNL(I,J)=DNL(I,J)+JTJ(I,J)
      write (6, 600)
  600 FORMAT(1H0,2X,' 1/2 D2(CHISQ)/DXI*DXJ ')
      DO 70 I=1,N
   70 write (6, 400)(DNL(I,J),J=1,N)
      DO 165 I=1,N
      DO 165 J=1,N
  165 A(I,J)=DNL(I,J)
      CALL SDIAG( N,N,1.D-13,30,A,VALS,A,XSTO)                          27210   
      write (6, 740)
  740 FORMAT(1H0,2X,'EIGENVALUES OF 1/2 D2(CHISQ)/DXI*DXJ ')
      write (6, 400)(VALS(I),I=1,N)
      CALL SYMINV(JTJ,N,XSTO,0,DET, N)
      DO 52 I=2,N
      JTOP=I-1
      DO 52 J=1,JTOP
   52 JTJ(I,J)=JTJ(J,I)
      write (6, 730)
  730 FORMAT(1H0,2X,' JTJ**-1 ')                                        27220   
      DO 54 I=1,N
   54 write (6, 400)(JTJ(J,I),J=1,N)
      DO 920 I=1,N
      DO 920 J=I,N
      A(I,J)=0
      DO 915 K=1,N
  915 A(I,J)=A(I,J)+JTJ(I,K)*FJAC(K,J)
  920 A(J,I)=A(I,J)
      CALL SDIAG(NA,N,1.D-13,30,FJAC,VALS,FJAC,XSTO)
      VMAX=0                                                            27230   
      DO 925 I=1,N
      TEM=DABS(VALS(I))
  925 IF(TEM.GT.VMAX) VMAX=TEM
      PP=VMAX
      write (6, 935)
  935 FORMAT(1H0,2X,'EIGENVALUES OF NON-LINEAR CORRECTION MATRIX')
      write (6, 400)(VALS(I),I=1,N)
      CALL SDIAG(N,N,1.D-13,30,A,VALS,A,XSTO)
      VMAX=0
      DO 930 I=1,N                                                      27240   
      TEM=DABS(VALS(I))
  930 IF(TEM.GT.VMAX) VMAX=TEM
      RP=VMAX
      CALL SYMINV(DNL,N,XSTO,0,DET, N)
      DO 56 I=2,N
      JTOP=I-1
      DO 56 J=1,JTOP
   56 DNL(I,J)=DNL(J,I)
      write (6, 770)
  770 FORMAT(1H0,2X,' 1/2 D2CHISQ**-1 ')                                27250   
      DO 58 I=1,N
   58 write (6, 400)(DNL(J,I),J=1,N)
      CALL SDIAG( N,N,1.D-13,30,JTJ,VALS,JTJ,XSTO)
      VMAX=0
      DO 940 I=1,N
  940 IF(VALS(I).GT.VMAX) VMAX=VALS(I)
      PP=PP*VMAX
      DO 75 I=1,N
      VALS(I)=DSQRT(VALS(I))
   75 FSTO(I)=1/VALS(I)                                                 27260   
      write (6, 700)
  700 FORMAT(1H0,2X,'SQRT EIGENVALUES OF JTJ**-1')
      write (6, 400)(VALS(J),J=1,N)
      write (6, 750)
  750 FORMAT(1H0,2X,'SQRT EIGENVALUES OF JTJ ')
      write (6, 400)(FSTO(J),J=1,N)
      write (6, 800)
  800 FORMAT(1H0,2X,'EIGENVECTORS')
      DO 80 I=1,N
   80 write (6, 400)(JTJ(K,I),K=1,N)                                    27270   
      CALL SDIAG( N,N,1.D-13,30,DNL,VALS,DNL,XSTO)
      write (6, 900)
  850 FORMAT(1H0,2X,'EIGENVALUES OF 1/2(D2(CHISQ)/DXI*DXJ) ')
      write (6, 400)(VALS(I),I=1,N)
      DO 175 I=1,N
      DO 175 J=1,N
      FSTO(I)=DABS(VALS(I))
  175 FSTO(I)=DSQRT(FSTO(I))
      write (6, 760)
  760 FORMAT(1H0,2X,'SQRT /EIGENVALUES/ OF 1/2(D2(CHISQ)/DXI*DXJ) ')    27280   
      write (6, 400)(FSTO(I),I=1,N)
      DO 90 J=1,N
   90 FSTO(J)=1/VALS(J)
      write (6, 850)
  900 FORMAT(1H0,2X,'EIGENVALUES OF 2*(D2(CHISQ)/DXI*DXJ**-1) ')
      write (6, 400)(FSTO(I),I=1,N)
      write (6, 800)
      DO 98 I=1,N
   98 write (6, 400)(DNL(K,I),K=1,N)
      write (6, 945)RP,PP                                               27290   
  945 FORMAT(1H0,2X,'+++++ MCKEOWN S PARAMETERS  +++++'/
     19X,'R = ',G12.6,' P = ',G12.6/3X,8('+++++'))
      RETURN
C
C     CHECK THE ANALYTIC FIRST DERIVATIVES
C
 1000 CALL DERCHK ( N, NA, DEL, X, F, FJAC, G, FSTO )
      RETURN
C
      END                                                               27300   
C*ID* SETBFC   C109.PTOLEMY.SOURCE                          PER701  11:
      SUBROUTINE  SETBFC ( NBINDX, MBINDX, BINDEX,
     1  MCHNDF, CHNDEF, RCHNDF, NUMLIS, LIS, R2S, LMXMX,
     2  SIG1, SIG2,
     3  RLOWER, ALLSW, IRORC, NMBFAC, BFAC, FFWORK, IDIM1, LDLDIM,
     4  WRKWK, FIWORK, IDIM2, WRKST, IRET, CLTIME )
C
C     GETS AND STORES THE B FACTORS  OR COULOMB FF2 INTEGRALS
C
C     NBINDX, MBINDX, BINDEX - THE B-INDEX ARRAY                        27310   
C     MCHNDF, RCHNDF - THE CHANNEL-DEFINITION ARRAY
C     NUMLIS, LIS - FOR B FACTORS, THIS IS THE ARRAY OF J'S (SO FAR
C              NOT 2*J) AT WHICH CALCULATIONS ARE TO BE DONE.
C              FOR FF2'S  NUMLIS IS A WORK VARIABLE AND
C              LIS(1) MUST BE
C              MIN(2*J) = 2*LMIN.
C     R2S - R2S(4) CONTAINS  -3*ZP*ZT*ALPHA*HBARC
C     LMXMX - MUST BE LMAX+LXMAX (LOMOST+LXMAX)
C             FOR FF2'S THIS VARIABLE IS SET IN HERE.
C     SIG1, SIG2 - ARRAYS TO HOLD THE COULOMB PHASE SHIFTS.  FOR        27320   
C          FF2, SIG1 MUST ALREADY HAVE THE ELASTIC PHASES.
C     RLOWER - SUMMAX FOR B FACTORS,  0 FOR FF2 INTS.
C     ALLSW - .TRUE. FOR B-FACTORS,  .FALSE. FOR FF2
C     IRORC - FIRST DIMENSION OF BFAC, = 2 FOR BFACTORS AND
C             1 FOR FF2INTS.
C     NMBFAC - SECOND DIMENSION OF BFAC, = NMBFAC FOR BFACTORS,
C              NMFFAC FOR FF2INTS.
C     BFAC - GETS THE B FACTORS OR FF2 INTS AS DESCRIBED BELOW.
C
C                                                                       27330   
C
C     THE QUANTITY COMPUTED IS  FOR B FACTORS
C        B(2,1)/X(1,2) =  FAC*( FG-GF + I(FF+GG) )
C     WHERE
C        FG = INTEGRAL(R,INF) F(1)*G(2)/R**(LX+1)
C     AND
C     FAC IS 3/2*ZP*ZT*ALPHA*HBARC/SQRT(K1*K2) * 2MU/HBAR**2
C     ETC.
C
C     OR FOR  FF2 INTS                                                  27340   
C        |S(BORN)|/X(1,ALPHA0) = 4*FAC*FF
C
C     HERE BASIS STATE 1 IS THE STATE WHOSE S-MATRIX IS TO BE FOUND.
C     2 IS A STATE THAT IS IN THE RHS OF 1.
C
C     1/8/80 - FIRST VERSION BASED ON ANGSET - S.P.
C     2/19/80 - INCLUDE LOOP ON NBINDX; DO FF2 INTS - S.P.
C     3/15/80 - STORE IN J BLOCKS - S.P.
C     4/8/80 - USE IPRINT/10 FOR FF2 DEBUG PRINT OUT - S.P.
C     4/25/80 - MAKE ETA2 REAL*8 CONSISTANT WITH ETA1, K1, K2 - S.P.    27350   
C     9/25/80 - MUST GET LIMOST FROM CHNDEF - S.P.
C     11/9/81 - FIX CLTIME ACCUMULATION - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
C
      DIMENSION LIS(NUMLIS), SIG1(1), SIG2(1),
     1  FFWORK(IDIM1,4), WRKWK(1), FIWORK(IDIM2,4), WRKST(1),
     2  R2S(4)
      REAL*4  BFAC(IRORC, NMBFAC, 1), RCHNDF(MCHNDF, 1)
      INTEGER  BINDEX(MBINDX, NBINDX), CHNDEF(MCHNDF, 1)                27360   
      LOGICAL  ALLSW
C
C
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
C
      LOGICAL PBUGSW
C
      IPRNT = IPRINT/10                                                 27370   
      IF ( ALLSW )  IPRNT = IPRINT/100
      IPRNT = MOD( IPRNT, 10 )
      PBUGSW = IPRNT .GE. 3
      CLTIME = 0
C
C
C     WE LOOP OVER ALL SETS OF B FACTORS
C
      DO 699  IBF = 1, NBINDX
C                                                                       27380   
C     IF DOING FF2, ONLY THE STUFF CONNECTED TO THE G.S. IS DONE.
C
         ASSIGN 350 TO IGO
         IF ( ALLSW )  GO TO 130
         IF ( BINDEX(9,IBF) .EQ. 0 )  GO TO 699
         ASSIGN 360 TO IGO
C
 130     LX = BINDEX(1,IBF)
         IC1 = BINDEX(2,IBF)
         IC2 = BINDEX(3,IBF)                                            27390   
         MXLMJ1 = BINDEX(4,IBF)
         MXLMJ2 = BINDEX(5,IBF)
         MNLMJ1 = BINDEX(6,IBF)
         MNLMJ2 = BINDEX(7,IBF)
         LB = BINDEX(8,IBF)
         ETA1 = RCHNDF(6,IC1)
         AK1 = RCHNDF(7,IC1)
         ETA2 = RCHNDF(6,IC2)
         AK2 = RCHNDF(7,IC2)
C                                                                       27400   
C ****  HERE WE NEED DOUBLE PRECISION ACCURACY FOR ETA, K. *******
C ****  WE COMPUTE THEM FROM THE INPUT BUT IT WOULD BE BETTER ****
C ****  AND MORE GENERAL TO HAVE REAL*8 VALUES STORED.     *******
C ****  WE ASSUME NO CHANGE IN THE REDUCED MASS BETWEEN CHANNELS.
C
         TEMP = IZS(1)*IZS(3)*AM/(AFINE*HBARC)
         X = ECM - RCHNDF(3,IC1) - RCHNDF(5,IC1)
         AK1 = DSQRT(2*AM*X)/HBARC
         ETA1 = TEMP/AK1
         X = ECM - RCHNDF(3,IC2) - RCHNDF(5,IC2)                        27410   
         AK2 = DSQRT(2*AM*X)/HBARC
         ETA2 = TEMP/AK2
C
         IF ( ALLSW )  GO TO 180
         LIMOST = CHNDEF(15,IC2)
         NUMLIS = LIMOST - LIS(1)/2 + 1
         LMXMX = LIMOST+LX
         LB = BINDEX(9,IBF)
         GO TO 190
C                                                                       27420   
 180     CALL DSGMAL ( ETA1, LMXMX+LX, SIG1 )
 190     CALL DSGMAL ( ETA2, LMXMX+LX, SIG2 )
C
C     FAC IS 3/2*ZP*ZT*ALPHA*HBARC/SQRT(K1*K2) * 2MU/HBAR**2
C     AND   4*ABOVE = 6*ZP*ZT*....  FOR FF2 FACTORS.
C
         FAC = -.5*R2S(4)/SQRT(AK1*AK2) * 2*AM/HBARC**2
         IF ( .NOT. ALLSW )  FAC = 4*FAC
C
         LMNMN = MAX0( LMIN+(MNLMJ1+MNLMJ2-3)/4, LX/2 )                 27430   
C
         IF ( PBUGSW )  write (6, 3) ETA1, AK1, ETA2, AK2,
     1     LX, MXLMJ1, MXLMJ2, MNLMJ1, MNLMJ2, NUMLIS, LMXMX, LMNMN
  3      FORMAT ( '0SETBFC, ETA1, K1, ETA2, K2 =', 4G20.5 /
     1      '    LX, MXLMJ1, MXLMJ2, MNLMJ1, MNLMJ2, NUMLIS, LMXMX,',
     1          ' LMNMN =', 8I8 )
C
         CALL COULIN ( LX+1, LX, LMNMN, LMXMX,
     2      ETA1, AK1, SIG1, ETA2, AK2, SIG2, RLOWER, ALLSW,
     2      FFWORK(1,1), FFWORK(1,2), FFWORK(1,3), FFWORK(1,4),         27440   
     3      LDLDIM, ACCINE, COULML, MXCOUL, NPCOUL,
     4      WRKWK, FIWORK(1,1), FIWORK(1,2), FIWORK(1,3), FIWORK(1,4),
     5      WRKST, IPRNT, IRET, TEMP )
         CLTIME = CLTIME + TEMP
         IF ( IRET .NE. 0 )  GO TO 9960
C
         MAXDEL = MAX0(2, LX)
C
C     THE REQUIRED QUANTITIES ARE INDEXED BY
C                                                                       27450   
C     I = ( L2-L1+LX + (LX+1)(L1-MIN(L1)) )/2 + LB
C
C     AND ARE SUCH THAT
C
C       B(2,1) = X(1,2) * ( BFAC(1,I,ILI) + 1I*BFAC(2,I,ILI) )
C
C     WHERE LB IS  BINDEX(8,IB))
C           IB = BASCPL(9,...)
C           BFAC IS ALLOC4(LCL1FF)
C                                                                       27460   
C     FOR FF2 INTEGRALS IT IS
C
C       FF2(2,1) = X(1,2) * BFAC(I+1)
C
C     WHERE  BFAC  IS ALLOC4(LCL2FF+BINDEX(9,IB))
C     I = ( L2-L1+LX + (LX+1)(L1-MIN(L1)) )/2
C         + (LX+1)*NM1FRJ*(J-JMIN)
C
C     NOTE THAT BOTH L2 AND L1 GO IN STEPS OF 2.
C                                                                       27470   
         NM1FRJ = (MXLMJ1-MNLMJ1)/4 + 1
         NMBFRJ = (LX+1)*NM1FRJ
C
         DO 399  ILI = 1, NUMLIS
            J = LIS(1)-2 + 2*ILI
            IF ( ALLSW )  J = 2*LIS(ILI)
            MINL1 = (MNLMJ1+J)/2
            L1ST = MAX0( MINL1, 0 )
            L1ST = L1ST + MOD( L1ST-MINL1, 2 )
C                                                                       27480   
            L1END = (MXLMJ1+J)/2
            L2 = (MNLMJ2+J)/2
            L2ST = MAX0( L2, 0 )
            L2ST = L2ST + MOD( L2ST-L2, 2 )
            L2END = (MXLMJ2+J)/2
C
            IF ( PBUGSW ) write (6, 323) L1ST, L1END, L2ST, L2END
 323        FORMAT ( ' L1ST, L1END, L2ST, L2END =', 4I8 )
C
            DO 389  L1 = L1ST, L1END, 2                                 27490   
               L2MN = MAX0( L2ST, IABS(L1-LX) )
               L2MN = L2MN + MOD(L2MN-L2ST, 2 )
               L2MX = MIN0( L2END, L1+LX )
               IF ( L2MX .LT. L2MN )  GO TO 389
C
               IF ( L1+L2MN .LT. 2*LMNMN  .OR.
     1         L1+L2MX .GT. 2*LMXMX )  GO TO 9950
C
               DO 379  L2 = L2MN, L2MX, 2
                  LDEL = L1-L2                                          27500   
                  ID = ishft( MAXDEL-LDEL,  -1 )
                  IL = L2 + ( L1-2*LMNMN )
                  I1 = ID + IL*LDLDIM + 1
                  I = (LX+1)*(L1-MINL1)
     1               - L1 + LX + L2
                  I = ishft(I, -1)
C
                  GO TO  IGO, ( 350, 360 )
C
 350              BFAC(1,I+LB,ILI) = FAC*( FFWORK(I1,2)-FFWORK(I1,3) )  27510   
                  BFAC(2,I+LB,ILI) = FAC*( FFWORK(I1,1) + FFWORK(I1,4) )
                  GO TO 379
C
 360              I = I + NMBFRJ*(ILI-1)
                  BFAC(1,LB+I,1) = FAC*FFWORK(I1,1)
C
 379           CONTINUE
 389        CONTINUE
 399     CONTINUE
C                                                                       27520   
 699  CONTINUE
C
      IRET = 0
      RETURN
C
 9950 write (6, 9953) ILI, J, LMNMN, LMXMX, L1ST, L1END,
     1   L2ST, L2END, L1, L2MN, L2MX, LX, MXLMJ1, MXLMJ2,
     2   MNLMJ1, MNLMJ2
 9953 FORMAT ( '0**** INTERNAL ERROR IN SETBFC AT 9950:' /
     1   (8I10) )                                                       27530   
C
 9960 write (6, 9963) IRET, LX, LMNMN, LMXMX, ETA2, AK2,
     1  ETA1, AK1, RLOWER, ALLSW,
     2  LDLDIM, ACCINE, COULML, MXCOUL, NPCOUL
 9963 FORMAT ( '0**** ERROR IN COULIN:', 4I12 /
     1  5G18.7, L5 /
     2  I10, 2G18.7, 2I10 )
      RETURN
      END
C*ID* SETBRN   C109.PTOLEMY.SOURCE                          PER701  13: 27540   
      SUBROUTINE SETBRN ( NBINDX, MBINDX, BINDEX, MCHNDF, CHNDEF,
     1  MBASDF, BASDEF, MBASCP, BASCUP, RBASCP,
     2  NUMLIS, LIS, JMIN, FF2INT,
     3  INDXS, SMATR, SMATI )
C
C     COMPUTES COULOMB BORN S MATRICES AND SUBTRACTS FROM CC
C
C     FOR ALL CHANNELS THAT ARE
C     FIRST-ORDER COULOMB COUPLED TO THE GROUND STATE, THE
C     FF INTEGRALS ARE THEN CONVERTED TO S(BORN) WITH THE               27550   
C     EXCEPTION OF THE FACTOR I.  THAT IS EITHER REAL(S) OR
C     IM(S) IS COMPUTED AS APPROPRIATE.  FINALLY THE BORS
C     S-MATRICES ARE SUBTRACTED FROM THE C.C. S-MATRICES.
C
C     3/21/80 - FIRST VERSION - S.P.
C     4/8/80 - PRINT |DIF| - S.P.
C     6/24/80 - DEFINE IPRINT, PRINT FOR 2 -- S.P.
C     7/2/80 - PRINT MCHN, NOT IC2 - S.P.
C     9/25/80 - MUST GET EACH JMOST FROM CHNDEF - S.P.
C     12/18/80 - IMPROVE COMMENTS  - S.P.                               27560   
C     1/12/81 - BOHR-MOTTELSON R.M.E. - S.P.
C     9/12/81 - ALLOW SEVERAL G.S. COUPLINGS DUE TO 2ND ORDER - S.P.
C     10/28/81 - ROOT 2 NEEDED FOR PARTIALLY SYMMETRIZED STATES - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
C
      INTEGER  BINDEX(MBINDX, NBINDX),  CHNDEF(MCHNDF, 1),
     1  BASDEF(MBASDF, 1),  BASCUP(MBASCP, 1),  LIS(1), INDXS(1)
      REAL*4  RBASCP(MBASCP, 1),  FF2INT(1)
      REAL*8  SMATR(1), SMATI(1)                                        27570   
C
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
C
      LOGICAL  PRNTSW, BADSW
C
      DATA ROOT2 / 1.41421 35623 731 0D0 /
C
c
C                                                                       27580   
      PRNTSW = MOD(IPRINT, 10) .GE. 2
C
C
C     WE ASSUME THAT THERE IS ONLY ONE BASIS STATE FOR THE
C     GROUND-STATE CHANNEL.
C
      L1MJ = 0
C
C     LOOP OVER ALL SETS OF FF2 BFACTORS
C                                                                       27590   
      DO 699  IBF = 1, NBINDX
         LB = BINDEX(9,IBF)
         IF ( LB .EQ. 0 )  GO TO 699
         LX = BINDEX(1,IBF)
         IC1 = BINDEX(2,IBF)
         IC2 = BINDEX(3,IBF)
         MXLMJ1 = BINDEX(4,IBF)
         MNLMJ1 = BINDEX(6,IBF)
C
C       FF2(2,1) = X(2,1) * BFAC(I+1)                                   27600   
C     WHERE  X(2,1)  EXPRESSES THE CONTRIBUTION OF THE G.S. CHANNEL (1)
C     TO THE BASIS STATE 2.  X(2,1) CONSISTS OF THE KINEMATICAL
C     PIECE    I**LX * SQRT( 1/4PI ) *
C               | CLEBSCH( L1 LX 0 0 ; L2 0 ) |
C     WHICH IS COMPUTED HERE, TIMES THE MODEL PIECE FROM THE
C     BASIS COUPLING ARRAY.
C     THIS EXPRESSION IS THE VALUE OF W(2,1) AS DEFINED IN
C     EQ. 21 OF THE NOTES, FOR THE CASE THAT
C       S(1) = JP(1) = JT(1) = 0,  L(1) = J .
C     WE USE THE FACT THAT                                              27610   
C        PHASE < L1 LX 0 0 ; L2 0 >  =  I**(L1+LX-L2)
C
C     HERE  BFAC  IS ALLOC4(LCL2FF+BINDEX(9,IB))
C     I = ( L2-L1+LX + (LX+1)(L1-MIN(L1)) )/2
C         + (LX+1)*NM1FRJ*(J-JMIN)
C
C     NOTE THAT BOTH L2 AND L1 GO IN STEPS OF 2.
C
         NM1FRJ = (MXLMJ1-MNLMJ1)/4 + 1
         NMBFRJ = (LX+1)*NM1FRJ                                         27620   
C
         MCHN = CHNDEF(1,IC2)
         IB2ST = CHNDEF(8,IC2)
         IB2ND = IB2ST + CHNDEF(9,IC2) - 1
         KSMAT = CHNDEF(10,IC2)
         NSPLI = CHNDEF(11,IC2)
         KINDXS = CHNDEF(12,IC2) + 3 + 3*LX
         KBASE = KSMAT + INDXS(KINDXS-2)
         LDELMN = INDXS(KINDXS-1)
         LIMOST = CHNDEF(15,IC2)                                        27630   
         JMOST = 2*LIMOST
         NUMJ = (JMOST-JMIN)/2 + 1
C
C     LOOP OVER ALL BSIS STATES FOR CHANNEL 2
C
         DO 659  IB2 = IB2ST, IB2ND
            L2MJ = BASDEF(3,IB2)
            ICUPST = BASDEF(4,IB2)
            ICUPND = ICUPST + BASDEF(5,IB2) - 1
            LDEL = ( L2MJ-L1MJ )/2                                      27640   
            KOFFS = KBASE + ishft( LDEL-LDELMN,  -1 )
C
C     LOCATE THE COUPLINGS TO THE G.S. OF THIS BASIS STATE, AND
C     ACCUMULATE THE MATRIX ELEMENT FOR THE 1/R**(LX+1) TAIL.
C
            FAC1 = 0
            DO 129  ICUP = ICUPST, ICUPND
               IF ( IABS(BASCUP(9,ICUP)) .EQ. IBF )
     1            FAC1 = FAC1 + RBASCP(6,ICUP)
 129        CONTINUE                                                    27650   
            IF ( FAC1 .EQ. 0 )  GO TO 659
            BADSW = .FALSE.
C
C     WE HAVE FOUND THE RELAVANT COUPLING PARAMETER
C     SINCE WE ASSUME ONLY ONE G.S. BASIS STATE, THERE IS
C     ONLY ONE POSSIBLE USE OF EACH FF2INT.
C     THEREFORE WE WEIGHT EACH ONE WITH THE APPROPRIATE SUM
C     OF MATRIX ELEMENTS.
C
C     HERE WE INCORPORATE THE SIGN OF I**(LX-1) IN THE FACTOR           27660   
C     THE EXTRA -1 COMES FROM MAKING AN S-MATRIX FROM THE T-MATRIX.
C
            FAC1 = FAC1/RT4PI
            IF ( BASDEF(7,IB2) .EQ. 2 )  FAC1 = ROOT2*FAC1
            LXP1 = LX+1
            IF ( .NOT. btest(LXP1, 1) )  FAC1 = -FAC1
C
            INDX1 = LB + ishft( LDEL+LX,  -1 )
C
C     NOW LOOP OVER ALL J'S AND COMPUTE S(BORN) FOR THIS L-J.           27670   
C
            DO 399  NJ = 1, NUMJ
               J = 2*NJ + (JMIN-2)
               L1X2 = J+L1MJ
               L2X2 = J+L2MJ
               IF ( L2X2 .LT. 2*LX-L1X2 )  GO TO 399
               I = INDX1 + NMBFRJ*(NJ-1)
               FF2INT(I) = FAC1*FF2INT(I) *
     1            ABS( CLEBSH( L1X2, 2*LX, 0, 0, L2X2, 0 ) )
 399        CONTINUE                                                    27680   
C
C     NOW SUBTGRACT THE BORN VALUES FROM ALL THE COMPUTED S MATRICES
C
            ASSIGN  460 TO IGOTO
            IF ( .NOT. btest(LX, 0) )  ASSIGN 465 TO IGOTO
C
            IF (PRNTSW)  write (6, 403) MCHN, IB2, LX, LDEL
 403        FORMAT ( '0COMPARASON OF C.C. AND COULOMB BORN',
     1         ' S MATRICES FOR CHANNEL', I3, ', BASIS STATE', I4,
     2         5X, 'LX =', I3, 5X, 'LOUT-LIN =', I3 /                   27690   
     3        '0   J   L IN  L OUT', T31, 'S(C.C.)',
     4         T54, 'S(BORN)', T74, 'DIFFERENCE', T96,
     5         '|DIFFERENCE|', T116, '%' )
C
            DO 499  ILI = 1, NUMLIS
               J = 2*LIS(ILI)
               L1X2 = J+L1MJ
               L2X2 = J+L2MJ
               IF ( L2X2 .LT. 2*LX-L1X2 )  GO TO 499
               L1 = ishft(L1X2,  -1)                                    27700   
               L2 = ishft(L2X2,  -1)
               I1 = (ILI-1)*NSPLI + KOFFS
               I2 = INDX1 + NMBFRJ*ishft(J-JMIN,  -1)
               SR = SMATR(I1)
               SI = SMATI(I1)
               SBORN = FF2INT(I2)
               GO TO IGOTO, ( 460, 465 )
 460           SMATR(I1) = SR-SBORN
               GO TO 480
 465           SMATI(I1) = SI-SBORN                                     27710   
C
 480           IF ( .NOT. PRNTSW )  GO TO 499
               SMAG = DSQRT( SMATR(I1)**2 + SMATI(I1)**2 )
               PERCNT = 100*SMAG/(DABS(SBORN)+1.D-20)
               write (6, 483) J, L1, L2, SR, SI,
     1            SBORN, SMATR(I1), SMATI(I1), SMAG, PERCNT
 483           FORMAT ( I5, '/2', I5, I6, G15.5, G13.5, G16.5,
     1            G16.5, G13.5, G14.4, F13.2 )
 499        CONTINUE
 659     CONTINUE                                                       27720   
         IF (BADSW) write (6, 673) IBF, LB, IC1, IC2, LX, IB2ST, IB2ND
 673     FORMAT ( '0*** INTERNAL ERROR IN SETBRN:', 8I8 )
 699  CONTINUE
C
      RETURN
      END
C*ID* SETCHN   C109.PTOLEMY.SOURCE                          PER701  17:
      SUBROUTINE  SETCHN ( ICHAN, IRET )
C
C     SETS UP PARAMETERS FOR A GIVEN CHANNEL                            27730   
C
C     THIS ROUTINE IS CALLED PRIOR TO EACH BOUND STATE AND
C     DISTORTED WAVE CALCULATION.  WHERE NECESSARY IT DEFINES
C     PROJECTILE (P) AND TARGET (T) PARAMETERS USING THE FIVE
C     PARTICLE PARAMETERS.  IT ALSO COMPUTES SOME OF THE 5 PARTILCLE
C     PARAMETERS FROM THE OTHERS.  IT FINDS E FROM VARIOUS
C     POSSIBLE SOURCES.  FINALLY IT STORES THE P AND T PARAMETERS
C     BACK INTO THE 5 PARTICLE PARAMETERS.
C     WHEN A DWBA IS NOT IN PROGRESS, THE 5 PARTICLE PARAMETERS
C     ARE NOT USED NOR RESET.                                           27740   
C
C     ICHAN - THE CHANNEL TO BE PROCESSED:
C     1)  PROJECTILE BOUND STATE
C     2)  TARGET BOUND STATE
C     3)  INCOMING DISTORTED WAVE
C     4)  OUTGOING DISTORTED WAVE
C     5)  BOUND STATE WITHOUT DWBA
C     6)  OPTICAL MODEL SCATTERING WITHOUT DWBA
C
C     IRET - SET TO 0 IF AN ERROR FOUND; 1 OTHERWISE.                   27750   
C
C     5/5/75 - FIRST VERSION
C     5/18/75 - USE Q BEFORE MASS EXCESS
C     5/30/75 - MORE J=0 STUFF.
C     7/20/75 - AUTO PICK L'S, J'S FOR STANDALONES
C     10/13/75 - ELAB AND ECM ALWAYS WIN IN ELASTIC SCATTERING.
C     12/14/76 - INELASTIC SCATTERING
C     4/24/77 - SET EXSPT FOR IDENTICAL PARTICLE DETERMINATION
C     9/24/77 - SET WASSET FOR JP, J, L; INITIALIZE WASSET
C     11/20/77 - SET CORRECT ASYMPTOPIA FROM NEW SPLIT VALUES - S.P.    27760   
C     2/11/78 - INDICATE WHEN ELAB HAS BEED DEFINED FROM ECM
C     5/4/79 - RATMAS; MP AND MT ALWAYS REQUIRED; PARITY; SPECTROSCOPIC
C              NOTATION CAN SET L, NODES - S.P.
C     6/5/79 - ELECTRON MASSES; FIX ELAB WASSET CONDITION - S.P.
C     12/28/79 - STANDARD MORTRAN - RPG
C     10/16/84 - USE ABS(SCTASY) - S.P.
C
C
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      parameter ( NUMJWORD = 12 )                                       /jblock/
      COMMON /JBLOCK/  J, JS(5),
     &  JP, JSP, JST,
     &  JPARM1, JPARM2, JPARM3
 
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
C
C     FOLLOWING IS ELECTRON MASS FOR CONVERTING ATOMIC MASSES
C     TO NUCLEAR MASSES.  FOLLOWING APPARENT CONVENTION, WE
C     IGNOR ELECTRON BINDING ENERGIES.
C                                                                       27780   
      DATA EMASS / .511 003 4 0D0 /
C
c
C
      IRET = 1
C
      JPOLD = JP
      JOLD = J
      LOLD = L
      IPOLD = PARITY                                                    27790   
C
C     WASSET IS USED TO KEEP TRACK OF THINGS SET TO OTHER THINGS
C     CLRCHN USES IT TO DETERMIN WHAT TO UNDEFINE.
C
      DO 19  I = 1, 32
 19   WASSET(I) = .FALSE.
C
C     IBND = 0  MEANS NOT A BOUND STATE CHANNEL,
C          > 0  MEANS A BOUND STATE, SEE STMNT NO 240 FOR MORE DETAILS
C                                                                       27800   
      IBND = 1
      IF ( ICHAN .EQ. 5 )  GO TO 300
      IBND = 0
      IF ( ICHAN .EQ. 6 )  GO TO 310
C
C     COMPUTE  MASS EXCESS = MASS EXCESS (GROUND STATE) + E*
C
      DO 129  I = 1, 5
         IF ( AMXCS(I) .NE. UNDEF )  GO TO 129
         IF ( AMXCGS(I) .EQ. UNDEF )  GO TO 129                         27810   
         AMXCS(I) = AMXCGS(I) + EXS(I)
 129  CONTINUE
C
C     FIND ZX, MX AND THE SIGNED ZX, MX
C       ( SIGNMX = MA-MB = MBIGB-MBIGA, ETC )
C
      SIGNMX = UNDEF
      ISGNZX = NOTDEF
C
C     IF THE CHARGE TRANSFER IS 0 OR IF MX = 0 (INELASTIC SCAT)         27820   
C     THEN NO AMBIGUITY
C
      IF ( DABS(AMX) .LT. .3 )  SIGNMX = 0
      IF ( IZS(5) .EQ. 0 )  ISGNZX = 0
C
      DO 149  I = 1, 3, 2
         IF ( IZS(I) .EQ. NOTDEF  .OR. IZS(I+1) .EQ. NOTDEF)
     1       GO TO 140
         ISGNZX = (IZS(I)-IZS(I+1)) * (2-I)
         IF ( IZS(5) .EQ. NOTDEF )  IZS(5) = IABS(ISGNZX)               27830   
 140     IF ( AMS(I) .EQ. UNDEF  .OR.  AMS(I+1) .EQ. UNDEF )
     1      GO TO 149
         SIGNMX = (AMS(I)-AMS(I+1)) * (2-I)
         IF ( AMS(5) .EQ. UNDEF )  AMS(5) = DABS(SIGNMX)
 149  CONTINUE
      IF ( DABS(SIGNMX) .LT. .3 )  SIGNMX = 0
C
C     NOW SUPPLY MISSING MASS OR Z VALUES IF POSSIBLE
C
      DO 189  I = 1, 4                                                  27840   
C     I, I2, AND 5 (=X)  MAKE A TRIPLE.
         I2 = I-1 + 2*MOD(I, 2)
         KSIGN = IABS(5-2*I) - 2
         IF ( ISGNZX .EQ. NOTDEF )  GO TO 180
         IF ( IZS(I) .NE. NOTDEF )  GO TO 180
         IF ( IZS(I2) .EQ. NOTDEF )  GO TO 180
         IZS(I) = IZS(I2) + KSIGN*ISGNZX
 180     IF ( SIGNMX .EQ. UNDEF )  GO TO 189
         IF ( AMS(I) .NE. UNDEF )  GO TO 189
         IF ( AMS(I2) .EQ. UNDEF )  GO TO 189                           27850   
         AMS(I) = AMS(I2) + KSIGN*SIGNMX
 189  CONTINUE
C
C     IF REQUESTED CONVERT ATOMIC NUMBERS TO TRUE MASSES FOR ALL USES
C
      IF ( MASTYP .NE. 2 )  GO TO 220
      DO 199  I = 1, 5
         IF ( AMXCS(I) .EQ. UNDEF )  GO TO  199
         M = AMS(I)
         IF ( AMS(I) .NE. M )  GO TO 199                                27860   
         AMS(I) = AMS(I) + AMXCS(I)/AMUMEV
 199  CONTINUE
C
C     WE HAVE DONE THE MOST WE CAN DO TO DEFINE THE M'S AND Z'S (1-5).
C     NOW PUSH ON AND DEFINE THE P AND T IF NECESSARY.
C
C     FIRST WE DETERMIN WHICH IS P AND T
C
C     WE SET:
C     IP - LABELS THE PROJECTILE (1, 2, OR 5)                           27870   
C     IT - LABELS THE TARGET (1-4)
C     IBND - FOR BOUND STATES LABELS THE COMPOSITE (1-4).
C            NOTE THAT THE PROJECTILE BOUND STATE (ICHAN=1) MAY BE
C            EITHER 1 OR 2 (STRIPING OR PICKUP) AND SIMILARLY THE
C            TARGET (ICHAN=2) MAY BE EITHER 4 OR 3.
C     THE ARRAYS LABELED BY IP, IT AND IBND ARE IN THE ORDER
C       A, B, BIGA, BIGB, X
C
C     ISTRIP IS SET TO +1 FOR STRIPPING; -1 FOR PICKUP; 0 FOR
C     INELASTIC SCATTERING.                                             27880   
C     IT IS ALSO USED BY BOUND WHEN COMPUTING Q.
C
 220  ISTRIP = NOTDEF
      IF ( ISGNZX .NE. NOTDEF )  ISTRIP = ISGNZX
      IF ( SIGNMX .NE. UNDEF  )  ISTRIP = SIGNMX
      IF ( ISTRIP .EQ. NOTDEF )  write (6, 223)
 223  FORMAT ('0***** WARNING:  NOT ENOUGH DATA TO DETERMIN IF',
     1  ' REACTION IS STRIPPING OR PICKUP - STRIPPING ASSUMED.')
      IF ( ISTRIP .EQ. NOTDEF )  ISTRIP = 1
      IF ( ISTRIP .NE. 0 )  ISTRIP = ISIGN( 1, ISTRIP )                 27890   
C
      IF ( ICHAN .GE. 3 )  GO TO 250
C
C     BOUND STATE,  PROJECTILE IS ALWAYS X.
C
      IP = 5
      IF ( ISTRIP .LT. 0 )  GO TO 240
      IT = ICHAN + 1
      IBND = IT + 2*ICHAN-3
      GO TO 280                                                         27900   
 240  IBND = ICHAN + 1
      IT = IBND + 2*ICHAN-3
      GO TO 280
C
C     SCATTERING STATES - NO COMPOSITE
C
 250  IBND = 0
      IP = ICHAN-2
      IT = IP + 2
C                                                                       27910   
C     NOW DEFINE UNDEFINED P AND T STUFF
C
 280  IF ( IZP .EQ. NOTDEF )  IZP = IZS(IP)
      IF ( IZT .EQ. NOTDEF )  IZT = IZS(IT)
      IF ( AMP .EQ. UNDEF )  AMP = AMS(IP)
      IF ( AMT .EQ. UNDEF )  AMT = AMS(IT)
      IF ( JSP .EQ. NOTDEF )  JSP = JS(IP)
      IF ( JST .EQ. NOTDEF )  JST = JS(IT)
C
C     COPY E* FOR P AND T.  THESE WILL BE UUSED BY WAVSET TO DETERMIN   27920   
C     IF THE PARTICLES ARE IDENTICAL
C
      IF ( EXSPT(1) .EQ. UNDEF )  EXSPT(1) = EXS(IP)
      IF ( EXSPT(2) .EQ. UNDEF )  EXSPT(2) = EXS(IT)
      IF ( AMXGPT(1) .EQ. UNDEF )  AMXGPT(1) = AMXCGS(IP)
      IF ( AMXGPT(2) .EQ. UNDEF )  AMXGPT(2) = AMXCGS(IT)
      IF ( PARIPT(1) .EQ. 0 )  PARIPT(1) = PARITS(IP)
      IF ( PARIPT(2) .EQ. 0 )  PARIPT(2) = PARITS(IT)
      LSPCPT(2) = LSPECS(IT)
      NODEPT(2) = NODESP(IT)                                            27930   
C
C     FOR SCATTERING ALLOW RANGES OF  L, JP, AND J.
C
      IF ( IBND .EQ. 0 )  GO TO 310
C
C     FOLLOWING PAGE OR SO IS FOR BOUND STATES ONLY.
C
      IF ( J .EQ. NOTDEF )  J = JS(IBND)
      IF ( PARITY .EQ. 0 )  PARITY = PARITS(IBND)
      IF ( L .EQ. NOTDEF )  L = LSPECS(IBND)                            27940   
      IF ( NODES .EQ. NOTDEF )  NODES = NODESP(IBND)
C
C     WE HAVE PULLED EVERYTING OUT OF 1-5 THAT WE WILL
C
C     THE FOLLOWING CODE IS ALSO USED WHEN NOT DOING A DWBA
C
C
C     TO ALLOW FOR HOLE STATES, WE ACCEPT LEVEL DESCRIPTORS OF
C     THE TARGET AS LEVEL DESCRIPTORS OF THE COMPOSITE.  LEVEL
C     DESCRIPTORS OF THE PROJECTILE ARE IGNORED.  NO CHECK IS MADE      27950   
C     FOR MULTIPLE LEVEL DESCRIPTORS -- THE COMPOSITE ALWAYS WINS.
C
 300  IF ( L .EQ. NOTDEF )  L = LSPCPT(2)
      IF ( NODES .EQ. NOTDEF )  NODES = NODEPT(2)
C
C     IF SOME ANGULAR MOMENTA ARE ZERO THEN WE CAN DEFINE OTHERS
C
      IF ( JP .EQ. NOTDEF  .AND.  JST .EQ. 0 )  JP = J
      IF ( JP .EQ. NOTDEF  .AND.  J .EQ. 0 )  JP = JST
      IF ( JP .EQ. NOTDEF  .AND.  L .EQ. 0 )  JP = JSP                  27960   
      IF ( JP .EQ. NOTDEF  .AND.  JSP .EQ. 0  .AND.
     1  L .NE. NOTDEF )  JP = 2*L
      IF ( J .EQ. NOTDEF   .AND.  JST .EQ. 0 )  J = JP
      IF ( L .NE. NOTDEF )  GO TO 305
      IF ( JP .NE. NOTDEF  .AND.  JSP .EQ. 0 )  L = JP/2
      IF ( JSP .NE. NOTDEF  .AND.  JP .EQ. 0 )  L = JSP/2
C
C     IF THERE ARE ONLY TWO POSSIBLE L'S, THEN PARITY CAN TELL
C     US WHAT TO DO.
C                                                                       27970   
      IF ( L .NE. NOTDEF )  GO TO 305
      I = PARITY*PARIPT(1)*PARIPT(2)
      IF ( I .EQ. 0 )  GO TO 310
      I = (I+3)/2
      IF ( JP .EQ. NOTDEF  .OR.  JSP .EQ. NOTDEF )  GO TO 310
      L1 = IABS(JP-JSP)/2
      L1 = L1 + MOD( I+L1, 2 )
      L2 = (JP+JSP)/2
      IF ( L2-L1 .GT. 1 )  GO TO 310
      L = L1                                                            27980   
C
C     L IS DEFINED; WE MAY BE ABLE TO PATCH UP A PARITY
C
 305  I = +1
      IF ( MOD( L, 2 ) .NE. 0 )  I = -1
      IF ( PARITY .EQ. 0 )  PARITY = PARIPT(1)*PARIPT(2)*I
      IF ( PARIPT(1) .EQ. 0 )  PARIPT(1) = I*PARITY*PARIPT(2)
      IF ( PARIPT(2) .EQ. 0 )  PARIPT(2) = I*PARITY*PARIPT(1)
C
C     FOLLOWING IS FOR BOTH SCATTERING AND BOUND STATES                 27990   
C
C
C     SETUP KINEMATIC PROJECTILE AND TARGET MASES
C
C     1)  TOTAL MASS EXCESS IN AMU
C
 310  AMXCP = 0
      IF ( AMXGPT(1) .NE. UNDEF )
     1   AMXCP = (AMXGPT(1)+EXSPT(1))/AMUMEV
      AMXCT = 0                                                         28000   
      IF ( AMXGPT(2) .NE. UNDEF )
     1   AMXCT = (AMXGPT(2)+EXSPT(2))/AMUMEV
C
C     MP AND MT MUST BE SEPARATELY DEFINED
C
      IF ( AMP .NE. UNDEF  .AND.  AMT .NE. UNDEF )  GO TO 330
      write (6, 323)
 323  FORMAT ( '0**** ERROR:  BOTH MP AND MT ARE REQUIRED.')
      IRET = 0
      GO TO 400                                                         28010   
C
C     2)  IF NECESSARY CONVERT TO FLOATING MASS
C
 330  IF ( MASTYP .NE. 2 )  GO TO 340
      M = AMP
      IF ( M .EQ. AMP )  AMP = AMP + AMXCP - IZP*(EMASS/AMUMEV)
      M = AMT
      IF ( M .EQ. AMT )  AMT = AMT + AMXCT - IZT*(EMASS/AMUMEV)
C
C     3)  NOW THE KINEMATIC MASSES IN TMP, TMT                          28020   
C
 340  TMP = AMP
      TMT = AMT
      IF ( MASTYP .NE. 0 )  GO TO 370
      M = TMP
      IF ( M .EQ. TMP )  TMP = TMP + AMXCP - IZP*(EMASS/AMUMEV)
      M = TMT
      IF ( M .EQ. TMT )  TMT = TMT + AMXCT - IZT*(EMASS/AMUMEV)
C
C     DEFINE THE REDUCED MASS IF NECESSARY                              28030   
C
 370  IF ( AM .NE. UNDEF )  GO TO 380
      AM = AMUMEV * TMP*TMT/(TMP+TMT)
      write(0,'(A,E18.12,A,E18.12,A,E18.12)')
     &  'FTN_MKIN TMP=',TMP,' TMT=',TMT,' AM=',AM
C
C     FIND ELAB TO ECM CONVERSION
C
 380  RATMAS = TMP/TMT
      CMLAB = 1 + RATMAS
C
C     FIND E IF NECESSARY                                               28040   
C
C     IN THE CASE OF ELASTIC SCATTERING, ELAB OR ECM ALWAYS
C     DOMINATES E.
C
 400  IF ( ICHAN .GE. 6 )  GO TO 450
      IF ( E .NE. UNDEF )  GO TO 500
      GO TO ( 410, 410, 450, 480, 430, 450 ), ICHAN
C
C     BOUND STATE; FIRST TRY Q AND THEN MASS EXCESS
 410  IF ( Q .EQ. UNDEF  .OR.  EBNDS(3-ICHAN) .EQ. UNDEF )              28050   
     1  GO TO 420
C     REMEMBER THAT THE PROJECTILE BOUND STATE MAY BE EITHER
C     INCOMING OR OUTGOING.
      E = (3-2*ICHAN) * ISTRIP * Q  +  EBNDS(3-ICHAN)
      GO TO 500
 420  IF ( AMXCS(IP) .EQ. UNDEF  .OR.  AMXCS(IT) .EQ. UNDEF
     1  .OR.  AMXCS(IBND) .EQ. UNDEF )  GO TO 430
      E = AMXCS(IBND) - AMXCS(IP) - AMXCS(IT)
      GO TO 500
 430  write (6, 433)                                                    28060   
 433  FORMAT ( '0**** E MUST BE DEFINED.')
      IRET = 0
      GO TO 500
C
C     INCOMING SCATTERING STATE; ECM OR ELAB APPLIES.
C     THIS IS ALSO USED FOR STAND ALONE SCATTERING
C     IF BOTH ELAB AND ECM ARE DEFINED; ELAB WINS
C
 450  IF ( ECM .NE. UNDEF )  E = ECM
      IF ( ELAB .EQ. UNDEF )  GO TO 465                                 28070   
      E = ELAB/CMLAB
      GO TO 500
 465  IF ( E .NE. UNDEF )  GO TO 500
      write (6, 468)
 468  FORMAT ('0**** E, ECM OR ELAB MUST BE DEFINED.')
      IRET = 0
      GO TO 500
C
C     OUTGOING SCATTERING STATE;  APPLY Q TO ECM
C                                                                       28080   
 480  IF ( ECM .EQ. UNDEF  )  GO TO 430
      IF ( Q .NE. UNDEF )  GO TO 495
C
C     ATTEMPT TO GET Q FROM TOTAL MASS EXCESSES
C     THIS WILL BE THE USUAL METHOD FOR INELASTIC SCATTERING
C
      DO 484  I = 1, 4
         IF ( AMXCS(I) .EQ. UNDEF )  GO TO 430
 484  CONTINUE
      Q = AMXCS(1) - AMXCS(2) + AMXCS(3) - AMXCS(4)                     28090   
 495  E = ECM + Q
      write(0,'(A,4E18.10,A,E18.10,A,E18.10)')
     &  'FTN_Q AMXCS=',AMXCS(1),AMXCS(2),AMXCS(3),AMXCS(4),
     &  ' Q=',Q,' ECM=',ECM
      GO TO 500
C
C     AT LAST E IS DEFINED.  FOR INCOMING WAVE DEFINE ECM, ELAB
C
 500  IF ( ICHAN .NE. 3  .AND.  ICHAN .NE. 6 )  GO TO 550
      ECM = E
      WASSET(16) = ELAB .EQ. UNDEF  .AND.  ICHAN .EQ. 6
      ELAB = E*CMLAB
C                                                                       28100   
C     FOR OUTGOING CHANNEL, DEFINE Q
C
 550  IF ( ICHAN .NE. 4 )  GO TO 600
      IF ( ECM .NE. UNDEF )  Q = E - ECM
C
C     NOW STORE THE P AND T STUFF BACK INTO THE 1-5 STUFF
C
 600  IF ( ICHAN .GT. 4 )  GO TO 700
      AMS(IP) = AMP
      AMS(IT) = AMT                                                     28110   
      IZS(IP) = IZP
      IZS(IT) = IZT
      JS(IP) = JSP
      JS(IT) = JST
      PARITS(IP) = PARIPT(1)
      PARITS(IT) = PARIPT(2)
      IF ( IBND .NE. 0 )  JS(IBND) = J
      IF ( IBND .NE. 0 )  PARITS(IBND) = PARITY
      IF ( SPAM .EQ. UNDEF )  GO TO 700
      IF ( ICHAN .EQ. 1 )  SPAMP = SPAM                                 28120   
      IF ( ICHAN .EQ. 2 )  SPAMT = SPAM
C
 700  WASSET(12) = JPOLD .NE. JP
      WASSET(13) = JOLD .NE. J
      WASSET(14) = LOLD .NE. L
      WASSET(29) = PARITY .NE. IPOLD
C
C     SET ASYMPTOPIA IF NEEDED
C
      IF ( ASYMPT .NE. UNDEF )  GO TO 750                               28130   
      WASSET(15) = .TRUE.
      ASYMPT = BNDASY
      IF ( IBND .EQ. 0 )  ASYMPT = ABS(SCTASY)
C
 750  RETURN
      END
C*ID* SETFG    C109.PTOLEMY.SOURCE                          PER701  16:
      SUBROUTINE  SETFG ( NCHNDF, MCHNDF, CHNDEF, RCHNDF,
     1  NBASDF, MBASDF, BASDEF, MCHNVL, CHNVAL, NUMLIS, LIS, FG,
     2  L1, L2P1, FGWORK, R1, R2, IRET )                                28140   
C
C     COMPUTES ALL F AND G COULOMB FUNCTIONS FOR C.C.
C
C     LOOPS THROUGH THE CHANNELS ARRAY AND GETS ALL F'S AND G'S
C     THEN STORES ACCORING TO BASIS DEF INDEXES.
C
C     FG HAS THE STRUCTURE  FG( I, IB, ILI )
C       ILI POINTS TO THE J-VALUE
C       IB  POINTS TO THE BASIS STATE
C       I = 1 FOR F(R-DELTA), 2 FOR G(R-DELTA), 3 FOR F(R),             28150   
C           4 FOR G(R)
C
C     1/17/80 - FIRST VERSION - S.P.
C     2/7/80 - FG ARRAY IS REAL*4 - S.P.
C     10/15/84 - REAL*8 FG POSSIBILITY; CHNVAL - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
C
      INTEGER  CHNDEF(MCHNDF, NCHNDF),  BASDEF(MBASDF, NBASDF)
      REAL*4  RCHNDF(MCHNDF, NCHNDF)                                    28160   
      INTEGER LIS(NUMLIS)
      REAL*4  FG(4, NBASDF, NUMLIS)                                     c4f
C8F      REAL*8  FG(4, NBASDF, NUMLIS)
      REAL*8  FGWORK(L2P1, 6), CHNVAL(MCHNVL, NCHNDF)
C
C
      L2 = L2P1-1
C
C     LOOP THROUGH THE CHANNELS ARRAY.
C                                                                       28170   
C     FOR EACH CHANNEL COMPUTE ALL THE COULOMB FUNCTIONS
C
      DO  499  NC = 1, NCHNDF
C
         AK = CHNVAL(1,NC)
         ETA = CHNVAL(2,NC)
         IB1 = CHNDEF(8,NC)
         IB2 = CHNDEF(9,NC) + IB1 - 1
C
         RHO = AK*R1                                                    28180   
         CALL  RCWFN ( RHO, ETA, L1, L2, FGWORK(1,1),
     1      FGWORK(1,5), FGWORK(1,2), FGWORK(1,6),
     2      1.D-12, IFLAG )
         IF ( IFLAG .NE. 0 )  GO TO 990
C
         RHO = AK*R2
         CALL  RCWFN ( RHO, ETA, L1, L2, FGWORK(1,3),
     1      FGWORK(1,5), FGWORK(1,4), FGWORK(1,6),
     2      1.D-12, IFLAG )
         IF ( IFLAG .NE. 0 )  GO TO 990                                 28190   
C
C     LOOP THROUGH THE L-J'S FOR THIS CHANNEL
C
         DO 399  IB = IB1, IB2
            LMJ = BASDEF(3,IB)
C
C     NOW LOOP THROUGH THE REQUIRED J'S AND STORE F AND G.
C
            DO 299  ILI = 1, NUMLIS
C                                                                       28200   
C**************************************************************
C
C*********  NOTE THAT J AND NOT 2*J IS STORED FOR NOW   *******
C
C**************************************************************
C
               J = 2*LIS(ILI)
               L = LMJ + J
               IF ( L .LT. 0 )  GO TO 299
               L = ishft( L,  -1 )                                      28210   
C
               DO 249  I = 1, 4
                  FG(I,IB,ILI) = FGWORK(L+1,I)
 249           CONTINUE
C
 299        CONTINUE
 399     CONTINUE
 499  CONTINUE
C
      IRET = 1                                                          28220   
      RETURN
C
C     ERROR IN RCWFN
C
 990  write (6, 993) IFLAG, NC, ETA, AK, RHO, L1, L2
 993  FORMAT ( '0**** RCWFN ERROR IN SETFG:' /
     1   2I8, 3G20.10, 2I8 )
      IRET = 0
      RETURN
C                                                                       28230   
      END
C*ID* SETFIT   C109.PTOLEMY.SOURCE                          PER701  11:
      SUBROUTINE SETFIT ( PARAM, IRET, NWP )
C
C  THIS ROUTINE CONSTRUCTS THE PARAMETER VECTOR FROM THE OPTICAL PARAMET
C  OR COMBINATIONS OF OPTICAL PARAMETERS TO BE FITTED.
C  THIS IS THE VERSION USED IF THE STANDARD PTOLEMY KEYWORDS ARE
C     ADEQUATE TO DESRIBE THE FIT.  ELSE A USER SUPPLIED ROUTINE SHOULD
C     BE CALLED AT THE DESIGNATED POINT BELOW.
C                                                                       28240   
C     IRET RETURN CODES:
C       1 - ALL O.K.
C       0 - INTERNAL ERROR - EQUAL ARRAY MESSED UP.
C      -1 - STEP WAS OUT OF BOUNDS.
C
C                                                   D.GLOECKNER 8/13/75
C     10/28/75 - MASSIVE CHANGES FOR GRADIENT COMPUTATION - S.P.
C     11/4/75 - CHECK FOR OUT-OF-BOUNDS STEPS.
C     2/18/76 - CHECK FOR IMPLAUSABLE STEPS
C     8/1/76 - 1/ELAB EXPANSION                                         28250   
C     4/15/77 - HANDLE RCP, RCT CORRECTLY
C     4/21/77 - RENORM AND ANGLE SHIFT MAY BE FIT
C     10/17/77 - POWERS OF WOODS-SAXONS
C     11/20/77 - DON'T STORE INTO WAVCOM.
C     11/29/77 - LET MAKPOT RETURN LINKULE IRET'S
C     5/10/79 - MODIFIED RC, RCP, RCT STUFF - S.P.
C     5/14/82 - SET LX=-1 FOR DEFORMED LINKULE - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
CDC      ALLOCLEVEL PARAM                                               28260   
C
      DIMENSION  PARAM(1)
C
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
C
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
C
      REAL*8  FLOAT(1)
      EQUIVALENCE ( FLOAT(1), A )
C                                                                       28270   
C
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
C
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      COMMON /LOCFIT/ IDATA, LPL, LSIGMA, LSMAT, IESETS, IMASK,         /locfit/
     &   IEQUAL, NPARA, IPARA, ITEMP, LSCSIG, LEPARM, LFS, NPTS, LEQNAM,
     &   MAXEQL, MAXVS, LVDERV, LSDELS, LDVTYP, LDSDP, LDFDX, LFGRAD,
     &   LTGRAD, LMASK, LEQUAL, MNDRIV, MXDRIV, IESIZE, LENPRE,
     &   LENKEY, LENHED,  ILNKBL
 
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
      COMMON /KANDM/ AKI, AKO, REDMI, REDMO, RIMAX, ROMAX, ISIGS(2),    /kandm/
     &  RSCTS(2), ASCTS(2), RCSCTS(2) ,ISMATS(2), LOMOST, LCRIT,
     &  ISCTMN, ISCTCR, ETAS(2), RCSCTP(2), RCSCTT(2), LCRITS(2),
     &  RATMSS(2), QMIN, ABAR
 
      DIMENSION  AKS(2), REDMS(2), RMAXS(2)
      EQUIVALENCE ( AKI, AKS(1) ), ( REDMI, REDMS(1) ),
     &  ( RIMAX, RMAXS(1) )
 
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
      COMMON / TEMPVS /  TVR, TVI, TVSOR, TVSOI, TAR, TAI               /tempvs/
 
c                                                                       /lnkblk/
c  STRUCTURE OF   /LNKBLK/
c
c  THERE IS A BLOCK OF 3 DOUBLE WORDS FOR EACH POSSIBLE USE
c  OF A LINKULE.  THE NUMLNK = NUMLINKULES USES ARE IN THE ORDER
c    REALPOTEN  IMAGPOTEN  REALVSO  IMAGVSO  COULOMB
c    WAVEFUNCTION  AND 6 TENSOR POTENTIALS
c  THE THREE-DOUBLE-WORD BLOCKS EACH HAVE THE STRUCTURE
c
c    LNKNAM(1,I)   LINKULE NAME
c
c      LNKADR(3,I)   LINKULE ADDRESS, O IF NO LINKULE IN USE.
c      LNKADR(4,I)   0 - NO L OR J DEPENDENCE IN POTENTIAL
c                    1 - L DEPENDENCE BUT NO J DEPENDENCE
c                    2 - BOTH L  AND J DEPENDENCE
c
c      LNKADR(5&6,I)  MYINTS - A TWO-ELEMENT ARRAY THAT THE
c                     LINKULE MAY USE FOR COMMUNICATION BETWEEN
c                     CALLS TO ITSELF.
c
      parameter ( NUMLINKULES = 13 )
      COMMON /LNKBLK/  NUMLNK, IUNIQU, LNKADR(6,NUMLINKULES)
      character*8  LNKNAM(3,NUMLINKULES)
      EQUIVALENCE ( LNKNAM(1,1), LNKADR(1,1) )
 
C
C
C  THE FOLLOWING PRODUCES A PARAMETER VECTOR AS SPECIFIED BYEHE FIT KEYW
C  IF NO PARAMETERS TO BE FITTED FOLLOW THE FIT KEYWORD (IN PARAENTHESIS
C  THEN IT IS ASSUMED THAT THE USER HAS MODIFIED THIS PROGRAM
C
      IRET=0
C
      DO 19 I=1,NPARA
            INDEX=ILLOC(LMASK+I-1)                                      28290   
            TEMP = PARAM(I)
            IF ( INDEX .GT. 0 )  GO TO 10
            INDEX = MOD( -INDEX, 10000 )
            ALLOC4(IDATA+INDEX) = TEMP
            GO TO 19
 10         FLOAT(INDEX) = TEMP
 19   CONTINUE
C
C
C                                                                       28300   
C  IF SOME OPTICAL PARAMETERS ARE REQUIRED TO BE EQUAL TO OTHERS--
C  SET THEM EQUAL HERE
C  EQUAL LOOKS LIKE:  2  1 2 3   4  1 2 3 4 5 ETC
C
      INDEX=LEQUAL
20    IMANY=ILLOC(INDEX)
      IF(IMANY)900,200,25
C  IF  3  THINGS EQUAL, IMANY IS THEN 2
C
 25   IMANY = IMANY + 1                                                 28310   
      DO 39  I = 1, IMANY
         KEY = ILLOC(INDEX+I)
         IF ( KEY .GT. 0 )  GO TO 30
         KEY = IDATA + MOD( -KEY, 10000 )
         IF ( I .EQ. 1 )  TEMP = ALLOC4(KEY)
         ALLOC4(KEY) = TEMP
         GO TO 39
 30     IF ( I .EQ. 1 )  TEMP = FLOAT(KEY)
         FLOAT(KEY) = TEMP
 39   CONTINUE                                                          28320   
C
      INDEX=INDEX+IMANY+1
      GO TO 20
C
C     NOW STORE LOTS OF STUFF IN THE WAVE COMMON BLOCKS
C
C
C  GET THE R'S FROM R0'S -- THIS ENERGY INDEPENDENT
C
 200  IF(RC0.NE.UNDEF)RC=R0MASS*RC0                                     28330   
      IF ( RC0P .NE. UNDEF )  RCP = RC0P * AMP**0.33333333333333333 0D0
      IF ( RC0T .NE. UNDEF )  RCT = RC0T * AMT**0.33333333333333333 0D0
      IF(RSO0.NE.UNDEF)RSO=R0MASS*RSO0
      IF(RSOI0.NE.UNDEF)RSOI=R0MASS*RSOI0
      IF(RSI0.NE.UNDEF)RSI=R0MASS*RSI0
C
C  THE FOLLOWING REPLACEMENTS MAY BE AFFECTED BY A NEW ELAB
C
      EMUL=ELAB
      IF(IEPOW.EQ.1) EMUL=1/ELAB                                        28340   
      TAR = A + EMUL*(AE+EMUL*AESQ)
      TAI = AI + EMUL*(AIE+EMUL*AIESQ)
      TVR = V + EMUL*(VE+EMUL*VESQ)
      TVI = VI + EMUL*(VIE+EMUL*VIESQ)
C  GET R'S  FROM R0'S
      IF ( R0 .NE. UNDEF )  R = R0MASS*(R0 +EMUL*(R0E + EMUL*R0ESQ))
      IF ( RI0 .NE. UNDEF )  RI = R0MASS*(RI0 +EMUL*(RI0E +
     1   EMUL*RI0ESQ))
      TVSOR = VSO + TVR*TAU
      TVSOI = VSOI + TVI*TAUI                                           28350   
C
C     WE HAVE SETUP ALL THE STANDARD PTOLEMY KEYWORDS.
C     THE USER'S LINKULES WILL HAVE TO PROCESS ANY NONSTANDARD
C     KEYWORDS.
C
C
C     CHECK THE POTENTIAL PARAMETERS FOR VALIDITY ( OUT-OF-BOUND STEPS )
C
C     FOLLOWING ARE CHECKS FOR PHYSICALLY IMPOSSIBLE OR IMPLAUSIBLE STEP
C                                                                       28360   
C     IF A LINKULE IS BEING USED, LET IT DO THE CHECKING
C
      IF ( LNKADR(3,1) .NE. 0 )  GO TO 420
      IF ( R .LE. 0  .OR.  TAR .LE. .001 )  GO TO 950
      IF ( TVR .LT. -100 )  GO TO 950
      IF ( TAR .GT. R )  GO TO 950
 420  IF ( LNKADR(3,2) .NE. 0 )  GO TO 440
      IF ( TVI .NE. 0  .AND.  ( RI .LE. 0  .OR.  TAI .LE. .001 ) )
     1  GO TO 950
      IF ( TVI .LT. 0  .OR.  VSI .LT. 0 )  GO TO 950                    28370   
      IF ( TVI .NE. 0  .AND.  TAI .GT. RI )  GO TO 950
      IF ( VSI .NE. 0  .AND.  ( RSI .LE. 0  .OR.  ASI .LE. .001 ) )
     1  GO TO 950
 440  IF ( LNKADR(3,5) .NE. 0 )  GO TO 500
      IF ( RC .LT. 0 )  GO TO 950
C
C     NOW ACTUALLY GENERATE THE POTENTIAL ARRAYS
C
 500  IF ( RCP .EQ. 0 )  RCT = RC
      RC = RCP + RCT                                                    28380   
      CALL SETVSQ ( RCP, RCT, IZP, IZT, 1 )
C
C     INDICATE THIS IS AN OPTICAL MODEL CALCULATION
C
      LX = -1
      IF ( NWP .NE. 0 )  CALL MAKPOT ( NWP, IRET )
C
      IF ( IRET .EQ. -1 )  GO TO 950
      IF ( IRET .GE. 0 )  IRET=1
      RETURN                                                            28390   
900   WRITE (6,910) IMANY
910   FORMAT(' EQUAL ARRAY MESSED UP',I8)
      RETURN
C
C     MADE AN OUT-OF-BOUNDS STEP
C
 950  write (6, 953) ELAB, (PARAM(I), I = 1, NPARA)
 953  FORMAT ( '0**** WARNING:  FITTER TRIED TO STEP TO NON-PHYSICAL',
     1    ' PARAMETERS (ELAB =', F8.2, ') :'  /
     2  ( 8G16.6 ) )                                                    28400   
      IRET = -1
      RETURN
C
      END
C*ID* SETINT   C109.PTOLEMY.SOURCE                          PER701  13:
      SUBROUTINE SETINT ( LMAX )
C
C     DEFINES TABLES FOR THE CRAY VERSION OF PLMSUB
C
C     A TABLE OF INTEGERS FROM 0 TO LMAX IS DEFINED.  AN EQUAL-SIZED    28410   
C     WORK AREA IS ALSO MADE.
C
C     5/10/85 - FIRST (?) VERSION
C
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      INTEGER WKBIAS
      REAL*8  INTTBL, INTVLS(1)
      COMMON /INTWRK/  MAXINT, INBIAS, WKBIAS, INTTBL(1)
CRA      POINTER (INBASE, INTVLS)                                       28420   
C
      IF ( LMAX .LE. MAXINT )  GO TO 100
      LMP1 = LMAX + 1
      IPLMIN = NALLOC(2*LMP1, 'PLMINTS ' )
      LPLMIN = Z(IPLMIN)
      MAXINT = LMAX
      INBIAS = LOC(ALLOC(LPLMIN)) - LOC(INTTBL)
      WKBIAS = INBIAS + LMP1
      INBASE = LOC(INTTBL) + INBIAS
      DO 29  I = 0, LMAX                                                28430   
         INTVLS(I+1) = I
 29   CONTINUE
      RETURN
C
C     THE TABLE IS BIG ENOUGH; UPDATE POINTERS
C
 100  IPLMIN = NAMLOC( 'PLMINTS ' )
      LPLMIN = Z(IPLMIN)
      INBIAS = LOC(ALLOC(LPLMIN)) - LOC(INTTBL)
      WKBIAS = INBIAS + MAXINT+1                                        28440   
      RETURN
      END
C*ID* SETLOG   C109.PTOLEMY.SOURCE                          PER701  11:
      SUBROUTINE  SETLOG ( MAXI )
C
C     CONSTRUCTS THE TABLE OF LOG(N|) FOR 3-J, ETC
C
C     7/31/80 - FIRST VERSION - SP
C
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
C
      REAL*8  LF
      COMMON /LOGFAC/  MAXLF, LFBIAS, LF(1)
C
      CHARACTER*8  LOGNAM / 'LOGFACS ' /
C
c
C
      ILOGFC = NAMLOC(LOGNAM)                                           28460   
      CALL DUMMY1
      IF ( MAXI .GT. MAXLF )  GO TO 100
      IF ( ILOGFC .EQ. 0 )  RETURN
      GO TO 300
C
 100  MAXLF = MAXI+10
      ILOGFC = NALLOC( MAXLF+1, LOGNAM )
      LLOGFC = Z(ILOGFC)
      ALLOC(LLOGFC) = 0
      X = 0                                                             28470   
      DI = 1
      DO 129  I = 1, MAXLF
         X = X + DLOG(DI)
         DI = DI+1
         ALLOC(LLOGFC+I) = X
 129  CONTINUE
C
 300  LFBIAS = Z(ILOGFC)-1 + (LOC(ALLOC)-LOC(LF))/FACFR1
      RETURN
      END                                                               28480   
C*ID* SETPOT   C109.PTOLEMY.SOURCE                          PER701  15:
      SUBROUTINE SETPOT ( IRET )
C
C     SETS UP POTENTIAL PARAMETERS FOR A SINGLE CHANNEL
C
C     THIS ROUTINE IS CALLED BEFORE EACH OF THE BOUND STATE AND
C     DISTORTED WAVE CALCULATIONS.  IT MAKES SURE THAT NECESSARY
C     R AND A PARAMETERS ARE DEFINED AS FOLLOWS:
C
C     FOR EACH NONZERO V(I) (AND ALWAYS FOR THE REAL V):                28490   
C
C     1)  IF R0(I) IS DEFINED USE IT; ELSE
C       A)  IF R(I) IS DEFINED USE IT R; ELSE
C       B1)  IF THIS IS AN IMAGINARY POT, USE CORRESPOND REAL R.
C       B2)  IF THIS IS REAL S.O. OR TENSOR, USE R FOR REAL V.
C       B3)  IF THIS IS IMAG S.O., USE R FOR REAL S.O.
C       B4)  IF THIS IS IMAG TENSOR, USE R FOR SURFACE ABSORPTION
C              IF DEFINED, ELSE USE R FOR VOLUME ABSORPTION.
C       C)  IF THESE FAIL TO DEFINE R(I) THEN COMPLAIN.
C                                                                       28500   
C     2)  IF A(I) IS DEFINED USE IT; ELSE
C       A1)  IF THIS IS AN IMAG V, USE CORRESPONDING REAL A
C       A2)  IF THIS IS REAL S.O. OR TENSOR, USE A FOR REAL V
C       A3)  IF THIS IS IMAG S.O., USE A FOR REAL S.O.
C       A4)  IF THIS IS IMAG TENSOR, USE A FOR SURFACE ABSORPTION
C              IF DEFINED, ELSE USE A FOR VOLUME ABSORPTION.
C       B)  COMPLAIN IF A(I) CANNOT BE DEFINED BY ABOVE.
C
C     WE KEEP TRACK OF THOSE PARAMETERS THAT HAVE BEEN SET EQUAL TO
C     OTHERS IN "WASSET".  THEN CLRCHN CAN RESET THEM TO UNDEFINED      28510   
C     AGAIN.
C     FOR THE COULOMB CHANNEL USE RC OR IF NOT DEFINED, USE RC0;
C     IF RC0 ALSO NOT DEFINED THEN USE FOLDED COULOMB FOR SCATTERING
C     IF ZP*ZT = 0, DO NOT REQUIRE DEFINITION OF RC.
C
C     R0 IS USED AS FOLLOWS:
C       R = R0 * MG**1/3                IF ML <= 2.5
C       R = R0 * (MG**1/3 + ML**1/3 )   IF ML > 2.5
C     WHERE ML = LESSER(MT, MP);  MG = GREATER(MT, MP).
C                                                                       28520   
C     5/2/75 - FIRST VERSION - S. PIEPER
C     5/22/75 - VSI ADDED
C     6/26/75 - DON'T SET RC = 1 FOR ZERO CHARGE
C     8/29/75 - R0MASS PUT IN COMMON
C     10/10/75 - USE R0E RI0E
C     10/21/75 - USE ESQ PARAMETERS
C     10/22/75 - USE WASSET ARRAY.
C     4/29/76 - AMEND INPUT TO PERMIT USE OF FOLDED COULOMB POTENTIALS
C     8/1/76 - 1/ELAB EXPANSION
C     1/9/77 - FIX RC0 ERROR                                            28530   
C     3/18/77 - FURTHER WORK ON ABOVE
C     4/24/77 - SET WASSET FOR RC STUUFF
C     9/27/77 - WASSET IS INITIALIZED BY SETCHN
C     11/29/77 - FOR LINKULE-COMPUTED POTENTIALS, DO NOT CHECK THINGS
C     12/13/77 - IMPROVE DEF OF RC0, RC FOR NO COULOMB FORCE - S.P.
C     3/25/78 - FIX ERROR IN LINKULES - LNKBLK SHOULD BE LNKADR
C     12/7/78 - ADD TENSOR POTENTIALS - RPG
C     2/27/79 - INCLUDE ML IN R/R0 ONLY IF ML > 2.5 - RPG
C              DO NOT ALWAYS DEFINE RC0, RC0P, RC0T - S.P.
C     7/21/79 - RESTORE PREVIOUS BOUND-STATE PARAMETERS ON PASS>=2 - RPG28540   
C
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      parameter ( NUMJWORD = 12 )                                       /jblock/
      COMMON /JBLOCK/  J, JS(5),
     &  JP, JSP, JST,
     &  JPARM1, JPARM2, JPARM3
 
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
c                                                                       /formf/
c ***  LNKADB was  numLINKULES but only 12 are used ???
c
      COMMON /FORMF/  IBDS(2), NPOTS(2), LBP, LBT, NBP, NBT, JBP, JBT,
     &  BNDMAX(2), BNDSTP(2), NSTPBD(2), RBNDS(2), ABNDS(2),
     &  RCBNDS(2), BNDMAS(2), BRATMS(2), RSOBDS(2), ASOBDS(2),
     &  VBNDS(2), VSOBDS(2), TAUBDS(2), LNKADB(6, 2, 12)
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
c                                                                       /lnkblk/
c  STRUCTURE OF   /LNKBLK/
c
c  THERE IS A BLOCK OF 3 DOUBLE WORDS FOR EACH POSSIBLE USE
c  OF A LINKULE.  THE NUMLNK = NUMLINKULES USES ARE IN THE ORDER
c    REALPOTEN  IMAGPOTEN  REALVSO  IMAGVSO  COULOMB
c    WAVEFUNCTION  AND 6 TENSOR POTENTIALS
c  THE THREE-DOUBLE-WORD BLOCKS EACH HAVE THE STRUCTURE
c
c    LNKNAM(1,I)   LINKULE NAME
c
c      LNKADR(3,I)   LINKULE ADDRESS, O IF NO LINKULE IN USE.
c      LNKADR(4,I)   0 - NO L OR J DEPENDENCE IN POTENTIAL
c                    1 - L DEPENDENCE BUT NO J DEPENDENCE
c                    2 - BOTH L  AND J DEPENDENCE
c
c      LNKADR(5&6,I)  MYINTS - A TWO-ELEMENT ARRAY THAT THE
c                     LINKULE MAY USE FOR COMMUNICATION BETWEEN
c                     CALLS TO ITSELF.
c
      parameter ( NUMLINKULES = 13 )
      COMMON /LNKBLK/  NUMLNK, IUNIQU, LNKADR(6,NUMLINKULES)
      character*8  LNKNAM(3,NUMLINKULES)
      EQUIVALENCE ( LNKNAM(1,1), LNKADR(1,1) )
 
C                                                                       28550   
C     THESE EQUIVALENCES ARE IN COMMON /FORMF/.
C
      DIMENSION LBNDS(2), NBNDS(2), JBNDS(2)
      EQUIVALENCE (LBNDS(1), LBP), (NBNDS(1), NBP), (JBNDS(1), JBP)
C
      DIMENSION RTEMP(2), ATEMP(2)
      character*4 TNAME(6) / 'TR', 'TRI', 'TL', 'TLI', 'TPR', 'TPRI' /
      CHARACTER*8 TNAMZ(6) / 'TR0', 'TRI0', 'TL0', 'TLI0', 'TPR0',
     1   'TPRI0' /
C                                                                       28560   
C
C
C
      IRET = 1
C
C     SETUP R0 MASS FACTOR INCASE IT IS NEEDED
C
      AMLESS = DMIN1( AMP, AMT )
      AMMORE = AMP+AMT-AMLESS
      THIRD = 1.D0/3.D0                                                 28570   
      I = R0TYPE+1
      GO TO ( 72, 74, 76, 78 ), I
C     R0DEFAULT
 72   R0MASS = AMMORE**THIRD
      IF ( AMLESS .GT. 2.5 )  R0MASS = R0MASS + AMLESS**(1.D0/3.D0)
      GO TO 100
C     R0TARGET
 74   R0MASS = AMMORE**THIRD
      GO TO 100
C     R0SUM                                                             28580   
 76   R0MASS = AMMORE**THIRD + AMLESS**THIRD
      GO TO 100
C     R0MTOT
 78   R0MASS = (AMLESS+AMMORE)**THIRD
C
C     ENERGY FACTOR FOR ENERGY-DEPENDANT POTENTIALS
C
100   EELAB = (1+RATMAS)*E
      EEMUL=EELAB
      IF(IEPOW.EQ.1) EEMUL=1/EELAB                                      28590   
C
C     ON THE SECOND AND SUBSEQUENT PASSES, RESTORE THOSE PARAMETERS
C     WHICH HAVE NOT BEEN REDEFINED.
C
      IF ( IBSPAS .LE. 1  .OR.  NEXT .LT. 1  .OR.  NEXT .GT. 2 )
     1   GO TO 140
      IF ( L .EQ. NOTDEF )  L = LBNDS(NEXT)
      IF ( NODES .EQ. NOTDEF )  NODES = NBNDS(NEXT)
      IF ( JP .EQ. NOTDEF )  JP = JBNDS(NEXT)
      IF ( ASYMPT .EQ. UNDEF )  ASYMPT = BNDMAX(NEXT)                   28600   
      IF ( STEPSZ .EQ. UNDEF )  STEPSZ = BNDSTP(NEXT)
      IF ( R .EQ. UNDEF )  R = RBNDS(NEXT)
      IF ( A .EQ. UNDEF )  A = ABNDS(NEXT)
      IF ( RC .EQ. UNDEF )  RC = RCBNDS(NEXT)
      IF ( AM .EQ. UNDEF )  AM = BNDMAS(NEXT)
      IF ( E .EQ. UNDEF )  E = EBNDS(NEXT)
      IF ( RSO .EQ. UNDEF )  RSO = RSOBDS(NEXT)
      IF ( ASO .EQ. UNDEF )  ASO = ASOBDS(NEXT)
      DO 129 I = 1, 6
         IF ( LNKADR(3,I) .GT. 0  .OR.  LNKADB(3,NEXT,I) .LE. 0 )       28610   
     1      GO TO 129
         DO 119 II = 1, 6
            LNKADR(II,I) = LNKADB(II,NEXT,I)
 119     CONTINUE
 129  CONTINUE
C     POTENTIALS ARE TURNED OFF BY "UNDEFINING" THEM.
      IF ( V .EQ. 0 )  V = VBNDS(NEXT)
      IF ( VSO .EQ. 0 )  VSO = VSOBDS(NEXT)
      IF ( TAU .EQ. 0 )  TAU = TAUBDS(NEXT)
C                                                                       28620   
 140  IF ( V .EQ. UNDEF )  V = 0
      IF ( VSO .EQ. UNDEF )  VSO = 0
      IF ( TAU .EQ. UNDEF )  TAU = 0
C
C     PARAMS FOR V REAL MUST ALWAYS BE DEFINED
C
 150  IF ( R0 .NE. UNDEF )  GO TO 160
      IF ( R .NE. UNDEF )  GO TO 190
      IF ( LNKADR(3,1) .NE. 0 )  GO TO 200
      write (6, 153)                                                    28630   
 153  FORMAT ( '0**** R OR R0 MUST BE DEFINED.')
      IRET = 0
      GO TO 190
 160  R = (R0+R0E*EEMUL+R0ESQ*EEMUL**2) * R0MASS
 190  IF ( A .NE. UNDEF )  GO TO 200
      write (6, 193)
 193  FORMAT ( '0**** A MUST BE DEFINED.')
      IRET = 0
C
C     NOW CHECK FOR THE EXISTANCE OF IMAG PART.                         28640   
C
 200  IF ( VI+VIE*EEMUL+VIESQ*EEMUL**2 .EQ. 0 )  GO TO 300
C
C     WHEN SPECIFIC IMAG PARAM IS NOT AVAIL, USE CORRESPONDING REAL
C
      IF ( RI0 .NE. UNDEF )  GO TO 210
      IF ( RI .NE. UNDEF )  GO TO 240
      RI = R
      RI0 = R0
      RI0E = R0E                                                        28650   
      RI0ESQ = R0ESQ
      WASSET(1) = .TRUE.
      IF ( RI .NE. UNDEF )  GO TO 240
      IF ( LNKADR(3,2) .NE. 0 )  GO TO 240
      write (6, 203)
 203  FORMAT ( '0**** RI OR RI0 MUST BE DEFINED' )
      IRET = 0
      GO TO 240
 210  RI = (RI0+RI0E*EEMUL+RI0ESQ*EEMUL**2) * R0MASS
 240  IF ( AI .NE. UNDEF )  GO TO 300                                   28660   
      AI = A
      AIE = AE
      AIESQ = AESQ
      WASSET(2) = .TRUE.
      IF ( AI .NE. UNDEF  .OR.  LNKADR(3,2) .NE. 0 )  GO TO 300
      write (6, 243)
 243  FORMAT ( '0**** AI MUST BE DEFINED.' )
      IRET = 0
C
C     NEXT THE REAL SPIN ORBIT                                          28670   
C
 300  IF ( VSO .EQ. 0  .AND.  TAU .EQ. 0 )  GO TO 350
C
C     WHEN S.O. PARMS NOT AVAILABLE, USE CORRESPONDING REAL ONES.
C
      IF ( RSO0 .NE. UNDEF )  GO TO 310
      IF ( RSO .NE. UNDEF )  GO TO 340
      RSO = R
      WASSET(3) = .TRUE.
      IF ( RSO .NE. UNDEF  .OR.  LNKADR(3,3) .NE. 0 )  GO TO 340        28680   
      write (6, 303)
 303  FORMAT ( '0**** RSO OR RSO0 MUST BE DEFINED.' )
      IRET = 0
      GO TO 340
 310  RSO = RSO0 * R0MASS
 340  IF ( ASO .NE. UNDEF )  GO TO 350
      ASO = A
      WASSET(4) = .TRUE.
      IF ( ASO .NE. UNDEF  .OR.  LNKADR(3,3) .NE. 0 )  GO TO 350
      write (6, 343)                                                    28690   
 343  FORMAT ( '0**** ASO MUST BE DEFINED.' )
      IRET = 0
C
C     NEXT IMAGINARY S.O.
C
 350  IF ( VSOI .EQ. 0  .AND.  TAUI .EQ. 0 )  GO TO 400
C
C     WHEN IMAG S.O. PARMS NOT AVAILABLE, USE REAL S.O. ONES.
C
      IF ( RSOI0 .NE. UNDEF )  GO TO 370                                28700   
      IF ( RSOI .NE. UNDEF )  GO TO 390
      RSOI = RSO
      WASSET(5) = .TRUE.
      IF ( RSOI .NE. UNDEF  .OR.  LNKADR(3,4) .NE. 0 )  GO TO 390
      write (6, 363)
 363  FORMAT ( '0**** RSOI OR RSOI0 MUST BE DEFINED.')
      IRET = 0
      GO TO 390
 370  RSOI = RSOI0 * R0MASS
 390  WASSET(6) = ASOI .EQ. UNDEF                                       28710   
      IF ( ASOI .EQ. UNDEF )  ASOI = ASO
      IF ( ASOI .NE. UNDEF  .OR.  LNKADR(3,4) .NE. 0 )  GO TO 400
      write (6, 393)
 393  FORMAT ( '0**** ASOI MUST BE DEFINED.')
      IRET = 0
C
C     NEXT SURFACE ABSORPTION
C
 400  IF ( VSI .EQ. 0 )  GO TO 500
C                                                                       28720   
C     WHEN SPECIFIC VSI PARAM IS NOT AVALABLE, USE CORRESPONDING IMAG
C
      IF ( RSI0 .NE. UNDEF )  GO TO 410
      IF ( RSI .NE. UNDEF )  GO TO 440
      RSI = RI
      WASSET(7) = .TRUE.
      IF ( RSI .NE. UNDEF  .OR.  LNKADR(3,2) .NE. 0 )  GO TO 440
      write (6, 403)
 403  FORMAT ( '0**** RSI OR RSI0 MUST BE DEFINED.' )
      IRET = 0                                                          28730   
      GO TO 440
 410  RSI = RSI0 * R0MASS
 440  WASSET(8) = ASI .EQ. UNDEF
      IF ( ASI .EQ. UNDEF )  ASI = AI
      IF ( ASI .NE. UNDEF  .OR.  LNKADR(3,2) .NE. 0 )  GO TO 500
      write (6, 443)
 443  FORMAT ( '0**** ASI MUST BE DEFINED.' )
      IRET = 0
C
C     NEXT COULOMB                                                      28740   
C
 500  IF ( IZP .NE. NOTDEF  .AND.  IZT .NE. NOTDEF )  GO TO 510
      write (6, 503)
 503  FORMAT ( '0**** ZP AND ZT MUST ALWAYS BE DEFINED.')
      IRET = 0
      IZPZT = 1
      GO TO 520
510   IZPZT = IZP*IZT
 520  IF ( RC0 .NE. UNDEF )  GO TO 530
      IF ( RC .NE. UNDEF )  GO TO 700                                   28750   
C
C     IF CHARGE IS 0 THEN RC NEED NOT BE DEFINED.  WE THEN SET IT
C     TO 1 TO AVOID PROBLEMS LATER ON
C
      RC = 1
      WASSET(9) = .TRUE.
      IF ( IZPZT .EQ. 0 )  GO TO 700
      IF((NEXT.EQ.3).OR.(NEXT.EQ.4).OR.(NEXT.EQ.6).OR.(NEXT.EQ.21))
     1  GO TO 620
      write (6, 523)                                                    28760   
 523  FORMAT ( '0**** RC OR RC0 MUST BE DEFINED FOR BS.')
      RC0 = UNDEF
      RC = UNDEF
      WASSET(9) = .FALSE.
      IRET = 0
      GO TO 600
  620 IF(RC0P.NE.UNDEF) GO TO 630
      IF(RCP.NE.UNDEF) GO TO 650
      IAMP=AMP+.5
      CALL REQUIV(RCP,RC0P,IZP,IAMP)                                    28770   
      RC0P = UNDEF
      WASSET(10) = .TRUE.
      GO TO 650
  630 RCP=RC0P*(AMP**(1.D0/3.D0))
  650 IF(RC0T.NE.UNDEF) GO TO 660
      IF(RCT.NE.UNDEF) GO TO 680
      IAMT=AMT+.5
      CALL REQUIV(RCT,RC0T,IZT,IAMT)
      RC0T = UNDEF
      WASSET(11) = .TRUE.                                               28780   
      GO TO 680
  660 RCT=RC0T*(AMT**(1.D0/3.D0))
  680 RC=RCP+RCT
      GO TO 600
 530  RC = RC0 * R0MASS
  700 IF((NEXT.LE.2).OR.(NEXT.EQ.5)) GO TO 600
      IF(IVRTEX.EQ.2) GO TO 720
      RCP=0
      RCT=RC
      GO TO 600                                                         28790   
  720 RCP=RC
      RCT=0
C
C     LOOP THROUGH TENSOR POTENTIAL TYPES:
C     REAL TR, IMAG TR, REAL TL, IMAG TL, REAL TP, IMAG TP.
C     DEFAULT REAL TENSOR PARTMETERS = REAL CENTRAL.
C     DEFAULT IMAG. TENSOR PARAMETERS = SURFACE IMAG. CENTRAL IF
C        DEFINED, ELSE VOLUME IMAG. CENTRAL.
C
 600  RTEMP(1) = R                                                      28800   
      RTEMP(2) = RSI
      IF ( RTEMP(2) .EQ. UNDEF ) RTEMP(2) = RI
      ATEMP(1) = A
      ATEMP(2) = ASI
      IF ( ATEMP(2) .EQ. UNDEF ) ATEMP(2) = AI
      IRI = 1
      DO 860 ITEN = 1, 6
      IF ( VTEN(ITEN) .EQ. 0 ) GO TO 850
      IF ( RTEN0(ITEN) .NE. UNDEF ) GO TO 810
      IF ( RTEN(ITEN) .NE. UNDEF ) GO TO 840                            28810   
      RTEN(ITEN) = RTEMP(IRI)
      WASSET(2*ITEN+15) = .TRUE.
      IF ( RTEN(ITEN) .NE. UNDEF  .OR.  LNKADR(3,ITEN+4) .NE. 0 )
     1  GO TO 840
      write (6, 803)  TNAME(ITEN), TNAMZ(ITEN)
 803  FORMAT ( '0**** R', A4, ' OR R', A5, ' MUST BE DEFINED.' )
      IRET = 0
      GO TO 840
 810  RTEN(ITEN) = RTEN0(ITEN) * R0MASS
 840  IF ( ATEN(ITEN) .NE. UNDEF ) GO TO 850                            28820   
      ATEN(ITEN) = ATEMP(IRI)
      WASSET(2*ITEN+16) = .TRUE.
      IF ( ATEN(ITEN) .NE. UNDEF  .OR.  LNKADR(3,ITEN+4) .NE. 0 )
     1  GO TO 850
      write (6, 843)  TNAME(ITEN)
 843  FORMAT ( '0**** A', A4, ' MUST BE DEFINED.' )
      IRET = 0
 850  IRI = 3 - IRI
 860  CONTINUE
      RETURN                                                            28830   
      END
C*ID* SETSPT   C109.PTOLEMY.SOURCE                          PER701  14:
      SUBROUTINE SETSPT ( ISIZE, LOC, IPASS, JBGBIN, JBIN, PBUGSW,
     1   BASDEF, MBASDF, NBASDF )
C
C     SETS UP S-MATRIX POINTERS
C
C     THIS IS BOB GODDARD'S LOOPS FROM ANGSET TO SET UP THE
C     INDXS AND TOCS ARRAYS.  THEY HAVE BEEN FRAGMENTED TO
C     ALLOW REPEATED CALLS TO BUILD UP THE ARRAYS FOR                   28840   
C     COUPLED-CHANNELS CALCULATIONS.
C
C     IPASS:
C        1   ADDS REQUIRED INDXS SIZE TO ISIZE.
C        2   STORES INDEXS AT ALLOC(LOC) AND ADDS NSPLI  TO
C            ISIZE (4*NSPLI = REQUIRED TOCS SIZE)
C        3   STORES TOCS IN ILLOC(ISIZE); USES INDXS FROM
C            ILLOC(LOC)
C
C     JBIN, JBGBIN - VALUES OF JB AND JBIGB FOR THIS CHANNEL            28850   
C
C     12/26/79 - TAKEN FROM ANGSET - S.P.
C     4/25/80 - PBUGSW MADE AN ARGUMENT - S.P.
C     7/16/80 - REMOVE LOGICAL SOSWT - S.P.
C     10/26/81 - CHECK BASDEF ARRAY FOR LX DEFINITIONS - S.P.
C
C
      implicit real*8 ( a-h, o-z )                                      implicit
C
      INTEGER  BASDEF(MBASDF, NBASDF)                                   28860   
      LOGICAL PBUGSW
C
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      parameter ( NUMJWORD = 12 )                                       /jblock/
      COMMON /JBLOCK/  J, JS(5),
     &  JP, JSP, JST,
     &  JPARM1, JPARM2, JPARM3
 
      COMMON /KANDM/ AKI, AKO, REDMI, REDMO, RIMAX, ROMAX, ISIGS(2),    /kandm/
     &  RSCTS(2), ASCTS(2), RCSCTS(2) ,ISMATS(2), LOMOST, LCRIT,
     &  ISCTMN, ISCTCR, ETAS(2), RCSCTP(2), RCSCTT(2), LCRITS(2),
     &  RATMSS(2), QMIN, ABAR
 
      DIMENSION  AKS(2), REDMS(2), RMAXS(2)
      EQUIVALENCE ( AKI, AKS(1) ), ( REDMI, REDMS(1) ),
     &  ( RIMAX, RMAXS(1) )
 
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
C
c                                                                       /formf/
c ***  LNKADB was  numLINKULES but only 12 are used ???
c
      COMMON /FORMF/  IBDS(2), NPOTS(2), LBP, LBT, NBP, NBT, JBP, JBT,
     &  BNDMAX(2), BNDSTP(2), NSTPBD(2), RBNDS(2), ABNDS(2),
     &  RCBNDS(2), BNDMAS(2), BRATMS(2), RSOBDS(2), ASOBDS(2),
     &  VBNDS(2), VSOBDS(2), TAUBDS(2), LNKADB(6, 2, 12)
 
      DIMENSION R2S(4)                                                  28870   
      EQUIVALENCE ( R2S(1), RBNDS(1) )
C
      LOGICAL ONELSW, IDENSW                                            /inelcm/
      COMMON /INELCM/  JBPF, JBTF, LXMIN, LXMAX, ILILOR, ILILOI, MSTOP,
     &  IA12M, NMLOLX, ONELSW, NUMLX, IRDINT, IELCUP, LILOSZ, NUMLIS,
     &  ILIS, IBETAS(3), ICL2FF, LXSTEP, IDENSW, LSKIP,
     &  JPMIN, JPMAX, JPBASE, NJP, JTMIN, JTMAX, JTBASE, NJT,
     &  IINDXS, ISMATR, ISMATI, NSMAT, NLX, NSPLI, ITOCS,
     &  NASPLI, IUNITR, LIFIT, ILIFIT, NOLFIT, IDELSR, IDELSI
      INTEGER INDXJS(4,2)
      EQUIVALENCE ( INDXJS(1,1), JPMIN )
 
C
      LOGICAL   MULTSW
C
C
C     SETUP SOME ANGULAR MOMENTUM STUFF FOR THIS CHANNEL
C
      JS(2) = JBIN                                                      28880   
      JS(4) = JBGBIN
C
      IF ( PROBLM .NE. 24 )  GO TO 50
C
      JPMIN = IABS( JS(1)-JS(2) )
      JPMAX = JS(1)+JS(2)
      JTMIN = IABS( JS(3)-JS(4) )
      JTMAX = JS(3)+JS(4)
      LBP = JPMIN/2
      LBT = JTMIN/2                                                     28890   
C
  50  JTBASE = IABS ( JS(3) - JS(4) )
      NJT = ( JS(3) + JS(4) - JTBASE ) / 2 + 1
      JPBASE = IABS ( JS(1) - JS(2) )
      NJP = ( JS(1) + JS(2) - JPBASE ) / 2 + 1
      NLX = ( JS(1) + JS(2) + JS(3) + JS(4) )/2 + 1
C
      GO TO ( 100, 200, 400 ), IPASS
C
C     RETURN REQUIRED INDXS SIZE                                        28900   
C
 100  ISIZE = ISIZE + 3*NLX*NJP*NJT
      RETURN
C
C     IPASS = 2 ; FILL IN INDXS AND COMPUTE NSPLI
C
 200  NSPLI = 0
      LINDXS = LOC
C
C     NOW FILL IN "INDXS" FOR ALL S-MATRIX ELEMENTS NEEDED ON THIS      28910   
C     AND SUBSEQUENT PASSES.
C
      MULTSW = SOSWS(1)  .OR.  SOSWS(2)  .OR.  IBSPAS .GT. 0
      JTMN = JTMIN
      JTMX = JTMAX
      IF ( IBSPAS .GT. 0 )  JTMN = JTBASE
      IF ( IBSPAS .GT. 0 )  JTMX = JS(3) + JS(4)
      JPMN = JPMIN
      JPMX = JPMAX
      IF ( MULTSW )  JPMN = JPBASE                                      28920   
      IF ( MULTSW )  JPMX = JS(1) + JS(2)
      DO  349  JTT = JTMN, JTMX, 2
         DO  339  JTP = JPMN, JPMX, 2
            LXMN = IABS ( JTT - JTP )/2
            LXMX = ( JTT + JTP )/2
            IF ( .NOT. MULTSW )  LXMN = MAX0( LXMN, LXMIN )
            IF ( .NOT. MULTSW )  LXMX = MIN0( LXMX, LXMAX )
            IF ( LXMX .LT. LXMN )  GO TO  339
            DO  329  LX = LXMN, LXMX
               IF ( PROBLM .NE. 24 )  GO TO 250                         28930   
C
C     FOR C.C. WE MUST MAKE SURE THAT EACH LX IS BEING FOUND
C
               DO 239  I = 1, NBASDF
                  IF ( BASDEF(2,I) .EQ. 2*LX )  GO TO 250
  239          CONTINUE
               GO TO 329
  250          NDEL = LX + 1 - MOD ( LX+LBP+LBT, 2 )
               IF ( NDEL .EQ. 0 ) GO TO  329
               K = ( JTP-JPBASE + NJP*(JTT-JTBASE) )/2                  28940   
               K = 1 + LX + NLX*K
               LDELMN = 1 - NDEL
               ILLOC(LINDXS+3*K-2) = NSPLI + 1
               ILLOC(LINDXS+3*K-1) = LDELMN
               ILLOC(LINDXS+3*K) = NDEL
               NSPLI = NSPLI + NDEL
  329       CONTINUE
  339    CONTINUE
  349 CONTINUE
      ISIZE = ISIZE + NSPLI                                             28950   
      I = 3*NLX*NJP*NJT
      IF ( PBUGSW ) write (6,  393)  NSPLI, ISIZE, NLX, JPMIN, JPMAX,
     1   JPBASE, NJP, JTMIN, JTMAX, JTBASE, NJT,
     1   ( ILLOC(LINDXS+K), K = 1, I )
  393 FORMAT ( ' NSPLI, ISIZE, NLX, JPMIN, JPMAX, JPBASE, NJP =',
     1    7I10 /
     1   ' JTMIN, JTMAX, JTBASE, NJT =', 4I10 /
     2   ( ' INDXS', 3I10 ) )
C
      RETURN                                                            28960   
C
C     PASS 3 - FILL IN TOCS
C
 400  LTOCS = ISIZE
      LINDXS = LOC
C
C
C     ALL PASSES:  FILL IN "TOCS" FOR THOSE S-MATRIX ELEMENTS WHICH
C     ARE USED ON THIS PASS.
C                                                                       28970   
      SOSWT = SOSWS(1) .OR. SOSWS(2)
      JPMN = JPMIN
      JPMX = JPMAX
      IF ( SOSWT ) JPMN = JPBASE
      IF ( SOSWT ) JPMX = JS(1) + JS(2)
      NLXJP = NLX*NJP
      N = NLXJP*NJT
      DO  469  K = 1, N
         NDEL = ILLOC(LINDXS+3*K)
         IF ( NDEL .EQ. 0 )  GO TO  469                                 28980   
         JTT = ( (K-1)/NLXJP )*2 + JTBASE
         IF ( JTT .LT. JTMIN  .OR.  JTT .GT. JTMAX )  GO TO  469
         JTP = MOD ( (K-1)/NLX, NJP )*2 + JPBASE
         IF ( JTP .LT. JPMN  .OR.  JTP .GT. JPMX )  GO TO  469
         LX = MOD ( K-1, NLX )
         IF ( .NOT. SOSWT  .AND.  ( LX .LT. LXMIN  .OR.
     1      LX .GT. LXMAX ) )  GO TO  469
         LDEL = ILLOC(LINDXS+3*K-1)
         KOFFS = ILLOC(LINDXS+3*K-2)
         DO  459  IDEL = 1, NDEL                                        28990   
            ILLOC(LTOCS+4*KOFFS-3) = LDEL
            ILLOC(LTOCS+4*KOFFS-2) = LX
            ILLOC(LTOCS+4*KOFFS-1) = JTP
            ILLOC(LTOCS+4*KOFFS) = JTT
            LDEL = LDEL + 2
            KOFFS = KOFFS + 1
  459    CONTINUE
  469 CONTINUE
C
      RETURN                                                            29000   
      END
C*ID* SFROMI   C109.PTOLEMY.SOURCE                          PER701  15:
      SUBROUTINE SFROMI ( LI, ILI, SMATR, SMATI, INDXS, XIREAL, XIIMAG,
     1   IINDEX, NI, INDXDW, IDWFI, IDWFO, RIROAB, ATERM, FACTOR,
     2   PINFSW, NLINE )
C
C     COMPUTES S MATRIX ELEMENTS FROM TRANSFER RADIAL INTEGRALS.
C
C     OPTIONALLY, THE S-MATRIX MAY ALSO BE PRINTED.
C                                                                       29010   
C
C     ARGUMENTS ARE:
C     NAME     BASE     MEANING
C     LI                INCIDENT L.
C     ILI               INDEX OF LI IN THE LIS ARRAY
C     SMATR    ISMATR   REAL S-MATRIX (OUTPUT).
C     SMATI    ISMATI   IMAGINARY S-MATRIX (OUTPUT).
C     INDXS    IINDXS   S-MATRIX INDICES FOR EACH (JP, JT) PAIR.
C     XIREAL   ILILOR   REAL RADIAL INTEGRALS.
C     XIIMAG   ILILOI   IMAG. RADIAL INTEGRALS.                         29020   
C     IINDEX   IIINDX   INDICES FOR EACH RADIAL INTEGRAL.
C     NI                NUMBER OF RADIAL INTEGRALS.
C     INDXDW   IDWI     INDICES FOR EACH FI*FO DISTORTED WAVE PRODUCT.
C     IDWFI    IWFII    INDICES FOR EACH INCIDENT DISTORTED WAVE.
C     IDWFO    IWFIO    INDICES FOR EACH OUTGOING DISTORTED WAVE.
C     RIROAB   IABS1    INTEGRALS OF ABS. VALUE OF INTEGRANDS.
C     ATERM    IBETAS(1)  SPECTROSCOPIC COEFFICIENTS A(LX,JBP,JBT)
C                           FOR EACH LX.
C     FACTOR            KINEMATIC FACTOR = 2*SQRT(KI*KF/EI*EF).
C     PINFSW            TRUE IF S-MATRIX ELEMENTS ARE TO BE PRINTED.    29030   
C     NLINE             NUMBER OF LINES ALREADY PRINTED ON THIS PAGE.
C
C     6/11/79 - NEW ROUTINE - RPG
C     11/20/79 - S-MATRICES STORED BY LO-LI; ILI ARGUMENT - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
c                                                                       /formf/
c ***  LNKADB was  numLINKULES but only 12 are used ???
c
      COMMON /FORMF/  IBDS(2), NPOTS(2), LBP, LBT, NBP, NBT, JBP, JBT,
     &  BNDMAX(2), BNDSTP(2), NSTPBD(2), RBNDS(2), ABNDS(2),
     &  RCBNDS(2), BNDMAS(2), BRATMS(2), RSOBDS(2), ASOBDS(2),
     &  VBNDS(2), VSOBDS(2), TAUBDS(2), LNKADB(6, 2, 12)
 
      CHARACTER*1  REACT, HEADER                                        /hedcom/
      COMMON /HEDCOM/  REACT(45), HEADER(65)
 
      LOGICAL ONELSW, IDENSW                                            /inelcm/
      COMMON /INELCM/  JBPF, JBTF, LXMIN, LXMAX, ILILOR, ILILOI, MSTOP,
     &  IA12M, NMLOLX, ONELSW, NUMLX, IRDINT, IELCUP, LILOSZ, NUMLIS,
     &  ILIS, IBETAS(3), ICL2FF, LXSTEP, IDENSW, LSKIP,
     &  JPMIN, JPMAX, JPBASE, NJP, JTMIN, JTMAX, JTBASE, NJT,
     &  IINDXS, ISMATR, ISMATI, NSMAT, NLX, NSPLI, ITOCS,
     &  NASPLI, IUNITR, LIFIT, ILIFIT, NOLFIT, IDELSR, IDELSI
      INTEGER INDXJS(4,2)
      EQUIVALENCE ( INDXJS(1,1), JPMIN )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
      EQUIVALENCE ( JA, JSPS(1) ), ( JB, JSPS(2) )
C
C     ARGUMENT DIMENSIONS, TYPES
C
      DIMENSION SMATR(1), SMATI(1), INDXS(3,1), XIREAL(1), XIIMAG(1),
     1   IINDEX(4,1), INDXDW(4,1), IDWFI(3,1), IDWFO(4,1), RIROAB(1),
     2   ATERM(1)                                                       29050   
      LOGICAL PINFSW
C
c
C
C
C     PRINT HEADINGS IF NECESSARY.
C
      IF ( .NOT. PINFSW ) GO TO 100
      NLINE = NLINE + NI + 1
      IF ( NLINE .LE. 58 ) GO TO 90                                     29060   
      IF ( NLINE .LT. 1000 ) write (6, 23) REACT, ELAB, HEADER
 23   FORMAT ( '1', T60, 'P T O L E M Y' /
     1   10X, 'COMPUTATION OF TRANSFER S-MATRIX ELEMENTS',
     2   T95, 'WHEELS WITHIN WHEELS' /
     3   '0', 45A1, 'ELAB =', F7.2, ' MEV', 5X, 65A1 / 1X )
C
C     THE FORMAT DEPENDS ON THE PRESENCE OF S.O. AND TENSOR POTENTIALS.
C
      IF ( .NOT. SOSWT ) write (6, 33)
 33   FORMAT ( '   L   L  LX',                                          29070   
     1   20X, 'S-MATRIX', 17X, 'CANCELLATION' /
     2   '   IN OUT',
     3   11X, 'REAL', 8X, 'IMAG', 7X, 'MAGNITUDE', 9X, 'RI, RO' )
      IF ( SOSWT .AND. .NOT. ( TCSWS(1) .OR. TCSWS(2) ) ) write (6, 43)
 43   FORMAT ( '   L    JP    L    JP   LX''',
     1   13X, 'S-MATRIX (BEFORE 9-J)', 10X, 'CANCELLATION' /
     2   '   IN   IN   OUT   OUT',
     3   11X, 'REAL', 8X, 'IMAG', 7X, 'MAGNITUDE', 9X, 'RI, RO' )
      IF ( TCSWS(1) .OR. TCSWS(2) ) write (6, 53)
 53   FORMAT ( '   L''  L    JP    L''  L    JP   LX''',                29080   
     1   13X, 'S-MATRIX (BEFORE 9-J)', 10X, 'CANCELLATION' /
     2   '   IN  IN   IN   OUT OUT   OUT',
     3   11X, 'REAL', 8X, 'IMAG', 7X, 'MAGNITUDE', 9X, 'RI, RO' )
      NLINE = 7 + NI
C
 90   write (6, 93)
 93   FORMAT ( 1X )
C
C     LOOP THROUGH THE RADIAL INTEGRALS.
C     RETRIEVE THE QUANTUM NUMBERS FROM THE INDEX ARRAYS.               29090   
C
 100  JPMX = JA + JB
      DO 299 II = 1, NI
         LXP = IINDEX(4,II)
         KDW = IINDEX(3,II)
         KWI = INDXDW(1,KDW)
         KWO = INDXDW(2,KDW)
         LASI = IDWFI(1,KWI) + LI
         JPI = IDWFI(2,KWI) + 2*LI
         LO = IDWFO(1,KWO) + LI                                         29100   
         LASO = IDWFO(2,KWO) + LI
         JPO = IDWFO(3,KWO) + 2*LI
C
C     GET PART OF THE INDEX TO THE S-MATRIX ARRAYS.
C     NOTE THAT FOR TENSOR POTS IN INCOMING CHANNEL,
C     LSTEP=1 IS GUARANTEED
C
         KSBASE = ILI-1
         IF ( TCSWS(1) )  KSBASE = LASI-LMIN
         KSBASE = NSPLI*KSBASE                                          29110   
C
C        MULTIPLY IN THE SPECTROSCOPIC STUFF ( ATERM), KINEMATIC
C        FACTOR, AND I**(LI+LO+1)*(-1)**LX'.
C
         TEMP = FACTOR*ATERM(LXP+1)/DSQRT(2*LASI+1.D0)
         ITEST = LASI + LASO + 2*LXP + 1
         IF ( MOD(ITEST, 4) .GE. 2 ) TEMP = -TEMP
         TEMPR = TEMP*XIREAL(II)
         TEMPI = TEMP*XIIMAG(II)
         SR = TEMPR                                                     29120   
         SI = TEMPI
         IF ( MOD(ITEST, 2) .EQ. 0 ) GO TO 150
         SR = -TEMPI
         SI = TEMPR
 150     IF ( .NOT. PINFSW ) GO TO 160
         AMPLI = DSQRT ( SR*SR + SI*SI )
         IF ( AMPLI .EQ. 0 ) AMPLI = 1.D-30
         TEMP = DABS(TEMP)*RIROAB(II)/AMPLI
C
C        IF THERE ARE NO SPIN-ORBIT OR TENSOR FORCES, STORE AND PRINT   29130   
C        (IF REQUIRED) AS IT STANDS.
C
 160     IF ( SOSWT ) GO TO 200
         K = ( JBP-JPBASE + NJP*(JBT-JTBASE) )/2
         K = 1 + LXP + NLX*K
         KOFFS = INDXS(1,K)
         LDELMN = INDXS(2,K)
         KS = KSBASE + KOFFS + ( LASO-LASI-LDELMN )/2
         SMATR(KS) = SMATR(KS) + SR
         SMATI(KS) = SMATI(KS) + SI                                     29140   
         IF ( PINFSW ) write (6, 173) LI, LO, LXP, SR, SI, AMPLI, TEMP
 173     FORMAT ( 1X, 2I4, I3, 1P G16.4, G12.4, G14.4, 0P F12.2 )
         GO TO 299
C
C     IF SPIN-ORBIT OR TENSOR POTENTIALS EXIST, WE MUST MULTIPLY
C     BY TWO 9-J SYMBOLS, SOME STATISTICAL FACTORS, AND THE
C     PHASE (-1)**(LX+LX'), AND ADD THE RESULT TO THE S-MATRIX
C     ELEMENTS FOR SEVERAL VALUES OF JP, LX.
C
C     FIRST, PRINT IF NECESSARY.                                        29150   
C
 200     IF ( .NOT. PINFSW ) GO TO 220
         IF ( TCSWS(1) .OR. TCSWS(2) ) GO TO 210
         write (6, 203) LI, JPI, LO, JPO, LXP, SR, SI, AMPLI, TEMP
 203     FORMAT ( 2( 1X, 2I4, '/2' ), I4,
     1      1P G16.4, G12.4, G14.4, 0P F12.2 )
         GO TO 220
 210     write (6, 213) LI, LASI, JPI, LO, LASO, JPO, LXP, SR, SI,
     1      AMPLI, TEMP
 213     FORMAT ( 2( 1X, 3I4, '/2' ), I4,                               29160   
     1      1P G16.4, G12.4, G14.4, 0P F12.2 )
C        QUIT IF THE AMPLITUDE IS ZERO.
 220     IF ( AMPLI .EQ. 1.D-30 ) GO TO 299
C
C        IF ONE CHANNEL HAS NO SPIN-ORBIT, WE MUST LOOP THROUGH
C        THOSE JP'S.
C
         JPIMN = JPI
         JPIMX = JPI
         IF ( .NOT. SOSWS(1) ) JPIMN = IABS( 2*LI - JSPS(1) )           29170   
         JPOMN = JPO
         JPOMX = JPO
         IF ( .NOT. SOSWS(2) ) JPOMN = IABS( 2*LO - JSPS(2) )
         DO 279 JPI = JPIMN, JPIMX, 2
         DO 269 JPO = JPOMN, JPOMX, 2
C
C           MULTIPLY S BY THE FIRST 9-J SYMBOL.
C
            SAV9J = (JPI+1) * (JPO+1) * (2*LXP+1) * (JBP+1)
            SAV9J = DSQRT(SAV9J) * WIG9J ( JBT, 2*LXP, JBP, JPI, 2*LI,  29180   
     1         JA, JPO, 2*LO, JB )
            IF ( SAV9J .EQ. 0 ) GO TO 269
            TEMPR = SAV9J*SR
            TEMPI = SAV9J*SI
C
C           LOOP THROUGH THE ALLOWED JP AND LX VALUES.
C
            DO 259 JP = JPBASE, JPMX, 2
               LXMN = MAX0( IABS(JBT-JP)/2, IABS(LASO-LASI) )
               LXMX = MIN0( (JBT+JP)/2, LASO+LASI )                     29190   
               IF ( LXMN .GT. LXMX )  GO TO 259
               DO 249 LX = LXMN, LXMX
                  K = ( JP-JPBASE + NJP*(JBT-JTBASE) )/2
                  K = 1 + LX + NLX*K
                  KOFFS = INDXS(1,K)
                  LDELMN = INDXS(2,K)
C
C              MULT. BY THE OTHER 9-J AND A PHASE, AND ADD IT INTO
C              THE APPROPRIATE S-MATRIX ELEMENT.
C                                                                       29200   
                  TEMP = SAV9J
                  IF ( LX .EQ. LXP  .AND.  JP .EQ. JBP  .AND.
     1               LASI .EQ. LI  .AND.  LASO .EQ. LO )  GO TO 240
                  TEMP = (JPI+1) * (JPO+1) * (2*LX+1) * (JP+1)
                  TEMP = DSQRT(TEMP) * WIG9J ( JBT, 2*LX, JP,
     1               JPI, 2*LASI, JA, JPO, 2*LASO, JB )
                  IF ( TEMP .EQ. 0 ) GO TO 249
 240              IF ( MOD(LX+LXP, 2) .NE. 0 ) TEMP = -TEMP
                  KS = KSBASE + KOFFS + ( LASO-LASI-LDELMN )/2
                  SMATR(KS) = SMATR(KS) + TEMP*TEMPR                    29210   
                  SMATI(KS) = SMATI(KS) + TEMP*TEMPI
 249           CONTINUE
 259        CONTINUE
 269     CONTINUE
 279     CONTINUE
 299  CONTINUE
      RETURN
      END
C*ID* SWKB     C109.PTOLEMY.SOURCE                          PER701  15:
      SUBROUTINE SWKB ( E, FK, L, EPS, IPRINT, ETA, RC,                 29220   
     1  NSTEPS, ROSTRT, H, VCONS, VARRAY, VCOEFS, WARRAY, WCOEFS,
     2  NGAUSS, PTS, WTS,
     3  DELTR, DELTIM, THETA, THETC, RHOT, ROTC, DUEFF )
C
C     EVALUATES WKB PHASE-SHIFT FOR PARTIAL WAVE L
C     AND THE CORRESPONDING CLASSICAL DEFLECTION FUNCTION
C
C     INPUT ARGUMENTS:
C
C     E   - COM KINETIC ENERGY                                          29230   
C     FK  - COM WAVE NUMBER
C     L   - PARTIAL WAVE QUANTUM NUMBER
C     EPS - ACCURACY CRITERION FOR LOCATING RTURN.
C           1D-14 IS REASONABLE
C     IPRINT = 0 MEANS NO PRINTING; =1 CAUSES DEBUGGING PRINTOUT
C     ETA - COULOMB STRENGTH PARAMETER
C     RC  - COULOMB RADIUS (NOT RC0)
C       ETA MAY BE ZERO BUT RC MUST ALWAYS BE > 0 (EVEN WHEN ETA=0).
C     NSTEPS, ROSTRT, H - DEFINE THE GRID OF K*R ON WHICH THE REAL
C           AND IMAGINARY POTENTIALS ARE DEFINED.                       29240   
C              RHOLAST = ASYMPTOPIA = (NSTEPS-1)*H + ROSTRT
C     VCONS - = 1 IF VARRAY CONTAINS THE H**2/12 TERM, = 0 IF NOT.
C             NORMALLY VCONS IS 1 BUT FOR C.C. CALCS IT IS 0.
C     VARRAY, WARRAY - ARRAYS OF THE POTENTIAL (INCLUDING COULOMB)
C           IN THE FORM MADE BY MAKPOT:
C              1 - (H/12)**2 (V/E-VCONS)
C     VCOEFS, WCOEFS - (NSTEPS,3) DIMENSIONAL ARRAYS CONTAINING
C           THE CUBIC SPLINE COEFFICENTS FOR VARRAY, WARRAY.
C           THE CUBIC SPLINES ARE IN TERMS OF RHO = K*R.
C     NGAUSS, PTS, WTS - A SET OF GAUSS POINTS ON (-1,1).               29250   
C
C     OUTPUT ARGUMENTS:
C
C     DELTR, DELTIM - REAL AND IMAGINARY PART OF THE WKB PHASE SHIFT.
C     THETA, THETC - NUCLEAR AND COULOMB DEFLECTION ANGLES.
C     RHOT, ROTC - NUCLEAR AND COULOMB TURNING POINTS (TIMES K).
C     DUEFF - DERIVATIVE OF EFFECTIVE POTENTIAL AT THE NUCLEAR TURNING
C             POINT.
C
C     MHM SEPT 12 1975                                                  29260   
C     2/25/76 - AVOID OVERFLOW/UNDERFLOW FOR EXTREME PARAMETER VALUES
C     3/19/77 - ALLOW ETA = 0 - S. P.
C     11/30/77 - GENERAL POTENTIALS - S.P.
C     12/10/77 - FIX ERRORS WHEN RHOTURN = 0 - S.P.
C                USE QUANTUM MECHANICAL L(L+1) TO AVOID TROUBLES
C     2/14/78 - DON'T LET RHOTURN BE 0 FOR L > 0.
C               ALLOW RHO(TURN) > RHO(MAX)  ( S = 1 )
C     10/24/79 - STANDARDIZE, PREVENT SQRT(NEGATIVE) FROM ROUNDOFF - RPG
C     5/8/80 - VCONS ADDED FOR C.C. - S.P.
C     6/16/80 - FIX XVAL UNDEF IF RHOT=0, UER .LE. 0 - S.P.             29270   
C
C
      implicit real*8 ( a-h, o-z )                                      implicit
C
CDC      ALLOCLEVEL PTS, WTS
CDC      ALLOCLEVEL VARRAY, VCOEFS, WARRAY, WCOEFS
      DIMENSION PTS(NGAUSS), WTS(NGAUSS)
      DIMENSION VARRAY(NSTEPS), VCOEFS(NSTEPS,3), WARRAY(NSTEPS),
     1  WCOEFS(NSTEPS,3)
C                                                                       29280   
C     INTRODUCE DIMENSIONLESS VARIABLES
C
      PI=3.14159 26535 89793 0D0
      RT2=1.41421 35623 73095 0D0
      TP=1/RT2
      NMAX=50
      RHOC=FK*RC
      UC0=(2*ETA)/RHOC
C
C     NOTE QUANTUM-MECHANICAL VALUE.  THIS AVOIDS SOME TROUBLES         29290   
C
      FLL = L*(L+1.D0)
      ECC = DSQRT( ETA**2 + FLL )
      DELTR=5.D0
      DELTIM=5.D0
C
C     OUTER LIMIT OF THE WKB INTEGRALS WILL BE ASYMPTOPIA
C
      ROMAX = ROSTRT + H*(NSTEPS-1)
C                                                                       29300   
C     CALCULATE CTP IN PURE COULOMB POTENTIAL
C
      ROTC = ETA + ECC
      IF ( ROTC.GE.RHOC  .OR.  ETA .EQ. 0 ) GO TO 24
      F1=(3*ETA-RHOC)/(2*ETA)
      ROTC=DSQRT(F1**2+FLL/(ETA*RHOC))+F1
      IF ( ROTC .LT. 0 )  ROTC = 0
      ROTC=DSQRT(ROTC)*RHOC
CCCCC
CCCCC     CHECK THAT ROMAX AND COULOMB TP ARE REASONABLE                29310   
CCCCC
CCCC   24 IF(ROMAX.GT.ROTC) GO TO 27
CCCC      write (6, 26) L, ETA, RC, ROTC, ROMAX
CCCC 26   FORMAT ( '0**** SWKB VALUE FOR RHOTURN(COULOMB) IS UNREASONABL
CCCC     1  I5, 4G15.5 )
CCCC      GO TO 50
C
C     CALCULATE CTP IN FULL(NUCLEAR +COULOMB) POTENTIAL
C
C     FIND INTERVAL (RHO,RHO-H) CONTAINING CTP                          29320   
C
   24 ULAS=0
      RHO=ROMAX
      N = NSTEPS
      NITS = 0
 2    UEFF = ((12/H**2)+VCONS) - (12/H**2)*VARRAY(N) + FLL/RHO**2
      IF(UEFF.GT.1) GO TO 4
      ULAS=UEFF
      RHO=RHO-H
      N = N-1                                                           29330   
      IF(RHO.GT.0) GO TO 2
      RHOT=0
      RHO = 0
      IF ( L .EQ. 0 )  GO TO 11
      write (6, 1010)L
 1010 FORMAT(1H0,2X,'--- RHOT < H FOR L = ',I3,' ---')
      RHOT = H
      GO TO 11
 4    RHOT = RHO
      IF ( RHO .GE. ROMAX )  GO TO 160                                  29340   
      IF(DABS(UEFF-1.D0).GT.EPS) GO TO 5
      GO TO 11
C
C     USE REGULA FALSI TO LOCATE CTP WITHIN (RHO,RHO-H)
C
  5   RO1=RHO
      RO2=RHO+H
      U1=UEFF
      U2=ULAS
    6 RO3=(RO2*(U1-1)+RO1*(1-U2))/(U1-U2)                               29350   
      RO=RO3
      ASSIGN 7 TO IK
      GO TO 710
    7 IF(DABS(UEFF-1.D0).GT.EPS) GO TO 8
      RHOT=RO3
      GO TO 11
    8 IF(UEFF.LT.1) GO TO 9
      RO1=RO3
      U1=UEFF
      GO TO 10                                                          29360   
    9 RO2=RO3
      U2=UEFF
   10 NITS=NITS+1
      IF(NITS.LE.NMAX) GO TO 6
      ACC=DABS(UEFF-1.D0)
      write (6, 110)L,NMAX,EPS,ACC
  110 FORMAT ( '0**** SWKB: FOR L = ',I3,' AFTER ',I4,' ITERATIONS'/
     1  3X, 'REQUESTED ACCURACY OF ',D12.4,' CANNOT BE ACHIEVED ',
     2  3X, 'ACCURACY ACHIEVED = ',D12.4)
      RHOT=RO3                                                          29370   
C
C     EVALUATE D(UEFF)/D(RHO) AT CTP
C
 11   X = (RHOT-RHO)
      DUN = -(12/H**2) * (VCOEFS(N,1) + X*(2*VCOEFS(N,2) +
     1     3*X*VCOEFS(N,3) ))
      DUL = 0
      IF ( L .NE. 0 )  DUL=-(2*FLL)/(RHOT**3)
      DUEFF=DUN+DUL
      RT=RHOT/FK                                                        29380   
      IF(IPRINT.GT.1) write (6, 120) L, NITS, RHOT, RT, DUEFF, DUN, DUL
  120 FORMAT ( 1H0,2X,'--- CTP FOR L = ',I3,' FOUND IN ',I4,
     1' ITERATIONS', 3X,'RHOT = ',G13.5,' RT = ',G13.5/
     2  ' DUEFF =', G14.5,
     3  '    DUN+DUC = ',G13.5,' DUL = ',G13.5 )
      IF ( DUEFF.LT.0  .OR.  RHOT .EQ. 0 )  GO TO 160
      write (6, 155)DUEFF
  155 FORMAT( '0****** DUEFF=',G15.5,' ERROR IN SWKB ***')
C
C     INTEGRATE FROM RHOT TO ROMAX TO EVALUATE WKB PHASE-SHIFT          29390   
C     AND CLASSICAL DEFLECTION FUNCTION
C
 160  IF ( ETA .NE. 0 )  GO TO 165
      PHC = 0
      TEMP = DSQRT(FLL)/ROMAX
      GO TO 170
 165  TEMP = ETA/ECC
      PHC = acos(TEMP)
      TEMP = ( ETA + FLL/ROMAX ) / ECC
 170  IF ( TEMP .GT. 1 )  TEMP = 1                                      29400   
      PHI = acos(TEMP)
C
      IF(ROMAX.GT.RHOT) GO TO 220
      DELTR=0
      DELTIM=0
      TURN=PHC
      GO TO 230
  220 AP=(ROMAX-RHOT)/2
      BP=(ROMAX+RHOT)/2
      AD = ROMAX/2                                                      29410   
      BD = 0
      IF ( RHOT .EQ. 0 )  GO TO 225
      AD=1/RHOT-1/ROMAX
      AD=.5*DSQRT(AD)
      BD = 1/RHOT
 225  TEMR=0
      TEMI=0
      TEMP=0
C
      DO 499  I = 1, NGAUSS                                             29420   
C
      WTP=AP*WTS(I)
      WTD=AD*WTS(I)
      RO=AP*PTS(I)+BP
      XVAL = AD*(1+PTS(I))
      ASSIGN 185 TO IK
      GO TO 700
  185 UEFFC=FLL/RO**2
      Y=RO/RHOC
      IF(RO.LT.RHOC) UEFFC=UEFFC+UC0*(1.5-.5*(Y**2))                    29430   
      IF(RO.GE.RHOC) UEFFC=UEFFC+UC0/Y
      W = -(12/H**2) * ( WARRAY(N) +
     1  X*(WCOEFS(N,1) + X*(WCOEFS(N,2) + X*WCOEFS(N,3) )))
      UE1=1-UEFF
      IF(UE1.LT.0) UE1=0
      UE2=DSQRT(UE1**2+W**2)
      IF((UE2-UE1).LT.0) UE2=UE1
      FINTI=TP*DSQRT(UE2-UE1)
      FINTR=TP*DSQRT(UE2+UE1)
      IF(RO.LE.ROTC) GO TO 195                                          29440   
      UEC=1-UEFFC
      IF(UEC.LT.0) UEC=0
      FINTR=FINTR-DSQRT(UEC)
 195  IF ( RHOT .EQ. 0 )  GO TO 190
      RO= BD-XVAL*XVAL
      RO=1/RO
      GO TO 197
 190  RO = .5*AD*(1+PTS(I))**2
 197  ASSIGN 200 TO IK
      GO TO 700                                                         29450   
  200 UER=1-UEFF
      IF (UER .LE. 0) GO TO 900
      FINTD=XVAL/DSQRT(UER)
  207 TEMI=TEMI+WTP*FINTI
      TEMR=TEMR+WTP*FINTR
      TEMP=TEMP+WTD*FINTD
C
 499  CONTINUE
C
      DELTR=TEMR                                                        29460   
      DELTIM=TEMI
      TURN=2*(L+.5)*TEMP+PHC-PHI
  230 THETA=PI-2*TURN
      THETC=PI-2*PHC
C
   50 RETURN
C
C     CALCULATE (DIMENSIONLESS) EFFECTIVE POTENTIAL
C
C                                                                       29470   
C     GET U EFFECTIVE
C
 700  N = (RO-ROSTRT)/H + 1
 710  X = (RO-ROSTRT-(N-1)*H)
      UEFF = ((12/H**2)+VCONS) - (12/H**2) * ( VARRAY(N)
     1  + X*(VCOEFS(N,1) + X*(VCOEFS(N,2) + X*VCOEFS(N,3) )))
     2  + FLL/RO**2
      GO TO IK, ( 7, 185, 200 )
C
C                                                                       29480   
 900  write (6, 903) L, I, RHOT, RT, XVAL, RO, UEFF, UER
 903  FORMAT ( '0**** SWKB ERROR AT STMNT 205:', 2I5 /
     1  6X, 6G15.5 )
      RETURN
      END
C*ID* TCOEF    C109.PTOLEMY.SOURCE                          PER701  15:
      FUNCTION TCOEF ( ITYP, LAS, L, JP, JSP )
C
C     COMPUTES COEFFICIENTS FOR THE TENSOR POTENTIALS.
C                                                                       29490   
C
C     ITYP = 1 FOR TR, 2 FOR TL, 3 FOR TPR.
C     LAS = ASYMPTOTIC ORBITAL ANGULAR MOMENTUM.
C     L = LOCAL ORBITAL ANGULAR MOMENTUM.
C     JP = 2 * PROJECTILE TOTAL ANGULAR MOMENTUM.
C     JSP = 2 * SPIN OF PROJECTILE.
C
C
C     THIS VERSION WORKS FOR SPIN-1 (JSP=2) PROJECTILES ONLY.
C     FOR OTHER VALUES OF JSP, A DIAGNOSTIC IS PRINTED FOR THE          29500   
C     LAS=L=0 PARTIAL WAVE ONLY, AND ZERO IS RETURNED.
C
C     NOTE:  TPR IS THE DIFFERENCE TP - P**2*TR, IN THE
C     LOCAL MOMENTUM APPROXIMATION.  SEE R. P. GODDARD,
C     PH.D. THESIS, UNIVERSITY OF WISCONSIN - MADISON (1978),
C     SECT. 4.4.
C
      implicit real*8 ( a-h, o-z )                                      implicit
C
      character*4 TNAME(3) / 'TR', 'TL', 'TPR' /                        29510   
C
c
C
C     CHECK FOR ILLEGAL SPIN.
C
      IF ( JSP .EQ. 2 ) GO TO 80
      IF ( L + LAS .EQ. 0 ) write (6, 23) TNAME(ITYP), JSP
 23   FORMAT ( '0***** TCOEF - ', A3, ' POTENTIAL IS LEGAL FOR SPIN 1',
     1  ' ONLY, SPIN =', I2, '/2.' )
 50   TCOEF = 0.                                                        29520   
      RETURN
C
C     BRANCH ACCORDING TO TYPE AND ANGULAR MOMENTA.
C
 80   AL = L
      I = L - JP/2 + 1
      IF ( L .NE. LAS ) I = 3
      I = 3*I + ITYP
      GO TO (110, 120, 50, 210, 220, 50, 310, 320, 50, 410, 50, 430), I
C                                                                       29530   
C     J = L+1 = LAS+1
C
C     TR
 110  TCOEF = -AL / (6.*AL + 9.)
      RETURN
C     TL
 120  TCOEF = AL*(2.*AL-1.)/6.
      RETURN
C
C     J = L = LAS                                                       29540   
C
C     TR
 210  TCOEF = 1.D0 / 3.D0
      RETURN
C     TL
 220  TCOEF = -(2.*AL-1.)*(2.*AL+3.)/6.
      RETURN
C
C     J = L-1 = LAS-1
C                                                                       29550   
C     TR
 310  TCOEF = -(AL+1.) / (6.*AL-3.)
      RETURN
C     TL
 320  TCOEF = (AL+1.)*(2.*AL+3.)/6.
      RETURN
C
C     OFF-DIAGONAL POTENTIAL
C
C     TR                                                                29560   
 410  AL = JP/2
      TCOEF = DSQRT (AL*(AL+1.))/(2.*AL+1.)
      RETURN
C     TPR ( = TP - TR*P**2 IN LOCAL MOMENTUM APPROXIMATION)
 430  AL = JP/2
      TCOEF = -(2.*AL+1.)*DSQRT (AL*(AL+1.))
      RETURN
      END
C*ID* TEMP     C109.PTOLEMY.SOURCE                          PER701  17:
ccc      SUBROUTINE TEMP1                                               29570   
C
C     THESE ARE 3 DUMMIES THAT ARE CALLED BY THE KEYWORD
C        CALL TEMP1, CALL TEMP2, CALL TEMP3
C
C     2/10/75 - S.P.
C
ccc      RETURN
ccc      END
      SUBROUTINE TEMP2
      RETURN                                                            29580   
      END
      SUBROUTINE TEMP3
      RETURN
      END
C*ID* TEMP1    C109.PTOLEMY.SOURCE                          PER701  10:
      SUBROUTINE TEMP1
C
C     TABULATE THE TOTAL REACTION CROSS SECTION CONTRIBUTIONS.
C     8/12/83 - FIRST VERSION - S.P.
C                                                                       29590   
      implicit real*8 ( a-h, o-z )                                      implicit
C
C
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      CHARACTER*1  REACT, HEADER                                        /hedcom/
      COMMON /HEDCOM/  REACT(45), HEADER(65)
 
      COMMON /KANDM/ AKI, AKO, REDMI, REDMO, RIMAX, ROMAX, ISIGS(2),    /kandm/
     &  RSCTS(2), ASCTS(2), RCSCTS(2) ,ISMATS(2), LOMOST, LCRIT,
     &  ISCTMN, ISCTCR, ETAS(2), RCSCTP(2), RCSCTT(2), LCRITS(2),
     &  RATMSS(2), QMIN, ABAR
 
      DIMENSION  AKS(2), REDMS(2), RMAXS(2)
      EQUIVALENCE ( AKI, AKS(1) ), ( REDMI, REDMS(1) ),
     &  ( RIMAX, RMAXS(1) )
 
      LOGICAL ONELSW, IDENSW                                            /inelcm/
      COMMON /INELCM/  JBPF, JBTF, LXMIN, LXMAX, ILILOR, ILILOI, MSTOP,
     &  IA12M, NMLOLX, ONELSW, NUMLX, IRDINT, IELCUP, LILOSZ, NUMLIS,
     &  ILIS, IBETAS(3), ICL2FF, LXSTEP, IDENSW, LSKIP,
     &  JPMIN, JPMAX, JPBASE, NJP, JTMIN, JTMAX, JTBASE, NJT,
     &  IINDXS, ISMATR, ISMATI, NSMAT, NLX, NSPLI, ITOCS,
     &  NASPLI, IUNITR, LIFIT, ILIFIT, NOLFIT, IDELSR, IDELSI
      INTEGER INDXJS(4,2)
      EQUIVALENCE ( INDXJS(1,1), JPMIN )
 
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
      COMMON /CCBLK/  ICHNDF, ICHNCP, ITRANS, IBASDF, IBASCP,           /ccblk/
     &    ICCBLK(2), IORDX, MCHNVL, ICHNVL,
     &    IHOMOA, IHOMOB, IINHR8, IINHI8
 
C
C
      DIMENSION  R1RAY(2,25), EXRAY(2,25), RESRAY(2,25), R2RAY(2,25),
     1  OUT(2)
      LOGICAL  CCSW
c
C                                                                       29610   
      CCSW = PROBLM .EQ. 24
C
      LSIN = Z(ISMATS(1))
      LSOUT = Z(ISMATS(2))
      IUNITR = NAMLOC( 'UNITARIT' )
      LUNITR = FACFR4*(Z(IUNITR)-1) + 1 - LMIN
C
C
C     FIRST WE PRINT THE ELASTIC S-MATRIX ELEMENTS AND UNITARITY
C                                                                       29620   
      LINECT = 100
      LINES = 1
C
      N1 = 0
      LISAVE = 100000
      IF ( (LIMOST-LMIN )/LSKIP  .LT. 10 )  GO TO 100
      LISAVE = LIMOST - 24*LSKIP
      LISAVE = MAX0( LISAVE, LMIN )
 100  SUMR1 = 0
      SUMEX = 0                                                         29630   
      FAC1 = LSKIP * 10*PI/AKI**2
      IF ( LMIN .EQ. 0 )  GO TO 200
      SUMR1 = LMIN**2
      IF ( LSKIP .EQ. 2 )  SUMR1 = LMIN*(LMIN-1)/2
      SUMR1 = FAC1*SUMR1
 200  SUMR2 = SUMR1
      SUMRES = SUMR1
C
C     LOOP THROUGH THE INCOMING L VALUES.
C                                                                       29640   
      DO 699  LI = LMIN, LIMOST, LSKIP
         FAC = FAC1*(2*LI+1)
C
C     PRINT THE HEADINGS IF NECESSARY.
C
         IF ( LINECT+LINES .LE. 58 )  GO TO 550
         write (6, 533) REACT, ELAB, HEADER
 533     FORMAT ( '1', T58, 'P T O L E M Y' /
     1     T41, 'CONTRIBUTIONS TO TOTAL REACTION CROSS SECTIONS' /
     2     '0', 45A1, 'ELAB =', F7.2, ' MEV', 5X, 65A1 / )              29650   
         write (6, 548)
 548     FORMAT ( 5X, 'L', 4X, 'C.C. REACTION CROSS SEC.',
     1      6X, 'EXCITATION CROSS SEC.',
     2      7X, 'RESIDUAL CROSS SEC.',
     3      7X, 'OPTICAL REACTION CROSS SEC.' /
     4    6X, 4( 7X, 'TERM', 10X, 'SUM', 4X ) / )
         LINECT = 9
C
 550     R1 = FAC*( 1 - ALLOC(LSIN+2*LI)**2 - ALLOC(LSIN+2*LI+1)**2 )
         SUMR1 = SUMR1 + R1                                             29660   
         EX = FAC*ALLOC4(LUNITR+LI)
         SUMEX = SUMEX + EX
         RES = R1 - EX
         SUMRES = SUMRES + RES
         R2 = FAC*( 1 - ALLOC(LSOUT+2*LI)**2 - ALLOC(LSOUT+2*LI+1)**2 )
         SUMR2 = SUMR2 + R2
         IF ( LI .LT. LISAVE )  GO TO 560
         N1 = N1+1
         R1RAY(1,N1) = SUMR1
         R1RAY(2,N1) = 0                                                29670   
         EXRAY(1,N1) = SUMEX
         EXRAY(2,N1) = 0
         RESRAY(1,N1) = SUMRES
         RESRAY(2,N1) = 0
         R2RAY(1,N1) = SUMR2
         R2RAY(2,N1) = 0
 560     IF ( LI .GT. LMAX  .AND.  LI .NE. LIMOST  .AND.
     1     MOD(LI, 10) .NE. 0 )  GO TO 699
         write (6, 577) LI, R1, SUMR1, EX, SUMEX, RES, SUMRES, R2, SUMR2
 577     FORMAT ( 1X, I5, 4( F14.5, G14.5 ) )                           29680   
         LINECT = LINECT + 1
         IADD = 0
         IF ( LI .EQ. LMAX  .OR.
     1      ( LI .LT. LMAX  .AND.  MOD(LI+LSKIP, 10) .EQ. 0 )  .OR.
     2      MOD(LI+10, 100) .EQ. 0 )  IADD = 1
         LINECT = LINECT+IADD
         IF ( IADD .EQ. 1 )  write (6, 583)
 583     FORMAT ( ' ' )
C
 699  CONTINUE                                                          29690   
C
C     NOW USE EPSILON IF POSSIBLE
C
      IF ( N1 .EQ. 0 )  RETURN
      R1ER = 1
      EXER = 1
      RESER = 1
      R2ER = 1
      OUT(1) = 0
      CALL EPSLON ( R1RAY, N1, OUT, 1.D-5, R1ER, I )                    29700   
      R1 = OUT(1)
      R1ER = R1*R1ER
      CALL EPSLON ( EXRAY, N1, OUT, 1.D-5, EXER, I )
      EX = OUT(1)
      EXER = EX*EXER
      CALL EPSLON ( RESRAY, N1, OUT, 1.D-5, RESER, I )
      RES = OUT(1)
      RESER = RES*RESER
      CALL EPSLON ( R2RAY, N1, OUT, 1.D-5, R2ER, I )
      R2 = OUT(1)                                                       29710   
      R2ER = R2*R2ER
      write (6, 683) R1, EX, RES, R2, R1ER, EXER, RESER, R2ER
 683  FORMAT ( '0EPSILON:', T21, 4( G14.5, 14X ) /
     1    T22, 4( '+-', G10.2, 16X ) )
C
      RETURN
      END
C*ID* TMATCH   C109.PTOLEMY.SOURCE                          PER701  15:
      SUBROUTINE TMATCH ( WAVR, WAVI, CR, CI, SMATS, JP, NWP, NWAVF )
C                                                                       29720   
C     CALCULATES S-MATRIX AND RENORMALIZATION FOR TENSOR-COUPLED WF.
C
C
C     THE ARGUMENTS ARE:
C
C     WAVR, WAVI - INPUT UN-NORMALIZED WAVE FUNCTIONS,
C        DIMENSION (NWAVEF,2,2) (SEE COMMENTS IN WAVETC).
C     CR, CI - COMPUTED RENORMALIZATIONS, DIMENSION (2,2),
C        INDEXED BY IS = 1 OR 2 FOR THE 2 INDEPENDENT SOLUTIONS,
C        AND BY ILAS = 1 OR 2 FOR LAS = J-1 OR J+1.                     29730   
C     SMATS - COMPUTED S-MATRIX ELEMENTS (STORED BY JPTOLX).
C     JP - 2*J OF PROJECTILE.
C     NWP - CHANNEL NUMBER (1 OR 2).
C
C     THE 4-BY-4 SYSTEM TO SOLVE IS
C
C     ( -AC(J-1,R1)    0       U(J-1,1,R1) U(J-1,2,R1) )
C     ( -AC(J-1,R2)    0       U(J-1,1,R2) U(J-1,2,R2) ) *
C     (     0      -AC(J+1,R1) U(J+1,1,R1) U(J+1,2,R1) )
C     (     0      -AC(J+1,R2) U(J+1,1,R2) U(J+1,2,R2) )                29740   
C
C        ( S(J-1,J-1) S(J-1,J+1) )   ( A(J-1,R1)    0      )
C      * ( S(J+1,J-1) S(J-1,J-1) ) = ( A(J-1,R2)    0      )
C        ( C(1,J-1)   C(1,J+1)   )   (     0     A(J+1,R1) )
C        ( C(2,J-1)   C(2,J+1)   )   (     0     A(J+1,R2) )
C
C     WHERE A(LAS,R) = (F + I*G)/2 (F, G = COULOMB WAVE FUNCTIONS),
C     AC(L,R) = (F - I*G)/2, U(L,I,R) IS THE UN-NORMALIZED WAVE
C     FUNCTION, S(L,LAS) IS THE NUCLEAR S MATRIX, AND C(I,LAS)
C     IS THE NORMALIZATION, FOR ORBITAL ANGULAR MOMENTUM L,             29750   
C     ASYMPTOTIC ORBITAL ANGULAR MOMENTUM LAS, RADII R = R1 AND R2,
C     AND SOLUTION I.
C
C          THE S-MATRIX ELEMENTS ARE PRINTED IF REQUESTED
C     (1000 DIGIT OF IPRINT).
C
C
C     2/7/79 - SPLIT OFF FROM WAVETC - RPG
C     3/1/79 - CHANGE TO GAUSSIAN ELIMINATION METHOD - RPG
C     8/3/79 - STANDARD PREFIXES, CALL JPTOLX TO TRANSLATE S - RPG      29760   
C     6/3/80 - GET NWAVF DIMENSION FOR CDC COMPATABILITY - S.P.
C
C
      implicit real*8 ( a-h, o-z )                                      implicit
CDC      ALLOCLEVEL WAVR, WAVI, SMATS
C
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
      COMMON /KANDM/ AKI, AKO, REDMI, REDMO, RIMAX, ROMAX, ISIGS(2),    /kandm/
     &  RSCTS(2), ASCTS(2), RCSCTS(2) ,ISMATS(2), LOMOST, LCRIT,
     &  ISCTMN, ISCTCR, ETAS(2), RCSCTP(2), RCSCTT(2), LCRITS(2),
     &  RATMSS(2), QMIN, ABAR
 
      DIMENSION  AKS(2), REDMS(2), RMAXS(2)
      EQUIVALENCE ( AKI, AKS(1) ), ( REDMI, REDMS(1) ),
     &  ( RIMAX, RMAXS(1) )
 
C                                                                       29770   
      DIMENSION WAVR(NWAVF,2,2), WAVI(NWAVF,2,2),
     1  CR(2,2), CI(2,2), SMATS(1)
C
      DIMENSION F1(2), G1(2), F2(2), G2(2), ABI(2), U1R(2,2),
     1  U1I(2,2), U2R(2,2), U2I(2,2), BYR(2,2), BYI(2,2)
      CHARACTER*8  CHANAM(3) / 'INCOMING', 'OUTGOING' , ' ' /
C
c
C      F IS THE REGULAR COULOMB WAVE
C      G IS THE IRREGULAR COULOMB WAVE                                  29780   
C  NOTE THAT F1,G1 ARE REGULAR AND IRREGULAR COULOMB FUNTIONS AT NBACK
C
      I = JP/2 - 1 + (IOFFIT-1)*(LOMOST+1)
      LF = (Z(NFS(NWP))+I)
      LG = (Z(NGS(NWP))+I)
      LF1 = (Z(NF1S(NWP))+I)
      LG1 = (Z(NG1S(NWP))+I)
      NSTEP = NSTPSS(NWP)
C
C     REDUCE THE 4-BY-4 SYSTEM TO A 2-BY-2 SYSTEM FOR THE NORMALIZATIONS29790   
C     ONLY.  THE RIGHT-HAND SIDE (ABI) IS A DIAGONAL, PURELY IMAGINARY
C     MATRIX.
C
      DO 519 IL = 1, 2
         I = 2*IL - 2
         F1(IL) = 0.5*ALLOC(LF+I)
         G1(IL) = 0.5*ALLOC(LG+I)
         F2(IL) = 0.5*ALLOC(LF1+I)
         G2(IL) = 0.5*ALLOC(LG1+I)
         ABI(IL) = F2(IL)*G1(IL) - F1(IL)*G2(IL)                        29800   
         ABI(IL) = ABI(IL) + ABI(IL)
         DO 509 IS = 1, 2
            U1R(IL,IS) = WAVR(NSTEP+1,IL,IS)
            U1I(IL,IS) = WAVI(NSTEP+1,IL,IS)
            U2R(IL,IS) = WAVR(NSTEP+1-NBAKCM,IL,IS)
            U2I(IL,IS) = WAVI(NSTEP+1-NBAKCM,IL,IS)
            BYR(IL,IS) = F2(IL)*U1R(IL,IS) + G2(IL)*U1I(IL,IS)
     1         - F1(IL)*U2R(IL,IS) - G1(IL)*U2I(IL,IS)
            BYI(IL,IS) = F2(IL)*U1I(IL,IS) - G2(IL)*U1R(IL,IS)
     1         - F1(IL)*U2I(IL,IS) + G1(IL)*U2R(IL,IS)                  29810   
 509     CONTINUE
 519  CONTINUE
C
C     SOLVE THE 2-BY-2 SYSTEM FOR THE NORMALIZATIONS (CR,CI).
C
C     THE SYSTEM IS SOLVED BY GAUSSIAN ELIMINATION.  FOR A COMPLEX
C     2-BY-2 SYSTEM THIS IS SLIGHTLY SLOWER THAN USING DETERMINANTS,
C     BUT IT AVOIDS INTERMEDIATE RESULTS INVOLVING THE FOURTH POWER
C     OF THE WAVE FUNCTIONS.  WE ASSUME THAT THE LARGEST ELEMENTS OF
C     BY ARE ON THE DIAGONAL - TRUE IF THE TENSOR POTENTIAL IS SMALL.   29820   
C
      TEMP = BYR(1,1)**2 + BYI(1,1)**2
      PIVR = BYR(1,1)/TEMP
      PIVI = -BYI(1,1)/TEMP
      TEMP = PIVR*BYR(1,2) - PIVI*BYI(1,2)
      BYI(1,2) = PIVR*BYI(1,2) + PIVI*BYR(1,2)
      BYR(1,2) = TEMP
      CR(1,1) = -PIVI*ABI(1)
      CI(1,1) = PIVR*ABI(1)
      BYR(2,2) = BYR(2,2) - BYR(2,1)*BYR(1,2) + BYI(2,1)*BYI(1,2)       29830   
      BYI(2,2) = BYI(2,2) - BYR(2,1)*BYI(1,2) - BYI(2,1)*BYR(1,2)
      CR(2,1) = -BYR(2,1)*CR(1,1) + BYI(2,1)*CI(1,1)
      CI(2,1) = -BYR(2,1)*CI(1,1) - BYI(2,1)*CR(1,1)
      TEMP = BYR(2,2)**2 + BYI(2,2)**2
      PIVR = BYR(2,2)/TEMP
      PIVI = -BYI(2,2)/TEMP
      TEMP = PIVR*CR(2,1) - PIVI*CI(2,1)
      CI(2,1) = PIVR*CI(2,1) + PIVI*CR(2,1)
      CR(2,1) = TEMP
      CR(2,2) = -PIVI*ABI(2)                                            29840   
      CI(2,2) = PIVR*ABI(2)
      CR(1,1) = CR(1,1) - BYR(1,2)*CR(2,1) + BYI(1,2)*CI(2,1)
      CI(1,1) = CI(1,1) - BYR(1,2)*CI(2,1) - BYI(1,2)*CR(2,1)
      CR(1,2) = -BYR(1,2)*CR(2,2) + BYI(1,2)*CI(2,2)
      CI(1,2) = -BYR(1,2)*CI(2,2) - BYI(1,2)*CR(2,2)
C
C     NOW SUBSTITUTE BACK TO FIND THE S-MATRIX ELEMENTS.
C
      NNWP = NWP
      IF ( STANSW )  NNWP = 3                                           29850   
      DO 559 IL = 1, 2
         LL = ( JP/2 - 3 ) + 2*IL
         DENA = F1(IL)*F1(IL) + G1(IL)*G1(IL)
         DENR = F1(IL)/DENA
         DENI = G1(IL)/DENA
         DO 549 ILAS = 1, 2
            LLAS = ( JP/2 - 3 ) + 2*ILAS
            TR = U1R(IL,1)*CR(1,ILAS) - U1I(IL,1)*CI(1,ILAS)
     1        + U1R(IL,2)*CR(2,ILAS) - U1I(IL,2)*CI(2,ILAS)
            TI = U1R(IL,1)*CI(1,ILAS) + U1I(IL,1)*CR(1,ILAS)            29860   
     1        + U1R(IL,2)*CI(2,ILAS) + U1I(IL,2)*CR(2,ILAS)
            IF ( IL .NE. ILAS ) GO TO 530
            TR = TR - F1(IL)
            TI = TI - G1(IL)
 530        SJR = TR*DENR - TI*DENI
            SJI = TR*DENI + TI*DENR
C
C           PRINT ELASTIC S-MATRIX IF REQUESTED (1000 DIGIT OF IPRINT)
C
            IF ( .NOT. PWAVSW )  GO TO 540                              29870   
            write (6, 543) CHANAM(NNWP), LL, LLAS, JP, SJR, SJI
 543        FORMAT ( 1X,A8, ' ELASTIC S-MATRIX FOR L =', I4, ',  LAS =',
     1        I4, ',   JP =', I4, '/2:', G15.5, ' +', G13.5, ' I' )
C
C           TRANSLATE S-MATRICES TO LX SYSTEM AND STORE THEM.
C
 540        LINDXE = FACFR4*Z(IINDXE(NWP))-FACFR4+1
            CALL JPTOLX ( LL, LLAS, JP, NWP, SJR, SJI,
     1         ILLOC(LINDXE), SMATS )
 549     CONTINUE                                                       29880   
 559  CONTINUE
C
      RETURN
      END
C*ID* VCSQ12   C109.PTOLEMY.SOURCE                          PER701  15:
      SUBROUTINE VCSQ12(R,VC,K)
C     COULOMB POTENTIAL BETWEEN TWO UNIFORM CHARGE DISTRIBUTIONS
C     USES EXPLICIT EXPRESSION V(COULOMB) = 1/R*(POLYNOMIAL IN R)
C     EXPRESSION GIVEN BY POLING ET.AL. PHYS.REV.C13,648,1976
C     SUBROUTINE CHECKED BY NUMERICAL QUADRATURE TO 12 FIGURES          29890   
C     MHM - MARCH 9 1976
C
C     IF R1 OR R2 IS ZERO EXPRESSION REDUCES TO COULOMB
C     POTENTIAL OF POINT CHARGE IN A UNIFORM FIELD OF RADIUS
C     EQUAL TO WHICHEVER OF R1 AND R2 IS NONZERO
C
C     MHM - APRIL 25 1976
C
C     DIMENSIONED TO PERMIT CALCULATION OF POTENTIAL BETWEEN UP TO
C     3 DISTINCT PAIRS OF CHARGE DISTRIBUTIONS                          29900   
C     MHM - APRIL 29 1976
C     4/26/78 - REMOVE ENTRIES FOR CRAY VERSION - S.P.
C     12/28/79 - CIB TO CND - RPG
C     7/14/80 - SECOND CRAY VERSION NOW THE SAME AS IBM - S.P.
C     7/16/80 - FIX BUG IN ABOVE - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
C
C     MAIN ENTRY ; COMPUTE COULOMB POTENTIAL AT R
C                                                                       29910   
      dimension A(3),B(3),C(3),D(3),E(3),F(3),X(3),Y(3),R1(3),
     1R2(3),VC0(3)
      save A,B,C,D,E,F,X,Y,R1,R2,VC0
C
      COMMON /CNSTNT/PI,RT4PI,PIINV,RAD,DEG,HBARC,AMUMEV,AFINE
C
      IF(R.LT.(R1(K)+R2(K))) GO TO 1
      VC=VC0(K)/R
      RETURN
    1 IF(R.GT.(R1(K)-R2(K))) GO TO 2                                    29920   
      VC=X(K)+Y(K)*R*R
      RETURN
    2 VC=A(K)+R*(B(K)+R*(C(K)+R*(D(K)+R*(E(K)+R*R*F(K)))))
      VC=VC/R
      RETURN
C
C     INITIAL ENTRY ONLY; COMPUTE COEFFICIENTS OF POLYNOMIALS
C
      ENTRY SETVSQ ( RR1, RR2, IZ1, IZ2, K )
C                                                                       29930   
C
CDC      RR1=R
CDC      RR2=VC
CDC      IZ1=KIN
CDC      K=KIN2
      R1(K)=RR1
      R2(K)=RR2
      VC0(K)=IZ1*IZ2*(HBARC/AFINE)
      IF(R1(K).GE.R2(K)) GO TO 3
      TEM=R2(K)                                                         29940   
      R2(K)=R1(K)
      R1(K)=TEM
    3 R1SQ=R1(K)*R1(K)
      R2SQ=R2(K)*R2(K)
      R13=R1SQ*R1(K)
      IF(R2(K).EQ.0) GO TO 4
      R14=R13*R1(K)
      R15=R14*R1(K)
      R16=R15*R1(K)
      R23=R2SQ*R2(K)                                                    29950   
      R24=R23*R2(K)
      R25=R24*R2(K)
      R26=R25*R2(K)
      R12C=R13*R23
      V=VC0(K)/R12C
      A(K)=(V*(R16-9*R14*R2SQ+16*R12C-9*R1SQ*R24+R26))/32
      B(K)=-(3*V*(R15-5*R13*R2SQ-5*R1SQ*R23+R25))/20
      C(K)=(9*V*(R14-2*R1SQ*R2SQ+R24))/32
      D(K)=-(V*(R13+R23))/4
      E(K)=(3*V*(R1SQ+R2SQ))/32                                         29960   
      F(K)=-V/160
    4 IF(R1(K).EQ.0) RETURN
      X(K)=.3D0*(5*R1SQ-R2SQ)*(VC0(K)/R13)
      Y(K)=-.5*(VC0(K)/R13)
C
   50 RETURN
      END
C*ID* WAVEF    C109.PTOLEMY.SOURCE                          PER701  20:
      SUBROUTINE WAVEF ( IRET )
C                                                                       29970   
C  WAVEF CALCULATES RADIAL WAVEFUNCTION FOR ALL PARTIAL WAVES
C  USING WOOD-SAXON POTENTIAL
C
C     THIS ROUTINE IS USED ONLY FOR STAND-ALONE CALCULATIONS OF
C     ELASTIC SCATTERING.  IT IS AN INTERFACE TO WAVSET, WAVPOT
C     AND WAVELJ WITH A COUPLE OF BELLS AND WHISTLES ADDED.
C
C     IF L IS DEFINED THEN THE CALC IS DONE FOR ONLY ONE VALUE OF
C     L; ELSE THE RANGE (LMIN, LMAX) IS USED.
C     IF THERE IS A SPIN-ORBIT FORCE THEN JP IS CHECKED.  IF IT IS      29980   
C     DEFINED THEN ONLY THAT JP (AND THE ASSOCIATED L'S) ARE DONE.
C     IF IT IS NOT DEFINED THEN ALL JP'S FOR EACH L ARE DONE.
C
C     SEE WAVSET FOR DEFINITIONS OF THE POTENTIALS AND WAVEFUNCTION.
C
C
C            THIS VERSION 3/73   D.GLOECKNER
C  REVISED 8/19/73
C     1/16/75 - ADD COULF; SMALL FIXES - S. PIEPER
C     1/28/75 - USE /CNSTNT/                                            29990   
C     1/31/75 - PRINTING CONTROLED BY IPRINT - S.P.
C     2/19/75 - NOLONGER USED FOR DWBA CALCS.
C     2/22/75 - DON'T DIVIDE BY 0 ASO, AIDIFU; CHANGE write (6, OUT)
C               USE IWAVES ARRAY; BETTER NFIRST CHOICE
C     2/25/75 - LOTS OF INPUT CHECKING, RETURN CODE
C     3/3/75  - PRINT OUTPUT NICELY
C     3/5/75 - AVOID UNDERFLOW DUE TO BKM1 UNDEFINED
C     4/20/75 - NEW COMMON BLOCK; REMOVE S.O. SINCE IT IS WROING
C     5/24/75 - MASSIVE SIMPLIFICATION - USE WAVSET, WAVPOT, WAVELJ
C     10/1/75 - NEW ELDCS CALL                                          30000   
C     10/7/75 - POTENTIALS TO MAKPOT
C     10/14/75 - AUTOMATIC LMIN, LMAX; IMPROVED PRINTOUT
C     11/6/75 - PHASE SHIFTS IN DEGREES
C     3/23/76 - USE MANCHESTER COULOMB ROUTINE
C     6/7/76 - T(L), REACTION CROSS SECTION, KAHANA
C     11/19/76 - AVOID OVERFLOWS IN ASYMPTOTIC CHECK.
C     2/3/77 - REMOVE SAVEWAVE; ADD REALWAVE; CHECK AND PRINT ONLY
C              ON LAST COMPUTATION OF A RANGE.
C     2/10/77 - CHANGE ELDCS CALL; IMPROVE CHOICE OF LMIN, LMAX
C     3/21/77 - FIX REACTION CROSS SEC. FOR S.O. FORCES - S.P.          30010   
C     4/18/77 - USE LMINSUB, LMAXMULT.
C     4/21/77 - FIX ERROR IN SINGLE JP CALCULATIONS
C     4/24/77 - IDENTICAL PARTICLES; FITSW
C     5/7/77 - NO CCOEFS; ELDCS DOES TOTAL CROSS SECTIONS
C     11/20/77 - NEW STORAGE OF WELL DEPTHS - S.P.
C     12/1/77 - WAVSET NOW FINDS LCRITICAL - S.P.
C     3/26/78 - GET OUTPUT INTO 80 COLUMNS; MUNICH FIXES - S.P.
C     4/24/78 - REVERSE LOMOST FOR LIMOST - S.P.
C     5/21/78 - NEW WAVELJ STRUCTURE, CRAY STUFF - S.P.
C     6/13/78 - IMAG S.O. NOLONGER REQUIRES SPECIAL ARRAY - S.P.        30020   
C     12/28/78 - ADD TENSOR COUPLING - RPG
C     9/10/79 - STANDARD PREFIXES ETC.; REMOVE OUTDATED CRAY STUFF;
C        USE TOC ARRAY, LX BASIS; S.O. ETC. FOR GENERAL SPIN - RPG
C     11/2/79 - CALCULATE ANALYZING POWERS - RPG
C     11/20/79 - S-MATRICES STORED BY L-LAS - S.P.
C     3/7/80 - FIX ISTRT PROBLEMS FOR REALWAVE, ETC. - S.P.
C     4/23/80 - USE PWBGSW INSTEAD OF PBUGSW - S.P.
C     9/17/81 - NAME FOR RUTHERFORD PASSED TO ELDCS - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      parameter ( NUMJWORD = 12 )                                       /jblock/
      COMMON /JBLOCK/  J, JS(5),
     &  JP, JSP, JST,
     &  JPARM1, JPARM2, JPARM3
 
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      CHARACTER*1  REACT, HEADER                                        /hedcom/
      COMMON /HEDCOM/  REACT(45), HEADER(65)
 
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
      COMMON /KANDM/ AKI, AKO, REDMI, REDMO, RIMAX, ROMAX, ISIGS(2),    /kandm/
     &  RSCTS(2), ASCTS(2), RCSCTS(2) ,ISMATS(2), LOMOST, LCRIT,
     &  ISCTMN, ISCTCR, ETAS(2), RCSCTP(2), RCSCTT(2), LCRITS(2),
     &  RATMSS(2), QMIN, ABAR
 
      DIMENSION  AKS(2), REDMS(2), RMAXS(2)
      EQUIVALENCE ( AKI, AKS(1) ), ( REDMI, REDMS(1) ),
     &  ( RIMAX, RMAXS(1) )
 
      COMMON / TEMPVS /  TVR, TVI, TVSOR, TVSOI, TAR, TAI               /tempvs/
 
C
      LOGICAL  ONEJSW, SOSW, TCSW, THISTC, FKEPSW
      CHARACTER*8  RUTNAM / 'TORUTHER' /,  RUTHNM / 'RUTHERFO' /
C
c
C
      IPRNT = MOD( IPRINT, 10 )
      IF ( IPRNT .GT. 0 )  write (6, 13) REACT, ELAB, HEADER
 13   FORMAT ( '1', T48, 'P T O L E M Y' /                              30050   
     1  '0', 45A1, F8.2, ' MEV', 5X, 65A1 )
C
C
C     TEST THE INPUT AND RETURN  0  COMPLETION CODE IF BAD
C
      IRET = 0
      LLMAX = LMAX
      LLMIN = LMIN
      LSAVE = L
      JPSAVE = JP                                                       30060   
C
      IF ( L .EQ. NOTDEF )  GO TO 60
C
C     DOING ONLY ONE L
C
      LLMAX = L
      LLMIN = L
C
 60   IF ( ICHANW .GT. 2 )  ICHANW = 1
C                                                                       30070   
C     SET UP ARRAYS AND PRINT PARAMETERS.
C
      CALL WAVSET (  IRET, .TRUE., .FALSE. )
      IF ( IRET .EQ. 0 )  GO TO 9900
      IRET = 0
      LSKIP = LSKIPS(ICHANW)
      ISTAT = ISTATS(ICHANW)
C
      IF ( LLMIN .EQ. NOTDEF  .OR.  LLMAX .EQ. NOTDEF )  GO TO 80
C                                                                       30080   
C     LSKIP = 2 ONLY FOR IDENTICAL SPIN 0 SCATTERING
C
      IF ( LSKIP .EQ. 2 )  LLMIN = IABS( LLMIN - MOD(LLMIN,2) )
      IF ( LSKIP .EQ. 2 )  LLMAX = LLMAX + MOD(LLMAX,2)
      GO TO 100
C
C     GET ESTIMATE OF L CRITICAL
C
 80   LCRIT = LCRITS(ICHANW)
C                                                                       30090   
      IF ( LLMIN .NE. NOTDEF )  GO TO 85
      LLMIN = LCRIT*ALMNMT
      LLMIN = MIN0( LLMIN, LCRIT-LMINSB )
      LLMIN = MAX0( LLMIN, 0 )
      IF ( LSKIP .EQ. 2 )  LLMIN = IABS( LLMIN - MOD(LLMIN,2) )
 85   IF ( LLMAX .EQ. NOTDEF )
     1  LLMAX = MAX0( LCRIT+LMAXAD, INT(ALMXMT*LCRIT) )
      IF ( LSKIP .EQ. 2 )  LLMAX = LLMAX + MOD(LLMAX,2)
C
 100  write (6, 103) LLMIN, LLMAX                                       30100   
 103  FORMAT ( '0', I10, ' =< L =<', I4 )
C     ARE WE DOING ONLY ONE JP
C
      SOSW = SOSWS(ICHANW)
      TCSW = TCSWS(ICHANW)
      ONEJSW = JP .NE. NOTDEF
      ISPST = 0
      ISPND = 0
      SPNAV = 1
      IF ( .NOT. SOSW )  GO TO 200                                      30110   
      SPNAV = 1.D0/(JSP+1)
      IF ( ONEJSW )  GO TO 150
C     DOING ALL JP FOR EACH L
      ISPST = -JSP
      ISPND = JSP
      GO TO 200
 150  IF ( MOD(JP+JSP, 2) .EQ. 0 )  GO TO 160
      write (6, 153) JP, JSP
 153  FORMAT ( '0**** JP AND SP ARE AN INVALID HALF-INTEGER AND ',
     1  'INTEGER COMBINATION:', 2(I6, '/2') )                           30120   
      GO TO 9900
C     ONLY DOING ONE JP, REDUCE L-RANGE
 160  LLMIN = MAX0( LLMIN, (JP-JSP)/2 )
      LLMAX = MIN0( LLMAX, (JP+JSP)/2 )
      IF ( LLMIN .LE. LLMAX )  GO TO 200
      write (6, 163) JP, JSP, LMIN, LMAX, L
 163  FORMAT ( '0**** THERE ARE NO VALID COMBINATIONS OF JP, SP AND L:',
     1  '   JP, SP =', 2(I5, '/2') /
     2  ' LMIN, LMAX =', 2I5, '  OR  L =', I5 )
      GO TO 9900                                                        30130   
C
 200  LOMOST = LLMAX
      IF ( TCSW  .AND.  L .NE. NOTDEF )  LOMOST = LLMAX + 2
C
C     SET UP S-MATRIX AND COULOMB WF ARRAYS.
C
      CALL WAVPOT (IRET)
      IF ( IRET .EQ. 0 )  GO TO 9900
      IRET = 0
      NSTEP = NSTPSS(ICHANW)                                            30140   
      NSTEPS = NSTEP + 1
      ETA = ETAS(ICHANW)
      H = HS(ICHANW)
      NSPL = NUMJS(ICHANW)
C
C     IF NECESSARY, GET WORK AREAS FOR THE ASYMPTOTIC CHECK
C
      IF ( ICHECK .EQ. 0 )  GO TO 210
      LOCWRK = NALLOC( 2*(LLMAX+1), 'ASYWRK  ' )
      NFJ = NALLOC( LLMAX+1, 'ASYF    ' )                               30150   
      NGJ = NALLOC( LLMAX+1, 'ASYG    ' )
C
 210  CONTINUE
C
C
C     ALL ALLOCATIONS DONE, GET LOCATIONS
C
      LWAVR = Z(IWAVR)
      LWAVI = Z(IWAVI)
      LSMATS = Z(ISMATS(ICHANW)) - 1                                    30160   
      LTOC = Z(ITOCE(ICHANW))*FACFR4 - FACFR4
      IF ( ICHECK .EQ. 0 )  GO TO 220
      LFJ = Z(NFJ)
      LGJ = Z(NGJ)
      LWORK = Z(LOCWRK)
C
C  SOME DERIVED DATA
C
C
C     INITIALIZE S-MATRIX ELEMENTS TO ZERO.                             30170   
C
 220  CALL INIT8 ( ISMATS(ICHANW), 0.D0 )
C
      IF ( LLMIN .EQ. LLMAX )  IPRNT = 1
C
C     PRINT HEADINGS IF NECESSARY.
C
      LINES = 35
      IF ( IPRNT .GT. 0 )  write (6, 255)
 255  FORMAT ( / '0 L    L''   LX', T33, 'S', T58, '|S|', T69,          30180   
     1   'PHASE SHIFT', T83, 'FRACTION' / T71, 'DEGREES',
     2   T83, 'ABSORBED' / 1X )
C
 1260 CONTINUE
C
C     THIS BRINGS IN THE TABLES NEEDED BY RACAH.
C
      CALL DUMMY1
      LREALV = Z(IRLVS(ICHANW))
      LIMAGV = Z(IIMVS(ICHANW))                                         30190   
      LCENTR = Z(ICENTR(ICHANW))
C
C     LOOP THROUGH INCIDENT L.
C
      DO 399  L = LLMIN, LLMAX, LSKIP
C
C        LOOP THROUGH JP = 2*J(PROJECTILE).  SPIN OF TARGET IS IGNORED.
C        S-MATRIX ELEMENTS FOR ALL LX ARE ACCUMULATED AS SUMS OVER JP.
C
         DO 259  ISP = ISPST, ISPND, 2                                  30200   
            IF ( .NOT. ONEJSW )  JP = 2*L + ISP
            THISTC = TCSW  .AND.  JP .NE. 2*L  .AND.  JP-L .GE. 0
C
C           SUBROUTINE WFGET CALLS EITHER WAVELJ (NO TENSOR) OR WAVETC
C           (TENSOR COUPLING) TO DO THE ACTUAL CALCULATION.
C
            CALL WFGET ( L, L, JP, ICHANW, 0, ALLOC4, ALLOC4, ALLOC4,
     1         ALLOC(LWAVR), ALLOC(LWAVI), ALLOC(LREALV), ALLOC(LIMAGV),
     2         ALLOC(LCENTR) )
C                                                                       30210   
 259     CONTINUE
C
C        END OF CALCULATION LOOP THROUGH JP.
C        IF NECESSARY, RETRIEVE AND PRINT THE S-MATRIX ELEMENTS.
C
         IF ( IPRNT .EQ. 0 )  GO TO 399
C
C        PRINT HEADINGS IF NECESSARY.
C
         IF ( LINES+NSPL .LT. 59 )  GO TO 270                           30220   
         write (6, 13)  REACT, ELAB, HEADER
         write (6, 255)
         LINES = 7
C
C        CALCULATE THE FRACTION ABSORBED FROM THIS L.
C
 270     TL = 1.
         I = LSMATS + 2*NSPL*L - 1
         DO 279  KOFFS = 1, NSPL
            I = I + 2                                                   30230   
            TL = TL - ALLOC(I)**2 - ALLOC(I+1)**2
 279     CONTINUE
C
C        LOOP THROUGH KOFFS = LX, LAS.  QUANTUM NUMBERS ARE
C        IN THE TABLE-OF CONTENTS ARRAY.
C
         DO 299  KOFFS = 1, NSPL
            LX = ILLOC(LTOC+4*KOFFS-2)
            LL = L + ILLOC(LTOC+4*KOFFS-3)
            IF ( LX .GT. L+LL )  GO TO 299                              30240   
C
C           RETRIEVE THE S-MATRIX ELEMENT, AND CALCULATE THE
C           MAGNITUDE, PHASE, AND FRACTION ABSORBED.
C
            I = LSMATS + 2*( NSPL*L + KOFFS ) - 1
            SR = ALLOC(I)
            SI = ALLOC(I+1)
            TEMP = DSQRT( SR**2 + SI**2 )
            IF ( TEMP .EQ. 0 )  GO TO 299
            PHASE = 0.5*RADIAN*DATAN2( SI, SR )                         30250   
C
C           write (6, IT.)
C
            IF ( KOFFS .EQ. 1 )  GO TO 290
            write (6, 283)  L, LL, LX, SR, SI, TEMP, PHASE
 283        FORMAT ( 1X, I3, 2I5, G17.5, ' +', G12.5, ' I', G17.5,
     1         F12.2, G16.5 )
            GO TO 295
 290        write (6, 283)  L, LL, LX, SR, SI, TEMP, PHASE, TL
 295        LINES = LINES + 1                                           30260   
 299     CONTINUE
C
C        END OF KOFFS LOOP FOR PRINTING.  INSERT A BLANK LINE IF NEEDED.
C
         IF ( NSPL .EQ. 1 )  GO TO 399
         write (6, 323)
 323     FORMAT ( 1X )
         LINES = LINES + 1
C
 399  CONTINUE                                                          30270   
C
C     END OF LOOP OVER ALL L'S AND J'S
C
      L = LLMAX
C
C     FOR SINGLE WAVEFUNCTION, REDEFINE WAVER AND WAVEI TO BE
C     THE CORRECT SIZE WITH NO SLOP AT THE END
C
      IF ( LLMAX .EQ. LLMIN  .AND.  .NOT. THISTC )
     1   CALL IREDEF ( NSTEP+1, IWAVR )                                 30280   
      IF ( LLMAX .EQ. LLMIN  .AND.  .NOT. THISTC )
     1   CALL IREDEF ( NSTEP+1, IWAVI )
C
      LWAVR = Z(IWAVR)
      LWAVI = Z(IWAVI)
      ISTRT = LASTNF(ICHANW)-2
C
C     IF REQUESTED, ATTEMPT TO MAKE SCATTERING WAVE REAL
C
      ROTR = 1                                                          30290   
      ROTI = 0
      IF ( IRLWAV .EQ. 0 )  GO TO 500
      ROTR = DCOS( DEGREE*PHASE )
      ROTI = -DSIN( DEGREE*PHASE )
      DO 459  II = ISTRT, NSTEP
         FR = ROTR*ALLOC(LWAVR+II) - ROTI*ALLOC(LWAVI+II)
         ALLOC(LWAVI+II) = ROTR*ALLOC(LWAVI+II) + ROTI*ALLOC(LWAVR+II)
         ALLOC(LWAVR+II) = FR
 459  CONTINUE
      IF ( .NOT. THISTC ) GO TO 500                                     30300   
      DO 469  II = ISTRT, NSTEP
         FR = ROTR*ALLOC(LWAVR+II+NWAVEF) - ROTI*ALLOC(LWAVI+II+NWAVEF)
         ALLOC(LWAVI+II+NWAVEF) = ROTR*ALLOC(LWAVI+II+NWAVEF)
     1      + ROTI*ALLOC(LWAVR+II+NWAVEF)
         ALLOC(LWAVR+II+NWAVEF) = FR
 469  CONTINUE
C
C     WF TABULATION INTERVAL IS 'WRITESTEP' KEYWORD.
C
 500  NWRITE = 1                                                        30310   
      IF ( WRITES .ne. undef )  NWRITE = DMAX1( WRITES/STEPSZ+.5, 1.D0 )
C
C     IF REQUESTED ('CHECKASYM'), DO ASYMPTOTIC CHECK.
C
      IF(ICHECK .EQ.0)GO TO 600
      WRITE(6,513)
513   FORMAT('         ** ASYMTOTIC CHECK ** ' /
     1  '  SOLUTION SHOULD GO TO ASYMPTOTIC FORM' //
     2  '    R', 16X, 'F(R)', 15X, 'ASYMPTOTIC FORM', 7X,
     3  'REL. ERROR' / )                                                30320   
C
C
      DO 559 II = NWRITE, NSTEP, NWRITE
      IF ( II .LT. ISTRT )  GO TO 559
      RHOO=H*II
      RVAL = STEPSZ*II
      CALL RCWFN ( RHOO, ETA, L, L, ALLOC(LFJ), ALLOC(LWORK),
     1  ALLOC(LGJ), ALLOC(LWORK+LLMAX+1), 1.D-8, IFLAG )
      IF ( IFLAG .NE. 0 )  GO TO 9920
      REALF=(ALLOC(LFJ+L)*(1.0D0+SR)+SI*ALLOC(LGJ                       30330   
     1  +L))/2.0D0
      AMAGF=(ALLOC(LGJ+L)*(1.0D0-SR)+SI*ALLOC(LFJ
     1  +L))/2.0D0
      FR = ROTR*REALF - ROTI*AMAGF
      AMAGF = ROTR*AMAGF + ROTI*REALF
      REALF = FR
      FR = ALLOC(LWAVR+II)
      FI = ALLOC(LWAVI+II)
      RATR = ( DABS(FR-REALF) + DABS(FI-AMAGF) ) /
     1    ( DABS(FR) + DABS(FI) )                                       30340   
      WRITE(6,553)RVAL, FR, FI, REALF, AMAGF,RATR
553   FORMAT( F7.2, 2X, 2G11.4, 4X, 2G11.4, G14.2 )
559   CONTINUE
C
C     FREE ALLOCATED SPACE
C
      Z(NFJ) = -Z(NFJ)
      Z(NGJ) = -Z(NGJ)
      Z(LOCWRK) = -Z(LOCWRK)
      GO TO 700                                                         30350   
C
C
C     ARE WE TO PRINT THE WAVEFUNCTION
C
 600  IF ( WRITES .eq. undef ) GO TO 700
C
      IF ( .NOT. SOSW )  write (6, 613) L
 613  FORMAT ( '0OPTICAL MODEL WAVEFUNCTION FOR L =', I4 / )
      IF ( SOSW )  WRITE(6, 617) L, JP
 617  FORMAT( '0OPTICAL MODEL WAVE FUNCTION FOR L =', I4,               30360   
     1   '  J =', I4, '/2' / )
      IF ( THISTC ) GO TO 670
      WRITE(6,331)
 331  FORMAT( 5X, 'R', 7X, 'REAL F', 7X, 'IMAG F' )
      DO  659 II=1,NSTEPS,NWRITE
         IF ( II .LT. ISTRT )  GO TO 659
         RR=(II-1)*STEPSZ
         WRITE(6, 653) RR ,ALLOC(LWAVR+II-1),ALLOC(LWAVI+II-1)
 653     FORMAT( F8.3, 2X, 2G13.5, 5X, 2G13.5 )
 659  CONTINUE                                                          30370   
      GO TO 700
C
C     IF TENSOR COUPLING EXISTS, PRINT BOTH PARTS OF COUPLED WF.
C
 670  LAS = JP - L
      write (6, 673) L, LAS
 673  FORMAT ( 2( 19X, 'LAS =', I3, 3X ) /
     1   5X, 'R', 2( 7X, 'REAL F', 7X, 'IMAG F', 4X ) )
      DO 679 II = 1, NSTEPS, NWRITE
         IF ( II .LT. ISTRT ) GO TO 679                                 30380   
         RR = (II-1)*STEPSZ
         write (6, 653) RR, ALLOC(LWAVR+II-1), ALLOC(LWAVI+II-1),
     1      ALLOC(LWAVR+II-1+NWAVEF), ALLOC(LWAVI+II-1+NWAVEF)
 679  CONTINUE
C
C     IF DESIRED, COMPUTE THE ELASTIC DIFFERENTIAL CROSS SECTIONS
C
 700  IF(IELAST.EQ.0)GO TO 850
      FKEPSW = ISAVB .EQ. 1  .OR.  SOSW
      CALL ELDCS ( H/STEPSZ, ETA, ANGMIN, ANGMAX, ANGSTP,               30390   
     1  LLMIN, LLMAX, LSKIP, ISTAT, JSP, ISMATS(ICHANW), ITOCE(ICHANW),
     2  NSPL, ISIGS(ICHANW), ELAB, ELAB/E-1, .TRUE., ITORUT, RUTNAM,
     3   FKEPSW, IFEL, 'F       ', SIGREA, IRUTH, RUTHNM )
C
C     NOW COMPUTE THE ANALYZING POWERS (IF NONZERO).
C
      IF ( .NOT. SOSW )  GO TO 850
      PWBGSW = MOD( IPRINT, 10 ) .GE. 3
      CALL ANAPOW ( ANGMIN, ANGMAX, ANGSTP, JSP, JSP, JST, JST,
     1   NSPL, 1, .TRUE., PWBGSW, 'ANPOW   ', ELAB, 'ELASTIC ',         30400   
     2   IFEL, ITOCE(ICHANW), IAPOW )
C
C     A L L   D O N E
C
C
 850  CONTINUE
      IRET = 1
      GO TO 9900
C
C                                                                       30410   
C     ERROR RETURNS
C
C
C     ERRORS IN RCWFN
 9920 write (6, 9927) IFLAG, ETA, RHOO, L
 9927 FORMAT ('-***** ERROR RETURN FROM RCWFN:', 5G18.8)
      Z(LOCWRK) = -Z(LOCWRK)
      IRET = 0
C
C     RESTORE COMMON                                                    30420   
C
 9900 L = LSAVE
      JP = JPSAVE
      RETURN
C
      END
C*ID* WAVELJ   C109.PTOLEMY.SOURCE                          PER701  09:
      SUBROUTINE  WAVELJ ( L, JP, NWP, NUMPTS, RGRID, WAVER, WAVEI,
     1  WAVR, WAVI, VREAL, VIMAG, VCENT )
C                                                                       30430   
C     COMPUTES SCATTERING WAVE FOR A GIVEN CHANNEL, L, JP.
C
C
C     THE INPUT IS
C
C     L - L VALUE.
C     JP - J OF PROJECTILE - USED ONLY FOR SPIN ORBIT FORCE.
C     NWP - CHANNEL NUMBER (1 OR 2).
C     NUMPTS - NUMBER OF DESIRED OUTPUT (BY INTERPOLATION) POINTS.
C              IF = <0, THEN THIS IS A REQUEST BY COUPLN TO JUST        30440   
C              INITIALIZE THE WAVR, WAVI ARRAYS WITH THE POTENTIALS
C              AND FIRST TWO XSI'S.  NOTE THAT THE FIRST TWO 12*U'S
C              MUST ALREADY BE IN WAVR AND WAVI.  ALSO FOR THIS
C              CASE, -NUMPTS MUST BE THE NFIRST TO USE.
C     RGRID - VALUES OF R ATWHICH OUTPUT IS TO BE FOUND.
C     WAVER, WAVEI - THE COMPUTED WAVE FUNCTION AT RGRID IS STORED HERE.
C     NUMPTS-WAVEI ARE IGNORED FOR STAND-ALONE CALCULATIONS
C     WAVR, WAVI - TWO WORK ARRAYS OF DIMENSION NSTEP+4.  THEY WILL
C         GET THE WAVEFUNCTION AT EQUALLY SPACED POINTS.  FOR OPTICAL
C         FITS THEY WILL NOT BE RENORMALIZED (THE RENORM CONSTANT WILL  30450   
C         BE ALPHAR+I*ALPHAI).
C     VREAL, VIMAG - THE REAL AND IMAGINARY PARTS (NOT INCLUDING S.O.
C         NOR CENTRIFIGAL TERMS) OF THE POTENTIAL IN THE NUMEROV
C         FORM (SEE MAKPOT OR BELOW).  IF THERE IS AN IMAG S.O.,
C         THEN VIMAG SHOULD INSTEAD BE  WAVI(4)  AND DOES NOT NEED
C         TO BE INITIALIZED.
C     VCENT - 1/RHO**2 IN THE NUMEROV FORM - USED TO COMPUTE THE
C         CENTRIFIGAL TERM IN THE POTENTIAL.
C
C                                                                       30460   
C     2/4/75 - SEPARATED FROM WAVEF - S. PIEPER
C     2/19/75 - USE AITLAG
C     2/25/75 - IMPROVE CHOICE OF STARTING POINT
C     3/5/75 - DEFINE BKM1 = 0 AT START; AVOID UNDERFLOW
C     3/20/75 - OUTPUT IS IN SINGLE PRECISION
C     4/4/75 - FIX NSTEP/NSTEPS BUG; IMPROVE LOOP SLIGHTLY
C     5/21/75 - DO ANY POSITIVE L THAT COMES IN.
C     5/22/75 - POTENTIALS AND AITKEN DONE HERE; STAND ALONE; SPIN ORBIT
C     5/26/75 - FURTHER CLEANUP OF THE LOOP, AVOID UNDERFLOWS.
C     10/1/75 - ADD TIMING  - D.G.                                      30470   
C     10/7/75 POTENTIALS MOVED TO MAKPOT; OTHER LOOP IMPROVEMENTS - S.P.
C     10/27/75 - SAVE SOME THINGS FOR D(S)/D(POT) CALCULATIONS.
C     11/5/75 - INCLUDE ABSORBTION IN CHOICE OF NFIRST
C     2/15/76 - (RHO/RHOTURN)**POW CHOICE OF NFIRST - S.P.
C     2/23/76 - FIXUP IMAGINARY PART OF NFIRST CHOICE
C     1/27/77 - REVISE LOOPS
C     2/1/77 - GREATLY SIMPLIFIED INITIAL VALUE PROCEEDURE - S.P.
C     5/8/77 - FIX BUG IN STORING S(L,J) FOR S.O. FORCES
C     11/20/77 - NEW ASYMPTOPIA; ONLY L.S LEFT OUT OF VSO
C     2/10/78 - LINKULES FOR WAVEFUNCTIONS - S.P.                       30480   
C     4/24/78 - REVERSE LOMOST FOR LIMOST - S.P.
C     4/29/78 - USE BIGNUM, SMLNUM FROM /CNSTNT/ - S.P.
C     5/5/78 - CENTRIFUGAL BARRIER COMES FROM AN ARRAY - S.P.
C     5/21/78 - MODIFIED NUMEROV; EXTRA ARGS FOR BETTER COMPILATION - S.
C     6/1/78 - MOVE IMAG POT FOR LINKULE CALLS
C     6/13/78 - L-DEPENDANT POTENTIALS - S.P.
C     7/11/78 - FIX ERROR IN ABOVE
C     11/11/78 - GO BACK TO 1.E-25 AS INNER CUTOFF FOR WAVEFUNC - S.P.
C     11/16/78 - STEP1R CONTROLS STARTING VALUE FOR BOTH REAL AND IMAG;
C                STEP1I NOW CONTROLS LOC OF NFIRST - S.P.               30490   
C     12/21/78 - ADD TENSOR POTENTIALS - RPG
C     1/10/79 - USE 5-POINT LAGRANGE INTERP., NOT AITKEN LOOP - RPG
C     2/19/79 - CHANGE LOCAL R TO RT TO PRESERVE PARAMETER - RPG
C     3/1/79 - ADD DUMPS, MOVE LASTZR TO /WAVCOM/ - RPG
C     3/19/79 - REMOVE DUMPS - RPG
C     3/22/79 - RESTORE /LNKBLK/ FROM LNKAD2 FOR DWBA - S.P.
C     4/21/79 - AVOID OVERFLOW FOR FIRST L GIGANTIC (500) - S.P.
C     8/3/79 - STANDARD PREFIXES, CALL JPTOLX, SMALLER N1ADD FOR BIG L,
C        FIX MINOR BUGS - RPG
C     11/10/79 - USE DOUBLE PRECISION EXP AT 410 - S.P.                 30500   
C     11/13/79 - PUT 1/24 IN DATA STATEMENT - S.P.
C     6/2/80 MODIFY POTENTIAL DEF. FOR MULTI-CHANNEL CALCULATIONS MRB
C           PUT IN NEW DEFINITION OF COULOMB FUNCTIONS(MULTI-CHANNEL)
C     4/17/80 - ADD TO DEBUG OUTPUT - S.P.
C     4/23/80 - USE PWBGSW INSTEAD OF PBUGSW - S.P.
C     4/25/80 - FIX N1ADD CHANGING BUG - S.P.
C     11/19/81 - PROCESS NUMPTS = -1 FOR COUPLN - S.P.
C     5/10/82 - STORE J FOR J-DEPENDANT LINKULES - S.P.
C     8/8/83 - DO NOT SETBACK NFIRST FOR LINKULES FOR B.C. - S.P.
C     10/15/84 - REAL*8 FG ARRAY - S.P.                                 30510   
C     6/10/85 - DO NOT BUGGER UP THE WAVER ARRAY - S.P.
C
C
      implicit real*8 ( a-h, o-z )                                      implicit
CDC      ALLOCLEVEL RGRID, WAVER, WAVEI, WAVR, WAVI, VREAL, VIMAG, VCENT
C
      REAL*4  RGRID(NUMPTS), WAVER(NUMPTS), WAVEI(NUMPTS)
      DIMENSION   WAVR(1),  WAVI(1), VREAL(1), VIMAG(1), VCENT(1)
C
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      COMMON /JBLOCK/ J
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
      COMMON /KANDM/ AKI, AKO, REDMI, REDMO, RIMAX, ROMAX, ISIGS(2),    /kandm/
     &  RSCTS(2), ASCTS(2), RCSCTS(2) ,ISMATS(2), LOMOST, LCRIT,
     &  ISCTMN, ISCTCR, ETAS(2), RCSCTP(2), RCSCTT(2), LCRITS(2),
     &  RATMSS(2), QMIN, ABAR
 
      DIMENSION  AKS(2), REDMS(2), RMAXS(2)
      EQUIVALENCE ( AKI, AKS(1) ), ( REDMI, REDMS(1) ),
     &  ( RIMAX, RMAXS(1) )
 
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
      REAL*4  TBEGIN, TIMES                                             /ftimef/
      COMMON /FTIME/ TBEGIN, NUMLOP, NUMWAV, TIMES(6), NUMCAL, NUMGRA
 
c                                                                       /lnkblk/
c  STRUCTURE OF   /LNKBLK/
c
c  THERE IS A BLOCK OF 3 DOUBLE WORDS FOR EACH POSSIBLE USE
c  OF A LINKULE.  THE NUMLNK = NUMLINKULES USES ARE IN THE ORDER
c    REALPOTEN  IMAGPOTEN  REALVSO  IMAGVSO  COULOMB
c    WAVEFUNCTION  AND 6 TENSOR POTENTIALS
c  THE THREE-DOUBLE-WORD BLOCKS EACH HAVE THE STRUCTURE
c
c    LNKNAM(1,I)   LINKULE NAME
c
c      LNKADR(3,I)   LINKULE ADDRESS, O IF NO LINKULE IN USE.
c      LNKADR(4,I)   0 - NO L OR J DEPENDENCE IN POTENTIAL
c                    1 - L DEPENDENCE BUT NO J DEPENDENCE
c                    2 - BOTH L  AND J DEPENDENCE
c
c      LNKADR(5&6,I)  MYINTS - A TWO-ELEMENT ARRAY THAT THE
c                     LINKULE MAY USE FOR COMMUNICATION BETWEEN
c                     CALLS TO ITSELF.
c
      parameter ( NUMLINKULES = 13 )
      COMMON /LNKBLK/  NUMLNK, IUNIQU, LNKADR(6,NUMLINKULES)
      character*8  LNKNAM(3,NUMLINKULES)
      EQUIVALENCE ( LNKNAM(1,1), LNKADR(1,1) )
 
      COMMON /LOCFIT/  LNKAD2(6,2,NUMLINKULES)                          /locfitf
 
C
      CHARACTER*8  CHANAM(3) / 'INCOMING', 'OUTGOING' , ' ' /
C
C8F      REAL*8 TEMP8S(4)
C8F      REAL*4 TEMP4S(4)
C8F      EQUIVALENCE ( TEMP4S(1), TEMP8S(1) )
C
      LOGICAL BADSW
C
C     FOLLOWING IS 1/12  AND  1/24                                      30540   
C
      DATA TWELTH / .0833333333333333333333 0D0 /
      DATA OVER24 / .041666666666666666667 0D0 /
C
C     LASTZR IS THE LAST STEP+1 TO HAVE BEEN ZEROED.
C     WE ASSUME THE PREVIOUS WORDS OF WAVR, WAVI TO STILL BE 0 UNLESS
C     LASTL INDICATES THAT WE HAVE STEPPED BACKWARDS.
C
c
C     SETUP THE PARAMETERS FOR THIS CHANNEL                             30550   
C
      IF ( NUMPTS .LT. 0 )  GO TO 5
      IF ( L .LT. 0 )  RETURN
      I = IABS( 2*L - JSPS(NWP) )
      IF ( SOSWS(NWP)  .AND.  JP .LT. I )  RETURN
C
      TT1=second()
  5   DL = L
      DLSQ = DL*(DL+1)
      H = HS(NWP)                                                       30560   
      H2 = H**2
      STEPSZ = RSTEPS(NWP)
      NSTEP = NSTPSS(NWP)
C     DEFINITION OF COULOMB FUNCTIONS FOR MULTI-CHANNEL
      IF ( PROBLM .NE. 24 )  GO TO 40
C
C     WE ARE PASSING THE F & G IN IN A REAL*4 ARRAY.  IF THIS
C     IS THE C8F VERSION OF PTOLEMY, THEN THE NUMBERS ARE
C     REALLY REAL*8 AND WE MUST MOVE THEM ACCORDINGALLY.
C     NOTE THAT ON MACHINES THAT HAVE NO REAL*4 (E.G. CRAY)             30570   
C     C4F (THE DEFAULT) IS IN EFFECT -- NOT C8F.
C
      F1=WAVER(1)                                                       c4f
      G1=WAVER(2)                                                       c4f
      F=WAVER(3)                                                        c4f
      G=WAVER(4)                                                        c4f
C8F      DO 39  I = 1, 8
C8F         TEMP4S(I) = WAVER(I)
C8F 39   CONTINUE
C8F      F1 = TEMP8S(1)                                                 30580   
C8F      G1 = TEMP8S(2)
C8F      F = TEMP8S(3)
C8F      G = TEMP8S(4)
      GO TO 45
C
C     FOR NON-C.C. CALCULATIONS, STORE J-TOTAL FOR L-DEPENDANT LINKULES
C
 40   J = 2*L
C
C     IF LINKULE POTENTIALS OR WAVEFUNCTIONS ARE IN USE,                30590   
C     AND IF THIS IS A DWBA, THEN WE MUST SETUP THE PROPER /LNKBLK/
C
 45   IF ( PROBLM .LT. 20  .OR.  PROBLM .EQ. 21 )  GO TO 50
      DO 49  I = 1, NUMLNK
         DO 49  II = 1, 6
            LNKADR(II,I) = LNKAD2(II,NWP,I)
 49   CONTINUE
C
C     START THE INTEGRATION AT THE POINT DETERMINED FOR THE PREVIOUS
C     SOLUTION IF WE HAVE NOT RESET TO A NEW, LOWER, L VALUE.           30600   
C
 50   NFIRST = -NUMPTS
      ISTRT = NFIRST - 2
      IF ( NUMPTS .LT. 0 )  GO TO 220
      NFIRST = LASTNF(NWP)
      ISTRT = NFIRST - 2
      IF ( L .GE. LASTL(NWP) )  GO TO 160
      NFIRST = 2
      ISTRT = 0
      LASTZR = 1                                                        30610   
C
C     STEP1I (=STEPI) IS THE SMALLEST VALUE OF THE WAVEFUNCTION TO
C     ALLOW AND THUS CONTROLS THE CHOICE OF NFIRST.  IT USE TO HAVE
C     A DEFAULT OF 1 WHICH WE MAP TO THE DEFAULT OF 1E-6.
C
 160  IF ( STEPI .EQ. 1 )  STEPI = 1.D-6
C
C     OUR INITIAL GUESS IS ALWAYS STEPR*STEPI.  WE WILL NEVER LET
C     |U| > BIGNUM.  THIS MEANS THAT THE REQUIRED RENORM WILL SATISFY
C     1/STEPI > RENORM > SMLNUM, AND THUS RENORM**2 WILL NOT            30620   
C     OVERFLOW OR UNDERFLOW.  THIS IS IMPORTANT FOR SDERIV.
C     NOTE THAT STEPR EXISTS ONLY FOR HISTORICAL REASONS AND IS
C     ALWAYS 1.
C
      THISR = STEPI*STEPR
      THISI = THISR
C
C     ASSUME   U(R) = R**(L+1)  TO GET RATIO OF FIRST TWO POINTS
C
      AA1 = ISTRT                                                       30630   
C     ZERO THE FIRST FEW POINTS IF NECESSARY.
      IF ( NUMFIT .NE. 0  .OR.  ISTRT .LT. LASTZR )  GO TO 180
      DO 174  I = LASTZR, ISTRT
            WAVR(I) = 0.
            WAVI(I) = 0.
 174  CONTINUE
 180  D = AA1/(AA1+1)
         WAVR(ISTRT+1) = THISR*D**(L+1)
         WAVI(ISTRT+1) = THISI*D**(L+1)
         WAVR(ISTRT+2) = THISR                                          30640   
         WAVI(ISTRT+2) = THISI
      THISR = THISR + THISI
      THSRSV = THISR
C
C     COMPUTE THE TOTAL EFFECTIVE POTENTIAL FOR THIS L AND TEMPORARILY
C     STORE IN THE WAVEFUNCTION ARRAYS.
C     MODIFY POTENTIAL FOR MULTI-CHANNELS
      IF ( PROBLM .EQ. 24 ) GO TO 220
C
      DO 204  I = ISTRT, NSTEP                                          30650   
         WAVR(I+4) = VREAL(I+1) + DLSQ*VCENT(I+1)
         WAVI(I+4) = VIMAG(I+1)
 204  CONTINUE
      GO TO 230
 220  CCH = H2*TWELTH
      DO 224 I = ISTRT, NSTEP
         WAVR(I+4) = VREAL(I+1)+CCH+DLSQ*VCENT(I+1)
         WAVI(I+4) = VIMAG(I+1)
 224  CONTINUE
C                                                                       30660   
C        MAKE ONE EXTRA SAFE
C
 230  WAVR(NSTEP+5) = 1
      WAVI(NSTEP+5) = 0
C
C     ADD IN THE SPIN ORBIT FORCES IF THEY EXIST
C
      IF ( ISORS(NWP)+ISOIS(NWP) .EQ. 0 )  GO TO 250
C
C     SDOTL IS REALLY  SIGMA.L .  NOTE THAT  JP, JSPS  ARE TWICE THE    30670   
C     REAL VALUES.
C
      SDOTL = .25*(JP*(JP+2) - JSPS(NWP)*(JSPS(NWP)+2)) - DLSQ
      SDOTL = SDOTL / JSPS(NWP)
      IF (L.EQ.1 .AND. JP.EQ.1 .AND. NWP.EQ.2) THEN
        write(0,'(A,E18.12,A,E18.12)') 'FTN_SDOTL= ',SDOTL,' DL2= ',
     &    DLSQ
        write(0,'(A,E18.12)') 'FTN_H2= ',H*H
        write(0,'(A,I5,A,I5,A,E18.12)') 'FTN_NSTEP= ',NSTEP,
     &    ' ISTRT= ',ISTRT,' STEPSZ= ',STEPSZ
        CALL FLUSH(0)
      ENDIF
      IF ( ISORS(NWP) .EQ. 0 )  GO TO 240
      LSOR = Z(ISORS(NWP))
      DO 239  I = ISTRT, NSTEP
         WAVR(I+4) = WAVR(I+4) + SDOTL*ALLOC(LSOR+I)
 239  CONTINUE
 240  IF ( ISOIS(NWP) .EQ. 0 )  GO TO 250                               30680   
      LSOI = Z(ISOIS(NWP))
      LIMV = Z(IIMVS(NWP))
      DO 249  I = ISTRT, NSTEP
         WAVI(I+4) = WAVI(I+4) + SDOTL*ALLOC(LSOI+I)
 249  CONTINUE
C
C     ADD IN THE TENSOR POTENTIALS IF THEY EXIST.
C
 250  DO 259 II = 1, 3
         IF ( ITENS(NWP,2*II-1)+ITENS(NWP,2*II) .EQ. 0 ) GO TO 259      30690   
         TCO = TCOEF ( II, L, L, JP, JSPS(NWP) )
         IF ( TCO .EQ. 0 ) GO TO 259
         IF ( ITENS(NWP,2*II-1) .EQ. 0 ) GO TO 255
         LTEN = Z(ITENS(NWP,2*II-1))
         DO 254 I = ISTRT, NSTEP
            WAVR(I+4) = WAVR(I+4) + TCO* ALLOC(LTEN+I)
 254     CONTINUE
 255     IF ( ITENS(NWP,2*II) .EQ. 0 ) GO TO 259
         LTEN = Z(ITENS(NWP,2*II))
         DO 257 I = ISTRT, NSTEP                                        30700   
            WAVI(I+4) = WAVI(I+4) + TCO* ALLOC(LTEN+I)
 257     CONTINUE
 259  CONTINUE
C
C     NOW PROCESS L-DEPENDENT POTENTIALS WHICH COME ONLY FROM LINKULES.
C
C     THE LINKULE MUST ADD THE L-DEPENDENT PART OF THE POTENTIAL
C     IN THE FORM    -H**2/(12*E) * V(L)   TO THE POTENTIAL ARRAYS
C     ALREADY BUILTUP IN WAVR, WAVI.  THESE ARRAYS CONTAIN THE
C     L-INDEPENDENT PART OF THE POTENTIAL THAT WAS RETURNED FOR         30710   
C     THE IREQUE=3 CALL MADE FROM MAKPOT.
C     THE FACTOR   -H**2/(12*E)  WILL BE PASSED AS THE 1ST ELEMENT
C     OF THE SECOND ARRAY TO THE LINKULE (A1 BELOW).
C
 260  A1 = -(STEPSZ/HBARC)**2 * REDMS(NWP) / 6.D0
      N = NSTEP-ISTRT+1
      RSTART = ISTRT*STEPSZ
C
      IF ( LNKADR(3,1) .EQ. 0  .OR.  LNKADR(4,1) .NE. 1 )  GO TO 270
      CALL LINKUL ( LNKADR(3,1), LNKNAM(1,1), LNKADR(5,1),              30720   
     1  1, 4, IRET,
     2  L, JP, RSTART, STEPSZ, N, WAVR(ISTRT+4), A1, NWP )
      IF ( IRET .LT. 0 )  STOP 7777
C
 270  IF ( LNKADR(3,2) .EQ. 0  .OR.
     1  LNKADR(4,2) .NE. 1 )  GO TO 300
      CALL LINKUL ( LNKADR(3,2), LNKNAM(1,2), LNKADR(5,2),
     1  2, 4, IRET,
     2  L, JP, RSTART, STEPSZ, N, WAVI(ISTRT+4), A1, NWP )
      IF ( IRET .LT. 0 )  STOP 7777                                     30730   
C
C     COMPUTE FIRST TWO XSI'S
C
C --- Surgical W(I) dump for L=1 JP=1 NWP=2 ---
C     (placed at label 300 so it's reached from all code paths)
 300  IF (L.EQ.1 .AND. JP.EQ.1 .AND. NWP.EQ.2) THEN
        DO 27701 I = ISTRT, NSTEP
          IF (MOD(I,50).EQ.0 .OR. I.LE.5 .OR. I.EQ.NSTEP
     &        .OR. I.EQ.NSTEP-4) THEN
            write(0,'(A,I5,F10.4,2E18.12)') 'FTN_W ',I,I*STEPSZ,
     &        WAVR(I+4), WAVI(I+4)
          ENDIF
27701   CONTINUE
        CALL FLUSH(0)
      ENDIF
      II = ISTRT+1
      DO 309  I = ISTRT, II
         WAVR(I+3) =
     1      TWELTH*( WAVR(I+1)*WAVR(I+4) - WAVI(I+1)*WAVI(I+4) )
         WAVI(I+3) =
     1      TWELTH*( WAVR(I+1)*WAVI(I+4) + WAVI(I+1)*WAVR(I+4))
 309  CONTINUE                                                          30740   
C
      IF ( NUMPTS .LT. 0 )  RETURN
C
C     READY TO DO THE INTEGRATION.
C     IS IT DONE HERE OR IN A LINKULE?
C
      T1=second()
      TIMES(1)=TIMES(1)+T1-TT1
C
      IF ( LNKADR(3,6) .EQ. 0)  GO TO 350                               30750   
C
      CALL LINKUL ( LNKADR(3,6), LNKNAM(1,6), LNKADR(5,6),
     1  NFIRST, 3, IRET, L, JP, H*ISTRT, H, NSTEP+1,
     2  WAVR, WAVI, NWP )
      IF ( IRET .GE. 0 )  GO TO 500
      STOP 7777
C
C     WILL DO INTEGRATION HERE
C
 350  CONTINUE                                                          30760   
C
C      NUMEROV METHOD (A LA RAYNAL) IS USED IN THE FOLLOWING LOOP
C
C     WE DEFINE
C       W(I) = 1 - (H**2/12)*(V(I)/E - 1)
C       XSI(I) = W(I)*U(I)/12
C     WHERE
C       V(I) = V(I*STEPSZ) = V(I*H/K)
C     CONTAINS THE COMPLETE NUCLEAR, COULOMB AND CENTRIFIGAL POTENTIALS.
C     MOST OF W(I) IS COMPUTED AND STORED IN MAKPOT, HOWEVER            30770   
C     THE L-DEPENDENT PIECES ARE ADDED IN JUST ABOVE.
C
C     THE DESIRED WAVEFUNCTION IS
C       U(I) = U(I*STEPSZ)
C     EXCEPT THAT AT THIS STAGE THE NORMALIZATION IS ARBITRARY:
C       U(R) ---> CONS*R**(L+1) .
C
C     AT STEP I IN THE LOOP, THE WAVR AND WAVI ARRAYS CONTAIN:
C
C     WAV_(...)   CONTENTS                                              30780   
C          I-1    U(I-2)     NOT USED
C          I      U(I-1)
C          I+1    XSI(I-2),   CHANGED TO U(I) DURING STEP
C          I+2    XSI(I-1)
C          I+3    W(I-1), NOT USED, CHANGED TO XSI(I) DURING STEP
C          I+4    W(I)
C
C     THE SMALLEST POSSIBLE NFIRST IS 2 WHICH RESULTS IN ISTRT=0.
C     THE U AND XSI FOR NFIRST-2, NFIRST-1 HAVE ALREADY BEEN STORED.
C                                                                       30790   
C
C     ON THE FIRST PARTIAL WAVE, WE MUST FROM TIME TO TIME CHECK
C     FOR IMMENENT OVERFLOW AND RENORMALIZE DOWN.  AFTER THE FIRST
C     PARTIAL WAVE WE KNOW WHERE TO START AND NEED NOT CHECK.
C
      N1 = NFIRST
      N2 = NSTEP
      IF ( L .GE. LASTL(NWP) )  GO TO 420
      N1ADD = 20
      IF ( L .GT. 16 )  N1ADD = EXP ( 50.D0/DL )                        30800   
C
 410  N2 = N1 + N1ADD
      N2 = MIN0(N2, NSTEP)
C
 420  D = ( 12. / ( WAVR(N1+4)**2 + WAVI(N1+4)**2 ) )
C
      DO 449  I = N1, N2
C
         WAVR(I+3) = ((-10.)*WAVR(I+2)) + (WAVR(I)-WAVR(I+1))
         WAVI(I+3) = ((-10.)*WAVI(I+2)) + (WAVI(I)-WAVI(I+1))           30810   
C
         WAVR(I+1) = ( WAVR(I+4)*WAVR(I+3) + WAVI(I+4)*WAVI(I+3) ) * D
         WAVI(I+1) = ( WAVR(I+4)*WAVI(I+3) - WAVI(I+4)*WAVR(I+3) ) * D
C
         D = ( 12. / ( WAVR(I+5)**2 + WAVI(I+5)**2 ) )
C
 449  CONTINUE
      IF ( N2 .EQ. NSTEP )  GO TO 500
C
C     CHECK FOR NEARNESS OF OVERFLOW                                    30820   
C
      THISR = DABS(WAVR(N2+1)) + DABS(WAVI(N2+1))
      IF ( PWBGSW )  write (6, 463) NWP, L, N1, N2, THISR
 463  FORMAT ( ' CHECKING SIZE: NWP, L, N1, N2, MAG =',
     1   4I5, G13.3 )
C
      IF ( THISR .GT. BIGNUM )  GO TO 470
      IF ( THISR .LT. 10000*THSRSV )  N1ADD = N1ADD+5
      GO TO 490
C                                                                       30830   
C     MUST SCALE DOWN.  WE WILL MULTIPLY EVERYTHING BY 1/THISR.
C     FIRST WE FIND WHERE THIS WILL RESULT IN |U| = STEPI.
C
 470  THISI = STEPI*THISR
      N1 = ISTRT
      DO 479  ISTRT = N1, N2
         IF ( DABS(WAVR(ISTRT+1)) .GE. THISI )  GO TO 480
         WAVR(ISTRT+1) = 0
         WAVI(ISTRT+1) = 0.
 479  CONTINUE                                                          30840   
C
C
C     SHOULD WE REDUCE N1ADD
C
 480  IF ( THISR*1.D-10 .GT. BIGNUM )  N1ADD = MAX0(N1ADD/2, 1)
      IF ( PWBGSW )  write (6, 483) ISTRT, N1ADD
 483  FORMAT ( 5X, 'RESCALING: NEW ISTRT =', 2I6 )
C
      THISI = 1/THISR
      N1 = N2+2                                                         30850   
      DO 489  I = ISTRT, N1
         WAVR(I+1) = THISI*WAVR(I+1)
         WAVI(I+1) = THISI*WAVI(I+1)
 489  CONTINUE
      THISR = 0
C
 490  N1 = N2+1
      THSRSV = THISR
      GO TO 410
C                                                                       30860   
C     END OF THE INTEGRATION
C
 500  T2=second()
C --- Surgical u(I) dump for L=1 JP=1 NWP=2 ---
      IF (L.EQ.1 .AND. JP.EQ.1 .AND. NWP.EQ.2) THEN
        write(0,'(A,2E18.12)') 'FTN_IC u0= ',WAVR(1),WAVI(1)
        write(0,'(A,2E18.12)') 'FTN_IC u1= ',WAVR(2),WAVI(2)
        DO 50001 I = 2, NSTEP
          IF (MOD(I,50).EQ.0 .OR. I.LE.5 .OR. I.EQ.NSTEP
     &        .OR. I.EQ.NSTEP-4) THEN
            write(0,'(A,I5,F10.4,2E18.12)') 'FTN_U ',I,
     &        I*STEPSZ,WAVR(I+1), WAVI(I+1)
          ENDIF
50001   CONTINUE
        CALL FLUSH(0)
      ENDIF
      TIMES(2)=TIMES(2)+T2-T1
      NUMWAV = NUMWAV + 1
      NUMLOP = NUMLOP + (NSTEP-NFIRST+1)
C
C     EXTRACT S-MATRIX AND NORMALIZATION FROM U AND U AT NBAKCM
C     STEPS BACK FROM END.
C                                                                       30870   
C F IS THE REGULAR COULOMB WAVE
C  G IS THE IRREGULAR COULOMB WAVE
C  NOTE THAT F1,G1 ARE REGULAR AND IRREGULAR COULOMB FUNTIONS AT NBACK
C
      I = L + (IOFFIT-1)*(LOMOST+1)
      IF(PROBLM.EQ.24)GO TO 520
      F = ALLOC(Z(NFS(NWP))+I)
      G = ALLOC(Z(NGS(NWP))+I)
      F1 = ALLOC(Z(NF1S(NWP))+I)
      G1 = ALLOC(Z(NG1S(NWP))+I)                                        30880   
C
 520  CONTINUE
C  NOW FINDING REAL S AND IMAG S
C
      A1 = WAVR(NSTEP+1)*F1 + WAVI(NSTEP+1)*G1
     1  - WAVR(NSTEP+1-NBAKCM)*F
     2  - WAVI(NSTEP+1-NBAKCM)*G
      A2 = -WAVR(NSTEP+1)*G1 + WAVI(NSTEP+1)*F1
     1  + WAVR(NSTEP+1-NBAKCM)*G
     2  - WAVI(NSTEP+1-NBAKCM)*F                                        30890   
      CR = -WAVR(NSTEP+1)*F1 + WAVI(NSTEP+1)*G1
     1  + WAVR(NSTEP+1-NBAKCM)*F
     2  - WAVI(NSTEP+1-NBAKCM)*G
      CI = -WAVR(NSTEP+1)*G1 - WAVI(NSTEP+1)*F1
     1  + WAVR(NSTEP+1-NBAKCM)*G
     2  + WAVI(NSTEP+1-NBAKCM)*F
C
C     TRANSLATE THE ELASTIC S-MATRICES TO THE LX SYSTEM AND SAVE THEM.
C
      SJR = ( CR*A1 + CI*A2 ) / ( A1*A1 + A2*A2 )                       30900   
      SJI = ( CI*A1 - CR*A2 ) / ( A1*A1 + A2*A2 )
C --- Surgical S-matrix dump for L=1 JP=1 NWP=2 ---
      IF (L.EQ.1 .AND. JP.EQ.1 .AND. NWP.EQ.2) THEN
        write(0,'(A,2E18.12,A,F12.8)') 'FTN_SMAT2 SR=',
     &    SJR,SJI,' |S|=',DSQRT(SJR**2+SJI**2)
        write(0,'(A,4E18.12)') 'FTN_COUL F1=',F1,G1,F,G
        write(0,'(A,I5,A,I5)') 'FTN_MATCH NSTEP=',
     &    NSTEP,' NBAKCM=',NBAKCM
        write(0,'(A,2E18.12)') 'FTN_U_N  ',
     &    WAVR(NSTEP+1),WAVI(NSTEP+1)
        write(0,'(A,2E18.12)') 'FTN_U_NB ',
     &    WAVR(NSTEP+1-NBAKCM),WAVI(NSTEP+1-NBAKCM)
        CALL FLUSH(0)
      ENDIF
      LINDXE = FACFR4*Z(IINDXE(NWP))-FACFR4+1
      IF ( (NWP .NE. 2)  .OR.  (PROBLM .NE. 24))
     1  CALL JPTOLX ( L, L, JP, NWP, SJR, SJI,
     1   ILLOC(LINDXE), ALLOC(Z(ISMATS(NWP))) )
      write(0,'(A,I2,A,I3,A,I3,2E18.10,A,F12.8)')
     &  'FTN_SMAT ch=',NWP-1,' L=',L,' JP=',JP,SJR,SJI,
     &  ' MAG=',DSQRT(SJR**2+SJI**2)
C
C  NORMALIZATION HERE
C
      A1 = .5*( F*( 1.+SJR ) + SJI*G )
      A2 = .5*( G*( 1.-SJR ) + SJI*F )                                  30910   
      CR = ( WAVR(NSTEP+1)*A1 + WAVI(NSTEP+1)*A2 ) /
     1      ( WAVR(NSTEP+1)**2 + WAVI(NSTEP+1)**2 )
      ALPHAR = CR
      CI = ( WAVR(NSTEP+1)*A2 - WAVI(NSTEP+1)*A1 ) /
     1      ( WAVR(NSTEP+1)**2 + WAVI(NSTEP+1)**2 )
      ALPHAI = CI
C
C     FIND NEXT STARTING POINT
C     FIND POINT WHERE ALL RENORMALIZED WAVEFUNCTION WILL BE < STEPI
C                                                                       30920   
      AA1 = DABS(CR) + DABS(CI)
      BB1 = STEPI/AA1
      DO 629  I = ISTRT, NSTEP
         IF ( DABS(WAVR(I+1)) + DABS(WAVI(I+1)) .GE. BB1 ) GO TO 630
            WAVR(I+1) = 0.
            WAVI(I+1) = 0.
 629  CONTINUE
C
 630  ISTRT = I
      LASTZR = I+1                                                      30930   
C
C     SET IT BACK SOME FOR LINKULES
C
CCC      IF ( LNKADR(3,6) .NE. 0 )  I = I - 10
      I = MAX0( I+1, 2 )
      LASTNF(NWP) = I
      LASTL(NWP) = L
      BADSW = ( AA1 .GT. BIGNUM*1.D-10  .AND.  NFIRST .GT. 2 )  .OR.
     1  AA1 .LT. SMLNUM*1.D-5
      IF ( BADSW )  write (6, 663)                                      30940   
 663  FORMAT ( '0**** WARNING, LARGE WAVEFUNCTION RENORMALIZATION:' )
      IF ( PWBGSW .OR. BADSW )  write (6, 668) NWP, L, NFIRST,
     1  I, AA1, NSTEP, NSTP2S(NWP), NUMPTS
 668  FORMAT ( ' NWP, L =', I2, I4, '  NFIRST =', I4,
     1  '  NEW NFIRST =', I4, '  RENORM =', D11.3 ,
     2  3X, 'NUM PTS:', 3I6 )
      NFIRST = ISTRT
C
      IF ( NUMFIT .NE. 0 )  GO TO 880
C                                                                       30950   
      IF ( .NOT. PWAVSW )  GO TO 750
      NNWP = NWP
      IF ( STANSW )  NNWP = 3
      IF ( SOSWS(NWP) )  GO TO 730
      write (6, 723)  CHANAM(NNWP), L, SJR, SJI
 723  FORMAT ( 1X, A8, ' ELASTIC S-MATRIX FOR L =', I4,
     1  ':', G15.5, ' +', G13.5, ' I' )
      GO TO 750
 730  IF ( TCSWS(NWP) ) GO TO 740
      write (6, 733) CHANAM(NNWP), L, JP, SJR, SJI                      30960   
 733  FORMAT ( 1X, A8, ' ELASTIC S-MATRIX FOR L =', I4, ',   JP =',
     1  I4, '/2:', G15.5, ' +', G13.5, ' I' )
      GO TO 750
 740  write (6, 743) CHANAM(NNWP), L, L, JP, SJR, SJI
 743  FORMAT ( 1X, A8, ' ELASTIC S-MATRIX FOR L =', I4, ',  LAS =',
     1  I4, ',   JP =', I4, '/2:', G15.5, ' +', G13.5, ' I' )
C
C  STORE NORMALIZED WAVE FUNCTIONS
C
C     CR AND CI WILL NORMALIZE THE WAVEFUNCTION TO                      30970   
C
C       U(L) ---> ( (1+S)*F(L) + I (1-S)*G(L) ) / 2
C
C     FOR STAND-ALONE CALCULATIONS WE MAY INSTEAD USE A NORMALIZATION
C     THAT RESULTS IN REAL U(L) FOR REAL POTENTIALS.  THIS NORM
C     IS COMPUTED AND APPLIED IN WAVEF.
C
 750  N2 = NSTEP+2
      DO 779 I = ISTRT, N2
            A1 = CR*WAVR(I+1) - CI*WAVI(I+1)                            30980   
            WAVI(I+1) = CR*WAVI(I+1) + CI*WAVR(I+1)
            WAVR(I+1) = A1
 779  CONTINUE
      II = ISTRT+2
      IF (PWBGSW)  write (6, 783) ( I, WAVR(I), WAVI(I), I = ISTRT, II )
 783  FORMAT ( ' STARTS:', 3( I5, 2G14.5 ) )
C
C     IF NECESSARY, CONTINUE THE INTEGRATION USING JUST COULOMB
C
      NSTEP2 = NSTP2S(NWP)                                              30990   
      IF ( NSTEP2 .LE. NSTEP )  GO TO 800
C
      NSTEP = NSTEP+1
      RT = NSTEP*STEPSZ
C
      DO 789  I = NSTEP, NSTEP2
         RINV = 1./RT
         WAVR(I+3) = (-10.)*WAVR(I+2) + ( WAVR(I) - WAVR(I+1) )
         WAVI(I+3) = (-10.)*WAVI(I+2) + ( WAVI(I) - WAVI(I+1) )
         D = 12./( XFACS(1,NWP) + RINV*( XFACS(2,NWP) +                 31000   
     1      (DLSQ*XFACS(3,NWP))*RINV ) )
         WAVR(I+1) = D*WAVR(I+3)
         WAVI(I+1) = D*WAVI(I+3)
         RT = RT + STEPSZ
 789  CONTINUE
C
 800  IF ( STANSW  .OR. NUMPTS .EQ. 0 )  GO TO 880
C
C     NOW INTERPOLATE TO THE DESIRED GRID
C                                                                       31010   
      STPINV = 1/RSTEPS(NWP)
      IMX = NSTEP2 - 2
      IF ( PWBGSW )  write (6, 803) NUMPTS, IMX, STPINV
 803  FORMAT ( ' INTERPOLATING:', 2I6, G15.5 )
      DO 859  IR = 1, NUMPTS
         RT = RGRID(IR)
C
C     FIND THE LOCATION OF R IN THE TABLE
C
         RBYH = RT*STPINV                                               31020   
         I = RBYH + 0.5
         I = MAX0 ( 2, MIN0 ( I, IMX ) )
         P = RBYH - I
C     USE 5-POINT LAGRANGIAN INTERPOLATION (ABRAMOWITZ & STEGUN 25.2.15)
         PS = P*P
         X1 = P*(PS-1.)*OVER24
         X2 = X1 + X1
         X3 = X1*P
         X4 = X2 + X2 - 0.5*P
         X5 = X4*P                                                      31030   
         C1 = X3 - X2
         C5 = X3 + X2
         C3 = X5 - X3
         C2 = X5 - X4
         C4 = X5 + X4
         C3 = C3 + C3 + 1.
         WAVER(IR) = C1*WAVR(I-1) - C2*WAVR(I) + C3*WAVR(I+1)
     1     - C4*WAVR(I+2) + C5*WAVR(I+3)
         WAVEI(IR) = C1*WAVI(I-1) - C2*WAVI(I) + C3*WAVI(I+1)
     1     - C4*WAVI(I+2) + C5*WAVI(I+3)                                31040   
C
 859  CONTINUE
C
 880  TIMES(3) = TIMES(3) + second() - T2
      RETURN
      END
C*ID* WAVETC   C109.PTOLEMY.SOURCE                          PER701  15:
      SUBROUTINE  WAVETC ( L, LAS, JP, NWP, NWAVF, NUMPTS, RGRID,
     1  WAVER, WAVEI, WAVR, WAVI, VREAL, VIMAG, VCENT )
C                                                                       31050   
C     COMPUTES TENSOR-COUPLED SCATTERING WAVE FOR A GIVEN L, LAS, JP.
C
C
C     THE INPUT IS
C
C     L - L VALUE.
C     LAS - ASYMPTOTIC L VALUE.
C     JP - 2*J OF PROJECTILE.
C     NWP - CHANNEL NUMBER (1 OR 2).
C     NUMPTS - NUMBER OF DESIRED OUTPUT POINTS.                         31060   
C     RGRID - VALUES OF R ATWHICH OUTPUT IS TO BE FOUND.
C     WAVER, WAVEI - THE COMPUTED WAVE FUNCTION AT RGRID IS STORED HERE.
C     NUMPTS-WAVEI ARE IGNORED FOR STAND-ALONE CALCULATIONS
C     WAVR, WAVI - TWO WORK ARRAYS OF DIMENSION 4*NWAVEF.  THEY WILL
C         GET THE WAVEFUNCTION AT EQUALLY SPACED POINTS.
C     NOTE:  NWAVEF (IN /WAVCOM/) IS AT LEAST NSTEP+4.
C     VREAL, VIMAG - THE REAL AND IMAGINARY PARTS (NOT INCLUDING S.O.
C         NOR CENTRIFIGAL TERMS) OF THE POTENTIAL IN THE NUMEROV
C         FORM (SEE MAKPOT OR BELOW).
C     VCENT - 1/RHO**2 IN THE NUMEROV FORM - USED TO COMPUTE THE        31070   
C         CENTRIFIGAL TERM IN THE POTENTIAL.
C
C
C           NOTE:  THIS SUBROUTINE IS USED FOR SPIN-1 PROJECTILES WHEN
C     TR OR TP TENSOR POTENTIALS ARE PRESENT.
C
C           IF THE WAVE FUNCTIONS ARE TO BE USED (STANSW = .FALSE.),
C     WAVETC SHOULD BE CALLED FIRST FOR ALL WAVES WITH ONE PARITY,
C     THEN FOR ALL WAVES WITH THE OTHER PARITY.  OTHERWISE,
C     THE WRONG WAVE FUNCTIONS WILL BE RETURNED WHENEVER L OR LAS       31080   
C     IS GREATER THAN J.
C
C           WHEN NUMPTS>0, THE COUPLED WAVE FUNCTIONS ARE STORED IN
C     THE ALLOCATOR, INDEXED BY IWAVRS/IWAVIS(JP) ON THE FIRST CALL
C     TO WAVETC FOR A GIVEN JP (L = LAS = JP/2-1).  ON SUBSEQUENT
C     CALLS FOR THE SAME JP, THE REQUESTED WAVE FUNCTION IS MERELY
C     TRANSFERRED TO WAVER/WAVEI.
C
C     1/30/79 - CREATE WAVETC, BASED ON WAVELJ - RPG
C     2/7/79 - SPLIT OFF TMATCH TO ALLOW EXPRESS COMPILATION - RPG      31090   
C     2/19/79 - USE SMLISH,BIGISH; CHANGE LOCAL R TO RT - RPG
C     2/27/79 - CHANGE LOWER L TO LOCAL LL - RPG
C     3/1/79 - INSERT DUMP, REMOVE SMLISH, BIGISH - RPG
C     3/20/79 - REMOVE DUMPS - RPG
C     8/3/79 - RESTORE /LNKBLK/ FROM LNKAD2 FOR DWBA, CHANGE SIZE
C        CHECKING - RPG
C     11/10/79 - USE DOUBLE-PRECISION EXP AT 410 - S.P.
C     11/15/79 - USE 1/24; REARRANGE INTERP STUFF - S.P.
C     4/23/80 - USE PWGSW INSTEAD OF PBUGSW - S.P.
C     6/3/80 - GET AND PASS NWAVF DIMENSION FOR CDC - S.P.              31100   
C     6/25/80 - DEFINE /SWITCH/ FOR PROBLM (MISSING) - S.P.
C
C
      implicit real*8 ( a-h, o-z )                                      implicit
CDC      ALLOCLEVEL RGRID, WAVER, WAVEI, WAVR, WAVI, VREAL, VIMAG, VCENT
C
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
      COMMON /KANDM/ AKI, AKO, REDMI, REDMO, RIMAX, ROMAX, ISIGS(2),    /kandm/
     &  RSCTS(2), ASCTS(2), RCSCTS(2) ,ISMATS(2), LOMOST, LCRIT,
     &  ISCTMN, ISCTCR, ETAS(2), RCSCTP(2), RCSCTT(2), LCRITS(2),
     &  RATMSS(2), QMIN, ABAR
 
      DIMENSION  AKS(2), REDMS(2), RMAXS(2)
      EQUIVALENCE ( AKI, AKS(1) ), ( REDMI, REDMS(1) ),
     &  ( RIMAX, RMAXS(1) )
 
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
      REAL*4  TBEGIN, TIMES                                             /ftimef/
      COMMON /FTIME/ TBEGIN, NUMLOP, NUMWAV, TIMES(6), NUMCAL, NUMGRA
 
c                                                                       /lnkblk/
c  STRUCTURE OF   /LNKBLK/
c
c  THERE IS A BLOCK OF 3 DOUBLE WORDS FOR EACH POSSIBLE USE
c  OF A LINKULE.  THE NUMLNK = NUMLINKULES USES ARE IN THE ORDER
c    REALPOTEN  IMAGPOTEN  REALVSO  IMAGVSO  COULOMB
c    WAVEFUNCTION  AND 6 TENSOR POTENTIALS
c  THE THREE-DOUBLE-WORD BLOCKS EACH HAVE THE STRUCTURE
c
c    LNKNAM(1,I)   LINKULE NAME
c
c      LNKADR(3,I)   LINKULE ADDRESS, O IF NO LINKULE IN USE.
c      LNKADR(4,I)   0 - NO L OR J DEPENDENCE IN POTENTIAL
c                    1 - L DEPENDENCE BUT NO J DEPENDENCE
c                    2 - BOTH L  AND J DEPENDENCE
c
c      LNKADR(5&6,I)  MYINTS - A TWO-ELEMENT ARRAY THAT THE
c                     LINKULE MAY USE FOR COMMUNICATION BETWEEN
c                     CALLS TO ITSELF.
c
      parameter ( NUMLINKULES = 13 )
      COMMON /LNKBLK/  NUMLNK, IUNIQU, LNKADR(6,NUMLINKULES)
      character*8  LNKNAM(3,NUMLINKULES)
      EQUIVALENCE ( LNKNAM(1,1), LNKADR(1,1) )
 
      COMMON /LOCFIT/  LNKAD2(6,2,NUMLINKULES)                          /locfitf
 
C
      REAL*4  RGRID(NUMPTS), WAVER(1), WAVEI(1)
      DIMENSION   WAVR(NWAVF,2,2),  WAVI(NWAVF,2,2),
     1  VREAL(1), VIMAG(1), VCENT(1)                                    31120   
C
      DIMENSION DLSQ(2), SDOTL(2), TCO(3), CR(2,2), CI(2,2),
     1  U1R(2,2), U1I(2,2), WIR(2), WII(2)
C
C
      LOGICAL BADSW
C
C     FOLLOWING IS 1/12
C
      DATA TWELTH / .0833333333333333333333 0D0 /                       31130   
      DATA OVER24 / .041666666666666666667 0D0 /
C
C     LASTZR IS THE LAST STEP+1 TO HAVE BEEN ZEROED.
C     WE ASSUME THE PREVIOUS WORDS OF WAVR, WAVI TO STILL BE 0 UNLESS
C     LASTL INDICATES THAT WE HAVE STEPPED BACKWARDS.
C
c
C     SETUP THE PARAMETERS FOR THIS CHANNEL
C
      LL = JP/2 - 1                                                     31140   
      IF ( L .LT. 0  .OR.  LL .LT. 0 )  RETURN
      TT1 = second()
      T2 = TT1
      LWAVRS = Z(IWAVRS(NWP))*FACFR4 - FACFR4
      LWAVIS = Z(IWAVIS(NWP))*FACFR4 - FACFR4
C
C     IF THIS WAVE HAS ALREADY BEEN CALCULATED, GO TRANSFER IT.
C
      IF ( ( LL .NE. L  .OR.  LAS .NE. L )
     1  .AND.  L .GE. LASTL(NWP) ) GO TO 900                            31150   
C
      DL = LL
      DLSQ(1) = DL*(DL+1)
      DLSQ(2) = (DL+2)*(DL+3)
      H = HS(NWP)
      STEPSZ = RSTEPS(NWP)
      NSTEP = NSTPSS(NWP)
C
C     IF LINKULE POTENTIALS OR WAVEFUNCTIONS ARE IN USE,
C     AND IF THIS IS A DWBA, THEN WE MUST SETUP THE PROPER /LNKBLK/     31160   
C
      IF ( PROBLM .LT. 20  .OR.  PROBLM .EQ. 21 )  GO TO 50
      DO 49  I = 1, NUMLNK
         DO 49  II = 1, 6
            LNKADR(II,I) = LNKAD2(II,NWP,I)
 49   CONTINUE
C
C     START THE INTEGRATION AT THE POINT DETERMINED FOR THE PREVIOUS
C     SOLUTION IF WE HAVE NOT RESET TO A NEW, LOWER, L VALUE.
C                                                                       31170   
 50   NFIRST = LASTNF(NWP)
      IF ( LL .GE. LASTL(NWP) )  GO TO 160
      NFIRST = 2
      LASTZR = 1
C
C     STEP1I (=STEPI) IS THE SMALLEST VALUE OF THE WAVEFUNCTION TO
C     ALLOW AND THUS CONTROLS THE CHOICE OF NFIRST.  IT USE TO HAVE
C     A DEFAULT OF 1 WHICH WE MAP TO THE DEFAULT OF 1E-6.
C
 160  IF ( STEPI .EQ. 1 )  STEPI = 1.D-6                                31180   
C
C     OUR INITIAL GUESS IS ALWAYS STEPR*STEPI.  WE WILL NEVER LET
C     |U| > BIGNUM.  THIS MEANS THAT THE REQUIRED RENORM WILL SATISFY
C     1/STEPI > RENORM > SMLNUM, AND THUS RENORM**2 WILL NOT
C     OVERFLOW OR UNDERFLOW.  THIS IS IMPORTANT FOR SDERIV.
C     NOTE THAT STEPR EXISTS ONLY FOR HISTORICAL REASONS AND IS
C     ALWAYS 1.
C
      THISR = STEPI*STEPR
      THISI = THISR                                                     31190   
C
C     ASSUME   U(R) = R**(L+1)  TO GET RATIO OF FIRST TWO POINTS
C
      AA1 = NFIRST - 2
      ISTRT = NFIRST - 2
C     ZERO THE FIRST FEW POINTS IF NECESSARY.
      IF ( NFIRST .LT. LASTZR )  GO TO 180
      DO 174  I = LASTZR, NFIRST
         DO 174 IL = 1, 4
            WAVR(I,IL,1) = 0.                                           31200   
            WAVI(I,IL,1) = 0.
 174  CONTINUE
 180  D = AA1/(AA1+1)
      WAVR(ISTRT+1,1,1) = THISR*D**(LL+1)
      WAVI(ISTRT+1,1,1) = THISI*D**(LL+1)
      WAVR(ISTRT+2,1,1) = THISR
      WAVI(ISTRT+2,1,1) = THISI
C     THE RATIO OF THE L+2 WAVE FUNCTION TO THE L WAVE FUNCTION
C     DEPENDS ON THE LOCAL WAVE NUMBER.
      AA1 = (2*LL+3)*(2*LL+5)                                           31210   
      AA1 = (NFIRST-1)**2 * 12.*(VREAL(NFIRST)-1.) / AA1
      WAVR(ISTRT+1,2,2) = THISR*AA1*D**(LL+3)
      WAVI(ISTRT+1,2,2) = THISI*AA1*D**(LL+3)
      WAVR(ISTRT+2,2,2) = THISR*AA1
      WAVI(ISTRT+2,2,2) = THISI*AA1
C
C     COMPUTE THE TOTAL EFFECTIVE POTENTIAL FOR THIS L AND TEMPORARILY
C     STORE IN THE WAVEFUNCTION ARRAYS.
C
      DO 224  I = ISTRT, NSTEP                                          31220   
         WAVR(I+4,1,1) = VREAL(I+1) + DLSQ(1)*VCENT(I+1)
         WAVR(I+4,2,1) = VREAL(I+1) + DLSQ(2)*VCENT(I+1)
         WAVI(I+4,1,1) = VIMAG(I+1)
         WAVI(I+4,2,1) = WAVI(I+4,1,1)
         WAVR(I+4,1,2) = 0.
         WAVI(I+4,1,2) = 0.
 224  CONTINUE
      THSRSV = THISR + THISI
C
C     ADD IN THE SPIN ORBIT FORCES IF THEY EXIST                        31230   
C
      IF ( ISORS(NWP)+ISOIS(NWP) .EQ. 0 )  GO TO 250
C
C     SDOTL IS REALLY  SIGMA.L.  NOTE THAT  JP, JSPS  ARE TWICE THE REAL
C     VALUES.
C
      AA1 = .25*(JP*(JP+2) - JSPS(NWP)*(JSPS(NWP)+2))
      SDOTL(1) = ( AA1 - DLSQ(1) ) / JSPS(NWP)
      SDOTL(2) = ( AA1 - DLSQ(2) ) / JSPS(NWP)
      IF ( ISORS(NWP) .EQ. 0 )  GO TO 240                               31240   
      LSOR = Z(ISORS(NWP))
      DO 239  I = ISTRT, NSTEP
         WAVR(I+4,1,1) = WAVR(I+4,1,1) + SDOTL(1)*ALLOC(LSOR+I)
         WAVR(I+4,2,1) = WAVR(I+4,2,1) + SDOTL(2)*ALLOC(LSOR+I)
 239  CONTINUE
 240  IF ( ISOIS(NWP) .EQ. 0 )  GO TO 250
      LSOI = Z(ISOIS(NWP))
      DO 249  I = ISTRT, NSTEP
         WAVI(I+4,1,1) = WAVI(I+4,1,1) + SDOTL(1)*ALLOC(LSOI+I)
         WAVI(I+4,2,1) = WAVI(I+4,2,1) + SDOTL(2)*ALLOC(LSOI+I)         31250   
 249  CONTINUE
C
C     ADD IN THE TENSOR POTENTIALS IF THEY EXIST.
C
 250  DO 259 II = 1, 3
         IF ( ITENS(NWP,2*II-1)+ITENS(NWP,2*II) .EQ. 0 ) GO TO 259
         TCO(1) = TCOEF ( II, LL, LL, JP, JSPS(NWP) )
         TCO(2) = TCOEF ( II, LL+2, LL+2, JP, JSPS(NWP) )
         TCO(3) = TCOEF ( II, LL, LL+2, JP, JSPS(NWP) )
         IF ( ITENS(NWP,2*II-1) .EQ. 0 ) GO TO 255                      31260   
         LTEN = Z(ITENS(NWP,2*II-1))
         DO 254 IL = 1, 3
            IF ( TCO(IL) .EQ. 0 ) GO TO 254
            DO 253 I = ISTRT, NSTEP
               WAVR(I+4,IL,1) = WAVR(I+4,IL,1) + TCO(IL)*ALLOC(LTEN+I)
 253        CONTINUE
 254     CONTINUE
 255     IF ( ITENS(NWP,2*II) .EQ. 0 ) GO TO 259
         LTEN = Z(ITENS(NWP,2*II))
         DO 258 IL = 1, 3                                               31270   
            IF ( TCO(IL) .EQ. 0 ) GO TO 258
            DO 257 I = ISTRT, NSTEP
               WAVI(I+4,IL,1) = WAVI(I+4,IL,1) + TCO(IL)*ALLOC(LTEN+I)
 257        CONTINUE
 258     CONTINUE
 259  CONTINUE
C
C     NOW PROCESS L-DEPENDENT POTENTIALS WHICH COME ONLY FROM LINKULES.
C
C     THE LINKULE MUST ADD THE L-DEPENDENT PART OF THE POTENTIAL        31280   
C     IN THE FORM    -H**2/(12*E) * V(L)   TO THE POTENTIAL ARRAYS
C     ALREADY BUILTUP IN WAVR, WAVI.  THESE ARRAYS CONTAIN THE
C     L-INDEPENDENT PART OF THE POTENTIAL THAT WAS RETURNED FOR
C     THE IREQUE=3 CALL MADE FROM MAKPOT.
C     THE FACTOR   -H**2/(12*E)  WILL BE PASSED AS THE 1ST ELEMENT
C     OF THE SECOND ARRAY TO THE LINKULE (A1 BELOW).
C
 260  A1 = -(STEPSZ/HBARC)**2 * REDMS(NWP) / 6.D0
C
      IF ( LNKADR(3,1) .EQ. 0  .OR.  LNKADR(4,1) .NE. 1 )  GO TO 270    31290   
      CALL LINKUL ( LNKADR(3,1), LNKNAM(1,1), LNKADR(5,1),
     1  1, 4, IRET,
     2  LL, J, 0.D0, STEPSZ, NSTEP+1, WAVR(4,1,1), A1, NWP )
      IF ( IRET .LT. 0 )  STOP 7777
      CALL LINKUL ( LNKADR(3,1), LNKNAM(1,1), LNKADR(5,1),
     1  1, 4, IRET,
     2  LL+2, J, 0.D0, STEPSZ, NSTEP+1, WAVR(4,2,1), A1, NWP )
      IF ( IRET .LT. 0 )  STOP 7777
C
 270  IF ( LNKADR(3,2) .EQ. 0  .OR.                                     31300   
     1  LNKADR(4,2) .NE. 1 )  GO TO 300
      CALL LINKUL ( LNKADR(3,2), LNKNAM(1,2), LNKADR(5,2),
     1  2, 4, IRET,
     2  LL, J, 0.D0, STEPSZ, NSTEP+1, WAVI(4,1,1), A1, NWP )
      IF ( IRET .LT. 0 )  STOP 7777
      CALL LINKUL ( LNKADR(3,2), LNKNAM(1,2), LNKADR(5,2),
     1  2, 4, IRET,
     2  LL+2, J, 0.D0, STEPSZ, NSTEP+1, WAVI(4,2,1), A1, NWP )
      IF ( IRET .LT. 0 )  STOP 7777
C                                                                       31310   
C     COMPUTE FIRST TWO XSI'S
C
 300  II = ISTRT+1
      DO 309  I = ISTRT, II
         DO 308 IL = 1, 2
         ILP = 3 - IL
            DO 307 IS = 1, 2
            WAVR(I+3,IL,IS) =
     1         TWELTH*( WAVR(I+1,IL,IS)*WAVR(I+4,IL,1)
     2         - WAVI(I+1,IL,IS)*WAVI(I+4,IL,1)                         31320   
     3         + WAVR(I+1,ILP,IS)*WAVR(I+4,1,2)
     4         - WAVI(I+1,ILP,IS)*WAVI(I+4,1,2) )
            WAVI(I+3,IL,IS) =
     1         TWELTH*( WAVR(I+1,IL,IS)*WAVI(I+4,IL,1)
     2         + WAVI(I+1,IL,IS)*WAVR(I+4,IL,1)
     3         + WAVR(I+1,ILP,IS)*WAVI(I+4,1,2)
     4         + WAVI(I+1,ILP,IS)*WAVR(I+4,1,2) )
 307        CONTINUE
 308     CONTINUE
C                                                                       31330   
 309  CONTINUE
C
C     READY TO DO THE INTEGRATION.
C     IS IT DONE HERE OR IN A LINKULE?
C
      T1=second()
      TIMES(1)=TIMES(1)+T1-TT1
C
      IF ( LNKADR(3,6) .EQ. 0)  GO TO 350
C                                                                       31340   
      CALL LINKUL ( LNKADR(3,6), LNKNAM(1,6), LNKADR(5,6),
     1  NFIRST, 3, IRET, L, JP, H*ISTRT, H, NSTEP+1,
     2  WAVR, WAVI, NWP )
      IF ( IRET .GE. 0 )  GO TO 500
      STOP 7777
C
C     WILL DO INTEGRATION HERE
C
 350  CONTINUE
C                                                                       31350   
C      NUMEROV METHOD (A LA RAYNAL) IS USED IN THE FOLLOWING LOOP
C
C     WE DEFINE
C       W(I) = 1 - (H**2/12)*(V(I)/E - 1)
C       XSI(I) = W(I)*U(I)/12
C     WHERE
C       V(I) = V(I*STEPSZ) = V(I*H/K)
C     CONTAINS THE COMPLETE NUCLEAR, COULOMB AND CENTRIFIGAL POTENTIALS.
C     MOST OF W(I) IS COMPUTED AND STORED IN MAKPOT, HOWEVER
C     THE L-DEPENDENT PIECES ARE ADDED IN JUST ABOVE.                   31360   
C
C     THE DESIRED WAVEFUNCTION IS
C       U(I) = U(I*STEPSZ)
C     EXCEPT THAT AT THIS STAGE THE NORMALIZATION IS ARBITRARY:
C       U(R) ---> CONS*R**(L+1) .
C
C     AT STEP I IN THE LOOP, THE WAVR AND WAVI ARRAYS CONTAIN:
C
C     WAV_(...)   CONTENTS
C          I-1    U(I-2)     NOT USED                                   31370   
C          I      U(I-1)
C          I+1    XSI(I-2),   CHANGED TO U(I) DURING STEP
C          I+2    XSI(I-1)
C          I+3    W(I-1), NOT USED, CHANGED TO XSI(I) DURING STEP
C          I+4    W(I)
C
C     THE SMALLEST POSSIBLE NFIRST IS 2 WHICH RESULTS IN ISTRT=0.
C     THE U AND XSI FOR NFIRST-2, NFIRST-1 HAVE ALREADY BEEN STORED.
C
C     NOTE THAT U AND XSI, AS DEFINED ABOVE, ARE 2-BY-2 MATRICES AT     31380   
C     EACH I, INDEXED BY IL (FOR THE UPPER OR LOWER L VALUE) AND
C     IS (FOR THE 2 INDEPENDENT SOLUTIONS).  THE DIAGONAL POTENTIALS
C     ARE STORED IN THE LOWER HALF OF WAV_ (IS=1).  THE
C     OFF-DIAGONAL (COUPLING) POTENTIAL IS IN WAV_(I+4,1,2).
C
C
C     ON THE FIRST PARTIAL WAVE, WE MUST FROM TIME TO TIME CHECK
C     FOR IMMINENT OVERFLOW AND RENORMALIZE DOWN.  AFTER THE FIRST
C     PARTIAL WAVE WE KNOW WHERE TO START AND NEED NOT CHECK.
C                                                                       31390   
      N1 = NFIRST
      N2 = NSTEP
      IF ( LL .GE. LASTL(NWP) )  GO TO 420
      N1ADD = 20
      IF ( L .GT. 16 ) N1ADD = EXP ( 50.D0/L )
C
 410  N2 = N1 + N1ADD
      N2 = MIN0(N2, NSTEP)
C
C     LOOP THROUGH RADII.                                               31400   
C
 420  DO 449 I = N1, N2
C
C        WI(I) = 12./W(I)  (MATRIX INVERSION)
C
         TR = WAVR(I+4,1,1)*WAVR(I+4,2,1) - WAVI(I+4,1,1)*WAVI(I+4,2,1)
     1      - WAVR(I+4,1,2)*WAVR(I+4,1,2) + WAVI(I+4,1,2)*WAVI(I+4,1,2)
         TI = WAVR(I+4,1,2)*WAVI(I+4,1,2)
         TI = TI + TI
     1       - WAVR(I+4,1,1)*WAVI(I+4,2,1) - WAVI(I+4,1,1)*WAVR(I+4,2,1)31410   
         TD = 12. / ( TR*TR + TI*TI )
         TR = TR*TD
         TI = TI*TD
         WIR(1) = TR*WAVR(I+4,2,1) - TI*WAVI(I+4,2,1)
         WII(1) = TR*WAVI(I+4,2,1) + TI*WAVR(I+4,2,1)
         WIR(2) = TR*WAVR(I+4,1,1) - TI*WAVI(I+4,1,1)
         WII(2) = TR*WAVI(I+4,1,1) + TI*WAVR(I+4,1,1)
         WTR = (-TR)*WAVR(I+4,1,2) + TI*WAVI(I+4,1,2)
         WTI = (-TR)*WAVI(I+4,1,2) - TI*WAVR(I+4,1,2)
C                                                                       31420   
C        LOOP THROUGH THE 2 INDEPENDENT SOLUTIONS.
C
         DO 439 IS = 1, 2
C
C        XSI(I) = (-10.)*XSI(I-1) + U(I-1) - XSI(I-2)  (FOR EACH L)
C
            DO 424 IL = 1, 2
               WAVR(I+3,IL,IS) = (-10.)*WAVR(I+2,IL,IS)
     1            + WAVR(I,IL,IS) - WAVR(I+1,IL,IS)
               WAVI(I+3,IL,IS) = (-10.)*WAVI(I+2,IL,IS)                 31430   
     1            + WAVI(I,IL,IS) - WAVI(I+1,IL,IS)
 424        CONTINUE
C
C           U(I) = (12/W(I))*XSI(I)  (FOR EACH L)
C
            DO 429 IL = 1, 2
               ILP = 3 - IL
               WAVR(I+1,IL,IS)
     1             = WIR(IL)*WAVR(I+3,IL,IS) - WII(IL)*WAVI(I+3,IL,IS)
     2             + WTR*WAVR(I+3,ILP,IS) - WTI*WAVI(I+3,ILP,IS)        31440   
               WAVI(I+1,IL,IS)
     1             = WIR(IL)*WAVI(I+3,IL,IS) + WII(IL)*WAVR(I+3,IL,IS)
     2             + WTR*WAVI(I+3,ILP,IS) + WTI*WAVR(I+3,ILP,IS)
 429        CONTINUE
C
 439     CONTINUE
C
 449  CONTINUE
      IF ( N2 .EQ. NSTEP )  GO TO 500
C                                                                       31450   
C     CHECK FOR NEARNESS OF OVERFLOW
C
      THISR = 0.
      DO 459 IL = 1, 4
         THISR = THISR + DABS(WAVR(N2+1,IL,1)) + DABS(WAVI(N2+1,IL,1))
 459  CONTINUE
      IF ( PWBGSW )  write (6, 463) NWP, LL, N1, N2, THISR
 463  FORMAT ( ' CHECKING SIZE: NWP, LL, N1, N2, MAG =',
     1   4I5, G13.3 )
C                                                                       31460   
      IF ( THISR .GT. BIGNUM )  GO TO 470
      IF ( THISR .LT. 100*THSRSV ) N1ADD = N1ADD + 5
      GO TO 490
C
C     MUST SCALE DOWN.  WE WILL MULTIPLY EVERYTHING BY SMLNUM.
C     FIRST WE FIND WHERE THIS WILL RESULT IN |U| = STEPI.
C
 470  THISI = STEPI*THISR
      N1 = ISTRT
      DO 479  ISTRT = N1, N2                                            31470   
         DO 478 IL = 1, 4
            IF ( DABS(WAVR(ISTRT+1,IL,1)) + DABS(WAVI(ISTRT+1,IL,1))
     1        .GE. THISI )  GO TO 480
            WAVR(ISTRT+1,IL,1) = 0
            WAVI(ISTRT+1,IL,1) = 0.
 478     CONTINUE
 479  CONTINUE
C
C
C     SHOULD WE REDUCE N1ADD?                                           31480   
C
 480  IF ( THISR*1.D-10 .GT. BIGNUM )  N1ADD = MAX0(N1ADD/2, 1 )
      IF ( PWBGSW )  write (6, 483) ISTRT
 483  FORMAT ( 5X, 'RESCALING: NEW ISTRT =', I6 )
C
      THISI = 1/THISR
      N1 = N2+2
      DO 489  I = ISTRT, N1
         DO 488 IL = 1, 4
            WAVR(I+1,IL,1) = THISI*WAVR(I+1,IL,1)                       31490   
            WAVI(I+1,IL,1) = THISI*WAVI(I+1,IL,1)
 488     CONTINUE
 489  CONTINUE
C
 490  N1 = N2+1
      THSRSV = THISR
      GO TO 410
C
C     END OF THE INTEGRATION
C                                                                       31500   
 500  T2=second()
      TIMES(2)=TIMES(2)+T2-T1
      NUMWAV = NUMWAV + 1
      NUMLOP = NUMLOP + (NSTEP-NFIRST+1)
C
C     EXTRACT S-MATRIX AND NORMALIZATION FROM U AND U AT NBAKCM
C     STEPS BACK FROM END.
C
      LFORS = Z(ISMATS(NWP))
      CALL TMATCH ( WAVR, WAVI, CR, CI, ALLOC(LFORS), JP, NWP, NWAVF )  31510   
C
C     FIND NEXT STARTING POINT
C     FIND POINT WHERE ALL RENORMALIZED WAVEFUNCTION WILL BE < STEPI
C
      AA1 = 0.
      DO 609 IL = 1, 4
         AA1 = AA1 + DABS(CR(IL,1)) + DABS(CI(IL,1))
 609  CONTINUE
      BB1 = STEPI/AA1
      DO 629  I = ISTRT, NSTEP                                          31520   
         DO 619 IL = 1, 4
            IF ( DABS(WAVR(I+1,IL,1)) + DABS(WAVI(I+1,IL,1)) .GE. BB1)
     1        GO TO 630
            WAVR(I+1,IL,1) = 0.
            WAVI(I+1,IL,1) = 0.
 619     CONTINUE
 629  CONTINUE
C
 630  ISTRT = I
      LASTZR = I+1                                                      31530   
C
         ILP = 3 - IL
C     SET IT BACK SOME FOR LINKULES
C
      IF ( LNKADR(3,6) .NE. 0 )  I = I - 10
      I = MAX0( I+1, 2 )
      LASTNF(NWP) = I
      LASTL(NWP) = LL
      BADSW = ( AA1 .GT. BIGNUM*1.D-10  .AND.  NFIRST .GT. 2 )  .OR.
     1  AA1 .LT. SMLNUM*1.D-5                                           31540   
      IF ( BADSW )  write (6, 663)
 663  FORMAT ( '0**** WARNING, LARGE WAVEFUNCTION RENORMALIZATION:' )
      IF ( PWBGSW .OR. BADSW )  write (6, 668) NWP, LL, NFIRST,
     1  I, AA1
 668  FORMAT ( ' NWP, LL =', I2, I4, '  NFIRST =', I4,
     1  '  NEW NFIRST =', I4, '  RENORM =', D11.3  )
      NFIRST = ISTRT
C
C*********  REVIEW THESE 3 LINES IF/WHEN TENSOR FITS ARE ADDED.
      ALPHAR = 1.                                                       31550   
      ALPHAI = 0.
CCC      IF ( NUMFIT .NE. 0 )  GO TO 880
C
C  STORE NORMALIZED WAVE FUNCTIONS
C
C     CR AND CI WILL NORMALIZE THE WAVEFUNCTION TO
C
C       U(L) ---> ( (1+S)*F(L) + I (1-S)*G(L) ) / 2
C
C     FOR STAND-ALONE CALCULATIONS WE MAY INSTEAD USE A NORMALIZATION   31560   
C     THAT RESULTS IN REAL U(L) FOR REAL POTENTIALS.  THIS NORM
C     IS COMPUTED AND APPLIED IN WAVEF.
C
 750  N2 = NSTEP+2
      DO 779 I = ISTRT, N2
         DO 759 IL = 1, 4
            U1R(IL,1) = WAVR(I+1,IL,1)
            U1I(IL,1) = WAVI(I+1,IL,1)
 759     CONTINUE
         DO 769 IL = 1, 2                                               31570   
            DO 764 ILAS = 1, 2
               WAVR(I+1,IL,ILAS)
     1            = U1R(IL,1)*CR(1,ILAS) - U1I(IL,1)*CI(1,ILAS)
     2            + U1R(IL,2)*CR(2,ILAS) - U1I(IL,2)*CI(2,ILAS)
               WAVI(I+1,IL,ILAS)
     1            = U1R(IL,1)*CI(1,ILAS) + U1I(IL,1)*CR(1,ILAS)
     2            + U1R(IL,2)*CI(2,ILAS) + U1I(IL,2)*CR(2,ILAS)
 764        CONTINUE
 769     CONTINUE
 779  CONTINUE                                                          31580   
C
C     IF NECESSARY, CONTINUE THE INTEGRATION USING JUST COULOMB
C
      NSTEP2 = NSTP2S(NWP)
      IF ( NSTEP2 .LE. NSTEP )  GO TO 800
C
      NSTEP = NSTEP+1
      RT = NSTEP*STEPSZ
      DLSQ(1) = DLSQ(1) * XFACS(3,NWP)
      DLSQ(2) = DLSQ(2) * XFACS(3,NWP)                                  31590   
C
      DO 789  I = NSTEP, NSTEP2
         RINV = 1./RT
         DO 787 IL = 1, 2
            D = 12. / ( XFACS(1,NWP) + RINV*( XFACS(2,NWP)
     1        + DLSQ(IL)*RINV ) )
            DO 784 ILAS = 1, 2
               WAVR(I+3,IL,ILAS) = (-10.)*WAVR(I+2,IL,ILAS)
     1           + WAVR(I,IL,ILAS) - WAVR(I+1,IL,ILAS)
               WAVI(I+3,IL,ILAS) = (-10.)*WAVI(I+2,IL,ILAS)             31600   
     1           + WAVI(I,IL,ILAS) - WAVI(I+1,IL,ILAS)
               WAVR(I+1,IL,ILAS) = D*WAVR(I+3,IL,ILAS)
               WAVI(I+1,IL,ILAS) = D*WAVI(I+3,IL,ILAS)
 784        CONTINUE
 787     CONTINUE
         RT = RT + STEPSZ
 789  CONTINUE
C
 800  IF ( STANSW  .OR.  NUMPTS .EQ. 0 )  GO TO 950
C                                                                       31610   
C     NOW INTERPOLATE TO THE DESIRED GRID
C
      STPINV = 1/RSTEPS(NWP)
      IMX = NSTEP2 - 2
      DO 859  IR = 1, NUMPTS
         RT = RGRID(IR)
C
C     FIND THE LOCATION OF R IN THE TABLE
C
         RBYH = RT*STPINV                                               31620   
         I = RBYH + 0.5
         I = MAX0 ( 2, MIN0 ( I, IMX ) )
         P = RBYH - I
C     USE 5-POINT LAGRANGIAN INTERPOLATION (ABRAMOWITZ & STEGUN 25.2.15)
         PS = P*P
         X1 = P*(PS-1.)*OVER24
         X2 = X1 + X1
         X3 = X1*P
         X4 = X2 + X2 - 0.5*P
         X5 = X4*P                                                      31630   
         C1 = X3 - X2
         C5 = X3 + X2
         C3 = X5 - X3
         C2 = X5 - X4
         C4 = X5 + X4
         C3 = C3 + C3 + 1.
         II = IR
         DO 849 IL = 1, 4
            ALLOC4(LWAVRS+II) = C1*WAVR(I-1,IL,1) - C2*WAVR(I,IL,1)
     1     + C3*WAVR(I+1,IL,1) - C4*WAVR(I+2,IL,1) + C5*WAVR(I+3,IL,1)  31640   
            ALLOC4(LWAVIS+II) = C1*WAVI(I-1,IL,1) - C2*WAVI(I,IL,1)
     1     + C3*WAVI(I+1,IL,1) - C4*WAVI(I+2,IL,1) + C5*WAVI(I+3,IL,1)
         II = II + NUMPTS
 849     CONTINUE
C
 859  CONTINUE
C
C     MOVE THE DESIRED WAVE FUNCTION FROM THE STORAGE ARRAY
C     TO THE OUTPUT ARRAY.
C                                                                       31650   
 900  IF ( STANSW  .OR.  NUMPTS .EQ. 0 )  GO TO 950
      I = ( (L-LL)/2 + LAS-LL ) * NUMPTS
      LWAVRS = LWAVRS + I
      LWAVIS = LWAVIS + I
      DO 919 IR = 1, NUMPTS
         WAVER(IR) = ALLOC4(LWAVRS+IR)
         WAVEI(IR) = ALLOC4(LWAVIS+IR)
 919  CONTINUE
C
 950  TIMES(3) = TIMES(3) + second() - T2                               31660   
      RETURN
      END
C*ID* WAVINH   C109.PTOLEMY.SOURCE                          PER701  11:
      SUBROUTINE WAVINH ( NFIRST, NSTEP, WAVR, WAVI,
     1  RHSR, RHSI, FLP, NSTPDM )
C
C     NUMEROV LOOP FOR INHOMOGENEOUS WAVEFUNCTIONS
C
C     4/17/80 - REMOVED FROM COUPLN - S.P.
C     4/19/80 - RHS MADE REAL*8 - S.P.                                  31670   
C     7/28/80 - SPLIT LOOP FOR CRAY VERSION - S.P.
C
C
      implicit real*8 ( a-h, o-z )                                      implicit
C
      REAL*8  WAVR(1), WAVI(1)                                          cnr
CRA      REAL*8  WAVR(NSTPDM, 3), WAVI(NSTPDM, 3)
      REAL*8  RHSR(1), RHSI(1)
C
C                                                                       31680   
C      NUMEROV METHOD (A LA RAYNAL) IS USED IN THE FOLLOWING LOOP
C
C     WE DEFINE
C       W(I) = 1 - (H**2/12)*(V(I)/E - 1)
C       XSI(I) = W(I)*U(I)/12
C     WHERE
C       V(I) = V(I*STEPSZ) = V(I*H/K)
C     CONTAINS THE COMPLETE NUCLEAR, COULOMB AND CENTRIFIGAL POTENTIALS.
C     W(I) IS COMPUTED BY COUPLN BEFORE CALLING US.
C                                                                       31690   
C     THE DESIRED WAVEFUNCTION IS
C       U(I) = U(I*STEPSZ)
C     EXCEPT THAT HERE WE REALLY COMPUTE 12*U WHICH IS WHAT
C     IS DESIGNATED AS U BELOW  ( U = 12*PSI*R ).
C
C     AT STEP I IN THE LOOP, THE WAVR AND WAVI ARRAYS CONTAIN:
C
C     WAV_(...)   CONTENTS
C          I-1    U(I-2)     NOT USED
C          I      U(I-1)                                                31700   
C          I+1    XSI(I-2),   CHANGED TO U(I) DURING STEP
C          I+2    XSI(I-1)
C          I+3    W(I-1), NOT USED, CHANGED TO XSI(I) DURING STEP
C          I+4    W(I)
C
C     THE SMALLEST POSSIBLE NFIRST IS 2 WHICH RESULTS IN ISTRT=0.
C     THE U AND XSI FOR NFIRST-2, NFIRST-1 HAVE ALREADY BEEN STORED.
C
C
      D = 12.D0/( WAVR(NFIRST+4)**2 + WAVI(NFIRST+4)**2 )               31710   
C
      DO 210 I = NFIRST,NSTEP                                           cnr
C
         WAVR(I+3) = 10.D0*(RHSR(I)-WAVR(I+2)) + (WAVR(I)-              cnr
     1     WAVR(I+1)+RHSR(I+1)+RHSR(I-1) )                              cnr
         WAVI(I+3) = 10.D0*(RHSI(I)-WAVI(I+2)) + (WAVI(I)-              cnr
     1     WAVI(I+1)+RHSI(I+1)+RHSI(I-1) )                              cnr
         WAVR(I+1) = (WAVR(I+4)*WAVR(I+3)+                              cnr
     1     WAVI(I+4)*WAVI(I+3))*D                                       cnr
         WAVI(I+1) = (WAVR(I+4)*WAVI(I+3)-                              31720   
     1     WAVI(I+4)*WAVR(I+3))*D                                       cnr
         D = (12.D0/(WAVR(I+5)**2+WAVI(I+5)**2))                        cnr
C
 210  CONTINUE                                                          cnr
C
C     FOR CRAY WE DO AS MUCH A POSSIBLE IN VECTOR MODE
C
CRA      DO 199  I = NFIRST, NSTEP
CRA         WAVR(I+4,2) = WAVR(I+4,1) * ( 12./(WAVR(I+4,1)**2 +
CRA     1        WAVI(I+4,1)**2) )                                      31730   
CRA         WAVI(I+4,2) = WAVI(I+4,1) * ( 12./(WAVR(I+4,1)**2 +
CRA     1        WAVI(I+4,1)**2) )
CRA         WAVR(I,3) = 10*RHSR(I) + RHSR(I-1) + RHSR(I+1)
CRA         WAVI(I,3) = 10*RHSI(I) + RHSI(I-1) + RHSI(I+1)
CRA 199  CONTINUE
C
CRA      DO 299  I = NFIRST, NSTEP
CRA         WAVR(I+3,1) = WAVR(I,3) - 10.*WAVR(I+2,1) + WAVR(I,1) -
CRA     1      WAVR(I+1,1)
CRA         WAVI(I+3,1) = WAVI(I,3) - 10.*WAVI(I+2,1) + WAVI(I,1) -     31740   
CRA     1      WAVI(I+1,1)
CRA         WAVR(I+1,1) = WAVR(I+4,2)*WAVR(I+3,1) +
CRA     1       WAVI(I+4,2)*WAVI(I+3,1)
CRA         WAVI(I+1,1) = WAVR(I+4,2)*WAVI(I+3,1) -
CRA     1       WAVI(I+4,2)*WAVR(I+3,1)
CRA 299  CONTINUE
C
      FLP = 24*(NSTEP-NFIRST+1)
C
      RETURN                                                            31750   
      END
C*ID* WAVPOT   C109.PTOLEMY.SOURCE                          PER701  11:
      SUBROUTINE WAVPOT (IRET)
C
C     GETS L-DEPENDENT STUFF (COULOMB FCNS, S-ARRAYS) FOR WAVELJ
C
C     THIS IS THE SECOND PART OF THE OLD WAVEF.  IT SETS UP THE
C     ARRAYS FOR THE S-MATRICES AND FINDS THE COULOMB
C     BOUNDRY CONDITIONS.  POINTERS AND PARAMETERS ARE LEFT IN 2-ELEMENT
C     ARRAYS THAT ARE LABELED BY THE CHANNEL NUMBER ( ICHANW = 1, 2 ).  31760   
C
C     2/4/75 - MASSIVE RUPTURE OF WAVEF - S. P.
C     2/10/75 - COMPUTE COULOMB PHASE SHIFTS FOR INELDC
C     2/24/75 - INTEGRATE TO SEVERAL STEPS PAST LARGEST R NEEDED
C     2/25/75 - LOTS OF INPUT CHECKS; DON'T DIVIDE BY 0 DIFUSNESS
C     4/16/75 - NEW COMMON BLOCKS; REMOVE S.O. SINCE IT IS WRONG
C     4/20/75 - SPLIT INTO WAVSET AND WAVPOT.
C     5/21/75 - DO THINGS UPTO LIMOST
C     5/22/75 - POTENTIALS MOVED TO WAVELJ; STANSW
C     10/7/75 - POTENTIALS MOVED TO MAKPOT                              31770   
C     10/15/75 - ELAB-DEPENDANCE OF STEPSIZE IN ELASTIC FITS.
C     3/23/76 - USE MANCHESTER COULOMB ROUTINE
C     4/15/77 DO NOT COMPUTE POTENTIAL WHEN NOT NEEDED
C     11/20/77 - AREA FOR MAKPOT TO CONSTRUCT POTENTIAL - S.P.
C                MUCH MOVED TO WAVSET.
C     4/24/78 - REVERSE LOMOST FOR LIMOST - S.P.
C     5/24/78 - INITIALIZE SMAT TO 0 - S.P.
C     8/1/79 - STANDARD PREFIXES, S-MATRIX INDICES - RPG
C     1/18/80 - SKIP COULOMB F & G FOR C.C. - S.P.
C     4/27/80 - COMPUTE FOR ONE VALUE OF L FOR C.C. - S.P.              31780   
C     5/14/82 - DO NOT DESTROY LX - HURTS DEFORMED FITS - S.P.
C
C
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      parameter ( NUMJWORD = 12 )                                       /jblock/
      COMMON /JBLOCK/  J, JS(5),
     &  JP, JSP, JST,
     &  JPARM1, JPARM2, JPARM3
 
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      LOGICAL ONELSW, IDENSW                                            /inelcm/
      COMMON /INELCM/  JBPF, JBTF, LXMIN, LXMAX, ILILOR, ILILOI, MSTOP,
     &  IA12M, NMLOLX, ONELSW, NUMLX, IRDINT, IELCUP, LILOSZ, NUMLIS,
     &  ILIS, IBETAS(3), ICL2FF, LXSTEP, IDENSW, LSKIP,
     &  JPMIN, JPMAX, JPBASE, NJP, JTMIN, JTMAX, JTBASE, NJT,
     &  IINDXS, ISMATR, ISMATI, NSMAT, NLX, NSPLI, ITOCS,
     &  NASPLI, IUNITR, LIFIT, ILIFIT, NOLFIT, IDELSR, IDELSI
      INTEGER INDXJS(4,2)
      EQUIVALENCE ( INDXJS(1,1), JPMIN )
 
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
      COMMON /KANDM/ AKI, AKO, REDMI, REDMO, RIMAX, ROMAX, ISIGS(2),    /kandm/
     &  RSCTS(2), ASCTS(2), RCSCTS(2) ,ISMATS(2), LOMOST, LCRIT,
     &  ISCTMN, ISCTCR, ETAS(2), RCSCTP(2), RCSCTT(2), LCRITS(2),
     &  RATMSS(2), QMIN, ABAR
 
      DIMENSION  AKS(2), REDMS(2), RMAXS(2)
      EQUIVALENCE ( AKI, AKS(1) ), ( REDMI, REDMS(1) ),
     &  ( RIMAX, RMAXS(1) )
 
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
C
      CHARACTER*8  NAMES(2, 8)  /
     1  'SIN', 'SOUT',
     2  'COULFA',  'COULFB',
     3  'COULGA',  'COULGB',
     4  'COULFBA',  'COULFBB',                                          31800   
     5  'COULGBA',  'COULGBB',
     6  'COULSIGA', 'COULSIGB',
     7  'INDXEA', 'INDXEB',
     8  'TOCEA', 'TOCEB' /
c
C
C
C
      IRET = 1
      STEPSZ = RSTEPS(ICHANW)                                           31810   
      ETA = ETAS(ICHANW)
      E = ES(ICHANW)
C
      NSTEP = NSTPSS(ICHANW)
C
      I = (LOMOST+1) * MAX0( NUMFIT, 1 )
      IOFF = (IOFFIT-1) * (LOMOST+1)
      L1 = 0
      L2 = LOMOST
C                                                                       31820   
      IF ( PROBLM .NE. 24 )  GO TO 150
C
      L1 = MAX0( 0, LMIN-LXMAX )
      L2 = L1
C
C   FIRST CALCULATE WAVEF AT ASYMTOPIA SINCE GET ALL L FOR PRICE OF ONE
C
C  NEED COULOMB WAVES
C
C     WE ALLOCATE SPACE ON THE 1ST CALL TO WAVPOT WHEN FITTING          31830   
C     AT MULTIPLE ENERGIES.  THEREAFTER WE JUST FILL IN AN ADDITIONAL
C     COLUMN OF THE ARRAYS FOR EACH NEW ENERGY.
C     FOR NON-FITTING JOBS (DWBA AND ELASTIC SCATTERING), WE ALWAYS
C     HAVE   NUMFIT = 0; IOFFIT = 1.
C
 150  NF = NFS(ICHANW)
      NG = NGS(ICHANW)
      NF1 = NF1S(ICHANW)
      NG1 = NG1S(ICHANW)
C                                                                       31840   
      IF ( IOFFIT .NE. 1 )  GO TO 200
C
      NF=NALLOC(I, NAMES(ICHANW,2) )
      NG=NALLOC(I, NAMES(ICHANW,3) )
      NF1=NALLOC(I, NAMES(ICHANW,4) )
      NG1=NALLOC(I, NAMES(ICHANW,5) )
C
C     SAVE THINGS FOR USE BY WAVELJ
C
      NFS(ICHANW) = NF                                                  31850   
      NGS(ICHANW) = NG
      NF1S(ICHANW) = NF1
      NG1S(ICHANW) = NG1
C
C     NOW COMPUTE THE COULOMB WAVE FUNCTIONS
C
 200  RHO=NSTEP*HS(ICHANW)
C
C     SETUP WORKAREA FOR RCWFN (F' AND G')
C                                                                       31860   
      IWRK = IALLOC(2*(LOMOST+1))
      LWRK = Z(IWRK)
C
      CALL RCWFN ( RHO, ETA, L1, L2, ALLOC(Z(NF)+IOFF),
     1  ALLOC(LWRK), ALLOC(Z(NG)+IOFF),
     2  ALLOC(LWRK+(LOMOST+1)), 1.D-14, IFLAG )
      IF ( IFLAG .NE. 0 )  GO TO 9910
C
C  CALCULATE COULOMB FUNCTION AT NBACK STEPS BACK
C                                                                       31870   
      RHO1=(NSTEP-NBAKCM)*HS(ICHANW)
      CALL RCWFN ( RHO1, ETA, L1, L2, ALLOC(Z(NF1)+IOFF),
     1  ALLOC(LWRK), ALLOC(Z(NG1)+IOFF),
     2  ALLOC(LWRK+(LOMOST+1)), 1.D-14, IFLAG )
      IF ( IFLAG .NE. 0 )  GO TO 9910
C
C     FREE THE WORK AREA
      Z(IWRK) = -Z(IWRK)
C
C                                                                       31880   
C     COULOMB PHASE SHIFTS
C
 300  IF ( IOFFIT .EQ. 1 )
     1   ISIGS(ICHANW) = NALLOC( I, NAMES(ICHANW,6) )
C
      CALL DSGMAL ( ETA, LOMOST, ALLOC(Z(ISIGS(ICHANW))+IOFF) )
C
C     REST IS NOT DONE FOR MULTIPLE ENERGY FITS AFTER 1ST ENERGY
C
      IF ( IOFFIT .NE. 1 )  RETURN                                      31890   
C
C     ALLOCATE SPACE FOR ELASTIC S-MATRICES AND INITIALIZE THEIR
C     INDICES AND TABLES OF CONTENTS.  FORMATS ARE THE SAME AS
C     "INDXS" AND "TOCS" (SEE ANGSET AND JPTOLX COMMENTS).
C
      NLXE = 1
      IF ( SOSWS(ICHANW) )  NLXE = JSPS(ICHANW) + 1
      IINDXE(ICHANW) = NALLOC( (3*NLXE*NLXE+1)/FACFR4, NAMES(ICHANW,7) )
      CALL INIT4I ( IINDXE(ICHANW), 0 )
      I = ( NLXE**2 + 1 )/2                                             31900   
      ITOCE(ICHANW) = NALLOC ( 4*I/FACFR4, NAMES(ICHANW,8) )
      LTOCE = Z(ITOCE(ICHANW))*FACFR4 - FACFR4
      LINDXE = Z(IINDXE(ICHANW))*FACFR4 - FACFR4
      II = 1
      DO 319  LXP = 1, NLXE
         LXTMP = LXP - 1
         NLO = ( LXTMP + LXP + MOD(LXP, 2) )/2
         LDEL = 1 - NLO
         K = LINDXE + 1 + 3*LXTMP*( JSPS(ICHANW) + 2 )
         ILLOC(K) = II                                                  31910   
         ILLOC(K+1) = LDEL
         ILLOC(K+2) = NLO
         DO 309  IDEL = 1, NLO
            ILLOC(LTOCE+4*II-3) = LDEL
            ILLOC(LTOCE+4*II-2) = LXTMP
            ILLOC(LTOCE+4*II-1) = 2*LXTMP
            ILLOC(LTOCE+4*II) = 0
            II = II + 1
            LDEL = LDEL + 2
 309     CONTINUE                                                       31920   
 319  CONTINUE
C
      NUMJS(ICHANW) = II - 1
      II = 2*NUMJS(ICHANW)*(LOMOST+1)
      ISMATS(ICHANW) = NALLOC( II, NAMES(ICHANW,1) )
      CALL INIT8 ( ISMATS(ICHANW), 0.D0 )
C
      RETURN
C
C                                                                       31930   
C     ERRORS IN RCWFN
 9910 write (6, 9927) IFLAG, ETA, RHO, L1, L2
 9927 FORMAT ('-***** ERROR RETURN FROM RCWFN:', I8, 2G18.8, 2I8)
      Z(IWRK) = -Z(IWRK)
      IRET = 0
      RETURN
C
      END
C*ID* WAVSET   C109.PTOLEMY.SOURCE                          PER701  16:
      SUBROUTINE WAVSET ( IRET, ALONSW, FITSW )                         31940   
C
C     INITIALIZES THE COMPUTATION OF THE SCATTERING WAVE FUNCTIONS.
C
C     THIS IS THE FIRST PART OF THE OLD WAVEF.  IT CHECKS AND
C     PRINTS THE INPUT AND STORES EVERYTHING FOR WAVPOT.
C     ARRAYS ARE SET UP FOR THE POTENTIAL IN THE FORM TO BE USED
C     BY WAVELJ.  IN ALL CASES EXCEPT FITS THESE ARRAYS ARE FILLED.
C     POINTERS AND PARAMETERS ARE LEFT IN 2-ELEMENT
C     ARRAYS THAT ARE LABELED BY THE CHANNEL NUMBER ( ICHANW = 1, 2 ).
C                                                                       31950   
C     IRET - SET TO 0 IF AN ERROR IS DETECTED; 1 IF O.K.
C     ALONSW - LOGICAL*4 - .TRUE. MEANS THIS IS A STAND ALONE CALC.
C              .FALSE. MEANS IT IS PART OF A DWBA.
C     FITSW - .TRUE. IF CALLED FROM THE FITTER (FITEL)
C
C
C     THE POTENTIALS ARE DEFINED AS:
C
C     REAL(V) = VC - V/(1+X)
C               + (VSO+TAU*V) * 4*L.S * (1/R) * (D/DR) 1/(1+XSO)        31960   
C               + TR, TL, TP TENSOR TERMS (IF JSP = 2)
C     IMAG(V) = -VI/(1+XI)
C               + (VSOI+TAUI*VI) * 4*L.S * (1/R) * (D/DR) 1/(1+XSOI)
C               + VSI * 4*ASI * (D/DR) 1/(1+XSI)
C               + TR, TL, TP TENSOR TERMS (IF JSP = 2)
C     WHERE
C
C     X = EXP( (RVAL-R)/A )
C     XI = EXP( RVAL-RI)/AI ), ...,
C     L.S = ( JP(JP+1) - SP(SP+1) - L(L+1) )/2                          31970   
C     VC = ZP*ZT*HBARC/(ALPHA*RVAL)         RVAL > RC
C          ZP*ZT*HBARC/(2*ALPHA*RC) * (3 - (RVAL/RC)**2)  RVAL < RC
C     ALPHA = FINE STRUCTURE CONSTANT.
C
C     THE COMPUTED WAVEFUNCTIONS ARE SOLUTIONS OF THE SCHROEDINGER
C     EQUATION
C
C       ( 1/(2M) * ( -(D/DR)**2 + L(L+1)/R**2 ) + V - E ) U(R) = 0
C
C     AND ARE NORMALIZED SUCH THAT                                      31980   
C
C       U(R) ---> (1/2) * ( (1+S)*F(KR) + I*(1-S)*G(KR) )
C
C     WHERE F(KR) AND G(KR) ARE THE REGULAR AND IRREGULAR COULOMB
C     FUNCTIONS AND S IS THE S-MATRIX.
C
C
C     2/4/75 - MASSIVE RUPTURE OF WAVEF - S. P.
C     2/10/75 - COMPUTE COULOMB PHASE SHIFTS FOR INELDC
C     2/24/75 - INTEGRATE TO SEVERAL STEPS PAST LARGEST R NEEDED        31990   
C     2/25/75 - LOTS OF INPUT CHECKS; DON'T DIVIDE BY 0 DIFUSNESS
C     4/16/75 - NEW COMMON BLOCKS; REMOVE S.O. SINCE IT IS WRONG
C     4/20/75 - SPLIT INTO WAVSET AND WAVPOT.
C     5/22/75 - ALONSW ADDED; VSI ADDED
C     6/10/75 - FIX ERROR IN VSI CONSTANT
C     6/27/75 - STEPSPER; NEW RC UNDEF CHECK
C     8/3/75 - ETAS INTO KANDM COMMON.
C     10/7/75 - POTENTIALS IN MAKPOT; PRINT R0'S - S.P.
C     10/10/75 - PROCESS ENERGY DEPENDANCE IN A, AI, V, VI.
C     10/20/75 - ESQ PARAMETERS                                         32000   
C     1/31/76 - NEW PWAVSW SETTING
C     2/15/76 - ADD PWBGSW
C     4/30/76 - MODIFIED COULOMB INPUT(MHM)
C     8/1/76 - 1/ELAB EXPANSION
C     4/25/77 - IDENTICAL PARTICLES, FITSW
C     10/16/77 - POWERS OF WOODS-SAXONS
C     11/20/77 - NEW ASYMPTOPIA; STORE POTENTIAL DEPTHS WITHOUT 1/E;
C                NOLONGER USE A IN STEPSPER; PIECES OF WAVPOT HERE NOW.
C     11/25/77 - LINKULES
C     12/1/77 - LCRITL NOW CALLED HERE - S.P.                           32010   
C     12/4/77 - SAVE LINKULE STUFF FOR DWBA IN LOCFIT - S.P.
C     2/10/78 - LINKULES FOR WAVEFUNCTIONS - S.P.
C     5/5/78 - CENTRIFIGAL BARRIER IN AN ARRAY - S.P.
C     5/21/78 - NEW WAVELJ STRUCTURES - S.P.
C     12/11/78 - ADD TENSOR POTENTIALS - RPG
C     2/19/79 - REDUCE VARIABLE ASYMPTOPIA - RPG
C     3/18/79 - SAVE ALL OF /LNKBLK/ IN LNKAD2 - S.P.
C     5/4/79 - RATMAS CHANGES; DEFINE RC0P FOR PRINT - S.P.
C     9/12/79 - STANDARD PREFIXES ETC; DELETE NUMJS DEFINITION
C        (NOW IN WAVPOT) - RPG                                          32020   
C     1/18/80 - DON'T CHANGE ASYMP & STEPSIZE FOR C.C. - S.P.
C     4/23/80 - USE PWBGSW INSTEAD OF PBUGSW - S.P.
C     6/3/80 - SET LMIN=0 WHEN LCRITL=0, CHANGE PARPRT - S.P.
C     7/16/80 - REMOVE LOGICAL SOSWT - S.P.
C     7/22/80 - FOR NEW CRAY VERSION USE 3*NPTS WORK ARRAYS -SP
C     7/29/81 - SET LX=0 FOR DEFORMED POTENTIALAS -S.P.
C     10/18/81 - SET LX=-1 AS FLAG FOR DEFORMED POTS - S.P.
C     10/16/84 - DO NOT ADJUST ASYMP IF SCATASYM WAS READ IN - S.P.
C     12/19/84 - VSI MAY BE COMPUTED BY A LINKULE - S.P.
C                                                                       32030   
C
      implicit real*8 ( a-h, o-z )                                      implicit
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      parameter ( NUMJWORD = 12 )                                       /jblock/
      COMMON /JBLOCK/  J, JS(5),
     &  JP, JSP, JST,
     &  JPARM1, JPARM2, JPARM3
 
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
c                                                                       /lnkblk/
c  STRUCTURE OF   /LNKBLK/
c
c  THERE IS A BLOCK OF 3 DOUBLE WORDS FOR EACH POSSIBLE USE
c  OF A LINKULE.  THE NUMLNK = NUMLINKULES USES ARE IN THE ORDER
c    REALPOTEN  IMAGPOTEN  REALVSO  IMAGVSO  COULOMB
c    WAVEFUNCTION  AND 6 TENSOR POTENTIALS
c  THE THREE-DOUBLE-WORD BLOCKS EACH HAVE THE STRUCTURE
c
c    LNKNAM(1,I)   LINKULE NAME
c
c      LNKADR(3,I)   LINKULE ADDRESS, O IF NO LINKULE IN USE.
c      LNKADR(4,I)   0 - NO L OR J DEPENDENCE IN POTENTIAL
c                    1 - L DEPENDENCE BUT NO J DEPENDENCE
c                    2 - BOTH L  AND J DEPENDENCE
c
c      LNKADR(5&6,I)  MYINTS - A TWO-ELEMENT ARRAY THAT THE
c                     LINKULE MAY USE FOR COMMUNICATION BETWEEN
c                     CALLS TO ITSELF.
c
      parameter ( NUMLINKULES = 13 )
      COMMON /LNKBLK/  NUMLNK, IUNIQU, LNKADR(6,NUMLINKULES)
      character*8  LNKNAM(3,NUMLINKULES)
      EQUIVALENCE ( LNKNAM(1,1), LNKADR(1,1) )
 
      COMMON /KANDM/ AKI, AKO, REDMI, REDMO, RIMAX, ROMAX, ISIGS(2),    /kandm/
     &  RSCTS(2), ASCTS(2), RCSCTS(2) ,ISMATS(2), LOMOST, LCRIT,
     &  ISCTMN, ISCTCR, ETAS(2), RCSCTP(2), RCSCTT(2), LCRITS(2),
     &  RATMSS(2), QMIN, ABAR
 
      DIMENSION  AKS(2), REDMS(2), RMAXS(2)
      EQUIVALENCE ( AKI, AKS(1) ), ( REDMI, REDMS(1) ),
     &  ( RIMAX, RMAXS(1) )
 
      COMMON / TEMPVS /  TVR, TVI, TVSOR, TVSOI, TAR, TAI               /tempvs/
 
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
      REAL*4  TBEGIN, TIMES                                             /ftimef/
      COMMON /FTIME/ TBEGIN, NUMLOP, NUMWAV, TIMES(6), NUMCAL, NUMGRA
 
      COMMON /LOCFIT/  LNKAD2(6,2,NUMLINKULES)                          /locfitf
 
C
      LOGICAL ALONSW, FITSW
      CHARACTER*8  CHANAM(2), STATWD(2), SOTNAM(2), NAMES(2,11)
      CHARACTER*4  TENNAM(6)
      CHARACTER*1  LINKID(4)                                            32050   
      character*8  linkfmtout
      equivalence ( linkfmtout, linkid(1) )
C
      DATA  CHANAM / 'INCOMING', 'OUTGOING' /
      DATA  STATWD / 'BOSONS', 'FERMIONS' /
      DATA  SOTNAM / 'SPIN-ORB', 'TENSOR' /
      DATA  TENNAM / 'TR', 'TRI', 'TL', 'TLI', 'TP', 'TPI' /
      DATA  NAMES /
     7  'REALVA', 'REALVB',
     8  'IMAGVA', 'IMAGVB',                                             32060   
     9  'REALVSOA', 'REALVSOB',
     A  'IMAGVSOA', 'IMAGVSOB' ,
     B  'CENTRIFA', 'CENTRIFB' ,
     C  'REALVTRA', 'REALVTRB',
     D  'IMAGVTRA', 'IMAGVTRB',
     E  'REALVTLA', 'REALVTLB',
     F  'IMAGVTLA', 'IMAGVTLB',
     G  'REALVTPA', 'REALVTPB',
     H  'IMAGVTPA', 'IMAGVTPB' /
C                                                                       32070   
      DATA  LINKID / '*', '1', '0', '0' /
C
      LOGICAL SOSW, SOISW, IMAGSW, TENSW
c
C
      IPRNT = 0
      IF ( FITSW )  GO TO 10
      NUMFIT = 0
      IOFFIT = 1
      IPRNT = MOD( IPRINT, 10 )                                         32080   
 10   PWAVSW = MOD(IPRINT/1000, 10) .GE. 1
      PWBGSW = MOD(IPRINT/1000, 10) .GE. 4
C
      STANSW = ALONSW
C
C     SOME OF THE PARAMETERS CAN HAVE AN ENERGY DEPENDENCE WHICH
C     IS EXPRESSED IN TERMS OF THE LABORATORY ENERGY
C
      EELAB = (1+RATMAS)*E
      EEMUL=EELAB                                                       32090   
      IF(IEPOW.EQ.1) EEMUL=1/EELAB
      TVR = V + VE*EEMUL + VESQ*EEMUL**2
      TVI = VI + VIE*EEMUL + VIESQ*EEMUL**2
      TAR = A + AE*EEMUL + AESQ*EEMUL**2
      TAI = AI + AIE*EEMUL + AIESQ*EEMUL**2
C
C     IS THERE AN IMAGINARY PART FOR THE POTENTIAL
C
      IMAGSW = TVI .NE. 0
C                                                                       32100   
C     IS THERE A SPIN-ORBIT POTENTIAL
C
      TVSOR = VSO + TAU*TVR
      TVSOI = VSOI + TAUI*TVI
      SOSW = TVSOR .NE. 0
      SOISW = TVSOI .NE. 0
      SOSWT = SOSW .OR. SOISW
C
C     IS THERE A TENSOR POTENTIAL?
C                                                                       32110   
      TCSWS(ICHANW) = VTR .NE. 0  .OR.  VTRI .NE. 0  .OR.
     1  VTP .NE. 0  .OR.  VTPI .NE. 0
      TENSW = TCSWS(ICHANW)  .OR.  VTL .NE. 0  .OR.  VTLI .NE. 0
      SOSWS(ICHANW) = SOSWT .OR. TENSW
C
C     TEST THE INPUT AND RETURN  0  COMPLETION CODE IF BAD
C
      IRET = 1
      IF ( LNKADR(3,1) .NE. 0 )  GO TO 25
      IF ( R .GT. 0  .AND.  TAR .GT. 0 )  GO TO 25                      32120   
      write (6, 23) R, TAR
 23   FORMAT ('0**** R OR A HAS INVALID VALUE:', 2G15.5 )
      IRET = 0
 25   IF ( .NOT. IMAGSW )  GO TO 30
      IF ( LNKADR(3,2) .NE. 0 )  GO TO 30
      IF ( RI .GT. 0  .AND.  TAI .GT. 0 )  GO TO 30
      write (6, 27) RI, TAI
 27   FORMAT ( '0**** RI OR AI HAS INVALID VALUE:', 2G15.5 )
      IRET = 0
 30   IF ( .NOT. SOSW )  GO TO 34                                       32130   
      IF ( LNKADR(3,3) .NE. 0 )  GO TO 34
      IF ( RSO .GT. 0  .AND.  ASO .GT. 0 )  GO TO 34
      write (6, 31) RSO, ASO
 31   FORMAT ( '0**** RSO OR ASO HAS INVALID VALUE:', 2G15.5 )
      IRET = 0
C
C     CHECK  SP  FOR EITHER REAL OR IMAG SPIN ORBIT.
C
 34   IF ( JSP .NE. NOTDEF  .OR.  .NOT. SOSWS(ICHANW) )  GO TO 40
      JSP = 1                                                           32140   
      IF (TENSW) JSP = 2
      write (6, 35) JSP, SOTNAM(JSP)
 35   FORMAT ( '0**** WARNING:  SP WAS NOT DEFINED; ',
     1  'IT IS ASSUMED TO BE ', I1, '/2 FOR THE ', A8, ' FORCE.' )
 40   IF ( E .GT. 0  .AND.  AM .GT. 0 )
     1  GO TO 45
      write (6, 43) E, AM
 43   FORMAT ('0**** ENERGY OR M (REDUCED MASS) HAS INVALID',
     1  ' VALUE:', 3G15.5 )
      IRET = 0                                                          32150   
 45   IF ( AMP .NE. UNDEF  .AND.  AMT .NE. UNDEF )  GO TO 50
      write (6, 47)
 47   FORMAT ( '0**** BOTH MP AND MT MUST BE DEFINED.' )
      IRET = 0
 50   IF ( RC .LT. ASYMPT )  GO TO 60
      write (6, 53) RC, ASYMPT
 53   FORMAT ('0**** RC MUST BE LESS THAN ASYMPTOPIA:', 2G15.5 )
      IRET = 0
 60   RCC = RC
      IF ( RC .EQ. UNDEF )  WASSET(9) = .TRUE.                          32160   
      IF ( RC .EQ. UNDEF )  RCC = 1
      IF ( IZP*IZT .EQ. 0 )  GO TO 70
      IF ( RC .GT. 0 )  GO TO 70
      write (6, 63) RC
 63   FORMAT ('0**** RC IS INVALID:', G15.5 )
      IRET = 0
  70  RC = RCC
      IF ( VSI .EQ. 0 )  GO TO 80
      IF ( LNKADR(3,2) .NE. 0 )  GO TO 80
      IF ( RSI .GT. 0  .AND.  ASI .GT. 0 )  GO TO 80                    32170   
      write (6, 73) RSI, ASI
 73   FORMAT ( '0**** RSI OR ASI IS INVALID:', 2G15.5 )
      IRET = 0
 80   IF ( .NOT. SOISW )  GO TO 90
      IF ( LNKADR(3,4) .NE. 0 )  GO TO 90
      IF ( RSOI .GT. 0  .AND.  ASOI .GT. 0 )  GO TO 90
      write (6, 83) RSOI, ASOI
 83   FORMAT ( '0**** RSOI OR ASOI HAS INVALID VALUE:', 2G15.5 )
C
 90   IF ( .NOT. TENSW ) GO TO 100                                      32180   
      IF (JSP .EQ. 2)  GO TO 93
      write (6, 91) JSP
 91   FORMAT ( '0**** SP MUST BE 1 FOR TENSOR POTENTIALS, SP =',
     1  I8, '/2' / ' **** TENSOR POTENTIALS ARE SET TO 0' )
      DO 92  I = 1, 6
         VTEN(I) = 0
 92   CONTINUE
      TENSW = .FALSE.
      TCSWS(ICHANW) = .FALSE.
      SOSWS(ICHANW) = SOSWT                                             32190   
 93   DO 95 I = 1, 6
      IF ( VTEN(I) .EQ. 0 ) GO TO 95
      IF ( LNKADR(3,I+4) .NE. 0 ) GO TO 95
      IF ( RTEN(I) .GT. 0  .AND.  ATEN(I) .GT. 0 ) GO TO 95
      write (6, 94)  TENNAM(I), TENNAM(I), RTEN(I), ATEN(I)
 94   FORMAT ( '0**** R', A3, ' OR A', A3, ' HAS INVALID VALUE:',
     1  2G15.5 )
      IRET = 0
 95   CONTINUE
 100  IF ( IRET .EQ. 0 )  RETURN                                        32200   
C
      NBAKCM = NBACK
C
C
C  SOME DERIVED DATA
C
C  K VALUE
C
      UK=DSQRT(2*AM*E)/HBARC
C                                                                       32210   
      ALAMBD = 2*PI/UK
C
C  COULOMB PARAMETER AND SIMPLE TERMS USING IT
C     INITIALIZE THE COULOMB POTENTIAL
C
      ETA=(IZP*IZT)*DSQRT(AM/(2.D0*E))/AFINE
      CALL SETVSQ(RCT,RCP,IZT,IZP,ICHANW)
C
C     COUPLED CHANNELS REQUIRE THE SAME STEPSIZE IN ALL CHANNELS
C                                                                       32220   
      IF ( PROBLM .LT. 23  .OR.  ICHANW .EQ. 1 )  GO TO 110
      RMAX = ASYMPS(1)
      STEPSZ = RSTEPS(1)
      GO TO 120
C
C
 110  IF ( STPSPR .NE. UNDEF )  STEPSZ = DMIN1( ALAMBD, 1.D0 ) / STPSPR
C
      RMAX = ASYMPT
C                                                                       32230   
C     ADJUST ASYMPTOPIA IF THERE WILL BE VERY LARGE L'S.
C     MATCHING MUST BE AT OR OUTSIDE THE CLASSICAL TURNING POINT.
C     HOWEVER, FITTER DOES NOT ALLOW VARIABLE ASYMPTOPIA RIGHT NOW
C     ALSO IF SCATASYM WAS READ IN, WE DO NOT OVERRIDE IT
C
      IF ( NUMFIT .EQ. 0  .AND.  LMAX .NE. NOTDEF .AND. SCTASY .LT. 0 )
     1  RMAX = MAX( RMAX, (ETA + DSQRT(ETA**2+LMAX*(LMAX+1)) )/UK )
C
C     NOTE - NSTEP IS COMPUTED HERE SEPARATLY FOR EACH CHANNEL
C     AND IS STORED IN /WAVCOM/.  IT NEED NOT BE RELATED TO THE         32240   
C     "NSTEPS" USED IN THE BOUND STATE CALCULATION.  HOWEVER, IF
C     ASYMPT AND STEPSZ  ARE THE SAME FOR THE ENTIRE JOB, THEN
C        NSTEP = NSTEPS-1.
C
 120  NSTEP = RMAX/STEPSZ + .5
      RMAX = NSTEP*STEPSZ
      H=UK*STEPSZ
C
C     TEST FOR IDENTICAL PARTICLES
C                                                                       32250   
      LSKIP = 1
      ISTAT = 3
      IF ( IZP .NE. IZT  .OR.  AMP .NE. AMT  .OR.  JSP .NE. JST
     1  .OR.  EXSPT(1) .NE. EXSPT(2) )  GO TO 150
      IF ( JSP .NE. NOTDEF )  GO TO 135
      write (6, 133)
 133  FORMAT ( '0*** WARNING:  THE PARTICLES APPEAR TO BE IDENTICAL',
     1    ' BUT THEIR SPINS HAVE NOT BEEN DEFINED;' /
     2  15X, 'NON-IDENTICAL PARTICLE SCATTERING WILL BE ASSUMED.' )
      GO TO 150                                                         32260   
 135  IF ( JSP .EQ. 0 )  LSKIP = 2
      ISTAT = iand(JSP, 1) + 1
C
C
C     SAVE THINGS FOR WAVPOT AND WAVELJ
C
 150  HS(ICHANW)=H
      V0RS(ICHANW) =TVR
      V0IS(ICHANW) =TVI
      V0SORS(ICHANW) = TVSOR                                            32270   
      V0SOIS(ICHANW) = TVSOI
      V0SIS(ICHANW) = VSI
      RSCTS(ICHANW) = R
      ASCTS(ICHANW) = TAR
      RCSCTS(ICHANW) = RC
      RCSCTP(ICHANW) = RCP
      RCSCTT(ICHANW) = RCT
      RIS(ICHANW) = RI
      AIS(ICHANW) = TAI
      RSOS(ICHANW) = RSO                                                32280   
      ASOS(ICHANW) = ASO
      RSOIS(ICHANW) = RSOI
      ASOIS(ICHANW) = ASOI
      RSIS(ICHANW) = RSI
      ASIS(ICHANW) = ASI
      DO 159 I = 1, 6
         VTENS(ICHANW,I) = VTEN(I)
         RTENS(ICHANW,I) = RTEN(I)
         ATENS(ICHANW,I) = ATEN(I)
 159  CONTINUE                                                          32290   
      ETAS(ICHANW) = ETA
      IZPS(ICHANW) = IZP
      IZTS(ICHANW) = IZT
      ASYMPS(ICHANW) = RMAX
      ES(ICHANW) = E
      RSTEPS(ICHANW) = STEPSZ
      NSTPSS(ICHANW) = NSTEP
      NSTP2S(ICHANW) = NSTEP
      AKS(ICHANW) = UK
      write(0,'(A,I2,A,E18.12,A,E18.12,A,E18.12)')
     &  'FTN_WAVSET ch=',ICHANW-1,' k=',UK,' E=',E,' mu=',AM
      REDMS(ICHANW) = AM                                                32300   
      RATMSS(ICHANW) = RATMAS
      JSPS(ICHANW) = JSP
      STEPR = STEP1R
      STEPI = STEP1I
      NUMAIT = NAITKN
      NUMLOP = 0
      NUMWAV = 0
      LSKIPS(ICHANW) = LSKIP
      ISTATS(ICHANW) = ISTAT
      POWRLS(ICHANW) = POWRL                                            32310   
      POWIMS(ICHANW) = POWIM
      IWAVRS(ICHANW) = 0
      IWAVIS(ICHANW) = 0
C
C     QUANTITIES FOR INTEGRATION PAST ASYMPTOPIA
C
      XFACS(1,ICHANW) = 1 + H**2/12
      XFACS(2,ICHANW) = - (H**2/12) * IZP*IZT*HBARC/(E*AFINE)
      XFACS(3,ICHANW) = - (H**2/12) / UK**2
      TIMES(1) = 0                                                      32320   
      TIMES(2) = 0
      TIMES(3) = 0
C
C     INITIALIZE LINKULES IF NEEDED
C
      DO 259  I = 1, NUMLNK
         IF ( LNKADR(3,I) .EQ. 0 )  GO TO 259
C
C     GENERATE THE SPECIAL UNIQUE NAME
C                                                                       32330   
         IUNIQU = IUNIQU + 1
ccc         CALL I4LIT ( IUNIQU, LINKID(2), -3 )
         write ( unit=LINKfmtout, fmt='("*", i3.3)' )  IUNIQU
ccc         write (6,*) 'formatted linkid: ', linkfmtout, '__', linkid
C
C     MAKE INITIALIZING CALL
C
         CALL LINKUL ( LNKADR(3,I), LNKNAM(1,I), LNKADR(5,I), I, 1,
     1      IRET, L, J, 0.D0, STEPSZ, NSTEP+1, DUMMY, DUMMY, LINKID )
         IF ( IRET .GE. 0 )  GO TO 240                                  32340   
         IRET = 0
         RETURN
 240     LNKADR(4,I) = IRET
 259  CONTINUE
C
      IF ( IPRNT .LT. 1 )  GO TO 600
C
C     PRINT OUT INPUT NICELY
C
 420  write (6, 423) CHANAM(ICHANW)                                     32350   
 423  FORMAT ( / '0', T10, 'OPTICAL MODEL SCATTERING FOR THE ',
     1     A8, ' CHANNEL' )
      write (6, 424) EELAB, E, UK, ALAMBD, AMP, AMT, AM
 424  FORMAT ( '0E LAB =', F9.3, ' MEV,    E CM =', F9.3,
     1     ' MEV,     K =', G12.5, 5X, 'WAVELENGTH =', F8.4, ' FM' /
     2  ' PROJECTILE MASS =', F7.2, ' AMU,', 5X,
     3    'TARGET MASS =', F7.2, ' AMU,', 5X,
     4    'REDUCED MASS =', F10.2, ' MEV/C**2' )
      IF ( ISTAT .EQ. 3 )  write (6, 425)
 425  FORMAT ( ' THIS IS NON-IDENTICAL PARTICLE SCATTERING')            32360   
      IF ( ISTAT .NE. 3 )  write (6, 426) STATWD(ISTAT)
 426  FORMAT ( ' THIS IS SCATTERING OF IDENTICAL ', A8 )
      IF ( JSP .NE. NOTDEF  .AND.  JST .NE. NOTDEF )
     1  write (6, 427) JSP, JST
 427  FORMAT ( ' PROJECTILE SPIN =', I3, '/2', 5X, 'TARGET SPIN =',
     1  I3, '/2' )
      write (6, 429) IZP, IZT
 429  FORMAT ( ' Z PROJECTILE =', I4, 5X, 'Z TARGET =', I4 /
     6  '0POTENTIAL', T20, 'COUPLING CONS.', T38, 'RADIUS',
     7      T48, 'DIFFUSENESS', T63, 'RADIUS PARAMETER'  )              32370   
C
      IRET = 1
      CALL PARPRT ( 1, 'REAL CENTRAL       ', TVR, R, TAR,
     1  R/R0MASS, POWRL, '   POWER', IRET )
      CALL PARPRT ( 2, 'VOLUME ABSORPTION   ', TVI, RI, TAI,
     1  RI/R0MASS, POWIM, '   POWER   ', IRET )
      CALL PARPRT ( 13, 'SURFACE ABSORPTION   ', VSI, RSI, ASI,
     1  RSI/R0MASS, 0.D0, '        ', IRET )
      CALL PARPRT ( 3, 'REAL SPIN-ORBIT    ', VSO, RSO, ASO,
     1  RSO/R0MASS, TAU, '     TAU', IRET )                             32380   
      CALL PARPRT ( 4, 'IMAG. SPIN-ORBIT   ', VSOI, RSOI, ASOI,
     1  RSOI/R0MASS, TAUI, '    TAUI', IRET )
      CALL PARPRT ( 7, 'REAL TR           ', VTR, RTR, ATR,
     1  RTR/R0MASS, 0.0D0, '        ', IRET )
      CALL PARPRT ( 8, 'IMAGINARY TR      ', VTRI, RTRI, ATRI,
     1  RTRI/R0MASS, 0.0D0, '        ', IRET )
      CALL PARPRT ( 9, 'REAL TL           ', VTL, RTL, ATL,
     1  RTL/R0MASS, 0.0D0, '        ', IRET )
      CALL PARPRT ( 10, 'IMAG. TL          ', VTLI, RTLI, ATLI,
     1  RTLI/R0MASS, 0.0D0, '        ', IRET )                          32390   
      CALL PARPRT ( 11, 'REAL TPR          ', VTP, RTP, ATP,
     1  RTP/R0MASS, 0.0D0, '        ', IRET )
      CALL PARPRT ( 12, 'IMAG. TPR         ', VTPI, RTPI, ATPI,
     1  RTPI/R0MASS, 0.0D0, '        ', IRET )
      CALL PARPRT ( 5, 'PT&SPHERE  COULOMB ', ETA, RC, 0.D0,
     1  RC/R0MASS, 0.0D0, '        ', IRET )
      IF((RCP.EQ.0).OR.(RCT.EQ.0)) GO TO 500
      TEMP2 = RCP/AMP**0.33333333333333333333333 0D0
      TEMP3 = RCT/AMT**0.33333333333333333333333 0D0
      write (6, 187) RCP, RCT, TEMP2, TEMP3                             32400   
  187 FORMAT( ' FOLDED COULOMB POTENTIALS - RCP = ',F7.4,2X,
     1'RCT = ',F7.4,2X,'RC0P = ',F7.4,2X,'RC0T = ',F7.4)
C
 500  TEMP = DMIN1( ALAMBD, 1.D0 )/STEPSZ
      write (6, 503) RMAX, STEPSZ, TEMP
  503 FORMAT(
     1  '0ASYMPTOPIA =', T15, F8.3, ' FM' /
     2  ' STEP SIZE =', T15, F8.3, ' FM' ,
     3    5X, F8.3, ' STEPS PER "WAVELENGTH"' / )
C                                                                       32410   
C     WILL THE WAVE FUNCTIONS BE FOUND BY A LINKULE
C
      IF ( LNKADR(3,6) .EQ. 0 )  GO TO 600
      write (6, 533) LNKNAM(1,6)
 533  FORMAT ( '0 THE SCATTERING WAVEFUNCTION IS BEING',
     1  ' COMPUTED BY THE ', A8, ' LINKULE:' )
      I = 6
C
C     CALL LINKULE TO PRINT STUFF ABOUT ITSELF
C                                                                       32420   
 560  CALL LINKUL ( LNKADR(3,I), LNKNAM(1,I), LNKADR(5,I),
     1  I, 2, IRTN,
     2  L, J, 0.D0, STEPSZ, NSTEP+1, DUMMY, DUMMY, ICHANW )
      write (6, 563)
 563  FORMAT ( ' ' )
      IRET = MIN0(IRTN, IRET)
      IF ( IRET .GE. 0 )  GO TO 600
 570  IRET = 0
      RETURN
C                                                                       32430   
C
C
C     SET ASIDE AREAS FOR THE POTENTIAL AND FOR V' USED BY WAVELJ
C     THESE ARE STORED ONLY TO ASYMPTOPIA
C
C     THIS IS DONE AS FOLLOWS:
C
C     1) FOR STAND-ALONE:  ON EVERY CALL TO WAVSET.
C     2) FOR ELASTIC FITS: MAXIMUM NUMBER OF STEPS IS ACCUMULATED IN
C        NSTPSS(2); AS THE SIZE GROWS, THEY ARE ALLOCATED.              32440   
C     3) FOR DWBA: POTENTIAL AREAS ARE ALLOCATED AT BOTH CALLS;
C        WAVEFUNCTION AREAS ARE ALLOCATED ONLY ON 2ND CALL.
C
 600  NSTPP1 = NSTEP+1
C
      IF ( NUMFIT .EQ. 0 )  GO TO 650
      IF ( NSTPSS(2) .GE. NSTEP )  GO TO 680
      NSTPSS(2) = NSTEP
C
 650  IVWORK = NALLOC( NSTPP1, 'VWORK   ' )                             32450   
      IRLVS(ICHANW) = NALLOC( NSTPP1, NAMES(ICHANW, 1) )
      IIMVS(ICHANW) = NALLOC( NSTPP1+1, NAMES(ICHANW, 2) )
      ICENTR(ICHANW) = NALLOC( NSTPP1, NAMES(ICHANW, 5) )
      ISORS(ICHANW) = 0
      ISOIS(ICHANW) = 0
      IF ( V0SORS(ICHANW) .NE. 0 )
     1  ISORS(ICHANW) = NALLOC( NSTPP1, NAMES(ICHANW, 3) )
      IF ( V0SOIS(ICHANW) .NE. 0 )
     1  ISOIS(ICHANW) = NALLOC( NSTPP1, NAMES(ICHANW, 4) )
      DO 659 II = 1, 6                                                  32460   
         ITENS(ICHANW,II) = 0
         IF ( VTENS(ICHANW,II) .NE. 0 ) ITENS(ICHANW,II) =
     1      NALLOC ( NSTPP1, NAMES(ICHANW,II+5) )
 659     CONTINUE
C
C     AND COMPUTE THE POTENTIAL
C     LX IS SET TO 0 FOR POSSIBLE USE BY DEFORMED POTENTIALS
C
 680  LXSAVE = LX
      LX = -1                                                           32470   
      CALL MAKPOT ( ICHANW, IRET )
      LX = LXSAVE
C
C     FOR DWBA MUST SAVE TWO SETS OF LINKULE INDICATORS
C
      IF ( NUMFIT .NE. 0 )  GO TO 690
      DO 685  I = 1, NUMLNK
         DO 685  II = 1, 6
            LNKAD2(II,ICHANW,I) = LNKADR(II,I)
 685  CONTINUE                                                          32480   
C
C     WORK AREA NOT NEEDED AFTER MAKPOT
C
 690  IF ( NUMFIT .EQ. 0 )  Z(IVWORK) = -Z(IVWORK)
C
      IF ( IRET .GE. 0 )  GO TO 700
      IRET = 0
      RETURN
C
C     DETERMINE LCRITICAL.                                              32490   
C     IF BOTH LMIN AND LMAX ARE DEFINED WE BYPASS THIS AND JUST USE
C     THE AVERAGE.
C
 700  IF ( LMIN .EQ. NOTDEF  .OR.  LMAX .EQ. NOTDEF )  GO TO 720
      LCRITS(ICHANW) = (LMIN+LMAX)/2
      GO TO 750
 720  CALL LCRITL ( E, UK, ETA, RC, NSTEP+1,
     1  0.D0, STEPSZ, IRLVS(ICHANW), IIMVS(ICHANW),
     2  48, MOD(IPRINT/10, 10),
     3  LC1, LC2, LCRITS(ICHANW) )                                      32500   
      IF ( IPRNT .NE. 0 )  write (6, 723) LCRITS(ICHANW), LC1, LC2
 723  FORMAT ( ' ESTIMATED CRITICAL L:', I4 ,
     1  5X, 'BY |S|:', I4, 5X, 'BY DEFLECTION FUNC.:', I4 )
C
C     IF LC1=0  THEN |S|=1 ALWAYS AND WE MUST FORCE LMIN=0.
C
      IF ( LC1 .EQ. 0  .AND.  LMIN .EQ. NOTDEF )  LMIN = 0
C
C     ON 2ND CALL ALLOCATE AREAS FOR THE WAVE FUNCTIONS USING LARGEST
C     NSTEP.                                                            32510   
C
 750  IF ( .NOT. STANSW  .AND.  ICHANW .EQ. 1 )  GO TO 800
      IF ( .NOT. STANSW )  NSTPP1 = MAX0(NSTPSS(1)+1, NSTPP1)
      I = NSTPP1+6
      NWAVEF = I
CCRA
CCRA     ON CRAY WE DO SOME OF THE WORK IN VECTOR WORK ARRAYS
CCRA
CRA      I = 3*I
C     WE NEED ROOM FOR 4 WAVE FUNCTIONS IF TENSOR COUPLING IS PRESENT.  32520   
      IF ( TCSWS(ICHANW) .OR. ( TCSWS(3-ICHANW) .AND. .NOT. STANSW ) )
     1   I = 4*I
      IWAVR = NALLOC( I, 'WAVER   ' )
      IWAVI = NALLOC( I, 'WAVEI   ' )
C
 800  IRET = 1
      RETURN
C
C
C                                                                       32530   
      END
C*ID* WFGET    C109.PTOLEMY.SOURCE                          PER701  15:
      SUBROUTINE WFGET ( L, LAS, JP, NWP, NUMPTS, RGRID, WAVER, WAVEI,
     1  WAVR, WAVI, VREAL, VIMAG, VCENT )
C
C     INTERFACE TO CALL WAVELJ OR WAVETC AS APPROPRIATE.
C
C
C     WAVETC IS CALLED IF THIS COMBINATION OF L, LAS, JP, NWP IS
C     TENSOR COUPLED.  OTHERWISE, WAVELJ IS CALLED.                     32540   
C
C     6/6/79 - NEW ROUTINE - RPG
C     6/8/79 - STANDARD PREFIXES - RPG
C     4/23/80 - USE PWBFSW INSTEAD OF PBUGSW - S.P.
C     6/4/80 - PASS NWAVEF TO WAVETC - S.P.
C
      implicit real*8 ( a-h, o-z )                                      implicit
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
      COMMON /KANDM/ AKI, AKO, REDMI, REDMO, RIMAX, ROMAX, ISIGS(2),    /kandm/
     &  RSCTS(2), ASCTS(2), RCSCTS(2) ,ISMATS(2), LOMOST, LCRIT,
     &  ISCTMN, ISCTCR, ETAS(2), RCSCTP(2), RCSCTT(2), LCRITS(2),
     &  RATMSS(2), QMIN, ABAR
 
      DIMENSION  AKS(2), REDMS(2), RMAXS(2)
      EQUIVALENCE ( AKI, AKS(1) ), ( REDMI, REDMS(1) ),
     &  ( RIMAX, RMAXS(1) )
 
C                                                                       32550   
      REAL*4 RGRID(NUMPTS), WAVER(NUMPTS), WAVEI(NUMPTS)
      DIMENSION WAVR(1), WAVI(1), VREAL(1), VIMAG(1), VCENT(1)
C
c
C
C
      IF ( PWBGSW ) write (6, 33)  L, LAS, JP, NWP, NUMPTS
 33   FORMAT ( ' WFGET:  L,LAS,JP,NWP,NUMPTS=', 5I8 )
C
C     CHECK FOR LEGALITY AND COUPLING.                                  32560   
C
      IF ( L .LT. 0 ) GO TO 200
      IF ( .NOT. SOSWS(NWP) ) GO TO 100
      IF ( JP .LT. IABS(2*L-JSPS(NWP)) ) GO TO 200
      IF ( .NOT. TCSWS(NWP) ) GO TO 100
      IF ( LAS .LT. 0  .OR.  LAS .GT. LOMOST ) GO TO 200
      IF ( JP .EQ. 2*L  .OR.  JP .EQ. 0  .OR.  JP .GE. 2*LOMOST )
     1  GO TO 100
C
C     TENSOR COUPLED                                                    32570   
C
      CALL WAVETC ( L, LAS, JP, NWP, NWAVEF, NUMPTS, RGRID,
     1  WAVER, WAVEI, WAVR, WAVI, VREAL, VIMAG, VCENT )
      RETURN
C
C     NOT TENSOR COUPLED
C
 100  CALL WAVELJ ( L, JP, NWP, NUMPTS, RGRID, WAVER, WAVEI,
     1   WAVR, WAVI, VREAL, VIMAG, VCENT )
      RETURN                                                            32580   
C
C     ILLEGAL - SET TO ZERO.
C
 200  IF ( NUMPTS .EQ. 0 )  RETURN
      DO 239 I = 1, NUMPTS
         WAVER(I) = 0
         WAVEI(I) = 0
 239  CONTINUE
      RETURN
      END                                                               32590   
C*ID* WOODSX   C109.PTOLEMY.SOURCE                          PER701  15:
      SUBROUTINE WOODSX ( NUMPTS, RSTRT, STEPSZ, VRAY, N1, N2,
     1  ITYPE, V, R, A, POWER )
C
C     COMPUTES WOODS-SAXON TYPE POTENTIALS
C
C     NUMPTS - NUMBER OF DESIRED POTENTIAL VALUES
C     RSTRT - FIRST R VALUE
C     STEPSZ - INCREMENT IN R - LASTR = RSTRT + (NUMPTS-1)*STEPSZ
C     VRAY - ARRAY OF NUMPTS LOCATIONS TO GET V                         32600   
C     N1 - SET TO INDEX OF FIRST ELEMENT OF VRAY THAT IS NONTRIVIAL
C     N2 - SET TO INDEX OF LAST NON-ZERO ELEMENT IN VRAY.
C     ITYPE - TYPE OF POTENTIAL DESIRED:
C       1 - WOODS SAXON.
C          -V / ( 1 + EXP((RVAL-R)/A) )**POWER
C       2 - SPIN ORBIT W.S.
C          + 2*V/RVAL * D/DR 1 / ( 1 + EXP((RVAL-R)/A) )
C       3 - DERIVATIVE OF W.S.
C          + 4*V*A * D/DR 1 / ( 1 + EXP((RVAL-R)/A) )
C       4 - FOLDED REAL TR                                              32610   
C         -2*V*RVAL * D/DR   1/RVAL * D/DR 1 / ( 1 + EXP((RVAL-R)/A) )
C       5 - FOLDED IMAG TR
C          +8*V*RVAL * D/DR   1/RVAL * D/DR
C                D/DR 1 / ( 1 + EXP((RVAL-R)/A) )
C     V, R, A, POWER - POTENTIAL PARAMETERS
C
C     11/21/77 - FIRST VERSION - S.P.
C     3/11/78 - DON'T GENERATE V'S < 1E-30 - S.P.
C     4/3/78 - DON'T GENERATE V'S < 1E-20 - S.P.
C     4/17/78 - KEEP N1 AND N2 IN BOUNDS; N2 > N1 - S.P.                32620   
C     6/23/78 - ALLOCLEVEL ADDED
C     12/13/78 - ADD SHAPES FOR TENSOR POTENTIALS (ITYPE = 4, 5) - RPG
C     2/19/79 - LOCAL R CHANGED TO RT TO PRESERVE ARGUMENT - RPG
C     12/28/79 - USE BIGLOG - RPG
C
      implicit real*8 ( a-h, o-z )                                      implicit
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
      DIMENSION  VRAY(NUMPTS)
C
C     CHECK FOR ZERO POTENTIAL                                          32630   
C
      N1 = 0
      N2 = 0
      IF ( V .EQ. 0 )  GO TO 300
C
      XSTP = STEPSZ/A
      YSTP = DEXP(XSTP)
      X = (RSTRT-STEPSZ - R)/A
C
C     BREAK THE REGION (RSTRT, REND) INTO THREE REGIONS:                32640   
C     1) SMALL R:  EXP((RVAL-R)/A)  <  EXP(-100)
C     2) MODERATE R:  EXP(..)**POWER IS COMPUTABLE
C     3) LARGE R:  V/( EXP((RVAL-R)/A) )**POWER  <  EXP(-46) = 1.E-20
C
      N1 = -(100+X)/XSTP
      N1 = MAX0( N1, 1 )
      N1 = MIN0( N1, NUMPTS )
      Y = 46 + DLOG( DABS(V) )
      Y = DMIN1( Y, BIGLOG )
      IF ( POWER .GT. 1 )  Y = Y/POWER                                  32650   
      N2 = (Y-X)/XSTP
      N2 = MIN0( N2, NUMPTS )
      N2 = MAX0( N2, N1 )
C
C     REGION 1 - POTENTIAL IS -V OR ZERO.
C
      IF ( N1 .EQ. 1 )  GO TO 200
      Y = -V
      IF ( ITYPE .GT. 1 )  Y = 0
      DO 189  I = 1, N1                                                 32660   
         VRAY(I) = Y
 189  CONTINUE
C
C     REGION 2 - COMPUTE THE POTENTIAL
C
 200  X = X + N1*XSTP
      Y = DEXP(X)
      GO TO ( 210, 230, 230, 250, 260 ), ITYPE
C
C     STRAIGHT W.S.                                                     32670   
C
 210  IF ( POWER .NE. 1 )  GO TO 220
      DO 214  I = N1, N2
         VRAY(I) = -V/(1+Y)
         Y = Y*YSTP
 214  CONTINUE
      GO TO 300
C
C     POWER OF W.S.
C                                                                       32680   
 220  DO  224  I = N1, N2
         VRAY(I) = -V/(1+Y)**POWER
         Y = Y*YSTP
 224  CONTINUE
      GO TO 300
C
C     DERIVATIVE OF W.S.
C
 230  DO 234  I = N1, N2
         VRAY(I) = (-4*V) * (Y/(1+Y))/(1+Y)                             32690   
         Y = Y*YSTP
 234  CONTINUE
C
      IF ( ITYPE .NE. 2 )  GO TO 300
C
C     CONVERT DERIVATIVE OF W.S. TO SPIN ORBIT
C
      RT = RSTRT + (N1-1)*STEPSZ + 1.D-30
      DO 244  I = N1, N2
         VRAY(I) = (.5/A) * VRAY(I)/RT                                  32700   
         RT = RT + STEPSZ
 244  CONTINUE
      GO TO 300
C
C     FOLDED REAL TR
C
 250  V1 = 2.*V/(A*A)
      RT = RSTRT + (N1-1)*STEPSZ + 1.D-30
      DO 254 I = N1, N2
         XX = 1. + Y                                                    32710   
         VRAY(I) = V1 * (Y/XX) * ( (1.-Y)/XX - A/RT ) / XX
         RT = RT + STEPSZ
         Y = Y * YSTP
 254  CONTINUE
      GO TO 300
C
C     FOLDED IMAGINARY TR
C
 260  V1 = 8. * V / A
      AA = 1. / A                                                       32720   
      A4 = 4.*AA
      RT = RSTRT + (N1-1)*STEPSZ + 1.D-30
      DO 264 I = N1, N2
         XX = 1. + Y
         YY = Y / XX
         RR = 1. / RT
         VRAY(I) = V1 * YY * ( ( (RR-AA)/XX + A4*YY )/XX
     1      - (RR+AA)*YY*YY ) / XX
         RT = RT + STEPSZ
         Y = Y * YSTP                                                   32730   
 264  CONTINUE
C
C     NOW FILL OUT THE REST OF THE ARRAY WITH 0
C
 300  IF ( N2 .EQ. NUMPTS )  RETURN
      N2P1 = N2+1
      DO 329  I = N2P1, NUMPTS
         VRAY(I) = 0
 329  CONTINUE
      RETURN                                                            32740   
      END
C*ID* XSECTN   C109.PTOLEMY.SOURCE                          PER701  13:
      SUBROUTINE XSECTN ( IRTN )
C
C     COMPUTES THE  TRANSFER OR INELASTIC CROSS SECTIONS.
C
C
C     THIS CALCULATES THE  F(LX, MX)  FROM THE S(LX, LO, LI).
C     THE CROSS SECTIONS ARE THEN SUMS OF  |F|**2.
C                                                                       32750   
C   D.GLOECKNER 10/15/73
C
C
C     1/23/75 - SPLIT INTO TWO PIECES - INELDC AND XSECTN - S.P.
C     2/10/75 - COMPUTE FAC2;  USE PRINT CONTROL
C     2/19/75 - CALL DUMMY1 TO SETUP CLEBSH, OTHER SMALL THINGS
C     2/28/75 - SAVE RESULTS IN ARRAYS
C     3/7/75 - REMOVE SPIN FACTORS FROM CROSS SECTION; MUCH COSMETICS;
C              FIX A FEW BUGS; TOTAL CROSS SECTIONS; ALLOW AMIN = 0.
C     4/8/75 - SUM ON LX, LOLA AND NON-LOLA SIGMAS, NEW I ARRAYS        32760   
C     4/18/75 - NEW COMMONS
C     6/1/75 - (-)**LO CHANGE; PHSPRT; ELASTIC D(SIGMA)
C     7/29/75 - PRINT ERRORS DUE TO L TRUNCATION
C     7/31/75 - LINTRP NOW EXTRAPOLATES
C     8/6/75 - PRINT TOTAL  L > LMAX (LINTRP EXTRAP) CONTRIBUTION
C     2/11/76 - STORE BETAR, BETAI ON TOP OF ILILOR, ILILOI - S.P.
C     2/24/76 - USE SIGNS OF CHAPTER 2 OF MANUAL; CORRECT PICKUP ERROR
C     4/27/76 - FIX TOTAL CROSS SECTIONS
C     9/13/76 - SUM TO LIMOST IN ELASTIC CROSS SECTIONS
C     11/7/76 - SAVE LX, MX CROSS SECTIONS, AND B'S.                    32770   
C     12/26/76 - INELASTIC SCATTERING ADDED
C     12031/76 - REMOVE LOLA CROSS SECTIONS
C     5/7/77 - IDENTICAL PARTICLES; ELDCS DOES ELASTIC.
C     4/24/78 - LI, LO INTERCHANGE SOMEWHAT; LIMOST FOR ELASTIC - S.P.
C     4/26/78 - RECREATE I FROM MAG & PHASE & COULOMB PHASES;
C               STORE COMPLEX ISUM - S.P.
C     9/7/78 - USE BETA=1 FOR COUPLED CHANNELS - S.P.
C     3/6/79 - S-MATRICES; USE P(L,M) - S.P.
C     4/12/79 - OUT IS IN FOR COUPLED - S.P.
C     5/4/79 - USE RATMAS IN ELDCS; FIX ERROR IN ABOVE; DETAILED TIMING 32780   
C     8/17/79 - STANDARDIZE, MAJOR REWRITE FOR SPIN-ORBIT ETC. - RPG
C     4/2/80 - C.C. VERSION; REAL*4 S MATRICES - S.P.
C     4/26/80 - PBUGSW NOLONGER IN WAVCOM - S.P.
C     5/9/80 - USE JMOST FOR ELDCS - S.P.
C     6/24/80 - PRINT HEADER BY DIFFERENT FORMATS (523,524) - S.P.
C     7/2/80 - PRINT MCHN INSTEAD OF NCHN - S.P.
C     7/11/80 - FOR C.C. REDEFINE BETAS FOR EACH CHAN - S.P.
C     7/28/80 - PASS SCRATCH ARRAYS TO AMPCAL - S.P.
C     8/1/80 - CALL SETLOG - S.P.
C     8/11/80 - PRINT CORRECT CHANNEL NUMBER ON 1ST PAGE - S.P.         32790   
C     9/26/80 - INITIALIZE FLO TO ZEROS - S.P.
C     12/14/80 - SAVE ALL F'S; PRINT JP, ... - S.P.
C     6/1/81 - LXSTP BECOMES LXSTEP - S.P.
C     9/17/81 - EPSILON ALGORITHM USED - S.P.
C     10/12/81 - SMALL PRINTING FIXES - S.P.
C     10/27/81 - CHANGE SYMMETRY INDICATOR FOR AMPCAL - S.P.
C     7/1/83 - DO LAB ANGLES AND CROSS SECTIONS, SAVE ELAS SIG - S.P.
C     10/16/84 - AVOID /0 FOR ZP=0; PRINT OPTICAL MB FOR ZP=0 - S.P.
C     5/10/85 - USE SETINT ON CRAY - S.P.
C     1/14/13 - Fix bug in labangles - s.p.                             32800   
C
C ***********************************
C
C     THIS IS A QUICK JOB AND IT REALLOCATES THE SCRATCH ARRAYS
C     FAR MORE THAN IS DESIRABLE FOR C.C. CALCULATIONS.
C
C ***********************************
C
C
C                                                                       32810   
      implicit real*8 ( a-h, o-z )                                      implicit
C
      parameter ( namdim = 500 )                                        /allocs/
c
      INTEGER*4 Z
      COMMON /LOCptrs/ Z(namdim)
      INTEGER  FACFR4, FACFR2, FACFR1
      COMMON /ALLOCS/ FACFR4, FACFR2, FACFR1
      DIMENSION  ALLOC(1)
      character*8 dalloc(1)
      character*1  chlloc(1)
      REAL*4  ALLOC4(1)
      INTEGER    ILLOC(1)
      INTEGER*2 ILLOC2(1)
      EQUIVALENCE ( facfr4, ALLOC(1), ILLOC(1), ILLOC2(1),
     &   ALLOC4(1), chlloc(1), dalloc(1) )
 
      CHARACTER*8 NAMES
      COMMON /NAMCOM/  NAMES(1)
C
      parameter ( numfloat = 153 )                                      /float/
      COMMON /FLOAT/  A, ACCURA, AI, ANGSTP, ANGMIN,
     &  ANGMAX, ASO, ASOI, ASYMPT, DELTVK,
     &  DWCUT, E, ECM, ELAB, EXS(5), GAMDIF,
     &  GAMSUM, TAU, TAUI, AM, AMA, AMB, AMBIGA, AMBIGB, AMX,
     &  AMXCS(5), AMXCGS(5), AMP,
     &  AMT, Q, R, R0, RC,
     &  RC0, RI, RI0, RSO, RSO0,
     &  RSOI, RSOI0, SPAM, SPAMP, SPAMT,
     &  STEPSZ, STEP1R, STEP1I, SUMMAX, SUMMID,
     &  SUMMIN, V, VI, VSO, VSOI,
     &  FITMUL, WRITES, ASI, RSI, RSI0,
     &  VSI, AMDMLT, STPSPR, R0E, RI0E,
     &  AE, AIE, VE, VIE, FITACC,
     &  ALMNMT, SPFACP, SPFACT, R0ESQ, RI0ESQ,
     &  AESQ, AIESQ, VESQ, VIESQ, DERIVS,
     &  FITRAT, RCP, RCT, RC0P, RC0T,
     &  SUMPTS, ACCINE, COULML, ALMXMT, EXSPT(2),
     &  POWRL, POWIM, BNDASY, SCTASY,
     &  VTR,VTRI,VTL,VTLI,VTP,VTPI,
     &  PARAM1, PARAM2, PARAM3, PARAM4, PARAM5,
     &  PAR620(15),
     &  RTR, RTRI, RTL, RTLI, RTP, RTPI,
     &  RTR0, RTRI0, RTL0, RTLI0, RTP0, RTPI0,
     &  ATR, ATRI, ATL, ATLI, ATP, ATPI,
     &  AMXGPT(2), PHIMID, GAMPHI
c
      DIMENSION PARAMS(20)
      EQUIVALENCE  ( PARAMS(1), PARAM1 )
      DIMENSION AMS(5)
      EQUIVALENCE ( AMS(1), AMA )
      DIMENSION VTEN(6), RTEN(6), RTEN0(6), ATEN(6)
      EQUIVALENCE ( VTEN(1), VTR ), (RTEN(1), RTR ),
     &  (RTEN0(1), RTR0 ), (ATEN(1), ATR )
 
      parameter ( NUMINTEGER = 53 )                                     /intger/
      INTEGER  PARITS, PARIPT, PARITY
      COMMON /INTGER/  L, LMAX, LMIN, LOOKST, LX,
     &  MAPSUM, MAPDIF, MAXITR, NAITKN, NBACK,
     &  NCOSIN, NODES, NPDIF, NPHIAD, NPPHI,
     &  NPSUM, IPRINT, ISIZE, IZS(5),
     &  IZP, IZT,
     &  LSTEP, LBACK, MAXLEX, LMAXAD, MAXFUN,
     &  IREINI, MODEFT, NUMRAN, NVPOLY, NPCOUL,
     &  MXCOUL, LMINSB,
     &  PARITS(5), PARIPT(2), PARITY,
     &  IPARM1, IPARM2, IPARM3, IPARM4, IPARM5,
     &  NBLKSZ, MAPPHI, NFIROF, LEBACK
 
      parameter ( NUMJWORD = 12 )                                       /jblock/
      COMMON /JBLOCK/  J, JS(5),
     &  JP, JSP, JST,
     &  JPARM1, JPARM2, JPARM3
 
      EQUIVALENCE ( JS(1), JA ), ( JS(2), JB ), ( JS(3), JBIGA ),       32820   
     1  ( JS(4), JBIGB ), ( JS(5), JX )
      parameter ( NUMSWITCHES = 34 )                                    /switch/
      INTEGER  PROBLM, R0TYPE, CONVRG
      COMMON /SWITCH/  IASYMP, ICHECK, IECHO, IELAST, IFIT,
     &  IVRTEX, IRLWAV, ITSO, LINEAR, NUCONL,
     &  NEXT, IFITER, IEPOW, ISAVMX, ISAVB,
     &  LABANG, PROBLM, MASTYP, R0TYPE, IBSPAS,
     &  ISW1, ISW2, ISW3, ISCRFL, NOBFAC,
     &  CONVRG, IEXTYP, IBRNSB, MEORD, KFRMTP,
     &  IWRTWV, LORNTZ, IRELPT, ISAVSM
 
      LOGICAL*1 WASSET                                                  /intrnl/
      COMMON /INTRNL/  UNDEF, NOTDEF, ICHANB, ICHANW, ICNTT, EBNDS(2),
     &  IDONE, ISTRIP, IHSAVE, NEXTSV, IPOT, IWFN, LIMOST, IEXCIT,
     &  R0MASS, WASSET(40), RATMAS,
     &  LSPECS(4), NODESP(4), LSPCPT(2), NODEPT(2),ICD3I
      real*4 undef4
      equivalence ( undef4, notdef )
 
      CHARACTER*1  REACT, HEADER                                        /hedcom/
      COMMON /HEDCOM/  REACT(45), HEADER(65)
 
      COMMON /KANDM/ AKI, AKO, REDMI, REDMO, RIMAX, ROMAX, ISIGS(2),    /kandm/
     &  RSCTS(2), ASCTS(2), RCSCTS(2) ,ISMATS(2), LOMOST, LCRIT,
     &  ISCTMN, ISCTCR, ETAS(2), RCSCTP(2), RCSCTT(2), LCRITS(2),
     &  RATMSS(2), QMIN, ABAR
 
      DIMENSION  AKS(2), REDMS(2), RMAXS(2)
      EQUIVALENCE ( AKI, AKS(1) ), ( REDMI, REDMS(1) ),
     &  ( RIMAX, RMAXS(1) )
 
      LOGICAL  PWAVSW, STANSW, SOSWS, PWBGSW, TCSWS, SOSWT              /wavcom/
      COMMON /WAVCOM/  HS(2), RSTEPS(2),
     &  NSTPSS(2), NFS(2), NGS(2), NF1S(2), NG1S(2),
     &  STEPR, STEPI,
     &  IWAVR, IWAVI, NUMAIT,
     &  NUMFIT, IOFFIT, PWAVSW, NBAKCM, STANSW,
     &  SOSWS(2), NUMJS(2), RIS(2), AIS(2),
     &  RSOS(2), ASOS(2), RSOIS(2), ASOIS(2), IRLVS(2), IIMVS(2),
     &  IZPS(2), IZTS(2), ASYMPS(2),
     &  V0RS(2), V0IS(2), V0SORS(2), V0SOIS(2), ES(2), JSPS(2),
     &  RSIS(2), ASIS(2), V0SIS(2), ISORS(2), ISOIS(2),
     &  ALPHAR, ALPHAI, NFIRST, PWBGSW, LASTL(2), LASTNF(2),
     &  LSKIPS(2), ISTATS(2), POWRLS(2), POWIMS(2),
     &  NSTP2S(2), XFACS(3,2), IVWORK, ICENTR(2), TCSWS(2),
     &  NWAVEF, VTENS(2,6), RTENS(2,6), ATENS(2,6), ITENS(2,6),
     &  IWAVRS(2), IWAVIS(2), LASTZR, SOSWT, IINDXE(2), ITOCE(2)
 
c                                                                       /formf/
c ***  LNKADB was  numLINKULES but only 12 are used ???
c
      COMMON /FORMF/  IBDS(2), NPOTS(2), LBP, LBT, NBP, NBT, JBP, JBT,
     &  BNDMAX(2), BNDSTP(2), NSTPBD(2), RBNDS(2), ABNDS(2),
     &  RCBNDS(2), BNDMAS(2), BRATMS(2), RSOBDS(2), ASOBDS(2),
     &  VBNDS(2), VSOBDS(2), TAUBDS(2), LNKADB(6, 2, 12)
 
      LOGICAL ONELSW, IDENSW                                            /inelcm/
      COMMON /INELCM/  JBPF, JBTF, LXMIN, LXMAX, ILILOR, ILILOI, MSTOP,
     &  IA12M, NMLOLX, ONELSW, NUMLX, IRDINT, IELCUP, LILOSZ, NUMLIS,
     &  ILIS, IBETAS(3), ICL2FF, LXSTEP, IDENSW, LSKIP,
     &  JPMIN, JPMAX, JPBASE, NJP, JTMIN, JTMAX, JTBASE, NJT,
     &  IINDXS, ISMATR, ISMATI, NSMAT, NLX, NSPLI, ITOCS,
     &  NASPLI, IUNITR, LIFIT, ILIFIT, NOLFIT, IDELSR, IDELSI
      INTEGER INDXJS(4,2)
      EQUIVALENCE ( INDXJS(1,1), JPMIN )
 
      COMMON /CCBLK/  ICHNDF, ICHNCP, ITRANS, IBASDF, IBASCP,           /ccblk/
     &    ICCBLK(2), IORDX, MCHNVL, ICHNVL,
     &    IHOMOA, IHOMOB, IINHR8, IINHI8
 
      COMMON /CNSTNT/  PI, RT4PI, PIINV, RADIAN, DEGREE,                /cnstnt/
     &  HBARC, AMUMEV, AFINE, BIGEST, SMLEST, BIGNUM, SMLNUM, BIGLOG
 
C
      CHARACTER*8 BETNAM / 'BETAS   ' /
      CHARACTER*8  RUTNAM(2) / 'TORUTHIN', 'TORUTHOT' /
      CHARACTER*8  FENAME(2) / 'FIN     ', 'FOUT    ' /
      CHARACTER*8  RUTHNM(2) / 'RUTHIN', 'RUTHOUT' /
      CHARACTER*8  SIGNAM(2) / 'SIGMAIN', 'SIGMAOUT' /
      CHARACTER*8  INHEAD(2) / 'INCOMING', ' COUPLED' /,
     1    OUTHED(2) / 'OUTGOING', ' OPTICAL' /
C
      CHARACTER*8  LABCM, LABWRD /'LAB.'/,  CMWRD /'C.M.'/              32840   
      CHARACTER*8  BLANK /' '/, RUTWRD /'/RUTH' /, tempwd
C
      CHARACTER*1  SIGNS(2) / '+', '-' /
C
      REAL*8 DUMMY8(1)
      LOGICAL  PBUGSW, PHEDSW, PCONSW, TRANSW, FKEPSW, CCSW
      DATA  IZERO / 0 /, LINEMX / 57 /
C
c
C                                                                       32850   
      TSTART = second()
      IRTN = 0
      CRSFLP = 0
      TRANSW = ISTRIP .NE. 0
      CCSW = PROBLM .EQ. 24
      JMOST = LIMOST
      IF (CCSW)  JMOST = LOMOST-LXMAX
C
      IPRNT = MOD(IPRINT, 10)
      PBUGSW = IPRNT .GE. 4                                             32860   
      PCONSW = IPRNT .GE. 3
C
      CALL PHSPRT ( IPRNT .GE. 1 )
C
      T1 = second()
      TBET = 0
      TCROSS = 0
C
      write (6, 3) REACT, ELAB, HEADER
  3   FORMAT ( '1', T56, 'P T O L E M Y'  /                             32870   
     1    10X, 'COMPUTATION OF CROSS SECTIONS',
     2  T78, 'SOPHISTICATED PROGRAMS CONTAIN SUBTLE ERRORS' /
     3  '0', 45A1, F7.2, ' MEV', 5X, 65A1 / )
      LINECT = 4
C
      PHEDSW = .TRUE.
CRAC
CRAC      SET UP INTEGER TABLE FOR PLM SUBROUTINE
CRAC
CRA      CALL SETINT ( LOMOST+LXMAX+2 )                                 32880   
C
      LABCM = CMWRD
      IF ( LABANG .NE. 0 )  LABCM = LABWRD
C
C     LOCATE MAGNITUDES AND PHASES OF RADIAL INTEGRALS
C
      IMAG = NAMLOC('SMAG    ')
      IPHASE = NAMLOC('SPHASE  ')
      IF ( CCSW )  Z(IRDINT) = -Z(IRDINT)
C                                                                       32890   
C
C     IF LAB ANGLES, ANGLE RANGE MAY HAVE TO BE LIMITED.
C
      ABAR = 1.E+5
      IF ( LABANG .EQ. 0 )  GO TO 100
C
C     LIMIT RANGE TO MIN OF ELASTIC AND REACTION.  FOR C.C.
C     QMIN HAS ALREADY BEEN SETUP BY BASLBL
C
      X = AMBIGA/AMA                                                    32900   
      IF ( .NOT. CCSW )  QMIN = Q
      TEMP = SQRT( X*AMBIGB*(AMA+AMBIGA)/(AMB*(AMB+AMBIGB))
     1  * (Ecm+QMIN)/Ecm )
!!!      write (0,*) 'temp', temp, ccsw, qmin, q, ambigb, ama, ambiga,
!!!     &   amb, e, ecm
      IF (PBUGSW)  write (6, 83) X, TEMP
  83  FORMAT ( '0LIMITS ON SIN(THETALAB):', 2G15.5 )
      X = DMIN1( X, TEMP )
      IF ( X .GT. 1 )  GO TO 100
      ANGBAR = RADIAN*ASIN(X)                                           32910   
      ABAR = ANGSTP*(DINT((ANGBAR-ANGMIN)/ANGSTP+1.D-10)+.5)+ANGMIN
      TABAR = 2*ABAR
      ANGMAX = DMIN1( ANGMAX, TABAR )
  100 NUMANG = (ANGMAX-ANGMIN)/ANGSTP + 1.5
 
!!!      write (0,*) 'numang', numang, angmax, angmin, angstp, abar,
!!!     &   angbar, x, temp,  AMBIGA/AMA
 
C
C     COMPUTE THE ELASTIC CROSS SECTIONS                                32920   
C
      FKEPSW = ISAVB .EQ. 1  .OR.  SOSWS(1)
      CALL ELDCS ( AKS(1), ETAS(1), ANGMIN, ANGMAX, ANGSTP,
     1  LMIN, JMOST, LSKIPS(1), ISTATS(1), JSPS(1), ISMATS(1),
     2  ITOCE(1), NUMJS(1), ISIGS(1), ELAB, RATMSS(1), .FALSE.,
     3  ITORT1, RUTNAM(1), FKEPSW, IFIN, FENAME(1), REACIN,
     4  IRUTH1, RUTHNM(1) )
      ISIGIN = NAMLOC( 'CROSSSEC' )
      NAMES(ISIGIN) = SIGNAM(1)
C                                                                       32930   
C     DOES THE 2ND ARRAY CONTAIN INCOMING OR OUTGOING
C
      IPROB = 2
      IF ( PROBLM .GE. 23 )  IPROB = 1
      FKEPSW = ISAVB .EQ. 1  .OR.  SOSWS(IPROB)
      CALL ELDCS ( AKS(IPROB), ETAS(IPROB), ANGMIN, ANGMAX, ANGSTP,
     2  LMIN, JMOST, LSKIPS(IPROB), ISTATS(IPROB), JSPS(IPROB),
     2  ISMATS(2), ITOCE(IPROB),
     2  NUMJS(IPROB), ISIGS(IPROB), ELAB, RATMSS(IPROB), .FALSE.,
     3  ITORT2, RUTNAM(2), FKEPSW, IFOUT, FENAME(2), REACOT,            32940   
     4  IRUTH2, RUTHNM(2) )
      ISIGOT = NAMLOC( 'CROSSSEC' )
      NAMES(ISIGOT) = SIGNAM(2)
C
      T2 = second()
C
C     POSSIBLY SETUP FOR C.C. CALCULATIONS
C
      NCHNDF = 2
      LTOCOF = 0                                                        32950   
      LSOFF = 0
      MCHN = 2
      IF = 0
      LFOFF = 0
C
C     TO COMPUTE  SIGMA(REACTION)/RUTHERFORD, WE USE
C     SQRT(RUTH(IN)*RUTH(OUT)).  RUTHFC  CONVERTS RUTH(IN)
C     TO THIS GEOMETRIC MEAN.
C
      RUTHFC = 1                                                        32960   
      IF ( ETAS(1) .NE. 0 )  RUTHFC = ETAS(2)*AKI/(ETAS(1)*AKO)
C
      IF ( .NOT. CCSW )  GO TO 200
C
      LCHNDF = FACFR4*(Z(ICHNDF)-1) + 1
      NCHNDF = ILLOC(LCHNDF)
      MCHNDF = ILLOC(LCHNDF+1)
      FKEPSW = ISAVB .EQ. 1
      IF ( FKEPSW )  IF = NALLOC( 2*NUMANG*NASPLI, 'F       ' )
C                                                                       32970   
 200  ICROSS = NALLOC( NUMANG*(NCHNDF-1), 'CROSSSEC' )
      IFEPSL = NALLOC( 2*LEBACK+1, 'FEPSILON' )
C
      IDNPAR = 0
      IF ( IDENSW ) IDNPAR = 1
C
      DO 1099  NCHN = 2, NCHNDF
         IF ( .NOT. CCSW )  GO TO 210
         LCHNDF = FACFR4*(Z(ICHNDF)-1)+1
         LCHNDF = LCHNDF + ILLOC(LCHNDF+2) + MCHNDF*(NCHN-1)            32980   
         MCHN = ILLOC(LCHNDF)
         JT = ILLOC(LCHNDF+1)
         IT = 1
         IF ( JT .LT. 0 )  IT = 2
         JT = IABS(JT)
         ET = ALLOC4(LCHNDF+2)
         JP = ILLOC(LCHNDF+3)
         IP = 1
         IF ( JP .LT. 0 )  IP = 2
         JP = IABS(JP)                                                  32990   
         EP = ALLOC4(LCHNDF+4)
         Q = -(EP+ET)
         KT = ILLOC(LCHNDF+15)
         KP = ILLOC(LCHNDF+16)
         IF ( IDENSW )  IDNPAR = 1
         IF ( IDENSW .AND.  JT .EQ. JP  .AND.  ET .EQ. EP )
     1        IDNPAR = 2
         write (6, 203) MCHN, EP, JP, SIGNS(IP), KP, ET, JT,
     1   SIGNS(IT), KT
 203     FORMAT ('0REACTION CROSS SECTIONS ARE FOR CHANNEL', I7,        33000   
     1   ':  PROJECTILE, E =', F7.3, '  J =', I3, '/2', A1,
     2    '  K =', I2, '/2',
     1   ';  TARGET, E =', F7.3, '  J =', I3, '/2', A1,
     2    '  K =', I2, '/2' )
         LINECT = LINECT+2
         ETAS(2) = ALLOC4(LCHNDF+5)
         RUTHFC = ECM/(ECM-ET-EP)
         NSPLI = ILLOC(LCHNDF+10)
         LTOCOF = ILLOC(LCHNDF+12)
         LSOFF = ILLOC(LCHNDF+13)                                       33010   
         LIMOST = ILLOC(LCHNDF+14)
         IF (PBUGSW)  write (6, 208) ETAS(2), NSPLI, LTOCOF, LSOFF,
     1      LIMOST
 208     FORMAT ( ' ETA2, NSPLI, LTOCOF, LSOFF, LIMOST:', 8I8 )
         IRDINT = NALLOC( (2*NSPLI*(LIMOST-LMIN+1))/FACFR4,
     1      'BETAS ' )
C
C     SCAN THE TABLE OF CONTENTS FOR EXTREMA IN LX, LI-LO.
C
 210  LXMN = 1000                                                       33020   
      LXMX = -1000
      LDELMX = -1000
      JPMX = -1000
      LTOCS = Z(ITOCS)*FACFR4 - FACFR4 + LTOCOF
      DO 249  KOFFS = 1, NSPLI
         IF ( ILLOC(LTOCS+4*KOFFS) .LT. 0 )  GO TO 249
         LX = ILLOC(LTOCS+4*KOFFS-2)
         LXMN = MIN0( LXMN, LX )
         LXMX = MAX0( LXMX, LX )
         LDEL = ILLOC(LTOCS+4*KOFFS-3)                                  33030   
         LDELMX = MAX0( LDELMX, LDEL )
         JPMX = MAX0( JPMX, ILLOC(LTOCS+4*KOFFS-1) )
249   CONTINUE
      LXRNGE = LXMX - LXMN + 1
      NMLX = (LXMX-LXMN+LXSTEP)/LXSTEP
      IF (PBUGSW)  write (6, 253) LXMN, LXMX, LDELMX, JPMX, NMLX, LXRNGE
 253  FORMAT ( ' LXMN, LXMX, LDELMX, JPMX, NMLX:', 8I8 )
C
C     "TEMPS" IS USED FOR SCRATCH STORAGE BY SUBROUTINE BETCAL.
C                                                                       33040   
      NTEMPS = ( LXMX+1 )*LXRNGE*( LDELMX+1 )
      ITEMPS = NALLOC( NTEMPS, 'TEMPS   ' )
      ILXTOT = NALLOC( LXMX+1, 'LXTOTS  ' )
      IMXTOT = NALLOC( NSPLI, 'MXTOTS  ' )
C
C     SUBROUTINE BETCAL CALCULATES THE ANGLE-INDEPENDENT PARTS
C     (BETA) OF THE REACTION AMPLITUDES F.
C     THEY ARE PUT INTO THE ARRAY "S", WHICH IS THEN RENAMED "BETAS".
C
      T3 = second()                                                     33050   
C
      CALL SETLOG ( 2*(LOMOST+LXMAX) )
C
      LMAG = FACFR4*(Z(IMAG)-1) + 1 + LSOFF
      LPHASE = FACFR4*(Z(IPHASE)-1) + 1 + LSOFF
      LRDINT = FACFR4*(Z(IRDINT)-1) + 1
      LTOCS = Z(ITOCS)*FACFR4 - FACFR4  + LTOCOF
C
      IF ( CCSW )  CALL DSGMAL ( ETAS(2), LIMOST+LXMAX,
     1  ALLOC(Z(ISIGS(2))) )                                            33060   
C
      CALL BETCAL ( .FALSE., AKI, JSPS(1), NSPLI, LMIN, LIMOST, LSKIP,
     1   LXMN, LXMX, LDELMX, NTEMPS, ISTATS(1), PBUGSW,
     2   SIGTOT, DUMMY,
     3   ILLOC(LTOCS+1), DUMMY8, ALLOC4(LMAG), ALLOC4(LPHASE),
     4   ALLOC(Z(ISIGS(1))), ALLOC(Z(ISIGS(2))),
     5   ALLOC4(LRDINT), ALLOC(Z(ILXTOT)), ALLOC(Z(IMXTOT)), DUMMY8,
     6   ALLOC(Z(ITEMPS)) )
C
C     FREE THE SCRATCH ARRAY.                                           33070   
C
      Z(ITEMPS) = -Z(ITEMPS)
C
      T4 = second()
      TBET = TBET + T4-T3
C
C     NOW COMPUTE THE REACTION CROSS SECTION FOR EACH ANGLE
C
      TAU = SQRT( AMA*AMB*(AMB+AMBIGB)*Ecm /
     1  ( AMBIGA*AMBIGB*(AMA+AMBIGA) * (Ecm+Q) ) )                      33080   
C
C     ALLOCATE SPACE FOR PLM
C
      ISPACE = LIMOST+1+ ((2*LIMOST+1-LXMX)*LXMX)/2
      IPLM = NALLOC(ISPACE, 'PLM     ' )
      ITMPCN = NALLOC( 2*(LIMOST+1), 'TMPCONTR' )
C
C     SPACE FOR CROSS SECTIONS
C     NOTE THAT THE NUMBER OF (LX, MX) COMBINATIONS IS THE SAME AS
C     THE NUMBER OF (LI, LX) COMBINATIONS FOR EACH LO.                  33090   
C
      ILXCRO = NALLOC( NUMANG*LXRNGE, 'LXCROSSS' )
      IMXCRO = 0
      IF ( ISAVMX .EQ. 1 )  IMXCRO = NALLOC( NUMANG*NSPLI, 'MXCROSSS' )
      IMXCON = NALLOC( NSPLI, 'MXCONS  ' )
      IF ( CCSW )  GO TO 350
      FKEPSW = ISAVB .EQ. 1  .OR.  MIN0( JS(1), JPMX, LXMX ) .GT. 0
      IF ( FKEPSW )  IF = NALLOC( 2*NUMANG*NSPLI, 'F       ' )
 350  ILXCNT = NALLOC( LXMX+1, 'LXCONTRB' )
      IFTEMP = NALLOC( 2*NSPLI, 'FTEMP   ' )                            33100   
      IFLO = NALLOC( 2*NSPLI, 'FLO     ' )
      IFHI = NALLOC ( 2*NSPLI, 'FHI     ' )
      IFERR = NALLOC( NSPLI, 'FERROR  ' )
      CALL INIT8 ( IFLO, 0.D0 )
C
      CALL SETLOG ( 2*(LOMOST+LXMAX) )
CRA      CALL SETINT ( LOMOST+LXMAX+2 )
C
C     NO MORE ALLOCATIONS SO GET SOME LOCATIONS
C                                                                       33110   
      LLXCNT = Z(ILXCNT)
      LRDINT = FACFR4*(Z(IRDINT)-1)+1
      LPLM = Z(IPLM)
      LTMPCN = Z(ITMPCN)
      LLXCRO = Z(ILXCRO) - LXMN*NUMANG - 1
      LMXCRO = Z(IMXCRO) - NUMANG - 1
      LFTEMP = Z(IFTEMP) - 2
      LFEND = LFTEMP + 2*NSPLI - 1
      LFLO = Z(IFLO) - 2
      LFHI = Z(IFHI) - 2                                                33120   
      LFERR = Z(IFERR)-1
      LF = Z(IF) - 2*NUMANG - 2 + LFOFF
      LMXCON = Z(IMXCON) - 1
      LTORT1 = Z(ITORT1) - 1
      LTORT2 = Z(ITORT2) - 1
      IF ( IZP*IZT .EQ. 0 )  LTORT2 = Z(ISIGOT) - 1
      LSIGIN = Z(ISIGIN) - 1
      LRUTH1 = Z(IRUTH1) - 1
      LCROSS = Z(ICROSS)-1 + NUMANG*(NCHN-2)
      LLXTOT = Z(ILXTOT)                                                33130   
      LMXTOT = Z(IMXTOT)
      LTOCS = Z(ITOCS)*FACFR4 - FACFR4 + LTOCOF
C
C     THE OUTER LOOP IS OVER THE ANGLES
C
C     THE INNER LOOPS ARE IN THE ORDER:
C        JT, JP, LX, MX (FROM "TOCS", INDEXED BY KOFFS)
C           LO
C
C     MAKE A SPACE EVERY ONCE AND A WHILE TO HELP APPEARANCES           33140   
C
      ANGBLK = 300
      IF ( NUMANG .LE. 40 )  GO TO 500
      ANGBLK = 10
      IF ( ANGSTP .GE. .99 )  GO TO 500
      ANGBLK = 5
      IF ( ANGSTP .GT. .201 )  GO TO 500
      ANGBLK = 1
C
C     DO FOR ALL ANGLES                                                 33150   
C
 500  NUMBLK = ANGBLK/ANGSTP + .5
      I = 3
      IF ( NCHN .GT. 2 )  I = 5
      LINADD = (NMLX+I-1)/I
      NUMBLK = NUMBLK*LINADD
      NMLXH = MIN0( NMLX, I )
C
      IF ( .NOT. PCONSW )  GO TO 510
C                                                                       33160   
C     WHEN PRINTING (LX,MX) CONTRIBUTIONS, SPACE EVERY ANGLE
C
      NUMBLK = NSPLI+LINADD
      ANGBLK = ANGSTP
C
      IF ( PBUGSW )  LINECT = 1000
C
C
 510  DO 889  NANG = 1, NUMANG
C                                                                       33170   
C        DO WE NEED A HEADER
C
         IF ( LINECT .LT. LINEMX )  GO TO 520
         write (6, 3) REACT, ELAB, HEADER
         LINECT = 4
         PHEDSW = .TRUE.
         IF ( CCSW )  write (6, 203) MCHN, EP, JP, SIGNS(IP), KP,
     1   ET, JT, SIGNS(IT), KT
         IF ( CCSW )  LINECT = LINECT+2
C     HAS THE SUBHEADER ALREADY BEEN PRINTED                            33180   
 520     IF ( .NOT. PHEDSW )  GO TO 550
         I2 = NMLXH+1
         IF ( NMLX .EQ. 1 )  I2 = 1
         N = 1
         IF ( CCSW )  N = 2
         write (6, 523) LABCM
 523     FORMAT ( '0', 2X, A4, T10, 'REACTION', 5X, 'REACTION',
     1     3X, 'LOW L', 2X, 'HIGH L', 3X, '% FROM' )
         IF ( NCHN .EQ. 2 )  write (6, 526) INHEAD(N), OUTHED(N),
     1      ( BLANK, I = 1, I2 )                                        33190   
 526     FORMAT ( '+', T60, A8, ' ELASTIC', T82, A8,
     1      A1, ( T91, 3( A1, 2X, 'REACTION', 3X ) ) )
         IF ( NCHN .GT. 2 )  write (6, 527) ( BLANK, I = 1, I2 )
 527     FORMAT ( '+', A1, ( T55, 5( A1, 2X, 'REACTION', 3X ) ) )
C
         write (6, 533) LABCM
 533     FORMAT ( '  ANGLE', T10, A4, ' MB', T25, '/RUTH', T35, '%/L',
     1      T41, '% ERROR', T50, 'L>LMAX' )
         IF ( NCHN .GT. 2 )  GO TO 540
         TEMPwd = RUTWRD                                                33200   
         IF ( IZP*IZT .EQ. 0 )  TEMPwd = BLANK
         write (6, 536) LABCM, TEMPwd
 536     FORMAT ( '+', T60, A4, ' MB', 6X, '/RUTH', T84, A5 )
         IF ( NMLX .GT. 1 )  write (6, 538) (BLANK, LX, LX=LXMN,
     1      LXMX, LXSTEP )
 538     FORMAT ( '+', ( T91, 3 ( A1, 3X, 'LX =', I2, 4X ) ) )
         GO TO 545
540      IF ( NMLX .GT. 1 )  write (6, 543) (BLANK, LX, LX=LXMN,
     1      LXMX, LXSTEP )
 543     FORMAT ( '+', ( T56, 5 ( A1, 3X, 'LX =', I2, 4X ) ) )          33210   
 545     write (6, 548)
 548     FORMAT ( ' ' )
         LINECT = LINECT + LINADD + 1
         PHEDSW = .FALSE.
C
 550     ANGLE = ANGMIN + (NANG-1)*ANGSTP
        ANGCM = ANGLE
        AJACOB = 1.
        IF ( LABANG .EQ. 0 )  GO TO 555
C                                                                       33220   
C     GET C.M. ANGLE AND JACOBIAN FROM LAB ANGLE.
C
      ANG = ANGLE
         IF ( ANGLE .GT. ABAR )  ANGLE = TABAR - ANGLE
         AN = DEGREE*ANGLE
         TEMP = 1 - (TAU*SIN(AN))**2
         IF ( TEMP .LT. 0 )  TEMP = 0
         TEMP = COS(AN)*SQRT(TEMP)
         IF ( ANG .GT. ABAR )  TEMP = -TEMP
         ANGCM = ACOS( TEMP - TAU*SIN(AN)**2 )                          33230   
         TEMP = TAU*( TAU + 2*COS(ANGCM) ) + 1
         IF ( TEMP .LT. 0 )  TEMP = 0
         AJACOB = TEMP*SQRT(TEMP) / ABS( TAU*COS(ANGCM) + 1 )
         ANGCM = RADIAN*ANGCM
         IF ( PBUGSW )  write (6, 553) ANGLE, ANGCM, AJACOB
 553     FORMAT ( ' LAB ANG, CM ANG, JACOBIAN:', 3G15.5 )
C
C     CALCULATE THE TRANSITION AMPLITUDES F AT THIS ANGLE.
C
 555     LHI = LMAX                                                     33240   
         CALL AMPCAL ( ANGCM, .FALSE., NSPLI, LMIN, LIMOST, LSKIP,
     1      LXMX, IDNPAR, DUMMY, DUMMY, DUMMY, .TRUE., LHI,
     2      ILLOC(LTOCS+1), ALLOC4(LRDINT), DUMMY8,
     3      ALLOC(LFTEMP+2), ALLOC(LFLO+2), ALLOC(LFHI+2),
     3      ALLOC(LFERR+1), DUMMY8,
     4      ALLOC(LPLM), ALLOC(LTMPCN), ALLOC(LTMPCN+LIMOST+1),
     5      LEBACK, ALLOC(Z(IFEPSL)), NFLPAM )
         CRSFLP = CRSFLP + NFLPAM
C
         SIGMA = 0                                                      33250   
         SUMLOW = 0
         SUMHI = 0
         SUMERR = 0
C
         DO 559  LX = IZERO, LXMX
            ALLOC(LLXCNT+LX) = 0
 559     CONTINUE
C
C     SUM OVER KOFFS = JT, JP, LX, MX.
C                                                                       33260   
         DO 689  KOFFS = 1, NSPLI
            IF ( ILLOC(LTOCS+4*KOFFS) .LT. 0 )  GO TO 689
            LX = ILLOC(LTOCS+4*KOFFS-2)
            MX = ( ILLOC(LTOCS+4*KOFFS-3) + LX + 1 )/2
C
            FMNEG = 1.0D0
            IF ( MX .NE. 0 )  FMNEG = 2.0D0
C
C     RETRIEVE F, ALREADY CALCULATED BY SUBROUTINE AMPCAL.
C                                                                       33270   
            FR = ALLOC(LFTEMP+2*KOFFS)
            FI = ALLOC(LFTEMP+2*KOFFS+1)
C
C        SAVE F IN "F" IF REQUESTED.
C
            IF ( .NOT. FKEPSW )  GO TO 600
            ALLOC(LF+2*NANG+2*NUMANG*KOFFS) = FR
            ALLOC(LF+2*NANG+2*NUMANG*KOFFS+1) = FI
C
C        CROSS SECTION CONTRIBUTION IS JUST |F|**2.                     33280   
C
 600        CONTRI = (10*AJACOB)*(FR*FR+FI*FI)
            ALLOC(LMXCON+KOFFS) = CONTRI
            IF ( ISAVMX .EQ. 1 )
     1        ALLOC(LMXCRO+NANG+NUMANG*KOFFS) = CONTRI
            CONTRI = CONTRI*FMNEG
            ALLOC(LLXCNT+LX) = CONTRI + ALLOC(LLXCNT+LX)
            SIGMA = SIGMA + CONTRI
C
C        WE ACCUMULATE THE CROSS SECTIONS WITH FIRST AND LAST 2 LO'S    33290   
C        REMOVED IN SUMLOW AND SUMHI
C
            SUMLOW = SUMLOW +  (10*FMNEG*AJACOB) *
     1         ( ALLOC(LFLO+2*KOFFS)**2 + ALLOC(LFLO+2*KOFFS+1)**2 )
            SUMHI = SUMHI +  (10*FMNEG*AJACOB) *
     1         ( ALLOC(LFHI+2*KOFFS)**2 + ALLOC(LFHI+2*KOFFS+1)**2 )
            SUMERR = SUMERR + ALLOC(LFERR+KOFFS)*CONTRI
C
            ALLOC(LLXCRO+NANG+NUMANG*LX) = ALLOC(LLXCNT+LX)
C                                                                       33300   
 689     CONTINUE
C
C     END OF KOFFS LOOP
C
         ALLOC(LCROSS+NANG) = SIGMA
C
C     COMPUTE ERRORS DUE TO L-TRUNCATIONS
C
         SAFE = DMAX1( SIGMA, SMLNUM )
         ERRLOW = 100 * (SIGMA-SUMLOW) / (SAFE+SUMLOW)                  33310   
         HICONT  = 100 * (SIGMA-SUMHI) / SAFE
         SUMERR = 200 * SUMERR/SAFE
C
         IF ( .NOT. PCONSW )  GO TO 700
         DO 699  KOFFS = 1, NSPLI
            IF (ILLOC(LTOCS+4*KOFFS) .LT. 0 )  GO TO 699
            LX = ILLOC(LTOCS+4*KOFFS-2)
            MX = ( ILLOC(LTOCS+4*KOFFS-3) + LX + 1 )/2
            GR = 100*ALLOC(LMXCON+KOFFS)/SAFE
             WRITE(6, 693)  ILLOC(LTOCS+4*KOFFS-1),                     33320   
     1         ILLOC(LTOCS+4*KOFFS), LX, MX, ALLOC(LMXCON+KOFFS), GR
 693        FORMAT ( 6X, ' JP, JT, LX, MX =', 2( I3, '/2' ), 2I3, 5X,
     1         'CONTRIBUTION =', G14.7, F8.2, '%' )
 699     CONTINUE
C
 700     RUTH = ALLOC(LRUTH1+NANG)
         ELAS = ALLOC(LSIGIN+NANG)
         SIGMAR = 0
         IF ( RUTH .NE. 0 )  SIGMAR = SIGMA/(RUTHFC*AJACOB*RUTH)
C                                                                       33330   
C     AT LAST, PRINT IT
C
         IF ( NCHN .GT. 2 )  GO TO 860
         IF ( NMLX .EQ. 1 )  write (6, 853) ANGLE, SIGMA, SIGMAR,
     1     ERRLOW, SUMERR, HICONT,
     1     ELAS, ALLOC(LTORT1+NANG), ALLOC(LTORT2+NANG)
         IF ( NMLX .GT. 1 )  write (6, 853) ANGLE, SIGMA, SIGMAR,
     1     ERRLOW, SUMERR, HICONT,
     2     ELAS, ALLOC(LTORT1+NANG), ALLOC(LTORT2+NANG),
     3      ( ALLOC(LLXCNT+LX), LX = LXMN, LXMX, LXSTEP )               33340   
 853     FORMAT ( F7.2, G13.5, F10.6, 2F8.2, F8.1,
     1      G14.5, F10.6, F12.6, ( T91, 3G14.5 ) )
         GO TO 880
 860     IF ( NMLX .EQ. 1 )  write (6, 863) ANGLE, SIGMA, SIGMAR,
     1      ERRLOW, SUMERR, HICONT
         IF ( NMLX .GT. 1 )  write (6, 863) ANGLE, SIGMA, SIGMAR,
     1     ERRLOW, SUMERR, HICONT,
     3      ( ALLOC(LLXCNT+LX), LX = LXMN, LXMX, LXSTEP )
 863     FORMAT ( F7.2, G13.5, F10.6, 2F8.2, F8.1,
     1      ( T56, 5G14.5 ) )                                           33350   
 880     LINECT = LINECT + LINADD
         IF ( PCONSW )  LINECT = LINECT + NSPLI
         IF ( DMOD( ANGLE+ANGSTP+1.D-7, ANGBLK ) .GT. 1.D-5 )  GO TO 889
         IF ( LINECT .LT. LINEMX )  write (6, 548)
         LINECT = LINECT + 1
         IF ( LINECT+NUMBLK .GT. LINEMX )  LINECT=1000
C
 889  CONTINUE
C
C     END OF LOOP OVER ANGLES                                           33360   
C
      T5 = second()
      TCROSS = TCROSS + T5-T4
C
      CRSFLP = CRSFLP + 26*NUMANG
C
      write (6, 923) SIGTOT
 923  FORMAT ( / '0TOTAL:', G15.5 )
      SAFE = DMAX1( SIGTOT, SMLNUM )
      IF ( NCHN .GT. 2 )  GO TO 935                                     33370   
      write (6, 927) REACIN, REACOT
 927  FORMAT ( '+', T55, G14.5, G24.5 )
      IF ( NMLX .EQ. 1 )  GO TO 980
      write (6, 933) ( ALLOC(LLXTOT+LX), LX = LXMN, LXMX, LXSTEP )
 933  FORMAT ( '+', ( T91, 3G14.5 ) )
      GO TO 950
 935  IF ( NMLX .EQ. 1 )  GO TO 980
      write (6, 938) ( ALLOC(LLXTOT+LX), LX = LXMN, LXMX, LXSTEP )
 938  FORMAT ( '+', ( T55, 5G14.5) )
C                                                                       33380   
 950  DO 955  LX = LXMN, LXMX, LXSTEP
         ALLOC(LLXTOT+LX) = 100*ALLOC(LLXTOT+LX)/SAFE
 955  CONTINUE
      IF ( NCHN .EQ. 2 )
     1  write (6, 963) ( ALLOC(LLXTOT+LX), LX = LXMN, LXMX, LXSTEP )
 963  FORMAT ( ( T87, 3(F13.2, '%') ) )
      IF ( NCHN .GT. 2 )
     1  write (6, 968) ( ALLOC(LLXTOT+LX), LX = LXMN, LXMX, LXSTEP )
 968  FORMAT ( ( T51, 5(F13.2, '%') ) )
C                                                                       33390   
 980  IF ( NSPLI .EQ. 1 )  GO TO 1000
      write (6, 983)
 983  FORMAT ( / '0 JP  JT  LX MX      TOTAL      PERCENT' ,
     1  5X, '(VALUES FOR M > 0 NOT DOUBLED.)' / )
      DO 999  KOFFS = 1, NSPLI
         JTT = ILLOC(LTOCS+4*KOFFS)
         IF ( JTT .LT. 0 )  GO TO 999
         LX = ILLOC(LTOCS+4*KOFFS-2)
         MX = ( ILLOC(LTOCS+4*KOFFS-3) + LX + 1 )/2
         GR = 100*ALLOC(LMXTOT+KOFFS-1)/SAFE                            33400   
         write (6, 993)  ILLOC(LTOCS+4*KOFFS-1), JTT,
     1      LX, MX, ALLOC(LMXTOT+KOFFS-1), GR
 993     FORMAT ( 2( I3, '/2' ), 2I3, G15.5, F8.2 )
 999  CONTINUE
C
C     GO TO THE NEXT CHANNEL
C
 1000 IF ( NCHN .EQ. NCHNDF )  GO TO 1099
      write (6, 3) REACT, ELAB, HEADER
      PHEDSW = .TRUE.                                                   33410   
      LINECT = 4
      LFOFF = LFOFF + 2*NSPLI*NUMANG
C
 1099 CONTINUE
C
C     A L L    D O N E    WITH CROSS SECTIONS
C
C
C     RENAME THE "S" ARRAY TO "BETAS" WHICH IT BY NOW REALLY IS.
C                                                                       33420   
      NAMES(IRDINT) = BETNAM
      Z(IPLM) = -Z(IPLM)
C
C     FREE VARIOUS ALLOCATOR ARRAYS.
C
      Z(IMXCON) = -Z(IMXCON)
      Z(ILXCNT) = -Z(ILXCNT)
      Z(IFTEMP) = -Z(IFTEMP)
      Z(IFLO) = -Z(IFLO)
      Z(IFHI) = -Z(IFHI)                                                33430   
C
C
C     NOW CALCULATE AND PRINT ANASYZING POWERS IF POSSIBLE.
C
C     THIS PART DOES NOT WORK FOR C.C.
C
      T6 = second()
      T7 = T6
      T8 = T7
      IF ( JS(1) .EQ. 0 )  GO TO 2150                                   33440   
C
C     FIRST REACTION AP'S.
C
      IF ( LXMX .NE. 0  .AND.  JPMX .NE. 0 )  GO TO 2050
      write (6, 2023)
 2023 FORMAT ( '0---- ALL REACTION ANALYZING POWERS ARE ZERO ----' )
      GO TO 2100
 2050 IPARIT = PARITS(1)*PARITS(2)*PARITS(3)*PARITS(4)
      IF ( IPARIT .EQ. 0  .AND.  TRANSW )
     1   IPARIT = 1 - 2*MOD( LBP+LBT, 2 )                               33450   
      IF ( IPARIT .NE. 0 )  GO TO 2060
      write (6, 2053)
 2053 FORMAT ( '0**** REACTION ANALYZING POWERS CANNOT BE CALCULATED',
     1   ' BECAUSE THE PARITY CHANGE IS UNKNOWN ****' )
      GO TO 2100
C
 2060 CALL ANAPOW ( ANGMIN, ANGMAX, ANGSTP, JS(1), JS(2), JS(3), JS(4),
     1   NSPLI, IPARIT, .TRUE., PBUGSW, 'ANPOW   ', ELAB, 'REACTION',
     3   IF, ITOCS, IANPOW )
      T7 = second()                                                     33460   
C
C     NEXT THE INCIDENT ELASTIC CHANNEL.
C
 2100 IF ( SOSWS(1) )  GO TO 2120
      write (6, 2113)
 2113 FORMAT ( '0---- ALL INCOMING ELASTIC ANALYZING POWERS ARE ZERO',
     1   ' ----' )
      GO TO 2150
C
 2120 CALL ANAPOW ( ANGMIN, ANGMAX, ANGSTP, JS(1), JS(1), JS(3), JS(3), 33470   
     1   NUMJS(1), 1, .TRUE., PBUGSW, 'ANPOWA  ', ELAB, 'INCOMING',
     2   IFIN, ITOCE(1), IAPOWA )
C
C     NOW THE OUTGOING ELASTIC CHANNEL.
C
 2150 IF ( JS(2) .EQ. 0 )  GO TO 2190
      IF ( SOSWS(2) )  GO TO 2170
      write (6, 2163)
 2163 FORMAT ( '0---- ALL OUTGOING ELASTIC ANALYZING POWERS ARE ZERO',
     1   ' ----' )                                                      33480   
      GO TO 2190
C
 2170 EELAB = (1+RATMSS(2))*(E+Q)
      CALL ANAPOW ( ANGMIN, ANGMAX, ANGSTP, JS(2), JS(2), JS(4), JS(4),
     1   NUMJS(2), 1, .TRUE., PBUGSW, 'ANPOWB  ', EELAB, 'OUTGOING',
     2   IFOUT, ITOCE(2), IAPOWB )
C
 2190 T8 = second()
C
C     PRINT SOME TIMING INFO.                                           33490   
C
      TIME = second() - TSTART
      TPHS = T1-TSTART
      T1 = T2-T1
      T6 = T7 - T6
      T7 = T8 - T7
      T9 = TIME-TPHS-T1-TBET-TCROSS-T6-T7
      CRSFLP = 1.E-6*CRSFLP
      CRSFPS = CRSFLP/TCROSS
      write (6, 2583) TPHS, T1, TBET, TCROSS, CRSFLP, CRSFPS, T6, T7,   33500   
     1   T9, TIME
 2583 FORMAT ( '0' / '0' / '0CPU TIMES FOR CROSS SECTIONS (SECONDS):' /
     1  '0PRINTING PHASE SHIFTS', T30, F10.3 /
     2  ' ELASTIC CROSS SECTIONS', T30, F10.3 /
     3  ' BETA''S (SUM ON LI)', T30, F10.3 /
     4  ' REACTION CROSS SECTIONS', T30, F10.3,
     4      10X, '(', F7.2, ' MFLOPS =', F7.3, ' MFLOP/SEC )' /
     5   ' REACTION ANALYZING POWERS', T30, F10.3 /
     6   ' ELASTIC ANALYZING POWERS', T30, F10.3 /
     7  ' ALL OTHER TIME', T30, F10.3 /                                 33510   
     8  ' TOTAL TIME', T30, F17.3 / / '0' )
C
      IRTN = 1
      RETURN
      END
